window.NOVEL_DATA_2701 = {"novelId": 2701, "title": "Moby Dick", "author": "Herman Melville", "numChunks": 8382, "inTraining": false, "chunks": [{"id": 0, "position": 0, "text": "MOBY-DICK;\n\nor, THE WHALE.\n\nBy Herman Melville\n\n\n\nCONTENTS\n\nETYMOLOGY.\n\nEXTRACTS (Supplied by a Sub-Sub-Librarian).\n\nCHAPTER 1. Loomings.\n\nCHAPTER 2. The Carpet-Bag.\n\nCHAPTER 3", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1, "position": 1, "text": "2. The Carpet-Bag.\n\nCHAPTER 3. The Spouter-Inn.\n\nCHAPTER 4. The Counterpane.\n\nCHAPTER 5. Breakfast.\n\nCHAPTER 6. The Street.\n\nCHAPTER 7. The Chapel.\n\nCHAPTER 8. The Pulpit.\n\nCHAPTER 9", "labels": {"50": 48, "100": 27, "250": 59, "500": 397, "1000": 598, "2000": 803}}, {"id": 2, "position": 2, "text": ".\n\nCHAPTER 7. The Chapel.\n\nCHAPTER 8. The Pulpit.\n\nCHAPTER 9. The Sermon.\n\nCHAPTER 10. A Bosom Friend.\n\nCHAPTER 11. Nightgown.\n\nCHAPTER 12. Biographical.\n\nCHAPTER 13. Wheelbarrow.\n\nCHAPTER 14", "labels": {"50": 17, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 3, "position": 3, "text": "12. Biographical.\n\nCHAPTER 13. Wheelbarrow.\n\nCHAPTER 14. Nantucket.\n\nCHAPTER 15. Chowder.\n\nCHAPTER 16. The Ship.\n\nCHAPTER 17. The Ramadan.\n\nCHAPTER 18. His Mark.\n\nCHAPTER 19. The Prophet.\n\nCHAPTER 20", "labels": {"50": 32, "100": 0, "250": 233, "500": 55, "1000": 856, "2000": 359}}, {"id": 4, "position": 4, "text": ".\n\nCHAPTER 18. His Mark.\n\nCHAPTER 19. The Prophet.\n\nCHAPTER 20. All Astir.\n\nCHAPTER 21. Going Aboard.\n\nCHAPTER 22. Merry Christmas.\n\nCHAPTER 23. The Lee Shore.\n\nCHAPTER 24. The Advocate.\n\nCHAPTER 25", "labels": {"50": 13, "100": 73, "250": 15, "500": 405, "1000": 598, "2000": 803}}, {"id": 5, "position": 5, "text": ". The Lee Shore.\n\nCHAPTER 24. The Advocate.\n\nCHAPTER 25. Postscript.\n\nCHAPTER 26. Knights and Squires.\n\nCHAPTER 27. Knights and Squires.\n\nCHAPTER 28. Ahab.\n\nCHAPTER 29", "labels": {"50": 17, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 6, "position": 6, "text": ". Ahab.\n\nCHAPTER 29. Enter Ahab; to Him, Stubb.\n\nCHAPTER 30. The Pipe.\n\nCHAPTER 31. Queen Mab.\n\nCHAPTER 32. Cetology.\n\nCHAPTER 33. The Specksnyder.\n\nCHAPTER 34", "labels": {"50": 38, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 7, "position": 7, "text": "CHAPTER 33. The Specksnyder.\n\nCHAPTER 34. The Cabin-Table.\n\nCHAPTER 35. The Mast-Head.\n\nCHAPTER 36. The Quarter-Deck.\n\nCHAPTER 37. Sunset.\n\nCHAPTER 38. Dusk.\n\nCHAPTER 39. First Night-Watch", "labels": {"50": 45, "100": 64, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 8, "position": 8, "text": ". Sunset.\n\nCHAPTER 38. Dusk.\n\nCHAPTER 39. First Night-Watch.\n\nCHAPTER 40. Midnight, Forecastle.\n\nCHAPTER 41. Moby Dick.\n\nCHAPTER 42. The Whiteness of the Whale.\n\nCHAPTER 43. Hark!\n\nCHAPTER 44", "labels": {"50": 45, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 9, "position": 9, "text": "Whiteness of the Whale.\n\nCHAPTER 43. Hark!\n\nCHAPTER 44. The Chart.\n\nCHAPTER 45. The Affidavit.\n\nCHAPTER 46. Surmises.\n\nCHAPTER 47. The Mat-Maker.\n\nCHAPTER 48. The First Lowering.", "labels": {"50": 38, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 10, "position": 10, "text": "47. The Mat-Maker.\n\nCHAPTER 48. The First Lowering.\n\nCHAPTER 49. The Hyena.\n\nCHAPTER 50. Ahab’s Boat and Crew. Fedallah.\n\nCHAPTER 51. The Spirit-Spout.\n\nCHAPTER 52", "labels": {"50": 44, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 11, "position": 11, "text": "h.\n\nCHAPTER 51. The Spirit-Spout.\n\nCHAPTER 52. The Albatross.\n\nCHAPTER 53. The Gam.\n\nCHAPTER 54. The Town-Ho’s Story.\n\nCHAPTER 55. Of the Monstrous Pictures of Whales.\n\nCHAPTER 56", "labels": {"50": 38, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 12, "position": 12, "text": "Story.\n\nCHAPTER 55. Of the Monstrous Pictures of Whales.\n\nCHAPTER 56. Of the Less Erroneous Pictures of Whales, and the True\nPictures of Whaling Scenes.\n\nCHAPTER 57. Of Whales in Paint; in Teeth; in Wood; in Sheet-", "labels": {"50": 3, "100": 98, "250": 96, "500": 72, "1000": 598, "2000": 1620}}, {"id": 13, "position": 13, "text": ". Of Whales in Paint; in Teeth; in Wood; in Sheet-Iron; in\nStone; in Mountains; in Stars.\n\nCHAPTER 58. Brit.\n\nCHAPTER 59. Squid.\n\nCHAPTER 60. The Line.\n\nCHAPTER 61. Stubb Kills a Whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 14, "position": 14, "text": ".\n\nCHAPTER 60. The Line.\n\nCHAPTER 61. Stubb Kills a Whale.\n\nCHAPTER 62. The Dart.\n\nCHAPTER 63. The Crotch.\n\nCHAPTER 64. Stubb’s Supper.\n\nCHAPTER 65. The Whale as a Dish.\n\nCHAPTER 66", "labels": {"50": 38, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 15, "position": 15, "text": "Supper.\n\nCHAPTER 65. The Whale as a Dish.\n\nCHAPTER 66. The Shark Massacre.\n\nCHAPTER 67. Cutting In.\n\nCHAPTER 68. The Blanket.\n\nCHAPTER 69. The Funeral.\n\nCHAPTER 70. The Sphynx.\n\nCHAPTER 71", "labels": {"50": 45, "100": 40, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 16, "position": 16, "text": ".\n\nCHAPTER 70. The Sphynx.\n\nCHAPTER 71. The Jeroboam’s Story.\n\nCHAPTER 72. The Monkey-Rope.\n\nCHAPTER 73. Stubb and Flask kill a Right Whale; and Then Have a Talk\nover Him.", "labels": {"50": 45, "100": 29, "250": 138, "500": 179, "1000": 598, "2000": 803}}, {"id": 17, "position": 17, "text": "Flask kill a Right Whale; and Then Have a Talk\nover Him.\n\nCHAPTER 74. The Sperm Whale’s Head—Contrasted View.\n\nCHAPTER 75. The Right Whale’s Head—Contrasted View.\n\nCHAPTER 76. The Battering-Ram.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 18, "position": 18, "text": "s Head—Contrasted View.\n\nCHAPTER 76. The Battering-Ram.\n\nCHAPTER 77. The Great Heidelburgh Tun.\n\nCHAPTER 78. Cistern and Buckets.\n\nCHAPTER 79. The Prairie.\n\nCHAPTER 80. The Nut.\n\nCHAPTER 81", "labels": {"50": 48, "100": 5, "250": 96, "500": 412, "1000": 598, "2000": 803}}, {"id": 19, "position": 19, "text": ".\n\nCHAPTER 79. The Prairie.\n\nCHAPTER 80. The Nut.\n\nCHAPTER 81. The Pequod Meets The Virgin.\n\nCHAPTER 82. The Honor and Glory of Whaling.\n\nCHAPTER 83. Jonah Historically Regarded.\n\nCHAPTER 84. Pitchpoling.\n\nCHAPTER 85", "labels": {"50": 38, "100": 38, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 20, "position": 20, "text": "83. Jonah Historically Regarded.\n\nCHAPTER 84. Pitchpoling.\n\nCHAPTER 85. The Fountain.\n\nCHAPTER 86. The Tail.\n\nCHAPTER 87. The Grand Armada.\n\nCHAPTER 88. Schools and Schoolmasters.\n\nCHAPTER 89. Fast-Fish and Loose-Fish", "labels": {"50": 38, "100": 98, "250": 225, "500": 132, "1000": 598, "2000": 803}}, {"id": 21, "position": 21, "text": "Schools and Schoolmasters.\n\nCHAPTER 89. Fast-Fish and Loose-Fish.\n\nCHAPTER 90. Heads or Tails.\n\nCHAPTER 91. The Pequod Meets The Rose-Bud.\n\nCHAPTER 92. Ambergris.\n\nCHAPTER 93. The Castaway.", "labels": {"50": 3, "100": 85, "250": 14, "500": 486, "1000": 598, "2000": 803}}, {"id": 22, "position": 22, "text": ".\n\nCHAPTER 92. Ambergris.\n\nCHAPTER 93. The Castaway.\n\nCHAPTER 94. A Squeeze of the Hand.\n\nCHAPTER 95. The Cassock.\n\nCHAPTER 96. The Try-Works.\n\nCHAPTER 97. The Lamp.\n\nCHAPTER 98", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 300, "2000": 1014}}, {"id": 23, "position": 23, "text": "Try-Works.\n\nCHAPTER 97. The Lamp.\n\nCHAPTER 98. Stowing Down and Clearing Up.\n\nCHAPTER 99. The Doubloon.\n\nCHAPTER 100. Leg and Arm.\n\nCHAPTER 101. The Decanter.\n\nCHAPTER 102", "labels": {"50": 24, "100": 40, "250": 96, "500": 17, "1000": 598, "2000": 803}}, {"id": 24, "position": 24, "text": ".\n\nCHAPTER 101. The Decanter.\n\nCHAPTER 102. A Bower in the Arsacides.\n\nCHAPTER 103. Measurement of The Whale’s Skeleton.\n\nCHAPTER 104. The Fossil Whale.\n\nCHAPTER 105", "labels": {"50": 38, "100": 98, "250": 225, "500": 132, "1000": 598, "2000": 803}}, {"id": 25, "position": 25, "text": "The Fossil Whale.\n\nCHAPTER 105. Does the Whale’s Magnitude Diminish?—Will He Perish?\n\nCHAPTER 106. Ahab’s Leg.\n\nCHAPTER 107. The Carpenter.\n\nCHAPTER 108. Ahab and the Carpenter.\n\nCHAPTER 109", "labels": {"50": 38, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 26, "position": 26, "text": "The Carpenter.\n\nCHAPTER 108. Ahab and the Carpenter.\n\nCHAPTER 109. Ahab and Starbuck in the Cabin.\n\nCHAPTER 110. Queequeg in His Coffin.\n\nCHAPTER 111. The Pacific.\n\nCHAPTER 112. The Blacksmith.\n\nCHAPTER 113", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 27, "position": 27, "text": "CHAPTER 111. The Pacific.\n\nCHAPTER 112. The Blacksmith.\n\nCHAPTER 113. The Forge.\n\nCHAPTER 114. The Gilder.\n\nCHAPTER 115. The Pequod Meets The Bachelor.\n\nCHAPTER 116. The Dying Whale.\n\nCHAPTER 117. The Whale Watch.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 598, "2000": 1620}}, {"id": 28, "position": 28, "text": ".\n\nCHAPTER 116. The Dying Whale.\n\nCHAPTER 117. The Whale Watch.\n\nCHAPTER 118. The Quadrant.\n\nCHAPTER 119. The Candles.\n\nCHAPTER 120. The Deck Towards the End of the First Night Watch.\n\nCHAPTER 121", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 598, "2000": 803}}, {"id": 29, "position": 29, "text": "of the First Night Watch.\n\nCHAPTER 121. Midnight.—The Forecastle Bulwarks.\n\nCHAPTER 122. Midnight Aloft.—Thunder and Lightning.\n\nCHAPTER 123. The Musket.\n\nCHAPTER 124. The Needle.\n\nCHAPTER 125", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 598, "2000": 803}}, {"id": 30, "position": 30, "text": "The Musket.\n\nCHAPTER 124. The Needle.\n\nCHAPTER 125. The Log and Line.\n\nCHAPTER 126. The Life-Buoy.\n\nCHAPTER 127. The Deck.\n\nCHAPTER 128. The Pequod Meets The Rachel.\n\nCHAPTER 129. The Cabin", "labels": {"50": 45, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 31, "position": 31, "text": "128. The Pequod Meets The Rachel.\n\nCHAPTER 129. The Cabin.\n\nCHAPTER 130. The Hat.\n\nCHAPTER 131. The Pequod Meets The Delight.\n\nCHAPTER 132. The Symphony.\n\nCHAPTER 133. The Chase—First Day.\n\nCHAPTER 134", "labels": {"50": 44, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 32, "position": 32, "text": ". The Symphony.\n\nCHAPTER 133. The Chase—First Day.\n\nCHAPTER 134. The Chase—Second Day.\n\nCHAPTER 135. The Chase.—Third Day.\n\nEpilogue\n\n\n\n\nOriginal Transcriber’s Notes:", "labels": {"50": 38, "100": 98, "250": 96, "500": 179, "1000": 598, "2000": 803}}, {"id": 33, "position": 33, "text": "criber’s Notes:\n\nThis text is a combination of etexts, one from the now-defunct ERIS\nproject at Virginia Tech and one from Project Gutenberg’s archives. The\nproofreaders of this version are indebted", "labels": {"50": 17, "100": 40, "250": 74, "500": 355, "1000": 667, "2000": 1352}}, {"id": 34, "position": 34, "text": "’s archives. The\nproofreaders of this version are indebted to The University of Adelaide\nLibrary for preserving the Virginia Tech version. The resulting etext\nwas compared with a public domain hard copy version of the text.\n\n\n\n\n\n  ETYMOLOGY.", "labels": {"50": 17, "100": 40, "250": 74, "500": 355, "1000": 667, "2000": 1352}}, {"id": 35, "position": 35, "text": "with a public domain hard copy version of the text.\n\n\n\n\n\n  ETYMOLOGY.\n\n\n  (Supplied by a Late Consumptive Usher to a Grammar School.)\n\n  The pale Usher—threadbare in coat, heart, body, and brain; I see him\n  now", "labels": {"50": 41, "100": 1, "250": 120, "500": 498, "1000": 647, "2000": 1649}}, {"id": 36, "position": 36, "text": "in coat, heart, body, and brain; I see him\n  now. He was ever dusting his old lexicons and grammars, with a queer\n  handkerchief, mockingly embellished with all the gay flags of all the\n  known nations of", "labels": {"50": 25, "100": 41, "250": 156, "500": 498, "1000": 329, "2000": 381}}, {"id": 37, "position": 37, "text": "ly embellished with all the gay flags of all the\n  known nations of the world. He loved to dust his old grammars; it\n  somehow mildly reminded him of his mortality.\n\n  “While you take in hand to school others, and to teach them", "labels": {"50": 31, "100": 37, "250": 175, "500": 453, "1000": 363, "2000": 695}}, {"id": 38, "position": 38, "text": ".\n\n  “While you take in hand to school others, and to teach them by what\n  name a whale-fish is to be called in our tongue, leaving out, through\n  ignorance, the letter H, which almost alone maketh up the\n  signification of", "labels": {"50": 45, "100": 64, "250": 30, "500": 72, "1000": 825, "2000": 1620}}, {"id": 39, "position": 39, "text": ", the letter H, which almost alone maketh up the\n  signification of the word, you deliver that which is not true.”\n  —_Hackluyt._\n\n  “WHALE. * * * Sw. and Dan. _hval_", "labels": {"50": 3, "100": 47, "250": 27, "500": 72, "1000": 803, "2000": 1620}}, {"id": 40, "position": 40, "text": "WHALE. * * * Sw. and Dan. _hval_. This animal is named from\n  roundness or rolling; for in Dan. _hvalt_ is arched or vaulted.”\n  —_Webster’s Dictionary._\n\n  “WHALE", "labels": {"50": 38, "100": 47, "250": 27, "500": 283, "1000": 803, "2000": 1620}}, {"id": 41, "position": 41, "text": "arched or vaulted.”\n  —_Webster’s Dictionary._\n\n  “WHALE. * * * It is more immediately from the Dut. and Ger. _Wallen_;\n  A.S. _Walw-ian_, to roll", "labels": {"50": 38, "100": 47, "250": 149, "500": 20, "1000": 704, "2000": 1362}}, {"id": 42, "position": 42, "text": "_;\n  A.S. _Walw-ian_, to roll, to wallow.” —_Richardson’s Dictionary._\n\n\n  ‏חו‎,                _Hebrew_.\n  ϰητος,             _Greek_.\n  CETUS,             _Latin_", "labels": {"50": 38, "100": 47, "250": 27, "500": 283, "1000": 449, "2000": 917}}, {"id": 43, "position": 43, "text": ".\n  ϰητος,             _Greek_.\n  CETUS,             _Latin_.\n  WHŒL,              _Anglo-Saxon_.\n  HVALT,             _Danish_.\n  WAL,               _Dutch_.\n  HWAL,              _Swedish_", "labels": {"50": 38, "100": 47, "250": 27, "500": 283, "1000": 112, "2000": 1160}}, {"id": 44, "position": 44, "text": "_Dutch_.\n  HWAL,              _Swedish_.\n  HVALUR,            _Icelandic_.\n  WHALE,             _English_.\n  BALEINE,           _French_.\n  BALLENA,           _Spanish_.\n  PEKEE-NUEE-NUEE,   _", "labels": {"50": 38, "100": 47, "250": 27, "500": 283, "1000": 112, "2000": 909}}, {"id": 45, "position": 45, "text": ",           _Spanish_.\n  PEKEE-NUEE-NUEE,   _Fegee_.\n  PEHEE-NUEE-NUEE,   _Erromangoan_.\n\n\n  EXTRACTS. (Supplied by a Sub-Sub-Librarian).", "labels": {"50": 38, "100": 47, "250": 27, "500": 283, "1000": 112, "2000": 1160}}, {"id": 46, "position": 46, "text": "EXTRACTS. (Supplied by a Sub-Sub-Librarian).\n\n\n\n  It will be seen that this mere painstaking burrower and grub-worm of\n  a poor devil of a Sub-Sub appears to have gone through the long\n  Vaticans and street-", "labels": {"50": 17, "100": 68, "250": 111, "500": 62, "1000": 472, "2000": 906}}, {"id": 47, "position": 47, "text": "Sub-Sub appears to have gone through the long\n  Vaticans and street-stalls of the earth, picking up whatever random\n  allusions to whales he could anyways find in any book whatsoever,\n  sacred or profane", "labels": {"50": 17, "100": 40, "250": 74, "500": 355, "1000": 162, "2000": 53}}, {"id": 48, "position": 48, "text": "book whatsoever,\n  sacred or profane. Therefore you must not, in every case at least,\n  take the higgledy-piggledy whale statements, however authentic, in\n  these extracts, for veritable gospel cetology. Far from it", "labels": {"50": 31, "100": 75, "250": 69, "500": 307, "1000": 372, "2000": 506}}, {"id": 49, "position": 49, "text": "these extracts, for veritable gospel cetology. Far from it. As\n  touching the ancient authors generally, as well as the poets here\n  appearing, these extracts are solely valuable or entertaining, as\n  affording a glancing bird’s eye view of what", "labels": {"50": 17, "100": 16, "250": 198, "500": 86, "1000": 736, "2000": 1302}}, {"id": 50, "position": 50, "text": "or entertaining, as\n  affording a glancing bird’s eye view of what has been promiscuously\n  said, thought, fancied, and sung of Leviathan, by many nations and\n  generations, including our own.", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 51, "position": 51, "text": "by many nations and\n  generations, including our own.\n\n  So fare thee well, poor devil of a Sub-Sub, whose commentator I am.\n  Thou belongest to that hopeless, sallow tribe which no wine of this\n  world will ever warm; and for", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 39}}, {"id": 52, "position": 52, "text": "sallow tribe which no wine of this\n  world will ever warm; and for whom even Pale Sherry would be too\n  rosy-strong; but with whom one sometimes loves to sit, and feel\n  poor-devilish, too; and grow convivial upon", "labels": {"50": 9, "100": 73, "250": 120, "500": 143, "1000": 50, "2000": 1886}}, {"id": 53, "position": 53, "text": "and feel\n  poor-devilish, too; and grow convivial upon tears; and say to them\n  bluntly, with full eyes and empty glasses, and in not altogether\n  unpleasant sadness—Give it up, Sub-Subs! For by how", "labels": {"50": 9, "100": 73, "250": 193, "500": 498, "1000": 637, "2000": 421}}, {"id": 54, "position": 54, "text": "unpleasant sadness—Give it up, Sub-Subs! For by how much the more\n  pains ye take to please the world, by so much the more shall ye for\n  ever go thankless! Would that I could clear out Hampton Court and the\n  Tu", "labels": {"50": 23, "100": 45, "250": 193, "500": 498, "1000": 849, "2000": 39}}, {"id": 55, "position": 55, "text": "go thankless! Would that I could clear out Hampton Court and the\n  Tuileries for ye! But gulp down your tears and hie aloft to the\n  royal-mast with your hearts; for your friends who have gone before\n  are clearing out the", "labels": {"50": 8, "100": 45, "250": 86, "500": 174, "1000": 591, "2000": 421}}, {"id": 56, "position": 56, "text": "with your hearts; for your friends who have gone before\n  are clearing out the seven-storied heavens, and making refugees of\n  long-pampered Gabriel, Michael, and Raphael, against your coming", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 709}}, {"id": 57, "position": 57, "text": "and Raphael, against your coming.\n  Here ye strike but splintered hearts together—there, ye shall strike\n  unsplinterable glasses!\n\nEXTRACTS.\n\n  “And God created great whales.” —_Genesis_.", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 779, "2000": 16}}, {"id": 58, "position": 58, "text": "whales.” —_Genesis_.\n\n  “Leviathan maketh a path to shine after him; One would think the deep\n  to be hoary.” —_Job_.\n\n  “Now the Lord had prepared a great fish to swallow up Jonah.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 59, "position": 59, "text": ".\n\n  “Now the Lord had prepared a great fish to swallow up Jonah.”\n  —_Jonah_.\n\n  “There go the ships; there is that Leviathan whom thou hast made to\n  play therein.” —_Psalms_.", "labels": {"50": 27, "100": 33, "250": 112, "500": 72, "1000": 825, "2000": 1620}}, {"id": 60, "position": 60, "text": "t made to\n  play therein.” —_Psalms_.\n\n  “In that day, the Lord with his sore, and great, and strong sword,\n  shall punish Leviathan the piercing serpent, even Leviathan that\n  crooked serpent; and he shall sl", "labels": {"50": 35, "100": 26, "250": 23, "500": 198, "1000": 201, "2000": 172}}, {"id": 61, "position": 61, "text": "the piercing serpent, even Leviathan that\n  crooked serpent; and he shall slay the dragon that is in the sea.”\n  —_Isaiah_.\n\n  “And what thing soever besides cometh within the chaos of this\n  monster’s mouth, be", "labels": {"50": 40, "100": 24, "250": 240, "500": 288, "1000": 673, "2000": 481}}, {"id": 62, "position": 62, "text": "ever besides cometh within the chaos of this\n  monster’s mouth, be it beast, boat, or stone, down it goes all\n  incontinently that foul great swallow of his, and perisheth in the\n  bottomless gulf of his pau", "labels": {"50": 18, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 63, "position": 63, "text": "of his, and perisheth in the\n  bottomless gulf of his paunch.” —_Holland’s Plutarch’s Morals_.\n\n  “The Indian Sea breedeth the most and the biggest fishes that are:\n  among which the Whales", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 64, "position": 64, "text": "breedeth the most and the biggest fishes that are:\n  among which the Whales and Whirlpooles called Balaene, take up as\n  much in length as four acres or arpens of land.” —_Holland’s Pliny_", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 447}}, {"id": 65, "position": 65, "text": "arpens of land.” —_Holland’s Pliny_.\n\n  “Scarcely had we proceeded two days on the sea, when about sunrise a\n  great many Whales and other monsters of the sea, appeared", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 66, "position": 66, "text": "other monsters of the sea, appeared. Among the\n  former, one was of a most monstrous size.... This came towards us,\n  open-mouthed, raising the waves on all sides, and beating the sea\n  before him into a foam.”", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 67, "position": 67, "text": "on all sides, and beating the sea\n  before him into a foam.” —_Tooke’s Lucian_. “_The True History_.”\n\n\n\n\n  “He visited this country also with a view of catching horse-whales,\n  which had bones", "labels": {"50": 3, "100": 24, "250": 234, "500": 288, "1000": 825, "2000": 1225}}, {"id": 68, "position": 68, "text": "this country also with a view of catching horse-whales,\n  which had bones of very great value for their teeth, of which he\n  brought some to the king.... The best whales were catched in his own\n  country, of which some were", "labels": {"50": 40, "100": 83, "250": 161, "500": 13, "1000": 575, "2000": 199}}, {"id": 69, "position": 69, "text": "The best whales were catched in his own\n  country, of which some were forty-eight, some fifty yards long. He\n  said that he was one of six who had killed sixty in two days.”\n  —_Other or Other’s verbal narrative", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 70, "position": 70, "text": "sixty in two days.”\n  —_Other or Other’s verbal narrative taken down from his mouth by King\n  Alfred, A.D._ 890.\n\n  “And whereas all the other things, whether beast or vessel, that\n  enter into the dreadful", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 71, "position": 71, "text": "all the other things, whether beast or vessel, that\n  enter into the dreadful gulf of this monster’s (whale’s) mouth, are\n  immediately lost and swallowed up, the sea-gudgeon retires into it in\n  great security, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 72, "position": 72, "text": "the sea-gudgeon retires into it in\n  great security, and there sleeps.” —MONTAIGNE. —_Apology for Raimond\n  Sebond_.\n\n  “Let us fly, let us fly! Old Nick take me if it", "labels": {"50": 40, "100": 24, "250": 30, "500": 288, "1000": 673, "2000": 715}}, {"id": 73, "position": 73, "text": "“Let us fly, let us fly! Old Nick take me if it is not Leviathan\n  described by the noble prophet Moses in the life of patient Job.”\n  —_Rabelais_.\n\n  “This whale’s liver was two cartload", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 74, "position": 74, "text": "Rabelais_.\n\n  “This whale’s liver was two cartloads.” —_Stowe’s Annals_.\n\n  “The great Leviathan that maketh the seas to seethe like boiling\n  pan.” —_Lord Bacon’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 75, "position": 75, "text": "the seas to seethe like boiling\n  pan.” —_Lord Bacon’s Version of the Psalms_.\n\n  “Touching that monstrous bulk of the whale or ork we have received\n  nothing certain. They grow exceeding fat, insomuch that an incredible", "labels": {"50": 17, "100": 16, "250": 87, "500": 449, "1000": 218, "2000": 301}}, {"id": 76, "position": 76, "text": "received\n  nothing certain. They grow exceeding fat, insomuch that an incredible\n  quantity of oil will be extracted out of one whale.” —_Ibid_.\n  “_History of Life and Death_.”", "labels": {"50": 3, "100": 24, "250": 34, "500": 72, "1000": 825, "2000": 1620}}, {"id": 77, "position": 77, "text": "History of Life and Death_.”\n\n\n\n\n  “The sovereignest thing on earth is parmacetti for an inward bruise.”\n  —_King Henry_.\n\n  “Very like a whale.” —_Hamlet_.", "labels": {"50": 3, "100": 47, "250": 227, "500": 324, "1000": 934, "2000": 469}}, {"id": 78, "position": 78, "text": "whale.” —_Hamlet_.\n\n\n  “Which to secure, no skill of leach’s art Mote him availle, but to\n  returne againe To his wound’s worker, that with lowly dart, Dinting\n  his breast,", "labels": {"50": 9, "100": 47, "250": 149, "500": 20, "1000": 921, "2000": 1362}}, {"id": 79, "position": 79, "text": "’s worker, that with lowly dart, Dinting\n  his breast, had bred his restless paine, Like as the wounded whale to\n  shore flies thro’ the maine.” —_The Fairie Queen_.", "labels": {"50": 9, "100": 73, "250": 120, "500": 498, "1000": 637, "2000": 1003}}, {"id": 80, "position": 80, "text": ".” —_The Fairie Queen_.\n\n\n\n  “Immense as whales, the motion of whose vast bodies can in a peaceful\n  calm trouble the ocean till it boil.” —_Sir William Davenant. Preface\n  to Gondibert_.", "labels": {"50": 3, "100": 24, "250": 139, "500": 72, "1000": 825, "2000": 1620}}, {"id": 81, "position": 81, "text": "_Sir William Davenant. Preface\n  to Gondibert_.\n\n  “What spermacetti is, men might justly doubt, since the learned\n  Hosmannus in his work of thirty years, saith plainly, _Nescio quid\n  sit_", "labels": {"50": 17, "100": 54, "250": 198, "500": 62, "1000": 803, "2000": 293}}, {"id": 82, "position": 82, "text": "of thirty years, saith plainly, _Nescio quid\n  sit_.” —_Sir T. Browne. Of Sperma Ceti and the Sperma Ceti Whale.\n  Vide his V. E._", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 83, "position": 83, "text": "Whale.\n  Vide his V. E._\n\n\n  “Like Spencer’s Talus with his modern flail He threatens ruin with\n  his ponderous tail. ... Their fixed jav’lins in his side he wears,\n  And on his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 84, "position": 84, "text": "fixed jav’lins in his side he wears,\n  And on his back a grove of pikes appears.” —_Waller’s Battle of the\n  Summer Islands_.\n\n\n\n  “By art is created that great Leviathan, called a Commonwealth or", "labels": {"50": 17, "100": 98, "250": 111, "500": 62, "1000": 725, "2000": 200}}, {"id": 85, "position": 85, "text": ".\n\n\n\n  “By art is created that great Leviathan, called a Commonwealth or\n  State—(in Latin, Civitas) which is but an artificial man.” —_Opening\n  sentence of Hobbes’s Leviathan_.", "labels": {"50": 21, "100": 95, "250": 76, "500": 107, "1000": 761, "2000": 1357}}, {"id": 86, "position": 86, "text": "Opening\n  sentence of Hobbes’s Leviathan_.\n\n  “Silly Mansoul swallowed it without chewing, as if it had been a\n  sprat in the mouth of a whale.” —_Pilgrim’s Progress_.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 87, "position": 87, "text": "whale.” —_Pilgrim’s Progress_.\n\n\n  “That sea beast Leviathan, which God of all his works Created hugest\n  that swim the ocean stream.” —_Paradise Lost_.\n\n  —“There Leviathan, Hugest of living", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 88, "position": 88, "text": "_Paradise Lost_.\n\n  —“There Leviathan, Hugest of living creatures, in the deep Stretched\n  like a promontory sleeps or swims, And seems a moving land; and at\n  his gills Draws in, and at his breath spouts", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 89, "position": 89, "text": "land; and at\n  his gills Draws in, and at his breath spouts out a sea.” —_Ibid_.\n\n\n\n  “The mighty whales which swim in a sea of water, and have a sea of\n  oil swimming in them.” —", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 90, "position": 90, "text": "of water, and have a sea of\n  oil swimming in them.” —_Fuller’s Profane and Holy State_.\n\n\n  “So close behind some promontory lie The huge Leviathan to attend\n  their prey, And give no chance, but", "labels": {"50": 31, "100": 37, "250": 143, "500": 294, "1000": 515, "2000": 433}}, {"id": 91, "position": 91, "text": "The huge Leviathan to attend\n  their prey, And give no chance, but swallow in the fry, Which through\n  their gaping jaws mistake the way.” —_Dryden’s Annus Mirabilis_.", "labels": {"50": 17, "100": 16, "250": 87, "500": 449, "1000": 187, "2000": 301}}, {"id": 92, "position": 92, "text": "s Annus Mirabilis_.\n\n\n\n  “While the whale is floating at the stern of the ship, they cut off\n  his head, and tow it with a boat as near the shore as it will come;\n  but it will be aground in twelve or thirteen", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 93, "position": 93, "text": "shore as it will come;\n  but it will be aground in twelve or thirteen feet water.” —_Thomas\n  Edge’s Ten Voyages to Spitzbergen, in Purchas_.\n\n  “In their way they saw many whales sporting in the", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 94, "position": 94, "text": "rchas_.\n\n  “In their way they saw many whales sporting in the ocean, and in\n  wantonness fuzzing up the water through their pipes and vents, which\n  nature has placed on their shoulders.” —_Sir T", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 95, "position": 95, "text": "nature has placed on their shoulders.” —_Sir T. Herbert’s Voyages\n  into Asia and Africa. Harris Coll_.\n\n  “Here they saw such huge troops of whales, that they were forced to\n  proceed with a great deal of caution for", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 96, "position": 96, "text": "whales, that they were forced to\n  proceed with a great deal of caution for fear they should run their\n  ship upon them.” —_Schouten’s Sixth Circumnavigation_.", "labels": {"50": 45, "100": 29, "250": 34, "500": 306, "1000": 622, "2000": 1950}}, {"id": 97, "position": 97, "text": "rcumnavigation_.\n\n  “We set sail from the Elbe, wind N.E. in the ship called The\n  Jonas-in-the-Whale.... Some say the whale can’t open his mouth, but\n  that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 98, "position": 98, "text": ".. Some say the whale can’t open his mouth, but\n  that is a fable.... They frequently climb up the masts to see whether\n  they can see a whale, for the first discoverer has a ducat for his\n  pains", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 99, "position": 99, "text": "a whale, for the first discoverer has a ducat for his\n  pains.... I was told of a whale taken near Shetland, that had above a\n  barrel of herrings in his belly...", "labels": {"50": 45, "100": 76, "250": 24, "500": 287, "1000": 975, "2000": 1627}}, {"id": 100, "position": 100, "text": "herrings in his belly.... One of our harpooneers told me\n  that he caught once a whale in Spitzbergen that was white all over.”\n  —_A Voyage to Greenland, A.D._ 1671", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 101, "position": 101, "text": "—_A Voyage to Greenland, A.D._ 1671. _Harris Coll_.\n\n  “Several whales have come in upon this coast (Fife) Anno 1652, one\n  eighty feet in length of the whale-bone kind came in", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 102, "position": 102, "text": "1652, one\n  eighty feet in length of the whale-bone kind came in, which (as I was\n  informed), besides a vast quantity of oil, did afford 500 weight of\n  baleen. The jaws of it stand for a gate in the garden", "labels": {"50": 45, "100": 29, "250": 234, "500": 72, "1000": 825, "2000": 1620}}, {"id": 103, "position": 103, "text": "of\n  baleen. The jaws of it stand for a gate in the garden of Pitferren.”\n  —_Sibbald’s Fife and Kinross_.\n\n  “Myself have agreed to try whether I can master and kill this\n  Sperma-", "labels": {"50": 8, "100": 14, "250": 81, "500": 486, "1000": 956, "2000": 227}}, {"id": 104, "position": 104, "text": "Myself have agreed to try whether I can master and kill this\n  Sperma-ceti whale, for I could never hear of any of that sort that\n  was killed by any man, such is his fierceness and swiftness.”\n  —_Richard St", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 105, "position": 105, "text": ", such is his fierceness and swiftness.”\n  —_Richard Strafford’s Letter from the Bermudas. Phil. Trans. A.D._\n  1668.\n\n  “Whales in the sea God’s voice obey.” —", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 106, "position": 106, "text": "8.\n\n  “Whales in the sea God’s voice obey.” —_N. E. Primer_.\n\n  “We saw also abundance of large whales, there being more in those\n  southern seas, as I may say, by a hundred to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 107, "position": 107, "text": "more in those\n  southern seas, as I may say, by a hundred to one; than we have to the\n  northward of us.” —_Captain Cowley’s Voyage round the Globe, A.D._\n  1729.\n\n  “..", "labels": {"50": 45, "100": 29, "250": 138, "500": 13, "1000": 622, "2000": 877}}, {"id": 108, "position": 108, "text": "round the Globe, A.D._\n  1729.\n\n  “... and the breath of the whale is frequently attended with such an\n  insupportable smell, as to bring on a disorder of the brain.”\n  —_Ulloa’", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 145}}, {"id": 109, "position": 109, "text": "bring on a disorder of the brain.”\n  —_Ulloa’s South America_.\n\n\n  “To fifty chosen sylphs of special note, We trust the important\n  charge, the petticoat", "labels": {"50": 31, "100": 7, "250": 193, "500": 453, "1000": 849, "2000": 1394}}, {"id": 110, "position": 110, "text": "charge, the petticoat. Oft have we known that seven-fold fence to\n  fail, Tho’ stuffed with hoops and armed with ribs of whale.” —_Rape\n  of the Lock_.", "labels": {"50": 43, "100": 48, "250": 71, "500": 498, "1000": 993, "2000": 1392}}, {"id": 111, "position": 111, "text": "_Rape\n  of the Lock_.\n\n\n\n  “If we compare land animals in respect to magnitude, with those that\n  take up their abode in the deep, we shall find they will appear\n  contemptible in the comparison", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 112, "position": 112, "text": "appear\n  contemptible in the comparison. The whale is doubtless the largest\n  animal in creation.” —_Goldsmith, Nat. Hist_.\n\n  “If you should write a fable for little fishes, you would make them\n  speak like great whales.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 113, "position": 113, "text": "fable for little fishes, you would make them\n  speak like great whales.” —_Goldsmith to Johnson_.\n\n  “In the afternoon we saw what was supposed to be a rock, but it was\n  found to be a dead whale, which some Asiatics", "labels": {"50": 17, "100": 68, "250": 87, "500": 449, "1000": 218, "2000": 1620}}, {"id": 114, "position": 114, "text": ", but it was\n  found to be a dead whale, which some Asiatics had killed, and were\n  then towing ashore. They seemed to endeavor to conceal themselves\n  behind the whale, in order to avoid being seen by us.” —_Cook’s", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 115, "position": 115, "text": "in order to avoid being seen by us.” —_Cook’s\n  Voyages_.\n\n  “The larger whales, they seldom venture to attack. They stand in so\n  great dread of some of them, that when out at sea they are afraid to\n  mention", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 116, "position": 116, "text": "of some of them, that when out at sea they are afraid to\n  mention even their names, and carry dung, lime-stone, juniper-wood,\n  and some other articles of the same nature in their boats, in order\n  to terrify and prevent", "labels": {"50": 45, "100": 42, "250": 161, "500": 242, "1000": 626, "2000": 1580}}, {"id": 117, "position": 117, "text": "of the same nature in their boats, in order\n  to terrify and prevent their too near approach.” —_Uno Von Troil’s\n  Letters on Banks’s and Solander’s Voyage to Iceland in_ 1772.", "labels": {"50": 14, "100": 68, "250": 241, "500": 62, "1000": 456, "2000": 1522}}, {"id": 118, "position": 118, "text": "and Solander’s Voyage to Iceland in_ 1772.\n\n  “The Spermacetti Whale found by the Nantuckois, is an active, fierce\n  animal, and requires vast address and boldness in the fishermen.”\n  —_Thomas Jefferson’", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 119, "position": 119, "text": "vast address and boldness in the fishermen.”\n  —_Thomas Jefferson’s Whale Memorial to the French minister in_ 1778.\n\n  “And pray, sir, what in the world is equal to it?” —_Edmund Burke’s\n  reference in", "labels": {"50": 16, "100": 95, "250": 133, "500": 67, "1000": 971, "2000": 231}}, {"id": 120, "position": 120, "text": "world is equal to it?” —_Edmund Burke’s\n  reference in Parliament to the Nantucket Whale-Fishery_.\n\n  “Spain—a great whale stranded on the shores of Europe.” —_Edmund\n  Burke_", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 121, "position": 121, "text": "of Europe.” —_Edmund\n  Burke_. (_somewhere_.)\n\n  “A tenth branch of the king’s ordinary revenue, said to be grounded\n  on the consideration of his guarding and protecting the seas from\n  pirates and robbers, is the right", "labels": {"50": 15, "100": 52, "250": 200, "500": 67, "1000": 973, "2000": 1258}}, {"id": 122, "position": 122, "text": "of his guarding and protecting the seas from\n  pirates and robbers, is the right to _royal_ fish, which are whale\n  and sturgeon. And these, when either thrown ashore or caught near the\n  coast, are the property of the king.” —", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 447}}, {"id": 123, "position": 123, "text": "or caught near the\n  coast, are the property of the king.” —_Blackstone_.\n\n\n  “Soon to the sport of death the crews repair: Rodmond unerring o’er\n  his head suspends The barbed steel, and every turn attends", "labels": {"50": 45, "100": 29, "250": 82, "500": 72, "1000": 851, "2000": 1620}}, {"id": 124, "position": 124, "text": "o’er\n  his head suspends The barbed steel, and every turn attends.”\n  —_Falconer’s Shipwreck_.\n\n  “Bright shone the roofs, the domes, the spires, And rockets blew self\n  driven, To hang their", "labels": {"50": 18, "100": 83, "250": 170, "500": 60, "1000": 946, "2000": 203}}, {"id": 125, "position": 125, "text": "domes, the spires, And rockets blew self\n  driven, To hang their momentary fire Around the vault of heaven.\n\n  “So fire with water to compare, The ocean serves on high, Up-spouted\n  by a whale in air, To express", "labels": {"50": 9, "100": 26, "250": 133, "500": 122, "1000": 437, "2000": 573}}, {"id": 126, "position": 126, "text": "high, Up-spouted\n  by a whale in air, To express unwieldy joy.” —_Cowper, on the Queen’s\n  Visit to London_.\n\n\n\n  “Ten or fifteen gallons of blood are thrown out of the heart", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 127, "position": 127, "text": "_.\n\n\n\n  “Ten or fifteen gallons of blood are thrown out of the heart at a\n  stroke, with immense velocity.” —_John Hunter’s account of the\n  dissection of a whale_. (_A small sized one_.)", "labels": {"50": 3, "100": 70, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 128, "position": 128, "text": "ction of a whale_. (_A small sized one_.)\n\n  “The aorta of a whale is larger in the bore than the main pipe of the\n  water-works at London Bridge, and the water roaring in its passage\n  through that pipe", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 129, "position": 129, "text": "works at London Bridge, and the water roaring in its passage\n  through that pipe is inferior in impetus and velocity to the blood\n  gushing from the whale’s heart.” —_Paley’s Theology_.", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 130, "position": 130, "text": "_Paley’s Theology_.\n\n  “The whale is a mammiferous animal without hind feet.” —_Baron\n  Cuvier_.\n\n  “In 40 degrees south, we saw Spermacetti Whales, but did not take any\n  till the first", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 131, "position": 131, "text": "we saw Spermacetti Whales, but did not take any\n  till the first of May, the sea being then covered with them.”\n  —_Colnett’s Voyage for the Purpose of Extending the Spermaceti Whale\n  Fishery_.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 132, "position": 132, "text": "the Purpose of Extending the Spermaceti Whale\n  Fishery_.\n\n\n  “In the free element beneath me swam, Floundered and dived, in play,\n  in chace, in battle, Fishes of every colour, form, and kind; Which\n  language", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 133, "position": 133, "text": "in battle, Fishes of every colour, form, and kind; Which\n  language cannot paint, and mariner Had never seen; from dread\n  Leviathan To insect millions peopling every wave: Gather’d in shoals\n  immense, like floating islands,", "labels": {"50": 9, "100": 26, "250": 240, "500": 72, "1000": 663, "2000": 16}}, {"id": 134, "position": 134, "text": "every wave: Gather’d in shoals\n  immense, like floating islands, Led by mysterious instincts through\n  that waste And trackless region, though on every side Assaulted by\n  voracious enemies, Whales, sharks, and monsters, arm’d in front", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 135, "position": 135, "text": "ious enemies, Whales, sharks, and monsters, arm’d in front or\n  jaw, With swords, saws, spiral horns, or hooked fangs.”\n  —_Montgomery’s World before the Flood_.", "labels": {"50": 3, "100": 66, "250": 211, "500": 490, "1000": 478, "2000": 1799}}, {"id": 136, "position": 136, "text": "’s World before the Flood_.\n\n  “Io!  Paean!  Io! sing. To the finny people’s king. Not a mightier\n  whale than this In the vast Atlantic is; Not a fatter fish than he,\n  Flound", "labels": {"50": 9, "100": 26, "250": 240, "500": 232, "1000": 779, "2000": 16}}, {"id": 137, "position": 137, "text": "the vast Atlantic is; Not a fatter fish than he,\n  Flounders round the Polar Sea.” —_Charles Lamb’s Triumph of the\n  Whale_.\n\n\n\n  “In the year 1690 some persons were on a high hill observing the\n  whales sp", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 138, "position": 138, "text": "In the year 1690 some persons were on a high hill observing the\n  whales spouting and sporting with each other, when one observed:\n  there—pointing to the sea—is a green pasture where our children’s\n  grand-children will go for bread", "labels": {"50": 45, "100": 42, "250": 53, "500": 72, "1000": 9, "2000": 682}}, {"id": 139, "position": 139, "text": "a green pasture where our children’s\n  grand-children will go for bread.” —_Obed Macy’s History of\n  Nantucket_.\n\n  “I built a cottage for Susan and myself and made a gateway in the\n  form of a Gothic Arch", "labels": {"50": 38, "100": 98, "250": 139, "500": 165, "1000": 725, "2000": 200}}, {"id": 140, "position": 140, "text": "for Susan and myself and made a gateway in the\n  form of a Gothic Arch, by setting up a whale’s jaw bones.”\n  —_Hawthorne’s Twice Told Tales_.\n\n  “She came to bespeak a monument for her first love", "labels": {"50": 44, "100": 37, "250": 175, "500": 294, "1000": 515, "2000": 739}}, {"id": 141, "position": 141, "text": "_.\n\n  “She came to bespeak a monument for her first love, who had been\n  killed by a whale in the Pacific ocean, no less than forty years\n  ago.” —_Ibid_.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 142, "position": 142, "text": "” —_Ibid_.\n\n  “No, Sir, ’tis a Right Whale,” answered Tom; “I saw his sprout; he\n  threw up a pair of as pretty rainbows as a Christian would wish to\n  look at", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 143, "position": 143, "text": "of as pretty rainbows as a Christian would wish to\n  look at. He’s a raal oil-butt, that fellow!” —_Cooper’s Pilot_.\n\n  “The papers were brought in, and we saw in the Berlin Gazette", "labels": {"50": 41, "100": 21, "250": 174, "500": 5, "1000": 54, "2000": 274}}, {"id": 144, "position": 144, "text": ".\n\n  “The papers were brought in, and we saw in the Berlin Gazette that\n  whales had been introduced on the stage there.” —_Eckermann’s\n  Conversations with Goethe_.\n\n  “My God! Mr", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 505, "2000": 1620}}, {"id": 145, "position": 145, "text": "Goethe_.\n\n  “My God! Mr. Chace, what is the matter?” I answered, “we have been\n  stove by a whale.” —“_Narrative of the Shipwreck of the Whale Ship\n  Essex of Nantucket, which", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 146, "position": 146, "text": "of the Shipwreck of the Whale Ship\n  Essex of Nantucket, which was attacked and finally destroyed by a\n  large Sperm Whale in the Pacific Ocean_.” _By Owen Chace of\n  Nantucket, first mate of said vessel", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 147, "position": 147, "text": "Chace of\n  Nantucket, first mate of said vessel. New York_, 1821.\n\n\n  “A mariner sat in the shrouds one night, The wind was piping free;\n  Now bright, now dimmed, was the moonlight pale,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 148, "position": 148, "text": "ing free;\n  Now bright, now dimmed, was the moonlight pale, And the phospher\n  gleamed in the wake of the whale, As it floundered in the sea.”\n  —_Elizabeth Oakes Smith_.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 149, "position": 149, "text": "sea.”\n  —_Elizabeth Oakes Smith_.\n\n\n\n  “The quantity of line withdrawn from the boats engaged in the capture\n  of this one whale, amounted altogether to 10,440 yards or nearly six\n  English miles....", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 150, "position": 150, "text": "yards or nearly six\n  English miles....\n\n  “Sometimes the whale shakes its tremendous tail in the air, which,\n  cracking like a whip, resounds to the distance of three or four\n  miles.” —_Scoresby_.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 151, "position": 151, "text": "of three or four\n  miles.” —_Scoresby_.\n\n  “Mad with the agonies he endures from these fresh attacks, the\n  infuriated Sperm Whale rolls over and over; he rears his enormous\n  head, and with wide expanded jaws", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 152, "position": 152, "text": "and over; he rears his enormous\n  head, and with wide expanded jaws snaps at everything around him; he\n  rushes at the boats with his head; they are propelled before him with\n  vast swiftness, and sometimes utterly destroyed...", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 825, "2000": 1225}}, {"id": 153, "position": 153, "text": "with\n  vast swiftness, and sometimes utterly destroyed.... It is a matter of\n  great astonishment that the consideration of the habits of so\n  interesting, and, in a commercial point of view, so important an\n  animal (as the Sperm Whale) should", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 154, "position": 154, "text": "point of view, so important an\n  animal (as the Sperm Whale) should have been so entirely neglected,\n  or should have excited so little curiosity among the numerous, and\n  many of them competent observers, that of late years, must have\n  possessed the most abundant", "labels": {"50": 3, "100": 85, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 155, "position": 155, "text": "them competent observers, that of late years, must have\n  possessed the most abundant and the most convenient opportunities of\n  witnessing their habitudes.” —_Thomas Beale’s History of the Sperm\n  Whale_, 1839.", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 156, "position": 156, "text": "the Sperm\n  Whale_, 1839.\n\n  “The Cachalot” (Sperm Whale) “is not only better armed than the True\n  Whale” (Greenland or Right Whale) “in possessing a formidable weapon\n  at either extremity of its body, but", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 157, "position": 157, "text": "in possessing a formidable weapon\n  at either extremity of its body, but also more frequently displays a\n  disposition to employ these weapons offensively and in manner at once\n  so artful, bold, and mischievous, as to lead to its being regarded as\n  the", "labels": {"50": 24, "100": 7, "250": 159, "500": 247, "1000": 845, "2000": 394}}, {"id": 158, "position": 158, "text": ", bold, and mischievous, as to lead to its being regarded as\n  the most dangerous to attack of all the known species of the whale\n  tribe.” —_Frederick Debell Bennett’s Whaling Voyage Round the Globe_,\n  1840.\n\n\n  October 13", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 159, "position": 159, "text": "Bennett’s Whaling Voyage Round the Globe_,\n  1840.\n\n\n  October 13.  “There she blows,” was sung out from the mast-head.\n  “Where away?” demanded the captain. “Three points off the lee bow,\n  sir.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 160, "position": 160, "text": "demanded the captain. “Three points off the lee bow,\n  sir.” “Raise up your wheel.  Steady!”  “Steady, sir.” “Mast-head\n  ahoy! Do you see that whale now?” “Ay ay", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 161, "position": 161, "text": "oy! Do you see that whale now?” “Ay ay, sir!  A shoal of Sperm\n  Whales! There she blows!  There she breaches!” “Sing out! sing out\n  every time!” “Ay Ay", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 162, "position": 162, "text": "“Sing out! sing out\n  every time!” “Ay Ay, sir!  There she blows! there—there—_thar_ she\n  blows—bowes—bo-o-os!” “How far off?” “", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 163, "position": 163, "text": "—bo-o-os!” “How far off?” “Two miles and a half.” “Thunder\n  and lightning! so near!  Call all hands.” —_J. Ross Browne’s Etchings\n  of a Whaling Cr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 164, "position": 164, "text": "—_J. Ross Browne’s Etchings\n  of a Whaling Cruize_.  1846.\n\n\n\n  “The Whale-ship Globe, on board of which vessel occurred the horrid\n  transactions we are about to relate, belonged to the island of", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 165, "position": 165, "text": "horrid\n  transactions we are about to relate, belonged to the island of\n  Nantucket.” —“_Narrative of the Globe Mutiny_,” _by Lay and Hussey\n  survivors. A.D._ 1828.", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 327, "2000": 1584}}, {"id": 166, "position": 166, "text": "ssey\n  survivors. A.D._ 1828.\n\n  Being once pursued by a whale which he had wounded, he parried the\n  assault for some time with a lance; but the furious monster at length\n  rushed on the boat; himself and comrades only being", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 167, "position": 167, "text": "the furious monster at length\n  rushed on the boat; himself and comrades only being preserved by\n  leaping into the water when they saw the onset was inevitable.”\n  —_Missionary Journal of Tyerman and Bennett_.\n\n  “Nantucket itself,” said Mr", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 168, "position": 168, "text": "Tyerman and Bennett_.\n\n  “Nantucket itself,” said Mr. Webster, “is a very striking and\n  peculiar portion of the National interest. There is a population of\n  eight or nine thousand persons living here in the sea, adding largely\n  every year", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 682}}, {"id": 169, "position": 169, "text": "eight or nine thousand persons living here in the sea, adding largely\n  every year to the National wealth by the boldest and most persevering\n  industry.” —_Report of Daniel Webster’s Speech in the U. S", "labels": {"50": 21, "100": 95, "250": 76, "500": 67, "1000": 451, "2000": 201}}, {"id": 170, "position": 170, "text": "of Daniel Webster’s Speech in the U. S. Senate,\n  on the application for the Erection of a Breakwater at Nantucket_.\n  1828.\n\n  “The whale fell directly over him, and probably killed him in a\n  moment.” —“", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 171, "position": 171, "text": "directly over him, and probably killed him in a\n  moment.” —“_The Whale and his Captors, or The Whaleman’s Adventures\n  and the Whale’s Biography, gathered on the Homeward Cruise of the\n  Commodore Preble_.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 172, "position": 172, "text": "Biography, gathered on the Homeward Cruise of the\n  Commodore Preble_.” _By Rev. Henry T. Cheever_.\n\n  “If you make the least damn bit of noise,” replied Samuel, “I will\n  send you to hell.", "labels": {"50": 45, "100": 29, "250": 82, "500": 239, "1000": 851, "2000": 1584}}, {"id": 173, "position": 173, "text": "of noise,” replied Samuel, “I will\n  send you to hell.” —_Life of Samuel Comstock_ (_the mutineer_), _by\n  his brother, William Comstock", "labels": {"50": 43, "100": 64, "250": 148, "500": 14, "1000": 687, "2000": 1584}}, {"id": 174, "position": 174, "text": "his brother, William Comstock. Another Version of the whale-ship\n  Globe narrative_.\n\n  “The voyages of the Dutch and English to the Northern Ocean, in\n  order, if possible, to discover a passage through it to India, though\n  they failed of", "labels": {"50": 45, "100": 29, "250": 34, "500": 72, "1000": 622, "2000": 1620}}, {"id": 175, "position": 175, "text": "possible, to discover a passage through it to India, though\n  they failed of their main object, laid-open the haunts of the whale.”\n  —_McCulloch’s Commercial Dictionary_.", "labels": {"50": 45, "100": 29, "250": 34, "500": 306, "1000": 978, "2000": 1950}}, {"id": 176, "position": 176, "text": "’s Commercial Dictionary_.\n\n  “These things are reciprocal; the ball rebounds, only to bound\n  forward again; for now in laying open the haunts of the whale, the\n  whalemen seem to have indirectly hit upon new clews to that same", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 177, "position": 177, "text": "whalemen seem to have indirectly hit upon new clews to that same\n  mystic North-West Passage.” —_From_ “_Something_” _unpublished_.\n\n  “It is impossible to meet a whale-ship on the ocean without being", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 178, "position": 178, "text": "“It is impossible to meet a whale-ship on the ocean without being\n  struck by her near appearance. The vessel under short sail, with\n  look-outs at the mast-heads, eagerly scanning the wide expanse around\n  them, has a totally different air", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 179, "position": 179, "text": "heads, eagerly scanning the wide expanse around\n  them, has a totally different air from those engaged in regular\n  voyage.” —_Currents and Whaling. U.S. Ex. Ex_.\n\n  “Pedestrians in the vicinity of London and elsewhere may recoll", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 180, "position": 180, "text": "Ex_.\n\n  “Pedestrians in the vicinity of London and elsewhere may recollect\n  having seen large curved bones set upright in the earth, either to\n  form arches over gateways, or entrances to alcoves, and they may\n  perhaps have been told that", "labels": {"50": 14, "100": 27, "250": 157, "500": 77, "1000": 478, "2000": 823}}, {"id": 181, "position": 181, "text": "or entrances to alcoves, and they may\n  perhaps have been told that these were the ribs of whales.” —_Tales\n  of a Whale Voyager to the Arctic Ocean_.\n\n  “It was not till the boats returned from the pursuit of these whales", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 631}}, {"id": 182, "position": 182, "text": ".\n\n  “It was not till the boats returned from the pursuit of these whales,\n  that the whites saw their ship in bloody possession of the savages\n  enrolled among the crew.” —_Newspaper Account of the Taking and\n  Retaking of the Whale-Ship", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 52}}, {"id": 183, "position": 183, "text": "—_Newspaper Account of the Taking and\n  Retaking of the Whale-Ship Hobomack_.\n\n  “It is generally well known that out of the crews of Whaling vessels\n  (American) few ever return in the ships on board of which they\n  departed.", "labels": {"50": 45, "100": 29, "250": 82, "500": 239, "1000": 899, "2000": 1584}}, {"id": 184, "position": 184, "text": "American) few ever return in the ships on board of which they\n  departed.” —_Cruise in a Whale Boat_.\n\n  “Suddenly a mighty mass emerged from the water, and shot up\n  perpendicularly into the air", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 185, "position": 185, "text": "and shot up\n  perpendicularly into the air. It was the whale.” —_Miriam Coffin or\n  the Whale Fisherman_.\n\n  “The Whale is harpooned to be sure; but bethink you, how you would\n  manage a powerful unbroken colt,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 186, "position": 186, "text": "; but bethink you, how you would\n  manage a powerful unbroken colt, with the mere appliance of a rope\n  tied to the root of his tail.” —_A Chapter on Whaling in Ribs and\n  Trucks_.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 187, "position": 187, "text": "A Chapter on Whaling in Ribs and\n  Trucks_.\n\n  “On one occasion I saw two of these monsters (whales) probably male\n  and female, slowly swimming, one after the other, within less than a\n  stone’s throw of the shore” (Terra", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 188, "position": 188, "text": ", within less than a\n  stone’s throw of the shore” (Terra Del Fuego), “over which the beech\n  tree extended its branches.” —_Darwin’s Voyage of a Naturalist_.", "labels": {"50": 8, "100": 85, "250": 34, "500": 486, "1000": 956, "2000": 1346}}, {"id": 189, "position": 189, "text": "s Voyage of a Naturalist_.\n\n  “‘Stern all!’ exclaimed the mate, as upon turning his head, he saw\n  the distended jaws of a large Sperm Whale close to the head of the\n  boat, threatening it with instant destruction;—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 190, "position": 190, "text": "close to the head of the\n  boat, threatening it with instant destruction;—‘Stern all, for your\n  lives!’” —_Wharton the Whale Killer_.\n\n  “So be cheery, my lads, let your hearts never fail, While the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 191, "position": 191, "text": "be cheery, my lads, let your hearts never fail, While the bold\n  harpooneer is striking the whale!” —_Nantucket Song_.\n\n\n  “Oh, the rare old Whale, mid storm and gale In his ocean home will be", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 192, "position": 192, "text": "the rare old Whale, mid storm and gale In his ocean home will be\n  A giant in might, where might is right, And King of the boundless\n  sea.” —_Whale Song_.\n\n\n\n\n\nCHAPTER 1. Loomings.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 193, "position": 193, "text": "_Whale Song_.\n\n\n\n\n\nCHAPTER 1. Loomings.\n\nCall me Ishmael. Some years ago—never mind how long precisely—having\nlittle or no money in my purse, and nothing particular to interest me\non shore, I thought I would sail", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1620}}, {"id": 194, "position": 194, "text": ", and nothing particular to interest me\non shore, I thought I would sail about a little and see the watery part\nof the world. It is a way I have of driving off the spleen and\nregulating the circulation", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 9, "2000": 682}}, {"id": 195, "position": 195, "text": "off the spleen and\nregulating the circulation. Whenever I find myself growing grim about\nthe mouth; whenever it is a damp, drizzly November in my soul; whenever\nI find myself involuntarily pausing before coffin warehouses, and\nbringing up the", "labels": {"50": 31, "100": 75, "250": 106, "500": 333, "1000": 27, "2000": 1204}}, {"id": 196, "position": 196, "text": "myself involuntarily pausing before coffin warehouses, and\nbringing up the rear of every funeral I meet; and especially whenever\nmy hypos get such an upper hand of me, that it requires a strong moral\nprinciple to prevent me from deliberately stepping", "labels": {"50": 31, "100": 20, "250": 193, "500": 126, "1000": 727, "2000": 1107}}, {"id": 197, "position": 197, "text": "me, that it requires a strong moral\nprinciple to prevent me from deliberately stepping into the street, and\nmethodically knocking people’s hats off—then, I account it high time to\nget to sea as soon as I can", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 581, "2000": 1828}}, {"id": 198, "position": 198, "text": "time to\nget to sea as soon as I can. This is my substitute for pistol and ball.\nWith a philosophical flourish Cato throws himself upon his sword; I\nquietly take to the ship. There is nothing surprising in this", "labels": {"50": 6, "100": 1, "250": 42, "500": 280, "1000": 719, "2000": 1273}}, {"id": 199, "position": 199, "text": "to the ship. There is nothing surprising in this. If they\nbut knew it, almost all men in their degree, some time or other,\ncherish very nearly the same feelings towards the ocean with me.", "labels": {"50": 31, "100": 7, "250": 69, "500": 453, "1000": 203, "2000": 1828}}, {"id": 200, "position": 200, "text": "feelings towards the ocean with me.\n\nThere now is your insular city of the Manhattoes, belted round by\nwharves as Indian isles by coral reefs—commerce surrounds it with her\nsurf", "labels": {"50": 16, "100": 20, "250": 15, "500": 162, "1000": 747, "2000": 682}}, {"id": 201, "position": 201, "text": "commerce surrounds it with her\nsurf. Right and left, the streets take you waterward. Its extreme\ndowntown is the battery, where that noble mole is washed by waves, and\ncooled by breezes, which a few hours previous were out of sight of", "labels": {"50": 48, "100": 20, "250": 90, "500": 162, "1000": 696, "2000": 1534}}, {"id": 202, "position": 202, "text": "cooled by breezes, which a few hours previous were out of sight of\nland. Look at the crowds of water-gazers there.\n\nCircumambulate the city of a dreamy Sabbath afternoon", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 35, "2000": 1071}}, {"id": 203, "position": 203, "text": "of a dreamy Sabbath afternoon. Go from Corlears\nHook to Coenties Slip, and from thence, by Whitehall, northward. What\ndo you see?—Posted like silent sentinels all around the town, stand\nthousands upon thousands of mortal", "labels": {"50": 48, "100": 20, "250": 49, "500": 334, "1000": 90, "2000": 1105}}, {"id": 204, "position": 204, "text": "like silent sentinels all around the town, stand\nthousands upon thousands of mortal men fixed in ocean reveries. Some\nleaning against the spiles; some seated upon the pier-heads; some\nlooking over the bulwarks of ships from China", "labels": {"50": 48, "100": 20, "250": 49, "500": 162, "1000": 747, "2000": 478}}, {"id": 205, "position": 205, "text": "-heads; some\nlooking over the bulwarks of ships from China; some high aloft in the\nrigging, as if striving to get a still better seaward peep. But these\nare all landsmen; of week days", "labels": {"50": 45, "100": 20, "250": 138, "500": 334, "1000": 747, "2000": 887}}, {"id": 206, "position": 206, "text": "seaward peep. But these\nare all landsmen; of week days pent up in lath and plaster—tied to\ncounters, nailed to benches, clinched to desks. How then is this? Are\nthe green fields gone? What do", "labels": {"50": 31, "100": 64, "250": 193, "500": 73, "1000": 851, "2000": 967}}, {"id": 207, "position": 207, "text": "s. How then is this? Are\nthe green fields gone? What do they here?\n\nBut look! here come more crowds, pacing straight for the water, and\nseemingly bound for a dive. Strange! Nothing will content them but the\nextremest limit", "labels": {"50": 48, "100": 20, "250": 90, "500": 339, "1000": 387, "2000": 532}}, {"id": 208, "position": 208, "text": "for a dive. Strange! Nothing will content them but the\nextremest limit of the land; loitering under the shady lee of yonder\nwarehouses will not suffice. No. They must get just as nigh the water\nas they possibly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 472}}, {"id": 209, "position": 209, "text": ". No. They must get just as nigh the water\nas they possibly can without falling in. And there they stand—miles of\nthem—leagues. Inlanders all, they come from lanes and alleys, streets\nand avenues—north, east", "labels": {"50": 26, "100": 82, "250": 135, "500": 189, "1000": 713, "2000": 1080}}, {"id": 210, "position": 210, "text": "they come from lanes and alleys, streets\nand avenues—north, east, south, and west. Yet here they all unite. Tell\nme, does the magnetic virtue of the needles of the compasses of all\nthose ships attract them thither", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 747, "2000": 709}}, {"id": 211, "position": 211, "text": "the needles of the compasses of all\nthose ships attract them thither?\n\nOnce more. Say you are in the country; in some high land of lakes. Take\nalmost any path you please, and ten to one it carries you down in a", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 747, "2000": 1710}}, {"id": 212, "position": 212, "text": "any path you please, and ten to one it carries you down in a\ndale, and leaves you there by a pool in the stream. There is magic in\nit. Let the most absent-minded of men be plunged in his deepest\nreveries—", "labels": {"50": 31, "100": 20, "250": 192, "500": 334, "1000": 275, "2000": 1710}}, {"id": 213, "position": 213, "text": "the most absent-minded of men be plunged in his deepest\nreveries—stand that man on his legs, set his feet a-going, and he will\ninfallibly lead you to water, if water there be in all that region", "labels": {"50": 9, "100": 26, "250": 30, "500": 498, "1000": 637, "2000": 39}}, {"id": 214, "position": 214, "text": "lead you to water, if water there be in all that region.\nShould you ever be athirst in the great American desert, try this\nexperiment, if your caravan happen to be supplied with a metaphysical\nprofessor", "labels": {"50": 10, "100": 71, "250": 13, "500": 314, "1000": 157, "2000": 48}}, {"id": 215, "position": 215, "text": "to be supplied with a metaphysical\nprofessor. Yes, as every one knows, meditation and water are wedded for\never.\n\nBut here is an artist. He desires to paint you the dreamiest, shadiest,\nquietest, most enchanting", "labels": {"50": 7, "100": 8, "250": 103, "500": 310, "1000": 115, "2000": 1833}}, {"id": 216, "position": 216, "text": "the dreamiest, shadiest,\nquietest, most enchanting bit of romantic landscape in all the valley\nof the Saco. What is the chief element he employs? There stand his\ntrees, each with a hollow trunk, as if a", "labels": {"50": 17, "100": 16, "250": 146, "500": 126, "1000": 515, "2000": 739}}, {"id": 217, "position": 217, "text": "? There stand his\ntrees, each with a hollow trunk, as if a hermit and a crucifix were\nwithin; and here sleeps his meadow, and there sleep his cattle; and up\nfrom yonder cottage goes a sleepy smoke", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 523}}, {"id": 218, "position": 218, "text": "cattle; and up\nfrom yonder cottage goes a sleepy smoke. Deep into distant woodlands\nwinds a mazy way, reaching to overlapping spurs of mountains bathed in\ntheir hill-side blue. But though the picture lies thus tranced, and\nthough this pine", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 523}}, {"id": 219, "position": 219, "text": "blue. But though the picture lies thus tranced, and\nthough this pine-tree shakes down its sighs like leaves upon this\nshepherd’s head, yet all were vain, unless the shepherd’s eye were\nfixed upon the magic stream before him", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 193}}, {"id": 220, "position": 220, "text": "unless the shepherd’s eye were\nfixed upon the magic stream before him. Go visit the Prairies in June,\nwhen for scores on scores of miles you wade knee-deep among\nTiger-lilies—what is the one charm wanting?—Water", "labels": {"50": 12, "100": 55, "250": 95, "500": 227, "1000": 714, "2000": 668}}, {"id": 221, "position": 221, "text": "among\nTiger-lilies—what is the one charm wanting?—Water—there is not a drop\nof water there! Were Niagara but a cataract of sand, would you travel\nyour thousand miles to see it? Why did the poor poet", "labels": {"50": 12, "100": 20, "250": 192, "500": 162, "1000": 816, "2000": 326}}, {"id": 222, "position": 222, "text": "would you travel\nyour thousand miles to see it? Why did the poor poet of Tennessee, upon\nsuddenly receiving two handfuls of silver, deliberate whether to buy\nhim a coat, which he sadly needed, or invest his money in a pedestrian\ntrip to Rock", "labels": {"50": 31, "100": 7, "250": 69, "500": 274, "1000": 203, "2000": 1741}}, {"id": 223, "position": 223, "text": "which he sadly needed, or invest his money in a pedestrian\ntrip to Rockaway Beach? Why is almost every robust healthy boy with a\nrobust healthy soul in him, at some time or other crazy to go to sea?\nWhy upon your first voyage as", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 887}}, {"id": 224, "position": 224, "text": "time or other crazy to go to sea?\nWhy upon your first voyage as a passenger, did you yourself feel such a\nmystical vibration, when first told that you and your ship were now out\nof sight of land? Why did the old Persians hold the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 887}}, {"id": 225, "position": 225, "text": "were now out\nof sight of land? Why did the old Persians hold the sea holy? Why did\nthe Greeks give it a separate deity, and own brother of Jove? Surely\nall this is not without meaning", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 730, "2000": 199}}, {"id": 226, "position": 226, "text": "Surely\nall this is not without meaning. And still deeper the meaning of that\nstory of Narcissus, who because he could not grasp the tormenting, mild\nimage he saw in the fountain, plunged into it and was drowned", "labels": {"50": 10, "100": 71, "250": 211, "500": 490, "1000": 507, "2000": 1010}}, {"id": 227, "position": 227, "text": "saw in the fountain, plunged into it and was drowned. But that\nsame image, we ourselves see in all rivers and oceans. It is the image\nof the ungraspable phantom of life; and this is the key to it all.", "labels": {"50": 10, "100": 71, "250": 13, "500": 414, "1000": 548, "2000": 1555}}, {"id": 228, "position": 228, "text": "able phantom of life; and this is the key to it all.\n\nNow, when I say that I am in the habit of going to sea whenever I begin\nto grow hazy about the eyes, and begin to be over conscious of my\nlungs, I", "labels": {"50": 31, "100": 20, "250": 132, "500": 280, "1000": 27, "2000": 1483}}, {"id": 229, "position": 229, "text": "about the eyes, and begin to be over conscious of my\nlungs, I do not mean to have it inferred that I ever go to sea as a\npassenger. For to go as a passenger you must needs have a purse, and a\npurse", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 701, "2000": 1793}}, {"id": 230, "position": 230, "text": "to go as a passenger you must needs have a purse, and a\npurse is but a rag unless you have something in it. Besides, passengers\nget sea-sick—grow quarrelsome—don’t sleep of nights—do not enjoy\nthemselves much", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 231, "position": 231, "text": "quarrelsome—don’t sleep of nights—do not enjoy\nthemselves much, as a general thing;—no, I never go as a passenger;\nnor, though I am something of a salt, do I ever go to sea as a\nCommodore", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 39}}, {"id": 232, "position": 232, "text": "am something of a salt, do I ever go to sea as a\nCommodore, or a Captain, or a Cook. I abandon the glory and distinction\nof such offices to those who like them. For my part, I abominate all\nhonorable respectable", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 233, "position": 233, "text": "who like them. For my part, I abominate all\nhonorable respectable toils, trials, and tribulations of every kind\nwhatsoever. It is quite as much as I can do to take care of myself,\nwithout taking care of ships,", "labels": {"50": 31, "100": 75, "250": 106, "500": 333, "1000": 344, "2000": 1204}}, {"id": 234, "position": 234, "text": "I can do to take care of myself,\nwithout taking care of ships, barques, brigs, schooners, and what not.\nAnd as for going as cook,—though I confess there is considerable glory\nin that, a cook being a", "labels": {"50": 8, "100": 14, "250": 58, "500": 158, "1000": 426, "2000": 173}}, {"id": 235, "position": 235, "text": "—though I confess there is considerable glory\nin that, a cook being a sort of officer on ship-board—yet, somehow, I\nnever fancied broiling fowls;—though once broiled, judiciously\nbuttered,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 236, "position": 236, "text": "owls;—though once broiled, judiciously\nbuttered, and judgmatically salted and peppered, there is no one who\nwill speak more respectfully, not to say reverentially, of a broiled", "labels": {"50": 20, "100": 79, "250": 176, "500": 120, "1000": 421, "2000": 251}}, {"id": 237, "position": 237, "text": "respectfully, not to say reverentially, of a broiled\nfowl than I will. It is out of the idolatrous dotings of the old\nEgyptians upon broiled ibis and roasted river horse, that you see the", "labels": {"50": 31, "100": 59, "250": 10, "500": 16, "1000": 364, "2000": 1592}}, {"id": 238, "position": 238, "text": "Egyptians upon broiled ibis and roasted river horse, that you see the\nmummies of those creatures in their huge bake-houses the pyramids.\n\nNo, when I go to sea, I go as a simple sailor, right before the mast", "labels": {"50": 31, "100": 20, "250": 69, "500": 274, "1000": 203, "2000": 1050}}, {"id": 239, "position": 239, "text": "go to sea, I go as a simple sailor, right before the mast,\nplumb down into the forecastle, aloft there to the royal mast-head.\nTrue, they rather order me about some, and make me jump from spar", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 240, "position": 240, "text": ", they rather order me about some, and make me jump from spar to\nspar, like a grasshopper in a May meadow. And at first, this sort of\nthing is unpleasant enough. It touches one’s sense of honor,\nparticularly", "labels": {"50": 31, "100": 75, "250": 106, "500": 496, "1000": 76, "2000": 1607}}, {"id": 241, "position": 241, "text": "thing is unpleasant enough. It touches one’s sense of honor,\nparticularly if you come of an old established family in the land, the\nVan Rensselaers, or Randolphs, or Hardicanutes", "labels": {"50": 8, "100": 28, "250": 175, "500": 230, "1000": 614, "2000": 47}}, {"id": 242, "position": 242, "text": "Randolphs, or Hardicanutes. And more than all, if\njust previous to putting your hand into the tar-pot, you have been\nlording it as a country schoolmaster, making the tallest boys stand in\nawe of you", "labels": {"50": 31, "100": 7, "250": 109, "500": 178, "1000": 203, "2000": 834}}, {"id": 243, "position": 243, "text": "country schoolmaster, making the tallest boys stand in\nawe of you. The transition is a keen one, I assure you, from a\nschoolmaster to a sailor, and requires a strong decoction of Seneca and\nthe Stoics to enable you to", "labels": {"50": 31, "100": 7, "250": 49, "500": 274, "1000": 203, "2000": 1288}}, {"id": 244, "position": 244, "text": "a strong decoction of Seneca and\nthe Stoics to enable you to grin and bear it. But even this wears off\nin time.\n\nWhat of it, if some old hunks of a sea-captain orders me to get a broom\nand", "labels": {"50": 31, "100": 7, "250": 69, "500": 274, "1000": 203, "2000": 1107}}, {"id": 245, "position": 245, "text": "hunks of a sea-captain orders me to get a broom\nand sweep down the decks? What does that indignity amount to, weighed,\nI mean, in the scales of the New Testament? Do you think the archangel\nGabriel thinks anything", "labels": {"50": 35, "100": 94, "250": 69, "500": 265, "1000": 919, "2000": 1061}}, {"id": 246, "position": 246, "text": "the scales of the New Testament? Do you think the archangel\nGabriel thinks anything the less of me, because I promptly and\nrespectfully obey that old hunks in that particular instance? Who ain’t\na slave? Tell me that", "labels": {"50": 31, "100": 41, "250": 132, "500": 274, "1000": 27, "2000": 1483}}, {"id": 247, "position": 247, "text": "instance? Who ain’t\na slave? Tell me that. Well, then, however the old sea-captains may\norder me about—however they may thump and punch me about, I have the\nsatisfaction of knowing that it is all right; that", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 248, "position": 248, "text": "about, I have the\nsatisfaction of knowing that it is all right; that everybody else is\none way or other served in much the same way—either in a physical or\nmetaphysical point of view, that is; and so the universal thump is\npassed round", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 811, "2000": 1618}}, {"id": 249, "position": 249, "text": "point of view, that is; and so the universal thump is\npassed round, and all hands should rub each other’s shoulder-blades,\nand be content.\n\nAgain, I always go to sea as a sailor, because they make a point of", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 250, "position": 250, "text": "I always go to sea as a sailor, because they make a point of\npaying me for my trouble, whereas they never pay passengers a single\npenny that I ever heard of. On the contrary, passengers themselves must\npay", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 1495}}, {"id": 251, "position": 251, "text": "On the contrary, passengers themselves must\npay. And there is all the difference in the world between paying and\nbeing paid. The act of paying is perhaps the most uncomfortable\ninfliction that the two orchard thieves entailed upon us", "labels": {"50": 31, "100": 75, "250": 88, "500": 295, "1000": 821, "2000": 1828}}, {"id": 252, "position": 252, "text": "ion that the two orchard thieves entailed upon us. But _being\npaid_,—what will compare with it? The urbane activity with which a man\nreceives money is really marvellous, considering that we so earnestly\nbelieve money to be", "labels": {"50": 31, "100": 75, "250": 88, "500": 496, "1000": 821, "2000": 1741}}, {"id": 253, "position": 253, "text": "is really marvellous, considering that we so earnestly\nbelieve money to be the root of all earthly ills, and that on no\naccount can a monied man enter heaven. Ah! how cheerfully we consign\nourselves to perdition!", "labels": {"50": 31, "100": 75, "250": 69, "500": 307, "1000": 343, "2000": 1268}}, {"id": 254, "position": 254, "text": ". Ah! how cheerfully we consign\nourselves to perdition!\n\nFinally, I always go to sea as a sailor, because of the wholesome\nexercise and pure air of the fore-castle deck. For as in this world,\nhead winds are", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 255, "position": 255, "text": "the fore-castle deck. For as in this world,\nhead winds are far more prevalent than winds from astern (that is, if\nyou never violate the Pythagorean maxim), so for the most part the\nCommodore on the quarter", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 256, "position": 256, "text": "gorean maxim), so for the most part the\nCommodore on the quarter-deck gets his atmosphere at second hand from\nthe sailors on the forecastle. He thinks he breathes it first; but not\nso", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 257, "position": 257, "text": "s it first; but not\nso. In much the same way do the commonalty lead their leaders in many\nother things, at the same time that the leaders little suspect it. But\nwherefore it was that after having repeatedly smelt the", "labels": {"50": 10, "100": 75, "250": 88, "500": 107, "1000": 183, "2000": 1986}}, {"id": 258, "position": 258, "text": "it. But\nwherefore it was that after having repeatedly smelt the sea as a\nmerchant sailor, I should now take it into my head to go on a whaling\nvoyage; this the invisible police officer of the Fates, who has the\nconstant surveillance", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 887}}, {"id": 259, "position": 259, "text": "; this the invisible police officer of the Fates, who has the\nconstant surveillance of me, and secretly dogs me, and influences me in\nsome unaccountable way—he can better answer than any one else", "labels": {"50": 20, "100": 5, "250": 45, "500": 120, "1000": 818, "2000": 1812}}, {"id": 260, "position": 260, "text": "can better answer than any one else. And,\ndoubtless, my going on this whaling voyage, formed part of the grand\nprogramme of Providence that was drawn up a long time ago. It came in\nas a sort of brief interlude and solo between more", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 261, "position": 261, "text": "ago. It came in\nas a sort of brief interlude and solo between more extensive\nperformances. I take it that this part of the bill must have run\nsomething like this:\n\n“_Grand Contested Election for the Presidency of the United States._\n“WHALING", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 262, "position": 262, "text": "_Grand Contested Election for the Presidency of the United States._\n“WHALING VOYAGE BY ONE ISHMAEL. “BLOODY BATTLE IN AFFGHANISTAN.”\n\nThough I cannot tell why it was exactly that those stage managers, the\nFates, put me", "labels": {"50": 15, "100": 36, "250": 108, "500": 95, "1000": 444, "2000": 316}}, {"id": 263, "position": 263, "text": "tell why it was exactly that those stage managers, the\nFates, put me down for this shabby part of a whaling voyage, when\nothers were set down for magnificent parts in high tragedies, and short\nand easy parts in genteel comedies", "labels": {"50": 25, "100": 41, "250": 91, "500": 146, "1000": 620, "2000": 1713}}, {"id": 264, "position": 264, "text": "high tragedies, and short\nand easy parts in genteel comedies, and jolly parts in farces—though I\ncannot tell why this was exactly; yet, now that I recall all the\ncircumstances, I think I can see a little into", "labels": {"50": 20, "100": 28, "250": 169, "500": 59, "1000": 576, "2000": 1420}}, {"id": 265, "position": 265, "text": "that I recall all the\ncircumstances, I think I can see a little into the springs and motives\nwhich being cunningly presented to me under various disguises, induced\nme to set about performing the part I did, besides cajoling me into the\ndel", "labels": {"50": 20, "100": 56, "250": 101, "500": 120, "1000": 651, "2000": 609}}, {"id": 266, "position": 266, "text": "about performing the part I did, besides cajoling me into the\ndelusion that it was a choice resulting from my own unbiased freewill\nand discriminating judgment.\n\nChief among these motives was the overwhelming idea of the great whale\nhimself", "labels": {"50": 25, "100": 28, "250": 156, "500": 407, "1000": 329, "2000": 381}}, {"id": 267, "position": 267, "text": "judgment.\n\nChief among these motives was the overwhelming idea of the great whale\nhimself. Such a portentous and mysterious monster roused all my\ncuriosity. Then the wild and distant seas where he rolled his island\nbulk; the undeliverable, name", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 268, "position": 268, "text": "seas where he rolled his island\nbulk; the undeliverable, nameless perils of the whale; these, with all\nthe attending marvels of a thousand Patagonian sights and sounds,\nhelped to sway me to my wish", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 269, "position": 269, "text": "nian sights and sounds,\nhelped to sway me to my wish. With other men, perhaps, such things\nwould not have been inducements; but as for me, I am tormented with an\neverlasting itch for things remote", "labels": {"50": 20, "100": 5, "250": 101, "500": 120, "1000": 773, "2000": 1278}}, {"id": 270, "position": 270, "text": "tormented with an\neverlasting itch for things remote. I love to sail forbidden seas, and\nland on barbarous coasts. Not ignoring what is good, I am quick to\nperceive a horror, and could still be social with it—would", "labels": {"50": 25, "100": 20, "250": 132, "500": 412, "1000": 727, "2000": 913}}, {"id": 271, "position": 271, "text": "quick to\nperceive a horror, and could still be social with it—would they let\nme—since it is but well to be on friendly terms with all the inmates of\nthe place one lodges in.\n\nBy reason of these things, then, the whaling", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 272, "position": 272, "text": "place one lodges in.\n\nBy reason of these things, then, the whaling voyage was welcome; the\ngreat flood-gates of the wonder-world swung open, and in the wild\nconceits that swayed me to my purpose, two and two there", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 273, "position": 273, "text": "wild\nconceits that swayed me to my purpose, two and two there floated into\nmy inmost soul, endless processions of the whale, and, mid most of them\nall, one grand hooded phantom, like a snow hill in the air.", "labels": {"50": 20, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1254}}, {"id": 274, "position": 274, "text": "all, one grand hooded phantom, like a snow hill in the air.\n\n\nCHAPTER 2. The Carpet-Bag.\n\nI stuffed a shirt or two into my old carpet-bag, tucked it under my\narm, and started for Cape Horn and the Pacific", "labels": {"50": 25, "100": 5, "250": 192, "500": 388, "1000": 9, "2000": 1521}}, {"id": 275, "position": 275, "text": ", tucked it under my\narm, and started for Cape Horn and the Pacific. Quitting the good city\nof old Manhatto, I duly arrived in New Bedford. It was a Saturday night\nin December", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 276, "position": 276, "text": "was a Saturday night\nin December. Much was I disappointed upon learning that the little\npacket for Nantucket had already sailed, and that no way of reaching\nthat place would offer, till the following Monday.\n\nAs most young candidates for the pains and penalties of", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 277, "position": 277, "text": "till the following Monday.\n\nAs most young candidates for the pains and penalties of whaling stop at\nthis same New Bedford, thence to embark on their voyage, it may as well\nbe related that I, for one, had no idea of so doing", "labels": {"50": 20, "100": 28, "250": 169, "500": 34, "1000": 564, "2000": 1115}}, {"id": 278, "position": 278, "text": "related that I, for one, had no idea of so doing. For my mind was\nmade up to sail in no other than a Nantucket craft, because there was a\nfine, boisterous something about everything connected with that famous\nold island,", "labels": {"50": 25, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 279, "position": 279, "text": "fine, boisterous something about everything connected with that famous\nold island, which amazingly pleased me. Besides though New Bedford has\nof late been gradually monopolising the business of whaling, and though\nin this matter poor old Nantucket is now much behind", "labels": {"50": 25, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 280, "position": 280, "text": "whaling, and though\nin this matter poor old Nantucket is now much behind her, yet Nantucket\nwas her great original—the Tyre of this Carthage;—the place where the\nfirst dead American whale was stranded", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 281, "position": 281, "text": "the\nfirst dead American whale was stranded. Where else but from Nantucket\ndid those aboriginal whalemen, the Red-Men, first sally out in canoes\nto give chase to the Leviathan? And where but from Nantucket, too, did\nthat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 282, "position": 282, "text": "the Leviathan? And where but from Nantucket, too, did\nthat first adventurous little sloop put forth, partly laden with\nimported cobblestones—so goes the story—to throw at the whales, in\norder to discover when they were nigh", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 283, "position": 283, "text": "to throw at the whales, in\norder to discover when they were nigh enough to risk a harpoon from the\nbowsprit?\n\nNow having a night, a day, and still another night following before me\nin New Bedford, ere I could", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 842, "2000": 1521}}, {"id": 284, "position": 284, "text": "and still another night following before me\nin New Bedford, ere I could embark for my destined port, it became a\nmatter of concernment where I was to eat and sleep meanwhile. It was a\nvery dubious-looking, nay, a very dark", "labels": {"50": 25, "100": 5, "250": 45, "500": 349, "1000": 51, "2000": 1149}}, {"id": 285, "position": 285, "text": "meanwhile. It was a\nvery dubious-looking, nay, a very dark and dismal night, bitingly cold\nand cheerless. I knew no one in the place. With anxious grapnels I had\nsounded my pocket, and only", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 286, "position": 286, "text": ". With anxious grapnels I had\nsounded my pocket, and only brought up a few pieces of silver,—So,\nwherever you go, Ishmael, said I to myself, as I stood in the middle of\na dreary", "labels": {"50": 25, "100": 41, "250": 156, "500": 134, "1000": 421, "2000": 1559}}, {"id": 287, "position": 287, "text": "I to myself, as I stood in the middle of\na dreary street shouldering my bag, and comparing the gloom towards the\nnorth with the darkness towards the south—wherever in your wisdom you\nmay conclude to lodge for the night, my dear", "labels": {"50": 20, "100": 5, "250": 45, "500": 134, "1000": 421, "2000": 1559}}, {"id": 288, "position": 288, "text": "wherever in your wisdom you\nmay conclude to lodge for the night, my dear Ishmael, be sure to\ninquire the price, and don’t be too particular.\n\nWith halting steps I paced the streets, and passed the sign of", "labels": {"50": 48, "100": 5, "250": 90, "500": 224, "1000": 529, "2000": 41}}, {"id": 289, "position": 289, "text": ".\n\nWith halting steps I paced the streets, and passed the sign of “The\nCrossed Harpoons”—but it looked too expensive and jolly there. Further\non, from the bright red windows of the “Sword-Fish Inn,” there came", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 409, "2000": 1698}}, {"id": 290, "position": 290, "text": "the bright red windows of the “Sword-Fish Inn,” there came\nsuch fervent rays, that it seemed to have melted the packed snow and\nice from before the house, for everywhere else the congealed frost lay\nten inches thick in", "labels": {"50": 22, "100": 78, "250": 53, "500": 286, "1000": 508, "2000": 1027}}, {"id": 291, "position": 291, "text": "house, for everywhere else the congealed frost lay\nten inches thick in a hard, asphaltic pavement,—rather weary for me,\nwhen I struck my foot against the flinty projections, because from\nhard, remorseless service the soles of", "labels": {"50": 20, "100": 5, "250": 45, "500": 412, "1000": 51, "2000": 381}}, {"id": 292, "position": 292, "text": "flinty projections, because from\nhard, remorseless service the soles of my boots were in a most\nmiserable plight. Too expensive and jolly, again thought I, pausing one\nmoment to watch the broad glare in the street, and hear the sounds of", "labels": {"50": 20, "100": 28, "250": 156, "500": 174, "1000": 421, "2000": 381}}, {"id": 293, "position": 293, "text": "moment to watch the broad glare in the street, and hear the sounds of\nthe tinkling glasses within. But go on, Ishmael, said I at last; don’t\nyou hear? get away from before the door; your patched", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 216}}, {"id": 294, "position": 294, "text": "’t\nyou hear? get away from before the door; your patched boots are\nstopping the way. So on I went. I now by instinct followed the streets\nthat took me waterward, for there, doubtless, were the cheapest,", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 462, "2000": 1702}}, {"id": 295, "position": 295, "text": "me waterward, for there, doubtless, were the cheapest, if not\nthe cheeriest inns.\n\nSuch dreary streets! blocks of blackness, not houses, on either hand,\nand here and there a candle, like a candle", "labels": {"50": 25, "100": 5, "250": 90, "500": 412, "1000": 529, "2000": 381}}, {"id": 296, "position": 296, "text": ", on either hand,\nand here and there a candle, like a candle moving about in a tomb. At\nthis hour of the night, of the last day of the week, that quarter of\nthe town proved all but deserted", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 57, "2000": 1657}}, {"id": 297, "position": 297, "text": ", that quarter of\nthe town proved all but deserted. But presently I came to a smoky light\nproceeding from a low, wide building, the door of which stood\ninvitingly open. It had a careless look, as if it were meant for the\nuses", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 298, "position": 298, "text": ". It had a careless look, as if it were meant for the\nuses of the public; so, entering, the first thing I did was to stumble\nover an ash-box in the porch. Ha! thought I, ha, as the flying", "labels": {"50": 20, "100": 79, "250": 176, "500": 443, "1000": 329, "2000": 44}}, {"id": 299, "position": 299, "text": "box in the porch. Ha! thought I, ha, as the flying\nparticles almost choked me, are these ashes from that destroyed city,\nGomorrah? But “The Crossed Harpoons,” and “The Sword-Fish?”—", "labels": {"50": 48, "100": 27, "250": 90, "500": 304, "1000": 35, "2000": 1735}}, {"id": 300, "position": 300, "text": "The Crossed Harpoons,” and “The Sword-Fish?”—this, then\nmust needs be the sign of “The Trap.” However, I picked myself up and\nhearing a loud voice within, pushed on and opened a second, interior", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 301, "position": 301, "text": "and\nhearing a loud voice within, pushed on and opened a second, interior\ndoor.\n\nIt seemed the great Black Parliament sitting in Tophet. A hundred black\nfaces turned round in their rows to peer; and beyond, a black Angel of\nDoom was beating", "labels": {"50": 22, "100": 30, "250": 205, "500": 262, "1000": 660, "2000": 685}}, {"id": 302, "position": 302, "text": "their rows to peer; and beyond, a black Angel of\nDoom was beating a book in a pulpit. It was a negro church; and the\npreacher’s text was about the blackness of darkness, and the weeping\nand wailing and teeth-g", "labels": {"50": 22, "100": 51, "250": 40, "500": 262, "1000": 322, "2000": 1902}}, {"id": 303, "position": 303, "text": "the blackness of darkness, and the weeping\nand wailing and teeth-gnashing there. Ha, Ishmael, muttered I, backing\nout, Wretched entertainment at the sign of ‘The Trap!’", "labels": {"50": 36, "100": 64, "250": 140, "500": 70, "1000": 850, "2000": 564}}, {"id": 304, "position": 304, "text": "the sign of ‘The Trap!’\n\nMoving on, I at last came to a dim sort of light not far from the\ndocks, and heard a forlorn creaking in the air; and looking up, saw a\nswinging sign over the", "labels": {"50": 25, "100": 5, "250": 136, "500": 313, "1000": 906, "2000": 453}}, {"id": 305, "position": 305, "text": "ing in the air; and looking up, saw a\nswinging sign over the door with a white painting upon it, faintly\nrepresenting a tall straight jet of misty spray, and these words\nunderneath—“The Spouter Inn:—Peter Coffin.”", "labels": {"50": 41, "100": 21, "250": 215, "500": 100, "1000": 59, "2000": 361}}, {"id": 306, "position": 306, "text": "words\nunderneath—“The Spouter Inn:—Peter Coffin.”\n\nCoffin?—Spouter?—Rather ominous in that particular connexion, thought\nI. But it is a common name in Nantucket, they say, and", "labels": {"50": 41, "100": 64, "250": 193, "500": 498, "1000": 849, "2000": 47}}, {"id": 307, "position": 307, "text": ". But it is a common name in Nantucket, they say, and I suppose this\nPeter here is an emigrant from there. As the light looked so dim, and\nthe place, for the time, looked quiet enough, and the dilapidated\nlittle", "labels": {"50": 41, "100": 64, "250": 163, "500": 367, "1000": 670, "2000": 824}}, {"id": 308, "position": 308, "text": "the place, for the time, looked quiet enough, and the dilapidated\nlittle wooden house itself looked as if it might have been carted here\nfrom the ruins of some burnt district, and as the swinging sign had a\npoverty-stricken sort of creak", "labels": {"50": 7, "100": 22, "250": 53, "500": 371, "1000": 777, "2000": 1623}}, {"id": 309, "position": 309, "text": ", and as the swinging sign had a\npoverty-stricken sort of creak to it, I thought that here was the very\nspot for cheap lodgings, and the best of pea coffee.\n\nIt was a queer sort of place—a gable-ended", "labels": {"50": 48, "100": 27, "250": 53, "500": 412, "1000": 619, "2000": 1623}}, {"id": 310, "position": 310, "text": "pea coffee.\n\nIt was a queer sort of place—a gable-ended old house, one side palsied\nas it were, and leaning over sadly. It stood on a sharp bleak corner,\nwhere that tempestuous wind Euroclydon kept", "labels": {"50": 48, "100": 27, "250": 53, "500": 371, "1000": 995, "2000": 1623}}, {"id": 311, "position": 311, "text": "a sharp bleak corner,\nwhere that tempestuous wind Euroclydon kept up a worse howling than\never it did about poor Paul’s tossed craft. Euroclydon, nevertheless,\nis a mighty pleasant zephyr to any one in-", "labels": {"50": 45, "100": 29, "250": 6, "500": 79, "1000": 338, "2000": 22}}, {"id": 312, "position": 312, "text": ", nevertheless,\nis a mighty pleasant zephyr to any one in-doors, with his feet on the\nhob quietly toasting for bed. “In judging of that tempestuous wind\ncalled Euroclydon,” says an old writer—", "labels": {"50": 31, "100": 20, "250": 193, "500": 126, "1000": 727, "2000": 1107}}, {"id": 313, "position": 313, "text": "tempestuous wind\ncalled Euroclydon,” says an old writer—of whose works I possess the\nonly copy extant—“it maketh a marvellous difference, whether thou\nlookest out at it from a glass window where the frost is all", "labels": {"50": 31, "100": 24, "250": 213, "500": 334, "1000": 692, "2000": 982}}, {"id": 314, "position": 314, "text": "thou\nlookest out at it from a glass window where the frost is all on the\noutside, or whether thou observest it from that sashless window, where\nthe frost is on both sides, and of which the wight Death is the only\ngla", "labels": {"50": 9, "100": 73, "250": 120, "500": 143, "1000": 616, "2000": 374}}, {"id": 315, "position": 315, "text": "on both sides, and of which the wight Death is the only\nglazier.” True enough, thought I, as this passage occurred to my\nmind—old black-letter, thou reasonest well", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 1003}}, {"id": 316, "position": 316, "text": "letter, thou reasonest well. Yes, these eyes are\nwindows, and this body of mine is the house. What a pity they didn’t\nstop up the chinks and the crannies though, and thrust in a little lint\nhere", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 647, "2000": 39}}, {"id": 317, "position": 317, "text": "and the crannies though, and thrust in a little lint\nhere and there. But it’s too late to make any improvements now. The\nuniverse is finished; the copestone is on, and the chips were carted\noff a million", "labels": {"50": 48, "100": 20, "250": 49, "500": 334, "1000": 747, "2000": 1710}}, {"id": 318, "position": 318, "text": "the copestone is on, and the chips were carted\noff a million years ago. Poor Lazarus there, chattering his teeth\nagainst the curbstone for his pillow, and shaking off his tatters with\nhis shiverings, he might plug up both", "labels": {"50": 25, "100": 41, "250": 91, "500": 407, "1000": 329, "2000": 1426}}, {"id": 319, "position": 319, "text": "shaking off his tatters with\nhis shiverings, he might plug up both ears with rags, and put a\ncorn-cob into his mouth, and yet that would not keep out the\ntempestuous Euroclydon", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 320, "position": 320, "text": "keep out the\ntempestuous Euroclydon. Euroclydon! says old Dives, in his red silken\nwrapper—(he had a redder one afterwards) pooh, pooh! What a fine frosty\nnight;", "labels": {"50": 16, "100": 73, "250": 15, "500": 143, "1000": 50, "2000": 1886}}, {"id": 321, "position": 321, "text": "afterwards) pooh, pooh! What a fine frosty\nnight; how Orion glitters; what northern lights! Let them talk of their\noriental summer climes of everlasting conservatories; give me the\nprivilege of making my", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 1107}}, {"id": 322, "position": 322, "text": "everlasting conservatories; give me the\nprivilege of making my own summer with my own coals.\n\nBut what thinks Lazarus? Can he warm his blue hands by holding them up\nto the grand northern lights? Would not Lazarus rather be in", "labels": {"50": 25, "100": 41, "250": 68, "500": 407, "1000": 194, "2000": 1359}}, {"id": 323, "position": 323, "text": "holding them up\nto the grand northern lights? Would not Lazarus rather be in Sumatra\nthan here? Would he not far rather lay him down lengthwise along the\nline of the equator; yea, ye gods! go down to the fiery pit itself,", "labels": {"50": 40, "100": 83, "250": 170, "500": 60, "1000": 946, "2000": 1766}}, {"id": 324, "position": 324, "text": "; yea, ye gods! go down to the fiery pit itself, in\norder to keep out this frost?\n\nNow, that Lazarus should lie stranded there on the curbstone before the\ndoor of Dives, this is more wonderful than that an ice", "labels": {"50": 16, "100": 73, "250": 133, "500": 198, "1000": 167, "2000": 464}}, {"id": 325, "position": 325, "text": "before the\ndoor of Dives, this is more wonderful than that an iceberg should be\nmoored to one of the Moluccas. Yet Dives himself, he too lives like a\nCzar in an ice palace made of frozen sighs,", "labels": {"50": 31, "100": 20, "250": 49, "500": 78, "1000": 747, "2000": 1717}}, {"id": 326, "position": 326, "text": "too lives like a\nCzar in an ice palace made of frozen sighs, and being a president of a\ntemperance society, he only drinks the tepid tears of orphans.\n\nBut no more of this blubbering now, we are going a-whaling", "labels": {"50": 31, "100": 20, "250": 69, "500": 274, "1000": 203, "2000": 777}}, {"id": 327, "position": 327, "text": "no more of this blubbering now, we are going a-whaling, and there\nis plenty of that yet to come. Let us scrape the ice from our frosted\nfeet, and see what sort of a place this “Spouter”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 328, "position": 328, "text": "feet, and see what sort of a place this “Spouter” may be.\n\n\nCHAPTER 3. The Spouter-Inn.\n\nEntering that gable-ended Spouter-Inn, you found yourself in a wide,\nlow, strag", "labels": {"50": 48, "100": 20, "250": 249, "500": 334, "1000": 747, "2000": 1710}}, {"id": 329, "position": 329, "text": "er-Inn, you found yourself in a wide,\nlow, straggling entry with old-fashioned wainscots, reminding one of\nthe bulwarks of some condemned old craft. On one side hung a very large\noilpaint", "labels": {"50": 48, "100": 27, "250": 53, "500": 371, "1000": 777, "2000": 1366}}, {"id": 330, "position": 330, "text": "some condemned old craft. On one side hung a very large\noilpainting so thoroughly besmoked, and every way defaced, that in the\nunequal crosslights by which you viewed it, it was only by diligent\nstudy", "labels": {"50": 1, "100": 80, "250": 59, "500": 371, "1000": 777, "2000": 1366}}, {"id": 331, "position": 331, "text": "lights by which you viewed it, it was only by diligent\nstudy and a series of systematic visits to it, and careful inquiry of\nthe neighbors, that you could any way arrive at an understanding of its\npurpose", "labels": {"50": 1, "100": 80, "250": 63, "500": 415, "1000": 353, "2000": 1695}}, {"id": 332, "position": 332, "text": "way arrive at an understanding of its\npurpose. Such unaccountable masses of shades and shadows, that at first\nyou almost thought some ambitious young artist, in the time of the New\nEngland hags, had endeavored to delineate chaos be", "labels": {"50": 17, "100": 16, "250": 196, "500": 483, "1000": 212, "2000": 1601}}, {"id": 333, "position": 333, "text": "the New\nEngland hags, had endeavored to delineate chaos bewitched. But by dint\nof much and earnest contemplation, and oft repeated ponderings, and\nespecially by throwing open the little window towards the back of", "labels": {"50": 41, "100": 21, "250": 219, "500": 286, "1000": 59, "2000": 32}}, {"id": 334, "position": 334, "text": "ponderings, and\nespecially by throwing open the little window towards the back of the\nentry, you at last come to the conclusion that such an idea, however\nwild, might not be altogether unwarranted.", "labels": {"50": 31, "100": 71, "250": 210, "500": 274, "1000": 985, "2000": 862}}, {"id": 335, "position": 335, "text": "be altogether unwarranted.\n\nBut what most puzzled and confounded you was a long, limber,\nportentous, black mass of something hovering in the centre of the\npicture over three blue, dim, perpendicular lines floating in a\nnameless", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 336, "position": 336, "text": "the\npicture over three blue, dim, perpendicular lines floating in a\nnameless yeast. A boggy, soggy, squitchy picture truly, enough to drive\na nervous man distracted. Yet was there a sort of indefinite,\nhalf-attained,", "labels": {"50": 39, "100": 88, "250": 196, "500": 138, "1000": 115, "2000": 1833}}, {"id": 337, "position": 337, "text": "man distracted. Yet was there a sort of indefinite,\nhalf-attained, unimaginable sublimity about it that fairly froze you to\nit, till you involuntarily took an oath with yourself to find out what\nthat marvellous", "labels": {"50": 48, "100": 27, "250": 90, "500": 339, "1000": 727, "2000": 1466}}, {"id": 338, "position": 338, "text": "luntarily took an oath with yourself to find out what\nthat marvellous painting meant. Ever and anon a bright, but, alas,\ndeceptive idea would dart you through.—It’s the Black Sea in a midnight\ngale.", "labels": {"50": 34, "100": 77, "250": 164, "500": 192, "1000": 427, "2000": 1925}}, {"id": 339, "position": 339, "text": "you through.—It’s the Black Sea in a midnight\ngale.—It’s the unnatural combat of the four primal elements.—It’s a\nblasted heath.—It’s a Hyperborean winter scene.—It’", "labels": {"50": 29, "100": 4, "250": 114, "500": 341, "1000": 101, "2000": 621}}, {"id": 340, "position": 340, "text": ".—It’s a Hyperborean winter scene.—It’s the breaking-up of\nthe icebound stream of Time. But at last all these fancies yielded to\nthat one portentous something in the picture’s midst", "labels": {"50": 48, "100": 20, "250": 50, "500": 33, "1000": 862, "2000": 1590}}, {"id": 341, "position": 341, "text": "yielded to\nthat one portentous something in the picture’s midst. _That_ once found\nout, and all the rest were plain. But stop; does it not bear a faint\nresemblance to a gigantic fish? even the great leviathan himself", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 342, "position": 342, "text": "bear a faint\nresemblance to a gigantic fish? even the great leviathan himself?\n\nIn fact, the artist’s design seemed this: a final theory of my own,\npartly based upon the aggregated opinions of many aged persons with\nwhom I conversed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 343, "position": 343, "text": "based upon the aggregated opinions of many aged persons with\nwhom I conversed upon the subject. The picture represents a Cape-Horner\nin a great hurricane; the half-foundered ship weltering there with its\nthree dismantled masts alone visible", "labels": {"50": 48, "100": 27, "250": 90, "500": 224, "1000": 619, "2000": 887}}, {"id": 344, "position": 344, "text": "foundered ship weltering there with its\nthree dismantled masts alone visible; and an exasperated whale,\npurposing to spring clean over the craft, is in the enormous act of\nimpaling himself upon the three mast-heads.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 345, "position": 345, "text": "act of\nimpaling himself upon the three mast-heads.\n\nThe opposite wall of this entry was hung all over with a heathenish\narray of monstrous clubs and spears. Some were thickly set with\nglittering teeth resembling ivory saws; others were tu", "labels": {"50": 22, "100": 10, "250": 205, "500": 380, "1000": 475, "2000": 481}}, {"id": 346, "position": 346, "text": "were thickly set with\nglittering teeth resembling ivory saws; others were tufted with knots\nof human hair; and one was sickle-shaped, with a vast handle sweeping\nround like the segment made in the new-mown grass by a long", "labels": {"50": 11, "100": 12, "250": 16, "500": 352, "1000": 695, "2000": 1186}}, {"id": 347, "position": 347, "text": "round like the segment made in the new-mown grass by a long-armed\nmower. You shuddered as you gazed, and wondered what monstrous cannibal\nand savage could ever have gone a death-harvesting with such a hacking,\nhorri", "labels": {"50": 48, "100": 20, "250": 53, "500": 334, "1000": 275, "2000": 1546}}, {"id": 348, "position": 348, "text": "could ever have gone a death-harvesting with such a hacking,\nhorrifying implement. Mixed with these were rusty old whaling lances\nand harpoons all broken and deformed. Some were storied weapons", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 349, "position": 349, "text": "med. Some were storied weapons. With\nthis once long lance, now wildly elbowed, fifty years ago did Nathan\nSwain kill fifteen whales between a sunrise and a sunset. And that\nharpoon—so like a corkscrew now—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 350, "position": 350, "text": "sunset. And that\nharpoon—so like a corkscrew now—was flung in Javan seas, and run away\nwith by a whale, years afterwards slain off the Cape of Blanco. The\noriginal iron entered nigh the tail, and,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 351, "position": 351, "text": "Cape of Blanco. The\noriginal iron entered nigh the tail, and, like a restless needle\nsojourning in the body of a man, travelled full forty feet, and at last\nwas found imbedded in the hump.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 556, "2000": 1897}}, {"id": 352, "position": 352, "text": "and at last\nwas found imbedded in the hump.\n\nCrossing this dusky entry, and on through yon low-arched way—cut\nthrough what in old times must have been a great central chimney with\nfireplaces all round—you enter", "labels": {"50": 48, "100": 27, "250": 157, "500": 223, "1000": 79, "2000": 166}}, {"id": 353, "position": 353, "text": "must have been a great central chimney with\nfireplaces all round—you enter the public room. A still duskier place\nis this, with such low ponderous beams above, and such old wrinkled\nplanks beneath, that you would almost fancy you tr", "labels": {"50": 48, "100": 27, "250": 53, "500": 371, "1000": 995, "2000": 1623}}, {"id": 354, "position": 354, "text": "and such old wrinkled\nplanks beneath, that you would almost fancy you trod some old craft’s\ncockpits, especially of such a howling night, when this corner-anchored\nold ark rocked so furiously", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 355, "position": 355, "text": "anchored\nold ark rocked so furiously. On one side stood a long, low, shelf-like\ntable covered with cracked glass cases, filled with dusty rarities\ngathered from this wide world’s remotest nooks", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 887}}, {"id": 356, "position": 356, "text": "wide world’s remotest nooks. Projecting from the\nfurther angle of the room stands a dark-looking den—the bar—a rude\nattempt at a right whale’s head. Be that how it may, there stands the\nvast arched", "labels": {"50": 48, "100": 20, "250": 49, "500": 78, "1000": 933, "2000": 1081}}, {"id": 357, "position": 357, "text": "’s head. Be that how it may, there stands the\nvast arched bone of the whale’s jaw, so wide, a coach might almost\ndrive beneath it. Within are shabby shelves, ranged round with old\ndecanters, bottles,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 358, "position": 358, "text": "are shabby shelves, ranged round with old\ndecanters, bottles, flasks; and in those jaws of swift destruction,\nlike another cursed Jonah (by which name indeed they called him),\nbustles a little withered old man,", "labels": {"50": 22, "100": 78, "250": 70, "500": 163, "1000": 383, "2000": 1102}}, {"id": 359, "position": 359, "text": "indeed they called him),\nbustles a little withered old man, who, for their money, dearly sells\nthe sailors deliriums and death.\n\nAbominable are the tumblers into which he pours his poison", "labels": {"50": 23, "100": 49, "250": 63, "500": 78, "1000": 165, "2000": 90}}, {"id": 360, "position": 360, "text": "are the tumblers into which he pours his poison. Though true\ncylinders without—within, the villanous green goggling glasses\ndeceitfully tapered downwards to a cheating bottom. Parallel meridians\nrudely pecked into the glass, surround", "labels": {"50": 9, "100": 4, "250": 193, "500": 498, "1000": 849, "2000": 1886}}, {"id": 361, "position": 361, "text": "cheating bottom. Parallel meridians\nrudely pecked into the glass, surround these footpads’ goblets. Fill to\n_this_ mark, and your charge is but a penny; to _this_ a penny more;\nand so on", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 637, "2000": 1003}}, {"id": 362, "position": 362, "text": "but a penny; to _this_ a penny more;\nand so on to the full glass—the Cape Horn measure, which you may gulp\ndown for a shilling.\n\nUpon entering the place I found a number of young seamen gathered about\na table", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 877}}, {"id": 363, "position": 363, "text": "Upon entering the place I found a number of young seamen gathered about\na table, examining by a dim light divers specimens of _skrimshander_. I\nsought the landlord, and telling him I desired to be accommodated with\na room, received for", "labels": {"50": 23, "100": 28, "250": 156, "500": 202, "1000": 421, "2000": 1068}}, {"id": 364, "position": 364, "text": ", and telling him I desired to be accommodated with\na room, received for answer that his house was full—not a bed\nunoccupied. “But avast,” he added, tapping his forehead, “you haint no\nobjections to", "labels": {"50": 25, "100": 56, "250": 156, "500": 349, "1000": 523, "2000": 652}}, {"id": 365, "position": 365, "text": "” he added, tapping his forehead, “you haint no\nobjections to sharing a harpooneer’s blanket, have ye? I s’pose you are\ngoin’ a-whalin’, so you’d better get used to", "labels": {"50": 25, "100": 64, "250": 163, "500": 363, "1000": 54, "2000": 786}}, {"id": 366, "position": 366, "text": "a-whalin’, so you’d better get used to that sort of thing.”\n\nI told him that I never liked to sleep two in a bed; that if I should\never do so, it would depend upon who the harp", "labels": {"50": 25, "100": 41, "250": 91, "500": 150, "1000": 483, "2000": 1707}}, {"id": 367, "position": 367, "text": "that if I should\never do so, it would depend upon who the harpooneer might be, and that\nif he (the landlord) really had no other place for me, and the\nharpooneer was not decidedly objectionable, why rather than", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 692, "2000": 982}}, {"id": 368, "position": 368, "text": ", and the\nharpooneer was not decidedly objectionable, why rather than wander\nfurther about a strange town on so bitter a night, I would put up with\nthe half of any decent man’s blanket.\n\n“I thought so", "labels": {"50": 25, "100": 41, "250": 91, "500": 407, "1000": 483, "2000": 1528}}, {"id": 369, "position": 369, "text": "any decent man’s blanket.\n\n“I thought so. All right; take a seat. Supper?—you want supper?\nSupper’ll be ready directly.”\n\nI sat down on an old wooden settle, carved all over like a bench on", "labels": {"50": 25, "100": 41, "250": 204, "500": 150, "1000": 483, "2000": 251}}, {"id": 370, "position": 370, "text": "sat down on an old wooden settle, carved all over like a bench on the\nBattery. At one end a ruminating tar was still further adorning it with\nhis jack-knife, stooping over and diligently working away at the space", "labels": {"50": 37, "100": 6, "250": 174, "500": 5, "1000": 726, "2000": 220}}, {"id": 371, "position": 371, "text": "-knife, stooping over and diligently working away at the space\nbetween his legs. He was trying his hand at a ship under full sail, but\nhe didn’t make much headway, I thought.", "labels": {"50": 25, "100": 64, "250": 136, "500": 388, "1000": 313, "2000": 786}}, {"id": 372, "position": 372, "text": "t make much headway, I thought.\n\nAt last some four or five of us were summoned to our meal in an\nadjoining room. It was cold as Iceland—no fire at all—the landlord said\nhe couldn’t afford it", "labels": {"50": 25, "100": 93, "250": 55, "500": 318, "1000": 868, "2000": 1138}}, {"id": 373, "position": 373, "text": "at all—the landlord said\nhe couldn’t afford it. Nothing but two dismal tallow candles, each in a\nwinding sheet. We were fain to button up our monkey jackets, and hold\nto our lips cups of scalding", "labels": {"50": 25, "100": 41, "250": 55, "500": 318, "1000": 868, "2000": 572}}, {"id": 374, "position": 374, "text": "up our monkey jackets, and hold\nto our lips cups of scalding tea with our half frozen fingers. But the\nfare was of the most substantial kind—not only meat and potatoes, but\ndumplings; good heavens! dumplings for supper!", "labels": {"50": 12, "100": 93, "250": 55, "500": 430, "1000": 585, "2000": 1138}}, {"id": 375, "position": 375, "text": "and potatoes, but\ndumplings; good heavens! dumplings for supper! One young fellow in a\ngreen box coat, addressed himself to these dumplings in a most direful\nmanner.\n\n“My boy,” said the landlord, “you’ll", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 317, "2000": 788}}, {"id": 376, "position": 376, "text": "manner.\n\n“My boy,” said the landlord, “you’ll have the nightmare to a dead\nsartainty.”\n\n“Landlord,” I whispered, “that aint the harpooneer is it?”", "labels": {"50": 25, "100": 41, "250": 136, "500": 180, "1000": 103, "2000": 786}}, {"id": 377, "position": 377, "text": "aint the harpooneer is it?”\n\n“Oh, no,” said he, looking a sort of diabolically funny, “the\nharpooneer is a dark complexioned chap. He never eats dumplings, he\ndon’", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 54, "2000": 1620}}, {"id": 378, "position": 378, "text": "dark complexioned chap. He never eats dumplings, he\ndon’t—he eats nothing but steaks, and he likes ’em rare.”\n\n“The devil he does,” says I", "labels": {"50": 23, "100": 88, "250": 241, "500": 440, "1000": 299, "2000": 1113}}, {"id": 379, "position": 379, "text": "he does,” says I. “Where is that harpooneer? Is he here?”\n\n“He’ll be here afore long,” was the answer.\n\nI could not help it, but I began to feel suspicious of this “", "labels": {"50": 45, "100": 64, "250": 95, "500": 72, "1000": 533, "2000": 778}}, {"id": 380, "position": 380, "text": "I could not help it, but I began to feel suspicious of this “dark\ncomplexioned” harpooneer. At any rate, I made up my mind that if it so\nturned out that we should sleep together, he must undress and get", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 381, "position": 381, "text": "so\nturned out that we should sleep together, he must undress and get into\nbed before I did.\n\nSupper over, the company went back to the bar-room, when, knowing not\nwhat else to do with myself, I resolved to spend the", "labels": {"50": 8, "100": 68, "250": 241, "500": 440, "1000": 299, "2000": 1113}}, {"id": 382, "position": 382, "text": ", knowing not\nwhat else to do with myself, I resolved to spend the rest of the\nevening as a looker on.\n\nPresently a rioting noise was heard without. Starting up, the landlord\ncried, “That’s the Grampus’s", "labels": {"50": 25, "100": 5, "250": 156, "500": 134, "1000": 421, "2000": 1068}}, {"id": 383, "position": 383, "text": "up, the landlord\ncried, “That’s the Grampus’s crew. I seed her reported in the offing\nthis morning; a three years’ voyage, and a full ship. Hurrah, boys; now\nwe’ll have", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 384, "position": 384, "text": "a full ship. Hurrah, boys; now\nwe’ll have the latest news from the Feegees.”\n\nA tramping of sea boots was heard in the entry; the door was flung\nopen, and in rolled a wild set of", "labels": {"50": 41, "100": 31, "250": 228, "500": 208, "1000": 516, "2000": 270}}, {"id": 385, "position": 385, "text": "entry; the door was flung\nopen, and in rolled a wild set of mariners enough. Enveloped in their\nshaggy watch coats, and with their heads muffled in woollen comforters,\nall bedarned and ragged, and their beards stiff with ic", "labels": {"50": 22, "100": 64, "250": 219, "500": 180, "1000": 496, "2000": 110}}, {"id": 386, "position": 386, "text": ",\nall bedarned and ragged, and their beards stiff with icicles, they\nseemed an eruption of bears from Labrador. They had just landed from\ntheir boat, and this was the first house they entered", "labels": {"50": 12, "100": 88, "250": 95, "500": 344, "1000": 377, "2000": 207}}, {"id": 387, "position": 387, "text": "this was the first house they entered. No wonder, then,\nthat they made a straight wake for the whale’s mouth—the bar—when the\nwrinkled little old Jonah, there officiating, soon poured them out\nbrimmers all round", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 388, "position": 388, "text": ", there officiating, soon poured them out\nbrimmers all round. One complained of a bad cold in his head, upon\nwhich Jonah mixed him a pitch-like potion of gin and molasses, which he\nswore was a sovereign cure", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 389, "position": 389, "text": "potion of gin and molasses, which he\nswore was a sovereign cure for all colds and catarrhs whatsoever, never\nmind of how long standing, or whether caught off the coast of Labrador,\nor on the weather side of an ice", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 390, "position": 390, "text": "caught off the coast of Labrador,\nor on the weather side of an ice-island.\n\nThe liquor soon mounted into their heads, as it generally does even\nwith the arrantest topers newly landed from sea, and they began\ncapering about most", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1584}}, {"id": 391, "position": 391, "text": "est topers newly landed from sea, and they began\ncapering about most obstreperously.\n\nI observed, however, that one of them held somewhat aloof, and though\nhe seemed desirous not to spoil the hilarity of", "labels": {"50": 45, "100": 42, "250": 189, "500": 297, "1000": 222, "2000": 1171}}, {"id": 392, "position": 392, "text": "and though\nhe seemed desirous not to spoil the hilarity of his shipmates by his\nown sober face, yet upon the whole he refrained from making as much\nnoise as the rest. This man interested me at once; and since the", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 967}}, {"id": 393, "position": 393, "text": "noise as the rest. This man interested me at once; and since the\nsea-gods had ordained that he should soon become my shipmate (though\nbut a sleeping-partner one, so far as this narrative is concerned), I\nwill here venture", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 394, "position": 394, "text": "one, so far as this narrative is concerned), I\nwill here venture upon a little description of him. He stood full six\nfeet in height, with noble shoulders, and a chest like a coffer-dam", "labels": {"50": 25, "100": 88, "250": 219, "500": 180, "1000": 383, "2000": 955}}, {"id": 395, "position": 395, "text": "a chest like a coffer-dam. I\nhave seldom seen such brawn in a man. His face was deeply brown and\nburnt, making his white teeth dazzling by the contrast; while in the\ndeep shadows of his eyes floated some reminisc", "labels": {"50": 25, "100": 41, "250": 156, "500": 128, "1000": 383, "2000": 202}}, {"id": 396, "position": 396, "text": "contrast; while in the\ndeep shadows of his eyes floated some reminiscences that did not seem\nto give him much joy. His voice at once announced that he was a\nSoutherner, and from his fine stature, I thought he must be", "labels": {"50": 44, "100": 37, "250": 175, "500": 294, "1000": 363, "2000": 221}}, {"id": 397, "position": 397, "text": "a\nSoutherner, and from his fine stature, I thought he must be one of\nthose tall mountaineers from the Alleghanian Ridge in Virginia. When\nthe revelry of his companions had mounted to its height, this man\nslipped away uno", "labels": {"50": 25, "100": 93, "250": 136, "500": 233, "1000": 718, "2000": 1412}}, {"id": 398, "position": 398, "text": "ry of his companions had mounted to its height, this man\nslipped away unobserved, and I saw no more of him till he became my\ncomrade on the sea. In a few minutes, however, he was missed by his\nshipmates, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 399, "position": 399, "text": "a few minutes, however, he was missed by his\nshipmates, and being, it seems, for some reason a huge favourite with\nthem, they raised a cry of “Bulkington! Bulkington! where’s\nBulkington?” and darted", "labels": {"50": 23, "100": 51, "250": 38, "500": 178, "1000": 734, "2000": 791}}, {"id": 400, "position": 400, "text": "Bulkington! Bulkington! where’s\nBulkington?” and darted out of the house in pursuit of him.\n\nIt was now about nine o’clock, and the room seeming almost\nsupernaturally quiet after these orgies, I began to cong", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 194, "2000": 1702}}, {"id": 401, "position": 401, "text": "room seeming almost\nsupernaturally quiet after these orgies, I began to congratulate myself\nupon a little plan that had occurred to me just previous to the\nentrance of the seamen.\n\nNo man prefers to sleep two in a bed", "labels": {"50": 25, "100": 41, "250": 156, "500": 388, "1000": 313, "2000": 786}}, {"id": 402, "position": 402, "text": ".\n\nNo man prefers to sleep two in a bed. In fact, you would a good deal\nrather not sleep with your own brother. I don’t know how it is, but\npeople like to be private when they are sleeping", "labels": {"50": 25, "100": 56, "250": 98, "500": 177, "1000": 700, "2000": 652}}, {"id": 403, "position": 403, "text": ", but\npeople like to be private when they are sleeping. And when it comes to\nsleeping with an unknown stranger, in a strange inn, in a strange town,\nand that stranger a harpooneer, then your objections indefinitely\nmultiply", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 1426}}, {"id": 404, "position": 404, "text": "stranger a harpooneer, then your objections indefinitely\nmultiply. Nor was there any earthly reason why I as a sailor should\nsleep two in a bed, more than anybody else; for sailors no more sleep\ntwo in a bed at sea, than bachelor", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 877}}, {"id": 405, "position": 405, "text": "; for sailors no more sleep\ntwo in a bed at sea, than bachelor Kings do ashore. To be sure they all\nsleep together in one apartment, but you have your own hammock, and\ncover yourself with your own blanket, and sleep in", "labels": {"50": 25, "100": 12, "250": 91, "500": 150, "1000": 533, "2000": 880}}, {"id": 406, "position": 406, "text": "hammock, and\ncover yourself with your own blanket, and sleep in your own skin.\n\nThe more I pondered over this harpooneer, the more I abominated the\nthought of sleeping with him", "labels": {"50": 25, "100": 5, "250": 136, "500": 72, "1000": 533, "2000": 1521}}, {"id": 407, "position": 407, "text": "the\nthought of sleeping with him. It was fair to presume that being a\nharpooneer, his linen or woollen, as the case might be, would not be of\nthe tidiest, certainly none of the finest", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 408, "position": 408, "text": "of\nthe tidiest, certainly none of the finest. I began to twitch all over.\nBesides, it was getting late, and my decent harpooneer ought to be home\nand going bedwards", "labels": {"50": 25, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 778}}, {"id": 409, "position": 409, "text": "home\nand going bedwards. Suppose now, he should tumble in upon me at\nmidnight—how could I tell from what vile hole he had been coming?\n\n“Landlord! I’ve changed my mind about that harpooneer.—I shan", "labels": {"50": 25, "100": 5, "250": 156, "500": 180, "1000": 103, "2000": 786}}, {"id": 410, "position": 410, "text": "I’ve changed my mind about that harpooneer.—I shan’t sleep\nwith him. I’ll try the bench here.”\n\n“Just as you please; I’m sorry I can’t spare ye a tablecloth for", "labels": {"50": 16, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 1521}}, {"id": 411, "position": 411, "text": "; I’m sorry I can’t spare ye a tablecloth for a\nmattress, and it’s a plaguy rough board here”—feeling of the knots and\nnotches. “But wait a bit, Skrimshander;", "labels": {"50": 41, "100": 21, "250": 219, "500": 180, "1000": 230, "2000": 1199}}, {"id": 412, "position": 412, "text": "and\nnotches. “But wait a bit, Skrimshander; I’ve got a carpenter’s plane\nthere in the bar—wait, I say, and I’ll make ye snug enough.” So saying\nhe pro", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 413, "position": 413, "text": "I’ll make ye snug enough.” So saying\nhe procured the plane; and with his old silk handkerchief first dusting\nthe bench, vigorously set to planing away at my bed, the while grinning\nlike an ape", "labels": {"50": 11, "100": 22, "250": 214, "500": 147, "1000": 59, "2000": 938}}, {"id": 414, "position": 414, "text": "ing away at my bed, the while grinning\nlike an ape. The shavings flew right and left; till at last the\nplane-iron came bump against an indestructible knot. The landlord was\nnear spraining his wrist,", "labels": {"50": 25, "100": 5, "250": 156, "500": 313, "1000": 329, "2000": 251}}, {"id": 415, "position": 415, "text": "ructible knot. The landlord was\nnear spraining his wrist, and I told him for heaven’s sake to quit—the\nbed was soft enough to suit me, and I did not know how all the planing\nin the world could", "labels": {"50": 25, "100": 56, "250": 156, "500": 134, "1000": 651, "2000": 652}}, {"id": 416, "position": 416, "text": ", and I did not know how all the planing\nin the world could make eider down of a pine plank. So gathering up the\nshavings with another grin, and throwing them into the great stove in\nthe middle of the room, he", "labels": {"50": 25, "100": 41, "250": 204, "500": 150, "1000": 483, "2000": 251}}, {"id": 417, "position": 417, "text": "and throwing them into the great stove in\nthe middle of the room, he went about his business, and left me in a\nbrown study.\n\nI now took the measure of the bench, and found that it was a foot too\nshort; but that could", "labels": {"50": 25, "100": 41, "250": 156, "500": 128, "1000": 329, "2000": 1559}}, {"id": 418, "position": 418, "text": "bench, and found that it was a foot too\nshort; but that could be mended with a chair. But it was a foot too\nnarrow, and the other bench in the room was about four inches higher\nthan the planed one—so there", "labels": {"50": 40, "100": 12, "250": 36, "500": 3, "1000": 817, "2000": 1236}}, {"id": 419, "position": 419, "text": "the room was about four inches higher\nthan the planed one—so there was no yoking them. I then placed the\nfirst bench lengthwise along the only clear space against the wall,\nleaving a little interval between, for my back to settle down", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 420, "position": 420, "text": "the wall,\nleaving a little interval between, for my back to settle down in. But I\nsoon found that there came such a draught of cold air over me from\nunder the sill of the window, that this plan would never do at all,", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 421, "position": 421, "text": "sill of the window, that this plan would never do at all,\nespecially as another current from the rickety door met the one from\nthe window, and both together formed a series of small whirlwinds in\nthe immediate vicinity of the", "labels": {"50": 13, "100": 3, "250": 154, "500": 371, "1000": 293, "2000": 1857}}, {"id": 422, "position": 422, "text": "a series of small whirlwinds in\nthe immediate vicinity of the spot where I had thought to spend the\nnight.\n\nThe devil fetch that harpooneer, thought I, but stop, couldn’t I steal\na march on him—bolt", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 967}}, {"id": 423, "position": 423, "text": ", but stop, couldn’t I steal\na march on him—bolt his door inside, and jump into his bed, not to be\nwakened by the most violent knockings? It seemed no bad idea; but upon\nsecond thoughts I dismissed it", "labels": {"50": 25, "100": 41, "250": 156, "500": 313, "1000": 462, "2000": 1702}}, {"id": 424, "position": 424, "text": "s? It seemed no bad idea; but upon\nsecond thoughts I dismissed it. For who could tell but what the next\nmorning, so soon as I popped out of the room, the harpooneer might be\nstanding in the entry, all ready to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1620}}, {"id": 425, "position": 425, "text": ", the harpooneer might be\nstanding in the entry, all ready to knock me down!\n\nStill, looking round me again, and seeing no possible chance of\nspending a sufferable night unless in some other person’s bed, I began\nto think", "labels": {"50": 25, "100": 5, "250": 136, "500": 313, "1000": 103, "2000": 453}}, {"id": 426, "position": 426, "text": "able night unless in some other person’s bed, I began\nto think that after all I might be cherishing unwarrantable prejudices\nagainst this unknown harpooneer. Thinks I, I’ll wait awhile; he must be\ndropping in", "labels": {"50": 25, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 427, "position": 427, "text": ". Thinks I, I’ll wait awhile; he must be\ndropping in before long. I’ll have a good look at him then, and perhaps\nwe may become jolly good bedfellows after all—there’s no telling.", "labels": {"50": 23, "100": 86, "250": 57, "500": 228, "1000": 800, "2000": 42}}, {"id": 428, "position": 428, "text": "good bedfellows after all—there’s no telling.\n\nBut though the other boarders kept coming in by ones, twos, and threes,\nand going to bed, yet no sign of my harpooneer.", "labels": {"50": 25, "100": 41, "250": 91, "500": 407, "1000": 194, "2000": 1426}}, {"id": 429, "position": 429, "text": "bed, yet no sign of my harpooneer.\n\n“Landlord!” said I, “what sort of a chap is he—does he always keep such\nlate hours?” It was now hard upon twelve o’clock.", "labels": {"50": 25, "100": 5, "250": 156, "500": 313, "1000": 483, "2000": 742}}, {"id": 430, "position": 430, "text": "?” It was now hard upon twelve o’clock.\n\nThe landlord chuckled again with his lean chuckle, and seemed to be\nmightily tickled at something beyond my comprehension. “No,” he\nanswered, “generally he’s an early bird", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 483, "2000": 251}}, {"id": 431, "position": 431, "text": "“No,” he\nanswered, “generally he’s an early bird—airley to bed and airley to\nrise—yes, he’s the bird what catches the worm. But to-night he went out\na peddling, you", "labels": {"50": 41, "100": 21, "250": 91, "500": 5, "1000": 627, "2000": 1199}}, {"id": 432, "position": 432, "text": "the worm. But to-night he went out\na peddling, you see, and I don’t see what on airth keeps him so late,\nunless, may be, he can’t sell his head.”", "labels": {"50": 41, "100": 21, "250": 75, "500": 100, "1000": 59, "2000": 501}}, {"id": 433, "position": 433, "text": "be, he can’t sell his head.”\n\n“Can’t sell his head?—What sort of a bamboozingly story is this you are\ntelling me?” getting into a towering rage", "labels": {"50": 34, "100": 77, "250": 164, "500": 192, "1000": 427, "2000": 491}}, {"id": 434, "position": 434, "text": "” getting into a towering rage. “Do you pretend to say,\nlandlord, that this harpooneer is actually engaged this blessed\nSaturday night, or rather Sunday morning, in peddling his head around\nthis town?”", "labels": {"50": 23, "100": 41, "250": 219, "500": 180, "1000": 317, "2000": 1199}}, {"id": 435, "position": 435, "text": "peddling his head around\nthis town?”\n\n“That’s precisely it,” said the landlord, “and I told him he couldn’t\nsell it here, the market’s overstocked.”\n\n“With what?” shouted I", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 483, "2000": 1099}}, {"id": 436, "position": 436, "text": "market’s overstocked.”\n\n“With what?” shouted I.\n\n“With heads to be sure; ain’t there too many heads in the world?”\n\n“I tell you what it is, landlord,” said I quite calmly", "labels": {"50": 23, "100": 41, "250": 219, "500": 221, "1000": 627, "2000": 1199}}, {"id": 437, "position": 437, "text": "“I tell you what it is, landlord,” said I quite calmly, “you’d better\nstop spinning that yarn to me—I’m not green.”\n\n“May be not,” taking out a stick and whittling a", "labels": {"50": 25, "100": 41, "250": 91, "500": 407, "1000": 483, "2000": 1199}}, {"id": 438, "position": 438, "text": "“May be not,” taking out a stick and whittling a toothpick, “but I\nrayther guess you’ll be done _brown_ if that ere harpooneer hears you a\nslanderin’ his head.", "labels": {"50": 41, "100": 21, "250": 145, "500": 180, "1000": 230, "2000": 380}}, {"id": 439, "position": 439, "text": "ere harpooneer hears you a\nslanderin’ his head.”\n\n“I’ll break it for him,” said I, now flying into a passion again at\nthis unaccountable farrago of the landlord’s.", "labels": {"50": 25, "100": 64, "250": 136, "500": 180, "1000": 103, "2000": 786}}, {"id": 440, "position": 440, "text": "at\nthis unaccountable farrago of the landlord’s.\n\n“It’s broke a’ready,” said he.\n\n“Broke,” said I—“_broke_, do you mean?”", "labels": {"50": 25, "100": 41, "250": 91, "500": 407, "1000": 627, "2000": 1199}}, {"id": 441, "position": 441, "text": "“_broke_, do you mean?”\n\n“Sartain, and that’s the very reason he can’t sell it, I guess.”\n\n“Landlord,” said I, going up to him as cool as Mt", "labels": {"50": 41, "100": 21, "250": 91, "500": 281, "1000": 333, "2000": 1082}}, {"id": 442, "position": 442, "text": "” said I, going up to him as cool as Mt. Hecla in a\nsnow-storm—“landlord, stop whittling. You and I must understand one\nanother, and that too without delay", "labels": {"50": 25, "100": 41, "250": 219, "500": 318, "1000": 345, "2000": 1068}}, {"id": 443, "position": 443, "text": "one\nanother, and that too without delay. I come to your house and want a\nbed; you tell me you can only give me half a one; that the other half\nbelongs to a certain harpooneer", "labels": {"50": 40, "100": 50, "250": 36, "500": 437, "1000": 817, "2000": 1236}}, {"id": 444, "position": 444, "text": "belongs to a certain harpooneer. And about this harpooneer, whom I have\nnot yet seen, you persist in telling me the most mystifying and\nexasperating stories tending to beget in me an uncomfortable feeling\ntowards the man", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 692, "2000": 982}}, {"id": 445, "position": 445, "text": "perating stories tending to beget in me an uncomfortable feeling\ntowards the man whom you design for my bedfellow—a sort of connexion,\nlandlord, which is an intimate and confidential one in the highest\ndegree", "labels": {"50": 20, "100": 28, "250": 101, "500": 120, "1000": 421, "2000": 1559}}, {"id": 446, "position": 446, "text": "is an intimate and confidential one in the highest\ndegree. I now demand of you to speak out and tell me who and what this\nharpooneer is, and whether I shall be in all respects safe to spend the\nnight with him", "labels": {"50": 36, "100": 35, "250": 117, "500": 112, "1000": 450, "2000": 987}}, {"id": 447, "position": 447, "text": "be in all respects safe to spend the\nnight with him. And in the first place, you will be so good as to unsay\nthat story about selling his head, which if true I take to be good\nevidence that this harpooneer is stark", "labels": {"50": 25, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 786}}, {"id": 448, "position": 448, "text": "if true I take to be good\nevidence that this harpooneer is stark mad, and I’ve no idea of\nsleeping with a madman; and you, sir, _you_ I mean, landlord, _you_,\nsir, by trying", "labels": {"50": 40, "100": 64, "250": 182, "500": 27, "1000": 574, "2000": 582}}, {"id": 449, "position": 449, "text": "you_ I mean, landlord, _you_,\nsir, by trying to induce me to do so knowingly, would thereby render\nyourself liable to a criminal prosecution.”\n\n“Wall,” said the landlord, fetching a long breath, “", "labels": {"50": 23, "100": 45, "250": 8, "500": 221, "1000": 943, "2000": 1881}}, {"id": 450, "position": 450, "text": "“Wall,” said the landlord, fetching a long breath, “that’s a purty long\nsarmon for a chap that rips a little now and then. But be easy, be\neasy, this here harpooneer", "labels": {"50": 23, "100": 64, "250": 219, "500": 221, "1000": 627, "2000": 1199}}, {"id": 451, "position": 451, "text": "and then. But be easy, be\neasy, this here harpooneer I have been tellin’ you of has just arrived\nfrom the south seas, where he bought up a lot of ’balmed New Zealand\nheads (great curios,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 452, "position": 452, "text": "a lot of ’balmed New Zealand\nheads (great curios, you know), and he’s sold all on ’em but one, and\nthat one he’s trying to sell to-night, cause to-morrow’s", "labels": {"50": 37, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 453, "position": 453, "text": "’s trying to sell to-night, cause to-morrow’s Sunday, and it\nwould not do to be sellin’ human heads about the streets when folks is\ngoin’ to churches. He wanted to, last Sunday, but I stopped", "labels": {"50": 41, "100": 21, "250": 215, "500": 428, "1000": 333, "2000": 497}}, {"id": 454, "position": 454, "text": "goin’ to churches. He wanted to, last Sunday, but I stopped him just as\nhe was goin’ out of the door with four heads strung on a string, for\nall the airth like a string of inions.”", "labels": {"50": 41, "100": 21, "250": 215, "500": 428, "1000": 333, "2000": 497}}, {"id": 455, "position": 455, "text": "all the airth like a string of inions.”\n\nThis account cleared up the otherwise unaccountable mystery, and showed\nthat the landlord, after all, had had no idea of fooling me—but at the\nsame time what could I", "labels": {"50": 25, "100": 28, "250": 156, "500": 407, "1000": 421, "2000": 1645}}, {"id": 456, "position": 456, "text": "no idea of fooling me—but at the\nsame time what could I think of a harpooneer who stayed out of a\nSaturday night clean into the holy Sabbath, engaged in such a cannibal\nbusiness as selling the heads of dead idolators", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 251}}, {"id": 457, "position": 457, "text": "in such a cannibal\nbusiness as selling the heads of dead idolators?\n\n“Depend upon it, landlord, that harpooneer is a dangerous man.”\n\n“He pays reg’lar,” was the rejoinder", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 692, "2000": 778}}, {"id": 458, "position": 458, "text": "pays reg’lar,” was the rejoinder. “But come, it’s getting dreadful\nlate, you had better be turning flukes—it’s a nice bed; Sal and me\nslept in that ere bed the night we", "labels": {"50": 41, "100": 21, "250": 91, "500": 281, "1000": 230, "2000": 380}}, {"id": 459, "position": 459, "text": "nice bed; Sal and me\nslept in that ere bed the night we were spliced. There’s plenty of room\nfor two to kick about in that bed; it’s an almighty big bed that", "labels": {"50": 11, "100": 51, "250": 38, "500": 147, "1000": 583, "2000": 1771}}, {"id": 460, "position": 460, "text": "it’s an almighty big bed that. Why,\nafore we give it up, Sal used to put our Sam and little Johnny in the\nfoot of it. But I got a dreaming and sprawling about one night, and\nsomehow, Sam got pitched", "labels": {"50": 41, "100": 51, "250": 91, "500": 229, "1000": 488, "2000": 1771}}, {"id": 461, "position": 461, "text": "got a dreaming and sprawling about one night, and\nsomehow, Sam got pitched on the floor, and came near breaking his arm.\nArter that, Sal said it wouldn’t do. Come along here, I’ll give ye a\nglim", "labels": {"50": 41, "100": 21, "250": 215, "500": 147, "1000": 958, "2000": 1771}}, {"id": 462, "position": 462, "text": "t do. Come along here, I’ll give ye a\nglim in a jiffy;” and so saying he lighted a candle and held it towards\nme, offering to lead the way. But I stood irresolute; when looking", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 463, "position": 463, "text": "to lead the way. But I stood irresolute; when looking at a\nclock in the corner, he exclaimed “I vum it’s Sunday—you won’t see that\nharpooneer to-night; he’s come", "labels": {"50": 25, "100": 41, "250": 163, "500": 407, "1000": 533, "2000": 786}}, {"id": 464, "position": 464, "text": "’t see that\nharpooneer to-night; he’s come to anchor somewhere—come along then;\n_do_ come; _won’t_ ye come?”\n\nI considered the matter a moment, and then up stairs we went", "labels": {"50": 25, "100": 41, "250": 136, "500": 388, "1000": 483, "2000": 786}}, {"id": 465, "position": 465, "text": "?”\n\nI considered the matter a moment, and then up stairs we went, and I was\nushered into a small room, cold as a clam, and furnished, sure enough,\nwith a prodigious bed, almost big enough indeed for", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 409, "2000": 1559}}, {"id": 466, "position": 466, "text": "enough,\nwith a prodigious bed, almost big enough indeed for any four\nharpooneers to sleep abreast.\n\n“There,” said the landlord, placing the candle on a crazy old sea chest\nthat did double duty as a wash", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 467, "position": 467, "text": "the candle on a crazy old sea chest\nthat did double duty as a wash-stand and centre table; “there, make\nyourself comfortable now, and good night to ye.” I turned round from\neyeing the bed, but he had disappeared.", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 468, "position": 468, "text": "” I turned round from\neyeing the bed, but he had disappeared.\n\nFolding back the counterpane, I stooped over the bed. Though none of\nthe most elegant, it yet stood the scrutiny tolerably well", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 462, "2000": 742}}, {"id": 469, "position": 469, "text": "it yet stood the scrutiny tolerably well. I then\nglanced round the room; and besides the bedstead and centre table,\ncould see no other furniture belonging to the place, but a rude shelf,\nthe four walls, and a papered fire", "labels": {"50": 25, "100": 5, "250": 45, "500": 412, "1000": 51, "2000": 381}}, {"id": 470, "position": 470, "text": ", but a rude shelf,\nthe four walls, and a papered fireboard representing a man striking a\nwhale. Of things not properly belonging to the room, there was a\nhammock lashed up, and thrown upon the floor in one corner;", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 533, "2000": 786}}, {"id": 471, "position": 471, "text": "hammock lashed up, and thrown upon the floor in one corner; also a\nlarge seaman’s bag, containing the harpooneer’s wardrobe, no doubt in\nlieu of a land trunk. Likewise, there was a parcel of outland", "labels": {"50": 25, "100": 5, "250": 136, "500": 313, "1000": 313, "2000": 786}}, {"id": 472, "position": 472, "text": "lieu of a land trunk. Likewise, there was a parcel of outlandish bone\nfish hooks on the shelf over the fire-place, and a tall harpoon\nstanding at the head of the bed.", "labels": {"50": 11, "100": 12, "250": 91, "500": 363, "1000": 692, "2000": 778}}, {"id": 473, "position": 473, "text": "the head of the bed.\n\nBut what is this on the chest? I took it up, and held it close to the\nlight, and felt it, and smelt it, and tried every way possible to\narrive at some satisfactory conclusion concerning it", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 474, "position": 474, "text": ", and tried every way possible to\narrive at some satisfactory conclusion concerning it. I can compare it\nto nothing but a large door mat, ornamented at the edges with little\ntinkling tags something like the stained porcupine quills round an\nIndian", "labels": {"50": 48, "100": 5, "250": 249, "500": 371, "1000": 777, "2000": 1366}}, {"id": 475, "position": 475, "text": "tinkling tags something like the stained porcupine quills round an\nIndian moccasin. There was a hole or slit in the middle of this mat, as\nyou see the same in South American ponchos", "labels": {"50": 12, "100": 42, "250": 65, "500": 171, "1000": 286, "2000": 482}}, {"id": 476, "position": 476, "text": "the same in South American ponchos. But could it be possible\nthat any sober harpooneer would get into a door mat, and parade the\nstreets of any Christian town in that sort of guise? I put it on, to\ntry it,", "labels": {"50": 25, "100": 7, "250": 91, "500": 247, "1000": 494, "2000": 880}}, {"id": 477, "position": 477, "text": "in that sort of guise? I put it on, to\ntry it, and it weighed me down like a hamper, being uncommonly shaggy\nand thick, and I thought a little damp, as though this mysterious\nharpooneer had been wearing it", "labels": {"50": 25, "100": 5, "250": 136, "500": 313, "1000": 313, "2000": 1521}}, {"id": 478, "position": 478, "text": "a little damp, as though this mysterious\nharpooneer had been wearing it of a rainy day. I went up in it to a bit\nof glass stuck against the wall, and I never saw such a sight in my\nlife", "labels": {"50": 25, "100": 79, "250": 45, "500": 313, "1000": 51, "2000": 1566}}, {"id": 479, "position": 479, "text": "and I never saw such a sight in my\nlife. I tore myself out of it in such a hurry that I gave myself a kink\nin the neck.\n\nI sat down on the side of the bed, and commenced thinking about this\nhead-pe", "labels": {"50": 25, "100": 5, "250": 204, "500": 150, "1000": 483, "2000": 345}}, {"id": 480, "position": 480, "text": "on the side of the bed, and commenced thinking about this\nhead-peddling harpooneer, and his door mat. After thinking some time on\nthe bed-side, I got up and took off my monkey jacket, and then stood in\nthe", "labels": {"50": 25, "100": 41, "250": 156, "500": 313, "1000": 462, "2000": 1702}}, {"id": 481, "position": 481, "text": "I got up and took off my monkey jacket, and then stood in\nthe middle of the room thinking. I then took off my coat, and thought a\nlittle more in my shirt sleeves. But beginning to feel very cold now,\nhalf undressed as", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 1566}}, {"id": 482, "position": 482, "text": "shirt sleeves. But beginning to feel very cold now,\nhalf undressed as I was, and remembering what the landlord said about\nthe harpooneer’s not coming home at all that night, it being so very\nlate, I made no more ad", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 1099}}, {"id": 483, "position": 483, "text": "all that night, it being so very\nlate, I made no more ado, but jumped out of my pantaloons and boots,\nand then blowing out the light tumbled into bed, and commended myself\nto the care of heaven.", "labels": {"50": 8, "100": 14, "250": 81, "500": 174, "1000": 421, "2000": 1068}}, {"id": 484, "position": 484, "text": "into bed, and commended myself\nto the care of heaven.\n\nWhether that mattress was stuffed with corn-cobs or broken crockery,\nthere is no telling, but I rolled about a good deal, and could not\nsleep for a long time", "labels": {"50": 25, "100": 41, "250": 156, "500": 34, "1000": 329, "2000": 652}}, {"id": 485, "position": 485, "text": "rolled about a good deal, and could not\nsleep for a long time. At last I slid off into a light doze, and had\npretty nearly made a good offing towards the land of Nod, when I heard\na heavy footfall in the", "labels": {"50": 25, "100": 5, "250": 136, "500": 233, "1000": 533, "2000": 1521}}, {"id": 486, "position": 486, "text": "towards the land of Nod, when I heard\na heavy footfall in the passage, and saw a glimmer of light come into\nthe room from under the door.\n\nLord save me, thinks I, that must be the harpooneer, the", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 487, "position": 487, "text": "save me, thinks I, that must be the harpooneer, the infernal\nhead-peddler. But I lay perfectly still, and resolved not to say a word\ntill spoken to. Holding a light in one hand, and that", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 786}}, {"id": 488, "position": 488, "text": "a word\ntill spoken to. Holding a light in one hand, and that identical New\nZealand head in the other, the stranger entered the room, and without\nlooking towards the bed, placed his candle a good way off from me on\nthe floor in one", "labels": {"50": 25, "100": 41, "250": 156, "500": 313, "1000": 964, "2000": 1375}}, {"id": 489, "position": 489, "text": ", placed his candle a good way off from me on\nthe floor in one corner, and then began working away at the knotted\ncords of the large bag I before spoke of as being in the room. I was\nall eagerness to see his face,", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 490, "position": 490, "text": "being in the room. I was\nall eagerness to see his face, but he kept it averted for some time\nwhile employed in unlacing the bag’s mouth. This accomplished, however,\nhe turned round—when, good heavens!", "labels": {"50": 25, "100": 41, "250": 156, "500": 313, "1000": 421, "2000": 1559}}, {"id": 491, "position": 491, "text": ". This accomplished, however,\nhe turned round—when, good heavens! what a sight! Such a face! It was\nof a dark, purplish, yellow colour, here and there stuck over with\nlarge blackish looking squares", "labels": {"50": 40, "100": 12, "250": 16, "500": 352, "1000": 695, "2000": 234}}, {"id": 492, "position": 492, "text": ", here and there stuck over with\nlarge blackish looking squares. Yes, it’s just as I thought, he’s a\nterrible bedfellow; he’s been in a fight, got dreadfully cut, and here\nhe is, just", "labels": {"50": 11, "100": 9, "250": 183, "500": 356, "1000": 798, "2000": 1046}}, {"id": 493, "position": 493, "text": "in a fight, got dreadfully cut, and here\nhe is, just from the surgeon. But at that moment he chanced to turn his\nface so towards the light, that I plainly saw they could not be\nsticking-plasters at all,", "labels": {"50": 25, "100": 41, "250": 125, "500": 388, "1000": 103, "2000": 1456}}, {"id": 494, "position": 494, "text": "that I plainly saw they could not be\nsticking-plasters at all, those black squares on his cheeks. They were\nstains of some sort or other. At first I knew not what to make of this;\nbut soon an inkling of the truth", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 462, "2000": 1702}}, {"id": 495, "position": 495, "text": "not what to make of this;\nbut soon an inkling of the truth occurred to me. I remembered a story\nof a white man—a whaleman too—who, falling among the cannibals, had\nbeen tattooed by them", "labels": {"50": 25, "100": 13, "250": 136, "500": 494, "1000": 533, "2000": 187}}, {"id": 496, "position": 496, "text": "falling among the cannibals, had\nbeen tattooed by them. I concluded that this harpooneer, in the course\nof his distant voyages, must have met with a similar adventure. And\nwhat is it, thought I, after all! It", "labels": {"50": 25, "100": 79, "250": 156, "500": 443, "1000": 329, "2000": 1559}}, {"id": 497, "position": 497, "text": "similar adventure. And\nwhat is it, thought I, after all! It’s only his outside; a man can be\nhonest in any sort of skin. But then, what to make of his unearthly\ncomplexion, that part of it,", "labels": {"50": 25, "100": 5, "250": 156, "500": 412, "1000": 329, "2000": 381}}, {"id": 498, "position": 498, "text": "what to make of his unearthly\ncomplexion, that part of it, I mean, lying round about, and completely\nindependent of the squares of tattooing. To be sure, it might be\nnothing but a good coat of tropical tanning; but", "labels": {"50": 39, "100": 41, "250": 57, "500": 407, "1000": 383, "2000": 1927}}, {"id": 499, "position": 499, "text": ", it might be\nnothing but a good coat of tropical tanning; but I never heard of a hot\nsun’s tanning a white man into a purplish yellow one. However, I had\nnever been in the South Seas; and perhaps", "labels": {"50": 25, "100": 41, "250": 156, "500": 388, "1000": 533, "2000": 187}}, {"id": 500, "position": 500, "text": "one. However, I had\nnever been in the South Seas; and perhaps the sun there produced these\nextraordinary effects upon the skin. Now, while all these ideas were\npassing through me like lightning, this harpooneer never noticed me at\nall", "labels": {"50": 25, "100": 5, "250": 45, "500": 411, "1000": 51, "2000": 1521}}, {"id": 501, "position": 501, "text": "me like lightning, this harpooneer never noticed me at\nall. But, after some difficulty having opened his bag, he commenced\nfumbling in it, and presently pulled out a sort of tomahawk, and a\nseal-skin wallet with the", "labels": {"50": 25, "100": 5, "250": 136, "500": 233, "1000": 842, "2000": 1521}}, {"id": 502, "position": 502, "text": "a sort of tomahawk, and a\nseal-skin wallet with the hair on. Placing these on the old chest in\nthe middle of the room, he then took the New Zealand head—a ghastly\nthing enough—and crammed it", "labels": {"50": 45, "100": 64, "250": 163, "500": 389, "1000": 531, "2000": 187}}, {"id": 503, "position": 503, "text": "New Zealand head—a ghastly\nthing enough—and crammed it down into the bag. He now took off his\nhat—a new beaver hat—when I came nigh singing out with fresh surprise", "labels": {"50": 25, "100": 41, "250": 91, "500": 229, "1000": 410, "2000": 1653}}, {"id": 504, "position": 504, "text": "nigh singing out with fresh surprise.\nThere was no hair on his head—none to speak of at least—nothing but a\nsmall scalp-knot twisted up on his forehead. His bald purplish head now\nlooked for all the world like a", "labels": {"50": 22, "100": 41, "250": 91, "500": 389, "1000": 0, "2000": 0}}, {"id": 505, "position": 505, "text": ". His bald purplish head now\nlooked for all the world like a mildewed skull. Had not the stranger\nstood between me and the door, I would have bolted out of it quicker\nthan ever I bolted a dinner.", "labels": {"50": 25, "100": 41, "250": 156, "500": 134, "1000": 130, "2000": 41}}, {"id": 506, "position": 506, "text": "out of it quicker\nthan ever I bolted a dinner.\n\nEven as it was, I thought something of slipping out of the window, but\nit was the second floor back. I am no coward, but what to make of this\nhead-peddling purple", "labels": {"50": 25, "100": 41, "250": 91, "500": 407, "1000": 568, "2000": 1359}}, {"id": 507, "position": 507, "text": "am no coward, but what to make of this\nhead-peddling purple rascal altogether passed my comprehension.\nIgnorance is the parent of fear, and being completely nonplussed and\nconfounded about the stranger, I confess I was now as much", "labels": {"50": 20, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 508, "position": 508, "text": "ed and\nconfounded about the stranger, I confess I was now as much afraid of\nhim as if it was the devil himself who had thus broken into my room at\nthe dead of night. In fact, I was so afraid of him that I was", "labels": {"50": 20, "100": 56, "250": 156, "500": 134, "1000": 421, "2000": 1068}}, {"id": 509, "position": 509, "text": "of night. In fact, I was so afraid of him that I was not game\nenough just then to address him, and demand a satisfactory answer\nconcerning what seemed inexplicable in him.\n\nMeanwhile, he continued the business of undressing", "labels": {"50": 20, "100": 56, "250": 45, "500": 313, "1000": 818, "2000": 729}}, {"id": 510, "position": 510, "text": "icable in him.\n\nMeanwhile, he continued the business of undressing, and at last showed\nhis chest and arms. As I live, these covered parts of him were\ncheckered with the same squares as his face; his back, too,", "labels": {"50": 25, "100": 5, "250": 125, "500": 349, "1000": 345, "2000": 1123}}, {"id": 511, "position": 511, "text": "checkered with the same squares as his face; his back, too, was all\nover the same dark squares; he seemed to have been in a Thirty Years’\nWar, and just escaped from it with a sticking-plaster shirt", "labels": {"50": 0, "100": 51, "250": 247, "500": 391, "1000": 288, "2000": 1506}}, {"id": 512, "position": 512, "text": "and just escaped from it with a sticking-plaster shirt. Still\nmore, his very legs were marked, as if a parcel of dark green frogs\nwere running up the trunks of young palms. It was now quite plain that\nhe must be some abomi", "labels": {"50": 22, "100": 12, "250": 16, "500": 389, "1000": 197, "2000": 234}}, {"id": 513, "position": 513, "text": "young palms. It was now quite plain that\nhe must be some abominable savage or other shipped aboard of a whaleman\nin the South Seas, and so landed in this Christian country. I quaked to\nthink of it", "labels": {"50": 25, "100": 41, "250": 125, "500": 388, "1000": 533, "2000": 187}}, {"id": 514, "position": 514, "text": "Christian country. I quaked to\nthink of it. A peddler of heads too—perhaps the heads of his own\nbrothers. He might take a fancy to mine—heavens! look at that tomahawk!", "labels": {"50": 25, "100": 41, "250": 156, "500": 174, "1000": 753, "2000": 610}}, {"id": 515, "position": 515, "text": "heavens! look at that tomahawk!\n\nBut there was no time for shuddering, for now the savage went about\nsomething that completely fascinated my attention, and convinced me\nthat he must indeed be a heathen", "labels": {"50": 25, "100": 5, "250": 136, "500": 313, "1000": 51, "2000": 937}}, {"id": 516, "position": 516, "text": "must indeed be a heathen. Going to his heavy grego, or wrapall,\nor dreadnaught, which he had previously hung on a chair, he fumbled in\nthe pockets, and produced at length a curious little deformed image\nwith", "labels": {"50": 23, "100": 88, "250": 219, "500": 180, "1000": 317, "2000": 1087}}, {"id": 517, "position": 517, "text": "the pockets, and produced at length a curious little deformed image\nwith a hunch on its back, and exactly the colour of a three days’ old\nCongo baby. Remembering the embalmed head, at first I almost thought\nthat this black", "labels": {"50": 25, "100": 13, "250": 56, "500": 353, "1000": 113, "2000": 139}}, {"id": 518, "position": 518, "text": "Remembering the embalmed head, at first I almost thought\nthat this black manikin was a real baby preserved in some similar\nmanner. But seeing that it was not at all limber, and that it glistened\na good deal like polished ebony", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1243}}, {"id": 519, "position": 519, "text": "limber, and that it glistened\na good deal like polished ebony, I concluded that it must be nothing\nbut a wooden idol, which indeed it proved to be. For now the savage\ngoes up to the empty fire-place, and removing", "labels": {"50": 25, "100": 13, "250": 91, "500": 154, "1000": 873, "2000": 893}}, {"id": 520, "position": 520, "text": "For now the savage\ngoes up to the empty fire-place, and removing the papered fire-board,\nsets up this little hunch-backed image, like a tenpin, between the\nandirons", "labels": {"50": 41, "100": 21, "250": 91, "500": 75, "1000": 230, "2000": 68}}, {"id": 521, "position": 521, "text": "pin, between the\nandirons. The chimney jambs and all the bricks inside were very sooty,\nso that I thought this fire-place made a very appropriate little shrine\nor chapel for his Congo idol.", "labels": {"50": 32, "100": 13, "250": 158, "500": 167, "1000": 922, "2000": 1946}}, {"id": 522, "position": 522, "text": "shrine\nor chapel for his Congo idol.\n\nI now screwed my eyes hard towards the half hidden image, feeling but\nill at ease meantime—to see what was next to follow. First he takes\nabout a double handful of shavings out of his greg", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 1099}}, {"id": 523, "position": 523, "text": "First he takes\nabout a double handful of shavings out of his grego pocket, and places\nthem carefully before the idol; then laying a bit of ship biscuit on\ntop and applying the flame from the lamp, he kindled the shaving", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 524, "position": 524, "text": "top and applying the flame from the lamp, he kindled the shavings into\na sacrificial blaze. Presently, after many hasty snatches into the\nfire, and still hastier withdrawals of his fingers (whereby he seemed\nto be", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 317, "2000": 1554}}, {"id": 525, "position": 525, "text": "and still hastier withdrawals of his fingers (whereby he seemed\nto be scorching them badly), he at last succeeded in drawing out the\nbiscuit; then blowing off the heat and ashes a little, he made a polite\noffer of it", "labels": {"50": 23, "100": 88, "250": 8, "500": 170, "1000": 943, "2000": 1881}}, {"id": 526, "position": 526, "text": "off the heat and ashes a little, he made a polite\noffer of it to the little negro. But the little devil did not seem to\nfancy such dry sort of fare at all; he never moved his lips", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 103, "2000": 1123}}, {"id": 527, "position": 527, "text": "all; he never moved his lips. All these\nstrange antics were accompanied by still stranger guttural noises from\nthe devotee, who seemed to be praying in a sing-song or else singing\nsome pagan psalmody or other, during which his", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 528, "position": 528, "text": "song or else singing\nsome pagan psalmody or other, during which his face twitched about in\nthe most unnatural manner. At last extinguishing the fire, he took the\nidol up very unceremoniously, and bagged it again in", "labels": {"50": 25, "100": 13, "250": 56, "500": 1, "1000": 682, "2000": 1689}}, {"id": 529, "position": 529, "text": "the\nidol up very unceremoniously, and bagged it again in his grego pocket\nas carelessly as if he were a sportsman bagging a dead woodcock.\n\nAll these queer proceedings increased my uncomfortableness, and seeing\nhim now exhibiting strong", "labels": {"50": 25, "100": 5, "250": 156, "500": 313, "1000": 329, "2000": 937}}, {"id": 530, "position": 530, "text": "All these queer proceedings increased my uncomfortableness, and seeing\nhim now exhibiting strong symptoms of concluding his business\noperations, and jumping into bed with me, I thought it was high time,\nnow or never, before the light was put out, to break the", "labels": {"50": 25, "100": 5, "250": 156, "500": 313, "1000": 462, "2000": 453}}, {"id": 531, "position": 531, "text": ",\nnow or never, before the light was put out, to break the spell in which\nI had so long been bound.\n\nBut the interval I spent in deliberating what to say, was a fatal one", "labels": {"50": 20, "100": 79, "250": 186, "500": 134, "1000": 103, "2000": 610}}, {"id": 532, "position": 532, "text": "to say, was a fatal one.\nTaking up his tomahawk from the table, he examined the head of it for\nan instant, and then holding it to the light, with his mouth at the\nhandle, he puffed out great clouds of", "labels": {"50": 12, "100": 38, "250": 65, "500": 227, "1000": 286, "2000": 668}}, {"id": 533, "position": 533, "text": ", with his mouth at the\nhandle, he puffed out great clouds of tobacco smoke. The next moment\nthe light was extinguished, and this wild cannibal, tomahawk between\nhis teeth, sprang into bed with me", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 251}}, {"id": 534, "position": 534, "text": "wk between\nhis teeth, sprang into bed with me. I sang out, I could not help it\nnow; and giving a sudden grunt of astonishment he began feeling me.\n\nStammering out something, I knew not what, I rolled away from him", "labels": {"50": 25, "100": 5, "250": 136, "500": 313, "1000": 483, "2000": 345}}, {"id": 535, "position": 535, "text": "ammering out something, I knew not what, I rolled away from him\nagainst the wall, and then conjured him, whoever or whatever he might\nbe, to keep quiet, and let me get up and light the lamp again", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 964, "2000": 1566}}, {"id": 536, "position": 536, "text": ", and let me get up and light the lamp again. But his\nguttural responses satisfied me at once that he but ill comprehended my\nmeaning.\n\n“Who-e debel you?”—he at last said—“you no speak", "labels": {"50": 25, "100": 41, "250": 156, "500": 313, "1000": 103, "2000": 610}}, {"id": 537, "position": 537, "text": "debel you?”—he at last said—“you no speak-e, dam-me, I kill-e.”\nAnd so saying the lighted tomahawk began flourishing about me in the\ndark.", "labels": {"50": 12, "100": 55, "250": 65, "500": 227, "1000": 580, "2000": 668}}, {"id": 538, "position": 538, "text": "wk began flourishing about me in the\ndark.\n\n“Landlord, for God’s sake, Peter Coffin!” shouted I. “Landlord! Watch!\nCoffin! Angels! save me!”\n\n“Speak-e! tell-ee me who-ee", "labels": {"50": 41, "100": 21, "250": 215, "500": 180, "1000": 272, "2000": 1954}}, {"id": 539, "position": 539, "text": "me!”\n\n“Speak-e! tell-ee me who-ee be, or dam-me, I kill-e!” again growled the\ncannibal, while his horrid flourishings of the tomahawk scattered the\nhot", "labels": {"50": 41, "100": 55, "250": 145, "500": 180, "1000": 272, "2000": 668}}, {"id": 540, "position": 540, "text": "while his horrid flourishings of the tomahawk scattered the\nhot tobacco ashes about me till I thought my linen would get on fire.\nBut thank heaven, at that moment the landlord came into the room light\nin hand, and leaping from the", "labels": {"50": 25, "100": 5, "250": 156, "500": 134, "1000": 421, "2000": 1068}}, {"id": 541, "position": 541, "text": "moment the landlord came into the room light\nin hand, and leaping from the bed I ran up to him.\n\n“Don’t be afraid now,” said he, grinning again, “Queequeg here wouldn’t\nharm a hair of", "labels": {"50": 25, "100": 41, "250": 91, "500": 407, "1000": 483, "2000": 1707}}, {"id": 542, "position": 542, "text": "again, “Queequeg here wouldn’t\nharm a hair of your head.”\n\n“Stop your grinning,” shouted I, “and why didn’t you tell me that that\ninfernal harpooneer was a cannibal", "labels": {"50": 12, "100": 93, "250": 65, "500": 227, "1000": 286, "2000": 668}}, {"id": 543, "position": 543, "text": "tell me that that\ninfernal harpooneer was a cannibal?”\n\n“I thought ye know’d it;—didn’t I tell ye, he was a peddlin’ heads\naround town?—but turn flukes", "labels": {"50": 41, "100": 21, "250": 215, "500": 281, "1000": 54, "2000": 1790}}, {"id": 544, "position": 544, "text": "was a peddlin’ heads\naround town?—but turn flukes again and go to sleep. Queequeg, look\nhere—you sabbee me, I sabbee—you this man sleepe you—you sabbe", "labels": {"50": 41, "100": 2, "250": 166, "500": 69, "1000": 844, "2000": 1247}}, {"id": 545, "position": 545, "text": "I sabbee—you this man sleepe you—you sabbee?”\n\n“Me sabbee plenty”—grunted Queequeg, puffing away at his pipe and\nsitting up in bed.", "labels": {"50": 41, "100": 21, "250": 163, "500": 180, "1000": 54, "2000": 1790}}, {"id": 546, "position": 546, "text": "at his pipe and\nsitting up in bed.\n\n“You gettee in,” he added, motioning to me with his tomahawk, and\nthrowing the clothes to one side. He really did this in not only a\ncivil but a really kind", "labels": {"50": 25, "100": 41, "250": 91, "500": 407, "1000": 494, "2000": 1528}}, {"id": 547, "position": 547, "text": "side. He really did this in not only a\ncivil but a really kind and charitable way. I stood looking at him a\nmoment. For all his tattooings he was on the whole a clean, comely\nlooking cannibal", "labels": {"50": 25, "100": 41, "250": 91, "500": 150, "1000": 533, "2000": 526}}, {"id": 548, "position": 548, "text": "the whole a clean, comely\nlooking cannibal. What’s all this fuss I have been making about,\nthought I to myself—the man’s a human being just as I am: he has just\nas much reason to fear me", "labels": {"50": 46, "100": 41, "250": 183, "500": 356, "1000": 798, "2000": 51}}, {"id": 549, "position": 549, "text": "being just as I am: he has just\nas much reason to fear me, as I have to be afraid of him. Better sleep\nwith a sober cannibal than a drunken Christian.\n\n“Landlord,” said I, “tell him to st", "labels": {"50": 35, "100": 94, "250": 192, "500": 304, "1000": 167, "2000": 464}}, {"id": 550, "position": 550, "text": "drunken Christian.\n\n“Landlord,” said I, “tell him to stash his tomahawk there, or pipe, or\nwhatever you call it; tell him to stop smoking, in short, and I will\nturn in with him", "labels": {"50": 25, "100": 5, "250": 156, "500": 349, "1000": 483, "2000": 652}}, {"id": 551, "position": 551, "text": "smoking, in short, and I will\nturn in with him. But I don’t fancy having a man smoking in bed with\nme. It’s dangerous. Besides, I ain’t insured.”", "labels": {"50": 39, "100": 99, "250": 63, "500": 402, "1000": 488, "2000": 51}}, {"id": 552, "position": 552, "text": "I ain’t insured.”\n\nThis being told to Queequeg, he at once complied, and again politely\nmotioned me to get into bed—rolling over to one side as much as to\nsay—“I won’t touch a", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 251}}, {"id": 553, "position": 553, "text": "one side as much as to\nsay—“I won’t touch a leg of ye.”\n\n“Good night, landlord,” said I, “you may go.”\n\nI turned in, and never slept better in my life.\n\n\nCHAPTER 4", "labels": {"50": 25, "100": 28, "250": 156, "500": 412, "1000": 483, "2000": 381}}, {"id": 554, "position": 554, "text": "”\n\nI turned in, and never slept better in my life.\n\n\nCHAPTER 4. The Counterpane.\n\nUpon waking next morning about daylight, I found Queequeg’s arm thrown\nover me in the most loving and affectionate manner", "labels": {"50": 25, "100": 5, "250": 156, "500": 313, "1000": 329, "2000": 251}}, {"id": 555, "position": 555, "text": "s arm thrown\nover me in the most loving and affectionate manner. You had almost\nthought I had been his wife. The counterpane was of patchwork, full of\nodd little parti-coloured squares and triangles; and this arm of his", "labels": {"50": 25, "100": 79, "250": 204, "500": 412, "1000": 329, "2000": 1420}}, {"id": 556, "position": 556, "text": "odd little parti-coloured squares and triangles; and this arm of his\ntattooed all over with an interminable Cretan labyrinth of a figure, no\ntwo parts of which were of one precise shade—owing I suppose to his\nkeeping his arm", "labels": {"50": 25, "100": 93, "250": 55, "500": 1, "1000": 381, "2000": 1243}}, {"id": 557, "position": 557, "text": "which were of one precise shade—owing I suppose to his\nkeeping his arm at sea unmethodically in sun and shade, his shirt\nsleeves irregularly rolled up at various times—this same arm of his, I\nsay, looked for all", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 1559}}, {"id": 558, "position": 558, "text": "various times—this same arm of his, I\nsay, looked for all the world like a strip of that same patchwork\nquilt. Indeed, partly lying on it as the arm did when I first awoke, I\ncould hardly tell it from the quilt", "labels": {"50": 25, "100": 5, "250": 136, "500": 412, "1000": 483, "2000": 1149}}, {"id": 559, "position": 559, "text": "arm did when I first awoke, I\ncould hardly tell it from the quilt, they so blended their hues\ntogether; and it was only by the sense of weight and pressure that I\ncould tell that Queequeg was hugging me.", "labels": {"50": 25, "100": 41, "250": 91, "500": 388, "1000": 533, "2000": 1620}}, {"id": 560, "position": 560, "text": "that I\ncould tell that Queequeg was hugging me.\n\nMy sensations were strange. Let me try to explain them. When I was a\nchild, I well remember a somewhat similar circumstance that befell me;\nwhether it was a reality or a", "labels": {"50": 25, "100": 5, "250": 204, "500": 349, "1000": 718, "2000": 345}}, {"id": 561, "position": 561, "text": "somewhat similar circumstance that befell me;\nwhether it was a reality or a dream, I never could entirely settle. The\ncircumstance was this. I had been cutting up some caper or other—I\nthink it was trying to crawl up the chimney,", "labels": {"50": 25, "100": 41, "250": 156, "500": 313, "1000": 462, "2000": 1702}}, {"id": 562, "position": 562, "text": "r or other—I\nthink it was trying to crawl up the chimney, as I had seen a little\nsweep do a few days previous; and my stepmother who, somehow or other,\nwas all the time whipping me, or sending me to bed supper", "labels": {"50": 25, "100": 5, "250": 204, "500": 315, "1000": 51, "2000": 1566}}, {"id": 563, "position": 563, "text": "other,\nwas all the time whipping me, or sending me to bed supperless,—my\nmother dragged me by the legs out of the chimney and packed me off to\nbed, though it was only two o’clock in the afternoon of the 21st", "labels": {"50": 20, "100": 79, "250": 101, "500": 315, "1000": 794, "2000": 1840}}, {"id": 564, "position": 564, "text": ", though it was only two o’clock in the afternoon of the 21st June,\nthe longest day in the year in our hemisphere. I felt dreadfully. But\nthere was no help for it, so up stairs I went to my little room in", "labels": {"50": 25, "100": 5, "250": 204, "500": 412, "1000": 483, "2000": 1150}}, {"id": 565, "position": 565, "text": "no help for it, so up stairs I went to my little room in the\nthird floor, undressed myself as slowly as possible so as to kill time,\nand with a bitter sigh got between the sheets.", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 566, "position": 566, "text": "bitter sigh got between the sheets.\n\nI lay there dismally calculating that sixteen entire hours must elapse\nbefore I could hope for a resurrection. Sixteen hours in bed! the small\nof my back ached to think of it", "labels": {"50": 25, "100": 41, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 567, "position": 567, "text": "the small\nof my back ached to think of it. And it was so light too; the sun\nshining in at the window, and a great rattling of coaches in the\nstreets, and the sound of gay voices all over the house", "labels": {"50": 25, "100": 41, "250": 204, "500": 150, "1000": 483, "2000": 1707}}, {"id": 568, "position": 568, "text": ", and the sound of gay voices all over the house. I felt worse\nand worse—at last I got up, dressed, and softly going down in my\nstockinged feet, sought out my stepmother, and suddenly threw myself at\nher feet,", "labels": {"50": 25, "100": 79, "250": 45, "500": 313, "1000": 51, "2000": 1566}}, {"id": 569, "position": 569, "text": "feet, sought out my stepmother, and suddenly threw myself at\nher feet, beseeching her as a particular favour to give me a good\nslippering for my misbehaviour; anything indeed but condemning me to\nlie abed such an", "labels": {"50": 20, "100": 5, "250": 45, "500": 57, "1000": 711, "2000": 1167}}, {"id": 570, "position": 570, "text": "haviour; anything indeed but condemning me to\nlie abed such an unendurable length of time. But she was the best and\nmost conscientious of stepmothers, and back I had to go to my room", "labels": {"50": 20, "100": 79, "250": 176, "500": 315, "1000": 638, "2000": 1840}}, {"id": 571, "position": 571, "text": "s, and back I had to go to my room. For\nseveral hours I lay there broad awake, feeling a great deal worse than\nI have ever done since, even from the greatest subsequent misfortunes", "labels": {"50": 20, "100": 28, "250": 169, "500": 59, "1000": 773, "2000": 1278}}, {"id": 572, "position": 572, "text": "the greatest subsequent misfortunes.\nAt last I must have fallen into a troubled nightmare of a doze; and\nslowly waking from it—half steeped in dreams—I opened my eyes, and the\nbefore sun-lit room was now wrapped in", "labels": {"50": 20, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 573, "position": 573, "text": "opened my eyes, and the\nbefore sun-lit room was now wrapped in outer darkness. Instantly I felt\na shock running through all my frame; nothing was to be seen, and\nnothing was to be heard; but a supernatural hand seemed placed in mine", "labels": {"50": 20, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 574, "position": 574, "text": "and\nnothing was to be heard; but a supernatural hand seemed placed in mine.\nMy arm hung over the counterpane, and the nameless, unimaginable,\nsilent form or phantom, to which the hand belonged, seemed closely\nseated by", "labels": {"50": 20, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 575, "position": 575, "text": "silent form or phantom, to which the hand belonged, seemed closely\nseated by my bed-side. For what seemed ages piled on ages, I lay there,\nfrozen with the most awful fears, not daring to drag away my hand; yet\never thinking", "labels": {"50": 20, "100": 5, "250": 45, "500": 411, "1000": 51, "2000": 742}}, {"id": 576, "position": 576, "text": "most awful fears, not daring to drag away my hand; yet\never thinking that if I could but stir it one single inch, the horrid\nspell would be broken. I knew not how this consciousness at last glided\naway from me; but waking", "labels": {"50": 20, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 577, "position": 577, "text": "I knew not how this consciousness at last glided\naway from me; but waking in the morning, I shudderingly remembered it\nall, and for days and weeks and months afterwards I lost myself in\nconfounding attempts to explain the mystery", "labels": {"50": 25, "100": 5, "250": 45, "500": 411, "1000": 51, "2000": 1254}}, {"id": 578, "position": 578, "text": "lost myself in\nconfounding attempts to explain the mystery. Nay, to this very hour, I\noften puzzle myself with it.\n\nNow, take away the awful fear, and my sensations at feeling the\nsupernatural hand in mine were very similar, in", "labels": {"50": 20, "100": 5, "250": 45, "500": 313, "1000": 462, "2000": 742}}, {"id": 579, "position": 579, "text": "and my sensations at feeling the\nsupernatural hand in mine were very similar, in their strangeness, to\nthose which I experienced on waking up and seeing Queequeg’s pagan arm\nthrown round me. But at length all the past night’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1620}}, {"id": 580, "position": 580, "text": "pagan arm\nthrown round me. But at length all the past night’s events soberly\nrecurred, one by one, in fixed reality, and then I lay only alive to\nthe comical predicament", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 453}}, {"id": 581, "position": 581, "text": "alive to\nthe comical predicament. For though I tried to move his arm—unlock his\nbridegroom clasp—yet, sleeping as he was, he still hugged me tightly,\nas though naught but death should part us twain", "labels": {"50": 36, "100": 35, "250": 26, "500": 57, "1000": 893, "2000": 986}}, {"id": 582, "position": 582, "text": "tightly,\nas though naught but death should part us twain. I now strove to rouse\nhim—“Queequeg!”—but his only answer was a snore. I then rolled over, my\nneck feeling as if it", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1620}}, {"id": 583, "position": 583, "text": "snore. I then rolled over, my\nneck feeling as if it were in a horse-collar; and suddenly felt a\nslight scratch. Throwing aside the counterpane, there lay the tomahawk\nsleeping by the savage’s side,", "labels": {"50": 25, "100": 5, "250": 136, "500": 233, "1000": 718, "2000": 937}}, {"id": 584, "position": 584, "text": ", there lay the tomahawk\nsleeping by the savage’s side, as if it were a hatchet-faced baby. A\npretty pickle, truly, thought I; abed here in a strange house in the\nbroad day, with a", "labels": {"50": 25, "100": 5, "250": 136, "500": 412, "1000": 272, "2000": 1551}}, {"id": 585, "position": 585, "text": "; abed here in a strange house in the\nbroad day, with a cannibal and a tomahawk! “Queequeg!—in the name of\ngoodness, Queequeg, wake!” At length, by din", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 586, "position": 586, "text": "goodness, Queequeg, wake!” At length, by dint of much wriggling, and\nloud and incessant expostulations upon the unbecomingness of his\nhugging a fellow male in that matrimonial", "labels": {"50": 23, "100": 88, "250": 219, "500": 180, "1000": 317, "2000": 1087}}, {"id": 587, "position": 587, "text": "becomingness of his\nhugging a fellow male in that matrimonial sort of style, I succeeded in\nextracting a grunt; and presently, he drew back his arm, shook himself\nall over like a Newfoundland dog just from the water, and", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 421, "2000": 1068}}, {"id": 588, "position": 588, "text": ", shook himself\nall over like a Newfoundland dog just from the water, and sat up in\nbed, stiff as a pike-staff, looking at me, and rubbing his eyes as if\nhe did not altogether remember how I came to be there, though", "labels": {"50": 41, "100": 41, "250": 91, "500": 221, "1000": 494, "2000": 1707}}, {"id": 589, "position": 589, "text": "as if\nhe did not altogether remember how I came to be there, though a dim\nconsciousness of knowing something about me seemed slowly dawning over\nhim. Meanwhile, I lay quietly eyeing him, having no serious misgivings\nnow, and bent upon narrowly", "labels": {"50": 25, "100": 5, "250": 156, "500": 128, "1000": 964, "2000": 1099}}, {"id": 590, "position": 590, "text": "eyeing him, having no serious misgivings\nnow, and bent upon narrowly observing so curious a creature. When, at\nlast, his mind seemed made up touching the character of his bedfellow,\nand he became, as it were, reconciled to", "labels": {"50": 22, "100": 78, "250": 229, "500": 286, "1000": 995, "2000": 1027}}, {"id": 591, "position": 591, "text": "his bedfellow,\nand he became, as it were, reconciled to the fact; he jumped out upon\nthe floor, and by certain signs and sounds gave me to understand that,\nif it pleased me, he would dress first and then leave me", "labels": {"50": 25, "100": 28, "250": 52, "500": 465, "1000": 204, "2000": 1387}}, {"id": 592, "position": 592, "text": "that,\nif it pleased me, he would dress first and then leave me to dress\nafterwards, leaving the whole apartment to myself. Thinks I, Queequeg,\nunder the circumstances, this is a very civilized overture; but, the\ntruth is", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 387, "2000": 1081}}, {"id": 593, "position": 593, "text": "the circumstances, this is a very civilized overture; but, the\ntruth is, these savages have an innate sense of delicacy, say what you\nwill; it is marvellous how essentially polite they are", "labels": {"50": 48, "100": 20, "250": 90, "500": 1, "1000": 806, "2000": 272}}, {"id": 594, "position": 594, "text": "marvellous how essentially polite they are. I pay this\nparticular compliment to Queequeg, because he treated me with so much\ncivility and consideration, while I was guilty of great rudeness;\nstaring at him from the bed, and watching all", "labels": {"50": 25, "100": 28, "250": 156, "500": 407, "1000": 421, "2000": 1068}}, {"id": 595, "position": 595, "text": "of great rudeness;\nstaring at him from the bed, and watching all his toilette motions; for\nthe time my curiosity getting the better of my breeding. Nevertheless,\na man like Queequeg you don’t see every day, he", "labels": {"50": 20, "100": 5, "250": 125, "500": 349, "1000": 421, "2000": 1068}}, {"id": 596, "position": 596, "text": "man like Queequeg you don’t see every day, he and his ways were well\nworth unusual regarding.\n\nHe commenced dressing at top by donning his beaver hat, a very tall\none, by the by, and then—still minus", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 383, "2000": 955}}, {"id": 597, "position": 597, "text": ", a very tall\none, by the by, and then—still minus his trowsers—he hunted up his\nboots. What under the heavens he did it for, I cannot tell, but his\nnext movement was to crush himself—boots in", "labels": {"50": 40, "100": 12, "250": 36, "500": 437, "1000": 817, "2000": 1236}}, {"id": 598, "position": 598, "text": "I cannot tell, but his\nnext movement was to crush himself—boots in hand, and hat on—under the\nbed; when, from sundry violent gaspings and strainings, I inferred he\nwas hard at work booting himself;", "labels": {"50": 25, "100": 41, "250": 156, "500": 313, "1000": 462, "2000": 742}}, {"id": 599, "position": 599, "text": "s, I inferred he\nwas hard at work booting himself; though by no law of propriety that I\never heard of, is any man required to be private when putting on his\nboots. But Queequeg, do you see", "labels": {"50": 41, "100": 21, "250": 219, "500": 221, "1000": 230, "2000": 1082}}, {"id": 600, "position": 600, "text": "when putting on his\nboots. But Queequeg, do you see, was a creature in the transition\nstage—neither caterpillar nor butterfly. He was just enough civilized\nto show off his outlandishness in the strangest possible manners", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 601, "position": 601, "text": "civilized\nto show off his outlandishness in the strangest possible manners. His\neducation was not yet completed. He was an undergraduate. If he had not\nbeen a small degree civilized, he very probably would not have troubled\nhimself with boots at all", "labels": {"50": 7, "100": 91, "250": 70, "500": 163, "1000": 177, "2000": 1685}}, {"id": 602, "position": 602, "text": "degree civilized, he very probably would not have troubled\nhimself with boots at all; but then, if he had not been still a savage,\nhe never would have dreamt of getting under the bed to put them on", "labels": {"50": 11, "100": 12, "250": 16, "500": 66, "1000": 688, "2000": 574}}, {"id": 603, "position": 603, "text": "getting under the bed to put them on. At\nlast, he emerged with his hat very much dented and crushed down over\nhis eyes, and began creaking and limping about the room, as if, not\nbeing much accustomed to boots,", "labels": {"50": 11, "100": 51, "250": 57, "500": 100, "1000": 800, "2000": 66}}, {"id": 604, "position": 604, "text": "ing about the room, as if, not\nbeing much accustomed to boots, his pair of damp, wrinkled cowhide\nones—probably not made to order either—rather pinched and tormented him\nat the first go off of a bitter cold morning.", "labels": {"50": 23, "100": 88, "250": 89, "500": 211, "1000": 962, "2000": 1102}}, {"id": 605, "position": 605, "text": "tormented him\nat the first go off of a bitter cold morning.\n\nSeeing, now, that there were no curtains to the window, and that the\nstreet being very narrow, the house opposite commanded a plain view\ninto the room, and observing more and more", "labels": {"50": 22, "100": 78, "250": 229, "500": 163, "1000": 383, "2000": 321}}, {"id": 606, "position": 606, "text": "house opposite commanded a plain view\ninto the room, and observing more and more the indecorous figure that\nQueequeg made, staving about with little else but his hat and boots on;\nI begged him as well as I could,", "labels": {"50": 25, "100": 5, "250": 156, "500": 180, "1000": 421, "2000": 1559}}, {"id": 607, "position": 607, "text": "his hat and boots on;\nI begged him as well as I could, to accelerate his toilet somewhat, and\nparticularly to get into his pantaloons as soon as possible. He\ncomplied, and then proceeded to wash himself", "labels": {"50": 25, "100": 41, "250": 156, "500": 318, "1000": 529, "2000": 251}}, {"id": 608, "position": 608, "text": "He\ncomplied, and then proceeded to wash himself. At that time in the\nmorning any Christian would have washed his face; but Queequeg, to my\namazement, contented himself with restricting his ablutions to his\nchest, arms, and", "labels": {"50": 12, "100": 42, "250": 125, "500": 349, "1000": 222, "2000": 1689}}, {"id": 609, "position": 609, "text": "ed himself with restricting his ablutions to his\nchest, arms, and hands. He then donned his waistcoat, and taking up a\npiece of hard soap on the wash-stand centre table, dipped it into water\nand commenced lathering", "labels": {"50": 24, "100": 51, "250": 109, "500": 178, "1000": 734, "2000": 969}}, {"id": 610, "position": 610, "text": "wash-stand centre table, dipped it into water\nand commenced lathering his face. I was watching to see where he kept\nhis razor, when lo and behold, he takes the harpoon from the bed\ncorner, slips out the long wooden stock", "labels": {"50": 25, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 611, "position": 611, "text": "takes the harpoon from the bed\ncorner, slips out the long wooden stock, unsheathes the head, whets it\na little on his boot, and striding up to the bit of mirror against the\nwall, begins a vigorous scraping", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 612, "position": 612, "text": "riding up to the bit of mirror against the\nwall, begins a vigorous scraping, or rather harpooning of his cheeks.\nThinks I, Queequeg, this is using Rogers’s best cutlery with a\nvengeance", "labels": {"50": 8, "100": 7, "250": 193, "500": 202, "1000": 849, "2000": 890}}, {"id": 613, "position": 613, "text": "using Rogers’s best cutlery with a\nvengeance. Afterwards I wondered the less at this operation when I came\nto know of what fine steel the head of a harpoon is made, and how\nexceedingly sharp the long straight edges are always kept.", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 393, "2000": 677}}, {"id": 614, "position": 614, "text": "made, and how\nexceedingly sharp the long straight edges are always kept.\n\nThe rest of his toilet was soon achieved, and he proudly marched out of\nthe room, wrapped up in his great pilot monkey jacket, and sporting his\nharpoon like a marshal", "labels": {"50": 45, "100": 64, "250": 163, "500": 178, "1000": 531, "2000": 110}}, {"id": 615, "position": 615, "text": "in his great pilot monkey jacket, and sporting his\nharpoon like a marshal’s baton.\n\n\nCHAPTER 5. Breakfast.\n\nI quickly followed suit, and descending into the bar-room accosted the\ngrinning landlord very pleasantly", "labels": {"50": 23, "100": 41, "250": 219, "500": 202, "1000": 851, "2000": 1068}}, {"id": 616, "position": 616, "text": "room accosted the\ngrinning landlord very pleasantly. I cherished no malice towards him,\nthough he had been skylarking with me not a little in the matter of my\nbedfellow.\n\nHowever, a good laugh is a mighty good thing, and", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 529, "2000": 652}}, {"id": 617, "position": 617, "text": "fellow.\n\nHowever, a good laugh is a mighty good thing, and rather too scarce a\ngood thing; the more’s the pity. So, if any one man, in his own proper\nperson, afford stuff for a good joke to anybody", "labels": {"50": 31, "100": 7, "250": 193, "500": 453, "1000": 203, "2000": 1828}}, {"id": 618, "position": 618, "text": ", in his own proper\nperson, afford stuff for a good joke to anybody, let him not be\nbackward, but let him cheerfully allow himself to spend and be spent in\nthat way. And the man that has anything bountifully laughable about", "labels": {"50": 31, "100": 7, "250": 69, "500": 453, "1000": 581, "2000": 1828}}, {"id": 619, "position": 619, "text": "way. And the man that has anything bountifully laughable about\nhim, be sure there is more in that man than you perhaps think for.\n\nThe bar-room was now full of the boarders who had been dropping in the\nnight previous", "labels": {"50": 39, "100": 39, "250": 19, "500": 438, "1000": 323, "2000": 119}}, {"id": 620, "position": 620, "text": "was now full of the boarders who had been dropping in the\nnight previous, and whom I had not as yet had a good look at. They were\nnearly all whalemen; chief mates, and second mates, and third mates,\nand sea carpenter", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 621, "position": 621, "text": "; chief mates, and second mates, and third mates,\nand sea carpenters, and sea coopers, and sea blacksmiths, and\nharpooneers, and ship keepers; a brown and brawny company, with bosky\nbeards; an", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 622, "position": 622, "text": "; a brown and brawny company, with bosky\nbeards; an unshorn, shaggy set, all wearing monkey jackets for morning\ngowns.\n\nYou could pretty plainly tell how long each one had been ashore", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 531, "2000": 187}}, {"id": 623, "position": 623, "text": "tell how long each one had been ashore. This\nyoung fellow’s healthy cheek is like a sun-toasted pear in hue, and\nwould seem to smell almost as musky; he cannot have been three days\nlanded from his Indian voyage", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 52}}, {"id": 624, "position": 624, "text": "sky; he cannot have been three days\nlanded from his Indian voyage. That man next him looks a few shades\nlighter; you might say a touch of satin wood is in him. In the\ncomplexion of a third still lingers a tropic ta", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 327, "2000": 887}}, {"id": 625, "position": 625, "text": ". In the\ncomplexion of a third still lingers a tropic tawn, but slightly\nbleached withal; _he_ doubtless has tarried whole weeks ashore. But who\ncould show a cheek like Queequeg? which", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 626, "position": 626, "text": "ashore. But who\ncould show a cheek like Queequeg? which, barred with various tints,\nseemed like the Andes’ western slope, to show forth in one array,\ncontrasting climates, zone by zone.", "labels": {"50": 45, "100": 19, "250": 138, "500": 73, "1000": 730, "2000": 1814}}, {"id": 627, "position": 627, "text": "array,\ncontrasting climates, zone by zone.\n\n“Grub, ho!” now cried the landlord, flinging open a door, and in we\nwent to breakfast.\n\nThey say that men who have seen the world, thereby become quite at ease\nin", "labels": {"50": 48, "100": 20, "250": 90, "500": 162, "1000": 90, "2000": 478}}, {"id": 628, "position": 628, "text": "say that men who have seen the world, thereby become quite at ease\nin manner, quite self-possessed in company. Not always, though:\nLedyard, the great New England traveller, and Mungo Park, the Scotch\none; of all men", "labels": {"50": 44, "100": 37, "250": 158, "500": 252, "1000": 712, "2000": 760}}, {"id": 629, "position": 629, "text": "England traveller, and Mungo Park, the Scotch\none; of all men, they possessed the least assurance in the parlor. But\nperhaps the mere crossing of Siberia in a sledge drawn by dogs as\nLedyard did, or the taking a long solitary", "labels": {"50": 12, "100": 55, "250": 95, "500": 344, "1000": 377, "2000": 207}}, {"id": 630, "position": 630, "text": "edge drawn by dogs as\nLedyard did, or the taking a long solitary walk on an empty stomach, in\nthe negro heart of Africa, which was the sum of poor Mungo’s\nperformances—this kind of travel, I say, may not", "labels": {"50": 48, "100": 13, "250": 56, "500": 1, "1000": 381, "2000": 1946}}, {"id": 631, "position": 631, "text": "ngo’s\nperformances—this kind of travel, I say, may not be the very best mode\nof attaining a high social polish. Still, for the most part, that sort\nof thing is to be had anywhere.", "labels": {"50": 7, "100": 8, "250": 117, "500": 224, "1000": 387, "2000": 695}}, {"id": 632, "position": 632, "text": "sort\nof thing is to be had anywhere.\n\nThese reflections just here are occasioned by the circumstance that\nafter we were all seated at the table, and I was preparing to hear some\ngood stories about whaling; to my no small surprise, nearly every man", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 851, "2000": 1620}}, {"id": 633, "position": 633, "text": "some\ngood stories about whaling; to my no small surprise, nearly every man\nmaintained a profound silence. And not only that, but they looked\nembarrassed. Yes, here were a set of sea-dogs, many of whom without the\nslightest bashfulness had", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 634, "position": 634, "text": "set of sea-dogs, many of whom without the\nslightest bashfulness had boarded great whales on the high seas—entire\nstrangers to them—and duelled them dead without winking; and yet, here\nthey sat at a social breakfast table—all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 635, "position": 635, "text": "ing; and yet, here\nthey sat at a social breakfast table—all of the same calling, all of\nkindred tastes—looking round as sheepishly at each other as though they\nhad never been out of sight of some sheepfold among the Green", "labels": {"50": 23, "100": 88, "250": 53, "500": 202, "1000": 727, "2000": 1466}}, {"id": 636, "position": 636, "text": "though they\nhad never been out of sight of some sheepfold among the Green\nMountains. A curious sight; these bashful bears, these timid warrior\nwhalemen!\n\nBut as for Queequeg—why, Queequeg sat there among", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 637, "position": 637, "text": "for Queequeg—why, Queequeg sat there among them—at the head of\nthe table, too, it so chanced; as cool as an icicle. To be sure I\ncannot say much for his breeding", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 638, "position": 638, "text": "icicle. To be sure I\ncannot say much for his breeding. His greatest admirer could not have\ncordially justified his bringing his harpoon into breakfast with him,\nand using it there without ceremony; reaching over the table with it,\nto", "labels": {"50": 31, "100": 7, "250": 193, "500": 496, "1000": 849, "2000": 1107}}, {"id": 639, "position": 639, "text": "and using it there without ceremony; reaching over the table with it,\nto the imminent jeopardy of many heads, and grappling the beefsteaks\ntowards him. But _that_ was certainly very coolly done by him, and\nevery one knows", "labels": {"50": 23, "100": 7, "250": 70, "500": 202, "1000": 858, "2000": 110}}, {"id": 640, "position": 640, "text": "that_ was certainly very coolly done by him, and\nevery one knows that in most people’s estimation, to do anything coolly\nis to do it genteelly.\n\nWe will not speak of all Queequeg’s peculiarities", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 858, "2000": 40}}, {"id": 641, "position": 641, "text": ".\n\nWe will not speak of all Queequeg’s peculiarities here; how he eschewed\ncoffee and hot rolls, and applied his undivided attention to\nbeefsteaks, done rare", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 110}}, {"id": 642, "position": 642, "text": "beefsteaks, done rare. Enough, that when breakfast was over he withdrew\nlike the rest into the public room, lighted his tomahawk-pipe, and was\nsitting there quietly digesting and smoking with his inseparable hat\non, when", "labels": {"50": 37, "100": 57, "250": 70, "500": 39, "1000": 346, "2000": 110}}, {"id": 643, "position": 643, "text": "there quietly digesting and smoking with his inseparable hat\non, when I sallied out for a stroll.\n\n\nCHAPTER 6. The Street.\n\nIf I had been astonished at first catching a glimpse of so outlandish\nan individual as Quee", "labels": {"50": 31, "100": 20, "250": 132, "500": 412, "1000": 727, "2000": 381}}, {"id": 644, "position": 644, "text": "at first catching a glimpse of so outlandish\nan individual as Queequeg circulating among the polite society of a\ncivilized town, that astonishment soon departed upon taking my first\ndaylight stroll through the streets of New Bedford.", "labels": {"50": 20, "100": 28, "250": 156, "500": 407, "1000": 421, "2000": 381}}, {"id": 645, "position": 645, "text": "daylight stroll through the streets of New Bedford.\n\nIn thoroughfares nigh the docks, any considerable seaport will\nfrequently offer to view the queerest looking nondescripts from foreign\nparts. Even in Broadway and Chestnut streets, Mediterranean mariners\nwill sometimes", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 646, "position": 646, "text": "from foreign\nparts. Even in Broadway and Chestnut streets, Mediterranean mariners\nwill sometimes jostle the affrighted ladies. Regent Street is not\nunknown to Lascars and Malays; and at Bombay, in the Apollo Green, live\nYankees have often scared", "labels": {"50": 48, "100": 20, "250": 90, "500": 224, "1000": 90, "2000": 478}}, {"id": 647, "position": 647, "text": "; and at Bombay, in the Apollo Green, live\nYankees have often scared the natives. But New Bedford beats all Water\nStreet and Wapping. In these last-mentioned haunts you see only\nsailors; but in New Bedford, actual cannibal", "labels": {"50": 48, "100": 20, "250": 90, "500": 224, "1000": 90, "2000": 478}}, {"id": 648, "position": 648, "text": "s you see only\nsailors; but in New Bedford, actual cannibals stand chatting at street\ncorners; savages outright; many of whom yet carry on their bones unholy\nflesh. It makes a stranger stare.", "labels": {"50": 45, "100": 20, "250": 49, "500": 78, "1000": 90, "2000": 478}}, {"id": 649, "position": 649, "text": "holy\nflesh. It makes a stranger stare.\n\nBut, besides the Feegeeans, Tongatobooarrs, Erromanggoans, Pannangians,\nand Brighggians, and, besides the wild specimens of the", "labels": {"50": 25, "100": 41, "250": 91, "500": 1, "1000": 533, "2000": 187}}, {"id": 650, "position": 650, "text": ",\nand Brighggians, and, besides the wild specimens of the whaling-craft\nwhich unheeded reel about the streets, you will see other sights still\nmore curious, certainly more comical. There weekly arrive in this town\nscores of green Vermont", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 1620}}, {"id": 651, "position": 651, "text": ", certainly more comical. There weekly arrive in this town\nscores of green Vermonters and New Hampshire men, all athirst for gain\nand glory in the fishery. They are mostly young, of stalwart frames;\nfellows who have felled forests", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 692, "2000": 982}}, {"id": 652, "position": 652, "text": "mostly young, of stalwart frames;\nfellows who have felled forests, and now seek to drop the axe and\nsnatch the whale-lance. Many are as green as the Green Mountains whence\nthey came", "labels": {"50": 41, "100": 20, "250": 49, "500": 78, "1000": 933, "2000": 1081}}, {"id": 653, "position": 653, "text": "the Green Mountains whence\nthey came. In some things you would think them but a few hours old.\nLook there! that chap strutting round the corner. He wears a beaver hat\nand swallow-tailed coat, girdled with a", "labels": {"50": 11, "100": 21, "250": 91, "500": 5, "1000": 333, "2000": 361}}, {"id": 654, "position": 654, "text": "wears a beaver hat\nand swallow-tailed coat, girdled with a sailor-belt and sheath-knife.\nHere comes another with a sou’-wester and a bombazine cloak.", "labels": {"50": 41, "100": 2, "250": 166, "500": 69, "1000": 199, "2000": 1780}}, {"id": 655, "position": 655, "text": "a bombazine cloak.\n\nNo town-bred dandy will compare with a country-bred one—I mean a\ndownright bumpkin dandy—a fellow that, in the dog-days, will mow his\ntwo acres in buckskin", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 656, "position": 656, "text": "in the dog-days, will mow his\ntwo acres in buckskin gloves for fear of tanning his hands. Now when a\ncountry dandy like this takes it into his head to make a distinguished\nreputation, and joins the great whale-fishery", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 525, "2000": 887}}, {"id": 657, "position": 657, "text": "his head to make a distinguished\nreputation, and joins the great whale-fishery, you should see the\ncomical things he does upon reaching the seaport. In bespeaking his\nsea-outfit, he orders bell-buttons to his waistcoats", "labels": {"50": 45, "100": 7, "250": 49, "500": 78, "1000": 165, "2000": 1081}}, {"id": 658, "position": 658, "text": "his\nsea-outfit, he orders bell-buttons to his waistcoats; straps to his\ncanvas trowsers. Ah, poor Hay-Seed! how bitterly will burst those\nstraps in the first howling gale, when thou art driven, straps,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 659, "position": 659, "text": "those\nstraps in the first howling gale, when thou art driven, straps,\nbuttons, and all, down the throat of the tempest.\n\nBut think not that this famous town has only harpooneers, cannibals,\nand bumpkins to show", "labels": {"50": 9, "100": 7, "250": 193, "500": 498, "1000": 327, "2000": 1620}}, {"id": 660, "position": 660, "text": "only harpooneers, cannibals,\nand bumpkins to show her visitors. Not at all. Still New Bedford is a\nqueer place. Had it not been for us whalemen, that tract of land would\nthis day perhaps have been in", "labels": {"50": 48, "100": 57, "250": 53, "500": 230, "1000": 995, "2000": 1105}}, {"id": 661, "position": 661, "text": "us whalemen, that tract of land would\nthis day perhaps have been in as howling condition as the coast of\nLabrador. As it is, parts of her back country are enough to frighten\none, they look so bony", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 662, "position": 662, "text": "to frighten\none, they look so bony. The town itself is perhaps the dearest place to\nlive in, in all New England. It is a land of oil, true enough: but not\nlike Canaan; a land, also, of", "labels": {"50": 48, "100": 20, "250": 90, "500": 224, "1000": 525, "2000": 525}}, {"id": 663, "position": 663, "text": "true enough: but not\nlike Canaan; a land, also, of corn and wine. The streets do not run\nwith milk; nor in the spring-time do they pave them with fresh eggs", "labels": {"50": 48, "100": 20, "250": 90, "500": 224, "1000": 689, "2000": 775}}, {"id": 664, "position": 664, "text": "pave them with fresh eggs.\nYet, in spite of this, nowhere in all America will you find more\npatrician-like houses; parks and gardens more opulent, than in New\nBedford. Whence came they? how planted upon this once", "labels": {"50": 48, "100": 20, "250": 49, "500": 334, "1000": 275, "2000": 1546}}, {"id": 665, "position": 665, "text": "than in New\nBedford. Whence came they? how planted upon this once scraggy scoria of\na country?\n\nGo and gaze upon the iron emblematical harpoons round yonder lofty\nmansion, and your question will be answered", "labels": {"50": 48, "100": 20, "250": 53, "500": 126, "1000": 727, "2000": 1107}}, {"id": 666, "position": 666, "text": "round yonder lofty\nmansion, and your question will be answered. Yes; all these brave\nhouses and flowery gardens came from the Atlantic, Pacific, and Indian\noceans. One and all, they were harpooned and dragged up hither from", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 667, "position": 667, "text": "One and all, they were harpooned and dragged up hither from the\nbottom of the sea. Can Herr Alexander perform a feat like that?\n\nIn New Bedford, fathers, they say, give whales for dowers to their\ndaughters, and portion", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 668, "position": 668, "text": ", they say, give whales for dowers to their\ndaughters, and portion off their nieces with a few porpoises a-piece.\nYou must go to New Bedford to see a brilliant wedding; for, they say,\nthey have reservoirs of", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 387, "2000": 478}}, {"id": 669, "position": 669, "text": "to see a brilliant wedding; for, they say,\nthey have reservoirs of oil in every house, and every night recklessly\nburn their lengths in spermaceti candles.\n\nIn summer time, the town is sweet to see; full of fine maples", "labels": {"50": 34, "100": 77, "250": 164, "500": 192, "1000": 427, "2000": 491}}, {"id": 670, "position": 670, "text": "summer time, the town is sweet to see; full of fine maples—long\navenues of green and gold. And in August, high in air, the beautiful\nand bountiful horse-chestnuts, candelabra-wise, prof", "labels": {"50": 48, "100": 20, "250": 49, "500": 334, "1000": 275, "2000": 1546}}, {"id": 671, "position": 671, "text": "untiful horse-chestnuts, candelabra-wise, proffer the passer-by\ntheir tapering upright cones of congregated blossoms. So omnipotent is\nart; which in many a district of New Bedford has super", "labels": {"50": 48, "100": 20, "250": 142, "500": 451, "1000": 275, "2000": 1560}}, {"id": 672, "position": 672, "text": "potent is\nart; which in many a district of New Bedford has superinduced bright\nterraces of flowers upon the barren refuse rocks thrown aside at\ncreation’s final day.\n\nAnd the women of New Bedford, they bloom like their own red roses", "labels": {"50": 31, "100": 7, "250": 53, "500": 126, "1000": 995, "2000": 1105}}, {"id": 673, "position": 673, "text": ".\n\nAnd the women of New Bedford, they bloom like their own red roses. But\nroses only bloom in summer; whereas the fine carnation of their cheeks\nis perennial as sunlight in the seventh heavens. Elsewhere match that\nbloom of theirs, ye cannot,", "labels": {"50": 31, "100": 20, "250": 159, "500": 126, "1000": 727, "2000": 1105}}, {"id": 674, "position": 674, "text": "in the seventh heavens. Elsewhere match that\nbloom of theirs, ye cannot, save in Salem, where they tell me the young\ngirls breathe such musk, their sailor sweethearts smell them miles off\nshore, as though they were drawing nigh the odor", "labels": {"50": 9, "100": 73, "250": 120, "500": 143, "1000": 118, "2000": 1393}}, {"id": 675, "position": 675, "text": "smell them miles off\nshore, as though they were drawing nigh the odorous Moluccas instead of\nthe Puritanic sands.\n\n\nCHAPTER 7. The Chapel.\n\nIn this same New Bedford there stands a Whaleman’s Chapel, and few", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 676, "position": 676, "text": "this same New Bedford there stands a Whaleman’s Chapel, and few are\nthe moody fishermen, shortly bound for the Indian Ocean or Pacific, who\nfail to make a Sunday visit to the spot. I am sure that I did not.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 677, "position": 677, "text": "visit to the spot. I am sure that I did not.\n\nReturning from my first morning stroll, I again sallied out upon this\nspecial errand. The sky had changed from clear, sunny cold, to driving\nsleet and mist", "labels": {"50": 48, "100": 5, "250": 192, "500": 423, "1000": 35, "2000": 731}}, {"id": 678, "position": 678, "text": "changed from clear, sunny cold, to driving\nsleet and mist. Wrapping myself in my shaggy jacket of the cloth called\nbearskin, I fought my way against the stubborn storm. Entering, I found\na small scattered congregation of sailors, and sailors’", "labels": {"50": 25, "100": 5, "250": 136, "500": 388, "1000": 313, "2000": 1521}}, {"id": 679, "position": 679, "text": ". Entering, I found\na small scattered congregation of sailors, and sailors’ wives and\nwidows. A muffled silence reigned, only broken at times by the shrieks\nof the storm. Each silent worshipper seemed purposely sitting apart\nfrom the other, as if", "labels": {"50": 25, "100": 30, "250": 40, "500": 262, "1000": 322, "2000": 654}}, {"id": 680, "position": 680, "text": ". Each silent worshipper seemed purposely sitting apart\nfrom the other, as if each silent grief were insular and\nincommunicable. The chaplain had not yet arrived; and there these\nsilent islands of men and women sat steadfastly eyeing", "labels": {"50": 22, "100": 78, "250": 28, "500": 469, "1000": 531, "2000": 472}}, {"id": 681, "position": 681, "text": "and there these\nsilent islands of men and women sat steadfastly eyeing several marble\ntablets, with black borders, masoned into the wall on either side the\npulpit. Three of them ran something like the following, but I do not\npretend to quote", "labels": {"50": 48, "100": 20, "250": 26, "500": 380, "1000": 930, "2000": 1466}}, {"id": 682, "position": 682, "text": "of them ran something like the following, but I do not\npretend to quote:—\n\nSACRED TO THE MEMORY OF JOHN TALBOT, Who, at the age of eighteen, was\nlost overboard, Near the Isle of Desolation, off Patagonia,", "labels": {"50": 16, "100": 64, "250": 138, "500": 232, "1000": 327, "2000": 16}}, {"id": 683, "position": 683, "text": "overboard, Near the Isle of Desolation, off Patagonia, _November_\n1_st_, 1836. THIS TABLET Is erected to his Memory BY HIS SISTER.\n\nSACRED TO THE MEMORY OF ROBERT LONG, WILLIS ELLERY, NATHAN COLEMAN", "labels": {"50": 38, "100": 98, "250": 96, "500": 179, "1000": 841, "2000": 429}}, {"id": 684, "position": 684, "text": ".\n\nSACRED TO THE MEMORY OF ROBERT LONG, WILLIS ELLERY, NATHAN COLEMAN,\nWALTER CANNY, SETH MACY, AND SAMUEL GLEIG, Forming one of the boats’\ncrews OF THE SHIP ELIZA Who were towed out of sight by a Whale,", "labels": {"50": 16, "100": 57, "250": 191, "500": 230, "1000": 515, "2000": 231}}, {"id": 685, "position": 685, "text": "crews OF THE SHIP ELIZA Who were towed out of sight by a Whale, On the\nOff-shore Ground in the PACIFIC, _December_ 31_st_, 1839. THIS MARBLE\nIs here placed by their surviving SHIPMATES.", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 686, "position": 686, "text": "THIS MARBLE\nIs here placed by their surviving SHIPMATES.\n\nSACRED TO THE MEMORY OF The late CAPTAIN EZEKIEL HARDY, Who in the bows\nof his boat was killed by a Sperm Whale on the coast of Japan, _August_\n3_d_, 1833", "labels": {"50": 16, "100": 73, "250": 133, "500": 72, "1000": 327, "2000": 1620}}, {"id": 687, "position": 687, "text": "on the coast of Japan, _August_\n3_d_, 1833. THIS TABLET Is erected to his Memory BY HIS WIDOW.\n\nShaking off the sleet from my ice-glazed hat and jacket, I seated\nmyself near the door, and turning", "labels": {"50": 45, "100": 90, "250": 130, "500": 499, "1000": 582, "2000": 370}}, {"id": 688, "position": 688, "text": "-glazed hat and jacket, I seated\nmyself near the door, and turning sideways was surprised to see\nQueequeg near me. Affected by the solemnity of the scene, there was a\nwondering gaze of incredulous curiosity in his countena", "labels": {"50": 25, "100": 64, "250": 219, "500": 180, "1000": 421, "2000": 1620}}, {"id": 689, "position": 689, "text": ", there was a\nwondering gaze of incredulous curiosity in his countenance. This savage\nwas the only person present who seemed to notice my entrance; because\nhe was the only one who could not read, and, therefore, was not reading\nthose", "labels": {"50": 32, "100": 13, "250": 56, "500": 1, "1000": 682, "2000": 56}}, {"id": 690, "position": 690, "text": "only one who could not read, and, therefore, was not reading\nthose frigid inscriptions on the wall. Whether any of the relatives of\nthe seamen whose names appeared there were now among the congregation,\nI knew not; but so many are the", "labels": {"50": 25, "100": 5, "250": 125, "500": 388, "1000": 313, "2000": 1521}}, {"id": 691, "position": 691, "text": "were now among the congregation,\nI knew not; but so many are the unrecorded accidents in the fishery,\nand so plainly did several women present wear the countenance if not\nthe trappings of some unceasing grief, that I", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 692, "2000": 447}}, {"id": 692, "position": 692, "text": "nce if not\nthe trappings of some unceasing grief, that I feel sure that here\nbefore me were assembled those, in whose unhealing hearts the sight of\nthose bleak tablets sympathetically caused the old wounds to bleed\nafresh.", "labels": {"50": 12, "100": 15, "250": 7, "500": 203, "1000": 475, "2000": 646}}, {"id": 693, "position": 693, "text": "bleak tablets sympathetically caused the old wounds to bleed\nafresh.\n\nOh! ye whose dead lie buried beneath the green grass; who standing\namong flowers can say—here, _here_ lies my beloved; ye know not the\ndesolation that brood", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 198}}, {"id": 694, "position": 694, "text": "here_ lies my beloved; ye know not the\ndesolation that broods in bosoms like these. What bitter blanks in\nthose black-bordered marbles which cover no ashes! What despair in\nthose immovable inscriptions! What deadly void", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 1177}}, {"id": 695, "position": 695, "text": "cover no ashes! What despair in\nthose immovable inscriptions! What deadly voids and unbidden\ninfidelities in the lines that seem to gnaw upon all Faith, and refuse\nresurrections to the beings who have placelessly perished without", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 573}}, {"id": 696, "position": 696, "text": "Faith, and refuse\nresurrections to the beings who have placelessly perished without a\ngrave. As well might those tablets stand in the cave of Elephanta as\nhere.\n\nIn what census of living creatures, the dead of mankind are included;\nwhy it is", "labels": {"50": 5, "100": 66, "250": 211, "500": 490, "1000": 375, "2000": 965}}, {"id": 697, "position": 697, "text": "census of living creatures, the dead of mankind are included;\nwhy it is that a universal proverb says of them, that they tell no\ntales, though containing more secrets than the Goodwin Sands; how it is\nthat to his name who yesterday departed for", "labels": {"50": 8, "100": 52, "250": 1, "500": 320, "1000": 664, "2000": 1729}}, {"id": 698, "position": 698, "text": "the Goodwin Sands; how it is\nthat to his name who yesterday departed for the other world, we prefix\nso significant and infidel a word, and yet do not thus entitle him, if\nhe but embarks for the remotest Indies", "labels": {"50": 45, "100": 29, "250": 34, "500": 13, "1000": 622, "2000": 1097}}, {"id": 699, "position": 699, "text": "entitle him, if\nhe but embarks for the remotest Indies of this living earth; why the\nLife Insurance Companies pay death-forfeitures upon immortals; in what\neternal, unstirring paralysis, and deadly, hopeless trance, yet", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 700, "position": 700, "text": "what\neternal, unstirring paralysis, and deadly, hopeless trance, yet lies\nantique Adam who died sixty round centuries ago; how it is that we\nstill refuse to be comforted for those who we nevertheless maintain are\ndwelling in unspeakable bliss", "labels": {"50": 10, "100": 75, "250": 13, "500": 307, "1000": 343, "2000": 761}}, {"id": 701, "position": 701, "text": "ed for those who we nevertheless maintain are\ndwelling in unspeakable bliss; why all the living so strive to hush all\nthe dead; wherefore but the rumor of a knocking in a tomb will terrify\na whole city", "labels": {"50": 16, "100": 20, "250": 13, "500": 370, "1000": 375, "2000": 970}}, {"id": 702, "position": 702, "text": "a knocking in a tomb will terrify\na whole city. All these things are not without their meanings.\n\nBut Faith, like a jackal, feeds among the tombs, and even from these\ndead doubts she gathers her most vital hope.", "labels": {"50": 22, "100": 78, "250": 205, "500": 380, "1000": 890, "2000": 988}}, {"id": 703, "position": 703, "text": "even from these\ndead doubts she gathers her most vital hope.\n\nIt needs scarcely to be told, with what feelings, on the eve of a\nNantucket voyage, I regarded those marble tablets, and by the murky\nlight of that darkened, dole", "labels": {"50": 13, "100": 3, "250": 201, "500": 405, "1000": 223, "2000": 1724}}, {"id": 704, "position": 704, "text": "marble tablets, and by the murky\nlight of that darkened, doleful day read the fate of the whalemen who\nhad gone before me. Yes, Ishmael, the same fate may be thine. But\nsomehow I grew merry again", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 705, "position": 705, "text": ", the same fate may be thine. But\nsomehow I grew merry again. Delightful inducements to embark, fine\nchance for promotion, it seems—aye, a stove boat will make me an\nimmortal by brevet", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1495}}, {"id": 706, "position": 706, "text": "will make me an\nimmortal by brevet. Yes, there is death in this business of whaling—a\nspeechlessly quick chaotic bundling of a man into Eternity. But what\nthen? Methinks we have hugely mistaken this matter of Life and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 707, "position": 707, "text": "what\nthen? Methinks we have hugely mistaken this matter of Life and Death.\nMethinks that what they call my shadow here on earth is my true\nsubstance. Methinks that in looking at things spiritual, we are too\nmuch like oyster", "labels": {"50": 35, "100": 94, "250": 13, "500": 414, "1000": 548, "2000": 1555}}, {"id": 708, "position": 708, "text": "hinks that in looking at things spiritual, we are too\nmuch like oysters observing the sun through the water, and thinking\nthat thick water the thinnest of air. Methinks my body is but the lees\nof my better being", "labels": {"50": 41, "100": 21, "250": 215, "500": 281, "1000": 333, "2000": 1082}}, {"id": 709, "position": 709, "text": "Methinks my body is but the lees\nof my better being. In fact take my body who will, take it I say, it is\nnot me. And therefore three cheers for Nantucket; and come a stove boat\nand stove body when", "labels": {"50": 8, "100": 14, "250": 81, "500": 426, "1000": 650, "2000": 557}}, {"id": 710, "position": 710, "text": "three cheers for Nantucket; and come a stove boat\nand stove body when they will, for stave my soul, Jove himself cannot.\n\n\nCHAPTER 8. The Pulpit.\n\nI had not been seated very long ere a man of a certain venerable", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 711, "position": 711, "text": "I had not been seated very long ere a man of a certain venerable\nrobustness entered; immediately as the storm-pelted door flew back upon\nadmitting him, a quick regardful eyeing of him by all the congregation,\nsufficiently attested that this", "labels": {"50": 23, "100": 28, "250": 156, "500": 202, "1000": 421, "2000": 1559}}, {"id": 712, "position": 712, "text": "quick regardful eyeing of him by all the congregation,\nsufficiently attested that this fine old man was the chaplain. Yes, it\nwas the famous Father Mapple, so called by the whalemen, among whom he\nwas a very great favourite", "labels": {"50": 23, "100": 30, "250": 40, "500": 160, "1000": 322, "2000": 877}}, {"id": 713, "position": 713, "text": "the whalemen, among whom he\nwas a very great favourite. He had been a sailor and a harpooneer in\nhis youth, but for many years past had dedicated his life to the\nministry. At the time I now write of, Father Map", "labels": {"50": 44, "100": 28, "250": 125, "500": 388, "1000": 576, "2000": 1495}}, {"id": 714, "position": 714, "text": "life to the\nministry. At the time I now write of, Father Mapple was in the hardy\nwinter of a healthy old age; that sort of old age which seems merging\ninto a second flowering youth, for among all the fissures of his", "labels": {"50": 44, "100": 37, "250": 143, "500": 94, "1000": 363, "2000": 1004}}, {"id": 715, "position": 715, "text": "into a second flowering youth, for among all the fissures of his\nwrinkles, there shone certain mild gleams of a newly developing\nbloom—the spring verdure peeping forth even beneath February’s snow", "labels": {"50": 22, "100": 78, "250": 39, "500": 481, "1000": 631, "2000": 1976}}, {"id": 716, "position": 716, "text": "peeping forth even beneath February’s snow. No\none having previously heard his history, could for the first time\nbehold Father Mapple without the utmost interest, because there were\ncertain engrafted clerical peculiarities about him, imputable to that\nadventurous", "labels": {"50": 23, "100": 88, "250": 219, "500": 160, "1000": 394, "2000": 1725}}, {"id": 717, "position": 717, "text": "certain engrafted clerical peculiarities about him, imputable to that\nadventurous maritime life he had led. When he entered I observed that\nhe carried no umbrella, and certainly had not come in his carriage, for\nhis tarpaulin hat ran down with", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 718, "position": 718, "text": "not come in his carriage, for\nhis tarpaulin hat ran down with melting sleet, and his great pilot\ncloth jacket seemed almost to drag him to the floor with the weight of\nthe water it had absorbed", "labels": {"50": 22, "100": 88, "250": 145, "500": 416, "1000": 296, "2000": 160}}, {"id": 719, "position": 719, "text": "weight of\nthe water it had absorbed. However, hat and coat and overshoes were one\nby one removed, and hung up in a little space in an adjacent corner;\nwhen, arrayed in a decent suit, he quietly approached the pulpit.", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 775, "2000": 1902}}, {"id": 720, "position": 720, "text": "when, arrayed in a decent suit, he quietly approached the pulpit.\n\nLike most old fashioned pulpits, it was a very lofty one, and since a\nregular stairs to such a height would, by its long angle with the\nfloor, seriously", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 322, "2000": 1902}}, {"id": 721, "position": 721, "text": "to such a height would, by its long angle with the\nfloor, seriously contract the already small area of the chapel, the\narchitect, it seemed, had acted upon the hint of Father Mapple, and\nfinished the pulpit without a stairs, substituting", "labels": {"50": 5, "100": 27, "250": 157, "500": 63, "1000": 765, "2000": 1696}}, {"id": 722, "position": 722, "text": "of Father Mapple, and\nfinished the pulpit without a stairs, substituting a perpendicular side\nladder, like those used in mounting a ship from a boat at sea. The wife\nof a whaling captain had provided the chapel with a handsome pair of\nred worst", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 322, "2000": 1743}}, {"id": 723, "position": 723, "text": "of a whaling captain had provided the chapel with a handsome pair of\nred worsted man-ropes for this ladder, which, being itself nicely\nheaded, and stained with a mahogany colour, the whole contrivance,\nconsidering what manner of chapel it was", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 724, "position": 724, "text": "colour, the whole contrivance,\nconsidering what manner of chapel it was, seemed by no means in bad\ntaste. Halting for an instant at the foot of the ladder, and with both\nhands grasping the ornamental knobs of the man-ropes", "labels": {"50": 33, "100": 69, "250": 173, "500": 245, "1000": 539, "2000": 1895}}, {"id": 725, "position": 725, "text": ", and with both\nhands grasping the ornamental knobs of the man-ropes, Father Mapple\ncast a look upwards, and then with a truly sailor-like but still\nreverential dexterity, hand over hand, mounted the steps as if\nascending", "labels": {"50": 22, "100": 78, "250": 205, "500": 286, "1000": 612, "2000": 472}}, {"id": 726, "position": 726, "text": "erential dexterity, hand over hand, mounted the steps as if\nascending the main-top of his vessel.\n\nThe perpendicular parts of this side ladder, as is usually the case\nwith swinging ones, were of cloth-covered rope, only the rounds", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 642, "2000": 1904}}, {"id": 727, "position": 727, "text": "case\nwith swinging ones, were of cloth-covered rope, only the rounds were of\nwood, so that at every step there was a joint. At my first glimpse of\nthe pulpit, it had not escaped me that however convenient for a ship,\nthese", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 842, "2000": 1495}}, {"id": 728, "position": 728, "text": "pulpit, it had not escaped me that however convenient for a ship,\nthese joints in the present instance seemed unnecessary. For I was not\nprepared to see Father Mapple after gaining the height, slowly turn\nround, and stooping over the pulpit, deliberately", "labels": {"50": 23, "100": 30, "250": 40, "500": 160, "1000": 322, "2000": 1902}}, {"id": 729, "position": 729, "text": "the height, slowly turn\nround, and stooping over the pulpit, deliberately drag up the ladder\nstep by step, till the whole was deposited within, leaving him\nimpregnable in his little Quebec.", "labels": {"50": 37, "100": 55, "250": 174, "500": 269, "1000": 661, "2000": 65}}, {"id": 730, "position": 730, "text": "ble in his little Quebec.\n\nI pondered some time without fully comprehending the reason for this.\nFather Mapple enjoyed such a wide reputation for sincerity and\nsanctity, that I could not suspect him of courting notoriety by any\nmere tricks of the", "labels": {"50": 20, "100": 56, "250": 177, "500": 134, "1000": 394, "2000": 267}}, {"id": 731, "position": 731, "text": "I could not suspect him of courting notoriety by any\nmere tricks of the stage. No, thought I, there must be some sober\nreason for this thing; furthermore, it must symbolize something unseen.\nCan it be, then, that by that", "labels": {"50": 20, "100": 17, "250": 101, "500": 120, "1000": 818, "2000": 729}}, {"id": 732, "position": 732, "text": "must symbolize something unseen.\nCan it be, then, that by that act of physical isolation, he signifies\nhis spiritual withdrawal for the time, from all outward worldly ties\nand connexions? Yes, for replenished with the meat", "labels": {"50": 10, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1010}}, {"id": 733, "position": 733, "text": "and connexions? Yes, for replenished with the meat and wine of the\nword, to the faithful man of God, this pulpit, I see, is a\nself-containing stronghold—a lofty Ehrenbreitstein,", "labels": {"50": 9, "100": 60, "250": 217, "500": 252, "1000": 712, "2000": 813}}, {"id": 734, "position": 734, "text": "a\nself-containing stronghold—a lofty Ehrenbreitstein, with a perennial\nwell of water within the walls.\n\nBut the side ladder was not the only strange feature of the place,\nborrowed from the chaplain’s former sea-farings", "labels": {"50": 22, "100": 78, "250": 231, "500": 286, "1000": 412, "2000": 166}}, {"id": 735, "position": 735, "text": "of the place,\nborrowed from the chaplain’s former sea-farings. Between the marble\ncenotaphs on either hand of the pulpit, the wall which formed its back\nwas adorned with a large painting representing a gallant ship beating\nagainst a terrible", "labels": {"50": 5, "100": 78, "250": 189, "500": 370, "1000": 890, "2000": 988}}, {"id": 736, "position": 736, "text": "back\nwas adorned with a large painting representing a gallant ship beating\nagainst a terrible storm off a lee coast of black rocks and snowy\nbreakers. But high above the flying scud and dark-rolling clouds, there\nfloated a little isle of sunlight, from which", "labels": {"50": 48, "100": 27, "250": 53, "500": 162, "1000": 9, "2000": 682}}, {"id": 737, "position": 737, "text": "dark-rolling clouds, there\nfloated a little isle of sunlight, from which beamed forth an angel’s\nface; and this bright face shed a distinct spot of radiance upon the\nship’s tossed deck, something like that silver plate now inserted", "labels": {"50": 16, "100": 73, "250": 133, "500": 401, "1000": 252, "2000": 970}}, {"id": 738, "position": 738, "text": "upon the\nship’s tossed deck, something like that silver plate now inserted into\nthe Victory’s plank where Nelson fell. “Ah, noble ship,” the angel\nseemed to say, “beat on, beat on, thou noble ship, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 739, "position": 739, "text": "to say, “beat on, beat on, thou noble ship, and bear a hardy\nhelm; for lo! the sun is breaking through; the clouds are rolling\noff—serenest azure is at hand.”", "labels": {"50": 16, "100": 73, "250": 240, "500": 232, "1000": 916, "2000": 16}}, {"id": 740, "position": 740, "text": "serenest azure is at hand.”\n\nNor was the pulpit itself without a trace of the same sea-taste that\nhad achieved the ladder and the picture. Its panelled front was in the\nlikeness of a ship’s bluff bows, and the Holy", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1014}}, {"id": 741, "position": 741, "text": "was in the\nlikeness of a ship’s bluff bows, and the Holy Bible rested on a\nprojecting piece of scroll work, fashioned after a ship’s fiddle-headed\nbeak.\n\nWhat could be more full of meaning?—for the pulpit is ever", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 851, "2000": 967}}, {"id": 742, "position": 742, "text": ".\n\nWhat could be more full of meaning?—for the pulpit is ever this earth’s\nforemost part; all the rest comes in its rear; the pulpit leads the\nworld. From thence it is the storm of God’s quick wrath is first", "labels": {"50": 35, "100": 94, "250": 23, "500": 414, "1000": 855, "2000": 1470}}, {"id": 743, "position": 743, "text": ". From thence it is the storm of God’s quick wrath is first\ndescried, and the bow must bear the earliest brunt. From thence it is\nthe God of breezes fair or foul is first invoked for favourable winds", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 663, "2000": 1666}}, {"id": 744, "position": 744, "text": "of breezes fair or foul is first invoked for favourable winds.\nYes, the world’s a ship on its passage out, and not a voyage complete;\nand the pulpit is its prow.\n\n\nCHAPTER 9. The Sermon.", "labels": {"50": 9, "100": 47, "250": 227, "500": 17, "1000": 803, "2000": 854}}, {"id": 745, "position": 745, "text": "is its prow.\n\n\nCHAPTER 9. The Sermon.\n\nFather Mapple rose, and in a mild voice of unassuming authority ordered\nthe scattered people to condense. “Starboard gangway, there! side away\nto larboard—la", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 746, "position": 746, "text": "Starboard gangway, there! side away\nto larboard—larboard gangway to starboard! Midships! midships!”\n\nThere was a low rumbling of heavy sea-boots among the benches, and a\nstill slight", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 747, "position": 747, "text": "low rumbling of heavy sea-boots among the benches, and a\nstill slighter shuffling of women’s shoes, and all was quiet again, and\nevery eye on the preacher.\n\nHe paused a little; then kneeling in the pulpit’s bows,", "labels": {"50": 22, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 472}}, {"id": 748, "position": 748, "text": ".\n\nHe paused a little; then kneeling in the pulpit’s bows, folded his\nlarge brown hands across his chest, uplifted his closed eyes, and\noffered a prayer so deeply devout that he seemed kneeling and praying\nat the bottom of the sea", "labels": {"50": 28, "100": 30, "250": 40, "500": 262, "1000": 775, "2000": 344}}, {"id": 749, "position": 749, "text": "so deeply devout that he seemed kneeling and praying\nat the bottom of the sea.\n\nThis ended, in prolonged solemn tones, like the continual tolling of a\nbell in a ship that is foundering at sea in a fog—in such tones he\ncommenced", "labels": {"50": 22, "100": 78, "250": 205, "500": 469, "1000": 475, "2000": 267}}, {"id": 750, "position": 750, "text": "that is foundering at sea in a fog—in such tones he\ncommenced reading the following hymn; but changing his manner towards\nthe concluding stanzas, burst forth with a pealing exultation and joy—", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 751, "position": 751, "text": "ling exultation and joy—\n\n\n  “The ribs and terrors in the whale, Arched over me a dismal gloom,\n  While all God’s sun-lit waves rolled by, And lift me deepening down\n  to doom.", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 752, "position": 752, "text": "rolled by, And lift me deepening down\n  to doom.\n\n  “I saw the opening maw of hell, With endless pains and sorrows there;\n  Which none but they that feel can tell— Oh, I was plunging to\n  despair.", "labels": {"50": 16, "100": 73, "250": 26, "500": 411, "1000": 914, "2000": 1860}}, {"id": 753, "position": 753, "text": "feel can tell— Oh, I was plunging to\n  despair.\n\n  “In black distress, I called my God, When I could scarce believe him\n  mine, He bowed his ear to my complaints— No more the whale did me\n  confine.", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 313, "2000": 1521}}, {"id": 754, "position": 754, "text": "my complaints— No more the whale did me\n  confine.\n\n  “With speed he flew to my relief, As on a radiant dolphin borne;\n  Awful, yet bright, as lightning shone The face of my Deliverer God.", "labels": {"50": 9, "100": 26, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 755, "position": 755, "text": "shone The face of my Deliverer God.\n\n  “My song for ever shall record That terrible, that joyful hour; I\n  give the glory to my God, His all the mercy and the power.”", "labels": {"50": 25, "100": 30, "250": 40, "500": 357, "1000": 941, "2000": 393}}, {"id": 756, "position": 756, "text": "mercy and the power.”\n\n\n\n\nNearly all joined in singing this hymn, which swelled high above the\nhowling of the storm. A brief pause ensued; the preacher slowly turned\nover the leaves of the Bible, and at last, folding his hand down upon\nthe", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 322, "2000": 1902}}, {"id": 757, "position": 757, "text": "leaves of the Bible, and at last, folding his hand down upon\nthe proper page, said: “Beloved shipmates, clinch the last verse of the\nfirst chapter of Jonah—‘And God had prepared a great fish to swallow up\nJonah.’", "labels": {"50": 27, "100": 33, "250": 112, "500": 159, "1000": 989, "2000": 161}}, {"id": 758, "position": 758, "text": "—‘And God had prepared a great fish to swallow up\nJonah.’”\n\n“Shipmates, this book, containing only four chapters—four yarns—is one\nof the smallest strands in the mighty cable of the Scriptures", "labels": {"50": 27, "100": 33, "250": 112, "500": 44, "1000": 503, "2000": 1620}}, {"id": 759, "position": 759, "text": "the smallest strands in the mighty cable of the Scriptures. Yet what\ndepths of the soul does Jonah’s deep sealine sound! what a pregnant\nlesson to us is this prophet! What a noble thing is that canticle in\nthe fish’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 760, "position": 760, "text": "! What a noble thing is that canticle in\nthe fish’s belly! How billow-like and boisterously grand! We feel the\nfloods surging over us; we sound with him to the kelpy bottom of the\nwaters", "labels": {"50": 48, "100": 20, "250": 193, "500": 126, "1000": 174, "2000": 1105}}, {"id": 761, "position": 761, "text": "us; we sound with him to the kelpy bottom of the\nwaters; sea-weed and all the slime of the sea is about us! But _what_\nis this lesson that the book of Jonah teaches? Shipmates, it is", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 762, "position": 762, "text": "is this lesson that the book of Jonah teaches? Shipmates, it is a\ntwo-stranded lesson; a lesson to us all as sinful men, and a lesson to\nme as a pilot of the living God", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 763, "position": 763, "text": "me as a pilot of the living God. As sinful men, it is a lesson to us\nall, because it is a story of the sin, hard-heartedness, suddenly\nawakened fears, the swift punishment, repentance, prayers,", "labels": {"50": 35, "100": 94, "250": 23, "500": 159, "1000": 855, "2000": 963}}, {"id": 764, "position": 764, "text": ", suddenly\nawakened fears, the swift punishment, repentance, prayers, and finally\nthe deliverance and joy of Jonah. As with all sinners among men, the\nsin of this son of Amittai was in his wilful disobed", "labels": {"50": 27, "100": 33, "250": 112, "500": 44, "1000": 503, "2000": 1052}}, {"id": 765, "position": 765, "text": "of this son of Amittai was in his wilful disobedience of the\ncommand of God—never mind now what that command was, or how\nconveyed—which he found a hard command. But all the things that God\nwould have us", "labels": {"50": 35, "100": 94, "250": 112, "500": 44, "1000": 201, "2000": 1464}}, {"id": 766, "position": 766, "text": "he found a hard command. But all the things that God\nwould have us do are hard for us to do—remember that—and hence, he\noftener commands us than endeavors to persuade. And if we obey God, we\nmust disobey", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 624, "2000": 859}}, {"id": 767, "position": 767, "text": "endeavors to persuade. And if we obey God, we\nmust disobey ourselves; and it is in this disobeying ourselves, wherein\nthe hardness of obeying God consists.\n\n“With this sin of disobedience in him, Jonah", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 624, "2000": 859}}, {"id": 768, "position": 768, "text": "consists.\n\n“With this sin of disobedience in him, Jonah still further flouts at\nGod, by seeking to flee from Him. He thinks that a ship made by men\nwill carry him into countries where God does not reign, but only", "labels": {"50": 35, "100": 33, "250": 194, "500": 86, "1000": 880, "2000": 608}}, {"id": 769, "position": 769, "text": "by men\nwill carry him into countries where God does not reign, but only the\nCaptains of this earth. He skulks about the wharves of Joppa, and seeks\na ship that’s bound for Tarshish", "labels": {"50": 40, "100": 26, "250": 240, "500": 104, "1000": 574, "2000": 524}}, {"id": 770, "position": 770, "text": "seeks\na ship that’s bound for Tarshish. There lurks, perhaps, a hitherto\nunheeded meaning here. By all accounts Tarshish could have been no\nother city than the modern Cadiz", "labels": {"50": 32, "100": 0, "250": 233, "500": 466, "1000": 575, "2000": 659}}, {"id": 771, "position": 771, "text": "have been no\nother city than the modern Cadiz. That’s the opinion of learned men.\nAnd where is Cadiz, shipmates? Cadiz is in Spain; as far by water, from\nJoppa, as Jonah could possibly have sailed in those ancient", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 772, "position": 772, "text": "water, from\nJoppa, as Jonah could possibly have sailed in those ancient days, when\nthe Atlantic was an almost unknown sea. Because Joppa, the modern\nJaffa, shipmates, is on the most easterly coast of the Mediterranean,\nthe", "labels": {"50": 27, "100": 33, "250": 194, "500": 44, "1000": 880, "2000": 608}}, {"id": 773, "position": 773, "text": "shipmates, is on the most easterly coast of the Mediterranean,\nthe Syrian; and Tarshish or Cadiz more than two thousand miles to the\nwestward from that, just outside the Straits of Gibraltar. See ye not\nthen, shipmates, that", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 774, "position": 774, "text": "outside the Straits of Gibraltar. See ye not\nthen, shipmates, that Jonah sought to flee world-wide from God?\nMiserable man! Oh! most contemptible and worthy of all scorn; with\nslouched hat and guilty eye, sk", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 779, "2000": 16}}, {"id": 775, "position": 775, "text": "of all scorn; with\nslouched hat and guilty eye, skulking from his God; prowling among the\nshipping like a vile burglar hastening to cross the seas. So\ndisordered, self-condemning is his look", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 776, "position": 776, "text": "to cross the seas. So\ndisordered, self-condemning is his look, that had there been policemen\nin those days, Jonah, on the mere suspicion of something wrong, had\nbeen arrested ere he touched a deck", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 777, "position": 777, "text": "had\nbeen arrested ere he touched a deck. How plainly he’s a fugitive! no\nbaggage, not a hat-box, valise, or carpet-bag,—no friends accompany him\nto the wharf with their adieux", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 778, "position": 778, "text": "—no friends accompany him\nto the wharf with their adieux. At last, after much dodging search, he\nfinds the Tarshish ship receiving the last items of her cargo; and as\nhe steps on board to see its Captain in the cabin", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 300, "2000": 558}}, {"id": 779, "position": 779, "text": "cargo; and as\nhe steps on board to see its Captain in the cabin, all the sailors for\nthe moment desist from hoisting in the goods, to mark the stranger’s\nevil eye. Jonah sees this; but in vain he tries", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 780, "position": 780, "text": "stranger’s\nevil eye. Jonah sees this; but in vain he tries to look all ease and\nconfidence; in vain essays his wretched smile. Strong intuitions of the\nman assure the mariners he can be no innocent", "labels": {"50": 22, "100": 78, "250": 49, "500": 78, "1000": 165, "2000": 1956}}, {"id": 781, "position": 781, "text": "man assure the mariners he can be no innocent. In their gamesome but\nstill serious way, one whispers to the other—“Jack, he’s robbed a\nwidow;” or, “Joe, do you mark him; he’s a", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1790}}, {"id": 782, "position": 782, "text": "” or, “Joe, do you mark him; he’s a bigamist;” or, “Harry lad, I\nguess he’s the adulterer that broke jail in old Gomorrah, or belike,\none", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 783, "position": 783, "text": "that broke jail in old Gomorrah, or belike,\none of the missing murderers from Sodom.” Another runs to read the bill\nthat’s stuck against the spile upon the wharf to which the ship is\nmoored, offering", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 784, "position": 784, "text": "the spile upon the wharf to which the ship is\nmoored, offering five hundred gold coins for the apprehension of a\nparricide, and containing a description of his person. He reads, and\nlooks from Jonah to the bill; while all his", "labels": {"50": 43, "100": 48, "250": 71, "500": 14, "1000": 165, "2000": 266}}, {"id": 785, "position": 785, "text": ". He reads, and\nlooks from Jonah to the bill; while all his sympathetic shipmates now\ncrowd round Jonah, prepared to lay their hands upon him. Frighted Jonah\ntrembles, and summoning all his boldness to his face, only looks", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 327, "2000": 967}}, {"id": 786, "position": 786, "text": "s, and summoning all his boldness to his face, only looks so\nmuch the more a coward. He will not confess himself suspected; but that\nitself is strong suspicion. So he makes the best of it; and when the\nsailors find him", "labels": {"50": 45, "100": 64, "250": 49, "500": 73, "1000": 165, "2000": 1956}}, {"id": 787, "position": 787, "text": ". So he makes the best of it; and when the\nsailors find him not to be the man that is advertised, they let him\npass, and he descends into the cabin.\n\n“‘Who’s there?’ cries the Captain at his busy", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1790}}, {"id": 788, "position": 788, "text": ".\n\n“‘Who’s there?’ cries the Captain at his busy desk, hurriedly making\nout his papers for the Customs—‘Who’s there?’ Oh! how that harmless\nquestion mangles Jonah! For the instant he almost turns to", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 789, "position": 789, "text": "how that harmless\nquestion mangles Jonah! For the instant he almost turns to flee again.\nBut he rallies. ‘I seek a passage in this ship to Tarshish; how soon\nsail ye, sir?’ Thus far the busy Captain had not", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 790, "position": 790, "text": "how soon\nsail ye, sir?’ Thus far the busy Captain had not looked up to Jonah,\nthough the man now stands before him; but no sooner does he hear that\nhollow voice, than he darts a scrutinizing glance", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 791, "position": 791, "text": "hollow voice, than he darts a scrutinizing glance. ‘We sail with the\nnext coming tide,’ at last he slowly answered, still intently eyeing\nhim. ‘No sooner, sir?’—‘Soon enough for any honest man that", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 925, "2000": 967}}, {"id": 792, "position": 792, "text": "No sooner, sir?’—‘Soon enough for any honest man that goes a\npassenger.’ Ha! Jonah, that’s another stab. But he swiftly calls away\nthe Captain from that scent. ‘I’ll sail with ye,’", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 793, "position": 793, "text": "the Captain from that scent. ‘I’ll sail with ye,’—he says,—‘the passage\nmoney how much is that?—I’ll pay now.’ For it is particularly written,\nshipmates, as if it were", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 627, "2000": 877}}, {"id": 794, "position": 794, "text": ".’ For it is particularly written,\nshipmates, as if it were a thing not to be overlooked in this history,\n‘that he paid the fare thereof’ ere the craft did sail. And taken with\nthe context, this is full of", "labels": {"50": 45, "100": 29, "250": 82, "500": 13, "1000": 257, "2000": 156}}, {"id": 795, "position": 795, "text": "the craft did sail. And taken with\nthe context, this is full of meaning.\n\n“Now Jonah’s Captain, shipmates, was one whose discernment detects\ncrime in any, but whose cupidity exposes it only in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 851, "2000": 1620}}, {"id": 796, "position": 796, "text": "crime in any, but whose cupidity exposes it only in the penniless. In\nthis world, shipmates, sin that pays its way can travel freely, and\nwithout a passport; whereas Virtue, if a pauper, is stopped", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 797, "position": 797, "text": "and\nwithout a passport; whereas Virtue, if a pauper, is stopped at all\nfrontiers. So Jonah’s Captain prepares to test the length of Jonah’s\npurse, ere he judge him openly", "labels": {"50": 31, "100": 75, "250": 88, "500": 496, "1000": 165, "2000": 1956}}, {"id": 798, "position": 798, "text": "ere he judge him openly. He charges him thrice the usual sum;\nand it’s assented to. Then the Captain knows that Jonah is a fugitive;\nbut at the same time resolves to help a flight that paves its rear", "labels": {"50": 27, "100": 33, "250": 194, "500": 44, "1000": 503, "2000": 84}}, {"id": 799, "position": 799, "text": "at the same time resolves to help a flight that paves its rear with\ngold. Yet when Jonah fairly takes out his purse, prudent suspicions\nstill molest the Captain. He rings every coin to find a counterfeit", "labels": {"50": 17, "100": 16, "250": 151, "500": 71, "1000": 366, "2000": 692}}, {"id": 800, "position": 800, "text": "Captain. He rings every coin to find a counterfeit.\nNot a forger, any way, he mutters; and Jonah is put down for his\npassage. ‘Point out my state-room, Sir,’ says Jonah now, ‘I", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1790}}, {"id": 801, "position": 801, "text": "out my state-room, Sir,’ says Jonah now, ‘I’m\ntravel-weary; I need sleep.’ ‘Thou lookest like it,’ says the Captain,\n‘there’s thy room.’ Jonah enters, and", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 802, "position": 802, "text": "the Captain,\n‘there’s thy room.’ Jonah enters, and would lock the door, but the lock\ncontains no key. Hearing him foolishly fumbling there, the Captain\nlaughs lowly to himself, and mutters something about the doors", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 803, "position": 803, "text": "the Captain\nlaughs lowly to himself, and mutters something about the doors of\nconvicts’ cells being never allowed to be locked within. All dressed\nand dusty as he is, Jonah throws himself into his berth, and finds the\nlittle state-room ceiling", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 804, "position": 804, "text": "Jonah throws himself into his berth, and finds the\nlittle state-room ceiling almost resting on his forehead. The air is\nclose, and Jonah gasps. Then, in that contracted hole, sunk, too,\nbeneath the ship’s water-line,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 805, "position": 805, "text": "hole, sunk, too,\nbeneath the ship’s water-line, Jonah feels the heralding presentiment\nof that stifling hour, when the whale shall hold him in the smallest of\nhis bowels’ wards.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 806, "position": 806, "text": "him in the smallest of\nhis bowels’ wards.\n\n“Screwed at its axis against the side, a swinging lamp slightly\noscillates in Jonah’s room; and the ship, heeling over towards the\nwharf with the weight of the last", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 807, "position": 807, "text": "the ship, heeling over towards the\nwharf with the weight of the last bales received, the lamp, flame and\nall, though in slight motion, still maintains a permanent obliquity\nwith reference to the room; though, in truth,", "labels": {"50": 48, "100": 20, "250": 49, "500": 78, "1000": 933, "2000": 1081}}, {"id": 808, "position": 808, "text": "obliquity\nwith reference to the room; though, in truth, infallibly straight\nitself, it but made obvious the false, lying levels among which it\nhung. The lamp alarms and frightens Jonah; as lying in his berth his\ntormented", "labels": {"50": 22, "100": 78, "250": 205, "500": 3, "1000": 475, "2000": 1554}}, {"id": 809, "position": 809, "text": "The lamp alarms and frightens Jonah; as lying in his berth his\ntormented eyes roll round the place, and this thus far successful\nfugitive finds no refuge for his restless glance. But that\ncontradiction in the lamp more and more appals him", "labels": {"50": 22, "100": 64, "250": 49, "500": 78, "1000": 531, "2000": 1620}}, {"id": 810, "position": 810, "text": "But that\ncontradiction in the lamp more and more appals him. The floor, the\nceiling, and the side, are all awry. ‘Oh! so my conscience hangs in\nme!’ he groans, ‘straight upwards, so it burns;", "labels": {"50": 22, "100": 20, "250": 49, "500": 78, "1000": 933, "2000": 292}}, {"id": 811, "position": 811, "text": "in\nme!’ he groans, ‘straight upwards, so it burns; but the chambers of my\nsoul are all in crookedness!’\n\n“Like one who after a night of drunken revelry hies to his bed, still\nreeling, but", "labels": {"50": 22, "100": 78, "250": 229, "500": 335, "1000": 631, "2000": 250}}, {"id": 812, "position": 812, "text": "of drunken revelry hies to his bed, still\nreeling, but with conscience yet pricking him, as the plungings of the\nRoman race-horse but so much the more strike his steel tags into him;\nas one who in that miserable", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 663, "2000": 1058}}, {"id": 813, "position": 813, "text": "the more strike his steel tags into him;\nas one who in that miserable plight still turns and turns in giddy\nanguish, praying God for annihilation until the fit be passed; and at\nlast amid the whirl of woe he feels", "labels": {"50": 9, "100": 26, "250": 120, "500": 12, "1000": 893, "2000": 1083}}, {"id": 814, "position": 814, "text": "passed; and at\nlast amid the whirl of woe he feels, a deep stupor steals over him, as\nover the man who bleeds to death, for conscience is the wound, and\nthere’s naught to staunch it;", "labels": {"50": 9, "100": 1, "250": 42, "500": 225, "1000": 589, "2000": 1441}}, {"id": 815, "position": 815, "text": "conscience is the wound, and\nthere’s naught to staunch it; so, after sore wrestlings in his berth,\nJonah’s prodigy of ponderous misery drags him drowning down to sleep.", "labels": {"50": 48, "100": 20, "250": 49, "500": 78, "1000": 933, "2000": 1081}}, {"id": 816, "position": 816, "text": "him drowning down to sleep.\n\n“And now the time of tide has come; the ship casts off her cables; and\nfrom the deserted wharf the uncheered ship for Tarshish, all careening,\nglides to sea", "labels": {"50": 16, "100": 73, "250": 240, "500": 104, "1000": 779, "2000": 16}}, {"id": 817, "position": 817, "text": "shish, all careening,\nglides to sea. That ship, my friends, was the first of recorded\nsmugglers! the contraband was Jonah. But the sea rebels; he will not\nbear the wicked burden", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 818, "position": 818, "text": "rebels; he will not\nbear the wicked burden. A dreadful storm comes on, the ship is like to\nbreak. But now when the boatswain calls all hands to lighten her; when\nboxes, bales, and jars are clattering", "labels": {"50": 45, "100": 64, "250": 148, "500": 28, "1000": 165, "2000": 83}}, {"id": 819, "position": 819, "text": "en her; when\nboxes, bales, and jars are clattering overboard; when the wind is\nshrieking, and the men are yelling, and every plank thunders with\ntrampling feet right over Jonah’s head; in all this raging", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 820, "position": 820, "text": "with\ntrampling feet right over Jonah’s head; in all this raging tumult,\nJonah sleeps his hideous sleep. He sees no black sky and raging sea,\nfeels not the reeling timbers, and little hears he or heeds he the far", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 821, "position": 821, "text": "not the reeling timbers, and little hears he or heeds he the far\nrush of the mighty whale, which even now with open mouth is cleaving\nthe seas after him. Aye, shipmates, Jonah was gone down into the sides\nof the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 822, "position": 822, "text": ". Aye, shipmates, Jonah was gone down into the sides\nof the ship—a berth in the cabin as I have taken it, and was fast\nasleep. But the frightened master comes to him, and shrieks in his dead\near, ‘", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 823, "position": 823, "text": "frightened master comes to him, and shrieks in his dead\near, ‘What meanest thou, O, sleeper! arise!’ Startled from his lethargy\nby that direful cry, Jonah staggers to his feet, and stumbling to", "labels": {"50": 35, "100": 94, "250": 23, "500": 159, "1000": 989, "2000": 1470}}, {"id": 824, "position": 824, "text": "direful cry, Jonah staggers to his feet, and stumbling to the\ndeck, grasps a shroud, to look out upon the sea. But at that moment he\nis sprung upon by a panther billow leaping over the bulwark", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 825, "position": 825, "text": "he\nis sprung upon by a panther billow leaping over the bulwarks. Wave\nafter wave thus leaps into the ship, and finding no speedy vent runs\nroaring fore and aft, till the mariners come nigh to drowning while yet\nafloat", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 826, "position": 826, "text": "aft, till the mariners come nigh to drowning while yet\nafloat. And ever, as the white moon shows her affrighted face from the\nsteep gullies in the blackness overhead, aghast Jonah sees the rearing\nbowspr", "labels": {"50": 9, "100": 64, "250": 138, "500": 143, "1000": 327, "2000": 1620}}, {"id": 827, "position": 827, "text": "in the blackness overhead, aghast Jonah sees the rearing\nbowsprit pointing high upward, but soon beat downward again towards the\ntormented deep.\n\n“Terrors upon terrors run shouting through his soul", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 828, "position": 828, "text": "s run shouting through his soul. In all his\ncringing attitudes, the God-fugitive is now too plainly known. The\nsailors mark him; more and more certain grow their suspicions of him,\nand at last, fully to test the truth, by", "labels": {"50": 9, "100": 64, "250": 49, "500": 73, "1000": 165, "2000": 16}}, {"id": 829, "position": 829, "text": "suspicions of him,\nand at last, fully to test the truth, by referring the whole matter to\nhigh Heaven, they fall to casting lots, to see for whose cause this\ngreat tempest was upon them. The lot is Jonah’s; that discovered", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 201, "2000": 1945}}, {"id": 830, "position": 830, "text": "great tempest was upon them. The lot is Jonah’s; that discovered, then\nhow furiously they mob him with their questions. ‘What is thine\noccupation? Whence comest thou? Thy country? What people? But mark now,\nmy", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 831, "position": 831, "text": "comest thou? Thy country? What people? But mark now,\nmy shipmates, the behavior of poor Jonah. The eager mariners but ask\nhim who he is, and where from; whereas, they not only receive an answer\nto those questions,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 832, "position": 832, "text": "where from; whereas, they not only receive an answer\nto those questions, but likewise another answer to a question not put\nby them, but the unsolicited answer is forced from Jonah by the hard\nhand of God that is upon him.", "labels": {"50": 35, "100": 94, "250": 112, "500": 373, "1000": 201, "2000": 172}}, {"id": 833, "position": 833, "text": "forced from Jonah by the hard\nhand of God that is upon him.\n\n“‘I am a Hebrew,’ he cries—and then—‘I fear the Lord the God of Heaven\nwho hath made the sea and the dry land!’ Fear", "labels": {"50": 27, "100": 33, "250": 112, "500": 44, "1000": 503, "2000": 84}}, {"id": 834, "position": 834, "text": "of Heaven\nwho hath made the sea and the dry land!’ Fear him, O Jonah? Aye, well\nmightest thou fear the Lord God _then!_ Straightway, he now goes on to\nmake a full confession; whereupon the mariners", "labels": {"50": 27, "100": 33, "250": 112, "500": 198, "1000": 654, "2000": 1893}}, {"id": 835, "position": 835, "text": "way, he now goes on to\nmake a full confession; whereupon the mariners became more and more\nappalled, but still are pitiful. For when Jonah, not yet supplicating\nGod for mercy, since he but too well knew the darkness of", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 624, "2000": 859}}, {"id": 836, "position": 836, "text": "licating\nGod for mercy, since he but too well knew the darkness of his\ndeserts,—when wretched Jonah cries out to them to take him and cast him\nforth into the sea, for he knew that for _his_ sake this great tempest", "labels": {"50": 35, "100": 94, "250": 23, "500": 198, "1000": 201, "2000": 172}}, {"id": 837, "position": 837, "text": "the sea, for he knew that for _his_ sake this great tempest\nwas upon them; they mercifully turn from him, and seek by other means\nto save the ship. But all in vain; the indignant gale howls louder;", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 838, "position": 838, "text": "ship. But all in vain; the indignant gale howls louder;\nthen, with one hand raised invokingly to God, with the other they not\nunreluctantly lay hold of Jonah.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 839, "position": 839, "text": "tantly lay hold of Jonah.\n\n“And now behold Jonah taken up as an anchor and dropped into the sea;\nwhen instantly an oily calmness floats out from the east, and the sea\nis still, as Jonah carries down the gale with him", "labels": {"50": 27, "100": 64, "250": 112, "500": 44, "1000": 503, "2000": 1620}}, {"id": 840, "position": 840, "text": ", and the sea\nis still, as Jonah carries down the gale with him, leaving smooth water\nbehind. He goes down in the whirling heart of such a masterless\ncommotion that he scarce heeds the moment when he drops seething into\nthe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 841, "position": 841, "text": "commotion that he scarce heeds the moment when he drops seething into\nthe yawning jaws awaiting him; and the whale shoots-to all his ivory\nteeth, like so many white bolts, upon his prison", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 842, "position": 842, "text": "many white bolts, upon his prison. Then Jonah prayed\nunto the Lord out of the fish’s belly. But observe his prayer, and\nlearn a weighty lesson. For sinful as he is, Jonah does not weep and\nwail for direct", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 843, "position": 843, "text": "sinful as he is, Jonah does not weep and\nwail for direct deliverance. He feels that his dreadful punishment is\njust. He leaves all his deliverance to God, contenting himself with\nthis, that spite of all his pains and pang", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 624, "2000": 172}}, {"id": 844, "position": 844, "text": ", contenting himself with\nthis, that spite of all his pains and pangs, he will still look towards\nHis holy temple. And here, shipmates, is true and faithful repentance;\nnot clamorous for pardon, but grateful for", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 448, "2000": 958}}, {"id": 845, "position": 845, "text": "faithful repentance;\nnot clamorous for pardon, but grateful for punishment. And how pleasing\nto God was this conduct in Jonah, is shown in the eventual deliverance\nof him from the sea and the whale", "labels": {"50": 35, "100": 33, "250": 23, "500": 159, "1000": 654, "2000": 608}}, {"id": 846, "position": 846, "text": "of him from the sea and the whale. Shipmates, I do not place Jonah\nbefore you to be copied for his sin but I do place him before you as a\nmodel for repentance. Sin not; but if you do, take hee", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 624, "2000": 1464}}, {"id": 847, "position": 847, "text": "for repentance. Sin not; but if you do, take heed to repent of it\nlike Jonah.”\n\nWhile he was speaking these words, the howling of the shrieking,\nslanting storm without seemed to add new power to the", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 848, "position": 848, "text": "the shrieking,\nslanting storm without seemed to add new power to the preacher, who,\nwhen describing Jonah’s sea-storm, seemed tossed by a storm himself.\nHis deep chest heaved as with a ground-swell; his tossed arms seemed", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 849, "position": 849, "text": "His deep chest heaved as with a ground-swell; his tossed arms seemed\nthe warring elements at work; and the thunders that rolled away from\noff his swarthy brow, and the light leaping from his eye, made all his\nsimple hearers", "labels": {"50": 16, "100": 73, "250": 240, "500": 122, "1000": 779, "2000": 1058}}, {"id": 850, "position": 850, "text": ", and the light leaping from his eye, made all his\nsimple hearers look on him with a quick fear that was strange to them.\n\nThere now came a lull in his look, as he silently turned over the\nleaves of the Book once more", "labels": {"50": 22, "100": 51, "250": 38, "500": 335, "1000": 496, "2000": 1902}}, {"id": 851, "position": 851, "text": "his look, as he silently turned over the\nleaves of the Book once more; and, at last, standing motionless, with\nclosed eyes, for the moment, seemed communing with God and himself.", "labels": {"50": 22, "100": 78, "250": 140, "500": 335, "1000": 473, "2000": 396}}, {"id": 852, "position": 852, "text": "ing with God and himself.\n\nBut again he leaned over towards the people, and bowing his head lowly,\nwith an aspect of the deepest yet manliest humility, he spake these\nwords:\n\n“Shipmates, God has laid but one hand", "labels": {"50": 35, "100": 64, "250": 138, "500": 198, "1000": 730, "2000": 1893}}, {"id": 853, "position": 853, "text": "spake these\nwords:\n\n“Shipmates, God has laid but one hand upon you; both his hands press\nupon me. I have read ye by what murky light may be mine the lesson that\nJonah teaches to all sinners; and therefore to", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 854, "position": 854, "text": "be mine the lesson that\nJonah teaches to all sinners; and therefore to ye, and still more to\nme, for I am a greater sinner than ye. And now how gladly would I come\ndown from this mast-head and sit on the", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 624, "2000": 859}}, {"id": 855, "position": 855, "text": "how gladly would I come\ndown from this mast-head and sit on the hatches there where you sit,\nand listen as you listen, while some one of you reads _me_ that other\nand more awful lesson which Jonah teaches to _me_", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 856, "position": 856, "text": "me_ that other\nand more awful lesson which Jonah teaches to _me_, as a pilot of the\nliving God. How being an anointed pilot-prophet, or speaker of true\nthings, and bidden by the Lord to sound those un", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 327, "2000": 1620}}, {"id": 857, "position": 857, "text": "speaker of true\nthings, and bidden by the Lord to sound those unwelcome truths in the\nears of a wicked Nineveh, Jonah, appalled at the hostility he should\nraise, fled from his mission, and sought to escape his duty", "labels": {"50": 27, "100": 33, "250": 112, "500": 44, "1000": 503, "2000": 84}}, {"id": 858, "position": 858, "text": "he should\nraise, fled from his mission, and sought to escape his duty and his God\nby taking ship at Joppa. But God is everywhere; Tarshish he never\nreached. As we have seen, God came upon him in the whale,", "labels": {"50": 35, "100": 94, "250": 23, "500": 159, "1000": 624, "2000": 1620}}, {"id": 859, "position": 859, "text": "reached. As we have seen, God came upon him in the whale, and swallowed\nhim down to living gulfs of doom, and with swift slantings tore him\nalong ‘into the midst of the seas,’ where the eddying depths sucked him", "labels": {"50": 9, "100": 26, "250": 138, "500": 72, "1000": 654, "2000": 1620}}, {"id": 860, "position": 860, "text": "into the midst of the seas,’ where the eddying depths sucked him\nten thousand fathoms down, and ‘the weeds were wrapped about his head,’\nand all the watery world of woe bowled over him", "labels": {"50": 45, "100": 64, "250": 161, "500": 28, "1000": 730, "2000": 1766}}, {"id": 861, "position": 861, "text": "the watery world of woe bowled over him. Yet even then beyond\nthe reach of any plummet—‘out of the belly of hell’—when the whale\ngrounded upon the ocean’s utmost bones, even then, God heard the\nengul", "labels": {"50": 9, "100": 26, "250": 240, "500": 72, "1000": 779, "2000": 1620}}, {"id": 862, "position": 862, "text": "the ocean’s utmost bones, even then, God heard the\nengulphed, repenting prophet when he cried. Then God spake unto the\nfish; and from the shuddering cold and blackness of the sea, the whale\ncame breeching up", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 863, "position": 863, "text": "the shuddering cold and blackness of the sea, the whale\ncame breeching up towards the warm and pleasant sun, and all the\ndelights of air and earth; and ‘vomited out Jonah upon the dry land;’\nwhen the word of the Lord", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 16}}, {"id": 864, "position": 864, "text": "ed out Jonah upon the dry land;’\nwhen the word of the Lord came a second time; and Jonah, bruised and\nbeaten—his ears, like two sea-shells, still multitudinously murmuring\nof the ocean—Jonah did the", "labels": {"50": 27, "100": 33, "250": 194, "500": 44, "1000": 503, "2000": 84}}, {"id": 865, "position": 865, "text": ", still multitudinously murmuring\nof the ocean—Jonah did the Almighty’s bidding. And what was that,\nshipmates? To preach the Truth to the face of Falsehood! That was it!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 866, "position": 866, "text": "of Falsehood! That was it!\n\n“This, shipmates, this is that other lesson; and woe to that pilot of\nthe living God who slights it. Woe to him whom this world charms from\nGospel duty! Woe to", "labels": {"50": 35, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 867, "position": 867, "text": "Woe to him whom this world charms from\nGospel duty! Woe to him who seeks to pour oil upon the waters when God\nhas brewed them into a gale! Woe to him who seeks to please rather than\nto appal! Woe", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 10}}, {"id": 868, "position": 868, "text": "e to him who seeks to please rather than\nto appal! Woe to him whose good name is more to him than goodness! Woe\nto him who, in this world, courts not dishonor! Woe to him who would\nnot", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 19, "2000": 1275}}, {"id": 869, "position": 869, "text": "world, courts not dishonor! Woe to him who would\nnot be true, even though to be false were salvation! Yea, woe to him\nwho, as the great Pilot Paul has it, while preaching to others is\nhimself a", "labels": {"50": 9, "100": 26, "250": 120, "500": 198, "1000": 437, "2000": 1208}}, {"id": 870, "position": 870, "text": "as the great Pilot Paul has it, while preaching to others is\nhimself a castaway!”\n\nHe dropped and fell away from himself for a moment; then lifting his\nface to them again, showed a deep joy in his eyes, as he cried out", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 7, "2000": 1902}}, {"id": 871, "position": 871, "text": "them again, showed a deep joy in his eyes, as he cried out with\na heavenly enthusiasm,—“But oh! shipmates! on the starboard hand of\nevery woe, there is a sure delight; and higher the top of that delight", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 872, "position": 872, "text": "e, there is a sure delight; and higher the top of that delight,\nthan the bottom of the woe is deep. Is not the main-truck higher than\nthe kelson is low? Delight is to him—a far, far upward", "labels": {"50": 31, "100": 20, "250": 13, "500": 414, "1000": 747, "2000": 1050}}, {"id": 873, "position": 873, "text": "kelson is low? Delight is to him—a far, far upward, and inward\ndelight—who against the proud gods and commodores of this earth, ever\nstands forth his own inexorable self", "labels": {"50": 31, "100": 75, "250": 13, "500": 307, "1000": 343, "2000": 1394}}, {"id": 874, "position": 874, "text": "his own inexorable self. Delight is to him whose strong\narms yet support him, when the ship of this base treacherous world has\ngone down beneath him. Delight is to him, who gives no quarter in the\ntruth, and kills, burns", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 193}}, {"id": 875, "position": 875, "text": "to him, who gives no quarter in the\ntruth, and kills, burns, and destroys all sin though he pluck it out\nfrom under the robes of Senators and Judges. Delight,—top-gallant\ndelight is to him, who acknowledges no law", "labels": {"50": 9, "100": 26, "250": 133, "500": 198, "1000": 511, "2000": 1208}}, {"id": 876, "position": 876, "text": "Delight,—top-gallant\ndelight is to him, who acknowledges no law or lord, but the Lord his\nGod, and is only a patriot to heaven. Delight is to him, whom all the\nwaves of the billows of the seas of the", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 573}}, {"id": 877, "position": 877, "text": "him, whom all the\nwaves of the billows of the seas of the boisterous mob can never shake\nfrom this sure Keel of the Ages. And eternal delight and deliciousness\nwill be his, who coming to lay him down, can say with", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 343, "2000": 709}}, {"id": 878, "position": 878, "text": "ness\nwill be his, who coming to lay him down, can say with his final\nbreath—O Father!—chiefly known to me by Thy rod—mortal or immortal,\nhere I die. I have striven to be Thine, more than", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 1203}}, {"id": 879, "position": 879, "text": "here I die. I have striven to be Thine, more than to be this world’s,\nor mine own. Yet this is nothing: I leave eternity to Thee; for what is\nman that he should live out the lifetime of his", "labels": {"50": 40, "100": 83, "250": 182, "500": 27, "1000": 574, "2000": 1570}}, {"id": 880, "position": 880, "text": "Thee; for what is\nman that he should live out the lifetime of his God?”\n\nHe said no more, but slowly waving a benediction, covered his face with\nhis hands, and so remained kneeling, till all the people had departed,\nand", "labels": {"50": 26, "100": 10, "250": 226, "500": 30, "1000": 335, "2000": 1843}}, {"id": 881, "position": 881, "text": "hands, and so remained kneeling, till all the people had departed,\nand he was left alone in the place.\n\n\nCHAPTER 10. A Bosom Friend.\n\nReturning to the Spouter-Inn from the Chapel, I found Queequeg there", "labels": {"50": 20, "100": 17, "250": 219, "500": 382, "1000": 348, "2000": 70}}, {"id": 882, "position": 882, "text": "outer-Inn from the Chapel, I found Queequeg there\nquite alone; he having left the Chapel before the benediction some\ntime. He was sitting on a bench before the fire, with his feet on the\nstove hearth, and in", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 851, "2000": 1620}}, {"id": 883, "position": 883, "text": "bench before the fire, with his feet on the\nstove hearth, and in one hand was holding close up to his face that\nlittle negro idol of his; peering hard into its face, and with a\njack-knife gently whittling away at its", "labels": {"50": 41, "100": 21, "250": 174, "500": 147, "1000": 58, "2000": 361}}, {"id": 884, "position": 884, "text": "face, and with a\njack-knife gently whittling away at its nose, meanwhile humming to\nhimself in his heathenish way.\n\nBut being now interrupted, he put up the image; and pretty soon, going\nto the table, took up", "labels": {"50": 30, "100": 88, "250": 219, "500": 240, "1000": 325, "2000": 820}}, {"id": 885, "position": 885, "text": "up the image; and pretty soon, going\nto the table, took up a large book there, and placing it on his lap\nbegan counting the pages with deliberate regularity; at every fiftieth\npage—as I fancied—stopping", "labels": {"50": 20, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 886, "position": 886, "text": "at every fiftieth\npage—as I fancied—stopping a moment, looking vacantly around him, and\ngiving utterance to a long-drawn gurgling whistle of astonishment. He\nwould then begin again at the next fifty;", "labels": {"50": 20, "100": 41, "250": 156, "500": 134, "1000": 421, "2000": 1559}}, {"id": 887, "position": 887, "text": "ling whistle of astonishment. He\nwould then begin again at the next fifty; seeming to commence at number\none each time, as though he could not count more than fifty, and it was\nonly by such a large number of fifties being found together, that", "labels": {"50": 39, "100": 86, "250": 144, "500": 464, "1000": 660, "2000": 258}}, {"id": 888, "position": 888, "text": "it was\nonly by such a large number of fifties being found together, that his\nastonishment at the multitude of pages was excited.\n\nWith much interest I sat watching him. Savage though he was, and\nhideously marred about the face—at least to my", "labels": {"50": 25, "100": 41, "250": 156, "500": 128, "1000": 329, "2000": 1099}}, {"id": 889, "position": 889, "text": "he was, and\nhideously marred about the face—at least to my taste—his countenance\nyet had a something in it which was by no means disagreeable. You\ncannot hide the soul. Through all his unearthly tattooings,", "labels": {"50": 25, "100": 41, "250": 156, "500": 128, "1000": 329, "2000": 1099}}, {"id": 890, "position": 890, "text": "You\ncannot hide the soul. Through all his unearthly tattooings, I thought I\nsaw the traces of a simple honest heart; and in his large, deep eyes,\nfiery black and bold, there seemed tokens of a spirit that would dare", "labels": {"50": 12, "100": 13, "250": 65, "500": 227, "1000": 580, "2000": 668}}, {"id": 891, "position": 891, "text": "fiery black and bold, there seemed tokens of a spirit that would dare a\nthousand devils. And besides all this, there was a certain lofty\nbearing about the Pagan, which even his uncouthness could not\naltogether maim", "labels": {"50": 18, "100": 87, "250": 102, "500": 205, "1000": 621, "2000": 1968}}, {"id": 892, "position": 892, "text": "which even his uncouthness could not\naltogether maim. He looked like a man who had never cringed and never\nhad had a creditor. Whether it was, too, that his head being shaved,\nhis forehead was drawn out in freer", "labels": {"50": 23, "100": 88, "250": 219, "500": 163, "1000": 460, "2000": 1927}}, {"id": 893, "position": 893, "text": ", that his head being shaved,\nhis forehead was drawn out in freer and brighter relief, and looked\nmore expansive than it otherwise would, this I will not venture to\ndecide; but certain it was his head was phrenologically an excellent\none", "labels": {"50": 44, "100": 37, "250": 143, "500": 286, "1000": 858, "2000": 955}}, {"id": 894, "position": 894, "text": "; but certain it was his head was phrenologically an excellent\none. It may seem ridiculous, but it reminded me of General Washington’s\nhead, as seen in the popular busts of him", "labels": {"50": 48, "100": 27, "250": 196, "500": 339, "1000": 878, "2000": 955}}, {"id": 895, "position": 895, "text": "the popular busts of him. It had the same long\nregularly graded retreating slope from above the brows, which were\nlikewise very projecting, like two long promontories thickly wooded on\ntop. Queequeg was George Washington cannibalistic", "labels": {"50": 12, "100": 38, "250": 65, "500": 344, "1000": 954, "2000": 1786}}, {"id": 896, "position": 896, "text": "wooded on\ntop. Queequeg was George Washington cannibalistically developed.\n\nWhilst I was thus closely scanning him, half-pretending meanwhile to be\nlooking out at the storm from the casement, he never heeded my\npresence, never", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 897, "position": 897, "text": "the storm from the casement, he never heeded my\npresence, never troubled himself with so much as a single glance; but\nappeared wholly occupied with counting the pages of the marvellous\nbook. Considering how sociably we had been sleeping together the", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 1645}}, {"id": 898, "position": 898, "text": "marvellous\nbook. Considering how sociably we had been sleeping together the night\nprevious, and especially considering the affectionate arm I had found\nthrown over me upon waking in the morning, I thought this indifference\nof his very strange", "labels": {"50": 25, "100": 41, "250": 176, "500": 443, "1000": 329, "2000": 1645}}, {"id": 899, "position": 899, "text": "morning, I thought this indifference\nof his very strange. But savages are strange beings; at times you do\nnot know exactly how to take them. At first they are overawing; their\ncalm self-collectedness of simplicity seems a Socratic", "labels": {"50": 44, "100": 68, "250": 241, "500": 440, "1000": 299, "2000": 1113}}, {"id": 900, "position": 900, "text": "awing; their\ncalm self-collectedness of simplicity seems a Socratic wisdom. I had\nnoticed also that Queequeg never consorted at all, or but very little,\nwith the other seamen in the inn", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 901, "position": 901, "text": "little,\nwith the other seamen in the inn. He made no advances whatever;\nappeared to have no desire to enlarge the circle of his acquaintances.\nAll this struck me as mighty singular; yet, upon second thoughts, there\nwas something almost sublime", "labels": {"50": 25, "100": 28, "250": 156, "500": 407, "1000": 329, "2000": 1645}}, {"id": 902, "position": 902, "text": "as mighty singular; yet, upon second thoughts, there\nwas something almost sublime in it. Here was a man some twenty thousand\nmiles from home, by the way of Cape Horn, that is—which was the only\nway he could get there—thrown", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 887}}, {"id": 903, "position": 903, "text": ", that is—which was the only\nway he could get there—thrown among people as strange to him as though\nhe were in the planet Jupiter; and yet he seemed entirely at his ease;\npreserving the utmost serenity; content with his own companions", "labels": {"50": 23, "100": 88, "250": 219, "500": 404, "1000": 406, "2000": 498}}, {"id": 904, "position": 904, "text": "at his ease;\npreserving the utmost serenity; content with his own companionship;\nalways equal to himself. Surely this was a touch of fine philosophy;\nthough no doubt he had never heard there was such a thing as that", "labels": {"50": 44, "100": 37, "250": 229, "500": 481, "1000": 984, "2000": 825}}, {"id": 905, "position": 905, "text": "had never heard there was such a thing as that. But,\nperhaps, to be true philosophers, we mortals should not be conscious of\nso living or so striving. So soon as I hear that such or such a man\ngives himself out for", "labels": {"50": 46, "100": 69, "250": 248, "500": 259, "1000": 570, "2000": 773}}, {"id": 906, "position": 906, "text": "So soon as I hear that such or such a man\ngives himself out for a philosopher, I conclude that, like the\ndyspeptic old woman, he must have “broken his digester.”", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 35, "2000": 1735}}, {"id": 907, "position": 907, "text": "broken his digester.”\n\nAs I sat there in that now lonely room; the fire burning low, in that\nmild stage when, after its first intensity has warmed the air, it then\nonly glows to be looked at; the evening shades and", "labels": {"50": 25, "100": 41, "250": 132, "500": 128, "1000": 964, "2000": 1099}}, {"id": 908, "position": 908, "text": ", it then\nonly glows to be looked at; the evening shades and phantoms gathering\nround the casements, and peering in upon us silent, solitary twain; the\nstorm booming without in solemn swells; I began to be sensible of\nstrange feelings", "labels": {"50": 20, "100": 5, "250": 26, "500": 412, "1000": 914, "2000": 1254}}, {"id": 909, "position": 909, "text": "booming without in solemn swells; I began to be sensible of\nstrange feelings. I felt a melting in me. No more my splintered heart\nand maddened hand were turned against the wolfish world. This soothing\nsavage had redeemed it", "labels": {"50": 20, "100": 5, "250": 45, "500": 411, "1000": 818, "2000": 1812}}, {"id": 910, "position": 910, "text": "against the wolfish world. This soothing\nsavage had redeemed it. There he sat, his very indifference speaking a\nnature in which there lurked no civilized hypocrisies and bland\ndeceits", "labels": {"50": 0, "100": 4, "250": 114, "500": 341, "1000": 649, "2000": 446}}, {"id": 911, "position": 911, "text": "risies and bland\ndeceits. Wild he was; a very sight of sights to see; yet I began to\nfeel myself mysteriously drawn towards him. And those same things that\nwould have repelled most others, they were the very magnets that", "labels": {"50": 20, "100": 28, "250": 132, "500": 128, "1000": 21, "2000": 1254}}, {"id": 912, "position": 912, "text": "that\nwould have repelled most others, they were the very magnets that thus\ndrew me. I’ll try a pagan friend, thought I, since Christian kindness\nhas proved but hollow courtesy. I drew my bench near him, and made some\nfriendly", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 483, "2000": 1812}}, {"id": 913, "position": 913, "text": "but hollow courtesy. I drew my bench near him, and made some\nfriendly signs and hints, doing my best to talk with him meanwhile. At\nfirst he little noticed these advances; but presently, upon my\nreferring to his last night’s hospitalities", "labels": {"50": 25, "100": 5, "250": 156, "500": 412, "1000": 483, "2000": 1149}}, {"id": 914, "position": 914, "text": "; but presently, upon my\nreferring to his last night’s hospitalities, he made out to ask me\nwhether we were again to be bedfellows. I told him yes; whereat I\nthought he looked pleased, perhaps a little complimented.", "labels": {"50": 20, "100": 56, "250": 186, "500": 134, "1000": 421, "2000": 1068}}, {"id": 915, "position": 915, "text": "yes; whereat I\nthought he looked pleased, perhaps a little complimented.\n\nWe then turned over the book together, and I endeavored to explain to\nhim the purpose of the printing, and the meaning of the few pictures\nthat were in it", "labels": {"50": 20, "100": 28, "250": 175, "500": 128, "1000": 363, "2000": 225}}, {"id": 916, "position": 916, "text": "printing, and the meaning of the few pictures\nthat were in it. Thus I soon engaged his interest; and from that we\nwent to jabbering the best we could about the various outer sights to\nbe seen in this famous town", "labels": {"50": 44, "100": 28, "250": 175, "500": 294, "1000": 363, "2000": 221}}, {"id": 917, "position": 917, "text": "the various outer sights to\nbe seen in this famous town. Soon I proposed a social smoke; and,\nproducing his pouch and tomahawk, he quietly offered me a puff. And\nthen we sat exchanging puffs from that wild pipe of his,", "labels": {"50": 25, "100": 5, "250": 156, "500": 134, "1000": 329, "2000": 1559}}, {"id": 918, "position": 918, "text": ". And\nthen we sat exchanging puffs from that wild pipe of his, and keeping it\nregularly passing between us.\n\nIf there yet lurked any ice of indifference towards me in the Pagan’s\nbreast, this pleasant, genial smoke we had,", "labels": {"50": 25, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 919, "position": 919, "text": "the Pagan’s\nbreast, this pleasant, genial smoke we had, soon thawed it out, and\nleft us cronies. He seemed to take to me quite as naturally and\nunbiddenly as I to him; and when our", "labels": {"50": 20, "100": 5, "250": 156, "500": 128, "1000": 421, "2000": 1559}}, {"id": 920, "position": 920, "text": "as naturally and\nunbiddenly as I to him; and when our smoke was over, he pressed his\nforehead against mine, clasped me round the waist, and said that\nhenceforth we were married; meaning, in his country’s phrase,", "labels": {"50": 20, "100": 28, "250": 125, "500": 349, "1000": 651, "2000": 896}}, {"id": 921, "position": 921, "text": "henceforth we were married; meaning, in his country’s phrase, that we\nwere bosom friends; he would gladly die for me, if need should be. In a\ncountryman, this sudden flame of friendship would have seemed far too\npremature", "labels": {"50": 49, "100": 56, "250": 126, "500": 177, "1000": 20, "2000": 1146}}, {"id": 922, "position": 922, "text": "a\ncountryman, this sudden flame of friendship would have seemed far too\npremature, a thing to be much distrusted; but in this simple savage\nthose old rules would not apply.\n\nAfter supper, and another social chat and smoke, we went to our", "labels": {"50": 12, "100": 93, "250": 55, "500": 318, "1000": 585, "2000": 1138}}, {"id": 923, "position": 923, "text": ".\n\nAfter supper, and another social chat and smoke, we went to our room\ntogether. He made me a present of his embalmed head; took out his\nenormous tobacco wallet, and groping under the tobacco, drew out some\nthirty dollars in", "labels": {"50": 39, "100": 57, "250": 47, "500": 39, "1000": 346, "2000": 1426}}, {"id": 924, "position": 924, "text": "wallet, and groping under the tobacco, drew out some\nthirty dollars in silver; then spreading them on the table, and\nmechanically dividing them into two equal portions, pushed one of them\ntowards me, and said it was mine", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 494, "2000": 1426}}, {"id": 925, "position": 925, "text": "of them\ntowards me, and said it was mine. I was going to remonstrate; but he\nsilenced me by pouring them into my trowsers’ pockets. I let them stay.\nHe then went about his evening prayers, took out", "labels": {"50": 32, "100": 25, "250": 93, "500": 362, "1000": 34, "2000": 196}}, {"id": 926, "position": 926, "text": "I let them stay.\nHe then went about his evening prayers, took out his idol, and removed\nthe paper fireboard. By certain signs and symptoms, I thought he seemed\nanxious for me to join him; but well knowing what was to follow,", "labels": {"50": 12, "100": 13, "250": 65, "500": 171, "1000": 286, "2000": 309}}, {"id": 927, "position": 927, "text": "anxious for me to join him; but well knowing what was to follow, I\ndeliberated a moment whether, in case he invited me, I would comply or\notherwise.\n\nI was a good Christian; born and bred in the bosom of the in", "labels": {"50": 25, "100": 5, "250": 125, "500": 134, "1000": 651, "2000": 652}}, {"id": 928, "position": 928, "text": "was a good Christian; born and bred in the bosom of the infallible\nPresbyterian Church. How then could I unite with this wild idolator in\nworshipping his piece of wood? But what is worship? thought I", "labels": {"50": 25, "100": 28, "250": 169, "500": 59, "1000": 21, "2000": 1615}}, {"id": 929, "position": 929, "text": "of wood? But what is worship? thought I. Do you\nsuppose now, Ishmael, that the magnanimous God of heaven and\nearth—pagans and all included—can possibly be jealous of an\ninsignificant bit of black wood? Impossible", "labels": {"50": 10, "100": 75, "250": 129, "500": 307, "1000": 343, "2000": 1201}}, {"id": 930, "position": 930, "text": "included—can possibly be jealous of an\ninsignificant bit of black wood? Impossible! But what is worship?—to do\nthe will of God—_that_ is worship. And what is the will of God?—to do\nto my fellow man", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 624, "2000": 859}}, {"id": 931, "position": 931, "text": "And what is the will of God?—to do\nto my fellow man what I would have my fellow man to do to me—_that_ is\nthe will of God. Now, Queequeg is my fellow man", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 616, "2000": 1464}}, {"id": 932, "position": 932, "text": ". Now, Queequeg is my fellow man. And what do I wish\nthat this Queequeg would do to me? Why, unite with me in my particular\nPresbyterian form of worship. Consequently, I must then unite with him\nin", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 933, "position": 933, "text": "particular\nPresbyterian form of worship. Consequently, I must then unite with him\nin his; ergo, I must turn idolator. So I kindled the shavings; helped\nprop up the innocent little idol; offered him burnt biscuit with\nQue", "labels": {"50": 5, "100": 30, "250": 40, "500": 59, "1000": 391, "2000": 1615}}, {"id": 934, "position": 934, "text": "helped\nprop up the innocent little idol; offered him burnt biscuit with\nQueequeg; salamed before him twice or thrice; kissed his nose; and that\ndone, we undressed and went to bed, at peace with our own", "labels": {"50": 32, "100": 42, "250": 56, "500": 55, "1000": 222, "2000": 1689}}, {"id": 935, "position": 935, "text": "done, we undressed and went to bed, at peace with our own consciences\nand all the world. But we did not go to sleep without some little chat.\n\nHow it is I know not; but there is no place like a bed for", "labels": {"50": 31, "100": 20, "250": 13, "500": 274, "1000": 15, "2000": 1050}}, {"id": 936, "position": 936, "text": "it is I know not; but there is no place like a bed for confidential\ndisclosures between friends. Man and wife, they say, there open the\nvery bottom of their souls to each other; and some old couples often\nlie and chat over old", "labels": {"50": 31, "100": 20, "250": 69, "500": 274, "1000": 203, "2000": 1050}}, {"id": 937, "position": 937, "text": "souls to each other; and some old couples often\nlie and chat over old times till nearly morning. Thus, then, in our\nhearts’ honeymoon, lay I and Queequeg—a cosy, loving pair.\n\n\nCHAPTER 11", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 938, "position": 938, "text": "queg—a cosy, loving pair.\n\n\nCHAPTER 11. Nightgown.\n\nWe had lain thus in bed, chatting and napping at short intervals, and\nQueequeg now and then affectionately throwing his brown tattooed legs\nover mine,", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 531, "2000": 1620}}, {"id": 939, "position": 939, "text": "equeg now and then affectionately throwing his brown tattooed legs\nover mine, and then drawing them back; so entirely sociable and free\nand easy were we; when, at last, by reason of our confabulations, what\nlittle nappis", "labels": {"50": 20, "100": 26, "250": 30, "500": 475, "1000": 345, "2000": 1988}}, {"id": 940, "position": 940, "text": "last, by reason of our confabulations, what\nlittle nappishness remained in us altogether departed, and we felt like\ngetting up again, though day-break was yet some way down the future.", "labels": {"50": 25, "100": 93, "250": 55, "500": 318, "1000": 868, "2000": 1138}}, {"id": 941, "position": 941, "text": "was yet some way down the future.\n\nYes, we became very wakeful; so much so that our recumbent position\nbegan to grow wearisome, and by little and little we found ourselves\nsitting up; the clothes well tucked around us,", "labels": {"50": 25, "100": 5, "250": 156, "500": 318, "1000": 868, "2000": 572}}, {"id": 942, "position": 942, "text": "and little we found ourselves\nsitting up; the clothes well tucked around us, leaning against the\nhead-board with our four knees drawn up close together, and our two\nnoses bending over them, as if our kneepans were warming-pans", "labels": {"50": 25, "100": 41, "250": 55, "500": 318, "1000": 868, "2000": 448}}, {"id": 943, "position": 943, "text": "over them, as if our kneepans were warming-pans. We felt\nvery nice and snug, the more so since it was so chilly out of doors;\nindeed out of bed-clothes too, seeing that there was no fire", "labels": {"50": 25, "100": 93, "250": 55, "500": 318, "1000": 585, "2000": 1138}}, {"id": 944, "position": 944, "text": ";\nindeed out of bed-clothes too, seeing that there was no fire in the\nroom. The more so, I say, because truly to enjoy bodily warmth, some\nsmall part of you must be cold, for there is no quality in this world", "labels": {"50": 31, "100": 14, "250": 132, "500": 274, "1000": 203, "2000": 1849}}, {"id": 945, "position": 945, "text": "part of you must be cold, for there is no quality in this world\nthat is not what it is merely by contrast. Nothing exists in itself. If\nyou flatter yourself that you are all over comfortable, and have been\nso a long time,", "labels": {"50": 31, "100": 20, "250": 69, "500": 274, "1000": 203, "2000": 1288}}, {"id": 946, "position": 946, "text": "that you are all over comfortable, and have been\nso a long time, then you cannot be said to be comfortable any more. But\nif, like Queequeg and me in the bed, the tip of your nose or the crown\nof your", "labels": {"50": 8, "100": 14, "250": 81, "500": 274, "1000": 203, "2000": 1849}}, {"id": 947, "position": 947, "text": "me in the bed, the tip of your nose or the crown\nof your head be slightly chilled, why then, indeed, in the general\nconsciousness you feel most delightfully and unmistakably warm. For\nthis reason a sleeping apartment should never be", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 948, "position": 948, "text": "unmistakably warm. For\nthis reason a sleeping apartment should never be furnished with a fire,\nwhich is one of the luxurious discomforts of the rich. For the height\nof this sort of deliciousness is to have nothing but the blanket\nbetween you", "labels": {"50": 12, "100": 43, "250": 55, "500": 1, "1000": 554, "2000": 1138}}, {"id": 949, "position": 949, "text": "of this sort of deliciousness is to have nothing but the blanket\nbetween you and your snugness and the cold of the outer air. Then there\nyou lie like the one warm spark in the heart of an arctic crystal.", "labels": {"50": 31, "100": 20, "250": 69, "500": 274, "1000": 203, "2000": 1849}}, {"id": 950, "position": 950, "text": "one warm spark in the heart of an arctic crystal.\n\nWe had been sitting in this crouching manner for some time, when all at\nonce I thought I would open my eyes; for when between sheets, whether\nby day or by night, and whether", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 51, "2000": 1254}}, {"id": 951, "position": 951, "text": "; for when between sheets, whether\nby day or by night, and whether asleep or awake, I have a way of always\nkeeping my eyes shut, in order the more to concentrate the snugness of\nbeing in bed", "labels": {"50": 8, "100": 65, "250": 224, "500": 10, "1000": 132, "2000": 1228}}, {"id": 952, "position": 952, "text": "concentrate the snugness of\nbeing in bed. Because no man can ever feel his own identity aright\nexcept his eyes be closed; as if darkness were indeed the proper\nelement of our essences, though light be more congenial to our", "labels": {"50": 10, "100": 71, "250": 13, "500": 236, "1000": 211, "2000": 1555}}, {"id": 953, "position": 953, "text": "element of our essences, though light be more congenial to our clayey\npart. Upon opening my eyes then, and coming out of my own pleasant and\nself-created darkness into the imposed and coarse outer gloom of the\nunilluminated", "labels": {"50": 10, "100": 75, "250": 13, "500": 289, "1000": 616, "2000": 1175}}, {"id": 954, "position": 954, "text": "created darkness into the imposed and coarse outer gloom of the\nunilluminated twelve-o’clock-at-night, I experienced a disagreeable\nrevulsion. Nor did I at all object to the hint from Queequeg that\nperhaps it", "labels": {"50": 25, "100": 5, "250": 156, "500": 313, "1000": 421, "2000": 1068}}, {"id": 955, "position": 955, "text": "I at all object to the hint from Queequeg that\nperhaps it were best to strike a light, seeing that we were so wide\nawake; and besides he felt a strong desire to have a few quiet puffs\nfrom his Tomahawk", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 956, "position": 956, "text": "strong desire to have a few quiet puffs\nfrom his Tomahawk. Be it said, that though I had felt such a strong\nrepugnance to his smoking in the bed the night before, yet see how\nelastic our stiff prejudices grow", "labels": {"50": 25, "100": 28, "250": 175, "500": 407, "1000": 363, "2000": 1645}}, {"id": 957, "position": 957, "text": "the bed the night before, yet see how\nelastic our stiff prejudices grow when love once comes to bend them.\nFor now I liked nothing better than to have Queequeg smoking by me,\neven in bed, because he seemed to be full", "labels": {"50": 25, "100": 5, "250": 55, "500": 412, "1000": 483, "2000": 1149}}, {"id": 958, "position": 958, "text": "g smoking by me,\neven in bed, because he seemed to be full of such serene household joy\nthen. I no more felt unduly concerned for the landlord’s policy of\ninsurance. I was only alive to the condensed confidential\ncomfortableness of", "labels": {"50": 25, "100": 28, "250": 156, "500": 412, "1000": 329, "2000": 381}}, {"id": 959, "position": 959, "text": "policy of\ninsurance. I was only alive to the condensed confidential\ncomfortableness of sharing a pipe and a blanket with a real friend.\nWith our shaggy jackets drawn about our shoulders, we now passed the\nTomahawk from one to the other, till slowly", "labels": {"50": 12, "100": 93, "250": 209, "500": 344, "1000": 554, "2000": 990}}, {"id": 960, "position": 960, "text": "we now passed the\nTomahawk from one to the other, till slowly there grew over us a blue\nhanging tester of smoke, illuminated by the flame of the new-lit lamp.\n\nWhether it was that this undulating tester rolled the savage", "labels": {"50": 12, "100": 93, "250": 65, "500": 389, "1000": 195, "2000": 668}}, {"id": 961, "position": 961, "text": "lit lamp.\n\nWhether it was that this undulating tester rolled the savage away to\nfar distant scenes, I know not, but he now spoke of his native island;\nand, eager to hear his history, I begged him to go on and tell", "labels": {"50": 25, "100": 64, "250": 163, "500": 72, "1000": 533, "2000": 187}}, {"id": 962, "position": 962, "text": ", eager to hear his history, I begged him to go on and tell it. He\ngladly complied. Though at the time I but ill comprehended not a few of\nhis words, yet subsequent disclosures, when I had become more familiar\nwith his", "labels": {"50": 20, "100": 56, "250": 98, "500": 177, "1000": 700, "2000": 1059}}, {"id": 963, "position": 963, "text": "words, yet subsequent disclosures, when I had become more familiar\nwith his broken phraseology, now enable me to present the whole story\nsuch as it may prove in the mere skeleton I give.\n\n\nCHAPTER 12. Biographical.", "labels": {"50": 44, "100": 40, "250": 165, "500": 374, "1000": 417, "2000": 53}}, {"id": 964, "position": 964, "text": "skeleton I give.\n\n\nCHAPTER 12. Biographical.\n\nQueequeg was a native of Rokovoko, an island far away to the West and\nSouth. It is not down in any map; true places never are.", "labels": {"50": 14, "100": 29, "250": 161, "500": 13, "1000": 257, "2000": 156}}, {"id": 965, "position": 965, "text": "in any map; true places never are.\n\nWhen a new-hatched savage running wild about his native woodlands in a\ngrass clout, followed by the nibbling goats, as if he were a green\nsapling; even then, in Quee", "labels": {"50": 9, "100": 73, "250": 193, "500": 498, "1000": 637, "2000": 1886}}, {"id": 966, "position": 966, "text": "as if he were a green\nsapling; even then, in Queequeg’s ambitious soul, lurked a strong\ndesire to see something more of Christendom than a specimen whaler or\ntwo", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 967, "position": 967, "text": "than a specimen whaler or\ntwo. His father was a High Chief, a King; his uncle a High Priest; and\non the maternal side he boasted aunts who were the wives of\nunconquerable warriors", "labels": {"50": 45, "100": 42, "250": 130, "500": 494, "1000": 480, "2000": 187}}, {"id": 968, "position": 968, "text": "the wives of\nunconquerable warriors. There was excellent blood in his veins—royal\nstuff; though sadly vitiated, I fear, by the cannibal propensity he\nnourished in his untutored youth.", "labels": {"50": 13, "100": 3, "250": 65, "500": 171, "1000": 714, "2000": 1322}}, {"id": 969, "position": 969, "text": "ensity he\nnourished in his untutored youth.\n\nA Sag Harbor ship visited his father’s bay, and Queequeg sought a\npassage to Christian lands. But the ship, having her full complement of\nseamen, spur", "labels": {"50": 12, "100": 38, "250": 5, "500": 346, "1000": 532, "2000": 264}}, {"id": 970, "position": 970, "text": "Christian lands. But the ship, having her full complement of\nseamen, spurned his suit; and not all the King his father’s influence\ncould prevail. But Queequeg vowed a vow", "labels": {"50": 18, "100": 83, "250": 60, "500": 61, "1000": 730, "2000": 430}}, {"id": 971, "position": 971, "text": "Queequeg vowed a vow. Alone in his canoe, he paddled\noff to a distant strait, which he knew the ship must pass through when\nshe quitted the island. On one side was a coral reef; on the other a\nlow", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 472}}, {"id": 972, "position": 972, "text": "island. On one side was a coral reef; on the other a\nlow tongue of land, covered with mangrove thickets that grew out into\nthe water. Hiding his canoe, still afloat, among these thickets, with\nits prow seaward", "labels": {"50": 45, "100": 19, "250": 161, "500": 494, "1000": 480, "2000": 1766}}, {"id": 973, "position": 973, "text": "still afloat, among these thickets, with\nits prow seaward, he sat down in the stern, paddle low in hand; and\nwhen the ship was gliding by, like a flash he darted out; gained her\nside; with one backward", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 974, "position": 974, "text": ", like a flash he darted out; gained her\nside; with one backward dash of his foot capsized and sank his canoe;\nclimbed up the chains; and throwing himself at full length upon the\ndeck, grappled a ring-bolt there,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 975, "position": 975, "text": "full length upon the\ndeck, grappled a ring-bolt there, and swore not to let it go, though\nhacked in pieces.\n\nIn vain the captain threatened to throw him overboard; suspended a\ncutlass over his naked wrists; Queeque", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 730, "2000": 967}}, {"id": 976, "position": 976, "text": "him overboard; suspended a\ncutlass over his naked wrists; Queequeg was the son of a King, and\nQueequeg budged not. Struck by his desperate dauntlessness, and his\nwild desire to visit Christendom,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 977, "position": 977, "text": "desperate dauntlessness, and his\nwild desire to visit Christendom, the captain at last relented, and\ntold him he might make himself at home. But this fine young savage—this\nsea Prince of Wales, never saw the Captain’", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 730, "2000": 1766}}, {"id": 978, "position": 978, "text": "fine young savage—this\nsea Prince of Wales, never saw the Captain’s cabin. They put him down\namong the sailors, and made a whaleman of him. But like Czar Peter\ncontent to toil in the shipyards of foreign cities", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 979, "position": 979, "text": "like Czar Peter\ncontent to toil in the shipyards of foreign cities, Queequeg disdained\nno seeming ignominy, if thereby he might happily gain the power of\nenlightening his untutored countrymen", "labels": {"50": 47, "100": 60, "250": 6, "500": 261, "1000": 338, "2000": 47}}, {"id": 980, "position": 980, "text": "power of\nenlightening his untutored countrymen. For at bottom—so he told me—he\nwas actuated by a profound desire to learn among the Christians, the\narts whereby to make his people still happier than they were; and", "labels": {"50": 20, "100": 13, "250": 125, "500": 384, "1000": 139, "2000": 1586}}, {"id": 981, "position": 981, "text": ", the\narts whereby to make his people still happier than they were; and more\nthan that, still better than they were. But, alas! the practices of\nwhalemen soon convinced him that even Christians could be both\nmiserable and wicked; infinitely more", "labels": {"50": 45, "100": 29, "250": 34, "500": 494, "1000": 480, "2000": 385}}, {"id": 982, "position": 982, "text": "soon convinced him that even Christians could be both\nmiserable and wicked; infinitely more so, than all his father’s\nheathens. Arrived at last in old Sag Harbor; and seeing what the\nsailors did there; and then going on to Nantucket", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 778, "2000": 1004}}, {"id": 983, "position": 983, "text": "and seeing what the\nsailors did there; and then going on to Nantucket, and seeing how they\nspent their wages in _that_ place also, poor Queequeg gave it up for\nlost. Thought he, it’s a wicked world", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 54, "2000": 1620}}, {"id": 984, "position": 984, "text": "gave it up for\nlost. Thought he, it’s a wicked world in all meridians; I’ll die a\npagan.\n\nAnd thus an old idolator at heart, he yet lived among these Christians,\nwore their clothes, and tried to", "labels": {"50": 9, "100": 26, "250": 132, "500": 414, "1000": 21, "2000": 1860}}, {"id": 985, "position": 985, "text": ", he yet lived among these Christians,\nwore their clothes, and tried to talk their gibberish. Hence the queer\nways about him, though now some time from home.\n\nBy hints, I asked him whether he did not propose going back, and", "labels": {"50": 40, "100": 13, "250": 204, "500": 128, "1000": 483, "2000": 12}}, {"id": 986, "position": 986, "text": "By hints, I asked him whether he did not propose going back, and having\na coronation; since he might now consider his father dead and gone, he\nbeing very old and feeble at the last accounts", "labels": {"50": 18, "100": 83, "250": 208, "500": 51, "1000": 980, "2000": 1519}}, {"id": 987, "position": 987, "text": "feeble at the last accounts. He answered no, not\nyet; and added that he was fearful Christianity, or rather Christians,\nhad unfitted him for ascending the pure and undefiled throne of thirty\npagan Kings before him", "labels": {"50": 47, "100": 60, "250": 6, "500": 22, "1000": 572, "2000": 553}}, {"id": 988, "position": 988, "text": "undefiled throne of thirty\npagan Kings before him. But by and by, he said, he would return,—as\nsoon as he felt himself baptized again. For the nonce, however, he\nproposed to sail about, and sow his", "labels": {"50": 18, "100": 83, "250": 170, "500": 433, "1000": 47, "2000": 1325}}, {"id": 989, "position": 989, "text": "nonce, however, he\nproposed to sail about, and sow his wild oats in all four oceans. They\nhad made a harpooneer of him, and that barbed iron was in lieu of a\nsceptre now.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 990, "position": 990, "text": "barbed iron was in lieu of a\nsceptre now.\n\nI asked him what might be his immediate purpose, touching his future\nmovements. He answered, to go to sea again, in his old vocation", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 991, "position": 991, "text": ", in his old vocation. Upon\nthis, I told him that whaling was my own design, and informed him of my\nintention to sail out of Nantucket, as being the most promising port\nfor an adventurous whaleman to embark from", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 992, "position": 992, "text": "the most promising port\nfor an adventurous whaleman to embark from. He at once resolved to\naccompany me to that island, ship aboard the same vessel, get into the\nsame watch, the same boat, the same mess with me, in short to share", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1243}}, {"id": 993, "position": 993, "text": ", the same boat, the same mess with me, in short to share my\nevery hap; with both my hands in his, boldly dip into the Potluck of\nboth worlds. To all this I joyously assented; for besides", "labels": {"50": 45, "100": 64, "250": 125, "500": 349, "1000": 842, "2000": 1706}}, {"id": 994, "position": 994, "text": "of\nboth worlds. To all this I joyously assented; for besides the affection\nI now felt for Queequeg, he was an experienced harpooneer, and as such,\ncould not fail to be of great usefulness to one,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 995, "position": 995, "text": "as such,\ncould not fail to be of great usefulness to one, who, like me, was\nwholly ignorant of the mysteries of whaling, though well acquainted\nwith the sea, as known to merchant seamen.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 996, "position": 996, "text": ", as known to merchant seamen.\n\nHis story being ended with his pipe’s last dying puff, Queequeg\nembraced me, pressed his forehead against mine, and blowing out the\nlight, we rolled over from each other, this way and that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 997, "position": 997, "text": "out the\nlight, we rolled over from each other, this way and that, and very soon\nwere sleeping.\n\n\nCHAPTER 13. Wheelbarrow.\n\nNext morning, Monday, after disposing of the embalmed head to a barber,\nfor a", "labels": {"50": 45, "100": 93, "250": 55, "500": 388, "1000": 313, "2000": 1243}}, {"id": 998, "position": 998, "text": "disposing of the embalmed head to a barber,\nfor a block, I settled my own and comrade’s bill; using, however, my\ncomrade’s money. The grinning landlord, as well as the boarders, seemed\namazingly", "labels": {"50": 25, "100": 56, "250": 156, "500": 134, "1000": 345, "2000": 251}}, {"id": 999, "position": 999, "text": "money. The grinning landlord, as well as the boarders, seemed\namazingly tickled at the sudden friendship which had sprung up between\nme and Queequeg—especially as Peter Coffin’s cock and bull stories\nabout him had previously so much alarmed", "labels": {"50": 37, "100": 41, "250": 91, "500": 229, "1000": 410, "2000": 1653}}, {"id": 1000, "position": 1000, "text": "Peter Coffin’s cock and bull stories\nabout him had previously so much alarmed me concerning the very person\nwhom I now companied with.\n\nWe borrowed a wheelbarrow, and embarking our things, including my own\npoor carpet-bag, and", "labels": {"50": 25, "100": 41, "250": 55, "500": 318, "1000": 529, "2000": 1209}}, {"id": 1001, "position": 1001, "text": "and embarking our things, including my own\npoor carpet-bag, and Queequeg’s canvas sack and hammock, away we went\ndown to “the Moss,” the little Nantucket packet schooner moored at the\nwharf", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 887}}, {"id": 1002, "position": 1002, "text": "Moss,” the little Nantucket packet schooner moored at the\nwharf. As we were going along the people stared; not at Queequeg so\nmuch—for they were used to seeing cannibals like him in their\nstreets,—", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1003, "position": 1003, "text": "were used to seeing cannibals like him in their\nstreets,—but at seeing him and me upon such confidential terms. But we\nheeded them not, going along wheeling the barrow by turns, and Queequeg\nnow and then stopping", "labels": {"50": 25, "100": 93, "250": 55, "500": 318, "1000": 533, "2000": 448}}, {"id": 1004, "position": 1004, "text": "wheeling the barrow by turns, and Queequeg\nnow and then stopping to adjust the sheath on his harpoon barbs. I\nasked him why he carried such a troublesome thing with him ashore, and\nwhether all whaling ships did not find their", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1005, "position": 1005, "text": "ome thing with him ashore, and\nwhether all whaling ships did not find their own harpoons. To this, in\nsubstance, he replied, that though what I hinted was true enough, yet\nhe had a particular affection for his own harpoon, because", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1006, "position": 1006, "text": "enough, yet\nhe had a particular affection for his own harpoon, because it was of\nassured stuff, well tried in many a mortal combat, and deeply intimate\nwith the hearts of whales. In short, like many inland reapers and\nmowers,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1007, "position": 1007, "text": "of whales. In short, like many inland reapers and\nmowers, who go into the farmers’ meadows armed with their own\nscythes—though in no wise obliged to furnish them—even so, Queequeg,\nfor his", "labels": {"50": 45, "100": 2, "250": 54, "500": 246, "1000": 491, "2000": 1620}}, {"id": 1008, "position": 1008, "text": "to furnish them—even so, Queequeg,\nfor his own private reasons, preferred his own harpoon.\n\nShifting the barrow from my hand to his, he told me a funny story about\nthe first wheelbarrow he had ever seen", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1009, "position": 1009, "text": "told me a funny story about\nthe first wheelbarrow he had ever seen. It was in Sag Harbor. The\nowners of his ship, it seems, had lent him one, in which to carry his\nheavy chest to his boarding house", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 531, "2000": 1790}}, {"id": 1010, "position": 1010, "text": "one, in which to carry his\nheavy chest to his boarding house. Not to seem ignorant about the\nthing—though in truth he was entirely so, concerning the precise way in\nwhich to manage the barrow—Queequeg puts his chest upon it", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1011, "position": 1011, "text": "which to manage the barrow—Queequeg puts his chest upon it; lashes it\nfast; and then shoulders the barrow and marches up the wharf. “Why,”\nsaid I, “Queequeg, you might have known better than", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1012, "position": 1012, "text": "said I, “Queequeg, you might have known better than that, one would\nthink. Didn’t the people laugh?”\n\nUpon this, he told me another story. The people of his island of\nRokovoko, it seems", "labels": {"50": 25, "100": 13, "250": 125, "500": 349, "1000": 533, "2000": 1586}}, {"id": 1013, "position": 1013, "text": "another story. The people of his island of\nRokovoko, it seems, at their wedding feasts express the fragrant water\nof young cocoanuts into a large stained calabash like a punchbowl; and\nthis punchbowl always", "labels": {"50": 31, "100": 42, "250": 131, "500": 329, "1000": 3, "2000": 616}}, {"id": 1014, "position": 1014, "text": "calabash like a punchbowl; and\nthis punchbowl always forms the great central ornament on the braided\nmat where the feast is held. Now a certain grand merchant ship once\ntouched at Rokovoko, and its commander—", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 1015, "position": 1015, "text": "certain grand merchant ship once\ntouched at Rokovoko, and its commander—from all accounts, a very\nstately punctilious gentleman, at least for a sea captain—this\ncommander was invited to the wedding feast of Queequeg’", "labels": {"50": 45, "100": 29, "250": 86, "500": 320, "1000": 851, "2000": 156}}, {"id": 1016, "position": 1016, "text": "—this\ncommander was invited to the wedding feast of Queequeg’s sister, a\npretty young princess just turned of ten. Well; when all the wedding\nguests were assembled at the bride’s bamboo cottage, this Captain\nmarches in, and", "labels": {"50": 16, "100": 38, "250": 65, "500": 227, "1000": 714, "2000": 668}}, {"id": 1017, "position": 1017, "text": "assembled at the bride’s bamboo cottage, this Captain\nmarches in, and being assigned the post of honor, placed himself over\nagainst the punchbowl, and between the High Priest and his majesty the\nKing, Queequeg’s father", "labels": {"50": 32, "100": 42, "250": 189, "500": 297, "1000": 78, "2000": 1646}}, {"id": 1018, "position": 1018, "text": "Priest and his majesty the\nKing, Queequeg’s father. Grace being said,—for those people have their\ngrace as well as we—though Queequeg told me that unlike us, who at such\ntimes look downwards to our", "labels": {"50": 35, "100": 65, "250": 224, "500": 320, "1000": 664, "2000": 97}}, {"id": 1019, "position": 1019, "text": "g told me that unlike us, who at such\ntimes look downwards to our platters, they, on the contrary, copying\nthe ducks, glance upwards to the great Giver of all feasts—Grace, I\nsay, being said, the High", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 1020, "position": 1020, "text": "of all feasts—Grace, I\nsay, being said, the High Priest opens the banquet by the immemorial\nceremony of the island; that is, dipping his consecrated and\nconsecrating fingers into the bowl before the blessed beverage\nci", "labels": {"50": 26, "100": 42, "250": 30, "500": 16, "1000": 858, "2000": 1592}}, {"id": 1021, "position": 1021, "text": "consecrated and\nconsecrating fingers into the bowl before the blessed beverage\ncirculates. Seeing himself placed next the Priest, and noting the\nceremony, and thinking himself—being Captain of a ship—as having plain\nprecedence over a mere island King,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1022, "position": 1022, "text": "Captain of a ship—as having plain\nprecedence over a mere island King, especially in the King’s own\nhouse—the Captain coolly proceeds to wash his hands in the\npunchbowl;—taking it I suppose for a huge finger-glass", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 877}}, {"id": 1023, "position": 1023, "text": "punchbowl;—taking it I suppose for a huge finger-glass. “Now,” said\nQueequeg, “what you tink now?—Didn’t our people laugh?”", "labels": {"50": 45, "100": 64, "250": 95, "500": 72, "1000": 533, "2000": 1620}}, {"id": 1024, "position": 1024, "text": "’t our people laugh?”\n\nAt last, passage paid, and luggage safe, we stood on board the\nschooner. Hoisting sail, it glided down the Acushnet river. On one\nside, New Bedford rose in terraces of streets,", "labels": {"50": 4, "100": 38, "250": 77, "500": 47, "1000": 823, "2000": 1119}}, {"id": 1025, "position": 1025, "text": "net river. On one\nside, New Bedford rose in terraces of streets, their ice-covered trees\nall glittering in the clear, cold air. Huge hills and mountains of\ncasks on casks were piled upon her wharves, and side by", "labels": {"50": 45, "100": 64, "250": 5, "500": 162, "1000": 994, "2000": 1801}}, {"id": 1026, "position": 1026, "text": "ks on casks were piled upon her wharves, and side by side the\nworld-wandering whale ships lay silent and safely moored at last; while\nfrom others came a sound of carpenters and coopers, with blended noises\nof fires and", "labels": {"50": 40, "100": 83, "250": 170, "500": 60, "1000": 520, "2000": 1604}}, {"id": 1027, "position": 1027, "text": "a sound of carpenters and coopers, with blended noises\nof fires and forges to melt the pitch, all betokening that new cruises\nwere on the start; that one most perilous and long voyage ended, only\nbegins a second;", "labels": {"50": 48, "100": 57, "250": 137, "500": 90, "1000": 309, "2000": 1903}}, {"id": 1028, "position": 1028, "text": "one most perilous and long voyage ended, only\nbegins a second; and a second ended, only begins a third, and so on,\nfor ever and for aye. Such is the endlessness, yea, the intolerableness\nof", "labels": {"50": 10, "100": 75, "250": 106, "500": 333, "1000": 616, "2000": 1175}}, {"id": 1029, "position": 1029, "text": "Such is the endlessness, yea, the intolerableness\nof all earthly effort.\n\nGaining the more open water, the bracing breeze waxed fresh; the little\nMoss tossed the quick foam from her bows, as a young colt his\nsnortings", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1904}}, {"id": 1030, "position": 1030, "text": "tossed the quick foam from her bows, as a young colt his\nsnortings. How I snuffed that Tartar air!—how I spurned that turnpike\nearth!—that common highway all over dented with the marks of slavish", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 779, "2000": 573}}, {"id": 1031, "position": 1031, "text": "—that common highway all over dented with the marks of slavish\nheels and hoofs; and turned me to admire the magnanimity of the sea\nwhich will permit no records.\n\nAt the same foam-fountain, Queequeg", "labels": {"50": 48, "100": 20, "250": 53, "500": 162, "1000": 35, "2000": 1546}}, {"id": 1032, "position": 1032, "text": "permit no records.\n\nAt the same foam-fountain, Queequeg seemed to drink and reel with me.\nHis dusky nostrils swelled apart; he showed his filed and pointed\nteeth. On, on we flew; and our offing gained,", "labels": {"50": 25, "100": 93, "250": 136, "500": 233, "1000": 718, "2000": 1735}}, {"id": 1033, "position": 1033, "text": "pointed\nteeth. On, on we flew; and our offing gained, the Moss did homage to\nthe blast; ducked and dived her bows as a slave before the Sultan.\nSideways leaning, we sideways darted; every ropeyarn tingling like a", "labels": {"50": 16, "100": 73, "250": 15, "500": 406, "1000": 779, "2000": 1860}}, {"id": 1034, "position": 1034, "text": ".\nSideways leaning, we sideways darted; every ropeyarn tingling like a\nwire; the two tall masts buckling like Indian canes in land tornadoes.\nSo full of this reeling scene were we, as we stood by the plunging\nbowsprit", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 1035, "position": 1035, "text": "this reeling scene were we, as we stood by the plunging\nbowsprit, that for some time we did not notice the jeering glances of\nthe passengers, a lubber-like assembly, who marvelled that two fellow\nbeings should be so companion", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1036, "position": 1036, "text": "-like assembly, who marvelled that two fellow\nbeings should be so companionable; as though a white man were anything\nmore dignified than a whitewashed negro. But there were some boobies\nand bumpkins there, who, by their intense green", "labels": {"50": 21, "100": 42, "250": 148, "500": 279, "1000": 429, "2000": 27}}, {"id": 1037, "position": 1037, "text": "were some boobies\nand bumpkins there, who, by their intense greenness, must have come\nfrom the heart and centre of all verdure. Queequeg caught one of these\nyoung saplings mimicking him behind his back", "labels": {"50": 37, "100": 55, "250": 145, "500": 389, "1000": 673, "2000": 110}}, {"id": 1038, "position": 1038, "text": "caught one of these\nyoung saplings mimicking him behind his back. I thought the bumpkin’s\nhour of doom was come. Dropping his harpoon, the brawny savage caught\nhim in his arms, and by an almost miraculous dexterity and", "labels": {"50": 25, "100": 64, "250": 136, "500": 72, "1000": 531, "2000": 778}}, {"id": 1039, "position": 1039, "text": "savage caught\nhim in his arms, and by an almost miraculous dexterity and strength,\nsent him high up bodily into the air; then slightly tapping his stern\nin mid-somerset, the fellow landed with bursting lungs upon his feet,\nwhile Queeque", "labels": {"50": 33, "100": 45, "250": 244, "500": 221, "1000": 748, "2000": 1212}}, {"id": 1040, "position": 1040, "text": ", the fellow landed with bursting lungs upon his feet,\nwhile Queequeg, turning his back upon him, lighted his tomahawk pipe\nand passed it to me for a puff.\n\n“Capting! Capting!” yelled the bumpkin", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 786}}, {"id": 1041, "position": 1041, "text": "a puff.\n\n“Capting! Capting!” yelled the bumpkin, running towards that officer;\n“Capting, Capting, here’s the devil.”\n\n“Hallo, _you_ sir,” cried the Captain, a", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1042, "position": 1042, "text": "“Hallo, _you_ sir,” cried the Captain, a gaunt rib of the sea, stalking\nup to Queequeg, “what in thunder do you mean by that? Don’t you know\nyou might have killed that cha", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 327, "2000": 1620}}, {"id": 1043, "position": 1043, "text": "mean by that? Don’t you know\nyou might have killed that chap?”\n\n“What him say?” said Queequeg, as he mildly turned to me.\n\n“He say,” said I, “that you came near", "labels": {"50": 41, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 877}}, {"id": 1044, "position": 1044, "text": "me.\n\n“He say,” said I, “that you came near kill-e that man there,” pointing\nto the still shivering greenhorn.\n\n“Kill-e,” cried Queequeg, twisting his tattooed face into an une", "labels": {"50": 25, "100": 93, "250": 65, "500": 227, "1000": 580, "2000": 668}}, {"id": 1045, "position": 1045, "text": ",” cried Queequeg, twisting his tattooed face into an unearthly\nexpression of disdain, “ah! him bevy small-e fish-e; Queequeg no kill-e\nso small-e fish-e;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1046, "position": 1046, "text": "equeg no kill-e\nso small-e fish-e; Queequeg kill-e big whale!”\n\n“Look you,” roared the Captain, “I’ll kill-e _you_, you cannibal", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1047, "position": 1047, "text": "“I’ll kill-e _you_, you cannibal, if\nyou try any more of your tricks aboard here; so mind your eye.”\n\nBut it so happened just then, that it was high time for the Captain to\nmind", "labels": {"50": 37, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 1048, "position": 1048, "text": "so happened just then, that it was high time for the Captain to\nmind his own eye. The prodigious strain upon the main-sail had parted\nthe weather-sheet, and the tremendous boom was now flying from side to\nside, completely", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 1049, "position": 1049, "text": "sheet, and the tremendous boom was now flying from side to\nside, completely sweeping the entire after part of the deck. The poor\nfellow whom Queequeg had handled so roughly, was swept overboard; all\nhands were in a panic; and to", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 1050, "position": 1050, "text": "roughly, was swept overboard; all\nhands were in a panic; and to attempt snatching at the boom to stay it,\nseemed madness. It flew from right to left, and back again, almost in\none ticking of a watch, and every instant", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 1051, "position": 1051, "text": "and back again, almost in\none ticking of a watch, and every instant seemed on the point of\nsnapping into splinters. Nothing was done, and nothing seemed capable\nof being done; those on deck rushed towards the bows, and stood eyeing\nthe boom", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 1052, "position": 1052, "text": "done; those on deck rushed towards the bows, and stood eyeing\nthe boom as if it were the lower jaw of an exasperated whale. In the\nmidst of this consternation, Queequeg dropped deftly to his knees, and\ncrawling under", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1053, "position": 1053, "text": ", Queequeg dropped deftly to his knees, and\ncrawling under the path of the boom, whipped hold of a rope, secured\none end to the bulwarks, and then flinging the other like a lasso,\ncaught it", "labels": {"50": 45, "100": 55, "250": 145, "500": 185, "1000": 959, "2000": 1904}}, {"id": 1054, "position": 1054, "text": "s, and then flinging the other like a lasso,\ncaught it round the boom as it swept over his head, and at the next\njerk, the spar was that way trapped, and all was safe", "labels": {"50": 37, "100": 64, "250": 91, "500": 180, "1000": 345, "2000": 110}}, {"id": 1055, "position": 1055, "text": "that way trapped, and all was safe. The schooner was\nrun into the wind, and while the hands were clearing away the stern\nboat, Queequeg, stripped to the waist, darted from the side with a long\nliving arc of a leap", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1056, "position": 1056, "text": "the waist, darted from the side with a long\nliving arc of a leap. For three minutes or more he was seen swimming\nlike a dog, throwing his long arms straight out before him, and by\nturns revealing his brawny shoulders through the freezing foam", "labels": {"50": 12, "100": 55, "250": 138, "500": 72, "1000": 99, "2000": 1111}}, {"id": 1057, "position": 1057, "text": "before him, and by\nturns revealing his brawny shoulders through the freezing foam. I\nlooked at the grand and glorious fellow, but saw no one to be saved.\nThe greenhorn had gone down. Shooting himself perpendicularly from the\nwater, Quee", "labels": {"50": 12, "100": 93, "250": 52, "500": 435, "1000": 653, "2000": 1652}}, {"id": 1058, "position": 1058, "text": "horn had gone down. Shooting himself perpendicularly from the\nwater, Queequeg, now took an instant’s glance around him, and seeming\nto see just how matters were, dived down and disappeared", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1059, "position": 1059, "text": "were, dived down and disappeared. A few minutes\nmore, and he rose again, one arm still striking out, and with the other\ndragging a lifeless form. The boat soon picked them up. The poor\nbumpkin was restored", "labels": {"50": 45, "100": 64, "250": 138, "500": 363, "1000": 251, "2000": 1668}}, {"id": 1060, "position": 1060, "text": "soon picked them up. The poor\nbumpkin was restored. All hands voted Queequeg a noble trump; the\ncaptain begged his pardon. From that hour I clove to Queequeg like a\nbarnacle; yea, till poor", "labels": {"50": 41, "100": 21, "250": 91, "500": 281, "1000": 230, "2000": 1082}}, {"id": 1061, "position": 1061, "text": "to Queequeg like a\nbarnacle; yea, till poor Queequeg took his last long dive.\n\nWas there ever such unconsciousness? He did not seem to think that he\nat all deserved a medal from the Humane and Magna", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 1062, "position": 1062, "text": "seem to think that he\nat all deserved a medal from the Humane and Magnanimous Societies. He\nonly asked for water—fresh water—something to wipe the brine off; that\ndone, he put on dry clothes, lighted his pipe, and", "labels": {"50": 12, "100": 43, "250": 209, "500": 344, "1000": 554, "2000": 1786}}, {"id": 1063, "position": 1063, "text": "; that\ndone, he put on dry clothes, lighted his pipe, and leaning against the\nbulwarks, and mildly eyeing those around him, seemed to be saying to\nhimself—“It’s a mutual, joint-stock world, in", "labels": {"50": 11, "100": 99, "250": 174, "500": 5, "1000": 367, "2000": 497}}, {"id": 1064, "position": 1064, "text": "himself—“It’s a mutual, joint-stock world, in all meridians. We\ncannibals must help these Christians.”\n\n\nCHAPTER 14. Nantucket.\n\nNothing more happened on the passage worthy the mentioning; so, after a", "labels": {"50": 12, "100": 43, "250": 78, "500": 379, "1000": 381, "2000": 978}}, {"id": 1065, "position": 1065, "text": ".\n\nNothing more happened on the passage worthy the mentioning; so, after a\nfine run, we safely arrived in Nantucket.\n\nNantucket! Take out your map and look at it. See what a real corner of\nthe world it occupies; how it", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 525, "2000": 1105}}, {"id": 1066, "position": 1066, "text": "it. See what a real corner of\nthe world it occupies; how it stands there, away off shore, more lonely\nthan the Eddystone lighthouse. Look at it—a mere hillock, and elbow of\nsand; all beach, without a background", "labels": {"50": 48, "100": 20, "250": 157, "500": 223, "1000": 9, "2000": 682}}, {"id": 1067, "position": 1067, "text": "mere hillock, and elbow of\nsand; all beach, without a background. There is more sand there than\nyou would use in twenty years as a substitute for blotting paper. Some\ngamesome wights will tell you that they have to plant", "labels": {"50": 48, "100": 20, "250": 53, "500": 334, "1000": 9, "2000": 682}}, {"id": 1068, "position": 1068, "text": "paper. Some\ngamesome wights will tell you that they have to plant weeds there, they\ndon’t grow naturally; that they import Canada thistles; that they have\nto send beyond seas for a spile to stop a leak in an oil", "labels": {"50": 31, "100": 7, "250": 91, "500": 36, "1000": 568, "2000": 1082}}, {"id": 1069, "position": 1069, "text": "to send beyond seas for a spile to stop a leak in an oil cask; that\npieces of wood in Nantucket are carried about like bits of the true\ncross in Rome; that people there plant toadstools before their houses,\nto get", "labels": {"50": 8, "100": 65, "250": 224, "500": 422, "1000": 789, "2000": 1100}}, {"id": 1070, "position": 1070, "text": "Rome; that people there plant toadstools before their houses,\nto get under the shade in summer time; that one blade of grass makes an\noasis, three blades in a day’s walk a prairie; that they wear quicksand\nshoes,", "labels": {"50": 48, "100": 20, "250": 15, "500": 126, "1000": 747, "2000": 1560}}, {"id": 1071, "position": 1071, "text": "day’s walk a prairie; that they wear quicksand\nshoes, something like Laplander snow-shoes; that they are so shut up,\nbelted about, every way inclosed, surrounded, and made an utter island\nof by the", "labels": {"50": 20, "100": 5, "250": 132, "500": 412, "1000": 727, "2000": 913}}, {"id": 1072, "position": 1072, "text": "way inclosed, surrounded, and made an utter island\nof by the ocean, that to their very chairs and tables small clams will\nsometimes be found adhering, as to the backs of sea turtles", "labels": {"50": 48, "100": 43, "250": 234, "500": 72, "1000": 9, "2000": 682}}, {"id": 1073, "position": 1073, "text": "to the backs of sea turtles. But these\nextravaganzas only show that Nantucket is no Illinois.\n\nLook now at the wondrous traditional story of how this island was\nsettled by the red-men. Thus goes the legend", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 682}}, {"id": 1074, "position": 1074, "text": "island was\nsettled by the red-men. Thus goes the legend. In olden times an eagle\nswooped down upon the New England coast, and carried off an infant\nIndian in his talons. With loud lament the parents saw their child\nborne", "labels": {"50": 40, "100": 38, "250": 65, "500": 171, "1000": 714, "2000": 668}}, {"id": 1075, "position": 1075, "text": "in his talons. With loud lament the parents saw their child\nborne out of sight over the wide waters. They resolved to follow in the\nsame direction. Setting out in their canoes, after a perilous passage\nthey discovered the island,", "labels": {"50": 12, "100": 38, "250": 65, "500": 171, "1000": 714, "2000": 668}}, {"id": 1076, "position": 1076, "text": "their canoes, after a perilous passage\nthey discovered the island, and there they found an empty ivory\ncasket,—the poor little Indian’s skeleton.\n\nWhat wonder, then, that these Nantucketers, born on a beach, should", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 300, "2000": 47}}, {"id": 1077, "position": 1077, "text": ", then, that these Nantucketers, born on a beach, should\ntake to the sea for a livelihood! They first caught crabs and quohogs\nin the sand; grown bolder, they waded out with nets for mackerel;", "labels": {"50": 45, "100": 29, "250": 138, "500": 421, "1000": 257, "2000": 156}}, {"id": 1078, "position": 1078, "text": "grown bolder, they waded out with nets for mackerel; more\nexperienced, they pushed off in boats and captured cod; and at last,\nlaunching a navy of great ships on the sea, explored this watery world;\nput an incess", "labels": {"50": 45, "100": 29, "250": 82, "500": 13, "1000": 354, "2000": 1766}}, {"id": 1079, "position": 1079, "text": "great ships on the sea, explored this watery world;\nput an incessant belt of circumnavigations round it; peeped in at\nBehring’s Straits; and in all seasons and all oceans declared\neverlasting", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1080, "position": 1080, "text": "’s Straits; and in all seasons and all oceans declared\neverlasting war with the mightiest animated mass that has survived the\nflood; most monstrous and most mountainous! That Himmalehan, salt-sea\nMastodon, clothed with such portento", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1081, "position": 1081, "text": "Himmalehan, salt-sea\nMastodon, clothed with such portentousness of unconscious power, that\nhis very panics are more to be dreaded than his most fearless and\nmalicious assaults!\n\nAnd thus have these naked Nantucketers, these", "labels": {"50": 45, "100": 64, "250": 193, "500": 307, "1000": 343, "2000": 1620}}, {"id": 1082, "position": 1082, "text": "fearless and\nmalicious assaults!\n\nAnd thus have these naked Nantucketers, these sea hermits, issuing from\ntheir ant-hill in the sea, overrun and conquered the watery world like\nso many Alexanders; parcelling out among them the Atlantic, Pacific", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1083, "position": 1083, "text": "like\nso many Alexanders; parcelling out among them the Atlantic, Pacific,\nand Indian oceans, as the three pirate powers did Poland. Let America\nadd Mexico to Texas, and pile Cuba upon Canada; let the English\noverswarm all India,", "labels": {"50": 21, "100": 95, "250": 76, "500": 307, "1000": 343, "2000": 759}}, {"id": 1084, "position": 1084, "text": "and pile Cuba upon Canada; let the English\noverswarm all India, and hang out their blazing banner from the sun;\ntwo thirds of this terraqueous globe are the Nantucketer’s. For the sea\nis his; he owns it", "labels": {"50": 9, "100": 26, "250": 133, "500": 122, "1000": 916, "2000": 16}}, {"id": 1085, "position": 1085, "text": "Nantucketer’s. For the sea\nis his; he owns it, as Emperors own empires; other seamen having but a\nright of way through it. Merchant ships are but extension bridges;\narmed ones but floating forts; even pirates and privateers", "labels": {"50": 31, "100": 7, "250": 49, "500": 78, "1000": 637, "2000": 16}}, {"id": 1086, "position": 1086, "text": "but extension bridges;\narmed ones but floating forts; even pirates and privateers, though\nfollowing the sea as highwaymen the road, they but plunder other ships,\nother fragments of the land like themselves, without seeking to draw\ntheir living from the bottom", "labels": {"50": 26, "100": 67, "250": 235, "500": 87, "1000": 760, "2000": 795}}, {"id": 1087, "position": 1087, "text": "of the land like themselves, without seeking to draw\ntheir living from the bottomless deep itself. The Nantucketer, he alone\nresides and riots on the sea; he alone, in Bible language, goes down to\nit in ships; to and fr", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1088, "position": 1088, "text": ", in Bible language, goes down to\nit in ships; to and fro ploughing it as his own special plantation.\n_There_ is his home; _there_ lies his business, which a Noah’s flood\nwould not interrupt,", "labels": {"50": 27, "100": 33, "250": 23, "500": 44, "1000": 624, "2000": 859}}, {"id": 1089, "position": 1089, "text": "_ lies his business, which a Noah’s flood\nwould not interrupt, though it overwhelmed all the millions in China.\nHe lives on the sea, as prairie cocks in the prairie; he hides among\nthe waves, he climbs them as chamo", "labels": {"50": 16, "100": 73, "250": 49, "500": 78, "1000": 165, "2000": 1956}}, {"id": 1090, "position": 1090, "text": "the prairie; he hides among\nthe waves, he climbs them as chamois hunters climb the Alps. For years\nhe knows not the land; so that when he comes to it at last, it smells\nlike another world, more strangely than the moon", "labels": {"50": 31, "100": 20, "250": 49, "500": 334, "1000": 165, "2000": 1050}}, {"id": 1091, "position": 1091, "text": "it at last, it smells\nlike another world, more strangely than the moon would to an Earthsman.\nWith the landless gull, that at sunset folds her wings and is rocked to\nsleep between billows; so at nightfall, the Nantucket", "labels": {"50": 16, "100": 20, "250": 15, "500": 334, "1000": 747, "2000": 1710}}, {"id": 1092, "position": 1092, "text": "is rocked to\nsleep between billows; so at nightfall, the Nantucketer, out of sight\nof land, furls his sails, and lays him to his rest, while under his\nvery pillow rush herds of walruses and whales.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1093, "position": 1093, "text": "while under his\nvery pillow rush herds of walruses and whales.\n\n\nCHAPTER 15. Chowder.\n\nIt was quite late in the evening when the little Moss came snugly to\nanchor, and Queequeg and I went ashore; so we", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1094, "position": 1094, "text": "to\nanchor, and Queequeg and I went ashore; so we could attend to no\nbusiness that day, at least none but a supper and a bed. The landlord\nof the Spouter-Inn had recommended us to his cousin Hosea", "labels": {"50": 32, "100": 0, "250": 233, "500": 55, "1000": 689, "2000": 978}}, {"id": 1095, "position": 1095, "text": "of the Spouter-Inn had recommended us to his cousin Hosea Hussey of the\nTry Pots, whom he asserted to be the proprietor of one of the best kept\nhotels in all Nantucket, and moreover he had assured us that Cousin", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 887}}, {"id": 1096, "position": 1096, "text": "kept\nhotels in all Nantucket, and moreover he had assured us that Cousin\nHosea, as he called him, was famous for his chowders. In short, he\nplainly hinted that we could not possibly do better than try pot-luck\nat the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1934}}, {"id": 1097, "position": 1097, "text": "hinted that we could not possibly do better than try pot-luck\nat the Try Pots. But the directions he had given us about keeping a\nyellow warehouse on our starboard hand till we opened a white church to\nthe larboard, and then keeping", "labels": {"50": 25, "100": 64, "250": 55, "500": 318, "1000": 868, "2000": 1028}}, {"id": 1098, "position": 1098, "text": "we opened a white church to\nthe larboard, and then keeping that on the larboard hand till we made a\ncorner three points to the starboard, and that done, then ask the first\nman we met where the place was:", "labels": {"50": 45, "100": 65, "250": 224, "500": 10, "1000": 741, "2000": 1250}}, {"id": 1099, "position": 1099, "text": "that done, then ask the first\nman we met where the place was: these crooked directions of his very\nmuch puzzled us at first, especially as, at the outset, Queequeg\ninsisted that the yellow warehouse—our first point of departure—", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 462, "2000": 1702}}, {"id": 1100, "position": 1100, "text": "equeg\ninsisted that the yellow warehouse—our first point of departure—must be\nleft on the larboard hand, whereas I had understood Peter Coffin to say\nit was on the starboard. However, by dint of beating about a little", "labels": {"50": 25, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 693}}, {"id": 1101, "position": 1101, "text": "was on the starboard. However, by dint of beating about a little in\nthe dark, and now and then knocking up a peaceable inhabitant to\ninquire the way, we at last came to something which there was no\nmistaking.", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 1102, "position": 1102, "text": "way, we at last came to something which there was no\nmistaking.\n\nTwo enormous wooden pots painted black, and suspended by asses’ ears,\nswung from the cross-trees of an old top-mast, planted in front of an\nold doorway", "labels": {"50": 25, "100": 27, "250": 189, "500": 371, "1000": 409, "2000": 1171}}, {"id": 1103, "position": 1103, "text": "trees of an old top-mast, planted in front of an\nold doorway. The horns of the cross-trees were sawed off on the other\nside, so that this old top-mast looked not a little like a gallows", "labels": {"50": 25, "100": 41, "250": 136, "500": 388, "1000": 313, "2000": 786}}, {"id": 1104, "position": 1104, "text": "old top-mast looked not a little like a gallows.\nPerhaps I was over sensitive to such impressions at the time, but I\ncould not help staring at this gallows with a vague misgiving. A sort\nof crick was in my neck", "labels": {"50": 25, "100": 41, "250": 156, "500": 313, "1000": 329, "2000": 453}}, {"id": 1105, "position": 1105, "text": "with a vague misgiving. A sort\nof crick was in my neck as I gazed up to the two remaining horns; yes,\n_two_ of them, one for Queequeg, and one for me", "labels": {"50": 25, "100": 5, "250": 136, "500": 180, "1000": 272, "2000": 1954}}, {"id": 1106, "position": 1106, "text": "Queequeg, and one for me. It’s ominous, thinks\nI. A Coffin my Innkeeper upon landing in my first whaling port;\ntombstones staring at me in the whalemen’s chapel; and here a gallows!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1107, "position": 1107, "text": "me in the whalemen’s chapel; and here a gallows!\nand a pair of prodigious black pots too! Are these last throwing out\noblique hints touching Tophet?\n\nI was called from these reflections by the sight of a fr", "labels": {"50": 9, "100": 64, "250": 193, "500": 498, "1000": 50, "2000": 1620}}, {"id": 1108, "position": 1108, "text": "Tophet?\n\nI was called from these reflections by the sight of a freckled woman\nwith yellow hair and a yellow gown, standing in the porch of the inn,\nunder a dull red lamp swinging there, that looked much like an injured\neye,", "labels": {"50": 25, "100": 5, "250": 53, "500": 412, "1000": 483, "2000": 1149}}, {"id": 1109, "position": 1109, "text": "a dull red lamp swinging there, that looked much like an injured\neye, and carrying on a brisk scolding with a man in a purple woollen\nshirt.\n\n“Get along with ye,” said she to the man, “or I’", "labels": {"50": 41, "100": 21, "250": 215, "500": 281, "1000": 230, "2000": 380}}, {"id": 1110, "position": 1110, "text": "along with ye,” said she to the man, “or I’ll be combing ye!”\n\n“Come on, Queequeg,” said I, “all right. There’s Mrs. Hussey.”", "labels": {"50": 41, "100": 31, "250": 228, "500": 208, "1000": 603, "2000": 270}}, {"id": 1111, "position": 1111, "text": "“all right. There’s Mrs. Hussey.”\n\nAnd so it turned out; Mr. Hosea Hussey being from home, but leaving\nMrs. Hussey entirely competent to attend to all his affairs", "labels": {"50": 7, "100": 8, "250": 203, "500": 429, "1000": 342, "2000": 1320}}, {"id": 1112, "position": 1112, "text": "Hussey entirely competent to attend to all his affairs. Upon\nmaking known our desires for a supper and a bed, Mrs. Hussey,\npostponing further scolding for the present, ushered us into a little\nroom, and seating", "labels": {"50": 23, "100": 17, "250": 127, "500": 382, "1000": 207, "2000": 1212}}, {"id": 1113, "position": 1113, "text": "olding for the present, ushered us into a little\nroom, and seating us at a table spread with the relics of a recently\nconcluded repast, turned round to us and said—“Clam or Cod?”", "labels": {"50": 41, "100": 88, "250": 219, "500": 202, "1000": 54, "2000": 110}}, {"id": 1114, "position": 1114, "text": "said—“Clam or Cod?”\n\n“What’s that about Cods, ma’am?” said I, with much politeness.\n\n“Clam or Cod?” she repeated.", "labels": {"50": 11, "100": 41, "250": 207, "500": 53, "1000": 385, "2000": 1359}}, {"id": 1115, "position": 1115, "text": "Cod?” she repeated.\n\n“A clam for supper? a cold clam; is _that_ what you mean, Mrs. Hussey?”\nsays I, “but that’s a rather cold and clammy reception in", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1116, "position": 1116, "text": ", “but that’s a rather cold and clammy reception in the winter\ntime, ain’t it, Mrs. Hussey?”\n\nBut being in a great hurry to resume scolding the man in the purple\nShirt, who", "labels": {"50": 23, "100": 88, "250": 203, "500": 100, "1000": 307, "2000": 259}}, {"id": 1117, "position": 1117, "text": "great hurry to resume scolding the man in the purple\nShirt, who was waiting for it in the entry, and seeming to hear nothing\nbut the word “clam,” Mrs. Hussey hurried towards an open door leading\nto the kitchen", "labels": {"50": 23, "100": 88, "250": 62, "500": 100, "1000": 59, "2000": 66}}, {"id": 1118, "position": 1118, "text": "” Mrs. Hussey hurried towards an open door leading\nto the kitchen, and bawling out “clam for two,” disappeared.\n\n“Queequeg,” said I, “do you think that we can make out a", "labels": {"50": 41, "100": 21, "250": 219, "500": 100, "1000": 416, "2000": 1199}}, {"id": 1119, "position": 1119, "text": ",” said I, “do you think that we can make out a supper for us\nboth on one clam?”\n\nHowever, a warm savory steam from the kitchen served to belie the\napparently cheerless prospect before us", "labels": {"50": 25, "100": 93, "250": 55, "500": 318, "1000": 868, "2000": 1243}}, {"id": 1120, "position": 1120, "text": "kitchen served to belie the\napparently cheerless prospect before us. But when that smoking chowder\ncame in, the mystery was delightfully explained. Oh, sweet friends!\nhearken to me. It was made of small juicy clams, scarcely bigger", "labels": {"50": 25, "100": 41, "250": 55, "500": 318, "1000": 868, "2000": 251}}, {"id": 1121, "position": 1121, "text": "ken to me. It was made of small juicy clams, scarcely bigger than\nhazel nuts, mixed with pounded ship biscuit, and salted pork cut up\ninto little flakes; the whole enriched with butter, and plentifully\nseasoned with", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1122, "position": 1122, "text": "akes; the whole enriched with butter, and plentifully\nseasoned with pepper and salt. Our appetites being sharpened by the\nfrosty voyage, and in particular, Queequeg seeing his favourite fishing\nfood before him, and the chowder", "labels": {"50": 12, "100": 42, "250": 209, "500": 247, "1000": 222, "2000": 624}}, {"id": 1123, "position": 1123, "text": "equeg seeing his favourite fishing\nfood before him, and the chowder being surpassingly excellent, we\ndespatched it with great expedition: when leaning back a moment and\nbethinking me of Mrs. Hussey’s clam and cod", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 851, "2000": 1620}}, {"id": 1124, "position": 1124, "text": "bethinking me of Mrs. Hussey’s clam and cod announcement, I thought I\nwould try a little experiment. Stepping to the kitchen door, I uttered\nthe word “cod” with great emphasis, and resumed my seat", "labels": {"50": 11, "100": 79, "250": 176, "500": 443, "1000": 504, "2000": 1958}}, {"id": 1125, "position": 1125, "text": "word “cod” with great emphasis, and resumed my seat. In a few\nmoments the savoury steam came forth again, but with a different\nflavor, and in good time a fine cod-chowder was placed before us.", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 251}}, {"id": 1126, "position": 1126, "text": "time a fine cod-chowder was placed before us.\n\nWe resumed business; and while plying our spoons in the bowl, thinks I\nto myself, I wonder now if this here has any effect on the head? What’s\nthat stu", "labels": {"50": 42, "100": 59, "250": 30, "500": 16, "1000": 364, "2000": 1592}}, {"id": 1127, "position": 1127, "text": "if this here has any effect on the head? What’s\nthat stultifying saying about chowder-headed people? “But look,\nQueequeg, ain’t that a live eel in your bowl? Where’s your harp", "labels": {"50": 9, "100": 64, "250": 30, "500": 498, "1000": 345, "2000": 1620}}, {"id": 1128, "position": 1128, "text": "’t that a live eel in your bowl? Where’s your harpoon?”\n\nFishiest of all fishy places was the Try Pots, which well deserved its\nname; for the pots there were always boiling chowders", "labels": {"50": 11, "100": 12, "250": 16, "500": 72, "1000": 416, "2000": 778}}, {"id": 1129, "position": 1129, "text": "; for the pots there were always boiling chowders. Chowder for\nbreakfast, and chowder for dinner, and chowder for supper, till you\nbegan to look for fish-bones coming through your clothes", "labels": {"50": 11, "100": 12, "250": 16, "500": 66, "1000": 688, "2000": 32}}, {"id": 1130, "position": 1130, "text": "-bones coming through your clothes. The area\nbefore the house was paved with clam-shells. Mrs. Hussey wore a\npolished necklace of codfish vertebra; and Hosea Hussey had his account\nbooks bound in superior old", "labels": {"50": 11, "100": 22, "250": 214, "500": 363, "1000": 531, "2000": 32}}, {"id": 1131, "position": 1131, "text": "; and Hosea Hussey had his account\nbooks bound in superior old shark-skin. There was a fishy flavor to the\nmilk, too, which I could not at all account for, till one morning\nhappening to take a stroll along the", "labels": {"50": 25, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 1132, "position": 1132, "text": "at all account for, till one morning\nhappening to take a stroll along the beach among some fishermen’s\nboats, I saw Hosea’s brindled cow feeding on fish remnants, and\nmarching along the sand with each foot in a cod’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1133, "position": 1133, "text": "fish remnants, and\nmarching along the sand with each foot in a cod’s decapitated head,\nlooking very slip-shod, I assure ye.\n\nSupper concluded, we received a lamp, and directions from Mrs", "labels": {"50": 25, "100": 41, "250": 55, "500": 318, "1000": 868, "2000": 251}}, {"id": 1134, "position": 1134, "text": "we received a lamp, and directions from Mrs. Hussey\nconcerning the nearest way to bed; but, as Queequeg was about to\nprecede me up the stairs, the lady reached forth her arm, and demanded\nhis harpoon;", "labels": {"50": 33, "100": 17, "250": 160, "500": 358, "1000": 485, "2000": 1262}}, {"id": 1135, "position": 1135, "text": "stairs, the lady reached forth her arm, and demanded\nhis harpoon; she allowed no harpoon in her chambers. “Why not?” said I;\n“every true whaleman sleeps with his harpoon—but why not?” “Because", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1136, "position": 1136, "text": "whaleman sleeps with his harpoon—but why not?” “Because\nit’s dangerous,” says she. “Ever since young Stiggs coming from that\nunfort’nt v’y’ge of his, when he was gone", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1137, "position": 1137, "text": "fort’nt v’y’ge of his, when he was gone four years and a half, with\nonly three barrels of _ile_, was found dead in my first floor back,\nwith his harpoon in his side; ever since then", "labels": {"50": 25, "100": 5, "250": 125, "500": 349, "1000": 842, "2000": 1586}}, {"id": 1138, "position": 1138, "text": "first floor back,\nwith his harpoon in his side; ever since then I allow no boarders to\ntake sich dangerous weepons in their rooms at night. So, Mr. Queequeg”\n(for she had learned his name)", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1139, "position": 1139, "text": "Mr. Queequeg”\n(for she had learned his name), “I will just take this here iron, and\nkeep it for you till morning. But the chowder; clam or cod to-morrow\nfor breakfast, men?", "labels": {"50": 39, "100": 64, "250": 163, "500": 53, "1000": 488, "2000": 1790}}, {"id": 1140, "position": 1140, "text": "chowder; clam or cod to-morrow\nfor breakfast, men?”\n\n“Both,” says I; “and let’s have a couple of smoked herring by way of\nvariety.”\n\n\nCHAPTER 16. The Ship.", "labels": {"50": 45, "100": 64, "250": 163, "500": 16, "1000": 364, "2000": 1592}}, {"id": 1141, "position": 1141, "text": "way of\nvariety.”\n\n\nCHAPTER 16. The Ship.\n\nIn bed we concocted our plans for the morrow. But to my surprise and no\nsmall concern, Queequeg now gave me to understand, that he had been\ndiligently consulting", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1142, "position": 1142, "text": "g now gave me to understand, that he had been\ndiligently consulting Yojo—the name of his black little god—and Yojo\nhad told him two or three times over, and strongly insisted upon it\neveryway, that instead of our", "labels": {"50": 25, "100": 13, "250": 210, "500": 389, "1000": 655, "2000": 1533}}, {"id": 1143, "position": 1143, "text": "times over, and strongly insisted upon it\neveryway, that instead of our going together among the whaling-fleet in\nharbor, and in concert selecting our craft; instead of this, I say,\nYojo earnestly enjoined that the selection of", "labels": {"50": 45, "100": 90, "250": 130, "500": 499, "1000": 582, "2000": 370}}, {"id": 1144, "position": 1144, "text": ", I say,\nYojo earnestly enjoined that the selection of the ship should rest\nwholly with me, inasmuch as Yojo purposed befriending us; and, in order\nto do so, had already pitched upon a", "labels": {"50": 20, "100": 90, "250": 130, "500": 499, "1000": 582, "2000": 370}}, {"id": 1145, "position": 1145, "text": "us; and, in order\nto do so, had already pitched upon a vessel, which, if left to myself,\nI, Ishmael, should infallibly light upon, for all the world as though\nit had turned out by chance;", "labels": {"50": 45, "100": 13, "250": 138, "500": 384, "1000": 139, "2000": 1243}}, {"id": 1146, "position": 1146, "text": "upon, for all the world as though\nit had turned out by chance; and in that vessel I must immediately ship\nmyself, for the present irrespective of Queequeg.\n\nI have forgotten to mention that, in many things, Que", "labels": {"50": 20, "100": 5, "250": 125, "500": 349, "1000": 842, "2000": 1706}}, {"id": 1147, "position": 1147, "text": "queg.\n\nI have forgotten to mention that, in many things, Queequeg placed great\nconfidence in the excellence of Yojo’s judgment and surprising forecast\nof things; and cherished Yojo with considerable esteem, as a rather\ngood sort", "labels": {"50": 20, "100": 28, "250": 101, "500": 120, "1000": 651, "2000": 1068}}, {"id": 1148, "position": 1148, "text": "; and cherished Yojo with considerable esteem, as a rather\ngood sort of god, who perhaps meant well enough upon the whole, but in\nall cases did not succeed in his benevolent designs.\n\nNow, this plan of Queequeg’s", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 1149, "position": 1149, "text": "his benevolent designs.\n\nNow, this plan of Queequeg’s, or rather Yojo’s, touching the selection\nof our craft; I did not like that plan at all. I had not a little\nrelied upon Queequeg", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1150, "position": 1150, "text": "plan at all. I had not a little\nrelied upon Queequeg’s sagacity to point out the whaler best fitted to\ncarry us and our fortunes securely. But as all my remonstrances\nproduced no effect upon Quee", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1151, "position": 1151, "text": "But as all my remonstrances\nproduced no effect upon Queequeg, I was obliged to acquiesce; and\naccordingly prepared to set about this business with a determined\nrushing sort of energy and vigor, that should quickly settle that", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1152, "position": 1152, "text": "with a determined\nrushing sort of energy and vigor, that should quickly settle that\ntrifling little affair. Next morning early, leaving Queequeg shut up\nwith Yojo in our little bedroom—for it seemed that it was some sort of\nLent", "labels": {"50": 7, "100": 22, "250": 214, "500": 109, "1000": 688, "2000": 370}}, {"id": 1153, "position": 1153, "text": "in our little bedroom—for it seemed that it was some sort of\nLent or Ramadan, or day of fasting, humiliation, and prayer with\nQueequeg and Yojo that day; _how_ it was I never could find out", "labels": {"50": 25, "100": 5, "250": 169, "500": 318, "1000": 576, "2000": 572}}, {"id": 1154, "position": 1154, "text": "Yojo that day; _how_ it was I never could find out, for,\nthough I applied myself to it several times, I never could master his\nliturgies and XXXIX Articles—leaving Queequeg, then, fast", "labels": {"50": 20, "100": 28, "250": 169, "500": 59, "1000": 576, "2000": 1420}}, {"id": 1155, "position": 1155, "text": "and XXXIX Articles—leaving Queequeg, then, fasting on his\ntomahawk pipe, and Yojo warming himself at his sacrificial fire of\nshavings, I sallied out among the shipping", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 1156, "position": 1156, "text": "of\nshavings, I sallied out among the shipping. After much prolonged\nsauntering and many random inquiries, I learnt that there were three\nships up for three-years’ voyages—The Devil-dam, the Tit-bit", "labels": {"50": 25, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1157, "position": 1157, "text": "-years’ voyages—The Devil-dam, the Tit-bit, and the\nPequod. _Devil-Dam_, I do not know the origin of; _Tit-bit_ is obvious;\n_Pequod_", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 1107}}, {"id": 1158, "position": 1158, "text": "; _Tit-bit_ is obvious;\n_Pequod_, you will no doubt remember, was the name of a celebrated\ntribe of Massachusetts Indians; now extinct as the ancient Medes. I\npeered and pryed about the Devil-", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 1159, "position": 1159, "text": "as the ancient Medes. I\npeered and pryed about the Devil-dam; from her, hopped over to the\nTit-bit; and finally, going on board the Pequod, looked around her for\na moment, and then decided", "labels": {"50": 25, "100": 64, "250": 163, "500": 388, "1000": 533, "2000": 693}}, {"id": 1160, "position": 1160, "text": "the Pequod, looked around her for\na moment, and then decided that this was the very ship for us.\n\nYou may have seen many a quaint craft in your day, for aught I\nknow;—square-toed lugger", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1161, "position": 1161, "text": "day, for aught I\nknow;—square-toed luggers; mountainous Japanese junks; butter-box\ngalliots, and what not; but take my word for it, you never saw such a\nrare old craft as this", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 174, "2000": 16}}, {"id": 1162, "position": 1162, "text": "my word for it, you never saw such a\nrare old craft as this same rare old Pequod. She was a ship of the old\nschool, rather small if anything; with an old-fashioned claw-footed\nlook about her", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1163, "position": 1163, "text": "; with an old-fashioned claw-footed\nlook about her. Long seasoned and weather-stained in the typhoons and\ncalms of all four oceans, her old hull’s complexion was darkened like a\nFrench grenadier’s, who has", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1164, "position": 1164, "text": "s complexion was darkened like a\nFrench grenadier’s, who has alike fought in Egypt and Siberia. Her\nvenerable bows looked bearded. Her masts—cut somewhere on the coast of\nJapan, where her original ones were lost overboard in a gale", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1165, "position": 1165, "text": "the coast of\nJapan, where her original ones were lost overboard in a gale—her masts\nstood stiffly up like the spines of the three old kings of Cologne. Her\nancient decks were worn and wrinkled, like the pilgrim-worshipped\nflag-stone in", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 9, "2000": 1904}}, {"id": 1166, "position": 1166, "text": "decks were worn and wrinkled, like the pilgrim-worshipped\nflag-stone in Canterbury Cathedral where Becket bled. But to all these\nher old antiquities, were added new and marvellous features, pertaining\nto the wild business that for more than half a century", "labels": {"50": 5, "100": 27, "250": 157, "500": 63, "1000": 322, "2000": 1743}}, {"id": 1167, "position": 1167, "text": "lous features, pertaining\nto the wild business that for more than half a century she had\nfollowed. Old Captain Peleg, many years her chief-mate, before he\ncommanded another vessel of his own, and now a retired seaman, and one\nof the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 877}}, {"id": 1168, "position": 1168, "text": "vessel of his own, and now a retired seaman, and one\nof the principal owners of the Pequod,—this old Peleg, during the term\nof his chief-mateship, had built upon her original grotesqueness, and\ninlaid", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1169, "position": 1169, "text": "-mateship, had built upon her original grotesqueness, and\ninlaid it, all over, with a quaintness both of material and device,\nunmatched by anything except it be Thorkill-Hake’s carved buckler or", "labels": {"50": 45, "100": 64, "250": 82, "500": 73, "1000": 851, "2000": 1584}}, {"id": 1170, "position": 1170, "text": "anything except it be Thorkill-Hake’s carved buckler or\nbedstead. She was apparelled like any barbaric Ethiopian emperor, his\nneck heavy with pendants of polished ivory. She was a thing of\ntrophies", "labels": {"50": 7, "100": 88, "250": 86, "500": 180, "1000": 298, "2000": 1091}}, {"id": 1171, "position": 1171, "text": "s of polished ivory. She was a thing of\ntrophies. A cannibal of a craft, tricking herself forth in the chased\nbones of her enemies. All round, her unpanelled, open bulwarks were\ngarnished like", "labels": {"50": 22, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1014}}, {"id": 1172, "position": 1172, "text": "her unpanelled, open bulwarks were\ngarnished like one continuous jaw, with the long sharp teeth of the\nsperm whale, inserted there for pins, to fasten her old hempen thews\nand tendons to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1173, "position": 1173, "text": "fasten her old hempen thews\nand tendons to. Those thews ran not through base blocks of land wood,\nbut deftly travelled over sheaves of sea-ivory. Scorning a turnstile\nwheel at her reverend helm, she", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 1174, "position": 1174, "text": "ivory. Scorning a turnstile\nwheel at her reverend helm, she sported there a tiller; and that tiller\nwas in one mass, curiously carved from the long narrow lower jaw of her\nhereditary foe", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 50, "2000": 1003}}, {"id": 1175, "position": 1175, "text": "long narrow lower jaw of her\nhereditary foe. The helmsman who steered by that tiller in a tempest,\nfelt like the Tartar, when he holds back his fiery steed by clutching\nits jaw. A noble craft, but somehow a most melancholy", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1176, "position": 1176, "text": "ed by clutching\nits jaw. A noble craft, but somehow a most melancholy! All noble things\nare touched with that.\n\nNow when I looked about the quarter-deck, for some one having\nauthority, in order to propose myself as a candidate for the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1177, "position": 1177, "text": "some one having\nauthority, in order to propose myself as a candidate for the voyage, at\nfirst I saw nobody; but I could not well overlook a strange sort of\ntent, or rather wigwam, pitched a little behind the main-mast", "labels": {"50": 25, "100": 28, "250": 156, "500": 34, "1000": 421, "2000": 1495}}, {"id": 1178, "position": 1178, "text": "or rather wigwam, pitched a little behind the main-mast. It\nseemed only a temporary erection used in port. It was of a conical\nshape, some ten feet high; consisting of the long, huge slabs of limber\nblack bone taken", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1179, "position": 1179, "text": "high; consisting of the long, huge slabs of limber\nblack bone taken from the middle and highest part of the jaws of the\nright-whale. Planted with their broad ends on the deck, a circle of\nthese slabs laced together, mutually sloped", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1180, "position": 1180, "text": "on the deck, a circle of\nthese slabs laced together, mutually sloped towards each other, and at\nthe apex united in a tufted point, where the loose hairy fibres waved\nto and fro like the top-knot on some old Pot", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 1181, "position": 1181, "text": "s waved\nto and fro like the top-knot on some old Pottowottamie Sachem’s head. A\ntriangular opening faced towards the bows of the ship, so that the\ninsider commanded a complete view forward.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1182, "position": 1182, "text": ", so that the\ninsider commanded a complete view forward.\n\nAnd half concealed in this queer tenement, I at length found one who by\nhis aspect seemed to have authority; and who, it being noon, and the\nship’s work suspended, was", "labels": {"50": 45, "100": 64, "250": 156, "500": 388, "1000": 313, "2000": 786}}, {"id": 1183, "position": 1183, "text": "who, it being noon, and the\nship’s work suspended, was now enjoying respite from the burden of\ncommand. He was seated on an old-fashioned oaken chair, wriggling all\nover with curious carving; and the bottom", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1184, "position": 1184, "text": "en chair, wriggling all\nover with curious carving; and the bottom of which was formed of a\nstout interlacing of the same elastic stuff of which the wigwam was\nconstructed.\n\nThere was nothing so very particular, perhaps, about the", "labels": {"50": 12, "100": 38, "250": 65, "500": 171, "1000": 286, "2000": 668}}, {"id": 1185, "position": 1185, "text": "m was\nconstructed.\n\nThere was nothing so very particular, perhaps, about the appearance of\nthe elderly man I saw; he was brown and brawny, like most old seamen,\nand heavily rolled up in blue pilot-cloth, cut in the Quaker style", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 1186, "position": 1186, "text": "and heavily rolled up in blue pilot-cloth, cut in the Quaker style;\nonly there was a fine and almost microscopic net-work of the minutest\nwrinkles interlacing round his eyes, which must have arisen from his\ncontinual sailings", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 877}}, {"id": 1187, "position": 1187, "text": "cing round his eyes, which must have arisen from his\ncontinual sailings in many hard gales, and always looking to\nwindward;—for this causes the muscles about the eyes to become pursed\ntogether", "labels": {"50": 26, "100": 82, "250": 30, "500": 475, "1000": 469, "2000": 398}}, {"id": 1188, "position": 1188, "text": "the eyes to become pursed\ntogether. Such eye-wrinkles are very effectual in a scowl.\n\n“Is this the Captain of the Pequod?” said I, advancing to the door of\nthe tent.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 965, "2000": 142}}, {"id": 1189, "position": 1189, "text": "advancing to the door of\nthe tent.\n\n“Supposing it be the captain of the Pequod, what dost thou want of\nhim?” he demanded.\n\n“I was thinking of shipping.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1190, "position": 1190, "text": "I was thinking of shipping.”\n\n“Thou wast, wast thou? I see thou art no Nantucketer—ever been in a\nstove boat?”\n\n“No, Sir, I never have.”", "labels": {"50": 41, "100": 21, "250": 163, "500": 53, "1000": 385, "2000": 1233}}, {"id": 1191, "position": 1191, "text": ", Sir, I never have.”\n\n“Dost know nothing at all about whaling, I dare say—eh?\n\n“Nothing, Sir; but I have no doubt I shall soon learn. I’ve been\nseveral voyages in the merchant service,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1192, "position": 1192, "text": "shall soon learn. I’ve been\nseveral voyages in the merchant service, and I think that—”\n\n“Merchant service be damned. Talk not that lingo to me. Dost see that\nleg?—I’ll take that leg away from", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 1193, "position": 1193, "text": "Dost see that\nleg?—I’ll take that leg away from thy stern, if ever thou talkest of\nthe marchant service to me again. Marchant service indeed! I suppose\nnow ye feel considerable proud of having served in those march", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1194, "position": 1194, "text": "indeed! I suppose\nnow ye feel considerable proud of having served in those marchant\nships. But flukes! man, what makes thee want to go a whaling, eh?—it\nlooks a little suspicious, don’t it, eh?—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1195, "position": 1195, "text": "—it\nlooks a little suspicious, don’t it, eh?—Hast not been a pirate, hast\nthou?—Didst not rob thy last Captain, didst thou?—Dost not think of\nmurdering the officers when thou", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1196, "position": 1196, "text": "didst thou?—Dost not think of\nmurdering the officers when thou gettest to sea?”\n\nI protested my innocence of these things. I saw that under the mask of\nthese half humorous innuendoes, this old seaman, as an", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1197, "position": 1197, "text": "of\nthese half humorous innuendoes, this old seaman, as an insulated\nQuakerish Nantucketer, was full of his insular prejudices, and rather\ndistrustful of all aliens, unless they hailed from Cape Cod or the\nVineyard.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 300, "2000": 877}}, {"id": 1198, "position": 1198, "text": "ful of all aliens, unless they hailed from Cape Cod or the\nVineyard.\n\n“But what takes thee a-whaling? I want to know that before I think of\nshipping ye.”\n\n“Well, sir, I want to see what whaling is", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1199, "position": 1199, "text": ".”\n\n“Well, sir, I want to see what whaling is. I want to see the world.”\n\n“Want to see what whaling is, eh? Have ye clapped eye on Captain Ahab?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1200, "position": 1200, "text": "clapped eye on Captain Ahab?”\n\n“Who is Captain Ahab, sir?”\n\n“Aye, aye, I thought so. Captain Ahab is the Captain of this ship.”\n\n“I am mistaken then", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1201, "position": 1201, "text": "ship.”\n\n“I am mistaken then. I thought I was speaking to the Captain himself.”\n\n“Thou art speaking to Captain Peleg—that’s who ye are speaking to,\nyoung man. It belongs to me and Captain Bildad", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1202, "position": 1202, "text": "speaking to,\nyoung man. It belongs to me and Captain Bildad to see the Pequod fitted\nout for the voyage, and supplied with all her needs, including crew. We\nare part owners and agents", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 1203, "position": 1203, "text": "crew. We\nare part owners and agents. But as I was going to say, if thou wantest\nto know what whaling is, as thou tellest ye do, I can put ye in a way\nof finding it out before ye bind yourself to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1204, "position": 1204, "text": "can put ye in a way\nof finding it out before ye bind yourself to it, past backing out. Clap\neye on Captain Ahab, young man, and thou wilt find that he has only one\nleg.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1205, "position": 1205, "text": "find that he has only one\nleg.”\n\n“What do you mean, sir? Was the other one lost by a whale?”\n\n“Lost by a whale! Young man, come nearer to me: it was devoured, chewed\nup, crunch", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1206, "position": 1206, "text": ", come nearer to me: it was devoured, chewed\nup, crunched by the monstrousest parmacetty that ever chipped a\nboat!—ah, ah!”\n\nI was a little alarmed by his energy, perhaps also a little touched", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1207, "position": 1207, "text": "”\n\nI was a little alarmed by his energy, perhaps also a little touched at\nthe hearty grief in his concluding exclamation, but said as calmly as I\ncould, “What you say is no doubt true enough, sir; but how", "labels": {"50": 20, "100": 72, "250": 186, "500": 153, "1000": 939, "2000": 610}}, {"id": 1208, "position": 1208, "text": ", “What you say is no doubt true enough, sir; but how could I know\nthere was any peculiar ferocity in that particular whale, though indeed\nI might have inferred as much from the simple fact of the accident.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1209, "position": 1209, "text": "ferred as much from the simple fact of the accident.”\n\n“Look ye now, young man, thy lungs are a sort of soft, d’ye see; thou\ndost not talk shark a bit", "labels": {"50": 41, "100": 55, "250": 95, "500": 227, "1000": 965, "2000": 848}}, {"id": 1210, "position": 1210, "text": "dost not talk shark a bit. _Sure_, ye’ve been to sea before now; sure\nof that?”\n\n“Sir,” said I, “I thought I told you that I had been four voyages in\nthe merchant—”", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 1211, "position": 1211, "text": "thought I told you that I had been four voyages in\nthe merchant—”\n\n“Hard down out of that! Mind what I said about the marchant\nservice—don’t aggravate me—I won’t have it", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 1212, "position": 1212, "text": "aggravate me—I won’t have it. But let us understand each\nother. I have given thee a hint about what whaling is; do ye yet feel\ninclined for it?”\n\n“I do, sir.”\n\n“Very good", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1213, "position": 1213, "text": "for it?”\n\n“I do, sir.”\n\n“Very good. Now, art thou the man to pitch a harpoon down a live\nwhale’s throat, and then jump after it? Answer, quick!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1214, "position": 1214, "text": "then jump after it? Answer, quick!”\n\n“I am, sir, if it should be positively indispensable to do so; not to\nbe got rid of, that is; which I don’t take to be the fact.", "labels": {"50": 23, "100": 88, "250": 8, "500": 228, "1000": 943, "2000": 1881}}, {"id": 1215, "position": 1215, "text": ", that is; which I don’t take to be the fact.”\n\n“Good again. Now then, thou not only wantest to go a-whaling, to find\nout by experience what whaling is, but ye also want to go in", "labels": {"50": 41, "100": 64, "250": 163, "500": 72, "1000": 54, "2000": 1620}}, {"id": 1216, "position": 1216, "text": "find\nout by experience what whaling is, but ye also want to go in order to\nsee the world? Was not that what ye said? I thought so. Well then, just\nstep forward there, and take a peep over the weather-bow", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1217, "position": 1217, "text": "just\nstep forward there, and take a peep over the weather-bow, and then back\nto me and tell me what ye see there.”\n\nFor a moment I stood a little puzzled by this curious request, not\nknowing exactly how to take it", "labels": {"50": 25, "100": 5, "250": 136, "500": 388, "1000": 313, "2000": 1521}}, {"id": 1218, "position": 1218, "text": "a little puzzled by this curious request, not\nknowing exactly how to take it, whether humorously or in earnest. But\nconcentrating all his crow’s feet into one scowl, Captain Peleg started\nme on the errand.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1219, "position": 1219, "text": "Captain Peleg started\nme on the errand.\n\nGoing forward and glancing over the weather bow, I perceived that the\nship swinging to her anchor with the flood-tide, was now obliquely\npointing towards the open ocean", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1220, "position": 1220, "text": "now obliquely\npointing towards the open ocean. The prospect was unlimited, but\nexceedingly monotonous and forbidding; not the slightest variety that I\ncould see.\n\n“Well, what’s the report?” said Peleg when I came back", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 631}}, {"id": 1221, "position": 1221, "text": ", what’s the report?” said Peleg when I came back; “what did ye\nsee?”\n\n“Not much,” I replied—“nothing but water; considerable horizon though,\nand there’s a squall coming up", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 1222, "position": 1222, "text": "; considerable horizon though,\nand there’s a squall coming up, I think.”\n\n“Well, what does thou think then of seeing the world? Do ye wish to go\nround Cape Horn to see any more of it, eh?", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1223, "position": 1223, "text": "wish to go\nround Cape Horn to see any more of it, eh? Can’t ye see the world where\nyou stand?”\n\nI was a little staggered, but go a-whaling I must, and I would; and the\nPequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1224, "position": 1224, "text": "a-whaling I must, and I would; and the\nPequod was as good a ship as any—I thought the best—and all this I now\nrepeated to Peleg. Seeing me so determined, he expressed his\nwillingness to ship me", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1225, "position": 1225, "text": "Peleg. Seeing me so determined, he expressed his\nwillingness to ship me.\n\n“And thou mayest as well sign the papers right off,” he added—“come\nalong with ye.” And so saying, he led the way below deck", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 967}}, {"id": 1226, "position": 1226, "text": "along with ye.” And so saying, he led the way below deck into the\ncabin.\n\nSeated on the transom was what seemed to me a most uncommon and\nsurprising figure. It turned out to be Captain Bildad, who along with\nCaptain", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 1227, "position": 1227, "text": ". It turned out to be Captain Bildad, who along with\nCaptain Peleg was one of the largest owners of the vessel; the other\nshares, as is sometimes the case in these ports, being held by a crowd\nof old annuitants", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 1228, "position": 1228, "text": "case in these ports, being held by a crowd\nof old annuitants; widows, fatherless children, and chancery wards;\neach owning about the value of a timber head, or a foot of plank, or a\nnail or two in the", "labels": {"50": 43, "100": 76, "250": 24, "500": 230, "1000": 995, "2000": 1787}}, {"id": 1229, "position": 1229, "text": "head, or a foot of plank, or a\nnail or two in the ship. People in Nantucket invest their money in\nwhaling vessels, the same way that you do yours in approved state\nstocks bringing in good interest.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 887}}, {"id": 1230, "position": 1230, "text": "in approved state\nstocks bringing in good interest.\n\nNow, Bildad, like Peleg, and indeed many other Nantucketers, was a\nQuaker, the island having been originally settled by that sect; and to\nthis day its inhabitants in general retain", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 723, "2000": 489}}, {"id": 1231, "position": 1231, "text": "originally settled by that sect; and to\nthis day its inhabitants in general retain in an uncommon measure the\npeculiarities of the Quaker, only variously and anomalously modified by\nthings altogether alien and heterogeneous", "labels": {"50": 31, "100": 7, "250": 53, "500": 126, "1000": 995, "2000": 1105}}, {"id": 1232, "position": 1232, "text": "things altogether alien and heterogeneous. For some of these same\nQuakers are the most sanguinary of all sailors and whale-hunters. They\nare fighting Quakers; they are Quakers with a vengeance.", "labels": {"50": 31, "100": 95, "250": 69, "500": 307, "1000": 560, "2000": 502}}, {"id": 1233, "position": 1233, "text": "are Quakers with a vengeance.\n\nSo that there are instances among them of men, who, named with\nScripture names—a singularly common fashion on the island—and in\nchildhood naturally imbibing the stately dramatic thee and thou of the\nQuaker id", "labels": {"50": 44, "100": 38, "250": 77, "500": 421, "1000": 257, "2000": 1987}}, {"id": 1234, "position": 1234, "text": "naturally imbibing the stately dramatic thee and thou of the\nQuaker idiom; still, from the audacious, daring, and boundless\nadventure of their subsequent lives, strangely blend with these\nunoutgrown peculiarities, a thousand bold", "labels": {"50": 17, "100": 37, "250": 146, "500": 182, "1000": 355, "2000": 1873}}, {"id": 1235, "position": 1235, "text": ", strangely blend with these\nunoutgrown peculiarities, a thousand bold dashes of character, not\nunworthy a Scandinavian sea-king, or a poetical Pagan Roman. And when\nthese things unite in a man of greatly superior natural force,", "labels": {"50": 17, "100": 16, "250": 87, "500": 182, "1000": 355, "2000": 521}}, {"id": 1236, "position": 1236, "text": ". And when\nthese things unite in a man of greatly superior natural force, with a\nglobular brain and a ponderous heart; who has also by the stillness and\nseclusion of many long night-watches in the remotest waters, and\nbeneath", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1237, "position": 1237, "text": "lusion of many long night-watches in the remotest waters, and\nbeneath constellations never seen here at the north, been led to think\nuntraditionally and independently; receiving all nature’s sweet or\nsavage impressions fresh from her own virgin voluntary", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 16}}, {"id": 1238, "position": 1238, "text": "receiving all nature’s sweet or\nsavage impressions fresh from her own virgin voluntary and confiding\nbreast, and thereby chiefly, but with some help from accidental\nadvantages, to learn a bold and nervous lofty language—that man makes\none in a whole", "labels": {"50": 9, "100": 26, "250": 120, "500": 12, "1000": 290, "2000": 348}}, {"id": 1239, "position": 1239, "text": "a bold and nervous lofty language—that man makes\none in a whole nation’s census—a mighty pageant creature, formed for\nnoble tragedies. Nor will it at all detract from him, dramatically\nregarded, if either by birth", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 858, "2000": 371}}, {"id": 1240, "position": 1240, "text": "at all detract from him, dramatically\nregarded, if either by birth or other circumstances, he have what seems\na half wilful overruling morbidness at the bottom of his nature. For\nall men tragically great are made so through", "labels": {"50": 17, "100": 16, "250": 87, "500": 71, "1000": 355, "2000": 521}}, {"id": 1241, "position": 1241, "text": "bottom of his nature. For\nall men tragically great are made so through a certain morbidness. Be\nsure of this, O young ambition, all mortal greatness is but disease.\nBut, as yet we have not to do with such an", "labels": {"50": 1, "100": 80, "250": 128, "500": 398, "1000": 799, "2000": 973}}, {"id": 1242, "position": 1242, "text": "but disease.\nBut, as yet we have not to do with such an one, but with quite another;\nand still a man, who, if indeed peculiar, it only results again from\nanother phase of the Quaker, modified by individual circumstances.", "labels": {"50": 31, "100": 95, "250": 76, "500": 307, "1000": 343, "2000": 761}}, {"id": 1243, "position": 1243, "text": "results again from\nanother phase of the Quaker, modified by individual circumstances.\n\nLike Captain Peleg, Captain Bildad was a well-to-do, retired whaleman.\nBut unlike Captain Peleg—who cared not a rush for what are called", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1244, "position": 1244, "text": "But unlike Captain Peleg—who cared not a rush for what are called\nserious things, and indeed deemed those self-same serious things the\nveriest of all trifles—Captain Bildad had not only been originally\neducated according to the strict", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1245, "position": 1245, "text": "—Captain Bildad had not only been originally\neducated according to the strictest sect of Nantucket Quakerism, but\nall his subsequent ocean life, and the sight of many unclad, lovely\nisland creatures, round the Horn—all that had", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1246, "position": 1246, "text": "unclad, lovely\nisland creatures, round the Horn—all that had not moved this native\nborn Quaker one single jot, had not so much as altered one angle of his\nvest. Still, for all this immutableness, was there", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 9, "2000": 1735}}, {"id": 1247, "position": 1247, "text": "his\nvest. Still, for all this immutableness, was there some lack of common\nconsistency about worthy Captain Bildad. Though refusing, from\nconscientious scruples, to bear arms against land invaders, yet himself\nhad ill", "labels": {"50": 45, "100": 29, "250": 82, "500": 73, "1000": 851, "2000": 1584}}, {"id": 1248, "position": 1248, "text": "scruples, to bear arms against land invaders, yet himself\nhad illimitably invaded the Atlantic and Pacific; and though a sworn\nfoe to human bloodshed, yet had he in his straight-bodied coat, spilled\ntuns upon tuns", "labels": {"50": 45, "100": 38, "250": 6, "500": 261, "1000": 338, "2000": 47}}, {"id": 1249, "position": 1249, "text": "had he in his straight-bodied coat, spilled\ntuns upon tuns of leviathan gore. How now in the contemplative evening\nof his days, the pious Bildad reconciled these things in the\nreminiscence, I do", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1250, "position": 1250, "text": "Bildad reconciled these things in the\nreminiscence, I do not know; but it did not seem to concern him much,\nand very probably he had long since come to the sage and sensible\nconclusion that a man’s religion is one", "labels": {"50": 10, "100": 94, "250": 13, "500": 236, "1000": 919, "2000": 1973}}, {"id": 1251, "position": 1251, "text": "come to the sage and sensible\nconclusion that a man’s religion is one thing, and this practical world\nquite another. This world pays dividends. Rising from a little\ncabin-boy in short clothes of the drabbest drab, to", "labels": {"50": 31, "100": 94, "250": 69, "500": 453, "1000": 560, "2000": 502}}, {"id": 1252, "position": 1252, "text": "-boy in short clothes of the drabbest drab, to a harpooneer in a\nbroad shad-bellied waistcoat; from that becoming boat-header,\nchief-mate, and captain, and finally a ship owner;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1253, "position": 1253, "text": "header,\nchief-mate, and captain, and finally a ship owner; Bildad, as I hinted\nbefore, had concluded his adventurous career by wholly retiring from\nactive life at the goodly age of sixty, and dedicating his remaining\ndays", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1254, "position": 1254, "text": "at the goodly age of sixty, and dedicating his remaining\ndays to the quiet receiving of his well-earned income.\n\nNow, Bildad, I am sorry to say, had the reputation of being an\nincorrigible old hu", "labels": {"50": 44, "100": 37, "250": 229, "500": 481, "1000": 448, "2000": 825}}, {"id": 1255, "position": 1255, "text": "to say, had the reputation of being an\nincorrigible old hunks, and in his sea-going days, a bitter, hard\ntask-master. They told me in Nantucket, though it certainly seems a\ncurious story, that", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1256, "position": 1256, "text": "told me in Nantucket, though it certainly seems a\ncurious story, that when he sailed the old Categut whaleman, his crew,\nupon arriving home, were mostly all carried ashore to the hospital,\nsore exhausted and worn out", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 1257, "position": 1257, "text": "all carried ashore to the hospital,\nsore exhausted and worn out. For a pious man, especially for a Quaker,\nhe was certainly rather hard-hearted, to say the least. He never used\nto swear, though, at his men, they said", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1258, "position": 1258, "text": ". He never used\nto swear, though, at his men, they said; but somehow he got an\ninordinate quantity of cruel, unmitigated hard work out of them. When\nBildad was a chief-mate, to have", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1790}}, {"id": 1259, "position": 1259, "text": "of them. When\nBildad was a chief-mate, to have his drab-coloured eye intently looking\nat you, made you feel completely nervous, till you could clutch\nsomething—a hammer or a marling-spike, and go to", "labels": {"50": 25, "100": 93, "250": 91, "500": 233, "1000": 533, "2000": 448}}, {"id": 1260, "position": 1260, "text": "clutch\nsomething—a hammer or a marling-spike, and go to work like mad, at\nsomething or other, never mind what. Indolence and idleness perished\nbefore him. His own person was the exact embodiment of his utili", "labels": {"50": 22, "100": 51, "250": 150, "500": 481, "1000": 990, "2000": 1966}}, {"id": 1261, "position": 1261, "text": "him. His own person was the exact embodiment of his utilitarian\ncharacter. On his long, gaunt body, he carried no spare flesh, no\nsuperfluous beard, his chin having a soft, economical nap to it, like\nthe", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 460, "2000": 1927}}, {"id": 1262, "position": 1262, "text": "beard, his chin having a soft, economical nap to it, like\nthe worn nap of his broad-brimmed hat.\n\nSuch, then, was the person that I saw seated on the transom when I\nfollowed Captain Peleg down into the", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 967}}, {"id": 1263, "position": 1263, "text": "saw seated on the transom when I\nfollowed Captain Peleg down into the cabin. The space between the decks\nwas small; and there, bolt-upright, sat old Bildad, who always sat so,\nand never leaned, and this to", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1264, "position": 1264, "text": "ldad, who always sat so,\nand never leaned, and this to save his coat tails. His broad-brim was\nplaced beside him; his legs were stiffly crossed; his drab vesture was\nbuttoned up to his chin; and", "labels": {"50": 23, "100": 78, "250": 39, "500": 178, "1000": 858, "2000": 955}}, {"id": 1265, "position": 1265, "text": "; his drab vesture was\nbuttoned up to his chin; and spectacles on nose, he seemed absorbed in\nreading from a ponderous volume.\n\n“Bildad,” cried Captain Peleg, “at it again, Bildad", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1266, "position": 1266, "text": ",” cried Captain Peleg, “at it again, Bildad, eh? Ye have been\nstudying those Scriptures, now, for the last thirty years, to my\ncertain knowledge. How far ye got, Bildad?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1267, "position": 1267, "text": "certain knowledge. How far ye got, Bildad?”\n\nAs if long habituated to such profane talk from his old shipmate,\nBildad, without noticing his present irreverence, quietly looked up,\nand seeing me,", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 877}}, {"id": 1268, "position": 1268, "text": "his present irreverence, quietly looked up,\nand seeing me, glanced again inquiringly towards Peleg.\n\n“He says he’s our man, Bildad,” said Peleg, “he wants to ship.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 1269, "position": 1269, "text": "ldad,” said Peleg, “he wants to ship.”\n\n“Dost thee?” said Bildad, in a hollow tone, and turning round to me.\n\n“I _dost_,” said I unconsciously,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1270, "position": 1270, "text": "me.\n\n“I _dost_,” said I unconsciously, he was so intense a Quaker.\n\n“What do ye think of him, Bildad?” said Peleg.\n\n“He’ll do,” said Bildad", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1271, "position": 1271, "text": "said Peleg.\n\n“He’ll do,” said Bildad, eyeing me, and then went on spelling away at\nhis book in a mumbling tone quite audible.\n\nI thought him the queerest old Quaker I ever saw, especially as", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 1272, "position": 1272, "text": ".\n\nI thought him the queerest old Quaker I ever saw, especially as Peleg,\nhis friend and old shipmate, seemed such a blusterer. But I said\nnothing, only looking round me sharply", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 786}}, {"id": 1273, "position": 1273, "text": "nothing, only looking round me sharply. Peleg now threw open a chest,\nand drawing forth the ship’s articles, placed pen and ink before him,\nand seated himself at a little table. I began to think it was high time\nto settle", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 1274, "position": 1274, "text": "at a little table. I began to think it was high time\nto settle with myself at what terms I would be willing to engage for\nthe voyage. I was already aware that in the whaling business they paid\nno wages; but all hands, including the", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1275, "position": 1275, "text": "in the whaling business they paid\nno wages; but all hands, including the captain, received certain shares\nof the profits called _lays_, and that these lays were proportioned to\nthe degree of importance pertaining to the respective duties of the\nship’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1276, "position": 1276, "text": "to\nthe degree of importance pertaining to the respective duties of the\nship’s company. I was also aware that being a green hand at whaling, my\nown lay would not be very large; but considering that I was used to the\nsea, could steer", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 1277, "position": 1277, "text": "very large; but considering that I was used to the\nsea, could steer a ship, splice a rope, and all that, I made no doubt\nthat from all I had heard I should be offered at least the 275th\nlay—that is", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1278, "position": 1278, "text": "had heard I should be offered at least the 275th\nlay—that is, the 275th part of the clear net proceeds of the voyage,\nwhatever that might eventually amount to. And though the 275th lay was\nwhat they call a rather _long", "labels": {"50": 45, "100": 28, "250": 125, "500": 349, "1000": 842, "2000": 1495}}, {"id": 1279, "position": 1279, "text": ". And though the 275th lay was\nwhat they call a rather _long lay_, yet it was better than nothing; and\nif we had a lucky voyage, might pretty nearly pay for the clothing I\nwould wear out on it, not to speak", "labels": {"50": 25, "100": 5, "250": 125, "500": 349, "1000": 483, "2000": 1707}}, {"id": 1280, "position": 1280, "text": "nearly pay for the clothing I\nwould wear out on it, not to speak of my three years’ beef and board,\nfor which I would not have to pay one stiver.\n\nIt might be thought that this was a poor way to accumulate a princely", "labels": {"50": 8, "100": 28, "250": 1, "500": 419, "1000": 926, "2000": 1750}}, {"id": 1281, "position": 1281, "text": ".\n\nIt might be thought that this was a poor way to accumulate a princely\nfortune—and so it was, a very poor way indeed. But I am one of those\nthat never take on about princely fortunes, and am quite content if the\nworld is", "labels": {"50": 21, "100": 19, "250": 161, "500": 242, "1000": 312, "2000": 445}}, {"id": 1282, "position": 1282, "text": "never take on about princely fortunes, and am quite content if the\nworld is ready to board and lodge me, while I am putting up at this\ngrim sign of the Thunder Cloud. Upon the whole, I thought that the\n275th lay would be about", "labels": {"50": 8, "100": 14, "250": 81, "500": 330, "1000": 28, "2000": 601}}, {"id": 1283, "position": 1283, "text": ". Upon the whole, I thought that the\n275th lay would be about the fair thing, but would not have been\nsurprised had I been offered the 200th, considering I was of a\nbroad-shouldered make.", "labels": {"50": 44, "100": 28, "250": 169, "500": 130, "1000": 629, "2000": 184}}, {"id": 1284, "position": 1284, "text": "was of a\nbroad-shouldered make.\n\nBut one thing, nevertheless, that made me a little distrustful about\nreceiving a generous share of the profits was this: Ashore, I had heard\nsomething of both Captain Peleg and his unaccountable old", "labels": {"50": 25, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1285, "position": 1285, "text": "had heard\nsomething of both Captain Peleg and his unaccountable old crony Bildad;\nhow that they being the principal proprietors of the Pequod, therefore\nthe other and more inconsiderable and scattered owners, left nearly", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1286, "position": 1286, "text": "therefore\nthe other and more inconsiderable and scattered owners, left nearly the\nwhole management of the ship’s affairs to these two. And I did not know\nbut what the stingy old Bildad might have a mighty deal to say about", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 1495}}, {"id": 1287, "position": 1287, "text": "the stingy old Bildad might have a mighty deal to say about\nshipping hands, especially as I now found him on board the Pequod,\nquite at home there in the cabin, and reading his Bible as if at his\nown fireside", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1288, "position": 1288, "text": "in the cabin, and reading his Bible as if at his\nown fireside. Now while Peleg was vainly trying to mend a pen with his\njack-knife, old Bildad, to my no small surprise, considering that he\nwas", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 1289, "position": 1289, "text": "old Bildad, to my no small surprise, considering that he\nwas such an interested party in these proceedings; Bildad never heeded\nus, but went on mumbling to himself out of his book, “_Lay_ not up for", "labels": {"50": 25, "100": 28, "250": 175, "500": 202, "1000": 421, "2000": 1645}}, {"id": 1290, "position": 1290, "text": "bling to himself out of his book, “_Lay_ not up for\nyourselves treasures upon earth, where moth—”\n\n“Well, Captain Bildad,” interrupted Peleg, “what d’ye say, what lay\nshall we give this", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1291, "position": 1291, "text": "leg, “what d’ye say, what lay\nshall we give this young man?”\n\n“Thou knowest best,” was the sepulchral reply, “the seven hundred and\nseventy-seventh wouldn’t be too much, would", "labels": {"50": 18, "100": 83, "250": 102, "500": 61, "1000": 672, "2000": 1091}}, {"id": 1292, "position": 1292, "text": "the seven hundred and\nseventy-seventh wouldn’t be too much, would it?—‘where moth and rust do\ncorrupt, but _lay_—’”\n\n_Lay_, indeed, thought I, and such a lay! the seven hundred", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1293, "position": 1293, "text": "_, indeed, thought I, and such a lay! the seven hundred and\nseventy-seventh! Well, old Bildad, you are determined that I, for one,\nshall not _lay_ up many _lays_ here below, where", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1294, "position": 1294, "text": ",\nshall not _lay_ up many _lays_ here below, where moth and rust do\ncorrupt. It was an exceedingly _long lay_ that, indeed; and though from\nthe magnitude of the figure it might at first deceive a", "labels": {"50": 8, "100": 68, "250": 193, "500": 374, "1000": 318, "2000": 906}}, {"id": 1295, "position": 1295, "text": "though from\nthe magnitude of the figure it might at first deceive a landsman, yet\nthe slightest consideration will show that though seven hundred and\nseventy-seven is a pretty large number, yet, when you come to make a\n_teenth_", "labels": {"50": 24, "100": 76, "250": 24, "500": 7, "1000": 834, "2000": 1334}}, {"id": 1296, "position": 1296, "text": "large number, yet, when you come to make a\n_teenth_ of it, you will then see, I say, that the seven hundred and\nseventy-seventh part of a farthing is a good deal less than seven\nhundred and seventy-", "labels": {"50": 23, "100": 88, "250": 24, "500": 154, "1000": 943, "2000": 651}}, {"id": 1297, "position": 1297, "text": "of a farthing is a good deal less than seven\nhundred and seventy-seven gold doubloons; and so I thought at the time.\n\n“Why, blast your eyes, Bildad,” cried Peleg, “thou dost", "labels": {"50": 18, "100": 87, "250": 219, "500": 180, "1000": 317, "2000": 1087}}, {"id": 1298, "position": 1298, "text": "eyes, Bildad,” cried Peleg, “thou dost not want to\nswindle this young man! he must have more than that.”\n\n“Seven hundred and seventy-seventh,” again said Bildad, without lifting", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 1299, "position": 1299, "text": "hundred and seventy-seventh,” again said Bildad, without lifting\nhis eyes; and then went on mumbling—“for where your treasure is, there\nwill your heart be also.”\n\n“I am going to put him down for the", "labels": {"50": 45, "100": 83, "250": 170, "500": 60, "1000": 520, "2000": 363}}, {"id": 1300, "position": 1300, "text": "heart be also.”\n\n“I am going to put him down for the three hundredth,” said Peleg, “do\nye hear that, Bildad! The three hundredth lay, I say.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 1620}}, {"id": 1301, "position": 1301, "text": "three hundredth lay, I say.”\n\nBildad laid down his book, and turning solemnly towards him said,\n“Captain Peleg, thou hast a generous heart; but thou must consider the\nduty thou owest to the other owners of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1302, "position": 1302, "text": "; but thou must consider the\nduty thou owest to the other owners of this ship—widows and orphans,\nmany of them—and that if we too abundantly reward the labors of this\nyoung man, we may be taking the bread from those", "labels": {"50": 23, "100": 17, "250": 219, "500": 205, "1000": 317, "2000": 1951}}, {"id": 1303, "position": 1303, "text": "labors of this\nyoung man, we may be taking the bread from those widows and those\norphans. The seven hundred and seventy-seventh lay, Captain Peleg.”\n\n“Thou Bildad!” roared Peleg, starting up and clatter", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1304, "position": 1304, "text": "Thou Bildad!” roared Peleg, starting up and clattering about the\ncabin. “Blast ye, Captain Bildad, if I had followed thy advice in these\nmatters, I would afore now had a conscience to lug", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1305, "position": 1305, "text": "in these\nmatters, I would afore now had a conscience to lug about that would be\nheavy enough to founder the largest ship that ever sailed round Cape\nHorn.”\n\n“Captain Peleg,” said Bildad steadily, “thy conscience may", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1306, "position": 1306, "text": "Captain Peleg,” said Bildad steadily, “thy conscience may be drawing\nten inches of water, or ten fathoms, I can’t tell; but as thou art\nstill an impenitent man, Captain Peleg,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1307, "position": 1307, "text": "as thou art\nstill an impenitent man, Captain Peleg, I greatly fear lest thy\nconscience be but a leaky one; and will in the end sink thee foundering\ndown to the fiery pit, Captain Peleg.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1308, "position": 1308, "text": "foundering\ndown to the fiery pit, Captain Peleg.”\n\n“Fiery pit! fiery pit! ye insult me, man; past all natural bearing, ye\ninsult me. It’s an all-fired outrage to tell any human creature that\nhe", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1309, "position": 1309, "text": "It’s an all-fired outrage to tell any human creature that\nhe’s bound to hell. Flukes and flames! Bildad, say that again to me,\nand start my soul-bolts, but I’ll—I’", "labels": {"50": 23, "100": 88, "250": 219, "500": 498, "1000": 627, "2000": 1199}}, {"id": 1310, "position": 1310, "text": ",\nand start my soul-bolts, but I’ll—I’ll—yes, I’ll swallow a live goat\nwith all his hair and horns on. Out of the cabin, ye canting,\ndrab-coloured son of a", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 851, "2000": 967}}, {"id": 1311, "position": 1311, "text": "of the cabin, ye canting,\ndrab-coloured son of a wooden gun—a straight wake with ye!”\n\nAs he thundered out this he made a rush at Bildad, but with a\nmarvellous oblique, sliding celer", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1312, "position": 1312, "text": "at Bildad, but with a\nmarvellous oblique, sliding celerity, Bildad for that time eluded him.\n\nAlarmed at this terrible outburst between the two principal and\nresponsible owners of the ship, and feeling half a mind to give", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1313, "position": 1313, "text": "principal and\nresponsible owners of the ship, and feeling half a mind to give up all\nidea of sailing in a vessel so questionably owned and temporarily\ncommanded, I stepped aside from the door to give egress to Bildad, who,\nI", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 1314, "position": 1314, "text": "the door to give egress to Bildad, who,\nI made no doubt, was all eagerness to vanish from before the awakened\nwrath of Peleg. But to my astonishment, he sat down again on the\ntransom very quietly,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1315, "position": 1315, "text": "to my astonishment, he sat down again on the\ntransom very quietly, and seemed to have not the slightest intention of\nwithdrawing. He seemed quite used to impenitent Peleg and his ways. As\nfor Peleg, after letting off his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1316, "position": 1316, "text": "Peleg and his ways. As\nfor Peleg, after letting off his rage as he had, there seemed no more\nleft in him, and he, too, sat down like a lamb, though he twitched a\nlittle as if still nervously agitated", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1620}}, {"id": 1317, "position": 1317, "text": "like a lamb, though he twitched a\nlittle as if still nervously agitated. “Whew!” he whistled at last—“the\nsquall’s gone off to leeward, I think", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1192}}, {"id": 1318, "position": 1318, "text": "to leeward, I think. Bildad, thou used to be good at\nsharpening a lance, mend that pen, will ye. My jack-knife here needs\nthe grindstone. That’s he; thank ye, Bilda", "labels": {"50": 41, "100": 83, "250": 170, "500": 60, "1000": 140, "2000": 363}}, {"id": 1319, "position": 1319, "text": "needs\nthe grindstone. That’s he; thank ye, Bildad. Now then, my young man,\nIshmael’s thy name, didn’t ye say? Well then, down ye go here, Ishmael,", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 1320, "position": 1320, "text": "ye say? Well then, down ye go here, Ishmael,\nfor the three hundredth lay.”\n\n“Captain Peleg,” said I, “I have a friend with me who wants to ship\ntoo—shall I bring him down", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 967}}, {"id": 1321, "position": 1321, "text": "a friend with me who wants to ship\ntoo—shall I bring him down to-morrow?”\n\n“To be sure,” said Peleg. “Fetch him along, and we’ll look at him.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1322, "position": 1322, "text": "and we’ll look at him.”\n\n“What lay does he want?” groaned Bildad, glancing up from the book in\nwhich he had again been burying himself.\n\n“Oh! never thee mind about that, Bildad,”", "labels": {"50": 39, "100": 99, "250": 163, "500": 432, "1000": 701, "2000": 1790}}, {"id": 1323, "position": 1323, "text": ".\n\n“Oh! never thee mind about that, Bildad,” said Peleg. “Has he ever\nwhaled it any?” turning to me.\n\n“Killed more whales than I can count, Captain Peleg.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1324, "position": 1324, "text": "more whales than I can count, Captain Peleg.”\n\n“Well, bring him along then.”\n\nAnd, after signing the papers, off I went; nothing doubting but that I\nhad done a good morning’s work, and that the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1325, "position": 1325, "text": "but that I\nhad done a good morning’s work, and that the Pequod was the identical\nship that Yojo had provided to carry Queequeg and me round the Cape.\n\nBut I had not proceeded far, when I began to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1326, "position": 1326, "text": "round the Cape.\n\nBut I had not proceeded far, when I began to bethink me that the\nCaptain with whom I was to sail yet remained unseen by me; though,\nindeed, in many cases, a whale-ship will be completely fitted out", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1327, "position": 1327, "text": "indeed, in many cases, a whale-ship will be completely fitted out, and\nreceive all her crew on board, ere the captain makes himself visible by\narriving to take command; for sometimes these voyages are so prolonged,\nand the shore intervals at", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1328, "position": 1328, "text": "command; for sometimes these voyages are so prolonged,\nand the shore intervals at home so exceedingly brief, that if the\ncaptain have a family, or any absorbing concernment of that sort, he\ndoes not trouble himself much about his ship in port,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 887}}, {"id": 1329, "position": 1329, "text": "that sort, he\ndoes not trouble himself much about his ship in port, but leaves her to\nthe owners till all is ready for sea. However, it is always as well to\nhave a look at him before irrevocably committing yourself into", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 877}}, {"id": 1330, "position": 1330, "text": "to\nhave a look at him before irrevocably committing yourself into his\nhands. Turning back I accosted Captain Peleg, inquiring where Captain\nAhab was to be found.\n\n“And what dost thou want of Captain Ah", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1331, "position": 1331, "text": "was to be found.\n\n“And what dost thou want of Captain Ahab? It’s all right enough; thou\nart shipped.”\n\n“Yes, but I should like to see him.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 1332, "position": 1332, "text": "like to see him.”\n\n“But I don’t think thou wilt be able to at present. I don’t know\nexactly what’s the matter with him; but he keeps close inside the\nhouse; a sort of sick, and", "labels": {"50": 46, "100": 58, "250": 75, "500": 157, "1000": 970, "2000": 1199}}, {"id": 1333, "position": 1333, "text": "; but he keeps close inside the\nhouse; a sort of sick, and yet he don’t look so. In fact, he ain’t\nsick; but no, he isn’t well either", "labels": {"50": 41, "100": 21, "250": 207, "500": 53, "1000": 333, "2000": 1082}}, {"id": 1334, "position": 1334, "text": "he isn’t well either. Any how, young man, he won’t always\nsee me, so I don’t suppose he will thee. He’s a queer man, Captain\nAhab—so some think—but a good one", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1335, "position": 1335, "text": "queer man, Captain\nAhab—so some think—but a good one. Oh, thou’lt like him well enough; no\nfear, no fear. He’s a grand, ungodly, god-like man, Captain Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1336, "position": 1336, "text": "a grand, ungodly, god-like man, Captain Ahab;\ndoesn’t speak much; but, when he does speak, then you may well listen.\nMark ye, be forewarned; Ahab’s above the common", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1337, "position": 1337, "text": "Mark ye, be forewarned; Ahab’s above the common; Ahab’s been in\ncolleges, as well as ’mong the cannibals; been used to deeper wonders\nthan the waves; fixed his fiery lance in", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 637, "2000": 39}}, {"id": 1338, "position": 1338, "text": "; been used to deeper wonders\nthan the waves; fixed his fiery lance in mightier, stranger foes than\nwhales. His lance! aye, the keenest and the surest that out of all our\nisle! Oh! he ain’t Captain", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1339, "position": 1339, "text": "st that out of all our\nisle! Oh! he ain’t Captain Bildad; no, and he ain’t Captain Peleg;\n_he’s Ahab_, boy; and Ahab of old, thou knowest,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1340, "position": 1340, "text": "ab_, boy; and Ahab of old, thou knowest, was a crowned king!”\n\n“And a very vile one. When that wicked king was slain, the dogs, did\nthey not lick his blood?”", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1341, "position": 1341, "text": "the dogs, did\nthey not lick his blood?”\n\n“Come hither to me—hither, hither,” said Peleg, with a significance in\nhis eye that almost startled me. “Look ye, lad; never say that on", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1342, "position": 1342, "text": "that almost startled me. “Look ye, lad; never say that on board\nthe Pequod. Never say it anywhere. Captain Ahab did not name himself.\n’Twas a foolish, ignorant whim of his crazy, widowed mother,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1343, "position": 1343, "text": "Twas a foolish, ignorant whim of his crazy, widowed mother, who died\nwhen he was only a twelvemonth old. And yet the old squaw Tistig, at\nGayhead, said that the name would somehow prove prophet", "labels": {"50": 41, "100": 21, "250": 174, "500": 428, "1000": 58, "2000": 1529}}, {"id": 1344, "position": 1344, "text": "tig, at\nGayhead, said that the name would somehow prove prophetic. And,\nperhaps, other fools like her may tell thee the same. I wish to warn\nthee. It’s a lie", "labels": {"50": 30, "100": 1, "250": 85, "500": 257, "1000": 587, "2000": 488}}, {"id": 1345, "position": 1345, "text": "thee. It’s a lie. I know Captain Ahab well; I’ve sailed with him as\nmate years ago; I know what he is—a good man—not a pious, good man,\nlike Bildad, but a", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1346, "position": 1346, "text": "—not a pious, good man,\nlike Bildad, but a swearing good man—something like me—only there’s a\ngood deal more of him. Aye, aye, I know that he was never very jolly;\nand I know", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1790}}, {"id": 1347, "position": 1347, "text": ", aye, I know that he was never very jolly;\nand I know that on the passage home, he was a little out of his mind\nfor a spell; but it was the sharp shooting pains in his bleeding stump\nthat brought that about, as", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1790}}, {"id": 1348, "position": 1348, "text": "was the sharp shooting pains in his bleeding stump\nthat brought that about, as any one might see. I know, too, that ever\nsince he lost his leg last voyage by that accursed whale, he’s been a\nkind of moody—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1349, "position": 1349, "text": "that accursed whale, he’s been a\nkind of moody—desperate moody, and savage sometimes; but that will all\npass off. And once for all, let me tell thee and assure thee, young\nman, it’s better to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1350, "position": 1350, "text": "me tell thee and assure thee, young\nman, it’s better to sail with a moody good captain than a laughing bad\none. So good-bye to thee—and wrong not Captain Ahab, because he happens\nto have a wicked name", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1351, "position": 1351, "text": "wrong not Captain Ahab, because he happens\nto have a wicked name. Besides, my boy, he has a wife—not three voyages\nwedded—a sweet, resigned girl. Think of that; by that sweet girl that\nold man has a", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1352, "position": 1352, "text": "girl. Think of that; by that sweet girl that\nold man has a child: hold ye then there can be any utter, hopeless harm\nin Ahab? No, no, my lad; stricken, blasted, if he be, Ahab has", "labels": {"50": 6, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 1353, "position": 1353, "text": ", my lad; stricken, blasted, if he be, Ahab has his\nhumanities!”\n\nAs I walked away, I was full of thoughtfulness; what had been\nincidentally revealed to me of Captain Ahab, filled me with a certain\nwild", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1354, "position": 1354, "text": "ally revealed to me of Captain Ahab, filled me with a certain\nwild vagueness of painfulness concerning him. And somehow, at the time,\nI felt a sympathy and a sorrow for him, but for I don’t know what,\nunless", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1355, "position": 1355, "text": "a sorrow for him, but for I don’t know what,\nunless it was the cruel loss of his leg. And yet I also felt a strange\nawe of him; but that sort of awe, which I cannot at all describe, was\nnot", "labels": {"50": 20, "100": 79, "250": 186, "500": 128, "1000": 964, "2000": 1099}}, {"id": 1356, "position": 1356, "text": "but that sort of awe, which I cannot at all describe, was\nnot exactly awe; I do not know what it was. But I felt it; and it did\nnot disincline me towards him; though I felt impatience at what seemed", "labels": {"50": 20, "100": 5, "250": 132, "500": 128, "1000": 21, "2000": 1634}}, {"id": 1357, "position": 1357, "text": "disincline me towards him; though I felt impatience at what seemed\nlike mystery in him, so imperfectly as he was known to me then.\nHowever, my thoughts were at length carried in other directions, so\nthat for the present dark Ah", "labels": {"50": 20, "100": 5, "250": 101, "500": 120, "1000": 421, "2000": 1559}}, {"id": 1358, "position": 1358, "text": "were at length carried in other directions, so\nthat for the present dark Ahab slipped my mind.\n\n\nCHAPTER 17. The Ramadan.\n\nAs Queequeg’s Ramadan, or Fasting and Humiliation, was to continue all\nday, I", "labels": {"50": 32, "100": 0, "250": 233, "500": 105, "1000": 61, "2000": 1620}}, {"id": 1359, "position": 1359, "text": "dan, or Fasting and Humiliation, was to continue all\nday, I did not choose to disturb him till towards night-fall; for I\ncherish the greatest respect towards everybody’s religious obligations,\nnever mind how comical, and could not find", "labels": {"50": 20, "100": 56, "250": 98, "500": 120, "1000": 651, "2000": 650}}, {"id": 1360, "position": 1360, "text": "everybody’s religious obligations,\nnever mind how comical, and could not find it in my heart to undervalue\neven a congregation of ants worshipping a toad-stool; or those other\ncreatures in certain parts of our earth, who with a degree", "labels": {"50": 20, "100": 28, "250": 169, "500": 59, "1000": 329, "2000": 1559}}, {"id": 1361, "position": 1361, "text": "or those other\ncreatures in certain parts of our earth, who with a degree of\nfootmanism quite unprecedented in other planets, bow down before the\ntorso of a deceased landed proprietor merely on account of the\ninordinate possessions yet owned and rented in his", "labels": {"50": 3, "100": 24, "250": 52, "500": 343, "1000": 505, "2000": 458}}, {"id": 1362, "position": 1362, "text": "merely on account of the\ninordinate possessions yet owned and rented in his name.\n\nI say, we good Presbyterian Christians should be charitable in these\nthings, and not fancy ourselves so vastly superior to other mortals,\npagans and what not, because of", "labels": {"50": 23, "100": 17, "250": 102, "500": 170, "1000": 376, "2000": 428}}, {"id": 1363, "position": 1363, "text": "so vastly superior to other mortals,\npagans and what not, because of their half-crazy conceits on these\nsubjects. There was Queequeg, now, certainly entertaining the most\nabsurd notions about Yojo and his Ramadan;—", "labels": {"50": 31, "100": 7, "250": 193, "500": 36, "1000": 849, "2000": 421}}, {"id": 1364, "position": 1364, "text": "certainly entertaining the most\nabsurd notions about Yojo and his Ramadan;—but what of that? Queequeg\nthought he knew what he was about, I suppose; he seemed to be content;\nand there let him rest", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1365, "position": 1365, "text": "he seemed to be content;\nand there let him rest. All our arguing with him would not avail; let\nhim be, I say: and Heaven have mercy on us all—Presbyterians and Pagans\nalike—for we are all somehow dreadfully", "labels": {"50": 23, "100": 31, "250": 228, "500": 320, "1000": 664, "2000": 1991}}, {"id": 1366, "position": 1366, "text": "—Presbyterians and Pagans\nalike—for we are all somehow dreadfully cracked about the head, and\nsadly need mending.\n\nTowards evening, when I felt assured that all his performances and\nrituals must be over, I went up to his room and", "labels": {"50": 25, "100": 93, "250": 55, "500": 318, "1000": 585, "2000": 1304}}, {"id": 1367, "position": 1367, "text": "his performances and\nrituals must be over, I went up to his room and knocked at the door;\nbut no answer. I tried to open it, but it was fastened inside.\n“Queequeg,” said I softly through the key-", "labels": {"50": 25, "100": 41, "250": 219, "500": 180, "1000": 272, "2000": 1954}}, {"id": 1368, "position": 1368, "text": ".\n“Queequeg,” said I softly through the key-hole:—all silent. “I say,\nQueequeg! why don’t you speak? It’s I—Ishmael.” But all remained", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1369, "position": 1369, "text": "speak? It’s I—Ishmael.” But all remained still\nas before. I began to grow alarmed. I had allowed him such abundant\ntime; I thought he might have had an apoplectic fit", "labels": {"50": 36, "100": 72, "250": 85, "500": 219, "1000": 280, "2000": 564}}, {"id": 1370, "position": 1370, "text": "he might have had an apoplectic fit. I looked through\nthe key-hole; but the door opening into an odd corner of the room, the\nkey-hole prospect was but a crooked and sinister one", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 462, "2000": 742}}, {"id": 1371, "position": 1371, "text": "was but a crooked and sinister one. I could only see\npart of the foot-board of the bed and a line of the wall, but nothing\nmore. I was surprised to behold resting against the wall the wooden\nshaft of Queequeg’", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 462, "2000": 742}}, {"id": 1372, "position": 1372, "text": "to behold resting against the wall the wooden\nshaft of Queequeg’s harpoon, which the landlady the evening previous\nhad taken from him, before our mounting to the chamber. That’s strange,\nthought I; but at any", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1373, "position": 1373, "text": "to the chamber. That’s strange,\nthought I; but at any rate, since the harpoon stands yonder, and he\nseldom or never goes abroad without it, therefore he must be inside\nhere, and no possible mistake.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1374, "position": 1374, "text": "therefore he must be inside\nhere, and no possible mistake.\n\n“Queequeg!—Queequeg!”—all still. Something must have happened.\nApoplexy! I tried to burst open the door; but it stubbornly", "labels": {"50": 25, "100": 5, "250": 45, "500": 3, "1000": 932, "2000": 742}}, {"id": 1375, "position": 1375, "text": "oplexy! I tried to burst open the door; but it stubbornly resisted.\nRunning down stairs, I quickly stated my suspicions to the first person\nI met—the chamber-maid. “La! la!” she cried, “I thought", "labels": {"50": 1, "100": 49, "250": 190, "500": 301, "1000": 284, "2000": 1123}}, {"id": 1376, "position": 1376, "text": "-maid. “La! la!” she cried, “I thought something must\nbe the matter. I went to make the bed after breakfast, and the door was\nlocked; and not a mouse to be heard; and it’s been just", "labels": {"50": 28, "100": 44, "250": 48, "500": 212, "1000": 320, "2000": 1923}}, {"id": 1377, "position": 1377, "text": "; and not a mouse to be heard; and it’s been just so silent ever\nsince. But I thought, may be, you had both gone off and locked your\nbaggage in for safe keeping. La! la, ma’am!—", "labels": {"50": 2, "100": 79, "250": 127, "500": 382, "1000": 342, "2000": 1212}}, {"id": 1378, "position": 1378, "text": "baggage in for safe keeping. La! la, ma’am!—Mistress! murder! Mrs.\nHussey! apoplexy!”—and with these cries, she ran towards the kitchen, I\nfollowing.\n\nMrs", "labels": {"50": 20, "100": 56, "250": 101, "500": 120, "1000": 421, "2000": 1068}}, {"id": 1379, "position": 1379, "text": ", she ran towards the kitchen, I\nfollowing.\n\nMrs. Hussey soon appeared, with a mustard-pot in one hand and a\nvinegar-cruet in the other, having just broken away from the occupation\nof attending to the castors,", "labels": {"50": 20, "100": 17, "250": 127, "500": 382, "1000": 207, "2000": 1212}}, {"id": 1380, "position": 1380, "text": ", having just broken away from the occupation\nof attending to the castors, and scolding her little black boy\nmeantime.\n\n“Wood-house!” cried I, “which way to it? Run for God’s sake, and fetch\nsomething", "labels": {"50": 41, "100": 79, "250": 86, "500": 221, "1000": 483, "2000": 1199}}, {"id": 1381, "position": 1381, "text": "which way to it? Run for God’s sake, and fetch\nsomething to pry open the door—the axe!—the axe! he’s had a stroke;\ndepend upon it!”—and so saying I was unmethodic", "labels": {"50": 25, "100": 5, "250": 136, "500": 313, "1000": 103, "2000": 453}}, {"id": 1382, "position": 1382, "text": "depend upon it!”—and so saying I was unmethodically rushing up stairs\nagain empty-handed, when Mrs. Hussey interposed the mustard-pot and\nvinegar-cruet, and the entire castor of her count", "labels": {"50": 23, "100": 41, "250": 219, "500": 174, "1000": 421, "2000": 1068}}, {"id": 1383, "position": 1383, "text": "pot and\nvinegar-cruet, and the entire castor of her countenance.\n\n“What’s the matter with you, young man?”\n\n“Get the axe! For God’s sake, run for the doctor, some one,", "labels": {"50": 11, "100": 21, "250": 190, "500": 157, "1000": 970, "2000": 1199}}, {"id": 1384, "position": 1384, "text": "! For God’s sake, run for the doctor, some one, while I pry\nit open!”\n\n“Look here,” said the landlady, quickly putting down the vinegar-cruet,\nso as to have one hand free;", "labels": {"50": 2, "100": 58, "250": 190, "500": 157, "1000": 141, "2000": 894}}, {"id": 1385, "position": 1385, "text": "down the vinegar-cruet,\nso as to have one hand free; “look here; are you talking about prying\nopen any of my doors?”—and with that she seized my arm. “What’s the\nmatter with you?", "labels": {"50": 25, "100": 79, "250": 45, "500": 57, "1000": 759, "2000": 1103}}, {"id": 1386, "position": 1386, "text": "that she seized my arm. “What’s the\nmatter with you? What’s the matter with you, shipmate?”\n\nIn as calm, but rapid a manner as possible, I gave her to understand\nthe whole case", "labels": {"50": 25, "100": 79, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 1387, "position": 1387, "text": "as possible, I gave her to understand\nthe whole case. Unconsciously clapping the vinegar-cruet to one side of\nher nose, she ruminated for an instant; then exclaimed—“No! I haven’t\nseen it since I put it", "labels": {"50": 20, "100": 79, "250": 176, "500": 57, "1000": 759, "2000": 1103}}, {"id": 1388, "position": 1388, "text": "exclaimed—“No! I haven’t\nseen it since I put it there.” Running to a little closet under the\nlanding of the stairs, she glanced in, and returning, told me that\nQueequeg’s harpoon was missing", "labels": {"50": 25, "100": 64, "250": 163, "500": 72, "1000": 533, "2000": 1620}}, {"id": 1389, "position": 1389, "text": "returning, told me that\nQueequeg’s harpoon was missing. “He’s killed himself,” she cried. “It’s\nunfort’nate Stiggs done over again—there goes another counterpane—God", "labels": {"50": 41, "100": 21, "250": 215, "500": 428, "1000": 58, "2000": 1529}}, {"id": 1390, "position": 1390, "text": "Stiggs done over again—there goes another counterpane—God\npity his poor mother!—it will be the ruin of my house. Has the poor lad\na sister? Where’s that girl?—there, Betty, go to", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 627, "2000": 1199}}, {"id": 1391, "position": 1391, "text": "sister? Where’s that girl?—there, Betty, go to Snarles the Painter,\nand tell him to paint me a sign, with—“no suicides permitted here, and\nno smoking in the parlor;”—might as well", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 50, "2000": 1886}}, {"id": 1392, "position": 1392, "text": "permitted here, and\nno smoking in the parlor;”—might as well kill both birds at once. Kill?\nThe Lord be merciful to his ghost! What’s that noise there? You, young\nman, avast there!”", "labels": {"50": 36, "100": 35, "250": 168, "500": 347, "1000": 163, "2000": 1912}}, {"id": 1393, "position": 1393, "text": "that noise there? You, young\nman, avast there!”\n\nAnd running up after me, she caught me as I was again trying to force\nopen the door.\n\n“I don’t allow it; I won’t have my premises spoiled", "labels": {"50": 25, "100": 79, "250": 45, "500": 313, "1000": 462, "2000": 20}}, {"id": 1394, "position": 1394, "text": "I don’t allow it; I won’t have my premises spoiled. Go for the\nlocksmith, there’s one about a mile from here. But avast!” putting her\nhand in her side-pocket, “here’s", "labels": {"50": 39, "100": 41, "250": 57, "500": 100, "1000": 488, "2000": 51}}, {"id": 1395, "position": 1395, "text": "!” putting her\nhand in her side-pocket, “here’s a key that’ll fit, I guess; let’s\nsee.” And with that, she turned it in the lock; but, alas! Queeque", "labels": {"50": 1, "100": 49, "250": 190, "500": 186, "1000": 801, "2000": 1879}}, {"id": 1396, "position": 1396, "text": "she turned it in the lock; but, alas! Queequeg’s\nsupplemental bolt remained unwithdrawn within.\n\n“Have to burst it open,” said I, and was running down the entry a\nlittle, for a good", "labels": {"50": 25, "100": 5, "250": 156, "500": 180, "1000": 462, "2000": 742}}, {"id": 1397, "position": 1397, "text": "said I, and was running down the entry a\nlittle, for a good start, when the landlady caught at me, again vowing\nI should not break down her premises; but I tore from her, and with a\nsudden bodily rush dashed", "labels": {"50": 20, "100": 5, "250": 45, "500": 349, "1000": 421, "2000": 1068}}, {"id": 1398, "position": 1398, "text": "premises; but I tore from her, and with a\nsudden bodily rush dashed myself full against the mark.\n\nWith a prodigious noise the door flew open, and the knob slamming\nagainst the wall, sent the plaster to the ceiling; and there", "labels": {"50": 20, "100": 79, "250": 45, "500": 57, "1000": 961, "2000": 1566}}, {"id": 1399, "position": 1399, "text": "knob slamming\nagainst the wall, sent the plaster to the ceiling; and there, good\nheavens! there sat Queequeg, altogether cool and self-collected; right\nin the middle of the room; squatting on his hams, and holding", "labels": {"50": 22, "100": 88, "250": 219, "500": 180, "1000": 345, "2000": 110}}, {"id": 1400, "position": 1400, "text": "the middle of the room; squatting on his hams, and holding Yojo on\ntop of his head. He looked neither one way nor the other way, but sat\nlike a carved image with scarce a sign of active life.", "labels": {"50": 37, "100": 51, "250": 145, "500": 444, "1000": 958, "2000": 1414}}, {"id": 1401, "position": 1401, "text": "like a carved image with scarce a sign of active life.\n\n“Queequeg,” said I, going up to him, “Queequeg, what’s the matter with\nyou?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 1402, "position": 1402, "text": "s the matter with\nyou?”\n\n“He hain’t been a sittin’ so all day, has he?” said the landlady.\n\nBut all we said, not a word could we drag out of him; I almost felt", "labels": {"50": 25, "100": 41, "250": 156, "500": 128, "1000": 329, "2000": 1099}}, {"id": 1403, "position": 1403, "text": "said, not a word could we drag out of him; I almost felt\nlike pushing him over, so as to change his position, for it was almost\nintolerable, it seemed so painfully and unnaturally constrained;\nespecially, as in all probability", "labels": {"50": 25, "100": 41, "250": 156, "500": 128, "1000": 964, "2000": 1645}}, {"id": 1404, "position": 1404, "text": "it seemed so painfully and unnaturally constrained;\nespecially, as in all probability he had been sitting so for upwards of\neight or ten hours, going too without his regular meals.\n\n“Mrs. Hussey,” said I, “he’s", "labels": {"50": 20, "100": 79, "250": 176, "500": 26, "1000": 638, "2000": 1958}}, {"id": 1405, "position": 1405, "text": "“Mrs. Hussey,” said I, “he’s _alive_ at all events; so leave us, if you\nplease, and I will see to this strange affair myself.”", "labels": {"50": 20, "100": 79, "250": 186, "500": 153, "1000": 812, "2000": 252}}, {"id": 1406, "position": 1406, "text": "this strange affair myself.”\n\nClosing the door upon the landlady, I endeavored to prevail upon\nQueequeg to take a chair; but in vain. There he sat; and all he could\ndo—for all my polite", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1407, "position": 1407, "text": ". There he sat; and all he could\ndo—for all my polite arts and blandishments—he would not move a peg,\nnor say a single word, nor even look at me, nor notice my presence in\nthe slightest way.", "labels": {"50": 25, "100": 41, "250": 156, "500": 128, "1000": 483, "2000": 1099}}, {"id": 1408, "position": 1408, "text": "even look at me, nor notice my presence in\nthe slightest way.\n\nI wonder, thought I, if this can possibly be a part of his Ramadan; do\nthey fast on their hams that way in his native island", "labels": {"50": 45, "100": 0, "250": 233, "500": 55, "1000": 856, "2000": 359}}, {"id": 1409, "position": 1409, "text": "on their hams that way in his native island. It must be so;\nyes, it’s part of his creed, I suppose; well, then, let him rest; he’ll\nget up sooner or later, no doubt", "labels": {"50": 41, "100": 21, "250": 91, "500": 5, "1000": 533, "2000": 1082}}, {"id": 1410, "position": 1410, "text": "rest; he’ll\nget up sooner or later, no doubt. It can’t last for ever, thank God,\nand his Ramadan only comes once a year; and I don’t believe it’s very\npunctual then.", "labels": {"50": 46, "100": 41, "250": 183, "500": 234, "1000": 798, "2000": 51}}, {"id": 1411, "position": 1411, "text": "and I don’t believe it’s very\npunctual then.\n\nI went down to supper. After sitting a long time listening to the long\nstories of some sailors who had just come from a plum-pudding voyage,\nas they called it (", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 1359}}, {"id": 1412, "position": 1412, "text": "had just come from a plum-pudding voyage,\nas they called it (that is, a short whaling-voyage in a schooner or\nbrig, confined to the north of the line, in the Atlantic Ocean only);\nafter listening to these plum-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1413, "position": 1413, "text": "line, in the Atlantic Ocean only);\nafter listening to these plum-puddingers till nearly eleven o’clock, I\nwent up stairs to go to bed, feeling quite sure by this time Queequeg\nmust certainly have brought his Ramadan", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1620}}, {"id": 1414, "position": 1414, "text": "sure by this time Queequeg\nmust certainly have brought his Ramadan to a termination. But no; there\nhe was just where I had left him; he had not stirred an inch. I began\nto grow vexed with him; it seemed", "labels": {"50": 25, "100": 5, "250": 136, "500": 349, "1000": 842, "2000": 937}}, {"id": 1415, "position": 1415, "text": "stirred an inch. I began\nto grow vexed with him; it seemed so downright senseless and insane to\nbe sitting there all day and half the night on his hams in a cold room,\nholding a piece of wood on his head.", "labels": {"50": 34, "100": 77, "250": 164, "500": 192, "1000": 427, "2000": 1698}}, {"id": 1416, "position": 1416, "text": "s in a cold room,\nholding a piece of wood on his head.\n\n“For heaven’s sake, Queequeg, get up and shake yourself; get up and\nhave some supper. You’ll starve; you’ll kill", "labels": {"50": 25, "100": 41, "250": 91, "500": 180, "1000": 496, "2000": 1199}}, {"id": 1417, "position": 1417, "text": "and\nhave some supper. You’ll starve; you’ll kill yourself, Queequeg.” But\nnot a word did he reply.\n\nDespairing of him, therefore, I determined to go to bed and to sleep;\nand no", "labels": {"50": 20, "100": 56, "250": 98, "500": 177, "1000": 700, "2000": 1059}}, {"id": 1418, "position": 1418, "text": ", therefore, I determined to go to bed and to sleep;\nand no doubt, before a great while, he would follow me. But previous to\nturning in, I took my heavy bearskin jacket, and threw it over him, as\nit promised", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 652}}, {"id": 1419, "position": 1419, "text": "my heavy bearskin jacket, and threw it over him, as\nit promised to be a very cold night; and he had nothing but his\nordinary round jacket on. For some time, do all I would, I could not\nget into the faintest", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 483, "2000": 1707}}, {"id": 1420, "position": 1420, "text": "time, do all I would, I could not\nget into the faintest doze. I had blown out the candle; and the mere\nthought of Queequeg—not four feet off—sitting there in that uneasy\nposition, stark alone in", "labels": {"50": 25, "100": 5, "250": 156, "500": 313, "1000": 421, "2000": 742}}, {"id": 1421, "position": 1421, "text": "not four feet off—sitting there in that uneasy\nposition, stark alone in the cold and dark; this made me really\nwretched. Think of it; sleeping all night in the same room with a wide\nawake pagan on his hams in this dr", "labels": {"50": 25, "100": 41, "250": 45, "500": 313, "1000": 51, "2000": 1566}}, {"id": 1422, "position": 1422, "text": "the same room with a wide\nawake pagan on his hams in this dreary, unaccountable Ramadan!\n\nBut somehow I dropped off at last, and knew nothing more till break of\nday; when, looking over the bedside, there", "labels": {"50": 32, "100": 0, "250": 233, "500": 142, "1000": 61, "2000": 359}}, {"id": 1423, "position": 1423, "text": "nothing more till break of\nday; when, looking over the bedside, there squatted Queequeg, as if he\nhad been screwed down to the floor. But as soon as the first glimpse of\nsun entered the window, up he got,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 1424, "position": 1424, "text": "soon as the first glimpse of\nsun entered the window, up he got, with stiff and grating joints, but\nwith a cheerful look; limped towards me where I lay; pressed his\nforehead again against mine; and said his Ramadan was over", "labels": {"50": 25, "100": 96, "250": 153, "500": 457, "1000": 514, "2000": 1631}}, {"id": 1425, "position": 1425, "text": "; pressed his\nforehead again against mine; and said his Ramadan was over.\n\nNow, as I before hinted, I have no objection to any person’s religion,\nbe it what it may, so long as that person does not kill or insult", "labels": {"50": 8, "100": 28, "250": 175, "500": 94, "1000": 560, "2000": 1615}}, {"id": 1426, "position": 1426, "text": "it what it may, so long as that person does not kill or insult any\nother person, because that other person don’t believe it also. But when\na man’s religion becomes really frantic; when it is a positive torment\nto him;", "labels": {"50": 35, "100": 94, "250": 12, "500": 265, "1000": 560, "2000": 1061}}, {"id": 1427, "position": 1427, "text": "s religion becomes really frantic; when it is a positive torment\nto him; and, in fine, makes this earth of ours an uncomfortable inn to\nlodge in; then I think it high time to take that individual aside and\nargue the point with him.", "labels": {"50": 31, "100": 71, "250": 69, "500": 265, "1000": 811, "2000": 506}}, {"id": 1428, "position": 1428, "text": "it high time to take that individual aside and\nargue the point with him.\n\nAnd just so I now did with Queequeg. “Queequeg,” said I, “get into bed\nnow, and lie and listen to me.", "labels": {"50": 25, "100": 5, "250": 136, "500": 134, "1000": 103, "2000": 786}}, {"id": 1429, "position": 1429, "text": "I, “get into bed\nnow, and lie and listen to me.” I then went on, beginning with the rise\nand progress of the primitive religions, and coming down to the various\nreligions of the present time, during which time I labored", "labels": {"50": 20, "100": 28, "250": 169, "500": 59, "1000": 773, "2000": 1615}}, {"id": 1430, "position": 1430, "text": "to the various\nreligions of the present time, during which time I labored to show\nQueequeg that all these Lents, Ramadans, and prolonged ham-squattings\nin cold, cheerless rooms were stark nonsense; bad for", "labels": {"50": 20, "100": 28, "250": 169, "500": 59, "1000": 773, "2000": 381}}, {"id": 1431, "position": 1431, "text": "squattings\nin cold, cheerless rooms were stark nonsense; bad for the health;\nuseless for the soul; opposed, in short, to the obvious laws of Hygiene\nand common sense. I told him, too, that he being in other things", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 251}}, {"id": 1432, "position": 1432, "text": "common sense. I told him, too, that he being in other things such\nan extremely sensible and sagacious savage, it pained me, very badly\npained me, to see him now so deplorably foolish about this ridiculous\nRamadan of his", "labels": {"50": 25, "100": 41, "250": 156, "500": 128, "1000": 716, "2000": 1099}}, {"id": 1433, "position": 1433, "text": "him now so deplorably foolish about this ridiculous\nRamadan of his. Besides, argued I, fasting makes the body cave in;\nhence the spirit caves in; and all thoughts born of a fast must\nnecessarily be half-starved", "labels": {"50": 35, "100": 75, "250": 30, "500": 333, "1000": 440, "2000": 374}}, {"id": 1434, "position": 1434, "text": "and all thoughts born of a fast must\nnecessarily be half-starved. This is the reason why most dyspeptic\nreligionists cherish such melancholy notions about their hereafters. In\none word, Queequeg, said I, rather", "labels": {"50": 1, "100": 53, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 1435, "position": 1435, "text": "ters. In\none word, Queequeg, said I, rather digressively; hell is an idea first\nborn on an undigested apple-dumpling; and since then perpetuated\nthrough the hereditary dyspepsias nur", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 1436, "position": 1436, "text": "and since then perpetuated\nthrough the hereditary dyspepsias nurtured by Ramadans.\n\nI then asked Queequeg whether he himself was ever troubled with\ndyspepsia; expressing the idea very plainly, so that", "labels": {"50": 48, "100": 20, "250": 90, "500": 224, "1000": 806, "2000": 978}}, {"id": 1437, "position": 1437, "text": "with\ndyspepsia; expressing the idea very plainly, so that he could take it\nin. He said no; only upon one memorable occasion. It was after a great\nfeast given by his father the king, on the gaining of a great", "labels": {"50": 1, "100": 53, "250": 208, "500": 51, "1000": 243, "2000": 860}}, {"id": 1438, "position": 1438, "text": "great\nfeast given by his father the king, on the gaining of a great battle\nwherein fifty of the enemy had been killed by about two o’clock in the\nafternoon, and all cooked and eaten that very evening.", "labels": {"50": 18, "100": 83, "250": 104, "500": 385, "1000": 250, "2000": 883}}, {"id": 1439, "position": 1439, "text": "all cooked and eaten that very evening.\n\n“No more, Queequeg,” said I, shuddering; “that will do;” for I knew the\ninferences without his further hinting them", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1440, "position": 1440, "text": "without his further hinting them. I had seen a sailor who\nhad visited that very island, and he told me that it was the custom,\nwhen a great battle had been gained there, to barbecue all the slain in\nthe yard or garden of the", "labels": {"50": 45, "100": 29, "250": 125, "500": 384, "1000": 139, "2000": 1586}}, {"id": 1441, "position": 1441, "text": "gained there, to barbecue all the slain in\nthe yard or garden of the victor; and then, one by one, they were\nplaced in great wooden trenchers, and garnished round like a pilau,\nwith breadfruit and cocoanut", "labels": {"50": 12, "100": 13, "250": 130, "500": 494, "1000": 480, "2000": 187}}, {"id": 1442, "position": 1442, "text": "rnished round like a pilau,\nwith breadfruit and cocoanuts; and with some parsley in their mouths,\nwere sent round with the victor’s compliments to all his friends, just\nas though these presents were so many Christmas", "labels": {"50": 45, "100": 64, "250": 130, "500": 494, "1000": 480, "2000": 187}}, {"id": 1443, "position": 1443, "text": "s to all his friends, just\nas though these presents were so many Christmas turkeys.\n\nAfter all, I do not think that my remarks about religion made much\nimpression upon Queequeg. Because, in the first place, he somehow\nseemed dull", "labels": {"50": 44, "100": 28, "250": 175, "500": 294, "1000": 363, "2000": 221}}, {"id": 1444, "position": 1444, "text": "equeg. Because, in the first place, he somehow\nseemed dull of hearing on that important subject, unless considered\nfrom his own point of view; and, in the second place, he did not more\nthan one third understand me, couch my", "labels": {"50": 25, "100": 28, "250": 175, "500": 202, "1000": 421, "2000": 1068}}, {"id": 1445, "position": 1445, "text": "second place, he did not more\nthan one third understand me, couch my ideas simply as I would; and,\nfinally, he no doubt thought he knew a good deal more about the true\nreligion than I did", "labels": {"50": 5, "100": 66, "250": 12, "500": 144, "1000": 560, "2000": 502}}, {"id": 1446, "position": 1446, "text": "about the true\nreligion than I did. He looked at me with a sort of condescending\nconcern and compassion, as though he thought it a great pity that such\na sensible young man should be so hopelessly lost to evangelical pagan\npiety.", "labels": {"50": 5, "100": 30, "250": 40, "500": 265, "1000": 919, "2000": 1615}}, {"id": 1447, "position": 1447, "text": "young man should be so hopelessly lost to evangelical pagan\npiety.\n\nAt last we rose and dressed; and Queequeg, taking a prodigiously hearty\nbreakfast of chowders of all sorts, so that the landlady should", "labels": {"50": 25, "100": 93, "250": 55, "500": 318, "1000": 868, "2000": 251}}, {"id": 1448, "position": 1448, "text": "breakfast of chowders of all sorts, so that the landlady should not\nmake much profit by reason of his Ramadan, we sallied out to board the\nPequod, sauntering along, and picking our teeth with halib", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 887}}, {"id": 1449, "position": 1449, "text": "quod, sauntering along, and picking our teeth with halibut bones.\n\n\nCHAPTER 18. His Mark.\n\nAs we were walking down the end of the wharf towards the ship, Queequeg\ncarrying his harpoon, Captain Peleg", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1450, "position": 1450, "text": "the ship, Queequeg\ncarrying his harpoon, Captain Peleg in his gruff voice loudly hailed us\nfrom his wigwam, saying he had not suspected my friend was a cannibal,\nand furthermore announcing that he let no canni", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1451, "position": 1451, "text": "was a cannibal,\nand furthermore announcing that he let no cannibals on board that\ncraft, unless they previously produced their papers.\n\n“What do you mean by that, Captain Peleg?” said I, now jumping on the\nbu", "labels": {"50": 25, "100": 41, "250": 156, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1452, "position": 1452, "text": "that, Captain Peleg?” said I, now jumping on the\nbulwarks, and leaving my comrade standing on the wharf.\n\n“I mean,” he replied, “he must show his papers.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1453, "position": 1453, "text": ", “he must show his papers.”\n\n“Yes,” said Captain Bildad in his hollow voice, sticking his head from\nbehind Peleg’s, out of the wigwam. “He must show that he’s converted", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1454, "position": 1454, "text": "the wigwam. “He must show that he’s converted.\nSon of darkness,” he added, turning to Queequeg, “art thou at present\nin communion with any Christian church?”", "labels": {"50": 5, "100": 87, "250": 65, "500": 227, "1000": 965, "2000": 668}}, {"id": 1455, "position": 1455, "text": "in communion with any Christian church?”\n\n“Why,” said I, “he’s a member of the first Congregational Church.” Here\nbe it said, that many tattooed savages sailing in Nantucket ships at\nlast come to be converted into", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1456, "position": 1456, "text": "tattooed savages sailing in Nantucket ships at\nlast come to be converted into the churches.\n\n“First Congregational Church,” cried Bildad, “what! that worships in\nDeacon Deuteronomy Coleman’s meeting-house?” and", "labels": {"50": 5, "100": 38, "250": 53, "500": 421, "1000": 199, "2000": 1987}}, {"id": 1457, "position": 1457, "text": "in\nDeacon Deuteronomy Coleman’s meeting-house?” and so saying, taking out\nhis spectacles, he rubbed them with his great yellow bandana\nhandkerchief, and putting them on very carefully, came out of the\nwigwam,", "labels": {"50": 41, "100": 21, "250": 215, "500": 428, "1000": 58, "2000": 497}}, {"id": 1458, "position": 1458, "text": "and putting them on very carefully, came out of the\nwigwam, and leaning stiffly over the bulwarks, took a good long look at\nQueequeg.\n\n“How long hath he been a member?” he then said", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1459, "position": 1459, "text": ".\n\n“How long hath he been a member?” he then said, turning to me; “not\nvery long, I rather guess, young man.”\n\n“No,” said Peleg, “and he hasn’t been baptized right", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 775, "2000": 1902}}, {"id": 1460, "position": 1460, "text": ",” said Peleg, “and he hasn’t been baptized right either, or it\nwould have washed some of that devil’s blue off his face.”\n\n“Do tell, now,” cried Bildad, “is this Phil", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1461, "position": 1461, "text": "Do tell, now,” cried Bildad, “is this Philistine a regular member of\nDeacon Deuteronomy’s meeting? I never saw him going there, and I pass\nit every Lord’s day.”", "labels": {"50": 18, "100": 31, "250": 228, "500": 208, "1000": 603, "2000": 270}}, {"id": 1462, "position": 1462, "text": "there, and I pass\nit every Lord’s day.”\n\n“I don’t know anything about Deacon Deuteronomy or his meeting,” said\nI; “all I know is, that Queequeg here is a born member", "labels": {"50": 41, "100": 21, "250": 215, "500": 281, "1000": 333, "2000": 1082}}, {"id": 1463, "position": 1463, "text": "all I know is, that Queequeg here is a born member of the First\nCongregational Church. He is a deacon himself, Queequeg is.”\n\n“Young man,” said Bildad sternly, “thou art skylar", "labels": {"50": 39, "100": 99, "250": 207, "500": 53, "1000": 385, "2000": 1233}}, {"id": 1464, "position": 1464, "text": "Young man,” said Bildad sternly, “thou art skylarking with me—explain\nthyself, thou young Hittite. What church dost thee mean? answer me.”\n\nFinding myself thus hard pushed, I replied", "labels": {"50": 32, "100": 25, "250": 93, "500": 362, "1000": 131, "2000": 1502}}, {"id": 1465, "position": 1465, "text": "? answer me.”\n\nFinding myself thus hard pushed, I replied. “I mean, sir, the same\nancient Catholic Church to which you and I, and Captain Peleg there,\nand Queequeg here, and all of us, and", "labels": {"50": 25, "100": 41, "250": 219, "500": 180, "1000": 103, "2000": 610}}, {"id": 1466, "position": 1466, "text": "there,\nand Queequeg here, and all of us, and every mother’s son and soul of us\nbelong; the great and everlasting First Congregation of this whole\nworshipping world; we all belong to that; only some of", "labels": {"50": 35, "100": 94, "250": 141, "500": 198, "1000": 616, "2000": 1464}}, {"id": 1467, "position": 1467, "text": "this whole\nworshipping world; we all belong to that; only some of us cherish some\nqueer crotchets no ways touching the grand belief; in _that_ we all\njoin hands.”\n\n“Splice, thou mean’st _splice", "labels": {"50": 2, "100": 58, "250": 214, "500": 278, "1000": 476, "2000": 451}}, {"id": 1468, "position": 1468, "text": "join hands.”\n\n“Splice, thou mean’st _splice_ hands,” cried Peleg, drawing nearer.\n“Young man, you’d better ship for a missionary, instead of a fore-mast\nhand; I never heard", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1469, "position": 1469, "text": "for a missionary, instead of a fore-mast\nhand; I never heard a better sermon. Deacon Deuteronomy—why Father\nMapple himself couldn’t beat it, and he’s reckoned something", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1470, "position": 1470, "text": ", and he’s reckoned something. Come\naboard, come aboard; never mind about the papers. I say, tell Quohog\nthere—what’s that you call him? tell Quohog to step along", "labels": {"50": 6, "100": 1, "250": 42, "500": 498, "1000": 647, "2000": 666}}, {"id": 1471, "position": 1471, "text": "him? tell Quohog to step along. By the great\nanchor, what a harpoon he’s got there! looks like good stuff that; and\nhe handles it about right. I say, Quohog, or whatever your name is, did", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1472, "position": 1472, "text": "right. I say, Quohog, or whatever your name is, did\nyou ever stand in the head of a whale-boat? did you ever strike a\nfish?”\n\nWithout saying a word, Queequeg, in his wild sort of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1473, "position": 1473, "text": "Without saying a word, Queequeg, in his wild sort of way, jumped upon\nthe bulwarks, from thence into the bows of one of the whale-boats\nhanging to the side; and then bracing his left knee, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1474, "position": 1474, "text": "-boats\nhanging to the side; and then bracing his left knee, and poising his\nharpoon, cried out in some such way as this:—\n\n“Cap’ain, you see him small drop tar on water dere? You see him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1475, "position": 1475, "text": ", you see him small drop tar on water dere? You see him? well,\nspose him one whale eye, well, den!” and taking sharp aim at it, he\ndarted the iron right over old Bildad’s broad", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1620}}, {"id": 1476, "position": 1476, "text": "it, he\ndarted the iron right over old Bildad’s broad brim, clean across the\nship’s decks, and struck the glistening tar spot out of sight.\n\n“Now,” said Queequeg, quietly hauling in the", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1477, "position": 1477, "text": ".\n\n“Now,” said Queequeg, quietly hauling in the line, “spos-ee him whale-e\neye; why, dad whale dead.”\n\n“Quick, Bildad,” said Peleg, his partner,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1478, "position": 1478, "text": "“Quick, Bildad,” said Peleg, his partner, who, aghast at the close\nvicinity of the flying harpoon, had retreated towards the cabin\ngangway. “Quick, I say, you Bildad, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1479, "position": 1479, "text": "gangway. “Quick, I say, you Bildad, and get the ship’s papers. We must\nhave Hedgehog there, I mean Quohog, in one of our boats. Look ye,\nQuohog, we’ll give", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 1480, "position": 1480, "text": "one of our boats. Look ye,\nQuohog, we’ll give ye the ninetieth lay, and that’s more than ever was\ngiven a harpooneer yet out of Nantucket.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1481, "position": 1481, "text": "yet out of Nantucket.”\n\nSo down we went into the cabin, and to my great joy Queequeg was soon\nenrolled among the same ship’s company to which I myself belonged.\n\nWhen all preliminaries were over and Pe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1482, "position": 1482, "text": "which I myself belonged.\n\nWhen all preliminaries were over and Peleg had got everything ready for\nsigning, he turned to me and said, “I guess, Quohog there don’t know\nhow to write, does he? I say", "labels": {"50": 23, "100": 41, "250": 91, "500": 221, "1000": 627, "2000": 1707}}, {"id": 1483, "position": 1483, "text": "hog there don’t know\nhow to write, does he? I say, Quohog, blast ye! dost thou sign thy name\nor make thy mark?”\n\nBut at this question, Queequeg, who had twice or thrice", "labels": {"50": 9, "100": 64, "250": 138, "500": 180, "1000": 851, "2000": 1620}}, {"id": 1484, "position": 1484, "text": "at this question, Queequeg, who had twice or thrice before taken\npart in similar ceremonies, looked no ways abashed; but taking the\noffered pen, copied upon the paper, in the proper place, an exact\ncounterpart of a queer", "labels": {"50": 41, "100": 64, "250": 138, "500": 72, "1000": 723, "2000": 1620}}, {"id": 1485, "position": 1485, "text": "upon the paper, in the proper place, an exact\ncounterpart of a queer round figure which was tattooed upon his arm; so\nthat through Captain Peleg’s obstinate mistake touching his\nappellative, it stood something like this:—", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1486, "position": 1486, "text": "mistake touching his\nappellative, it stood something like this:—\n\nQuohog. his X mark.\n\nMeanwhile Captain Bildad sat earnestly and steadfastly eyeing Queequeg,\nand at last rising solemnly and fumbling in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1487, "position": 1487, "text": "Queequeg,\nand at last rising solemnly and fumbling in the huge pockets of his\nbroad-skirted drab coat, took out a bundle of tracts, and selecting one\nentitled “The Latter Day Coming; or No Time to Lose,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1488, "position": 1488, "text": "selecting one\nentitled “The Latter Day Coming; or No Time to Lose,” placed it in\nQueequeg’s hands, and then grasping them and the book with both his,\nlooked earnestly into his eyes, and said, “Son", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 977, "2000": 1625}}, {"id": 1489, "position": 1489, "text": "both his,\nlooked earnestly into his eyes, and said, “Son of darkness, I must do\nmy duty by thee; I am part owner of this ship, and feel concerned for\nthe souls of all its crew; if thou still clinge", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 730, "2000": 801}}, {"id": 1490, "position": 1490, "text": "feel concerned for\nthe souls of all its crew; if thou still clingest to thy Pagan ways,\nwhich I sadly fear, I beseech thee, remain not for aye a Belial\nbondsman", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1491, "position": 1491, "text": "aye a Belial\nbondsman. Spurn the idol Bell, and the hideous dragon; turn from the\nwrath to come; mind thine eye, I say; oh! goodness gracious! steer\nclear of the fiery pit!”", "labels": {"50": 9, "100": 87, "250": 102, "500": 205, "1000": 621, "2000": 1951}}, {"id": 1492, "position": 1492, "text": "goodness gracious! steer\nclear of the fiery pit!”\n\nSomething of the salt sea yet lingered in old Bildad’s language,\nheterogeneously mixed with Scriptural and domestic phrases.", "labels": {"50": 48, "100": 27, "250": 192, "500": 304, "1000": 35, "2000": 1304}}, {"id": 1493, "position": 1493, "text": "Scriptural and domestic phrases.\n\n“Avast there, avast there, Bildad, avast now spoiling our harpooneer,”\ncried Peleg. “Pious harpooneers never make good voyagers—it takes the\nshark out", "labels": {"50": 32, "100": 0, "250": 233, "500": 105, "1000": 61, "2000": 1800}}, {"id": 1494, "position": 1494, "text": "Pious harpooneers never make good voyagers—it takes the\nshark out of ’em; no harpooneer is worth a straw who aint pretty\nsharkish. There was young Nat Swaine, once the bravest boat-header out\nof", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 531, "2000": 1620}}, {"id": 1495, "position": 1495, "text": "was young Nat Swaine, once the bravest boat-header out\nof all Nantucket and the Vineyard; he joined the meeting, and never\ncame to good. He got so frightened about his plaguy soul, that he\nshrinked and sheer", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1766}}, {"id": 1496, "position": 1496, "text": "so frightened about his plaguy soul, that he\nshrinked and sheered away from whales, for fear of after-claps, in case\nhe got stove and went to Davy Jones.”\n\n“Peleg! Peleg!” said Bi", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 1620}}, {"id": 1497, "position": 1497, "text": "to Davy Jones.”\n\n“Peleg! Peleg!” said Bildad, lifting his eyes and hands, “thou thyself,\nas I myself, hast seen many a perilous time; thou knowest, Peleg", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1498, "position": 1498, "text": "t seen many a perilous time; thou knowest, Peleg, what\nit is to have the fear of death; how, then, can’st thou prate in this\nungodly guise", "labels": {"50": 9, "100": 26, "250": 141, "500": 198, "1000": 19, "2000": 111}}, {"id": 1499, "position": 1499, "text": "ate in this\nungodly guise. Thou beliest thine own heart, Peleg. Tell me, when this\nsame Pequod here had her three masts overboard in that typhoon on\nJapan, that same voyage when thou went mate with Captain", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1500, "position": 1500, "text": "in that typhoon on\nJapan, that same voyage when thou went mate with Captain Ahab, did’st\nthou not think of Death and the Judgment then?”\n\n“Hear him, hear him now,” cried Peleg, marching across the cabin,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1501, "position": 1501, "text": ", hear him now,” cried Peleg, marching across the cabin, and\nthrusting his hands far down into his pockets,—“hear him, all of ye.\nThink of that! When every moment we thought the ship would sink! Death\nand", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1502, "position": 1502, "text": "of that! When every moment we thought the ship would sink! Death\nand the Judgment then? What? With all three masts making such an\neverlasting thundering against the side; and every sea breaking over\nus, fore and aft", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 1503, "position": 1503, "text": "the side; and every sea breaking over\nus, fore and aft. Think of Death and the Judgment then? No! no time to\nthink about Death then. Life was what Captain Ahab and I was thinking\nof; and how to save all hands", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 1504, "position": 1504, "text": "Captain Ahab and I was thinking\nof; and how to save all hands—how to rig jury-masts—how to get into the\nnearest port; that was what I was thinking of.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1620}}, {"id": 1505, "position": 1505, "text": "I was thinking of.”\n\nBildad said no more, but buttoning up his coat, stalked on deck, where\nwe followed him. There he stood, very quietly overlooking some\nsailmakers who were mending a top-sail in the waist", "labels": {"50": 40, "100": 83, "250": 170, "500": 433, "1000": 980, "2000": 1519}}, {"id": 1506, "position": 1506, "text": "overlooking some\nsailmakers who were mending a top-sail in the waist. Now and then he\nstooped to pick up a patch, or save an end of tarred twine, which\notherwise might have been wasted.\n\n\nCHAPTER 19. The Prophet", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 1507, "position": 1507, "text": "twine, which\notherwise might have been wasted.\n\n\nCHAPTER 19. The Prophet.\n\n“Shipmates, have ye shipped in that ship?”\n\nQueequeg and I had just left the Pequod, and were sauntering away from\nthe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1508, "position": 1508, "text": "just left the Pequod, and were sauntering away from\nthe water, for the moment each occupied with his own thoughts, when the\nabove words were put to us by a stranger, who, pausing before us,\nlevelled his massive fore", "labels": {"50": 25, "100": 64, "250": 219, "500": 180, "1000": 317, "2000": 1954}}, {"id": 1509, "position": 1509, "text": "by a stranger, who, pausing before us,\nlevelled his massive forefinger at the vessel in question. He was but\nshabbily apparelled in faded jacket and patched trowsers; a rag of a\nblack handkerchief investing his neck", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 967}}, {"id": 1510, "position": 1510, "text": "ed trowsers; a rag of a\nblack handkerchief investing his neck. A confluent small-pox had in all\ndirections flowed over his face, and left it like the complicated\nribbed bed of a torrent, when the rushing", "labels": {"50": 37, "100": 6, "250": 174, "500": 5, "1000": 367, "2000": 1593}}, {"id": 1511, "position": 1511, "text": "it like the complicated\nribbed bed of a torrent, when the rushing waters have been dried up.\n\n“Have ye shipped in her?” he repeated.\n\n“You mean the ship Pequod, I suppose,” said I, trying to", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 1620}}, {"id": 1512, "position": 1512, "text": "the ship Pequod, I suppose,” said I, trying to gain a little\nmore time for an uninterrupted look at him.\n\n“Aye, the Pequod—that ship there,” he said, drawing back his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1513, "position": 1513, "text": "Pequod—that ship there,” he said, drawing back his whole arm,\nand then rapidly shoving it straight out from him, with the fixed\nbayonet of his pointed finger darted full at the object.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1514, "position": 1514, "text": "his pointed finger darted full at the object.\n\n“Yes,” said I, “we have just signed the articles.”\n\n“Anything down there about your souls?”\n\n“About what?”\n\n“Oh, perhaps you hav’n’t", "labels": {"50": 39, "100": 41, "250": 91, "500": 407, "1000": 488, "2000": 51}}, {"id": 1515, "position": 1515, "text": "About what?”\n\n“Oh, perhaps you hav’n’t got any,” he said quickly. “No matter though,\nI know many chaps that hav’n’t got any,—good luck to ’em;", "labels": {"50": 41, "100": 99, "250": 91, "500": 229, "1000": 583, "2000": 581}}, {"id": 1516, "position": 1516, "text": "v’n’t got any,—good luck to ’em; and they are\nall the better off for it. A soul’s a sort of a fifth wheel to a\nwagon.”\n\n“What are you jabbering about, ship", "labels": {"50": 41, "100": 21, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1517, "position": 1517, "text": "to a\nwagon.”\n\n“What are you jabbering about, shipmate?” said I.\n\n“_He’s_ got enough, though, to make up for all deficiencies of that\nsort in other chaps,” abruptly said", "labels": {"50": 25, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1518, "position": 1518, "text": "for all deficiencies of that\nsort in other chaps,” abruptly said the stranger, placing a nervous\nemphasis upon the word _he_.\n\n“Queequeg,” said I, “let’s go; this fellow has broken loose", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1519, "position": 1519, "text": "” said I, “let’s go; this fellow has broken loose from\nsomewhere; he’s talking about something and somebody we don’t know.”\n\n“Stop!” cried the stranger. “Ye said true—ye hav’", "labels": {"50": 41, "100": 41, "250": 219, "500": 180, "1000": 317, "2000": 1954}}, {"id": 1520, "position": 1520, "text": "!” cried the stranger. “Ye said true—ye hav’n’t seen Old Thunder\nyet, have ye?”\n\n“Who’s Old Thunder?” said I, again riveted with the insane earnestness\nof his manner", "labels": {"50": 41, "100": 21, "250": 215, "500": 180, "1000": 272, "2000": 1954}}, {"id": 1521, "position": 1521, "text": "said I, again riveted with the insane earnestness\nof his manner.\n\n“Captain Ahab.”\n\n“What! the captain of our ship, the Pequod?”\n\n“Aye, among some of us old sailor chaps, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 1522, "position": 1522, "text": "?”\n\n“Aye, among some of us old sailor chaps, he goes by that name. Ye\nhav’n’t seen him yet, have ye?”\n\n“No, we hav’n’t", "labels": {"50": 39, "100": 99, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1523, "position": 1523, "text": "“No, we hav’n’t. He’s sick they say, but is getting better, and will be\nall right again before long.”\n\n“All right again before long!” laughed the stranger, with a solemnly\nderisi", "labels": {"50": 11, "100": 51, "250": 174, "500": 100, "1000": 798, "2000": 51}}, {"id": 1524, "position": 1524, "text": "right again before long!” laughed the stranger, with a solemnly\nderisive sort of laugh. “Look ye; when Captain Ahab is all right, then\nthis left arm of mine will be all right; not before.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1525, "position": 1525, "text": "arm of mine will be all right; not before.”\n\n“What do you know about him?”\n\n“What did they _tell_ you about him? Say that!”\n\n“They didn’t tell much of anything about him; only I", "labels": {"50": 46, "100": 72, "250": 183, "500": 115, "1000": 29, "2000": 595}}, {"id": 1526, "position": 1526, "text": "”\n\n“They didn’t tell much of anything about him; only I’ve heard that he’s\na good whale-hunter, and a good captain to his crew.”\n\n“That’s true, that’s true—yes,", "labels": {"50": 11, "100": 64, "250": 163, "500": 53, "1000": 385, "2000": 1233}}, {"id": 1527, "position": 1527, "text": ".”\n\n“That’s true, that’s true—yes, both true enough. But you must jump when\nhe gives an order. Step and growl; growl and go—that’s the word with\nCaptain Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1528, "position": 1528, "text": "go—that’s the word with\nCaptain Ahab. But nothing about that thing that happened to him off\nCape Horn, long ago, when he lay like dead for three days and nights;\nnothing about that deadly skrimmage with the Spaniard", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1529, "position": 1529, "text": "days and nights;\nnothing about that deadly skrimmage with the Spaniard afore the altar\nin Santa?—heard nothing about that, eh? Nothing about the silver\ncalabash he spat into? And nothing about his losing his leg last\nvoyage", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 730, "2000": 16}}, {"id": 1530, "position": 1530, "text": "abash he spat into? And nothing about his losing his leg last\nvoyage, according to the prophecy. Didn’t ye hear a word about them\nmatters and something more, eh? No, I don’t think ye did; how could ye", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1620}}, {"id": 1531, "position": 1531, "text": "eh? No, I don’t think ye did; how could ye?\nWho knows it? Not all Nantucket, I guess. But hows’ever, mayhap, ye’ve\nheard tell about the leg, and how he", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 54, "2000": 1620}}, {"id": 1532, "position": 1532, "text": "hap, ye’ve\nheard tell about the leg, and how he lost it; aye, ye have heard of\nthat, I dare say. Oh yes, _that_ every one knows a’most—I mean they\nknow he’s", "labels": {"50": 41, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 1199}}, {"id": 1533, "position": 1533, "text": "_ every one knows a’most—I mean they\nknow he’s only one leg; and that a parmacetti took the other off.”\n\n“My friend,” said I, “what all this gibberish of yours is about", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1534, "position": 1534, "text": "” said I, “what all this gibberish of yours is about, I\ndon’t know, and I don’t much care; for it seems to me that you must be\na little damaged in the head", "labels": {"50": 25, "100": 41, "250": 91, "500": 221, "1000": 627, "2000": 1199}}, {"id": 1535, "position": 1535, "text": "that you must be\na little damaged in the head. But if you are speaking of Captain Ahab,\nof that ship there, the Pequod, then let me tell you, that I know all\nabout the loss of his leg.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1536, "position": 1536, "text": "you, that I know all\nabout the loss of his leg.”\n\n“_All_ about it, eh—sure you do?—all?”\n\n“Pretty sure.”\n\nWith finger pointed and eye levelled at the Pequod, the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1537, "position": 1537, "text": "”\n\nWith finger pointed and eye levelled at the Pequod, the beggar-like\nstranger stood a moment, as if in a troubled reverie; then starting a\nlittle, turned and said:—“Ye’ve shipped, have ye", "labels": {"50": 9, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 1620}}, {"id": 1538, "position": 1538, "text": "little, turned and said:—“Ye’ve shipped, have ye? Names down on the\npapers? Well, well, what’s signed, is signed; and what’s to be, will\nbe; and then again, perhaps it", "labels": {"50": 41, "100": 21, "250": 163, "500": 432, "1000": 54, "2000": 1199}}, {"id": 1539, "position": 1539, "text": "what’s to be, will\nbe; and then again, perhaps it won’t be, after all. Anyhow, it’s all\nfixed and arranged a’ready; and some sailors or other must go with him,\nI suppose;", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1540, "position": 1540, "text": "ready; and some sailors or other must go with him,\nI suppose; as well these as any other men, God pity ’em! Morning to ye,\nshipmates, morning; the ineffable heavens bless ye; I’m sorry", "labels": {"50": 9, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 16}}, {"id": 1541, "position": 1541, "text": "morning; the ineffable heavens bless ye; I’m sorry I stopped\nye.”\n\n“Look here, friend,” said I, “if you have anything important to tell\nus, out with it; but if you are only trying", "labels": {"50": 23, "100": 31, "250": 219, "500": 221, "1000": 421, "2000": 610}}, {"id": 1542, "position": 1542, "text": "important to tell\nus, out with it; but if you are only trying to bamboozle us, you are\nmistaken in your game; that’s all I have to say.”\n\n“And it’s said very well, and I like to", "labels": {"50": 39, "100": 99, "250": 117, "500": 112, "1000": 766, "2000": 51}}, {"id": 1543, "position": 1543, "text": ".”\n\n“And it’s said very well, and I like to hear a chap talk up that way;\nyou are just the man for him—the likes of ye. Morning to ye, shipmates,\nmorning! Oh! when ye", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1544, "position": 1544, "text": "ye. Morning to ye, shipmates,\nmorning! Oh! when ye get there, tell ’em I’ve concluded not to make one\nof ’em.”\n\n“Ah, my dear fellow, you can’t fool us that way—", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1545, "position": 1545, "text": "Ah, my dear fellow, you can’t fool us that way—you can’t fool us. It\nis the easiest thing in the world for a man to look as if he had a\ngreat secret in him.”", "labels": {"50": 39, "100": 39, "250": 117, "500": 226, "1000": 939, "2000": 610}}, {"id": 1546, "position": 1546, "text": "as if he had a\ngreat secret in him.”\n\n“Morning to ye, shipmates, morning.”\n\n“Morning it is,” said I. “Come along, Queequeg, let’s leave this crazy\nman", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1547, "position": 1547, "text": "Queequeg, let’s leave this crazy\nman. But stop, tell me your name, will you?”\n\n“Elijah.”\n\nElijah! thought I, and we walked away, both commenting, after each\nother’s fashion, upon", "labels": {"50": 25, "100": 41, "250": 219, "500": 180, "1000": 421, "2000": 1954}}, {"id": 1548, "position": 1548, "text": "we walked away, both commenting, after each\nother’s fashion, upon this ragged old sailor; and agreed that he was\nnothing but a humbug, trying to be a bugbear. But we had not gone\nperhaps above a hundred yards", "labels": {"50": 25, "100": 41, "250": 55, "500": 388, "1000": 533, "2000": 693}}, {"id": 1549, "position": 1549, "text": "a bugbear. But we had not gone\nperhaps above a hundred yards, when chancing to turn a corner, and\nlooking back as I did so, who should be seen but Elijah following us,\nthough at a distance", "labels": {"50": 25, "100": 93, "250": 136, "500": 233, "1000": 130, "2000": 750}}, {"id": 1550, "position": 1550, "text": "seen but Elijah following us,\nthough at a distance. Somehow, the sight of him struck me so, that I\nsaid nothing to Queequeg of his being behind, but passed on with my\ncomrade, anxious to see whether the stranger would turn", "labels": {"50": 25, "100": 5, "250": 136, "500": 233, "1000": 103, "2000": 1871}}, {"id": 1551, "position": 1551, "text": "but passed on with my\ncomrade, anxious to see whether the stranger would turn the same corner\nthat we did. He did; and then it seemed to me that he was dogging us,\nbut with what intent I could not for the life of me", "labels": {"50": 25, "100": 5, "250": 156, "500": 134, "1000": 103, "2000": 750}}, {"id": 1552, "position": 1552, "text": "ing us,\nbut with what intent I could not for the life of me imagine. This\ncircumstance, coupled with his ambiguous, half-hinting, half-revealing,\nshrouded sort of talk, now begat in me all kinds of vague", "labels": {"50": 20, "100": 56, "250": 101, "500": 382, "1000": 207, "2000": 711}}, {"id": 1553, "position": 1553, "text": "rouded sort of talk, now begat in me all kinds of vague wonderments\nand half-apprehensions, and all connected with the Pequod; and Captain\nAhab; and the leg he had lost; and the Cape Horn fit;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1554, "position": 1554, "text": "ab; and the leg he had lost; and the Cape Horn fit; and the silver\ncalabash; and what Captain Peleg had said of him, when I left the ship\nthe day previous; and the prediction of the squaw Tis", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1555, "position": 1555, "text": "the ship\nthe day previous; and the prediction of the squaw Tistig; and the\nvoyage we had bound ourselves to sail; and a hundred other shadowy\nthings.\n\nI was resolved to satisfy myself whether this ragged Elijah was really\ndogging us", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 693}}, {"id": 1556, "position": 1556, "text": "I was resolved to satisfy myself whether this ragged Elijah was really\ndogging us or not, and with that intent crossed the way with Queequeg,\nand on that side of it retraced our steps", "labels": {"50": 25, "100": 5, "250": 136, "500": 233, "1000": 718, "2000": 937}}, {"id": 1557, "position": 1557, "text": "of it retraced our steps. But Elijah passed on,\nwithout seeming to notice us. This relieved me; and once more, and\nfinally as it seemed to me, I pronounced him in my heart, a humbug.\n\n\nCHAPTER 20", "labels": {"50": 12, "100": 93, "250": 55, "500": 233, "1000": 718, "2000": 1735}}, {"id": 1558, "position": 1558, "text": "I pronounced him in my heart, a humbug.\n\n\nCHAPTER 20. All Astir.\n\nA day or two passed, and there was great activity aboard the Pequod.\nNot only were the old sails being mended, but new sails", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1559, "position": 1559, "text": "od.\nNot only were the old sails being mended, but new sails were coming on\nboard, and bolts of canvas, and coils of rigging; in short, everything\nbetokened that the ship’s preparations were hurrying to a close", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 1560, "position": 1560, "text": "everything\nbetokened that the ship’s preparations were hurrying to a close.\nCaptain Peleg seldom or never went ashore, but sat in his wigwam\nkeeping a sharp look-out upon the hands: Bildad did all the purchasing\nand", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1561, "position": 1561, "text": "look-out upon the hands: Bildad did all the purchasing\nand providing at the stores; and the men employed in the hold and on\nthe rigging were working till long after night-fall.", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1790}}, {"id": 1562, "position": 1562, "text": "long after night-fall.\n\nOn the day following Queequeg’s signing the articles, word was given at\nall the inns where the ship’s company were stopping, that their chests\nmust be on board before night, for there was", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1563, "position": 1563, "text": "stopping, that their chests\nmust be on board before night, for there was no telling how soon the\nvessel might be sailing. So Queequeg and I got down our traps,\nresolving, however, to sleep ashore till the last", "labels": {"50": 25, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1243}}, {"id": 1564, "position": 1564, "text": "traps,\nresolving, however, to sleep ashore till the last. But it seems they\nalways give very long notice in these cases, and the ship did not sail\nfor several days. But no wonder; there was a good deal to be done, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 1565, "position": 1565, "text": ". But no wonder; there was a good deal to be done, and\nthere is no telling how many things to be thought of, before the Pequod\nwas fully equipped.\n\nEvery one knows what a multitude of things—beds, sauce-pan", "labels": {"50": 37, "100": 64, "250": 91, "500": 72, "1000": 54, "2000": 1620}}, {"id": 1566, "position": 1566, "text": ".\n\nEvery one knows what a multitude of things—beds, sauce-pans, knives and\nforks, shovels and tongs, napkins, nut-crackers, and what not, are\nindispensable to the business of housekeeping", "labels": {"50": 42, "100": 59, "250": 159, "500": 298, "1000": 247, "2000": 1658}}, {"id": 1567, "position": 1567, "text": "and what not, are\nindispensable to the business of housekeeping. Just so with whaling,\nwhich necessitates a three-years’ housekeeping upon the wide ocean, far\nfrom all grocers, costermongers,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1568, "position": 1568, "text": "wide ocean, far\nfrom all grocers, costermongers, doctors, bakers, and bankers. And\nthough this also holds true of merchant vessels, yet not by any means\nto the same extent as with whalemen", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1569, "position": 1569, "text": "by any means\nto the same extent as with whalemen. For besides the great length of\nthe whaling voyage, the numerous articles peculiar to the prosecution\nof the fishery, and the impossibility of replacing them at the remote\nharbors usually frequented, it", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1570, "position": 1570, "text": "impossibility of replacing them at the remote\nharbors usually frequented, it must be remembered, that of all ships,\nwhaling vessels are the most exposed to accidents of all kinds, and\nespecially to the destruction and loss of the very things upon which\nthe", "labels": {"50": 45, "100": 29, "250": 34, "500": 72, "1000": 825, "2000": 682}}, {"id": 1571, "position": 1571, "text": ", and\nespecially to the destruction and loss of the very things upon which\nthe success of the voyage most depends. Hence, the spare boats, spare\nspars, and spare lines and harpoons, and spare everythings, almost, but\na spare Captain", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1572, "position": 1572, "text": "and harpoons, and spare everythings, almost, but\na spare Captain and duplicate ship.\n\nAt the period of our arrival at the Island, the heaviest storage of the\nPequod had been almost completed; comprising her beef, bread, water,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1573, "position": 1573, "text": "quod had been almost completed; comprising her beef, bread, water,\nfuel, and iron hoops and staves. But, as before hinted, for some time\nthere was a continual fetching and carrying on board of divers odds and\nends of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1574, "position": 1574, "text": "was a continual fetching and carrying on board of divers odds and\nends of things, both large and small.\n\nChief among those who did this fetching and carrying was Captain\nBildad’s sister, a lean old lady of a most determined and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1575, "position": 1575, "text": "ldad’s sister, a lean old lady of a most determined and indefatigable\nspirit, but withal very kindhearted, who seemed resolved that, if _she_\ncould help it, nothing should be found wanting in the Pe", "labels": {"50": 33, "100": 69, "250": 154, "500": 245, "1000": 293, "2000": 1591}}, {"id": 1576, "position": 1576, "text": "_she_\ncould help it, nothing should be found wanting in the Pequod, after\nonce fairly getting to sea. At one time she would come on board with a\njar of pickles for the steward’s pantry; another time with a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 489}}, {"id": 1577, "position": 1577, "text": "jar of pickles for the steward’s pantry; another time with a bunch of\nquills for the chief mate’s desk, where he kept his log; a third time\nwith a roll of flannel for the small of some one’", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 1578, "position": 1578, "text": "time\nwith a roll of flannel for the small of some one’s rheumatic back.\nNever did any woman better deserve her name, which was Charity—Aunt\nCharity, as everybody called her", "labels": {"50": 11, "100": 22, "250": 214, "500": 428, "1000": 58, "2000": 1332}}, {"id": 1579, "position": 1579, "text": "Charity, as everybody called her. And like a sister of charity did this\ncharitable Aunt Charity bustle about hither and thither, ready to turn\nher hand and heart to anything that promised to yield safety, comfort,\nand consolation to all on", "labels": {"50": 13, "100": 3, "250": 41, "500": 271, "1000": 870, "2000": 1923}}, {"id": 1580, "position": 1580, "text": "to anything that promised to yield safety, comfort,\nand consolation to all on board a ship in which her beloved brother\nBildad was concerned, and in which she herself owned a score or two of\nwell-saved dollars.", "labels": {"50": 45, "100": 64, "250": 138, "500": 60, "1000": 155, "2000": 592}}, {"id": 1581, "position": 1581, "text": "a score or two of\nwell-saved dollars.\n\nBut it was startling to see this excellent hearted Quakeress coming on\nboard, as she did the last day, with a long oil-ladle in one hand, and\na still longer whaling lance in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1582, "position": 1582, "text": "oil-ladle in one hand, and\na still longer whaling lance in the other. Nor was Bildad himself nor\nCaptain Peleg at all backward. As for Bildad, he carried about with him\na long list of the articles needed", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1583, "position": 1583, "text": "ldad, he carried about with him\na long list of the articles needed, and at every fresh arrival, down\nwent his mark opposite that article upon the paper. Every once in a\nwhile Peleg came hobbling out of his whalebone den,", "labels": {"50": 23, "100": 64, "250": 219, "500": 228, "1000": 851, "2000": 1620}}, {"id": 1584, "position": 1584, "text": "in a\nwhile Peleg came hobbling out of his whalebone den, roaring at the men\ndown the hatchways, roaring up to the riggers at the mast-head, and\nthen concluded by roaring back into his wigwam.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1585, "position": 1585, "text": ", and\nthen concluded by roaring back into his wigwam.\n\nDuring these days of preparation, Queequeg and I often visited the\ncraft, and as often I asked about Captain Ahab, and how he was, and\nwhen he was going", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1586, "position": 1586, "text": "about Captain Ahab, and how he was, and\nwhen he was going to come on board his ship. To these questions they\nwould answer, that he was getting better and better, and was expected\naboard every day; meantime, the two captains,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 1587, "position": 1587, "text": "better, and was expected\naboard every day; meantime, the two captains, Peleg and Bildad, could\nattend to everything necessary to fit the vessel for the voyage. If I\nhad been downright honest with myself, I would have seen very", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 851, "2000": 967}}, {"id": 1588, "position": 1588, "text": "If I\nhad been downright honest with myself, I would have seen very plainly\nin my heart that I did but half fancy being committed this way to so\nlong a voyage, without once laying my eyes on the man who was to be the\nabsolute dictator", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1589, "position": 1589, "text": "without once laying my eyes on the man who was to be the\nabsolute dictator of it, so soon as the ship sailed out upon the open\nsea. But when a man suspects any wrong, it sometimes happens that if he\nbe already involved in the matter", "labels": {"50": 25, "100": 41, "250": 156, "500": 388, "1000": 313, "2000": 786}}, {"id": 1590, "position": 1590, "text": "any wrong, it sometimes happens that if he\nbe already involved in the matter, he insensibly strives to cover up\nhis suspicions even from himself. And much this way it was with me. I\nsaid nothing, and tried to think nothing.", "labels": {"50": 46, "100": 72, "250": 186, "500": 226, "1000": 812, "2000": 1398}}, {"id": 1591, "position": 1591, "text": "it was with me. I\nsaid nothing, and tried to think nothing.\n\nAt last it was given out that some time next day the ship would\ncertainly sail. So next morning, Queequeg and I took a very early\nstart.\n\n\nCHAPTER 21", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1192}}, {"id": 1592, "position": 1592, "text": ", Queequeg and I took a very early\nstart.\n\n\nCHAPTER 21. Going Aboard.\n\nIt was nearly six o’clock, but only grey imperfect misty dawn, when we\ndrew nigh the wharf.", "labels": {"50": 25, "100": 41, "250": 156, "500": 388, "1000": 529, "2000": 693}}, {"id": 1593, "position": 1593, "text": "we\ndrew nigh the wharf.\n\n“There are some sailors running ahead there, if I see right,” said I to\nQueequeg, “it can’t be shadows; she’s off by sunrise, I guess; come\non", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1594, "position": 1594, "text": "be shadows; she’s off by sunrise, I guess; come\non!”\n\n“Avast!” cried a voice, whose owner at the same time coming close\nbehind us, laid a hand upon both our shoulders, and then insinuating", "labels": {"50": 25, "100": 5, "250": 136, "500": 134, "1000": 930, "2000": 117}}, {"id": 1595, "position": 1595, "text": "us, laid a hand upon both our shoulders, and then insinuating\nhimself between us, stood stooping forward a little, in the uncertain\ntwilight, strangely peering from Queequeg to me. It was Elijah.\n\n“Going aboard?”", "labels": {"50": 41, "100": 64, "250": 163, "500": 180, "1000": 54, "2000": 786}}, {"id": 1596, "position": 1596, "text": "equeg to me. It was Elijah.\n\n“Going aboard?”\n\n“Hands off, will you,” said I.\n\n“Lookee here,” said Queequeg, shaking himself, “go ’way!”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 1597, "position": 1597, "text": "queg, shaking himself, “go ’way!”\n\n“Ain’t going aboard, then?”\n\n“Yes, we are,” said I, “but what business is that of yours? Do you\nknow, Mr", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 1620}}, {"id": 1598, "position": 1598, "text": "business is that of yours? Do you\nknow, Mr. Elijah, that I consider you a little impertinent?”\n\n“No, no, no; I wasn’t aware of that,” said Elijah, slowly and\nwonderingly looking", "labels": {"50": 39, "100": 99, "250": 202, "500": 84, "1000": 315, "2000": 661}}, {"id": 1599, "position": 1599, "text": "’t aware of that,” said Elijah, slowly and\nwonderingly looking from me to Queequeg, with the most unaccountable\nglances.\n\n“Elijah,” said I, “you will oblige my friend and me by", "labels": {"50": 25, "100": 93, "250": 136, "500": 388, "1000": 718, "2000": 786}}, {"id": 1600, "position": 1600, "text": "” said I, “you will oblige my friend and me by withdrawing. We\nare going to the Indian and Pacific Oceans, and would prefer not to be\ndetained.”\n\n“Ye be, be ye? Coming back afore breakfast?”", "labels": {"50": 41, "100": 31, "250": 219, "500": 221, "1000": 317, "2000": 1199}}, {"id": 1601, "position": 1601, "text": "”\n\n“Ye be, be ye? Coming back afore breakfast?”\n\n“He’s cracked, Queequeg,” said I, “come on.”\n\n“Holloa!” cried stationary Elijah, hailing us when we", "labels": {"50": 41, "100": 31, "250": 228, "500": 208, "1000": 516, "2000": 270}}, {"id": 1602, "position": 1602, "text": "“Holloa!” cried stationary Elijah, hailing us when we had removed a few\npaces.\n\n“Never mind him,” said I, “Queequeg, come on.”\n\nBut he stole up to us again, and suddenly", "labels": {"50": 25, "100": 93, "250": 136, "500": 180, "1000": 718, "2000": 1954}}, {"id": 1603, "position": 1603, "text": ", come on.”\n\nBut he stole up to us again, and suddenly clapping his hand on my\nshoulder, said—“Did ye see anything looking like men going towards that\nship a while ago?”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 786}}, {"id": 1604, "position": 1604, "text": "ship a while ago?”\n\nStruck by this plain matter-of-fact question, I answered, saying, “Yes,\nI thought I did see four or five men; but it was too dim to be sure.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 1605, "position": 1605, "text": "but it was too dim to be sure.”\n\n“Very dim, very dim,” said Elijah. “Morning to ye.”\n\nOnce more we quitted him; but once more he came softly after us; and\ntouching my shoulder again, said", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1860}}, {"id": 1606, "position": 1606, "text": "once more he came softly after us; and\ntouching my shoulder again, said, “See if you can find ’em now, will\nye?\n\n“Find who?”\n\n“Morning to ye! morning to ye!” he rejoined, again moving off", "labels": {"50": 25, "100": 5, "250": 136, "500": 233, "1000": 730, "2000": 1521}}, {"id": 1607, "position": 1607, "text": "Morning to ye! morning to ye!” he rejoined, again moving off. “Oh! I\nwas going to warn ye against—but never mind, never mind—it’s all one,\nall in the family too;—sharp frost this", "labels": {"50": 41, "100": 88, "250": 219, "500": 221, "1000": 627, "2000": 1199}}, {"id": 1608, "position": 1608, "text": "’s all one,\nall in the family too;—sharp frost this morning, ain’t it? Good-bye to\nye. Shan’t see ye again very soon, I guess; unless it’s before the\nGrand Jury.”", "labels": {"50": 41, "100": 21, "250": 174, "500": 5, "1000": 58, "2000": 1783}}, {"id": 1609, "position": 1609, "text": "soon, I guess; unless it’s before the\nGrand Jury.” And with these cracked words he finally departed, leaving\nme, for the moment, in no small wonderment at his frantic impudence.", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 462, "2000": 1702}}, {"id": 1610, "position": 1610, "text": "ment at his frantic impudence.\n\nAt last, stepping on board the Pequod, we found everything in profound\nquiet, not a soul moving. The cabin entrance was locked within; the\nhatches were all on, and lumbered with coils", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1611, "position": 1611, "text": "within; the\nhatches were all on, and lumbered with coils of rigging. Going forward\nto the forecastle, we found the slide of the scuttle open. Seeing a\nlight, we went down, and found only an old", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 1612, "position": 1612, "text": "open. Seeing a\nlight, we went down, and found only an old rigger there, wrapped in a\ntattered pea-jacket. He was thrown at whole length upon two chests, his\nface downwards and inclosed in his folded arms", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 1613, "position": 1613, "text": "two chests, his\nface downwards and inclosed in his folded arms. The profoundest slumber\nslept upon him.\n\n“Those sailors we saw, Queequeg, where can they have gone to?” said I,\nlooking dubiously at", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1614, "position": 1614, "text": "where can they have gone to?” said I,\nlooking dubiously at the sleeper. But it seemed that, when on the\nwharf, Queequeg had not at all noticed what I now alluded to; hence I\nwould have thought myself", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 462, "2000": 742}}, {"id": 1615, "position": 1615, "text": "all noticed what I now alluded to; hence I\nwould have thought myself to have been optically deceived in that\nmatter, were it not for Elijah’s otherwise inexplicable question", "labels": {"50": 5, "100": 33, "250": 194, "500": 32, "1000": 966, "2000": 608}}, {"id": 1616, "position": 1616, "text": "inexplicable question. But I\nbeat the thing down; and again marking the sleeper, jocularly hinted to\nQueequeg that perhaps we had best sit up with the body; telling him to\nestablish himself accordingly", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1620}}, {"id": 1617, "position": 1617, "text": "up with the body; telling him to\nestablish himself accordingly. He put his hand upon the sleeper’s rear,\nas though feeling if it was soft enough; and then, without more ado,\nsat quietly down there.", "labels": {"50": 22, "100": 55, "250": 145, "500": 3, "1000": 932, "2000": 1554}}, {"id": 1618, "position": 1618, "text": "without more ado,\nsat quietly down there.\n\n“Gracious! Queequeg, don’t sit there,” said I.\n\n“Oh! perry dood seat,” said Queequeg, “my country way; won", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1619, "position": 1619, "text": "seat,” said Queequeg, “my country way; won’t hurt him\nface.”\n\n“Face!” said I, “call that his face? very benevolent countenance then;\nbut how hard he breathes, he", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1620, "position": 1620, "text": "very benevolent countenance then;\nbut how hard he breathes, he’s heaving himself; get off, Queequeg, you\nare heavy, it’s grinding the face of the poor", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 637, "2000": 39}}, {"id": 1621, "position": 1621, "text": "grinding the face of the poor. Get off, Queequeg! Look,\nhe’ll twitch you off soon. I wonder he don’t wake.”\n\nQueequeg removed himself to just beyond the head of the sleeper, and", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 327, "2000": 1620}}, {"id": 1622, "position": 1622, "text": "equeg removed himself to just beyond the head of the sleeper, and\nlighted his tomahawk pipe. I sat at the feet. We kept the pipe passing\nover the sleeper, from one to the other", "labels": {"50": 25, "100": 93, "250": 136, "500": 233, "1000": 906, "2000": 453}}, {"id": 1623, "position": 1623, "text": "sleeper, from one to the other. Meanwhile, upon questioning\nhim in his broken fashion, Queequeg gave me to understand that, in his\nland, owing to the absence of settees and sofas of all sorts, the king,\nchiefs", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1624, "position": 1624, "text": "absence of settees and sofas of all sorts, the king,\nchiefs, and great people generally, were in the custom of fattening\nsome of the lower orders for ottomans; and to furnish a house\ncomfortably in that respect, you had", "labels": {"50": 26, "100": 10, "250": 226, "500": 474, "1000": 269, "2000": 804}}, {"id": 1625, "position": 1625, "text": "ottomans; and to furnish a house\ncomfortably in that respect, you had only to buy up eight or ten lazy\nfellows, and lay them round in the piers and alcoves. Besides, it was\nvery convenient on an excursion; much better than", "labels": {"50": 48, "100": 0, "250": 90, "500": 224, "1000": 689, "2000": 978}}, {"id": 1626, "position": 1626, "text": "ves. Besides, it was\nvery convenient on an excursion; much better than those garden-chairs\nwhich are convertible into walking-sticks; upon occasion, a chief\ncalling his attendant, and desiring him to make a settee of himself\nunder a spreading", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 485, "2000": 1002}}, {"id": 1627, "position": 1627, "text": ", and desiring him to make a settee of himself\nunder a spreading tree, perhaps in some damp marshy place.\n\nWhile narrating these things, every time Queequeg received the tomahawk\nfrom me, he flourished the hatch", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 1628, "position": 1628, "text": "equeg received the tomahawk\nfrom me, he flourished the hatchet-side of it over the sleeper’s head.\n\n“What’s that for, Queequeg?”\n\n“Perry easy, kill-e; oh!", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 1629, "position": 1629, "text": "equeg?”\n\n“Perry easy, kill-e; oh! perry easy!”\n\nHe was going on with some wild reminiscences about his tomahawk-pipe,\nwhich, it seemed, had in its two uses both", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 1630, "position": 1630, "text": "wk-pipe,\nwhich, it seemed, had in its two uses both brained his foes and soothed\nhis soul, when we were directly attracted to the sleeping rigger. The\nstrong vapor now completely filling the contracted hole, it began to", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 1631, "position": 1631, "text": "ger. The\nstrong vapor now completely filling the contracted hole, it began to\ntell upon him. He breathed with a sort of muffledness; then seemed\ntroubled in the nose; then revolved over once or twice; then sat up and\nrubbed his eyes", "labels": {"50": 22, "100": 78, "250": 205, "500": 469, "1000": 508, "2000": 1066}}, {"id": 1632, "position": 1632, "text": "then revolved over once or twice; then sat up and\nrubbed his eyes.\n\n“Holloa!” he breathed at last, “who be ye smokers?”\n\n“Shipped men,” answered I, “when does she sail?”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1633, "position": 1633, "text": "“Shipped men,” answered I, “when does she sail?”\n\n“Aye, aye, ye are going in her, be ye? She sails to-day. The Captain\ncame aboard last night.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 1634, "position": 1634, "text": "The Captain\ncame aboard last night.”\n\n“What Captain?—Ahab?”\n\n“Who but him indeed?”\n\nI was going to ask him some further questions concerning Ahab, when we\nheard a noise on deck.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 1790}}, {"id": 1635, "position": 1635, "text": "ab, when we\nheard a noise on deck.\n\n“Holloa! Starbuck’s astir,” said the rigger. “He’s a lively chief mate,\nthat; good man, and a pious; but all alive", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1636, "position": 1636, "text": "chief mate,\nthat; good man, and a pious; but all alive now, I must turn to.” And so\nsaying he went on deck, and we followed.\n\nIt was now clear sunrise. Soon the crew came on board in twos", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 1637, "position": 1637, "text": "It was now clear sunrise. Soon the crew came on board in twos and\nthrees; the riggers bestirred themselves; the mates were actively\nengaged; and several of the shore people were busy in bringing various\nlast things on board", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 1638, "position": 1638, "text": "of the shore people were busy in bringing various\nlast things on board. Meanwhile Captain Ahab remained invisibly\nenshrined within his cabin.\n\n\nCHAPTER 22. Merry Christmas.\n\nAt length, towards noon, upon the final dismissal of the ship’", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1639, "position": 1639, "text": ".\n\nAt length, towards noon, upon the final dismissal of the ship’s\nriggers, and after the Pequod had been hauled out from the wharf, and\nafter the ever-thoughtful Charity had come off in a whale-boat, with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1640, "position": 1640, "text": "the ever-thoughtful Charity had come off in a whale-boat, with\nher last gift—a night-cap for Stubb, the second mate, her\nbrother-in-law, and a spare Bible for the steward—after all this,", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1790}}, {"id": 1641, "position": 1641, "text": "-law, and a spare Bible for the steward—after all this, the\ntwo Captains, Peleg and Bildad, issued from the cabin, and turning to\nthe chief mate, Peleg said:\n\n“Now, Mr", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1642, "position": 1642, "text": "chief mate, Peleg said:\n\n“Now, Mr. Starbuck, are you sure everything is right? Captain Ahab is\nall ready—just spoke to him—nothing more to be got from shore, eh?\nWell, call all hands,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1643, "position": 1643, "text": "more to be got from shore, eh?\nWell, call all hands, then. Muster ’em aft here—blast ’em!”\n\n“No need of profane words, however great the hurry, Peleg,” said\nBildad,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1644, "position": 1644, "text": ", however great the hurry, Peleg,” said\nBildad, “but away with thee, friend Starbuck, and do our bidding.”\n\nHow now! Here upon the very point of starting for the voyage, Captain\nPeleg and Captain", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1645, "position": 1645, "text": "upon the very point of starting for the voyage, Captain\nPeleg and Captain Bildad were going it with a high hand on the\nquarter-deck, just as if they were to be joint-commanders at sea, as\nwell as to all appearances", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1646, "position": 1646, "text": "were to be joint-commanders at sea, as\nwell as to all appearances in port. And, as for Captain Ahab, no sign\nof him was yet to be seen; only, they said he was in the cabin", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1647, "position": 1647, "text": "; only, they said he was in the cabin. But\nthen, the idea was, that his presence was by no means necessary in\ngetting the ship under weigh, and steering her well out to sea. Indeed,\nas that was not at all his", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 1648, "position": 1648, "text": "her well out to sea. Indeed,\nas that was not at all his proper business, but the pilot’s; and as he\nwas not yet completely recovered—so they said—therefore, Captain Ahab\nstayed below", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1649, "position": 1649, "text": "said—therefore, Captain Ahab\nstayed below. And all this seemed natural enough; especially as in the\nmerchant service many captains never show themselves on deck for a\nconsiderable time after heaving up the anchor, but remain over the\ncabin table, having a farewell", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1650, "position": 1650, "text": "heaving up the anchor, but remain over the\ncabin table, having a farewell merry-making with their shore friends,\nbefore they quit the ship for good with the pilot.\n\nBut there was not much chance to think over the matter, for Captain\nPeleg", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1651, "position": 1651, "text": "there was not much chance to think over the matter, for Captain\nPeleg was now all alive. He seemed to do most of the talking and\ncommanding, and not Bildad.\n\n“Aft here, ye sons of bachelors,” he cried", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1652, "position": 1652, "text": "d.\n\n“Aft here, ye sons of bachelors,” he cried, as the sailors lingered at\nthe main-mast. “Mr. Starbuck, drive ’em aft.”\n\n“Strike the tent there!”—was the next order", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1653, "position": 1653, "text": "aft.”\n\n“Strike the tent there!”—was the next order. As I hinted before, this\nwhalebone marquee was never pitched except in port; and on board the\nPequod, for thirty years, the order to strike", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1654, "position": 1654, "text": "on board the\nPequod, for thirty years, the order to strike the tent was well known\nto be the next thing to heaving up the anchor.\n\n“Man the capstan! Blood and thunder!—jump!”—was the next command", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1655, "position": 1655, "text": "tan! Blood and thunder!—jump!”—was the next command, and\nthe crew sprang for the handspikes.\n\nNow in getting under weigh, the station generally occupied by the pilot\nis the forward part of the ship", "labels": {"50": 37, "100": 64, "250": 163, "500": 176, "1000": 642, "2000": 974}}, {"id": 1656, "position": 1656, "text": "occupied by the pilot\nis the forward part of the ship. And here Bildad, who, with Peleg, be\nit known, in addition to his other officers, was one of the licensed\npilots of the port—he being suspected to have", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1657, "position": 1657, "text": "was one of the licensed\npilots of the port—he being suspected to have got himself made a pilot\nin order to save the Nantucket pilot-fee to all the ships he was\nconcerned in, for he never piloted any other craft—Bildad", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 300, "2000": 1014}}, {"id": 1658, "position": 1658, "text": "was\nconcerned in, for he never piloted any other craft—Bildad, I say, might\nnow be seen actively engaged in looking over the bows for the\napproaching anchor, and at intervals singing what seemed a dismal stave\nof psalmod", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1659, "position": 1659, "text": "and at intervals singing what seemed a dismal stave\nof psalmody, to cheer the hands at the windlass, who roared forth some\nsort of a chorus about the girls in Booble Alley, with hearty good\nwill", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1660, "position": 1660, "text": "the girls in Booble Alley, with hearty good\nwill. Nevertheless, not three days previous, Bildad had told them that\nno profane songs would be allowed on board the Pequod, particularly in\ngetting under weigh; and Charity,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1661, "position": 1661, "text": "board the Pequod, particularly in\ngetting under weigh; and Charity, his sister, had placed a small choice\ncopy of Watts in each seaman’s berth.\n\nMeantime, overseeing the other part of the ship, Captain Peleg ripped\nand swore as", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1662, "position": 1662, "text": "overseeing the other part of the ship, Captain Peleg ripped\nand swore astern in the most frightful manner. I almost thought he\nwould sink the ship before the anchor could be got up; involuntarily I\npaused on my handspi", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 1663, "position": 1663, "text": "be got up; involuntarily I\npaused on my handspike, and told Queequeg to do the same, thinking of\nthe perils we both ran, in starting on the voyage with such a devil for\na pilot", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1664, "position": 1664, "text": "ran, in starting on the voyage with such a devil for\na pilot. I was comforting myself, however, with the thought that in\npious Bildad might be found some salvation, spite of his seven hundred\nand seventy-seventh lay; when I", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1665, "position": 1665, "text": "salvation, spite of his seven hundred\nand seventy-seventh lay; when I felt a sudden sharp poke in my rear,\nand turning round, was horrified at the apparition of Captain Peleg in\nthe act of withdrawing his leg from my immediate vicinity", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1666, "position": 1666, "text": "of Captain Peleg in\nthe act of withdrawing his leg from my immediate vicinity. That was my\nfirst kick.\n\n“Is that the way they heave in the marchant service?” he roared.\n“Spring, thou sheep-head; spring,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1667, "position": 1667, "text": "?” he roared.\n“Spring, thou sheep-head; spring, and break thy backbone! Why don’t ye\nspring, I say, all of ye—spring! Quohog! spring, thou chap with the red\nwhiskers", "labels": {"50": 9, "100": 12, "250": 16, "500": 99, "1000": 345, "2000": 1880}}, {"id": 1668, "position": 1668, "text": "! Quohog! spring, thou chap with the red\nwhiskers; spring there, Scotch-cap; spring, thou green pants. Spring, I\nsay, all of ye, and spring your eyes out!” And so saying, he", "labels": {"50": 11, "100": 12, "250": 16, "500": 99, "1000": 197, "2000": 1880}}, {"id": 1669, "position": 1669, "text": "of ye, and spring your eyes out!” And so saying, he moved\nalong the windlass, here and there using his leg very freely, while\nimperturbable Bildad kept leading off with his psalmody", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1670, "position": 1670, "text": "ble Bildad kept leading off with his psalmody. Thinks I,\nCaptain Peleg must have been drinking something to-day.\n\nAt last the anchor was up, the sails were set, and off we glided", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1671, "position": 1671, "text": "the sails were set, and off we glided. It\nwas a short, cold Christmas; and as the short northern day merged into\nnight, we found ourselves almost broad upon the wintry ocean, whose\nfreezing spray cased us in ice, as in", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 1672, "position": 1672, "text": "wintry ocean, whose\nfreezing spray cased us in ice, as in polished armor. The long rows of\nteeth on the bulwarks glistened in the moonlight; and like the white\nivory tusks of some huge elephant, vast", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1028}}, {"id": 1673, "position": 1673, "text": "; and like the white\nivory tusks of some huge elephant, vast curving icicles depended from\nthe bows.\n\nLank Bildad, as pilot, headed the first watch, and ever and anon, as\nthe old craft deep dived", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 1674, "position": 1674, "text": "watch, and ever and anon, as\nthe old craft deep dived into the green seas, and sent the shivering\nfrost all over her, and the winds howled, and the cordage rang, his\nsteady notes were heard,—", "labels": {"50": 16, "100": 73, "250": 15, "500": 406, "1000": 779, "2000": 16}}, {"id": 1675, "position": 1675, "text": "the cordage rang, his\nsteady notes were heard,—\n\n\n_“Sweet fields beyond the swelling flood, Stand dressed in living\ngreen. So to the Jews old Canaan stood, While Jordan rolled between.”_", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 779, "2000": 198}}, {"id": 1676, "position": 1676, "text": ", While Jordan rolled between.”_\n\n\n\nNever did those sweet words sound more sweetly to me than then. They\nwere full of hope and fruition. Spite of this frigid winter night in\nthe boisterous Atlantic, spite of my wet feet", "labels": {"50": 25, "100": 41, "250": 204, "500": 412, "1000": 329, "2000": 1860}}, {"id": 1677, "position": 1677, "text": "id winter night in\nthe boisterous Atlantic, spite of my wet feet and wetter jacket, there\nwas yet, it then seemed to me, many a pleasant haven in store; and\nmeads and glades so eternally vernal,", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 1678, "position": 1678, "text": "store; and\nmeads and glades so eternally vernal, that the grass shot up by the\nspring, untrodden, unwilted, remains at midsummer.\n\nAt last we gained such an offing, that the two pilots were", "labels": {"50": 9, "100": 26, "250": 120, "500": 406, "1000": 118, "2000": 1393}}, {"id": 1679, "position": 1679, "text": ".\n\nAt last we gained such an offing, that the two pilots were needed no\nlonger. The stout sail-boat that had accompanied us began ranging\nalongside.\n\nIt was curious and not unpleasing, how Peleg and Bildad were", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1680, "position": 1680, "text": "and not unpleasing, how Peleg and Bildad were affected\nat this juncture, especially Captain Bildad. For loath to depart, yet;\nvery loath to leave, for good, a ship bound on so long", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1681, "position": 1681, "text": "very loath to leave, for good, a ship bound on so long and perilous a\nvoyage—beyond both stormy Capes; a ship in which some thousands of his\nhard earned dollars were invested; a ship, in which an old ship", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1682, "position": 1682, "text": "his\nhard earned dollars were invested; a ship, in which an old shipmate\nsailed as captain; a man almost as old as he, once more starting to\nencounter all the terrors of the pitiless jaw; loath to say good-", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1683, "position": 1683, "text": "terrors of the pitiless jaw; loath to say good-bye to\na thing so every way brimful of every interest to him,—poor old Bildad\nlingered long; paced the deck with anxious strides; ran down into", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1684, "position": 1684, "text": "ldad\nlingered long; paced the deck with anxious strides; ran down into the\ncabin to speak another farewell word there; again came on deck, and\nlooked to windward; looked towards the wide and endless waters, only\nbounded by the far-off", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 300, "2000": 1014}}, {"id": 1685, "position": 1685, "text": "looked towards the wide and endless waters, only\nbounded by the far-off unseen Eastern Continents; looked towards the\nland; looked aloft; looked right and left; looked everywhere and\nnowhere; and at last, mechanically coiling a rope upon its pin", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 1686, "position": 1686, "text": "and\nnowhere; and at last, mechanically coiling a rope upon its pin,\nconvulsively grasped stout Peleg by the hand, and holding up a lantern,\nfor a moment stood gazing heroically in his face, as much as to say", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 272, "2000": 786}}, {"id": 1687, "position": 1687, "text": "a moment stood gazing heroically in his face, as much as to say,\n“Nevertheless, friend Peleg, I can stand it; yes, I can.”\n\nAs for Peleg himself, he took it more like a philosopher; but for", "labels": {"50": 39, "100": 99, "250": 57, "500": 187, "1000": 488, "2000": 51}}, {"id": 1688, "position": 1688, "text": "for Peleg himself, he took it more like a philosopher; but for all\nhis philosophy, there was a tear twinkling in his eye, when the lantern\ncame too near. And he, too, did not a little run from cabin to deck", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1689, "position": 1689, "text": ". And he, too, did not a little run from cabin to deck—now\na word below, and now a word with Starbuck, the chief mate.\n\nBut, at last, he turned to his comrade, with a final sort of look", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1690, "position": 1690, "text": "at last, he turned to his comrade, with a final sort of look about\nhim,—“Captain Bildad—come, old shipmate, we must go. Back the main-yard\nthere! Boat ahoy! Stand by to come", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 1691, "position": 1691, "text": "Back the main-yard\nthere! Boat ahoy! Stand by to come close alongside, now! Careful,\ncareful!—come, Bildad, boy—say your last. Luck to ye, Starbuck—luck to\nye, Mr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1692, "position": 1692, "text": "last. Luck to ye, Starbuck—luck to\nye, Mr. Stubb—luck to ye, Mr. Flask—good-bye and good luck to ye\nall—and this day three years I’ll have a hot supper smoking", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 1693, "position": 1693, "text": "all—and this day three years I’ll have a hot supper smoking for ye in\nold Nantucket. Hurrah and away!”\n\n“God bless ye, and have ye in His holy keeping, men,” murmured old\nBildad", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1694, "position": 1694, "text": "have ye in His holy keeping, men,” murmured old\nBildad, almost incoherently. “I hope ye’ll have fine weather now, so\nthat Captain Ahab may soon be moving among ye—a pleasant sun is all", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1695, "position": 1695, "text": "Captain Ahab may soon be moving among ye—a pleasant sun is all he\nneeds, and ye’ll have plenty of them in the tropic voyage ye go. Be\ncareful in the hunt, ye mates", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1696, "position": 1696, "text": "Be\ncareful in the hunt, ye mates. Don’t stave the boats needlessly, ye\nharpooneers; good white cedar plank is raised full three per cent.\nwithin the year. Don’t forget your prayers, either. Mr", "labels": {"50": 12, "100": 38, "250": 209, "500": 344, "1000": 286, "2000": 624}}, {"id": 1697, "position": 1697, "text": ".\nwithin the year. Don’t forget your prayers, either. Mr. Starbuck, mind\nthat cooper don’t waste the spare staves. Oh! the sail-needles are in\nthe green locker! Don’t whale it too much", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1698, "position": 1698, "text": "-needles are in\nthe green locker! Don’t whale it too much a’ Lord’s days, men; but\ndon’t miss a fair chance either, that’s rejecting Heaven’s good gifts", "labels": {"50": 41, "100": 21, "250": 215, "500": 281, "1000": 230, "2000": 68}}, {"id": 1699, "position": 1699, "text": "’s rejecting Heaven’s good gifts.\nHave an eye to the molasses tierce, Mr. Stubb; it was a little leaky, I\nthought. If ye touch at the islands, Mr", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1700, "position": 1700, "text": "If ye touch at the islands, Mr. Flask, beware of fornication.\nGood-bye, good-bye! Don’t keep that cheese too long down in the hold,\nMr. Starbuck; it’ll spoil", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1701, "position": 1701, "text": "down in the hold,\nMr. Starbuck; it’ll spoil. Be careful with the butter—twenty cents the\npound it was, and mind ye, if—”\n\n“Come, come, Captain Bildad; stop palavering,", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1702, "position": 1702, "text": "“Come, come, Captain Bildad; stop palavering,—away!” and with that,\nPeleg hurried him over the side, and both dropt into the boat.\n\nShip and boat diverged; the cold, damp night", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1703, "position": 1703, "text": "into the boat.\n\nShip and boat diverged; the cold, damp night breeze blew between; a\nscreaming gull flew overhead; the two hulls wildly rolled; we gave\nthree heavy-hearted cheers, and blindly plunged like fate into the lone\nAtlantic", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 1704, "position": 1704, "text": "three heavy-hearted cheers, and blindly plunged like fate into the lone\nAtlantic.\n\n\nCHAPTER 23. The Lee Shore.\n\nSome chapters back, one Bulkington was spoken of, a tall, newlanded\nmariner, encountered in New Bedford at the inn", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1584}}, {"id": 1705, "position": 1705, "text": "tall, newlanded\nmariner, encountered in New Bedford at the inn.\n\nWhen on that shivering winter’s night, the Pequod thrust her vindictive\nbows into the cold malicious waves, who should I see standing at her\nhelm but", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1706, "position": 1706, "text": "into the cold malicious waves, who should I see standing at her\nhelm but Bulkington! I looked with sympathetic awe and fearfulness upon\nthe man, who in mid-winter just landed from a four years’ dangerous\nvoyage, could so unrestingly push", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 54, "2000": 967}}, {"id": 1707, "position": 1707, "text": "just landed from a four years’ dangerous\nvoyage, could so unrestingly push off again for still another\ntempestuous term. The land seemed scorching to his feet. Wonderfullest\nthings are ever the unmentionable; deep memories yield no", "labels": {"50": 25, "100": 20, "250": 90, "500": 162, "1000": 529, "2000": 1735}}, {"id": 1708, "position": 1708, "text": "lest\nthings are ever the unmentionable; deep memories yield no epitaphs;\nthis six-inch chapter is the stoneless grave of Bulkington. Let me only\nsay that it fared with him as with the storm-tossed ship", "labels": {"50": 16, "100": 73, "250": 133, "500": 449, "1000": 944, "2000": 1993}}, {"id": 1709, "position": 1709, "text": "only\nsay that it fared with him as with the storm-tossed ship, that\nmiserably drives along the leeward land. The port would fain give\nsuccor; the port is pitiful; in the port is safety, comfort", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 779, "2000": 16}}, {"id": 1710, "position": 1710, "text": "r; the port is pitiful; in the port is safety, comfort,\nhearthstone, supper, warm blankets, friends, all that’s kind to our\nmortalities. But in that gale, the port, the land, is that ship", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 185, "2000": 463}}, {"id": 1711, "position": 1711, "text": ". But in that gale, the port, the land, is that ship’s\ndirest jeopardy; she must fly all hospitality; one touch of land,\nthough it but graze the keel, would make her shudder through and\nthrough", "labels": {"50": 9, "100": 73, "250": 133, "500": 73, "1000": 437, "2000": 16}}, {"id": 1712, "position": 1712, "text": "graze the keel, would make her shudder through and\nthrough. With all her might she crowds all sail off shore; in so doing,\nfights ’gainst the very winds that fain would blow her homeward; seeks\nall the lashed sea’", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 663, "2000": 1058}}, {"id": 1713, "position": 1713, "text": "that fain would blow her homeward; seeks\nall the lashed sea’s landlessness again; for refuge’s sake forlornly\nrushing into peril; her only friend her bitterest foe!", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 779, "2000": 573}}, {"id": 1714, "position": 1714, "text": "only friend her bitterest foe!\n\nKnow ye now, Bulkington? Glimpses do ye seem to see of that mortally\nintolerable truth; that all deep, earnest thinking is but the intrepid\neffort of the soul to keep the open independence", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 437, "2000": 193}}, {"id": 1715, "position": 1715, "text": "is but the intrepid\neffort of the soul to keep the open independence of her sea; while the\nwildest winds of heaven and earth conspire to cast her on the\ntreacherous, slavish shore?", "labels": {"50": 16, "100": 73, "250": 13, "500": 414, "1000": 548, "2000": 336}}, {"id": 1716, "position": 1716, "text": "the\ntreacherous, slavish shore?\n\nBut as in landlessness alone resides highest truth, shoreless,\nindefinite as God—so, better is it to perish in that howling infinite,\nthan be ingloriously dashed upon the lee, even if", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 1717, "position": 1717, "text": "howling infinite,\nthan be ingloriously dashed upon the lee, even if that were safety! For\nworm-like, then, oh! who would craven crawl to land! Terrors of the\nterrible! is all this agony so vain? Take heart", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 16}}, {"id": 1718, "position": 1718, "text": "Terrors of the\nterrible! is all this agony so vain? Take heart, take heart, O\nBulkington! Bear thee grimly, demigod! Up from the spray of thy\nocean-perishing—straight up, leaps thy apotheo", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 16}}, {"id": 1719, "position": 1719, "text": "of thy\nocean-perishing—straight up, leaps thy apotheosis!\n\n\nCHAPTER 24. The Advocate.\n\nAs Queequeg and I are now fairly embarked in this business of whaling;\nand as this business of whaling has somehow come to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1720, "position": 1720, "text": "this business of whaling;\nand as this business of whaling has somehow come to be regarded among\nlandsmen as a rather unpoetical and disreputable pursuit; therefore, I\nam all anxiety to convince ye, ye landsmen, of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1721, "position": 1721, "text": ", I\nam all anxiety to convince ye, ye landsmen, of the injustice hereby\ndone to us hunters of whales.\n\nIn the first place, it may be deemed almost superfluous to establish\nthe fact, that among people at large, the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1722, "position": 1722, "text": "superfluous to establish\nthe fact, that among people at large, the business of whaling is not\naccounted on a level with what are called the liberal professions. If a\nstranger were introduced into any miscellaneous metropolitan society,\nit would but slightly advance the general", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1723, "position": 1723, "text": "were introduced into any miscellaneous metropolitan society,\nit would but slightly advance the general opinion of his merits, were\nhe presented to the company as a harpooneer, say; and if in emulation\nof the naval officers he should append the initials S", "labels": {"50": 44, "100": 68, "250": 193, "500": 202, "1000": 858, "2000": 371}}, {"id": 1724, "position": 1724, "text": "if in emulation\nof the naval officers he should append the initials S.W.F. (Sperm Whale\nFishery) to his visiting card, such a procedure would be deemed\npre-eminently presuming and ridiculous.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1725, "position": 1725, "text": "deemed\npre-eminently presuming and ridiculous.\n\nDoubtless one leading reason why the world declines honoring us\nwhalemen, is this: they think that, at best, our vocation amounts to a\nbutchering sort of business; and that when", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1726, "position": 1726, "text": "our vocation amounts to a\nbutchering sort of business; and that when actively engaged therein, we\nare surrounded by all manner of defilements. Butchers we are, that is\ntrue. But butchers, also, and butchers of", "labels": {"50": 31, "100": 7, "250": 193, "500": 16, "1000": 364, "2000": 1592}}, {"id": 1727, "position": 1727, "text": ", that is\ntrue. But butchers, also, and butchers of the bloodiest badge have been\nall Martial Commanders whom the world invariably delights to honor. And\nas for the matter of the alleged uncleanliness of our business, ye\nshall", "labels": {"50": 31, "100": 95, "250": 193, "500": 307, "1000": 76, "2000": 1543}}, {"id": 1728, "position": 1728, "text": "for the matter of the alleged uncleanliness of our business, ye\nshall soon be initiated into certain facts hitherto pretty generally\nunknown, and which, upon the whole, will triumphantly plant the sperm\nwhale-ship at least among the cleanliest", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1729, "position": 1729, "text": "will triumphantly plant the sperm\nwhale-ship at least among the cleanliest things of this tidy earth. But\neven granting the charge in question to be true; what disordered\nslippery decks of a whale-ship are comparable to the unspeakable", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1730, "position": 1730, "text": "slippery decks of a whale-ship are comparable to the unspeakable\ncarrion of those battle-fields from which so many soldiers return to\ndrink in all ladies’ plaudits? And if the idea of peril so much\nenhances the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1731, "position": 1731, "text": "audits? And if the idea of peril so much\nenhances the popular conceit of the soldier’s profession; let me assure\nye that many a veteran who has freely marched up to a battery, would\nquickly recoil at the appari", "labels": {"50": 31, "100": 75, "250": 114, "500": 307, "1000": 290, "2000": 962}}, {"id": 1732, "position": 1732, "text": "has freely marched up to a battery, would\nquickly recoil at the apparition of the sperm whale’s vast tail,\nfanning into eddies the air over his head. For what are the\ncomprehensible terrors of man compared with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1733, "position": 1733, "text": ". For what are the\ncomprehensible terrors of man compared with the interlinked terrors and\nwonders of God!\n\nBut, though the world scouts at us whale hunters, yet does it\nunwittingly pay us the profoundest homage", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1734, "position": 1734, "text": "hunters, yet does it\nunwittingly pay us the profoundest homage; yea, an all-abounding\nadoration! for almost all the tapers, lamps, and candles that burn\nround the globe, burn, as before so", "labels": {"50": 16, "100": 20, "250": 13, "500": 414, "1000": 747, "2000": 970}}, {"id": 1735, "position": 1735, "text": "lamps, and candles that burn\nround the globe, burn, as before so many shrines, to our glory!\n\nBut look at this matter in other lights; weigh it in all sorts of\nscales; see what we whalemen are, and have been.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1736, "position": 1736, "text": "sorts of\nscales; see what we whalemen are, and have been.\n\nWhy did the Dutch in De Witt’s time have admirals of their whaling\nfleets? Why did Louis XVI. of France, at his own personal expense, fit\nout", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1737, "position": 1737, "text": "did Louis XVI. of France, at his own personal expense, fit\nout whaling ships from Dunkirk, and politely invite to that town some\nscore or two of families from our own island of Nantucket? Why did\nBritain between the years 1750 and 1788 pay", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 327, "2000": 1584}}, {"id": 1738, "position": 1738, "text": "island of Nantucket? Why did\nBritain between the years 1750 and 1788 pay to her whalemen in bounties\nupwards of £1,000,000? And lastly, how comes it that we whalemen of\nAmerica now outnumber all the rest", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 327, "2000": 1620}}, {"id": 1739, "position": 1739, "text": "comes it that we whalemen of\nAmerica now outnumber all the rest of the banded whalemen in the world;\nsail a navy of upwards of seven hundred vessels; manned by eighteen\nthousand men; yearly consuming 4,000,000 of dollars;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1740, "position": 1740, "text": "by eighteen\nthousand men; yearly consuming 4,000,000 of dollars; the ships worth,\nat the time of sailing, $20,000,000! and every year importing into our\nharbors a well reaped harvest of $7", "labels": {"50": 45, "100": 29, "250": 82, "500": 239, "1000": 245, "2000": 1121}}, {"id": 1741, "position": 1741, "text": "importing into our\nharbors a well reaped harvest of $7,000,000. How comes all this, if\nthere be not something puissant in whaling?\n\nBut this is not the half; look again.", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1742, "position": 1742, "text": "?\n\nBut this is not the half; look again.\n\nI freely assert, that the cosmopolite philosopher cannot, for his life,\npoint out one single peaceful influence, which within the last sixty\nyears has operated more potentially upon the whole broad world", "labels": {"50": 21, "100": 95, "250": 43, "500": 480, "1000": 347, "2000": 151}}, {"id": 1743, "position": 1743, "text": "which within the last sixty\nyears has operated more potentially upon the whole broad world, taken\nin one aggregate, than the high and mighty business of whaling. One way\nand another, it has begotten events so remarkable in themselves, and so\ncontinuously moment", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1744, "position": 1744, "text": "it has begotten events so remarkable in themselves, and so\ncontinuously momentous in their sequential issues, that whaling may\nwell be regarded as that Egyptian mother, who bore offspring themselves\npregnant from her womb. It would be a hopeless, endless task to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1745, "position": 1745, "text": "themselves\npregnant from her womb. It would be a hopeless, endless task to\ncatalogue all these things. Let a handful suffice. For many years past\nthe whale-ship has been the pioneer in ferreting out the remotest and\nleast known", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1746, "position": 1746, "text": "has been the pioneer in ferreting out the remotest and\nleast known parts of the earth. She has explored seas and archipelagoes\nwhich had no chart, where no Cook or Vancouver had ever sailed. If\nAmerican and European men-of-war", "labels": {"50": 21, "100": 95, "250": 43, "500": 480, "1000": 347, "2000": 1543}}, {"id": 1747, "position": 1747, "text": "or Vancouver had ever sailed. If\nAmerican and European men-of-war now peacefully ride in once savage\nharbors, let them fire salutes to the honor and glory of the\nwhale-ship, which originally showed them the way, and first interpreted", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 525, "2000": 1620}}, {"id": 1748, "position": 1748, "text": "the\nwhale-ship, which originally showed them the way, and first interpreted\nbetween them and the savages. They may celebrate as they will the\nheroes of Exploring Expeditions, your Cooks, your Krusensterns; but I\nsay that scores of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 1749, "position": 1749, "text": "Cooks, your Krusensterns; but I\nsay that scores of anonymous Captains have sailed out of Nantucket,\nthat were as great, and greater than your Cook and your Krusenstern.\nFor in their succourless empty-", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1750, "position": 1750, "text": "your Krusenstern.\nFor in their succourless empty-handedness, they, in the heathenish\nsharked waters, and by the beaches of unrecorded, javelin islands,\nbattled with virgin wonders and terrors that", "labels": {"50": 31, "100": 73, "250": 193, "500": 307, "1000": 343, "2000": 1107}}, {"id": 1751, "position": 1751, "text": "recorded, javelin islands,\nbattled with virgin wonders and terrors that Cook with all his marines\nand muskets would not willingly have dared. All that is made such a\nflourish of in the old South Sea Voyages, those things were but the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1752, "position": 1752, "text": "a\nflourish of in the old South Sea Voyages, those things were but the\nlife-time commonplaces of our heroic Nantucketers. Often, adventures\nwhich Vancouver dedicates three chapters to, these men accounted\nunworthy of being set down in the", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1753, "position": 1753, "text": "three chapters to, these men accounted\nunworthy of being set down in the ship’s common log. Ah, the world! Oh,\nthe world!\n\nUntil the whale fishery rounded Cape Horn, no commerce but colonial,\nscarcely any intercourse but colonial,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1754, "position": 1754, "text": "rounded Cape Horn, no commerce but colonial,\nscarcely any intercourse but colonial, was carried on between Europe\nand the long line of the opulent Spanish provinces on the Pacific\ncoast. It was the whaleman who first broke through the jealous policy\nof the Spanish", "labels": {"50": 45, "100": 29, "250": 138, "500": 13, "1000": 327, "2000": 887}}, {"id": 1755, "position": 1755, "text": "It was the whaleman who first broke through the jealous policy\nof the Spanish crown, touching those colonies; and, if space permitted,\nit might be distinctly shown how from those whalemen at last eventuated\nthe liberation of Peru, Chili, and Bolivia", "labels": {"50": 21, "100": 66, "250": 76, "500": 144, "1000": 319, "2000": 1536}}, {"id": 1756, "position": 1756, "text": "whalemen at last eventuated\nthe liberation of Peru, Chili, and Bolivia from the yoke of Old Spain,\nand the establishment of the eternal democracy in those parts.\n\nThat great America on the other side of the sphere, Australia, was\ngiven to", "labels": {"50": 5, "100": 19, "250": 66, "500": 144, "1000": 319, "2000": 1536}}, {"id": 1757, "position": 1757, "text": "great America on the other side of the sphere, Australia, was\ngiven to the enlightened world by the whaleman. After its first\nblunder-born discovery by a Dutchman, all other ships long shunned\nthose shores as pestiferous", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1758, "position": 1758, "text": "Dutchman, all other ships long shunned\nthose shores as pestiferously barbarous; but the whale-ship touched\nthere. The whale-ship is the true mother of that now mighty colony", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1759, "position": 1759, "text": "mother of that now mighty colony.\nMoreover, in the infancy of the first Australian settlement, the\nemigrants were several times saved from starvation by the benevolent\nbiscuit of the whale-ship luckily dropping an anchor in their waters", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 31}}, {"id": 1760, "position": 1760, "text": "-ship luckily dropping an anchor in their waters.\nThe uncounted isles of all Polynesia confess the same truth, and do\ncommercial homage to the whale-ship, that cleared the way for the\nmissionary and the merchant, and in many cases", "labels": {"50": 45, "100": 29, "250": 138, "500": 494, "1000": 480, "2000": 187}}, {"id": 1761, "position": 1761, "text": "that cleared the way for the\nmissionary and the merchant, and in many cases carried the primitive\nmissionaries to their first destinations. If that double-bolted land,\nJapan, is ever to become hospitable, it is the whale-ship alone to", "labels": {"50": 45, "100": 29, "250": 158, "500": 13, "1000": 622, "2000": 385}}, {"id": 1762, "position": 1762, "text": "to become hospitable, it is the whale-ship alone to whom\nthe credit will be due; for already she is on the threshold.\n\nBut if, in the face of all this, you still declare that whaling has no\næsthetic", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1763, "position": 1763, "text": "face of all this, you still declare that whaling has no\næsthetically noble associations connected with it, then am I ready to\nshiver fifty lances with you there, and unhorse you with a split helmet\nevery time.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1764, "position": 1764, "text": "and unhorse you with a split helmet\nevery time.\n\nThe whale has no famous author, and whaling no famous chronicler, you\nwill say.\n\n_The whale no famous author, and whaling no famous chronicler?_ Who\nwrote the first account of", "labels": {"50": 31, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1765, "position": 1765, "text": ", and whaling no famous chronicler?_ Who\nwrote the first account of our Leviathan? Who but mighty Job! And who\ncomposed the first narrative of a whaling-voyage? Who, but no less a\nprince than Alfred the Great, who,", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 343, "2000": 1620}}, {"id": 1766, "position": 1766, "text": "? Who, but no less a\nprince than Alfred the Great, who, with his own royal pen, took down\nthe words from Other, the Norwegian whale-hunter of those times! And\nwho pronounced our glowing eulogy in Parliament? Who, but", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 709}}, {"id": 1767, "position": 1767, "text": "times! And\nwho pronounced our glowing eulogy in Parliament? Who, but Edmund Burke!\n\nTrue enough, but then whalemen themselves are poor devils; they have no\ngood blood in their veins.\n\n_No good blood in their veins?_ They have", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1768, "position": 1768, "text": "in their veins.\n\n_No good blood in their veins?_ They have something better than royal\nblood there. The grandmother of Benjamin Franklin was Mary Morrel;\nafterwards, by marriage, Mary Folger, one of the old settlers of\nNantucket", "labels": {"50": 13, "100": 69, "250": 154, "500": 230, "1000": 186, "2000": 1987}}, {"id": 1769, "position": 1769, "text": "marriage, Mary Folger, one of the old settlers of\nNantucket, and the ancestress to a long line of Folgers and\nharpooneers—all kith and kin to noble Benjamin—this day darting the\nbarbed iron", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1770, "position": 1770, "text": "all kith and kin to noble Benjamin—this day darting the\nbarbed iron from one side of the world to the other.\n\nGood again; but then all confess that somehow whaling is not\nrespectable.\n\n_Whaling not respectable?_ Whaling is imperial! By", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1771, "position": 1771, "text": "is not\nrespectable.\n\n_Whaling not respectable?_ Whaling is imperial! By old English\nstatutory law, the whale is declared “a royal fish.” *\n\nOh, that’s only nominal! The whale himself has never figured in any\ngrand imposing way", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1772, "position": 1772, "text": "s only nominal! The whale himself has never figured in any\ngrand imposing way.\n\n_The whale never figured in any grand imposing way?_ In one of the\nmighty triumphs given to a Roman general upon his entering the world’s\ncapital, the", "labels": {"50": 10, "100": 71, "250": 129, "500": 136, "1000": 811, "2000": 1858}}, {"id": 1773, "position": 1773, "text": "given to a Roman general upon his entering the world’s\ncapital, the bones of a whale, brought all the way from the Syrian\ncoast, were the most conspicuous object in the cymballed procession.*", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1774, "position": 1774, "text": "the cymballed procession.*\n\n*See subsequent chapters for something more on this head.\n\nGrant it, since you cite it; but, say what you will, there is no real\ndignity in whaling.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1775, "position": 1775, "text": "no real\ndignity in whaling.\n\n_No dignity in whaling?_ The dignity of our calling the very heavens\nattest. Cetus is a constellation in the South! No more! Drive down your\nhat in presence of the Czar, and take it", "labels": {"50": 31, "100": 20, "250": 69, "500": 72, "1000": 343, "2000": 1620}}, {"id": 1776, "position": 1776, "text": "! Drive down your\nhat in presence of the Czar, and take it off to Queequeg! No more! I\nknow a man that, in his lifetime, has taken three hundred and fifty\nwhales", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1777, "position": 1777, "text": "has taken three hundred and fifty\nwhales. I account that man more honorable than that great captain of\nantiquity who boasted of taking as many walled towns.\n\nAnd, as for me, if, by any possibility, there be any as yet\nundiscovered", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1778, "position": 1778, "text": "if, by any possibility, there be any as yet\nundiscovered prime thing in me; if I shall ever deserve any real repute\nin that small but high hushed world which I might not be unreasonably\nambitious of; if here", "labels": {"50": 9, "100": 10, "250": 226, "500": 56, "1000": 349, "2000": 672}}, {"id": 1779, "position": 1779, "text": "world which I might not be unreasonably\nambitious of; if hereafter I shall do anything that, upon the whole, a\nman might rather have done than to have left undone; if, at my death,\nmy executors", "labels": {"50": 44, "100": 68, "250": 1, "500": 320, "1000": 148, "2000": 1750}}, {"id": 1780, "position": 1780, "text": "have left undone; if, at my death,\nmy executors, or more properly my creditors, find any precious MSS. in\nmy desk, then here I prospectively ascribe all the honor and the glory\nto whaling; for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1781, "position": 1781, "text": "prospectively ascribe all the honor and the glory\nto whaling; for a whale-ship was my Yale College and my Harvard.\n\n\nCHAPTER 25. Postscript.\n\nIn behalf of the dignity of whaling, I would fain advance naught but\nsub", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1782, "position": 1782, "text": "of the dignity of whaling, I would fain advance naught but\nsubstantiated facts. But after embattling his facts, an advocate who\nshould wholly suppress a not unreasonable surmise, which might tell\neloquently upon his cause", "labels": {"50": 3, "100": 85, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1783, "position": 1783, "text": "not unreasonable surmise, which might tell\neloquently upon his cause—such an advocate, would he not be\nblameworthy?\n\nIt is well known that at the coronation of kings and queens, even\nmodern ones, a certain curious process of season", "labels": {"50": 33, "100": 32, "250": 21, "500": 400, "1000": 820, "2000": 1369}}, {"id": 1784, "position": 1784, "text": "of kings and queens, even\nmodern ones, a certain curious process of seasoning them for their\nfunctions is gone through. There is a saltcellar of state, so called,\nand there may be a castor of state", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 387, "2000": 1081}}, {"id": 1785, "position": 1785, "text": ",\nand there may be a castor of state. How they use the salt,\nprecisely—who knows? Certain I am, however, that a king’s head is\nsolemnly oiled at his coronation, even as a head of salad", "labels": {"50": 31, "100": 7, "250": 30, "500": 498, "1000": 849, "2000": 39}}, {"id": 1786, "position": 1786, "text": "solemnly oiled at his coronation, even as a head of salad. Can it be,\nthough, that they anoint it with a view of making its interior run\nwell, as they anoint machinery? Much might be ruminated here,\nconcerning the", "labels": {"50": 31, "100": 64, "250": 193, "500": 73, "1000": 851, "2000": 877}}, {"id": 1787, "position": 1787, "text": "as they anoint machinery? Much might be ruminated here,\nconcerning the essential dignity of this regal process, because in\ncommon life we esteem but meanly and contemptibly a fellow who anoints\nhis hair, and palpably smells of that", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 1788, "position": 1788, "text": "fellow who anoints\nhis hair, and palpably smells of that anointing. In truth, a mature man\nwho uses hair-oil, unless medicinally, that man has probably got a\nquoggy spot in him somewhere", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 851, "2000": 110}}, {"id": 1789, "position": 1789, "text": "that man has probably got a\nquoggy spot in him somewhere. As a general rule, he can’t amount to\nmuch in his totality.\n\nBut the only thing to be considered here, is this—what kind of oil is\nused at coronation", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1790, "position": 1790, "text": "be considered here, is this—what kind of oil is\nused at coronations? Certainly it cannot be olive oil, nor macassar\noil, nor castor oil, nor bear’s oil, nor train oil, nor cod-liver oil", "labels": {"50": 42, "100": 70, "250": 46, "500": 197, "1000": 117, "2000": 1333}}, {"id": 1791, "position": 1791, "text": "nor bear’s oil, nor train oil, nor cod-liver oil.\nWhat then can it possibly be, but sperm oil in its unmanufactured,\nunpolluted state, the sweetest of all oils?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1792, "position": 1792, "text": "polluted state, the sweetest of all oils?\n\nThink of that, ye loyal Britons! we whalemen supply your kings and\nqueens with coronation stuff!\n\n\nCHAPTER 26. Knights and Squires.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1793, "position": 1793, "text": ". Knights and Squires.\n\nThe chief mate of the Pequod was Starbuck, a native of Nantucket, and a\nQuaker by descent. He was a long, earnest man, and though born on an\nicy coast, seemed well adapted to", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1794, "position": 1794, "text": "earnest man, and though born on an\nicy coast, seemed well adapted to endure hot latitudes, his flesh being\nhard as twice-baked biscuit. Transported to the Indies, his live blood\nwould not spoil like bottled ale", "labels": {"50": 0, "100": 57, "250": 70, "500": 39, "1000": 984, "2000": 623}}, {"id": 1795, "position": 1795, "text": ", his live blood\nwould not spoil like bottled ale. He must have been born in some time\nof general drought and famine, or upon one of those fast days for which\nhis state is famous. Only some thirty arid summers had he seen; those\nsummers", "labels": {"50": 44, "100": 37, "250": 143, "500": 294, "1000": 833, "2000": 1966}}, {"id": 1796, "position": 1796, "text": "state is famous. Only some thirty arid summers had he seen; those\nsummers had dried up all his physical superfluousness. But this, his\nthinness, so to speak, seemed no more the token of wasting anxieties\nand cares,", "labels": {"50": 44, "100": 57, "250": 70, "500": 481, "1000": 316, "2000": 1966}}, {"id": 1797, "position": 1797, "text": "speak, seemed no more the token of wasting anxieties\nand cares, than it seemed the indication of any bodily blight. It was\nmerely the condensation of the man. He was by no means ill-looking;\nquite the contrary", "labels": {"50": 46, "100": 88, "250": 89, "500": 211, "1000": 863, "2000": 1964}}, {"id": 1798, "position": 1798, "text": "man. He was by no means ill-looking;\nquite the contrary. His pure tight skin was an excellent fit; and\nclosely wrapped up in it, and embalmed with inner health and strength,\nlike a revivified Egyptian, this Star", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 858, "2000": 955}}, {"id": 1799, "position": 1799, "text": "with inner health and strength,\nlike a revivified Egyptian, this Starbuck seemed prepared to endure for\nlong ages to come, and to endure always, as now; for be it Polar snow\nor torrid sun, like a patent chronometer", "labels": {"50": 16, "100": 64, "250": 138, "500": 162, "1000": 343, "2000": 1620}}, {"id": 1800, "position": 1800, "text": "be it Polar snow\nor torrid sun, like a patent chronometer, his interior vitality was\nwarranted to do well in all climates. Looking into his eyes, you seemed\nto see there the yet lingering images of those thousand-fold per", "labels": {"50": 22, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 1801, "position": 1801, "text": "you seemed\nto see there the yet lingering images of those thousand-fold perils he\nhad calmly confronted through life. A staid, steadfast man, whose life\nfor the most part was a telling pantomime of action, and not a", "labels": {"50": 45, "100": 64, "250": 143, "500": 481, "1000": 531, "2000": 1563}}, {"id": 1802, "position": 1802, "text": "the most part was a telling pantomime of action, and not a tame\nchapter of sounds. Yet, for all his hardy sobriety and fortitude, there\nwere certain qualities in him which at times affected, and in some\ncases seemed well ni", "labels": {"50": 44, "100": 88, "250": 70, "500": 202, "1000": 858, "2000": 110}}, {"id": 1803, "position": 1803, "text": "qualities in him which at times affected, and in some\ncases seemed well nigh to overbalance all the rest. Uncommonly\nconscientious for a seaman, and endued with a deep natural reverence,\nthe wild watery loneliness of his", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 877}}, {"id": 1804, "position": 1804, "text": "ued with a deep natural reverence,\nthe wild watery loneliness of his life did therefore strongly incline\nhim to superstition; but to that sort of superstition, which in some\norganizations seems rather to spring, somehow, from intelligence than\nfrom", "labels": {"50": 22, "100": 78, "250": 229, "500": 380, "1000": 252, "2000": 1976}}, {"id": 1805, "position": 1805, "text": "which in some\norganizations seems rather to spring, somehow, from intelligence than\nfrom ignorance. Outward portents and inward presentiments were his. And\nif at times these things bent the welded iron of his soul, much more\ndid his far-away domestic", "labels": {"50": 10, "100": 71, "250": 229, "500": 29, "1000": 448, "2000": 958}}, {"id": 1806, "position": 1806, "text": "the welded iron of his soul, much more\ndid his far-away domestic memories of his young Cape wife and child,\ntend to bend him still more from the original ruggedness of his nature,\nand open him still further to those latent influences which", "labels": {"50": 17, "100": 16, "250": 146, "500": 369, "1000": 314, "2000": 1726}}, {"id": 1807, "position": 1807, "text": "of his nature,\nand open him still further to those latent influences which, in some\nhonest-hearted men, restrain the gush of dare-devil daring, so often\nevinced by others in the more perilous vicissitudes", "labels": {"50": 0, "100": 4, "250": 114, "500": 341, "1000": 649, "2000": 446}}, {"id": 1808, "position": 1808, "text": "evinced by others in the more perilous vicissitudes of the fishery. “I\nwill have no man in my boat,” said Starbuck, “who is not afraid of a\nwhale.” By this, he seemed to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1809, "position": 1809, "text": "who is not afraid of a\nwhale.” By this, he seemed to mean, not only that the most reliable and\nuseful courage was that which arises from the fair estimation of the\nencountered peril, but that an utterly fearless man is a far more", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1810, "position": 1810, "text": "the\nencountered peril, but that an utterly fearless man is a far more\ndangerous comrade than a coward.\n\n“Aye, aye,” said Stubb, the second mate, “Starbuck, there, is as\ncareful a man as you’ll", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1811, "position": 1811, "text": "“Starbuck, there, is as\ncareful a man as you’ll find anywhere in this fishery.” But we shall\nere long see what that word “careful” precisely means when used by a\nman like Stubb, or almost any other", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1812, "position": 1812, "text": "precisely means when used by a\nman like Stubb, or almost any other whale hunter.\n\nStarbuck was no crusader after perils; in him courage was not a\nsentiment; but a thing simply useful to him, and always at hand upon\nall mortally", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1813, "position": 1813, "text": "but a thing simply useful to him, and always at hand upon\nall mortally practical occasions. Besides, he thought, perhaps, that in\nthis business of whaling, courage was one of the great staple outfits\nof the ship, like her beef and her bread", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1814, "position": 1814, "text": "of the great staple outfits\nof the ship, like her beef and her bread, and not to be foolishly\nwasted. Wherefore he had no fancy for lowering for whales after\nsun-down; nor for persisting in fighting a fish that too", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1815, "position": 1815, "text": "after\nsun-down; nor for persisting in fighting a fish that too much persisted\nin fighting him. For, thought Starbuck, I am here in this critical\nocean to kill whales for my living, and not to be killed by them for\ntheirs", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1816, "position": 1816, "text": "kill whales for my living, and not to be killed by them for\ntheirs; and that hundreds of men had been so killed Starbuck well knew.\nWhat doom was his own father’s? Where, in the bottomless deeps, could\nhe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1817, "position": 1817, "text": "father’s? Where, in the bottomless deeps, could\nhe find the torn limbs of his brother?\n\nWith memories like these in him, and, moreover, given to a certain\nsuperstitiousness, as has been said; the courage", "labels": {"50": 1, "100": 80, "250": 39, "500": 497, "1000": 623, "2000": 1952}}, {"id": 1818, "position": 1818, "text": "to a certain\nsuperstitiousness, as has been said; the courage of this Starbuck which\ncould, nevertheless, still flourish, must indeed have been extreme. But\nit was not in reasonable nature that a man so organized, and with such\nterrible", "labels": {"50": 45, "100": 64, "250": 138, "500": 29, "1000": 343, "2000": 958}}, {"id": 1819, "position": 1819, "text": "was not in reasonable nature that a man so organized, and with such\nterrible experiences and remembrances as he had; it was not in nature\nthat these things should fail in latently engendering an element in\nhim, which, under suitable circumstances,", "labels": {"50": 10, "100": 71, "250": 88, "500": 236, "1000": 368, "2000": 710}}, {"id": 1820, "position": 1820, "text": "ntly engendering an element in\nhim, which, under suitable circumstances, would break out from its\nconfinement, and burn all his courage up. And brave as he might be, it\nwas that sort of bravery chiefly, visible in some intrepid", "labels": {"50": 17, "100": 60, "250": 217, "500": 252, "1000": 712, "2000": 813}}, {"id": 1821, "position": 1821, "text": ", it\nwas that sort of bravery chiefly, visible in some intrepid men, which,\nwhile generally abiding firm in the conflict with seas, or winds, or\nwhales, or any of the ordinary irrational horrors of the world, yet\ncannot", "labels": {"50": 44, "100": 37, "250": 143, "500": 29, "1000": 448, "2000": 825}}, {"id": 1822, "position": 1822, "text": "whales, or any of the ordinary irrational horrors of the world, yet\ncannot withstand those more terrific, because more spiritual terrors,\nwhich sometimes menace you from the concentrating brow of an enraged\nand mighty man.", "labels": {"50": 10, "100": 75, "250": 13, "500": 482, "1000": 15, "2000": 1620}}, {"id": 1823, "position": 1823, "text": "an enraged\nand mighty man.\n\nBut were the coming narrative to reveal in any instance, the complete\nabasement of poor Starbuck’s fortitude, scarce might I have the heart\nto write it; for it is a thing most sorrowful,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1824, "position": 1824, "text": "the heart\nto write it; for it is a thing most sorrowful, nay shocking, to expose\nthe fall of valour in the soul. Men may seem detestable as joint\nstock-companies and nations; knaves, fools, and murderers", "labels": {"50": 9, "100": 73, "250": 193, "500": 19, "1000": 499, "2000": 629}}, {"id": 1825, "position": 1825, "text": "as joint\nstock-companies and nations; knaves, fools, and murderers there may be;\nmen may have mean and meagre faces; but man, in the ideal, is so noble\nand so sparkling, such a grand and glowing creature,", "labels": {"50": 31, "100": 75, "250": 106, "500": 307, "1000": 343, "2000": 1886}}, {"id": 1826, "position": 1826, "text": ", is so noble\nand so sparkling, such a grand and glowing creature, that over any\nignominious blemish in him all his fellows should run to throw their\ncostliest robes. That immaculate manliness we feel within ourselves, so\nfar", "labels": {"50": 31, "100": 75, "250": 69, "500": 307, "1000": 343, "2000": 962}}, {"id": 1827, "position": 1827, "text": "costliest robes. That immaculate manliness we feel within ourselves, so\nfar within us, that it remains intact though all the outer character\nseem gone; bleeds with keenest anguish at the undraped spectacle of a\nvalor-ruined man", "labels": {"50": 31, "100": 75, "250": 13, "500": 414, "1000": 15, "2000": 970}}, {"id": 1828, "position": 1828, "text": "anguish at the undraped spectacle of a\nvalor-ruined man. Nor can piety itself, at such a shameful sight,\ncompletely stifle her upbraidings against the permitting stars", "labels": {"50": 17, "100": 40, "250": 146, "500": 369, "1000": 355, "2000": 1394}}, {"id": 1829, "position": 1829, "text": "ngs against the permitting stars. But\nthis august dignity I treat of, is not the dignity of kings and robes,\nbut that abounding dignity which has no robed investiture. Thou shalt\nsee it shining in the arm that wi", "labels": {"50": 9, "100": 26, "250": 141, "500": 365, "1000": 859, "2000": 1307}}, {"id": 1830, "position": 1830, "text": "investiture. Thou shalt\nsee it shining in the arm that wields a pick or drives a spike; that\ndemocratic dignity which, on all hands, radiates without end from God;\nHimself! The great God absolute! The centre", "labels": {"50": 9, "100": 26, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 1831, "position": 1831, "text": "tes without end from God;\nHimself! The great God absolute! The centre and circumference of all\ndemocracy! His omnipresence, our divine equality!\n\nIf, then, to meanest mariners, and renegades and castaways", "labels": {"50": 9, "100": 73, "250": 133, "500": 232, "1000": 343, "2000": 761}}, {"id": 1832, "position": 1832, "text": ", then, to meanest mariners, and renegades and castaways, I shall\nhereafter ascribe high qualities, though dark; weave round them tragic\ngraces; if even the most mournful, perchance the most aba", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 1177}}, {"id": 1833, "position": 1833, "text": "s; if even the most mournful, perchance the most abased, among\nthem all, shall at times lift himself to the exalted mounts; if I shall\ntouch that workman’s arm with some ethereal light; if", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 709}}, {"id": 1834, "position": 1834, "text": "shall\ntouch that workman’s arm with some ethereal light; if I shall spread a\nrainbow over his disastrous set of sun; then against all mortal critics\nbear me out in it, thou just Spirit of Equality, which hast spread one\nroyal", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 193}}, {"id": 1835, "position": 1835, "text": "in it, thou just Spirit of Equality, which hast spread one\nroyal mantle of humanity over all my kind! Bear me out in it, thou\ngreat democratic God! who didst not refuse to the swart convict,\nBunyan, the pale", "labels": {"50": 9, "100": 75, "250": 120, "500": 307, "1000": 343, "2000": 761}}, {"id": 1836, "position": 1836, "text": "didst not refuse to the swart convict,\nBunyan, the pale, poetic pearl; Thou who didst clothe with doubly\nhammered leaves of finest gold, the stumped and paupered arm of old\nCervantes; Thou", "labels": {"50": 9, "100": 26, "250": 180, "500": 18, "1000": 709, "2000": 1237}}, {"id": 1837, "position": 1837, "text": "the stumped and paupered arm of old\nCervantes; Thou who didst pick up Andrew Jackson from the pebbles; who\ndidst hurl him upon a war-horse; who didst thunder him higher than a\nthrone! Thou who", "labels": {"50": 18, "100": 15, "250": 180, "500": 18, "1000": 709, "2000": 805}}, {"id": 1838, "position": 1838, "text": "-horse; who didst thunder him higher than a\nthrone! Thou who, in all Thy mighty, earthly marchings, ever cullest\nThy selectest champions from the kingly commons; bear me out in it, O\nGod!\n\n\nCHAPTER 27", "labels": {"50": 9, "100": 26, "250": 240, "500": 487, "1000": 63, "2000": 111}}, {"id": 1839, "position": 1839, "text": "kingly commons; bear me out in it, O\nGod!\n\n\nCHAPTER 27. Knights and Squires.\n\nStubb was the second mate. He was a native of Cape Cod; and hence,\naccording to local usage, was called a Cape-Cod", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1584}}, {"id": 1840, "position": 1840, "text": "; and hence,\naccording to local usage, was called a Cape-Cod-man. A happy-go-lucky;\nneither craven nor valiant; taking perils as they came with an\nindifferent air; and while engaged in the most imminent crisis of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1841, "position": 1841, "text": "came with an\nindifferent air; and while engaged in the most imminent crisis of the\nchase, toiling away, calm and collected as a journeyman joiner engaged\nfor the year. Good-humored, easy, and careless, he presided over his", "labels": {"50": 37, "100": 6, "250": 47, "500": 39, "1000": 541, "2000": 1593}}, {"id": 1842, "position": 1842, "text": ". Good-humored, easy, and careless, he presided over his\nwhale-boat as if the most deadly encounter were but a dinner, and his\ncrew all invited guests. He was as particular about the comfortable\narrangement of his part of the boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1843, "position": 1843, "text": ". He was as particular about the comfortable\narrangement of his part of the boat, as an old stage-driver is about\nthe snugness of his box. When close to the whale, in the very\ndeath-lock of the fight, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1844, "position": 1844, "text": "to the whale, in the very\ndeath-lock of the fight, he handled his unpitying lance coolly and\noff-handedly, as a whistling tinker his hammer. He would hum over his\nold rigadig tunes while flank and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1845, "position": 1845, "text": "hammer. He would hum over his\nold rigadig tunes while flank and flank with the most exasperated\nmonster. Long usage had, for this Stubb, converted the jaws of death\ninto an easy chair. What he thought of death itself, there is", "labels": {"50": 37, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 1846, "position": 1846, "text": "death\ninto an easy chair. What he thought of death itself, there is no\ntelling. Whether he ever thought of it at all, might be a question;\nbut, if he ever did chance to cast his mind that way after a\ncomfortable dinner,", "labels": {"50": 0, "100": 91, "250": 229, "500": 481, "1000": 32, "2000": 1469}}, {"id": 1847, "position": 1847, "text": "he ever did chance to cast his mind that way after a\ncomfortable dinner, no doubt, like a good sailor, he took it to be a\nsort of call of the watch to tumble aloft, and bestir themselves there,\nabout something which he", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1848, "position": 1848, "text": "to tumble aloft, and bestir themselves there,\nabout something which he would find out when he obeyed the order, and\nnot sooner.\n\nWhat, perhaps, with other things, made Stubb such an easy-going,\nunfearing man,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1849, "position": 1849, "text": ", made Stubb such an easy-going,\nunfearing man, so cheerily trudging off with the burden of life in a\nworld full of grave pedlars, all bowed to the ground with their packs;\nwhat helped to bring", "labels": {"50": 31, "100": 64, "250": 193, "500": 72, "1000": 531, "2000": 1620}}, {"id": 1850, "position": 1850, "text": "ars, all bowed to the ground with their packs;\nwhat helped to bring about that almost impious good-humor of his; that\nthing must have been his pipe. For, like his nose, his short, black\nlittle pipe was one of the", "labels": {"50": 17, "100": 68, "250": 193, "500": 202, "1000": 858, "2000": 1993}}, {"id": 1851, "position": 1851, "text": ", like his nose, his short, black\nlittle pipe was one of the regular features of his face. You would\nalmost as soon have expected him to turn out of his bunk without his\nnose as without his pipe", "labels": {"50": 45, "100": 64, "250": 70, "500": 202, "1000": 851, "2000": 110}}, {"id": 1852, "position": 1852, "text": "without his\nnose as without his pipe. He kept a whole row of pipes there ready\nloaded, stuck in a rack, within easy reach of his hand; and, whenever\nhe turned in, he smoked them all out in succession, lighting one from\nthe", "labels": {"50": 41, "100": 88, "250": 219, "500": 202, "1000": 59, "2000": 110}}, {"id": 1853, "position": 1853, "text": "turned in, he smoked them all out in succession, lighting one from\nthe other to the end of the chapter; then loading them again to be in\nreadiness anew. For, when Stubb dressed, instead of first putting his\nlegs into his tr", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1854, "position": 1854, "text": ", when Stubb dressed, instead of first putting his\nlegs into his trowsers, he put his pipe into his mouth.\n\nI say this continual smoking must have been one cause, at least, of his\npeculiar disposition; for every one knows that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1855, "position": 1855, "text": "cause, at least, of his\npeculiar disposition; for every one knows that this earthly air,\nwhether ashore or afloat, is terribly infected with the nameless\nmiseries of the numberless mortals who have died exhaling it; and as in\ntime", "labels": {"50": 31, "100": 75, "250": 138, "500": 73, "1000": 448, "2000": 1620}}, {"id": 1856, "position": 1856, "text": "the numberless mortals who have died exhaling it; and as in\ntime of the cholera, some people go about with a camphorated\nhandkerchief to their mouths; so, likewise, against all mortal\ntribulations, Stubb’s tobacco smoke", "labels": {"50": 31, "100": 7, "250": 155, "500": 80, "1000": 117, "2000": 809}}, {"id": 1857, "position": 1857, "text": "likewise, against all mortal\ntribulations, Stubb’s tobacco smoke might have operated as a sort of\ndisinfecting agent.\n\nThe third mate was Flask, a native of Tisbury, in Martha’s Vineyard", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1858, "position": 1858, "text": "a native of Tisbury, in Martha’s Vineyard. A\nshort, stout, ruddy young fellow, very pugnacious concerning whales,\nwho somehow seemed to think that the great leviathans had personally\nand hereditarily affronted", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1859, "position": 1859, "text": "the great leviathans had personally\nand hereditarily affronted him; and therefore it was a sort of point of\nhonor with him, to destroy them whenever encountered. So utterly lost\nwas he to all sense of reverence for the many", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1860, "position": 1860, "text": ". So utterly lost\nwas he to all sense of reverence for the many marvels of their majestic\nbulk and mystic ways; and so dead to anything like an apprehension of\nany possible danger from encountering them; that in his poor opinion,\nthe won", "labels": {"50": 10, "100": 66, "250": 211, "500": 111, "1000": 448, "2000": 825}}, {"id": 1861, "position": 1861, "text": "possible danger from encountering them; that in his poor opinion,\nthe wondrous whale was but a species of magnified mouse, or at least\nwater-rat, requiring only a little circumvention and some small\napplication of time and", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 1862, "position": 1862, "text": "only a little circumvention and some small\napplication of time and trouble in order to kill and boil. This\nignorant, unconscious fearlessness of his made him a little waggish in\nthe matter of whales; he followed these fish for the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 1863, "position": 1863, "text": "waggish in\nthe matter of whales; he followed these fish for the fun of it; and a\nthree years’ voyage round Cape Horn was only a jolly joke that lasted\nthat length of time. As a carpenter’s nails are divided into wrought", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1864, "position": 1864, "text": "that length of time. As a carpenter’s nails are divided into wrought\nnails and cut nails; so mankind may be similarly divided. Little Flask\nwas one of the wrought ones; made to clinch tight and last long", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 678, "2000": 694}}, {"id": 1865, "position": 1865, "text": "ones; made to clinch tight and last long. They\ncalled him King-Post on board of the Pequod; because, in form, he could\nbe well likened to the short, square timber known by that name in\nArctic whalers; and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1866, "position": 1866, "text": "the short, square timber known by that name in\nArctic whalers; and which by the means of many radiating side timbers\ninserted into it, serves to brace the ship against the icy concussions\nof those battering seas.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1867, "position": 1867, "text": "icy concussions\nof those battering seas.\n\nNow these three mates—Starbuck, Stubb, and Flask, were momentous men.\nThey it was who by universal prescription commanded three of the\nPequod’s boats as headsmen", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1868, "position": 1868, "text": "prescription commanded three of the\nPequod’s boats as headsmen. In that grand order of battle in which\nCaptain Ahab would probably marshal his forces to descend on the\nwhales, these three headsmen were as captains of companies", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1869, "position": 1869, "text": "whales, these three headsmen were as captains of companies. Or, being\narmed with their long keen whaling spears, they were as a picked trio\nof lancers; even as the harpooneers were flingers of javelins.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1870, "position": 1870, "text": "the harpooneers were flingers of javelins.\n\nAnd since in this famous fishery, each mate or headsman, like a Gothic\nKnight of old, is always accompanied by his boat-steerer or harpooneer,\nwho in certain conjun", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1871, "position": 1871, "text": "his boat-steerer or harpooneer,\nwho in certain conjunctures provides him with a fresh lance, when the\nformer one has been badly twisted, or elbowed in the assault; and\nmoreover, as there generally subsists between", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1872, "position": 1872, "text": "ed in the assault; and\nmoreover, as there generally subsists between the two, a close intimacy\nand friendliness; it is therefore but meet, that in this place we set\ndown who the Pequod’s harpooneers were,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1873, "position": 1873, "text": "we set\ndown who the Pequod’s harpooneers were, and to what headsman each of\nthem belonged.\n\nFirst of all was Queequeg, whom Starbuck, the chief mate, had selected\nfor his squire", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1874, "position": 1874, "text": "Starbuck, the chief mate, had selected\nfor his squire. But Queequeg is already known.\n\nNext was Tashtego, an unmixed Indian from Gay Head, the most westerly\npromontory of Martha’s Vineyard", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 257, "2000": 156}}, {"id": 1875, "position": 1875, "text": "Gay Head, the most westerly\npromontory of Martha’s Vineyard, where there still exists the last\nremnant of a village of red men, which has long supplied the\nneighboring island of Nantucket with many of her most daring\nharpooneers", "labels": {"50": 45, "100": 38, "250": 138, "500": 72, "1000": 995, "2000": 47}}, {"id": 1876, "position": 1876, "text": "neighboring island of Nantucket with many of her most daring\nharpooneers. In the fishery, they usually go by the generic name of\nGay-Headers. Tashtego’s long, lean, sable hair, his high cheek bones,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1877, "position": 1877, "text": "go’s long, lean, sable hair, his high cheek bones,\nand black rounding eyes—for an Indian, Oriental in their largeness, but\nAntarctic in their glittering expression—all this sufficiently\nproclaimed him an inheritor of the unvitia", "labels": {"50": 22, "100": 55, "250": 229, "500": 389, "1000": 195, "2000": 783}}, {"id": 1878, "position": 1878, "text": "expression—all this sufficiently\nproclaimed him an inheritor of the unvitiated blood of those proud\nwarrior hunters, who, in quest of the great New England moose, had\nscoured, bow in hand, the aboriginal forests of the main", "labels": {"50": 12, "100": 38, "250": 65, "500": 43, "1000": 965, "2000": 624}}, {"id": 1879, "position": 1879, "text": "scoured, bow in hand, the aboriginal forests of the main. But no longer\nsnuffing in the trail of the wild beasts of the woodland, Tashtego now\nhunted in the wake of the great whales of the sea; the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1880, "position": 1880, "text": "go now\nhunted in the wake of the great whales of the sea; the unerring harpoon\nof the son fitly replacing the infallible arrow of the sires. To look\nat the tawny brawn of his lithe snaky", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 1881, "position": 1881, "text": "To look\nat the tawny brawn of his lithe snaky limbs, you would almost have\ncredited the superstitions of some of the earlier Puritans, and\nhalf-believed this wild Indian to be a son of the Prince of", "labels": {"50": 44, "100": 37, "250": 70, "500": 178, "1000": 316, "2000": 1563}}, {"id": 1882, "position": 1882, "text": "and\nhalf-believed this wild Indian to be a son of the Prince of the Powers\nof the Air. Tashtego was Stubb the second mate’s squire.\n\nThird among the harpooneers was Daggoo, a gigantic, coal", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1883, "position": 1883, "text": "Third among the harpooneers was Daggoo, a gigantic, coal-black\nnegro-savage, with a lion-like tread—an Ahasuerus to behold. Suspended\nfrom his ears were two golden hoops, so large that the", "labels": {"50": 45, "100": 64, "250": 30, "500": 475, "1000": 902, "2000": 1620}}, {"id": 1884, "position": 1884, "text": ". Suspended\nfrom his ears were two golden hoops, so large that the sailors called\nthem ring-bolts, and would talk of securing the top-sail halyards to\nthem. In his youth Daggoo had voluntarily shipped on board of a", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 531, "2000": 783}}, {"id": 1885, "position": 1885, "text": "them. In his youth Daggoo had voluntarily shipped on board of a whaler,\nlying in a lonely bay on his native coast. And never having been\nanywhere in the world but in Africa, Nantucket, and the pagan harbors\nmost frequented", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 723, "2000": 1620}}, {"id": 1886, "position": 1886, "text": "world but in Africa, Nantucket, and the pagan harbors\nmost frequented by whalemen; and having now led for many years the bold\nlife of the fishery in the ships of owners uncommonly heedful of what\nmanner of men they shipped;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1887, "position": 1887, "text": "of owners uncommonly heedful of what\nmanner of men they shipped; Daggoo retained all his barbaric virtues,\nand erect as a giraffe, moved about the decks in all the pomp of six\nfeet five in his socks", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 783}}, {"id": 1888, "position": 1888, "text": "about the decks in all the pomp of six\nfeet five in his socks. There was a corporeal humility in looking up at\nhim; and a white man standing before him seemed a white flag come to\nbeg truce of a fortress", "labels": {"50": 45, "100": 64, "250": 163, "500": 494, "1000": 480, "2000": 187}}, {"id": 1889, "position": 1889, "text": "before him seemed a white flag come to\nbeg truce of a fortress. Curious to tell, this imperial negro,\nAhasuerus Daggoo, was the Squire of little Flask, who looked like a\nchess-man beside him", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 967}}, {"id": 1890, "position": 1890, "text": "Flask, who looked like a\nchess-man beside him. As for the residue of the Pequod’s company, be it\nsaid, that at the present day not one in two of the many thousand men\nbefore the mast employed in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1891, "position": 1891, "text": "not one in two of the many thousand men\nbefore the mast employed in the American whale fishery, are Americans\nborn, though pretty nearly all the officers are. Herein it is the same\nwith the American whale fishery as with the American army and military\nand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1892, "position": 1892, "text": "the same\nwith the American whale fishery as with the American army and military\nand merchant navies, and the engineering forces employed in the\nconstruction of the American Canals and Railroads. The same, I say,\nbecause in all these cases the native American liberally", "labels": {"50": 3, "100": 42, "250": 24, "500": 417, "1000": 245, "2000": 447}}, {"id": 1893, "position": 1893, "text": "same, I say,\nbecause in all these cases the native American liberally provides the\nbrains, the rest of the world as generously supplying the muscles. No\nsmall number of these whaling seamen belong to the Azores, where the\noutward bound Nantucket whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1894, "position": 1894, "text": "these whaling seamen belong to the Azores, where the\noutward bound Nantucket whalers frequently touch to augment their crews\nfrom the hardy peasants of those rocky shores. In like manner, the\nGreenland whalers sailing out of Hull or London, put in at", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1895, "position": 1895, "text": ", the\nGreenland whalers sailing out of Hull or London, put in at the Shetland\nIslands, to receive the full complement of their crew. Upon the passage\nhomewards, they drop them there again. How it is, there is no telling,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1896, "position": 1896, "text": "they drop them there again. How it is, there is no telling,\nbut Islanders seem to make the best whalemen. They were nearly all\nIslanders in the Pequod, _Isolatoes_ too, I call such, not\nacknowledging the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1897, "position": 1897, "text": ", _Isolatoes_ too, I call such, not\nacknowledging the common continent of men, but each _Isolato_ living on\na separate continent of his own. Yet now, federated along one keel,\nwhat a set these Iso", "labels": {"50": 10, "100": 2, "250": 54, "500": 246, "1000": 491, "2000": 1345}}, {"id": 1898, "position": 1898, "text": ". Yet now, federated along one keel,\nwhat a set these Isolatoes were! An Anacharsis Clootz deputation from\nall the isles of the sea, and all the ends of the earth, accompanying\nOld Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1899, "position": 1899, "text": "the sea, and all the ends of the earth, accompanying\nOld Ahab in the Pequod to lay the world’s grievances before that bar\nfrom which not very many of them ever come back", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1900, "position": 1900, "text": "very many of them ever come back. Black Little Pip—he\nnever did—oh, no! he went before. Poor Alabama boy! On the grim\nPequod’s forecastle, ye shall ere long see him, beating his tam", "labels": {"50": 41, "100": 64, "250": 163, "500": 72, "1000": 531, "2000": 1620}}, {"id": 1901, "position": 1901, "text": "s forecastle, ye shall ere long see him, beating his tambourine;\nprelusive of the eternal time, when sent for, to the great quarter-deck\non high, he was bid strike in with angels, and beat his", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 779, "2000": 16}}, {"id": 1902, "position": 1902, "text": "deck\non high, he was bid strike in with angels, and beat his tambourine in\nglory; called a coward here, hailed a hero there!\n\n\nCHAPTER 28. Ahab.\n\nFor several days after leaving Nantucket, nothing above hatches was", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1903, "position": 1903, "text": "ab.\n\nFor several days after leaving Nantucket, nothing above hatches was\nseen of Captain Ahab. The mates regularly relieved each other at the\nwatches, and for aught that could be seen to the contrary, they seemed\nto be the only commanders", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1904, "position": 1904, "text": "that could be seen to the contrary, they seemed\nto be the only commanders of the ship; only they sometimes issued from\nthe cabin with orders so sudden and peremptory, that after all it was\nplain they but commanded vicariously", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1905, "position": 1905, "text": "that after all it was\nplain they but commanded vicariously. Yes, their supreme lord and\ndictator was there, though hitherto unseen by any eyes not permitted to\npenetrate into the now sacred retreat of the cabin.", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 1906, "position": 1906, "text": "the now sacred retreat of the cabin.\n\nEvery time I ascended to the deck from my watches below, I instantly\ngazed aft to mark if any strange face were visible; for my first vague\ndisquietude touching the unknown captain, now in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 1907, "position": 1907, "text": "first vague\ndisquietude touching the unknown captain, now in the seclusion of the\nsea, became almost a perturbation. This was strangely heightened at\ntimes by the ragged Elijah’s diabolical incoherences uninvite", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1908, "position": 1908, "text": "the ragged Elijah’s diabolical incoherences uninvitedly\nrecurring to me, with a subtle energy I could not have before conceived\nof. But poorly could I withstand them, much as in other moods I was\nalmost ready to smile", "labels": {"50": 25, "100": 28, "250": 156, "500": 388, "1000": 329, "2000": 381}}, {"id": 1909, "position": 1909, "text": "I withstand them, much as in other moods I was\nalmost ready to smile at the solemn whimsicalities of that outlandish\nprophet of the wharves. But whatever it was of apprehensiveness or\nuneasiness—", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1192}}, {"id": 1910, "position": 1910, "text": "But whatever it was of apprehensiveness or\nuneasiness—to call it so—which I felt, yet whenever I came to look\nabout me in the ship, it seemed against all warrantry to cherish such\nemotions", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1911, "position": 1911, "text": ", it seemed against all warrantry to cherish such\nemotions. For though the harpooneers, with the great body of the crew,\nwere a far more barbaric, heathenish, and motley set than any of the\ntame merchant", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1912, "position": 1912, "text": ", heathenish, and motley set than any of the\ntame merchant-ship companies which my previous experiences had made me\nacquainted with, still I ascribed this—and rightly ascribed it—to the\nfierce uniqueness of the very nature of that", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 1913, "position": 1913, "text": "ly ascribed it—to the\nfierce uniqueness of the very nature of that wild Scandinavian vocation\nin which I had so abandonedly embarked. But it was especially the\naspect of the three chief officers of the ship, the mates, which was\nmost forcibly", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 1914, "position": 1914, "text": "the three chief officers of the ship, the mates, which was\nmost forcibly calculated to allay these colourless misgivings, and\ninduce confidence and cheerfulness in every presentment of the voyage.\nThree better, more likely sea-officers and men", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 1915, "position": 1915, "text": "ment of the voyage.\nThree better, more likely sea-officers and men, each in his own\ndifferent way, could not readily be found, and they were every one of\nthem Americans; a Nantucketer, a Vineyarder, a Cape man", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 1916, "position": 1916, "text": "them Americans; a Nantucketer, a Vineyarder, a Cape man. Now, it being\nChristmas when the ship shot from out her harbor, for a space we had\nbiting Polar weather, though all the time running away from it to the\nsouthward", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 1917, "position": 1917, "text": "biting Polar weather, though all the time running away from it to the\nsouthward; and by every degree and minute of latitude which we sailed,\ngradually leaving that merciless winter, and all its intolerable\nweather behind us", "labels": {"50": 45, "100": 64, "250": 138, "500": 48, "1000": 327, "2000": 1028}}, {"id": 1918, "position": 1918, "text": ", and all its intolerable\nweather behind us. It was one of those less lowering, but still grey\nand gloomy enough mornings of the transition, when with a fair wind the\nship was rushing through the water with a vindictive sort of", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 1919, "position": 1919, "text": "wind the\nship was rushing through the water with a vindictive sort of leaping\nand melancholy rapidity, that as I mounted to the deck at the call of\nthe forenoon watch, so soon as I levelled my glance towards the\ntaff", "labels": {"50": 45, "100": 64, "250": 136, "500": 180, "1000": 272, "2000": 1765}}, {"id": 1920, "position": 1920, "text": "on watch, so soon as I levelled my glance towards the\ntaffrail, foreboding shivers ran over me. Reality outran apprehension;\nCaptain Ahab stood upon his quarter-deck.\n\nThere seemed no sign of common bodily illness about him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1921, "position": 1921, "text": "his quarter-deck.\n\nThere seemed no sign of common bodily illness about him, nor of the\nrecovery from any. He looked like a man cut away from the stake, when\nthe fire has overrunningly wasted all the limbs without consuming them,\nor", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1922, "position": 1922, "text": "the fire has overrunningly wasted all the limbs without consuming them,\nor taking away one particle from their compacted aged robustness. His\nwhole high, broad form, seemed made of solid bronze, and shaped in an\nunalterable mould,", "labels": {"50": 35, "100": 78, "250": 205, "500": 414, "1000": 475, "2000": 1859}}, {"id": 1923, "position": 1923, "text": "made of solid bronze, and shaped in an\nunalterable mould, like Cellini’s cast Perseus. Threading its way out\nfrom among his grey hairs, and continuing right down one side of his\ntawny scorched face", "labels": {"50": 25, "100": 5, "250": 136, "500": 134, "1000": 103, "2000": 453}}, {"id": 1924, "position": 1924, "text": ", and continuing right down one side of his\ntawny scorched face and neck, till it disappeared in his clothing, you\nsaw a slender rod-like mark, lividly whitish. It resembled that\nperpendicular seam sometimes made in the straight,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 1925, "position": 1925, "text": "idly whitish. It resembled that\nperpendicular seam sometimes made in the straight, lofty trunk of a\ngreat tree, when the upper lightning tearingly darts down it, and\nwithout wrenching a single twig, peels and grooves out the bark from", "labels": {"50": 45, "100": 64, "250": 192, "500": 162, "1000": 35, "2000": 1735}}, {"id": 1926, "position": 1926, "text": "wrenching a single twig, peels and grooves out the bark from\ntop to bottom, ere running off into the soil, leaving the tree still\ngreenly alive, but branded. Whether that mark was born with him, or\nwhether it was", "labels": {"50": 31, "100": 94, "250": 132, "500": 265, "1000": 203, "2000": 1050}}, {"id": 1927, "position": 1927, "text": "but branded. Whether that mark was born with him, or\nwhether it was the scar left by some desperate wound, no one could\ncertainly say. By some tacit consent, throughout the voyage little or\nno allusion was made to it, especially by", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 300, "2000": 1014}}, {"id": 1928, "position": 1928, "text": "throughout the voyage little or\nno allusion was made to it, especially by the mates. But once\nTashtego’s senior, an old Gay-Head Indian among the crew,\nsuperstitiously asserted that not till he was full forty", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1929, "position": 1929, "text": "the crew,\nsuperstitiously asserted that not till he was full forty years old did\nAhab become that way branded, and then it came upon him, not in the\nfury of any mortal fray, but in an elemental strife at sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1930, "position": 1930, "text": "fury of any mortal fray, but in an elemental strife at sea. Yet, this\nwild hint seemed inferentially negatived, by what a grey Manxman\ninsinuated, an old sepulchral man, who, having never", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1931, "position": 1931, "text": "inuated, an old sepulchral man, who, having never before sailed out\nof Nantucket, had never ere this laid eye upon wild Ahab. Nevertheless,\nthe old sea-traditions, the immemorial creduli", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1932, "position": 1932, "text": ",\nthe old sea-traditions, the immemorial credulities, popularly invested\nthis old Manxman with preternatural powers of discernment. So that no\nwhite sailor seriously contradicted him when he said that if", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 187}}, {"id": 1933, "position": 1933, "text": "So that no\nwhite sailor seriously contradicted him when he said that if ever\nCaptain Ahab should be tranquilly laid out—which might hardly come to\npass, so he muttered—then, whoever should do that last office for the\ndead,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1934, "position": 1934, "text": "he muttered—then, whoever should do that last office for the\ndead, would find a birth-mark on him from crown to sole.\n\nSo powerfully did the whole grim aspect of Ahab affect me, and the\nlivid brand which streaked it", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 1935, "position": 1935, "text": "aspect of Ahab affect me, and the\nlivid brand which streaked it, that for the first few moments I hardly\nnoted that not a little of this overbearing grimness was owing to the\nbarbaric white leg upon which he partly stood", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1936, "position": 1936, "text": "ness was owing to the\nbarbaric white leg upon which he partly stood. It had previously come\nto me that this ivory leg had at sea been fashioned from the polished\nbone of the sperm whale’s jaw", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1937, "position": 1937, "text": "of the sperm whale’s jaw. “Aye, he was dismasted off Japan,” said\nthe old Gay-Head Indian once; “but like his dismasted craft, he shipped\nanother mast without coming home for it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1938, "position": 1938, "text": "sted craft, he shipped\nanother mast without coming home for it. He has a quiver of ’em.”\n\nI was struck with the singular posture he maintained. Upon each side of\nthe Pequod’s quarter deck, and pretty close to the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1939, "position": 1939, "text": "of\nthe Pequod’s quarter deck, and pretty close to the mizzen shrouds,\nthere was an auger hole, bored about half an inch or so, into the\nplank. His bone leg steadied in that hole", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1940, "position": 1940, "text": "so, into the\nplank. His bone leg steadied in that hole; one arm elevated, and\nholding by a shroud; Captain Ahab stood erect, looking straight out\nbeyond the ship’s ever-pitching prow", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1941, "position": 1941, "text": "out\nbeyond the ship’s ever-pitching prow. There was an infinity of firmest\nfortitude, a determinate, unsurrenderable wilfulness, in the fixed and\nfearless, forward dedication of that glance", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1942, "position": 1942, "text": "the fixed and\nfearless, forward dedication of that glance. Not a word he spoke; nor\ndid his officers say aught to him; though by all their minutest\ngestures and expressions, they plainly showed the uneasy, if not\npainful, consciousness of being", "labels": {"50": 47, "100": 87, "250": 102, "500": 43, "1000": 737, "2000": 819}}, {"id": 1943, "position": 1943, "text": "expressions, they plainly showed the uneasy, if not\npainful, consciousness of being under a troubled master-eye. And not\nonly that, but moody stricken Ahab stood before them with a crucifixion\nin his face; in all the name", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1944, "position": 1944, "text": "with a crucifixion\nin his face; in all the nameless regal overbearing dignity of some\nmighty woe.\n\nEre long, from his first visit in the air, he withdrew into his cabin", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1192}}, {"id": 1945, "position": 1945, "text": "in the air, he withdrew into his cabin.\nBut after that morning, he was every day visible to the crew; either\nstanding in his pivot-hole, or seated upon an ivory stool he had; or\nheavily walking the deck", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1790}}, {"id": 1946, "position": 1946, "text": "upon an ivory stool he had; or\nheavily walking the deck. As the sky grew less gloomy; indeed, began to\ngrow a little genial, he became still less and less a recluse; as if,\nwhen the ship had sailed", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 300, "2000": 1014}}, {"id": 1947, "position": 1947, "text": "and less a recluse; as if,\nwhen the ship had sailed from home, nothing but the dead wintry\nbleakness of the sea had then kept him so secluded. And, by and by, it\ncame to pass, that he was", "labels": {"50": 22, "100": 78, "250": 229, "500": 336, "1000": 252, "2000": 396}}, {"id": 1948, "position": 1948, "text": ". And, by and by, it\ncame to pass, that he was almost continually in the air; but, as yet,\nfor all that he said, or perceptibly did, on the at last sunny deck, he\nseemed as unnecessary", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1949, "position": 1949, "text": "ptibly did, on the at last sunny deck, he\nseemed as unnecessary there as another mast. But the Pequod was only\nmaking a passage now; not regularly cruising; nearly all whaling\npreparatives needing supervision the mates were fully competent to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1950, "position": 1950, "text": "; nearly all whaling\npreparatives needing supervision the mates were fully competent to, so\nthat there was little or nothing, out of himself, to employ or excite\nAhab, now; and thus chase away, for that one interval, the clouds", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1951, "position": 1951, "text": ", now; and thus chase away, for that one interval, the clouds that\nlayer upon layer were piled upon his brow, as ever all clouds choose\nthe loftiest peaks to pile themselves upon.\n\nNevertheless, ere long, the warm, warbling", "labels": {"50": 9, "100": 26, "250": 133, "500": 122, "1000": 437, "2000": 573}}, {"id": 1952, "position": 1952, "text": "pile themselves upon.\n\nNevertheless, ere long, the warm, warbling persuasiveness of the\npleasant, holiday weather we came to, seemed gradually to charm him\nfrom his mood. For, as when the red-cheeked, dancing", "labels": {"50": 16, "100": 20, "250": 53, "500": 276, "1000": 707, "2000": 822}}, {"id": 1953, "position": 1953, "text": "from his mood. For, as when the red-cheeked, dancing girls, April and\nMay, trip home to the wintry, misanthropic woods; even the barest,\nruggedest, most thunder-cloven old oak", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 185, "2000": 523}}, {"id": 1954, "position": 1954, "text": "even the barest,\nruggedest, most thunder-cloven old oak will at least send forth some\nfew green sprouts, to welcome such glad-hearted visitants; so Ahab did,\nin the end, a little respond to the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1955, "position": 1955, "text": "; so Ahab did,\nin the end, a little respond to the playful allurings of that girlish\nair. More than once did he put forth the faint blossom of a look,\nwhich, in any other man, would have soon flower", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1956, "position": 1956, "text": "of a look,\nwhich, in any other man, would have soon flowered out in a smile.\n\n\nCHAPTER 29. Enter Ahab; to Him, Stubb.\n\nSome days elapsed, and ice and icebergs all astern,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1957, "position": 1957, "text": "days elapsed, and ice and icebergs all astern, the Pequod now went\nrolling through the bright Quito spring, which, at sea, almost\nperpetually reigns on the threshold of the eternal August of the\nTropic", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1958, "position": 1958, "text": "perpetually reigns on the threshold of the eternal August of the\nTropic. The warmly cool, clear, ringing, perfumed, overflowing,\nredundant days, were as crystal goblets of Persian sherbet, heaped\nup—", "labels": {"50": 16, "100": 73, "250": 193, "500": 498, "1000": 50, "2000": 1107}}, {"id": 1959, "position": 1959, "text": "as crystal goblets of Persian sherbet, heaped\nup—flaked up, with rose-water snow. The starred and stately nights\nseemed haughty dames in jewelled velvets, nursing at home in lonely\npride", "labels": {"50": 7, "100": 7, "250": 70, "500": 39, "1000": 897, "2000": 1701}}, {"id": 1960, "position": 1960, "text": "y dames in jewelled velvets, nursing at home in lonely\npride, the memory of their absent conquering Earls, the golden helmeted\nsuns! For sleeping man, ’twas hard to choose between such winsome days\nand such sedu", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 118, "2000": 1177}}, {"id": 1961, "position": 1961, "text": "’twas hard to choose between such winsome days\nand such seducing nights. But all the witcheries of that unwaning\nweather did not merely lend new spells and potencies to the outward\nworld", "labels": {"50": 16, "100": 73, "250": 53, "500": 412, "1000": 995, "2000": 913}}, {"id": 1962, "position": 1962, "text": "and potencies to the outward\nworld. Inward they turned upon the soul, especially when the still mild\nhours of eve came on; then, memory shot her crystals as the clear ice\nmost forms of noiseless twilights", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 779, "2000": 16}}, {"id": 1963, "position": 1963, "text": "ice\nmost forms of noiseless twilights. And all these subtle agencies, more\nand more they wrought on Ahab’s texture.\n\nOld age is always wakeful; as if, the longer linked with life, the less\nman has to do with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1964, "position": 1964, "text": "if, the longer linked with life, the less\nman has to do with aught that looks like death. Among sea-commanders,\nthe old greybeards will oftenest leave their berths to visit the\nnight-cloaked deck", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1965, "position": 1965, "text": "leave their berths to visit the\nnight-cloaked deck. It was so with Ahab; only that now, of late, he\nseemed so much to live in the open air, that truly speaking, his visits\nwere more to the cabin,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1966, "position": 1966, "text": "open air, that truly speaking, his visits\nwere more to the cabin, than from the cabin to the planks. “It feels\nlike going down into one’s tomb,”—he would mutter to himself—“for an\nold captain like", "labels": {"50": 23, "100": 88, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 1967, "position": 1967, "text": ",”—he would mutter to himself—“for an\nold captain like me to be descending this narrow scuttle, to go to my\ngrave-dug berth.”\n\nSo, almost every twenty-four hours, when the watches of the night", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1968, "position": 1968, "text": "So, almost every twenty-four hours, when the watches of the night were\nset, and the band on deck sentinelled the slumbers of the band below;\nand when if a rope was to be hauled upon the forecastle, the sailors", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1969, "position": 1969, "text": "when if a rope was to be hauled upon the forecastle, the sailors\nflung it not rudely down, as by day, but with some cautiousness dropt\nit to its place for fear of disturbing their slumbering shipmates; when\nthis", "labels": {"50": 26, "100": 82, "250": 246, "500": 474, "1000": 255, "2000": 398}}, {"id": 1970, "position": 1970, "text": "its place for fear of disturbing their slumbering shipmates; when\nthis sort of steady quietude would begin to prevail, habitually, the\nsilent steersman would watch the cabin-scuttle; and ere long the old\nman", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1971, "position": 1971, "text": "watch the cabin-scuttle; and ere long the old\nman would emerge, gripping at the iron banister, to help his crippled\nway. Some considering touch of humanity was in him; for at times like\nthese, he usually abstained", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1972, "position": 1972, "text": "humanity was in him; for at times like\nthese, he usually abstained from patrolling the quarter-deck; because\nto his wearied mates, seeking repose within six inches of his ivory\nheel, such would have been the reverberating crack", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 1973, "position": 1973, "text": "of his ivory\nheel, such would have been the reverberating crack and din of that bony\nstep, that their dreams would have been on the crunching teeth of\nsharks. But once, the mood was on him too deep for common regardings", "labels": {"50": 37, "100": 64, "250": 163, "500": 389, "1000": 531, "2000": 110}}, {"id": 1974, "position": 1974, "text": ". But once, the mood was on him too deep for common regardings;\nand as with heavy, lumber-like pace he was measuring the ship from\ntaffrail to mainmast, Stubb, the old second mate, came up from", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1975, "position": 1975, "text": "mainmast, Stubb, the old second mate, came up from below,\nwith a certain unassured, deprecating humorousness, hinted that if\nCaptain Ahab was pleased to walk the planks, then, no one could say", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1976, "position": 1976, "text": "ab was pleased to walk the planks, then, no one could say\nnay; but there might be some way of muffling the noise; hinting\nsomething indistinctly and hesitatingly about a globe of tow, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 1977, "position": 1977, "text": "inctly and hesitatingly about a globe of tow, and the\ninsertion into it, of the ivory heel. Ah! Stubb, thou didst not know\nAhab then.\n\n“Am I a cannon-ball, Stubb,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1978, "position": 1978, "text": "Ahab then.\n\n“Am I a cannon-ball, Stubb,” said Ahab, “that thou wouldst wad me that\nfashion? But go thy ways; I had forgot. Below to thy nightly grave;\nwhere such as ye", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1979, "position": 1979, "text": "; I had forgot. Below to thy nightly grave;\nwhere such as ye sleep between shrouds, to use ye to the filling one at\nlast.—Down, dog, and kennel!”", "labels": {"50": 9, "100": 26, "250": 141, "500": 406, "1000": 779, "2000": 1859}}, {"id": 1980, "position": 1980, "text": ", and kennel!”\n\nStarting at the unforseen concluding exclamation of the so suddenly\nscornful old man, Stubb was speechless a moment; then said excitedly,\n“I am not used to be spoken to that way", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 317, "2000": 1087}}, {"id": 1981, "position": 1981, "text": "then said excitedly,\n“I am not used to be spoken to that way, sir; I do but less than half\nlike it, sir.”\n\n“Avast! gritted Ahab between his set teeth, and violently moving away,\nas if to", "labels": {"50": 23, "100": 45, "250": 219, "500": 170, "1000": 317, "2000": 389}}, {"id": 1982, "position": 1982, "text": "Ahab between his set teeth, and violently moving away,\nas if to avoid some passionate temptation.\n\n“No, sir; not yet,” said Stubb, emboldened, “I will not tamely be\ncalled a dog, sir.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1983, "position": 1983, "text": "ened, “I will not tamely be\ncalled a dog, sir.”\n\n“Then be called ten times a donkey, and a mule, and an ass, and begone,\nor I’ll clear the world of thee!”", "labels": {"50": 40, "100": 50, "250": 36, "500": 248, "1000": 817, "2000": 1236}}, {"id": 1984, "position": 1984, "text": "one,\nor I’ll clear the world of thee!”\n\nAs he said this, Ahab advanced upon him with such overbearing terrors\nin his aspect, that Stubb involuntarily retreated.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 1985, "position": 1985, "text": "Stubb involuntarily retreated.\n\n“I was never served so before without giving a hard blow for it,”\nmuttered Stubb, as he found himself descending the cabin-scuttle. “It’s\nvery queer", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 1986, "position": 1986, "text": "cabin-scuttle. “It’s\nvery queer. Stop, Stubb; somehow, now, I don’t well know whether to go\nback and strike him, or—what’s that?—down here on my knees and", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 1987, "position": 1987, "text": ", or—what’s that?—down here on my knees and pray for\nhim? Yes, that was the thought coming up in me; but it would be the\nfirst time I ever _did_ pray", "labels": {"50": 11, "100": 58, "250": 204, "500": 356, "1000": 29, "2000": 108}}, {"id": 1988, "position": 1988, "text": "first time I ever _did_ pray. It’s queer; very queer; and he’s queer\ntoo; aye, take him fore and aft, he’s about the queerest old man Stubb\never sailed with", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 1989, "position": 1989, "text": "about the queerest old man Stubb\never sailed with. How he flashed at me!—his eyes like powder-pans! is\nhe mad? Anyway there’s something on his mind, as sure as there must be\nsomething on a deck", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 1990, "position": 1990, "text": "something on his mind, as sure as there must be\nsomething on a deck when it cracks. He aint in his bed now, either,\nmore than three hours out of the twenty-four; and he don’t sleep then", "labels": {"50": 11, "100": 51, "250": 91, "500": 53, "1000": 798, "2000": 1199}}, {"id": 1991, "position": 1991, "text": "the twenty-four; and he don’t sleep then.\nDidn’t that Dough-Boy, the steward, tell me that of a morning he always\nfinds the old man’s hammock clothes all rumpled and tumbled, and the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 1992, "position": 1992, "text": "man’s hammock clothes all rumpled and tumbled, and the\nsheets down at the foot, and the coverlid almost tied into knots, and\nthe pillow a sort of frightful hot, as though a baked brick had been on\nit?", "labels": {"50": 11, "100": 22, "250": 214, "500": 116, "1000": 416, "2000": 1857}}, {"id": 1993, "position": 1993, "text": "of frightful hot, as though a baked brick had been on\nit? A hot old man! I guess he’s got what some folks ashore call a\nconscience; it’s a kind of Tic-Dolly-row they say—worse", "labels": {"50": 41, "100": 41, "250": 91, "500": 229, "1000": 533, "2000": 1199}}, {"id": 1994, "position": 1994, "text": "’s a kind of Tic-Dolly-row they say—worse nor a\ntoothache. Well, well; I don’t know what it is, but the Lord keep me\nfrom catching it", "labels": {"50": 41, "100": 21, "250": 91, "500": 281, "1000": 333, "2000": 1199}}, {"id": 1995, "position": 1995, "text": "Lord keep me\nfrom catching it. He’s full of riddles; I wonder what he goes into the\nafter hold for, every night, as Dough-Boy tells me he suspects; what’s\nthat for, I should like to know?", "labels": {"50": 6, "100": 1, "250": 42, "500": 180, "1000": 851, "2000": 666}}, {"id": 1996, "position": 1996, "text": "he suspects; what’s\nthat for, I should like to know? Who’s made appointments with him in\nthe hold? Ain’t that queer, now? But there’s no telling, it’s the old\ngame—Here goes", "labels": {"50": 39, "100": 39, "250": 57, "500": 438, "1000": 323, "2000": 51}}, {"id": 1997, "position": 1997, "text": "there’s no telling, it’s the old\ngame—Here goes for a snooze. Damn me, it’s worth a fellow’s while to be\nborn into the world, if only to fall right asleep", "labels": {"50": 11, "100": 41, "250": 91, "500": 229, "1000": 798, "2000": 51}}, {"id": 1998, "position": 1998, "text": "be\nborn into the world, if only to fall right asleep. And now that I think\nof it, that’s about the first thing babies do, and that’s a sort of\nqueer, too", "labels": {"50": 25, "100": 12, "250": 91, "500": 150, "1000": 533, "2000": 234}}, {"id": 1999, "position": 1999, "text": "a sort of\nqueer, too. Damn me, but all things are queer, come to think of ’em.\nBut that’s against my principles. Think not, is my eleventh\ncommandment; and sleep when you can, is my twelfth—", "labels": {"50": 39, "100": 88, "250": 57, "500": 100, "1000": 798, "2000": 51}}, {"id": 2000, "position": 2000, "text": "my eleventh\ncommandment; and sleep when you can, is my twelfth—So here goes again.\nBut how’s that? didn’t he call me a dog? blazes! he called me ten times\na donkey, and piled a lot", "labels": {"50": 41, "100": 41, "250": 91, "500": 180, "1000": 627, "2000": 1199}}, {"id": 2001, "position": 2001, "text": "blazes! he called me ten times\na donkey, and piled a lot of jackasses on top of _that!_ He might as\nwell have kicked me, and done with it. Maybe he _did_ kick me, and I\ndidn", "labels": {"50": 11, "100": 9, "250": 207, "500": 356, "1000": 488, "2000": 157}}, {"id": 2002, "position": 2002, "text": "done with it. Maybe he _did_ kick me, and I\ndidn’t observe it, I was so taken all aback with his brow, somehow. It\nflashed like a bleached bone. What the devil’s the matter with me", "labels": {"50": 25, "100": 41, "250": 183, "500": 407, "1000": 488, "2000": 51}}, {"id": 2003, "position": 2003, "text": "a bleached bone. What the devil’s the matter with me? I\ndon’t stand right on my legs. Coming afoul of that old man has a sort\nof turned me wrong side out", "labels": {"50": 39, "100": 41, "250": 91, "500": 407, "1000": 488, "2000": 51}}, {"id": 2004, "position": 2004, "text": "a sort\nof turned me wrong side out. By the Lord, I must have been dreaming,\nthough—How? how? how?—but the only way’s to stash it; so here goes to\nhammock again; and in", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1620}}, {"id": 2005, "position": 2005, "text": "stash it; so here goes to\nhammock again; and in the morning, I’ll see how this plaguey juggling\nthinks over by daylight.”\n\n\nCHAPTER 30. The Pipe.\n\nWhen Stubb had departed, Ahab stood for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2006, "position": 2006, "text": "30. The Pipe.\n\nWhen Stubb had departed, Ahab stood for a while leaning over the\nbulwarks; and then, as had been usual with him of late, calling a\nsailor of the watch, he sent him below for his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2007, "position": 2007, "text": "late, calling a\nsailor of the watch, he sent him below for his ivory stool, and also\nhis pipe. Lighting the pipe at the binnacle lamp and planting the stool\non the weather side of the deck, he sat and smoked.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 2008, "position": 2008, "text": "stool\non the weather side of the deck, he sat and smoked.\n\nIn old Norse times, the thrones of the sea-loving Danish kings were\nfabricated, saith tradition, of the tusks of the narwhale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1766}}, {"id": 2009, "position": 2009, "text": ", of the tusks of the narwhale. How could\none look at Ahab then, seated on that tripod of bones, without\nbethinking him of the royalty it symbolized? For a Khan of the plank,\nand a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2010, "position": 2010, "text": "the royalty it symbolized? For a Khan of the plank,\nand a king of the sea, and a great lord of Leviathans was Ahab.\n\nSome moments passed, during which the thick vapor came from his mouth\nin quick and constant puff", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2011, "position": 2011, "text": ", during which the thick vapor came from his mouth\nin quick and constant puffs, which blew back again into his face. “How\nnow,” he soliloquized at last, withdrawing the tube, “this smoking no\nlonger soothes", "labels": {"50": 34, "100": 77, "250": 164, "500": 192, "1000": 992, "2000": 491}}, {"id": 2012, "position": 2012, "text": "at last, withdrawing the tube, “this smoking no\nlonger soothes. Oh, my pipe! hard must it go with me if thy charm be\ngone! Here have I been unconsciously toiling, not pleasuring—aye, and\nignorantly", "labels": {"50": 30, "100": 45, "250": 245, "500": 240, "1000": 641, "2000": 1459}}, {"id": 2013, "position": 2013, "text": "been unconsciously toiling, not pleasuring—aye, and\nignorantly smoking to windward all the while; to windward, and with\nsuch nervous whiffs, as if, like the dying whale, my final jets were\nthe strongest and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1620}}, {"id": 2014, "position": 2014, "text": "as if, like the dying whale, my final jets were\nthe strongest and fullest of trouble. What business have I with this\npipe? This thing that is meant for sereneness, to send up mild white\nvapors among mild white hairs, not", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2015, "position": 2015, "text": "ness, to send up mild white\nvapors among mild white hairs, not among torn iron-grey locks like\nmine. I’ll smoke no more—”\n\nHe tossed the still lighted pipe into the sea", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 2016, "position": 2016, "text": "still lighted pipe into the sea. The fire hissed in the\nwaves; the same instant the ship shot by the bubble the sinking pipe\nmade. With slouched hat, Ahab lurchingly paced the planks.\n\n\nCHAPTER 31. Queen Mab.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2017, "position": 2017, "text": "ab lurchingly paced the planks.\n\n\nCHAPTER 31. Queen Mab.\n\nNext morning Stubb accosted Flask.\n\n“Such a queer dream, King-Post, I never had. You know the old man’s\nivory leg, well", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2018, "position": 2018, "text": "I never had. You know the old man’s\nivory leg, well I dreamed he kicked me with it; and when I tried to\nkick back, upon my soul, my little man, I kicked my leg right off! And\nthen, pre", "labels": {"50": 25, "100": 41, "250": 91, "500": 128, "1000": 533, "2000": 1199}}, {"id": 2019, "position": 2019, "text": "my little man, I kicked my leg right off! And\nthen, presto! Ahab seemed a pyramid, and I, like a blazing fool, kept\nkicking at it. But what was still more curious, Flask—you know how\ncurious", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2020, "position": 2020, "text": ". But what was still more curious, Flask—you know how\ncurious all dreams are—through all this rage that I was in, I somehow\nseemed to be thinking to myself, that after all, it was not much of an\ninsult, that", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1254}}, {"id": 2021, "position": 2021, "text": "myself, that after all, it was not much of an\ninsult, that kick from Ahab. ‘Why,’ thinks I, ‘what’s the row? It’s not\na real leg, only a false leg.’ And there", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2022, "position": 2022, "text": "’s not\na real leg, only a false leg.’ And there’s a mighty difference between\na living thump and a dead thump. That’s what makes a blow from the\nhand, Flask, fifty times more savage to bear than", "labels": {"50": 25, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 1620}}, {"id": 2023, "position": 2023, "text": "blow from the\nhand, Flask, fifty times more savage to bear than a blow from a cane.\nThe living member—that makes the living insult, my little man. And\nthinks I to myself all the while, mind, while I was stu", "labels": {"50": 6, "100": 41, "250": 69, "500": 274, "1000": 203, "2000": 1199}}, {"id": 2024, "position": 2024, "text": "And\nthinks I to myself all the while, mind, while I was stubbing my silly\ntoes against that cursed pyramid—so confoundedly contradictory was it\nall, all the while, I say, I was thinking to myself, ‘what’s", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 2025, "position": 2025, "text": "while, I say, I was thinking to myself, ‘what’s his leg\nnow, but a cane—a whalebone cane. Yes,’ thinks I, ‘it was only a\nplayful cudgelling—in fact, only a whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2026, "position": 2026, "text": "it was only a\nplayful cudgelling—in fact, only a whaleboning that he gave me—not a\nbase kick. Besides,’ thinks I, ‘look at it once; why, the end of it—the\nfoot part—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2027, "position": 2027, "text": "at it once; why, the end of it—the\nfoot part—what a small sort of end it is; whereas, if a broad footed\nfarmer kicked me, _there’s_ a devilish broad insult", "labels": {"50": 40, "100": 12, "250": 212, "500": 21, "1000": 690, "2000": 401}}, {"id": 2028, "position": 2028, "text": "there’s_ a devilish broad insult. But this insult is\nwhittled down to a point only.’ But now comes the greatest joke of the\ndream, Flask. While I was battering away at the pyramid, a sort of", "labels": {"50": 17, "100": 16, "250": 87, "500": 182, "1000": 355, "2000": 1961}}, {"id": 2029, "position": 2029, "text": "ask. While I was battering away at the pyramid, a sort of\nbadger-haired old merman, with a hump on his back, takes me by the\nshoulders, and slews me round", "labels": {"50": 25, "100": 5, "250": 136, "500": 388, "1000": 533, "2000": 1521}}, {"id": 2030, "position": 2030, "text": ", and slews me round. ‘What are you ’bout?’ says he. Slid!\nman, but I was frightened. Such a phiz! But, somehow, next moment I was\nover the fright", "labels": {"50": 37, "100": 41, "250": 91, "500": 229, "1000": 494, "2000": 1199}}, {"id": 2031, "position": 2031, "text": "somehow, next moment I was\nover the fright. ‘What am I about?’ says I at last. ‘And what business\nis that of yours, I should like to know, Mr. Humpback? Do _you_ want a\nkick", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 194, "2000": 610}}, {"id": 2032, "position": 2032, "text": "know, Mr. Humpback? Do _you_ want a\nkick?’ By the lord, Flask, I had no sooner said that, than he turned\nround his stern to me, bent over, and dragging up a lot of sea", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 851, "2000": 1620}}, {"id": 2033, "position": 2033, "text": "his stern to me, bent over, and dragging up a lot of seaweed he\nhad for a clout—what do you think, I saw?—why thunder alive, man, his\nstern was stuck full of marlinspikes, with the", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 2034, "position": 2034, "text": ", man, his\nstern was stuck full of marlinspikes, with the points out. Says I, on\nsecond thoughts, ‘I guess I won’t kick you, old fellow.’ ‘Wise Stubb,’\nsaid he, ‘wise", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 2035, "position": 2035, "text": "old fellow.’ ‘Wise Stubb,’\nsaid he, ‘wise Stubb;’ and kept muttering it all the time, a sort of\neating of his own gums like a chimney hag", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 54, "2000": 1620}}, {"id": 2036, "position": 2036, "text": "s like a chimney hag. Seeing he wasn’t going to\nstop saying over his ‘wise Stubb, wise Stubb,’ I thought I might as\nwell fall to kicking the pyramid again. But I had only just lifted my\nfoot for", "labels": {"50": 25, "100": 64, "250": 91, "500": 180, "1000": 54, "2000": 1620}}, {"id": 2037, "position": 2037, "text": "to kicking the pyramid again. But I had only just lifted my\nfoot for it, when he roared out, ‘Stop that kicking!’ ‘Halloa,’ says I,\n‘what’s the matter now, old fellow?’ ‘Look", "labels": {"50": 25, "100": 13, "250": 91, "500": 457, "1000": 533, "2000": 1631}}, {"id": 2038, "position": 2038, "text": ",\n‘what’s the matter now, old fellow?’ ‘Look ye here,’ says he; ‘let’s\nargue the insult. Captain Ahab kicked ye, didn’t he?’ ‘Yes, he did,’\nsays", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 2039, "position": 2039, "text": ", didn’t he?’ ‘Yes, he did,’\nsays I—‘right _here_ it was.’ ‘Very good,’ says he—‘he used his ivory\nleg, didn’t he?’ ‘Yes,", "labels": {"50": 25, "100": 41, "250": 91, "500": 229, "1000": 533, "2000": 1199}}, {"id": 2040, "position": 2040, "text": "he used his ivory\nleg, didn’t he?’ ‘Yes, he did,’ says I. ‘Well then,’ says he, ‘wise\nStubb, what have you to complain of? Didn’t he kick with right good", "labels": {"50": 41, "100": 21, "250": 91, "500": 229, "1000": 494, "2000": 1528}}, {"id": 2041, "position": 2041, "text": "what have you to complain of? Didn’t he kick with right good\nwill? it wasn’t a common pitch pine leg he kicked with, was it? No, you\nwere kicked by a great man, and with a beautiful ivory leg,", "labels": {"50": 39, "100": 99, "250": 91, "500": 305, "1000": 494, "2000": 1468}}, {"id": 2042, "position": 2042, "text": "you\nwere kicked by a great man, and with a beautiful ivory leg, Stubb. It’s\nan honor; I consider it an honor. Listen, wise Stubb. In old England\nthe greatest lords think it great glory to be slapped by", "labels": {"50": 23, "100": 88, "250": 185, "500": 221, "1000": 317, "2000": 51}}, {"id": 2043, "position": 2043, "text": ". In old England\nthe greatest lords think it great glory to be slapped by a queen, and\nmade garter-knights of; but, be _your_ boast, Stubb, that ye were\nkicked by old Ahab, and made a", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 2044, "position": 2044, "text": "Stubb, that ye were\nkicked by old Ahab, and made a wise man of. Remember what I say; _be_\nkicked by him; account his kicks honors; and on no account kick back;\nfor you can’t help yourself", "labels": {"50": 9, "100": 64, "250": 193, "500": 498, "1000": 327, "2000": 1620}}, {"id": 2045, "position": 2045, "text": "; and on no account kick back;\nfor you can’t help yourself, wise Stubb. Don’t you see that pyramid?’\nWith that, he all of a sudden seemed somehow, in some queer fashion, to\nswim off into the", "labels": {"50": 40, "100": 24, "250": 16, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2046, "position": 2046, "text": "a sudden seemed somehow, in some queer fashion, to\nswim off into the air. I snored; rolled over; and there I was in my\nhammock! Now, what do you think of that dream, Flask?”", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 2047, "position": 2047, "text": "Now, what do you think of that dream, Flask?”\n\n“I don’t know; it seems a sort of foolish to me, tho.’”\n\n“May be; may be. But it’s made a wise man of", "labels": {"50": 25, "100": 41, "250": 219, "500": 180, "1000": 345, "2000": 1199}}, {"id": 2048, "position": 2048, "text": "May be; may be. But it’s made a wise man of me, Flask. D’ye see Ahab\nstanding there, sideways looking over the stern? Well, the best thing\nyou can do, Flask, is to let", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2049, "position": 2049, "text": "Well, the best thing\nyou can do, Flask, is to let the old man alone; never speak to him,\nwhatever he says. Halloa! What’s that he shouts? Hark!”", "labels": {"50": 40, "100": 77, "250": 205, "500": 437, "1000": 345, "2000": 1947}}, {"id": 2050, "position": 2050, "text": "that he shouts? Hark!”\n\n“Mast-head, there! Look sharp, all of ye! There are whales hereabouts!\n\n“If ye see a white one, split your lungs for him!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2051, "position": 2051, "text": "one, split your lungs for him!\n\n“What do you think of that now, Flask? ain’t there a small drop of\nsomething queer about that, eh? A white whale—did ye mark that, man?\nLook ye—there", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2052, "position": 2052, "text": "A white whale—did ye mark that, man?\nLook ye—there’s something special in the wind. Stand by for it, Flask.\nAhab has that that’s bloody on his mind", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2053, "position": 2053, "text": "that’s bloody on his mind. But, mum; he comes this way.”\n\n\nCHAPTER 32. Cetology.\n\nAlready we are boldly launched upon the deep; but soon we shall be lost\nin its unshored, harbourless immen", "labels": {"50": 48, "100": 7, "250": 59, "500": 19, "1000": 499, "2000": 629}}, {"id": 2054, "position": 2054, "text": "soon we shall be lost\nin its unshored, harbourless immensities. Ere that come to pass; ere\nthe Pequod’s weedy hull rolls side by side with the barnacled hulls of\nthe leviathan", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2055, "position": 2055, "text": "rolls side by side with the barnacled hulls of\nthe leviathan; at the outset it is but well to attend to a matter\nalmost indispensable to a thorough appreciative understanding of the\nmore special leviathanic revelations and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2056, "position": 2056, "text": "thorough appreciative understanding of the\nmore special leviathanic revelations and allusions of all sorts which\nare to follow.\n\nIt is some systematized exhibition of the whale in his broad genera,\nthat I would now fain put before you", "labels": {"50": 3, "100": 85, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2057, "position": 2057, "text": "in his broad genera,\nthat I would now fain put before you. Yet is it no easy task. The\nclassification of the constituents of a chaos, nothing less is here\nessayed. Listen to what the best and latest authorities have laid down.", "labels": {"50": 10, "100": 75, "250": 232, "500": 273, "1000": 122, "2000": 712}}, {"id": 2058, "position": 2058, "text": "essayed. Listen to what the best and latest authorities have laid down.\n\n“No branch of Zoology is so much involved as that which is entitled\nCetology,” says Captain Scoresby, A.D. 1820.", "labels": {"50": 44, "100": 85, "250": 165, "500": 486, "1000": 956, "2000": 952}}, {"id": 2059, "position": 2059, "text": "Scoresby, A.D. 1820.\n\n“It is not my intention, were it in my power, to enter into the inquiry\nas to the true method of dividing the cetacea into groups and families", "labels": {"50": 45, "100": 29, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2060, "position": 2060, "text": "cetacea into groups and families.\n* * * Utter confusion exists among the historians of this animal”\n(sperm whale), says Surgeon Beale, A.D. 1839.\n\n“Unfitness to pursue our research in the unfathomable waters", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2061, "position": 2061, "text": ".\n\n“Unfitness to pursue our research in the unfathomable waters.”\n“Impenetrable veil covering our knowledge of the cetacea.” “A field\nstrewn with thorns.” “All these incomplete indications but serve to\ntorture", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 631}}, {"id": 2062, "position": 2062, "text": "field\nstrewn with thorns.” “All these incomplete indications but serve to\ntorture us naturalists.”\n\nThus speak of the whale, the great Cuvier, and John Hunter, and Lesson,\nthose lights of zoology and anatomy", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2063, "position": 2063, "text": "and Lesson,\nthose lights of zoology and anatomy. Nevertheless, though of real\nknowledge there be little, yet of books there are a plenty; and so in\nsome small degree, with cetology, or the science of whales", "labels": {"50": 10, "100": 75, "250": 106, "500": 288, "1000": 134, "2000": 1986}}, {"id": 2064, "position": 2064, "text": "with cetology, or the science of whales. Many are\nthe men, small and great, old and new, landsmen and seamen, who have at\nlarge or in little, written of the whale. Run over a few:—The Authors\nof", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2065, "position": 2065, "text": ", written of the whale. Run over a few:—The Authors\nof the Bible; Aristotle; Pliny; Aldrovandi; Sir Thomas Browne; Gesner;\nRay; Linnæus; Rondeletius; Willoughby; Green", "labels": {"50": 10, "100": 66, "250": 111, "500": 32, "1000": 630, "2000": 1620}}, {"id": 2066, "position": 2066, "text": "Ray; Linnæus; Rondeletius; Willoughby; Green; Artedi; Sibbald; Brisson;\nMarten; Lacépède; Bonneterre; Desmarest; Baron Cuvier; Frederick\nCuvier; John Hunter", "labels": {"50": 17, "100": 98, "250": 96, "500": 179, "1000": 188, "2000": 1796}}, {"id": 2067, "position": 2067, "text": "; Desmarest; Baron Cuvier; Frederick\nCuvier; John Hunter; Owen; Scoresby; Beale; Bennett; J. Ross Browne;\nthe Author of Miriam Coffin; Olmstead; and the Rev. T. Cheever", "labels": {"50": 15, "100": 36, "250": 108, "500": 448, "1000": 828, "2000": 1906}}, {"id": 2068, "position": 2068, "text": "; Olmstead; and the Rev. T. Cheever. But to\nwhat ultimate generalizing purpose all these have written, the above\ncited extracts will show.\n\nOf the names in this list of whale authors, only those following Owen\never saw living", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 622, "2000": 1620}}, {"id": 2069, "position": 2069, "text": "names in this list of whale authors, only those following Owen\never saw living whales; and but one of them was a real professional\nharpooneer and whaleman. I mean Captain Scoresby. On the separate\nsubject of the Greenland or right-whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2070, "position": 2070, "text": "Captain Scoresby. On the separate\nsubject of the Greenland or right-whale, he is the best existing\nauthority. But Scoresby knew nothing and says nothing of the great\nsperm whale, compared with which the Greenland whale is almost unworthy\nmentioning", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2071, "position": 2071, "text": "whale, compared with which the Greenland whale is almost unworthy\nmentioning. And here be it said, that the Greenland whale is an usurper\nupon the throne of the seas. He is not even by any means the largest of\nthe whales", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2072, "position": 2072, "text": ". He is not even by any means the largest of\nthe whales. Yet, owing to the long priority of his claims, and the\nprofound ignorance which, till some seventy years back, invested the\nthen fabulous or utterly unknown sperm-whale, and which", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2073, "position": 2073, "text": "back, invested the\nthen fabulous or utterly unknown sperm-whale, and which ignorance to\nthis present day still reigns in all but some few scientific retreats\nand whale-ports; this usurpation has been every way complete", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2074, "position": 2074, "text": "this usurpation has been every way complete. Reference\nto nearly all the leviathanic allusions in the great poets of past\ndays, will satisfy you that the Greenland whale, without one rival, was\nto them the monarch of the seas", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2075, "position": 2075, "text": "whale, without one rival, was\nto them the monarch of the seas. But the time has at last come for a\nnew proclamation. This is Charing Cross; hear ye! good people all,—the\nGreenland whale is deposed,—the great", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2076, "position": 2076, "text": "! good people all,—the\nGreenland whale is deposed,—the great sperm whale now reigneth!\n\nThere are only two books in being which at all pretend to put the\nliving sperm whale before you, and at the same time, in the remote", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2077, "position": 2077, "text": "living sperm whale before you, and at the same time, in the remotest\ndegree succeed in the attempt. Those books are Beale’s and Bennett’s;\nboth in their time surgeons to English South-Sea whale-ships, and both\nexact", "labels": {"50": 31, "100": 85, "250": 14, "500": 72, "1000": 134, "2000": 1620}}, {"id": 2078, "position": 2078, "text": "their time surgeons to English South-Sea whale-ships, and both\nexact and reliable men. The original matter touching the sperm whale to\nbe found in their volumes is necessarily small; but so far as it goes,\nit is of excellent quality, though", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2079, "position": 2079, "text": "; but so far as it goes,\nit is of excellent quality, though mostly confined to scientific\ndescription. As yet, however, the sperm whale, scientific or poetic,\nlives not complete in any literature. Far above all other hunted\nwhales, his is", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2080, "position": 2080, "text": "not complete in any literature. Far above all other hunted\nwhales, his is an unwritten life.\n\nNow the various species of whales need some sort of popular\ncomprehensive classification, if only an easy outline one for the\npresent, hereafter to be filled", "labels": {"50": 45, "100": 85, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2081, "position": 2081, "text": "only an easy outline one for the\npresent, hereafter to be filled in all its departments by subsequent\nlaborers. As no better man advances to take this matter in hand, I\nhereupon offer my own poor endeavors", "labels": {"50": 21, "100": 95, "250": 76, "500": 455, "1000": 134, "2000": 1280}}, {"id": 2082, "position": 2082, "text": "I\nhereupon offer my own poor endeavors. I promise nothing complete;\nbecause any human thing supposed to be complete, must for that very\nreason infallibly be faulty. I shall not pretend to a minute anatomical\ndescription of the various species, or", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 134, "2000": 458}}, {"id": 2083, "position": 2083, "text": "I shall not pretend to a minute anatomical\ndescription of the various species, or—in this place at least—to much\nof any description. My object here is simply to project the draught of\na systematization of cetology", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 634, "2000": 313}}, {"id": 2084, "position": 2084, "text": "the draught of\na systematization of cetology. I am the architect, not the builder.\n\nBut it is a ponderous task; no ordinary letter-sorter in the\nPost-Office is equal to it", "labels": {"50": 31, "100": 7, "250": 132, "500": 453, "1000": 27, "2000": 1037}}, {"id": 2085, "position": 2085, "text": "the\nPost-Office is equal to it. To grope down into the bottom of the sea\nafter them; to have one’s hands among the unspeakable foundations,\nribs, and very pelvis of the world; this is a fearful", "labels": {"50": 48, "100": 20, "250": 90, "500": 162, "1000": 260, "2000": 682}}, {"id": 2086, "position": 2086, "text": ",\nribs, and very pelvis of the world; this is a fearful thing. What am I\nthat I should essay to hook the nose of this leviathan! The awful\ntauntings in Job might well appal me", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 50, "2000": 1859}}, {"id": 2087, "position": 2087, "text": "tauntings in Job might well appal me. Will he (the leviathan) make a\ncovenant with thee? Behold the hope of him is vain! But I have swam\nthrough libraries and sailed through oceans; I have had to do with\nwhales with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2088, "position": 2088, "text": "through libraries and sailed through oceans; I have had to do with\nwhales with these visible hands; I am in earnest; and I will try. There\nare some preliminaries to settle.\n\nFirst: The uncertain, unsettled condition of this", "labels": {"50": 31, "100": 14, "250": 132, "500": 307, "1000": 27, "2000": 761}}, {"id": 2089, "position": 2089, "text": "ries to settle.\n\nFirst: The uncertain, unsettled condition of this science of Cetology\nis in the very vestibule attested by the fact, that in some quarters it\nstill remains a moot point whether a whale be a fish", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 2090, "position": 2090, "text": "it\nstill remains a moot point whether a whale be a fish. In his System of\nNature, A.D. 1776, Linnæus declares, “I hereby separate the whales from\nthe fish.” But of my own knowledge,", "labels": {"50": 3, "100": 85, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2091, "position": 2091, "text": "by separate the whales from\nthe fish.” But of my own knowledge, I know that down to the year 1850,\nsharks and shad, alewives and herring, against Linnæus’s express edict,\nwere still found dividing the possession", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2092, "position": 2092, "text": "Linnæus’s express edict,\nwere still found dividing the possession of the same seas with the\nLeviathan.\n\nThe grounds upon which Linnæus would fain have banished the whales from\nthe waters, he states as follows: “On", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2093, "position": 2093, "text": "have banished the whales from\nthe waters, he states as follows: “On account of their warm bilocular\nheart, their lungs, their movable eyelids, their hollow ears, penem\nintrantem feminam mammis lactantem", "labels": {"50": 45, "100": 85, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2094, "position": 2094, "text": ", penem\nintrantem feminam mammis lactantem,” and finally, “ex lege naturæ jure\nmeritoque.” I submitted all this to my friends Simeon Macey and Charley\nCoffin, of Nan", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 39}}, {"id": 2095, "position": 2095, "text": "submitted all this to my friends Simeon Macey and Charley\nCoffin, of Nantucket, both messmates of mine in a certain voyage, and\nthey united in the opinion that the reasons set forth were altogether\ninsufficient", "labels": {"50": 15, "100": 36, "250": 9, "500": 34, "1000": 564, "2000": 316}}, {"id": 2096, "position": 2096, "text": "reasons set forth were altogether\ninsufficient. Charley profanely hinted they were humbug.\n\nBe it known that, waiving all argument, I take the good old fashioned\nground that the whale is a fish, and call upon holy Jonah to back me", "labels": {"50": 20, "100": 28, "250": 132, "500": 72, "1000": 417, "2000": 381}}, {"id": 2097, "position": 2097, "text": "that the whale is a fish, and call upon holy Jonah to back me.\nThis fundamental thing settled, the next point is, in what internal\nrespect does the whale differ from other fish. Above, Linnæus has given\nyou those items", "labels": {"50": 35, "100": 94, "250": 23, "500": 32, "1000": 966, "2000": 1122}}, {"id": 2098, "position": 2098, "text": "other fish. Above, Linnæus has given\nyou those items. But in brief, they are these: lungs and warm blood;\nwhereas, all other fish are lungless and cold blooded.\n\nNext: how shall we define the whale, by", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2099, "position": 2099, "text": "less and cold blooded.\n\nNext: how shall we define the whale, by his obvious externals, so as\nconspicuously to label him for all time to come? To be short, then, a\nwhale is _a spouting fish with a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2100, "position": 2100, "text": "short, then, a\nwhale is _a spouting fish with a horizontal tail_. There you have him.\nHowever contracted, that definition is the result of expanded\nmeditation. A walrus spouts much like a whale, but the walrus", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2101, "position": 2101, "text": ". A walrus spouts much like a whale, but the walrus is not a\nfish, because he is amphibious. But the last term of the definition is\nstill more cogent, as coupled with the first", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2102, "position": 2102, "text": "cogent, as coupled with the first. Almost any one must have\nnoticed that all the fish familiar to landsmen have not a flat, but a\nvertical, or up-and-down tail. Whereas, among spouting fish the tail,", "labels": {"50": 3, "100": 24, "250": 14, "500": 288, "1000": 825, "2000": 447}}, {"id": 2103, "position": 2103, "text": "and-down tail. Whereas, among spouting fish the tail,\nthough it may be similarly shaped, invariably assumes a horizontal\nposition.\n\nBy the above definition of what a whale is, I do by no means exclude\nfrom the leviathanic brotherhood", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2104, "position": 2104, "text": "whale is, I do by no means exclude\nfrom the leviathanic brotherhood any sea creature hitherto identified\nwith the whale by the best informed Nantucketers; nor, on the other\nhand, link with it any fish hitherto authoritatively", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2105, "position": 2105, "text": "on the other\nhand, link with it any fish hitherto authoritatively regarded as\nalien.* Hence, all the smaller, spouting, and horizontal tailed fish\nmust be included in this ground-plan of Cetology", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 2106, "position": 2106, "text": "be included in this ground-plan of Cetology. Now, then, come the\ngrand divisions of the entire whale host.\n\n*I am aware that down to the present time, the fish styled Lamatins and\nDugongs (Pig-fish", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2107, "position": 2107, "text": ", the fish styled Lamatins and\nDugongs (Pig-fish and Sow-fish of the Coffins of Nantucket) are\nincluded by many naturalists among the whales. But as these pig-fish\nare a noisy, contemptible", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2108, "position": 2108, "text": "the whales. But as these pig-fish\nare a noisy, contemptible set, mostly lurking in the mouths of rivers,\nand feeding on wet hay, and especially as they do not spout, I deny\ntheir credentials as whales; and have presented", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 2109, "position": 2109, "text": "do not spout, I deny\ntheir credentials as whales; and have presented them with their\npassports to quit the Kingdom of Cetology.\n\nFirst: According to magnitude I divide the whales into three primary\nBOOKS (subdivisible into CHAPTERS), and", "labels": {"50": 31, "100": 24, "250": 193, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2110, "position": 2110, "text": "whales into three primary\nBOOKS (subdivisible into CHAPTERS), and these shall comprehend them\nall, both small and large.\n\nI. THE FOLIO WHALE; II. the OCTAVO WHALE; III. the DUODECIMO WHALE.", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2111, "position": 2111, "text": "the OCTAVO WHALE; III. the DUODECIMO WHALE.\n\nAs the type of the FOLIO I present the _Sperm Whale_; of the OCTAVO,\nthe _Grampus_; of the DUODECIMO, the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2112, "position": 2112, "text": ",\nthe _Grampus_; of the DUODECIMO, the _Porpoise_.\n\nFOLIOS. Among these I here include the following chapters:—I. The\n_Sperm Whale_; II", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2113, "position": 2113, "text": "I. The\n_Sperm Whale_; II. the _Right Whale_; III. the _Fin-Back Whale_; IV.\nthe _Hump-backed Whale_; V. the _Razor Back Whale_; VI", "labels": {"50": 3, "100": 24, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2114, "position": 2114, "text": "_; V. the _Razor Back Whale_; VI. the _Sulphur\nBottom Whale_.\n\nBOOK I. (_Folio_), CHAPTER I. (_Sperm Whale_).—This whale, among the\nEnglish of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2115, "position": 2115, "text": "(_Sperm Whale_).—This whale, among the\nEnglish of old vaguely known as the Trumpa whale, and the Physeter\nwhale, and the Anvil Headed whale, is the present Cachalot of the\nFrench, and the", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2116, "position": 2116, "text": "Headed whale, is the present Cachalot of the\nFrench, and the Pottsfich of the Germans, and the Macrocephalus of the\nLong Words. He is, without doubt, the largest inhabitant of the globe;\nthe most", "labels": {"50": 3, "100": 24, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2117, "position": 2117, "text": "is, without doubt, the largest inhabitant of the globe;\nthe most formidable of all whales to encounter; the most majestic in\naspect; and lastly, by far the most valuable in commerce; he being the\nonly creature from which that valuable substance,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2118, "position": 2118, "text": "valuable in commerce; he being the\nonly creature from which that valuable substance, spermaceti, is\nobtained. All his peculiarities will, in many other places, be enlarged\nupon. It is chiefly with his name that I now have to do", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 2119, "position": 2119, "text": "upon. It is chiefly with his name that I now have to do. Philologically\nconsidered, it is absurd. Some centuries ago, when the Sperm whale was\nalmost wholly unknown in his own proper individuality, and when his oil\nwas only accidentally", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2120, "position": 2120, "text": "unknown in his own proper individuality, and when his oil\nwas only accidentally obtained from the stranded fish; in those days\nspermaceti, it would seem, was popularly supposed to be derived from a\ncreature identical with the one then known in England as", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 511}}, {"id": 2121, "position": 2121, "text": "to be derived from a\ncreature identical with the one then known in England as the Greenland\nor Right Whale. It was the idea also, that this same spermaceti was\nthat quickening humor of the Greenland Whale which the first syllable\nof the word literally", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2122, "position": 2122, "text": "quickening humor of the Greenland Whale which the first syllable\nof the word literally expresses. In those times, also, spermaceti was\nexceedingly scarce, not being used for light, but only as an ointment\nand medicament", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2123, "position": 2123, "text": "light, but only as an ointment\nand medicament. It was only to be had from the druggists as you\nnowadays buy an ounce of rhubarb. When, as I opine, in the course of\ntime,", "labels": {"50": 8, "100": 14, "250": 81, "500": 272, "1000": 28, "2000": 776}}, {"id": 2124, "position": 2124, "text": "b. When, as I opine, in the course of\ntime, the true nature of spermaceti became known, its original name was\nstill retained by the dealers; no doubt to enhance its value by a\nnotion so strangely significant of its scar", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2125, "position": 2125, "text": "no doubt to enhance its value by a\nnotion so strangely significant of its scarcity. And so the appellation\nmust at last have come to be bestowed upon the whale from which this\nspermaceti was really derived.\n\nBOOK I", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2126, "position": 2126, "text": "which this\nspermaceti was really derived.\n\nBOOK I. (_Folio_), CHAPTER II. (_Right Whale_).—In one respect this is\nthe most venerable of the leviathans, being the one first regularly\nhunted", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2127, "position": 2127, "text": "the most venerable of the leviathans, being the one first regularly\nhunted by man. It yields the article commonly known as whalebone or\nbaleen; and the oil specially known as “whale oil,” an inferior article\nin commerce", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2128, "position": 2128, "text": "known as “whale oil,” an inferior article\nin commerce. Among the fishermen, he is indiscriminately designated by\nall the following titles: The Whale; the Greenland Whale; the Black\nWhale; the Great Whale; the True Whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2129, "position": 2129, "text": "the Greenland Whale; the Black\nWhale; the Great Whale; the True Whale; the Right Whale. There is a\ndeal of obscurity concerning the identity of the species thus\nmultitudinously baptised. What then is the whale, which I include", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2130, "position": 2130, "text": "multitudinously baptised. What then is the whale, which I include in\nthe second species of my Folios? It is the Great Mysticetus of the\nEnglish naturalists; the Greenland Whale of the English whalemen; the\nBalein", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2131, "position": 2131, "text": "naturalists; the Greenland Whale of the English whalemen; the\nBaleine Ordinaire of the French whalemen; the Growlands Walfish of the\nSwedes. It is the whale which for more than two centuries past has been\nhunted by", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 825, "2000": 1620}}, {"id": 2132, "position": 2132, "text": "It is the whale which for more than two centuries past has been\nhunted by the Dutch and English in the Arctic seas; it is the whale\nwhich the American fishermen have long pursued in the Indian ocean, on\nthe Brazil Banks, on the Nor’ West", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2133, "position": 2133, "text": "in the Indian ocean, on\nthe Brazil Banks, on the Nor’ West Coast, and various other parts of\nthe world, designated by them Right Whale Cruising Grounds.\n\nSome pretend to see a difference between the Greenland whale of the\nEnglish and the right whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2134, "position": 2134, "text": "to see a difference between the Greenland whale of the\nEnglish and the right whale of the Americans. But they precisely agree\nin all their grand features; nor has there yet been presented a single\ndeterminate fact upon which to ground a radical distinction", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2135, "position": 2135, "text": "a single\ndeterminate fact upon which to ground a radical distinction. It is by\nendless subdivisions based upon the most inconclusive differences, that\nsome departments of natural history become so repellingly intricate.\nThe right whale will be elsewhere treated of at some", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 2136, "position": 2136, "text": "repellingly intricate.\nThe right whale will be elsewhere treated of at some length, with\nreference to elucidating the sperm whale.\n\nBOOK I. (_Folio_), CHAPTER III. (_Fin-Back_).—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2137, "position": 2137, "text": "_), CHAPTER III. (_Fin-Back_).—Under this head I reckon\na monster which, by the various names of Fin-Back, Tall-Spout, and\nLong-John, has been seen almost in every sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2138, "position": 2138, "text": "Spout, and\nLong-John, has been seen almost in every sea and is commonly the whale\nwhose distant jet is so often descried by passengers crossing the\nAtlantic, in the New York packet-tracks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2139, "position": 2139, "text": "in the New York packet-tracks. In the length he attains, and\nin his baleen, the Fin-back resembles the right whale, but is of a less\nportly girth, and a lighter colour, approaching to olive", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2140, "position": 2140, "text": "portly girth, and a lighter colour, approaching to olive. His great\nlips present a cable-like aspect, formed by the intertwisting, slanting\nfolds of large wrinkles. His grand distinguishing feature, the fin,\nfrom", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2141, "position": 2141, "text": "folds of large wrinkles. His grand distinguishing feature, the fin,\nfrom which he derives his name, is often a conspicuous object. This fin\nis some three or four feet long, growing vertically from the hinder\npart of the back, of an", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2142, "position": 2142, "text": "long, growing vertically from the hinder\npart of the back, of an angular shape, and with a very sharp pointed\nend. Even if not the slightest other part of the creature be visible,\nthis isolated fin will, at times, be seen plainly", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 447}}, {"id": 2143, "position": 2143, "text": "creature be visible,\nthis isolated fin will, at times, be seen plainly projecting from the\nsurface. When the sea is moderately calm, and slightly marked with\nspherical ripples, and this gnomon-like fin stands up and casts shadows\nupon the", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2144, "position": 2144, "text": "and this gnomon-like fin stands up and casts shadows\nupon the wrinkled surface, it may well be supposed that the watery\ncircle surrounding it somewhat resembles a dial, with its style and\nwavy hour-lines graved on it", "labels": {"50": 48, "100": 20, "250": 49, "500": 334, "1000": 747, "2000": 1710}}, {"id": 2145, "position": 2145, "text": "its style and\nwavy hour-lines graved on it. On that Ahaz-dial the shadow often goes\nback. The Fin-Back is not gregarious. He seems a whale-hater, as some\nmen are man-haters", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2146, "position": 2146, "text": "seems a whale-hater, as some\nmen are man-haters. Very shy; always going solitary; unexpectedly\nrising to the surface in the remotest and most sullen waters; his\nstraight and single lofty jet rising like a tall mis", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2147, "position": 2147, "text": "len waters; his\nstraight and single lofty jet rising like a tall misanthropic spear\nupon a barren plain; gifted with such wondrous power and velocity in\nswimming, as to defy all present pursuit from man; this leviathan", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 174, "2000": 523}}, {"id": 2148, "position": 2148, "text": "swimming, as to defy all present pursuit from man; this leviathan seems\nthe banished and unconquerable Cain of his race, bearing for his mark\nthat style upon his back. From having the baleen in his mouth, the\nFin-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2149, "position": 2149, "text": "his back. From having the baleen in his mouth, the\nFin-Back is sometimes included with the right whale, among a theoretic\nspecies denominated _Whalebone whales_, that is, whales with baleen", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2150, "position": 2150, "text": "bone whales_, that is, whales with baleen. Of\nthese so called Whalebone whales, there would seem to be several\nvarieties, most of which, however, are little known. Broad-nosed whales\nand beaked whales; pike-headed", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2151, "position": 2151, "text": "little known. Broad-nosed whales\nand beaked whales; pike-headed whales; bunched whales; under-jawed\nwhales and rostrated whales, are the fishermen’s names for a few sorts.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2152, "position": 2152, "text": "’s names for a few sorts.\n\nIn connection with this appellative of “Whalebone whales,” it is of\ngreat importance to mention, that however such a nomenclature may be\nconvenient in facilitating allusions to some kind of whales, yet it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2153, "position": 2153, "text": "may be\nconvenient in facilitating allusions to some kind of whales, yet it is\nin vain to attempt a clear classification of the Leviathan, founded\nupon either his baleen, or hump, or fin, or teeth; notwithstanding that\nthose marked parts", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2154, "position": 2154, "text": "or hump, or fin, or teeth; notwithstanding that\nthose marked parts or features very obviously seem better adapted to\nafford the basis for a regular system of Cetology than any other\ndetached bodily distinctions, which the whale, in his kinds, presents", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 2155, "position": 2155, "text": "other\ndetached bodily distinctions, which the whale, in his kinds, presents.\nHow then? The baleen, hump, back-fin, and teeth; these are things whose\npeculiarities are indiscriminately dispersed among all sorts of", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2156, "position": 2156, "text": "whose\npeculiarities are indiscriminately dispersed among all sorts of whales,\nwithout any regard to what may be the nature of their structure in\nother and more essential particulars. Thus, the sperm whale and the\nhumpbacked whale,", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2157, "position": 2157, "text": "s. Thus, the sperm whale and the\nhumpbacked whale, each has a hump; but there the similitude ceases.\nThen, this same humpbacked whale and the Greenland whale, each of these\nhas baleen", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2158, "position": 2158, "text": "pbacked whale and the Greenland whale, each of these\nhas baleen; but there again the similitude ceases. And it is just the\nsame with the other parts above mentioned. In various sorts of whales,\nthey form such irregular combinations", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2159, "position": 2159, "text": "parts above mentioned. In various sorts of whales,\nthey form such irregular combinations; or, in the case of any one of\nthem detached, such an irregular isolation; as utterly to defy all\ngeneral methodization formed upon such a basis", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2160, "position": 2160, "text": "to defy all\ngeneral methodization formed upon such a basis. On this rock every one\nof the whale-naturalists has split.\n\nBut it may possibly be conceived that, in the internal parts of the\nwhale, in his anatomy—there, at", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2161, "position": 2161, "text": "in the internal parts of the\nwhale, in his anatomy—there, at least, we shall be able to hit the\nright classification. Nay; what thing, for example, is there in the\nGreenland whale’s anatomy more striking than his baleen", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2162, "position": 2162, "text": "is there in the\nGreenland whale’s anatomy more striking than his baleen? Yet we have\nseen that by his baleen it is impossible correctly to classify the\nGreenland whale. And if you descend into the bowels of the various\nleviathans,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2163, "position": 2163, "text": "And if you descend into the bowels of the various\nleviathans, why there you will not find distinctions a fiftieth part as\navailable to the systematizer as those external ones already\nenumerated", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 18, "2000": 1618}}, {"id": 2164, "position": 2164, "text": "as those external ones already\nenumerated. What then remains? nothing but to take hold of the whales\nbodily, in their entire liberal volume, and boldly sort them that way.\nAnd this is the Bibliographical system here adopted;", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2165, "position": 2165, "text": "way.\nAnd this is the Bibliographical system here adopted; and it is the only\none that can possibly succeed, for it alone is practicable. To proceed.\n\nBOOK I. (_Folio_) CHAPTER IV", "labels": {"50": 17, "100": 40, "250": 111, "500": 355, "1000": 667, "2000": 1245}}, {"id": 2166, "position": 2166, "text": "proceed.\n\nBOOK I. (_Folio_) CHAPTER IV. (_Hump Back_).—This whale is often seen\non the northern American coast. He has been frequently captured there,\nand towed into harbor", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2167, "position": 2167, "text": "has been frequently captured there,\nand towed into harbor. He has a great pack on him like a peddler; or\nyou might call him the Elephant and Castle whale. At any rate, the\npopular name for him does not sufficiently distinguish him,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2168, "position": 2168, "text": "At any rate, the\npopular name for him does not sufficiently distinguish him, since the\nsperm whale also has a hump though a smaller one. His oil is not very\nvaluable. He has baleen. He is the most gamesome and light-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2169, "position": 2169, "text": ". He has baleen. He is the most gamesome and light-hearted of\nall the whales, making more gay foam and white water generally than any\nother of them.\n\nBOOK I. (_Folio_), CHAPTER V", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2170, "position": 2170, "text": "BOOK I. (_Folio_), CHAPTER V. (_Razor Back_).—Of this whale little is\nknown but his name. I have seen him at a distance off Cape Horn", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2171, "position": 2171, "text": "at a distance off Cape Horn. Of a\nretiring nature, he eludes both hunters and philosophers. Though no\ncoward, he has never yet shown any part of him but his back, which\nrises in a long sharp ridge. Let him go", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2172, "position": 2172, "text": "back, which\nrises in a long sharp ridge. Let him go. I know little more of him, nor\ndoes anybody else.\n\nBOOK I. (_Folio_), CHAPTER VI. (_Sulphur Bottom_).—Another", "labels": {"50": 3, "100": 20, "250": 192, "500": 72, "1000": 825, "2000": 1710}}, {"id": 2173, "position": 2173, "text": ", CHAPTER VI. (_Sulphur Bottom_).—Another retiring\ngentleman, with a brimstone belly, doubtless got by scraping along the\nTartarian tiles in some of his profounder divings", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2174, "position": 2174, "text": "in some of his profounder divings. He is seldom seen;\nat least I have never seen him except in the remoter southern seas, and\nthen always at too great a distance to study his countenance", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2175, "position": 2175, "text": "a distance to study his countenance. He is\nnever chased; he would run away with rope-walks of line. Prodigies are\ntold of him. Adieu, Sulphur Bottom! I can say nothing more that is true\nof", "labels": {"50": 31, "100": 20, "250": 193, "500": 288, "1000": 849, "2000": 1394}}, {"id": 2176, "position": 2176, "text": ", Sulphur Bottom! I can say nothing more that is true\nof ye, nor can the oldest Nantucketer.\n\nThus ends BOOK I. (_Folio_), and now begins BOOK II. (_Octavo_)", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 2177, "position": 2177, "text": "), and now begins BOOK II. (_Octavo_).\n\nOCTAVOES.*—These embrace the whales of middling magnitude, among which\npresent may be numbered:—I., the _Grampus_; II.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2178, "position": 2178, "text": "be numbered:—I., the _Grampus_; II., the _Black Fish_;\nIII., the _Narwhale_; IV., the _Thrasher_; V., the _Killer_.", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 447}}, {"id": 2179, "position": 2179, "text": ", the _Thrasher_; V., the _Killer_.\n\n*Why this book of whales is not denominated the Quarto is very plain.\nBecause, while the whales of this order, though smaller than those of\nthe former", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2180, "position": 2180, "text": ", while the whales of this order, though smaller than those of\nthe former order, nevertheless retain a proportionate likeness to them\nin figure, yet the bookbinder’s Quarto volume in its dimensioned form\ndoes not preserve the shape of", "labels": {"50": 3, "100": 24, "250": 234, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2181, "position": 2181, "text": "Quarto volume in its dimensioned form\ndoes not preserve the shape of the Folio volume, but the Octavo volume\ndoes.\n\nBOOK II. (_Octavo_), CHAPTER I", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 988, "2000": 1334}}, {"id": 2182, "position": 2182, "text": "o_), CHAPTER I. (_Grampus_).—Though this fish, whose\nloud sonorous breathing, or rather blowing, has furnished a proverb to\nlandsmen, is so well known a denizen of the deep,", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2183, "position": 2183, "text": "landsmen, is so well known a denizen of the deep, yet is he not\npopularly classed among whales. But possessing all the grand\ndistinctive features of the leviathan, most naturalists have recognised\nhim for one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2184, "position": 2184, "text": ", most naturalists have recognised\nhim for one. He is of moderate octavo size, varying from fifteen to\ntwenty-five feet in length, and of corresponding dimensions round the\nwaist. He swims in herds; he is never regularly hunted,", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 825, "2000": 1225}}, {"id": 2185, "position": 2185, "text": "the\nwaist. He swims in herds; he is never regularly hunted, though his oil\nis considerable in quantity, and pretty good for light. By some\nfishermen his approach is regarded as premonitory of the advance of the\ngreat sperm whale.", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2186, "position": 2186, "text": "regarded as premonitory of the advance of the\ngreat sperm whale.\n\nBOOK II. (_Octavo_), CHAPTER II. (_Black Fish_).—I give the popular\nfishermen’s names for all these fish, for", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2187, "position": 2187, "text": "—I give the popular\nfishermen’s names for all these fish, for generally they are the best.\nWhere any name happens to be vague or inexpressive, I shall say so, and\nsuggest another", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 692, "2000": 447}}, {"id": 2188, "position": 2188, "text": "say so, and\nsuggest another. I do so now, touching the Black Fish, so-called,\nbecause blackness is the rule among almost all whales. So, call him the\nHyena Whale, if you please", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2189, "position": 2189, "text": "the\nHyena Whale, if you please. His voracity is well known, and from the\ncircumstance that the inner angles of his lips are curved upwards, he\ncarries an everlasting Mephistophelean grin on his face", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2190, "position": 2190, "text": "an everlasting Mephistophelean grin on his face. This whale\naverages some sixteen or eighteen feet in length. He is found in almost\nall latitudes. He has a peculiar way of showing his dorsal hooked fin\nin swimming, which", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2191, "position": 2191, "text": "He has a peculiar way of showing his dorsal hooked fin\nin swimming, which looks something like a Roman nose. When not more\nprofitably employed, the sperm whale hunters sometimes capture the\nHyena whale, to keep up the supply of cheap oil for", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2192, "position": 2192, "text": "the\nHyena whale, to keep up the supply of cheap oil for domestic\nemployment—as some frugal housekeepers, in the absence of company, and\nquite alone by themselves, burn unsavory tallow instead of odorous wax", "labels": {"50": 42, "100": 24, "250": 49, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2193, "position": 2193, "text": "by themselves, burn unsavory tallow instead of odorous wax.\nThough their blubber is very thin, some of these whales will yield you\nupwards of thirty gallons of oil.\n\nBOOK II. (_Octavo_), CHAPTER", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2194, "position": 2194, "text": "of oil.\n\nBOOK II. (_Octavo_), CHAPTER III. (_Narwhale_), that is, _Nostril\nwhale_.—Another instance of a curiously named whale, so named I suppose\nfrom", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2195, "position": 2195, "text": ".—Another instance of a curiously named whale, so named I suppose\nfrom his peculiar horn being originally mistaken for a peaked nose. The\ncreature is some sixteen feet in length, while its horn averages five\nfeet, though some exceed ten, and even attain", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2196, "position": 2196, "text": "while its horn averages five\nfeet, though some exceed ten, and even attain to fifteen feet. Strictly\nspeaking, this horn is but a lengthened tusk, growing out from the jaw\nin a line a little depressed from the horizontal", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 2197, "position": 2197, "text": "the jaw\nin a line a little depressed from the horizontal. But it is only found\non the sinister side, which has an ill effect, giving its owner\nsomething analogous to the aspect of a clumsy left-handed man", "labels": {"50": 3, "100": 42, "250": 155, "500": 309, "1000": 294, "2000": 1681}}, {"id": 2198, "position": 2198, "text": "aspect of a clumsy left-handed man. What\nprecise purpose this ivory horn or lance answers, it would be hard to\nsay. It does not seem to be used like the blade of the sword-fish and\nbill-fish; though some sailors tell", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 2199, "position": 2199, "text": "blade of the sword-fish and\nbill-fish; though some sailors tell me that the Narwhale employs it for\na rake in turning over the bottom of the sea for food. Charley Coffin\nsaid it was used for an ice-piercer", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2200, "position": 2200, "text": "for food. Charley Coffin\nsaid it was used for an ice-piercer; for the Narwhale, rising to the\nsurface of the Polar Sea, and finding it sheeted with ice, thrusts his\nhorn up, and so breaks through", "labels": {"50": 45, "100": 24, "250": 34, "500": 48, "1000": 997, "2000": 1931}}, {"id": 2201, "position": 2201, "text": "sheeted with ice, thrusts his\nhorn up, and so breaks through. But you cannot prove either of these\nsurmises to be correct. My own opinion is, that however this one-sided\nhorn may really be used by the Narw", "labels": {"50": 3, "100": 85, "250": 14, "500": 486, "1000": 956, "2000": 1346}}, {"id": 2202, "position": 2202, "text": "however this one-sided\nhorn may really be used by the Narwhale—however that may be—it would\ncertainly be very convenient to him for a folder in reading pamphlets.\nThe Narwhale I have heard called the Tusked", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 2203, "position": 2203, "text": "pamphlets.\nThe Narwhale I have heard called the Tusked whale, the Horned whale,\nand the Unicorn whale. He is certainly a curious example of the\nUnicornism to be found in almost every kingdom of animated nature", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2204, "position": 2204, "text": "ism to be found in almost every kingdom of animated nature. From\ncertain cloistered old authors I have gathered that this same\nsea-unicorn’s horn was in ancient days regarded as the great antidote\nagainst poison, and as such, preparations of", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 505, "2000": 744}}, {"id": 2205, "position": 2205, "text": "regarded as the great antidote\nagainst poison, and as such, preparations of it brought immense prices.\nIt was also distilled to a volatile salts for fainting ladies, the same\nway that the horns of the male deer are manufactured into hartsho", "labels": {"50": 40, "100": 13, "250": 182, "500": 27, "1000": 673, "2000": 984}}, {"id": 2206, "position": 2206, "text": "the same\nway that the horns of the male deer are manufactured into hartshorn.\nOriginally it was in itself accounted an object of great curiosity.\nBlack Letter tells me that Sir Martin Frobisher on his return from that\nvoyage, when Queen Be", "labels": {"50": 3, "100": 85, "250": 14, "500": 486, "1000": 956, "2000": 167}}, {"id": 2207, "position": 2207, "text": "Martin Frobisher on his return from that\nvoyage, when Queen Bess did gallantly wave her jewelled hand to him\nfrom a window of Greenwich Palace, as his bold ship sailed down the\nThames; “when Sir Martin returned from that voyage", "labels": {"50": 18, "100": 32, "250": 21, "500": 487, "1000": 748, "2000": 1091}}, {"id": 2208, "position": 2208, "text": "bold ship sailed down the\nThames; “when Sir Martin returned from that voyage,” saith Black\nLetter, “on bended knees he presented to her highness a prodigious long\nhorn of the Narwhale, which for a long", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2209, "position": 2209, "text": "gious long\nhorn of the Narwhale, which for a long period after hung in the castle\nat Windsor.” An Irish author avers that the Earl of Leicester, on\nbended knees, did likewise present to her highness another horn,", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 2210, "position": 2210, "text": ", on\nbended knees, did likewise present to her highness another horn,\npertaining to a land beast of the unicorn nature.\n\nThe Narwhale has a very picturesque, leopard-like look, being of a\nmilk-white ground colour, dotted", "labels": {"50": 32, "100": 0, "250": 153, "500": 466, "1000": 131, "2000": 727}}, {"id": 2211, "position": 2211, "text": "leopard-like look, being of a\nmilk-white ground colour, dotted with round and oblong spots of black.\nHis oil is very superior, clear and fine; but there is little of it,\nand he is seldom hunted", "labels": {"50": 12, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 2212, "position": 2212, "text": "there is little of it,\nand he is seldom hunted. He is mostly found in the circumpolar seas.\n\nBOOK II. (_Octavo_), CHAPTER IV. (_Killer_).—Of this whale little is", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2213, "position": 2213, "text": "CHAPTER IV. (_Killer_).—Of this whale little is\nprecisely known to the Nantucketer, and nothing at all to the professed\nnaturalist. From what I have seen of him at a distance, I should say\nthat he was", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2214, "position": 2214, "text": "I have seen of him at a distance, I should say\nthat he was about the bigness of a grampus. He is very savage—a sort of\nFeegee fish. He sometimes takes the great Folio whales by the lip, and\nhangs", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 825, "2000": 447}}, {"id": 2215, "position": 2215, "text": ". He sometimes takes the great Folio whales by the lip, and\nhangs there like a leech, till the mighty brute is worried to death.\nThe Killer is never hunted. I never heard what sort of oil he has", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2216, "position": 2216, "text": ". I never heard what sort of oil he has.\nException might be taken to the name bestowed upon this whale, on the\nground of its indistinctness. For we are all killers, on land and on\nsea; Bonapartes and Sharks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2217, "position": 2217, "text": "we are all killers, on land and on\nsea; Bonapartes and Sharks included.\n\nBOOK II. (_Octavo_), CHAPTER V. (_Thrasher_).—This gentleman is famous\nfor his tail, which he uses", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2218, "position": 2218, "text": "_).—This gentleman is famous\nfor his tail, which he uses for a ferule in thrashing his foes. He\nmounts the Folio whale’s back, and as he swims, he works his passage by\nflog", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2219, "position": 2219, "text": "back, and as he swims, he works his passage by\nflogging him; as some schoolmasters get along in the world by a similar\nprocess. Still less is known of the Thrasher than of the Killer", "labels": {"50": 43, "100": 48, "250": 148, "500": 127, "1000": 927, "2000": 1154}}, {"id": 2220, "position": 2220, "text": "known of the Thrasher than of the Killer. Both\nare outlaws, even in the lawless seas.\n\n Thus ends BOOK II. (_Octavo_), and begins BOOK III. (_Duodecimo_).", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 9, "2000": 16}}, {"id": 2221, "position": 2221, "text": "begins BOOK III. (_Duodecimo_).\n\nDUODECIMOES.—These include the smaller whales. I. The Huzza Porpoise.\nII. The Algerine Porpoise. III", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2222, "position": 2222, "text": "II. The Algerine Porpoise. III. The Mealy-mouthed Porpoise.\n\nTo those who have not chanced specially to study the subject, it may\npossibly seem strange, that fishes not commonly exceeding four or five\nfeet should", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 447}}, {"id": 2223, "position": 2223, "text": "may\npossibly seem strange, that fishes not commonly exceeding four or five\nfeet should be marshalled among WHALES—a word, which, in the popular\nsense, always conveys an idea of hugeness. But the creatures set down\nabove as Duodeci", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2224, "position": 2224, "text": "idea of hugeness. But the creatures set down\nabove as Duodecimoes are infallibly whales, by the terms of my\ndefinition of what a whale is—_i.e._ a spouting fish, with a horizontal", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2225, "position": 2225, "text": "_i.e._ a spouting fish, with a horizontal\ntail.\n\nBOOK III. (_Duodecimo_), CHAPTER 1. (_Huzza Porpoise_).—This is the\ncommon porpoise", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2226, "position": 2226, "text": "zza Porpoise_).—This is the\ncommon porpoise found almost all over the globe. The name is of my own\nbestowal; for there are more than one sort of porpoises, and something\nmust be done to", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 2227, "position": 2227, "text": "more than one sort of porpoises, and something\nmust be done to distinguish them. I call him thus, because he always\nswims in hilarious shoals, which upon the broad sea keep tossing\nthemselves to heaven like caps in a Fourth-of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2228, "position": 2228, "text": "the broad sea keep tossing\nthemselves to heaven like caps in a Fourth-of-July crowd. Their\nappearance is generally hailed with delight by the mariner. Full of\nfine spirits, they invariably come from the breezy billows to windward", "labels": {"50": 31, "100": 20, "250": 49, "500": 334, "1000": 747, "2000": 1710}}, {"id": 2229, "position": 2229, "text": ", they invariably come from the breezy billows to windward.\nThey are the lads that always live before the wind. They are accounted\na lucky omen. If you yourself can withstand three cheers at beholding\nthese vivacious fish, then heaven", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 447}}, {"id": 2230, "position": 2230, "text": "yourself can withstand three cheers at beholding\nthese vivacious fish, then heaven help ye; the spirit of godly\ngamesomeness is not in ye. A well-fed, plump Huzza Porpoise will yield\nyou one good gallon of good", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2231, "position": 2231, "text": ", plump Huzza Porpoise will yield\nyou one good gallon of good oil. But the fine and delicate fluid\nextracted from his jaws is exceedingly valuable. It is in request among\njewellers and watchmakers. Sailors put it on their hones", "labels": {"50": 42, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 447}}, {"id": 2232, "position": 2232, "text": "request among\njewellers and watchmakers. Sailors put it on their hones. Porpoise meat\nis good eating, you know. It may never have occurred to you that a\nporpoise spouts", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2233, "position": 2233, "text": "a\nporpoise spouts. Indeed, his spout is so small that it is not very\nreadily discernible. But the next time you have a chance, watch him;\nand you will then see the great Sperm whale himself in miniature.", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2234, "position": 2234, "text": "him;\nand you will then see the great Sperm whale himself in miniature.\n\nBOOK III. (_Duodecimo_), CHAPTER II. (_Algerine Porpoise_).—A pirate.\nVery savage", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2235, "position": 2235, "text": "Porpoise_).—A pirate.\nVery savage. He is only found, I think, in the Pacific. He is somewhat\nlarger than the Huzza Porpoise, but much of the same general make", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2236, "position": 2236, "text": "ise, but much of the same general make.\nProvoke him, and he will buckle to a shark. I have lowered for him many\ntimes, but never yet saw him captured.\n\nBOOK III. (_Duodecimo_), CHAPTER III", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2237, "position": 2237, "text": ".\n\nBOOK III. (_Duodecimo_), CHAPTER III. (_Mealy-mouthed Porpoise_).—The\nlargest kind of Porpoise; and only found in the Pacific, so far as it\nis known", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2238, "position": 2238, "text": "ise; and only found in the Pacific, so far as it\nis known. The only English name, by which he has hitherto been\ndesignated, is that of the fishers—Right-Whale Porpoise, from the\ncircumstance that he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2239, "position": 2239, "text": "fishers—Right-Whale Porpoise, from the\ncircumstance that he is chiefly found in the vicinity of that Folio. In\nshape, he differs in some degree from the Huzza Porpoise, being of a\nless rotund and jolly", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2240, "position": 2240, "text": "the Huzza Porpoise, being of a\nless rotund and jolly girth; indeed, he is of quite a neat and\ngentleman-like figure. He has no fins on his back (most other porpoises\nhave), he has", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2241, "position": 2241, "text": "fins on his back (most other porpoises\nhave), he has a lovely tail, and sentimental Indian eyes of a hazel\nhue. But his mealy-mouth spoils all. Though his entire back down to his\nside fins is of a", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2242, "position": 2242, "text": "s all. Though his entire back down to his\nside fins is of a deep sable, yet a boundary line, distinct as the mark\nin a ship’s hull, called the “bright waist,” that line streaks him from\nstem to stern,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2243, "position": 2243, "text": "the “bright waist,” that line streaks him from\nstem to stern, with two separate colours, black above and white below.\nThe white comprises part of his head, and the whole of his mouth, which\nmakes him look as if he had just", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2244, "position": 2244, "text": "the whole of his mouth, which\nmakes him look as if he had just escaped from a felonious visit to a\nmeal-bag. A most mean and mealy aspect! His oil is much like that of\nthe common porpoise.", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2245, "position": 2245, "text": "! His oil is much like that of\nthe common porpoise.\n\n  * * * * * *\n\nBeyond the DUODECIMO, this system does not proceed, inasmuch as the\nPorpoise is the smallest of the whales", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2246, "position": 2246, "text": "uch as the\nPorpoise is the smallest of the whales. Above, you have all the\nLeviathans of note. But there are a rabble of uncertain, fugitive,\nhalf-fabulous whales, which, as an American whaleman, I", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2247, "position": 2247, "text": ",\nhalf-fabulous whales, which, as an American whaleman, I know by\nreputation, but not personally. I shall enumerate them by their\nfore-castle appellations; for possibly such a list may be valuable to\nfuture investigators,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2248, "position": 2248, "text": "ellations; for possibly such a list may be valuable to\nfuture investigators, who may complete what I have here but begun. If\nany of the following whales, shall hereafter be caught and marked, then\nhe can readily be incorporated into this System", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2249, "position": 2249, "text": "ter be caught and marked, then\nhe can readily be incorporated into this System, according to his\nFolio, Octavo, or Duodecimo magnitude:—The Bottle-Nose Whale; the Junk\nWhale; the Pudding-Headed Whale;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2250, "position": 2250, "text": "Bottle-Nose Whale; the Junk\nWhale; the Pudding-Headed Whale; the Cape Whale; the Leading Whale; the\nCannon Whale; the Scragg Whale; the Coppered Whale; the Elephant Whale;\nthe Iceberg Whale; the Quog", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2251, "position": 2251, "text": "ed Whale; the Elephant Whale;\nthe Iceberg Whale; the Quog Whale; the Blue Whale; etc. From Icelandic,\nDutch, and old English authorities, there might be quoted other lists\nof uncertain whales, blessed with all manner of unco", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2252, "position": 2252, "text": "be quoted other lists\nof uncertain whales, blessed with all manner of uncouth names. But I\nomit them as altogether obsolete; and can hardly help suspecting them\nfor mere sounds, full of Leviathanism, but signifying nothing.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2253, "position": 2253, "text": "mere sounds, full of Leviathanism, but signifying nothing.\n\nFinally: It was stated at the outset, that this system would not be\nhere, and at once, perfected. You cannot but plainly see that I have\nkept my word", "labels": {"50": 21, "100": 75, "250": 76, "500": 107, "1000": 761, "2000": 1497}}, {"id": 2254, "position": 2254, "text": "perfected. You cannot but plainly see that I have\nkept my word. But I now leave my cetological System standing thus\nunfinished, even as the great Cathedral of Cologne was left, with the\ncrane still standing upon the top of the uncom", "labels": {"50": 31, "100": 27, "250": 69, "500": 339, "1000": 27, "2000": 180}}, {"id": 2255, "position": 2255, "text": "was left, with the\ncrane still standing upon the top of the uncompleted tower. For small\nerections may be finished by their first architects; grand ones, true\nones, ever leave the copestone to posterity", "labels": {"50": 48, "100": 27, "250": 157, "500": 63, "1000": 765, "2000": 1696}}, {"id": 2256, "position": 2256, "text": "ones, ever leave the copestone to posterity. God keep me from ever\ncompleting anything. This whole book is but a draught—nay, but the\ndraught of a draught. Oh, Time, Strength, Cash, and Patience!\n\n\nCHAPTER 33", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 1495}}, {"id": 2257, "position": 2257, "text": ". Oh, Time, Strength, Cash, and Patience!\n\n\nCHAPTER 33. The Specksnyder.\n\nConcerning the officers of the whale-craft, this seems as good a place\nas any to set down a little domestic peculiarity on ship-board", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2258, "position": 2258, "text": "place\nas any to set down a little domestic peculiarity on ship-board, arising\nfrom the existence of the harpooneer class of officers, a class unknown\nof course in any other marine than the whale-fleet.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2259, "position": 2259, "text": "any other marine than the whale-fleet.\n\nThe large importance attached to the harpooneer’s vocation is evinced\nby the fact, that originally in the old Dutch Fishery, two centuries\nand more ago, the command of a whale ship", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2260, "position": 2260, "text": "Dutch Fishery, two centuries\nand more ago, the command of a whale ship was not wholly lodged in the\nperson now called the captain, but was divided between him and an\nofficer called the Specksnyder", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2261, "position": 2261, "text": "called the Specksnyder. Literally this word means Fat-Cutter;\nusage, however, in time made it equivalent to Chief Harpooneer. In\nthose days, the captain’s authority was restricted to the navigation\nand general management of the vessel", "labels": {"50": 45, "100": 64, "250": 82, "500": 73, "1000": 851, "2000": 967}}, {"id": 2262, "position": 2262, "text": "captain’s authority was restricted to the navigation\nand general management of the vessel; while over the whale-hunting\ndepartment and all its concerns, the Specksnyder or Chief Harpooneer\nreigned supreme. In the British Greenland Fishery, under the corrupted", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2263, "position": 2263, "text": "Harpooneer\nreigned supreme. In the British Greenland Fishery, under the corrupted\ntitle of Specksioneer, this old Dutch official is still retained, but\nhis former dignity is sadly abridged. At present he ranks simply as\nsenior Harpooneer", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 692, "2000": 447}}, {"id": 2264, "position": 2264, "text": "sadly abridged. At present he ranks simply as\nsenior Harpooneer; and as such, is but one of the captain’s more\ninferior subalterns. Nevertheless, as upon the good conduct of the\nharpooneers the success of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2265, "position": 2265, "text": "Nevertheless, as upon the good conduct of the\nharpooneers the success of a whaling voyage largely depends, and since\nin the American Fishery he is not only an important officer in the\nboat, but under certain circumstances (night watches on a whaling\nground)", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2266, "position": 2266, "text": "the\nboat, but under certain circumstances (night watches on a whaling\nground) the command of the ship’s deck is also his; therefore the grand\npolitical maxim of the sea demands, that he should nominally live apart\nfrom the men before the mast,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2267, "position": 2267, "text": "demands, that he should nominally live apart\nfrom the men before the mast, and be in some way distinguished as their\nprofessional superior; though always, by them, familiarly regarded as\ntheir social equal.\n\nNow, the grand distinction drawn between officer and man", "labels": {"50": 45, "100": 29, "250": 159, "500": 73, "1000": 851, "2000": 887}}, {"id": 2268, "position": 2268, "text": "as\ntheir social equal.\n\nNow, the grand distinction drawn between officer and man at sea, is\nthis—the first lives aft, the last forward. Hence, in whale-ships and\nmerchantmen alike, the mates have their quarters with the captain;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2269, "position": 2269, "text": "ships and\nmerchantmen alike, the mates have their quarters with the captain; and\nso, too, in most of the American whalers the harpooneers are lodged in\nthe after part of the ship. That is to say, they take their meals", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2270, "position": 2270, "text": "after part of the ship. That is to say, they take their meals in\nthe captain’s cabin, and sleep in a place indirectly communicating with\nit.\n\nThough the long period of a Southern whaling voyage (by far the longest\nof all voyages now", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2271, "position": 2271, "text": "period of a Southern whaling voyage (by far the longest\nof all voyages now or ever made by man), the peculiar perils of it, and\nthe community of interest prevailing among a company, all of whom, high\nor low, depend for their", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2272, "position": 2272, "text": "among a company, all of whom, high\nor low, depend for their profits, not upon fixed wages, but upon their\ncommon luck, together with their common vigilance, intrepidity, and\nhard work; though all these things do", "labels": {"50": 21, "100": 95, "250": 76, "500": 107, "1000": 821, "2000": 1073}}, {"id": 2273, "position": 2273, "text": ", intrepidity, and\nhard work; though all these things do in some cases tend to beget a\nless rigorous discipline than in merchantmen generally; yet, never mind\nhow much like an old Mesopotamian family these whalemen may, in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2274, "position": 2274, "text": "mind\nhow much like an old Mesopotamian family these whalemen may, in some\nprimitive instances, live together; for all that, the punctilious\nexternals, at least, of the quarter-deck are seldom materially relaxed,\nand in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2275, "position": 2275, "text": "least, of the quarter-deck are seldom materially relaxed,\nand in no instance done away. Indeed, many are the Nantucket ships in\nwhich you will see the skipper parading his quarter-deck with an elated\ngrandeur not surpassed in", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2276, "position": 2276, "text": "parading his quarter-deck with an elated\ngrandeur not surpassed in any military navy; nay, extorting almost as\nmuch outward homage as if he wore the imperial purple, and not the\nshabbiest of pilot-cloth.", "labels": {"50": 47, "100": 53, "250": 230, "500": 92, "1000": 110, "2000": 1063}}, {"id": 2277, "position": 2277, "text": "purple, and not the\nshabbiest of pilot-cloth.\n\nAnd though of all men the moody captain of the Pequod was the least\ngiven to that sort of shallowest assumption; and though the only homage\nhe ever exacted, was implicit", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2278, "position": 2278, "text": "est assumption; and though the only homage\nhe ever exacted, was implicit, instantaneous obedience; though he\nrequired no man to remove the shoes from his feet ere stepping upon the\nquarter-deck; and though there were times when, owing to", "labels": {"50": 45, "100": 68, "250": 82, "500": 73, "1000": 851, "2000": 1584}}, {"id": 2279, "position": 2279, "text": "upon the\nquarter-deck; and though there were times when, owing to peculiar\ncircumstances connected with events hereafter to be detailed, he\naddressed them in unusual terms, whether of condescension or _in\nterrorem_, or otherwise;", "labels": {"50": 44, "100": 17, "250": 160, "500": 336, "1000": 448, "2000": 825}}, {"id": 2280, "position": 2280, "text": "of condescension or _in\nterrorem_, or otherwise; yet even Captain Ahab was by no means\nunobservant of the paramount forms and usages of the sea.\n\nNor, perhaps, will it fail to be eventually perceived", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2281, "position": 2281, "text": "of the sea.\n\nNor, perhaps, will it fail to be eventually perceived, that behind\nthose forms and usages, as it were, he sometimes masked himself;\nincidentally making use of them for other and more private ends than\nthey were legitimately", "labels": {"50": 14, "100": 32, "250": 187, "500": 29, "1000": 92, "2000": 1834}}, {"id": 2282, "position": 2282, "text": "making use of them for other and more private ends than\nthey were legitimately intended to subserve. That certain sultanism of\nhis brain, which had otherwise in a good degree remained unmanifested;\nthrough those forms that same sultanism became", "labels": {"50": 32, "100": 90, "250": 121, "500": 142, "1000": 879, "2000": 956}}, {"id": 2283, "position": 2283, "text": "degree remained unmanifested;\nthrough those forms that same sultanism became incarnate in an\nirresistible dictatorship. For be a man’s intellectual superiority what\nit will, it can never assume the practical, available supremacy over\nother men, without the", "labels": {"50": 32, "100": 0, "250": 233, "500": 83, "1000": 484, "2000": 1846}}, {"id": 2284, "position": 2284, "text": "it can never assume the practical, available supremacy over\nother men, without the aid of some sort of external arts and\nentrenchments, always, in themselves, more or less paltry and base.\nThis it is, that for ever keeps God", "labels": {"50": 10, "100": 75, "250": 12, "500": 144, "1000": 560, "2000": 1945}}, {"id": 2285, "position": 2285, "text": "less paltry and base.\nThis it is, that for ever keeps God’s true princes of the Empire from\nthe world’s hustings; and leaves the highest honors that this air can\ngive, to those men who become famous more", "labels": {"50": 9, "100": 26, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2286, "position": 2286, "text": "highest honors that this air can\ngive, to those men who become famous more through their infinite\ninferiority to the choice hidden handful of the Divine Inert, than\nthrough their undoubted superiority over the dead level of the mass", "labels": {"50": 31, "100": 75, "250": 106, "500": 29, "1000": 355, "2000": 710}}, {"id": 2287, "position": 2287, "text": "ubted superiority over the dead level of the mass.\nSuch large virtue lurks in these small things when extreme political\nsuperstitions invest them, that in some royal instances even to idiot\nimbecility they have imparted potency", "labels": {"50": 21, "100": 95, "250": 76, "500": 455, "1000": 319, "2000": 1605}}, {"id": 2288, "position": 2288, "text": "to idiot\nimbecility they have imparted potency. But when, as in the case of\nNicholas the Czar, the ringed crown of geographical empire encircles an\nimperial brain; then, the plebeian herds", "labels": {"50": 21, "100": 95, "250": 76, "500": 307, "1000": 343, "2000": 1497}}, {"id": 2289, "position": 2289, "text": "circles an\nimperial brain; then, the plebeian herds crouch abased before the\ntremendous centralization. Nor, will the tragic dramatist who would\ndepict mortal indomitableness in its fullest sweep and direct swing,\never forget", "labels": {"50": 17, "100": 16, "250": 151, "500": 71, "1000": 608, "2000": 131}}, {"id": 2290, "position": 2290, "text": "indomitableness in its fullest sweep and direct swing,\never forget a hint, incidentally so important in his art, as the one\nnow alluded to.\n\nBut Ahab, my Captain, still moves before me in all his Nantucket", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2291, "position": 2291, "text": "Ahab, my Captain, still moves before me in all his Nantucket\ngrimness and shagginess; and in this episode touching Emperors and\nKings, I must not conceal that I have only to do with a poor old\nwhale-hunter like him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2292, "position": 2292, "text": "that I have only to do with a poor old\nwhale-hunter like him; and, therefore, all outward majestical trappings\nand housings are denied me. Oh, Ahab! what shall be grand in thee, it\nmust needs be plucked", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2293, "position": 2293, "text": "Ahab! what shall be grand in thee, it\nmust needs be plucked at from the skies, and dived for in the deep, and\nfeatured in the unbodied air!\n\n\nCHAPTER 34. The Cabin-Table.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2294, "position": 2294, "text": "d air!\n\n\nCHAPTER 34. The Cabin-Table.\n\nIt is noon; and Dough-Boy, the steward, thrusting his pale\nloaf-of-bread face from the cabin-scuttle, announces dinner to his lord\nand master; who,", "labels": {"50": 31, "100": 7, "250": 193, "500": 16, "1000": 851, "2000": 1620}}, {"id": 2295, "position": 2295, "text": "-scuttle, announces dinner to his lord\nand master; who, sitting in the lee quarter-boat, has just been taking\nan observation of the sun; and is now mutely reckoning the latitude on\nthe smooth, medallion-shaped tablet", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 2296, "position": 2296, "text": "now mutely reckoning the latitude on\nthe smooth, medallion-shaped tablet, reserved for that daily purpose on\nthe upper part of his ivory leg. From his complete inattention to the\ntidings, you would think that moody Ahab had", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2297, "position": 2297, "text": "tion to the\ntidings, you would think that moody Ahab had not heard his menial. But\npresently, catching hold of the mizen shrouds, he swings himself to the\ndeck, and in an even, unexhilarated", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2298, "position": 2298, "text": "swings himself to the\ndeck, and in an even, unexhilarated voice, saying, “Dinner, Mr.\nStarbuck,” disappears into the cabin.\n\nWhen the last echo of his sultan’s step has died away, and Starbuck", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2299, "position": 2299, "text": "last echo of his sultan’s step has died away, and Starbuck,\nthe first Emir, has every reason to suppose that he is seated, then\nStarbuck rouses from his quietude, takes a few turns along the planks,\nand", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 2300, "position": 2300, "text": "from his quietude, takes a few turns along the planks,\nand, after a grave peep into the binnacle, says, with some touch of\npleasantness, “Dinner, Mr. Stubb,” and descends the scut", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2301, "position": 2301, "text": ", “Dinner, Mr. Stubb,” and descends the scuttle. The second\nEmir lounges about the rigging awhile, and then slightly shaking the\nmain brace, to see whether it will be all right with that important\nrope, he", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 2302, "position": 2302, "text": ", to see whether it will be all right with that important\nrope, he likewise takes up the old burden, and with a rapid “Dinner,\nMr. Flask,” follows after his predecessors.\n\nBut the third Emir, now seeing himself all alone", "labels": {"50": 32, "100": 0, "250": 233, "500": 142, "1000": 716, "2000": 397}}, {"id": 2303, "position": 2303, "text": "follows after his predecessors.\n\nBut the third Emir, now seeing himself all alone on the quarter-deck,\nseems to feel relieved from some curious restraint; for, tipping all\nsorts of knowing winks in all sorts of directions, and kicking off his\nshoes", "labels": {"50": 32, "100": 0, "250": 233, "500": 55, "1000": 806, "2000": 272}}, {"id": 2304, "position": 2304, "text": "of knowing winks in all sorts of directions, and kicking off his\nshoes, he strikes into a sharp but noiseless squall of a hornpipe right\nover the Grand Turk’s head; and then, by a dexterous sleight", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 317, "2000": 1087}}, {"id": 2305, "position": 2305, "text": "Turk’s head; and then, by a dexterous sleight, pitching\nhis cap up into the mizentop for a shelf, he goes down rollicking so\nfar at least as he remains visible from the deck, reversing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2306, "position": 2306, "text": "so\nfar at least as he remains visible from the deck, reversing all other\nprocessions, by bringing up the rear with music. But ere stepping into\nthe cabin doorway below, he pauses, ships a new face altogether, and,\nthen", "labels": {"50": 45, "100": 64, "250": 49, "500": 78, "1000": 925, "2000": 1081}}, {"id": 2307, "position": 2307, "text": "doorway below, he pauses, ships a new face altogether, and,\nthen, independent, hilarious little Flask enters King Ahab’s presence,\nin the character of Abjectus, or the Slave.", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 963, "2000": 1239}}, {"id": 2308, "position": 2308, "text": "jectus, or the Slave.\n\nIt is not the least among the strange things bred by the intense\nartificialness of sea-usages, that while in the open air of the deck\nsome officers will, upon provocation, bear themselves boldly and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2309, "position": 2309, "text": "the deck\nsome officers will, upon provocation, bear themselves boldly and\ndefyingly enough towards their commander; yet, ten to one, let those\nvery officers the next moment go down to their customary dinner in that\nsame commander’s cabin,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 2310, "position": 2310, "text": "moment go down to their customary dinner in that\nsame commander’s cabin, and straightway their inoffensive, not to say\ndeprecatory and humble air towards him, as he sits at the head of the\ntable; this is marvel", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2311, "position": 2311, "text": "him, as he sits at the head of the\ntable; this is marvellous, sometimes most comical. Wherefore this\ndifference? A problem? Perhaps not. To have been Belshazzar, King of\nBabylon; and to have been Bel", "labels": {"50": 31, "100": 7, "250": 193, "500": 453, "1000": 849, "2000": 1394}}, {"id": 2312, "position": 2312, "text": "been Belshazzar, King of\nBabylon; and to have been Belshazzar, not haughtily but courteously,\ntherein certainly must have been some touch of mundane grandeur. But he\nwho in the rightly regal and", "labels": {"50": 32, "100": 25, "250": 93, "500": 135, "1000": 92, "2000": 578}}, {"id": 2313, "position": 2313, "text": "touch of mundane grandeur. But he\nwho in the rightly regal and intelligent spirit presides over his own\nprivate dinner-table of invited guests, that man’s unchallenged power\nand dominion of individual influence for the time; that", "labels": {"50": 23, "100": 88, "250": 189, "500": 16, "1000": 858, "2000": 371}}, {"id": 2314, "position": 2314, "text": "unchallenged power\nand dominion of individual influence for the time; that man’s royalty\nof state transcends Belshazzar’s, for Belshazzar was not the greatest.\nWho has but once dined his friends,", "labels": {"50": 27, "100": 33, "250": 194, "500": 135, "1000": 503, "2000": 84}}, {"id": 2315, "position": 2315, "text": "r was not the greatest.\nWho has but once dined his friends, has tasted what it is to be Cæsar.\nIt is a witchery of social czarship which there is no withstanding", "labels": {"50": 8, "100": 14, "250": 81, "500": 426, "1000": 42, "2000": 1180}}, {"id": 2316, "position": 2316, "text": "ship which there is no withstanding.\nNow, if to this consideration you superadd the official supremacy of a\nship-master, then, by inference, you will derive the cause of that\npeculiarity of sea-life just mentioned.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2317, "position": 2317, "text": "the cause of that\npeculiarity of sea-life just mentioned.\n\nOver his ivory-inlaid table, Ahab presided like a mute, maned sea-lion\non the white coral beach, surrounded by his warlike but still\ndeferential cubs", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2318, "position": 2318, "text": "white coral beach, surrounded by his warlike but still\ndeferential cubs. In his own proper turn, each officer waited to be\nserved. They were as little children before Ahab; and yet, in Ahab,\nthere seemed not to lu", "labels": {"50": 22, "100": 64, "250": 70, "500": 178, "1000": 531, "2000": 110}}, {"id": 2319, "position": 2319, "text": "Ahab; and yet, in Ahab,\nthere seemed not to lurk the smallest social arrogance. With one mind,\ntheir intent eyes all fastened upon the old man’s knife, as he carved\nthe chief dish before him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2320, "position": 2320, "text": "s knife, as he carved\nthe chief dish before him. I do not suppose that for the world they\nwould have profaned that moment with the slightest observation, even\nupon so neutral a topic as the weather", "labels": {"50": 31, "100": 7, "250": 193, "500": 202, "1000": 858, "2000": 371}}, {"id": 2321, "position": 2321, "text": "so neutral a topic as the weather. No! And when reaching out his\nknife and fork, between which the slice of beef was locked, Ahab\nthereby motioned Starbuck’s plate towards him, the mate received his\nmeat as though receiving alms", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2322, "position": 2322, "text": "s plate towards him, the mate received his\nmeat as though receiving alms; and cut it tenderly; and a little\nstarted if, perchance, the knife grazed against the plate; and chewed\nit noiselessly; and swallowed it, not without ci", "labels": {"50": 45, "100": 26, "250": 30, "500": 73, "1000": 345, "2000": 967}}, {"id": 2323, "position": 2323, "text": "plate; and chewed\nit noiselessly; and swallowed it, not without circumspection. For, like\nthe Coronation banquet at Frankfort, where the German Emperor\nprofoundly dines with the seven Imperial Electors, so these cabin meals\nwere somehow solemn", "labels": {"50": 23, "100": 59, "250": 189, "500": 16, "1000": 364, "2000": 1592}}, {"id": 2324, "position": 2324, "text": "dines with the seven Imperial Electors, so these cabin meals\nwere somehow solemn meals, eaten in awful silence; and yet at table old\nAhab forbade not conversation; only he himself was dumb. What a relief\nit was to choking Stubb, when", "labels": {"50": 30, "100": 87, "250": 231, "500": 300, "1000": 235, "2000": 1494}}, {"id": 2325, "position": 2325, "text": "himself was dumb. What a relief\nit was to choking Stubb, when a rat made a sudden racket in the hold\nbelow. And poor little Flask, he was the youngest son, and little boy\nof this weary family party", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 2326, "position": 2326, "text": "the youngest son, and little boy\nof this weary family party. His were the shinbones of the saline beef;\nhis would have been the drumsticks. For Flask to have presumed to help\nhimself, this must have seemed to him tan", "labels": {"50": 22, "100": 88, "250": 70, "500": 202, "1000": 858, "2000": 110}}, {"id": 2327, "position": 2327, "text": "ask to have presumed to help\nhimself, this must have seemed to him tantamount to larceny in the\nfirst degree. Had he helped himself at that table, doubtless, never\nmore would he have been able to hold his head up in", "labels": {"50": 39, "100": 99, "250": 174, "500": 100, "1000": 367, "2000": 274}}, {"id": 2328, "position": 2328, "text": "less, never\nmore would he have been able to hold his head up in this honest world;\nnevertheless, strange to say, Ahab never forbade him. And had Flask\nhelped himself, the chances were Ahab had never so much as noticed it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2329, "position": 2329, "text": "helped himself, the chances were Ahab had never so much as noticed it.\nLeast of all, did Flask presume to help himself to butter. Whether he\nthought the owners of the ship denied it to him, on account of its\nclotti", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2330, "position": 2330, "text": "owners of the ship denied it to him, on account of its\nclotting his clear, sunny complexion; or whether he deemed that, on so\nlong a voyage in such marketless waters, butter was at a premium, and\ntherefore was not for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 364, "2000": 1620}}, {"id": 2331, "position": 2331, "text": "marketless waters, butter was at a premium, and\ntherefore was not for him, a subaltern; however it was, Flask, alas!\nwas a butterless man!\n\nAnother thing. Flask was the last person down at the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 2332, "position": 2332, "text": "less man!\n\nAnother thing. Flask was the last person down at the dinner, and Flask\nis the first man up. Consider! For hereby Flask’s dinner was badly\njammed in point of time", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2333, "position": 2333, "text": "dinner was badly\njammed in point of time. Starbuck and Stubb both had the start of him;\nand yet they also have the privilege of lounging in the rear. If Stubb\neven, who is but a peg higher than Flask,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2334, "position": 2334, "text": "If Stubb\neven, who is but a peg higher than Flask, happens to have but a small\nappetite, and soon shows symptoms of concluding his repast, then Flask\nmust bestir himself, he will not get more than three mouthfuls", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2335, "position": 2335, "text": "ask\nmust bestir himself, he will not get more than three mouthfuls that\nday; for it is against holy usage for Stubb to precede Flask to the\ndeck. Therefore it was that Flask once admitted in private, that ever\nsince", "labels": {"50": 42, "100": 59, "250": 10, "500": 16, "1000": 364, "2000": 1592}}, {"id": 2336, "position": 2336, "text": ". Therefore it was that Flask once admitted in private, that ever\nsince he had arisen to the dignity of an officer, from that moment he\nhad never known what it was to be otherwise than hungry, more or less", "labels": {"50": 23, "100": 88, "250": 219, "500": 404, "1000": 858, "2000": 1716}}, {"id": 2337, "position": 2337, "text": "was to be otherwise than hungry, more or less.\nFor what he ate did not so much relieve his hunger, as keep it immortal\nin him. Peace and satisfaction, thought Flask, have for ever departed\nfrom my stomach", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2338, "position": 2338, "text": "Flask, have for ever departed\nfrom my stomach. I am an officer; but, how I wish I could fish a bit of\nold-fashioned beef in the forecastle, as I used to when I was before\nthe mast", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 2339, "position": 2339, "text": ", as I used to when I was before\nthe mast. There’s the fruits of promotion now; there’s the vanity of\nglory: there’s the insanity of life! Besides, if it were so that any\nmere sailor of the Pe", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 1773}}, {"id": 2340, "position": 2340, "text": "life! Besides, if it were so that any\nmere sailor of the Pequod had a grudge against Flask in Flask’s\nofficial capacity, all that sailor had to do, in order to obtain ample\nvengeance, was to go aft", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2341, "position": 2341, "text": "had to do, in order to obtain ample\nvengeance, was to go aft at dinner-time, and get a peep at Flask\nthrough the cabin sky-light, sitting silly and dumfoundered before\nawful Ahab.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2342, "position": 2342, "text": "sitting silly and dumfoundered before\nawful Ahab.\n\nNow, Ahab and his three mates formed what may be called the first table\nin the Pequod’s cabin. After their departure, taking place in inverted\norder to their arrival", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2343, "position": 2343, "text": "s cabin. After their departure, taking place in inverted\norder to their arrival, the canvas cloth was cleared, or rather was\nrestored to some hurried order by the pallid steward. And then the\nthree harpooneers were bidden to the feast,", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 2344, "position": 2344, "text": ". And then the\nthree harpooneers were bidden to the feast, they being its residuary\nlegatees. They made a sort of temporary servants’ hall of the high and\nmighty cabin.", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 531, "2000": 1620}}, {"id": 2345, "position": 2345, "text": "the high and\nmighty cabin.\n\nIn strange contrast to the hardly tolerable constraint and nameless\ninvisible domineerings of the captain’s table, was the entire care-free\nlicense and ease, the almost frantic democracy of those inferior\nfellows the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 887}}, {"id": 2346, "position": 2346, "text": "-free\nlicense and ease, the almost frantic democracy of those inferior\nfellows the harpooneers. While their masters, the mates, seemed afraid\nof the sound of the hinges of their own jaws, the harpooneers chewed\ntheir food with such a re", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2347, "position": 2347, "text": "their own jaws, the harpooneers chewed\ntheir food with such a relish that there was a report to it. They dined\nlike lords; they filled their bellies like Indian ships all day loading\nwith spices", "labels": {"50": 45, "100": 29, "250": 161, "500": 13, "1000": 730, "2000": 1814}}, {"id": 2348, "position": 2348, "text": "like Indian ships all day loading\nwith spices. Such portentous appetites had Queequeg and Tashtego, that\nto fill out the vacancies made by the previous repast, often the pale\nDough-Boy was fain", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2349, "position": 2349, "text": "by the previous repast, often the pale\nDough-Boy was fain to bring on a great baron of salt-junk, seemingly\nquarried out of the solid ox. And if he were not lively about it, if he\ndid not go", "labels": {"50": 31, "100": 75, "250": 30, "500": 307, "1000": 343, "2000": 374}}, {"id": 2350, "position": 2350, "text": ". And if he were not lively about it, if he\ndid not go with a nimble hop-skip-and-jump, then Tashtego had an\nungentlemanly way of accelerating him by darting a fork at his back", "labels": {"50": 18, "100": 15, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 2351, "position": 2351, "text": "gentlemanly way of accelerating him by darting a fork at his back,\nharpoon-wise. And once Daggoo, seized with a sudden humor, assisted\nDough-Boy’s memory by snatching him up bodily, and thrusting his", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 531, "2000": 1620}}, {"id": 2352, "position": 2352, "text": "-Boy’s memory by snatching him up bodily, and thrusting his head\ninto a great empty wooden trencher, while Tashtego, knife in hand,\nbegan laying out the circle preliminary to scalping him", "labels": {"50": 37, "100": 55, "250": 145, "500": 389, "1000": 661, "2000": 314}}, {"id": 2353, "position": 2353, "text": "laying out the circle preliminary to scalping him. He was\nnaturally a very nervous, shuddering sort of little fellow, this\nbread-faced steward; the progeny of a bankrupt baker and a hospital\nnurse. And what with the standing spectacle of the black", "labels": {"50": 23, "100": 88, "250": 70, "500": 202, "1000": 660, "2000": 110}}, {"id": 2354, "position": 2354, "text": "baker and a hospital\nnurse. And what with the standing spectacle of the black terrific Ahab,\nand the periodical tumultuous visitations of these three savages,\nDough-Boy’s whole life was one continual lip-quiver", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2355, "position": 2355, "text": "-Boy’s whole life was one continual lip-quiver. Commonly, after\nseeing the harpooneers furnished with all things they demanded, he\nwould escape from their clutches into his little pantry adjoining, and\nfearfully peep out at them through the", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2356, "position": 2356, "text": "his little pantry adjoining, and\nfearfully peep out at them through the blinds of its door, till all was\nover.\n\nIt was a sight to see Queequeg seated over against Tashtego, opposing\nhis filed teeth to the Indian", "labels": {"50": 41, "100": 64, "250": 138, "500": 72, "1000": 965, "2000": 1620}}, {"id": 2357, "position": 2357, "text": "seated over against Tashtego, opposing\nhis filed teeth to the Indian’s: crosswise to them, Daggoo seated on\nthe floor, for a bench would have brought his hearse-plumed head to the\nlow carlines;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 2358, "position": 2358, "text": "have brought his hearse-plumed head to the\nlow carlines; at every motion of his colossal limbs, making the low\ncabin framework to shake, as when an African elephant goes passenger in\na ship", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2359, "position": 2359, "text": "elephant goes passenger in\na ship. But for all this, the great negro was wonderfully abstemious,\nnot to say dainty. It seemed hardly possible that by such comparatively\nsmall mouthfuls he could keep up the vitality diffused through so", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 531, "2000": 783}}, {"id": 2360, "position": 2360, "text": "comparatively\nsmall mouthfuls he could keep up the vitality diffused through so\nbroad, baronial, and superb a person. But, doubtless, this noble savage\nfed strong and drank deep of the abounding element of air; and through\nhis", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 317, "2000": 1087}}, {"id": 2361, "position": 2361, "text": "and drank deep of the abounding element of air; and through\nhis dilated nostrils snuffed in the sublime life of the worlds. Not by\nbeef or by bread, are giants made or nourished", "labels": {"50": 3, "100": 70, "250": 46, "500": 102, "1000": 109, "2000": 1374}}, {"id": 2362, "position": 2362, "text": ", are giants made or nourished. But Queequeg, he had a\nmortal, barbaric smack of the lip in eating—an ugly sound enough—so\nmuch so, that the trembling Dough-Boy almost looked to see whether", "labels": {"50": 22, "100": 88, "250": 219, "500": 202, "1000": 858, "2000": 110}}, {"id": 2363, "position": 2363, "text": "so\nmuch so, that the trembling Dough-Boy almost looked to see whether any\nmarks of teeth lurked in his own lean arms. And when he would hear\nTashtego singing out for him to produce himself, that his bones might\nbe picked", "labels": {"50": 22, "100": 77, "250": 39, "500": 178, "1000": 992, "2000": 144}}, {"id": 2364, "position": 2364, "text": "go singing out for him to produce himself, that his bones might\nbe picked, the simple-witted steward all but shattered the crockery\nhanging round him in the pantry, by his sudden fits of the palsy", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 307, "2000": 1087}}, {"id": 2365, "position": 2365, "text": ", by his sudden fits of the palsy. Nor\ndid the whetstone which the harpooneers carried in their pockets, for\ntheir lances and other weapons; and with which whetstones, at dinner,\nthey would ostentatiously", "labels": {"50": 44, "100": 68, "250": 1, "500": 419, "1000": 681, "2000": 1978}}, {"id": 2366, "position": 2366, "text": "with which whetstones, at dinner,\nthey would ostentatiously sharpen their knives; that grating sound did\nnot at all tend to tranquillize poor Dough-Boy. How could he forget\nthat in his Island days, Que", "labels": {"50": 31, "100": 20, "250": 53, "500": 126, "1000": 727, "2000": 1107}}, {"id": 2367, "position": 2367, "text": "Dough-Boy. How could he forget\nthat in his Island days, Queequeg, for one, must certainly have been\nguilty of some murderous, convivial indiscretions. Alas! Dough-Boy!\nhard fares the white", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 2368, "position": 2368, "text": "iscretions. Alas! Dough-Boy!\nhard fares the white waiter who waits upon cannibals. Not a napkin\nshould he carry on his arm, but a buckler. In good time, though, to his\ngreat delight,", "labels": {"50": 31, "100": 7, "250": 49, "500": 16, "1000": 387, "2000": 1592}}, {"id": 2369, "position": 2369, "text": "a buckler. In good time, though, to his\ngreat delight, the three salt-sea warriors would rise and depart; to\nhis credulous, fable-mongering ears, all their martial bones jingling\nin them at every step", "labels": {"50": 48, "100": 78, "250": 53, "500": 162, "1000": 9, "2000": 682}}, {"id": 2370, "position": 2370, "text": "gering ears, all their martial bones jingling\nin them at every step, like Moorish scimetars in scabbards.\n\nBut, though these barbarians dined in the cabin, and nominally lived\nthere; still, being anything but se", "labels": {"50": 25, "100": 5, "250": 189, "500": 297, "1000": 728, "2000": 1171}}, {"id": 2371, "position": 2371, "text": "in the cabin, and nominally lived\nthere; still, being anything but sedentary in their habits, they were\nscarcely ever in it except at mealtimes, and just before sleeping-time,\nwhen they passed through it to their own peculiar quarters", "labels": {"50": 43, "100": 29, "250": 148, "500": 279, "1000": 190, "2000": 722}}, {"id": 2372, "position": 2372, "text": "before sleeping-time,\nwhen they passed through it to their own peculiar quarters.\n\nIn this one matter, Ahab seemed no exception to most American whale\ncaptains, who, as a set, rather incline to the opinion that by rights\nthe ship’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2373, "position": 2373, "text": "a set, rather incline to the opinion that by rights\nthe ship’s cabin belongs to them; and that it is by courtesy alone that\nanybody else is, at any time, permitted there. So that, in real truth,\nthe mates and harp", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 2374, "position": 2374, "text": ", permitted there. So that, in real truth,\nthe mates and harpooneers of the Pequod might more properly be said to\nhave lived out of the cabin than in it. For when they did enter it, it\nwas something as a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2375, "position": 2375, "text": "in it. For when they did enter it, it\nwas something as a street-door enters a house; turning inwards for a\nmoment, only to be turned out the next; and, as a permanent thing,\nresiding in the open air", "labels": {"50": 48, "100": 27, "250": 53, "500": 371, "1000": 777, "2000": 1623}}, {"id": 2376, "position": 2376, "text": "next; and, as a permanent thing,\nresiding in the open air. Nor did they lose much hereby; in the cabin\nwas no companionship; socially, Ahab was inaccessible. Though nominally\nincluded in the census of Christendom, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2377, "position": 2377, "text": "was inaccessible. Though nominally\nincluded in the census of Christendom, he was still an alien to it. He\nlived in the world, as the last of the Grisly Bears lived in settled\nMissouri", "labels": {"50": 44, "100": 57, "250": 191, "500": 151, "1000": 907, "2000": 954}}, {"id": 2378, "position": 2378, "text": "ly Bears lived in settled\nMissouri. And as when Spring and Summer had departed, that wild Logan\nof the woods, burying himself in the hollow of a tree, lived out the\nwinter there, sucking his own paws; so, in his inclement", "labels": {"50": 12, "100": 38, "250": 65, "500": 171, "1000": 586, "2000": 1720}}, {"id": 2379, "position": 2379, "text": "winter there, sucking his own paws; so, in his inclement, howling old\nage, Ahab’s soul, shut up in the caved trunk of his body, there fed\nupon the sullen paws of its gloom!\n\n\nCHAPTER 35", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2380, "position": 2380, "text": "body, there fed\nupon the sullen paws of its gloom!\n\n\nCHAPTER 35. The Mast-Head.\n\nIt was during the more pleasant weather, that in due rotation with the\nother seamen my first mast-head came round.", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 851, "2000": 1192}}, {"id": 2381, "position": 2381, "text": "other seamen my first mast-head came round.\n\nIn most American whalemen the mast-heads are manned almost\nsimultaneously with the vessel’s leaving her port; even though she may\nhave fifteen thousand miles, and more, to sail ere reaching her", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2382, "position": 2382, "text": "may\nhave fifteen thousand miles, and more, to sail ere reaching her proper\ncruising ground. And if, after a three, four, or five years’ voyage she\nis drawing nigh home with anything empty in her—say, an empty vial", "labels": {"50": 45, "100": 20, "250": 138, "500": 162, "1000": 327, "2000": 887}}, {"id": 2383, "position": 2383, "text": "drawing nigh home with anything empty in her—say, an empty vial\neven—then, her mast-heads are kept manned to the last; and not till her\nskysail-poles sail in among the spires of the port, does", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 16}}, {"id": 2384, "position": 2384, "text": "sail-poles sail in among the spires of the port, does she altogether\nrelinquish the hope of capturing one whale more.\n\nNow, as the business of standing mast-heads, ashore or afloat, is a\nvery ancient and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2385, "position": 2385, "text": "standing mast-heads, ashore or afloat, is a\nvery ancient and interesting one, let us in some measure expatiate\nhere. I take it, that the earliest standers of mast-heads were the old\nEgyptians; because, in all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2386, "position": 2386, "text": "standers of mast-heads were the old\nEgyptians; because, in all my researches, I find none prior to them.\nFor though their progenitors, the builders of Babel, must doubtless, by\ntheir tower, have intended to rear", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2387, "position": 2387, "text": "Babel, must doubtless, by\ntheir tower, have intended to rear the loftiest mast-head in all Asia,\nor Africa either; yet (ere the final truck was put to it) as that great\nstone mast of theirs may be", "labels": {"50": 26, "100": 54, "250": 30, "500": 307, "1000": 343, "2000": 761}}, {"id": 2388, "position": 2388, "text": "truck was put to it) as that great\nstone mast of theirs may be said to have gone by the board, in the\ndread gale of God’s wrath; therefore, we cannot give these Babel\nbuilders priority over the Egyptians", "labels": {"50": 32, "100": 33, "250": 194, "500": 135, "1000": 677, "2000": 253}}, {"id": 2389, "position": 2389, "text": "we cannot give these Babel\nbuilders priority over the Egyptians. And that the Egyptians were a\nnation of mast-head standers, is an assertion based upon the general\nbelief among archæologists, that the first pyramids were founded for\nastronomical purposes:", "labels": {"50": 32, "100": 66, "250": 211, "500": 490, "1000": 677, "2000": 1821}}, {"id": 2390, "position": 2390, "text": "archæologists, that the first pyramids were founded for\nastronomical purposes: a theory singularly supported by the peculiar\nstair-like formation of all four sides of those edifices; whereby, with\nprodigious long upliftings of their", "labels": {"50": 5, "100": 66, "250": 249, "500": 77, "1000": 384, "2000": 147}}, {"id": 2391, "position": 2391, "text": "s; whereby, with\nprodigious long upliftings of their legs, those old astronomers were\nwont to mount to the apex, and sing out for new stars; even as the\nlook-outs of a modern ship sing out for a", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 2392, "position": 2392, "text": "; even as the\nlook-outs of a modern ship sing out for a sail, or a whale just bearing\nin sight. In Saint Stylites, the famous Christian hermit of old times,\nwho built him a lofty stone pillar in the desert", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 2393, "position": 2393, "text": "of old times,\nwho built him a lofty stone pillar in the desert and spent the whole\nlatter portion of his life on its summit, hoisting his food from the\nground with a tackle; in him we have a remarkable instance of a\nda", "labels": {"50": 48, "100": 27, "250": 59, "500": 304, "1000": 689, "2000": 775}}, {"id": 2394, "position": 2394, "text": "ground with a tackle; in him we have a remarkable instance of a\ndauntless stander-of-mast-heads; who was not to be driven from his\nplace by fogs or frosts, rain, hail, or sleet;", "labels": {"50": 44, "100": 86, "250": 70, "500": 202, "1000": 858, "2000": 110}}, {"id": 2395, "position": 2395, "text": "by fogs or frosts, rain, hail, or sleet; but valiantly facing\neverything out to the last, literally died at his post. Of modern\nstanders-of-mast-heads we have but a lifeless set; mere stone", "labels": {"50": 31, "100": 20, "250": 193, "500": 126, "1000": 343, "2000": 24}}, {"id": 2396, "position": 2396, "text": "-of-mast-heads we have but a lifeless set; mere stone, iron,\nand bronze men; who, though well capable of facing out a stiff gale,\nare still entirely incompetent to the business of singing out upon\ndiscovering any", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 2397, "position": 2397, "text": "still entirely incompetent to the business of singing out upon\ndiscovering any strange sight. There is Napoleon; who, upon the top of\nthe column of Vendome, stands with arms folded, some one hundred and\nfifty feet in the air;", "labels": {"50": 1, "100": 53, "250": 128, "500": 415, "1000": 799, "2000": 298}}, {"id": 2398, "position": 2398, "text": "stands with arms folded, some one hundred and\nfifty feet in the air; careless, now, who rules the decks below;\nwhether Louis Philippe, Louis Blanc, or Louis the Devil. Great\nWashington, too, stands high aloft on his towering main", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 2399, "position": 2399, "text": "Devil. Great\nWashington, too, stands high aloft on his towering main-mast in\nBaltimore, and like one of Hercules’ pillars, his column marks that\npoint of human grandeur beyond which few mortals will go", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 2400, "position": 2400, "text": "grandeur beyond which few mortals will go. Admiral\nNelson, also, on a capstan of gun-metal, stands his mast-head in\nTrafalgar Square; and ever when most obscured by that London smoke,\ntoken is yet given that", "labels": {"50": 48, "100": 27, "250": 157, "500": 223, "1000": 542, "2000": 532}}, {"id": 2401, "position": 2401, "text": "and ever when most obscured by that London smoke,\ntoken is yet given that a hidden hero is there; for where there is\nsmoke, must be fire. But neither great Washington, nor Napoleon, nor\nNelson, will answer a single hail from below,", "labels": {"50": 45, "100": 64, "250": 193, "500": 73, "1000": 851, "2000": 967}}, {"id": 2402, "position": 2402, "text": ", nor Napoleon, nor\nNelson, will answer a single hail from below, however madly invoked to\nbefriend by their counsels the distracted decks upon which they gaze;\nhowever it may be surmised, that their spirits penetrate through the\nthick", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 2403, "position": 2403, "text": "however it may be surmised, that their spirits penetrate through the\nthick haze of the future, and descry what shoals and what rocks must be\nshunned.\n\nIt may seem unwarrantable to couple in any respect the mast", "labels": {"50": 31, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 1620}}, {"id": 2404, "position": 2404, "text": ".\n\nIt may seem unwarrantable to couple in any respect the mast-head\nstanders of the land with those of the sea; but that in truth it is not\nso, is plainly evinced by an item for which Obed Macy", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 2405, "position": 2405, "text": "so, is plainly evinced by an item for which Obed Macy, the sole\nhistorian of Nantucket, stands accountable. The worthy Obed tells us,\nthat in the early times of the whale fishery, ere ships were regularly\nlaunched in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2406, "position": 2406, "text": "the early times of the whale fishery, ere ships were regularly\nlaunched in pursuit of the game, the people of that island erected\nlofty spars along the sea-coast, to which the look-outs ascended by\nmeans of nailed cleats", "labels": {"50": 48, "100": 31, "250": 53, "500": 223, "1000": 282, "2000": 1650}}, {"id": 2407, "position": 2407, "text": ", to which the look-outs ascended by\nmeans of nailed cleats, something as fowls go upstairs in a hen-house.\nA few years ago this same plan was adopted by the Bay whalemen of New\nZealand, who, upon", "labels": {"50": 45, "100": 24, "250": 213, "500": 288, "1000": 161, "2000": 1905}}, {"id": 2408, "position": 2408, "text": "plan was adopted by the Bay whalemen of New\nZealand, who, upon descrying the game, gave notice to the ready-manned\nboats nigh the beach. But this custom has now become obsolete; turn we\nthen to the one proper mast", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 480, "2000": 1620}}, {"id": 2409, "position": 2409, "text": "this custom has now become obsolete; turn we\nthen to the one proper mast-head, that of a whale-ship at sea. The\nthree mast-heads are kept manned from sun-rise to sun-set; the seamen\ntaking their regular turns", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2410, "position": 2410, "text": "from sun-rise to sun-set; the seamen\ntaking their regular turns (as at the helm), and relieving each other\nevery two hours. In the serene weather of the tropics it is exceedingly\npleasant the mast-head", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 2411, "position": 2411, "text": "weather of the tropics it is exceedingly\npleasant the mast-head; nay, to a dreamy meditative man it is\ndelightful. There you stand, a hundred feet above the silent decks,\nstriding along the deep, as if the", "labels": {"50": 45, "100": 20, "250": 138, "500": 494, "1000": 480, "2000": 187}}, {"id": 2412, "position": 2412, "text": "feet above the silent decks,\nstriding along the deep, as if the masts were gigantic stilts, while\nbeneath you and between your legs, as it were, swim the hugest monsters\nof the sea, even as ships once sailed between the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 887}}, {"id": 2413, "position": 2413, "text": "the hugest monsters\nof the sea, even as ships once sailed between the boots of the famous\nColossus at old Rhodes. There you stand, lost in the infinite series of\nthe sea, with nothing ruffled but the waves", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2414, "position": 2414, "text": "of\nthe sea, with nothing ruffled but the waves. The tranced ship\nindolently rolls; the drowsy trade winds blow; everything resolves you\ninto languor. For the most part, in this tropic whaling life", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2415, "position": 2415, "text": "uor. For the most part, in this tropic whaling life, a sublime\nuneventfulness invests you; you hear no news; read no gazettes; extras\nwith startling accounts of commonplaces never delude you into\nunnecessary excitement", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 480, "2000": 887}}, {"id": 2416, "position": 2416, "text": "; extras\nwith startling accounts of commonplaces never delude you into\nunnecessary excitements; you hear of no domestic afflictions; bankrupt\nsecurities; fall of stocks; are never troubled with the thought of what\nyou shall have for dinner—for all your", "labels": {"50": 31, "100": 7, "250": 159, "500": 274, "1000": 203, "2000": 962}}, {"id": 2417, "position": 2417, "text": "troubled with the thought of what\nyou shall have for dinner—for all your meals for three years and more\nare snugly stowed in casks, and your bill of fare is immutable.", "labels": {"50": 31, "100": 7, "250": 159, "500": 16, "1000": 364, "2000": 1592}}, {"id": 2418, "position": 2418, "text": "fare is immutable.\n\nIn one of those southern whalesmen, on a long three or four years’\nvoyage, as often happens, the sum of the various hours you spend at the\nmast-head would amount to several entire months", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2419, "position": 2419, "text": "spend at the\nmast-head would amount to several entire months. And it is much to be\ndeplored that the place to which you devote so considerable a portion\nof the whole term of your natural life, should be so sadly destitute of", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 732, "2000": 1584}}, {"id": 2420, "position": 2420, "text": "whole term of your natural life, should be so sadly destitute of\nanything approaching to a cosy inhabitiveness, or adapted to breed a\ncomfortable localness of feeling, such as pertains to a bed, a hammock,", "labels": {"50": 48, "100": 20, "250": 90, "500": 126, "1000": 727, "2000": 24}}, {"id": 2421, "position": 2421, "text": ", such as pertains to a bed, a hammock,\na hearse, a sentry box, a pulpit, a coach, or any other of those small\nand snug contrivances in which men temporarily isolate themselves", "labels": {"50": 31, "100": 7, "250": 159, "500": 37, "1000": 387, "2000": 880}}, {"id": 2422, "position": 2422, "text": "small\nand snug contrivances in which men temporarily isolate themselves. Your\nmost usual point of perch is the head of the t’ gallant-mast, where you\nstand upon two thin parallel sticks (almost peculiar to whalemen)\ncalled the t", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2423, "position": 2423, "text": "upon two thin parallel sticks (almost peculiar to whalemen)\ncalled the t’ gallant cross-trees. Here, tossed about by the sea, the\nbeginner feels about as cosy as he would standing on a bull’s horns", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2424, "position": 2424, "text": "cosy as he would standing on a bull’s horns. To\nbe sure, in cold weather you may carry your house aloft with you, in\nthe shape of a watch-coat; but properly speaking the thickest\nwatch-coat is no", "labels": {"50": 31, "100": 7, "250": 159, "500": 247, "1000": 199, "2000": 880}}, {"id": 2425, "position": 2425, "text": "watch-coat; but properly speaking the thickest\nwatch-coat is no more of a house than the unclad body; for as the soul\nis glued inside of its fleshy tabernacle, and cannot freely move about\nin it, nor", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2426, "position": 2426, "text": "fleshy tabernacle, and cannot freely move about\nin it, nor even move out of it, without running great risk of perishing\n(like an ignorant pilgrim crossing the snowy Alps in winter); so a\nwatch-coat is not so much", "labels": {"50": 31, "100": 7, "250": 159, "500": 247, "1000": 199, "2000": 1294}}, {"id": 2427, "position": 2427, "text": "snowy Alps in winter); so a\nwatch-coat is not so much of a house as it is a mere envelope, or\nadditional skin encasing you. You cannot put a shelf or chest of\ndrawers in your body, and no more can", "labels": {"50": 31, "100": 7, "250": 159, "500": 247, "1000": 199, "2000": 880}}, {"id": 2428, "position": 2428, "text": "put a shelf or chest of\ndrawers in your body, and no more can you make a convenient closet of\nyour watch-coat.\n\nConcerning all this, it is much to be deplored that the mast-heads of a\nsouthern whale ship are un", "labels": {"50": 45, "100": 7, "250": 138, "500": 247, "1000": 199, "2000": 1620}}, {"id": 2429, "position": 2429, "text": "deplored that the mast-heads of a\nsouthern whale ship are unprovided with those enviable little tents or\npulpits, called _crow’s-nests_, in which the look-outs of a Greenland\nwhaler are", "labels": {"50": 48, "100": 27, "250": 249, "500": 247, "1000": 542, "2000": 1633}}, {"id": 2430, "position": 2430, "text": "nests_, in which the look-outs of a Greenland\nwhaler are protected from the inclement weather of the frozen seas. In\nthe fireside narrative of Captain Sleet, entitled “A Voyage among the\nIcebergs, in quest of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2431, "position": 2431, "text": "eet, entitled “A Voyage among the\nIcebergs, in quest of the Greenland Whale, and incidentally for the\nre-discovery of the Lost Icelandic Colonies of Old Greenland;” in this\nadmirable volume, all standers of mast-", "labels": {"50": 45, "100": 29, "250": 34, "500": 13, "1000": 622, "2000": 1950}}, {"id": 2432, "position": 2432, "text": ";” in this\nadmirable volume, all standers of mast-heads are furnished with a\ncharmingly circumstantial account of the then recently invented\n_crow’s-nest_ of the Glacier, which was the name of Captain", "labels": {"50": 3, "100": 85, "250": 34, "500": 48, "1000": 956, "2000": 952}}, {"id": 2433, "position": 2433, "text": "’s-nest_ of the Glacier, which was the name of Captain Sleet’s\ngood craft. He called it the _Sleet’s crow’s-nest_, in honor of\nhimself; he being the original inventor and patent", "labels": {"50": 45, "100": 43, "250": 34, "500": 48, "1000": 997, "2000": 207}}, {"id": 2434, "position": 2434, "text": "nest_, in honor of\nhimself; he being the original inventor and patentee, and free from all\nridiculous false delicacy, and holding that if we call our own children\nafter our own names (we fathers being the original inventors and\npatent", "labels": {"50": 31, "100": 7, "250": 193, "500": 36, "1000": 849, "2000": 890}}, {"id": 2435, "position": 2435, "text": "children\nafter our own names (we fathers being the original inventors and\npatentees), so likewise should we denominate after ourselves any other\napparatus we may beget. In shape, the Sleet’s crow’s-nest is something", "labels": {"50": 31, "100": 20, "250": 13, "500": 126, "1000": 15, "2000": 1560}}, {"id": 2436, "position": 2436, "text": "In shape, the Sleet’s crow’s-nest is something\nlike a large tierce or pipe; it is open above, however, where it is\nfurnished with a movable side-screen to keep to windward of your head\nin", "labels": {"50": 31, "100": 7, "250": 49, "500": 78, "1000": 933, "2000": 1081}}, {"id": 2437, "position": 2437, "text": "a movable side-screen to keep to windward of your head\nin a hard gale. Being fixed on the summit of the mast, you ascend into\nit through a little trap-hatch in the bottom", "labels": {"50": 31, "100": 7, "250": 49, "500": 453, "1000": 387, "2000": 1081}}, {"id": 2438, "position": 2438, "text": "little trap-hatch in the bottom. On the after side, or\nside next the stern of the ship, is a comfortable seat, with a locker\nunderneath for umbrellas, comforters, and coats. In front is a leather\nrack, in which", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 887}}, {"id": 2439, "position": 2439, "text": "comforters, and coats. In front is a leather\nrack, in which to keep your speaking trumpet, pipe, telescope, and\nother nautical conveniences. When Captain Sleet in person stood his\nmast-head in this crow’s-nest of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 2440, "position": 2440, "text": "in person stood his\nmast-head in this crow’s-nest of his, he tells us that he always had a\nrifle with him (also fixed in the rack), together with a powder flask\nand shot, for the purpose of popping", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2441, "position": 2441, "text": ", together with a powder flask\nand shot, for the purpose of popping off the stray narwhales, or\nvagrant sea unicorns infesting those waters; for you cannot\nsuccessfully shoot at them from the deck owing to the resistance", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 2442, "position": 2442, "text": "; for you cannot\nsuccessfully shoot at them from the deck owing to the resistance of the\nwater, but to shoot down upon them is a very different thing. Now, it\nwas plainly a labor of love for Captain Sleet to describe, as he does", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 2443, "position": 2443, "text": "plainly a labor of love for Captain Sleet to describe, as he does,\nall the little detailed conveniences of his crow’s-nest; but though he\nso enlarges upon many of these, and though he treats us to a very", "labels": {"50": 45, "100": 64, "250": 138, "500": 48, "1000": 997, "2000": 1931}}, {"id": 2444, "position": 2444, "text": "larges upon many of these, and though he treats us to a very\nscientific account of his experiments in this crow’s-nest, with a small\ncompass he kept there for the purpose of counteracting the errors\nresulting from what is called the", "labels": {"50": 12, "100": 43, "250": 34, "500": 344, "1000": 222, "2000": 823}}, {"id": 2445, "position": 2445, "text": "for the purpose of counteracting the errors\nresulting from what is called the “local attraction” of all binnacle\nmagnets; an error ascribable to the horizontal vicinity of the iron in\nthe ship’s planks, and in", "labels": {"50": 45, "100": 63, "250": 152, "500": 206, "1000": 83, "2000": 735}}, {"id": 2446, "position": 2446, "text": "horizontal vicinity of the iron in\nthe ship’s planks, and in the Glacier’s case, perhaps, to there having\nbeen so many broken-down blacksmiths among her crew; I say, that though\nthe Captain is very discreet and scientific", "labels": {"50": 45, "100": 64, "250": 138, "500": 48, "1000": 723, "2000": 576}}, {"id": 2447, "position": 2447, "text": "her crew; I say, that though\nthe Captain is very discreet and scientific here, yet, for all his\nlearned “binnacle deviations,” “azimuth compass observations,” and\n“approximate errors,” he knows very well,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 877}}, {"id": 2448, "position": 2448, "text": "compass observations,” and\n“approximate errors,” he knows very well, Captain Sleet, that he was\nnot so much immersed in those profound magnetic meditations, as to fail\nbeing attracted occasionally towards that well replenished little\ncase-bottle,", "labels": {"50": 45, "100": 29, "250": 34, "500": 48, "1000": 327, "2000": 1692}}, {"id": 2449, "position": 2449, "text": "fail\nbeing attracted occasionally towards that well replenished little\ncase-bottle, so nicely tucked in on one side of his crow’s nest, within\neasy reach of his hand. Though, upon the whole, I greatly admire and\neven love the brave", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 462, "2000": 1702}}, {"id": 2450, "position": 2450, "text": ". Though, upon the whole, I greatly admire and\neven love the brave, the honest, and learned Captain; yet I take it\nvery ill of him that he should so utterly ignore that case-bottle,\nseeing what a faithful friend and comforter", "labels": {"50": 23, "100": 17, "250": 127, "500": 393, "1000": 710, "2000": 1933}}, {"id": 2451, "position": 2451, "text": "utterly ignore that case-bottle,\nseeing what a faithful friend and comforter it must have been, while\nwith mittened fingers and hooded head he was studying the mathematics\naloft there in that bird’s nest within three or four perches of", "labels": {"50": 37, "100": 24, "250": 213, "500": 331, "1000": 987, "2000": 72}}, {"id": 2452, "position": 2452, "text": "oft there in that bird’s nest within three or four perches of the\npole.\n\nBut if we Southern whale-fishers are not so snugly housed aloft as\nCaptain Sleet and his Greenlandmen were; yet that disadvantage is\ngreatly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2453, "position": 2453, "text": "as\nCaptain Sleet and his Greenlandmen were; yet that disadvantage is\ngreatly counter-balanced by the widely contrasting serenity of those\nseductive seas in which we South fishers mostly float. For one, I used\nto lounge up the rigging very leisure", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1192}}, {"id": 2454, "position": 2454, "text": "float. For one, I used\nto lounge up the rigging very leisurely, resting in the top to have a\nchat with Queequeg, or any one else off duty whom I might find there;\nthen ascending a little way further,", "labels": {"50": 25, "100": 28, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 2455, "position": 2455, "text": "off duty whom I might find there;\nthen ascending a little way further, and throwing a lazy leg over the\ntop-sail yard, take a preliminary view of the watery pastures, and so\nat last mount to my ultimate destination.", "labels": {"50": 48, "100": 20, "250": 138, "500": 162, "1000": 727, "2000": 682}}, {"id": 2456, "position": 2456, "text": ", and so\nat last mount to my ultimate destination.\n\nLet me make a clean breast of it here, and frankly admit that I kept\nbut sorry guard. With the problem of the universe revolving in me, how\ncould I—being left completely to myself", "labels": {"50": 20, "100": 5, "250": 45, "500": 411, "1000": 51, "2000": 1812}}, {"id": 2457, "position": 2457, "text": "the universe revolving in me, how\ncould I—being left completely to myself at such a thought-engendering\naltitude—how could I but lightly hold my obligations to observe all\nwhale-ships’ standing orders, “Keep your weather eye open,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2458, "position": 2458, "text": "all\nwhale-ships’ standing orders, “Keep your weather eye open, and sing out\nevery time.”\n\nAnd let me in this place movingly admonish you, ye ship-owners of\nNantucket! Beware of enlisting in your", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2459, "position": 2459, "text": "ye ship-owners of\nNantucket! Beware of enlisting in your vigilant fisheries any lad with\nlean brow and hollow eye; given to unseasonable meditativeness; and who\noffers to ship with the Phædon instead of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2460, "position": 2460, "text": "itativeness; and who\noffers to ship with the Phædon instead of Bowditch in his head. Beware\nof such an one, I say; your whales must be seen before they can be\nkilled; and this sunken-eyed young Plato", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2461, "position": 2461, "text": "be seen before they can be\nkilled; and this sunken-eyed young Platonist will tow you ten wakes\nround the world, and never make you one pint of sperm the richer. Nor\nare these monitions at all unneeded", "labels": {"50": 31, "100": 20, "250": 193, "500": 72, "1000": 692, "2000": 982}}, {"id": 2462, "position": 2462, "text": "richer. Nor\nare these monitions at all unneeded. For nowadays, the whale-fishery\nfurnishes an asylum for many romantic, melancholy, and absent-minded\nyoung men, disgusted with the carking cares of earth, and seeking", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2463, "position": 2463, "text": "minded\nyoung men, disgusted with the carking cares of earth, and seeking\nsentiment in tar and blubber. Childe Harold not unfrequently perches\nhimself upon the mast-head of some luckless disappointed whale-ship,\nand in", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 448, "2000": 958}}, {"id": 2464, "position": 2464, "text": "the mast-head of some luckless disappointed whale-ship,\nand in moody phrase ejaculates:—\n\n\n“Roll on, thou deep and dark blue ocean, roll! Ten thousand\nblubber-hunters sweep over thee in vain.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2465, "position": 2465, "text": "! Ten thousand\nblubber-hunters sweep over thee in vain.”\n\n\n\nVery often do the captains of such ships take those absent-minded young\nphilosophers to task, upbraiding them with not feeling sufficient\n“interest” in the voyage; half-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2466, "position": 2466, "text": "ng them with not feeling sufficient\n“interest” in the voyage; half-hinting that they are so hopelessly lost\nto all honorable ambition, as that in their secret souls they would\nrather not see whales than otherwise", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2467, "position": 2467, "text": "they would\nrather not see whales than otherwise. But all in vain; those young\nPlatonists have a notion that their vision is imperfect; they are\nshort-sighted; what use, then, to strain the visual nerve? They have\nleft their opera", "labels": {"50": 31, "100": 16, "250": 87, "500": 483, "1000": 100, "2000": 1916}}, {"id": 2468, "position": 2468, "text": "use, then, to strain the visual nerve? They have\nleft their opera-glasses at home.\n\n“Why, thou monkey,” said a harpooneer to one of these lads, “we’ve been\ncruising now hard upon three years,", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 531, "2000": 1668}}, {"id": 2469, "position": 2469, "text": "these lads, “we’ve been\ncruising now hard upon three years, and thou hast not raised a whale\nyet. Whales are scarce as hen’s teeth whenever thou art up here.”\nPerhaps they were; or perhaps there might have been", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2470, "position": 2470, "text": "art up here.”\nPerhaps they were; or perhaps there might have been shoals of them in\nthe far horizon; but lulled into such an opium-like listlessness of\nvacant, unconscious reverie is this absent-minded youth by the blending", "labels": {"50": 7, "100": 9, "250": 203, "500": 463, "1000": 142, "2000": 329}}, {"id": 2471, "position": 2471, "text": "of\nvacant, unconscious reverie is this absent-minded youth by the blending\ncadence of waves with thoughts, that at last he loses his identity;\ntakes the mystic ocean at his feet for the visible image of that deep,\nblue, bottomless soul,", "labels": {"50": 16, "100": 73, "250": 138, "500": 414, "1000": 9, "2000": 16}}, {"id": 2472, "position": 2472, "text": "feet for the visible image of that deep,\nblue, bottomless soul, pervading mankind and nature; and every strange,\nhalf-seen, gliding, beautiful thing that eludes him; every\ndimly-discovered, uprising fin of some undis", "labels": {"50": 22, "100": 78, "250": 229, "500": 401, "1000": 473, "2000": 849}}, {"id": 2473, "position": 2473, "text": "eludes him; every\ndimly-discovered, uprising fin of some undiscernible form, seems to him\nthe embodiment of those elusive thoughts that only people the soul by\ncontinually flitting through it", "labels": {"50": 10, "100": 75, "250": 129, "500": 236, "1000": 368, "2000": 710}}, {"id": 2474, "position": 2474, "text": "soul by\ncontinually flitting through it. In this enchanted mood, thy spirit\nebbs away to whence it came; becomes diffused through time and space;\nlike Cranmer’s sprinkled Pantheistic ashes, forming at last", "labels": {"50": 9, "100": 73, "250": 141, "500": 414, "1000": 548, "2000": 1859}}, {"id": 2475, "position": 2475, "text": "anmer’s sprinkled Pantheistic ashes, forming at last a part of\nevery shore the round globe over.\n\nThere is no life in thee, now, except that rocking life imparted by a\ngently rolling ship; by her,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 2476, "position": 2476, "text": "that rocking life imparted by a\ngently rolling ship; by her, borrowed from the sea; by the sea, from\nthe inscrutable tides of God. But while this sleep, this dream is on\nye, move your foot or hand an", "labels": {"50": 16, "100": 73, "250": 13, "500": 414, "1000": 747, "2000": 709}}, {"id": 2477, "position": 2477, "text": "this sleep, this dream is on\nye, move your foot or hand an inch; slip your hold at all; and your\nidentity comes back in horror. Over Descartian vortices you hover", "labels": {"50": 10, "100": 71, "250": 13, "500": 236, "1000": 15, "2000": 1050}}, {"id": 2478, "position": 2478, "text": "vortices you hover. And\nperhaps, at mid-day, in the fairest weather, with one half-throttled\nshriek you drop through that transparent air into the summer sea, no\nmore to rise for ever", "labels": {"50": 31, "100": 20, "250": 49, "500": 334, "1000": 747, "2000": 1710}}, {"id": 2479, "position": 2479, "text": "the summer sea, no\nmore to rise for ever. Heed it well, ye Pantheists!\n\n\nCHAPTER 36. The Quarter-Deck.\n\n(_Enter Ahab: Then, all._)", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2480, "position": 2480, "text": "Then, all._)\n\nIt was not a great while after the affair of the pipe, that one morning\nshortly after breakfast, Ahab, as was his wont, ascended the\ncabin-gangway to the deck", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2481, "position": 2481, "text": "ascended the\ncabin-gangway to the deck. There most sea-captains usually walk at that\nhour, as country gentlemen, after the same meal, take a few turns in\nthe garden.\n\nSoon his steady, ivory stride was heard, as to and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 2482, "position": 2482, "text": "the garden.\n\nSoon his steady, ivory stride was heard, as to and fro he paced his old\nrounds, upon planks so familiar to his tread, that they were all over\ndented, like geological stones, with the peculiar mark of his", "labels": {"50": 22, "100": 78, "250": 53, "500": 286, "1000": 631, "2000": 1027}}, {"id": 2483, "position": 2483, "text": "all over\ndented, like geological stones, with the peculiar mark of his walk. Did\nyou fixedly gaze, too, upon that ribbed and dented brow; there also,\nyou would see still stranger foot-prints—the foot-prints", "labels": {"50": 22, "100": 78, "250": 229, "500": 469, "1000": 631, "2000": 1027}}, {"id": 2484, "position": 2484, "text": "also,\nyou would see still stranger foot-prints—the foot-prints of his one\nunsleeping, ever-pacing thought.\n\nBut on the occasion in question, those dents looked deeper, even as his\nnervous step that morning left a", "labels": {"50": 22, "100": 78, "250": 229, "500": 286, "1000": 631, "2000": 1723}}, {"id": 2485, "position": 2485, "text": "those dents looked deeper, even as his\nnervous step that morning left a deeper mark. And, so full of his\nthought was Ahab, that at every uniform turn that he made, now at the\nmain-mast and now at the binnac", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2486, "position": 2486, "text": "he made, now at the\nmain-mast and now at the binnacle, you could almost see that thought\nturn in him as he turned, and pace in him as he paced; so completely\npossessing him, indeed, that it all but seemed", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 2487, "position": 2487, "text": "he paced; so completely\npossessing him, indeed, that it all but seemed the inward mould of\nevery outer movement.\n\n“D’ye mark him, Flask?” whispered Stubb; “the chick that’s in him pecks\nthe", "labels": {"50": 9, "100": 26, "250": 133, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2488, "position": 2488, "text": "whispered Stubb; “the chick that’s in him pecks\nthe shell. ’Twill soon be out.”\n\nThe hours wore on;—Ahab now shut up within his cabin; anon, pacing the\ndeck, with the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2489, "position": 2489, "text": "shut up within his cabin; anon, pacing the\ndeck, with the same intense bigotry of purpose in his aspect.\n\nIt drew near the close of day. Suddenly he came to a halt by the\nbulwarks, and inserting", "labels": {"50": 22, "100": 64, "250": 19, "500": 73, "1000": 808, "2000": 1852}}, {"id": 2490, "position": 2490, "text": "he came to a halt by the\nbulwarks, and inserting his bone leg into the auger-hole there, and\nwith one hand grasping a shroud, he ordered Starbuck to send everybody\naft.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2491, "position": 2491, "text": "he ordered Starbuck to send everybody\naft.\n\n“Sir!” said the mate, astonished at an order seldom or never given on\nship-board except in some extraordinary case.\n\n“Send everybody aft,” repeated Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2492, "position": 2492, "text": "“Send everybody aft,” repeated Ahab. “Mast-heads, there! come down!”\n\nWhen the entire ship’s company were assembled, and with curious and not\nwholly unapprehensive faces, were eyeing him, for he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2493, "position": 2493, "text": "not\nwholly unapprehensive faces, were eyeing him, for he looked not unlike\nthe weather horizon when a storm is coming up, Ahab, after rapidly\nglancing over the bulwarks, and then darting his eyes among the crew,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2494, "position": 2494, "text": "the bulwarks, and then darting his eyes among the crew,\nstarted from his standpoint; and as though not a soul were nigh him\nresumed his heavy turns upon the deck. With bent head and half-slouched\nhat he", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2495, "position": 2495, "text": "upon the deck. With bent head and half-slouched\nhat he continued to pace, unmindful of the wondering whispering among\nthe men; till Stubb cautiously whispered to Flask, that Ahab must have\nsummoned them there for the purpose", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2496, "position": 2496, "text": "to Flask, that Ahab must have\nsummoned them there for the purpose of witnessing a pedestrian feat.\nBut this did not last long. Vehemently pausing, he cried:—\n\n“What do ye do when ye see a whale, men?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2497, "position": 2497, "text": ":—\n\n“What do ye do when ye see a whale, men?”\n\n“Sing out for him!” was the impulsive rejoinder from a score of clubbed\nvoices.\n\n“Good!” cried Ahab, with a wild approval in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2498, "position": 2498, "text": "voices.\n\n“Good!” cried Ahab, with a wild approval in his tones; observing the\nhearty animation into which his unexpected question had so magnetically\nthrown them.\n\n“And what do ye next, men?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2499, "position": 2499, "text": "“And what do ye next, men?”\n\n“Lower away, and after him!”\n\n“And what tune is it ye pull to, men?”\n\n“A dead whale or a stove boat!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2500, "position": 2500, "text": "whale or a stove boat!”\n\nMore and more strangely and fiercely glad and approving, grew the\ncountenance of the old man at every shout; while the mariners began to\ngaze curiously at each other, as if marvelling how it was that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2501, "position": 2501, "text": "to\ngaze curiously at each other, as if marvelling how it was that they\nthemselves became so excited at such seemingly purposeless questions.\n\nBut, they were all eagerness again, as Ahab, now half-revolving in his\npivot-hole", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2502, "position": 2502, "text": ", as Ahab, now half-revolving in his\npivot-hole, with one hand reaching high up a shroud, and tightly,\nalmost convulsively grasping it, addressed them thus:—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2503, "position": 2503, "text": "it, addressed them thus:—\n\n“All ye mast-headers have before now heard me give orders about a white\nwhale. Look ye! d’ye see this Spanish ounce of gold?”—holding up a\nbroad bright coin to the sun", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 730, "2000": 967}}, {"id": 2504, "position": 2504, "text": "ounce of gold?”—holding up a\nbroad bright coin to the sun—“it is a sixteen dollar piece, men. D’ye\nsee it? Mr. Starbuck, hand me yon top-maul.”", "labels": {"50": 37, "100": 64, "250": 163, "500": 154, "1000": 873, "2000": 1830}}, {"id": 2505, "position": 2505, "text": "buck, hand me yon top-maul.”\n\nWhile the mate was getting the hammer, Ahab, without speaking, was\nslowly rubbing the gold piece against the skirts of his jacket, as if\nto heighten its lustre, and without", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2506, "position": 2506, "text": "of his jacket, as if\nto heighten its lustre, and without using any words was meanwhile lowly\nhumming to himself, producing a sound so strangely muffled and\ninarticulate that it seemed the mechanical humming of the wheels of his\nvitality", "labels": {"50": 22, "100": 88, "250": 205, "500": 297, "1000": 383, "2000": 1066}}, {"id": 2507, "position": 2507, "text": "culate that it seemed the mechanical humming of the wheels of his\nvitality in him.\n\nReceiving the top-maul from Starbuck, he advanced towards the main-mast\nwith the hammer uplifted in one hand, exhibiting the gold with the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2508, "position": 2508, "text": "with the hammer uplifted in one hand, exhibiting the gold with the\nother, and with a high raised voice exclaiming: “Whosoever of ye raises\nme a white-headed whale with a wrinkled brow and a crooked jaw;\nwhoso", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2509, "position": 2509, "text": "white-headed whale with a wrinkled brow and a crooked jaw;\nwhosoever of ye raises me that white-headed whale, with three holes\npunctured in his starboard fluke—look ye, whosoever of ye raises me\nthat same", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2510, "position": 2510, "text": "fluke—look ye, whosoever of ye raises me\nthat same white whale, he shall have this gold ounce, my boys!”\n\n“Huzza! huzza!” cried the seamen, as with swinging tarpaulins they\nhailed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2511, "position": 2511, "text": "!” cried the seamen, as with swinging tarpaulins they\nhailed the act of nailing the gold to the mast.\n\n“It’s a white whale, I say,” resumed Ahab, as he threw down the\ntopmaul", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2512, "position": 2512, "text": "say,” resumed Ahab, as he threw down the\ntopmaul: “a white whale. Skin your eyes for him, men; look sharp for\nwhite water; if ye see but a bubble, sing out.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2513, "position": 2513, "text": "if ye see but a bubble, sing out.”\n\nAll this while Tashtego, Daggoo, and Queequeg had looked on with even\nmore intense interest and surprise than the rest, and at the mention of\nthe wrinkled brow", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2514, "position": 2514, "text": "interest and surprise than the rest, and at the mention of\nthe wrinkled brow and crooked jaw they had started as if each was\nseparately touched by some specific recollection.\n\n“Captain Ahab,” said Tashtego, “that white whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2515, "position": 2515, "text": "Captain Ahab,” said Tashtego, “that white whale must be the same that\nsome call Moby Dick.”\n\n“Moby Dick?” shouted Ahab. “Do ye know the white whale then, Tash?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2516, "position": 2516, "text": "ab. “Do ye know the white whale then, Tash?”\n\n“Does he fan-tail a little curious, sir, before he goes down?” said the\nGay-Header deliberately.\n\n“And has he a curious spout, too", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2517, "position": 2517, "text": "Gay-Header deliberately.\n\n“And has he a curious spout, too,” said Daggoo, “very bushy, even for a\nparmacetty, and mighty quick, Captain Ahab?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2518, "position": 2518, "text": "mighty quick, Captain Ahab?”\n\n“And he have one, two, three—oh! good many iron in him hide, too,\nCaptain,” cried Queequeg disjointedly, “all twiske-tee", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2519, "position": 2519, "text": "queg disjointedly, “all twiske-tee be-twisk, like\nhim—him—” faltering hard for a word, and screwing his hand round and\nround as though uncorking a bottle—", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 2520, "position": 2520, "text": "and screwing his hand round and\nround as though uncorking a bottle—“like him—him—”\n\n“Corkscrew!” cried Ahab, “aye, Queequeg, the harpoons lie all twisted\nand wrenched in him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2521, "position": 2521, "text": "Queequeg, the harpoons lie all twisted\nand wrenched in him; aye, Daggoo, his spout is a big one, like a whole\nshock of wheat, and white as a pile of our Nantucket wool after the\ngreat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2522, "position": 2522, "text": "wheat, and white as a pile of our Nantucket wool after the\ngreat annual sheep-shearing; aye, Tashtego, and he fan-tails like a\nsplit jib in a squall", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2523, "position": 2523, "text": "split jib in a squall. Death and devils! men, it is Moby Dick ye have\nseen—Moby Dick—Moby Dick!”\n\n“Captain Ahab,” said Starbuck, who, with Stubb and Fl", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2524, "position": 2524, "text": "Ahab,” said Starbuck, who, with Stubb and Flask, had thus far\nbeen eyeing his superior with increasing surprise, but at last seemed\nstruck with a thought which somewhat explained all the wonder", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2525, "position": 2525, "text": "thought which somewhat explained all the wonder. “Captain\nAhab, I have heard of Moby Dick—but it was not Moby Dick that took off\nthy leg?”\n\n“Who told thee that?” cried Ahab; then pausing, “", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2526, "position": 2526, "text": "“Who told thee that?” cried Ahab; then pausing, “Aye, Starbuck; aye, my\nhearties all round; it was Moby Dick that dismasted me; Moby Dick that\nbrought me to this dead stump I", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2527, "position": 2527, "text": "smasted me; Moby Dick that\nbrought me to this dead stump I stand on now. Aye, aye,” he shouted\nwith a terrific, loud, animal sob, like that of a heart-stricken moose;\n“Aye, aye! it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2528, "position": 2528, "text": "like that of a heart-stricken moose;\n“Aye, aye! it was that accursed white whale that razeed me; made a poor\npegging lubber of me for ever and a day!” Then tossing both arms, with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2529, "position": 2529, "text": "of me for ever and a day!” Then tossing both arms, with\nmeasureless imprecations he shouted out: “Aye, aye! and I’ll chase him\nround Good Hope, and round the Horn, and round the Norway Mae", "labels": {"50": 22, "100": 64, "250": 163, "500": 180, "1000": 627, "2000": 1389}}, {"id": 2530, "position": 2530, "text": "him\nround Good Hope, and round the Horn, and round the Norway Maelstrom,\nand round perdition’s flames before I give him up. And this is what ye\nhave shipped for, men! to chase that white whale on both sides", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2531, "position": 2531, "text": "ye\nhave shipped for, men! to chase that white whale on both sides of land,\nand over all sides of earth, till he spouts black blood and rolls fin\nout. What say ye, men, will ye splice hands on it,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2532, "position": 2532, "text": ". What say ye, men, will ye splice hands on it, now? I think ye do\nlook brave.”\n\n“Aye, aye!” shouted the harpooneers and seamen, running closer to the\nexcited old man: “A sharp", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2533, "position": 2533, "text": "eers and seamen, running closer to the\nexcited old man: “A sharp eye for the white whale; a sharp lance for\nMoby Dick!”\n\n“God bless ye,” he seemed to half sob and half shout", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2534, "position": 2534, "text": "” he seemed to half sob and half shout. “God bless ye,\nmen. Steward! go draw the great measure of grog. But what’s this long\nface about, Mr. Starbuck; wilt thou not chase the white whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2535, "position": 2535, "text": "about, Mr. Starbuck; wilt thou not chase the white whale? art not\ngame for Moby Dick?”\n\n“I am game for his crooked jaw, and for the jaws of Death too, Captain\nAhab, if it fairly comes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2536, "position": 2536, "text": "for the jaws of Death too, Captain\nAhab, if it fairly comes in the way of the business we follow; but I\ncame here to hunt whales, not my commander’s vengeance. How many\nbarrels will thy vengeance yield thee even if thou", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2537, "position": 2537, "text": "’s vengeance. How many\nbarrels will thy vengeance yield thee even if thou gettest it, Captain\nAhab? it will not fetch thee much in our Nantucket market.”\n\n“Nantucket market! Hoot! But come closer, Starbuck", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2538, "position": 2538, "text": "”\n\n“Nantucket market! Hoot! But come closer, Starbuck; thou requirest a\nlittle lower layer. If money’s to be the measurer, man, and the\naccountants have computed their great counting-house the globe, by", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 2539, "position": 2539, "text": ", and the\naccountants have computed their great counting-house the globe, by\ngirdling it with guineas, one to every three parts of an inch; then,\nlet me tell thee, that my vengeance will fetch a great premium _here!_", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 2540, "position": 2540, "text": "tell thee, that my vengeance will fetch a great premium _here!_”\n\n“He smites his chest,” whispered Stubb, “what’s that for? methinks it\nrings most vast, but hollow.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2541, "position": 2541, "text": "methinks it\nrings most vast, but hollow.”\n\n“Vengeance on a dumb brute!” cried Starbuck, “that simply smote thee\nfrom blindest instinct! Madness! To be enraged with a dumb thing,\nCaptain Ahab, seems", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2542, "position": 2542, "text": "Madness! To be enraged with a dumb thing,\nCaptain Ahab, seems blasphemous.”\n\n“Hark ye yet again—the little lower layer. All visible objects, man,\nare but as pasteboard masks", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2543, "position": 2543, "text": "visible objects, man,\nare but as pasteboard masks. But in each event—in the living act, the\nundoubted deed—there, some unknown but still reasoning thing puts forth\nthe mouldings of its features from behind the unrea", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 193}}, {"id": 2544, "position": 2544, "text": "thing puts forth\nthe mouldings of its features from behind the unreasoning mask. If man\nwill strike, strike through the mask! How can the prisoner reach\noutside except by thrusting through the wall? To me, the white whale is\nthat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2545, "position": 2545, "text": "except by thrusting through the wall? To me, the white whale is\nthat wall, shoved near to me. Sometimes I think there’s naught beyond.\nBut ’tis enough. He tasks me; he heaps me; I see in him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2546, "position": 2546, "text": "enough. He tasks me; he heaps me; I see in him outrageous\nstrength, with an inscrutable malice sinewing it. That inscrutable\nthing is chiefly what I hate; and be the white whale agent, or be the", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 589, "2000": 872}}, {"id": 2547, "position": 2547, "text": "chiefly what I hate; and be the white whale agent, or be the\nwhite whale principal, I will wreak that hate upon him. Talk not to me\nof blasphemy, man; I’d strike the sun if it insulted me", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2548, "position": 2548, "text": "phemy, man; I’d strike the sun if it insulted me. For could the\nsun do that, then could I do the other; since there is ever a sort of\nfair play herein, jealousy presiding over all creations", "labels": {"50": 9, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2549, "position": 2549, "text": "sort of\nfair play herein, jealousy presiding over all creations. But not my\nmaster, man, is even that fair play. Who’s over me? Truth hath no\nconfines. Take off thine eye! more intolerable than fi", "labels": {"50": 9, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 216}}, {"id": 2550, "position": 2550, "text": "no\nconfines. Take off thine eye! more intolerable than fiends’ glarings is\na doltish stare! So, so; thou reddenest and palest; my heat has melted\nthee to anger-glow", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 437, "2000": 946}}, {"id": 2551, "position": 2551, "text": "and palest; my heat has melted\nthee to anger-glow. But look ye, Starbuck, what is said in heat, that\nthing unsays itself. There are men from whom warm words are small\nindignity", "labels": {"50": 9, "100": 1, "250": 42, "500": 225, "1000": 589, "2000": 946}}, {"id": 2552, "position": 2552, "text": "are men from whom warm words are small\nindignity. I meant not to incense thee. Let it go. Look! see yonder\nTurkish cheeks of spotted tawn—living, breathing pictures painted by\nthe sun", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 16}}, {"id": 2553, "position": 2553, "text": "living, breathing pictures painted by\nthe sun. The Pagan leopards—the unrecking and unworshipping things,\nthat live; and seek, and give no reasons for the torrid life they feel!\nThe crew, man, the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 2554, "position": 2554, "text": "reasons for the torrid life they feel!\nThe crew, man, the crew! Are they not one and all with Ahab, in this\nmatter of the whale? See Stubb! he laughs! See yonder Chilian! he\nsnorts", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2555, "position": 2555, "text": "Stubb! he laughs! See yonder Chilian! he\nsnorts to think of it. Stand up amid the general hurricane, thy one\ntost sapling cannot, Starbuck! And what is it? Reckon it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2556, "position": 2556, "text": "Starbuck! And what is it? Reckon it. ’Tis but to\nhelp strike a fin; no wondrous feat for Starbuck. What is it more? From\nthis one poor hunt, then, the best lance out of all Nantucket", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2557, "position": 2557, "text": "this one poor hunt, then, the best lance out of all Nantucket, surely\nhe will not hang back, when every foremast-hand has clutched a\nwhetstone? Ah! constrainings seize thee; I see! the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2558, "position": 2558, "text": "stone? Ah! constrainings seize thee; I see! the billow lifts thee!\nSpeak, but speak!—Aye, aye! thy silence, then, _that_ voices thee.\n(_Aside_) Something shot from my", "labels": {"50": 9, "100": 26, "250": 42, "500": 225, "1000": 589, "2000": 946}}, {"id": 2559, "position": 2559, "text": "_that_ voices thee.\n(_Aside_) Something shot from my dilated nostrils, he has inhaled it in\nhis lungs. Starbuck now is mine; cannot oppose me now, without\nrebellion.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 2560, "position": 2560, "text": "me now, without\nrebellion.”\n\n“God keep me!—keep us all!” murmured Starbuck, lowly.\n\nBut in his joy at the enchanted, tacit acquiescence of the mate, Ahab\ndid not hear his forebo", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2561, "position": 2561, "text": "acquiescence of the mate, Ahab\ndid not hear his foreboding invocation; nor yet the low laugh from the\nhold; nor yet the presaging vibrations of the winds in the cordage; nor\nyet the hollow flap of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2562, "position": 2562, "text": "of the winds in the cordage; nor\nyet the hollow flap of the sails against the masts, as for a moment\ntheir hearts sank in. For again Starbuck’s downcast eyes lighted up\nwith the stubbornness of life; the subterranean", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 2563, "position": 2563, "text": "s downcast eyes lighted up\nwith the stubbornness of life; the subterranean laugh died away; the\nwinds blew on; the sails filled out; the ship heaved and rolled as\nbefore. Ah, ye admonitions and warnings! why stay ye", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 779, "2000": 16}}, {"id": 2564, "position": 2564, "text": "before. Ah, ye admonitions and warnings! why stay ye not when ye come?\nBut rather are ye predictions than warnings, ye shadows! Yet not so\nmuch predictions from without, as verifications of the foregoing things\nwithin", "labels": {"50": 9, "100": 26, "250": 141, "500": 198, "1000": 616, "2000": 1859}}, {"id": 2565, "position": 2565, "text": "predictions from without, as verifications of the foregoing things\nwithin. For with little external to constrain us, the innermost\nnecessities in our being, these still drive us on.\n\n“The measure! the measure!” cried Ah", "labels": {"50": 10, "100": 71, "250": 33, "500": 236, "1000": 211, "2000": 1618}}, {"id": 2566, "position": 2566, "text": "still drive us on.\n\n“The measure! the measure!” cried Ahab.\n\nReceiving the brimming pewter, and turning to the harpooneers, he\nordered them to produce their weapons. Then ranging them before him\nnear the capstan", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2567, "position": 2567, "text": "them to produce their weapons. Then ranging them before him\nnear the capstan, with their harpoons in their hands, while his three\nmates stood at his side with their lances, and the rest of the ship’s\ncompany formed a circle round", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2568, "position": 2568, "text": "s, and the rest of the ship’s\ncompany formed a circle round the group; he stood for an instant\nsearchingly eyeing every man of his crew. But those wild eyes met his,\nas the bloodshot eyes of the prairie wolves meet the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 2569, "position": 2569, "text": "eyes met his,\nas the bloodshot eyes of the prairie wolves meet the eye of their\nleader, ere he rushes on at their head in the trail of the bison; but,\nalas! only to fall into the hidden snare of the", "labels": {"50": 37, "100": 55, "250": 65, "500": 93, "1000": 580, "2000": 668}}, {"id": 2570, "position": 2570, "text": "but,\nalas! only to fall into the hidden snare of the Indian.\n\n“Drink and pass!” he cried, handing the heavy charged flagon to the\nnearest seaman. “The crew alone now drink", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 1904}}, {"id": 2571, "position": 2571, "text": "seaman. “The crew alone now drink. Round with it, round! Short\ndraughts—long swallows, men; ’tis hot as Satan’s hoof. So, so; it goes\nround excellently", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 2572, "position": 2572, "text": ", so; it goes\nround excellently. It spiralizes in ye; forks out at the\nserpent-snapping eye. Well done; almost drained. That way it went, this\nway it comes. Hand it me—here’s a hollow!", "labels": {"50": 9, "100": 64, "250": 30, "500": 498, "1000": 345, "2000": 1620}}, {"id": 2573, "position": 2573, "text": "this\nway it comes. Hand it me—here’s a hollow! Men, ye seem the years; so\nbrimming life is gulped and gone. Steward, refill!\n\n“Attend now, my braves", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 174, "2000": 709}}, {"id": 2574, "position": 2574, "text": "ill!\n\n“Attend now, my braves. I have mustered ye all round this capstan; and\nye mates, flank me with your lances; and ye harpooneers, stand there\nwith your irons; and ye, stout mariners, ring", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 2575, "position": 2575, "text": ", stand there\nwith your irons; and ye, stout mariners, ring me in, that I may in some\nsort revive a noble custom of my fisherman fathers before me. O men,\nyou will yet see that—Ha! boy, come back", "labels": {"50": 9, "100": 26, "250": 42, "500": 498, "1000": 50, "2000": 16}}, {"id": 2576, "position": 2576, "text": "O men,\nyou will yet see that—Ha! boy, come back? bad pennies come not sooner.\nHand it me. Why, now, this pewter had run brimming again, wer’t not\nthou St", "labels": {"50": 41, "100": 26, "250": 120, "500": 498, "1000": 627, "2000": 39}}, {"id": 2577, "position": 2577, "text": "run brimming again, wer’t not\nthou St. Vitus’ imp—away, thou ague!\n\n“Advance, ye mates! Cross your lances full before me. Well done! Let me\ntouch the axis.” So", "labels": {"50": 9, "100": 26, "250": 30, "500": 498, "1000": 637, "2000": 39}}, {"id": 2578, "position": 2578, "text": "full before me. Well done! Let me\ntouch the axis.” So saying, with extended arm, he grasped the three\nlevel, radiating lances at their crossed centre; while so doing,\nsuddenly and nervously twitched them; meanwhile, glancing intently from", "labels": {"50": 9, "100": 26, "250": 205, "500": 425, "1000": 783, "2000": 1620}}, {"id": 2579, "position": 2579, "text": "while so doing,\nsuddenly and nervously twitched them; meanwhile, glancing intently from\nStarbuck to Stubb; from Stubb to Flask. It seemed as though, by some\nnameless, interior volition, he would fain have shocked into them", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2580, "position": 2580, "text": "nameless, interior volition, he would fain have shocked into them the\nsame fiery emotion accumulated within the Leyden jar of his own\nmagnetic life. The three mates quailed before his strong, sustained,\nand mystic aspect", "labels": {"50": 22, "100": 88, "250": 70, "500": 206, "1000": 83, "2000": 1365}}, {"id": 2581, "position": 2581, "text": "ailed before his strong, sustained,\nand mystic aspect. Stubb and Flask looked sideways from him; the honest\neye of Starbuck fell downright.\n\n“In vain!” cried Ahab; “but, maybe, ’tis well", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2582, "position": 2582, "text": "” cried Ahab; “but, maybe, ’tis well. For did ye three but\nonce take the full-forced shock, then mine own electric thing, _that_\nhad perhaps expired from out me", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2583, "position": 2583, "text": "_\nhad perhaps expired from out me. Perchance, too, it would have dropped\nye dead. Perchance ye need it not. Down lances! And now, ye mates, I do\nappoint ye three cupbearers to my three pagan", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 663, "2000": 908}}, {"id": 2584, "position": 2584, "text": "mates, I do\nappoint ye three cupbearers to my three pagan kinsmen there—yon three\nmost honorable gentlemen and noblemen, my valiant harpooneers. Disdain\nthe task? What, when the great Pope washes the feet", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 637, "2000": 39}}, {"id": 2585, "position": 2585, "text": ". Disdain\nthe task? What, when the great Pope washes the feet of beggars, using\nhis tiara for ewer? Oh, my sweet cardinals! your own condescension,\n_that_ shall bend ye to it", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 1886}}, {"id": 2586, "position": 2586, "text": "own condescension,\n_that_ shall bend ye to it. I do not order ye; ye will it. Cut your\nseizings and draw the poles, ye harpooneers!”\n\nSilently obeying the order, the three harpoon", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2587, "position": 2587, "text": "harpooneers!”\n\nSilently obeying the order, the three harpooneers now stood with the\ndetached iron part of their harpoons, some three feet long, held, barbs\nup, before him.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2588, "position": 2588, "text": "barbs\nup, before him.\n\n“Stab me not with that keen steel! Cant them; cant them over! know ye\nnot the goblet end? Turn up the socket! So, so; now, ye cup-bearers", "labels": {"50": 18, "100": 83, "250": 240, "500": 61, "1000": 672, "2000": 1885}}, {"id": 2589, "position": 2589, "text": "up the socket! So, so; now, ye cup-bearers,\nadvance. The irons! take them; hold them while I fill!” Forthwith,\nslowly going from one officer to the other, he brimmed the harp", "labels": {"50": 9, "100": 87, "250": 189, "500": 19, "1000": 298, "2000": 1646}}, {"id": 2590, "position": 2590, "text": "slowly going from one officer to the other, he brimmed the harpoon\nsockets with the fiery waters from the pewter.\n\n“Now, three to three, ye stand. Commend the murderous chalices! Bestow\nthem, ye who", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2591, "position": 2591, "text": ". Commend the murderous chalices! Bestow\nthem, ye who are now made parties to this indissoluble league. Ha!\nStarbuck! but the deed is done! Yon ratifying sun now waits to sit upon\nit", "labels": {"50": 9, "100": 26, "250": 133, "500": 122, "1000": 437, "2000": 573}}, {"id": 2592, "position": 2592, "text": "deed is done! Yon ratifying sun now waits to sit upon\nit. Drink, ye harpooneers! drink and swear, ye men that man the\ndeathful whaleboat’s bow—Death to Moby Dick! God hunt us all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2593, "position": 2593, "text": "boat’s bow—Death to Moby Dick! God hunt us all, if we do\nnot hunt Moby Dick to his death!” The long, barbed steel goblets were\nlifted; and to cries and maledictions against the white", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2594, "position": 2594, "text": "blets were\nlifted; and to cries and maledictions against the white whale, the\nspirits were simultaneously quaffed down with a hiss. Starbuck paled,\nand turned, and shivered. Once more, and finally, the replenished", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2595, "position": 2595, "text": "turned, and shivered. Once more, and finally, the replenished\npewter went the rounds among the frantic crew; when, waving his free\nhand to them, they all dispersed; and Ahab retired within his cabin.\n\n\nCHAPTER 37. Sunset", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2596, "position": 2596, "text": "all dispersed; and Ahab retired within his cabin.\n\n\nCHAPTER 37. Sunset.\n\n_The cabin; by the stern windows; Ahab sitting alone, and gazing out_.\n\nI leave a white and turbid wake; pale waters, paler cheeks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2597, "position": 2597, "text": "I leave a white and turbid wake; pale waters, paler cheeks, where’er I\nsail. The envious billows sidelong swell to whelm my track; let them;\nbut first I pass.", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 118, "2000": 16}}, {"id": 2598, "position": 2598, "text": "; let them;\nbut first I pass.\n\nYonder, by ever-brimming goblet’s rim, the warm waves blush like wine.\nThe gold brow plumbs the blue. The diver sun—slow dived from noon—", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 50, "2000": 369}}, {"id": 2599, "position": 2599, "text": "plumbs the blue. The diver sun—slow dived from noon—goes\ndown; my soul mounts up! she wearies with her endless hill. Is, then,\nthe crown too heavy that I wear? this Iron Crown of Lombardy", "labels": {"50": 49, "100": 74, "250": 126, "500": 195, "1000": 330, "2000": 1441}}, {"id": 2600, "position": 2600, "text": "the crown too heavy that I wear? this Iron Crown of Lombardy. Yet is it\nbright with many a gem; I the wearer, see not its far flashings; but\ndarkly feel that I wear that, that dazzlingly confounds", "labels": {"50": 9, "100": 26, "250": 42, "500": 225, "1000": 589, "2000": 946}}, {"id": 2601, "position": 2601, "text": "but\ndarkly feel that I wear that, that dazzlingly confounds. ’Tis iron—that\nI know—not gold. ’Tis split, too—that I feel; the jagged edge galls me\nso, my brain seems to beat against", "labels": {"50": 9, "100": 73, "250": 120, "500": 441, "1000": 50, "2000": 946}}, {"id": 2602, "position": 2602, "text": "; the jagged edge galls me\nso, my brain seems to beat against the solid metal; aye, steel skull,\nmine; the sort that needs no helmet in the most brain-battering fight!", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 589, "2000": 916}}, {"id": 2603, "position": 2603, "text": "brain-battering fight!\n\nDry heat upon my brow? Oh! time was, when as the sunrise nobly spurred\nme, so the sunset soothed. No more. This lovely light, it lights not\nme; all loveliness is anguish to", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 986}}, {"id": 2604, "position": 2604, "text": "This lovely light, it lights not\nme; all loveliness is anguish to me, since I can ne’er enjoy. Gifted\nwith the high perception, I lack the low, enjoying power; damned, most\nsubtly and most malignantly! damned", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 50, "2000": 946}}, {"id": 2605, "position": 2605, "text": ", enjoying power; damned, most\nsubtly and most malignantly! damned in the midst of Paradise! Good\nnight—good night! (_waving his hand, he moves from the window_.)\n\n’Twas not so hard a task", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 573}}, {"id": 2606, "position": 2606, "text": "from the window_.)\n\n’Twas not so hard a task. I thought to find one stubborn, at the least;\nbut my one cogged circle fits into all their various wheels, and they\nrevolve", "labels": {"50": 6, "100": 20, "250": 132, "500": 412, "1000": 727, "2000": 381}}, {"id": 2607, "position": 2607, "text": "their various wheels, and they\nrevolve. Or, if you will, like so many ant-hills of powder, they all\nstand before me; and I their match. Oh, hard! that to fire others, the\nmatch itself must needs", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 50, "2000": 1886}}, {"id": 2608, "position": 2608, "text": ". Oh, hard! that to fire others, the\nmatch itself must needs be wasting! What I’ve dared, I’ve willed; and\nwhat I’ve willed, I’ll do! They think me mad—Starbuck does;", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2609, "position": 2609, "text": ", I’ll do! They think me mad—Starbuck does; but I’m\ndemoniac, I am madness maddened! That wild madness that’s only calm to\ncomprehend itself! The prophecy was that I should be dismem", "labels": {"50": 9, "100": 1, "250": 193, "500": 498, "1000": 50, "2000": 421}}, {"id": 2610, "position": 2610, "text": "calm to\ncomprehend itself! The prophecy was that I should be dismembered;\nand—Aye! I lost this leg. I now prophesy that I will dismember my\ndismemberer", "labels": {"50": 9, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1859}}, {"id": 2611, "position": 2611, "text": "smember my\ndismemberer. Now, then, be the prophet and the fulfiller one. That’s\nmore than ye, ye great gods, ever were. I laugh and hoot at ye, ye\ncricket-players,", "labels": {"50": 9, "100": 26, "250": 141, "500": 198, "1000": 616, "2000": 1859}}, {"id": 2612, "position": 2612, "text": "were. I laugh and hoot at ye, ye\ncricket-players, ye pugilists, ye deaf Burkes and blinded Bendigoes! I\nwill not say as schoolboys do to bullies—Take some one of your own\nsize;", "labels": {"50": 31, "100": 86, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 2613, "position": 2613, "text": "schoolboys do to bullies—Take some one of your own\nsize; don’t pommel _me!_ No, ye’ve knocked me down, and I am up again;\nbut _ye_ have run and hidden", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2614, "position": 2614, "text": "am up again;\nbut _ye_ have run and hidden. Come forth from behind your cotton bags!\nI have no long gun to reach ye. Come, Ahab’s compliments to ye; come\nand see if ye can swerve", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2615, "position": 2615, "text": "s compliments to ye; come\nand see if ye can swerve me. Swerve me? ye cannot swerve me, else ye\nswerve yourselves! man has ye there. Swerve me? The path to my", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 118, "2000": 523}}, {"id": 2616, "position": 2616, "text": "! man has ye there. Swerve me? The path to my fixed\npurpose is laid with iron rails, whereon my soul is grooved to run.\nOver unsounded gorges, through the rifled hearts of mountains, under", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 946}}, {"id": 2617, "position": 2617, "text": "sounded gorges, through the rifled hearts of mountains, under\ntorrents’ beds, unerringly I rush! Naught’s an obstacle, naught’s an\nangle to the iron way!\n\n\nCHAPTER 38. Dusk.", "labels": {"50": 20, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1860}}, {"id": 2618, "position": 2618, "text": "’s an\nangle to the iron way!\n\n\nCHAPTER 38. Dusk.\n\n_By the Mainmast; Starbuck leaning against it_.\n\nMy soul is more than matched; she’s overmanned; and by a madman!\nInsuffera", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2619, "position": 2619, "text": "she’s overmanned; and by a madman!\nInsufferable sting, that sanity should ground arms on such a field! But\nhe drilled deep down, and blasted all my reason out of me! I think I\nsee his impious", "labels": {"50": 36, "100": 35, "250": 4, "500": 226, "1000": 29, "2000": 979}}, {"id": 2620, "position": 2620, "text": "blasted all my reason out of me! I think I\nsee his impious end; but feel that I must help him to it. Will I, nill\nI, the ineffable thing has tied me to him; tows me with", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 589, "2000": 1169}}, {"id": 2621, "position": 2621, "text": "ineffable thing has tied me to him; tows me with a cable I have\nno knife to cut. Horrible old man! Who’s over him, he cries;—aye, he\nwould be a democrat to all above; look", "labels": {"50": 25, "100": 64, "250": 219, "500": 72, "1000": 533, "2000": 1620}}, {"id": 2622, "position": 2622, "text": "cries;—aye, he\nwould be a democrat to all above; look, how he lords it over all below!\nOh! I plainly see my miserable office,—to obey, rebelling; and worse\nyet, to hate with touch of pity", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 1886}}, {"id": 2623, "position": 2623, "text": "obey, rebelling; and worse\nyet, to hate with touch of pity! For in his eyes I read some lurid woe\nwould shrivel me up, had I it. Yet is there hope. Time and tide flow\nwide", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 118, "2000": 1177}}, {"id": 2624, "position": 2624, "text": "it. Yet is there hope. Time and tide flow\nwide. The hated whale has the round watery world to swim in, as the\nsmall gold-fish has its glassy globe. His heaven-insulting purpose, God\nmay wedge aside", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 747, "2000": 16}}, {"id": 2625, "position": 2625, "text": "globe. His heaven-insulting purpose, God\nmay wedge aside. I would up heart, were it not like lead. But my whole\nclock’s run down; my heart the all-controlling weight, I have no key to\nlift again.", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 851, "2000": 1620}}, {"id": 2626, "position": 2626, "text": "the all-controlling weight, I have no key to\nlift again.\n\n[_A burst of revelry from the forecastle_.]\n\nOh, God! to sail with such a heathen crew that have small touch of\nhuman mothers in them", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 16}}, {"id": 2627, "position": 2627, "text": "with such a heathen crew that have small touch of\nhuman mothers in them! Whelped somewhere by the sharkish sea. The white\nwhale is their demigorgon. Hark! the infernal orgies! that revelry is", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 343, "2000": 1620}}, {"id": 2628, "position": 2628, "text": "Hark! the infernal orgies! that revelry is\nforward! mark the unfaltering silence aft! Methinks it pictures life.\nForemost through the sparkling sea shoots on the gay, embattled,\nbantering bow", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 16}}, {"id": 2629, "position": 2629, "text": "the sparkling sea shoots on the gay, embattled,\nbantering bow, but only to drag dark Ahab after it, where he broods\nwithin his sternward cabin, builded over the dead water of the wake,\nand further on,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2630, "position": 2630, "text": ", builded over the dead water of the wake,\nand further on, hunted by its wolfish gurglings. The long howl thrills\nme through! Peace! ye revellers, and set the watch! Oh, life! ’tis", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 1203}}, {"id": 2631, "position": 2631, "text": "revellers, and set the watch! Oh, life! ’tis in\nan hour like this, with soul beat down and held to knowledge,—as wild,\nuntutored things are forced to feed—Oh, life! ’tis", "labels": {"50": 9, "100": 73, "250": 120, "500": 143, "1000": 437, "2000": 1886}}, {"id": 2632, "position": 2632, "text": "tutored things are forced to feed—Oh, life! ’tis now that I do feel\nthe latent horror in thee! but ’tis not me! that horror’s out of me!\nand with the soft feeling of the human in", "labels": {"50": 10, "100": 75, "250": 13, "500": 236, "1000": 548, "2000": 872}}, {"id": 2633, "position": 2633, "text": "’s out of me!\nand with the soft feeling of the human in me, yet will I try to fight\nye, ye grim, phantom futures! Stand by me, hold me, bind me, O ye\nblessed influences!\n\n\nCHAPTER 39", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 193}}, {"id": 2634, "position": 2634, "text": "hold me, bind me, O ye\nblessed influences!\n\n\nCHAPTER 39. First Night-Watch.\n\nFore-Top.\n\n(_Stubb solus, and mending a brace_.)\n\nHa! ha! ha! ha! hem! clear my", "labels": {"50": 6, "100": 1, "250": 42, "500": 498, "1000": 50, "2000": 916}}, {"id": 2635, "position": 2635, "text": "_.)\n\nHa! ha! ha! ha! hem! clear my throat!—I’ve been thinking over it ever\nsince, and that ha, ha’s the final consequence. Why so? Because a\nlaugh’s the wisest", "labels": {"50": 6, "100": 1, "250": 68, "500": 192, "1000": 427, "2000": 900}}, {"id": 2636, "position": 2636, "text": "the final consequence. Why so? Because a\nlaugh’s the wisest, easiest answer to all that’s queer; and come what\nwill, one comfort’s always left—that unfailing comfort is, it’s all\npredes", "labels": {"50": 31, "100": 7, "250": 49, "500": 453, "1000": 203, "2000": 1107}}, {"id": 2637, "position": 2637, "text": "left—that unfailing comfort is, it’s all\npredestinated. I heard not all his talk with Starbuck; but to my poor\neye Starbuck then looked something as I the other evening felt", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 327, "2000": 967}}, {"id": 2638, "position": 2638, "text": "then looked something as I the other evening felt. Be sure\nthe old Mogul has fixed him, too. I twigged it, knew it; had had the\ngift, might readily have prophesied it—for when I clapped my eye", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 54, "2000": 967}}, {"id": 2639, "position": 2639, "text": ", might readily have prophesied it—for when I clapped my eye upon\nhis skull I saw it. Well, Stubb, _wise_ Stubb—that’s my title—well,\nStubb, what of it, Stubb", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2640, "position": 2640, "text": "s my title—well,\nStubb, what of it, Stubb? Here’s a carcase. I know not all that may be\ncoming, but be it what it will, I’ll go to it laughing", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 2641, "position": 2641, "text": "what it will, I’ll go to it laughing. Such a waggish\nleering as lurks in all your horribles! I feel funny. Fa, la! lirra,\nskirra! What’s my juicy little pear at", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 719, "2000": 916}}, {"id": 2642, "position": 2642, "text": "! lirra,\nskirra! What’s my juicy little pear at home doing now? Crying its eyes\nout?—Giving a party to the last arrived harpooneers, I dare say, gay as\na frigate’s pennant, and so", "labels": {"50": 45, "100": 64, "250": 193, "500": 498, "1000": 849, "2000": 1620}}, {"id": 2643, "position": 2643, "text": ", I dare say, gay as\na frigate’s pennant, and so am I—fa, la! lirra, skirra! Oh—\n\n\nWe’ll drink to-night with hearts as light, To love, as gay and fleeting\nAs", "labels": {"50": 16, "100": 64, "250": 193, "500": 498, "1000": 851, "2000": 967}}, {"id": 2644, "position": 2644, "text": "-night with hearts as light, To love, as gay and fleeting\nAs bubbles that swim, on the beaker’s brim, And break on the lips while\nmeeting.\n\n\n\nA brave stave that—who calls? Mr", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 185, "2000": 1203}}, {"id": 2645, "position": 2645, "text": ".\n\n\n\nA brave stave that—who calls? Mr. Starbuck? Aye, aye, sir—(_Aside_)\nhe’s my superior, he has his too, if I’m not mistaken.—Aye, aye, sir", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2646, "position": 2646, "text": "too, if I’m not mistaken.—Aye, aye, sir,\njust through with this job—coming.\n\n\nCHAPTER 40. Midnight, Forecastle.\n\nHARPOONEERS AND SAILORS.\n\n(_Foresail rises and discovers the watch standing,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2647, "position": 2647, "text": "AND SAILORS.\n\n(_Foresail rises and discovers the watch standing, lounging, leaning,\nand lying in various attitudes, all singing in chorus_.)\n\n\n  Farewell and adieu to you, Spanish ladies! Farewell and adieu to you,", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 719, "2000": 916}}, {"id": 2648, "position": 2648, "text": "adieu to you, Spanish ladies! Farewell and adieu to you,\n  ladies of Spain! Our captain’s commanded.—\n\n\n\n1ST NANTUCKET SAILOR. Oh, boys, don’t be sentimental; it’s bad for the\ndigestion!", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 916}}, {"id": 2649, "position": 2649, "text": "don’t be sentimental; it’s bad for the\ndigestion! Take a tonic, follow me!\n\n(_Sings, and all follow._)\n\n\n Our captain stood upon the deck, A spy-glass in his hand, A viewing of", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 289, "2000": 1253}}, {"id": 2650, "position": 2650, "text": "upon the deck, A spy-glass in his hand, A viewing of\n those gallant whales That blew at every strand. Oh, your tubs in your\n boats, my boys, And by your braces stand, And we’ll have one of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2651, "position": 2651, "text": ", And by your braces stand, And we’ll have one of those\n fine whales, Hand, boys, over hand! So, be cheery, my lads! may your\n hearts never fail! While the bold harpooner is striking the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2652, "position": 2652, "text": "may your\n hearts never fail! While the bold harpooner is striking the whale!\n\n\n\nMATE’S VOICE FROM THE QUARTER-DECK. Eight bells there, forward!\n\n2ND NANTUCKET SAILOR. Avast the chorus! Eight bells there! d’ye", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2653, "position": 2653, "text": "TUCKET SAILOR. Avast the chorus! Eight bells there! d’ye hear,\nbell-boy? Strike the bell eight, thou Pip! thou blackling! and let me\ncall the watch. I’ve the sort of mouth for that—", "labels": {"50": 6, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 2654, "position": 2654, "text": "me\ncall the watch. I’ve the sort of mouth for that—the hogshead mouth. So,\nso, (_thrusts his head down the scuttle_,) Star-bo-l-e-e-n-", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2655, "position": 2655, "text": "_,) Star-bo-l-e-e-n-s, a-h-o-y!\nEight bells there below! Tumble up!\n\nDUTCH SAILOR. Grand snoozing to-night, maty; fat night", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 719, "2000": 68}}, {"id": 2656, "position": 2656, "text": ". Grand snoozing to-night, maty; fat night for that. I mark\nthis in our old Mogul’s wine; it’s quite as deadening to some as\nfilliping to others", "labels": {"50": 23, "100": 88, "250": 193, "500": 202, "1000": 849, "2000": 371}}, {"id": 2657, "position": 2657, "text": "deadening to some as\nfilliping to others. We sing; they sleep—aye, lie down there, like\nground-tier butts. At ’em again! There, take this copper-pump, and hail\n’em through it", "labels": {"50": 16, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 2658, "position": 2658, "text": "There, take this copper-pump, and hail\n’em through it. Tell ’em to avast dreaming of their lasses. Tell ’em\nit’s the resurrection; they must kiss their last, and come to judgment", "labels": {"50": 9, "100": 26, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2659, "position": 2659, "text": "; they must kiss their last, and come to judgment.\nThat’s the way—_that’s_ it; thy throat ain’t spoiled with eating\nAmsterdam butter.\n\nFRENCH SAILOR. Hist, boys! let’s have a ji", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2660, "position": 2660, "text": ".\n\nFRENCH SAILOR. Hist, boys! let’s have a jig or two before we ride to\nanchor in Blanket Bay. What say ye? There comes the other watch. Stand\nby all legs! Pip! little Pip! hurrah", "labels": {"50": 6, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 2661, "position": 2661, "text": "watch. Stand\nby all legs! Pip! little Pip! hurrah with your tambourine!\n\nPIP. (_Sulky and sleepy._) Don’t know where it is.\n\nFRENCH SAILOR", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 719, "2000": 1253}}, {"id": 2662, "position": 2662, "text": "know where it is.\n\nFRENCH SAILOR. Beat thy belly, then, and wag thy ears. Jig it, men, I\nsay; merry’s the word; hurrah! Damn me, won’t you dance? Form,", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2663, "position": 2663, "text": "hurrah! Damn me, won’t you dance? Form, now,\nIndian-file, and gallop into the double-shuffle? Throw yourselves!\nLegs! legs!\n\nICELAND SAILOR. I don’t like your floor, maty", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 719, "2000": 916}}, {"id": 2664, "position": 2664, "text": "legs!\n\nICELAND SAILOR. I don’t like your floor, maty; it’s too springy to my\ntaste. I’m used to ice-floors. I’m sorry to throw cold water on the\nsubject; but excuse me", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 719, "2000": 1253}}, {"id": 2665, "position": 2665, "text": "I’m sorry to throw cold water on the\nsubject; but excuse me.\n\nMALTESE SAILOR. Me too; where’s your girls? Who but a fool would take\nhis left hand by his right, and say to himself, how d’ye", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 289, "2000": 1479}}, {"id": 2666, "position": 2666, "text": "left hand by his right, and say to himself, how d’ye do? Partners!\nI must have partners!\n\nSICILIAN SAILOR. Aye; girls and a green!—then I’ll hop with ye; yea,\nturn grasshopper!", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 50, "2000": 916}}, {"id": 2667, "position": 2667, "text": "then I’ll hop with ye; yea,\nturn grasshopper!\n\nLONG-ISLAND SAILOR. Well, well, ye sulkies, there’s plenty more of us.\nHoe corn when you may, say I", "labels": {"50": 41, "100": 64, "250": 163, "500": 498, "1000": 54, "2000": 1082}}, {"id": 2668, "position": 2668, "text": "us.\nHoe corn when you may, say I. All legs go to harvest soon. Ah! here\ncomes the music; now for it!\n\nAZORE SAILOR. (_Ascending, and pitching the tambourine up the\nscuttle_", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 719, "2000": 916}}, {"id": 2669, "position": 2669, "text": "_Ascending, and pitching the tambourine up the\nscuttle_.) Here you are, Pip; and there’s the windlass-bitts; up you\nmount! Now, boys! (_The half of them dance to", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 50, "2000": 916}}, {"id": 2670, "position": 2670, "text": "you\nmount! Now, boys! (_The half of them dance to the tambourine; some go\nbelow; some sleep or lie among the coils of rigging. Oaths a-plenty_.)\n\nAZORE SAILOR", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 719, "2000": 916}}, {"id": 2671, "position": 2671, "text": ". Oaths a-plenty_.)\n\nAZORE SAILOR. (_Dancing_) Go it, Pip! Bang it, bell-boy! Rig it, dig\nit, stig it, quig it, bell-boy! Make fire", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 719, "2000": 1253}}, {"id": 2672, "position": 2672, "text": ", stig it, quig it, bell-boy! Make fire-flies; break the jinglers!\n\nPIP. Jinglers, you say?—there goes another, dropped off; I pound it so.\n\nCHINA SAILOR", "labels": {"50": 9, "100": 1, "250": 30, "500": 498, "1000": 647, "2000": 39}}, {"id": 2673, "position": 2673, "text": ", dropped off; I pound it so.\n\nCHINA SAILOR. Rattle thy teeth, then, and pound away; make a pagoda of\nthyself.\n\nFRENCH SAILOR. Merry-mad! Hold up thy hoop, Pip, till I jump through\nit!", "labels": {"50": 6, "100": 1, "250": 42, "500": 498, "1000": 50, "2000": 916}}, {"id": 2674, "position": 2674, "text": "mad! Hold up thy hoop, Pip, till I jump through\nit! Split jibs! tear yourselves!\n\nTASHTEGO. (_Quietly smoking._) That’s a white man; he calls that fun:\nhumph! I", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 719, "2000": 916}}, {"id": 2675, "position": 2675, "text": "’s a white man; he calls that fun:\nhumph! I save my sweat.\n\nOLD MANX SAILOR. I wonder whether those jolly lads bethink them of what\nthey are dancing over. I’ll dance over your grave, I will", "labels": {"50": 6, "100": 1, "250": 163, "500": 326, "1000": 24, "2000": 369}}, {"id": 2676, "position": 2676, "text": "they are dancing over. I’ll dance over your grave, I will—that’s the\nbitterest threat of your night-women, that beat head-winds round\ncorners. O Christ! to think of the green navies and the green", "labels": {"50": 6, "100": 1, "250": 68, "500": 276, "1000": 50, "2000": 1282}}, {"id": 2677, "position": 2677, "text": "corners. O Christ! to think of the green navies and the green-skulled\ncrews! Well, well; belike the whole world’s a ball, as you scholars\nhave it; and so ’tis right to make one ballroom of", "labels": {"50": 6, "100": 1, "250": 42, "500": 498, "1000": 50, "2000": 916}}, {"id": 2678, "position": 2678, "text": "you scholars\nhave it; and so ’tis right to make one ballroom of it. Dance on, lads,\nyou’re young; I was once.\n\n3D NANTUCKET SAILOR. Spell oh!—whew! this is worse than pulling after", "labels": {"50": 6, "100": 64, "250": 163, "500": 498, "1000": 851, "2000": 967}}, {"id": 2679, "position": 2679, "text": ". Spell oh!—whew! this is worse than pulling after\nwhales in a calm—give us a whiff, Tash.\n\n(_They cease dancing, and gather in clusters. Meantime the sky\ndarkens—the wind rises_", "labels": {"50": 16, "100": 73, "250": 138, "500": 498, "1000": 327, "2000": 16}}, {"id": 2680, "position": 2680, "text": "and gather in clusters. Meantime the sky\ndarkens—the wind rises_.)\n\nLASCAR SAILOR. By Brahma! boys, it’ll be douse sail soon. The sky-born,\nhigh-tide Ganges turned to wind!", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 463}}, {"id": 2681, "position": 2681, "text": ". The sky-born,\nhigh-tide Ganges turned to wind! Thou showest thy black brow, Seeva!\n\nMALTESE SAILOR. (_Reclining and shaking his cap_.) It’s the waves—the\nsnow’s caps", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 16}}, {"id": 2682, "position": 2682, "text": "cap_.) It’s the waves—the\nsnow’s caps turn to jig it now. They’ll shake their tassels soon. Now\nwould all the waves were women, then I’d go drown, and chassee", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 24, "2000": 768}}, {"id": 2683, "position": 2683, "text": "the waves were women, then I’d go drown, and chassee with\nthem evermore! There’s naught so sweet on earth—heaven may not match\nit!—as those swift glances of warm, wild bosoms in the", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 118, "2000": 1860}}, {"id": 2684, "position": 2684, "text": "!—as those swift glances of warm, wild bosoms in the dance, when the\nover-arboring arms hide such ripe, bursting grapes.\n\nSICILIAN SAILOR. (_Reclining_.) Tell me not of it! Hark ye", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 50, "2000": 916}}, {"id": 2685, "position": 2685, "text": "_Reclining_.) Tell me not of it! Hark ye, lad—fleet\ninterlacings of the limbs—lithe swayings—coyings—flutterings! lip!\nheart! hip! all graze: un", "labels": {"50": 16, "100": 73, "250": 120, "500": 143, "1000": 50, "2000": 1312}}, {"id": 2686, "position": 2686, "text": "—flutterings! lip!\nheart! hip! all graze: unceasing touch and go! not taste, observe ye,\nelse come satiety. Eh, Pagan? (_Nudging_.)\n\nTAHITAN SAILOR", "labels": {"50": 6, "100": 1, "250": 42, "500": 498, "1000": 50, "2000": 916}}, {"id": 2687, "position": 2687, "text": "Pagan? (_Nudging_.)\n\nTAHITAN SAILOR. (_Reclining on a mat_.) Hail, holy nakedness of our\ndancing girls!—the Heeva-Heeva! Ah! low veiled, high", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 719, "2000": 216}}, {"id": 2688, "position": 2688, "text": "—the Heeva-Heeva! Ah! low veiled, high palmed Tahiti! I\nstill rest me on thy mat, but the soft soil has slid! I saw thee woven\nin the wood, my mat! green the first day", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 187}}, {"id": 2689, "position": 2689, "text": "I saw thee woven\nin the wood, my mat! green the first day I brought ye thence; now worn\nand wilted quite. Ah me!—not thou nor I can bear the change! How then,\nif so be transplanted to yo", "labels": {"50": 9, "100": 73, "250": 120, "500": 143, "1000": 118, "2000": 193}}, {"id": 2690, "position": 2690, "text": "can bear the change! How then,\nif so be transplanted to yon sky? Hear I the roaring streams from\nPirohitee’s peak of spears, when they leap down the crags and drown the\nvillages?—The blast!", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 463}}, {"id": 2691, "position": 2691, "text": "they leap down the crags and drown the\nvillages?—The blast! the blast! Up, spine, and meet it! (_Leaps to his\nfeet_.)\n\nPORTUGUESE SAILOR. How the sea rolls swashing ’gainst the side", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 24, "2000": 369}}, {"id": 2692, "position": 2692, "text": "PORTUGUESE SAILOR. How the sea rolls swashing ’gainst the side! Stand\nby for reefing, hearties! the winds are just crossing swords, pell-mell\nthey’ll go lunging presently.\n\nDANISH SAILOR", "labels": {"50": 16, "100": 73, "250": 170, "500": 60, "1000": 520, "2000": 1604}}, {"id": 2693, "position": 2693, "text": "mell\nthey’ll go lunging presently.\n\nDANISH SAILOR. Crack, crack, old ship! so long as thou crackest, thou\nholdest! Well done! The mate there holds ye to it stiffly", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 2694, "position": 2694, "text": "mate there holds ye to it stiffly. He’s no more\nafraid than the isle fort at Cattegat, put there to fight the Baltic\nwith storm-lashed guns, on which the sea-salt cakes!\n\n4TH NANTUCKET SAILOR", "labels": {"50": 9, "100": 64, "250": 193, "500": 498, "1000": 851, "2000": 967}}, {"id": 2695, "position": 2695, "text": "on which the sea-salt cakes!\n\n4TH NANTUCKET SAILOR. He has his orders, mind ye that. I heard old Ahab\ntell him he must always kill a squall, something as they burst a\nwaterspout with a pistol—", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 2696, "position": 2696, "text": "uall, something as they burst a\nwaterspout with a pistol—fire your ship right into it!\n\nENGLISH SAILOR. Blood! but that old man’s a grand old cove! We are the\nlads to hunt him up his whale!\n\nALL", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2697, "position": 2697, "text": "old cove! We are the\nlads to hunt him up his whale!\n\nALL. Aye! aye!\n\nOLD MANX SAILOR. How the three pines shake! Pines are the hardest sort\nof tree to live when shifted to any other soil, and here there", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 174, "2000": 16}}, {"id": 2698, "position": 2698, "text": "sort\nof tree to live when shifted to any other soil, and here there’s none\nbut the crew’s cursed clay. Steady, helmsman! steady. This is the sort\nof weather when brave hearts snap ashore, and keeled hulls", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 174, "2000": 16}}, {"id": 2699, "position": 2699, "text": "the sort\nof weather when brave hearts snap ashore, and keeled hulls split at\nsea. Our captain has his birthmark; look yonder, boys, there’s another\nin the sky—lurid-like, ye see, all else", "labels": {"50": 16, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 2700, "position": 2700, "text": "another\nin the sky—lurid-like, ye see, all else pitch black.\n\nDAGGOO. What of that? Who’s afraid of black’s afraid of me! I’m\nquarried out of it!\n\nSPANISH SAILOR", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 2701, "position": 2701, "text": "of me! I’m\nquarried out of it!\n\nSPANISH SAILOR. (_Aside_.) He wants to bully, ah!—the old grudge makes\nme touchy (_Advancing_.) Aye, harpooneer,", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 2702, "position": 2702, "text": "me touchy (_Advancing_.) Aye, harpooneer, thy race is the undeniable\ndark side of mankind—devilish dark at that. No offence.\n\nDAGGOO (_grimly_). None.\n\nST", "labels": {"50": 6, "100": 1, "250": 193, "500": 36, "1000": 849, "2000": 890}}, {"id": 2703, "position": 2703, "text": ".\n\nDAGGOO (_grimly_). None.\n\nST. JAGO’S SAILOR. That Spaniard’s mad or drunk. But that can’t be, or\nelse in his one case our old Mogul’s fire-", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 2704, "position": 2704, "text": ", or\nelse in his one case our old Mogul’s fire-waters are somewhat long in\nworking.\n\n5TH NANTUCKET SAILOR. What’s that I saw—lightning? Yes.\n\nSPANISH SAILOR. No; Daggoo showing his teeth.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 2705, "position": 2705, "text": "? Yes.\n\nSPANISH SAILOR. No; Daggoo showing his teeth.\n\nDAGGOO (_springing_). Swallow thine, mannikin! White skin, white liver!\n\nSPANISH SAILOR (_meeting him_)", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 1253}}, {"id": 2706, "position": 2706, "text": ", white liver!\n\nSPANISH SAILOR (_meeting him_). Knife thee heartily! big frame, small\nspirit!\n\nALL. A row! a row! a row!\n\nTASHTEGO (_with a whiff_)", "labels": {"50": 6, "100": 1, "250": 42, "500": 180, "1000": 719, "2000": 967}}, {"id": 2707, "position": 2707, "text": "TASHTEGO (_with a whiff_). A row a’low, and a row aloft—Gods and\nmen—both brawlers! Humph!\n\nBELFAST SAILOR. A row! arrah a row! The Virgin be", "labels": {"50": 41, "100": 64, "250": 163, "500": 498, "1000": 54, "2000": 16}}, {"id": 2708, "position": 2708, "text": "!\n\nBELFAST SAILOR. A row! arrah a row! The Virgin be blessed, a row!\nPlunge in with ye!\n\nENGLISH SAILOR. Fair play! Snatch the Spaniard’s knife! A ring, a ring!\n\nOLD MANX SAILOR", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 2709, "position": 2709, "text": "’s knife! A ring, a ring!\n\nOLD MANX SAILOR. Ready formed. There! the ringed horizon. In that ring\nCain struck Abel. Sweet work, right work! No? Why then, God, mad’st\nthou the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2710, "position": 2710, "text": "right work! No? Why then, God, mad’st\nthou the ring?\n\nMATE’S VOICE FROM THE QUARTER-DECK. Hands by the halyards! in\ntop-gallant sails! Stand by to reef topsails!\n\nALL", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 2711, "position": 2711, "text": "top-gallant sails! Stand by to reef topsails!\n\nALL. The squall! the squall! jump, my jollies! (_They scatter_.)\n\nPIP (_shrinking under the windlass_)", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 2712, "position": 2712, "text": "scatter_.)\n\nPIP (_shrinking under the windlass_). Jollies? Lord help such jollies!\nCrish, crash! there goes the jib-stay! Blang-whang! God! Duck lower", "labels": {"50": 6, "100": 64, "250": 163, "500": 498, "1000": 54, "2000": 68}}, {"id": 2713, "position": 2713, "text": "jib-stay! Blang-whang! God! Duck lower,\nPip, here comes the royal yard! It’s worse than being in the whirled\nwoods, the last day of the year! Who’d go climbing after chestnuts", "labels": {"50": 6, "100": 86, "250": 193, "500": 498, "1000": 627, "2000": 1091}}, {"id": 2714, "position": 2714, "text": "the last day of the year! Who’d go climbing after chestnuts now?\nBut there they go, all cursing, and here I don’t. Fine prospects to\n’em; they’re on the road to heaven", "labels": {"50": 11, "100": 20, "250": 207, "500": 116, "1000": 237, "2000": 621}}, {"id": 2715, "position": 2715, "text": "’em; they’re on the road to heaven. Hold on hard! Jimmini, what a\nsquall! But those chaps there are worse yet—they are your white\nsqualls, they", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1192}}, {"id": 2716, "position": 2716, "text": "are your white\nsqualls, they. White squalls? white whale, shirr! shirr! Here have I\nheard all their chat just now, and the white whale—shirr! shirr!—but\nspoken of once!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2717, "position": 2717, "text": "white whale—shirr! shirr!—but\nspoken of once! and only this evening—it makes me jingle all over like\nmy tambourine—that anaconda of an old man swore ’em in to hunt him! Oh,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2718, "position": 2718, "text": "da of an old man swore ’em in to hunt him! Oh,\nthou big white God aloft there somewhere in yon darkness, have mercy on\nthis small black boy down here; preserve him from all men that have no\nbowels to feel", "labels": {"50": 41, "100": 21, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 2719, "position": 2719, "text": "down here; preserve him from all men that have no\nbowels to feel fear!\n\n\nCHAPTER 41. Moby Dick.\n\nI, Ishmael, was one of that crew; my shouts had gone up with the rest;\nmy oath had been welded", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2720, "position": 2720, "text": "; my shouts had gone up with the rest;\nmy oath had been welded with theirs; and stronger I shouted, and more\ndid I hammer and clinch my oath, because of the dread in my soul. A\nwild, mystical, sympathetical feeling was", "labels": {"50": 16, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1860}}, {"id": 2721, "position": 2721, "text": "the dread in my soul. A\nwild, mystical, sympathetical feeling was in me; Ahab’s quenchless feud\nseemed mine. With greedy ears I learned the history of that murderous\nmonster against whom I and all the others had taken our", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2722, "position": 2722, "text": "history of that murderous\nmonster against whom I and all the others had taken our oaths of\nviolence and revenge.\n\nFor some time past, though at intervals only, the unaccompanied,\nsecluded White Whale had haunted those uncivilized seas", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2723, "position": 2723, "text": "mpanied,\nsecluded White Whale had haunted those uncivilized seas mostly\nfrequented by the Sperm Whale fishermen. But not all of them knew of\nhis existence; only a few of them, comparatively, had knowingly seen\nhim; while the number", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2724, "position": 2724, "text": "few of them, comparatively, had knowingly seen\nhim; while the number who as yet had actually and knowingly given\nbattle to him, was small indeed. For, owing to the large number of\nwhale-cruisers; the disorderly way they were", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2725, "position": 2725, "text": "to the large number of\nwhale-cruisers; the disorderly way they were sprinkled over the entire\nwatery circumference, many of them adventurously pushing their quest\nalong solitary latitudes, so as seldom or never for a whole twelvemont", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2726, "position": 2726, "text": "along solitary latitudes, so as seldom or never for a whole twelvemonth\nor more on a stretch, to encounter a single news-telling sail of any\nsort; the inordinate length of each separate voyage; the irregularity\nof the times", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 2727, "position": 2727, "text": "inordinate length of each separate voyage; the irregularity\nof the times of sailing from home; all these, with other circumstances,\ndirect and indirect, long obstructed the spread through the whole\nworld-wide whaling-fleet of the special", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2728, "position": 2728, "text": "cted the spread through the whole\nworld-wide whaling-fleet of the special individualizing tidings\nconcerning Moby Dick. It was hardly to be doubted, that several vessels\nreported to have encountered, at such or such a time, or on such", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2729, "position": 2729, "text": "reported to have encountered, at such or such a time, or on such or\nsuch a meridian, a Sperm Whale of uncommon magnitude and malignity,\nwhich whale, after doing great mischief to his assailants, had\ncompletely escaped them; to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2730, "position": 2730, "text": "doing great mischief to his assailants, had\ncompletely escaped them; to some minds it was not an unfair\npresumption, I say, that the whale in question must have been no other\nthan Moby Dick", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2731, "position": 2731, "text": "have been no other\nthan Moby Dick. Yet as of late the Sperm Whale fishery had been marked\nby various and not unfrequent instances of great ferocity, cunning, and\nmalice in the monster attacked; therefore it was, that those who", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2732, "position": 2732, "text": ", and\nmalice in the monster attacked; therefore it was, that those who by\naccident ignorantly gave battle to Moby Dick; such hunters, perhaps,\nfor the most part, were content to ascribe the peculiar terror he bred,\nmore,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2733, "position": 2733, "text": ", were content to ascribe the peculiar terror he bred,\nmore, as it were, to the perils of the Sperm Whale fishery at large,\nthan to the individual cause. In that way, mostly, the disastrous\nencounter between Ahab and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2734, "position": 2734, "text": "cause. In that way, mostly, the disastrous\nencounter between Ahab and the whale had hitherto been popularly\nregarded.\n\nAnd as for those who, previously hearing of the White Whale, by chance\ncaught sight of him; in the beginning of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2735, "position": 2735, "text": "White Whale, by chance\ncaught sight of him; in the beginning of the thing they had every one\nof them, almost, as boldly and fearlessly lowered for him, as for any\nother whale of that species", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2736, "position": 2736, "text": "as for any\nother whale of that species. But at length, such calamities did ensue\nin these assaults—not restricted to sprained wrists and ankles, broken\nlimbs, or devouring amputations—but fatal to the last degree", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2737, "position": 2737, "text": "limbs, or devouring amputations—but fatal to the last degree of\nfatality; those repeated disastrous repulses, all accumulating and\npiling their terrors upon Moby Dick; those things had gone far to shake\nthe fort", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2738, "position": 2738, "text": "s upon Moby Dick; those things had gone far to shake\nthe fortitude of many brave hunters, to whom the story of the White\nWhale had eventually come.\n\nNor did wild rumors of all sorts fail to exaggerate, and still the more", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2739, "position": 2739, "text": "wild rumors of all sorts fail to exaggerate, and still the more\nhorrify the true histories of these deadly encounters. For not only do\nfabulous rumors naturally grow out of the very body of all surprising\nterrible events,—as the smitte", "labels": {"50": 33, "100": 69, "250": 160, "500": 14, "1000": 57, "2000": 1588}}, {"id": 2740, "position": 2740, "text": "of the very body of all surprising\nterrible events,—as the smitten tree gives birth to its fungi; but, in\nmaritime life, far more than in that of terra firma, wild rumors\nabound, wherever there is any adequate reality", "labels": {"50": 22, "100": 78, "250": 53, "500": 286, "1000": 448, "2000": 1027}}, {"id": 2741, "position": 2741, "text": "terra firma, wild rumors\nabound, wherever there is any adequate reality for them to cling to.\nAnd as the sea surpasses the land in this matter, so the whale fishery\nsurpasses every other sort of maritime life, in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2742, "position": 2742, "text": "so the whale fishery\nsurpasses every other sort of maritime life, in the wonderfulness and\nfearfulness of the rumors which sometimes circulate there. For not only\nare whalemen as a body unexempt from that ignorance and\nsupersti", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2743, "position": 2743, "text": "whalemen as a body unexempt from that ignorance and\nsuperstitiousness hereditary to all sailors; but of all sailors, they\nare by all odds the most directly brought into contact with whatever is\nappallingly astonishing in the sea; face", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2744, "position": 2744, "text": "brought into contact with whatever is\nappallingly astonishing in the sea; face to face they not only eye its\ngreatest marvels, but, hand to jaw, give battle to them. Alone, in such\nremotest waters, that though you sailed a", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 2745, "position": 2745, "text": "them. Alone, in such\nremotest waters, that though you sailed a thousand miles, and passed a\nthousand shores, you would not come to any chiseled hearth-stone, or\naught hospitable beneath that part of the sun", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 9, "2000": 682}}, {"id": 2746, "position": 2746, "text": "stone, or\naught hospitable beneath that part of the sun; in such latitudes and\nlongitudes, pursuing too such a calling as he does, the whaleman is\nwrapped by influences all tending to make his fancy pregnant with many\na", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2747, "position": 2747, "text": "man is\nwrapped by influences all tending to make his fancy pregnant with many\na mighty birth.\n\nNo wonder, then, that ever gathering volume from the mere transit over\nthe widest watery spaces, the outblown rumors of the White Whale did in\nthe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2748, "position": 2748, "text": "watery spaces, the outblown rumors of the White Whale did in\nthe end incorporate with themselves all manner of morbid hints, and\nhalf-formed fœtal suggestions of supernatural agencies, which\neventually invested Moby Dick with new terrors unbor", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2749, "position": 2749, "text": "supernatural agencies, which\neventually invested Moby Dick with new terrors unborrowed from anything\nthat visibly appears. So that in many cases such a panic did he finally\nstrike, that few who by those rumors, at least, had heard of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2750, "position": 2750, "text": ", that few who by those rumors, at least, had heard of the White\nWhale, few of those hunters were willing to encounter the perils of his\njaw.\n\nBut there were still other and more vital practical influences at work", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2751, "position": 2751, "text": "were still other and more vital practical influences at work.\nNot even at the present day has the original prestige of the Sperm\nWhale, as fearfully distinguished from all other species of the\nleviathan, died out of the minds of the whalemen as a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2752, "position": 2752, "text": "the\nleviathan, died out of the minds of the whalemen as a body. There are\nthose this day among them, who, though intelligent and courageous\nenough in offering battle to the Greenland or Right whale, would\nperhaps—either from professional inex", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2753, "position": 2753, "text": "to the Greenland or Right whale, would\nperhaps—either from professional inexperience, or incompetency, or\ntimidity, decline a contest with the Sperm Whale; at any rate, there\nare plenty of whalemen, especially among", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2754, "position": 2754, "text": "Whale; at any rate, there\nare plenty of whalemen, especially among those whaling nations not\nsailing under the American flag, who have never hostilely encountered\nthe Sperm Whale, but whose sole knowledge of the leviathan is\nrestricted to the ignoble", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2755, "position": 2755, "text": "but whose sole knowledge of the leviathan is\nrestricted to the ignoble monster primitively pursued in the North;\nseated on their hatches, these men will hearken with a childish\nfireside interest and awe, to the wild, strange tales of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2756, "position": 2756, "text": "a childish\nfireside interest and awe, to the wild, strange tales of Southern\nwhaling. Nor is the pre-eminent tremendousness of the great Sperm Whale\nanywhere more feelingly comprehended, than on board of those prows\nwhich stem him.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2757, "position": 2757, "text": "comprehended, than on board of those prows\nwhich stem him.\n\nAnd as if the now tested reality of his might had in former legendary\ntimes thrown its shadow before it; we find some book\nnaturalists—Olassen and Povelson—", "labels": {"50": 17, "100": 37, "250": 87, "500": 182, "1000": 355, "2000": 1873}}, {"id": 2758, "position": 2758, "text": "we find some book\nnaturalists—Olassen and Povelson—declaring the Sperm Whale not only to\nbe a consternation to every other creature in the sea, but also to be\nso incredibly ferocious as continually to be athirst for", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2759, "position": 2759, "text": "but also to be\nso incredibly ferocious as continually to be athirst for human blood.\nNor even down to so late a time as Cuvier’s, were these or almost\nsimilar impressions effaced", "labels": {"50": 10, "100": 75, "250": 129, "500": 307, "1000": 343, "2000": 1620}}, {"id": 2760, "position": 2760, "text": "almost\nsimilar impressions effaced. For in his Natural History, the Baron\nhimself affirms that at sight of the Sperm Whale, all fish (sharks\nincluded) are “struck with the most lively terrors,” and “often in the\npre", "labels": {"50": 3, "100": 24, "250": 14, "500": 288, "1000": 825, "2000": 447}}, {"id": 2761, "position": 2761, "text": "struck with the most lively terrors,” and “often in the\nprecipitancy of their flight dash themselves against the rocks with\nsuch violence as to cause instantaneous death.” And however the general\nexperiences in the fishery may amend such reports as", "labels": {"50": 45, "100": 29, "250": 34, "500": 72, "1000": 825, "2000": 447}}, {"id": 2762, "position": 2762, "text": ".” And however the general\nexperiences in the fishery may amend such reports as these; yet in\ntheir full terribleness, even to the bloodthirsty item of Povelson, the\nsuperstitious belief in them is, in some viciss", "labels": {"50": 45, "100": 31, "250": 228, "500": 239, "1000": 692, "2000": 447}}, {"id": 2763, "position": 2763, "text": "son, the\nsuperstitious belief in them is, in some vicissitudes of their\nvocation, revived in the minds of the hunters.\n\nSo that overawed by the rumors and portents concerning him, not a few\nof the fishermen", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 692, "2000": 447}}, {"id": 2764, "position": 2764, "text": "by the rumors and portents concerning him, not a few\nof the fishermen recalled, in reference to Moby Dick, the earlier days\nof the Sperm Whale fishery, when it was oftentimes hard to induce long\npractised Right whalemen to embark in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2765, "position": 2765, "text": "was oftentimes hard to induce long\npractised Right whalemen to embark in the perils of this new and daring\nwarfare; such men protesting that although other leviathans might be\nhopefully pursued, yet to chase and point lance at such an appari", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2766, "position": 2766, "text": "be\nhopefully pursued, yet to chase and point lance at such an apparition\nas the Sperm Whale was not for mortal man. That to attempt it, would be\ninevitably to be torn into a quick eternity", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2767, "position": 2767, "text": "be torn into a quick eternity. On this head, there are\nsome remarkable documents that may be consulted.\n\nNevertheless, some there were, who even in the face of these things\nwere ready to give chase to Moby Dick; and a still greater number", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2768, "position": 2768, "text": "were ready to give chase to Moby Dick; and a still greater number who,\nchancing only to hear of him distantly and vaguely, without the\nspecific details of any certain calamity, and without superstitious\naccompaniments, were sufficiently", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2769, "position": 2769, "text": "certain calamity, and without superstitious\naccompaniments, were sufficiently hardy not to flee from the battle if\noffered.\n\nOne of the wild suggestions referred to, as at last coming to be linked\nwith the White Whale in the minds of the super", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2770, "position": 2770, "text": "last coming to be linked\nwith the White Whale in the minds of the superstitiously inclined, was\nthe unearthly conceit that Moby Dick was ubiquitous; that he had\nactually been encountered in opposite latitudes at one and the same", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2771, "position": 2771, "text": "that he had\nactually been encountered in opposite latitudes at one and the same\ninstant of time.\n\nNor, credulous as such minds must have been, was this conceit\naltogether without some faint show of superstitious probability", "labels": {"50": 22, "100": 78, "250": 229, "500": 469, "1000": 631, "2000": 110}}, {"id": 2772, "position": 2772, "text": "it\naltogether without some faint show of superstitious probability. For as\nthe secrets of the currents in the seas have never yet been divulged,\neven to the most erudite research; so the hidden ways of the Sperm\nWhale when beneath", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2773, "position": 2773, "text": "erudite research; so the hidden ways of the Sperm\nWhale when beneath the surface remain, in great part, unaccountable to\nhis pursuers; and from time to time have originated the most curious\nand contradictory speculations regarding them, especially", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2774, "position": 2774, "text": "to time have originated the most curious\nand contradictory speculations regarding them, especially concerning\nthe mystic modes whereby, after sounding to a great depth, he\ntransports himself with such vast swiftness to the most widely distant\npoints.", "labels": {"50": 10, "100": 71, "250": 50, "500": 395, "1000": 368, "2000": 1374}}, {"id": 2775, "position": 2775, "text": "ness to the most widely distant\npoints.\n\nIt is a thing well known to both American and English whale-ships, and\nas well a thing placed upon authoritative record years ago by Scoresby,\nthat some whales have been captured far north in the Pacific,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2776, "position": 2776, "text": "Scoresby,\nthat some whales have been captured far north in the Pacific, in whose\nbodies have been found the barbs of harpoons darted in the Greenland\nseas. Nor is it to be gainsaid, that in some of these instances it has\nbeen", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2777, "position": 2777, "text": "it to be gainsaid, that in some of these instances it has\nbeen declared that the interval of time between the two assaults could\nnot have exceeded very many days. Hence, by inference, it has been\nbelieved by some whalemen, that the Nor", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2778, "position": 2778, "text": "by inference, it has been\nbelieved by some whalemen, that the Nor’ West Passage, so long a\nproblem to man, was never a problem to the whale. So that here, in the\nreal living experience of living men, the prodi", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2779, "position": 2779, "text": "that here, in the\nreal living experience of living men, the prodigies related in old\ntimes of the inland Strello mountain in Portugal (near whose top there\nwas said to be a lake in which the wrecks of ships floated up to", "labels": {"50": 45, "100": 29, "250": 161, "500": 13, "1000": 9, "2000": 682}}, {"id": 2780, "position": 2780, "text": "said to be a lake in which the wrecks of ships floated up to the\nsurface); and that still more wonderful story of the Arethusa fountain\nnear Syracuse (whose waters were believed to have come from the Holy\nLand by an underground passage)", "labels": {"50": 40, "100": 50, "250": 211, "500": 102, "1000": 9, "2000": 199}}, {"id": 2781, "position": 2781, "text": "waters were believed to have come from the Holy\nLand by an underground passage); these fabulous narrations are almost\nfully equalled by the realities of the whalemen.\n\nForced into familiarity, then, with such prodigies as these; and\nknowing that", "labels": {"50": 45, "100": 66, "250": 211, "500": 13, "1000": 622, "2000": 1097}}, {"id": 2782, "position": 2782, "text": "familiarity, then, with such prodigies as these; and\nknowing that after repeated, intrepid assaults, the White Whale had\nescaped alive; it cannot be much matter of surprise that some whalemen\nshould go still further in their superstitions", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2783, "position": 2783, "text": "of surprise that some whalemen\nshould go still further in their superstitions; declaring Moby Dick not\nonly ubiquitous, but immortal (for immortality is but ubiquity in\ntime); that though groves of spears should be planted in his flanks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2784, "position": 2784, "text": "in\ntime); that though groves of spears should be planted in his flanks, he\nwould still swim away unharmed; or if indeed he should ever be made to\nspout thick blood, such a sight would be but a ghastly deception; for", "labels": {"50": 32, "100": 83, "250": 131, "500": 420, "1000": 191, "2000": 727}}, {"id": 2785, "position": 2785, "text": "blood, such a sight would be but a ghastly deception; for\nagain in unensanguined billows hundreds of leagues away, his unsullied\njet would once more be seen.", "labels": {"50": 22, "100": 78, "250": 28, "500": 469, "1000": 473, "2000": 1257}}, {"id": 2786, "position": 2786, "text": "would once more be seen.\n\nBut even stripped of these supernatural surmisings, there was enough in\nthe earthly make and incontestable character of the monster to strike\nthe imagination with unwonted power", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 2787, "position": 2787, "text": "imagination with unwonted power. For, it was not so much his\nuncommon bulk that so much distinguished him from other sperm whales,\nbut, as was elsewhere thrown out—a peculiar snow-white wrinkled\nforehead, and a high, pyramidical white", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2788, "position": 2788, "text": "a peculiar snow-white wrinkled\nforehead, and a high, pyramidical white hump. These were his prominent\nfeatures; the tokens whereby, even in the limitless, uncharted seas, he\nrevealed his identity, at a long distance,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 2789, "position": 2789, "text": "uncharted seas, he\nrevealed his identity, at a long distance, to those who knew him.\n\nThe rest of his body was so streaked, and spotted, and marbled with the\nsame shrouded hue, that, in the end,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2790, "position": 2790, "text": "d with the\nsame shrouded hue, that, in the end, he had gained his distinctive\nappellation of the White Whale; a name, indeed, literally justified by\nhis vivid aspect, when seen gliding at high noon through a dark blue", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2791, "position": 2791, "text": "by\nhis vivid aspect, when seen gliding at high noon through a dark blue\nsea, leaving a milky-way wake of creamy foam, all spangled with golden\ngleamings.\n\nNor was it his unwonted magnitude, nor his remarkable hue, nor", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 193}}, {"id": 2792, "position": 2792, "text": "Nor was it his unwonted magnitude, nor his remarkable hue, nor yet his\ndeformed lower jaw, that so much invested the whale with natural\nterror, as that unexampled, intelligent malignity which, according to\nspecific accounts", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2793, "position": 2793, "text": "unexampled, intelligent malignity which, according to\nspecific accounts, he had over and over again evinced in his assaults.\nMore than all, his treacherous retreats struck more of dismay than\nperhaps aught else", "labels": {"50": 47, "100": 60, "250": 134, "500": 38, "1000": 92, "2000": 1892}}, {"id": 2794, "position": 2794, "text": "retreats struck more of dismay than\nperhaps aught else. For, when swimming before his exulting pursuers,\nwith every apparent symptom of alarm, he had several times been known\nto turn round suddenly, and, bearing down upon them", "labels": {"50": 45, "100": 55, "250": 138, "500": 43, "1000": 737, "2000": 1620}}, {"id": 2795, "position": 2795, "text": "several times been known\nto turn round suddenly, and, bearing down upon them, either stave their\nboats to splinters, or drive them back in consternation to their ship.\n\nAlready several fatalities had attended his chase", "labels": {"50": 45, "100": 64, "250": 138, "500": 327, "1000": 327, "2000": 576}}, {"id": 2796, "position": 2796, "text": "ship.\n\nAlready several fatalities had attended his chase. But though similar\ndisasters, however little bruited ashore, were by no means unusual in\nthe fishery; yet, in most instances, such seemed the White Whale’s\ninfernal aforeth", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2797, "position": 2797, "text": "instances, such seemed the White Whale’s\ninfernal aforethought of ferocity, that every dismembering or death\nthat he caused, was not wholly regarded as having been inflicted by an\nunintelligent agent.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2798, "position": 2798, "text": "not wholly regarded as having been inflicted by an\nunintelligent agent.\n\nJudge, then, to what pitches of inflamed, distracted fury the minds of\nhis more desperate hunters were impelled, when amid the chips of chewed\nboats, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2799, "position": 2799, "text": "desperate hunters were impelled, when amid the chips of chewed\nboats, and the sinking limbs of torn comrades, they swam out of the\nwhite curds of the whale’s direful wrath into the serene, exasperating\nsunlight, that smiled", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2800, "position": 2800, "text": "direful wrath into the serene, exasperating\nsunlight, that smiled on, as if at a birth or a bridal.\n\nHis three boats stove around him, and oars and men both whirling in the\neddies; one captain", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 9, "2000": 16}}, {"id": 2801, "position": 2801, "text": "oars and men both whirling in the\neddies; one captain, seizing the line-knife from his broken prow, had\ndashed at the whale, as an Arkansas duellist at his foe, blindly\nseeking with a six inch blade to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2802, "position": 2802, "text": "Arkansas duellist at his foe, blindly\nseeking with a six inch blade to reach the fathom-deep life of the\nwhale. That captain was Ahab. And then it was, that suddenly sweeping\nhis sickle-shaped lower jaw beneath him,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2803, "position": 2803, "text": "was, that suddenly sweeping\nhis sickle-shaped lower jaw beneath him, Moby Dick had reaped away\nAhab’s leg, as a mower a blade of grass in the field. No turbaned Turk,\nno hired Venetian", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2804, "position": 2804, "text": "of grass in the field. No turbaned Turk,\nno hired Venetian or Malay, could have smote him with more seeming\nmalice. Small reason was there to doubt, then, that ever since that\nalmost fatal encounter, Ahab had cherished", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 477, "2000": 110}}, {"id": 2805, "position": 2805, "text": "then, that ever since that\nalmost fatal encounter, Ahab had cherished a wild vindictiveness\nagainst the whale, all the more fell for that in his frantic morbidness\nhe at last came to identify with him, not only all his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2806, "position": 2806, "text": "bidness\nhe at last came to identify with him, not only all his bodily woes, but\nall his intellectual and spiritual exasperations. The White Whale swam\nbefore him as the monomaniac incarnation of all those malicious\nagencies which some deep", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2807, "position": 2807, "text": "him as the monomaniac incarnation of all those malicious\nagencies which some deep men feel eating in them, till they are left\nliving on with half a heart and half a lung. That intangible malignity\nwhich has been from the beginning;", "labels": {"50": 10, "100": 75, "250": 155, "500": 80, "1000": 840, "2000": 809}}, {"id": 2808, "position": 2808, "text": ". That intangible malignity\nwhich has been from the beginning; to whose dominion even the modern\nChristians ascribe one-half of the worlds; which the ancient Ophites of\nthe east reverenced in their statue devil;—", "labels": {"50": 10, "100": 75, "250": 129, "500": 307, "1000": 343, "2000": 336}}, {"id": 2809, "position": 2809, "text": "Ophites of\nthe east reverenced in their statue devil;—Ahab did not fall down and\nworship it like them; but deliriously transferring its idea to the\nabhorred white whale, he pitted himself, all mutilated", "labels": {"50": 9, "100": 26, "250": 240, "500": 72, "1000": 437, "2000": 1620}}, {"id": 2810, "position": 2810, "text": "the\nabhorred white whale, he pitted himself, all mutilated, against it. All\nthat most maddens and torments; all that stirs up the lees of things;\nall truth with malice in it; all that cracks the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2811, "position": 2811, "text": "s of things;\nall truth with malice in it; all that cracks the sinews and cakes the\nbrain; all the subtle demonisms of life and thought; all evil, to crazy\nAhab, were visibly personified, and made practically ass", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 624, "2000": 859}}, {"id": 2812, "position": 2812, "text": ", to crazy\nAhab, were visibly personified, and made practically assailable in Moby\nDick. He piled upon the whale’s white hump the sum of all the general\nrage and hate felt by his whole race from Adam down;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2813, "position": 2813, "text": "all the general\nrage and hate felt by his whole race from Adam down; and then, as if\nhis chest had been a mortar, he burst his hot heart’s shell upon it.\n\nIt is not probable that this monomania in him took its", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 448, "2000": 250}}, {"id": 2814, "position": 2814, "text": "upon it.\n\nIt is not probable that this monomania in him took its instant rise at\nthe precise time of his bodily dismemberment. Then, in darting at the\nmonster, knife in hand, he had but given loose to a sudden", "labels": {"50": 0, "100": 4, "250": 229, "500": 336, "1000": 477, "2000": 425}}, {"id": 2815, "position": 2815, "text": "the\nmonster, knife in hand, he had but given loose to a sudden, passionate,\ncorporal animosity; and when he received the stroke that tore him, he\nprobably but felt the agonizing bodily laceration, but nothing more", "labels": {"50": 22, "100": 55, "250": 145, "500": 479, "1000": 959, "2000": 481}}, {"id": 2816, "position": 2816, "text": "but felt the agonizing bodily laceration, but nothing more.\nYet, when by this collision forced to turn towards home, and for long\nmonths of days and weeks, Ahab and anguish lay stretched together in\none hammock, rounding in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2817, "position": 2817, "text": "Ahab and anguish lay stretched together in\none hammock, rounding in mid winter that dreary, howling Patagonian\nCape; then it was, that his torn body and gashed soul bled into one\nanother; and so interfusing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2818, "position": 2818, "text": "body and gashed soul bled into one\nanother; and so interfusing, made him mad. That it was only then, on\nthe homeward voyage, after the encounter, that the final monomania\nseized him, seems all but certain from the", "labels": {"50": 22, "100": 64, "250": 138, "500": 469, "1000": 531, "2000": 1014}}, {"id": 2819, "position": 2819, "text": ", that the final monomania\nseized him, seems all but certain from the fact that, at intervals\nduring the passage, he was a raving lunatic; and, though unlimbed of a\nleg, yet such vital strength yet lurked in his", "labels": {"50": 22, "100": 55, "250": 28, "500": 469, "1000": 959, "2000": 481}}, {"id": 2820, "position": 2820, "text": "limbed of a\nleg, yet such vital strength yet lurked in his Egyptian chest, and was\nmoreover intensified by his delirium, that his mates were forced to\nlace him fast, even there, as he sailed, raving in his ham", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2821, "position": 2821, "text": "him fast, even there, as he sailed, raving in his hammock. In a\nstrait-jacket, he swung to the mad rockings of the gales. And, when\nrunning into more sufferable latitudes, the ship,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 2822, "position": 2822, "text": ". And, when\nrunning into more sufferable latitudes, the ship, with mild stun’sails\nspread, floated across the tranquil tropics, and, to all appearances,\nthe old man’s delirium seemed left behind him", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 300, "2000": 1014}}, {"id": 2823, "position": 2823, "text": "all appearances,\nthe old man’s delirium seemed left behind him with the Cape Horn\nswells, and he came forth from his dark den into the blessed light and\nair; even then, when he bore that firm, collected front, however", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2824, "position": 2824, "text": "air; even then, when he bore that firm, collected front, however pale,\nand issued his calm orders once again; and his mates thanked God the\ndireful madness was now gone; even then, Ahab, in his hidden self,\nrave", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2825, "position": 2825, "text": "now gone; even then, Ahab, in his hidden self,\nraved on. Human madness is oftentimes a cunning and most feline thing.\nWhen you think it fled, it may have but become transfigured into some\nstill", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2826, "position": 2826, "text": "it fled, it may have but become transfigured into some\nstill subtler form. Ahab’s full lunacy subsided not, but deepeningly\ncontracted; like the unabated Hudson, when that noble Northman flows\nnarrowly,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2827, "position": 2827, "text": "like the unabated Hudson, when that noble Northman flows\nnarrowly, but unfathomably through the Highland gorge. But, as in his\nnarrow-flowing monomania, not one jot of Ahab’s broad madness had been\nleft", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2828, "position": 2828, "text": ", not one jot of Ahab’s broad madness had been\nleft behind; so in that broad madness, not one jot of his great natural\nintellect had perished. That before living agent, now became the living\ninstrument", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2829, "position": 2829, "text": "That before living agent, now became the living\ninstrument. If such a furious trope may stand, his special lunacy\nstormed his general sanity, and carried it, and turned all its\nconcentred cannon upon its own mad mark; so that far", "labels": {"50": 22, "100": 78, "250": 205, "500": 469, "1000": 448, "2000": 1554}}, {"id": 2830, "position": 2830, "text": "all its\nconcentred cannon upon its own mad mark; so that far from having lost\nhis strength, Ahab, to that one end, did now possess a thousand fold\nmore potency than ever he had sanely brought to bear upon any one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2831, "position": 2831, "text": "more potency than ever he had sanely brought to bear upon any one\nreasonable object.\n\nThis is much; yet Ahab’s larger, darker, deeper part remains unhinted.\nBut vain to popularize profundities, and all truth", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2832, "position": 2832, "text": "hinted.\nBut vain to popularize profundities, and all truth is profound. Winding\nfar down from within the very heart of this spiked Hotel de Cluny where\nwe here stand—however grand and wonderful, now quit it;—and", "labels": {"50": 20, "100": 45, "250": 245, "500": 401, "1000": 893, "2000": 842}}, {"id": 2833, "position": 2833, "text": "we here stand—however grand and wonderful, now quit it;—and take your\nway, ye nobler, sadder souls, to those vast Roman halls of Thermes;\nwhere far beneath the fantastic towers of man’s upper earth,", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 463}}, {"id": 2834, "position": 2834, "text": "es;\nwhere far beneath the fantastic towers of man’s upper earth, his root\nof grandeur, his whole awful essence sits in bearded state; an antique\nburied beneath antiquities, and throned on torsoes! So with a broken\nthrone, the", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 573}}, {"id": 2835, "position": 2835, "text": ", and throned on torsoes! So with a broken\nthrone, the great gods mock that captive king; so like a Caryatid, he\npatient sits, upholding on his frozen brow the piled entablatures of\nages", "labels": {"50": 9, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 573}}, {"id": 2836, "position": 2836, "text": "on his frozen brow the piled entablatures of\nages. Wind ye down there, ye prouder, sadder souls! question that\nproud, sad king! A family likeness! aye, he did beget ye, ye young\nexiled royalties;", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 198}}, {"id": 2837, "position": 2837, "text": "likeness! aye, he did beget ye, ye young\nexiled royalties; and from your grim sire only will the old\nState-secret come.\n\nNow, in his heart, Ahab had some glimpse of this, namely: all my means\nare sane", "labels": {"50": 9, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2838, "position": 2838, "text": "Ahab had some glimpse of this, namely: all my means\nare sane, my motive and my object mad. Yet without power to kill, or\nchange, or shun the fact; he likewise knew that to mankind he did long\ndissemble", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2839, "position": 2839, "text": "the fact; he likewise knew that to mankind he did long\ndissemble; in some sort, did still. But that thing of his dissembling\nwas only subject to his perceptibility, not to his will determinate", "labels": {"50": 10, "100": 71, "250": 129, "500": 307, "1000": 343, "2000": 761}}, {"id": 2840, "position": 2840, "text": "his perceptibility, not to his will determinate.\nNevertheless, so well did he succeed in that dissembling, that when\nwith ivory leg he stepped ashore at last, no Nantucketer thought him\notherwise than but naturally grieved", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2841, "position": 2841, "text": "last, no Nantucketer thought him\notherwise than but naturally grieved, and that to the quick, with the\nterrible casualty which had overtaken him.\n\nThe report of his undeniable delirium at sea was likewise popularly\nascribed to a", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2842, "position": 2842, "text": "his undeniable delirium at sea was likewise popularly\nascribed to a kindred cause. And so too, all the added moodiness which\nalways afterwards, to the very day of sailing in the Pequod on the\npresent voyage, sat brooding", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2843, "position": 2843, "text": "day of sailing in the Pequod on the\npresent voyage, sat brooding on his brow. Nor is it so very unlikely,\nthat far from distrusting his fitness for another whaling voyage, on\naccount of such dark symptoms, the calculating people of that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2844, "position": 2844, "text": "whaling voyage, on\naccount of such dark symptoms, the calculating people of that prudent\nisle were inclined to harbor the conceit, that for those very reasons\nhe was all the better qualified and set on edge, for a pursuit so full\nof", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 723, "2000": 1620}}, {"id": 2845, "position": 2845, "text": "all the better qualified and set on edge, for a pursuit so full\nof rage and wildness as the bloody hunt of whales. Gnawed within and\nscorched without, with the infixed, unrelenting fangs of some incurable\nidea", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2846, "position": 2846, "text": ", with the infixed, unrelenting fangs of some incurable\nidea; such an one, could he be found, would seem the very man to dart\nhis iron and lift his lance against the most appalling of all brutes", "labels": {"50": 23, "100": 45, "250": 244, "500": 202, "1000": 851, "2000": 425}}, {"id": 2847, "position": 2847, "text": "lift his lance against the most appalling of all brutes.\nOr, if for any reason thought to be corporeally incapacitated for that,\nyet such an one would seem superlatively competent to cheer and howl on\nhis underlings", "labels": {"50": 23, "100": 4, "250": 193, "500": 202, "1000": 649, "2000": 371}}, {"id": 2848, "position": 2848, "text": "one would seem superlatively competent to cheer and howl on\nhis underlings to the attack. But be all this as it may, certain it is,\nthat with the mad secret of his unabated rage bolted up and keyed in\nhim,", "labels": {"50": 22, "100": 88, "250": 145, "500": 180, "1000": 296, "2000": 110}}, {"id": 2849, "position": 2849, "text": "secret of his unabated rage bolted up and keyed in\nhim, Ahab had purposely sailed upon the present voyage with the one\nonly and all-engrossing object of hunting the White Whale. Had any one\nof his old acquaintances on shore", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2850, "position": 2850, "text": "of hunting the White Whale. Had any one\nof his old acquaintances on shore but half dreamed of what was lurking\nin him then, how soon would their aghast and righteous souls have\nwrenched the ship from such a fiendish man! They were", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2851, "position": 2851, "text": "souls have\nwrenched the ship from such a fiendish man! They were bent on\nprofitable cruises, the profit to be counted down in dollars from the\nmint. He was intent on an audacious, immitigable, and supernatural\nrevenge.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 1904}}, {"id": 2852, "position": 2852, "text": "on an audacious, immitigable, and supernatural\nrevenge.\n\nHere, then, was this grey-headed, ungodly old man, chasing with curses\na Job’s whale round the world, at the head of a crew,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2853, "position": 2853, "text": "Job’s whale round the world, at the head of a crew, too, chiefly made\nup of mongrel renegades, and castaways, and cannibals—morally enfeebled\nalso, by the incompete", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2854, "position": 2854, "text": "bals—morally enfeebled\nalso, by the incompetence of mere unaided virtue or right-mindedness in\nStarbuck, the invulnerable jollity of indifference and recklessness in\nStubb, and the", "labels": {"50": 21, "100": 75, "250": 88, "500": 15, "1000": 821, "2000": 1268}}, {"id": 2855, "position": 2855, "text": "ble jollity of indifference and recklessness in\nStubb, and the pervading mediocrity in Flask. Such a crew, so\nofficered, seemed specially picked and packed by some infernal fatality\nto help him to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2856, "position": 2856, "text": "specially picked and packed by some infernal fatality\nto help him to his monomaniac revenge. How it was that they so\naboundingly responded to the old man’s ire—by what evil magic their\nsouls were possessed, that", "labels": {"50": 5, "100": 78, "250": 210, "500": 420, "1000": 57, "2000": 1101}}, {"id": 2857, "position": 2857, "text": "’s ire—by what evil magic their\nsouls were possessed, that at times his hate seemed almost theirs; the\nWhite Whale as much their insufferable foe as his; how all this came to\nbe—what the White Whale was to", "labels": {"50": 22, "100": 78, "250": 229, "500": 72, "1000": 448, "2000": 1620}}, {"id": 2858, "position": 2858, "text": "his; how all this came to\nbe—what the White Whale was to them, or how to their unconscious\nunderstandings, also, in some dim, unsuspected way, he might have\nseemed the gliding great demon of the seas of life", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2859, "position": 2859, "text": "way, he might have\nseemed the gliding great demon of the seas of life,—all this to\nexplain, would be to dive deeper than Ishmael can go. The subterranean\nminer that works in us all, how can one tell whither", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2860, "position": 2860, "text": "subterranean\nminer that works in us all, how can one tell whither leads his shaft by\nthe ever shifting, muffled sound of his pick? Who does not feel the\nirresistible arm drag? What skiff in tow of a seventy-four can stand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 631}}, {"id": 2861, "position": 2861, "text": "arm drag? What skiff in tow of a seventy-four can stand\nstill? For one, I gave myself up to the abandonment of the time and the\nplace; but while yet all a-rush to encounter the whale, could see\nnaught", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1521}}, {"id": 2862, "position": 2862, "text": "while yet all a-rush to encounter the whale, could see\nnaught in that brute but the deadliest ill.\n\n\nCHAPTER 42. The Whiteness of the Whale.\n\nWhat the white whale was to Ahab, has been hinted; what, at", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2863, "position": 2863, "text": "the white whale was to Ahab, has been hinted; what, at times, he\nwas to me, as yet remains unsaid.\n\nAside from those more obvious considerations touching Moby Dick, which\ncould not but occasionally awaken in any man", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2864, "position": 2864, "text": "touching Moby Dick, which\ncould not but occasionally awaken in any man’s soul some alarm, there\nwas another thought, or rather vague, nameless horror concerning him,\nwhich at times by its intensity completely overpowered all the rest;\nand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2865, "position": 2865, "text": ",\nwhich at times by its intensity completely overpowered all the rest;\nand yet so mystical and well nigh ineffable was it, that I almost\ndespair of putting it in a comprehensible form", "labels": {"50": 20, "100": 56, "250": 116, "500": 0, "1000": 173, "2000": 926}}, {"id": 2866, "position": 2866, "text": "it in a comprehensible form. It was the whiteness of\nthe whale that above all things appalled me. But how can I hope to\nexplain myself here; and yet, in some dim, random way, explain myself I\nmust, else", "labels": {"50": 25, "100": 5, "250": 45, "500": 411, "1000": 21, "2000": 1254}}, {"id": 2867, "position": 2867, "text": "yet, in some dim, random way, explain myself I\nmust, else all these chapters might be naught.\n\nThough in many natural objects, whiteness refiningly enhances beauty,\nas if imparting some special virtue of its own, as", "labels": {"50": 48, "100": 20, "250": 90, "500": 162, "1000": 727, "2000": 1735}}, {"id": 2868, "position": 2868, "text": "beauty,\nas if imparting some special virtue of its own, as in marbles,\njaponicas, and pearls; and though various nations have in some way\nrecognised a certain royal preeminence in this hue; even the bar", "labels": {"50": 23, "100": 45, "250": 244, "500": 202, "1000": 102, "2000": 507}}, {"id": 2869, "position": 2869, "text": "recognised a certain royal preeminence in this hue; even the barbaric,\ngrand old kings of Pegu placing the title “Lord of the White Elephants”\nabove all their other magniloquent ascriptions of dominion; and the", "labels": {"50": 32, "100": 42, "250": 153, "500": 466, "1000": 555, "2000": 271}}, {"id": 2870, "position": 2870, "text": "all their other magniloquent ascriptions of dominion; and the\nmodern kings of Siam unfurling the same snow-white quadruped in the\nroyal standard; and the Hanoverian flag bearing the one figure of a\nsnow-white charge", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 886, "2000": 174}}, {"id": 2871, "position": 2871, "text": "and the Hanoverian flag bearing the one figure of a\nsnow-white charger; and the great Austrian Empire, Cæsarian, heir to\noverlording Rome, having for the imperial colour the same imperial hue;\nand though this pre-", "labels": {"50": 21, "100": 95, "250": 43, "500": 480, "1000": 347, "2000": 151}}, {"id": 2872, "position": 2872, "text": "having for the imperial colour the same imperial hue;\nand though this pre-eminence in it applies to the human race itself,\ngiving the white man ideal mastership over every dusky tribe; and\nthough, besides, all this, whiteness", "labels": {"50": 32, "100": 42, "250": 158, "500": 414, "1000": 451, "2000": 835}}, {"id": 2873, "position": 2873, "text": "every dusky tribe; and\nthough, besides, all this, whiteness has been even made significant of\ngladness, for among the Romans a white stone marked a joyful day; and\nthough in other mortal sympathies and symbolizings", "labels": {"50": 48, "100": 27, "250": 223, "500": 339, "1000": 832, "2000": 440}}, {"id": 2874, "position": 2874, "text": "day; and\nthough in other mortal sympathies and symbolizings, this same hue is\nmade the emblem of many touching, noble things—the innocence of brides,\nthe benignity of age; though among the Red Men of America the", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 252, "2000": 970}}, {"id": 2875, "position": 2875, "text": ",\nthe benignity of age; though among the Red Men of America the giving of\nthe white belt of wampum was the deepest pledge of honor; though in\nmany climes, whiteness typifies the majesty of Justice in the er", "labels": {"50": 5, "100": 66, "250": 189, "500": 490, "1000": 858, "2000": 1171}}, {"id": 2876, "position": 2876, "text": "imes, whiteness typifies the majesty of Justice in the ermine of\nthe Judge, and contributes to the daily state of kings and queens drawn\nby milk-white steeds; though even in the higher mysteries of the most\naugust religions", "labels": {"50": 43, "100": 48, "250": 71, "500": 396, "1000": 336, "2000": 439}}, {"id": 2877, "position": 2877, "text": "steeds; though even in the higher mysteries of the most\naugust religions it has been made the symbol of the divine spotlessness\nand power; by the Persian fire worshippers, the white forked flame\nbeing held the holiest on the altar;", "labels": {"50": 32, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1010}}, {"id": 2878, "position": 2878, "text": ", the white forked flame\nbeing held the holiest on the altar; and in the Greek mythologies,\nGreat Jove himself being made incarnate in a snow-white bull; and\nthough to the noble Iroquois, the midwinter sacrifice", "labels": {"50": 10, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1010}}, {"id": 2879, "position": 2879, "text": "white bull; and\nthough to the noble Iroquois, the midwinter sacrifice of the sacred\nWhite Dog was by far the holiest festival of their theology, that\nspotless, faithful creature being held the purest envoy they could send\nto the Great Spirit", "labels": {"50": 12, "100": 38, "250": 65, "500": 171, "1000": 954, "2000": 309}}, {"id": 2880, "position": 2880, "text": "faithful creature being held the purest envoy they could send\nto the Great Spirit with the annual tidings of their own fidelity; and\nthough directly from the Latin word for white, all Christian priests\nderive the name of one part of their sacred vesture", "labels": {"50": 26, "100": 66, "250": 211, "500": 23, "1000": 662, "2000": 205}}, {"id": 2881, "position": 2881, "text": ", all Christian priests\nderive the name of one part of their sacred vesture, the alb or tunic,\nworn beneath the cassock; and though among the holy pomps of the Romish\nfaith, white is specially employed in the celebration of the", "labels": {"50": 48, "100": 66, "250": 139, "500": 165, "1000": 398, "2000": 747}}, {"id": 2882, "position": 2882, "text": "of the Romish\nfaith, white is specially employed in the celebration of the Passion of\nour Lord; though in the Vision of St. John, white robes are given to\nthe redeemed, and the four-and-twenty elders stand clothed in", "labels": {"50": 49, "100": 66, "250": 177, "500": 322, "1000": 762, "2000": 127}}, {"id": 2883, "position": 2883, "text": "redeemed, and the four-and-twenty elders stand clothed in white\nbefore the great white throne, and the Holy One that sitteth there\nwhite like wool; yet for all these accumulated associations, with\nwhatever is sweet, and honorable,", "labels": {"50": 27, "100": 97, "250": 112, "500": 50, "1000": 654, "2000": 1363}}, {"id": 2884, "position": 2884, "text": "yet for all these accumulated associations, with\nwhatever is sweet, and honorable, and sublime, there yet lurks an\nelusive something in the innermost idea of this hue, which strikes more\nof panic to the soul than that redness which affright", "labels": {"50": 17, "100": 16, "250": 87, "500": 483, "1000": 15, "2000": 1601}}, {"id": 2885, "position": 2885, "text": "strikes more\nof panic to the soul than that redness which affrights in blood.\n\nThis elusive quality it is, which causes the thought of whiteness, when\ndivorced from more kindly associations, and coupled with any object\nterrible in itself, to", "labels": {"50": 10, "100": 71, "250": 13, "500": 483, "1000": 100, "2000": 1916}}, {"id": 2886, "position": 2886, "text": "from more kindly associations, and coupled with any object\nterrible in itself, to heighten that terror to the furthest bounds.\nWitness the white bear of the poles, and the white shark of the\ntropics; what but their smooth, flak", "labels": {"50": 10, "100": 75, "250": 13, "500": 414, "1000": 448, "2000": 710}}, {"id": 2887, "position": 2887, "text": "white shark of the\ntropics; what but their smooth, flaky whiteness makes them the\ntranscendent horrors they are? That ghastly whiteness it is which\nimparts such an abhorrent mildness, even more lo", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 2888, "position": 2888, "text": "is which\nimparts such an abhorrent mildness, even more loathsome than terrific,\nto the dumb gloating of their aspect. So that not the fierce-fanged\ntiger in his heraldic coat can so stagger courage as the", "labels": {"50": 25, "100": 41, "250": 156, "500": 134, "1000": 103, "2000": 453}}, {"id": 2889, "position": 2889, "text": "-fanged\ntiger in his heraldic coat can so stagger courage as the white-shrouded\nbear or shark.*\n\n*With reference to the Polar bear, it may possibly be urged by him who\nwould fain go still deeper into this matter", "labels": {"50": 14, "100": 52, "250": 187, "500": 168, "1000": 326, "2000": 1497}}, {"id": 2890, "position": 2890, "text": "possibly be urged by him who\nwould fain go still deeper into this matter, that it is not the\nwhiteness, separately regarded, which heightens the intolerable\nhideousness of that brute; for, analysed, that heightened hideousness", "labels": {"50": 10, "100": 75, "250": 88, "500": 15, "1000": 256, "2000": 710}}, {"id": 2891, "position": 2891, "text": "ness of that brute; for, analysed, that heightened hideousness,\nit might be said, only rises from the circumstance, that the\nirresponsible ferociousness of the creature stands invested in the\nfleece of celestial innocence and love;", "labels": {"50": 17, "100": 16, "250": 87, "500": 483, "1000": 355, "2000": 515}}, {"id": 2892, "position": 2892, "text": "of the creature stands invested in the\nfleece of celestial innocence and love; and hence, by bringing together\ntwo such opposite emotions in our minds, the Polar bear frightens us\nwith so unnatural a contrast. But even assuming all this to be true;", "labels": {"50": 10, "100": 94, "250": 13, "500": 236, "1000": 548, "2000": 1973}}, {"id": 2893, "position": 2893, "text": "with so unnatural a contrast. But even assuming all this to be true;\nyet, were it not for the whiteness, you would not have that intensified\nterror.\n\nAs for the white shark, the white gliding ghostliness of repose in that\ncreature", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 747, "2000": 1735}}, {"id": 2894, "position": 2894, "text": "the white shark, the white gliding ghostliness of repose in that\ncreature, when beheld in his ordinary moods, strangely tallies with the\nsame quality in the Polar quadruped. This peculiarity is most vividly\nhit by the French in", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 2895, "position": 2895, "text": "ruped. This peculiarity is most vividly\nhit by the French in the name they bestow upon that fish. The Romish\nmass for the dead begins with “Requiem eternam” (eternal rest), whence\n_Requiem_ den", "labels": {"50": 48, "100": 27, "250": 157, "500": 63, "1000": 375, "2000": 965}}, {"id": 2896, "position": 2896, "text": "eternam” (eternal rest), whence\n_Requiem_ denominating the mass itself, and any other funeral music.\nNow, in allusion to the white, silent stillness of death in this shark,\nand the mild deadliness", "labels": {"50": 49, "100": 16, "250": 116, "500": 0, "1000": 173, "2000": 1191}}, {"id": 2897, "position": 2897, "text": "white, silent stillness of death in this shark,\nand the mild deadliness of his habits, the French call him _Requin_.\n\nBethink thee of the albatross, whence come those clouds of spiritual\nwonderment and pale dread,", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 16}}, {"id": 2898, "position": 2898, "text": "ss, whence come those clouds of spiritual\nwonderment and pale dread, in which that white phantom sails in all\nimaginations? Not Coleridge first threw that spell; but God’s great,\nunflattering laureate, Nature.*", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 1203}}, {"id": 2899, "position": 2899, "text": "God’s great,\nunflattering laureate, Nature.*\n\n*I remember the first albatross I ever saw. It was during a prolonged\ngale, in waters hard upon the Antarctic seas. From my forenoon watch\nbelow, I", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2900, "position": 2900, "text": "hard upon the Antarctic seas. From my forenoon watch\nbelow, I ascended to the overclouded deck; and there, dashed upon the\nmain hatches, I saw a regal, feathery thing of unspotted whiteness, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 2901, "position": 2901, "text": "saw a regal, feathery thing of unspotted whiteness, and\nwith a hooked, Roman bill sublime. At intervals, it arched forth its\nvast archangel wings, as if to embrace some holy ark", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 471}}, {"id": 2902, "position": 2902, "text": "if to embrace some holy ark. Wondrous\nflutterings and throbbings shook it. Though bodily unharmed, it uttered\ncries, as some king’s ghost in supernatural distress. Through its\ninexpressible, strange eyes, methought I", "labels": {"50": 16, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2903, "position": 2903, "text": ". Through its\ninexpressible, strange eyes, methought I peeped to secrets which took\nhold of God. As Abraham before the angels, I bowed myself; the white\nthing was so white, its wings so wide, and in those", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1254}}, {"id": 2904, "position": 2904, "text": "the white\nthing was so white, its wings so wide, and in those for ever exiled\nwaters, I had lost the miserable warping memories of traditions and of\ntowns. Long I gazed at that prodigy of plumage", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 986}}, {"id": 2905, "position": 2905, "text": "I gazed at that prodigy of plumage. I cannot tell, can only\nhint, the things that darted through me then. But at last I awoke; and\nturning, asked a sailor what bird was this. A goney, he replied", "labels": {"50": 16, "100": 24, "250": 213, "500": 331, "1000": 987, "2000": 1198}}, {"id": 2906, "position": 2906, "text": "sailor what bird was this. A goney, he replied. Goney!\nnever had heard that name before; is it conceivable that this glorious\nthing is utterly unknown to men ashore! never! But some time after, I\nlearned that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 967}}, {"id": 2907, "position": 2907, "text": "unknown to men ashore! never! But some time after, I\nlearned that goney was some seaman’s name for albatross. So that by no\npossibility could Coleridge’s wild Rhyme have had aught to do with\nthose mystical impressions", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2908, "position": 2908, "text": "ridge’s wild Rhyme have had aught to do with\nthose mystical impressions which were mine, when I saw that bird upon\nour deck. For neither had I then read the Rhyme, nor knew the bird to\nbe an albatross", "labels": {"50": 3, "100": 24, "250": 213, "500": 331, "1000": 332, "2000": 1198}}, {"id": 2909, "position": 2909, "text": "Rhyme, nor knew the bird to\nbe an albatross. Yet, in saying this, I do but indirectly burnish a\nlittle brighter the noble merit of the poem and the poet.\n\nI assert, then, that in the wondrous bodily", "labels": {"50": 16, "100": 73, "250": 87, "500": 331, "1000": 944, "2000": 737}}, {"id": 2910, "position": 2910, "text": "the poet.\n\nI assert, then, that in the wondrous bodily whiteness of the bird\nchiefly lurks the secret of the spell; a truth the more evinced in\nthis, that by a solecism of terms there are birds", "labels": {"50": 3, "100": 24, "250": 213, "500": 331, "1000": 987, "2000": 1198}}, {"id": 2911, "position": 2911, "text": "ced in\nthis, that by a solecism of terms there are birds called grey\nalbatrosses; and these I have frequently seen, but never with such\nemotions as when I beheld the Antarctic fowl.", "labels": {"50": 45, "100": 29, "250": 34, "500": 306, "1000": 161, "2000": 665}}, {"id": 2912, "position": 2912, "text": "when I beheld the Antarctic fowl.\n\nBut how had the mystic thing been caught? Whisper it not, and I will\ntell; with a treacherous hook and line, as the fowl floated on the sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 2913, "position": 2913, "text": "as the fowl floated on the sea.\nAt last the Captain made a postman of it; tying a lettered, leathern\ntally round its neck, with the ship’s time and place; and then letting\nit escape", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 2914, "position": 2914, "text": "ship’s time and place; and then letting\nit escape. But I doubt not, that leathern tally, meant for man, was\ntaken off in Heaven, when the white fowl flew to join the wing-folding,\nthe invoking", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 2915, "position": 2915, "text": "white fowl flew to join the wing-folding,\nthe invoking, and adoring cherubim!\n\nMost famous in our Western annals and Indian traditions is that of the\nWhite Steed of the Prairies; a magnificent milk-white", "labels": {"50": 12, "100": 38, "250": 65, "500": 171, "1000": 954, "2000": 309}}, {"id": 2916, "position": 2916, "text": "of the\nWhite Steed of the Prairies; a magnificent milk-white charger,\nlarge-eyed, small-headed, bluff-chested, and with the dignity of a\nthousand monarchs in his lofty, overscorning carriage", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 198}}, {"id": 2917, "position": 2917, "text": "of a\nthousand monarchs in his lofty, overscorning carriage. He was the\nelected Xerxes of vast herds of wild horses, whose pastures in those\ndays were only fenced by the Rocky Mountains and the Alleghanies", "labels": {"50": 37, "100": 6, "250": 25, "500": 93, "1000": 772, "2000": 114}}, {"id": 2918, "position": 2918, "text": "fenced by the Rocky Mountains and the Alleghanies. At\ntheir flaming head he westward trooped it like that chosen star which\nevery evening leads on the hosts of light. The flashing cascade of his\nmane, the curving comet of his tail,", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 198}}, {"id": 2919, "position": 2919, "text": ". The flashing cascade of his\nmane, the curving comet of his tail, invested him with housings more\nresplendent than gold and silver-beaters could have furnished him. A\nmost imperial and archangelical apparition of that unfall", "labels": {"50": 22, "100": 78, "250": 189, "500": 297, "1000": 298, "2000": 1646}}, {"id": 2920, "position": 2920, "text": "him. A\nmost imperial and archangelical apparition of that unfallen, western\nworld, which to the eyes of the old trappers and hunters revived the\nglories of those primeval times when Adam walked majestic as a god,\nbluff", "labels": {"50": 5, "100": 66, "250": 69, "500": 307, "1000": 343, "2000": 761}}, {"id": 2921, "position": 2921, "text": "ies of those primeval times when Adam walked majestic as a god,\nbluff-browed and fearless as this mighty steed. Whether marching amid\nhis aides and marshals in the van of countless cohorts that endlessly\nstreamed it over the", "labels": {"50": 22, "100": 78, "250": 140, "500": 286, "1000": 252, "2000": 923}}, {"id": 2922, "position": 2922, "text": "in the van of countless cohorts that endlessly\nstreamed it over the plains, like an Ohio; or whether with his\ncircumambient subjects browsing all around at the horizon, the White\nSteed gallopingly reviewed them with warm", "labels": {"50": 22, "100": 88, "250": 70, "500": 202, "1000": 858, "2000": 110}}, {"id": 2923, "position": 2923, "text": "at the horizon, the White\nSteed gallopingly reviewed them with warm nostrils reddening through\nhis cool milkiness; in whatever aspect he presented himself, always to\nthe bravest Indians he was the object of trembling reverence and awe", "labels": {"50": 12, "100": 19, "250": 161, "500": 203, "1000": 41, "2000": 445}}, {"id": 2924, "position": 2924, "text": "bravest Indians he was the object of trembling reverence and awe.\nNor can it be questioned from what stands on legendary record of this\nnoble horse, that it was his spiritual whiteness chiefly, which so\nclothed him with divineness; and that this", "labels": {"50": 12, "100": 38, "250": 65, "500": 171, "1000": 954, "2000": 309}}, {"id": 2925, "position": 2925, "text": "whiteness chiefly, which so\nclothed him with divineness; and that this divineness had that in it\nwhich, though commanding worship, at the same time enforced a certain\nnameless terror.\n\nBut there are other instances where this whiteness loses all that", "labels": {"50": 31, "100": 75, "250": 106, "500": 483, "1000": 199, "2000": 1294}}, {"id": 2926, "position": 2926, "text": "less terror.\n\nBut there are other instances where this whiteness loses all that\naccessory and strange glory which invests it in the White Steed and\nAlbatross.\n\nWhat is it that in the Albino man so peculiarly repels and often shocks", "labels": {"50": 31, "100": 7, "250": 13, "500": 453, "1000": 15, "2000": 1828}}, {"id": 2927, "position": 2927, "text": "it that in the Albino man so peculiarly repels and often shocks\nthe eye, as that sometimes he is loathed by his own kith and kin! It is\nthat whiteness which invests him, a thing expressed by the name", "labels": {"50": 31, "100": 75, "250": 13, "500": 307, "1000": 355, "2000": 1394}}, {"id": 2928, "position": 2928, "text": "is\nthat whiteness which invests him, a thing expressed by the name he\nbears. The Albino is as well made as other men—has no substantive\ndeformity—and yet this mere aspect of all-pervading whiteness makes", "labels": {"50": 31, "100": 75, "250": 13, "500": 29, "1000": 355, "2000": 433}}, {"id": 2929, "position": 2929, "text": "—and yet this mere aspect of all-pervading whiteness makes him\nmore strangely hideous than the ugliest abortion. Why should this be\nso?\n\nNor, in quite other aspects, does Nature in her least palpable but not\nthe", "labels": {"50": 31, "100": 16, "250": 146, "500": 483, "1000": 314, "2000": 1394}}, {"id": 2930, "position": 2930, "text": "quite other aspects, does Nature in her least palpable but not\nthe less malicious agencies, fail to enlist among her forces this\ncrowning attribute of the terrible. From its snowy aspect, the\ngauntleted ghost of the Southern Seas has been den", "labels": {"50": 31, "100": 20, "250": 13, "500": 126, "1000": 747, "2000": 1560}}, {"id": 2931, "position": 2931, "text": "snowy aspect, the\ngauntleted ghost of the Southern Seas has been denominated the White\nSquall. Nor, in some historic instances, has the art of human malice\nomitted so potent an auxiliary", "labels": {"50": 31, "100": 95, "250": 146, "500": 29, "1000": 355, "2000": 1394}}, {"id": 2932, "position": 2932, "text": "malice\nomitted so potent an auxiliary. How wildly it heightens the effect of\nthat passage in Froissart, when, masked in the snowy symbol of their\nfaction, the desperate White Hoods of Ghent murder their bailiff in the\nmarket-place", "labels": {"50": 47, "100": 60, "250": 6, "500": 261, "1000": 338, "2000": 254}}, {"id": 2933, "position": 2933, "text": "desperate White Hoods of Ghent murder their bailiff in the\nmarket-place!\n\nNor, in some things, does the common, hereditary experience of all\nmankind fail to bear witness to the supernaturalism of this hue", "labels": {"50": 1, "100": 80, "250": 11, "500": 497, "1000": 475, "2000": 1554}}, {"id": 2934, "position": 2934, "text": "to the supernaturalism of this hue. It\ncannot well be doubted, that the one visible quality in the aspect of\nthe dead which most appals the gazer, is the marble pallor lingering\nthere; as if indeed that pallor were as much", "labels": {"50": 49, "100": 74, "250": 196, "500": 322, "1000": 762, "2000": 175}}, {"id": 2935, "position": 2935, "text": "marble pallor lingering\nthere; as if indeed that pallor were as much like the badge of\nconsternation in the other world, as of mortal trepidation here. And\nfrom that pallor of the dead, we borrow the expressive hue of", "labels": {"50": 49, "100": 27, "250": 223, "500": 339, "1000": 832, "2000": 175}}, {"id": 2936, "position": 2936, "text": "And\nfrom that pallor of the dead, we borrow the expressive hue of the\nshroud in which we wrap them. Nor even in our superstitions do we fail\nto throw the same snowy mantle round our phantoms; all ghosts rising in\na", "labels": {"50": 16, "100": 20, "250": 210, "500": 370, "1000": 375, "2000": 965}}, {"id": 2937, "position": 2937, "text": "throw the same snowy mantle round our phantoms; all ghosts rising in\na milk-white fog—Yea, while these terrors seize us, let us add, that\neven the king of terrors, when personified by the evangelist, rides", "labels": {"50": 17, "100": 16, "250": 87, "500": 71, "1000": 361, "2000": 521}}, {"id": 2938, "position": 2938, "text": "even the king of terrors, when personified by the evangelist, rides on\nhis pallid horse.\n\nTherefore, in his other moods, symbolize whatever grand or gracious\nthing he will by whiteness, no man can deny that in its profound", "labels": {"50": 48, "100": 27, "250": 249, "500": 339, "1000": 878, "2000": 180}}, {"id": 2939, "position": 2939, "text": "thing he will by whiteness, no man can deny that in its profoundest\nidealized significance it calls up a peculiar apparition to the soul.\n\nBut though without dissent this point be fixed, how is mortal man to\naccount for it? To", "labels": {"50": 10, "100": 71, "250": 13, "500": 236, "1000": 548, "2000": 1944}}, {"id": 2940, "position": 2940, "text": "this point be fixed, how is mortal man to\naccount for it? To analyse it, would seem impossible. Can we, then, by\nthe citation of some of those instances wherein this thing of\nwhiteness—though for the time either wholly or", "labels": {"50": 10, "100": 71, "250": 129, "500": 64, "1000": 256, "2000": 515}}, {"id": 2941, "position": 2941, "text": "instances wherein this thing of\nwhiteness—though for the time either wholly or in great part stripped\nof all direct associations calculated to impart to it aught fearful,\nbut nevertheless, is found to exert over us the same sorcery, however", "labels": {"50": 10, "100": 71, "250": 210, "500": 41, "1000": 134, "2000": 1101}}, {"id": 2942, "position": 2942, "text": ", is found to exert over us the same sorcery, however\nmodified;—can we thus hope to light upon some chance clue to conduct us\nto the hidden cause we seek?\n\nLet us try", "labels": {"50": 10, "100": 71, "250": 210, "500": 395, "1000": 368, "2000": 1365}}, {"id": 2943, "position": 2943, "text": "we seek?\n\nLet us try. But in a matter like this, subtlety appeals to subtlety,\nand without imagination no man can follow another into these halls. And\nthough, doubtless, some at least of the imaginative impressions about\nto be presented", "labels": {"50": 17, "100": 16, "250": 146, "500": 369, "1000": 314, "2000": 521}}, {"id": 2944, "position": 2944, "text": ", doubtless, some at least of the imaginative impressions about\nto be presented may have been shared by most men, yet few perhaps were\nentirely conscious of them at the time, and therefore may not be able\nto recall them now.", "labels": {"50": 17, "100": 16, "250": 146, "500": 369, "1000": 366, "2000": 131}}, {"id": 2945, "position": 2945, "text": "and therefore may not be able\nto recall them now.\n\nWhy to the man of untutored ideality, who happens to be but loosely\nacquainted with the peculiar character of the day, does the bare\nmention of Whitsuntide marshal in", "labels": {"50": 44, "100": 52, "250": 200, "500": 218, "1000": 49, "2000": 1039}}, {"id": 2946, "position": 2946, "text": "the day, does the bare\nmention of Whitsuntide marshal in the fancy such long, dreary,\nspeechless processions of slow-pacing pilgrims, down-cast and hooded\nwith new-fallen snow? Or, to the unrea", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 185, "2000": 523}}, {"id": 2947, "position": 2947, "text": "cast and hooded\nwith new-fallen snow? Or, to the unread, unsophisticated Protestant of\nthe Middle American States, why does the passing mention of a White\nFriar or a White Nun, evoke such an eyeless statue", "labels": {"50": 48, "100": 27, "250": 223, "500": 339, "1000": 762, "2000": 180}}, {"id": 2948, "position": 2948, "text": "a White\nFriar or a White Nun, evoke such an eyeless statue in the soul?\n\nOr what is there apart from the traditions of dungeoned warriors and\nkings (which will not wholly account for it) that makes the White Tower\nof London tell", "labels": {"50": 31, "100": 16, "250": 13, "500": 414, "1000": 15, "2000": 1466}}, {"id": 2949, "position": 2949, "text": "will not wholly account for it) that makes the White Tower\nof London tell so much more strongly on the imagination of an\nuntravelled American, than those other storied structures, its\nneighbors—the Byward Tower, or even the Bloody", "labels": {"50": 48, "100": 27, "250": 90, "500": 224, "1000": 619, "2000": 532}}, {"id": 2950, "position": 2950, "text": "ed structures, its\nneighbors—the Byward Tower, or even the Bloody? And those sublimer\ntowers, the White Mountains of New Hampshire, whence, in peculiar\nmoods, comes that gigantic ghostliness over the soul at the bare\nmention of that", "labels": {"50": 48, "100": 20, "250": 192, "500": 126, "1000": 727, "2000": 1466}}, {"id": 2951, "position": 2951, "text": ", comes that gigantic ghostliness over the soul at the bare\nmention of that name, while the thought of Virginia’s Blue Ridge is\nfull of a soft, dewy, distant dreaminess? Or why, irrespective of all\nlatitudes", "labels": {"50": 31, "100": 20, "250": 132, "500": 126, "1000": 727, "2000": 1560}}, {"id": 2952, "position": 2952, "text": "distant dreaminess? Or why, irrespective of all\nlatitudes and longitudes, does the name of the White Sea exert such a\nspectralness over the fancy, while that of the Yellow Sea lulls us with\nmortal thoughts of long", "labels": {"50": 48, "100": 20, "250": 132, "500": 126, "1000": 747, "2000": 1466}}, {"id": 2953, "position": 2953, "text": ", while that of the Yellow Sea lulls us with\nmortal thoughts of long lacquered mild afternoons on the waves,\nfollowed by the gaudiest and yet sleepiest of sunsets? Or, to choose a\nwholly unsubstantial instance", "labels": {"50": 48, "100": 20, "250": 223, "500": 126, "1000": 747, "2000": 1560}}, {"id": 2954, "position": 2954, "text": "sunsets? Or, to choose a\nwholly unsubstantial instance, purely addressed to the fancy, why, in\nreading the old fairy tales of Central Europe, does “the tall pale man”\nof the Hartz forests, whose changeless", "labels": {"50": 17, "100": 16, "250": 146, "500": 483, "1000": 15, "2000": 521}}, {"id": 2955, "position": 2955, "text": "“the tall pale man”\nof the Hartz forests, whose changeless pallor unrustlingly glides\nthrough the green of the groves—why is this phantom more terrible than\nall the whooping imps of the Blocksburg?", "labels": {"50": 48, "100": 20, "250": 210, "500": 334, "1000": 747, "2000": 1560}}, {"id": 2956, "position": 2956, "text": "terrible than\nall the whooping imps of the Blocksburg?\n\nNor is it, altogether, the remembrance of her cathedral-toppling\nearthquakes; nor the stampedoes of her frantic seas; nor the\ntearlessness of arid skies that never rain; nor", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 887}}, {"id": 2957, "position": 2957, "text": "frantic seas; nor the\ntearlessness of arid skies that never rain; nor the sight of her wide\nfield of leaning spires, wrenched cope-stones, and crosses all adroop\n(like canted yards of anchored fleets); and her suburban", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 16}}, {"id": 2958, "position": 2958, "text": "roop\n(like canted yards of anchored fleets); and her suburban avenues of\nhouse-walls lying over upon each other, as a tossed pack of cards;—it\nis not these things alone which make tearless Lima, the strangest,", "labels": {"50": 16, "100": 73, "250": 193, "500": 19, "1000": 499, "2000": 16}}, {"id": 2959, "position": 2959, "text": "is not these things alone which make tearless Lima, the strangest,\nsaddest city thou can’st see. For Lima has taken the white veil; and\nthere is a higher horror in this whiteness of her woe", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 118, "2000": 1393}}, {"id": 2960, "position": 2960, "text": "is a higher horror in this whiteness of her woe. Old as Pizarro,\nthis whiteness keeps her ruins for ever new; admits not the cheerful\ngreenness of complete decay; spreads over her broken ramparts the rigid\npallor of", "labels": {"50": 16, "100": 20, "250": 49, "500": 334, "1000": 747, "2000": 1717}}, {"id": 2961, "position": 2961, "text": "of complete decay; spreads over her broken ramparts the rigid\npallor of an apoplexy that fixes its own distortions.\n\nI know that, to the common apprehension, this phenomenon of whiteness\nis not confessed to be the prime agent in", "labels": {"50": 20, "100": 79, "250": 155, "500": 80, "1000": 117, "2000": 809}}, {"id": 2962, "position": 2962, "text": ", this phenomenon of whiteness\nis not confessed to be the prime agent in exaggerating the terror of\nobjects otherwise terrible; nor to the unimaginative mind is there\naught of terror in those appearances whose awfulness to another mind\nalmost solely", "labels": {"50": 10, "100": 71, "250": 210, "500": 41, "1000": 57, "2000": 1588}}, {"id": 2963, "position": 2963, "text": "aught of terror in those appearances whose awfulness to another mind\nalmost solely consists in this one phenomenon, especially when\nexhibited under any form at all approaching to muteness or\nuniversality. What I mean by these two statements may perhaps be\nrespectively eluc", "labels": {"50": 31, "100": 71, "250": 210, "500": 41, "1000": 796, "2000": 1466}}, {"id": 2964, "position": 2964, "text": "ity. What I mean by these two statements may perhaps be\nrespectively elucidated by the following examples.\n\nFirst: The mariner, when drawing nigh the coasts of foreign lands, if\nby night he hear the roar of breakers, starts to", "labels": {"50": 10, "100": 75, "250": 87, "500": 64, "1000": 218, "2000": 515}}, {"id": 2965, "position": 2965, "text": "foreign lands, if\nby night he hear the roar of breakers, starts to vigilance, and feels\njust enough of trepidation to sharpen all his faculties; but under\nprecisely similar circumstances, let him be called from his hammock to", "labels": {"50": 45, "100": 64, "250": 82, "500": 73, "1000": 851, "2000": 967}}, {"id": 2966, "position": 2966, "text": "under\nprecisely similar circumstances, let him be called from his hammock to\nview his ship sailing through a midnight sea of milky whiteness—as if\nfrom encircling headlands shoals of combed white bears were swimming\nround him, then", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 2967, "position": 2967, "text": "headlands shoals of combed white bears were swimming\nround him, then he feels a silent, superstitious dread; the shrouded\nphantom of the whitened waters is horrible to him as a real ghost; in\nvain the lead assures", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 448, "2000": 958}}, {"id": 2968, "position": 2968, "text": "is horrible to him as a real ghost; in\nvain the lead assures him he is still off soundings; heart and helm\nthey both go down; he never rests till blue water is under him again", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 2969, "position": 2969, "text": "blue water is under him again.\nYet where is the mariner who will tell thee, “Sir, it was not so much\nthe fear of striking hidden rocks, as the fear of that hideous\nwhiteness that so stirred me?”", "labels": {"50": 31, "100": 64, "250": 138, "500": 72, "1000": 747, "2000": 1620}}, {"id": 2970, "position": 2970, "text": "fear of that hideous\nwhiteness that so stirred me?”\n\nSecond: To the native Indian of Peru, the continual sight of the\nsnow-howdahed Andes conveys naught of dread, except, perhaps, in the\nmere fancying of the", "labels": {"50": 12, "100": 42, "250": 78, "500": 379, "1000": 782, "2000": 1051}}, {"id": 2971, "position": 2971, "text": "ught of dread, except, perhaps, in the\nmere fancying of the eternal frosted desolateness reigning at such vast\naltitudes, and the natural conceit of what a fearfulness it would be to\nlose oneself in such inhuman solitudes", "labels": {"50": 23, "100": 5, "250": 101, "500": 202, "1000": 421, "2000": 1027}}, {"id": 2972, "position": 2972, "text": "a fearfulness it would be to\nlose oneself in such inhuman solitudes. Much the same is it with the\nbackwoodsman of the West, who with comparative indifference views an\nunbounded prairie sheeted with driven snow, no shadow of tree or", "labels": {"50": 12, "100": 93, "250": 192, "500": 344, "1000": 554, "2000": 1953}}, {"id": 2973, "position": 2973, "text": "unbounded prairie sheeted with driven snow, no shadow of tree or twig\nto break the fixed trance of whiteness. Not so the sailor, beholding\nthe scenery of the Antarctic seas; where at times, by some infernal\ntrick", "labels": {"50": 16, "100": 20, "250": 13, "500": 414, "1000": 747, "2000": 1560}}, {"id": 2974, "position": 2974, "text": "of the Antarctic seas; where at times, by some infernal\ntrick of legerdemain in the powers of frost and air, he, shivering and\nhalf shipwrecked, instead of rainbows speaking hope and solace to his\nmisery,", "labels": {"50": 17, "100": 16, "250": 30, "500": 4, "1000": 448, "2000": 958}}, {"id": 2975, "position": 2975, "text": "ed, instead of rainbows speaking hope and solace to his\nmisery, views what seems a boundless churchyard grinning upon him with\nits lean ice monuments and splintered crosses.\n\nBut thou sayest, methinks that white-lead chapter about white", "labels": {"50": 31, "100": 20, "250": 49, "500": 78, "1000": 165, "2000": 1394}}, {"id": 2976, "position": 2976, "text": "But thou sayest, methinks that white-lead chapter about whiteness is\nbut a white flag hung out from a craven soul; thou surrenderest to a\nhypo, Ishmael.", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 111}}, {"id": 2977, "position": 2977, "text": "o, Ishmael.\n\nTell me, why this strong young colt, foaled in some peaceful valley of\nVermont, far removed from all beasts of prey—why is it that upon the\nsunniest day, if you but shake a fresh buffalo", "labels": {"50": 31, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 2978, "position": 2978, "text": "it that upon the\nsunniest day, if you but shake a fresh buffalo robe behind him, so that\nhe cannot even see it, but only smells its wild animal muskiness—why\nwill he start, snort, and with bursting eyes paw the", "labels": {"50": 12, "100": 20, "250": 52, "500": 334, "1000": 275, "2000": 1710}}, {"id": 2979, "position": 2979, "text": "ess—why\nwill he start, snort, and with bursting eyes paw the ground in\nphrensies of affright? There is no remembrance in him of any gorings of\nwild creatures in his green northern home, so that the strange\nmu", "labels": {"50": 9, "100": 73, "250": 120, "500": 143, "1000": 637, "2000": 1886}}, {"id": 2980, "position": 2980, "text": "s of\nwild creatures in his green northern home, so that the strange\nmuskiness he smells cannot recall to him anything associated with the\nexperience of former perils; for what knows he, this New England colt,\nof the black bisons of distant", "labels": {"50": 48, "100": 20, "250": 13, "500": 126, "1000": 747, "2000": 1560}}, {"id": 2981, "position": 2981, "text": "knows he, this New England colt,\nof the black bisons of distant Oregon?\n\nNo: but here thou beholdest even in a dumb brute, the instinct of the\nknowledge of the demonism in the world", "labels": {"50": 9, "100": 24, "250": 52, "500": 307, "1000": 343, "2000": 1620}}, {"id": 2982, "position": 2982, "text": "of the demonism in the world. Though thousands of miles from\nOregon, still when he smells that savage musk, the rending, goring\nbison herds are as present as to the deserted wild foal of the\nprairies, which this", "labels": {"50": 10, "100": 71, "250": 13, "500": 414, "1000": 134, "2000": 336}}, {"id": 2983, "position": 2983, "text": "as to the deserted wild foal of the\nprairies, which this instant they may be trampling into dust.\n\nThus, then, the muffled rollings of a milky sea; the bleak rustlings of\nthe festooned frosts of mountains", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 779, "2000": 1203}}, {"id": 2984, "position": 2984, "text": "sea; the bleak rustlings of\nthe festooned frosts of mountains; the desolate shiftings of the\nwindrowed snows of prairies; all these, to Ishmael, are as the shaking\nof that buffalo robe to the", "labels": {"50": 12, "100": 55, "250": 65, "500": 171, "1000": 965, "2000": 624}}, {"id": 2985, "position": 2985, "text": "to Ishmael, are as the shaking\nof that buffalo robe to the frightened colt!\n\nThough neither knows where lie the nameless things of which the mystic\nsign gives forth such hints; yet with me, as with the colt, somewhere\nthose things must", "labels": {"50": 9, "100": 55, "250": 138, "500": 72, "1000": 965, "2000": 1620}}, {"id": 2986, "position": 2986, "text": "hints; yet with me, as with the colt, somewhere\nthose things must exist. Though in many of its aspects this visible\nworld seems formed in love, the invisible spheres were formed in\nfright.\n\nBut not yet have we solved the incantation of this", "labels": {"50": 9, "100": 73, "250": 44, "500": 19, "1000": 499, "2000": 629}}, {"id": 2987, "position": 2987, "text": "formed in\nfright.\n\nBut not yet have we solved the incantation of this whiteness, and\nlearned why it appeals with such power to the soul; and more strange\nand far more portentous—why, as we have seen, it is at", "labels": {"50": 10, "100": 71, "250": 13, "500": 236, "1000": 548, "2000": 1555}}, {"id": 2988, "position": 2988, "text": "more portentous—why, as we have seen, it is at once the most\nmeaning symbol of spiritual things, nay, the very veil of the\nChristian’s Deity; and yet should be as it is, the intensifying agent\nin", "labels": {"50": 10, "100": 94, "250": 12, "500": 236, "1000": 793, "2000": 1010}}, {"id": 2989, "position": 2989, "text": "; and yet should be as it is, the intensifying agent\nin things the most appalling to mankind.\n\nIs it that by its indefiniteness it shadows forth the heartless voids\nand immensities of the universe, and thus stab", "labels": {"50": 10, "100": 75, "250": 13, "500": 307, "1000": 343, "2000": 761}}, {"id": 2990, "position": 2990, "text": "heartless voids\nand immensities of the universe, and thus stabs us from behind with the\nthought of annihilation, when beholding the white depths of the milky\nway? Or is it, that as in essence whiteness is not", "labels": {"50": 16, "100": 20, "250": 13, "500": 414, "1000": 747, "2000": 1555}}, {"id": 2991, "position": 2991, "text": "milky\nway? Or is it, that as in essence whiteness is not so much a colour as\nthe visible absence of colour; and at the same time the concrete of all\ncolours; is it for these reasons that there is such a dumb blankness", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 18, "2000": 1274}}, {"id": 2992, "position": 2992, "text": "colours; is it for these reasons that there is such a dumb blankness,\nfull of meaning, in a wide landscape of snows—a colourless, all-colour\nof atheism from which we shrink? And when we consider that other", "labels": {"50": 10, "100": 71, "250": 13, "500": 453, "1000": 15, "2000": 1828}}, {"id": 2993, "position": 2993, "text": "of atheism from which we shrink? And when we consider that other theory\nof the natural philosophers, that all other earthly hues—every stately\nor lovely emblazoning—the sweet tinges of sunset skies and woods; yea", "labels": {"50": 10, "100": 71, "250": 129, "500": 307, "1000": 343, "2000": 761}}, {"id": 2994, "position": 2994, "text": "zoning—the sweet tinges of sunset skies and woods; yea,\nand the gilded velvets of butterflies, and the butterfly cheeks of\nyoung girls; all these are but subtile deceits, not actually inherent\nin substances, but only", "labels": {"50": 7, "100": 20, "250": 214, "500": 116, "1000": 452, "2000": 218}}, {"id": 2995, "position": 2995, "text": "but subtile deceits, not actually inherent\nin substances, but only laid on from without; so that all deified\nNature absolutely paints like the harlot, whose allurements cover\nnothing but the charnel-house within; and when", "labels": {"50": 31, "100": 75, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 2996, "position": 2996, "text": "allurements cover\nnothing but the charnel-house within; and when we proceed further, and\nconsider that the mystical cosmetic which produces every one of her\nhues, the great principle of light, for ever remains white or colorless\nin itself,", "labels": {"50": 10, "100": 66, "250": 129, "500": 473, "1000": 220, "2000": 1329}}, {"id": 2997, "position": 2997, "text": "great principle of light, for ever remains white or colorless\nin itself, and if operating without medium upon matter, would touch all\nobjects, even tulips and roses, with its own blank tinge—pondering all\nthis, the palsie", "labels": {"50": 10, "100": 71, "250": 13, "500": 289, "1000": 548, "2000": 1555}}, {"id": 2998, "position": 2998, "text": "with its own blank tinge—pondering all\nthis, the palsied universe lies before us a leper; and like wilful\ntravellers in Lapland, who refuse to wear coloured and colouring\nglasses upon their eyes, so the wretched", "labels": {"50": 31, "100": 16, "250": 146, "500": 453, "1000": 355, "2000": 1394}}, {"id": 2999, "position": 2999, "text": "to wear coloured and colouring\nglasses upon their eyes, so the wretched infidel gazes himself blind at\nthe monumental white shroud that wraps all the prospect around him. And\nof all these things the Albino whale was the symbol", "labels": {"50": 10, "100": 0, "250": 69, "500": 414, "1000": 560, "2000": 1620}}, {"id": 3000, "position": 3000, "text": "And\nof all these things the Albino whale was the symbol. Wonder ye then at\nthe fiery hunt?\n\n\nCHAPTER 43. Hark!\n\n“HIST! Did you hear that noise, Cabaco?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3001, "position": 3001, "text": "noise, Cabaco?”\n\nIt was the middle-watch: a fair moonlight; the seamen were standing in\na cordon, extending from one of the fresh-water butts in the waist, to\nthe scuttle-butt near the ta", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3002, "position": 3002, "text": "s in the waist, to\nthe scuttle-butt near the taffrail. In this manner, they passed the\nbuckets to fill the scuttle-butt. Standing, for the most part, on the\nhallowed precincts of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3003, "position": 3003, "text": ". Standing, for the most part, on the\nhallowed precincts of the quarter-deck, they were careful not to speak\nor rustle their feet. From hand to hand, the buckets went in the\ndeepest silence, only broken by the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 3004, "position": 3004, "text": "hand, the buckets went in the\ndeepest silence, only broken by the occasional flap of a sail, and the\nsteady hum of the unceasingly advancing keel.\n\nIt was in the midst of this repose, that Archy, one of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 3005, "position": 3005, "text": "was in the midst of this repose, that Archy, one of the cordon,\nwhose post was near the after-hatches, whispered to his neighbor, a\nCholo, the words above.", "labels": {"50": 1, "100": 15, "250": 22, "500": 263, "1000": 498, "2000": 1984}}, {"id": 3006, "position": 3006, "text": "Cholo, the words above.\n\n“Hist! did you hear that noise, Cabaco?”\n\n“Take the bucket, will ye, Archy? what noise d’ye mean?”\n\n“There it is again—under the hatches", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 3007, "position": 3007, "text": "’ye mean?”\n\n“There it is again—under the hatches—don’t you hear it—a cough—it\nsounded like a cough.”\n\n“Cough be damned! Pass along that return bucket.”", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3008, "position": 3008, "text": "be damned! Pass along that return bucket.”\n\n“There again—there it is!—it sounds like two or three sleepers turning\nover, now!”\n\n“Caramba! have done, shipmate, will ye? It’s the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3009, "position": 3009, "text": "mba! have done, shipmate, will ye? It’s the three soaked biscuits\nye eat for supper turning over inside of ye—nothing else. Look to the\nbucket!”\n\n“Say what ye will, shipmate; I’ve sharp", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3010, "position": 3010, "text": "!”\n\n“Say what ye will, shipmate; I’ve sharp ears.”\n\n“Aye, you are the chap, ain’t ye, that heard the hum of the old\nQuakeress’s knitting-needles fifty miles at sea", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3011, "position": 3011, "text": "hum of the old\nQuakeress’s knitting-needles fifty miles at sea from Nantucket; you’re\nthe chap.”\n\n“Grin away; we’ll see what turns up. Hark ye, Cabaco, there is somebody\ndown", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3012, "position": 3012, "text": "what turns up. Hark ye, Cabaco, there is somebody\ndown in the after-hold that has not yet been seen on deck; and I\nsuspect our old Mogul knows something of it too", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3013, "position": 3013, "text": "gul knows something of it too. I heard Stubb tell\nFlask, one morning watch, that there was something of that sort in the\nwind.”\n\n“Tish! the bucket!”\n\n\nCHAPTER 44. The Chart.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1668}}, {"id": 3014, "position": 3014, "text": "the bucket!”\n\n\nCHAPTER 44. The Chart.\n\nHad you followed Captain Ahab down into his cabin after the squall that\ntook place on the night succeeding that wild ratification of his\npurpose with his crew, you would have seen him go to a", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3015, "position": 3015, "text": "of his\npurpose with his crew, you would have seen him go to a locker in the\ntransom, and bringing out a large wrinkled roll of yellowish sea\ncharts, spread them before him on his screwed-down table", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 3016, "position": 3016, "text": "before him on his screwed-down table. Then seating\nhimself before it, you would have seen him intently study the various\nlines and shadings which there met his eye; and with slow but steady\npencil trace additional courses over spaces that before were blank", "labels": {"50": 39, "100": 51, "250": 196, "500": 138, "1000": 115, "2000": 1833}}, {"id": 3017, "position": 3017, "text": "and with slow but steady\npencil trace additional courses over spaces that before were blank. At\nintervals, he would refer to piles of old log-books beside him, wherein\nwere set down the seasons and places in which, on various former\nvoyages of various ships", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 1793}}, {"id": 3018, "position": 3018, "text": "down the seasons and places in which, on various former\nvoyages of various ships, sperm whales had been captured or seen.\n\nWhile thus employed, the heavy pewter lamp suspended in chains over his\nhead, continually rocked with the motion of the ship, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3019, "position": 3019, "text": "chains over his\nhead, continually rocked with the motion of the ship, and for ever\nthrew shifting gleams and shadows of lines upon his wrinkled brow, till\nit almost seemed that while he himself was marking out lines and\ncourses on the wrinkled charts, some", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3020, "position": 3020, "text": "while he himself was marking out lines and\ncourses on the wrinkled charts, some invisible pencil was also tracing\nlines and courses upon the deeply marked chart of his forehead.\n\nBut it was not this night in particular that, in the solitude of his\ncabin, Ah", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1904}}, {"id": 3021, "position": 3021, "text": "not this night in particular that, in the solitude of his\ncabin, Ahab thus pondered over his charts. Almost every night they were\nbrought out; almost every night some pencil marks were effaced, and\nothers were substituted", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3022, "position": 3022, "text": "marks were effaced, and\nothers were substituted. For with the charts of all four oceans before\nhim, Ahab was threading a maze of currents and eddies, with a view to\nthe more certain accomplishment of that monomaniac thought of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3023, "position": 3023, "text": "with a view to\nthe more certain accomplishment of that monomaniac thought of his soul.\n\nNow, to any one not fully acquainted with the ways of the leviathans,\nit might seem an absurdly hopeless task thus to seek out one solitary\ncreature", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 448, "2000": 1620}}, {"id": 3024, "position": 3024, "text": "it might seem an absurdly hopeless task thus to seek out one solitary\ncreature in the unhooped oceans of this planet. But not so did it seem\nto Ahab, who knew the sets of all tides and currents; and thereby\ncalculating the drifting", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3025, "position": 3025, "text": "who knew the sets of all tides and currents; and thereby\ncalculating the driftings of the sperm whale’s food; and, also, calling\nto mind the regular, ascertained seasons for hunting him in particular\nlatitudes; could arrive at reasonable", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3026, "position": 3026, "text": "certained seasons for hunting him in particular\nlatitudes; could arrive at reasonable surmises, almost approaching to\ncertainties, concerning the timeliest day to be upon this or that\nground in search of his prey.", "labels": {"50": 31, "100": 75, "250": 129, "500": 307, "1000": 256, "2000": 962}}, {"id": 3027, "position": 3027, "text": "that\nground in search of his prey.\n\nSo assured, indeed, is the fact concerning the periodicalness of the\nsperm whale’s resorting to given waters, that many hunters believe\nthat, could he be closely observed and studied throughout the world;\nwere", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3028, "position": 3028, "text": "believe\nthat, could he be closely observed and studied throughout the world;\nwere the logs for one voyage of the entire whale fleet carefully\ncollated, then the migrations of the sperm whale would be found to\ncorrespond in invariability to those of", "labels": {"50": 3, "100": 85, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3029, "position": 3029, "text": "sperm whale would be found to\ncorrespond in invariability to those of the herring-shoals or the\nflights of swallows. On this hint, attempts have been made to construct\nelaborate migratory charts of the sperm whale.*", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3030, "position": 3030, "text": "construct\nelaborate migratory charts of the sperm whale.*\n\n\n  *Since the above was written, the statement is happily borne out by\n  an official circular, issued by Lieutenant Maury, of the National\n  Observatory, Washington, April 16th, 1851", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3031, "position": 3031, "text": "the National\n  Observatory, Washington, April 16th, 1851. By that circular, it\n  appears that precisely such a chart is in course of completion; and\n  portions of it are presented in the circular. “This chart divides the\n  ocean into districts of five degrees of", "labels": {"50": 3, "100": 70, "250": 50, "500": 102, "1000": 875, "2000": 1727}}, {"id": 3032, "position": 3032, "text": "the circular. “This chart divides the\n  ocean into districts of five degrees of latitude by five degrees of\n  longitude; perpendicularly through each of which districts are twelve\n  columns for the twelve months; and horizontally through each of which\n  districts are three lines; one to", "labels": {"50": 45, "100": 70, "250": 138, "500": 72, "1000": 825, "2000": 631}}, {"id": 3033, "position": 3033, "text": "months; and horizontally through each of which\n  districts are three lines; one to show the number of days that have\n  been spent in each month in every district, and the two others to\n  show the number of days in which whales, sperm or right, have", "labels": {"50": 3, "100": 24, "250": 211, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3034, "position": 3034, "text": "to\n  show the number of days in which whales, sperm or right, have been\n  seen.”\n\n\n\n\nBesides, when making a passage from one feeding-ground to another, the\nsperm whales, guided by some infallible instinct—say, rather, secret", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3035, "position": 3035, "text": "whales, guided by some infallible instinct—say, rather, secret\nintelligence from the Deity—mostly swim in _veins_, as they are called;\ncontinuing their way along a given ocean-line with such undeviating\nexactitude, that", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3036, "position": 3036, "text": "along a given ocean-line with such undeviating\nexactitude, that no ship ever sailed her course, by any chart, with one\ntithe of such marvellous precision. Though, in these cases, the\ndirection taken by any one whale be", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3037, "position": 3037, "text": ". Though, in these cases, the\ndirection taken by any one whale be straight as a surveyor’s parallel,\nand though the line of advance be strictly confined to its own\nunavoidable, straight wake, yet the arbitrary _vein_ in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3038, "position": 3038, "text": "unavoidable, straight wake, yet the arbitrary _vein_ in which at these\ntimes he is said to swim, generally embraces some few miles in width\n(more or less, as the vein is presumed to expand or contract); but", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3039, "position": 3039, "text": "or less, as the vein is presumed to expand or contract); but\nnever exceeds the visual sweep from the whale-ship’s mast-heads, when\ncircumspectly gliding along this magic zone", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3040, "position": 3040, "text": "pectly gliding along this magic zone. The sum is, that at\nparticular seasons within that breadth and along that path, migrating\nwhales may with great confidence be looked for.\n\nAnd hence not only at substantiated times, upon well known separate", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3041, "position": 3041, "text": "And hence not only at substantiated times, upon well known separate\nfeeding-grounds, could Ahab hope to encounter his prey; but in crossing\nthe widest expanses of water between those grounds he could, by his\nart, so place", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3042, "position": 3042, "text": "s of water between those grounds he could, by his\nart, so place and time himself on his way, as even then not to be\nwholly without prospect of a meeting.\n\nThere was a circumstance which at first sight seemed to entangle his\ndeliri", "labels": {"50": 22, "100": 78, "250": 229, "500": 286, "1000": 62, "2000": 1699}}, {"id": 3043, "position": 3043, "text": "There was a circumstance which at first sight seemed to entangle his\ndelirious but still methodical scheme. But not so in the reality,\nperhaps. Though the gregarious sperm whales have their regular seasons\nfor particular grounds, yet in general you", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3044, "position": 3044, "text": "us sperm whales have their regular seasons\nfor particular grounds, yet in general you cannot conclude that the\nherds which haunted such and such a latitude or longitude this year,\nsay, will turn out to be identically the same with those that were\nfound there the", "labels": {"50": 3, "100": 24, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3045, "position": 3045, "text": "turn out to be identically the same with those that were\nfound there the preceding season; though there are peculiar and\nunquestionable instances where the contrary of this has proved true. In\ngeneral, the same remark, only within a less wide limit", "labels": {"50": 3, "100": 29, "250": 34, "500": 306, "1000": 126, "2000": 447}}, {"id": 3046, "position": 3046, "text": "true. In\ngeneral, the same remark, only within a less wide limit, applies to the\nsolitaries and hermits among the matured, aged sperm whales. So that\nthough Moby Dick had in a former year been seen, for example", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3047, "position": 3047, "text": "that\nthough Moby Dick had in a former year been seen, for example, on what\nis called the Seychelle ground in the Indian ocean, or Volcano Bay on\nthe Japanese Coast; yet it did not follow, that were the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3048, "position": 3048, "text": "Japanese Coast; yet it did not follow, that were the Pequod to\nvisit either of those spots at any subsequent corresponding season, she\nwould infallibly encounter him there. So, too, with some other feeding\ngrounds, where he had at", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3049, "position": 3049, "text": ". So, too, with some other feeding\ngrounds, where he had at times revealed himself. But all these seemed\nonly his casual stopping-places and ocean-inns, so to speak, not his\nplaces of prolonged abode", "labels": {"50": 44, "100": 37, "250": 143, "500": 481, "1000": 984, "2000": 1966}}, {"id": 3050, "position": 3050, "text": "so to speak, not his\nplaces of prolonged abode. And where Ahab’s chances of accomplishing\nhis object have hitherto been spoken of, allusion has only been made to\nwhatever way-side, antecedent, extra prospects", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3051, "position": 3051, "text": "only been made to\nwhatever way-side, antecedent, extra prospects were his, ere a\nparticular set time or place were attained, when all possibilities\nwould become probabilities, and, as Ahab fondly thought, every\npossibility the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3052, "position": 3052, "text": "babilities, and, as Ahab fondly thought, every\npossibility the next thing to a certainty. That particular set time and\nplace were conjoined in the one technical phrase—the\nSeason-on-the-Line", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3053, "position": 3053, "text": "phrase—the\nSeason-on-the-Line. For there and then, for several consecutive years,\nMoby Dick had been periodically descried, lingering in those waters for\nawhile, as the sun, in its annual round, loiters", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3054, "position": 3054, "text": "for\nawhile, as the sun, in its annual round, loiters for a predicted\ninterval in any one sign of the Zodiac. There it was, too, that most of\nthe deadly encounters with the white whale had taken place; there the\nwaves", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3055, "position": 3055, "text": "of\nthe deadly encounters with the white whale had taken place; there the\nwaves were storied with his deeds; there also was that tragic spot\nwhere the monomaniac old man had found the awful motive to his\nvengeance", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3056, "position": 3056, "text": "man had found the awful motive to his\nvengeance. But in the cautious comprehensiveness and unloitering\nvigilance with which Ahab threw his brooding soul into this unfaltering\nhunt, he would not permit himself to rest all his hopes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3057, "position": 3057, "text": "faltering\nhunt, he would not permit himself to rest all his hopes upon the one\ncrowning fact above mentioned, however flattering it might be to those\nhopes; nor in the sleeplessness of his vow could he so tranquillize his", "labels": {"50": 19, "100": 10, "250": 226, "500": 56, "1000": 123, "2000": 804}}, {"id": 3058, "position": 3058, "text": "in the sleeplessness of his vow could he so tranquillize his\nunquiet heart as to postpone all intervening quest.\n\nNow, the Pequod had sailed from Nantucket at the very beginning of the\nSeason-on-the-", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3059, "position": 3059, "text": "from Nantucket at the very beginning of the\nSeason-on-the-Line. No possible endeavor then could enable her\ncommander to make the great passage southwards, double Cape Horn, and\nthen running down sixty degrees of latitude arrive in the equatorial\nPacific", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 3060, "position": 3060, "text": "Horn, and\nthen running down sixty degrees of latitude arrive in the equatorial\nPacific in time to cruise there. Therefore, he must wait for the next\nensuing season. Yet the premature hour of the Pequod’s sailing had,\nperhaps, been correctly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3061, "position": 3061, "text": "hour of the Pequod’s sailing had,\nperhaps, been correctly selected by Ahab, with a view to this very\ncomplexion of things. Because, an interval of three hundred and\nsixty-five days and nights was before him; an interval", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3062, "position": 3062, "text": "three hundred and\nsixty-five days and nights was before him; an interval which, instead\nof impatiently enduring ashore, he would spend in a miscellaneous hunt;\nif by chance the White Whale, spending his vacation in seas far remote\nfrom his periodical feeding-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 3063, "position": 3063, "text": "White Whale, spending his vacation in seas far remote\nfrom his periodical feeding-grounds, should turn up his wrinkled brow\noff the Persian Gulf, or in the Bengal Bay, or China Seas, or in any\nother waters haunted by his race", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3064, "position": 3064, "text": "China Seas, or in any\nother waters haunted by his race. So that Monsoons, Pampas,\nNor’-Westers, Harmattans, Trades; any wind but the Levanter and Simoon,\nmight blow Moby Dick into the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3065, "position": 3065, "text": "but the Levanter and Simoon,\nmight blow Moby Dick into the devious zig-zag world-circle of the\nPequod’s circumnavigating wake.\n\nBut granting all this; yet, regarded discreetly", "labels": {"50": 31, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3066, "position": 3066, "text": "navigating wake.\n\nBut granting all this; yet, regarded discreetly and coolly, seems it\nnot but a mad idea, this; that in the broad boundless ocean, one\nsolitary whale, even if encountered, should be thought capable of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3067, "position": 3067, "text": "ocean, one\nsolitary whale, even if encountered, should be thought capable of\nindividual recognition from his hunter, even as a white-bearded Mufti\nin the thronged thoroughfares of Constantinople? Yes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3068, "position": 3068, "text": "thoroughfares of Constantinople? Yes. For the peculiar\nsnow-white brow of Moby Dick, and his snow-white hump, could not but be\nunmistakable. And have I not tallied the whale, Ahab would mutter to\nhimself,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3069, "position": 3069, "text": "have I not tallied the whale, Ahab would mutter to\nhimself, as after poring over his charts till long after midnight he\nwould throw himself back in reveries—tallied him, and shall he escape?\nHis broad fins are bored,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3070, "position": 3070, "text": "tallied him, and shall he escape?\nHis broad fins are bored, and scalloped out like a lost sheep’s ear!\nAnd here, his mad mind would run on in a breathless race; till a\nweariness and faintness of", "labels": {"50": 22, "100": 64, "250": 28, "500": 72, "1000": 692, "2000": 1620}}, {"id": 3071, "position": 3071, "text": "run on in a breathless race; till a\nweariness and faintness of pondering came over him; and in the open air\nof the deck he would seek to recover his strength. Ah, God! what\ntrances of torments does that man", "labels": {"50": 22, "100": 78, "250": 229, "500": 469, "1000": 631, "2000": 250}}, {"id": 3072, "position": 3072, "text": "strength. Ah, God! what\ntrances of torments does that man endure who is consumed with one\nunachieved revengeful desire. He sleeps with clenched hands; and wakes\nwith his own bloody nails in his palms.", "labels": {"50": 36, "100": 35, "250": 242, "500": 254, "1000": 850, "2000": 689}}, {"id": 3073, "position": 3073, "text": "and wakes\nwith his own bloody nails in his palms.\n\nOften, when forced from his hammock by exhausting and intolerably vivid\ndreams of the night, which, resuming his own intense thoughts through\nthe day, carried them on amid a", "labels": {"50": 22, "100": 78, "250": 39, "500": 481, "1000": 631, "2000": 321}}, {"id": 3074, "position": 3074, "text": "resuming his own intense thoughts through\nthe day, carried them on amid a clashing of phrensies, and whirled them\nround and round and round in his blazing brain, till the very throbbing\nof his life-spot became insufferable anguish", "labels": {"50": 22, "100": 78, "250": 229, "500": 469, "1000": 631, "2000": 1976}}, {"id": 3075, "position": 3075, "text": "till the very throbbing\nof his life-spot became insufferable anguish; and when, as was\nsometimes the case, these spiritual throes in him heaved his being up\nfrom its base, and a chasm seemed opening in him, from", "labels": {"50": 35, "100": 78, "250": 229, "500": 289, "1000": 584, "2000": 586}}, {"id": 3076, "position": 3076, "text": "up\nfrom its base, and a chasm seemed opening in him, from which forked\nflames and lightnings shot up, and accursed fiends beckoned him to leap\ndown among them; when this hell in himself yawned beneath him,", "labels": {"50": 22, "100": 78, "250": 205, "500": 198, "1000": 167, "2000": 1893}}, {"id": 3077, "position": 3077, "text": "to leap\ndown among them; when this hell in himself yawned beneath him, a wild\ncry would be heard through the ship; and with glaring eyes Ahab would\nburst from his state room, as though escaping from a bed that was on\nfire", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3078, "position": 3078, "text": "state room, as though escaping from a bed that was on\nfire. Yet these, perhaps, instead of being the unsuppressable symptoms\nof some latent weakness, or fright at his own resolve, were but the\nplainest tokens of", "labels": {"50": 22, "100": 78, "250": 229, "500": 163, "1000": 141, "2000": 119}}, {"id": 3079, "position": 3079, "text": "or fright at his own resolve, were but the\nplainest tokens of its intensity. For, at such times, crazy Ahab, the\nscheming, unappeasedly steadfast hunter of the white whale; this Ahab\nthat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3080, "position": 3080, "text": "asedly steadfast hunter of the white whale; this Ahab\nthat had gone to his hammock, was not the agent that so caused him to\nburst from it in horror again. The latter was the eternal, living\nprinciple or soul in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3081, "position": 3081, "text": "in horror again. The latter was the eternal, living\nprinciple or soul in him; and in sleep, being for the time dissociated\nfrom the characterizing mind, which at other times employed it for its\nouter vehicle or agent, it spontaneously", "labels": {"50": 20, "100": 5, "250": 210, "500": 41, "1000": 818, "2000": 729}}, {"id": 3082, "position": 3082, "text": "which at other times employed it for its\nouter vehicle or agent, it spontaneously sought escape from the\nscorching contiguity of the frantic thing, of which, for the time, it\nwas no longer an integral", "labels": {"50": 5, "100": 66, "250": 229, "500": 144, "1000": 448, "2000": 1605}}, {"id": 3083, "position": 3083, "text": "the time, it\nwas no longer an integral. But as the mind does not exist unless\nleagued with the soul, therefore it must have been that, in Ahab’s\ncase, yielding up all his thoughts and fancies to his one supreme", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3084, "position": 3084, "text": "s\ncase, yielding up all his thoughts and fancies to his one supreme\npurpose; that purpose, by its own sheer inveteracy of will, forced\nitself against gods and devils into a kind of self-assumed, independent\nbeing of its own", "labels": {"50": 10, "100": 71, "250": 129, "500": 236, "1000": 368, "2000": 1858}}, {"id": 3085, "position": 3085, "text": "and devils into a kind of self-assumed, independent\nbeing of its own. Nay, could grimly live and burn, while the common\nvitality to which it was conjoined, fled horror-stricken from the\nunbidden and unfathered", "labels": {"50": 10, "100": 71, "250": 33, "500": 236, "1000": 211, "2000": 1201}}, {"id": 3086, "position": 3086, "text": "ined, fled horror-stricken from the\nunbidden and unfathered birth. Therefore, the tormented spirit that\nglared out of bodily eyes, when what seemed Ahab rushed from his room,\nwas for the time but a vacated thing, a form", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3087, "position": 3087, "text": "from his room,\nwas for the time but a vacated thing, a formless somnambulistic being,\na ray of living light, to be sure, but without an object to colour, and\ntherefore a blankness in itself", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 631, "2000": 825}}, {"id": 3088, "position": 3088, "text": "an object to colour, and\ntherefore a blankness in itself. God help thee, old man, thy thoughts\nhave created a creature in thee; and he whose intense thinking thus\nmakes him a Prometheus; a vulture feeds upon that heart for ever", "labels": {"50": 31, "100": 75, "250": 13, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3089, "position": 3089, "text": "makes him a Prometheus; a vulture feeds upon that heart for ever; that\nvulture the very creature he creates.\n\n\nCHAPTER 45. The Affidavit.\n\nSo far as what there may be of a narrative in this book; and, indeed", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3090, "position": 3090, "text": "as what there may be of a narrative in this book; and, indeed,\nas indirectly touching one or two very interesting and curious\nparticulars in the habits of sperm whales, the foregoing chapter, in\nits earlier part, is as important a one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3091, "position": 3091, "text": "the foregoing chapter, in\nits earlier part, is as important a one as will be found in this\nvolume; but the leading matter of it requires to be still further and\nmore familiarly enlarged upon, in order to be adequately understood,\nand moreover", "labels": {"50": 17, "100": 40, "250": 146, "500": 369, "1000": 667, "2000": 1520}}, {"id": 3092, "position": 3092, "text": "more familiarly enlarged upon, in order to be adequately understood,\nand moreover to take away any incredulity which a profound ignorance of\nthe entire subject may induce in some minds, as to the natural verity\nof the main points of this affair.", "labels": {"50": 32, "100": 0, "250": 233, "500": 55, "1000": 321, "2000": 1536}}, {"id": 3093, "position": 3093, "text": "minds, as to the natural verity\nof the main points of this affair.\n\nI care not to perform this part of my task methodically; but shall be\ncontent to produce the desired impression by separate citations of\nitems, practically or reliably known to", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 811, "2000": 412}}, {"id": 3094, "position": 3094, "text": "desired impression by separate citations of\nitems, practically or reliably known to me as a whaleman; and from\nthese citations, I take it—the conclusion aimed at will naturally\nfollow of itself.\n\nFirst: I have personally known three instances where a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3095, "position": 3095, "text": "naturally\nfollow of itself.\n\nFirst: I have personally known three instances where a whale, after\nreceiving a harpoon, has effected a complete escape; and, after an\ninterval (in one instance of three years), has been again struck by the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3096, "position": 3096, "text": "(in one instance of three years), has been again struck by the\nsame hand, and slain; when the two irons, both marked by the same\nprivate cypher, have been taken from the body", "labels": {"50": 39, "100": 39, "250": 79, "500": 118, "1000": 590, "2000": 415}}, {"id": 3097, "position": 3097, "text": ", have been taken from the body. In the instance where\nthree years intervened between the flinging of the two harpoons; and I\nthink it may have been something more than that; the man who darted\nthem happening, in the interval, to go", "labels": {"50": 3, "100": 70, "250": 234, "500": 77, "1000": 478, "2000": 1620}}, {"id": 3098, "position": 3098, "text": "that; the man who darted\nthem happening, in the interval, to go in a trading ship on a voyage to\nAfrica, went ashore there, joined a discovery party, and penetrated far\ninto the interior, where he travelled for a period of nearly two", "labels": {"50": 45, "100": 29, "250": 158, "500": 239, "1000": 321, "2000": 760}}, {"id": 3099, "position": 3099, "text": "penetrated far\ninto the interior, where he travelled for a period of nearly two years,\noften endangered by serpents, savages, tigers, poisonous miasmas, with\nall the other common perils incident to wandering in the heart of\nunknown regions", "labels": {"50": 12, "100": 13, "250": 158, "500": 167, "1000": 321, "2000": 760}}, {"id": 3100, "position": 3100, "text": "the other common perils incident to wandering in the heart of\nunknown regions. Meanwhile, the whale he had struck must also have been\non its travels; no doubt it had thrice circumnavigated the globe,\nbrushing with its flanks all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3101, "position": 3101, "text": "rice circumnavigated the globe,\nbrushing with its flanks all the coasts of Africa; but to no purpose.\nThis man and this whale again came together, and the one vanquished the\nother", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3102, "position": 3102, "text": "the one vanquished the\nother. I say I, myself, have known three instances similar to this;\nthat is in two of them I saw the whales struck; and, upon the second\nattack, saw the two irons with the respective marks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3103, "position": 3103, "text": ", upon the second\nattack, saw the two irons with the respective marks cut in them,\nafterwards taken from the dead fish. In the three-year instance, it so\nfell out that I was in the boat both times, first and last,", "labels": {"50": 45, "100": 29, "250": 34, "500": 306, "1000": 126, "2000": 1817}}, {"id": 3104, "position": 3104, "text": "fell out that I was in the boat both times, first and last, and the\nlast time distinctly recognised a peculiar sort of huge mole under the\nwhale’s eye, which I had observed there three years previous", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1620}}, {"id": 3105, "position": 3105, "text": "I had observed there three years previous. I say\nthree years, but I am pretty sure it was more than that. Here are three\ninstances, then, which I personally know the truth of; but I have heard\nof many other instances from persons whose", "labels": {"50": 12, "100": 24, "250": 24, "500": 287, "1000": 975, "2000": 447}}, {"id": 3106, "position": 3106, "text": "the truth of; but I have heard\nof many other instances from persons whose veracity in the matter there\nis no good ground to impeach.\n\nSecondly: It is well known in the Sperm Whale Fishery, however ignorant\nthe world ashore may be of", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3107, "position": 3107, "text": "known in the Sperm Whale Fishery, however ignorant\nthe world ashore may be of it, that there have been several memorable\nhistorical instances where a particular whale in the ocean has been at\ndistant times and places popularly cognisable", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3108, "position": 3108, "text": "distant times and places popularly cognisable. Why such a whale became\nthus marked was not altogether and originally owing to his bodily\npeculiarities as distinguished from other whales; for however peculiar\nin that respect any chance whale may be, they soon put an end", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3109, "position": 3109, "text": "peculiar\nin that respect any chance whale may be, they soon put an end to his\npeculiarities by killing him, and boiling him down into a peculiarly\nvaluable oil. No: the reason was this: that from the fatal experiences\nof the fishery there", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3110, "position": 3110, "text": ": the reason was this: that from the fatal experiences\nof the fishery there hung a terrible prestige of perilousness about\nsuch a whale as there did about Rinaldo Rinaldini, insomuch that most\nfishermen were content to recognise him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3111, "position": 3111, "text": "Rinaldini, insomuch that most\nfishermen were content to recognise him by merely touching their\ntarpaulins when he would be discovered lounging by them on the sea,\nwithout seeking to cultivate a more intimate acquaintance", "labels": {"50": 49, "100": 74, "250": 126, "500": 195, "1000": 330, "2000": 1512}}, {"id": 3112, "position": 3112, "text": ",\nwithout seeking to cultivate a more intimate acquaintance. Like some\npoor devils ashore that happen to know an irascible great man, they\nmake distant unobtrusive salutations to him in the street, lest if they\npursued the acquaintance further", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 15, "2000": 1027}}, {"id": 3113, "position": 3113, "text": "utations to him in the street, lest if they\npursued the acquaintance further, they might receive a summary thump\nfor their presumption.\n\nBut not only did each of these famous whales enjoy great individual\ncelebrity—Nay, you may call it an ocean", "labels": {"50": 31, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3114, "position": 3114, "text": "famous whales enjoy great individual\ncelebrity—Nay, you may call it an ocean-wide renown; not only was he\nfamous in life and now is immortal in forecastle stories after death,\nbut he was admitted into all the rights, privileges, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3115, "position": 3115, "text": "after death,\nbut he was admitted into all the rights, privileges, and distinctions\nof a name; had as much a name indeed as Cambyses or Cæsar. Was it not\nso, O Timor Tom! thou famed leviathan, scarred", "labels": {"50": 9, "100": 26, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 3116, "position": 3116, "text": "Was it not\nso, O Timor Tom! thou famed leviathan, scarred like an iceberg, who so\nlong did’st lurk in the Oriental straits of that name, whose spout was\noft seen from the palmy beach of Om", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3117, "position": 3117, "text": ", whose spout was\noft seen from the palmy beach of Ombay? Was it not so, O New Zealand\nJack! thou terror of all cruisers that crossed their wakes in the\nvicinity of the Tattoo Land? Was it not so, O", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 3118, "position": 3118, "text": "wakes in the\nvicinity of the Tattoo Land? Was it not so, O Morquan! King of Japan,\nwhose lofty jet they say at times assumed the semblance of a snow-white\ncross against the sky? Was it not so", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3119, "position": 3119, "text": "lance of a snow-white\ncross against the sky? Was it not so, O Don Miguel! thou Chilian whale,\nmarked like an old tortoise with mystic hieroglyphics upon the back! In\nplain prose, here are four", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3120, "position": 3120, "text": "eroglyphics upon the back! In\nplain prose, here are four whales as well known to the students of\nCetacean History as Marius or Sylla to the classic scholar.\n\nBut this is not all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3121, "position": 3121, "text": "classic scholar.\n\nBut this is not all. New Zealand Tom and Don Miguel, after at various\ntimes creating great havoc among the boats of different vessels, were\nfinally gone in quest of, systematically hunted out, chased and killed\nby valiant whaling captains, who", "labels": {"50": 12, "100": 29, "250": 34, "500": 72, "1000": 556, "2000": 624}}, {"id": 3122, "position": 3122, "text": "of, systematically hunted out, chased and killed\nby valiant whaling captains, who heaved up their anchors with that\nexpress object as much in view, as in setting out through the\nNarragansett Woods, Captain Butler of old had it in his mind to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3123, "position": 3123, "text": "rragansett Woods, Captain Butler of old had it in his mind to capture\nthat notorious murderous savage Annawon, the headmost warrior of the\nIndian King Philip.\n\nI do not know where I can find a better place than just here, to make", "labels": {"50": 25, "100": 93, "250": 37, "500": 227, "1000": 103, "2000": 1032}}, {"id": 3124, "position": 3124, "text": "not know where I can find a better place than just here, to make\nmention of one or two other things, which to me seem important, as in\nprinted form establishing in all respects the reasonableness of the\nwhole story of the White Whale, more", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3125, "position": 3125, "text": "all respects the reasonableness of the\nwhole story of the White Whale, more especially the catastrophe. For\nthis is one of those disheartening instances where truth requires full\nas much bolstering as error", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3126, "position": 3126, "text": "much bolstering as error. So ignorant are most landsmen of some of\nthe plainest and most palpable wonders of the world, that without some\nhints touching the plain facts, historical and otherwise, of the\nfishery, they might scout at", "labels": {"50": 31, "100": 75, "250": 106, "500": 307, "1000": 256, "2000": 1986}}, {"id": 3127, "position": 3127, "text": "plain facts, historical and otherwise, of the\nfishery, they might scout at Moby Dick as a monstrous fable, or still\nworse and more detestable, a hideous and intolerable allegory.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3128, "position": 3128, "text": "intolerable allegory.\n\nFirst: Though most men have some vague flitting ideas of the general\nperils of the grand fishery, yet they have nothing like a fixed, vivid\nconception of those perils, and the frequency with which they", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3129, "position": 3129, "text": "fixed, vivid\nconception of those perils, and the frequency with which they recur.\nOne reason perhaps is, that not one in fifty of the actual disasters\nand deaths by casualties in the fishery, ever finds a public record at\nhome, however transient", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 3130, "position": 3130, "text": "casualties in the fishery, ever finds a public record at\nhome, however transient and immediately forgotten that record. Do you\nsuppose that that poor fellow there, who this moment perhaps caught by\nthe whale-line off the coast of New Guinea, is being carried", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3131, "position": 3131, "text": "by\nthe whale-line off the coast of New Guinea, is being carried down to\nthe bottom of the sea by the sounding leviathan—do you suppose that\nthat poor fellow’s name will appear in the newspaper obituary you will\nread to-morrow", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3132, "position": 3132, "text": "’s name will appear in the newspaper obituary you will\nread to-morrow at your breakfast? No: because the mails are very\nirregular between here and New Guinea. In fact, did you ever hear what\nmight be called regular news direct or indirect", "labels": {"50": 31, "100": 7, "250": 58, "500": 494, "1000": 480, "2000": 187}}, {"id": 3133, "position": 3133, "text": "fact, did you ever hear what\nmight be called regular news direct or indirect from New Guinea? Yet I\ntell you that upon one particular voyage which I made to the Pacific,\namong many others we spoke thirty different ships, every one of which\nhad had", "labels": {"50": 45, "100": 13, "250": 130, "500": 494, "1000": 480, "2000": 187}}, {"id": 3134, "position": 3134, "text": "among many others we spoke thirty different ships, every one of which\nhad had a death by a whale, some of them more than one, and three that\nhad each lost a boat’s crew. For God’s sake, be economical with your", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3135, "position": 3135, "text": "boat’s crew. For God’s sake, be economical with your\nlamps and candles! not a gallon you burn, but at least one drop of\nman’s blood was spilled for it.\n\nSecondly: People ashore have indeed some indefinite idea that", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 3136, "position": 3136, "text": "was spilled for it.\n\nSecondly: People ashore have indeed some indefinite idea that a whale\nis an enormous creature of enormous power; but I have ever found that\nwhen narrating to them some specific example of this two-fold\nenormousness, they have", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3137, "position": 3137, "text": "to them some specific example of this two-fold\nenormousness, they have significantly complimented me upon my\nfacetiousness; when, I declare upon my soul, I had no more idea of\nbeing facetious than Moses, when he wrote the history of", "labels": {"50": 20, "100": 28, "250": 101, "500": 349, "1000": 773, "2000": 1278}}, {"id": 3138, "position": 3138, "text": "more idea of\nbeing facetious than Moses, when he wrote the history of the plagues of\nEgypt.\n\nBut fortunately the special point I here seek can be established upon\ntestimony entirely independent of my own. That point is this: The Sperm\nWhale is in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3139, "position": 3139, "text": "independent of my own. That point is this: The Sperm\nWhale is in some cases sufficiently powerful, knowing, and judiciously\nmalicious, as with direct aforethought to stave in, utterly destroy,\nand sink a large ship;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3140, "position": 3140, "text": "t to stave in, utterly destroy,\nand sink a large ship; and what is more, the Sperm Whale _has_ done it.\n\nFirst: In the year 1820 the ship Essex, Captain Pollard, of Nantucket,\nwas cruising in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3141, "position": 3141, "text": "the ship Essex, Captain Pollard, of Nantucket,\nwas cruising in the Pacific Ocean. One day she saw spouts, lowered her\nboats, and gave chase to a shoal of sperm whales. Ere long, several of\nthe whales were wounded", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 327, "2000": 1584}}, {"id": 3142, "position": 3142, "text": "al of sperm whales. Ere long, several of\nthe whales were wounded; when, suddenly, a very large whale escaping\nfrom the boats, issued from the shoal, and bore directly down upon the\nship", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1243}}, {"id": 3143, "position": 3143, "text": "and bore directly down upon the\nship. Dashing his forehead against her hull, he so stove her in, that\nin less than “ten minutes” she settled down and fell over. Not a\nsurviving plank of her has been seen since", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 3144, "position": 3144, "text": "over. Not a\nsurviving plank of her has been seen since. After the severest\nexposure, part of the crew reached the land in their boats. Being\nreturned home at last, Captain Pollard once more sailed for the Pacific\nin command of another ship,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 3145, "position": 3145, "text": ", Captain Pollard once more sailed for the Pacific\nin command of another ship, but the gods shipwrecked him again upon\nunknown rocks and breakers; for the second time his ship was utterly\nlost, and forthwith forswearing the sea, he", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 300, "2000": 1584}}, {"id": 3146, "position": 3146, "text": "ship was utterly\nlost, and forthwith forswearing the sea, he has never tempted it since.\nAt this day Captain Pollard is a resident of Nantucket. I have seen\nOwen Chace, who was chief mate of the Essex at the time", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1495}}, {"id": 3147, "position": 3147, "text": "seen\nOwen Chace, who was chief mate of the Essex at the time of the tragedy;\nI have read his plain and faithful narrative; I have conversed with his\nson; and all this within a few miles of the scene of the catastrophe.", "labels": {"50": 45, "100": 64, "250": 138, "500": 327, "1000": 327, "2000": 282}}, {"id": 3148, "position": 3148, "text": "; and all this within a few miles of the scene of the catastrophe.*\n\n*The following are extracts from Chace’s narrative: “Every fact seemed\nto warrant me in concluding that it was anything but chance which\ndirected his operations; he made", "labels": {"50": 17, "100": 48, "250": 210, "500": 41, "1000": 667, "2000": 1520}}, {"id": 3149, "position": 3149, "text": "in concluding that it was anything but chance which\ndirected his operations; he made two several attacks upon the ship, at\na short interval between them, both of which, according to their\ndirection, were calculated to do us the most injury, by being made", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 354, "2000": 1518}}, {"id": 3150, "position": 3150, "text": "their\ndirection, were calculated to do us the most injury, by being made\nahead, and thereby combining the speed of the two objects for the\nshock; to effect which, the exact manœuvres which he made were\nnecessary", "labels": {"50": 45, "100": 64, "250": 138, "500": 48, "1000": 723, "2000": 576}}, {"id": 3151, "position": 3151, "text": "exact manœuvres which he made were\nnecessary. His aspect was most horrible, and such as indicated\nresentment and fury. He came directly from the shoal which we had just\nbefore entered, and in which we had struck three of his companions,", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1243}}, {"id": 3152, "position": 3152, "text": "just\nbefore entered, and in which we had struck three of his companions, as\nif fired with revenge for their sufferings.” Again: “At all events, the\nwhole circumstances taken together, all happening before my own eyes,\nand producing, at", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 3153, "position": 3153, "text": "circumstances taken together, all happening before my own eyes,\nand producing, at the time, impressions in my mind of decided,\ncalculating mischief, on the part of the whale (many of which\nimpressions I cannot now recall), induce me to be satisfied", "labels": {"50": 45, "100": 64, "250": 125, "500": 72, "1000": 313, "2000": 1620}}, {"id": 3154, "position": 3154, "text": "many of which\nimpressions I cannot now recall), induce me to be satisfied that I am\ncorrect in my opinion.”\n\nHere are his reflections some time after quitting the ship, during a\nblack night in an open boat, when almost despairing of", "labels": {"50": 45, "100": 64, "250": 191, "500": 151, "1000": 907, "2000": 845}}, {"id": 3155, "position": 3155, "text": ", during a\nblack night in an open boat, when almost despairing of reaching any\nhospitable shore. “The dark ocean and swelling waters were nothing; the\nfears of being swallowed up by some dreadful tempest, or dashed upon\nhidden rocks,", "labels": {"50": 45, "100": 29, "250": 138, "500": 28, "1000": 300, "2000": 282}}, {"id": 3156, "position": 3156, "text": "of being swallowed up by some dreadful tempest, or dashed upon\nhidden rocks, with all the other ordinary subjects of fearful\ncontemplation, seemed scarcely entitled to a moment’s thought; the\ndismal looking wreck, and _the horri", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 723, "2000": 1584}}, {"id": 3157, "position": 3157, "text": "s thought; the\ndismal looking wreck, and _the horrid aspect and revenge of the whale_,\nwholly engrossed my reflections, until day again made its appearance.”\n\nIn another place—p", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 3158, "position": 3158, "text": "its appearance.”\n\nIn another place—p. 45,—he speaks of “_the mysterious and mortal attack\nof the animal_.”\n\nSecondly: The ship Union, also of Nantucket, was in the year 1807\ntotally lost off the Azores", "labels": {"50": 3, "100": 85, "250": 14, "500": 288, "1000": 622, "2000": 1616}}, {"id": 3159, "position": 3159, "text": "also of Nantucket, was in the year 1807\ntotally lost off the Azores by a similar onset, but the authentic\nparticulars of this catastrophe I have never chanced to encounter,\nthough from the whale hunters I have now and then heard casual\nallusions", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3160, "position": 3160, "text": ",\nthough from the whale hunters I have now and then heard casual\nallusions to it.\n\nThirdly: Some eighteen or twenty years ago Commodore J——, then\ncommanding an American sloop-of-war of the first class, happened to be\ndining", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3161, "position": 3161, "text": "American sloop-of-war of the first class, happened to be\ndining with a party of whaling captains, on board a Nantucket ship in\nthe harbor of Oahu, Sandwich Islands. Conversation turning upon whales,\nthe Commodore was pleased to be sc", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3162, "position": 3162, "text": "Sandwich Islands. Conversation turning upon whales,\nthe Commodore was pleased to be sceptical touching the amazing strength\nascribed to them by the professional gentlemen present. He peremptorily\ndenied for example, that any whale could so smite his stout\nsloop-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3163, "position": 3163, "text": "denied for example, that any whale could so smite his stout\nsloop-of-war as to cause her to leak so much as a thimbleful. Very\ngood; but there is more coming", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3164, "position": 3164, "text": "; but there is more coming. Some weeks after, the Commodore set\nsail in this impregnable craft for Valparaiso. But he was stopped on\nthe way by a portly sperm whale, that begged a few moments’\nconfidential business with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3165, "position": 3165, "text": "a portly sperm whale, that begged a few moments’\nconfidential business with him. That business consisted in fetching the\nCommodore’s craft such a thwack, that with all his pumps going he made\nstraight for the nearest port to heave", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3166, "position": 3166, "text": "with all his pumps going he made\nstraight for the nearest port to heave down and repair. I am not\nsuperstitious, but I consider the Commodore’s interview with that whale\nas providential. Was not Saul of Tarsus converted from un", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3167, "position": 3167, "text": "that whale\nas providential. Was not Saul of Tarsus converted from unbelief by a\nsimilar fright? I tell you, the sperm whale will stand no nonsense.\n\nI will now refer you to Langsdorff’s Voyages for a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3168, "position": 3168, "text": "I will now refer you to Langsdorff’s Voyages for a little circumstance\nin point, peculiarly interesting to the writer hereof. Langsdorff, you\nmust know by the way, was attached to the Russian Admiral Krusens", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 300, "2000": 1584}}, {"id": 3169, "position": 3169, "text": "must know by the way, was attached to the Russian Admiral Krusenstern’s\nfamous Discovery Expedition in the beginning of the present century.\nCaptain Langsdorff thus begins his seventeenth chapter:\n\n“By the thirteenth of May our ship was ready", "labels": {"50": 45, "100": 29, "250": 138, "500": 48, "1000": 300, "2000": 207}}, {"id": 3170, "position": 3170, "text": "begins his seventeenth chapter:\n\n“By the thirteenth of May our ship was ready to sail, and the next day\nwe were out in the open sea, on our way to Ochotsh. The weather was\nvery clear and fine, but so intoler", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 3171, "position": 3171, "text": "otsh. The weather was\nvery clear and fine, but so intolerably cold that we were obliged to\nkeep on our fur clothing. For some days we had very little wind; it was\nnot till the nineteenth that a brisk gale from the northwest", "labels": {"50": 12, "100": 43, "250": 209, "500": 384, "1000": 139, "2000": 1784}}, {"id": 3172, "position": 3172, "text": "wind; it was\nnot till the nineteenth that a brisk gale from the northwest sprang up.\nAn uncommon large whale, the body of which was larger than the ship\nitself, lay almost at the surface of the water, but was not perceived\nby any one", "labels": {"50": 45, "100": 64, "250": 138, "500": 48, "1000": 997, "2000": 1931}}, {"id": 3173, "position": 3173, "text": "almost at the surface of the water, but was not perceived\nby any one on board till the moment when the ship, which was in full\nsail, was almost upon him, so that it was impossible to prevent its\nstriking against him", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 3174, "position": 3174, "text": "so that it was impossible to prevent its\nstriking against him. We were thus placed in the most imminent danger,\nas this gigantic creature, setting up its back, raised the ship three\nfeet at least out of the water", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1243}}, {"id": 3175, "position": 3175, "text": "three\nfeet at least out of the water. The masts reeled, and the sails fell\naltogether, while we who were below all sprang instantly upon the deck,\nconcluding that we had struck upon some rock; instead of this we saw\nthe monster sailing", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1243}}, {"id": 3176, "position": 3176, "text": "we had struck upon some rock; instead of this we saw\nthe monster sailing off with the utmost gravity and solemnity. Captain\nD’Wolf applied immediately to the pumps to examine whether or not the\nvessel had received any damage from the shock, but we", "labels": {"50": 45, "100": 43, "250": 55, "500": 48, "1000": 313, "2000": 1243}}, {"id": 3177, "position": 3177, "text": "whether or not the\nvessel had received any damage from the shock, but we found that very\nhappily it had escaped entirely uninjured.”\n\nNow, the Captain D’Wolf here alluded to as commanding the ship in\nquestion, is a New England", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 732, "2000": 1584}}, {"id": 3178, "position": 3178, "text": "here alluded to as commanding the ship in\nquestion, is a New Englander, who, after a long life of unusual\nadventures as a sea-captain, this day resides in the village of\nDorchester near Boston", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 327, "2000": 1584}}, {"id": 3179, "position": 3179, "text": "in the village of\nDorchester near Boston. I have the honor of being a nephew of his. I\nhave particularly questioned him concerning this passage in Langsdorff.\nHe substantiates every word. The ship, however, was by no means", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1584}}, {"id": 3180, "position": 3180, "text": "stantiates every word. The ship, however, was by no means a large\none: a Russian craft built on the Siberian coast, and purchased by my\nuncle after bartering away the vessel in which he sailed from home.", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 3181, "position": 3181, "text": "ering away the vessel in which he sailed from home.\n\nIn that up and down manly book of old-fashioned adventure, so full,\ntoo, of honest wonders—the voyage of Lionel Wafer, one of ancient\nDampier’s old chums", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1790}}, {"id": 3182, "position": 3182, "text": "of Lionel Wafer, one of ancient\nDampier’s old chums—I found a little matter set down so like that just\nquoted from Langsdorff, that I cannot forbear inserting it here for a\ncorroborative", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 3183, "position": 3183, "text": "I cannot forbear inserting it here for a\ncorroborative example, if such be needed.\n\nLionel, it seems, was on his way to “John Ferdinando,” as he calls the\nmodern Juan Fernandes", "labels": {"50": 45, "100": 29, "250": 82, "500": 73, "1000": 851, "2000": 1584}}, {"id": 3184, "position": 3184, "text": "o,” as he calls the\nmodern Juan Fernandes. “In our way thither,” he says, “about four\no’clock in the morning, when we were about one hundred and fifty\nleagues from the Main of America,", "labels": {"50": 45, "100": 29, "250": 138, "500": 306, "1000": 126, "2000": 1028}}, {"id": 3185, "position": 3185, "text": "when we were about one hundred and fifty\nleagues from the Main of America, our ship felt a terrible shock, which\nput our men in such consternation that they could hardly tell where\nthey were or what to think; but every one began to prepare", "labels": {"50": 45, "100": 29, "250": 125, "500": 384, "1000": 139, "2000": 801}}, {"id": 3186, "position": 3186, "text": "tell where\nthey were or what to think; but every one began to prepare for death.\nAnd, indeed, the shock was so sudden and violent, that we took it for\ngranted the ship had struck against a rock; but when the amazement was\na", "labels": {"50": 45, "100": 64, "250": 112, "500": 384, "1000": 139, "2000": 801}}, {"id": 3187, "position": 3187, "text": "granted the ship had struck against a rock; but when the amazement was\na little over, we cast the lead, and sounded, but found no ground. * *\n* * * The suddenness of the shock made the guns leap in their\ncarriages,", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 3188, "position": 3188, "text": "* The suddenness of the shock made the guns leap in their\ncarriages, and several of the men were shaken out of their hammocks.\nCaptain Davis, who lay with his head on a gun, was thrown out of his\ncabin!” Lionel", "labels": {"50": 45, "100": 64, "250": 82, "500": 28, "1000": 642, "2000": 282}}, {"id": 3189, "position": 3189, "text": "his head on a gun, was thrown out of his\ncabin!” Lionel then goes on to impute the shock to an earthquake, and\nseems to substantiate the imputation by stating that a great\nearthquake, somewhere about that time, did", "labels": {"50": 44, "100": 57, "250": 137, "500": 77, "1000": 57, "2000": 823}}, {"id": 3190, "position": 3190, "text": "imputation by stating that a great\nearthquake, somewhere about that time, did actually do great mischief\nalong the Spanish land. But I should not much wonder if, in the\ndarkness of that early hour of the morning, the shock was after all\ncaused by", "labels": {"50": 48, "100": 19, "250": 234, "500": 102, "1000": 875, "2000": 333}}, {"id": 3191, "position": 3191, "text": "of that early hour of the morning, the shock was after all\ncaused by an unseen whale vertically bumping the hull from beneath.\n\nI might proceed with several more examples, one way or another known to\nme, of the great power and malice at times", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3192, "position": 3192, "text": "way or another known to\nme, of the great power and malice at times of the sperm whale. In more\nthan one instance, he has been known, not only to chase the assailing\nboats back to their ships, but to pursue the ship itself", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3193, "position": 3193, "text": "the assailing\nboats back to their ships, but to pursue the ship itself, and long\nwithstand all the lances hurled at him from its decks. The English ship\nPusie Hall can tell a story on that head; and, as for his strength", "labels": {"50": 45, "100": 64, "250": 82, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3194, "position": 3194, "text": "Hall can tell a story on that head; and, as for his strength, let\nme say, that there have been examples where the lines attached to a\nrunning sperm whale have, in a calm, been transferred to the ship, and\nsecured there;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3195, "position": 3195, "text": ", in a calm, been transferred to the ship, and\nsecured there; the whale towing her great hull through the water, as a\nhorse walks off with a cart. Again, it is very often observed that, if\nthe sperm whale, once struck", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3196, "position": 3196, "text": ", it is very often observed that, if\nthe sperm whale, once struck, is allowed time to rally, he then acts,\nnot so often with blind rage, as with wilful, deliberate designs of\ndestruction to his pursuers; nor is it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3197, "position": 3197, "text": "wilful, deliberate designs of\ndestruction to his pursuers; nor is it without conveying some eloquent\nindication of his character, that upon being attacked he will\nfrequently open his mouth, and retain it in that dread expansion for\nseveral consecutive minutes", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 744}}, {"id": 3198, "position": 3198, "text": "his mouth, and retain it in that dread expansion for\nseveral consecutive minutes. But I must be content with only one more\nand a concluding illustration; a remarkable and most significant one,\nby which you will not fail to see, that not only is the", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 145}}, {"id": 3199, "position": 3199, "text": ",\nby which you will not fail to see, that not only is the most marvellous\nevent in this book corroborated by plain facts of the present day, but\nthat these marvels (like all marvels) are mere repetitions of", "labels": {"50": 45, "100": 29, "250": 138, "500": 13, "1000": 622, "2000": 1097}}, {"id": 3200, "position": 3200, "text": "that these marvels (like all marvels) are mere repetitions of the ages;\nso that for the millionth time we say amen with Solomon—Verily there is\nnothing new under the sun.", "labels": {"50": 31, "100": 75, "250": 13, "500": 307, "1000": 15, "2000": 336}}, {"id": 3201, "position": 3201, "text": "is\nnothing new under the sun.\n\nIn the sixth Christian century lived Procopius, a Christian magistrate\nof Constantinople, in the days when Justinian was Emperor and\nBelisarius general. As many know, he wrote the history of his own\ntimes", "labels": {"50": 26, "100": 54, "250": 198, "500": 188, "1000": 404, "2000": 580}}, {"id": 3202, "position": 3202, "text": "rius general. As many know, he wrote the history of his own\ntimes, a work every way of uncommon value. By the best authorities, he\nhas always been considered a most trustworthy and unexaggerating\nhistorian, except in some one or", "labels": {"50": 26, "100": 54, "250": 113, "500": 188, "1000": 404, "2000": 580}}, {"id": 3203, "position": 3203, "text": "most trustworthy and unexaggerating\nhistorian, except in some one or two particulars, not at all affecting\nthe matter presently to be mentioned.\n\nNow, in this history of his, Procopius mentions that, during the term\nof his", "labels": {"50": 26, "100": 66, "250": 198, "500": 86, "1000": 736, "2000": 1302}}, {"id": 3204, "position": 3204, "text": "of his, Procopius mentions that, during the term\nof his prefecture at Constantinople, a great sea-monster was captured\nin the neighboring Propontis, or Sea of Marmora, after having destroyed\nvessels at intervals in those waters for a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3205, "position": 3205, "text": "of Marmora, after having destroyed\nvessels at intervals in those waters for a period of more than fifty\nyears. A fact thus set down in substantial history cannot easily be\ngainsaid. Nor is there any reason it should be", "labels": {"50": 45, "100": 29, "250": 82, "500": 239, "1000": 899, "2000": 1584}}, {"id": 3206, "position": 3206, "text": ". Nor is there any reason it should be. Of what precise species\nthis sea-monster was, is not mentioned. But as he destroyed ships, as\nwell as for other reasons, he must have been a whale; and I am strongly\ninclined to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3207, "position": 3207, "text": "reasons, he must have been a whale; and I am strongly\ninclined to think a sperm whale. And I will tell you why. For a long\ntime I fancied that the sperm whale had been always unknown in the\nMediterranean and the deep waters", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3208, "position": 3208, "text": "that the sperm whale had been always unknown in the\nMediterranean and the deep waters connecting with it. Even now I am\ncertain that those seas are not, and perhaps never can be, in the\npresent constitution of things, a place for his habitual greg", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3209, "position": 3209, "text": ", in the\npresent constitution of things, a place for his habitual gregarious\nresort. But further investigations have recently proved to me, that in\nmodern times there have been isolated instances of the presence of the\nsperm whale in the Mediterranean", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3210, "position": 3210, "text": "isolated instances of the presence of the\nsperm whale in the Mediterranean. I am told, on good authority, that on\nthe Barbary coast, a Commodore Davis of the British navy found the\nskeleton of a sperm whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3211, "position": 3211, "text": "navy found the\nskeleton of a sperm whale. Now, as a vessel of war readily passes\nthrough the Dardanelles, hence a sperm whale could, by the same route,\npass out of the Mediterranean into the Propontis.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3212, "position": 3212, "text": "pass out of the Mediterranean into the Propontis.\n\nIn the Propontis, as far as I can learn, none of that peculiar\nsubstance called _brit_ is to be found, the aliment of the right whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3213, "position": 3213, "text": "be found, the aliment of the right whale.\nBut I have every reason to believe that the food of the sperm\nwhale—squid or cuttle-fish—lurks at the bottom of that sea, because\nlarge creatures, but by no means", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3214, "position": 3214, "text": "at the bottom of that sea, because\nlarge creatures, but by no means the largest of that sort, have been\nfound at its surface. If, then, you properly put these statements\ntogether, and reason upon them a bit, you will clearly perceive", "labels": {"50": 3, "100": 70, "250": 234, "500": 108, "1000": 37, "2000": 1285}}, {"id": 3215, "position": 3215, "text": "these statements\ntogether, and reason upon them a bit, you will clearly perceive that,\naccording to all human reasoning, Procopius’s sea-monster, that for\nhalf a century stove the ships of a Roman Emperor, must in all\nprobability", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3216, "position": 3216, "text": "half a century stove the ships of a Roman Emperor, must in all\nprobability have been a sperm whale.\n\n\nCHAPTER 46. Surmises.\n\nThough, consumed with the hot fire of his purpose, Ahab in all his\nthoughts and actions ever had in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3217, "position": 3217, "text": "of his purpose, Ahab in all his\nthoughts and actions ever had in view the ultimate capture of Moby\nDick; though he seemed ready to sacrifice all mortal interests to that\none passion; nevertheless it may have been that he was by nature and\nlong", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3218, "position": 3218, "text": "one passion; nevertheless it may have been that he was by nature and\nlong habituation far too wedded to a fiery whaleman’s ways, altogether\nto abandon the collateral prosecution of the voyage. Or at least if\nthis were otherwise, there were", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3219, "position": 3219, "text": "prosecution of the voyage. Or at least if\nthis were otherwise, there were not wanting other motives much more\ninfluential with him. It would be refining too much, perhaps, even\nconsidering his monomania, to hint that his vindictiveness towards the", "labels": {"50": 45, "100": 64, "250": 138, "500": 239, "1000": 300, "2000": 1584}}, {"id": 3220, "position": 3220, "text": "considering his monomania, to hint that his vindictiveness towards the\nWhite Whale might have possibly extended itself in some degree to all\nsperm whales, and that the more monsters he slew by so much the more he\nmultiplied the chances that each subsequently", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3221, "position": 3221, "text": "he slew by so much the more he\nmultiplied the chances that each subsequently encountered whale would\nprove to be the hated one he hunted. But if such an hypothesis be\nindeed exceptionable, there were still additional considerations which,\nthough not so strictly according with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3222, "position": 3222, "text": "able, there were still additional considerations which,\nthough not so strictly according with the wildness of his ruling\npassion, yet were by no means incapable of swaying him.\n\nTo accomplish his object Ahab must use tools; and of all tools used in\nthe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3223, "position": 3223, "text": "his object Ahab must use tools; and of all tools used in\nthe shadow of the moon, men are most apt to get out of order. He knew,\nfor example, that however magnetic his ascendency in some respects was\nover Starbuck", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 723, "2000": 1620}}, {"id": 3224, "position": 3224, "text": ", that however magnetic his ascendency in some respects was\nover Starbuck, yet that ascendency did not cover the complete spiritual\nman any more than mere corporeal superiority involves intellectual\nmastership; for to the purely spiritual, the intellectual but", "labels": {"50": 44, "100": 37, "250": 219, "500": 202, "1000": 858, "2000": 371}}, {"id": 3225, "position": 3225, "text": "superiority involves intellectual\nmastership; for to the purely spiritual, the intellectual but stand in\na sort of corporeal relation. Starbuck’s body and Starbuck’s coerced\nwill were Ahab’s, so long as Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3226, "position": 3226, "text": "coerced\nwill were Ahab’s, so long as Ahab kept his magnet at Starbuck’s brain;\nstill he knew that for all this the chief mate, in his soul, abhorred\nhis captain’s quest, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3227, "position": 3227, "text": ", in his soul, abhorred\nhis captain’s quest, and could he, would joyfully disintegrate himself\nfrom it, or even frustrate it. It might be that a long interval would\nelapse ere the", "labels": {"50": 33, "100": 17, "250": 160, "500": 358, "1000": 138, "2000": 1262}}, {"id": 3228, "position": 3228, "text": ". It might be that a long interval would\nelapse ere the White Whale was seen. During that long interval Starbuck\nwould ever be apt to fall into open relapses of rebellion against his\ncaptain’s leadership, unless some ordinary", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3229, "position": 3229, "text": "lapses of rebellion against his\ncaptain’s leadership, unless some ordinary, prudential, circumstantial\ninfluences were brought to bear upon him. Not only that, but the subtle\ninsanity of Ahab respecting Moby Dick was now", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3230, "position": 3230, "text": "that, but the subtle\ninsanity of Ahab respecting Moby Dick was noways more significantly\nmanifested than in his superlative sense and shrewdness in foreseeing\nthat, for the present, the hunt should in some way be stripped of that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3231, "position": 3231, "text": ", for the present, the hunt should in some way be stripped of that\nstrange imaginative impiousness which naturally invested it; that the\nfull terror of the voyage must be kept withdrawn into the obscure\nbackground (for few men’s courage is proof against", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3232, "position": 3232, "text": "withdrawn into the obscure\nbackground (for few men’s courage is proof against protracted\nmeditation unrelieved by action); that when they stood their long night\nwatches, his officers and men must have some nearer things to think of\nthan Moby", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3233, "position": 3233, "text": "his officers and men must have some nearer things to think of\nthan Moby Dick. For however eagerly and impetuously the savage crew had\nhailed the announcement of his quest; yet all sailors of all sorts are\nmore or less capricious and unreliable", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3234, "position": 3234, "text": "yet all sailors of all sorts are\nmore or less capricious and unreliable—they live in the varying outer\nweather, and they inhale its fickleness—and when retained for any\nobject remote and blank in the pursuit, however promissory", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3235, "position": 3235, "text": "retained for any\nobject remote and blank in the pursuit, however promissory of life and\npassion in the end, it is above all things requisite that temporary\ninterests and employments should intervene and hold them healthily\nsuspended for the final dash.", "labels": {"50": 45, "100": 29, "250": 82, "500": 73, "1000": 723, "2000": 1584}}, {"id": 3236, "position": 3236, "text": "s should intervene and hold them healthily\nsuspended for the final dash.\n\nNor was Ahab unmindful of another thing. In times of strong emotion\nmankind disdain all base considerations; but such times are evanescent", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3237, "position": 3237, "text": "; but such times are evanescent.\nThe permanent constitutional condition of the manufactured man, thought\nAhab, is sordidness. Granting that the White Whale fully incites the\nhearts of this my savage crew, and playing round their savageness", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3238, "position": 3238, "text": "ites the\nhearts of this my savage crew, and playing round their savageness even\nbreeds a certain generous knight-errantism in them, still, while for\nthe love of it they give chase to Moby Dick, they must also have food\nfor", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3239, "position": 3239, "text": "it they give chase to Moby Dick, they must also have food\nfor their more common, daily appetites. For even the high lifted and\nchivalric Crusaders of old times were not content to traverse two\nthousand miles of land to fight for their", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3240, "position": 3240, "text": "times were not content to traverse two\nthousand miles of land to fight for their holy sepulchre, without\ncommitting burglaries, picking pockets, and gaining other pious\nperquisites by the way", "labels": {"50": 48, "100": 27, "250": 53, "500": 144, "1000": 319, "2000": 1630}}, {"id": 3241, "position": 3241, "text": "perquisites by the way. Had they been strictly held to their one final\nand romantic object—that final and romantic object, too many would have\nturned from in disgust. I will not strip these men, thought Ahab, of\nall hopes of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3242, "position": 3242, "text": "I will not strip these men, thought Ahab, of\nall hopes of cash—aye, cash. They may scorn cash now; but let some\nmonths go by, and no perspective promise of it to them, and then this\nsame quies", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3243, "position": 3243, "text": "and no perspective promise of it to them, and then this\nsame quiescent cash all at once mutinying in them, this same cash would\nsoon cashier Ahab.\n\nNor was there wanting still another precautionary motive more related\nto Ah", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3244, "position": 3244, "text": "Nor was there wanting still another precautionary motive more related\nto Ahab personally. Having impulsively, it is probable, and perhaps\nsomewhat prematurely revealed the prime but private purpose of the\nPequod’s voyage, Ahab was now", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3245, "position": 3245, "text": "private purpose of the\nPequod’s voyage, Ahab was now entirely conscious that, in so doing, he\nhad indirectly laid himself open to the unanswerable charge of\nusurpation; and with perfect impunity, both", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3246, "position": 3246, "text": "charge of\nusurpation; and with perfect impunity, both moral and legal, his crew\nif so disposed, and to that end competent, could refuse all further\nobedience to him, and even violently wrest from him the command", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3247, "position": 3247, "text": "obedience to him, and even violently wrest from him the command. From\neven the barely hinted imputation of usurpation, and the possible\nconsequences of such a suppressed impression gaining ground, Ahab must\nof course have been most anxious to protect", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3248, "position": 3248, "text": "impression gaining ground, Ahab must\nof course have been most anxious to protect himself. That protection\ncould only consist in his own predominating brain and heart and hand,\nbacked by a heedful, closely calculating attention to every minute\natmospheric influence which", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3249, "position": 3249, "text": "by a heedful, closely calculating attention to every minute\natmospheric influence which it was possible for his crew to be\nsubjected to.\n\nFor all these reasons then, and others perhaps too analytic to be\nverbally developed here, Ahab plainly saw that he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3250, "position": 3250, "text": "too analytic to be\nverbally developed here, Ahab plainly saw that he must still in a good\ndegree continue true to the natural, nominal purpose of the Pequod’s\nvoyage; observe all customary usages; and not only that, but", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3251, "position": 3251, "text": "s\nvoyage; observe all customary usages; and not only that, but force\nhimself to evince all his well known passionate interest in the general\npursuit of his profession.\n\nBe all this as it may, his voice was now often heard hailing", "labels": {"50": 31, "100": 75, "250": 106, "500": 496, "1000": 901, "2000": 1926}}, {"id": 3252, "position": 3252, "text": "Be all this as it may, his voice was now often heard hailing the three\nmast-heads and admonishing them to keep a bright look-out, and not omit\nreporting even a porpoise", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3253, "position": 3253, "text": "omit\nreporting even a porpoise. This vigilance was not long without reward.\n\n\nCHAPTER 47. The Mat-Maker.\n\nIt was a cloudy, sultry afternoon; the seamen were lazily lounging\nabout the decks, or vacantly", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3254, "position": 3254, "text": "; the seamen were lazily lounging\nabout the decks, or vacantly gazing over into the lead-coloured waters.\nQueequeg and I were mildly employed weaving what is called a sword-mat,\nfor an additional lashing to our boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3255, "position": 3255, "text": "is called a sword-mat,\nfor an additional lashing to our boat. So still and subdued and yet\nsomehow preluding was all the scene, and such an incantation of reverie\nlurked in the air, that each silent sailor seemed", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3256, "position": 3256, "text": "ntation of reverie\nlurked in the air, that each silent sailor seemed resolved into his own\ninvisible self.\n\nI was the attendant or page of Queequeg, while busy at the mat. As I\nkept passing and repassing the filling", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 967}}, {"id": 3257, "position": 3257, "text": "busy at the mat. As I\nkept passing and repassing the filling or woof of marline between the\nlong yarns of the warp, using my own hand for the shuttle, and as\nQueequeg, standing sideways, ever and", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 3258, "position": 3258, "text": "the shuttle, and as\nQueequeg, standing sideways, ever and anon slid his heavy oaken sword\nbetween the threads, and idly looking off upon the water, carelessly\nand unthinkingly drove home every yarn: I say", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3259, "position": 3259, "text": ", carelessly\nand unthinkingly drove home every yarn: I say so strange a dreaminess\ndid there then reign all over the ship and all over the sea, only\nbroken by the intermitting dull sound of the sword, that it seemed", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 3260, "position": 3260, "text": "broken by the intermitting dull sound of the sword, that it seemed as\nif this were the Loom of Time, and I myself were a shuttle mechanically\nweaving and weaving away at the Fates. There lay the fixed threads of\nthe warp subject to", "labels": {"50": 20, "100": 5, "250": 132, "500": 412, "1000": 914, "2000": 381}}, {"id": 3261, "position": 3261, "text": "away at the Fates. There lay the fixed threads of\nthe warp subject to but one single, ever returning, unchanging\nvibration, and that vibration merely enough to admit of the crosswise\ninterblending of other threads with its own", "labels": {"50": 22, "100": 78, "250": 229, "500": 163, "1000": 808, "2000": 1852}}, {"id": 3262, "position": 3262, "text": "the crosswise\ninterblending of other threads with its own. This warp seemed\nnecessity; and here, thought I, with my own hand I ply my own shuttle\nand weave my own destiny into these unalterable threads", "labels": {"50": 16, "100": 20, "250": 132, "500": 411, "1000": 914, "2000": 1254}}, {"id": 3263, "position": 3263, "text": "weave my own destiny into these unalterable threads. Meantime,\nQueequeg’s impulsive, indifferent sword, sometimes hitting the woof\nslantingly, or crookedly, or strongly, or weakly, as the case might be;\nand", "labels": {"50": 20, "100": 5, "250": 45, "500": 280, "1000": 421, "2000": 381}}, {"id": 3264, "position": 3264, "text": "ly, or strongly, or weakly, as the case might be;\nand by this difference in the concluding blow producing a corresponding\ncontrast in the final aspect of the completed fabric; this savage’s\nsword, thought I, which thus finally shapes and fashion", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 437, "2000": 573}}, {"id": 3265, "position": 3265, "text": "this savage’s\nsword, thought I, which thus finally shapes and fashions both warp and\nwoof; this easy, indifferent sword must be chance—aye, chance, free\nwill, and necessity—nowise incompatible—all interweaving", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 437, "2000": 193}}, {"id": 3266, "position": 3266, "text": "free\nwill, and necessity—nowise incompatible—all interweavingly working\ntogether. The straight warp of necessity, not to be swerved from its\nultimate course—its every alternating vibration, indeed, only tending\nto that; free will still", "labels": {"50": 10, "100": 71, "250": 33, "500": 395, "1000": 211, "2000": 1944}}, {"id": 3267, "position": 3267, "text": "its every alternating vibration, indeed, only tending\nto that; free will still free to ply her shuttle between given threads;\nand chance, though restrained in its play within the right lines of\nnecessity, and sideways in its motions directed by free will,", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 368, "2000": 1175}}, {"id": 3268, "position": 3268, "text": "right lines of\nnecessity, and sideways in its motions directed by free will, though\nthus prescribed to by both, chance by turns rules either, and has the\nlast featuring blow at events.\n\nThus we were weaving and weaving away when I started at a sound", "labels": {"50": 9, "100": 26, "250": 106, "500": 333, "1000": 344, "2000": 1208}}, {"id": 3269, "position": 3269, "text": "events.\n\nThus we were weaving and weaving away when I started at a sound so\nstrange, long drawn, and musically wild and unearthly, that the ball of\nfree will dropped from my hand, and I stood gazing up at the clouds\nwhence", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1254}}, {"id": 3270, "position": 3270, "text": "dropped from my hand, and I stood gazing up at the clouds\nwhence that voice dropped like a wing. High aloft in the cross-trees\nwas that mad Gay-Header, Tashtego", "labels": {"50": 16, "100": 5, "250": 26, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3271, "position": 3271, "text": "Header, Tashtego. His body was reaching eagerly\nforward, his hand stretched out like a wand, and at brief sudden\nintervals he continued his cries. To be sure the same sound was that\nvery moment perhaps being heard all over the seas,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3272, "position": 3272, "text": "the same sound was that\nvery moment perhaps being heard all over the seas, from hundreds of\nwhalemen’s look-outs perched as high in the air; but from few of those\nlungs could that accustomed old cry have derived such a marvellous\ncadence", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3273, "position": 3273, "text": "of those\nlungs could that accustomed old cry have derived such a marvellous\ncadence as from Tashtego the Indian’s.\n\nAs he stood hovering over you half suspended in air, so wildly and\neagerly peering towards the horizon, you would have thought", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3274, "position": 3274, "text": "air, so wildly and\neagerly peering towards the horizon, you would have thought him some\nprophet or seer beholding the shadows of Fate, and by those wild cries\nannouncing their coming.\n\n“There she blows! there! there! there! she blows", "labels": {"50": 34, "100": 77, "250": 164, "500": 89, "1000": 267, "2000": 721}}, {"id": 3275, "position": 3275, "text": "coming.\n\n“There she blows! there! there! there! she blows! she blows!”\n\n“Where-away?”\n\n“On the lee-beam, about two miles off! a school of them!”\n\nInstantly all was commotion.", "labels": {"50": 45, "100": 64, "250": 163, "500": 176, "1000": 601, "2000": 473}}, {"id": 3276, "position": 3276, "text": "miles off! a school of them!”\n\nInstantly all was commotion.\n\nThe Sperm Whale blows as a clock ticks, with the same undeviating and\nreliable uniformity. And thereby whalemen distinguish this fish from\nother tribes of his genus.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3277, "position": 3277, "text": "And thereby whalemen distinguish this fish from\nother tribes of his genus.\n\n“There go flukes!” was now the cry from Tashtego; and the whales\ndisappeared.\n\n“Quick, steward!” cried Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3278, "position": 3278, "text": ".\n\n“Quick, steward!” cried Ahab. “Time! time!”\n\nDough-Boy hurried below, glanced at the watch, and reported the exact\nminute to Ahab.\n\nThe ship was now kept away from the wind, and she went", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3279, "position": 3279, "text": "ab.\n\nThe ship was now kept away from the wind, and she went gently rolling\nbefore it. Tashtego reporting that the whales had gone down heading to\nleeward, we confidently looked to see them again directly in advance of\nour bows", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3280, "position": 3280, "text": ", we confidently looked to see them again directly in advance of\nour bows. For that singular craft at times evinced by the Sperm Whale\nwhen, sounding with his head in one direction, he nevertheless, while\nconcealed beneath the surface, mills round,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3281, "position": 3281, "text": "one direction, he nevertheless, while\nconcealed beneath the surface, mills round, and swiftly swims off in\nthe opposite quarter—this deceitfulness of his could not now be in\naction; for there was no reason to suppose that the fish seen by", "labels": {"50": 12, "100": 24, "250": 213, "500": 288, "1000": 692, "2000": 778}}, {"id": 3282, "position": 3282, "text": "in\naction; for there was no reason to suppose that the fish seen by\nTashtego had been in any way alarmed, or indeed knew at all of our\nvicinity. One of the men selected for shipkeepers—that is, those not\nappointed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3283, "position": 3283, "text": "One of the men selected for shipkeepers—that is, those not\nappointed to the boats, by this time relieved the Indian at the\nmain-mast head. The sailors at the fore and mizzen had come down; the\nline tubs were", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 3284, "position": 3284, "text": "the fore and mizzen had come down; the\nline tubs were fixed in their places; the cranes were thrust out; the\nmainyard was backed, and the three boats swung over the sea like three\nsamphire baskets over high cliffs", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1790}}, {"id": 3285, "position": 3285, "text": "boats swung over the sea like three\nsamphire baskets over high cliffs. Outside of the bulwarks their eager\ncrews with one hand clung to the rail, while one foot was expectantly\npoised on the gunwale", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 3286, "position": 3286, "text": "foot was expectantly\npoised on the gunwale. So look the long line of man-of-war’s men about\nto throw themselves on board an enemy’s ship.\n\nBut at this critical instant a sudden exclamation was heard", "labels": {"50": 45, "100": 64, "250": 82, "500": 73, "1000": 851, "2000": 967}}, {"id": 3287, "position": 3287, "text": "ship.\n\nBut at this critical instant a sudden exclamation was heard that took\nevery eye from the whale. With a start all glared at dark Ahab, who was\nsurrounded by five dusky phantoms that seemed fresh formed out of air.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3288, "position": 3288, "text": "surrounded by five dusky phantoms that seemed fresh formed out of air.\n\n\nCHAPTER 48. The First Lowering.\n\nThe phantoms, for so they then seemed, were flitting on the other side\nof the deck, and, with a noiseless", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 642, "2000": 967}}, {"id": 3289, "position": 3289, "text": "ing on the other side\nof the deck, and, with a noiseless celerity, were casting loose the\ntackles and bands of the boat which swung there. This boat had always\nbeen deemed one of the spare boats, though technically called the\ncaptain", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 3290, "position": 3290, "text": "had always\nbeen deemed one of the spare boats, though technically called the\ncaptain’s, on account of its hanging from the starboard quarter. The\nfigure that now stood by its bows was tall and swart, with one white\ntooth evilly protruding from", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3291, "position": 3291, "text": "bows was tall and swart, with one white\ntooth evilly protruding from its steel-like lips. A rumpled Chinese\njacket of black cotton funereally invested him, with wide black\ntrowsers of the same dark stuff", "labels": {"50": 39, "100": 88, "250": 70, "500": 163, "1000": 383, "2000": 110}}, {"id": 3292, "position": 3292, "text": "with wide black\ntrowsers of the same dark stuff. But strangely crowning this ebonness\nwas a glistening white plaited turban, the living hair braided and\ncoiled round and round upon his head", "labels": {"50": 32, "100": 13, "250": 182, "500": 142, "1000": 131, "2000": 1145}}, {"id": 3293, "position": 3293, "text": "ed and\ncoiled round and round upon his head. Less swart in aspect, the\ncompanions of this figure were of that vivid, tiger-yellow complexion\npeculiar to some of the aboriginal natives of the Manillas;—a race\nnotorious for a certain dia", "labels": {"50": 12, "100": 42, "250": 131, "500": 58, "1000": 222, "2000": 1227}}, {"id": 3294, "position": 3294, "text": "aboriginal natives of the Manillas;—a race\nnotorious for a certain diabolism of subtilty, and by some honest white\nmariners supposed to be the paid spies and secret confidential agents\non the water of the devil, their lord, whose counting", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1243}}, {"id": 3295, "position": 3295, "text": "secret confidential agents\non the water of the devil, their lord, whose counting-room they suppose\nto be elsewhere.\n\nWhile yet the wondering ship’s company were gazing upon these\nstrangers, Ahab cried out to the white-turbaned old man", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3296, "position": 3296, "text": "strangers, Ahab cried out to the white-turbaned old man at their head,\n“All ready there, Fedallah?”\n\n“Ready,” was the half-hissed reply.\n\n“Lower away then; d’ye hear?", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 3297, "position": 3297, "text": "half-hissed reply.\n\n“Lower away then; d’ye hear?” shouting across the deck. “Lower away\nthere, I say.”\n\nSuch was the thunder of his voice, that spite of their amazement the\nmen sprang over the rail;", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 3298, "position": 3298, "text": "his voice, that spite of their amazement the\nmen sprang over the rail; the sheaves whirled round in the blocks; with\na wallow, the three boats dropped into the sea; while, with a\ndexterous, off-handed daring, unknown", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 3299, "position": 3299, "text": "sea; while, with a\ndexterous, off-handed daring, unknown in any other vocation, the\nsailors, goat-like, leaped down the rolling ship’s side into the tossed\nboats below.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 967}}, {"id": 3300, "position": 3300, "text": "side into the tossed\nboats below.\n\nHardly had they pulled out from under the ship’s lee, when a fourth\nkeel, coming from the windward side, pulled round under the stern, and\nshowed the five strangers rowing Ahab, who, standing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3301, "position": 3301, "text": "the stern, and\nshowed the five strangers rowing Ahab, who, standing erect in the\nstern, loudly hailed Starbuck, Stubb, and Flask, to spread themselves\nwidely, so as to cover a large expanse of water", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3302, "position": 3302, "text": "widely, so as to cover a large expanse of water. But with all their\neyes again riveted upon the swart Fedallah and his crew, the inmates of\nthe other boats obeyed not the command.", "labels": {"50": 32, "100": 25, "250": 93, "500": 142, "1000": 131, "2000": 1145}}, {"id": 3303, "position": 3303, "text": "the other boats obeyed not the command.\n\n“Captain Ahab?—” said Starbuck.\n\n“Spread yourselves,” cried Ahab; “give way, all four boats. Thou,\nFlask, pull out more to leeward!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3304, "position": 3304, "text": ". Thou,\nFlask, pull out more to leeward!”\n\n“Aye, aye, sir,” cheerily cried little King-Post, sweeping round his\ngreat steering oar. “Lay back!” addressing his crew", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3305, "position": 3305, "text": "oar. “Lay back!” addressing his crew.\n“There!—there!—there again! There she blows right ahead, boys!—lay\nback!”\n\n“Never heed yonder yellow boys, Archy.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 327, "2000": 967}}, {"id": 3306, "position": 3306, "text": "“Never heed yonder yellow boys, Archy.”\n\n“Oh, I don’t mind ’em, sir,” said Archy; “I knew it all before now.\nDidn’t I hear ’em in the hold?", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 3307, "position": 3307, "text": "all before now.\nDidn’t I hear ’em in the hold? And didn’t I tell Cabaco here of it?\nWhat say ye, Cabaco? They are stowaways, Mr. Flask.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 3308, "position": 3308, "text": "are stowaways, Mr. Flask.”\n\n“Pull, pull, my fine hearts-alive; pull, my children; pull, my little\nones,” drawlingly and soothingly sighed Stubb to his crew, some of whom", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3309, "position": 3309, "text": "lingly and soothingly sighed Stubb to his crew, some of whom\nstill showed signs of uneasiness. “Why don’t you break your backbones,\nmy boys? What is it you stare at? Those chaps in yonder", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3310, "position": 3310, "text": "boys? What is it you stare at? Those chaps in yonder boat? Tut! They\nare only five more hands come to help us—never mind from where—the more\nthe merrier", "labels": {"50": 45, "100": 64, "250": 138, "500": 363, "1000": 251, "2000": 1977}}, {"id": 3311, "position": 3311, "text": "—the more\nthe merrier. Pull, then, do pull; never mind the brimstone—devils are\ngood fellows enough. So, so; there you are now; that’s the stroke for a\nthousand pounds; that’s the", "labels": {"50": 9, "100": 1, "250": 30, "500": 475, "1000": 902, "2000": 39}}, {"id": 3312, "position": 3312, "text": "; that’s the stroke for a\nthousand pounds; that’s the stroke to sweep the stakes! Hurrah for the\ngold cup of sperm oil, my heroes! Three cheers, men—all hearts alive!\nEasy, easy; don’", "labels": {"50": 16, "100": 64, "250": 163, "500": 432, "1000": 174, "2000": 16}}, {"id": 3313, "position": 3313, "text": "Three cheers, men—all hearts alive!\nEasy, easy; don’t be in a hurry—don’t be in a hurry. Why don’t you snap\nyour oars, you rascals? Bite something, you dogs!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3314, "position": 3314, "text": "your oars, you rascals? Bite something, you dogs! So, so, so,\nthen:—softly, softly! That’s it—that’s it! long and strong", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 3315, "position": 3315, "text": "s it! long and strong. Give way\nthere, give way! The devil fetch ye, ye ragamuffin rapscallions; ye are\nall asleep. Stop snoring, ye sleepers, and pull", "labels": {"50": 16, "100": 73, "250": 240, "500": 61, "1000": 672, "2000": 16}}, {"id": 3316, "position": 3316, "text": "snoring, ye sleepers, and pull. Pull, will ye? pull,\ncan’t ye? pull, won’t ye? Why in the name of gudgeons and ginger-cakes\ndon’t ye pull?—pull", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3317, "position": 3317, "text": "gudgeons and ginger-cakes\ndon’t ye pull?—pull and break something! pull, and start your eyes out!\nHere!” whipping out the sharp knife from his girdle; “every mother’s\nson of ye draw", "labels": {"50": 41, "100": 64, "250": 193, "500": 498, "1000": 54, "2000": 1620}}, {"id": 3318, "position": 3318, "text": "from his girdle; “every mother’s\nson of ye draw his knife, and pull with the blade between his teeth.\nThat’s it—that’s it. Now ye do something; that looks like it, my\nsteel-", "labels": {"50": 41, "100": 64, "250": 163, "500": 180, "1000": 230, "2000": 160}}, {"id": 3319, "position": 3319, "text": "it. Now ye do something; that looks like it, my\nsteel-bits. Start her—start her, my silver-spoons! Start her,\nmarling-spikes!”\n\nStubb’s exordium to his crew is given", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 3320, "position": 3320, "text": "spikes!”\n\nStubb’s exordium to his crew is given here at large, because he had\nrather a peculiar way of talking to them in general, and especially in\ninculcating the religion of rowing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3321, "position": 3321, "text": "in\ninculcating the religion of rowing. But you must not suppose from this\nspecimen of his sermonizings that he ever flew into downright passions\nwith his congregation. Not at all; and therein consisted his chief\npeculiarity", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 322, "2000": 1004}}, {"id": 3322, "position": 3322, "text": "at all; and therein consisted his chief\npeculiarity. He would say the most terrific things to his crew, in a\ntone so strangely compounded of fun and fury, and the fury seemed so\ncalculated merely as a spice to the fun, that", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3323, "position": 3323, "text": "and the fury seemed so\ncalculated merely as a spice to the fun, that no oarsman could hear\nsuch queer invocations without pulling for dear life, and yet pulling\nfor the mere joke of the thing", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 3324, "position": 3324, "text": "for the mere joke of the thing. Besides he all the time looked so easy\nand indolent himself, so loungingly managed his steering-oar, and so\nbroadly gaped—open-mouthed at times—that the mere sight of such a", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 531, "2000": 110}}, {"id": 3325, "position": 3325, "text": "gaped—open-mouthed at times—that the mere sight of such a\nyawning commander, by sheer force of contrast, acted like a charm upon\nthe crew. Then again, Stubb was one of those odd sort of humorists,\nwhose", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3326, "position": 3326, "text": "again, Stubb was one of those odd sort of humorists,\nwhose jollity is sometimes so curiously ambiguous, as to put all\ninferiors on their guard in the matter of obeying them.", "labels": {"50": 34, "100": 77, "250": 116, "500": 0, "1000": 0, "2000": 0}}, {"id": 3327, "position": 3327, "text": "matter of obeying them.\n\nIn obedience to a sign from Ahab, Starbuck was now pulling obliquely\nacross Stubb’s bow; and when for a minute or so the two boats were\npretty near to each other, Stubb hailed the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3328, "position": 3328, "text": "so the two boats were\npretty near to each other, Stubb hailed the mate.\n\n“Mr. Starbuck! larboard boat there, ahoy! a word with ye, sir, if ye\nplease!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3329, "position": 3329, "text": "with ye, sir, if ye\nplease!”\n\n“Halloa!” returned Starbuck, turning round not a single inch as he\nspoke; still earnestly but whisperingly urging his crew; his face set\nlike a flint from Stubb’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3330, "position": 3330, "text": "urging his crew; his face set\nlike a flint from Stubb’s.\n\n“What think ye of those yellow boys, sir!”\n\n“Smuggled on board, somehow, before the ship sailed. (Strong, strong,\nboys!)”", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3331, "position": 3331, "text": ", before the ship sailed. (Strong, strong,\nboys!)” in a whisper to his crew, then speaking out loud again: “A sad\nbusiness, Mr. Stubb! (seethe her, seethe her, my lads!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3332, "position": 3332, "text": "Stubb! (seethe her, seethe her, my lads!) but never mind,\nMr. Stubb, all for the best. Let all your crew pull strong, come what\nwill. (Spring, my men, spring!)", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3333, "position": 3333, "text": "strong, come what\nwill. (Spring, my men, spring!) There’s hogsheads of sperm ahead, Mr.\nStubb, and that’s what ye came for. (Pull, my boys!) Sperm, sperm", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3334, "position": 3334, "text": "what ye came for. (Pull, my boys!) Sperm, sperm’s the\nplay! This at least is duty; duty and profit hand in hand.”\n\n“Aye, aye, I thought as much,” soliloquized Stu", "labels": {"50": 23, "100": 88, "250": 57, "500": 100, "1000": 800, "2000": 1199}}, {"id": 3335, "position": 3335, "text": "Aye, aye, I thought as much,” soliloquized Stubb, when the boats\ndiverged, “as soon as I clapt eye on ’em, I thought so. Aye, and that’s\nwhat he went into the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3336, "position": 3336, "text": "I thought so. Aye, and that’s\nwhat he went into the after hold for, so often, as Dough-Boy long\nsuspected. They were hidden down there. The White Whale’s at the bottom\nof it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3337, "position": 3337, "text": "The White Whale’s at the bottom\nof it. Well, well, so be it! Can’t be helped! All right! Give way, men!\nIt ain’t the White Whale to-day! Give way!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3338, "position": 3338, "text": "’t the White Whale to-day! Give way!”\n\nNow the advent of these outlandish strangers at such a critical instant\nas the lowering of the boats from the deck, this had not unreasonably\nawakened a sort of supersti", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3339, "position": 3339, "text": "deck, this had not unreasonably\nawakened a sort of superstitious amazement in some of the ship’s\ncompany; but Archy’s fancied discovery having some time previous got\nabroad among them, though indeed not credited then,", "labels": {"50": 48, "100": 60, "250": 217, "500": 439, "1000": 412, "2000": 423}}, {"id": 3340, "position": 3340, "text": "having some time previous got\nabroad among them, though indeed not credited then, this had in some\nsmall measure prepared them for the event. It took off the extreme edge\nof their wonder; and so what with all this and Stubb’s confident way", "labels": {"50": 0, "100": 91, "250": 0, "500": 98, "1000": 443, "2000": 1217}}, {"id": 3341, "position": 3341, "text": "wonder; and so what with all this and Stubb’s confident way of\naccounting for their appearance, they were for the time freed from\nsuperstitious surmisings; though the affair still left abundant room\nfor all manner of wild conjectures as", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3342, "position": 3342, "text": "though the affair still left abundant room\nfor all manner of wild conjectures as to dark Ahab’s precise agency in\nthe matter from the beginning. For me, I silently recalled the\nmysterious shadows I had seen creeping on board the Pequod during", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3343, "position": 3343, "text": "recalled the\nmysterious shadows I had seen creeping on board the Pequod during the\ndim Nantucket dawn, as well as the enigmatical hintings of the\nunaccountable Elijah.\n\nMeantime, Ahab, out of hearing of his officers, having", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3344, "position": 3344, "text": "Elijah.\n\nMeantime, Ahab, out of hearing of his officers, having sided the\nfurthest to windward, was still ranging ahead of the other boats; a\ncircumstance bespeaking how potent a crew was pulling him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3345, "position": 3345, "text": "speaking how potent a crew was pulling him. Those tiger\nyellow creatures of his seemed all steel and whalebone; like five\ntrip-hammers they rose and fell with regular strokes of strength, which\nperiodically started the boat along the water like a", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1111}}, {"id": 3346, "position": 3346, "text": "regular strokes of strength, which\nperiodically started the boat along the water like a horizontal burst\nboiler out of a Mississippi steamer. As for Fedallah, who was seen\npulling the harpooneer oar, he had thrown aside his black jacket, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1620}}, {"id": 3347, "position": 3347, "text": "harpooneer oar, he had thrown aside his black jacket, and\ndisplayed his naked chest with the whole part of his body above the\ngunwale, clearly cut against the alternating depressions of the watery\nhorizon; while at the other end of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3348, "position": 3348, "text": "the alternating depressions of the watery\nhorizon; while at the other end of the boat Ahab, with one arm, like a\nfencer’s, thrown half backward into the air, as if to counterbalance\nany tendency to trip; Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3349, "position": 3349, "text": "the air, as if to counterbalance\nany tendency to trip; Ahab was seen steadily managing his steering oar\nas in a thousand boat lowerings ere the White Whale had torn him. All\nat once the outstretched arm gave a peculiar motion and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3350, "position": 3350, "text": "had torn him. All\nat once the outstretched arm gave a peculiar motion and then remained\nfixed, while the boat’s five oars were seen simultaneously peaked. Boat\nand crew sat motionless on the sea. Instantly the three spread boats in\nthe rear paused", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 3351, "position": 3351, "text": "sat motionless on the sea. Instantly the three spread boats in\nthe rear paused on their way. The whales had irregularly settled bodily\ndown into the blue, thus giving no distantly discernible token of the\nmovement, though from his closer vicinity Ah", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3352, "position": 3352, "text": "ly discernible token of the\nmovement, though from his closer vicinity Ahab had observed it.\n\n“Every man look out along his oars!” cried Starbuck. “Thou, Queequeg,\nstand up!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3353, "position": 3353, "text": "“Thou, Queequeg,\nstand up!”\n\nNimbly springing up on the triangular raised box in the bow, the savage\nstood erect there, and with intensely eager eyes gazed off towards the\nspot where the chase had last been des", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3354, "position": 3354, "text": "intensely eager eyes gazed off towards the\nspot where the chase had last been descried. Likewise upon the extreme\nstern of the boat where it was also triangularly platformed level with\nthe gunwale, Starbuck himself was seen coolly and ad", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3355, "position": 3355, "text": "with\nthe gunwale, Starbuck himself was seen coolly and adroitly balancing\nhimself to the jerking tossings of his chip of a craft, and silently\neyeing the vast blue eye of the sea.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3356, "position": 3356, "text": "vast blue eye of the sea.\n\nNot very far distant Flask’s boat was also lying breathlessly still;\nits commander recklessly standing upon the top of the loggerhead, a\nstout sort of post rooted in the keel, and rising some", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3357, "position": 3357, "text": "head, a\nstout sort of post rooted in the keel, and rising some two feet above\nthe level of the stern platform. It is used for catching turns with the\nwhale line. Its top is not more spacious than the palm of a man’s", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3358, "position": 3358, "text": ". Its top is not more spacious than the palm of a man’s hand,\nand standing upon such a base as that, Flask seemed perched at the\nmast-head of some ship which had sunk to all but her trucks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3359, "position": 3359, "text": "of some ship which had sunk to all but her trucks. But little\nKing-Post was small and short, and at the same time little King-Post\nwas full of a large and tall ambition, so that this loggerhead\nstand-point of", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 967}}, {"id": 3360, "position": 3360, "text": "large and tall ambition, so that this loggerhead\nstand-point of his did by no means satisfy King-Post.\n\n“I can’t see three seas off; tip us up an oar there, and let me on to\nthat.", "labels": {"50": 23, "100": 31, "250": 219, "500": 221, "1000": 317, "2000": 1087}}, {"id": 3361, "position": 3361, "text": "tip us up an oar there, and let me on to\nthat.”\n\nUpon this, Daggoo, with either hand upon the gunwale to steady his way,\nswiftly slid aft, and then erecting himself volunteered his lofty\nshoulders", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 3362, "position": 3362, "text": ",\nswiftly slid aft, and then erecting himself volunteered his lofty\nshoulders for a pedestal.\n\n“Good a mast-head as any, sir. Will you mount?”\n\n“That I will, and thank ye very much, my fine fellow;", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3363, "position": 3363, "text": "“That I will, and thank ye very much, my fine fellow; only I wish you\nfifty feet taller.”\n\nWhereupon planting his feet firmly against two opposite planks of the\nboat, the gigantic negro, stooping a little, presented his flat", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3364, "position": 3364, "text": "the\nboat, the gigantic negro, stooping a little, presented his flat palm to\nFlask’s foot, and then putting Flask’s hand on his hearse-plumed head\nand bidding him spring as he himself should toss, with", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 3365, "position": 3365, "text": "-plumed head\nand bidding him spring as he himself should toss, with one dexterous\nfling landed the little man high and dry on his shoulders. And here was\nFlask now standing, Daggoo with one lifted arm furnishing him with", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3366, "position": 3366, "text": "now standing, Daggoo with one lifted arm furnishing him with a\nbreastband to lean against and steady himself by.\n\nAt any time it is a strange sight to the tyro to see with what wondrous\nhabitude of unconscious skill", "labels": {"50": 37, "100": 55, "250": 145, "500": 444, "1000": 959, "2000": 314}}, {"id": 3367, "position": 3367, "text": "the tyro to see with what wondrous\nhabitude of unconscious skill the whaleman will maintain an erect\nposture in his boat, even when pitched about by the most riotously\nperverse and cross-running seas", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3368, "position": 3368, "text": "ously\nperverse and cross-running seas. Still more strange to see him giddily\nperched upon the loggerhead itself, under such circumstances. But the\nsight of little Flask mounted upon gigantic Daggoo was yet more\ncurious; for sustaining", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3369, "position": 3369, "text": "Flask mounted upon gigantic Daggoo was yet more\ncurious; for sustaining himself with a cool, indifferent, easy,\nunthought of, barbaric majesty, the noble negro to every roll of the\nsea harmoniously rolled his fine form", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3370, "position": 3370, "text": "the noble negro to every roll of the\nsea harmoniously rolled his fine form. On his broad back, flaxen-haired\nFlask seemed a snow-flake. The bearer looked nobler than the rider", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1904}}, {"id": 3371, "position": 3371, "text": "The bearer looked nobler than the rider.\nThough truly vivacious, tumultuous, ostentatious little Flask would now\nand then stamp with impatience; but not one added heave did he thereby\ngive to the negro’s lord", "labels": {"50": 32, "100": 0, "250": 233, "500": 55, "1000": 856, "2000": 86}}, {"id": 3372, "position": 3372, "text": "not one added heave did he thereby\ngive to the negro’s lordly chest. So have I seen Passion and Vanity\nstamping the living magnanimous earth, but the earth did not alter her\ntides and her seasons for that.", "labels": {"50": 9, "100": 26, "250": 133, "500": 232, "1000": 437, "2000": 573}}, {"id": 3373, "position": 3373, "text": "the earth did not alter her\ntides and her seasons for that.\n\nMeanwhile Stubb, the third mate, betrayed no such far-gazing\nsolicitudes. The whales might have made one of their regular soundings,\nnot a temporary dive from mere", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3374, "position": 3374, "text": "have made one of their regular soundings,\nnot a temporary dive from mere fright; and if that were the case,\nStubb, as his wont in such cases, it seems, was resolved to solace the\nlanguishing interval with his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3375, "position": 3375, "text": "it seems, was resolved to solace the\nlanguishing interval with his pipe. He withdrew it from his hatband,\nwhere he always wore it aslant like a feather. He loaded it, and rammed\nhome the loading with his thumb-", "labels": {"50": 22, "100": 78, "250": 28, "500": 469, "1000": 328, "2000": 110}}, {"id": 3376, "position": 3376, "text": "feather. He loaded it, and rammed\nhome the loading with his thumb-end; but hardly had he ignited his\nmatch across the rough sandpaper of his hand, when Tashtego, his\nharpooneer, whose eyes had been setting to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3377, "position": 3377, "text": "shtego, his\nharpooneer, whose eyes had been setting to windward like two fixed\nstars, suddenly dropped like light from his erect attitude to his seat,\ncrying out in a quick phrensy of hurry, “Down, down all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3378, "position": 3378, "text": "out in a quick phrensy of hurry, “Down, down all, and give\nway!—there they are!”\n\nTo a landsman, no whale, nor any sign of a herring, would have been\nvisible at that moment; nothing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3379, "position": 3379, "text": "any sign of a herring, would have been\nvisible at that moment; nothing but a troubled bit of greenish white\nwater, and thin scattered puffs of vapor hovering over it, and\nsuffusingly blowing off to leeward, like the confused sc", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3380, "position": 3380, "text": "and\nsuffusingly blowing off to leeward, like the confused scud from white\nrolling billows. The air around suddenly vibrated and tingled, as it\nwere, like the air over intensely heated plates of iron", "labels": {"50": 37, "100": 18, "250": 122, "500": 392, "1000": 705, "2000": 1637}}, {"id": 3381, "position": 3381, "text": "like the air over intensely heated plates of iron. Beneath this\natmospheric waving and curling, and partially beneath a thin layer of\nwater, also, the whales were swimming. Seen in advance of all the other\nindications, the puffs of vapor they spout", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3382, "position": 3382, "text": "advance of all the other\nindications, the puffs of vapor they spouted, seemed their forerunning\ncouriers and detached flying outriders.\n\nAll four boats were now in keen pursuit of that one spot of troubled\nwater and air", "labels": {"50": 45, "100": 64, "250": 138, "500": 363, "1000": 251, "2000": 73}}, {"id": 3383, "position": 3383, "text": "in keen pursuit of that one spot of troubled\nwater and air. But it bade fair to outstrip them; it flew on and on, as\na mass of interblending bubbles borne down a rapid stream from the\nhills.", "labels": {"50": 22, "100": 78, "250": 28, "500": 469, "1000": 631, "2000": 849}}, {"id": 3384, "position": 3384, "text": "nding bubbles borne down a rapid stream from the\nhills.\n\n“Pull, pull, my good boys,” said Starbuck, in the lowest possible but\nintensest concentrated whisper to his men; while the sharp fixed glance\nfrom his eyes darted straight ahead of", "labels": {"50": 16, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3385, "position": 3385, "text": "his men; while the sharp fixed glance\nfrom his eyes darted straight ahead of the bow, almost seemed as two\nvisible needles in two unerring binnacle compasses. He did not say much\nto his crew, though, nor did his crew say", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3386, "position": 3386, "text": "did not say much\nto his crew, though, nor did his crew say anything to him. Only the\nsilence of the boat was at intervals startlingly pierced by one of his\npeculiar whispers, now harsh with command, now soft with entreaty", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 3387, "position": 3387, "text": "peculiar whispers, now harsh with command, now soft with entreaty.\n\nHow different the loud little King-Post. “Sing out and say something,\nmy hearties. Roar and pull, my thunderbolts! Beach me, beach me", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 16}}, {"id": 3388, "position": 3388, "text": ". Roar and pull, my thunderbolts! Beach me, beach me on\ntheir black backs, boys; only do that for me, and I’ll sign over to you\nmy Martha’s Vineyard plantation, boys; including wife and children,", "labels": {"50": 45, "100": 64, "250": 82, "500": 73, "1000": 851, "2000": 967}}, {"id": 3389, "position": 3389, "text": "you\nmy Martha’s Vineyard plantation, boys; including wife and children,\nboys. Lay me on—lay me on! O Lord, Lord! but I shall go stark, staring\nmad! See! see that white water!” And so shouting", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 3390, "position": 3390, "text": ", staring\nmad! See! see that white water!” And so shouting, he pulled his hat\nfrom his head, and stamped up and down on it; then picking it up,\nflirted it far off upon the sea; and finally fell to", "labels": {"50": 25, "100": 41, "250": 219, "500": 180, "1000": 533, "2000": 1199}}, {"id": 3391, "position": 3391, "text": "up,\nflirted it far off upon the sea; and finally fell to rearing and\nplunging in the boat’s stern like a crazed colt from the prairie.\n\n“Look at that chap now,” philosophically drawled Stubb, who", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3392, "position": 3392, "text": "at that chap now,” philosophically drawled Stubb, who, with his\nunlighted short pipe, mechanically retained between his teeth, at a\nshort distance, followed after—“He’s got fits, that Flask has", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3393, "position": 3393, "text": "followed after—“He’s got fits, that Flask has. Fits?\nyes, give him fits—that’s the very word—pitch fits into ’em. Merrily,\nmerrily, hearts-alive", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 3394, "position": 3394, "text": ". Merrily,\nmerrily, hearts-alive. Pudding for supper, you know;—merry’s the word.\nPull, babes—pull, sucklings—pull, all. But what the devil are you\nhurrying about? Softly,", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 50, "2000": 916}}, {"id": 3395, "position": 3395, "text": "pull, all. But what the devil are you\nhurrying about? Softly, softly, and steadily, my men. Only pull, and\nkeep pulling; nothing more. Crack all your backbones, and bite your\nknives in two—that’s all", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 3396, "position": 3396, "text": "your backbones, and bite your\nknives in two—that’s all. Take it easy—why don’t ye take it easy, I\nsay, and burst all your livers and lungs!”", "labels": {"50": 37, "100": 55, "250": 145, "500": 444, "1000": 959, "2000": 324}}, {"id": 3397, "position": 3397, "text": "your livers and lungs!”\n\nBut what it was that inscrutable Ahab said to that tiger-yellow crew of\nhis—these were words best omitted here; for you live under the blessed\nlight of the evangelical land", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3398, "position": 3398, "text": "you live under the blessed\nlight of the evangelical land. Only the infidel sharks in the audacious\nseas may give ear to such words, when, with tornado brow, and eyes of\nred murder, and foam-glued lips, Ahab", "labels": {"50": 35, "100": 94, "250": 69, "500": 307, "1000": 343, "2000": 1620}}, {"id": 3399, "position": 3399, "text": ", and eyes of\nred murder, and foam-glued lips, Ahab leaped after his prey.\n\nMeanwhile, all the boats tore on. The repeated specific allusions of\nFlask to “that whale,” as he called the fictitious monster which he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3400, "position": 3400, "text": "ask to “that whale,” as he called the fictitious monster which he\ndeclared to be incessantly tantalizing his boat’s bow with its\ntail—these allusions of his were at times so vivid and life-like, that\nthey", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3401, "position": 3401, "text": "usions of his were at times so vivid and life-like, that\nthey would cause some one or two of his men to snatch a fearful look\nover the shoulder. But this was against all rule; for the oarsmen must\nput out their eyes", "labels": {"50": 26, "100": 82, "250": 246, "500": 148, "1000": 255, "2000": 1513}}, {"id": 3402, "position": 3402, "text": "was against all rule; for the oarsmen must\nput out their eyes, and ram a skewer through their necks; usage\npronouncing that they must have no organs but ears, and no limbs but\narms, in these critical moments", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3403, "position": 3403, "text": "no organs but ears, and no limbs but\narms, in these critical moments.\n\nIt was a sight full of quick wonder and awe! The vast swells of the\nomnipotent sea; the surging, hollow roar they made, as they", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 3404, "position": 3404, "text": "potent sea; the surging, hollow roar they made, as they rolled\nalong the eight gunwales, like gigantic bowls in a boundless\nbowling-green; the brief suspended agony of the boat, as it would tip\nfor an instant on", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 3405, "position": 3405, "text": "brief suspended agony of the boat, as it would tip\nfor an instant on the knife-like edge of the sharper waves, that almost\nseemed threatening to cut it in two; the sudden profound dip into the\nwatery glens and hollows; the", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 3406, "position": 3406, "text": "; the sudden profound dip into the\nwatery glens and hollows; the keen spurrings and goadings to gain the\ntop of the opposite hill; the headlong, sled-like slide down its other\nside;—all these,", "labels": {"50": 31, "100": 20, "250": 193, "500": 126, "1000": 275, "2000": 1107}}, {"id": 3407, "position": 3407, "text": ", sled-like slide down its other\nside;—all these, with the cries of the headsmen and harpooneers, and\nthe shuddering gasps of the oarsmen, with the wondrous sight of the\nivory Pequod bearing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3408, "position": 3408, "text": "men, with the wondrous sight of the\nivory Pequod bearing down upon her boats with outstretched sails, like\na wild hen after her screaming brood;—all this was thrilling.\n\nNot the raw recruit, marching from the bosom of his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3409, "position": 3409, "text": "was thrilling.\n\nNot the raw recruit, marching from the bosom of his wife into the fever\nheat of his first battle; not the dead man’s ghost encountering the\nfirst unknown phantom in the other world;—neither of these can feel\nstranger", "labels": {"50": 17, "100": 16, "250": 146, "500": 369, "1000": 355, "2000": 521}}, {"id": 3410, "position": 3410, "text": "first unknown phantom in the other world;—neither of these can feel\nstranger and stronger emotions than that man does, who for the first\ntime finds himself pulling into the charmed, churned circle of the\nhunted sperm whale.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3411, "position": 3411, "text": ", churned circle of the\nhunted sperm whale.\n\nThe dancing white water made by the chase was now becoming more and\nmore visible, owing to the increasing darkness of the dun cloud-shadows\nflung upon the sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3412, "position": 3412, "text": "-shadows\nflung upon the sea. The jets of vapor no longer blended, but tilted\neverywhere to right and left; the whales seemed separating their wakes.\nThe boats were pulled more apart; Starbuck giving chase to three whales\nrunning dead to leeward", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 3413, "position": 3413, "text": "apart; Starbuck giving chase to three whales\nrunning dead to leeward. Our sail was now set, and, with the still\nrising wind, we rushed along; the boat going with such madness through\nthe water, that the lee oars could scarcely", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3414, "position": 3414, "text": "going with such madness through\nthe water, that the lee oars could scarcely be worked rapidly enough to\nescape being torn from the row-locks.\n\nSoon we were running through a suffusing wide veil of mist; neither\nship nor boat to be seen", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3415, "position": 3415, "text": "suffusing wide veil of mist; neither\nship nor boat to be seen.\n\n“Give way, men,” whispered Starbuck, drawing still further aft the\nsheet of his sail; “there is time to kill a fish yet before the squal", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3416, "position": 3416, "text": "sail; “there is time to kill a fish yet before the squall\ncomes. There’s white water again!—close to! Spring!”\n\nSoon after, two cries in quick succession on each side of us denoted\nthat the other boats", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3417, "position": 3417, "text": "two cries in quick succession on each side of us denoted\nthat the other boats had got fast; but hardly were they overheard, when\nwith a lightning-like hurtling whisper Starbuck said: “Stand up!” and\nQueequeg, harp", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3418, "position": 3418, "text": "buck said: “Stand up!” and\nQueequeg, harpoon in hand, sprang to his feet.\n\nThough not one of the oarsmen was then facing the life and death peril\nso close to them ahead, yet with their", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3419, "position": 3419, "text": "the life and death peril\nso close to them ahead, yet with their eyes on the intense countenance\nof the mate in the stern of the boat, they knew that the imminent\ninstant had come; they heard, too, an enormous wallowing", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 282}}, {"id": 3420, "position": 3420, "text": "the imminent\ninstant had come; they heard, too, an enormous wallowing sound as of\nfifty elephants stirring in their litter. Meanwhile the boat was still\nbooming through the mist, the waves curling and hissing around us like\nthe erected crests of enraged serpent", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 99, "2000": 1111}}, {"id": 3421, "position": 3421, "text": "the waves curling and hissing around us like\nthe erected crests of enraged serpents.\n\n“That’s his hump. _There_, _there_, give it to him!” whispered\nStarbuck.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3422, "position": 3422, "text": "to him!” whispered\nStarbuck.\n\nA short rushing sound leaped out of the boat; it was the darted iron of\nQueequeg. Then all in one welded commotion came an invisible push from\nastern, while forward the boat seemed striking on", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3423, "position": 3423, "text": "came an invisible push from\nastern, while forward the boat seemed striking on a ledge; the sail\ncollapsed and exploded; a gush of scalding vapor shot up near by;\nsomething rolled and tumbled like an earthquake beneath us", "labels": {"50": 25, "100": 5, "250": 26, "500": 233, "1000": 783, "2000": 377}}, {"id": 3424, "position": 3424, "text": "by;\nsomething rolled and tumbled like an earthquake beneath us. The whole\ncrew were half suffocated as they were tossed helter-skelter into the\nwhite curdling cream of the squall", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1192}}, {"id": 3425, "position": 3425, "text": "rdling cream of the squall. Squall, whale, and harpoon had all\nblended together; and the whale, merely grazed by the iron, escaped.\n\nThough completely swamped, the boat was nearly unharmed", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1620}}, {"id": 3426, "position": 3426, "text": "Though completely swamped, the boat was nearly unharmed. Swimming round\nit we picked up the floating oars, and lashing them across the gunwale,\ntumbled back to our places. There we sat up to our knees in the sea,\nthe", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1243}}, {"id": 3427, "position": 3427, "text": "our places. There we sat up to our knees in the sea,\nthe water covering every rib and plank, so that to our downward gazing\neyes the suspended craft seemed a coral boat grown up to us from the\nbottom of the ocean.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1243}}, {"id": 3428, "position": 3428, "text": "boat grown up to us from the\nbottom of the ocean.\n\nThe wind increased to a howl; the waves dashed their bucklers together;\nthe whole squall roared, forked, and crackled around us like a white\nfire upon the prairie,", "labels": {"50": 45, "100": 93, "250": 55, "500": 388, "1000": 313, "2000": 1243}}, {"id": 3429, "position": 3429, "text": "ed, and crackled around us like a white\nfire upon the prairie, in which, unconsumed, we were burning; immortal\nin these jaws of death! In vain we hailed the other boats; as well roar\nto the live coals", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 174, "2000": 1735}}, {"id": 3430, "position": 3430, "text": "vain we hailed the other boats; as well roar\nto the live coals down the chimney of a flaming furnace as hail those\nboats in that storm. Meanwhile the driving scud, rack, and mist, grew\ndarker with the shadows of night; no", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 779, "2000": 16}}, {"id": 3431, "position": 3431, "text": ", rack, and mist, grew\ndarker with the shadows of night; no sign of the ship could be seen.\nThe rising sea forbade all attempts to bale out the boat. The oars were\nuseless as propellers, performing now the office of life", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 282}}, {"id": 3432, "position": 3432, "text": ". The oars were\nuseless as propellers, performing now the office of life-preservers.\nSo, cutting the lashing of the waterproof match keg, after many\nfailures Starbuck contrived to ignite the lamp in the lantern;", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1668}}, {"id": 3433, "position": 3433, "text": "failures Starbuck contrived to ignite the lamp in the lantern; then\nstretching it on a waif pole, handed it to Queequeg as the\nstandard-bearer of this forlorn hope", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3434, "position": 3434, "text": "bearer of this forlorn hope. There, then, he sat, holding up\nthat imbecile candle in the heart of that almighty forlornness. There,\nthen, he sat, the sign and symbol of a man without faith", "labels": {"50": 28, "100": 44, "250": 140, "500": 27, "1000": 668, "2000": 792}}, {"id": 3435, "position": 3435, "text": ",\nthen, he sat, the sign and symbol of a man without faith, hopelessly\nholding up hope in the midst of despair.\n\nWet, drenched through, and shivering cold, despairing of ship or boat,\nwe lifted up our eyes as the", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 3436, "position": 3436, "text": ", despairing of ship or boat,\nwe lifted up our eyes as the dawn came on. The mist still spread over\nthe sea, the empty lantern lay crushed in the bottom of the boat.\nSuddenly Queequeg started to his feet, hollow", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 3437, "position": 3437, "text": "of the boat.\nSuddenly Queequeg started to his feet, hollowing his hand to his ear.\nWe all heard a faint creaking, as of ropes and yards hitherto muffled\nby the storm", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3438, "position": 3438, "text": "yards hitherto muffled\nby the storm. The sound came nearer and nearer; the thick mists were\ndimly parted by a huge, vague form. Affrighted, we all sprang into the\nsea as the ship at last loomed into view,", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3439, "position": 3439, "text": "we all sprang into the\nsea as the ship at last loomed into view, bearing right down upon us\nwithin a distance of not much more than its length.\n\nFloating on the waves we saw the abandoned boat, as for one instant it\ntossed and gaped beneath", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1243}}, {"id": 3440, "position": 3440, "text": "we saw the abandoned boat, as for one instant it\ntossed and gaped beneath the ship’s bows like a chip at the base of a\ncataract; and then the vast hull rolled over it, and it was seen no\nmore till it came", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3441, "position": 3441, "text": "vast hull rolled over it, and it was seen no\nmore till it came up weltering astern. Again we swam for it, were\ndashed against it by the seas, and were at last taken up and safely\nlanded on board", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3442, "position": 3442, "text": ", and were at last taken up and safely\nlanded on board. Ere the squall came close to, the other boats had cut\nloose from their fish and returned to the ship in good time. The ship\nhad given us up, but was", "labels": {"50": 40, "100": 93, "250": 125, "500": 384, "1000": 139, "2000": 801}}, {"id": 3443, "position": 3443, "text": "the ship in good time. The ship\nhad given us up, but was still cruising, if haply it might light upon\nsome token of our perishing,—an oar or a lance pole.\n\n\nCHAPTER 49. The Hyena.", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 3444, "position": 3444, "text": "ar or a lance pole.\n\n\nCHAPTER 49. The Hyena.\n\nThere are certain queer times and occasions in this strange mixed\naffair we call life when a man takes this whole universe for a vast\npractical joke, though the wit thereof he but dimly disc", "labels": {"50": 31, "100": 20, "250": 52, "500": 453, "1000": 15, "2000": 1394}}, {"id": 3445, "position": 3445, "text": "universe for a vast\npractical joke, though the wit thereof he but dimly discerns, and more\nthan suspects that the joke is at nobody’s expense but his own.\nHowever, nothing dispirits, and nothing seems worth while disp", "labels": {"50": 31, "100": 7, "250": 49, "500": 453, "1000": 165, "2000": 1956}}, {"id": 3446, "position": 3446, "text": "However, nothing dispirits, and nothing seems worth while disputing. He\nbolts down all events, all creeds, and beliefs, and persuasions, all\nhard things visible and invisible, never mind how knobby; as an os", "labels": {"50": 31, "100": 75, "250": 129, "500": 29, "1000": 165, "2000": 1956}}, {"id": 3447, "position": 3447, "text": "hard things visible and invisible, never mind how knobby; as an ostrich\nof potent digestion gobbles down bullets and gun flints. And as for\nsmall difficulties and worryings, prospects of sudden disaster, peril\nof life and", "labels": {"50": 23, "100": 88, "250": 57, "500": 229, "1000": 800, "2000": 1716}}, {"id": 3448, "position": 3448, "text": "difficulties and worryings, prospects of sudden disaster, peril\nof life and limb; all these, and death itself, seem to him only sly,\ngood-natured hits, and jolly punches in the side bestowed by the unseen\nand unaccount", "labels": {"50": 31, "100": 75, "250": 13, "500": 482, "1000": 15, "2000": 1417}}, {"id": 3449, "position": 3449, "text": ", and jolly punches in the side bestowed by the unseen\nand unaccountable old joker. That odd sort of wayward mood I am\nspeaking of, comes over a man only in some time of extreme tribulation;\nit comes in the very", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 858, "2000": 371}}, {"id": 3450, "position": 3450, "text": "only in some time of extreme tribulation;\nit comes in the very midst of his earnestness, so that what just before\nmight have seemed to him a thing most momentous, now seems but a part\nof the general joke", "labels": {"50": 10, "100": 16, "250": 13, "500": 236, "1000": 366, "2000": 1601}}, {"id": 3451, "position": 3451, "text": "ous, now seems but a part\nof the general joke. There is nothing like the perils of whaling to\nbreed this free and easy sort of genial, desperado philosophy; and with\nit I now regarded this whole voyage of the Pequ", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3452, "position": 3452, "text": "philosophy; and with\nit I now regarded this whole voyage of the Pequod, and the great White\nWhale its object.\n\n“Queequeg,” said I, when they had dragged me, the last man, to the\ndeck, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3453, "position": 3453, "text": "when they had dragged me, the last man, to the\ndeck, and I was still shaking myself in my jacket to fling off the\nwater; “Queequeg, my fine friend, does this sort of thing often\nhappen?” Without much", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 3454, "position": 3454, "text": "my fine friend, does this sort of thing often\nhappen?” Without much emotion, though soaked through just like me, he\ngave me to understand that such things did often happen.\n\n“Mr. Stubb,” said I, turning to that worthy", "labels": {"50": 25, "100": 41, "250": 219, "500": 407, "1000": 421, "2000": 1068}}, {"id": 3455, "position": 3455, "text": ".\n\n“Mr. Stubb,” said I, turning to that worthy, who, buttoned up in his\noil-jacket, was now calmly smoking his pipe in the rain; “Mr. Stubb, I\nthink I have heard you say", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 3456, "position": 3456, "text": "rain; “Mr. Stubb, I\nthink I have heard you say that of all whalemen you ever met, our chief\nmate, Mr. Starbuck, is by far the most careful and prudent", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3457, "position": 3457, "text": "far the most careful and prudent. I suppose\nthen, that going plump on a flying whale with your sail set in a foggy\nsquall is the height of a whaleman’s discretion?”\n\n“Certain", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3458, "position": 3458, "text": "a whaleman’s discretion?”\n\n“Certain. I’ve lowered for whales from a leaking ship in a gale off\nCape Horn.”\n\n“Mr. Flask,” said I, turning to little King-Post, who was standing\nclose", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3459, "position": 3459, "text": "” said I, turning to little King-Post, who was standing\nclose by; “you are experienced in these things, and I am not. Will you\ntell me whether it is an unalterable law in this fishery, Mr", "labels": {"50": 23, "100": 64, "250": 8, "500": 73, "1000": 943, "2000": 610}}, {"id": 3460, "position": 3460, "text": "it is an unalterable law in this fishery, Mr. Flask,\nfor an oarsman to break his own back pulling himself back-foremost into\ndeath’s jaws?”\n\n“Can’t you twist that smaller?” said Fl", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3461, "position": 3461, "text": "jaws?”\n\n“Can’t you twist that smaller?” said Flask. “Yes, that’s the law. I\nshould like to see a boat’s crew backing water up to a whale face\nforemost", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3462, "position": 3462, "text": "crew backing water up to a whale face\nforemost. Ha, ha! the whale would give them squint for squint, mind\nthat!”\n\nHere then, from three impartial witnesses, I had a deliberate statement\nof the entire case", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3463, "position": 3463, "text": "three impartial witnesses, I had a deliberate statement\nof the entire case. Considering, therefore, that squalls and capsizings\nin the water and consequent bivouacks on the deep, were matters of\ncommon occurrence in this", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3464, "position": 3464, "text": "bivouacks on the deep, were matters of\ncommon occurrence in this kind of life; considering that at the\nsuperlatively critical instant of going on to the whale I must resign\nmy life into the hands of him who steered the boat—often", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3465, "position": 3465, "text": "must resign\nmy life into the hands of him who steered the boat—oftentimes a fellow\nwho at that very moment is in his impetuousness upon the point of\nscuttling the craft with his own frantic stampings; considering that\nthe", "labels": {"50": 20, "100": 28, "250": 101, "500": 120, "1000": 818, "2000": 1671}}, {"id": 3466, "position": 3466, "text": "scuttling the craft with his own frantic stampings; considering that\nthe particular disaster to our own particular boat was chiefly to be\nimputed to Starbuck’s driving on to his whale almost in the teeth of a\nsquall, and considering", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3467, "position": 3467, "text": "to his whale almost in the teeth of a\nsquall, and considering that Starbuck, notwithstanding, was famous for\nhis great heedfulness in the fishery; considering that I belonged to\nthis uncommonly prudent Starbuck’s boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3468, "position": 3468, "text": "that I belonged to\nthis uncommonly prudent Starbuck’s boat; and finally considering in\nwhat a devil’s chase I was implicated, touching the White Whale: taking\nall things together, I say, I thought I might as well go", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3469, "position": 3469, "text": "taking\nall things together, I say, I thought I might as well go below and make\na rough draft of my will. “Queequeg,” said I, “come along, you shall be\nmy lawyer, executor,", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 381}}, {"id": 3470, "position": 3470, "text": "“come along, you shall be\nmy lawyer, executor, and legatee.”\n\nIt may seem strange that of all men sailors should be tinkering at\ntheir last wills and testaments, but there are no people in the", "labels": {"50": 36, "100": 72, "250": 8, "500": 214, "1000": 860, "2000": 617}}, {"id": 3471, "position": 3471, "text": "at\ntheir last wills and testaments, but there are no people in the world\nmore fond of that diversion. This was the fourth time in my nautical\nlife that I had done the same thing. After the ceremony was concluded\nupon the present occasion, I", "labels": {"50": 20, "100": 28, "250": 169, "500": 388, "1000": 794, "2000": 1495}}, {"id": 3472, "position": 3472, "text": "the same thing. After the ceremony was concluded\nupon the present occasion, I felt all the easier; a stone was rolled\naway from my heart. Besides, all the days I should now live would be as\ngood as the days that Lazarus lived after his", "labels": {"50": 20, "100": 79, "250": 204, "500": 315, "1000": 941, "2000": 1840}}, {"id": 3473, "position": 3473, "text": "should now live would be as\ngood as the days that Lazarus lived after his resurrection; a\nsupplementary clean gain of so many months or weeks as the case might\nbe. I survived myself; my death and burial were locked up in my chest", "labels": {"50": 25, "100": 5, "250": 125, "500": 388, "1000": 313, "2000": 1521}}, {"id": 3474, "position": 3474, "text": "myself; my death and burial were locked up in my chest.\nI looked round me tranquilly and contentedly, like a quiet ghost with a\nclean conscience sitting inside the bars of a snug family vault.", "labels": {"50": 20, "100": 5, "250": 45, "500": 411, "1000": 51, "2000": 1812}}, {"id": 3475, "position": 3475, "text": "bars of a snug family vault.\n\nNow then, thought I, unconsciously rolling up the sleeves of my frock,\nhere goes for a cool, collected dive at death and destruction, and the\ndevil fetch the hindmost.\n\n\nCHAPTER 50", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3476, "position": 3476, "text": "death and destruction, and the\ndevil fetch the hindmost.\n\n\nCHAPTER 50. Ahab’s Boat and Crew. Fedallah.\n\n“Who would have thought it, Flask!” cried Stubb; “if I had but one leg\nyou", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3477, "position": 3477, "text": "ask!” cried Stubb; “if I had but one leg\nyou would not catch me in a boat, unless maybe to stop the plug-hole\nwith my timber toe. Oh! he’s a wonderful old man!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3478, "position": 3478, "text": ". Oh! he’s a wonderful old man!”\n\n“I don’t think it so strange, after all, on that account,” said Flask.\n“If his leg were off at the hip, now, it would be a", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3479, "position": 3479, "text": "If his leg were off at the hip, now, it would be a different thing.\nThat would disable him; but he has one knee, and good part of the other\nleft, you know.”", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 877}}, {"id": 3480, "position": 3480, "text": "other\nleft, you know.”\n\n“I don’t know that, my little man; I never yet saw him kneel.”\n\nAmong whale-wise people it has often been argued whether, considering\nthe paramount importance of his life to the success", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3481, "position": 3481, "text": "often been argued whether, considering\nthe paramount importance of his life to the success of the voyage, it\nis right for a whaling captain to jeopardize that life in the active\nperils of the chase", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3482, "position": 3482, "text": "active\nperils of the chase. So Tamerlane’s soldiers often argued with tears in\ntheir eyes, whether that invaluable life of his ought to be carried\ninto the thickest of the fight.", "labels": {"50": 26, "100": 67, "250": 246, "500": 87, "1000": 76, "2000": 450}}, {"id": 3483, "position": 3483, "text": "into the thickest of the fight.\n\nBut with Ahab the question assumed a modified aspect. Considering that\nwith two legs man is but a hobbling wight in all times of danger;\nconsidering that the pursuit of whales is always under great and\nextraordinary difficulties", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3484, "position": 3484, "text": "danger;\nconsidering that the pursuit of whales is always under great and\nextraordinary difficulties; that every individual moment, indeed, then\ncomprises a peril; under these circumstances is it wise for any maimed\nman to enter a whale-boat in the hunt?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3485, "position": 3485, "text": "for any maimed\nman to enter a whale-boat in the hunt? As a general thing, the\njoint-owners of the Pequod must have plainly thought not.\n\nAhab well knew that although his friends at home would think little of\nhis", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3486, "position": 3486, "text": "Ahab well knew that although his friends at home would think little of\nhis entering a boat in certain comparatively harmless vicissitudes of\nthe chase, for the sake of being near the scene of action and giving\nhis orders in person, yet for Captain", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3487, "position": 3487, "text": "near the scene of action and giving\nhis orders in person, yet for Captain Ahab to have a boat actually\napportioned to him as a regular headsman in the hunt—above all for\nCaptain Ahab to be supplied with five extra men,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3488, "position": 3488, "text": "—above all for\nCaptain Ahab to be supplied with five extra men, as that same boat’s\ncrew, he well knew that such generous conceits never entered the heads\nof the owners of the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3489, "position": 3489, "text": "heads\nof the owners of the Pequod. Therefore he had not solicited a boat’s\ncrew from them, nor had he in any way hinted his desires on that head.\nNevertheless he had taken private measures of his own touching all that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3490, "position": 3490, "text": "that head.\nNevertheless he had taken private measures of his own touching all that\nmatter. Until Cabaco’s published discovery, the sailors had little\nforeseen it, though to be sure when, after being a little while out of\nport, all", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3491, "position": 3491, "text": "to be sure when, after being a little while out of\nport, all hands had concluded the customary business of fitting the\nwhaleboats for service; when some time after this Ahab was now and then\nfound bestirring himself in the matter of making", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3492, "position": 3492, "text": "ab was now and then\nfound bestirring himself in the matter of making thole-pins with his\nown hands for what was thought to be one of the spare boats, and even\nsolicitously cutting the small wooden skewers,", "labels": {"50": 45, "100": 64, "250": 170, "500": 60, "1000": 946, "2000": 203}}, {"id": 3493, "position": 3493, "text": "and even\nsolicitously cutting the small wooden skewers, which when the line is\nrunning out are pinned over the groove in the bow: when all this was\nobserved in him, and particularly his solicitude in having an extra", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3494, "position": 3494, "text": "observed in him, and particularly his solicitude in having an extra\ncoat of sheathing in the bottom of the boat, as if to make it better\nwithstand the pointed pressure of his ivory limb; and also the anxiety\nhe evinced in", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 1620}}, {"id": 3495, "position": 3495, "text": "pressure of his ivory limb; and also the anxiety\nhe evinced in exactly shaping the thigh board, or clumsy cleat, as it\nis sometimes called, the horizontal piece in the boat’s bow for bracing\nthe knee against in darting or", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 3496, "position": 3496, "text": "piece in the boat’s bow for bracing\nthe knee against in darting or stabbing at the whale; when it was\nobserved how often he stood up in that boat with his solitary knee\nfixed in the semi-circular depression in the cleat, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3497, "position": 3497, "text": "knee\nfixed in the semi-circular depression in the cleat, and with the\ncarpenter’s chisel gouged out a little here and straightened it a\nlittle there; all these things, I say, had awakened much interest and\ncuriosity at", "labels": {"50": 48, "100": 27, "250": 90, "500": 412, "1000": 619, "2000": 1149}}, {"id": 3498, "position": 3498, "text": "; all these things, I say, had awakened much interest and\ncuriosity at the time. But almost everybody supposed that this\nparticular preparative heedfulness in Ahab must only be with a view to\nthe ultimate chase of Moby Dick;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3499, "position": 3499, "text": "must only be with a view to\nthe ultimate chase of Moby Dick; for he had already revealed his\nintention to hunt that mortal monster in person. But such a supposition\ndid by no means involve the remotest suspicion as to any boat’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3500, "position": 3500, "text": "osition\ndid by no means involve the remotest suspicion as to any boat’s crew\nbeing assigned to that boat.\n\nNow, with the subordinate phantoms, what wonder remained soon waned\naway; for in a whaler wonders soon wane", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3501, "position": 3501, "text": "waned\naway; for in a whaler wonders soon wane. Besides, now and then such\nunaccountable odds and ends of strange nations come up from the unknown\nnooks and ash-holes of the earth to man these floating outlaws", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3502, "position": 3502, "text": "nooks and ash-holes of the earth to man these floating outlaws of\nwhalers; and the ships themselves often pick up such queer castaway\ncreatures found tossing about the open sea on planks, bits of wreck,\noars, whaleboats", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3503, "position": 3503, "text": "open sea on planks, bits of wreck,\noars, whaleboats, canoes, blown-off Japanese junks, and what not; that\nBeelzebub himself might climb up the side and step down into the cabin\nto chat with", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3504, "position": 3504, "text": "himself might climb up the side and step down into the cabin\nto chat with the captain, and it would not create any unsubduable\nexcitement in the forecastle.\n\nBut be all this as it may, certain it is that while the subordinate", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 642, "2000": 558}}, {"id": 3505, "position": 3505, "text": "But be all this as it may, certain it is that while the subordinate\nphantoms soon found their place among the crew, though still as it were\nsomehow distinct from them, yet that hair-turbaned Fedallah remained a\nmuffled mystery to", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 642, "2000": 399}}, {"id": 3506, "position": 3506, "text": "yet that hair-turbaned Fedallah remained a\nmuffled mystery to the last. Whence he came in a mannerly world like\nthis, by what sort of unaccountable tie he soon evinced himself to be\nlinked with Ah", "labels": {"50": 32, "100": 0, "250": 233, "500": 142, "1000": 716, "2000": 397}}, {"id": 3507, "position": 3507, "text": "ccountable tie he soon evinced himself to be\nlinked with Ahab’s peculiar fortunes; nay, so far as to have some sort\nof a half-hinted influence; Heaven knows, but it might have been even\nauthority over him;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3508, "position": 3508, "text": "influence; Heaven knows, but it might have been even\nauthority over him; all this none knew. But one cannot sustain an\nindifferent air concerning Fedallah. He was such a creature as\ncivilized, domestic people in the temperate zone only see in their", "labels": {"50": 32, "100": 96, "250": 70, "500": 481, "1000": 477, "2000": 1102}}, {"id": 3509, "position": 3509, "text": "a creature as\ncivilized, domestic people in the temperate zone only see in their\ndreams, and that but dimly; but the like of whom now and then glide\namong the unchanging Asiatic communities, especially the Oriental isles\nto the east of the continent—", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 505, "2000": 612}}, {"id": 3510, "position": 3510, "text": "ing Asiatic communities, especially the Oriental isles\nto the east of the continent—those insulated, immemorial, unalterable\ncountries, which even in these modern days still preserve much of the\nghostly aboriginalness of earth’s primal generations,", "labels": {"50": 16, "100": 81, "250": 211, "500": 414, "1000": 548, "2000": 1555}}, {"id": 3511, "position": 3511, "text": "still preserve much of the\nghostly aboriginalness of earth’s primal generations, when the memory\nof the first man was a distinct recollection, and all men his\ndescendants, unknowing whence he came, eyed each other as real\nphantom", "labels": {"50": 10, "100": 66, "250": 211, "500": 490, "1000": 655, "2000": 1533}}, {"id": 3512, "position": 3512, "text": "unknowing whence he came, eyed each other as real\nphantoms, and asked of the sun and the moon why they were created and\nto what end; when though, according to Genesis, the angels indeed\nconsorted with the daughters of", "labels": {"50": 35, "100": 94, "250": 112, "500": 289, "1000": 654, "2000": 1622}}, {"id": 3513, "position": 3513, "text": "though, according to Genesis, the angels indeed\nconsorted with the daughters of men, the devils also, add the\nuncanonical Rabbins, indulged in mundane amours.\n\n\nCHAPTER 51. The Spirit-Spout.", "labels": {"50": 27, "100": 66, "250": 167, "500": 495, "1000": 553, "2000": 416}}, {"id": 3514, "position": 3514, "text": "s.\n\n\nCHAPTER 51. The Spirit-Spout.\n\nDays, weeks passed, and under easy sail, the ivory Pequod had slowly\nswept across four several cruising-grounds; that off the Azores; off\nthe Cape de Verdes; on the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3515, "position": 3515, "text": "; that off the Azores; off\nthe Cape de Verdes; on the Plate (so called), being off the mouth of\nthe Rio de la Plata; and the Carrol Ground, an unstaked, watery\nlocality, southerly from St", "labels": {"50": 3, "100": 70, "250": 234, "500": 102, "1000": 875, "2000": 1872}}, {"id": 3516, "position": 3516, "text": "ol Ground, an unstaked, watery\nlocality, southerly from St. Helena.\n\nIt was while gliding through these latter waters that one serene and\nmoonlight night, when all the waves rolled by like scrolls of silver;\nand, by their soft,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 9, "2000": 576}}, {"id": 3517, "position": 3517, "text": "the waves rolled by like scrolls of silver;\nand, by their soft, suffusing seethings, made what seemed a silvery\nsilence, not a solitude; on such a silent night a silvery jet was seen\nfar in advance of the white bubbles", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 9, "2000": 472}}, {"id": 3518, "position": 3518, "text": "a silent night a silvery jet was seen\nfar in advance of the white bubbles at the bow. Lit up by the moon, it\nlooked celestial; seemed some plumed and glittering god uprising from\nthe sea. Fedallah first descried this jet", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 783, "2000": 1904}}, {"id": 3519, "position": 3519, "text": "god uprising from\nthe sea. Fedallah first descried this jet. For of these moonlight\nnights, it was his wont to mount to the main-mast head, and stand a\nlook-out there, with the same precision as if", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3520, "position": 3520, "text": ", and stand a\nlook-out there, with the same precision as if it had been day. And yet,\nthough herds of whales were seen by night, not one whaleman in a\nhundred would venture a lowering for them", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3521, "position": 3521, "text": "man in a\nhundred would venture a lowering for them. You may think with what\nemotions, then, the seamen beheld this old Oriental perched aloft at\nsuch unusual hours; his turban and the moon, companions in one sky", "labels": {"50": 32, "100": 0, "250": 233, "500": 142, "1000": 806, "2000": 1465}}, {"id": 3522, "position": 3522, "text": "his turban and the moon, companions in one sky. But\nwhen, after spending his uniform interval there for several successive\nnights without uttering a single sound; when, after all this silence,\nhis unearthly voice was heard announcing that silvery", "labels": {"50": 32, "100": 81, "250": 3, "500": 366, "1000": 236, "2000": 1976}}, {"id": 3523, "position": 3523, "text": "after all this silence,\nhis unearthly voice was heard announcing that silvery, moon-lit jet,\nevery reclining mariner started to his feet as if some winged spirit\nhad lighted in the rigging, and hailed the mortal crew", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3524, "position": 3524, "text": "had lighted in the rigging, and hailed the mortal crew. “There she\nblows!” Had the trump of judgment blown, they could not have quivered\nmore; yet still they felt no terror; rather pleasure", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 3525, "position": 3525, "text": "still they felt no terror; rather pleasure. For though it was\na most unwonted hour, yet so impressive was the cry, and so deliriously\nexciting, that almost every soul on board instinctively desired a\nlowering.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 3526, "position": 3526, "text": "almost every soul on board instinctively desired a\nlowering.\n\nWalking the deck with quick, side-lunging strides, Ahab commanded the\nt’gallant sails and royals to be set, and every stunsail spread", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3527, "position": 3527, "text": ", and every stunsail spread. The\nbest man in the ship must take the helm. Then, with every mast-head\nmanned, the piled-up craft rolled down before the wind. The strange,\nupheaving, lifting tendency of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 3528, "position": 3528, "text": "before the wind. The strange,\nupheaving, lifting tendency of the taffrail breeze filling the hollows\nof so many sails, made the buoyant, hovering deck to feel like air\nbeneath the feet; while still she rushed along,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 3529, "position": 3529, "text": "deck to feel like air\nbeneath the feet; while still she rushed along, as if two antagonistic\ninfluences were struggling in her—one to mount direct to heaven, the\nother to drive yawingly to some horizontal goal", "labels": {"50": 45, "100": 64, "250": 48, "500": 28, "1000": 99, "2000": 844}}, {"id": 3530, "position": 3530, "text": "to drive yawingly to some horizontal goal. And had you watched\nAhab’s face that night, you would have thought that in him also two\ndifferent things were warring. While his one live leg made lively\nechoes along the deck, every stroke", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3531, "position": 3531, "text": ". While his one live leg made lively\nechoes along the deck, every stroke of his dead limb sounded like a\ncoffin-tap. On life and death this old man walked. But though the ship\nso swiftly sped, and though from every eye, like", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3532, "position": 3532, "text": "But though the ship\nso swiftly sped, and though from every eye, like arrows, the eager\nglances shot, yet the silvery jet was no more seen that night. Every\nsailor swore he saw it once, but not a second time.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 3533, "position": 3533, "text": "swore he saw it once, but not a second time.\n\nThis midnight-spout had almost grown a forgotten thing, when, some days\nafter, lo! at the same silent hour, it was again announced: again it\nwas descried by", "labels": {"50": 22, "100": 60, "250": 217, "500": 252, "1000": 712, "2000": 813}}, {"id": 3534, "position": 3534, "text": "silent hour, it was again announced: again it\nwas descried by all; but upon making sail to overtake it, once more it\ndisappeared as if it had never been. And so it served us night after\nnight, till no one hee", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 3535, "position": 3535, "text": "been. And so it served us night after\nnight, till no one heeded it but to wonder at it. Mysteriously jetted\ninto the clear moonlight, or starlight, as the case might be;\ndisappearing again for one whole day, or two", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 448}}, {"id": 3536, "position": 3536, "text": "as the case might be;\ndisappearing again for one whole day, or two days, or three; and\nsomehow seeming at every distinct repetition to be advancing still\nfurther and further in our van, this solitary jet seemed for ever\nalluring us on.", "labels": {"50": 45, "100": 64, "250": 55, "500": 388, "1000": 313, "2000": 887}}, {"id": 3537, "position": 3537, "text": "our van, this solitary jet seemed for ever\nalluring us on.\n\nNor with the immemorial superstition of their race, and in accordance\nwith the preternaturalness, as it seemed, which in many things invested\nthe Pe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3538, "position": 3538, "text": "aturalness, as it seemed, which in many things invested\nthe Pequod, were there wanting some of the seamen who swore that\nwhenever and wherever descried; at however remote times, or in however\nfar apart latitudes and longitudes", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3539, "position": 3539, "text": "at however remote times, or in however\nfar apart latitudes and longitudes, that unnearable spout was cast by\none self-same whale; and that whale, Moby Dick. For a time, there\nreigned, too, a sense", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3540, "position": 3540, "text": "Moby Dick. For a time, there\nreigned, too, a sense of peculiar dread at this flitting apparition, as\nif it were treacherously beckoning us on and on, in order that the\nmonster might turn round upon us", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3541, "position": 3541, "text": "us on and on, in order that the\nmonster might turn round upon us, and rend us at last in the remotest\nand most savage seas.\n\nThese temporary apprehensions, so vague but so awful, derived a\nwondrous potency from", "labels": {"50": 25, "100": 5, "250": 156, "500": 388, "1000": 313, "2000": 1495}}, {"id": 3542, "position": 3542, "text": ", so vague but so awful, derived a\nwondrous potency from the contrasting serenity of the weather, in\nwhich, beneath all its blue blandness, some thought there lurked a\ndevilish charm, as for days and days we voyage", "labels": {"50": 25, "100": 5, "250": 26, "500": 388, "1000": 313, "2000": 1521}}, {"id": 3543, "position": 3543, "text": "there lurked a\ndevilish charm, as for days and days we voyaged along, through seas so\nwearily, lonesomely mild, that all space, in repugnance to our vengeful\nerrand, seemed vacating itself", "labels": {"50": 16, "100": 73, "250": 138, "500": 162, "1000": 313, "2000": 16}}, {"id": 3544, "position": 3544, "text": "ugnance to our vengeful\nerrand, seemed vacating itself of life before our urn-like prow.\n\nBut, at last, when turning to the eastward, the Cape winds began\nhowling around us, and we rose and fell", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3545, "position": 3545, "text": "eastward, the Cape winds began\nhowling around us, and we rose and fell upon the long, troubled seas\nthat are there; when the ivory-tusked Pequod sharply bowed to the\nblast, and gored the dark waves in her madness", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 16}}, {"id": 3546, "position": 3546, "text": "sharply bowed to the\nblast, and gored the dark waves in her madness, till, like showers of\nsilver chips, the foam-flakes flew over her bulwarks; then all this\ndesolate vacuity of life went away,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 3547, "position": 3547, "text": "s; then all this\ndesolate vacuity of life went away, but gave place to sights more\ndismal than before.\n\nClose to our bows, strange forms in the water darted hither and thither\nbefore us; while thick in", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 437, "2000": 1208}}, {"id": 3548, "position": 3548, "text": "the water darted hither and thither\nbefore us; while thick in our rear flew the inscrutable sea-ravens. And\nevery morning, perched on our stays, rows of these birds were seen; and\nspite of our hootings,", "labels": {"50": 45, "100": 43, "250": 55, "500": 162, "1000": 9, "2000": 1735}}, {"id": 3549, "position": 3549, "text": "rows of these birds were seen; and\nspite of our hootings, for a long time obstinately clung to the hemp,\nas though they deemed our ship some drifting, uninhabited craft; a\nthing appointed to desolation, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 3550, "position": 3550, "text": "some drifting, uninhabited craft; a\nthing appointed to desolation, and therefore fit roosting-place for\ntheir homeless selves. And heaved and heaved, still unrestingly heaved\nthe black sea, as if its vast tides were a conscience;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3551, "position": 3551, "text": "ingly heaved\nthe black sea, as if its vast tides were a conscience; and the great\nmundane soul were in anguish and remorse for the long sin and suffering\nit had bred.\n\nCape of Good Hope, do they call ye? Rather Cape Tormentoso,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3552, "position": 3552, "text": "Cape of Good Hope, do they call ye? Rather Cape Tormentoso, as called\nof yore; for long allured by the perfidious silences that before had\nattended us, we found ourselves launched into this tormented sea, where\nguilty", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3553, "position": 3553, "text": "had\nattended us, we found ourselves launched into this tormented sea, where\nguilty beings transformed into those fowls and these fish, seemed\ncondemned to swim on everlastingly without any haven in store, or beat\nthat black air without any horizon", "labels": {"50": 25, "100": 93, "250": 30, "500": 475, "1000": 902, "2000": 1784}}, {"id": 3554, "position": 3554, "text": "without any haven in store, or beat\nthat black air without any horizon. But calm, snow-white, and\nunvarying; still directing its fountain of feathers to the sky; still\nbeckoning us on from before, the solitary jet would at", "labels": {"50": 48, "100": 20, "250": 192, "500": 334, "1000": 275, "2000": 1710}}, {"id": 3555, "position": 3555, "text": "sky; still\nbeckoning us on from before, the solitary jet would at times be\ndescried.\n\nDuring all this blackness of the elements, Ahab, though assuming for\nthe time the almost continual command of the drenched and dangerous\ndeck, manifested the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3556, "position": 3556, "text": "the time the almost continual command of the drenched and dangerous\ndeck, manifested the gloomiest reserve; and more seldom than ever\naddressed his mates. In tempestuous times like these, after everything\nabove and aloft has been secured, nothing more can be done", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 3557, "position": 3557, "text": "after everything\nabove and aloft has been secured, nothing more can be done but\npassively to await the issue of the gale. Then Captain and crew become\npractical fatalists. So, with his ivory leg inserted into its\naccustomed hole, and with one", "labels": {"50": 3, "100": 24, "250": 213, "500": 255, "1000": 546, "2000": 831}}, {"id": 3558, "position": 3558, "text": "So, with his ivory leg inserted into its\naccustomed hole, and with one hand firmly grasping a shroud, Ahab for\nhours and hours would stand gazing dead to windward, while an\noccasional squall of sleet or snow would all but", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3559, "position": 3559, "text": ", while an\noccasional squall of sleet or snow would all but congeal his very\neyelashes together. Meantime, the crew driven from the forward part of\nthe ship by the perilous seas that burstingly broke over its bows,\nstood in", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 3560, "position": 3560, "text": "the perilous seas that burstingly broke over its bows,\nstood in a line along the bulwarks in the waist; and the better to\nguard against the leaping waves, each man had slipped himself into a\nsort of bowline secured to", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 3561, "position": 3561, "text": "waves, each man had slipped himself into a\nsort of bowline secured to the rail, in which he swung as in a loosened\nbelt. Few or no words were spoken; and the silent ship, as if manned by\npainted sailors in wax, day", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 3562, "position": 3562, "text": "and the silent ship, as if manned by\npainted sailors in wax, day after day tore on through all the swift\nmadness and gladness of the demoniac waves. By night the same muteness\nof humanity before the shrieks of the ocean prevailed;", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 3563, "position": 3563, "text": "the same muteness\nof humanity before the shrieks of the ocean prevailed; still in silence\nthe men swung in the bowlines; still wordless Ahab stood up to the\nblast. Even when wearied nature seemed demanding repose he would not\nseek", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3564, "position": 3564, "text": "blast. Even when wearied nature seemed demanding repose he would not\nseek that repose in his hammock. Never could Starbuck forget the old\nman’s aspect, when one night going down into the cabin to mark how the\nbarometer", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3565, "position": 3565, "text": ", when one night going down into the cabin to mark how the\nbarometer stood, he saw him with closed eyes sitting straight in his\nfloor-screwed chair; the rain and half-melted sleet of the storm from\nwhich he had some time before", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1904}}, {"id": 3566, "position": 3566, "text": "half-melted sleet of the storm from\nwhich he had some time before emerged, still slowly dripping from the\nunremoved hat and coat. On the table beside him lay unrolled one of\nthose charts of tides and currents which have previously", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 324}}, {"id": 3567, "position": 3567, "text": "lay unrolled one of\nthose charts of tides and currents which have previously been spoken\nof. His lantern swung from his tightly clenched hand. Though the body\nwas erect, the head was thrown back so that the closed eyes were\npointed towards the needle of", "labels": {"50": 22, "100": 64, "250": 19, "500": 28, "1000": 808, "2000": 1904}}, {"id": 3568, "position": 3568, "text": "head was thrown back so that the closed eyes were\npointed towards the needle of the tell-tale that swung from a beam in\nthe ceiling.*\n\n*The cabin-compass is called the tell-tale, because without going to\nthe compass at the helm", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 1192}}, {"id": 3569, "position": 3569, "text": "called the tell-tale, because without going to\nthe compass at the helm, the Captain, while below, can inform himself\nof the course of the ship.\n\nTerrible old man! thought Starbuck with a shudder, sleeping in this\ngale, still thou", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3570, "position": 3570, "text": "! thought Starbuck with a shudder, sleeping in this\ngale, still thou steadfastly eyest thy purpose.\n\n\nCHAPTER 52. The Albatross.\n\nSouth-eastward from the Cape, off the distant Crozetts, a good cruising", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3571, "position": 3571, "text": "from the Cape, off the distant Crozetts, a good cruising\nground for Right Whalemen, a sail loomed ahead, the Goney (Albatross)\nby name. As she slowly drew nigh, from my lofty perch at", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3572, "position": 3572, "text": "name. As she slowly drew nigh, from my lofty perch at the\nfore-mast-head, I had a good view of that sight so remarkable to a tyro\nin the far ocean fisheries—a whaler at sea, and long", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3573, "position": 3573, "text": "ro\nin the far ocean fisheries—a whaler at sea, and long absent from home.\n\nAs if the waves had been fullers, this craft was bleached like the\nskeleton of a stranded walrus", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3574, "position": 3574, "text": "the\nskeleton of a stranded walrus. All down her sides, this spectral\nappearance was traced with long channels of reddened rust, while all\nher spars and her rigging were like the thick branches of trees furred\nover with hoar-frost", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 1620}}, {"id": 3575, "position": 3575, "text": "were like the thick branches of trees furred\nover with hoar-frost. Only her lower sails were set. A wild sight it\nwas to see her long-bearded look-outs at those three mast-heads", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 3576, "position": 3576, "text": "-outs at those three mast-heads. They\nseemed clad in the skins of beasts, so torn and bepatched the raiment\nthat had survived nearly four years of cruising. Standing in iron hoops\nnailed to the mast, they swayed and swung", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1192}}, {"id": 3577, "position": 3577, "text": ". Standing in iron hoops\nnailed to the mast, they swayed and swung over a fathomless sea; and\nthough, when the ship slowly glided close under our stern, we six men\nin the air came so nigh to each other that we", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 3578, "position": 3578, "text": "we six men\nin the air came so nigh to each other that we might almost have leaped\nfrom the mast-heads of one ship to those of the other; yet, those\nforlorn-looking fishermen, mildly eyeing us as they passed,", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3579, "position": 3579, "text": "those\nforlorn-looking fishermen, mildly eyeing us as they passed, said not\none word to our own look-outs, while the quarter-deck hail was being\nheard from below.\n\n“Ship ahoy! Have ye seen the White Whale?", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3580, "position": 3580, "text": "from below.\n\n“Ship ahoy! Have ye seen the White Whale?”\n\nBut as the strange captain, leaning over the pallid bulwarks, was in\nthe act of putting his trumpet to his mouth, it somehow fell from his\nhand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3581, "position": 3581, "text": "act of putting his trumpet to his mouth, it somehow fell from his\nhand into the sea; and the wind now rising amain, he in vain strove to\nmake himself heard without it. Meantime his ship was still increasing\nthe distance between", "labels": {"50": 1, "100": 80, "250": 39, "500": 497, "1000": 300, "2000": 687}}, {"id": 3582, "position": 3582, "text": "heard without it. Meantime his ship was still increasing\nthe distance between. While in various silent ways the seamen of the\nPequod were evincing their observance of this ominous incident at the\nfirst mere mention of the White Whale’s name", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3583, "position": 3583, "text": "this ominous incident at the\nfirst mere mention of the White Whale’s name to another ship, Ahab for\na moment paused; it almost seemed as though he would have lowered a\nboat to board the stranger, had not the threatening wind forbade", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3584, "position": 3584, "text": "a\nboat to board the stranger, had not the threatening wind forbade. But\ntaking advantage of his windward position, he again seized his trumpet,\nand knowing by her aspect that the stranger vessel was a Nantucketer\nand shortly bound home, he loudly", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 300, "2000": 489}}, {"id": 3585, "position": 3585, "text": "the stranger vessel was a Nantucketer\nand shortly bound home, he loudly hailed—“Ahoy there! This is the\nPequod, bound round the world! Tell them to address all future letters\nto the Pacific ocean! and this time three", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3586, "position": 3586, "text": "them to address all future letters\nto the Pacific ocean! and this time three years, if I am not at home,\ntell them to address them to ——”\n\nAt that moment the two wakes were fairly crossed, and instantly, then,\nin accordance", "labels": {"50": 20, "100": 28, "250": 169, "500": 59, "1000": 417, "2000": 53}}, {"id": 3587, "position": 3587, "text": "moment the two wakes were fairly crossed, and instantly, then,\nin accordance with their singular ways, shoals of small harmless fish,\nthat for some days before had been placidly swimming by our side,\ndarted away with what seemed shuddering fins", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1028}}, {"id": 3588, "position": 3588, "text": "acidly swimming by our side,\ndarted away with what seemed shuddering fins, and ranged themselves\nfore and aft with the stranger’s flanks. Though in the course of his\ncontinual voyagings Ahab must often before have noticed a similar\nsight", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3589, "position": 3589, "text": "continual voyagings Ahab must often before have noticed a similar\nsight, yet, to any monomaniac man, the veriest trifles capriciously\ncarry meanings.\n\n“Swim away from me, do ye?” murmured Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3590, "position": 3590, "text": "meanings.\n\n“Swim away from me, do ye?” murmured Ahab, gazing over into the water.\nThere seemed but little in the words, but the tone conveyed more of\ndeep helpless sadness than the insane old man had ever before evinced", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3591, "position": 3591, "text": "of\ndeep helpless sadness than the insane old man had ever before evinced.\nBut turning to the steersman, who thus far had been holding the ship in\nthe wind to diminish her headway, he cried out in his old lion\nvoice", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 967}}, {"id": 3592, "position": 3592, "text": "diminish her headway, he cried out in his old lion\nvoice,—“Up helm! Keep her off round the world!”\n\nRound the world! There is much in that sound to inspire proud feelings;\nbut whereto does all that", "labels": {"50": 31, "100": 16, "250": 87, "500": 71, "1000": 258, "2000": 1394}}, {"id": 3593, "position": 3593, "text": "much in that sound to inspire proud feelings;\nbut whereto does all that circumnavigation conduct? Only through\nnumberless perils to the very point whence we started, where those that\nwe left behind secure, were all the time", "labels": {"50": 9, "100": 75, "250": 106, "500": 307, "1000": 343, "2000": 761}}, {"id": 3594, "position": 3594, "text": "we started, where those that\nwe left behind secure, were all the time before us.\n\nWere this world an endless plain, and by sailing eastward we could for\never reach new distances, and discover sights more sweet and strange\nthan any Cyclades or", "labels": {"50": 45, "100": 29, "250": 161, "500": 384, "1000": 139, "2000": 1784}}, {"id": 3595, "position": 3595, "text": "distances, and discover sights more sweet and strange\nthan any Cyclades or Islands of King Solomon, then there were promise\nin the voyage. But in pursuit of those far mysteries we dream of, or in\ntormented chase of that demon phantom that, some", "labels": {"50": 16, "100": 73, "250": 26, "500": 406, "1000": 730, "2000": 16}}, {"id": 3596, "position": 3596, "text": "we dream of, or in\ntormented chase of that demon phantom that, some time or other, swims\nbefore all human hearts; while chasing such over this round globe, they\neither lead us on in barren mazes or midway leave us whelmed", "labels": {"50": 16, "100": 20, "250": 132, "500": 126, "1000": 727, "2000": 1107}}, {"id": 3597, "position": 3597, "text": "either lead us on in barren mazes or midway leave us whelmed.\n\n\nCHAPTER 53. The Gam.\n\nThe ostensible reason why Ahab did not go on board of the whaler we had\nspoken was this: the wind and sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3598, "position": 3598, "text": "board of the whaler we had\nspoken was this: the wind and sea betokened storms. But even had this\nnot been the case, he would not after all, perhaps, have boarded\nher—judging by his subsequent conduct on similar occasions—", "labels": {"50": 45, "100": 29, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 3599, "position": 3599, "text": "perhaps, have boarded\nher—judging by his subsequent conduct on similar occasions—if so it had\nbeen that, by the process of hailing, he had obtained a negative answer\nto the question he put. For, as it eventually turned out, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 877}}, {"id": 3600, "position": 3600, "text": "to the question he put. For, as it eventually turned out, he cared not\nto consort, even for five minutes, with any stranger captain, except he\ncould contribute some of that information he so absorbingly sought", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 3601, "position": 3601, "text": "of that information he so absorbingly sought. But\nall this might remain inadequately estimated, were not something said\nhere of the peculiar usages of whaling-vessels when meeting each other\nin foreign seas, and especially on a common cruising-ground.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3602, "position": 3602, "text": "other\nin foreign seas, and especially on a common cruising-ground.\n\nIf two strangers crossing the Pine Barrens in New York State, or the\nequally desolate Salisbury Plain in England; if casually encountering\neach other in such inhospitable wild", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 387, "2000": 898}}, {"id": 3603, "position": 3603, "text": "England; if casually encountering\neach other in such inhospitable wilds, these twain, for the life of\nthem, cannot well avoid a mutual salutation; and stopping for a moment\nto interchange the news; and, perhaps, sitting down", "labels": {"50": 23, "100": 60, "250": 217, "500": 202, "1000": 858, "2000": 371}}, {"id": 3604, "position": 3604, "text": "stopping for a moment\nto interchange the news; and, perhaps, sitting down for a while and\nresting in concert: then, how much more natural that upon the\nillimitable Pine Barrens and Salisbury Plains of the sea, two whaling\nvessels descr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3605, "position": 3605, "text": "Pine Barrens and Salisbury Plains of the sea, two whaling\nvessels descrying each other at the ends of the earth—off lone\nFanning’s Island, or the far away King’s Mills; how much more natural,\nI say,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3606, "position": 3606, "text": "far away King’s Mills; how much more natural,\nI say, that under such circumstances these ships should not only\ninterchange hails, but come into still closer, more friendly and\nsociable contact. And especially would this seem to be a matter", "labels": {"50": 31, "100": 7, "250": 69, "500": 73, "1000": 925, "2000": 877}}, {"id": 3607, "position": 3607, "text": "friendly and\nsociable contact. And especially would this seem to be a matter of\ncourse, in the case of vessels owned in one seaport, and whose\ncaptains, officers, and not a few of the men are personally known to\neach other; and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 887}}, {"id": 3608, "position": 3608, "text": "and not a few of the men are personally known to\neach other; and consequently, have all sorts of dear domestic things to\ntalk about.\n\nFor the long absent ship, the outward-bounder, perhaps, has letters on\nboard; at any rate", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 3609, "position": 3609, "text": "outward-bounder, perhaps, has letters on\nboard; at any rate, she will be sure to let her have some papers of a\ndate a year or two later than the last one on her blurred and\nthumb-worn files", "labels": {"50": 7, "100": 20, "250": 49, "500": 78, "1000": 90, "2000": 862}}, {"id": 3610, "position": 3610, "text": "the last one on her blurred and\nthumb-worn files. And in return for that courtesy, the outward-bound\nship would receive the latest whaling intelligence from the\ncruising-ground to which she may be destined, a thing of the utmost\nimportance to her", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 300, "2000": 1793}}, {"id": 3611, "position": 3611, "text": "to which she may be destined, a thing of the utmost\nimportance to her. And in degree, all this will hold true concerning\nwhaling vessels crossing each other’s track on the cruising-ground\nitself, even though they are equally long absent from home", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3612, "position": 3612, "text": "the cruising-ground\nitself, even though they are equally long absent from home. For one of\nthem may have received a transfer of letters from some third, and now\nfar remote vessel; and some of those letters may be for the people of\nthe ship", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 851, "2000": 887}}, {"id": 3613, "position": 3613, "text": "vessel; and some of those letters may be for the people of\nthe ship she now meets. Besides, they would exchange the whaling news,\nand have an agreeable chat. For not only would they meet with all the\nsympathies of sailors", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 3614, "position": 3614, "text": "For not only would they meet with all the\nsympathies of sailors, but likewise with all the peculiar\ncongenialities arising from a common pursuit and mutually shared\nprivations and perils.", "labels": {"50": 45, "100": 29, "250": 82, "500": 73, "1000": 851, "2000": 1584}}, {"id": 3615, "position": 3615, "text": "vations and perils.\n\nNor would difference of country make any very essential difference;\nthat is, so long as both parties speak one language, as is the case\nwith Americans and English. Though, to be sure, from the small number\nof English", "labels": {"50": 31, "100": 95, "250": 76, "500": 453, "1000": 581, "2000": 898}}, {"id": 3616, "position": 3616, "text": "and English. Though, to be sure, from the small number\nof English whalers, such meetings do not very often occur, and when\nthey do occur there is too apt to be a sort of shyness between them;\nfor your Englishman is rather", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3617, "position": 3617, "text": "to be a sort of shyness between them;\nfor your Englishman is rather reserved, and your Yankee, he does not\nfancy that sort of thing in anybody but himself. Besides, the English\nwhalers sometimes affect a kind of metropolitan superiority over the\nAmerican", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 887}}, {"id": 3618, "position": 3618, "text": ", the English\nwhalers sometimes affect a kind of metropolitan superiority over the\nAmerican whalers; regarding the long, lean Nantucketer, with his\nnondescript provincialisms, as a sort of sea-peasant", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 387, "2000": 898}}, {"id": 3619, "position": 3619, "text": "as a sort of sea-peasant. But where this\nsuperiority in the English whalemen does really consist, it would be\nhard to say, seeing that the Yankees in one day, collectively, kill\nmore whales than all the English, collectively, in ten", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3620, "position": 3620, "text": ", collectively, kill\nmore whales than all the English, collectively, in ten years. But this\nis a harmless little foible in the English whale-hunters, which the\nNantucketer does not take much to heart; probably, because he knows", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3621, "position": 3621, "text": "Nantucketer does not take much to heart; probably, because he knows\nthat he has a few foibles himself.\n\nSo, then, we see that of all ships separately sailing the sea, the\nwhalers have most reason to be sociable", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3622, "position": 3622, "text": "separately sailing the sea, the\nwhalers have most reason to be sociable—and they are so. Whereas, some\nmerchant ships crossing each other’s wake in the mid-Atlantic, will\noftentimes pass on without so much as a single", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3623, "position": 3623, "text": "-Atlantic, will\noftentimes pass on without so much as a single word of recognition,\nmutually cutting each other on the high seas, like a brace of dandies\nin Broadway; and all the time indulging, perhaps, in finical", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 3624, "position": 3624, "text": "Broadway; and all the time indulging, perhaps, in finical criticism\nupon each other’s rig. As for Men-of-War, when they chance to meet at\nsea, they first go through such a string of silly bowings", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3625, "position": 3625, "text": "meet at\nsea, they first go through such a string of silly bowings and\nscrapings, such a ducking of ensigns, that there does not seem to be\nmuch right-down hearty good-will and brotherly love about it at", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 887}}, {"id": 3626, "position": 3626, "text": "right-down hearty good-will and brotherly love about it at all. As\ntouching Slave-ships meeting, why, they are in such a prodigious hurry,\nthey run away from each other as soon as possible", "labels": {"50": 21, "100": 95, "250": 148, "500": 279, "1000": 755, "2000": 69}}, {"id": 3627, "position": 3627, "text": "hurry,\nthey run away from each other as soon as possible. And as for Pirates,\nwhen they chance to cross each other’s cross-bones, the first hail\nis—“How many skulls?”—the same way that whalers hail", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 3628, "position": 3628, "text": "—“How many skulls?”—the same way that whalers hail—“How many\nbarrels?” And that question once answered, pirates straightway steer\napart, for they are infernal villains on both sides, and don’t like", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3629, "position": 3629, "text": "they are infernal villains on both sides, and don’t like to\nsee overmuch of each other’s villanous likenesses.\n\nBut look at the godly, honest, unostentatious, hospitable, soc", "labels": {"50": 31, "100": 75, "250": 69, "500": 453, "1000": 581, "2000": 1828}}, {"id": 3630, "position": 3630, "text": "ly, honest, unostentatious, hospitable, sociable,\nfree-and-easy whaler! What does the whaler do when she meets another\nwhaler in any sort of decent weather? She has a “_Ga", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 3631, "position": 3631, "text": "whaler in any sort of decent weather? She has a “_Gam_,” a thing so\nutterly unknown to all other ships that they never heard of the name\neven; and if by chance they should hear of it, they only grin", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3632, "position": 3632, "text": "even; and if by chance they should hear of it, they only grin at it,\nand repeat gamesome stuff about “spouters” and “blubber-boilers,” and\nsuch like pretty exclamations", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 387, "2000": 1828}}, {"id": 3633, "position": 3633, "text": ",” and\nsuch like pretty exclamations. Why it is that all Merchant-seamen, and\nalso all Pirates and Man-of-War’s men, and Slave-ship sailors, cherish\nsuch a scornful feeling towards Whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3634, "position": 3634, "text": "Slave-ship sailors, cherish\nsuch a scornful feeling towards Whale-ships; this is a question it\nwould be hard to answer. Because, in the case of pirates, say, I should\nlike to know whether that profession of theirs has", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3635, "position": 3635, "text": "pirates, say, I should\nlike to know whether that profession of theirs has any peculiar glory\nabout it. It sometimes ends in uncommon elevation, indeed; but only at\nthe gallows. And besides, when a man is elevated in that odd fashion,", "labels": {"50": 31, "100": 75, "250": 69, "500": 307, "1000": 343, "2000": 761}}, {"id": 3636, "position": 3636, "text": "ws. And besides, when a man is elevated in that odd fashion,\nhe has no proper foundation for his superior altitude. Hence, I\nconclude, that in boasting himself to be high lifted above a whaleman,\nin that assertion the pirate", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3637, "position": 3637, "text": "himself to be high lifted above a whaleman,\nin that assertion the pirate has no solid basis to stand on.\n\nBut what is a _Gam?_ You might wear out your index-finger running up\nand down the columns of dictionaries", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 3638, "position": 3638, "text": "out your index-finger running up\nand down the columns of dictionaries, and never find the word. Dr.\nJohnson never attained to that erudition; Noah Webster’s ark does not\nhold it", "labels": {"50": 31, "100": 40, "250": 74, "500": 7, "1000": 85, "2000": 1380}}, {"id": 3639, "position": 3639, "text": "’s ark does not\nhold it. Nevertheless, this same expressive word has now for many years\nbeen in constant use among some fifteen thousand true born Yankees.\nCertainly, it needs a definition, and should be incorporated into the\nLexicon", "labels": {"50": 48, "100": 7, "250": 137, "500": 7, "1000": 85, "2000": 898}}, {"id": 3640, "position": 3640, "text": "a definition, and should be incorporated into the\nLexicon. With that view, let me learnedly define it.\n\nGAM. NOUN—_A social meeting of two_ (_or more_) _Whaleships, generally\non a cruising-", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3641, "position": 3641, "text": "(_or more_) _Whaleships, generally\non a cruising-ground; when, after exchanging hails, they exchange\nvisits by boats’ crews: the two captains remaining, for the time, on\nboard of one ship, and the two", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3642, "position": 3642, "text": "remaining, for the time, on\nboard of one ship, and the two chief mates on the other._\n\nThere is another little item about Gamming which must not be forgotten\nhere. All professions have their own little peculiarities of detail; so\nhas", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 3643, "position": 3643, "text": "here. All professions have their own little peculiarities of detail; so\nhas the whale fishery. In a pirate, man-of-war, or slave ship, when the\ncaptain is rowed anywhere in his boat, he always sits in the stern", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3644, "position": 3644, "text": "captain is rowed anywhere in his boat, he always sits in the stern\nsheets on a comfortable, sometimes cushioned seat there, and often\nsteers himself with a pretty little milliner’s tiller decorated with\ngay cords and ribbons", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 887}}, {"id": 3645, "position": 3645, "text": "milliner’s tiller decorated with\ngay cords and ribbons. But the whale-boat has no seat astern, no sofa\nof that sort whatever, and no tiller at all. High times indeed, if\nwhaling captains were wheeled about the water", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3646, "position": 3646, "text": "at all. High times indeed, if\nwhaling captains were wheeled about the water on castors like gouty old\naldermen in patent chairs. And as for a tiller, the whale-boat never\nadmits of any such effeminacy", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3647, "position": 3647, "text": "er, the whale-boat never\nadmits of any such effeminacy; and therefore as in gamming a complete\nboat’s crew must leave the ship, and hence as the boat steerer or\nharpooneer is of the number, that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3648, "position": 3648, "text": "as the boat steerer or\nharpooneer is of the number, that subordinate is the steersman upon the\noccasion, and the captain, having no place to sit in, is pulled off to\nhis visit all standing like a pine tree", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3649, "position": 3649, "text": "is pulled off to\nhis visit all standing like a pine tree. And often you will notice that\nbeing conscious of the eyes of the whole visible world resting on him\nfrom the sides of the two ships, this standing captain is all alive to\nthe importance of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 887}}, {"id": 3650, "position": 3650, "text": "of the two ships, this standing captain is all alive to\nthe importance of sustaining his dignity by maintaining his legs. Nor\nis this any very easy matter; for in his rear is the immense projecting\nsteering oar hitting him now and then in the small", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3651, "position": 3651, "text": "is the immense projecting\nsteering oar hitting him now and then in the small of his back, the\nafter-oar reciprocating by rapping his knees in front. He is thus\ncompletely wedged before and behind, and can only expand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3652, "position": 3652, "text": ". He is thus\ncompletely wedged before and behind, and can only expand himself\nsideways by settling down on his stretched legs; but a sudden, violent\npitch of the boat will often go far to topple him, because length of\nfoundation is nothing without", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3653, "position": 3653, "text": "often go far to topple him, because length of\nfoundation is nothing without corresponding breadth. Merely make a\nspread angle of two poles, and you cannot stand them up. Then, again,\nit would never do in plain sight of the world’s", "labels": {"50": 31, "100": 7, "250": 106, "500": 496, "1000": 290, "2000": 962}}, {"id": 3654, "position": 3654, "text": ", again,\nit would never do in plain sight of the world’s riveted eyes, it would\nnever do, I say, for this straddling captain to be seen steadying\nhimself the slightest particle by catching hold of anything with his", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3655, "position": 3655, "text": "be seen steadying\nhimself the slightest particle by catching hold of anything with his\nhands; indeed, as token of his entire, buoyant self-command, he\ngenerally carries his hands in his trowsers’ pockets; but perhaps being\ngenerally very", "labels": {"50": 31, "100": 7, "250": 193, "500": 202, "1000": 858, "2000": 371}}, {"id": 3656, "position": 3656, "text": "his hands in his trowsers’ pockets; but perhaps being\ngenerally very large, heavy hands, he carries them there for ballast.\nNevertheless there have occurred instances, well authenticated ones\ntoo, where the captain has been known for an uncommonly critical", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3657, "position": 3657, "text": "ated ones\ntoo, where the captain has been known for an uncommonly critical moment\nor two, in a sudden squall say—to seize hold of the nearest oarsman’s\nhair, and hold on there like grim death.\n\n\nCHAPTER 54", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3658, "position": 3658, "text": "man’s\nhair, and hold on there like grim death.\n\n\nCHAPTER 54. The Town-Ho’s Story.\n\n(_As told at the Golden Inn._)\n\nThe Cape of Good Hope, and all the watery region round about there,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 9, "2000": 682}}, {"id": 3659, "position": 3659, "text": "The Cape of Good Hope, and all the watery region round about there, is\nmuch like some noted four corners of a great highway, where you meet\nmore travellers than in any other part.\n\nIt was not very long after speaking the Goney that another", "labels": {"50": 23, "100": 88, "250": 91, "500": 229, "1000": 627, "2000": 110}}, {"id": 3660, "position": 3660, "text": "other part.\n\nIt was not very long after speaking the Goney that another\nhomeward-bound whaleman, the Town-Ho,* was encountered. She was manned\nalmost wholly by Polynesians. In the short gam that ensued she gave", "labels": {"50": 45, "100": 42, "250": 130, "500": 494, "1000": 480, "2000": 385}}, {"id": 3661, "position": 3661, "text": "wholly by Polynesians. In the short gam that ensued she gave us\nstrong news of Moby Dick. To some the general interest in the White\nWhale was now wildly heightened by a circumstance of the Town-Ho’s\nstory, which seemed", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 480, "2000": 1620}}, {"id": 3662, "position": 3662, "text": "heightened by a circumstance of the Town-Ho’s\nstory, which seemed obscurely to involve with the whale a certain\nwondrous, inverted visitation of one of those so called judgments of\nGod which at times are said to overtake some men", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3663, "position": 3663, "text": "called judgments of\nGod which at times are said to overtake some men. This latter\ncircumstance, with its own particular accompaniments, forming what may\nbe called the secret part of the tragedy about to be narrated, never\nreached the ears of Captain Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3664, "position": 3664, "text": "the tragedy about to be narrated, never\nreached the ears of Captain Ahab or his mates. For that secret part of\nthe story was unknown to the captain of the Town-Ho himself. It was the\nprivate property of three confederate white seamen of that", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3665, "position": 3665, "text": "Ho himself. It was the\nprivate property of three confederate white seamen of that ship, one of\nwhom, it seems, communicated it to Tashtego with Romish injunctions of\nsecrecy, but the following night Tashtego rambled in", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1584}}, {"id": 3666, "position": 3666, "text": "s of\nsecrecy, but the following night Tashtego rambled in his sleep, and\nrevealed so much of it in that way, that when he was wakened he could\nnot well withhold the rest", "labels": {"50": 22, "100": 55, "250": 229, "500": 14, "1000": 477, "2000": 1995}}, {"id": 3667, "position": 3667, "text": "could\nnot well withhold the rest. Nevertheless, so potent an influence did\nthis thing have on those seamen in the Pequod who came to the full\nknowledge of it, and by such a strange delicacy, to call it so, were", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3668, "position": 3668, "text": "and by such a strange delicacy, to call it so, were\nthey governed in this matter, that they kept the secret among\nthemselves so that it never transpired abaft the Pequod’s main-mast", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 327, "2000": 1620}}, {"id": 3669, "position": 3669, "text": "ft the Pequod’s main-mast.\nInterweaving in its proper place this darker thread with the story as\npublicly narrated on the ship, the whole of this strange affair I now\nproceed to put on lasting record.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3670, "position": 3670, "text": "this strange affair I now\nproceed to put on lasting record.\n\n*The ancient whale-cry upon first sighting a whale from the mast-head,\nstill used by whalemen in hunting the famous Gallipagos terrapin.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3671, "position": 3671, "text": "hunting the famous Gallipagos terrapin.\n\nFor my humor’s sake, I shall preserve the style in which I once\nnarrated it at Lima, to a lounging circle of my Spanish friends, one\nsaint’s eve, smoking upon the", "labels": {"50": 45, "100": 24, "250": 138, "500": 162, "1000": 35, "2000": 1735}}, {"id": 3672, "position": 3672, "text": "circle of my Spanish friends, one\nsaint’s eve, smoking upon the thick-gilt tiled piazza of the Golden\nInn. Of those fine cavaliers, the young Dons, Pedro and Sebastian, were\non the closer terms with me; and hence", "labels": {"50": 49, "100": 15, "250": 22, "500": 364, "1000": 498, "2000": 674}}, {"id": 3673, "position": 3673, "text": ", Pedro and Sebastian, were\non the closer terms with me; and hence the interluding questions they\noccasionally put, and which are duly answered at the time.\n\n“Some two years prior to my first learning the events which I am about\nrehear", "labels": {"50": 20, "100": 15, "250": 22, "500": 364, "1000": 523, "2000": 674}}, {"id": 3674, "position": 3674, "text": "two years prior to my first learning the events which I am about\nrehearsing to you, gentlemen, the Town-Ho, Sperm Whaler of Nantucket,\nwas cruising in your Pacific here, not very many days’ sail eastward\nfrom the ea", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3675, "position": 3675, "text": "in your Pacific here, not very many days’ sail eastward\nfrom the eaves of this good Golden Inn. She was somewhere to the\nnorthward of the Line. One morning upon handling the pumps, according\nto daily usage, it was observed that she made", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 3676, "position": 3676, "text": "handling the pumps, according\nto daily usage, it was observed that she made more water in her hold\nthan common. They supposed a sword-fish had stabbed her, gentlemen. But\nthe captain, having some unusual reason for believing that rare good\nluck awaited", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 3677, "position": 3677, "text": "But\nthe captain, having some unusual reason for believing that rare good\nluck awaited him in those latitudes; and therefore being very averse to\nquit them, and the leak not being then considered at all dangerous,\nthough, indeed, they could not find", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 877}}, {"id": 3678, "position": 3678, "text": "being then considered at all dangerous,\nthough, indeed, they could not find it after searching the hold as low\ndown as was possible in rather heavy weather, the ship still continued\nher cruisings, the mariners working at the pumps at wide and easy\nintervals", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 723, "2000": 282}}, {"id": 3679, "position": 3679, "text": "her cruisings, the mariners working at the pumps at wide and easy\nintervals; but no good luck came; more days went by, and not only was\nthe leak yet undiscovered, but it sensibly increased", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1668}}, {"id": 3680, "position": 3680, "text": "iscovered, but it sensibly increased. So much so, that\nnow taking some alarm, the captain, making all sail, stood away for the\nnearest harbor among the islands, there to have his hull hove out and\nrepaired.", "labels": {"50": 45, "100": 29, "250": 138, "500": 28, "1000": 723, "2000": 576}}, {"id": 3681, "position": 3681, "text": "the islands, there to have his hull hove out and\nrepaired.\n\n“Though no small passage was before her, yet, if the commonest chance\nfavoured, he did not at all fear that his ship would founder by the\nway, because his pumps were", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 3682, "position": 3682, "text": "all fear that his ship would founder by the\nway, because his pumps were of the best, and being periodically\nrelieved at them, those six-and-thirty men of his could easily keep the\nship free; never mind if the leak should double on", "labels": {"50": 45, "100": 29, "250": 138, "500": 384, "1000": 139, "2000": 801}}, {"id": 3683, "position": 3683, "text": "could easily keep the\nship free; never mind if the leak should double on her. In truth, well\nnigh the whole of this passage being attended by very prosperous\nbreezes, the Town-Ho had all but certainly arrived in perfect safety at\nher", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 723, "2000": 576}}, {"id": 3684, "position": 3684, "text": ", the Town-Ho had all but certainly arrived in perfect safety at\nher port without the occurrence of the least fatality, had it not been\nfor the brutal overbearing of Radney, the mate, a Vineyarder, and the\nbitterly", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1584}}, {"id": 3685, "position": 3685, "text": "of Radney, the mate, a Vineyarder, and the\nbitterly provoked vengeance of Steelkilt, a Lakeman and desperado from\nBuffalo.\n\n“‘Lakeman!—Buffalo! Pray, what is a Lakeman, and where", "labels": {"50": 37, "100": 6, "250": 145, "500": 444, "1000": 905, "2000": 1581}}, {"id": 3686, "position": 3686, "text": "man!—Buffalo! Pray, what is a Lakeman, and where is Buffalo?’\nsaid Don Sebastian, rising in his swinging mat of grass.\n\n“On the eastern shore of our Lake Erie, Don; but—I crave your\ncourtesy", "labels": {"50": 37, "100": 38, "250": 77, "500": 230, "1000": 525, "2000": 47}}, {"id": 3687, "position": 3687, "text": "shore of our Lake Erie, Don; but—I crave your\ncourtesy—may be, you shall soon hear further of all that. Now,\ngentlemen, in square-sail brigs and three-masted ships, well-nigh as", "labels": {"50": 15, "100": 62, "250": 9, "500": 67, "1000": 971, "2000": 201}}, {"id": 3688, "position": 3688, "text": "sail brigs and three-masted ships, well-nigh as\nlarge and stout as any that ever sailed out of your old Callao to far\nManilla; this Lakeman, in the land-locked heart of our America, had yet", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 9, "2000": 16}}, {"id": 3689, "position": 3689, "text": "Lakeman, in the land-locked heart of our America, had yet\nbeen nurtured by all those agrarian freebooting impressions popularly\nconnected with the open ocean. For in their interflowing aggregate,\nthose grand fresh-water seas of ours", "labels": {"50": 44, "100": 37, "250": 193, "500": 182, "1000": 515, "2000": 1107}}, {"id": 3690, "position": 3690, "text": "in their interflowing aggregate,\nthose grand fresh-water seas of ours,—Erie, and Ontario, and Huron, and\nSuperior, and Michigan,—possess an ocean-like expansiveness, with many\nof the ocean’s noblest traits", "labels": {"50": 21, "100": 66, "250": 211, "500": 156, "1000": 602, "2000": 1536}}, {"id": 3691, "position": 3691, "text": "-like expansiveness, with many\nof the ocean’s noblest traits; with many of its rimmed varieties of\nraces and of climes. They contain round archipelagoes of romantic\nisles, even as the Polynesian waters do; in large", "labels": {"50": 45, "100": 29, "250": 161, "500": 72, "1000": 480, "2000": 887}}, {"id": 3692, "position": 3692, "text": "es of romantic\nisles, even as the Polynesian waters do; in large part, are shored by\ntwo great contrasting nations, as the Atlantic is; they furnish long\nmaritime approaches to our numerous territorial colonies from the East,\ndotted all round their", "labels": {"50": 45, "100": 29, "250": 161, "500": 13, "1000": 622, "2000": 1097}}, {"id": 3693, "position": 3693, "text": "maritime approaches to our numerous territorial colonies from the East,\ndotted all round their banks; here and there are frowned upon by\nbatteries, and by the goat-like craggy guns of lofty Mackinaw; they\nhave heard the fleet thunderings", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 3694, "position": 3694, "text": "guns of lofty Mackinaw; they\nhave heard the fleet thunderings of naval victories; at intervals, they\nyield their beaches to wild barbarians, whose red painted faces flash\nfrom out their peltry wigwams; for leagues and leagues are", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 198}}, {"id": 3695, "position": 3695, "text": "from out their peltry wigwams; for leagues and leagues are flanked by\nancient and unentered forests, where the gaunt pines stand like serried\nlines of kings in Gothic genealogies; those same woods harboring wild\nAfric beasts", "labels": {"50": 16, "100": 20, "250": 133, "500": 162, "1000": 747, "2000": 1105}}, {"id": 3696, "position": 3696, "text": "in Gothic genealogies; those same woods harboring wild\nAfric beasts of prey, and silken creatures whose exported furs give\nrobes to Tartar Emperors; they mirror the paved capitals of Buffalo and\nCleveland, as well as Winnebago", "labels": {"50": 48, "100": 38, "250": 5, "500": 346, "1000": 525, "2000": 1264}}, {"id": 3697, "position": 3697, "text": "the paved capitals of Buffalo and\nCleveland, as well as Winnebago villages; they float alike the\nfull-rigged merchant ship, the armed cruiser of the State, the steamer,\nand the beech canoe; they are swept by Borean and di", "labels": {"50": 48, "100": 20, "250": 137, "500": 162, "1000": 525, "2000": 1264}}, {"id": 3698, "position": 3698, "text": "steamer,\nand the beech canoe; they are swept by Borean and dismasting blasts as\ndireful as any that lash the salted wave; they know what shipwrecks\nare, for out of sight of land, however inland,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 887}}, {"id": 3699, "position": 3699, "text": "wrecks\nare, for out of sight of land, however inland, they have drowned full\nmany a midnight ship with all its shrieking crew. Thus, gentlemen,\nthough an inlander, Steelkilt was wild-ocean born, and wild", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3700, "position": 3700, "text": "an inlander, Steelkilt was wild-ocean born, and wild-ocean\nnurtured; as much of an audacious mariner as any. And for Radney,\nthough in his infancy he may have laid him down on", "labels": {"50": 25, "100": 41, "250": 156, "500": 388, "1000": 329, "2000": 693}}, {"id": 3701, "position": 3701, "text": "Radney,\nthough in his infancy he may have laid him down on the lone Nantucket\nbeach, to nurse at his maternal sea; though in after life he had long\nfollowed our austere Atlantic and your contemplative Pacific; yet", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 3702, "position": 3702, "text": "followed our austere Atlantic and your contemplative Pacific; yet was\nhe quite as vengeful and full of social quarrel as the backwoods\nseaman, fresh from the latitudes of buck-horn handled Bowie-knives", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3703, "position": 3703, "text": "the latitudes of buck-horn handled Bowie-knives. Yet\nwas this Nantucketer a man with some good-hearted traits; and this\nLakeman, a mariner, who though a sort of devil indeed, might yet by\ninflexi", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3704, "position": 3704, "text": ", who though a sort of devil indeed, might yet by\ninflexible firmness, only tempered by that common decency of human\nrecognition which is the meanest slave’s right; thus treated, this\nSteelkilt had long been retained", "labels": {"50": 33, "100": 17, "250": 229, "500": 336, "1000": 858, "2000": 1027}}, {"id": 3705, "position": 3705, "text": "’s right; thus treated, this\nSteelkilt had long been retained harmless and docile. At all events, he\nhad proved so thus far; but Radney was doomed and made mad, and\nSteelkilt—but, gentlemen,", "labels": {"50": 25, "100": 64, "250": 55, "500": 388, "1000": 313, "2000": 693}}, {"id": 3706, "position": 3706, "text": "was doomed and made mad, and\nSteelkilt—but, gentlemen, you shall hear.\n\n“It was not more than a day or two at the furthest after pointing her\nprow for her island haven, that the Town-Ho’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 3707, "position": 3707, "text": "her\nprow for her island haven, that the Town-Ho’s leak seemed again\nincreasing, but only so as to require an hour or more at the pumps\nevery day. You must know that in a settled and civilized ocean like our\nAtlantic,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 3708, "position": 3708, "text": ". You must know that in a settled and civilized ocean like our\nAtlantic, for example, some skippers think little of pumping their\nwhole way across it; though of a still, sleepy night, should the\nofficer of the deck happen to forget his duty", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 3709, "position": 3709, "text": ", sleepy night, should the\nofficer of the deck happen to forget his duty in that respect, the\nprobability would be that he and his shipmates would never again\nremember it, on account of all hands gently subsiding to the bottom", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3710, "position": 3710, "text": "on account of all hands gently subsiding to the bottom.\nNor in the solitary and savage seas far from you to the westward,\ngentlemen, is it altogether unusual for ships to keep clanging at their\npump-handles in full chorus even for a", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 3711, "position": 3711, "text": "to keep clanging at their\npump-handles in full chorus even for a voyage of considerable length;\nthat is, if it lie along a tolerably accessible coast, or if any other\nreasonable retreat is afforded them", "labels": {"50": 48, "100": 20, "250": 138, "500": 162, "1000": 9, "2000": 682}}, {"id": 3712, "position": 3712, "text": "if any other\nreasonable retreat is afforded them. It is only when a leaky vessel is\nin some very out of the way part of those waters, some really landless\nlatitude, that her captain begins to feel a little anxious.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 3713, "position": 3713, "text": ", that her captain begins to feel a little anxious.\n\n“Much this way had it been with the Town-Ho; so when her leak was found\ngaining once more, there was in truth some small concern manifested by\nseveral of her company; especially by", "labels": {"50": 2, "100": 69, "250": 127, "500": 257, "1000": 676, "2000": 1459}}, {"id": 3714, "position": 3714, "text": "was in truth some small concern manifested by\nseveral of her company; especially by Radney the mate. He commanded the\nupper sails to be well hoisted, sheeted home anew, and every way\nexpanded to the breeze", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 3715, "position": 3715, "text": "ew, and every way\nexpanded to the breeze. Now this Radney, I suppose, was as little of a\ncoward, and as little inclined to any sort of nervous apprehensiveness\ntouching his own person as any fearless, unthi", "labels": {"50": 37, "100": 6, "250": 174, "500": 24, "1000": 661, "2000": 736}}, {"id": 3716, "position": 3716, "text": "apprehensiveness\ntouching his own person as any fearless, unthinking creature on land or\non sea that you can conveniently imagine, gentlemen. Therefore when he\nbetrayed this solicitude about the safety of the ship, some of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 877}}, {"id": 3717, "position": 3717, "text": "betrayed this solicitude about the safety of the ship, some of the\nseamen declared that it was only on account of his being a part owner\nin her. So when they were working that evening at the pumps, there was\non this head no", "labels": {"50": 45, "100": 29, "250": 82, "500": 239, "1000": 851, "2000": 1584}}, {"id": 3718, "position": 3718, "text": "they were working that evening at the pumps, there was\non this head no small gamesomeness slily going on among them, as they\nstood with their feet continually overflowed by the rippling clear\nwater; clear as any mountain spring, gentlemen", "labels": {"50": 48, "100": 20, "250": 53, "500": 162, "1000": 35, "2000": 32}}, {"id": 3719, "position": 3719, "text": "ed by the rippling clear\nwater; clear as any mountain spring, gentlemen—that bubbling from the\npumps ran across the deck, and poured itself out in steady spouts at\nthe lee scupper-holes.", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 816, "2000": 326}}, {"id": 3720, "position": 3720, "text": "the lee scupper-holes.\n\n“Now, as you well know, it is not seldom the case in this conventional\nworld of ours—watery or otherwise; that when a person placed in command\nover his fellow-men finds one of them to", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 3721, "position": 3721, "text": "a person placed in command\nover his fellow-men finds one of them to be very significantly his\nsuperior in general pride of manhood, straightway against that man he\nconceives an unconquerable dislike and bitterness; and if he have a", "labels": {"50": 21, "100": 95, "250": 88, "500": 107, "1000": 761, "2000": 1644}}, {"id": 3722, "position": 3722, "text": "ives an unconquerable dislike and bitterness; and if he have a\nchance he will pull down and pulverize that subaltern’s tower, and make\na little heap of dust of it", "labels": {"50": 23, "100": 88, "250": 244, "500": 211, "1000": 460, "2000": 1685}}, {"id": 3723, "position": 3723, "text": "little heap of dust of it. Be this conceit of mine as it may,\ngentlemen, at all events Steelkilt was a tall and noble animal with a\nhead like a Roman, and a flowing golden beard like the tasseled\nhousing", "labels": {"50": 25, "100": 41, "250": 156, "500": 407, "1000": 329, "2000": 1426}}, {"id": 3724, "position": 3724, "text": "like a Roman, and a flowing golden beard like the tasseled\nhousings of your last viceroy’s snorting charger; and a brain, and a\nheart, and a soul in him, gentlemen, which had made Steelkilt\nCharlemagne", "labels": {"50": 1, "100": 80, "250": 63, "500": 415, "1000": 728, "2000": 1695}}, {"id": 3725, "position": 3725, "text": "and a soul in him, gentlemen, which had made Steelkilt\nCharlemagne, had he been born son to Charlemagne’s father. But Radney,\nthe mate, was ugly as a mule; yet as hardy, as stubborn, as malicious", "labels": {"50": 22, "100": 55, "250": 95, "500": 269, "1000": 994, "2000": 1915}}, {"id": 3726, "position": 3726, "text": "was ugly as a mule; yet as hardy, as stubborn, as malicious.\nHe did not love Steelkilt, and Steelkilt knew it.\n\n“Espying the mate drawing near as he was toiling at the pump with the\nrest", "labels": {"50": 37, "100": 12, "250": 212, "500": 21, "1000": 690, "2000": 401}}, {"id": 3727, "position": 3727, "text": "the mate drawing near as he was toiling at the pump with the\nrest, the Lakeman affected not to notice him, but unawed, went on with\nhis gay banterings.\n\n“‘Aye, aye, my merry lads, it’", "labels": {"50": 41, "100": 88, "250": 163, "500": 432, "1000": 54, "2000": 380}}, {"id": 3728, "position": 3728, "text": "terings.\n\n“‘Aye, aye, my merry lads, it’s a lively leak this; hold a cannikin,\none of ye, and let’s have a taste. By the Lord, it’s worth bottling!", "labels": {"50": 18, "100": 55, "250": 145, "500": 180, "1000": 672, "2000": 1091}}, {"id": 3729, "position": 3729, "text": "have a taste. By the Lord, it’s worth bottling! I\ntell ye what, men, old Rad’s investment must go for it! he had best cut\naway his part of the hull and tow it home", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3730, "position": 3730, "text": "best cut\naway his part of the hull and tow it home. The fact is, boys, that\nsword-fish only began the job; he’s come back again with a gang of\nship-carpenters, saw-fish, and file-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3731, "position": 3731, "text": "a gang of\nship-carpenters, saw-fish, and file-fish, and what not; and the whole\nposse of ’em are now hard at work cutting and slashing at the bottom;\nmaking improvements, I suppose", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3732, "position": 3732, "text": "slashing at the bottom;\nmaking improvements, I suppose. If old Rad were here now, I’d tell him\nto jump overboard and scatter ’em. They’re playing the devil with his\nestate, I can tell him", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3733, "position": 3733, "text": "’re playing the devil with his\nestate, I can tell him. But he’s a simple old soul,—Rad, and a beauty\ntoo. Boys, they say the rest of his property is invested in\nlooking-glasses", "labels": {"50": 37, "100": 6, "250": 174, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3734, "position": 3734, "text": "say the rest of his property is invested in\nlooking-glasses. I wonder if he’d give a poor devil like me the model\nof his nose.’\n\n“‘Damn your eyes! what’s that pump stopping for?’ roared Rad", "labels": {"50": 41, "100": 21, "250": 207, "500": 5, "1000": 333, "2000": 1937}}, {"id": 3735, "position": 3735, "text": "your eyes! what’s that pump stopping for?’ roared Radney,\npretending not to have heard the sailors’ talk. ‘Thunder away at it!’\n\n“‘Aye, aye, sir,’ said Steelkilt, merry as", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3736, "position": 3736, "text": "‘Aye, aye, sir,’ said Steelkilt, merry as a cricket. ‘Lively, boys,\nlively, now!’ And with that the pump clanged like fifty fire-engines;\nthe men tossed their hats off to it,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 3737, "position": 3737, "text": "like fifty fire-engines;\nthe men tossed their hats off to it, and ere long that peculiar gasping\nof the lungs was heard which denotes the fullest tension of life’s\nutmost energies.\n\n“Quitting the pump at last, with the", "labels": {"50": 45, "100": 64, "250": 138, "500": 425, "1000": 327, "2000": 1904}}, {"id": 3738, "position": 3738, "text": "’s\nutmost energies.\n\n“Quitting the pump at last, with the rest of his band, the Lakeman went\nforward all panting, and sat himself down on the windlass; his face\nfiery red, his eyes bloodshot, and wiping the", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3739, "position": 3739, "text": "lass; his face\nfiery red, his eyes bloodshot, and wiping the profuse sweat from his\nbrow. Now what cozening fiend it was, gentlemen, that possessed Radney\nto meddle with such a man in that corpore", "labels": {"50": 22, "100": 55, "250": 145, "500": 184, "1000": 959, "2000": 314}}, {"id": 3740, "position": 3740, "text": "possessed Radney\nto meddle with such a man in that corporeally exasperated state, I know\nnot; but so it happened. Intolerably striding along the deck, the mate\ncommanded him to get a broom and sweep down the plank", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1192}}, {"id": 3741, "position": 3741, "text": "deck, the mate\ncommanded him to get a broom and sweep down the planks, and also a\nshovel, and remove some offensive matters consequent upon allowing a\npig to run at large.\n\n“Now, gentlemen, sweeping a ship’s deck", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 3742, "position": 3742, "text": "run at large.\n\n“Now, gentlemen, sweeping a ship’s deck at sea is a piece of household\nwork which in all times but raging gales is regularly attended to every\nevening; it has been known to be done in the case of ships", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 887}}, {"id": 3743, "position": 3743, "text": "every\nevening; it has been known to be done in the case of ships actually\nfoundering at the time. Such, gentlemen, is the inflexibility of\nsea-usages and the instinctive love of neatness in seamen; some of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3744, "position": 3744, "text": "usages and the instinctive love of neatness in seamen; some of whom\nwould not willingly drown without first washing their faces. But in all\nvessels this broom business is the prescriptive province of the boys,\nif boys there be aboard", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3745, "position": 3745, "text": "prescriptive province of the boys,\nif boys there be aboard. Besides, it was the stronger men in the\nTown-Ho that had been divided into gangs, taking turns at the pumps;\nand being the most athletic seaman of them all, Steel", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 3746, "position": 3746, "text": "at the pumps;\nand being the most athletic seaman of them all, Steelkilt had been\nregularly assigned captain of one of the gangs; consequently he should\nhave been freed from any trivial business not connected with truly\nnautical duties, such being the case with", "labels": {"50": 45, "100": 29, "250": 82, "500": 73, "1000": 851, "2000": 1584}}, {"id": 3747, "position": 3747, "text": "any trivial business not connected with truly\nnautical duties, such being the case with his comrades. I mention all\nthese particulars so that you may understand exactly how this affair\nstood between the two men.\n\n“But there was more than this: the order about", "labels": {"50": 1, "100": 49, "250": 63, "500": 301, "1000": 305, "2000": 1504}}, {"id": 3748, "position": 3748, "text": "the two men.\n\n“But there was more than this: the order about the shovel was almost as\nplainly meant to sting and insult Steelkilt, as though Radney had spat\nin his face. Any man who has gone sailor in a whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3749, "position": 3749, "text": "had spat\nin his face. Any man who has gone sailor in a whale-ship will\nunderstand this; and all this and doubtless much more, the Lakeman\nfully comprehended when the mate uttered his command", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 531, "2000": 967}}, {"id": 3750, "position": 3750, "text": "ed when the mate uttered his command. But as he sat\nstill for a moment, and as he steadfastly looked into the mate’s\nmalignant eye and perceived the stacks of powder-casks heaped up in him\nand the slow", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 3751, "position": 3751, "text": "the stacks of powder-casks heaped up in him\nand the slow-match silently burning along towards them; as he\ninstinctively saw all this, that strange forbearance and unwillingness\nto stir up the deeper passionateness in any already ir", "labels": {"50": 22, "100": 78, "250": 205, "500": 469, "1000": 496, "2000": 1593}}, {"id": 3752, "position": 3752, "text": "ce and unwillingness\nto stir up the deeper passionateness in any already ireful being—a\nrepugnance most felt, when felt at all, by really valiant men even when\naggrieved—this nameless phantom feeling, gentlemen", "labels": {"50": 23, "100": 88, "250": 219, "500": 170, "1000": 421, "2000": 389}}, {"id": 3753, "position": 3753, "text": "men even when\naggrieved—this nameless phantom feeling, gentlemen, stole over\nSteelkilt.\n\n“Therefore, in his ordinary tone, only a little broken by the bodily\nexhaustion he was temporarily in, he answered him saying that sweeping\nthe", "labels": {"50": 23, "100": 31, "250": 228, "500": 208, "1000": 603, "2000": 428}}, {"id": 3754, "position": 3754, "text": "the bodily\nexhaustion he was temporarily in, he answered him saying that sweeping\nthe deck was not his business, and he would not do it. And then,\nwithout at all alluding to the shovel, he pointed to three lads as the\ncustomary sweepers", "labels": {"50": 37, "100": 88, "250": 163, "500": 432, "1000": 531, "2000": 1593}}, {"id": 3755, "position": 3755, "text": "uding to the shovel, he pointed to three lads as the\ncustomary sweepers; who, not being billeted at the pumps, had done\nlittle or nothing all day. To this, Radney replied with an oath, in a\nmost dom", "labels": {"50": 37, "100": 6, "250": 25, "500": 24, "1000": 772, "2000": 9}}, {"id": 3756, "position": 3756, "text": "To this, Radney replied with an oath, in a\nmost domineering and outrageous manner unconditionally reiterating his\ncommand; meanwhile advancing upon the still seated Lakeman, with an\nuplifted cooper’s club hammer which", "labels": {"50": 37, "100": 55, "250": 145, "500": 444, "1000": 959, "2000": 314}}, {"id": 3757, "position": 3757, "text": "seated Lakeman, with an\nuplifted cooper’s club hammer which he had snatched from a cask near\nby.\n\n“Heated and irritated as he was by his spasmodic toil at the pumps, for\nall his first nameless feeling", "labels": {"50": 23, "100": 88, "250": 70, "500": 100, "1000": 962, "2000": 638}}, {"id": 3758, "position": 3758, "text": "smodic toil at the pumps, for\nall his first nameless feeling of forbearance the sweating Steelkilt\ncould but ill brook this bearing in the mate; but somehow still\nsmothering the conflagration within him, without", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3759, "position": 3759, "text": "but somehow still\nsmothering the conflagration within him, without speaking he remained\ndoggedly rooted to his seat, till at last the incensed Radney shook the\nhammer within a few inches of his face, furiously commanding him to do", "labels": {"50": 39, "100": 99, "250": 20, "500": 133, "1000": 379, "2000": 1361}}, {"id": 3760, "position": 3760, "text": "the\nhammer within a few inches of his face, furiously commanding him to do\nhis bidding.\n\n“Steelkilt rose, and slowly retreating round the windlass, steadily\nfollowed by the mate with his menacing hammer, deliberately repeated\nhis intention not to obey", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 3761, "position": 3761, "text": "the mate with his menacing hammer, deliberately repeated\nhis intention not to obey. Seeing, however, that his forbearance had\nnot the slightest effect, by an awful and unspeakable intimation with\nhis twisted hand he warned off the", "labels": {"50": 22, "100": 55, "250": 145, "500": 43, "1000": 959, "2000": 481}}, {"id": 3762, "position": 3762, "text": "unspeakable intimation with\nhis twisted hand he warned off the foolish and infatuated man; but it\nwas to no purpose. And in this way the two went once slowly round the\nwindlass; when, resolved at last no longer", "labels": {"50": 22, "100": 78, "250": 28, "500": 469, "1000": 328, "2000": 213}}, {"id": 3763, "position": 3763, "text": "went once slowly round the\nwindlass; when, resolved at last no longer to retreat, bethinking him\nthat he had now forborne as much as comported with his humor, the\nLakeman paused on the hatches and thus spoke to the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 3764, "position": 3764, "text": "humor, the\nLakeman paused on the hatches and thus spoke to the officer:\n\n“‘Mr. Radney, I will not obey you. Take that hammer away, or look to\nyourself.’ But the predestinated mate coming", "labels": {"50": 37, "100": 64, "250": 163, "500": 363, "1000": 54, "2000": 324}}, {"id": 3765, "position": 3765, "text": ", or look to\nyourself.’ But the predestinated mate coming still closer to him, where\nthe Lakeman stood fixed, now shook the heavy hammer within an inch of\nhis teeth; meanwhile repeating a string of insufferable maledict", "labels": {"50": 23, "100": 88, "250": 19, "500": 163, "1000": 383, "2000": 1066}}, {"id": 3766, "position": 3766, "text": "of\nhis teeth; meanwhile repeating a string of insufferable maledictions.\nRetreating not the thousandth part of an inch; stabbing him in the eye\nwith the unflinching poniard of his glance, Steelkilt, clenching", "labels": {"50": 23, "100": 17, "250": 160, "500": 358, "1000": 485, "2000": 1002}}, {"id": 3767, "position": 3767, "text": "flinching poniard of his glance, Steelkilt, clenching his\nright hand behind him and creepingly drawing it back, told his\npersecutor that if the hammer but grazed his cheek he (Steelkilt) would\nmurder him", "labels": {"50": 37, "100": 55, "250": 95, "500": 227, "1000": 580, "2000": 65}}, {"id": 3768, "position": 3768, "text": "the hammer but grazed his cheek he (Steelkilt) would\nmurder him. But, gentlemen, the fool had been branded for the slaughter\nby the gods. Immediately the hammer touched the cheek; the next instant\nthe lower jaw of the mate was stove", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 531, "2000": 1904}}, {"id": 3769, "position": 3769, "text": "touched the cheek; the next instant\nthe lower jaw of the mate was stove in his head; he fell on the hatch\nspouting blood like a whale.\n\n“Ere the cry could go aft Steelkilt was shaking one of the backsta", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 3770, "position": 3770, "text": "the cry could go aft Steelkilt was shaking one of the backstays\nleading far aloft to where two of his comrades were standing their\nmastheads. They were both Canallers.\n\n“‘Canallers!’ cried Don Pedro", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 3771, "position": 3771, "text": "Canallers.\n\n“‘Canallers!’ cried Don Pedro. ‘We have seen many whale-ships in our\nharbours, but never heard of your Canallers. Pardon: who and what are\nthey?’", "labels": {"50": 45, "100": 19, "250": 22, "500": 364, "1000": 730, "2000": 1814}}, {"id": 3772, "position": 3772, "text": ": who and what are\nthey?’\n\n“‘Canallers, Don, are the boatmen belonging to our grand Erie Canal.\nYou must have heard of it.’\n\n“‘Nay, Senor; hereabouts in this dull, warm,", "labels": {"50": 7, "100": 7, "250": 203, "500": 240, "1000": 676, "2000": 862}}, {"id": 3773, "position": 3773, "text": "‘Nay, Senor; hereabouts in this dull, warm, most lazy, and hereditary\nland, we know but little of your vigorous North.’\n\n“‘Aye? Well then, Don, refill my cup", "labels": {"50": 18, "100": 15, "250": 102, "500": 205, "1000": 523, "2000": 1070}}, {"id": 3774, "position": 3774, "text": "? Well then, Don, refill my cup. Your chicha’s very fine; and ere\nproceeding further I will tell ye what our Canallers are; for such\ninformation may throw side-light upon my story.’", "labels": {"50": 25, "100": 15, "250": 180, "500": 18, "1000": 523, "2000": 674}}, {"id": 3775, "position": 3775, "text": "such\ninformation may throw side-light upon my story.’\n\n“For three hundred and sixty miles, gentlemen, through the entire\nbreadth of the state of New York; through numerous populous cities and\nmost thriving villages; through long, dismal, uninhabited", "labels": {"50": 48, "100": 57, "250": 90, "500": 224, "1000": 525, "2000": 525}}, {"id": 3776, "position": 3776, "text": "populous cities and\nmost thriving villages; through long, dismal, uninhabited swamps, and\naffluent, cultivated fields, unrivalled for fertility; by billiard-room\nand bar-room; through the holy-of-holies of great", "labels": {"50": 45, "100": 38, "250": 137, "500": 13, "1000": 525, "2000": 1264}}, {"id": 3777, "position": 3777, "text": "and bar-room; through the holy-of-holies of great forests; on Roman\narches over Indian rivers; through sun and shade; by happy hearts or\nbroken; through all the wide contrasting scenery of those noble Mohawk\ncounties; and especially,", "labels": {"50": 25, "100": 38, "250": 77, "500": 230, "1000": 159, "2000": 1032}}, {"id": 3778, "position": 3778, "text": "through all the wide contrasting scenery of those noble Mohawk\ncounties; and especially, by rows of snow-white chapels, whose spires\nstand almost like milestones, flows one continual stream of Venetianly\ncorrupt and often lawless life", "labels": {"50": 48, "100": 20, "250": 90, "500": 126, "1000": 747, "2000": 532}}, {"id": 3779, "position": 3779, "text": "stream of Venetianly\ncorrupt and often lawless life. There’s your true Ashantee, gentlemen;\nthere howl your pagans; where you ever find them, next door to you;\nunder the long-flung shadow, and the snu", "labels": {"50": 9, "100": 73, "250": 193, "500": 498, "1000": 637, "2000": 421}}, {"id": 3780, "position": 3780, "text": "door to you;\nunder the long-flung shadow, and the snug patronising lee of churches.\nFor by some curious fatality, as it is often noted of your metropolitan\nfreebooters that they ever encamp around the halls of justice", "labels": {"50": 16, "100": 73, "250": 193, "500": 498, "1000": 637, "2000": 1886}}, {"id": 3781, "position": 3781, "text": "your metropolitan\nfreebooters that they ever encamp around the halls of justice, so\nsinners, gentlemen, most abound in holiest vicinities.\n\n“‘Is that a friar passing?’ said Don Pedro, looking downwards into the\ncrowded", "labels": {"50": 18, "100": 87, "250": 102, "500": 61, "1000": 621, "2000": 1214}}, {"id": 3782, "position": 3782, "text": "that a friar passing?’ said Don Pedro, looking downwards into the\ncrowded plazza, with humorous concern.\n\n“‘Well for our northern friend, Dame Isabella’s Inquisition wanes in\nLima,’ laughed Don Sebastian", "labels": {"50": 49, "100": 15, "250": 22, "500": 364, "1000": 706, "2000": 1070}}, {"id": 3783, "position": 3783, "text": "Inquisition wanes in\nLima,’ laughed Don Sebastian. ‘Proceed, Senor.’\n\n“‘A moment! Pardon!’ cried another of the company. ‘In the name of all\nus Limeese, I but desire to express to you,", "labels": {"50": 23, "100": 15, "250": 22, "500": 364, "1000": 317, "2000": 674}}, {"id": 3784, "position": 3784, "text": "name of all\nus Limeese, I but desire to express to you, sir sailor, that we have by\nno means overlooked your delicacy in not substituting present Lima for\ndistant Venice in your corrupt comparison", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1014}}, {"id": 3785, "position": 3785, "text": "for\ndistant Venice in your corrupt comparison. Oh! do not bow and look\nsurprised; you know the proverb all along this coast—“Corrupt as Lima.”\nIt but bears out your saying, too; churches more plentiful than\nbilliard", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 637, "2000": 1886}}, {"id": 3786, "position": 3786, "text": "bears out your saying, too; churches more plentiful than\nbilliard-tables, and for ever open—and “Corrupt as Lima.” So, too,\nVenice; I have been there; the holy city of the blessed evangelist, St", "labels": {"50": 49, "100": 74, "250": 223, "500": 339, "1000": 867, "2000": 374}}, {"id": 3787, "position": 3787, "text": "; I have been there; the holy city of the blessed evangelist, St.\nMark!—St. Dominic, purge it! Your cup! Thanks: here I refill; now, you\npour out again.’", "labels": {"50": 49, "100": 74, "250": 126, "500": 195, "1000": 330, "2000": 1512}}, {"id": 3788, "position": 3788, "text": "; now, you\npour out again.’\n\n“Freely depicted in his own vocation, gentlemen, the Canaller would\nmake a fine dramatic hero, so abundantly and picturesquely wicked is\nhe. Like Mark Antony, for days and days along his", "labels": {"50": 30, "100": 8, "250": 183, "500": 240, "1000": 676, "2000": 621}}, {"id": 3789, "position": 3789, "text": "ly wicked is\nhe. Like Mark Antony, for days and days along his green-turfed, flowery\nNile, he indolently floats, openly toying with his red-cheeked\nCleopatra, ripening his apricot thigh upon the", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 1203}}, {"id": 3790, "position": 3790, "text": "red-cheeked\nCleopatra, ripening his apricot thigh upon the sunny deck. But ashore,\nall this effeminacy is dashed. The brigandish guise which the Canaller\nso proudly sports; his slouched and gaily", "labels": {"50": 31, "100": 7, "250": 49, "500": 78, "1000": 387, "2000": 1081}}, {"id": 3791, "position": 3791, "text": "which the Canaller\nso proudly sports; his slouched and gaily-ribboned hat betoken his\ngrand features. A terror to the smiling innocence of the villages\nthrough which he floats; his swart visage and bold swagger are", "labels": {"50": 48, "100": 20, "250": 59, "500": 439, "1000": 260, "2000": 535}}, {"id": 3792, "position": 3792, "text": "through which he floats; his swart visage and bold swagger are not\nunshunned in cities. Once a vagabond on his own canal, I have received\ngood turns from one of these Canallers; I thank him heart", "labels": {"50": 8, "100": 14, "250": 132, "500": 450, "1000": 27, "2000": 1037}}, {"id": 3793, "position": 3793, "text": "have received\ngood turns from one of these Canallers; I thank him heartily; would\nfain be not ungrateful; but it is often one of the prime redeeming\nqualities of your man of violence, that at times he has as", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 290, "2000": 962}}, {"id": 3794, "position": 3794, "text": "eeming\nqualities of your man of violence, that at times he has as stiff an arm\nto back a poor stranger in a strait, as to plunder a wealthy one. In\nsum, gentlemen, what the wildness of this canal life is,", "labels": {"50": 23, "100": 87, "250": 219, "500": 205, "1000": 317, "2000": 1087}}, {"id": 3795, "position": 3795, "text": "In\nsum, gentlemen, what the wildness of this canal life is, is\nemphatically evinced by this; that our wild whale-fishery contains so\nmany of its most finished graduates, and that scarce any race of\nmankind, except Sydney", "labels": {"50": 45, "100": 29, "250": 34, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3796, "position": 3796, "text": "its most finished graduates, and that scarce any race of\nmankind, except Sydney men, are so much distrusted by our whaling\ncaptains. Nor does it at all diminish the curiousness of this matter,\nthat to many thousands of our rural boys", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 723, "2000": 489}}, {"id": 3797, "position": 3797, "text": "the curiousness of this matter,\nthat to many thousands of our rural boys and young men born along its\nline, the probationary life of the Grand Canal furnishes the sole\ntransition between quietly reaping in a Christian corn-field, and", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 525, "2000": 1934}}, {"id": 3798, "position": 3798, "text": "sole\ntransition between quietly reaping in a Christian corn-field, and\nrecklessly ploughing the waters of the most barbaric seas.\n\n“‘I see! I see!’ impetuously exclaimed Don Pedro, spilling his chicha", "labels": {"50": 49, "100": 15, "250": 22, "500": 364, "1000": 498, "2000": 1174}}, {"id": 3799, "position": 3799, "text": "I see!’ impetuously exclaimed Don Pedro, spilling his chicha\nupon his silvery ruffles. ‘No need to travel! The world’s one Lima. I\nhad thought, now, that at your temperate North the generations were\ncold", "labels": {"50": 12, "100": 19, "250": 78, "500": 379, "1000": 782, "2000": 1263}}, {"id": 3800, "position": 3800, "text": "I\nhad thought, now, that at your temperate North the generations were\ncold and holy as the hills.—But the story.’\n\n“I left off, gentlemen, where the Lakeman shook the backstay", "labels": {"50": 25, "100": 41, "250": 91, "500": 407, "1000": 483, "2000": 1199}}, {"id": 3801, "position": 3801, "text": "the Lakeman shook the backstay. Hardly\nhad he done so, when he was surrounded by the three junior mates and\nthe four harpooneers, who all crowded him to the deck. But sliding down\nthe ropes like baleful comets,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 3802, "position": 3802, "text": "to the deck. But sliding down\nthe ropes like baleful comets, the two Canallers rushed into the\nuproar, and sought to drag their man out of it towards the forecastle.\nOthers of the sailors joined with them in this attempt", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 642, "2000": 282}}, {"id": 3803, "position": 3803, "text": "towards the forecastle.\nOthers of the sailors joined with them in this attempt, and a twisted\nturmoil ensued; while standing out of harm’s way, the valiant captain\ndanced up and down with a whale-pike, calling upon his officers to\nman", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 3804, "position": 3804, "text": "up and down with a whale-pike, calling upon his officers to\nmanhandle that atrocious scoundrel, and smoke him along to the\nquarter-deck. At intervals, he ran close up to the revolving border of\nthe confusion,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3805, "position": 3805, "text": "At intervals, he ran close up to the revolving border of\nthe confusion, and prying into the heart of it with his pike, sought to\nprick out the object of his resentment. But Steelkilt and his\ndesperadoes were too much", "labels": {"50": 37, "100": 55, "250": 145, "500": 444, "1000": 661, "2000": 314}}, {"id": 3806, "position": 3806, "text": "resentment. But Steelkilt and his\ndesperadoes were too much for them all; they succeeded in gaining the\nforecastle deck, where, hastily slewing about three or four large casks\nin a line with the windlass, these", "labels": {"50": 45, "100": 64, "250": 82, "500": 28, "1000": 327, "2000": 967}}, {"id": 3807, "position": 3807, "text": "three or four large casks\nin a line with the windlass, these sea-Parisians entrenched themselves\nbehind the barricade.\n\n“‘Come out of that, ye pirates!’ roared the captain, now menacing them\nwith a pistol", "labels": {"50": 45, "100": 64, "250": 11, "500": 479, "1000": 642, "2000": 967}}, {"id": 3808, "position": 3808, "text": ", ye pirates!’ roared the captain, now menacing them\nwith a pistol in each hand, just brought to him by the steward. ‘Come\nout of that, ye cut-throats!’\n\n“Steelkilt leaped on the barricade", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 642, "2000": 967}}, {"id": 3809, "position": 3809, "text": "-throats!’\n\n“Steelkilt leaped on the barricade, and striding up and down there,\ndefied the worst the pistols could do; but gave the captain to\nunderstand distinctly, that his (Steelkilt’s)", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 642, "2000": 324}}, {"id": 3810, "position": 3810, "text": "the captain to\nunderstand distinctly, that his (Steelkilt’s) death would be the signal\nfor a murderous mutiny on the part of all hands. Fearing in his heart\nlest this might prove but too true, the captain a little desisted", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 558}}, {"id": 3811, "position": 3811, "text": "lest this might prove but too true, the captain a little desisted, but\nstill commanded the insurgents instantly to return to their duty.\n\n“‘Will you promise not to touch us, if we do?’ demanded their\nringleader.", "labels": {"50": 1, "100": 49, "250": 185, "500": 375, "1000": 733, "2000": 830}}, {"id": 3812, "position": 3812, "text": "touch us, if we do?’ demanded their\nringleader.\n\n“‘Turn to! turn to!—I make no promise;—to your duty! Do you want to\nsink the ship, by knocking off at a time like this? Turn", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3813, "position": 3813, "text": "to\nsink the ship, by knocking off at a time like this? Turn to!’ and he\nonce more raised a pistol.\n\n“‘Sink the ship?’ cried Steelkilt. ‘Aye, let her sink", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 642, "2000": 324}}, {"id": 3814, "position": 3814, "text": "kilt. ‘Aye, let her sink. Not a man of us\nturns to, unless you swear not to raise a rope-yarn against us. What\nsay ye, men?’ turning to his comrades. A fierce cheer was their\nresponse.", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 642, "2000": 324}}, {"id": 3815, "position": 3815, "text": "men?’ turning to his comrades. A fierce cheer was their\nresponse.\n\n“The Lakeman now patrolled the barricade, all the while keeping his eye\non the Captain, and jerking out such sentences as these:—‘It’s", "labels": {"50": 37, "100": 99, "250": 145, "500": 9, "1000": 593, "2000": 1782}}, {"id": 3816, "position": 3816, "text": "Captain, and jerking out such sentences as these:—‘It’s not our\nfault; we didn’t want it; I told him to take his hammer away; it was\nboy’s business; he might have known me before this;", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3817, "position": 3817, "text": "it was\nboy’s business; he might have known me before this; I told him not to\nprick the buffalo; I believe I have broken a finger here against his\ncursed jaw; ain’t those mincing knives down in the forecastle there", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 3818, "position": 3818, "text": "jaw; ain’t those mincing knives down in the forecastle there,\nmen? look to those handspikes, my hearties. Captain, by God, look to\nyourself; say the word; don’t be a fool; forget", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3819, "position": 3819, "text": "to\nyourself; say the word; don’t be a fool; forget it all; we are ready to\nturn to; treat us decently, and we’re your men; but we won’t be\nflogged.’", "labels": {"50": 34, "100": 77, "250": 164, "500": 89, "1000": 992, "2000": 1407}}, {"id": 3820, "position": 3820, "text": "men; but we won’t be\nflogged.’\n\n“‘Turn to! I make no promises, turn to, I say!’\n\n“‘Look ye, now,’ cried the Lakeman, flinging out his arm towards him", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 925, "2000": 967}}, {"id": 3821, "position": 3821, "text": "now,’ cried the Lakeman, flinging out his arm towards him,\n‘there are a few of us here (and I am one of them) who have shipped for\nthe cruise, d’ye see; now as you well know,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 3822, "position": 3822, "text": "for\nthe cruise, d’ye see; now as you well know, sir, we can claim our\ndischarge as soon as the anchor is down; so we don’t want a row; it’s\nnot our interest; we want to be", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3823, "position": 3823, "text": "want a row; it’s\nnot our interest; we want to be peaceable; we are ready to work, but we\nwon’t be flogged.’\n\n“‘Turn to!’ roared the Captain.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 3824, "position": 3824, "text": "“‘Turn to!’ roared the Captain.\n\n“Steelkilt glanced round him a moment, and then said:—‘I tell you what\nit is now, Captain, rather than kill ye, and be hung for such a shabby\nras", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 3825, "position": 3825, "text": ", rather than kill ye, and be hung for such a shabby\nrascal, we won’t lift a hand against ye unless ye attack us; but till\nyou say the word about not flogging us, we don’t do a", "labels": {"50": 43, "100": 48, "250": 145, "500": 180, "1000": 687, "2000": 1691}}, {"id": 3826, "position": 3826, "text": "the word about not flogging us, we don’t do a hand’s turn.’\n\n“‘Down into the forecastle then, down with ye, I’ll keep ye there till\nye’re sick of it", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 3827, "position": 3827, "text": "’ll keep ye there till\nye’re sick of it. Down ye go.’\n\n“‘Shall we?’ cried the ringleader to his men. Most of them were against\nit; but at length, in obedience to Steelkilt,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 3828, "position": 3828, "text": "were against\nit; but at length, in obedience to Steelkilt, they preceded him down\ninto their dark den, growlingly disappearing, like bears into a cave.\n\n“As the Lakeman’s bare head was just level with the planks", "labels": {"50": 37, "100": 55, "250": 95, "500": 60, "1000": 377, "2000": 65}}, {"id": 3829, "position": 3829, "text": "As the Lakeman’s bare head was just level with the planks, the Captain\nand his posse leaped the barricade, and rapidly drawing over the slide\nof the scuttle, planted their group of hands upon it, and loudly called", "labels": {"50": 45, "100": 64, "250": 145, "500": 479, "1000": 642, "2000": 324}}, {"id": 3830, "position": 3830, "text": "scuttle, planted their group of hands upon it, and loudly called\nfor the steward to bring the heavy brass padlock belonging to the\ncompanionway. Then opening the slide a little, the Captain whispered\nsomething down the crack, closed it, and", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 642, "2000": 1668}}, {"id": 3831, "position": 3831, "text": "a little, the Captain whispered\nsomething down the crack, closed it, and turned the key upon them—ten\nin number—leaving on deck some twenty or more, who thus far had\nremained neutral.\n\n“All night a wide-awake watch was kept", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 3832, "position": 3832, "text": "far had\nremained neutral.\n\n“All night a wide-awake watch was kept by all the officers, forward and\naft, especially about the forecastle scuttle and fore hatchway; at\nwhich last place it was feared the insurgents might emerge, after", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3833, "position": 3833, "text": "way; at\nwhich last place it was feared the insurgents might emerge, after\nbreaking through the bulkhead below. But the hours of darkness passed\nin peace; the men who still remained at their duty toiling hard at the\npumps, whose clinking and", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 642, "2000": 1904}}, {"id": 3834, "position": 3834, "text": "remained at their duty toiling hard at the\npumps, whose clinking and clanking at intervals through the dreary\nnight dismally resounded through the ship.\n\n“At sunrise the Captain went forward, and knocking on the deck,\nsummoned the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 3835, "position": 3835, "text": "At sunrise the Captain went forward, and knocking on the deck,\nsummoned the prisoners to work; but with a yell they refused. Water was\nthen lowered down to them, and a couple of handfuls of biscuit were\ntossed after it; when again", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 3836, "position": 3836, "text": "a couple of handfuls of biscuit were\ntossed after it; when again turning the key upon them and pocketing it,\nthe Captain returned to the quarter-deck. Twice every day for three\ndays this was repeated; but on the fourth morning a", "labels": {"50": 45, "100": 64, "250": 163, "500": 239, "1000": 851, "2000": 1584}}, {"id": 3837, "position": 3837, "text": "every day for three\ndays this was repeated; but on the fourth morning a confused wrangling,\nand then a scuffling was heard, as the customary summons was delivered;\nand suddenly four men burst up from the forecastle, saying they", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 967}}, {"id": 3838, "position": 3838, "text": "delivered;\nand suddenly four men burst up from the forecastle, saying they were\nready to turn to. The fetid closeness of the air, and a famishing diet,\nunited perhaps to some fears of ultimate retribution, had constrained\nthem to", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 642, "2000": 967}}, {"id": 3839, "position": 3839, "text": "diet,\nunited perhaps to some fears of ultimate retribution, had constrained\nthem to surrender at discretion. Emboldened by this, the Captain\nreiterated his demand to the rest, but Steelkilt shouted up to him a\nterrific hint to stop his babbling", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 3840, "position": 3840, "text": "Steelkilt shouted up to him a\nterrific hint to stop his babbling and betake himself where he\nbelonged. On the fifth morning three others of the mutineers bolted up\ninto the air from the desperate arms below that sought to restrain\nthem", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 642, "2000": 324}}, {"id": 3841, "position": 3841, "text": "up\ninto the air from the desperate arms below that sought to restrain\nthem. Only three were left.\n\n“‘Better turn to, now?’ said the Captain with a heartless jeer.\n\n“‘Shut us up again, will ye!’", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 324}}, {"id": 3842, "position": 3842, "text": "less jeer.\n\n“‘Shut us up again, will ye!’ cried Steelkilt.\n\n“‘Oh certainly,’ said the Captain, and the key clicked.\n\n“It was at this point, gentlemen, that enraged by the defection", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 3843, "position": 3843, "text": "“It was at this point, gentlemen, that enraged by the defection of\nseven of his former associates, and stung by the mocking voice that had\nlast hailed him, and maddened by his long entombment in a place as\nblack as", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 142}}, {"id": 3844, "position": 3844, "text": "maddened by his long entombment in a place as\nblack as the bowels of despair; it was then that Steelkilt proposed to\nthe two Canallers, thus far apparently of one mind with him, to burst\nout of their hole", "labels": {"50": 45, "100": 64, "250": 138, "500": 14, "1000": 485, "2000": 1002}}, {"id": 3845, "position": 3845, "text": "thus far apparently of one mind with him, to burst\nout of their hole at the next summoning of the garrison; and armed with\ntheir keen mincing knives (long, crescentic, heavy implements with a\nhandle at each end) run amuck", "labels": {"50": 18, "100": 87, "250": 102, "500": 205, "1000": 62, "2000": 1699}}, {"id": 3846, "position": 3846, "text": "crescentic, heavy implements with a\nhandle at each end) run amuck from the bowsprit to the taffrail; and if\nby any devilishness of desperation possible, seize the ship. For\nhimself, he would do this, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 3847, "position": 3847, "text": "possible, seize the ship. For\nhimself, he would do this, he said, whether they joined him or not.\nThat was the last night he should spend in that den. But the scheme met\nwith no opposition on the part of the other two", "labels": {"50": 45, "100": 64, "250": 28, "500": 28, "1000": 642, "2000": 558}}, {"id": 3848, "position": 3848, "text": ". But the scheme met\nwith no opposition on the part of the other two; they swore they were\nready for that, or for any other mad thing, for anything in short but a\nsurrender. And what was more, they each insisted upon being the", "labels": {"50": 37, "100": 11, "250": 171, "500": 384, "1000": 639, "2000": 325}}, {"id": 3849, "position": 3849, "text": "but a\nsurrender. And what was more, they each insisted upon being the first\nman on deck, when the time to make the rush should come. But to this\ntheir leader as fiercely objected, reserving that priority for himself;\nparticularly as his two", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 642, "2000": 1904}}, {"id": 3850, "position": 3850, "text": "as fiercely objected, reserving that priority for himself;\nparticularly as his two comrades would not yield, the one to the other,\nin the matter; and both of them could not be first, for the ladder\nwould but admit one man at a time", "labels": {"50": 45, "100": 29, "250": 82, "500": 384, "1000": 139, "2000": 801}}, {"id": 3851, "position": 3851, "text": "not be first, for the ladder\nwould but admit one man at a time. And here, gentlemen, the foul play\nof these miscreants must come out.\n\n“Upon hearing the frantic project of their leader, each in his own\nseparate soul had", "labels": {"50": 45, "100": 64, "250": 11, "500": 479, "1000": 642, "2000": 1691}}, {"id": 3852, "position": 3852, "text": "hearing the frantic project of their leader, each in his own\nseparate soul had suddenly lighted, it would seem, upon the same piece\nof treachery, namely: to be foremost in breaking out, in order to be\nthe first of the three,", "labels": {"50": 45, "100": 64, "250": 11, "500": 479, "1000": 737, "2000": 924}}, {"id": 3853, "position": 3853, "text": "foremost in breaking out, in order to be\nthe first of the three, though the last of the ten, to surrender; and\nthereby secure whatever small chance of pardon such conduct might\nmerit. But when Steelkilt made known his determination still to lead", "labels": {"50": 37, "100": 55, "250": 145, "500": 479, "1000": 959, "2000": 1691}}, {"id": 3854, "position": 3854, "text": "might\nmerit. But when Steelkilt made known his determination still to lead\nthem to the last, they in some way, by some subtle chemistry of\nvillany, mixed their before secret treacheries together; and when their\nleader fell into a do", "labels": {"50": 37, "100": 55, "250": 145, "500": 185, "1000": 959, "2000": 29}}, {"id": 3855, "position": 3855, "text": "before secret treacheries together; and when their\nleader fell into a doze, verbally opened their souls to each other in\nthree sentences; and bound the sleeper with cords, and gagged him with\ncords; and shrieked out for the Captain at", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 1766}}, {"id": 3856, "position": 3856, "text": ", and gagged him with\ncords; and shrieked out for the Captain at midnight.\n\n“Thinking murder at hand, and smelling in the dark for the blood, he\nand all his armed mates and harpooneers rushed for the forecastle", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 3857, "position": 3857, "text": "his armed mates and harpooneers rushed for the forecastle. In a\nfew minutes the scuttle was opened, and, bound hand and foot, the still\nstruggling ringleader was shoved up into the air by his perfidious\nallies,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 642, "2000": 1904}}, {"id": 3858, "position": 3858, "text": "leader was shoved up into the air by his perfidious\nallies, who at once claimed the honor of securing a man who had been\nfully ripe for murder. But all these were collared, and dragged along\nthe deck like dead cattle; and", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1584}}, {"id": 3859, "position": 3859, "text": "these were collared, and dragged along\nthe deck like dead cattle; and, side by side, were seized up into the\nmizzen rigging, like three quarters of meat, and there they hung till\nmorning", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1192}}, {"id": 3860, "position": 3860, "text": "meat, and there they hung till\nmorning. ‘Damn ye,’ cried the Captain, pacing to and fro before them,\n‘the vultures would not touch ye, ye villains!’\n\n“At sunrise he summoned all hands; and separating those", "labels": {"50": 18, "100": 55, "250": 182, "500": 180, "1000": 672, "2000": 1885}}, {"id": 3861, "position": 3861, "text": "ye villains!’\n\n“At sunrise he summoned all hands; and separating those who had\nrebelled from those who had taken no part in the mutiny, he told the\nformer that he had a good mind to flog them all round—thought, upon the", "labels": {"50": 18, "100": 15, "250": 104, "500": 493, "1000": 595, "2000": 77}}, {"id": 3862, "position": 3862, "text": "had a good mind to flog them all round—thought, upon the\nwhole, he would do so—he ought to—justice demanded it; but for the\npresent, considering their timely surrender, he would let them go with\na reprimand", "labels": {"50": 22, "100": 78, "250": 11, "500": 316, "1000": 322, "2000": 1102}}, {"id": 3863, "position": 3863, "text": "considering their timely surrender, he would let them go with\na reprimand, which he accordingly administered in the vernacular.\n\n“‘But as for you, ye carrion rogues,’ turning to the three men in the\nrigging—‘for", "labels": {"50": 18, "100": 87, "250": 37, "500": 180, "1000": 851, "2000": 324}}, {"id": 3864, "position": 3864, "text": "s,’ turning to the three men in the\nrigging—‘for you, I mean to mince ye up for the try-pots;’ and, seizing\na rope, he applied it with all his might to the backs of the two", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3865, "position": 3865, "text": "rope, he applied it with all his might to the backs of the two\ntraitors, till they yelled no more, but lifelessly hung their heads\nsideways, as the two crucified thieves are drawn.", "labels": {"50": 22, "100": 55, "250": 11, "500": 479, "1000": 475, "2000": 351}}, {"id": 3866, "position": 3866, "text": "crucified thieves are drawn.\n\n“‘My wrist is sprained with ye!’ he cried, at last; ‘but there is still\nrope enough left for you, my fine bantam, that wouldn’t give up", "labels": {"50": 23, "100": 88, "250": 219, "500": 180, "1000": 627, "2000": 1091}}, {"id": 3867, "position": 3867, "text": "my fine bantam, that wouldn’t give up. Take\nthat gag from his mouth, and let us hear what he can say for himself.’\n\n“For a moment the exhausted mutineer made a tremulous motion of his\ncramped jaws", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3868, "position": 3868, "text": "the exhausted mutineer made a tremulous motion of his\ncramped jaws, and then painfully twisting round his head, said in a\nsort of hiss, ‘What I say is this—and mind it well—if you flog me, I", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3869, "position": 3869, "text": "is this—and mind it well—if you flog me, I\nmurder you!’\n\n“‘Say ye so? then see how ye frighten me’—and the Captain drew off with\nthe rope to strike.", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 3870, "position": 3870, "text": "the Captain drew off with\nthe rope to strike.\n\n“‘Best not,’ hissed the Lakeman.\n\n“‘But I must,’—and the rope was once more drawn back for the stroke.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 3871, "position": 3871, "text": "drawn back for the stroke.\n\n“Steelkilt here hissed out something, inaudible to all but the Captain;\nwho, to the amazement of all hands, started back, paced the deck\nrapidly two or three times, and then suddenly throwing down", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 3872, "position": 3872, "text": ", paced the deck\nrapidly two or three times, and then suddenly throwing down his rope,\nsaid, ‘I won’t do it—let him go—cut him down: d’ye hear?’", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 3873, "position": 3873, "text": ": d’ye hear?’\n\n“But as the junior mates were hurrying to execute the order, a pale\nman, with a bandaged head, arrested them—Radney the chief mate. Ever\nsince the blow, he had lain in", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 3874, "position": 3874, "text": "ney the chief mate. Ever\nsince the blow, he had lain in his berth; but that morning, hearing the\ntumult on the deck, he had crept out, and thus far had watched the\nwhole scene", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 3875, "position": 3875, "text": ", and thus far had watched the\nwhole scene. Such was the state of his mouth, that he could hardly\nspeak; but mumbling something about _his_ being willing and able to do\nwhat the captain dared not attempt, he snatched the rope and", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 3876, "position": 3876, "text": "able to do\nwhat the captain dared not attempt, he snatched the rope and advanced\nto his pinioned foe.\n\n“‘You are a coward!’ hissed the Lakeman.\n\n“‘So I am, but take that.’ The mate was in", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 3877, "position": 3877, "text": "“‘So I am, but take that.’ The mate was in the very act of striking,\nwhen another hiss stayed his uplifted arm. He paused: and then pausing\nno more, made good his word, spite of Steelkilt", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 3878, "position": 3878, "text": "then pausing\nno more, made good his word, spite of Steelkilt’s threat, whatever that\nmight have been. The three men were then cut down, all hands were\nturned to, and, sullenly worked by the moody seamen,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 642, "2000": 324}}, {"id": 3879, "position": 3879, "text": "were\nturned to, and, sullenly worked by the moody seamen, the iron pumps\nclanged as before.\n\n“Just after dark that day, when one watch had retired below, a clamor\nwas heard in the forecastle; and the", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 3880, "position": 3880, "text": "below, a clamor\nwas heard in the forecastle; and the two trembling traitors running up,\nbesieged the cabin door, saying they durst not consort with the crew.\nEntreaties, cuffs, and kicks could not drive them", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3881, "position": 3881, "text": "crew.\nEntreaties, cuffs, and kicks could not drive them back, so at their own\ninstance they were put down in the ship’s run for salvation. Still, no\nsign of mutiny reappeared among the rest", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 327, "2000": 1584}}, {"id": 3882, "position": 3882, "text": "Still, no\nsign of mutiny reappeared among the rest. On the contrary, it seemed,\nthat mainly at Steelkilt’s instigation, they had resolved to maintain\nthe strictest peacefulness, obey all orders to the last, and,", "labels": {"50": 12, "100": 43, "250": 209, "500": 344, "1000": 554, "2000": 207}}, {"id": 3883, "position": 3883, "text": "the strictest peacefulness, obey all orders to the last, and, when the\nship reached port, desert her in a body. But in order to insure the\nspeediest end to the voyage, they all agreed to another thing—namely,", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 723, "2000": 576}}, {"id": 3884, "position": 3884, "text": "iest end to the voyage, they all agreed to another thing—namely,\nnot to sing out for whales, in case any should be discovered. For,\nspite of her leak, and spite of all her other perils, the Town-Ho still", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3885, "position": 3885, "text": ", and spite of all her other perils, the Town-Ho still\nmaintained her mast-heads, and her captain was just as willing to lower\nfor a fish that moment, as on the day his craft first struck the\ncruising ground; and Ra", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 3886, "position": 3886, "text": ", as on the day his craft first struck the\ncruising ground; and Radney the mate was quite as ready to change his\nberth for a boat, and with his bandaged mouth seek to gag in death the\nvital jaw of the whale.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3887, "position": 3887, "text": "d mouth seek to gag in death the\nvital jaw of the whale.\n\n“But though the Lakeman had induced the seamen to adopt this sort of\npassiveness in their conduct, he kept his own counsel (at least till\nall was over) concerning his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3888, "position": 3888, "text": "he kept his own counsel (at least till\nall was over) concerning his own proper and private revenge upon the\nman who had stung him in the ventricles of his heart. He was in Radney\nthe chief mate’s watch; and", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 3889, "position": 3889, "text": ". He was in Radney\nthe chief mate’s watch; and as if the infatuated man sought to run more\nthan half way to meet his doom, after the scene at the rigging, he\ninsisted, against the express counsel of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3890, "position": 3890, "text": "the scene at the rigging, he\ninsisted, against the express counsel of the captain, upon resuming the\nhead of his watch at night. Upon this, and one or two other\ncircumstances, Steelkilt systematically built the plan of his revenge.", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3891, "position": 3891, "text": "two other\ncircumstances, Steelkilt systematically built the plan of his revenge.\n\n“During the night, Radney had an unseamanlike way of sitting on the\nbulwarks of the quarter-deck, and leaning his arm upon the", "labels": {"50": 37, "100": 64, "250": 145, "500": 127, "1000": 927, "2000": 1154}}, {"id": 3892, "position": 3892, "text": "lwarks of the quarter-deck, and leaning his arm upon the gunwale of\nthe boat which was hoisted up there, a little above the ship’s side. In\nthis attitude, it was well known, he sometimes dozed", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3893, "position": 3893, "text": ". In\nthis attitude, it was well known, he sometimes dozed. There was a\nconsiderable vacancy between the boat and the ship, and down between\nthis was the sea. Steelkilt calculated his time, and found that his\nnext trick at the", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 3894, "position": 3894, "text": "Steelkilt calculated his time, and found that his\nnext trick at the helm would come round at two o’clock, in the morning\nof the third day from that in which he had been betrayed. At his\nleisure, he employed the interval in", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 576}}, {"id": 3895, "position": 3895, "text": "which he had been betrayed. At his\nleisure, he employed the interval in braiding something very carefully\nin his watches below.\n\n“‘What are you making there?’ said a shipmate.\n\n“‘What do you think? what does it look", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 3896, "position": 3896, "text": "a shipmate.\n\n“‘What do you think? what does it look like?’\n\n“‘Like a lanyard for your bag; but it’s an odd one, seems to me.’", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 786}}, {"id": 3897, "position": 3897, "text": ", seems to me.’\n\n“‘Yes, rather oddish,’ said the Lakeman, holding it at arm’s length\nbefore him; ‘but I think it will answer. Shipmate, I haven’t enough\ntwine,—", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 3898, "position": 3898, "text": "will answer. Shipmate, I haven’t enough\ntwine,—have you any?’\n\n“But there was none in the forecastle.\n\n“‘Then I must get some from old Rad;’ and he rose to go aft.", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 3899, "position": 3899, "text": "get some from old Rad;’ and he rose to go aft.\n\n“‘You don’t mean to go a begging to _him!_’ said a sailor.\n\n“‘Why not? Do you think he won’t do me", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3900, "position": 3900, "text": ".\n\n“‘Why not? Do you think he won’t do me a turn, when it’s to help\nhimself in the end, shipmate?’ and going to the mate, he looked at him\nquietly, and asked him for some", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 3901, "position": 3901, "text": "to the mate, he looked at him\nquietly, and asked him for some twine to mend his hammock. It was given\nhim—neither twine nor lanyard were seen again; but the next night an\niron ball, closely net", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 3902, "position": 3902, "text": "yard were seen again; but the next night an\niron ball, closely netted, partly rolled from the pocket of the\nLakeman’s monkey jacket, as he was tucking the coat into his hammock\nfor a pillow", "labels": {"50": 37, "100": 55, "250": 52, "500": 389, "1000": 129, "2000": 449}}, {"id": 3903, "position": 3903, "text": "the coat into his hammock\nfor a pillow. Twenty-four hours after, his trick at the silent\nhelm—nigh to the man who was apt to doze over the grave always ready\ndug to the seaman’s hand—that fatal", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1904}}, {"id": 3904, "position": 3904, "text": "over the grave always ready\ndug to the seaman’s hand—that fatal hour was then to come; and in the\nfore-ordaining soul of Steelkilt, the mate was already stark and\nstretched as a corpse, with his forehead crushed", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3905, "position": 3905, "text": "the mate was already stark and\nstretched as a corpse, with his forehead crushed in.\n\n“But, gentlemen, a fool saved the would-be murderer from the bloody\ndeed he had planned. Yet complete revenge he had, and without being the\navenger", "labels": {"50": 23, "100": 87, "250": 219, "500": 134, "1000": 103, "2000": 610}}, {"id": 3906, "position": 3906, "text": "had planned. Yet complete revenge he had, and without being the\navenger. For by a mysterious fatality, Heaven itself seemed to step in\nto take out of his hands into its own the damning thing he would have\ndone.", "labels": {"50": 22, "100": 78, "250": 19, "500": 184, "1000": 328, "2000": 213}}, {"id": 3907, "position": 3907, "text": "into its own the damning thing he would have\ndone.\n\n“It was just between daybreak and sunrise of the morning of the second\nday, when they were washing down the decks, that a stupid Teneriffe\nman, drawing water in the main", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 3908, "position": 3908, "text": "decks, that a stupid Teneriffe\nman, drawing water in the main-chains, all at once shouted out, ‘There\nshe rolls! there she rolls!’ Jesu, what a whale! It was Moby Dick.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3909, "position": 3909, "text": "su, what a whale! It was Moby Dick.\n\n“‘Moby Dick!’ cried Don Sebastian; ‘St. Dominic! Sir sailor, but do\nwhales have christenings? Whom call you Moby Dick?’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3910, "position": 3910, "text": "christenings? Whom call you Moby Dick?’\n\n“‘A very white, and famous, and most deadly immortal monster, Don;—but\nthat would be too long a story.’\n\n“‘How? how?’ cried all the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 3911, "position": 3911, "text": "long a story.’\n\n“‘How? how?’ cried all the young Spaniards, crowding.\n\n“‘Nay, Dons, Dons—nay, nay! I cannot rehearse that now", "labels": {"50": 49, "100": 15, "250": 22, "500": 364, "1000": 523, "2000": 674}}, {"id": 3912, "position": 3912, "text": "I cannot rehearse that now. Let me get more\ninto the air, Sirs.’\n\n“‘The chicha! the chicha!’ cried Don Pedro; ‘our vigorous friend looks\nfaint;—fill up his empty glass!’", "labels": {"50": 20, "100": 15, "250": 22, "500": 364, "1000": 284, "2000": 1123}}, {"id": 3913, "position": 3913, "text": "‘our vigorous friend looks\nfaint;—fill up his empty glass!’\n\n“No need, gentlemen; one moment, and I proceed.—Now, gentlemen, so\nsuddenly perceiving the snowy whale within fifty yards of the\nship—forgetful", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 1620}}, {"id": 3914, "position": 3914, "text": "perceiving the snowy whale within fifty yards of the\nship—forgetful of the compact among the crew—in the excitement of the\nmoment, the Teneriffe man had instinctively and involuntarily lifted\nhis voice for the monster, though", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3915, "position": 3915, "text": "instinctively and involuntarily lifted\nhis voice for the monster, though for some little time past it had been\nplainly beheld from the three sullen mast-heads. All was now a phrensy", "labels": {"50": 41, "100": 21, "250": 215, "500": 180, "1000": 230, "2000": 380}}, {"id": 3916, "position": 3916, "text": "All was now a phrensy.\n‘The White Whale—the White Whale!’ was the cry from captain, mates, and\nharpooneers, who, undeterred by fearful rumours, were all anxious to\ncapture so famous and precious a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3917, "position": 3917, "text": "red by fearful rumours, were all anxious to\ncapture so famous and precious a fish; while the dogged crew eyed\naskance, and with curses, the appalling beauty of the vast milky mass,\nthat lit up by a horizontal spangling sun", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3918, "position": 3918, "text": "of the vast milky mass,\nthat lit up by a horizontal spangling sun, shifted and glistened like a\nliving opal in the blue morning sea. Gentlemen, a strange fatality\npervades the whole career of these events, as if", "labels": {"50": 16, "100": 78, "250": 26, "500": 414, "1000": 116, "2000": 1265}}, {"id": 3919, "position": 3919, "text": "strange fatality\npervades the whole career of these events, as if verily mapped out\nbefore the world itself was charted. The mutineer was the bowsman of\nthe mate, and when fast to a fish, it was his duty to", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 3920, "position": 3920, "text": "the mate, and when fast to a fish, it was his duty to sit next him,\nwhile Radney stood up with his lance in the prow, and haul in or\nslacken the line, at the word of command", "labels": {"50": 22, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 778}}, {"id": 3921, "position": 3921, "text": "in or\nslacken the line, at the word of command. Moreover, when the four boats\nwere lowered, the mate’s got the start; and none howled more fiercely\nwith delight than did Steelkilt, as he strained at his oar", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 3922, "position": 3922, "text": "with delight than did Steelkilt, as he strained at his oar. After a\nstiff pull, their harpooneer got fast, and, spear in hand, Radney\nsprang to the bow", "labels": {"50": 37, "100": 64, "250": 163, "500": 363, "1000": 251, "2000": 778}}, {"id": 3923, "position": 3923, "text": "dney\nsprang to the bow. He was always a furious man, it seems, in a boat.\nAnd now his bandaged cry was, to beach him on the whale’s topmost back.\nNothing loath, his bowsman hauled him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3924, "position": 3924, "text": "’s topmost back.\nNothing loath, his bowsman hauled him up and up, through a blinding\nfoam that blent two whitenesses together; till of a sudden the boat\nstruck as against a sunken ledge, and keeling over,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 3925, "position": 3925, "text": "sudden the boat\nstruck as against a sunken ledge, and keeling over, spilled out the\nstanding mate. That instant, as he fell on the whale’s slippery back,\nthe boat righted, and was dashed aside by the swell, while Ra", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3926, "position": 3926, "text": "the boat righted, and was dashed aside by the swell, while Radney was\ntossed over into the sea, on the other flank of the whale. He struck\nout through the spray, and, for an instant, was dimly seen through that", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 3927, "position": 3927, "text": "through the spray, and, for an instant, was dimly seen through that\nveil, wildly seeking to remove himself from the eye of Moby Dick. But\nthe whale rushed round in a sudden maelstrom; seized the swimmer\nbetween his jaws; and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3928, "position": 3928, "text": "in a sudden maelstrom; seized the swimmer\nbetween his jaws; and rearing high up with him, plunged headlong again,\nand went down.\n\n“Meantime, at the first tap of the boat’s bottom, the Lakeman had\nslack", "labels": {"50": 22, "100": 55, "250": 145, "500": 28, "1000": 99, "2000": 1111}}, {"id": 3929, "position": 3929, "text": "the first tap of the boat’s bottom, the Lakeman had\nslackened the line, so as to drop astern from the whirlpool; calmly\nlooking on, he thought his own thoughts", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 3930, "position": 3930, "text": ", he thought his own thoughts. But a sudden, terrific,\ndownward jerking of the boat, quickly brought his knife to the line. He\ncut it; and the whale was free. But, at some distance, Moby Dick rose\nagain, with", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1620}}, {"id": 3931, "position": 3931, "text": "free. But, at some distance, Moby Dick rose\nagain, with some tatters of Radney’s red woollen shirt, caught in the\nteeth that had destroyed him. All four boats gave chase again; but the\nwhale eluded", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3932, "position": 3932, "text": "destroyed him. All four boats gave chase again; but the\nwhale eluded them, and finally wholly disappeared.\n\n“In good time, the Town-Ho reached her port—a savage, solitary\nplace—where no civilized creature resided", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 300, "2000": 1584}}, {"id": 3933, "position": 3933, "text": "a savage, solitary\nplace—where no civilized creature resided. There, headed by the\nLakeman, all but five or six of the foremastmen deliberately deserted\namong the palms; eventually, as it turned out, seizing a large double\nwar-", "labels": {"50": 12, "100": 55, "250": 122, "500": 389, "1000": 949, "2000": 1339}}, {"id": 3934, "position": 3934, "text": "palms; eventually, as it turned out, seizing a large double\nwar-canoe of the savages, and setting sail for some other harbor.\n\n“The ship’s company being reduced to but a handful, the captain called\nupon the Islanders to assist", "labels": {"50": 45, "100": 64, "250": 163, "500": 239, "1000": 480, "2000": 52}}, {"id": 3935, "position": 3935, "text": "being reduced to but a handful, the captain called\nupon the Islanders to assist him in the laborious business of heaving\ndown the ship to stop the leak. But to such unresting vigilance over\ntheir dangerous allies was this small band of whites necessitated", "labels": {"50": 45, "100": 64, "250": 138, "500": 494, "1000": 480, "2000": 385}}, {"id": 3936, "position": 3936, "text": "ing vigilance over\ntheir dangerous allies was this small band of whites necessitated, both\nby night and by day, and so extreme was the hard work they underwent,\nthat upon the vessel being ready again for sea, they were in such a\nweakened condition", "labels": {"50": 12, "100": 38, "250": 65, "500": 43, "1000": 954, "2000": 1786}}, {"id": 3937, "position": 3937, "text": "the vessel being ready again for sea, they were in such a\nweakened condition that the captain durst not put off with them in so\nheavy a vessel. After taking counsel with his officers, he anchored the\nship as far off shore as possible; loaded", "labels": {"50": 45, "100": 29, "250": 138, "500": 28, "1000": 300, "2000": 801}}, {"id": 3938, "position": 3938, "text": "his officers, he anchored the\nship as far off shore as possible; loaded and ran out his two cannon\nfrom the bows; stacked his muskets on the poop; and warning the\nIslanders not to approach the ship at their peril, took", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 52}}, {"id": 3939, "position": 3939, "text": "and warning the\nIslanders not to approach the ship at their peril, took one man with\nhim, and setting the sail of his best whale-boat, steered straight\nbefore the wind for Tahiti, five hundred miles distant, to procure a\nreinforcement", "labels": {"50": 45, "100": 64, "250": 138, "500": 494, "1000": 480, "2000": 187}}, {"id": 3940, "position": 3940, "text": "wind for Tahiti, five hundred miles distant, to procure a\nreinforcement to his crew.\n\n“On the fourth day of the sail, a large canoe was descried, which\nseemed to have touched at a low isle of corals", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1766}}, {"id": 3941, "position": 3941, "text": ", which\nseemed to have touched at a low isle of corals. He steered away from\nit; but the savage craft bore down on him; and soon the voice of\nSteelkilt hailed him to heave to, or he would run him under", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1904}}, {"id": 3942, "position": 3942, "text": "kilt hailed him to heave to, or he would run him under water. The\ncaptain presented a pistol. With one foot on each prow of the yoked\nwar-canoes, the Lakeman laughed him to scorn; assuring", "labels": {"50": 37, "100": 55, "250": 95, "500": 28, "1000": 99, "2000": 1111}}, {"id": 3943, "position": 3943, "text": "-canoes, the Lakeman laughed him to scorn; assuring him that if the\npistol so much as clicked in the lock, he would bury him in bubbles and\nfoam.\n\n“‘What do you want of me?’ cried the captain", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 531, "2000": 324}}, {"id": 3944, "position": 3944, "text": "foam.\n\n“‘What do you want of me?’ cried the captain.\n\n“‘Where are you bound? and for what are you bound?’ demanded Steelkilt;\n‘no lies.’", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 324}}, {"id": 3945, "position": 3945, "text": ";\n‘no lies.’\n\n“‘I am bound to Tahiti for more men.’\n\n“‘Very good. Let me board you a moment—I come in peace.’ With that he\nleaped from the canoe, swam to the boat;", "labels": {"50": 45, "100": 64, "250": 163, "500": 494, "1000": 531, "2000": 187}}, {"id": 3946, "position": 3946, "text": ".’ With that he\nleaped from the canoe, swam to the boat; and climbing the gunwale,\nstood face to face with the captain.\n\n“‘Cross your arms, sir; throw back your head. Now, repeat after me", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 3947, "position": 3947, "text": ", sir; throw back your head. Now, repeat after me. As\nsoon as Steelkilt leaves me, I swear to beach this boat on yonder\nisland, and remain there six days. If I do not, may lightnings strike\nme", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 3948, "position": 3948, "text": "remain there six days. If I do not, may lightnings strike\nme!’\n\n“‘A pretty scholar,’ laughed the Lakeman. ‘Adios, Senor!’ and leaping\ninto the sea, he swam back to his comrades.", "labels": {"50": 40, "100": 64, "250": 205, "500": 437, "1000": 99, "2000": 472}}, {"id": 3949, "position": 3949, "text": "!’ and leaping\ninto the sea, he swam back to his comrades.\n\n“Watching the boat till it was fairly beached, and drawn up to the\nroots of the cocoa-nut trees, Steelkilt made sail again, and in due\ntime", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 324}}, {"id": 3950, "position": 3950, "text": "-nut trees, Steelkilt made sail again, and in due\ntime arrived at Tahiti, his own place of destination. There, luck\nbefriended him; two ships were about to sail for France, and were\nprovidentially in want of precisely", "labels": {"50": 45, "100": 29, "250": 130, "500": 494, "1000": 480, "2000": 187}}, {"id": 3951, "position": 3951, "text": "about to sail for France, and were\nprovidentially in want of precisely that number of men which the sailor\nheaded. They embarked; and so for ever got the start of their former\ncaptain, had he been at all minded to work them legal retribution", "labels": {"50": 45, "100": 29, "250": 82, "500": 384, "1000": 139, "2000": 801}}, {"id": 3952, "position": 3952, "text": "their former\ncaptain, had he been at all minded to work them legal retribution.\n\n“Some ten days after the French ships sailed, the whale-boat arrived,\nand the captain was forced to enlist some of the more civilized\nTahitians, who had", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1790}}, {"id": 3953, "position": 3953, "text": "was forced to enlist some of the more civilized\nTahitians, who had been somewhat used to the sea. Chartering a small\nnative schooner, he returned with them to his vessel; and finding all\nright there, again resumed his cruisings.", "labels": {"50": 45, "100": 29, "250": 34, "500": 494, "1000": 480, "2000": 385}}, {"id": 3954, "position": 3954, "text": "vessel; and finding all\nright there, again resumed his cruisings.\n\n“Where Steelkilt now is, gentlemen, none know; but upon the island of\nNantucket, the widow of Radney still turns to the sea which refuses to\ngive", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 3955, "position": 3955, "text": "the widow of Radney still turns to the sea which refuses to\ngive up its dead; still in dreams sees the awful white whale that\ndestroyed him.  * * * *\n\n“‘Are you through?’ said Don Sebastian, quietly.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 730, "2000": 16}}, {"id": 3956, "position": 3956, "text": "“‘Are you through?’ said Don Sebastian, quietly.\n\n“‘I am, Don.’\n\n“‘Then I entreat you, tell me if to the best of your own convictions,\nthis your story is in substance really true?", "labels": {"50": 36, "100": 15, "250": 22, "500": 364, "1000": 706, "2000": 1070}}, {"id": 3957, "position": 3957, "text": "best of your own convictions,\nthis your story is in substance really true? It is so passing\nwonderful! Did you get it from an unquestionable source? Bear with me\nif I seem to press.’", "labels": {"50": 23, "100": 40, "250": 8, "500": 214, "1000": 943, "2000": 1881}}, {"id": 3958, "position": 3958, "text": "me\nif I seem to press.’\n\n“‘Also bear with all of us, sir sailor; for we all join in Don\nSebastian’s suit,’ cried the company, with exceeding interest.\n\n“‘Is there a copy of the Holy Evangelist", "labels": {"50": 49, "100": 7, "250": 193, "500": 297, "1000": 849, "2000": 1107}}, {"id": 3959, "position": 3959, "text": ", with exceeding interest.\n\n“‘Is there a copy of the Holy Evangelists in the Golden Inn,\ngentlemen?’\n\n“‘Nay,’ said Don Sebastian; ‘but I know a worthy priest near by, who\nwill quickly procure one for", "labels": {"50": 49, "100": 15, "250": 177, "500": 91, "1000": 523, "2000": 674}}, {"id": 3960, "position": 3960, "text": "I know a worthy priest near by, who\nwill quickly procure one for me. I go for it; but are you well advised?\nthis may grow too serious.’\n\n“‘Will you be so good as to bring the priest also, Don", "labels": {"50": 1, "100": 49, "250": 177, "500": 437, "1000": 394, "2000": 267}}, {"id": 3961, "position": 3961, "text": "“‘Will you be so good as to bring the priest also, Don?’\n\n“‘Though there are no Auto-da-Fés in Lima now,’ said one of the company\nto another; ‘I fear our sailor friend runs risk", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 730, "2000": 1389}}, {"id": 3962, "position": 3962, "text": "one of the company\nto another; ‘I fear our sailor friend runs risk of the archiepiscopacy.\nLet us withdraw more out of the moonlight. I see no need of this.’\n\n“‘Excuse me for running after you, Don", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 3963, "position": 3963, "text": "need of this.’\n\n“‘Excuse me for running after you, Don Sebastian; but may I also beg\nthat you will be particular in procuring the largest sized Evangelists\nyou can.’\n\n* * * * * *", "labels": {"50": 49, "100": 15, "250": 22, "500": 364, "1000": 730, "2000": 75}}, {"id": 3964, "position": 3964, "text": "s\nyou can.’\n\n* * * * * *\n\n“‘This is the priest, he brings you the Evangelists,’ said Don\nSebastian, gravely, returning with a tall and solemn figure.\n\n“‘Let me remove my hat", "labels": {"50": 49, "100": 74, "250": 177, "500": 250, "1000": 394, "2000": 267}}, {"id": 3965, "position": 3965, "text": "tall and solemn figure.\n\n“‘Let me remove my hat. Now, venerable priest, further into the light,\nand hold the Holy Book before me that I may touch it.\n\n“‘So help me Heaven, and on my honor the story I", "labels": {"50": 18, "100": 87, "250": 177, "500": 250, "1000": 890, "2000": 1214}}, {"id": 3966, "position": 3966, "text": ".\n\n“‘So help me Heaven, and on my honor the story I have told ye,\ngentlemen, is in substance and its great items, true. I know it to be\ntrue; it happened on this ball; I trod the ship;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 3967, "position": 3967, "text": "be\ntrue; it happened on this ball; I trod the ship; I knew the crew; I\nhave seen and talked with Steelkilt since the death of Radney.’”\n\n\nCHAPTER 55. Of the Monstrous Pictures of Whales.", "labels": {"50": 12, "100": 24, "250": 52, "500": 72, "1000": 505, "2000": 1620}}, {"id": 3968, "position": 3968, "text": "ney.’”\n\n\nCHAPTER 55. Of the Monstrous Pictures of Whales.\n\nI shall ere long paint to you as well as one can without canvas,\nsomething like the true form of the whale as he actually appears to the\neye of the whaleman when", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3969, "position": 3969, "text": "of the whale as he actually appears to the\neye of the whaleman when in his own absolute body the whale is moored\nalongside the whale-ship so that he can be fairly stepped upon there.\nIt may be worth while, therefore, previously to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3970, "position": 3970, "text": "fairly stepped upon there.\nIt may be worth while, therefore, previously to advert to those curious\nimaginary portraits of him which even down to the present day\nconfidently challenge the faith of the landsman. It is time to set the\nworld right in this", "labels": {"50": 17, "100": 16, "250": 196, "500": 138, "1000": 212, "2000": 1686}}, {"id": 3971, "position": 3971, "text": "of the landsman. It is time to set the\nworld right in this matter, by proving such pictures of the whale all\nwrong.\n\nIt may be that the primal source of all those pictorial delusions will\nbe found among the oldest Hindoo, Egyptian", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3972, "position": 3972, "text": "all those pictorial delusions will\nbe found among the oldest Hindoo, Egyptian, and Grecian sculptures. For\never since those inventive but unscrupulous times when on the marble\npanellings of temples, the pedestals of statues,", "labels": {"50": 48, "100": 66, "250": 249, "500": 322, "1000": 878, "2000": 565}}, {"id": 3973, "position": 3973, "text": "when on the marble\npanellings of temples, the pedestals of statues, and on shields,\nmedallions, cups, and coins, the dolphin was drawn in scales of\nchain-armor like Saladin’s, and a helmeted head like St", "labels": {"50": 45, "100": 7, "250": 138, "500": 72, "1000": 825, "2000": 887}}, {"id": 3974, "position": 3974, "text": "-armor like Saladin’s, and a helmeted head like St. George’s; ever\nsince then has something of the same sort of license prevailed, not\nonly in most popular pictures of the whale, but in many scientific\npresentations of him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3975, "position": 3975, "text": "in most popular pictures of the whale, but in many scientific\npresentations of him.\n\nNow, by all odds, the most ancient extant portrait anyways purporting\nto be the whale’s, is to be found in the famous cavern-pagoda", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3976, "position": 3976, "text": "the whale’s, is to be found in the famous cavern-pagoda of\nElephanta, in India. The Brahmins maintain that in the almost endless\nsculptures of that immemorial pagoda, all the trades and pursuits,\nevery conce", "labels": {"50": 3, "100": 24, "250": 211, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3977, "position": 3977, "text": "immemorial pagoda, all the trades and pursuits,\nevery conceivable avocation of man, were prefigured ages before any of\nthem actually came into being. No wonder then, that in some sort our\nnoble profession of whaling", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3978, "position": 3978, "text": "being. No wonder then, that in some sort our\nnoble profession of whaling should have been there shadowed forth. The\nHindoo whale referred to, occurs in a separate department of the wall,\ndepicting the incarnation of Vishnu in the form of leviathan,", "labels": {"50": 3, "100": 24, "250": 249, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3979, "position": 3979, "text": "the wall,\ndepicting the incarnation of Vishnu in the form of leviathan, learnedly\nknown as the Matse Avatar. But though this sculpture is half man and\nhalf whale, so as only to give the tail of the latter, yet that small\nsection", "labels": {"50": 32, "100": 81, "250": 211, "500": 72, "1000": 555, "2000": 1620}}, {"id": 3980, "position": 3980, "text": "so as only to give the tail of the latter, yet that small\nsection of him is all wrong. It looks more like the tapering tail of an\nanaconda, than the broad palms of the true whale’s majestic flukes.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3981, "position": 3981, "text": "than the broad palms of the true whale’s majestic flukes.\n\nBut go to the old Galleries, and look now at a great Christian\npainter’s portrait of this fish; for he succeeds no better than the\nantediluvian Hindoo", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 3982, "position": 3982, "text": "; for he succeeds no better than the\nantediluvian Hindoo. It is Guido’s picture of Perseus rescuing\nAndromeda from the sea-monster or whale. Where did Guido get the model\nof such a strange creature as", "labels": {"50": 40, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1533}}, {"id": 3983, "position": 3983, "text": "or whale. Where did Guido get the model\nof such a strange creature as that? Nor does Hogarth, in painting the\nsame scene in his own “Perseus Descending,” make out one whit better", "labels": {"50": 3, "100": 24, "250": 196, "500": 483, "1000": 212, "2000": 1686}}, {"id": 3984, "position": 3984, "text": ",” make out one whit better.\nThe huge corpulence of that Hogarthian monster undulates on the\nsurface, scarcely drawing one inch of water. It has a sort of howdah on\nits back, and its distended tu", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3985, "position": 3985, "text": "a sort of howdah on\nits back, and its distended tusked mouth into which the billows are\nrolling, might be taken for the Traitors’ Gate leading from the Thames\nby water into the Tower", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 3986, "position": 3986, "text": "leading from the Thames\nby water into the Tower. Then, there are the Prodromus whales of old\nScotch Sibbald, and Jonah’s whale, as depicted in the prints of old\nBibles and the cuts of old primers", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 887}}, {"id": 3987, "position": 3987, "text": "the prints of old\nBibles and the cuts of old primers. What shall be said of these? As for\nthe book-binder’s whale winding like a vine-stalk round the stock of a\ndescending anchor—as stamped and gilded on", "labels": {"50": 31, "100": 20, "250": 49, "500": 126, "1000": 747, "2000": 1620}}, {"id": 3988, "position": 3988, "text": "-stalk round the stock of a\ndescending anchor—as stamped and gilded on the backs and title-pages of\nmany books both old and new—that is a very picturesque but purely\nfabulous creature, imitated, I take it, from the like figures", "labels": {"50": 31, "100": 40, "250": 132, "500": 126, "1000": 727, "2000": 1107}}, {"id": 3989, "position": 3989, "text": "purely\nfabulous creature, imitated, I take it, from the like figures on\nantique vases. Though universally denominated a dolphin, I nevertheless\ncall this book-binder’s fish an attempt at a whale; because it was so\nintended", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3990, "position": 3990, "text": "er’s fish an attempt at a whale; because it was so\nintended when the device was first introduced. It was introduced by an\nold Italian publisher somewhere about the 15th century, during the\nRevival of Learning; and in those days, and even down", "labels": {"50": 3, "100": 24, "250": 198, "500": 72, "1000": 825, "2000": 447}}, {"id": 3991, "position": 3991, "text": ", during the\nRevival of Learning; and in those days, and even down to a\ncomparatively late period, dolphins were popularly supposed to be a\nspecies of the Leviathan.\n\nIn the vignettes and other embellishments of some ancient books you", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3992, "position": 3992, "text": "the vignettes and other embellishments of some ancient books you\nwill at times meet with very curious touches at the whale, where all\nmanner of spouts, jets d’eau, hot springs and cold, Saratoga and\nBaden-Baden", "labels": {"50": 48, "100": 27, "250": 249, "500": 77, "1000": 162, "2000": 565}}, {"id": 3993, "position": 3993, "text": "d’eau, hot springs and cold, Saratoga and\nBaden-Baden, come bubbling up from his unexhausted brain. In the\ntitle-page of the original edition of the “Advancement of Learning” you\nwill find some curious whales.", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3994, "position": 3994, "text": "edition of the “Advancement of Learning” you\nwill find some curious whales.\n\nBut quitting all these unprofessional attempts, let us glance at those\npictures of leviathan purporting to be sober, scientific delineations,\nby", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3995, "position": 3995, "text": "athan purporting to be sober, scientific delineations,\nby those who know. In old Harris’s collection of voyages there are some\nplates of whales extracted from a Dutch book of voyages, A.D", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3996, "position": 3996, "text": "a Dutch book of voyages, A.D. 1671,\nentitled “A Whaling Voyage to Spitzbergen in the ship Jonas in the\nWhale, Peter Peterson of Friesland, master.” In one of those plates the\nwhales, like great", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3997, "position": 3997, "text": "land, master.” In one of those plates the\nwhales, like great rafts of logs, are represented lying among\nice-isles, with white bears running over their living backs. In another\nplate, the prodigious blunder is made", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3998, "position": 3998, "text": "backs. In another\nplate, the prodigious blunder is made of representing the whale with\nperpendicular flukes.\n\nThen again, there is an imposing quarto, written by one Captain\nColnett, a Post Captain in the English navy,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 3999, "position": 3999, "text": "written by one Captain\nColnett, a Post Captain in the English navy, entitled “A Voyage round\nCape Horn into the South Seas, for the purpose of extending the\nSpermaceti Whale Fisheries.” In this book is an outline purporting", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 4000, "position": 4000, "text": "ti Whale Fisheries.” In this book is an outline purporting to\nbe a “Picture of a Physeter or Spermaceti whale, drawn by scale from\none killed on the coast of Mexico, August, 1793, and hoisted on", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4001, "position": 4001, "text": "one killed on the coast of Mexico, August, 1793, and hoisted on deck.”\nI doubt not the captain had this veracious picture taken for the\nbenefit of his marines. To mention but one thing about it, let me say\nthat it has", "labels": {"50": 49, "100": 27, "250": 196, "500": 322, "1000": 762, "2000": 765}}, {"id": 4002, "position": 4002, "text": ". To mention but one thing about it, let me say\nthat it has an eye which applied, according to the accompanying scale,\nto a full grown sperm whale, would make the eye of that whale a\nbow-window some five feet long", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4003, "position": 4003, "text": "the eye of that whale a\nbow-window some five feet long. Ah, my gallant captain, why did ye not\ngive us Jonah looking out of that eye!\n\nNor are the most conscientious compilations of Natural History for the\nbenefit of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4004, "position": 4004, "text": "the most conscientious compilations of Natural History for the\nbenefit of the young and tender, free from the same heinousness of\nmistake. Look at that popular work “Goldsmith’s Animated Nature.” In\nthe abridged London edition", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 505, "2000": 744}}, {"id": 4005, "position": 4005, "text": "“Goldsmith’s Animated Nature.” In\nthe abridged London edition of 1807, there are plates of an alleged\n“whale” and a “narwhale.” I do not wish to seem inelegant, but this\nun", "labels": {"50": 17, "100": 68, "250": 111, "500": 419, "1000": 681, "2000": 1620}}, {"id": 4006, "position": 4006, "text": "” I do not wish to seem inelegant, but this\nunsightly whale looks much like an amputated sow; and, as for the\nnarwhale, one glimpse at it is enough to amaze one, that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4007, "position": 4007, "text": "whale, one glimpse at it is enough to amaze one, that in this\nnineteenth century such a hippogriff could be palmed for genuine upon\nany intelligent public of schoolboys.\n\nThen, again, in 1825, Bernard Germain, Count", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4008, "position": 4008, "text": "of schoolboys.\n\nThen, again, in 1825, Bernard Germain, Count de Lacépède, a great\nnaturalist, published a scientific systemized whale book, wherein are\nseveral pictures of the different species of the Leviathan", "labels": {"50": 3, "100": 24, "250": 14, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4009, "position": 4009, "text": "pictures of the different species of the Leviathan. All these\nare not only incorrect, but the picture of the Mysticetus or Greenland\nwhale (that is to say, the Right whale), even Scoresby, a long\nexperienced man as touching that", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4010, "position": 4010, "text": "Right whale), even Scoresby, a long\nexperienced man as touching that species, declares not to have its\ncounterpart in nature.\n\nBut the placing of the cap-sheaf to all this blundering business was\nreserved for the scientific Frederick Cuvier", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4011, "position": 4011, "text": "to all this blundering business was\nreserved for the scientific Frederick Cuvier, brother to the famous\nBaron. In 1836, he published a Natural History of Whales, in which he\ngives what he calls a picture of the Sperm Whale", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4012, "position": 4012, "text": "he\ngives what he calls a picture of the Sperm Whale. Before showing that\npicture to any Nantucketer, you had best provide for your summary\nretreat from Nantucket. In a word, Frederick Cuvier’s Sperm Whale is\nnot a Sperm Whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4013, "position": 4013, "text": "a word, Frederick Cuvier’s Sperm Whale is\nnot a Sperm Whale, but a squash. Of course, he never had the benefit of\na whaling voyage (such men seldom have), but whence he derived that\npicture, who can tell", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4014, "position": 4014, "text": "seldom have), but whence he derived that\npicture, who can tell? Perhaps he got it as his scientific predecessor\nin the same field, Desmarest, got one of his authentic abortions; that\nis, from a Chinese drawing", "labels": {"50": 10, "100": 71, "250": 196, "500": 322, "1000": 212, "2000": 765}}, {"id": 4015, "position": 4015, "text": "of his authentic abortions; that\nis, from a Chinese drawing. And what sort of lively lads with the\npencil those Chinese are, many queer cups and saucers inform us.\n\nAs for the sign-painters’ whales seen in the streets hanging over", "labels": {"50": 31, "100": 16, "250": 196, "500": 483, "1000": 212, "2000": 1394}}, {"id": 4016, "position": 4016, "text": ".\n\nAs for the sign-painters’ whales seen in the streets hanging over the\nshops of oil-dealers, what shall be said of them? They are generally\nRichard III. whales, with dromedary humps, and very savage;\nbreakfast", "labels": {"50": 9, "100": 98, "250": 193, "500": 498, "1000": 637, "2000": 1620}}, {"id": 4017, "position": 4017, "text": "whales, with dromedary humps, and very savage;\nbreakfasting on three or four sailor tarts, that is whaleboats full of\nmariners: their deformities floundering in seas of blood and blue\npaint.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4018, "position": 4018, "text": "mities floundering in seas of blood and blue\npaint.\n\nBut these manifold mistakes in depicting the whale are not so very\nsurprising after all. Consider! Most of the scientific drawings have\nbeen taken from the stranded fish; and these are about as correct", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4019, "position": 4019, "text": "drawings have\nbeen taken from the stranded fish; and these are about as correct as a\ndrawing of a wrecked ship, with broken back, would correctly represent\nthe noble animal itself in all its undashed pride of hull and spars", "labels": {"50": 17, "100": 29, "250": 1, "500": 13, "1000": 622, "2000": 1620}}, {"id": 4020, "position": 4020, "text": "all its undashed pride of hull and spars.\nThough elephants have stood for their full-lengths, the living\nLeviathan has never yet fairly floated himself for his portrait. The\nliving whale, in his full majesty and significance, is only to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4021, "position": 4021, "text": ". The\nliving whale, in his full majesty and significance, is only to be seen\nat sea in unfathomable waters; and afloat the vast bulk of him is out\nof sight, like a launched line-of-battle ship; and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4022, "position": 4022, "text": "out\nof sight, like a launched line-of-battle ship; and out of that element\nit is a thing eternally impossible for mortal man to hoist him bodily\ninto the air, so as to preserve all his mighty swells and undulation", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4023, "position": 4023, "text": "the air, so as to preserve all his mighty swells and undulations.\nAnd, not to speak of the highly presumable difference of contour\nbetween a young sucking whale and a full-grown Platonian Leviathan;\nyet, even", "labels": {"50": 10, "100": 71, "250": 129, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4024, "position": 4024, "text": "sucking whale and a full-grown Platonian Leviathan;\nyet, even in the case of one of those young sucking whales hoisted to a\nship’s deck, such is then the outlandish, eel-like, limbered, varying\nshape", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4025, "position": 4025, "text": "then the outlandish, eel-like, limbered, varying\nshape of him, that his precise expression the devil himself could not\ncatch.\n\nBut it may be fancied, that from the naked skeleton of the stranded\nwhale, accurate hints may", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4026, "position": 4026, "text": "d, that from the naked skeleton of the stranded\nwhale, accurate hints may be derived touching his true form. Not at\nall. For it is one of the more curious things about this Leviathan,\nthat his skeleton gives very little idea of his general", "labels": {"50": 3, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4027, "position": 4027, "text": "about this Leviathan,\nthat his skeleton gives very little idea of his general shape. Though\nJeremy Bentham’s skeleton, which hangs for candelabra in the library of\none of his executors, correctly conveys the idea of", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 505, "2000": 744}}, {"id": 4028, "position": 4028, "text": "of\none of his executors, correctly conveys the idea of a burly-browed\nutilitarian old gentleman, with all Jeremy’s other leading personal\ncharacteristics; yet nothing of this kind could be inferred from any\nlevi", "labels": {"50": 20, "100": 28, "250": 175, "500": 59, "1000": 421, "2000": 1645}}, {"id": 4029, "position": 4029, "text": "characteristics; yet nothing of this kind could be inferred from any\nleviathan’s articulated bones. In fact, as the great Hunter says, the\nmere skeleton of the whale bears the same relation to the fully\ninvested and padded animal as the insect", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4030, "position": 4030, "text": "whale bears the same relation to the fully\ninvested and padded animal as the insect does to the chrysalis that so\nroundingly envelopes it. This peculiarity is strikingly evinced in the\nhead, as in some part of this book will", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4031, "position": 4031, "text": "evinced in the\nhead, as in some part of this book will be incidentally shown. It is\nalso very curiously displayed in the side fin, the bones of which\nalmost exactly answer to the bones of the human hand, minus only the\nthumb", "labels": {"50": 3, "100": 85, "250": 14, "500": 486, "1000": 956, "2000": 167}}, {"id": 4032, "position": 4032, "text": "almost exactly answer to the bones of the human hand, minus only the\nthumb. This fin has four regular bone-fingers, the index, middle, ring,\nand little finger. But all these are permanently lodged in their fleshy\ncovering, as the", "labels": {"50": 3, "100": 70, "250": 14, "500": 403, "1000": 634, "2000": 313}}, {"id": 4033, "position": 4033, "text": ". But all these are permanently lodged in their fleshy\ncovering, as the human fingers in an artificial covering. “However\nrecklessly the whale may sometimes serve us,” said humorous Stubb one\nday, “he can never be truly said to handle", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4034, "position": 4034, "text": "humorous Stubb one\nday, “he can never be truly said to handle us without mittens.”\n\nFor all these reasons, then, any way you may look at it, you must needs\nconclude that the great Leviathan is that one creature in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4035, "position": 4035, "text": ", you must needs\nconclude that the great Leviathan is that one creature in the world\nwhich must remain unpainted to the last. True, one portrait may hit the\nmark much nearer than another, but none can hit it with any very\nconsiderable", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 825, "2000": 1620}}, {"id": 4036, "position": 4036, "text": "mark much nearer than another, but none can hit it with any very\nconsiderable degree of exactness. So there is no earthly way of finding\nout precisely what the whale really looks like. And the only mode in\nwhich you can derive even a toler", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4037, "position": 4037, "text": "like. And the only mode in\nwhich you can derive even a tolerable idea of his living contour, is by\ngoing a whaling yourself; but by so doing, you run no small risk of\nbeing eternally stove and sunk by him", "labels": {"50": 31, "100": 7, "250": 193, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4038, "position": 4038, "text": "you run no small risk of\nbeing eternally stove and sunk by him. Wherefore, it seems to me you\nhad best not be too fastidious in your curiosity touching this\nLeviathan.\n\n\nCHAPTER 56", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4039, "position": 4039, "text": "touching this\nLeviathan.\n\n\nCHAPTER 56. Of the Less Erroneous Pictures of Whales, and the True\nPictures of Whaling Scenes.\n\nIn connexion with the monstrous pictures of whales, I am strongly\ntempted here to enter upon those still more monstrous", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4040, "position": 4040, "text": "of whales, I am strongly\ntempted here to enter upon those still more monstrous stories of them\nwhich are to be found in certain books, both ancient and modern,\nespecially in Pliny, Purchas, Hackluyt, Harris, Cuvier,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4041, "position": 4041, "text": "iny, Purchas, Hackluyt, Harris, Cuvier, etc. But I pass\nthat matter by.\n\nI know of only four published outlines of the great Sperm Whale;\nColnett’s, Huggins’s, Frederick Cuvier", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4042, "position": 4042, "text": "Whale;\nColnett’s, Huggins’s, Frederick Cuvier’s, and Beale’s. In the previous\nchapter Colnett and Cuvier have been referred to. Huggins’s is far\nbetter than theirs; but, by", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4043, "position": 4043, "text": "to. Huggins’s is far\nbetter than theirs; but, by great odds, Beale’s is the best. All\nBeale’s drawings of this whale are good, excepting the middle figure in\nthe picture of three whales in various attitudes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4044, "position": 4044, "text": ", excepting the middle figure in\nthe picture of three whales in various attitudes, capping his second\nchapter. His frontispiece, boats attacking Sperm Whales, though no\ndoubt calculated to excite the civil scepticism of some parlor men,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4045, "position": 4045, "text": "calculated to excite the civil scepticism of some parlor men, is\nadmirably correct and life-like in its general effect. Some of the\nSperm Whale drawings in J. Ross Browne are pretty correct in contour;\nbut they are", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4046, "position": 4046, "text": "in J. Ross Browne are pretty correct in contour;\nbut they are wretchedly engraved. That is not his fault though.\n\nOf the Right Whale, the best outline pictures are in Scoresby; but they\nare drawn on too small a scale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4047, "position": 4047, "text": "pictures are in Scoresby; but they\nare drawn on too small a scale to convey a desirable impression. He has\nbut one picture of whaling scenes, and this is a sad deficiency,\nbecause it is by such pictures only, when at all well done", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4048, "position": 4048, "text": "deficiency,\nbecause it is by such pictures only, when at all well done, that you\ncan derive anything like a truthful idea of the living whale as seen by\nhis living hunters.\n\nBut, taken for all in all, by far the finest,", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4049, "position": 4049, "text": "hunters.\n\nBut, taken for all in all, by far the finest, though in some details\nnot the most correct, presentations of whales and whaling scenes to be\nanywhere found, are two large French engravings, well executed, and\ntaken from paintings by one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4050, "position": 4050, "text": "are two large French engravings, well executed, and\ntaken from paintings by one Garnery. Respectively, they represent\nattacks on the Sperm and Right Whale. In the first engraving a noble\nSperm Whale is depicted in full majesty of might, just risen beneath\nthe", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4051, "position": 4051, "text": "noble\nSperm Whale is depicted in full majesty of might, just risen beneath\nthe boat from the profundities of the ocean, and bearing high in the\nair upon his back the terrific wreck of the stoven planks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4052, "position": 4052, "text": "terrific wreck of the stoven planks. The prow of\nthe boat is partially unbroken, and is drawn just balancing upon the\nmonster’s spine; and standing in that prow, for that one single\nincomputable flash of time, you", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4053, "position": 4053, "text": "prow, for that one single\nincomputable flash of time, you behold an oarsman, half shrouded by the\nincensed boiling spout of the whale, and in the act of leaping, as if\nfrom a precipic", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4054, "position": 4054, "text": ", and in the act of leaping, as if\nfrom a precipice. The action of the whole thing is wonderfully good and\ntrue. The half-emptied line-tub floats on the whitened sea; the wooden\npoles of the spilled", "labels": {"50": 48, "100": 20, "250": 49, "500": 334, "1000": 9, "2000": 472}}, {"id": 4055, "position": 4055, "text": "-tub floats on the whitened sea; the wooden\npoles of the spilled harpoons obliquely bob in it; the heads of the\nswimming crew are scattered about the whale in contrasting expressions\nof affright; while in the black stormy distance the ship", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4056, "position": 4056, "text": "contrasting expressions\nof affright; while in the black stormy distance the ship is bearing\ndown upon the scene. Serious fault might be found with the anatomical\ndetails of this whale, but let that pass; since, for the life of me, I\ncould", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4057, "position": 4057, "text": "but let that pass; since, for the life of me, I\ncould not draw so good a one.\n\nIn the second engraving, the boat is in the act of drawing alongside\nthe barnacled flank of a large running Right Whale, that rolls", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4058, "position": 4058, "text": "alongside\nthe barnacled flank of a large running Right Whale, that rolls his\nblack weedy bulk in the sea like some mossy rock-slide from the\nPatagonian cliffs. His jets are erect, full, and black like soot;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4059, "position": 4059, "text": "cliffs. His jets are erect, full, and black like soot; so\nthat from so abounding a smoke in the chimney, you would think there\nmust be a brave supper cooking in the great bowels below", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4060, "position": 4060, "text": "brave supper cooking in the great bowels below. Sea fowls are\npecking at the small crabs, shell-fish, and other sea candies and\nmaccaroni, which the Right Whale sometimes carries on his pestilent\nback", "labels": {"50": 45, "100": 64, "250": 49, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4061, "position": 4061, "text": ", which the Right Whale sometimes carries on his pestilent\nback. And all the while the thick-lipped leviathan is rushing through\nthe deep, leaving tons of tumultuous white curds in his wake, and\ncausing the slight boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4062, "position": 4062, "text": "multuous white curds in his wake, and\ncausing the slight boat to rock in the swells like a skiff caught nigh\nthe paddle-wheels of an ocean steamer. Thus, the foreground is all\nraging commotion; but behind,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4063, "position": 4063, "text": "steamer. Thus, the foreground is all\nraging commotion; but behind, in admirable artistic contrast, is the\nglassy level of a sea becalmed, the drooping unstarched sails of the\npowerless ship, and the inert", "labels": {"50": 45, "100": 20, "250": 138, "500": 162, "1000": 747, "2000": 887}}, {"id": 4064, "position": 4064, "text": "drooping unstarched sails of the\npowerless ship, and the inert mass of a dead whale, a conquered\nfortress, with the flag of capture lazily hanging from the whale-pole\ninserted into his spout-hole.", "labels": {"50": 16, "100": 20, "250": 133, "500": 162, "1000": 747, "2000": 16}}, {"id": 4065, "position": 4065, "text": "whale-pole\ninserted into his spout-hole.\n\nWho Garnery the painter is, or was, I know not. But my life for it he\nwas either practically conversant with his subject, or else\nmarvellously tutored by some", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4066, "position": 4066, "text": "versant with his subject, or else\nmarvellously tutored by some experienced whaleman. The French are the\nlads for painting action. Go and gaze upon all the paintings of Europe,\nand where will you find such a gallery of living and breathing", "labels": {"50": 48, "100": 16, "250": 196, "500": 322, "1000": 144, "2000": 765}}, {"id": 4067, "position": 4067, "text": "of Europe,\nand where will you find such a gallery of living and breathing\ncommotion on canvas, as in that triumphal hall at Versailles; where the\nbeholder fights his way, pell-mell, through the consecutive great\nbattles of France;", "labels": {"50": 48, "100": 20, "250": 196, "500": 322, "1000": 212, "2000": 765}}, {"id": 4068, "position": 4068, "text": ", pell-mell, through the consecutive great\nbattles of France; where every sword seems a flash of the Northern\nLights, and the successive armed kings and Emperors dash by, like a\ncharge of crowned centaurs? Not wholly unworthy of", "labels": {"50": 31, "100": 20, "250": 193, "500": 126, "1000": 15, "2000": 1466}}, {"id": 4069, "position": 4069, "text": ", like a\ncharge of crowned centaurs? Not wholly unworthy of a place in that\ngallery, are these sea battle-pieces of Garnery.\n\nThe natural aptitude of the French for seizing the picturesqueness of\nthings seems to be peculiarly", "labels": {"50": 48, "100": 20, "250": 196, "500": 322, "1000": 212, "2000": 765}}, {"id": 4070, "position": 4070, "text": "of the French for seizing the picturesqueness of\nthings seems to be peculiarly evinced in what paintings and engravings\nthey have of their whaling scenes. With not one tenth of England’s\nexperience in the fishery, and not the thousandth part of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4071, "position": 4071, "text": "England’s\nexperience in the fishery, and not the thousandth part of that of the\nAmericans, they have nevertheless furnished both nations with the only\nfinished sketches at all capable of conveying the real spirit of the\nwhale hunt", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4072, "position": 4072, "text": "conveying the real spirit of the\nwhale hunt. For the most part, the English and American whale\ndraughtsmen seem entirely content with presenting the mechanical\noutline of things, such as the vacant profile of the whale; which, so\nfar as picturesqueness", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4073, "position": 4073, "text": "as the vacant profile of the whale; which, so\nfar as picturesqueness of effect is concerned, is about tantamount to\nsketching the profile of a pyramid. Even Scoresby, the justly renowned\nRight whaleman, after giving us a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4074, "position": 4074, "text": "Scoresby, the justly renowned\nRight whaleman, after giving us a stiff full length of the Greenland\nwhale, and three or four delicate miniatures of narwhales and\nporpoises, treats us to a series of classical engravings of boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4075, "position": 4075, "text": "and\nporpoises, treats us to a series of classical engravings of boat hooks,\nchopping knives, and grapnels; and with the microscopic diligence of a\nLeuwenhoeck submits to the inspection of a shivering world", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 825, "2000": 1710}}, {"id": 4076, "position": 4076, "text": "a\nLeuwenhoeck submits to the inspection of a shivering world ninety-six\nfac-similes of magnified Arctic snow crystals. I mean no disparagement\nto the excellent voyager (I honor him for a veteran),", "labels": {"50": 45, "100": 64, "250": 138, "500": 48, "1000": 327, "2000": 1620}}, {"id": 4077, "position": 4077, "text": "agement\nto the excellent voyager (I honor him for a veteran), but in so\nimportant a matter it was certainly an oversight not to have procured\nfor every crystal a sworn affidavit taken before a Greenland Justice of\nthe Peace.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4078, "position": 4078, "text": "sworn affidavit taken before a Greenland Justice of\nthe Peace.\n\nIn addition to those fine engravings from Garnery, there are two other\nFrench engravings worthy of note, by some one who subscribes himself\n“H", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 1584}}, {"id": 4079, "position": 4079, "text": "some one who subscribes himself\n“H. Durand.” One of them, though not precisely adapted to our present\npurpose, nevertheless deserves mention on other accounts. It is a quiet\nnoon-scene among the isles of the Pacific; a French", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4080, "position": 4080, "text": "is a quiet\nnoon-scene among the isles of the Pacific; a French whaler anchored,\ninshore, in a calm, and lazily taking water on board; the loosened\nsails of the ship, and the long leaves of the palms in the", "labels": {"50": 48, "100": 20, "250": 130, "500": 494, "1000": 480, "2000": 187}}, {"id": 4081, "position": 4081, "text": "loosened\nsails of the ship, and the long leaves of the palms in the background,\nboth drooping together in the breezeless air. The effect is very fine,\nwhen considered with reference to its presenting the hardy fishermen\nunder one of their few aspects of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4082, "position": 4082, "text": "with reference to its presenting the hardy fishermen\nunder one of their few aspects of oriental repose. The other engraving\nis quite a different affair: the ship hove-to upon the open sea, and in\nthe very heart of the Leviathanic life,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4083, "position": 4083, "text": "open sea, and in\nthe very heart of the Leviathanic life, with a Right Whale alongside;\nthe vessel (in the act of cutting-in) hove over to the monster as if to\na quay; and a boat, hurriedly pushing off", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4084, "position": 4084, "text": "the monster as if to\na quay; and a boat, hurriedly pushing off from this scene of activity,\nis about giving chase to whales in the distance. The harpoons and\nlances lie levelled for use; three oarsmen are just setting", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4085, "position": 4085, "text": "lances lie levelled for use; three oarsmen are just setting the mast in\nits hole; while from a sudden roll of the sea, the little craft stands\nhalf-erect out of the water, like a rearing horse", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4086, "position": 4086, "text": "-erect out of the water, like a rearing horse. From the ship, the\nsmoke of the torments of the boiling whale is going up like the smoke\nover a village of smithies; and to windward, a black cloud, rising", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4087, "position": 4087, "text": "village of smithies; and to windward, a black cloud, rising up\nwith earnest of squalls and rains, seems to quicken the activity of the\nexcited seamen.\n\n\nCHAPTER 57. Of Whales in Paint; in Teeth; in Wood;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4088, "position": 4088, "text": ".\n\n\nCHAPTER 57. Of Whales in Paint; in Teeth; in Wood; in Sheet-Iron; in\nStone; in Mountains; in Stars.\n\nOn Tower-hill, as you go down to the London docks, you may have seen a\ncrippled beg", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4089, "position": 4089, "text": "you go down to the London docks, you may have seen a\ncrippled beggar (or _kedger_, as the sailors say) holding a painted\nboard before him, representing the tragic scene in which he lost his\nleg", "labels": {"50": 31, "100": 7, "250": 193, "500": 247, "1000": 175, "2000": 1268}}, {"id": 4090, "position": 4090, "text": "representing the tragic scene in which he lost his\nleg. There are three whales and three boats; and one of the boats\n(presumed to contain the missing leg in all its original integrity) is\nbeing crunched by the jaws of the foremost whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4091, "position": 4091, "text": "integrity) is\nbeing crunched by the jaws of the foremost whale. Any time these ten\nyears, they tell me, has that man held up that picture, and exhibited\nthat stump to an incredulous world", "labels": {"50": 31, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4092, "position": 4092, "text": "stump to an incredulous world. But the time of his justification\nhas now come. His three whales are as good whales as were ever\npublished in Wapping, at any rate; and his stump as unquestionable a\nstump as any you", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4093, "position": 4093, "text": "rate; and his stump as unquestionable a\nstump as any you will find in the western clearings. But, though for\never mounted on that stump, never a stump-speech does the poor whaleman\nmake; but, with downcast", "labels": {"50": 31, "100": 7, "250": 193, "500": 307, "1000": 165, "2000": 1620}}, {"id": 4094, "position": 4094, "text": "stump-speech does the poor whaleman\nmake; but, with downcast eyes, stands ruefully contemplating his own\namputation.\n\nThroughout the Pacific, and also in Nantucket, and New Bedford, and Sag\nHarbor, you will come across lively", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4095, "position": 4095, "text": ", and New Bedford, and Sag\nHarbor, you will come across lively sketches of whales and\nwhaling-scenes, graven by the fishermen themselves on Sperm\nWhale-teeth, or ladies’ busks wrought out of the Right Whale-bone, and", "labels": {"50": 31, "100": 7, "250": 49, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4096, "position": 4096, "text": "or ladies’ busks wrought out of the Right Whale-bone, and\nother like skrimshander articles, as the whalemen call the numerous\nlittle ingenious contrivances they elaborately carve out of the rough\nmaterial, in their", "labels": {"50": 31, "100": 7, "250": 193, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4097, "position": 4097, "text": "trivances they elaborately carve out of the rough\nmaterial, in their hours of ocean leisure. Some of them have little\nboxes of dentistical-looking implements, specially intended for the\nskrimshandering business", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4098, "position": 4098, "text": "for the\nskrimshandering business. But, in general, they toil with their\njack-knives alone; and, with that almost omnipotent tool of the sailor,\nthey will turn you out anything you please, in the way", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 4099, "position": 4099, "text": "the sailor,\nthey will turn you out anything you please, in the way of a mariner’s\nfancy.\n\nLong exile from Christendom and civilization inevitably restores a man\nto that condition in which God placed him, _i.e.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 558}}, {"id": 4100, "position": 4100, "text": "man\nto that condition in which God placed him, _i.e._ what is called\nsavagery. Your true whale-hunter is as much a savage as an Iroquois. I\nmyself am a savage, owning no allegiance but to the King of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4101, "position": 4101, "text": ". I\nmyself am a savage, owning no allegiance but to the King of the\nCannibals; and ready at any moment to rebel against him.\n\nNow, one of the peculiar characteristics of the savage in his domestic\nhours, is his wonderful patience", "labels": {"50": 20, "100": 28, "250": 132, "500": 412, "1000": 329, "2000": 381}}, {"id": 4102, "position": 4102, "text": "the peculiar characteristics of the savage in his domestic\nhours, is his wonderful patience of industry. An ancient Hawaiian\nwar-club or spear-paddle, in its full multiplicity and elaboration of\ncarving, is as great a trophy of human perse", "labels": {"50": 42, "100": 42, "250": 130, "500": 247, "1000": 917, "2000": 616}}, {"id": 4103, "position": 4103, "text": "elaboration of\ncarving, is as great a trophy of human perseverance as a Latin lexicon.\nFor, with but a bit of broken sea-shell or a shark’s tooth, that\nmiraculous intricacy of wooden net-work", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4104, "position": 4104, "text": "shark’s tooth, that\nmiraculous intricacy of wooden net-work has been achieved; and it has\ncost steady years of steady application.\n\nAs with the Hawaiian savage, so with the white sailor-savage", "labels": {"50": 12, "100": 42, "250": 130, "500": 494, "1000": 480, "2000": 187}}, {"id": 4105, "position": 4105, "text": "so with the white sailor-savage. With the\nsame marvellous patience, and with the same single shark’s tooth, of\nhis one poor jack-knife, he will carve you a bit of bone sculpture, not\nquite as workmanlike", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4106, "position": 4106, "text": "carve you a bit of bone sculpture, not\nquite as workmanlike, but as close packed in its maziness of design, as\nthe Greek savage, Achilles’s shield; and full of barbaric spirit and\nsuggestiveness,", "labels": {"50": 48, "100": 20, "250": 205, "500": 72, "1000": 747, "2000": 1466}}, {"id": 4107, "position": 4107, "text": "s shield; and full of barbaric spirit and\nsuggestiveness, as the prints of that fine old Dutch savage, Albert\nDurer.\n\nWooden whales, or whales cut in profile out of the small dark slabs of\nthe noble South Sea war-", "labels": {"50": 48, "100": 27, "250": 249, "500": 77, "1000": 878, "2000": 565}}, {"id": 4108, "position": 4108, "text": "in profile out of the small dark slabs of\nthe noble South Sea war-wood, are frequently met with in the\nforecastles of American whalers. Some of them are done with much\naccuracy.\n\nAt some old gable-roofed country houses you will see", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4109, "position": 4109, "text": "with much\naccuracy.\n\nAt some old gable-roofed country houses you will see brass whales hung\nby the tail for knockers to the road-side door. When the porter is\nsleepy, the anvil-headed whale would be best", "labels": {"50": 31, "100": 24, "250": 49, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4110, "position": 4110, "text": "sleepy, the anvil-headed whale would be best. But these knocking whales\nare seldom remarkable as faithful essays. On the spires of some\nold-fashioned churches you will see sheet-iron whales placed there for\nweather-cocks; but they", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4111, "position": 4111, "text": "see sheet-iron whales placed there for\nweather-cocks; but they are so elevated, and besides that are to all\nintents and purposes so labelled with “_Hands off!_” you cannot examine\nthem closely enough to decide upon their merit", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4112, "position": 4112, "text": "off!_” you cannot examine\nthem closely enough to decide upon their merit.\n\nIn bony, ribby regions of the earth, where at the base of high broken\ncliffs masses of rock lie strewn in fantastic groupings upon the plain,\nyou will often", "labels": {"50": 31, "100": 20, "250": 234, "500": 108, "1000": 37, "2000": 1285}}, {"id": 4113, "position": 4113, "text": "of rock lie strewn in fantastic groupings upon the plain,\nyou will often discover images as of the petrified forms of the\nLeviathan partly merged in grass, which of a windy day breaks against\nthem in a surf of green surges.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 887}}, {"id": 4114, "position": 4114, "text": "windy day breaks against\nthem in a surf of green surges.\n\nThen, again, in mountainous countries where the traveller is\ncontinually girdled by amphitheatrical heights; here and there from\nsome lucky point of view you will catch passing glimpse", "labels": {"50": 48, "100": 20, "250": 192, "500": 423, "1000": 816, "2000": 1710}}, {"id": 4115, "position": 4115, "text": "; here and there from\nsome lucky point of view you will catch passing glimpses of the\nprofiles of whales defined along the undulating ridges. But you must be\na thorough whaleman, to see these sights; and not only that, but if you", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4116, "position": 4116, "text": "man, to see these sights; and not only that, but if you\nwish to return to such a sight again, you must be sure and take the\nexact intersecting latitude and longitude of your first stand-point,\nelse so chance-like are such", "labels": {"50": 8, "100": 14, "250": 81, "500": 272, "1000": 147, "2000": 776}}, {"id": 4117, "position": 4117, "text": "longitude of your first stand-point,\nelse so chance-like are such observations of the hills, that your\nprecise, previous stand-point would require a laborious re-discovery;\nlike the Soloma Islands, which still remain incognita", "labels": {"50": 45, "100": 43, "250": 34, "500": 306, "1000": 381, "2000": 1817}}, {"id": 4118, "position": 4118, "text": "discovery;\nlike the Soloma Islands, which still remain incognita, though once\nhigh-ruffed Mendanna trod them and old Figuera chronicled them.\n\nNor when expandingly lifted by your subject, can you fail to", "labels": {"50": 45, "100": 29, "250": 161, "500": 13, "1000": 622, "2000": 1097}}, {"id": 4119, "position": 4119, "text": "them.\n\nNor when expandingly lifted by your subject, can you fail to trace out\ngreat whales in the starry heavens, and boats in pursuit of them; as\nwhen long filled with thoughts of war the Eastern nations saw armies\nlocked in battle among the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4120, "position": 4120, "text": "filled with thoughts of war the Eastern nations saw armies\nlocked in battle among the clouds. Thus at the North have I chased\nLeviathan round and round the Pole with the revolutions of the bright\npoints that first defined him to me", "labels": {"50": 4, "100": 18, "250": 64, "500": 129, "1000": 884, "2000": 781}}, {"id": 4121, "position": 4121, "text": "the bright\npoints that first defined him to me. And beneath the effulgent\nAntarctic skies I have boarded the Argo-Navis, and joined the chase\nagainst the starry Cetus far beyond the utmost stretch of Hydrus and\nthe", "labels": {"50": 45, "100": 64, "250": 50, "500": 72, "1000": 862, "2000": 631}}, {"id": 4122, "position": 4122, "text": "starry Cetus far beyond the utmost stretch of Hydrus and\nthe Flying Fish.\n\nWith a frigate’s anchors for my bridle-bitts and fasces of harpoons for\nspurs, would I could mount that whale and leap", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4123, "position": 4123, "text": "es of harpoons for\nspurs, would I could mount that whale and leap the topmost skies, to\nsee whether the fabled heavens with all their countless tents really\nlie encamped beyond my mortal sight!\n\n\nCHAPTER 58. Brit.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4124, "position": 4124, "text": "camped beyond my mortal sight!\n\n\nCHAPTER 58. Brit.\n\nSteering north-eastward from the Crozetts, we fell in with vast meadows\nof brit, the minute, yellow substance, upon which the Right Whale\nlargely feeds", "labels": {"50": 45, "100": 43, "250": 138, "500": 48, "1000": 997, "2000": 1931}}, {"id": 4125, "position": 4125, "text": "yellow substance, upon which the Right Whale\nlargely feeds. For leagues and leagues it undulated round us, so that\nwe seemed to be sailing through boundless fields of ripe and golden\nwheat.\n\nOn the second day, numbers of Right Whales were seen,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 631}}, {"id": 4126, "position": 4126, "text": "golden\nwheat.\n\nOn the second day, numbers of Right Whales were seen, who, secure from\nthe attack of a Sperm Whaler like the Pequod, with open jaws sluggishly\nswam through the brit, which, adhering to the fr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4127, "position": 4127, "text": "sluggishly\nswam through the brit, which, adhering to the fringing fibres of that\nwondrous Venetian blind in their mouths, was in that manner separated\nfrom the water that escaped at the lip.", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 858, "2000": 110}}, {"id": 4128, "position": 4128, "text": "the water that escaped at the lip.\n\nAs morning mowers, who side by side slowly and seethingly advance their\nscythes through the long wet grass of marshy meads; even so these\nmonsters swam, making a strange, grassy", "labels": {"50": 48, "100": 20, "250": 53, "500": 162, "1000": 995, "2000": 1650}}, {"id": 4129, "position": 4129, "text": "y meads; even so these\nmonsters swam, making a strange, grassy, cutting sound; and leaving\nbehind them endless swaths of blue upon the yellow sea.*\n\n*That part of the sea known among whalemen as the “Brazil Banks”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4130, "position": 4130, "text": "That part of the sea known among whalemen as the “Brazil Banks” does\nnot bear that name as the Banks of Newfoundland do, because of there\nbeing shallows and soundings there, but because of this remarkable\nmeadow-like appearance, caused by", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4131, "position": 4131, "text": "s there, but because of this remarkable\nmeadow-like appearance, caused by the vast drifts of brit continually\nfloating in those latitudes, where the Right Whale is often chased.\n\nBut it was only the sound they made as they parted the brit which", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4132, "position": 4132, "text": ".\n\nBut it was only the sound they made as they parted the brit which at\nall reminded one of mowers. Seen from the mast-heads, especially when\nthey paused and were stationary for a while, their vast black forms\nlooked more like lifeless", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 4133, "position": 4133, "text": "and were stationary for a while, their vast black forms\nlooked more like lifeless masses of rock than anything else. And as in\nthe great hunting countries of India, the stranger at a distance will\nsometimes pass on the plains recumbent elephants without knowing them", "labels": {"50": 12, "100": 24, "250": 52, "500": 435, "1000": 653, "2000": 145}}, {"id": 4134, "position": 4134, "text": "a distance will\nsometimes pass on the plains recumbent elephants without knowing them\nto be such, taking them for bare, blackened elevations of the soil;\neven so, often, with him, who for the first time beholds this species\nof the levi", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 145}}, {"id": 4135, "position": 4135, "text": "with him, who for the first time beholds this species\nof the leviathans of the sea. And even when recognised at last, their\nimmense magnitude renders it very hard really to believe that such\nbulky masses of overgrowth can possibly be instinct", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4136, "position": 4136, "text": "hard really to believe that such\nbulky masses of overgrowth can possibly be instinct, in all parts, with\nthe same sort of life that lives in a dog or a horse.\n\nIndeed, in other respects, you can hardly regard any creatures of the\ndeep", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 4137, "position": 4137, "text": "Indeed, in other respects, you can hardly regard any creatures of the\ndeep with the same feelings that you do those of the shore. For though\nsome old naturalists have maintained that all creatures of the land are\nof their kind in the sea; and", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4138, "position": 4138, "text": "that all creatures of the land are\nof their kind in the sea; and though taking a broad general view of the\nthing, this may very well be; yet coming to specialties, where, for\nexample, does the ocean furnish any fish that", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 368, "2000": 334}}, {"id": 4139, "position": 4139, "text": "ties, where, for\nexample, does the ocean furnish any fish that in disposition answers to\nthe sagacious kindness of the dog? The accursed shark alone can in any\ngeneric respect be said to bear comparative analogy to him.", "labels": {"50": 31, "100": 75, "250": 129, "500": 307, "1000": 134, "2000": 1394}}, {"id": 4140, "position": 4140, "text": "any\ngeneric respect be said to bear comparative analogy to him.\n\nBut though, to landsmen in general, the native inhabitants of the seas\nhave ever been regarded with emotions unspeakably unsocial and\nrepelling; though we know the sea to", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 4141, "position": 4141, "text": "eakably unsocial and\nrepelling; though we know the sea to be an everlasting terra incognita,\nso that Columbus sailed over numberless unknown worlds to discover his\none superficial western one; though, by vast odds, the", "labels": {"50": 31, "100": 20, "250": 132, "500": 126, "1000": 727, "2000": 1466}}, {"id": 4142, "position": 4142, "text": "to discover his\none superficial western one; though, by vast odds, the most terrific of\nall mortal disasters have immemorially and indiscriminately befallen\ntens and hundreds of thousands of those who have gone upon the waters;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 4143, "position": 4143, "text": "en\ntens and hundreds of thousands of those who have gone upon the waters;\nthough but a moment’s consideration will teach, that however baby man\nmay brag of his science and skill, and however much, in a flattering\nfuture, that science", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 4144, "position": 4144, "text": "and skill, and however much, in a flattering\nfuture, that science and skill may augment; yet for ever and for ever,\nto the crack of doom, the sea will insult and murder him, and pulverize\nthe stateliest,", "labels": {"50": 10, "100": 75, "250": 13, "500": 307, "1000": 256, "2000": 1385}}, {"id": 4145, "position": 4145, "text": "sea will insult and murder him, and pulverize\nthe stateliest, stiffest frigate he can make; nevertheless, by the\ncontinual repetition of these very impressions, man has lost that sense\nof the full awfulness of the sea which aboriginally belongs", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 887}}, {"id": 4146, "position": 4146, "text": "lost that sense\nof the full awfulness of the sea which aboriginally belongs to it.\n\nThe first boat we read of, floated on an ocean, that with Portuguese\nvengeance had whelmed a whole world without leaving so much as a widow", "labels": {"50": 15, "100": 95, "250": 43, "500": 480, "1000": 347, "2000": 759}}, {"id": 4147, "position": 4147, "text": "whelmed a whole world without leaving so much as a widow.\nThat same ocean rolls now; that same ocean destroyed the wrecked ships\nof last year. Yea, foolish mortals, Noah’s flood is not yet subsided;\ntwo thirds of the", "labels": {"50": 16, "100": 20, "250": 69, "500": 414, "1000": 747, "2000": 709}}, {"id": 4148, "position": 4148, "text": "mortals, Noah’s flood is not yet subsided;\ntwo thirds of the fair world it yet covers.\n\nWherein differ the sea and the land, that a miracle upon one is not a\nmiracle upon the other? Preternatural terrors rested upon", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4149, "position": 4149, "text": "not a\nmiracle upon the other? Preternatural terrors rested upon the Hebrews,\nwhen under the feet of Korah and his company the live ground opened and\nswallowed them up for ever; yet not a modern sun ever sets, but in", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 709}}, {"id": 4150, "position": 4150, "text": "them up for ever; yet not a modern sun ever sets, but in\nprecisely the same manner the live sea swallows up ships and crews.\n\nBut not only is the sea such a foe to man who is an alien to it, but it\nis also", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 4151, "position": 4151, "text": "a foe to man who is an alien to it, but it\nis also a fiend to its own off-spring; worse than the Persian host who\nmurdered his own guests; sparing not the creatures which itself hath\nspawned", "labels": {"50": 31, "100": 75, "250": 69, "500": 307, "1000": 343, "2000": 1394}}, {"id": 4152, "position": 4152, "text": "; sparing not the creatures which itself hath\nspawned. Like a savage tigress that tossing in the jungle overlays her\nown cubs, so the sea dashes even the mightiest whales against the\nrocks, and leaves them there side by", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 437, "2000": 1374}}, {"id": 4153, "position": 4153, "text": "even the mightiest whales against the\nrocks, and leaves them there side by side with the split wrecks of\nships. No mercy, no power but its own controls it. Panting and snorting\nlike a mad battle steed that has lost its rider", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4154, "position": 4154, "text": "Panting and snorting\nlike a mad battle steed that has lost its rider, the masterless ocean\noverruns the globe.\n\nConsider the subtleness of the sea; how its most dreaded creatures\nglide under water, unapparent for the most part", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 631}}, {"id": 4155, "position": 4155, "text": "most dreaded creatures\nglide under water, unapparent for the most part, and treacherously\nhidden beneath the loveliest tints of azure. Consider also the devilish\nbrilliance and beauty of many of its most remorseless tribes, as the\ndainty", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 4156, "position": 4156, "text": "and beauty of many of its most remorseless tribes, as the\ndainty embellished shape of many species of sharks. Consider, once\nmore, the universal cannibalism of the sea; all whose creatures prey\nupon each other, carrying on", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4157, "position": 4157, "text": "ism of the sea; all whose creatures prey\nupon each other, carrying on eternal war since the world began.\n\nConsider all this; and then turn to this green, gentle, and most docile\nearth; consider them both, the sea and the land", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4158, "position": 4158, "text": "and most docile\nearth; consider them both, the sea and the land; and do you not find a\nstrange analogy to something in yourself? For as this appalling ocean\nsurrounds the verdant land, so in the soul of man there", "labels": {"50": 31, "100": 20, "250": 13, "500": 307, "1000": 343, "2000": 761}}, {"id": 4159, "position": 4159, "text": "ocean\nsurrounds the verdant land, so in the soul of man there lies one\ninsular Tahiti, full of peace and joy, but encompassed by all the\nhorrors of the half known life. God keep thee! Push not off from that\nisle", "labels": {"50": 45, "100": 20, "250": 130, "500": 494, "1000": 480, "2000": 187}}, {"id": 4160, "position": 4160, "text": "the half known life. God keep thee! Push not off from that\nisle, thou canst never return!\n\n\nCHAPTER 59. Squid.\n\nSlowly wading through the meadows of brit, the Pequod still held on her\nway north-eastward towards the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4161, "position": 4161, "text": ", the Pequod still held on her\nway north-eastward towards the island of Java; a gentle air impelling\nher keel, so that in the surrounding serenity her three tall tapering\nmasts mildly waved to that languid breeze, as", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4162, "position": 4162, "text": "three tall tapering\nmasts mildly waved to that languid breeze, as three mild palms on a\nplain. And still, at wide intervals in the silvery night, the lonely,\nalluring jet would be seen.", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 531, "2000": 887}}, {"id": 4163, "position": 4163, "text": ",\nalluring jet would be seen.\n\nBut one transparent blue morning, when a stillness almost preternatural\nspread over the sea, however unattended with any stagnant calm; when\nthe long burnished sun-glade on the waters", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 1620}}, {"id": 4164, "position": 4164, "text": "nant calm; when\nthe long burnished sun-glade on the waters seemed a golden finger laid\nacross them, enjoining some secrecy; when the slippered waves whispered\ntogether as they softly ran on; in this profound hush of the visible", "labels": {"50": 16, "100": 73, "250": 15, "500": 406, "1000": 779, "2000": 471}}, {"id": 4165, "position": 4165, "text": "whispered\ntogether as they softly ran on; in this profound hush of the visible\nsphere a strange spectre was seen by Daggoo from the main-mast-head.\n\nIn the distance, a great white mass lazily rose, and rising higher and", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4166, "position": 4166, "text": "the distance, a great white mass lazily rose, and rising higher and\nhigher, and disentangling itself from the azure, at last gleamed before\nour prow like a snow-slide, new slid from the hills", "labels": {"50": 25, "100": 5, "250": 26, "500": 233, "1000": 35, "2000": 448}}, {"id": 4167, "position": 4167, "text": "a snow-slide, new slid from the hills. Thus glistening\nfor a moment, as slowly it subsided, and sank. Then once more arose,\nand silently gleamed. It seemed not a whale; and yet is this Moby Dick?\nthought Da", "labels": {"50": 16, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 16}}, {"id": 4168, "position": 4168, "text": "seemed not a whale; and yet is this Moby Dick?\nthought Daggoo. Again the phantom went down, but on re-appearing once\nmore, with a stiletto-like cry that startled every man from his nod,\nthe negro yelled", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4169, "position": 4169, "text": "etto-like cry that startled every man from his nod,\nthe negro yelled out—“There! there again! there she breaches! right\nahead! The White Whale, the White Whale!”\n\nUpon this, the seamen rushed to the yard-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4170, "position": 4170, "text": "the White Whale!”\n\nUpon this, the seamen rushed to the yard-arms, as in swarming-time the\nbees rush to the boughs. Bare-headed in the sultry sun, Ahab stood on\nthe bowsprit,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4171, "position": 4171, "text": "in the sultry sun, Ahab stood on\nthe bowsprit, and with one hand pushed far behind in readiness to wave\nhis orders to the helmsman, cast his eager glance in the direction\nindicated aloft by the outstretched motionless arm of Da", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4172, "position": 4172, "text": "eager glance in the direction\nindicated aloft by the outstretched motionless arm of Daggoo.\n\nWhether the flitting attendance of the one still and solitary jet had\ngradually worked upon Ahab, so that he was now prepared to connect the\nideas of mild", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4173, "position": 4173, "text": "Ahab, so that he was now prepared to connect the\nideas of mildness and repose with the first sight of the particular\nwhale he pursued; however this was, or whether his eagerness betrayed\nhim; whichever way it might have been, no", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4174, "position": 4174, "text": "whether his eagerness betrayed\nhim; whichever way it might have been, no sooner did he distinctly\nperceive the white mass, than with a quick intensity he instantly gave\norders for lowering.\n\nThe four boats were soon on the water; Ahab’s in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4175, "position": 4175, "text": ".\n\nThe four boats were soon on the water; Ahab’s in advance, and all\nswiftly pulling towards their prey. Soon it went down, and while, with\noars suspended, we were awaiting its reappearance, lo! in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4176, "position": 4176, "text": "ars suspended, we were awaiting its reappearance, lo! in the same spot\nwhere it sank, once more it slowly rose. Almost forgetting for the\nmoment all thoughts of Moby Dick, we now gazed at the most wondrous\nphenomenon", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4177, "position": 4177, "text": "of Moby Dick, we now gazed at the most wondrous\nphenomenon which the secret seas have hitherto revealed to mankind. A\nvast pulpy mass, furlongs in length and breadth, of a glancing\ncream-colour, lay floating on the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4178, "position": 4178, "text": "length and breadth, of a glancing\ncream-colour, lay floating on the water, innumerable long arms\nradiating from its centre, and curling and twisting like a nest of\nanacondas, as if blindly to clutch at any hapless object", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4179, "position": 4179, "text": "anacondas, as if blindly to clutch at any hapless object within reach.\nNo perceptible face or front did it have; no conceivable token of\neither sensation or instinct; but undulated there on the billows", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1014}}, {"id": 4180, "position": 4180, "text": "token of\neither sensation or instinct; but undulated there on the billows, an\nunearthly, formless, chance-like apparition of life.\n\nAs with a low sucking sound it slowly disappeared again, Starbuck still\ngazing at the", "labels": {"50": 22, "100": 78, "250": 28, "500": 469, "1000": 328, "2000": 213}}, {"id": 4181, "position": 4181, "text": "a low sucking sound it slowly disappeared again, Starbuck still\ngazing at the agitated waters where it had sunk, with a wild voice\nexclaimed—“Almost rather had I seen Moby Dick and fought him, than to\nhave seen thee, thou white ghost", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4182, "position": 4182, "text": "y Dick and fought him, than to\nhave seen thee, thou white ghost!”\n\n“What was it, Sir?” said Flask.\n\n“The great live squid, which, they say, few whale-ships ever beheld,\nand returned", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4183, "position": 4183, "text": "which, they say, few whale-ships ever beheld,\nand returned to their ports to tell of it.”\n\nBut Ahab said nothing; turning his boat, he sailed back to the vessel;\nthe rest as silently following.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4184, "position": 4184, "text": "sailed back to the vessel;\nthe rest as silently following.\n\nWhatever superstitions the sperm whalemen in general have connected\nwith the sight of this object, certain it is, that a glimpse of it\nbeing so very unusual, that circumstance has gone far", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4185, "position": 4185, "text": "that a glimpse of it\nbeing so very unusual, that circumstance has gone far to invest it with\nportentousness. So rarely is it beheld, that though one and all of them\ndeclare it to be the largest animated thing in the ocean,", "labels": {"50": 31, "100": 20, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4186, "position": 4186, "text": "all of them\ndeclare it to be the largest animated thing in the ocean, yet very few\nof them have any but the most vague ideas concerning its true nature\nand form; notwithstanding, they believe it to furnish to the sperm\nwhale his only food", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4187, "position": 4187, "text": ", they believe it to furnish to the sperm\nwhale his only food. For though other species of whales find their food\nabove water, and may be seen by man in the act of feeding, the\nspermaceti whale obtains his whole food in", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4188, "position": 4188, "text": "act of feeding, the\nspermaceti whale obtains his whole food in unknown zones below the\nsurface; and only by inference is it that any one can tell of what,\nprecisely, that food consists. At times, when closely pursued, he will", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4189, "position": 4189, "text": "precisely, that food consists. At times, when closely pursued, he will\ndisgorge what are supposed to be the detached arms of the squid; some\nof them thus exhibited exceeding twenty and thirty feet in length", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4190, "position": 4190, "text": "exhibited exceeding twenty and thirty feet in length. They\nfancy that the monster to which these arms belonged ordinarily clings\nby them to the bed of the ocean; and that the sperm whale, unlike other\nspecies, is supplied with teeth in order to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4191, "position": 4191, "text": "the sperm whale, unlike other\nspecies, is supplied with teeth in order to attack and tear it.\n\nThere seems some ground to imagine that the great Kraken of Bishop\nPontoppodan may ultimately resolve itself into Squid", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4192, "position": 4192, "text": "oppodan may ultimately resolve itself into Squid. The manner in\nwhich the Bishop describes it, as alternately rising and sinking, with\nsome other particulars he narrates, in all this the two correspond", "labels": {"50": 5, "100": 66, "250": 12, "500": 32, "1000": 966, "2000": 1122}}, {"id": 4193, "position": 4193, "text": "in all this the two correspond. But\nmuch abatement is necessary with respect to the incredible bulk he\nassigns it.\n\nBy some naturalists who have vaguely heard rumors of the mysterious\ncreature, here spoken of, it is included among the class of\ncut", "labels": {"50": 45, "100": 42, "250": 131, "500": 13, "1000": 622, "2000": 1533}}, {"id": 4194, "position": 4194, "text": "mysterious\ncreature, here spoken of, it is included among the class of\ncuttle-fish, to which, indeed, in certain external respects it would\nseem to belong, but only as the Anak of the tribe.\n\n\nCHAPTER 60. The Line.", "labels": {"50": 3, "100": 24, "250": 211, "500": 288, "1000": 825, "2000": 1620}}, {"id": 4195, "position": 4195, "text": "only as the Anak of the tribe.\n\n\nCHAPTER 60. The Line.\n\nWith reference to the whaling scene shortly to be described, as well as\nfor the better understanding of all similar scenes elsewhere presented,\nI have here to speak of the magical, sometimes", "labels": {"50": 45, "100": 42, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4196, "position": 4196, "text": "similar scenes elsewhere presented,\nI have here to speak of the magical, sometimes horrible whale-line.\n\nThe line originally used in the fishery was of the best hemp, slightly\nvapored with tar, not impregnated with it, as in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4197, "position": 4197, "text": "vapored with tar, not impregnated with it, as in the case of ordinary\nropes; for while tar, as ordinarily used, makes the hemp more pliable\nto the rope-maker, and also renders the rope", "labels": {"50": 42, "100": 46, "250": 46, "500": 197, "1000": 210, "2000": 307}}, {"id": 4198, "position": 4198, "text": "more pliable\nto the rope-maker, and also renders the rope itself more convenient to\nthe sailor for common ship use; yet, not only would the ordinary\nquantity too much stiffen the whale-line for the close coiling to which\nit", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4199, "position": 4199, "text": "much stiffen the whale-line for the close coiling to which\nit must be subjected; but as most seamen are beginning to learn, tar in\ngeneral by no means adds to the rope’s durability or strength, however\nmuch it may", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4200, "position": 4200, "text": "to the rope’s durability or strength, however\nmuch it may give it compactness and gloss.\n\nOf late years the Manilla rope has in the American fishery almost\nentirely superseded hemp as a material for whale-lines; for, though", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4201, "position": 4201, "text": "entirely superseded hemp as a material for whale-lines; for, though not\nso durable as hemp, it is stronger, and far more soft and elastic; and\nI will add (since there is an æsthetics in all things)", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4202, "position": 4202, "text": "will add (since there is an æsthetics in all things), is much more\nhandsome and becoming to the boat, than hemp. Hemp is a dusky, dark\nfellow, a sort of Indian; but Manilla is as", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 505, "2000": 744}}, {"id": 4203, "position": 4203, "text": "y, dark\nfellow, a sort of Indian; but Manilla is as a golden-haired Circassian\nto behold.\n\nThe whale-line is only two-thirds of an inch in thickness. At first\nsight, you would not think it so", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4204, "position": 4204, "text": "an inch in thickness. At first\nsight, you would not think it so strong as it really is. By experiment\nits one and fifty yarns will each suspend a weight of one hundred and\ntwenty pounds; so that the whole rope will bear a strain", "labels": {"50": 45, "100": 63, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4205, "position": 4205, "text": "one hundred and\ntwenty pounds; so that the whole rope will bear a strain nearly equal\nto three tons. In length, the common sperm whale-line measures\nsomething over two hundred fathoms. Towards the stern of the boat it is\nspirally coiled", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4206, "position": 4206, "text": "fathoms. Towards the stern of the boat it is\nspirally coiled away in the tub, not like the worm-pipe of a still\nthough, but so as to form one round, cheese-shaped mass of densely\nbedded “sheaves", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4207, "position": 4207, "text": "form one round, cheese-shaped mass of densely\nbedded “sheaves,” or layers of concentric spiralizations, without any\nhollow but the “heart,” or minute vertical tube formed at the axis of\nthe cheese", "labels": {"50": 3, "100": 70, "250": 46, "500": 255, "1000": 109, "2000": 670}}, {"id": 4208, "position": 4208, "text": "minute vertical tube formed at the axis of\nthe cheese. As the least tangle or kink in the coiling would, in\nrunning out, infallibly take somebody’s arm, leg, or entire body off,\nthe utmost precaution is", "labels": {"50": 3, "100": 70, "250": 46, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4209, "position": 4209, "text": "arm, leg, or entire body off,\nthe utmost precaution is used in stowing the line in its tub. Some\nharpooneers will consume almost an entire morning in this business,\ncarrying the line high aloft and then reeving it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4210, "position": 4210, "text": "in this business,\ncarrying the line high aloft and then reeving it downwards through a\nblock towards the tub, so as in the act of coiling to free it from all\npossible wrinkles and twists.", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 486, "2000": 447}}, {"id": 4211, "position": 4211, "text": "all\npossible wrinkles and twists.\n\nIn the English boats two tubs are used instead of one; the same line\nbeing continuously coiled in both tubs. There is some advantage in\nthis; because these twin-tubs being so small they fit more", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 611, "2000": 735}}, {"id": 4212, "position": 4212, "text": "in\nthis; because these twin-tubs being so small they fit more readily into\nthe boat, and do not strain it so much; whereas, the American tub,\nnearly three feet in diameter and of proportionate depth, makes a\nrather bulky freight", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 887}}, {"id": 4213, "position": 4213, "text": "three feet in diameter and of proportionate depth, makes a\nrather bulky freight for a craft whose planks are but one half-inch in\nthickness; for the bottom of the whale-boat is like critical ice, which\nwill bear up a considerable distributed", "labels": {"50": 45, "100": 64, "250": 138, "500": 48, "1000": 327, "2000": 1620}}, {"id": 4214, "position": 4214, "text": "whale-boat is like critical ice, which\nwill bear up a considerable distributed weight, but not very much of a\nconcentrated one. When the painted canvas cover is clapped on the\nAmerican line-tub, the boat looks as if it were pulling off with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4215, "position": 4215, "text": "American line-tub, the boat looks as if it were pulling off with a\nprodigious great wedding-cake to present to the whales.\n\nBoth ends of the line are exposed; the lower end terminating in an\neye-splice or loop", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4216, "position": 4216, "text": "are exposed; the lower end terminating in an\neye-splice or loop coming up from the bottom against the side of the\ntub, and hanging over its edge completely disengaged from everything.\nThis arrangement of the lower end is necessary on two", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 486, "2000": 628}}, {"id": 4217, "position": 4217, "text": "gaged from everything.\nThis arrangement of the lower end is necessary on two accounts. First:\nIn order to facilitate the fastening to it of an additional line from a\nneighboring boat, in case the stricken whale should sound so deep as to\nthreaten to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4218, "position": 4218, "text": "boat, in case the stricken whale should sound so deep as to\nthreaten to carry off the entire line originally attached to the\nharpoon. In these instances, the whale of course is shifted like a mug\nof ale, as it were, from the one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4219, "position": 4219, "text": "is shifted like a mug\nof ale, as it were, from the one boat to the other; though the first\nboat always hovers at hand to assist its consort. Second: This\narrangement is indispensable for common safety’s sake;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4220, "position": 4220, "text": ": This\narrangement is indispensable for common safety’s sake; for were the\nlower end of the line in any way attached to the boat, and were the\nwhale then to run the line out to the end almost in a single, smoking", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4221, "position": 4221, "text": "then to run the line out to the end almost in a single, smoking\nminute as he sometimes does, he would not stop there, for the doomed\nboat would infallibly be dragged down after him into the profundity of\nthe sea; and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4222, "position": 4222, "text": "be dragged down after him into the profundity of\nthe sea; and in that case no town-crier would ever find her again.\n\nBefore lowering the boat for the chase, the upper end of the line is\ntaken aft from the tub,", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4223, "position": 4223, "text": "chase, the upper end of the line is\ntaken aft from the tub, and passing round the loggerhead there, is\nagain carried forward the entire length of the boat, resting crosswise\nupon the loom or handle of every man’s o", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4224, "position": 4224, "text": "resting crosswise\nupon the loom or handle of every man’s oar, so that it jogs against his\nwrist in rowing; and also passing between the men, as they alternately\nsit at the opposite gunwales, to the leaded", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4225, "position": 4225, "text": "as they alternately\nsit at the opposite gunwales, to the leaded chocks or grooves in the\nextreme pointed prow of the boat, where a wooden pin or skewer the size\nof a common quill, prevents it from slipping out", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4226, "position": 4226, "text": "ewer the size\nof a common quill, prevents it from slipping out. From the chocks it\nhangs in a slight festoon over the bows, and is then passed inside the\nboat again; and some ten or twenty fathoms (called", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4227, "position": 4227, "text": "inside the\nboat again; and some ten or twenty fathoms (called box-line) being\ncoiled upon the box in the bows, it continues its way to the gunwale\nstill a little further aft, and is then attached to the short", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4228, "position": 4228, "text": "wale\nstill a little further aft, and is then attached to the short-warp—the\nrope which is immediately connected with the harpoon; but previous to\nthat connexion, the short-warp goes through sundry mystifications", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4229, "position": 4229, "text": "xion, the short-warp goes through sundry mystifications too\ntedious to detail.\n\nThus the whale-line folds the whole boat in its complicated coils,\ntwisting and writhing around it in almost every direction", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4230, "position": 4230, "text": ",\ntwisting and writhing around it in almost every direction. All the\noarsmen are involved in its perilous contortions; so that to the timid\neye of the landsman, they seem as Indian jugglers, with the deadliest", "labels": {"50": 48, "100": 42, "250": 49, "500": 247, "1000": 917, "2000": 616}}, {"id": 4231, "position": 4231, "text": "the landsman, they seem as Indian jugglers, with the deadliest\nsnakes sportively festooning their limbs. Nor can any son of mortal\nwoman, for the first time, seat himself amid those hempen intricacies,\nand while straining", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 39}}, {"id": 4232, "position": 4232, "text": "time, seat himself amid those hempen intricacies,\nand while straining his utmost at the oar, bethink him that at any\nunknown instant the harpoon may be darted, and all these horrible\ncontortions be put in play like ring", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4233, "position": 4233, "text": "darted, and all these horrible\ncontortions be put in play like ringed lightnings; he cannot be thus\ncircumstanced without a shudder that makes the very marrow in his bones\nto quiver in him like a shaken jelly", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 39}}, {"id": 4234, "position": 4234, "text": "bones\nto quiver in him like a shaken jelly. Yet habit—strange thing! what\ncannot habit accomplish?—Gayer sallies, more merry mirth, better jokes,\nand brighter repartees, you never heard over your mahogany, than you", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 4235, "position": 4235, "text": "and brighter repartees, you never heard over your mahogany, than you\nwill hear over the half-inch white cedar of the whale-boat, when thus\nhung in hangman’s nooses; and, like the six burghers of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4236, "position": 4236, "text": "man’s nooses; and, like the six burghers of Calais before\nKing Edward, the six men composing the crew pull into the jaws of\ndeath, with a halter around every neck, as you may say.", "labels": {"50": 18, "100": 83, "250": 92, "500": 61, "1000": 672, "2000": 430}}, {"id": 4237, "position": 4237, "text": "halter around every neck, as you may say.\n\nPerhaps a very little thought will now enable you to account for those\nrepeated whaling disasters—some few of which are casually chronicled—of\nthis man or that man being taken out of the boat by", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4238, "position": 4238, "text": "d—of\nthis man or that man being taken out of the boat by the line, and lost.\nFor, when the line is darting out, to be seated then in the boat, is\nlike being seated in the midst of the manifold whi", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 18, "2000": 1274}}, {"id": 4239, "position": 4239, "text": "the boat, is\nlike being seated in the midst of the manifold whizzings of a\nsteam-engine in full play, when every flying beam, and shaft, and\nwheel, is grazing you", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4240, "position": 4240, "text": "and\nwheel, is grazing you. It is worse; for you cannot sit motionless in\nthe heart of these perils, because the boat is rocking like a cradle,\nand you are pitched one way and the other, without the slightest\nwarning; and only", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 4241, "position": 4241, "text": "are pitched one way and the other, without the slightest\nwarning; and only by a certain self-adjusting buoyancy and\nsimultaneousness of volition and action, can you escape being made a\nMazeppa of, and run away with where the all", "labels": {"50": 31, "100": 20, "250": 49, "500": 334, "1000": 747, "2000": 1710}}, {"id": 4242, "position": 4242, "text": "escape being made a\nMazeppa of, and run away with where the all-seeing sun himself could\nnever pierce you out.\n\nAgain: as the profound calm which only apparently precedes and\nprophesies of the storm, is perhaps more awful than", "labels": {"50": 8, "100": 14, "250": 132, "500": 374, "1000": 318, "2000": 1031}}, {"id": 4243, "position": 4243, "text": "cedes and\nprophesies of the storm, is perhaps more awful than the storm itself;\nfor, indeed, the calm is but the wrapper and envelope of the storm; and\ncontains it in itself, as the seemingly harmless rifle holds the fatal", "labels": {"50": 45, "100": 5, "250": 138, "500": 388, "1000": 9, "2000": 731}}, {"id": 4244, "position": 4244, "text": "; and\ncontains it in itself, as the seemingly harmless rifle holds the fatal\npowder, and the ball, and the explosion; so the graceful repose of the\nline, as it silently serpentines about the oarsmen before being brought\ninto actual play", "labels": {"50": 31, "100": 24, "250": 49, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4245, "position": 4245, "text": "it silently serpentines about the oarsmen before being brought\ninto actual play—this is a thing which carries more of true terror than\nany other aspect of this dangerous affair. But why say more? All men\nlive enveloped in whale-lines", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4246, "position": 4246, "text": "But why say more? All men\nlive enveloped in whale-lines. All are born with halters round their\nnecks; but it is only when caught in the swift, sudden turn of death,\nthat mortals realize the silent, subtle, ever-present", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4247, "position": 4247, "text": "turn of death,\nthat mortals realize the silent, subtle, ever-present perils of life.\nAnd if you be a philosopher, though seated in the whale-boat, you would\nnot at heart feel one whit more of terror, than though", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4248, "position": 4248, "text": "you would\nnot at heart feel one whit more of terror, than though seated before\nyour evening fire with a poker, and not a harpoon, by your side.\n\n\nCHAPTER 61. Stubb Kills a Whale.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4249, "position": 4249, "text": "61. Stubb Kills a Whale.\n\nIf to Starbuck the apparition of the Squid was a thing of portents, to\nQueequeg it was quite a different object.\n\n“When you see him ’quid,” said the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4250, "position": 4250, "text": "different object.\n\n“When you see him ’quid,” said the savage, honing his harpoon in the\nbow of his hoisted boat, “then you quick see him ’parm whale.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 480, "2000": 187}}, {"id": 4251, "position": 4251, "text": "him ’parm whale.”\n\nThe next day was exceedingly still and sultry, and with nothing special\nto engage them, the Pequod’s crew could hardly resist the spell of\nsleep induced by such a vacant sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4252, "position": 4252, "text": "resist the spell of\nsleep induced by such a vacant sea. For this part of the Indian Ocean\nthrough which we then were voyaging is not what whalemen call a lively\nground; that is, it affords fewer glimpses of porpoises", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4253, "position": 4253, "text": "ground; that is, it affords fewer glimpses of porpoises, dolphins,\nflying-fish, and other vivacious denizens of more stirring waters, than\nthose off the Rio de la Plata, or the in-shore ground off", "labels": {"50": 3, "100": 24, "250": 234, "500": 288, "1000": 825, "2000": 1225}}, {"id": 4254, "position": 4254, "text": "those off the Rio de la Plata, or the in-shore ground off Peru.\n\nIt was my turn to stand at the foremast-head; and with my shoulders\nleaning against the slackened royal shrouds, to and fro I", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 4255, "position": 4255, "text": "leaning against the slackened royal shrouds, to and fro I idly swayed\nin what seemed an enchanted air. No resolution could withstand it; in\nthat dreamy mood losing all consciousness, at last my soul went out of\nmy body;", "labels": {"50": 20, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1254}}, {"id": 4256, "position": 4256, "text": "mood losing all consciousness, at last my soul went out of\nmy body; though my body still continued to sway as a pendulum will,\nlong after the power which first moved it is withdrawn.\n\nEre forgetfulness altogether came over me, I had noticed", "labels": {"50": 20, "100": 5, "250": 45, "500": 411, "1000": 51, "2000": 1254}}, {"id": 4257, "position": 4257, "text": "is withdrawn.\n\nEre forgetfulness altogether came over me, I had noticed that the\nseamen at the main and mizzen-mast-heads were already drowsy. So that\nat last all three of us lifelessly swung from the spars", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1192}}, {"id": 4258, "position": 4258, "text": "So that\nat last all three of us lifelessly swung from the spars, and for every\nswing that we made there was a nod from below from the slumbering\nhelmsman. The waves, too, nodded their indolent crests; and", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 4259, "position": 4259, "text": "sman. The waves, too, nodded their indolent crests; and across the\nwide trance of the sea, east nodded to west, and the sun over all.\n\nSuddenly bubbles seemed bursting beneath my closed eyes; like vices my\nhands grasped the", "labels": {"50": 16, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1860}}, {"id": 4260, "position": 4260, "text": "bubbles seemed bursting beneath my closed eyes; like vices my\nhands grasped the shrouds; some invisible, gracious agency preserved\nme; with a shock I came back to life. And lo! close under our lee, not\nforty fathoms", "labels": {"50": 16, "100": 73, "250": 26, "500": 411, "1000": 914, "2000": 1860}}, {"id": 4261, "position": 4261, "text": "life. And lo! close under our lee, not\nforty fathoms off, a gigantic Sperm Whale lay rolling in the water like\nthe capsized hull of a frigate, his broad, glossy back, of an Ethiopian\nhue, glistening in the sun", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4262, "position": 4262, "text": "his broad, glossy back, of an Ethiopian\nhue, glistening in the sun’s rays like a mirror. But lazily undulating\nin the trough of the sea, and ever and anon tranquilly spouting his\nvapory jet,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4263, "position": 4263, "text": "ever and anon tranquilly spouting his\nvapory jet, the whale looked like a portly burgher smoking his pipe of\na warm afternoon. But that pipe, poor whale, was thy last", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4264, "position": 4264, "text": "pipe, poor whale, was thy last. As if struck\nby some enchanter’s wand, the sleepy ship and every sleeper in it all\nat once started into wakefulness; and more than a score of voices from\nall parts of the vessel", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4265, "position": 4265, "text": "fulness; and more than a score of voices from\nall parts of the vessel, simultaneously with the three notes from\naloft, shouted forth the accustomed cry, as the great fish slowly and\nregularly spouted the sparkling brine into the air.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4266, "position": 4266, "text": "slowly and\nregularly spouted the sparkling brine into the air.\n\n“Clear away the boats! Luff!” cried Ahab. And obeying his own order, he\ndashed the helm down before the helmsman could handle the spokes.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4267, "position": 4267, "text": "he\ndashed the helm down before the helmsman could handle the spokes.\n\nThe sudden exclamations of the crew must have alarmed the whale; and\nere the boats were down, majestically turning, he swam away to the\nleeward,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4268, "position": 4268, "text": "were down, majestically turning, he swam away to the\nleeward, but with such a steady tranquillity, and making so few ripples\nas he swam, that thinking after all he might not as yet be alarmed,\nAhab gave orders", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4269, "position": 4269, "text": "thinking after all he might not as yet be alarmed,\nAhab gave orders that not an oar should be used, and no man must speak\nbut in whispers. So seated like Ontario Indians on the gunwales of the\nboats, we swiftly but", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4270, "position": 4270, "text": "like Ontario Indians on the gunwales of the\nboats, we swiftly but silently paddled along; the calm not admitting of\nthe noiseless sails being set. Presently, as we thus glided in chase,\nthe monster perpendicularly flitted his tail", "labels": {"50": 12, "100": 64, "250": 95, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4271, "position": 4271, "text": "we thus glided in chase,\nthe monster perpendicularly flitted his tail forty feet into the air,\nand then sank out of sight like a tower swallowed up.\n\n“There go flukes!” was the cry, an announcement immediately followed by\nStu", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4272, "position": 4272, "text": "go flukes!” was the cry, an announcement immediately followed by\nStubb’s producing his match and igniting his pipe, for now a respite\nwas granted. After the full interval of his sounding had elapsed, the\nwhale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4273, "position": 4273, "text": ". After the full interval of his sounding had elapsed, the\nwhale rose again, and being now in advance of the smoker’s boat, and\nmuch nearer to it than to any of the others, Stubb counted upon the\nhonor of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4274, "position": 4274, "text": "it than to any of the others, Stubb counted upon the\nhonor of the capture. It was obvious, now, that the whale had at length\nbecome aware of his pursuers. All silence of cautiousness was therefore\nno longer of use", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4275, "position": 4275, "text": "rs. All silence of cautiousness was therefore\nno longer of use. Paddles were dropped, and oars came loudly into play.\nAnd still puffing at his pipe, Stubb cheered on his crew to the\nassault.", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4276, "position": 4276, "text": "Stubb cheered on his crew to the\nassault.\n\nYes, a mighty change had come over the fish. All alive to his jeopardy,\nhe was going “head out”; that part obliquely projecting from the mad\nyeast which he brewed.*", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4277, "position": 4277, "text": "that part obliquely projecting from the mad\nyeast which he brewed.*\n\n*It will be seen in some other place of what a very light substance the\nentire interior of the sperm whale’s enormous head consists", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4278, "position": 4278, "text": "sperm whale’s enormous head consists. Though\napparently the most massive, it is by far the most buoyant part about\nhim. So that with ease he elevates it in the air, and invariably does\nso when going at his utmost speed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4279, "position": 4279, "text": "it in the air, and invariably does\nso when going at his utmost speed. Besides, such is the breadth of the\nupper part of the front of his head, and such the tapering cut-water\nformation of the lower part, that by oblique", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4280, "position": 4280, "text": "the tapering cut-water\nformation of the lower part, that by obliquely elevating his head, he\nthereby may be said to transform himself from a bluff-bowed sluggish\ngalliot into a sharppointed New York pilot-boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4281, "position": 4281, "text": "sluggish\ngalliot into a sharppointed New York pilot-boat.\n\n“Start her, start her, my men! Don’t hurry yourselves; take plenty of\ntime—but start her; start her like thunder-claps, that", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4282, "position": 4282, "text": "time—but start her; start her like thunder-claps, that’s all,” cried\nStubb, spluttering out the smoke as he spoke. “Start her, now; give ’em\nthe long and strong stroke, Ta", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4283, "position": 4283, "text": "Start her, now; give ’em\nthe long and strong stroke, Tashtego. Start her, Tash, my boy—start\nher, all; but keep cool, keep cool—cucumbers is the word—easy,\neasy", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 4284, "position": 4284, "text": "cool, keep cool—cucumbers is the word—easy,\neasy—only start her like grim death and grinning devils, and raise the\nburied dead perpendicular out of their graves, boys—that’s all. Start\nher!”", "labels": {"50": 34, "100": 77, "250": 164, "500": 89, "1000": 992, "2000": 721}}, {"id": 4285, "position": 4285, "text": "graves, boys—that’s all. Start\nher!”\n\n“Woo-hoo! Wa-hee!” screamed the Gay-Header in reply, raising some old\nwar-whoop to the skies; as every oarsman in the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 4286, "position": 4286, "text": "war-whoop to the skies; as every oarsman in the strained boat\ninvoluntarily bounced forward with the one tremendous leading stroke\nwhich the eager Indian gave.\n\nBut his wild screams were answered by others quite as wild", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1111}}, {"id": 4287, "position": 4287, "text": ".\n\nBut his wild screams were answered by others quite as wild. “Kee-hee!\nKee-hee!” yelled Daggoo, straining forwards and backwards on his seat,\nlike a pacing tiger in his cage.", "labels": {"50": 37, "100": 55, "250": 52, "500": 389, "1000": 653, "2000": 114}}, {"id": 4288, "position": 4288, "text": "his seat,\nlike a pacing tiger in his cage.\n\n“Ka-la! Koo-loo!” howled Queequeg, as if smacking his lips over a\nmouthful of Grenadier’s steak", "labels": {"50": 22, "100": 24, "250": 52, "500": 389, "1000": 673, "2000": 110}}, {"id": 4289, "position": 4289, "text": "over a\nmouthful of Grenadier’s steak. And thus with oars and yells the keels\ncut the sea. Meanwhile, Stubb retaining his place in the van, still\nencouraged his men to the onset, all the while puffing the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4290, "position": 4290, "text": ", still\nencouraged his men to the onset, all the while puffing the smoke from\nhis mouth. Like desperadoes they tugged and they strained, till the\nwelcome cry was heard—“Stand up, Tashtego!—give it", "labels": {"50": 22, "100": 55, "250": 65, "500": 43, "1000": 737, "2000": 481}}, {"id": 4291, "position": 4291, "text": "was heard—“Stand up, Tashtego!—give it to him!” The harpoon\nwas hurled. “Stern all!” The oarsmen backed water; the same moment\nsomething went hot and hissing along every one of their", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4292, "position": 4292, "text": "water; the same moment\nsomething went hot and hissing along every one of their wrists. It was\nthe magical line. An instant before, Stubb had swiftly caught two\nadditional turns with it round the loggerhead, whence, by reason of its", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4293, "position": 4293, "text": "with it round the loggerhead, whence, by reason of its\nincreased rapid circlings, a hempen blue smoke now jetted up and\nmingled with the steady fumes from his pipe. As the line passed round\nand round the logger", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4294, "position": 4294, "text": "mes from his pipe. As the line passed round\nand round the loggerhead; so also, just before reaching that point, it\nblisteringly passed through and through both of Stubb’s hands, from\nwhich the hand-cloths", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4295, "position": 4295, "text": "both of Stubb’s hands, from\nwhich the hand-cloths, or squares of quilted canvas sometimes worn at\nthese times, had accidentally dropped. It was like holding an enemy’s\nsharp two-edged sword by the blade, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4296, "position": 4296, "text": "holding an enemy’s\nsharp two-edged sword by the blade, and that enemy all the time\nstriving to wrest it out of your clutch.\n\n“Wet the line! wet the line!” cried Stubb to the tub oars", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4297, "position": 4297, "text": "line! wet the line!” cried Stubb to the tub oarsman (him\nseated by the tub) who, snatching off his hat, dashed sea-water into\nit.* More turns were taken, so that the line began holding", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4298, "position": 4298, "text": "into\nit.* More turns were taken, so that the line began holding its place.\nThe boat now flew through the boiling water like a shark all fins.\nStubb and Tashtego here changed places—stem for stern—a staggering\nbusiness", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4299, "position": 4299, "text": "Tashtego here changed places—stem for stern—a staggering\nbusiness truly in that rocking commotion.\n\n*Partly to show the indispensableness of this act, it may here be\nstated, that, in the old Dutch fishery, a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4300, "position": 4300, "text": "it may here be\nstated, that, in the old Dutch fishery, a mop was used to dash the\nrunning line with water; in many other ships, a wooden piggin, or\nbailer, is set apart for that purpose", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4301, "position": 4301, "text": "gin, or\nbailer, is set apart for that purpose. Your hat, however, is the most\nconvenient.\n\nFrom the vibrating line extending the entire length of the upper part\nof the boat, and from its now being more tight than a harpst", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 4302, "position": 4302, "text": "of the boat, and from its now being more tight than a harpstring, you\nwould have thought the craft had two keels—one cleaving the water, the\nother the air—as the boat churned on through both opposing elements", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4303, "position": 4303, "text": "the\nother the air—as the boat churned on through both opposing elements at\nonce. A continual cascade played at the bows; a ceaseless whirling eddy\nin her wake; and, at the slightest motion from within, even but of a", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 925, "2000": 576}}, {"id": 4304, "position": 4304, "text": "wake; and, at the slightest motion from within, even but of a\nlittle finger, the vibrating, cracking craft canted over her spasmodic\ngunwale into the sea. Thus they rushed; each man with might and main\nclinging to his", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1904}}, {"id": 4305, "position": 4305, "text": "sea. Thus they rushed; each man with might and main\nclinging to his seat, to prevent being tossed to the foam; and the tall\nform of Tashtego at the steering oar crouching almost double, in order\nto bring down his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4306, "position": 4306, "text": "the steering oar crouching almost double, in order\nto bring down his centre of gravity. Whole Atlantics and Pacifics\nseemed passed as they shot on their way, till at length the whale\nsomewhat slackened his flight.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4307, "position": 4307, "text": "at length the whale\nsomewhat slackened his flight.\n\n“Haul in—haul in!” cried Stubb to the bowsman! and, facing round\ntowards the whale, all hands began pulling the boat up to him, while\nyet the boat was being", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4308, "position": 4308, "text": "hands began pulling the boat up to him, while\nyet the boat was being towed on. Soon ranging up by his flank, Stubb,\nfirmly planting his knee in the clumsy cleat, darted dart after dart\ninto the flying fish; at the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4309, "position": 4309, "text": "cleat, darted dart after dart\ninto the flying fish; at the word of command, the boat alternately\nsterning out of the way of the whale’s horrible wallow, and then\nranging up for another fling.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4310, "position": 4310, "text": "ow, and then\nranging up for another fling.\n\nThe red tide now poured from all sides of the monster like brooks down\na hill. His tormented body rolled not in brine but in blood, which\nbubbled and seethed for furlongs behind in their", "labels": {"50": 22, "100": 55, "250": 28, "500": 93, "1000": 959, "2000": 481}}, {"id": 4311, "position": 4311, "text": "but in blood, which\nbubbled and seethed for furlongs behind in their wake. The slanting sun\nplaying upon this crimson pond in the sea, sent back its reflection\ninto every face, so that they all glowed to each other like red men", "labels": {"50": 22, "100": 55, "250": 28, "500": 479, "1000": 661, "2000": 160}}, {"id": 4312, "position": 4312, "text": "every face, so that they all glowed to each other like red men.\nAnd all the while, jet after jet of white smoke was agonizingly shot\nfrom the spiracle of the whale, and vehement puff after puff from the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4313, "position": 4313, "text": "iracle of the whale, and vehement puff after puff from the\nmouth of the excited headsman; as at every dart, hauling in upon his\ncrooked lance (by the line attached to it), Stubb straightened it again\nand again,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4314, "position": 4314, "text": "the line attached to it), Stubb straightened it again\nand again, by a few rapid blows against the gunwale, then again and\nagain sent it into the whale.\n\n“Pull up—pull up!” he now cried to the bows", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4315, "position": 4315, "text": ".\n\n“Pull up—pull up!” he now cried to the bowsman, as the waning whale\nrelaxed in his wrath. “Pull up!—close to!” and the boat ranged along\nthe fish’s flank", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4316, "position": 4316, "text": "” and the boat ranged along\nthe fish’s flank. When reaching far over the bow, Stubb slowly churned\nhis long sharp lance into the fish, and kept it there, carefully\nchurning and churning, as if cautiously seeking to feel after some", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4317, "position": 4317, "text": "there, carefully\nchurning and churning, as if cautiously seeking to feel after some gold\nwatch that the whale might have swallowed, and which he was fearful of\nbreaking ere he could hook it out. But that gold watch he sought was\nthe innermost life", "labels": {"50": 22, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 4318, "position": 4318, "text": "hook it out. But that gold watch he sought was\nthe innermost life of the fish. And now it is struck; for, starting\nfrom his trance into that unspeakable thing called his “flurry,” the\nmonster horribly wallowed", "labels": {"50": 22, "100": 55, "250": 28, "500": 72, "1000": 692, "2000": 778}}, {"id": 4319, "position": 4319, "text": "eakable thing called his “flurry,” the\nmonster horribly wallowed in his blood, overwrapped himself in\nimpenetrable, mad, boiling spray, so that the imperilled craft,\ninstantly dropping astern, had much", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4320, "position": 4320, "text": "so that the imperilled craft,\ninstantly dropping astern, had much ado blindly to struggle out from\nthat phrensied twilight into the clear air of the day.\n\nAnd now abating in his flurry, the whale once more rolled", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4321, "position": 4321, "text": ".\n\nAnd now abating in his flurry, the whale once more rolled out into\nview; surging from side to side; spasmodically dilating and contracting\nhis spout-hole, with sharp, cracking, agonized respiration", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4322, "position": 4322, "text": "spout-hole, with sharp, cracking, agonized respirations. At last,\ngush after gush of clotted red gore, as if it had been the purple lees\nof red wine, shot into the frighted air", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4323, "position": 4323, "text": "been the purple lees\nof red wine, shot into the frighted air; and falling back again, ran\ndripping down his motionless flanks into the sea. His heart had burst!\n\n“He’s dead, Mr", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 54, "2000": 967}}, {"id": 4324, "position": 4324, "text": "!\n\n“He’s dead, Mr. Stubb,” said Daggoo.\n\n“Yes; both pipes smoked out!” and withdrawing his own from his mouth,\nStubb scattered the dead ashes over the water; and, for a moment", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 4325, "position": 4325, "text": "Stubb scattered the dead ashes over the water; and, for a moment, stood\nthoughtfully eyeing the vast corpse he had made.\n\n\nCHAPTER 62. The Dart.\n\nA word concerning an incident in the last chapter.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4326, "position": 4326, "text": "an incident in the last chapter.\n\nAccording to the invariable usage of the fishery, the whale-boat pushes\noff from the ship, with the headsman or whale-killer as temporary\nsteersman, and the harpooneer or whale-fast", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4327, "position": 4327, "text": "killer as temporary\nsteersman, and the harpooneer or whale-fastener pulling the foremost\noar, the one known as the harpooneer-oar. Now it needs a strong,\nnervous arm to strike the first iron into the fish", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4328, "position": 4328, "text": "it needs a strong,\nnervous arm to strike the first iron into the fish; for often, in what\nis called a long dart, the heavy implement has to be flung to the\ndistance of twenty or thirty feet", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 447}}, {"id": 4329, "position": 4329, "text": "the\ndistance of twenty or thirty feet. But however prolonged and exhausting\nthe chase, the harpooneer is expected to pull his oar meanwhile to the\nuttermost; indeed, he is expected to set an example of superhuman\nactivity to the rest,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4330, "position": 4330, "text": ", he is expected to set an example of superhuman\nactivity to the rest, not only by incredible rowing, but by repeated\nloud and intrepid exclamations; and what it is to keep shouting at the\ntop of one’s compass,", "labels": {"50": 31, "100": 42, "250": 159, "500": 247, "1000": 917, "2000": 616}}, {"id": 4331, "position": 4331, "text": "what it is to keep shouting at the\ntop of one’s compass, while all the other muscles are strained and half\nstarted—what that is none know but those who have tried it. For one, I\ncannot bawl very heartily and work", "labels": {"50": 8, "100": 14, "250": 58, "500": 486, "1000": 956, "2000": 227}}, {"id": 4332, "position": 4332, "text": "tried it. For one, I\ncannot bawl very heartily and work very recklessly at one and the same\ntime. In this straining, bawling state, then, with his back to the\nfish, all at once the exhausted harpoon", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 4333, "position": 4333, "text": ", with his back to the\nfish, all at once the exhausted harpooneer hears the exciting\ncry—“Stand up, and give it to him!” He now has to drop and secure his\noar, turn round on his centre half way", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4334, "position": 4334, "text": "to drop and secure his\noar, turn round on his centre half way, seize his harpoon from the\ncrotch, and with what little strength may remain, he essays to pitch it\nsomehow into the whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4335, "position": 4335, "text": "pitch it\nsomehow into the whale. No wonder, taking the whole fleet of whalemen\nin a body, that out of fifty fair chances for a dart, not five are\nsuccessful; no wonder that so many hapless harpooneers are madly cursed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4336, "position": 4336, "text": "; no wonder that so many hapless harpooneers are madly cursed\nand disrated; no wonder that some of them actually burst their\nblood-vessels in the boat; no wonder that some sperm whalemen are\nabsent four years with four barrels", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4337, "position": 4337, "text": "; no wonder that some sperm whalemen are\nabsent four years with four barrels; no wonder that to many ship\nowners, whaling is but a losing concern; for it is the harpooneer that\nmakes the voyage, and if you take the breath out", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4338, "position": 4338, "text": "harpooneer that\nmakes the voyage, and if you take the breath out of his body how can\nyou expect to find it there when most wanted!\n\nAgain, if the dart be successful, then at the second critical instant,\nthat is, when the", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4339, "position": 4339, "text": "be successful, then at the second critical instant,\nthat is, when the whale starts to run, the boatheader and harpooneer\nlikewise start to running fore and aft, to the imminent jeopardy of\nthemselves and every one else", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4340, "position": 4340, "text": ", to the imminent jeopardy of\nthemselves and every one else. It is then they change places; and the\nheadsman, the chief officer of the little craft, takes his proper\nstation in the bows of the boat.", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 327, "2000": 1584}}, {"id": 4341, "position": 4341, "text": "station in the bows of the boat.\n\nNow, I care not who maintains the contrary, but all this is both\nfoolish and unnecessary. The headsman should stay in the bows from\nfirst to last; he should both dart the harpoon and the lance", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4342, "position": 4342, "text": "from\nfirst to last; he should both dart the harpoon and the lance, and no\nrowing whatever should be expected of him, except under circumstances\nobvious to any fisherman. I know that this would sometimes involve a\nslight loss of speed in the chase;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4343, "position": 4343, "text": "know that this would sometimes involve a\nslight loss of speed in the chase; but long experience in various\nwhalemen of more than one nation has convinced me that in the vast\nmajority of failures in the fishery, it has not by any means been so\nmuch", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4344, "position": 4344, "text": "of failures in the fishery, it has not by any means been so\nmuch the speed of the whale as the before described exhaustion of the\nharpooneer that has caused them.\n\nTo insure the greatest efficiency in the dart, the harpooneers of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4345, "position": 4345, "text": "To insure the greatest efficiency in the dart, the harpooneers of this\nworld must start to their feet from out of idleness, and not from out\nof toil.\n\n\nCHAPTER 63. The Crotch.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4346, "position": 4346, "text": ".\n\n\nCHAPTER 63. The Crotch.\n\nOut of the trunk, the branches grow; out of them, the twigs. So, in\nproductive subjects, grow the chapters.\n\nThe crotch alluded to on a previous page deserves independent mention", "labels": {"50": 3, "100": 46, "250": 142, "500": 403, "1000": 294, "2000": 538}}, {"id": 4347, "position": 4347, "text": "alluded to on a previous page deserves independent mention.\nIt is a notched stick of a peculiar form, some two feet in length,\nwhich is perpendicularly inserted into the starboard gunwale near the\nbow, for the purpose of furnishing", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4348, "position": 4348, "text": "starboard gunwale near the\nbow, for the purpose of furnishing a rest for the wooden extremity of\nthe harpoon, whose other naked, barbed end slopingly projects from the\nprow", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4349, "position": 4349, "text": "ly projects from the\nprow. Thereby the weapon is instantly at hand to its hurler, who\nsnatches it up as readily from its rest as a backwoodsman swings his\nrifle from the wall", "labels": {"50": 12, "100": 24, "250": 52, "500": 288, "1000": 393, "2000": 677}}, {"id": 4350, "position": 4350, "text": "swings his\nrifle from the wall. It is customary to have two harpoons reposing in\nthe crotch, respectively called the first and second irons.\n\nBut these two harpoons, each by its own cord, are both connected with\nthe line; the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4351, "position": 4351, "text": ", each by its own cord, are both connected with\nthe line; the object being this: to dart them both, if possible, one\ninstantly after the other into the same whale; so that if, in the\ncoming drag, one should draw out", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4352, "position": 4352, "text": "whale; so that if, in the\ncoming drag, one should draw out, the other may still retain a hold. It\nis a doubling of the chances. But it very often happens that owing to\nthe instantaneous, violent, convulsive", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4353, "position": 4353, "text": "often happens that owing to\nthe instantaneous, violent, convulsive running of the whale upon\nreceiving the first iron, it becomes impossible for the harpooneer,\nhowever lightning-like in his movements, to pitch the second iron into\nhim", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4354, "position": 4354, "text": "lightning-like in his movements, to pitch the second iron into\nhim. Nevertheless, as the second iron is already connected with the\nline, and the line is running, hence that weapon must, at all events,\nbe anticipatingly tossed out of the", "labels": {"50": 45, "100": 86, "250": 138, "500": 288, "1000": 680, "2000": 1620}}, {"id": 4355, "position": 4355, "text": "that weapon must, at all events,\nbe anticipatingly tossed out of the boat, somehow and somewhere; else\nthe most terrible jeopardy would involve all hands. Tumbled into the\nwater, it accordingly is in such cases; the spare coils of box line", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4356, "position": 4356, "text": ", it accordingly is in such cases; the spare coils of box line\n(mentioned in a preceding chapter) making this feat, in most instances,\nprudently practicable. But this critical act is not always unattended\nwith the sad", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 4357, "position": 4357, "text": "able. But this critical act is not always unattended\nwith the saddest and most fatal casualties.\n\nFurthermore: you must know that when the second iron is thrown\noverboard, it thenceforth becomes a dangling, sharp-edged terror,\nskitti", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4358, "position": 4358, "text": ", it thenceforth becomes a dangling, sharp-edged terror,\nskittishly curvetting about both boat and whale, entangling the lines,\nor cutting them, and making a prodigious sensation in all directions", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4359, "position": 4359, "text": "and making a prodigious sensation in all directions.\nNor, in general, is it possible to secure it again until the whale is\nfairly captured and a corpse.\n\nConsider, now, how it must be in the case of four boats all engaging", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4360, "position": 4360, "text": ", now, how it must be in the case of four boats all engaging\none unusually strong, active, and knowing whale; when owing to these\nqualities in him, as well as to the thousand concurring accidents of\nsuch an audacious enterprise", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4361, "position": 4361, "text": "as to the thousand concurring accidents of\nsuch an audacious enterprise, eight or ten loose second irons may be\nsimultaneously dangling about him. For, of course, each boat is\nsupplied with several harpoons to bend on to the line should", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4362, "position": 4362, "text": "each boat is\nsupplied with several harpoons to bend on to the line should the first\none be ineffectually darted without recovery. All these particulars are\nfaithfully narrated here, as they will not fail to elucidate several\nmost important", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4363, "position": 4363, "text": "here, as they will not fail to elucidate several\nmost important, however intricate passages, in scenes hereafter to be\npainted.\n\n\nCHAPTER 64. Stubb’s Supper.\n\nStubb’s whale had been killed some distance from the", "labels": {"50": 42, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4364, "position": 4364, "text": "s Supper.\n\nStubb’s whale had been killed some distance from the ship. It was a\ncalm; so, forming a tandem of three boats, we commenced the slow\nbusiness of towing the trophy to the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4365, "position": 4365, "text": "business of towing the trophy to the Pequod. And now, as we eighteen\nmen with our thirty-six arms, and one hundred and eighty thumbs and\nfingers, slowly toiled hour after hour upon that inert, sluggish corpse\nin", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4366, "position": 4366, "text": "toiled hour after hour upon that inert, sluggish corpse\nin the sea; and it seemed hardly to budge at all, except at long\nintervals; good evidence was hereby furnished of the enormousness of\nthe mass we moved", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1243}}, {"id": 4367, "position": 4367, "text": "hereby furnished of the enormousness of\nthe mass we moved. For, upon the great canal of Hang-Ho, or whatever\nthey call it, in China, four or five laborers on the foot-path will\ndraw a bulky freighted junk at", "labels": {"50": 48, "100": 90, "250": 121, "500": 328, "1000": 567, "2000": 546}}, {"id": 4368, "position": 4368, "text": "five laborers on the foot-path will\ndraw a bulky freighted junk at the rate of a mile an hour; but this\ngrand argosy we towed heavily forged along, as if laden with pig-lead\nin bulk.", "labels": {"50": 48, "100": 20, "250": 90, "500": 162, "1000": 90, "2000": 478}}, {"id": 4369, "position": 4369, "text": "as if laden with pig-lead\nin bulk.\n\nDarkness came on; but three lights up and down in the Pequod’s\nmain-rigging dimly guided our way; till drawing nearer we saw Ahab\ndropping one of several more lanterns over", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4370, "position": 4370, "text": "; till drawing nearer we saw Ahab\ndropping one of several more lanterns over the bulwarks. Vacantly\neyeing the heaving whale for a moment, he issued the usual orders for\nsecuring it for the night, and then handing his lantern to a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4371, "position": 4371, "text": "orders for\nsecuring it for the night, and then handing his lantern to a seaman,\nwent his way into the cabin, and did not come forward again until\nmorning.\n\nThough, in overseeing the pursuit of this whale, Captain Ahab had\nevinced", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4372, "position": 4372, "text": "in overseeing the pursuit of this whale, Captain Ahab had\nevinced his customary activity, to call it so; yet now that the\ncreature was dead, some vague dissatisfaction, or impatience, or\ndespair, seemed working in him; as if the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4373, "position": 4373, "text": ", or impatience, or\ndespair, seemed working in him; as if the sight of that dead body\nreminded him that Moby Dick was yet to be slain; and though a thousand\nother whales were brought to his ship, all that would not one jo", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4374, "position": 4374, "text": "thousand\nother whales were brought to his ship, all that would not one jot\nadvance his grand, monomaniac object. Very soon you would have thought\nfrom the sound on the Pequod’s decks, that all hands were preparing to\ncast", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4375, "position": 4375, "text": "the Pequod’s decks, that all hands were preparing to\ncast anchor in the deep; for heavy chains are being dragged along the\ndeck, and thrust rattling out of the port-holes. But by those clanking\nlinks, the vast corpse", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4376, "position": 4376, "text": "the port-holes. But by those clanking\nlinks, the vast corpse itself, not the ship, is to be moored. Tied by\nthe head to the stern, and by the tail to the bows, the whale now lies\nwith its black", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4377, "position": 4377, "text": "and by the tail to the bows, the whale now lies\nwith its black hull close to the vessel’s and seen through the darkness\nof the night, which obscured the spars and rigging aloft, the two—ship\nand whale, seemed", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 4378, "position": 4378, "text": "rs and rigging aloft, the two—ship\nand whale, seemed yoked together like colossal bullocks, whereof one\nreclines while the other remains standing.*\n\n*A little item may as well be related here", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4379, "position": 4379, "text": "*A little item may as well be related here. The strongest and most\nreliable hold which the ship has upon the whale when moored alongside,\nis by the flukes or tail; and as from its greater density that part is\nrelatively heavier than any", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4380, "position": 4380, "text": "tail; and as from its greater density that part is\nrelatively heavier than any other (excepting the side-fins), its\nflexibility even in death, causes it to sink low beneath the surface;\nso that with the hand you cannot get at it", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 4381, "position": 4381, "text": "low beneath the surface;\nso that with the hand you cannot get at it from the boat, in order to\nput the chain round it. But this difficulty is ingeniously overcome: a\nsmall, strong line is prepared with a wooden float at its", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 99, "2000": 778}}, {"id": 4382, "position": 4382, "text": "overcome: a\nsmall, strong line is prepared with a wooden float at its outer end,\nand a weight in its middle, while the other end is secured to the ship.\nBy adroit management the wooden float is made to rise on the other", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 4383, "position": 4383, "text": "By adroit management the wooden float is made to rise on the other side\nof the mass, so that now having girdled the whale, the chain is readily\nmade to follow suit; and being slipped along the body, is at last\nlocked", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4384, "position": 4384, "text": "to follow suit; and being slipped along the body, is at last\nlocked fast round the smallest part of the tail, at the point of\njunction with its broad flukes or lobes.\n\nIf moody Ahab was now all quiescence, at least so", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4385, "position": 4385, "text": "lobes.\n\nIf moody Ahab was now all quiescence, at least so far as could be known\non deck, Stubb, his second mate, flushed with conquest, betrayed an\nunusual but still good-natured excitement", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4386, "position": 4386, "text": "an\nunusual but still good-natured excitement. Such an unwonted bustle was\nhe in that the staid Starbuck, his official superior, quietly resigned\nto him for the time the sole management of affairs", "labels": {"50": 37, "100": 6, "250": 70, "500": 463, "1000": 142, "2000": 1128}}, {"id": 4387, "position": 4387, "text": "for the time the sole management of affairs. One small, helping\ncause of all this liveliness in Stubb, was soon made strangely\nmanifest. Stubb was a high liver; he was somewhat intemperately fond of\nthe whale as a flavor", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4388, "position": 4388, "text": "; he was somewhat intemperately fond of\nthe whale as a flavorish thing to his palate.\n\n“A steak, a steak, ere I sleep! You, Daggoo! overboard you go, and cut\nme one from his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4389, "position": 4389, "text": ", Daggoo! overboard you go, and cut\nme one from his small!”\n\nHere be it known, that though these wild fishermen do not, as a general\nthing, and according to the great military maxim, make the enemy defray\nthe", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 4390, "position": 4390, "text": ", and according to the great military maxim, make the enemy defray\nthe current expenses of the war (at least before realizing the proceeds\nof the voyage), yet now and then you find some of these Nantucketers\nwho have a genuine relish", "labels": {"50": 48, "100": 20, "250": 90, "500": 224, "1000": 90, "2000": 682}}, {"id": 4391, "position": 4391, "text": "then you find some of these Nantucketers\nwho have a genuine relish for that particular part of the Sperm Whale\ndesignated by Stubb; comprising the tapering extremity of the body.\n\nAbout midnight that steak was cut and cooked; and lighted", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4392, "position": 4392, "text": "of the body.\n\nAbout midnight that steak was cut and cooked; and lighted by two\nlanterns of sperm oil, Stubb stoutly stood up to his spermaceti supper\nat the capstan-head, as if that capstan were a sideboard", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4393, "position": 4393, "text": "the capstan-head, as if that capstan were a sideboard. Nor was Stubb\nthe only banqueter on whale’s flesh that night. Mingling their\nmumblings with his own mastications, thousands on thousands of sharks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4394, "position": 4394, "text": "mumblings with his own mastications, thousands on thousands of sharks,\nswarming round the dead leviathan, smackingly feasted on its fatness.\nThe few sleepers below in their bunks were often startled by the sharp\nslapping of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 4395, "position": 4395, "text": "sleepers below in their bunks were often startled by the sharp\nslapping of their tails against the hull, within a few inches of the\nsleepers’ hearts. Peering over the side you could just see them (as\nbefore you heard them) wallowing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1668}}, {"id": 4396, "position": 4396, "text": "side you could just see them (as\nbefore you heard them) wallowing in the sullen, black waters, and\nturning over on their backs as they scooped out huge globular pieces of\nthe whale of the bigness of a human head", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4397, "position": 4397, "text": "lobular pieces of\nthe whale of the bigness of a human head. This particular feat of the\nshark seems all but miraculous. How at such an apparently unassailable\nsurface, they contrive to gouge out such symmetrical mouthfuls,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4398, "position": 4398, "text": "surface, they contrive to gouge out such symmetrical mouthfuls, remains\na part of the universal problem of all things. The mark they thus leave\non the whale, may best be likened to the hollow made by a carpenter in\ncountersinking for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4399, "position": 4399, "text": "may best be likened to the hollow made by a carpenter in\ncountersinking for a screw.\n\nThough amid all the smoking horror and diabolism of a sea-fight, sharks\nwill be seen longingly gazing up to the ship’s decks, like", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4400, "position": 4400, "text": "will be seen longingly gazing up to the ship’s decks, like hungry dogs\nround a table where red meat is being carved, ready to bolt down every\nkilled man that is tossed to them; and though, while the valiant\nbutchers over the", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 4401, "position": 4401, "text": "is tossed to them; and though, while the valiant\nbutchers over the deck-table are thus cannibally carving each other’s\nlive meat with carving-knives all gilded and tasselled, the sharks,\nalso, with their jewel", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4402, "position": 4402, "text": "all gilded and tasselled, the sharks,\nalso, with their jewel-hilted mouths, are quarrelsomely carving away\nunder the table at the dead meat; and though, were you to turn the\nwhole affair upside down, it would still", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4403, "position": 4403, "text": "though, were you to turn the\nwhole affair upside down, it would still be pretty much the same thing,\nthat is to say, a shocking sharkish business enough for all parties;\nand though sharks also are the invariable outriders of all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4404, "position": 4404, "text": "parties;\nand though sharks also are the invariable outriders of all slave ships\ncrossing the Atlantic, systematically trotting alongside, to be handy\nin case a parcel is to be carried anywhere, or a dead slave to be\ndecently buried;", "labels": {"50": 45, "100": 29, "250": 138, "500": 388, "1000": 851, "2000": 1495}}, {"id": 4405, "position": 4405, "text": "to be carried anywhere, or a dead slave to be\ndecently buried; and though one or two other like instances might be\nset down, touching the set terms, places, and occasions, when sharks do\nmost socially congregate, and most hilarious", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 851, "2000": 1620}}, {"id": 4406, "position": 4406, "text": "and occasions, when sharks do\nmost socially congregate, and most hilariously feast; yet is there no\nconceivable time or occasion when you will find them in such countless\nnumbers, and in gayer or more jovial spirits, than", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4407, "position": 4407, "text": "such countless\nnumbers, and in gayer or more jovial spirits, than around a dead sperm\nwhale, moored by night to a whaleship at sea. If you have never seen\nthat sight, then suspend your decision about the propriety of\ndevil", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4408, "position": 4408, "text": "never seen\nthat sight, then suspend your decision about the propriety of\ndevil-worship, and the expediency of conciliating the devil.\n\nBut, as yet, Stubb heeded not the mumblings of the banquet that", "labels": {"50": 9, "100": 20, "250": 30, "500": 72, "1000": 343, "2000": 1620}}, {"id": 4409, "position": 4409, "text": "yet, Stubb heeded not the mumblings of the banquet that was\ngoing on so nigh him, no more than the sharks heeded the smacking of\nhis own epicurean lips.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4410, "position": 4410, "text": "own epicurean lips.\n\n“Cook, cook!—where’s that old Fleece?” he cried at length, widening his\nlegs still further, as if to form a more secure base for his supper;\nand, at the same time", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 317, "2000": 1087}}, {"id": 4411, "position": 4411, "text": "form a more secure base for his supper;\nand, at the same time darting his fork into the dish, as if stabbing\nwith his lance; “cook, you cook!—sail this way, cook!”", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 747, "2000": 523}}, {"id": 4412, "position": 4412, "text": "—sail this way, cook!”\n\nThe old black, not in any very high glee at having been previously\nroused from his warm hammock at a most unseasonable hour, came\nshambling along from his galley, for, like", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 4413, "position": 4413, "text": "sonable hour, came\nshambling along from his galley, for, like many old blacks, there was\nsomething the matter with his knee-pans, which he did not keep well\nscoured like his other pans; this old Fleece,", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 4414, "position": 4414, "text": "keep well\nscoured like his other pans; this old Fleece, as they called him, came\nshuffling and limping along, assisting his step with his tongs, which,\nafter a clumsy fashion, were made of straightened iron hoops;", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1620}}, {"id": 4415, "position": 4415, "text": "which,\nafter a clumsy fashion, were made of straightened iron hoops; this old\nEbony floundered along, and in obedience to the word of command, came\nto a dead stop on the opposite side of Stubb’s sideboard; when", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 4416, "position": 4416, "text": "dead stop on the opposite side of Stubb’s sideboard; when, with\nboth hands folded before him, and resting on his two-legged cane, he\nbowed his arched back still further over, at the same time sideways\ninclining his head", "labels": {"50": 23, "100": 87, "250": 102, "500": 205, "1000": 317, "2000": 1087}}, {"id": 4417, "position": 4417, "text": "arched back still further over, at the same time sideways\ninclining his head, so as to bring his best ear into play.\n\n“Cook,” said Stubb, rapidly lifting a rather reddish morsel to his\nmouth, “don’t you", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4418, "position": 4418, "text": "lifting a rather reddish morsel to his\nmouth, “don’t you think this steak is rather overdone? You’ve been\nbeating this steak too much, cook; it’s too tender", "labels": {"50": 39, "100": 99, "250": 57, "500": 100, "1000": 488, "2000": 274}}, {"id": 4419, "position": 4419, "text": "; it’s too tender. Don’t I always say\nthat to be good, a whale-steak must be tough? There are those sharks\nnow over the side, don’t you see they prefer it tough and rare? What a\nshin", "labels": {"50": 31, "100": 7, "250": 193, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4420, "position": 4420, "text": "don’t you see they prefer it tough and rare? What a\nshindy they are kicking up! Cook, go and talk to ’em; tell ’em they are\nwelcome to help themselves civilly, and in moderation, but they must", "labels": {"50": 31, "100": 7, "250": 69, "500": 187, "1000": 996, "2000": 1199}}, {"id": 4421, "position": 4421, "text": "welcome to help themselves civilly, and in moderation, but they must\nkeep quiet. Blast me, if I can hear my own voice. Away, cook, and\ndeliver my message. Here, take this lantern,” snatching one from his", "labels": {"50": 23, "100": 87, "250": 219, "500": 205, "1000": 317, "2000": 1087}}, {"id": 4422, "position": 4422, "text": "my message. Here, take this lantern,” snatching one from his\nsideboard; “now then, go and preach to ’em!”\n\nSullenly taking the offered lantern, old Fleece limped across the deck\nto the bul", "labels": {"50": 37, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 4423, "position": 4423, "text": "offered lantern, old Fleece limped across the deck\nto the bulwarks; and then, with one hand dropping his light low over\nthe sea, so as to get a good view of his congregation, with the other\nhand he solemnly flourished", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 4424, "position": 4424, "text": "get a good view of his congregation, with the other\nhand he solemnly flourished his tongs, and leaning far over the side in\na mumbling voice began addressing the sharks, while Stubb, softly\ncrawling behind, overheard all that was said.", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 531, "2000": 1620}}, {"id": 4425, "position": 4425, "text": "while Stubb, softly\ncrawling behind, overheard all that was said.\n\n“Fellow-critters: I’se ordered here to say dat you must stop dat dam\nnoise dare. You hear? Stop dat dam smackin’ ob de lip!", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4426, "position": 4426, "text": "dare. You hear? Stop dat dam smackin’ ob de lip! Massa Stubb say\ndat you can fill your dam bellies up to de hatchings, but by Gor! you\nmust stop dat dam racket!”", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4427, "position": 4427, "text": "by Gor! you\nmust stop dat dam racket!”\n\n“Cook,” here interposed Stubb, accompanying the word with a sudden slap\non the shoulder,—“Cook! why, damn your eyes, you mustn’t swear", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 4428, "position": 4428, "text": "“Cook! why, damn your eyes, you mustn’t swear that way\nwhen you’re preaching. That’s no way to convert sinners, cook!”\n\n“Who dat? Den preach to him yourself,” sullenly", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4429, "position": 4429, "text": "”\n\n“Who dat? Den preach to him yourself,” sullenly turning to go.\n\n“No, cook; go on, go on.”\n\n“Well, den, Belubed fellow-critters:”—", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4430, "position": 4430, "text": ", Belubed fellow-critters:”—\n\n“Right!” exclaimed Stubb, approvingly, “coax ’em to it; try that,” and\nFleece continued.", "labels": {"50": 37, "100": 24, "250": 95, "500": 199, "1000": 129, "2000": 736}}, {"id": 4431, "position": 4431, "text": "” and\nFleece continued.\n\n“Do you is all sharks, and by natur wery woracious, yet I zay to you,\nfellow-critters, dat dat woraciousness—’top dat dam slappin’", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 4432, "position": 4432, "text": ", dat dat woraciousness—’top dat dam slappin’ ob de\ntail! How you tink to hear, spose you keep up such a dam slappin’ and\nbitin’ dare?”", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4433, "position": 4433, "text": "pin’ and\nbitin’ dare?”\n\n“Cook,” cried Stubb, collaring him, “I won’t have that swearing. Talk\nto ’em gentlemanly.”\n\nOnce more the sermon proceeded.", "labels": {"50": 37, "100": 99, "250": 40, "500": 262, "1000": 496, "2000": 497}}, {"id": 4434, "position": 4434, "text": "ly.”\n\nOnce more the sermon proceeded.\n\n“Your woraciousness, fellow-critters, I don’t blame ye so much for; dat\nis natur, and can’t be helped; but to gobern dat", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4435, "position": 4435, "text": "ur, and can’t be helped; but to gobern dat wicked natur, dat is\nde pint. You is sharks, sartin; but if you gobern de shark in you, why\nden you be angel; for", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4436, "position": 4436, "text": "gobern de shark in you, why\nden you be angel; for all angel is not’ing more dan de shark well\ngoberned. Now, look here, bred’ren, just try wonst to be cibil, a\nhelping", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4437, "position": 4437, "text": "bred’ren, just try wonst to be cibil, a\nhelping yourselbs from dat whale. Don’t be tearin’ de blubber out your\nneighbour’s mout, I say", "labels": {"50": 41, "100": 21, "250": 215, "500": 281, "1000": 333, "2000": 1082}}, {"id": 4438, "position": 4438, "text": "’s mout, I say. Is not one shark dood right as toder to dat\nwhale? And, by Gor, none on you has de right to dat whale; dat whale\nbelong to some one else", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1544}}, {"id": 4439, "position": 4439, "text": "dat whale; dat whale\nbelong to some one else. I know some o’ you has berry brig mout,\nbrigger dan oders; but den de brig mouts sometimes has de small\nbellies; so dat de brigness of de mo", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4440, "position": 4440, "text": "sometimes has de small\nbellies; so dat de brigness of de mout is not to swaller wid, but to\nbit off de blubber for de small fry ob sharks, dat can’t get into de\nscrouge to", "labels": {"50": 45, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4441, "position": 4441, "text": "fry ob sharks, dat can’t get into de\nscrouge to help demselves.”\n\n“Well done, old Fleece!” cried Stubb, “that’s Christianity; go on.”", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4442, "position": 4442, "text": "that’s Christianity; go on.”\n\n“No use goin’ on; de dam willains will keep a scougin’ and slappin’\neach oder, Massa Stubb; dey don’t hear one word; no use", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4443, "position": 4443, "text": "a Stubb; dey don’t hear one word; no use a-preachin’ to\nsuch dam g’uttons as you call ’em, till dare bellies is full, and dare\nbellies is bottomless; and", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1082}}, {"id": 4444, "position": 4444, "text": "dare bellies is full, and dare\nbellies is bottomless; and when dey do get ’em full, dey wont hear you\nden; for den dey sink in de sea, go fast to sleep on de coral, and", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4445, "position": 4445, "text": "y sink in de sea, go fast to sleep on de coral, and\ncan’t hear not’ing at all, no more, for eber and eber.”\n\n“Upon my soul, I am about of the same opinion; so", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 54, "2000": 1434}}, {"id": 4446, "position": 4446, "text": "”\n\n“Upon my soul, I am about of the same opinion; so give the benediction,\nFleece, and I’ll away to my supper.”\n\nUpon this, Fleece, holding both hands over the fishy mob, raised his", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 345, "2000": 1087}}, {"id": 4447, "position": 4447, "text": ", Fleece, holding both hands over the fishy mob, raised his\nshrill voice, and cried—\n\n“Cussed fellow-critters! Kick up de damndest row as ever you can; fill\nyour dam’ bellies ’till", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4448, "position": 4448, "text": "t row as ever you can; fill\nyour dam’ bellies ’till dey bust—and den die.”\n\n“Now, cook,” said Stubb, resuming his supper at the capstan; “stand\njust where you stood before", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1620}}, {"id": 4449, "position": 4449, "text": "uming his supper at the capstan; “stand\njust where you stood before, there, over against me, and pay particular\nattention.”\n\n“All dention,” said Fleece, again stooping over upon his tongs in the\ndesired position", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 4450, "position": 4450, "text": "Fleece, again stooping over upon his tongs in the\ndesired position.\n\n“Well,” said Stubb, helping himself freely meanwhile; “I shall now go\nback to the subject of this steak", "labels": {"50": 23, "100": 59, "250": 219, "500": 16, "1000": 364, "2000": 1592}}, {"id": 4451, "position": 4451, "text": "to the subject of this steak. In the first place, how old are you,\ncook?”\n\n“What dat do wid de ’teak,” said the old black, testily.\n\n“Silence! How old are you, cook?", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4452, "position": 4452, "text": "black, testily.\n\n“Silence! How old are you, cook?”\n\n“’Bout ninety, dey say,” he gloomily muttered.\n\n“And you have lived in this world hard upon one hundred years, cook,\nand don’", "labels": {"50": 41, "100": 21, "250": 174, "500": 5, "1000": 726, "2000": 1783}}, {"id": 4453, "position": 4453, "text": "lived in this world hard upon one hundred years, cook,\nand don’t know yet how to cook a whale-steak?” rapidly bolting another\nmouthful at the last word, so that morsel seemed a continuation of the\nquestion", "labels": {"50": 7, "100": 59, "250": 10, "500": 16, "1000": 364, "2000": 1592}}, {"id": 4454, "position": 4454, "text": "word, so that morsel seemed a continuation of the\nquestion. “Where were you born, cook?”\n\n“’Hind de hatchway, in ferry-boat, goin’ ober de Roanoke.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 4455, "position": 4455, "text": "’ ober de Roanoke.”\n\n“Born in a ferry-boat! That’s queer, too. But I want to know what\ncountry you were born in, cook!”\n\n“Didn’t I say de Roanoke country?” he cried", "labels": {"50": 37, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 4456, "position": 4456, "text": "!”\n\n“Didn’t I say de Roanoke country?” he cried sharply.\n\n“No, you didn’t, cook; but I’ll tell you what I’m coming to, cook", "labels": {"50": 37, "100": 6, "250": 174, "500": 5, "1000": 726, "2000": 1125}}, {"id": 4457, "position": 4457, "text": "’m coming to, cook. You\nmust go home and be born over again; you don’t know how to cook a\nwhale-steak yet.”\n\n“Bress my soul, if I cook noder one,” he growled, angrily", "labels": {"50": 40, "100": 50, "250": 36, "500": 248, "1000": 817, "2000": 793}}, {"id": 4458, "position": 4458, "text": "my soul, if I cook noder one,” he growled, angrily, turning\nround to depart.\n\n“Come back, cook;—here, hand me those tongs;—now take that bit of steak\nthere, and tell me if you", "labels": {"50": 37, "100": 88, "250": 219, "500": 221, "1000": 627, "2000": 324}}, {"id": 4459, "position": 4459, "text": ";—now take that bit of steak\nthere, and tell me if you think that steak cooked as it should be? Take\nit, I say”—holding the tongs towards him—“take it, and taste it.”", "labels": {"50": 25, "100": 93, "250": 97, "500": 435, "1000": 345, "2000": 251}}, {"id": 4460, "position": 4460, "text": "towards him—“take it, and taste it.”\n\nFaintly smacking his withered lips over it for a moment, the old negro\nmuttered, “Best cooked ’teak I eber taste; joosy, berry joosy.”", "labels": {"50": 23, "100": 88, "250": 219, "500": 180, "1000": 627, "2000": 40}}, {"id": 4461, "position": 4461, "text": "k I eber taste; joosy, berry joosy.”\n\n“Cook,” said Stubb, squaring himself once more; “do you belong to the\nchurch?”\n\n“Passed one once in Cape-Down,” said the", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 858, "2000": 110}}, {"id": 4462, "position": 4462, "text": "church?”\n\n“Passed one once in Cape-Down,” said the old man sullenly.\n\n“And you have once in your life passed a holy church in Cape-Town,\nwhere you doubtless overheard a holy parson addressing his hear", "labels": {"50": 5, "100": 30, "250": 40, "500": 262, "1000": 322, "2000": 497}}, {"id": 4463, "position": 4463, "text": "-Town,\nwhere you doubtless overheard a holy parson addressing his hearers as\nhis beloved fellow-creatures, have you, cook! And yet you come here,\nand tell me such a dreadful lie as you did just now, eh?”", "labels": {"50": 23, "100": 30, "250": 40, "500": 160, "1000": 322, "2000": 1902}}, {"id": 4464, "position": 4464, "text": "tell me such a dreadful lie as you did just now, eh?” said Stubb.\n“Where do you expect to go to, cook?”\n\n“Go to bed berry soon,” he mumbled, half-turning as he spoke.", "labels": {"50": 37, "100": 99, "250": 163, "500": 432, "1000": 593, "2000": 324}}, {"id": 4465, "position": 4465, "text": "berry soon,” he mumbled, half-turning as he spoke.\n\n“Avast! heave to! I mean when you die, cook. It’s an awful question.\nNow what’s your answer?”", "labels": {"50": 41, "100": 21, "250": 174, "500": 5, "1000": 958, "2000": 361}}, {"id": 4466, "position": 4466, "text": "question.\nNow what’s your answer?”\n\n“When dis old brack man dies,” said the negro slowly, changing his\nwhole air and demeanor, “he hisself won’t go nowhere; but some bressed\nangel will", "labels": {"50": 41, "100": 21, "250": 215, "500": 418, "1000": 671, "2000": 1434}}, {"id": 4467, "position": 4467, "text": "hisself won’t go nowhere; but some bressed\nangel will come and fetch him.”\n\n“Fetch him? How? In a coach and four, as they fetched Elijah? And fetch\nhim where?”", "labels": {"50": 35, "100": 21, "250": 91, "500": 274, "1000": 203, "2000": 1199}}, {"id": 4468, "position": 4468, "text": "fetched Elijah? And fetch\nhim where?”\n\n“Up dere,” said Fleece, holding his tongs straight over his head, and\nkeeping it there very solemnly.\n\n“So, then, you expect to go up into our main-", "labels": {"50": 41, "100": 12, "250": 38, "500": 178, "1000": 59, "2000": 1525}}, {"id": 4469, "position": 4469, "text": ".\n\n“So, then, you expect to go up into our main-top, do you, cook, when\nyou are dead? But don’t you know the higher you climb, the colder it\ngets? Main-top, eh?”", "labels": {"50": 37, "100": 55, "250": 171, "500": 185, "1000": 615, "2000": 1739}}, {"id": 4470, "position": 4470, "text": "you climb, the colder it\ngets? Main-top, eh?”\n\n“Didn’t say dat t’all,” said Fleece, again in the sulks.\n\n“You said up there, didn’t you? and now look", "labels": {"50": 37, "100": 6, "250": 25, "500": 24, "1000": 377, "2000": 65}}, {"id": 4471, "position": 4471, "text": ".\n\n“You said up there, didn’t you? and now look yourself, and see where\nyour tongs are pointing. But, perhaps you expect to get into heaven by\ncrawling through the lubber’s hole, cook; but, no", "labels": {"50": 37, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 4472, "position": 4472, "text": "by\ncrawling through the lubber’s hole, cook; but, no, no, cook, you don’t\nget there, except you go the regular way, round by the rigging. It’s a\nticklish business, but must", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4473, "position": 4473, "text": "by the rigging. It’s a\nticklish business, but must be done, or else it’s no go. But none of us\nare in heaven yet. Drop your tongs, cook, and hear my orders", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 4474, "position": 4474, "text": "Drop your tongs, cook, and hear my orders. Do ye\nhear? Hold your hat in one hand, and clap t’other a’top of your heart,\nwhen I’m giving my orders, cook", "labels": {"50": 37, "100": 55, "250": 145, "500": 180, "1000": 54, "2000": 324}}, {"id": 4475, "position": 4475, "text": "when I’m giving my orders, cook. What! that your heart, there?—that’s\nyour gizzard! Aloft! aloft!—that’s it—now you have it", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 4476, "position": 4476, "text": "’s it—now you have it. Hold it there\nnow, and pay attention.”\n\n“All ’dention,” said the old black, with both hands placed as desired,\nvainly wriggling his grizzled head,", "labels": {"50": 37, "100": 88, "250": 145, "500": 180, "1000": 383, "2000": 110}}, {"id": 4477, "position": 4477, "text": "as desired,\nvainly wriggling his grizzled head, as if to get both ears in front at\none and the same time.\n\n“Well then, cook, you see this whale-steak of yours was so very bad,\nthat", "labels": {"50": 45, "100": 64, "250": 219, "500": 73, "1000": 851, "2000": 1620}}, {"id": 4478, "position": 4478, "text": ", you see this whale-steak of yours was so very bad,\nthat I have put it out of sight as soon as possible; you see that,\ndon’t you? Well, for the future, when you cook another whale-steak for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 4479, "position": 4479, "text": "? Well, for the future, when you cook another whale-steak for\nmy private table here, the capstan, I’ll tell you what to do so as not\nto spoil it by overdoing", "labels": {"50": 25, "100": 64, "250": 163, "500": 72, "1000": 825, "2000": 631}}, {"id": 4480, "position": 4480, "text": "to spoil it by overdoing. Hold the steak in one hand, and show a live\ncoal to it with the other; that done, dish it; d’ye hear? And now\nto-morrow, cook, when we are cutting in", "labels": {"50": 31, "100": 7, "250": 193, "500": 16, "1000": 849, "2000": 1082}}, {"id": 4481, "position": 4481, "text": "hear? And now\nto-morrow, cook, when we are cutting in the fish, be sure you stand by\nto get the tips of his fins; have them put in pickle. As for the ends\nof the flukes, have them sous", "labels": {"50": 42, "100": 59, "250": 30, "500": 72, "1000": 692, "2000": 447}}, {"id": 4482, "position": 4482, "text": "pickle. As for the ends\nof the flukes, have them soused, cook. There, now ye may go.”\n\nBut Fleece had hardly got three paces off, when he was recalled.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 4483, "position": 4483, "text": "off, when he was recalled.\n\n“Cook, give me cutlets for supper to-morrow night in the mid-watch.\nD’ye hear? away you sail, then.—Halloa! stop! make a bow before you\ngo.", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1192}}, {"id": 4484, "position": 4484, "text": "then.—Halloa! stop! make a bow before you\ngo.—Avast heaving again! Whale-balls for breakfast—don’t forget.”\n\n“Wish, by gor! whale eat him, ’stead of him eat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 4485, "position": 4485, "text": ", by gor! whale eat him, ’stead of him eat whale. I’m bressed if\nhe ain’t more of shark dan Massa Shark hisself,” muttered the old man,\nlimping away; with which", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4486, "position": 4486, "text": "elf,” muttered the old man,\nlimping away; with which sage ejaculation he went to his hammock.\n\n\nCHAPTER 65. The Whale as a Dish.\n\nThat mortal man should feed upon the creature that feeds his lamp,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 4487, "position": 4487, "text": "Dish.\n\nThat mortal man should feed upon the creature that feeds his lamp, and,\nlike Stubb, eat him by his own light, as you may say; this seems so\noutlandish a thing that one must needs go a little into the", "labels": {"50": 31, "100": 75, "250": 13, "500": 16, "1000": 134, "2000": 1592}}, {"id": 4488, "position": 4488, "text": "so\noutlandish a thing that one must needs go a little into the history and\nphilosophy of it.\n\nIt is upon record, that three centuries ago the tongue of the Right\nWhale was esteemed a great delicacy in France, and commanded large", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4489, "position": 4489, "text": "Whale was esteemed a great delicacy in France, and commanded large\nprices there. Also, that in Henry VIIIth’s time, a certain cook of the\ncourt obtained a handsome reward for inventing an admirable sauce to be\neaten", "labels": {"50": 45, "100": 24, "250": 10, "500": 72, "1000": 825, "2000": 447}}, {"id": 4490, "position": 4490, "text": "obtained a handsome reward for inventing an admirable sauce to be\neaten with barbacued porpoises, which, you remember, are a species of\nwhale. Porpoises, indeed, are to this day considered fine eating", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4491, "position": 4491, "text": "Porpoises, indeed, are to this day considered fine eating. The\nmeat is made into balls about the size of billiard balls, and being\nwell seasoned and spiced might be taken for turtle-balls or veal balls", "labels": {"50": 3, "100": 24, "250": 78, "500": 288, "1000": 782, "2000": 1905}}, {"id": 4492, "position": 4492, "text": "might be taken for turtle-balls or veal balls.\nThe old monks of Dunfermline were very fond of them. They had a great\nporpoise grant from the crown.\n\nThe fact is, that among his hunters at least, the", "labels": {"50": 48, "100": 27, "250": 157, "500": 223, "1000": 9, "2000": 682}}, {"id": 4493, "position": 4493, "text": "the crown.\n\nThe fact is, that among his hunters at least, the whale would by all\nhands be considered a noble dish, were there not so much of him; but\nwhen you come to sit down before a meat-pie nearly one hundred feet", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4494, "position": 4494, "text": "when you come to sit down before a meat-pie nearly one hundred feet\nlong, it takes away your appetite. Only the most unprejudiced of men\nlike Stubb, nowadays partake of cooked whales; but the Esquimaux", "labels": {"50": 42, "100": 59, "250": 10, "500": 16, "1000": 364, "2000": 1592}}, {"id": 4495, "position": 4495, "text": "bb, nowadays partake of cooked whales; but the Esquimaux are\nnot so fastidious. We all know how they live upon whales, and have rare\nold vintages of prime old train oil", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4496, "position": 4496, "text": "vintages of prime old train oil. Zogranda, one of their most famous\ndoctors, recommends strips of blubber for infants, as being exceedingly\njuicy and nourishing. And this reminds me that certain Englishmen, who\nlong ago", "labels": {"50": 42, "100": 7, "250": 193, "500": 36, "1000": 435, "2000": 895}}, {"id": 4497, "position": 4497, "text": "urishing. And this reminds me that certain Englishmen, who\nlong ago were accidentally left in Greenland by a whaling vessel—that\nthese men actually lived for several months on the mouldy scraps of\nwhales which had been left ashore after trying out", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4498, "position": 4498, "text": "mouldy scraps of\nwhales which had been left ashore after trying out the blubber. Among\nthe Dutch whalemen these scraps are called “fritters”; which, indeed,\nthey greatly resemble, being brown and crisp, and smelling", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4499, "position": 4499, "text": "which, indeed,\nthey greatly resemble, being brown and crisp, and smelling something\nlike old Amsterdam housewives’ dough-nuts or oly-cooks, when fresh.\nThey have such an eatable look that the most self-denying stranger can\nhardly", "labels": {"50": 48, "100": 7, "250": 49, "500": 247, "1000": 917, "2000": 616}}, {"id": 4500, "position": 4500, "text": "have such an eatable look that the most self-denying stranger can\nhardly keep his hands off.\n\nBut what further depreciates the whale as a civilized dish, is his\nexceeding richness. He is the great prize ox of the sea,", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4501, "position": 4501, "text": "his\nexceeding richness. He is the great prize ox of the sea, too fat to be\ndelicately good. Look at his hump, which would be as fine eating as the\nbuffalo’s (which is esteemed a rare dish), were", "labels": {"50": 12, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 4502, "position": 4502, "text": "the\nbuffalo’s (which is esteemed a rare dish), were it not such a solid\npyramid of fat. But the spermaceti itself, how bland and creamy that\nis; like the transparent, half-jellied, white meat", "labels": {"50": 25, "100": 41, "250": 156, "500": 435, "1000": 364, "2000": 251}}, {"id": 4503, "position": 4503, "text": "that\nis; like the transparent, half-jellied, white meat of a cocoanut in the\nthird month of its growth, yet far too rich to supply a substitute for\nbutter. Nevertheless, many whalemen have a method of absorbing it into", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4504, "position": 4504, "text": "for\nbutter. Nevertheless, many whalemen have a method of absorbing it into\nsome other substance, and then partaking of it. In the long try watches\nof the night it is a common thing for the seamen to dip their\nship-biscuit into", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4505, "position": 4505, "text": "is a common thing for the seamen to dip their\nship-biscuit into the huge oil-pots and let them fry there awhile. Many\na good supper have I thus made.\n\nIn the case of a small Sperm Whale the brains are accounted a fine", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4506, "position": 4506, "text": ".\n\nIn the case of a small Sperm Whale the brains are accounted a fine\ndish. The casket of the skull is broken into with an axe, and the two\nplump, whitish lobes being withdrawn (precisely resembling two large\npuddings), they are then", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4507, "position": 4507, "text": "lobes being withdrawn (precisely resembling two large\npuddings), they are then mixed with flour, and cooked into a most\ndelectable mess, in flavor somewhat resembling calves’ head, which is\nquite a dish among some epicures; and every one", "labels": {"50": 42, "100": 59, "250": 10, "500": 16, "1000": 364, "2000": 1592}}, {"id": 4508, "position": 4508, "text": "head, which is\nquite a dish among some epicures; and every one knows that some young\nbucks among the epicures, by continually dining upon calves’ brains, by\nand by get to have a little brains of their own, so as to be", "labels": {"50": 31, "100": 7, "250": 193, "500": 16, "1000": 849, "2000": 1592}}, {"id": 4509, "position": 4509, "text": "by get to have a little brains of their own, so as to be able to\ntell a calf’s head from their own heads; which, indeed, requires\nuncommon discrimination. And that is the reason why a young buck with\nan intelligent looking calf", "labels": {"50": 12, "100": 93, "250": 97, "500": 117, "1000": 938, "2000": 382}}, {"id": 4510, "position": 4510, "text": ". And that is the reason why a young buck with\nan intelligent looking calf’s head before him, is somehow one of the\nsaddest sights you can see. The head looks a sort of reproachfully at\nhim, with an “", "labels": {"50": 37, "100": 24, "250": 52, "500": 417, "1000": 129, "2000": 145}}, {"id": 4511, "position": 4511, "text": "head looks a sort of reproachfully at\nhim, with an “Et tu Brute!” expression.\n\nIt is not, perhaps, entirely because the whale is so excessively\nunctuous that landsmen seem to regard the eating of him with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4512, "position": 4512, "text": "ly\nunctuous that landsmen seem to regard the eating of him with\nabhorrence; that appears to result, in some way, from the consideration\nbefore mentioned: _i.e._ that a man should eat a newly murdered thing\nof", "labels": {"50": 12, "100": 42, "250": 131, "500": 417, "1000": 222, "2000": 1580}}, {"id": 4513, "position": 4513, "text": "i.e._ that a man should eat a newly murdered thing\nof the sea, and eat it too by its own light. But no doubt the first man\nthat ever murdered an ox was regarded as a murderer; perhaps he was\nhung; and", "labels": {"50": 10, "100": 85, "250": 211, "500": 490, "1000": 655, "2000": 1533}}, {"id": 4514, "position": 4514, "text": "murdered an ox was regarded as a murderer; perhaps he was\nhung; and if he had been put on his trial by oxen, he certainly would\nhave been; and he certainly deserved it if any murderer does", "labels": {"50": 21, "100": 95, "250": 76, "500": 295, "1000": 761, "2000": 1376}}, {"id": 4515, "position": 4515, "text": "certainly deserved it if any murderer does. Go to the\nmeat-market of a Saturday night and see the crowds of live bipeds\nstaring up at the long rows of dead quadrupeds. Does not that sight\ntake a tooth out of the", "labels": {"50": 21, "100": 24, "250": 52, "500": 417, "1000": 581, "2000": 402}}, {"id": 4516, "position": 4516, "text": "quadrupeds. Does not that sight\ntake a tooth out of the cannibal’s jaw? Cannibals? who is not a\ncannibal? I tell you it will be more tolerable for the Fejee that", "labels": {"50": 32, "100": 96, "250": 153, "500": 457, "1000": 514, "2000": 1631}}, {"id": 4517, "position": 4517, "text": "I tell you it will be more tolerable for the Fejee that\nsalted down a lean missionary in his cellar against a coming famine; it\nwill be more tolerable for that provident Fejee, I say, in the day of", "labels": {"50": 32, "100": 96, "250": 153, "500": 457, "1000": 514, "2000": 1631}}, {"id": 4518, "position": 4518, "text": "able for that provident Fejee, I say, in the day of\njudgment, than for thee, civilized and enlightened gourmand, who\nnailest geese to the ground and feastest on their bloated livers in thy", "labels": {"50": 9, "100": 26, "250": 30, "500": 16, "1000": 364, "2000": 1592}}, {"id": 4519, "position": 4519, "text": "to the ground and feastest on their bloated livers in thy\npaté-de-foie-gras.\n\nBut Stubb, he eats the whale by its own light, does he? and that is\nadding insult to injury", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 343, "2000": 1620}}, {"id": 4520, "position": 4520, "text": "by its own light, does he? and that is\nadding insult to injury, is it? Look at your knife-handle, there, my\ncivilized and enlightened gourmand dining off that roast beef, what is\nthat handle made of", "labels": {"50": 3, "100": 70, "250": 46, "500": 403, "1000": 109, "2000": 268}}, {"id": 4521, "position": 4521, "text": "urmand dining off that roast beef, what is\nthat handle made of?—what but the bones of the brother of the very ox\nyou are eating? And what do you pick your teeth with, after devouring\nthat fat goose? With a", "labels": {"50": 31, "100": 7, "250": 30, "500": 274, "1000": 345, "2000": 421}}, {"id": 4522, "position": 4522, "text": "you pick your teeth with, after devouring\nthat fat goose? With a feather of the same fowl. And with what quill\ndid the Secretary of the Society for the Suppression of Cruelty to\nGanders formally indite his circulars? It", "labels": {"50": 31, "100": 24, "250": 193, "500": 498, "1000": 849, "2000": 1107}}, {"id": 4523, "position": 4523, "text": "the Suppression of Cruelty to\nGanders formally indite his circulars? It is only within the last month\nor two that that society passed a resolution to patronize nothing but\nsteel pens.\n\n\nCHAPTER 66. The Shark Massacre.", "labels": {"50": 1, "100": 7, "250": 44, "500": 220, "1000": 225, "2000": 1022}}, {"id": 4524, "position": 4524, "text": "pens.\n\n\nCHAPTER 66. The Shark Massacre.\n\nWhen in the Southern Fishery, a captured Sperm Whale, after long and\nweary toil, is brought alongside late at night, it is not, as a general\nthing at least, customary to proceed at once", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4525, "position": 4525, "text": "is not, as a general\nthing at least, customary to proceed at once to the business of cutting\nhim in. For that business is an exceedingly laborious one; is not very\nsoon completed; and requires all hands to set about it", "labels": {"50": 31, "100": 75, "250": 106, "500": 298, "1000": 290, "2000": 1064}}, {"id": 4526, "position": 4526, "text": "not very\nsoon completed; and requires all hands to set about it. Therefore, the\ncommon usage is to take in all sail; lash the helm a’lee; and then send\nevery one below to his hammock till daylight, with the reservation", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4527, "position": 4527, "text": "send\nevery one below to his hammock till daylight, with the reservation\nthat, until that time, anchor-watches shall be kept; that is, two and\ntwo for an hour, each couple, the crew in rotation shall mount the deck\nto", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 4528, "position": 4528, "text": "an hour, each couple, the crew in rotation shall mount the deck\nto see that all goes well.\n\nBut sometimes, especially upon the Line in the Pacific, this plan will\nnot answer at all; because such incalculable hosts of sharks gather", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4529, "position": 4529, "text": "not answer at all; because such incalculable hosts of sharks gather\nround the moored carcase, that were he left so for six hours, say, on a\nstretch, little more than the skeleton would be visible by morning", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4530, "position": 4530, "text": "stretch, little more than the skeleton would be visible by morning. In\nmost other parts of the ocean, however, where these fish do not so\nlargely abound, their wondrous voracity can be at times considerably\ndiminished, by vigorously stirring", "labels": {"50": 3, "100": 70, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 4531, "position": 4531, "text": "drous voracity can be at times considerably\ndiminished, by vigorously stirring them up with sharp whaling-spades, a\nprocedure notwithstanding, which, in some instances, only seems to\ntickle them into still greater activity", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4532, "position": 4532, "text": "seems to\ntickle them into still greater activity. But it was not thus in the\npresent case with the Pequod’s sharks; though, to be sure, any man\nunaccustomed to such sights, to have looked over her side", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4533, "position": 4533, "text": "man\nunaccustomed to such sights, to have looked over her side that night,\nwould have almost thought the whole round sea was one huge cheese, and\nthose sharks the maggots in it.", "labels": {"50": 0, "100": 91, "250": 247, "500": 21, "1000": 690, "2000": 1469}}, {"id": 4534, "position": 4534, "text": "maggots in it.\n\nNevertheless, upon Stubb setting the anchor-watch after his supper was\nconcluded; and when, accordingly, Queequeg and a forecastle seaman came\non deck, no small excitement was created among the sharks; for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4535, "position": 4535, "text": "seaman came\non deck, no small excitement was created among the sharks; for\nimmediately suspending the cutting stages over the side, and lowering\nthree lanterns, so that they cast long gleams of light over the turbid\nsea, these two mariners,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4536, "position": 4536, "text": "gleams of light over the turbid\nsea, these two mariners, darting their long whaling-spades, kept up an\nincessant murdering of the sharks,* by striking the keen steel deep\ninto their skulls, seemingly their only vital part", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4537, "position": 4537, "text": "by striking the keen steel deep\ninto their skulls, seemingly their only vital part. But in the foamy\nconfusion of their mixed and struggling hosts, the marksmen could not\nalways hit their mark; and this brought about new revelations of the\nincredible ferocity", "labels": {"50": 22, "100": 55, "250": 11, "500": 479, "1000": 959, "2000": 481}}, {"id": 4538, "position": 4538, "text": "hit their mark; and this brought about new revelations of the\nincredible ferocity of the foe. They viciously snapped, not only at\neach other’s disembowelments, but like flexible bows, bent round, and\nbit their own", "labels": {"50": 22, "100": 80, "250": 39, "500": 263, "1000": 959, "2000": 687}}, {"id": 4539, "position": 4539, "text": "lments, but like flexible bows, bent round, and\nbit their own; till those entrails seemed swallowed over and over again\nby the same mouth, to be oppositely voided by the gaping wound. Nor was\nthis all", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 437, "2000": 1374}}, {"id": 4540, "position": 4540, "text": "ly voided by the gaping wound. Nor was\nthis all. It was unsafe to meddle with the corpses and ghosts of these\ncreatures. A sort of generic or Pantheistic vitality seemed to lurk in\ntheir very joints and bones, after", "labels": {"50": 22, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1904}}, {"id": 4541, "position": 4541, "text": "istic vitality seemed to lurk in\ntheir very joints and bones, after what might be called the individual\nlife had departed. Killed and hoisted on deck for the sake of his skin,\none of these sharks almost took poor Queequeg’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4542, "position": 4542, "text": "skin,\none of these sharks almost took poor Queequeg’s hand off, when he tried\nto shut down the dead lid of his murderous jaw.\n\n*The whaling-spade used for cutting-in is made of the very best steel;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4543, "position": 4543, "text": "-spade used for cutting-in is made of the very best steel;\nis about the bigness of a man’s spread hand; and in general shape,\ncorresponds to the garden implement after which it is named; only its\nsides are perfectly flat", "labels": {"50": 42, "100": 46, "250": 142, "500": 209, "1000": 597, "2000": 1903}}, {"id": 4544, "position": 4544, "text": "the garden implement after which it is named; only its\nsides are perfectly flat, and its upper end considerably narrower than\nthe lower. This weapon is always kept as sharp as possible; and when\nbeing used is occasionally honed, just like a razor", "labels": {"50": 32, "100": 42, "250": 131, "500": 329, "1000": 569, "2000": 338}}, {"id": 4545, "position": 4545, "text": "; and when\nbeing used is occasionally honed, just like a razor. In its socket, a\nstiff pole, from twenty to thirty feet long, is inserted for a handle.\n\n“Queequeg no care what god made him shark,”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4546, "position": 4546, "text": ".\n\n“Queequeg no care what god made him shark,” said the savage,\nagonizingly lifting his hand up and down; “wedder Fejee god or\nNantucket god; but de god wat made shark must be one", "labels": {"50": 41, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 4547, "position": 4547, "text": "god or\nNantucket god; but de god wat made shark must be one dam Ingin.”\n\n\nCHAPTER 67. Cutting In.\n\nIt was a Saturday night, and such a Sabbath as followed! Ex officio\nprofessors of Sabbath breaking are all whalemen", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4548, "position": 4548, "text": "Sabbath as followed! Ex officio\nprofessors of Sabbath breaking are all whalemen. The ivory Pequod was\nturned into what seemed a shamble; every sailor a butcher. You would\nhave thought we were offering up ten thousand red oxen to the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4549, "position": 4549, "text": "You would\nhave thought we were offering up ten thousand red oxen to the sea gods.\n\nIn the first place, the enormous cutting tackles, among other ponderous\nthings comprising a cluster of blocks generally painted green, and\nwhich no single man can possibly lift", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4550, "position": 4550, "text": "cluster of blocks generally painted green, and\nwhich no single man can possibly lift—this vast bunch of grapes was\nswayed up to the main-top and firmly lashed to the lower mast-head, the\nstrongest point anywhere above a ship’s deck", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4551, "position": 4551, "text": "mast-head, the\nstrongest point anywhere above a ship’s deck. The end of the\nhawser-like rope winding through these intricacies, was then conducted\nto the windlass, and the huge lower block of the tackles was swung", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 4552, "position": 4552, "text": "to the windlass, and the huge lower block of the tackles was swung over\nthe whale; to this block the great blubber hook, weighing some one\nhundred pounds, was attached. And now suspended in stages over the\nside, Starbuck and Stu", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4553, "position": 4553, "text": "attached. And now suspended in stages over the\nside, Starbuck and Stubb, the mates, armed with their long spades,\nbegan cutting a hole in the body for the insertion of the hook just\nabove the nearest of the two side-fins", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4554, "position": 4554, "text": "the insertion of the hook just\nabove the nearest of the two side-fins. This done, a broad,\nsemicircular line is cut round the hole, the hook is inserted, and the\nmain body of the crew striking up a wild chorus", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 692, "2000": 447}}, {"id": 4555, "position": 4555, "text": "is inserted, and the\nmain body of the crew striking up a wild chorus, now commence heaving\nin one dense crowd at the windlass. When instantly, the entire ship\ncareens over on her side; every bolt in her starts like the nail-", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 4556, "position": 4556, "text": "ens over on her side; every bolt in her starts like the nail-heads\nof an old house in frosty weather; she trembles, quivers, and nods her\nfrighted mast-heads to the sky", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 4557, "position": 4557, "text": "frighted mast-heads to the sky. More and more she leans over to the\nwhale, while every gasping heave of the windlass is answered by a\nhelping heave from the billows; till at last, a swift, startling snap\nis", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4558, "position": 4558, "text": "from the billows; till at last, a swift, startling snap\nis heard; with a great swash the ship rolls upwards and backwards from\nthe whale, and the triumphant tackle rises into sight dragging after it\nthe disengaged semicirc", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4559, "position": 4559, "text": "tackle rises into sight dragging after it\nthe disengaged semicircular end of the first strip of blubber. Now as\nthe blubber envelopes the whale precisely as the rind does an orange,\nso is it stripped off from the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4560, "position": 4560, "text": "as the rind does an orange,\nso is it stripped off from the body precisely as an orange is sometimes\nstripped by spiralizing it. For the strain constantly kept up by the\nwindlass continually keeps the whale rolling over and over in the\nwater,", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4561, "position": 4561, "text": "the\nwindlass continually keeps the whale rolling over and over in the\nwater, and as the blubber in one strip uniformly peels off along the\nline called the “scarf,” simultaneously cut by the spades of Starbuck\nand Stubb, the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4562, "position": 4562, "text": "” simultaneously cut by the spades of Starbuck\nand Stubb, the mates; and just as fast as it is thus peeled off, and\nindeed by that very act itself, it is all the time being hoisted higher\nand higher aloft till its", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4563, "position": 4563, "text": ", it is all the time being hoisted higher\nand higher aloft till its upper end grazes the main-top; the men at the\nwindlass then cease heaving, and for a moment or two the prodigious\nblood-dripping mass sway", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4564, "position": 4564, "text": "for a moment or two the prodigious\nblood-dripping mass sways to and fro as if let down from the sky, and\nevery one present must take good heed to dodge it when it swings, else\nit may box his ears", "labels": {"50": 31, "100": 20, "250": 49, "500": 334, "1000": 747, "2000": 1710}}, {"id": 4565, "position": 4565, "text": "heed to dodge it when it swings, else\nit may box his ears and pitch him headlong overboard.\n\nOne of the attending harpooneers now advances with a long, keen weapon\ncalled a boarding-sword, and watching his chance he dexterously", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4566, "position": 4566, "text": "keen weapon\ncalled a boarding-sword, and watching his chance he dexterously slices\nout a considerable hole in the lower part of the swaying mass. Into\nthis hole, the end of the second alternating great tackle is then\nhooked so as to retain a hold", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 505, "2000": 1225}}, {"id": 4567, "position": 4567, "text": "of the second alternating great tackle is then\nhooked so as to retain a hold upon the blubber, in order to prepare for\nwhat follows. Whereupon, this accomplished swordsman, warning all hands\nto stand off, once more makes a scientific dash at the", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4568, "position": 4568, "text": "warning all hands\nto stand off, once more makes a scientific dash at the mass, and with a\nfew sidelong, desperate, lunging slicings, severs it completely in\ntwain; so that while the short lower part is still fast, the", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4569, "position": 4569, "text": "in\ntwain; so that while the short lower part is still fast, the long upper\nstrip, called a blanket-piece, swings clear, and is all ready for\nlowering. The heavers forward now resume their song, and while the one\ntackle", "labels": {"50": 12, "100": 42, "250": 52, "500": 417, "1000": 486, "2000": 880}}, {"id": 4570, "position": 4570, "text": "The heavers forward now resume their song, and while the one\ntackle is peeling and hoisting a second strip from the whale, the other\nis slowly slackened away, and down goes the first strip through the\nmain hatchway right beneath,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4571, "position": 4571, "text": ", and down goes the first strip through the\nmain hatchway right beneath, into an unfurnished parlor called the\nblubber-room. Into this twilight apartment sundry nimble hands keep\ncoiling away the long blanket-piece as if it were", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4572, "position": 4572, "text": "mble hands keep\ncoiling away the long blanket-piece as if it were a great live mass of\nplaited serpents. And thus the work proceeds; the two tackles hoisting\nand lowering simultaneously; both whale and windlass heaving, the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4573, "position": 4573, "text": "hoisting\nand lowering simultaneously; both whale and windlass heaving, the\nheavers singing, the blubber-room gentlemen coiling, the mates\nscarfing, the ship straining, and all hands swearing occasionally, by\nway of assuaging", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4574, "position": 4574, "text": "ship straining, and all hands swearing occasionally, by\nway of assuaging the general friction.\n\n\nCHAPTER 68. The Blanket.\n\nI have given no small attention to that not unvexed subject, the skin\nof the whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4575, "position": 4575, "text": "vexed subject, the skin\nof the whale. I have had controversies about it with experienced\nwhalemen afloat, and learned naturalists ashore. My original opinion\nremains unchanged; but it is only an opinion.", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4576, "position": 4576, "text": "but it is only an opinion.\n\nThe question is, what and where is the skin of the whale? Already you\nknow what his blubber is. That blubber is something of the consistence\nof firm, close-grained beef, but tough", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4577, "position": 4577, "text": "of the consistence\nof firm, close-grained beef, but tougher, more elastic and compact, and\nranges from eight or ten to twelve and fifteen inches in thickness.\n\nNow, however preposterous it may at first seem to talk", "labels": {"50": 3, "100": 85, "250": 14, "500": 395, "1000": 276, "2000": 458}}, {"id": 4578, "position": 4578, "text": ".\n\nNow, however preposterous it may at first seem to talk of any\ncreature’s skin as being of that sort of consistence and thickness, yet\nin point of fact these are no arguments against such a presumption;\nbecause you", "labels": {"50": 3, "100": 71, "250": 33, "500": 403, "1000": 134, "2000": 458}}, {"id": 4579, "position": 4579, "text": "of fact these are no arguments against such a presumption;\nbecause you cannot raise any other dense enveloping layer from the\nwhale’s body but that same blubber; and the outermost enveloping layer\nof any animal, if reasonably", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4580, "position": 4580, "text": "; and the outermost enveloping layer\nof any animal, if reasonably dense, what can that be but the skin?\nTrue, from the unmarred dead body of the whale, you may scrape off with\nyour hand an infinitely thin, transparent", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4581, "position": 4581, "text": "the whale, you may scrape off with\nyour hand an infinitely thin, transparent substance, somewhat\nresembling the thinnest shreds of isinglass, only it is almost as\nflexible and soft as satin; that is, previous to being dried,", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4582, "position": 4582, "text": "as\nflexible and soft as satin; that is, previous to being dried, when it\nnot only contracts and thickens, but becomes rather hard and brittle. I\nhave several such dried bits, which I use for marks in my whale-books", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 4583, "position": 4583, "text": "dried bits, which I use for marks in my whale-books.\nIt is transparent, as I said before; and being laid upon the printed\npage, I have sometimes pleased myself with fancying it exerted a\nmagnifying influence", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4584, "position": 4584, "text": "myself with fancying it exerted a\nmagnifying influence. At any rate, it is pleasant to read about whales\nthrough their own spectacles, as you may say. But what I am driving at\nhere is this", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4585, "position": 4585, "text": "But what I am driving at\nhere is this. That same infinitely thin, isinglass substance, which, I\nadmit, invests the entire body of the whale, is not so much to be\nregarded as the skin of the creature, as the", "labels": {"50": 3, "100": 24, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4586, "position": 4586, "text": "not so much to be\nregarded as the skin of the creature, as the skin of the skin, so to\nspeak; for it were simply ridiculous to say, that the proper skin of\nthe tremendous whale is thinner and more tender than the skin of a", "labels": {"50": 3, "100": 24, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4587, "position": 4587, "text": "skin of\nthe tremendous whale is thinner and more tender than the skin of a\nnew-born child. But no more of this.\n\nAssuming the blubber to be the skin of the whale; then, when this skin,\nas in the case of a", "labels": {"50": 3, "100": 24, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4588, "position": 4588, "text": "the whale; then, when this skin,\nas in the case of a very large Sperm Whale, will yield the bulk of one\nhundred barrels of oil; and, when it is considered that, in quantity,\nor rather weight, that oil, in", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4589, "position": 4589, "text": "is considered that, in quantity,\nor rather weight, that oil, in its expressed state, is only three\nfourths, and not the entire substance of the coat; some idea may hence\nbe had of the enormousness of that animated mass, a", "labels": {"50": 3, "100": 70, "250": 46, "500": 197, "1000": 109, "2000": 1548}}, {"id": 4590, "position": 4590, "text": "idea may hence\nbe had of the enormousness of that animated mass, a mere part of whose\nmere integument yields such a lake of liquid as that. Reckoning ten\nbarrels to the ton, you have ten tons for the net weight of", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4591, "position": 4591, "text": "ten\nbarrels to the ton, you have ten tons for the net weight of only three\nquarters of the stuff of the whale’s skin.\n\nIn life, the visible surface of the Sperm Whale is not the least among\nthe many marvels he presents", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4592, "position": 4592, "text": "the Sperm Whale is not the least among\nthe many marvels he presents. Almost invariably it is all over\nobliquely crossed and re-crossed with numberless straight marks in\nthick array, something like those in the finest Italian line\nengravings", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4593, "position": 4593, "text": "array, something like those in the finest Italian line\nengravings. But these marks do not seem to be impressed upon the\nisinglass substance above mentioned, but seem to be seen through it, as\nif they were engraved upon the body itself", "labels": {"50": 3, "100": 70, "250": 234, "500": 108, "1000": 825, "2000": 1620}}, {"id": 4594, "position": 4594, "text": "through it, as\nif they were engraved upon the body itself. Nor is this all. In some\ninstances, to the quick, observant eye, those linear marks, as in a\nveritable engraving, but afford the ground for far other", "labels": {"50": 48, "100": 20, "250": 192, "500": 77, "1000": 478, "2000": 965}}, {"id": 4595, "position": 4595, "text": "as in a\nveritable engraving, but afford the ground for far other delineations.\nThese are hieroglyphical; that is, if you call those mysterious cyphers\non the walls of pyramids hieroglyphics,", "labels": {"50": 10, "100": 71, "250": 211, "500": 77, "1000": 134, "2000": 965}}, {"id": 4596, "position": 4596, "text": "cyphers\non the walls of pyramids hieroglyphics, then that is the proper word to\nuse in the present connexion. By my retentive memory of the\nhieroglyphics upon one Sperm Whale in particular", "labels": {"50": 31, "100": 85, "250": 193, "500": 7, "1000": 256, "2000": 1380}}, {"id": 4597, "position": 4597, "text": "tive memory of the\nhieroglyphics upon one Sperm Whale in particular, I was much struck\nwith a plate representing the old Indian characters chiselled on the\nfamous hieroglyphic palisades on the banks of the Upper Mississippi", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4598, "position": 4598, "text": "eroglyphic palisades on the banks of the Upper Mississippi.\nLike those mystic rocks, too, the mystic-marked whale remains\nundecipherable. This allusion to the Indian rocks reminds me of another\nthing", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4599, "position": 4599, "text": "usion to the Indian rocks reminds me of another\nthing. Besides all the other phenomena which the exterior of the Sperm\nWhale presents, he not seldom displays the back, and more especially\nhis flanks, effaced in great part of the regular linear appearance,", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4600, "position": 4600, "text": "his flanks, effaced in great part of the regular linear appearance, by\nreason of numerous rude scratches, altogether of an irregular, random\naspect. I should say that those New England rocks on the sea-coast,\nwhich Agassiz imagines", "labels": {"50": 45, "100": 37, "250": 143, "500": 294, "1000": 723, "2000": 739}}, {"id": 4601, "position": 4601, "text": "New England rocks on the sea-coast,\nwhich Agassiz imagines to bear the marks of violent scraping contact\nwith vast floating icebergs—I should say, that those rocks must not a\nlittle resemble the Sperm Whale in this particular", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 825, "2000": 1620}}, {"id": 4602, "position": 4602, "text": "those rocks must not a\nlittle resemble the Sperm Whale in this particular. It also seems to me\nthat such scratches in the whale are probably made by hostile contact\nwith other whales; for I have most remarked them in the large,\nfull-grown bulls of", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4603, "position": 4603, "text": "for I have most remarked them in the large,\nfull-grown bulls of the species.\n\nA word or two more concerning this matter of the skin or blubber of the\nwhale. It has already been said, that it is stript from him in", "labels": {"50": 12, "100": 43, "250": 209, "500": 181, "1000": 43, "2000": 1054}}, {"id": 4604, "position": 4604, "text": ". It has already been said, that it is stript from him in long\npieces, called blanket-pieces. Like most sea-terms, this one is very\nhappy and significant. For the whale is indeed wrapt up in his blubber\nas", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4605, "position": 4605, "text": "significant. For the whale is indeed wrapt up in his blubber\nas in a real blanket or counterpane; or, still better, an Indian poncho\nslipt over his head, and skirting his extremity", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4606, "position": 4606, "text": "t over his head, and skirting his extremity. It is by reason of\nthis cosy blanketing of his body, that the whale is enabled to keep\nhimself comfortable in all weathers, in all seas, times, and tides", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4607, "position": 4607, "text": "comfortable in all weathers, in all seas, times, and tides.\nWhat would become of a Greenland whale, say, in those shuddering, icy\nseas of the North, if unsupplied with his cosy surtout? True", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4608, "position": 4608, "text": "if unsupplied with his cosy surtout? True, other\nfish are found exceedingly brisk in those Hyperborean waters; but\nthese, be it observed, are your cold-blooded, lungless fish, whose very\nbell", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4609, "position": 4609, "text": "observed, are your cold-blooded, lungless fish, whose very\nbellies are refrigerators; creatures, that warm themselves under the\nlee of an iceberg, as a traveller in winter would bask before an inn\nfire; whereas, like man", "labels": {"50": 31, "100": 75, "250": 193, "500": 307, "1000": 343, "2000": 1107}}, {"id": 4610, "position": 4610, "text": "traveller in winter would bask before an inn\nfire; whereas, like man, the whale has lungs and warm blood. Freeze his\nblood, and he dies. How wonderful is it then—except after\nexplanation—that this great monster, to whom corp", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4611, "position": 4611, "text": "it then—except after\nexplanation—that this great monster, to whom corporeal warmth is as\nindispensable as it is to man; how wonderful that he should be found at\nhome, immersed to his lips for life in those Arctic waters", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4612, "position": 4612, "text": "be found at\nhome, immersed to his lips for life in those Arctic waters! where, when\nseamen fall overboard, they are sometimes found, months afterwards,\nperpendicularly frozen into the hearts of fields of ice, as a fly is\nfound glued in amber", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4613, "position": 4613, "text": "the hearts of fields of ice, as a fly is\nfound glued in amber. But more surprising is it to know, as has been\nproved by experiment, that the blood of a Polar whale is warmer than\nthat of a Borneo negro in summer.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4614, "position": 4614, "text": "a Polar whale is warmer than\nthat of a Borneo negro in summer.\n\nIt does seem to me, that herein we see the rare virtue of a strong\nindividual vitality, and the rare virtue of thick walls, and the rare\nvirtue of interior spacious", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4615, "position": 4615, "text": "and the rare virtue of thick walls, and the rare\nvirtue of interior spaciousness. Oh, man! admire and model thyself\nafter the whale! Do thou, too, remain warm among ice. Do thou, too,\nlive in this world", "labels": {"50": 9, "100": 26, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4616, "position": 4616, "text": ", remain warm among ice. Do thou, too,\nlive in this world without being of it. Be cool at the equator; keep\nthy blood fluid at the Pole. Like the great dome of St. Peter’s, and\nlike the great whale", "labels": {"50": 16, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 16}}, {"id": 4617, "position": 4617, "text": "the great dome of St. Peter’s, and\nlike the great whale, retain, O man! in all seasons a temperature of\nthine own.\n\nBut how easy and how hopeless to teach these fine things! Of erections,\nhow few are", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4618, "position": 4618, "text": "how hopeless to teach these fine things! Of erections,\nhow few are domed like St. Peter’s! of creatures, how few vast as the\nwhale!\n\n\nCHAPTER 69. The Funeral.\n\n“Haul in the chains! Let the carcase go", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4619, "position": 4619, "text": ". The Funeral.\n\n“Haul in the chains! Let the carcase go astern!”\n\nThe vast tackles have now done their duty. The peeled white body of the\nbeheaded whale flashes like a marble sepulchre; though changed in hue,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4620, "position": 4620, "text": "whale flashes like a marble sepulchre; though changed in hue,\nit has not perceptibly lost anything in bulk. It is still colossal.\nSlowly it floats more and more away, the water round it torn and\nsplashed by the ins", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4621, "position": 4621, "text": "more and more away, the water round it torn and\nsplashed by the insatiate sharks, and the air above vexed with\nrapacious flights of screaming fowls, whose beaks are like so many\ninsulting poniards in the whale", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 4622, "position": 4622, "text": "whose beaks are like so many\ninsulting poniards in the whale. The vast white headless phantom floats\nfurther and further from the ship, and every rod that it so floats,\nwhat seem square roods of sharks and cubic roods of f", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4623, "position": 4623, "text": "floats,\nwhat seem square roods of sharks and cubic roods of fowls, augment the\nmurderous din. For hours and hours from the almost stationary ship that\nhideous sight is seen. Beneath the unclouded and mild azure sky,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 4624, "position": 4624, "text": "sight is seen. Beneath the unclouded and mild azure sky, upon\nthe fair face of the pleasant sea, wafted by the joyous breezes, that\ngreat mass of death floats on and on, till lost in infinite\nperspectives.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4625, "position": 4625, "text": "mass of death floats on and on, till lost in infinite\nperspectives.\n\nThere’s a most doleful and most mocking funeral! The sea-vultures all\nin pious mourning, the air-sharks all punctiliously in black or\nspec", "labels": {"50": 16, "100": 73, "250": 133, "500": 72, "1000": 747, "2000": 1620}}, {"id": 4626, "position": 4626, "text": "mourning, the air-sharks all punctiliously in black or\nspeckled. In life but few of them would have helped the whale, I ween,\nif peradventure he had needed it; but upon the banquet of his funeral", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4627, "position": 4627, "text": "adventure he had needed it; but upon the banquet of his funeral\nthey most piously do pounce. Oh, horrible vultureism of earth! from\nwhich not the mightiest whale is free.\n\nNor is this the end", "labels": {"50": 22, "100": 78, "250": 133, "500": 414, "1000": 437, "2000": 1554}}, {"id": 4628, "position": 4628, "text": "mightiest whale is free.\n\nNor is this the end. Desecrated as the body is, a vengeful ghost\nsurvives and hovers over it to scare. Espied by some timid man-of-war\nor blundering", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4629, "position": 4629, "text": "pied by some timid man-of-war\nor blundering discovery-vessel from afar, when the distance obscuring\nthe swarming fowls, nevertheless still shows the white mass floating in\nthe sun, and the white spray heaving", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4630, "position": 4630, "text": "still shows the white mass floating in\nthe sun, and the white spray heaving high against it; straightway the\nwhale’s unharming corpse, with trembling fingers is set down in the\nlog—_shoals, rocks, and breakers hereab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4631, "position": 4631, "text": "down in the\nlog—_shoals, rocks, and breakers hereabouts: beware!_ And for years\nafterwards, perhaps, ships shun the place; leaping over it as silly\nsheep leap over a vacuum, because their leader originally leaped", "labels": {"50": 9, "100": 73, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 4632, "position": 4632, "text": "over it as silly\nsheep leap over a vacuum, because their leader originally leaped there\nwhen a stick was held. There’s your law of precedents; there’s your\nutility of traditions; there’s the story of your obstinate survival", "labels": {"50": 10, "100": 71, "250": 69, "500": 236, "1000": 919, "2000": 506}}, {"id": 4633, "position": 4633, "text": "utility of traditions; there’s the story of your obstinate survival of\nold beliefs never bottomed on the earth, and now not even hovering in\nthe air! There’s orthodoxy!\n\nThus, while in life the great whale’s body", "labels": {"50": 10, "100": 66, "250": 129, "500": 490, "1000": 134, "2000": 1676}}, {"id": 4634, "position": 4634, "text": "’s orthodoxy!\n\nThus, while in life the great whale’s body may have been a real terror\nto his foes, in his death his ghost becomes a powerless panic to a\nworld.\n\nAre you a believer in ghosts, my friend? There", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4635, "position": 4635, "text": "to a\nworld.\n\nAre you a believer in ghosts, my friend? There are other ghosts than\nthe Cock-Lane one, and far deeper men than Doctor Johnson who believe\nin them.\n\n\nCHAPTER 70. The Sphynx.", "labels": {"50": 31, "100": 71, "250": 210, "500": 41, "1000": 796, "2000": 1588}}, {"id": 4636, "position": 4636, "text": "them.\n\n\nCHAPTER 70. The Sphynx.\n\nIt should not have been omitted that previous to completely stripping\nthe body of the leviathan, he was beheaded. Now, the beheading of the\nSperm Whale is a scientific anatomical feat, upon which", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4637, "position": 4637, "text": "beheading of the\nSperm Whale is a scientific anatomical feat, upon which experienced\nwhale surgeons very much pride themselves: and not without reason.\n\nConsider that the whale has nothing that can properly be called a neck;\non the contrary, where his head and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4638, "position": 4638, "text": "can properly be called a neck;\non the contrary, where his head and body seem to join, there, in that\nvery place, is the thickest part of him. Remember, also, that the\nsurgeon must operate from above, some eight or", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 845, "2000": 268}}, {"id": 4639, "position": 4639, "text": "Remember, also, that the\nsurgeon must operate from above, some eight or ten feet intervening\nbetween him and his subject, and that subject almost hidden in a\ndiscoloured, rolling, and oftentimes tumultuous and bursting sea", "labels": {"50": 31, "100": 20, "250": 13, "500": 453, "1000": 134, "2000": 1620}}, {"id": 4640, "position": 4640, "text": "rolling, and oftentimes tumultuous and bursting sea. Bear\nin mind, too, that under these untoward circumstances he has to cut\nmany feet deep in the flesh; and in that subterraneous manner, without\nso much as", "labels": {"50": 9, "100": 24, "250": 30, "500": 475, "1000": 902, "2000": 1374}}, {"id": 4641, "position": 4641, "text": "flesh; and in that subterraneous manner, without\nso much as getting one single peep into the ever-contracting gash thus\nmade, he must skilfully steer clear of all adjacent, interdicted parts,\nand exactly divide", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4642, "position": 4642, "text": "y steer clear of all adjacent, interdicted parts,\nand exactly divide the spine at a critical point hard by its insertion\ninto the skull. Do you not marvel, then, at Stubb’s boast, that he\ndemanded but ten minutes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4643, "position": 4643, "text": ", at Stubb’s boast, that he\ndemanded but ten minutes to behead a sperm whale?\n\nWhen first severed, the head is dropped astern and held there by a\ncable till the body is stripped", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4644, "position": 4644, "text": "by a\ncable till the body is stripped. That done, if it belong to a small\nwhale it is hoisted on deck to be deliberately disposed of. But, with a\nfull grown leviathan this is impossible; for the sperm whale’s head\nembrace", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4645, "position": 4645, "text": "grown leviathan this is impossible; for the sperm whale’s head\nembraces nearly one third of his entire bulk, and completely to suspend\nsuch a burden as that, even by the immense tackles of a whaler, this\nwere as vain a thing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4646, "position": 4646, "text": "by the immense tackles of a whaler, this\nwere as vain a thing as to attempt weighing a Dutch barn in jewellers’\nscales.\n\nThe Pequod’s whale being decapitated and the body stripped, the head\nwas hoisted against the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4647, "position": 4647, "text": "being decapitated and the body stripped, the head\nwas hoisted against the ship’s side—about half way out of the sea, so\nthat it might yet in great part be buoyed up by its native element", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4648, "position": 4648, "text": "part be buoyed up by its native element. And\nthere with the strained craft steeply leaning over to it, by reason of\nthe enormous downward drag from the lower mast-head, and every yard-arm\non that side projecting like a crane", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4649, "position": 4649, "text": "-head, and every yard-arm\non that side projecting like a crane over the waves; there, that\nblood-dripping head hung to the Pequod’s waist like the giant\nHolofernes’s from the girdle of", "labels": {"50": 9, "100": 26, "250": 240, "500": 332, "1000": 663, "2000": 1620}}, {"id": 4650, "position": 4650, "text": "like the giant\nHolofernes’s from the girdle of Judith.\n\nWhen this last task was accomplished it was noon, and the seamen went\nbelow to their dinner. Silence reigned over the before tumultuous but\nnow deserted deck", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 1904}}, {"id": 4651, "position": 4651, "text": ". Silence reigned over the before tumultuous but\nnow deserted deck. An intense copper calm, like a universal yellow\nlotus, was more and more unfolding its noiseless measureless leaves\nupon the sea.", "labels": {"50": 16, "100": 64, "250": 205, "500": 162, "1000": 783, "2000": 889}}, {"id": 4652, "position": 4652, "text": "measureless leaves\nupon the sea.\n\nA short space elapsed, and up into this noiselessness came Ahab alone\nfrom his cabin. Taking a few turns on the quarter-deck, he paused to\ngaze over the side, then slowly getting into", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4653, "position": 4653, "text": "-deck, he paused to\ngaze over the side, then slowly getting into the main-chains he took\nStubb’s long spade—still remaining there after the whale’s\ndecapitation—and striking it into the lower part of the half", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4654, "position": 4654, "text": "s\ndecapitation—and striking it into the lower part of the half-suspended\nmass, placed its other end crutch-wise under one arm, and so stood\nleaning over with eyes attentively fixed on this head.", "labels": {"50": 22, "100": 55, "250": 205, "500": 479, "1000": 959, "2000": 481}}, {"id": 4655, "position": 4655, "text": "leaning over with eyes attentively fixed on this head.\n\nIt was a black and hooded head; and hanging there in the midst of so\nintense a calm, it seemed the Sphynx’s in the desert", "labels": {"50": 9, "100": 5, "250": 26, "500": 411, "1000": 930, "2000": 1860}}, {"id": 4656, "position": 4656, "text": "Sphynx’s in the desert. “Speak, thou vast\nand venerable head,” muttered Ahab, “which, though ungarnished with a\nbeard, yet here and there lookest hoary with mosses; speak, mighty\nhead", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4657, "position": 4657, "text": "here and there lookest hoary with mosses; speak, mighty\nhead, and tell us the secret thing that is in thee. Of all divers, thou\nhast dived the deepest. That head upon which the upper sun now gleams,", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 16}}, {"id": 4658, "position": 4658, "text": "d the deepest. That head upon which the upper sun now gleams,\nhas moved amid this world’s foundations. Where unrecorded names and\nnavies rust, and untold hopes and anchors rot; where in her murderous\nhold this frigate", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 573}}, {"id": 4659, "position": 4659, "text": "and untold hopes and anchors rot; where in her murderous\nhold this frigate earth is ballasted with bones of millions of the\ndrowned; there, in that awful water-land, there was thy most familiar\nhome", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 779, "2000": 16}}, {"id": 4660, "position": 4660, "text": ", there was thy most familiar\nhome. Thou hast been where bell or diver never went; hast slept by many\na sailor’s side, where sleepless mothers would give their lives to lay\nthem down", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 16}}, {"id": 4661, "position": 4661, "text": "give their lives to lay\nthem down. Thou saw’st the locked lovers when leaping from their\nflaming ship; heart to heart they sank beneath the exulting wave; true\nto each other, when heaven seemed false to them", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 471}}, {"id": 4662, "position": 4662, "text": "to each other, when heaven seemed false to them. Thou saw’st the\nmurdered mate when tossed by pirates from the midnight deck; for hours\nhe fell into the deeper midnight of the insatiate maw; and his\nmurderers still sailed on unharmed", "labels": {"50": 9, "100": 26, "250": 133, "500": 72, "1000": 437, "2000": 1620}}, {"id": 4663, "position": 4663, "text": "of the insatiate maw; and his\nmurderers still sailed on unharmed—while swift lightnings shivered the\nneighboring ship that would have borne a righteous husband to\noutstretched, longing arms. O head! thou hast seen enough to split the\nplanets and", "labels": {"50": 9, "100": 26, "250": 141, "500": 365, "1000": 859, "2000": 1785}}, {"id": 4664, "position": 4664, "text": "arms. O head! thou hast seen enough to split the\nplanets and make an infidel of Abraham, and not one syllable is thine!”\n\n“Sail ho!” cried a triumphant voice from the main-mast-head.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4665, "position": 4665, "text": "!” cried a triumphant voice from the main-mast-head.\n\n“Aye? Well, now, that’s cheering,” cried Ahab, suddenly erecting\nhimself, while whole thunder-clouds swept aside from his brow", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4666, "position": 4666, "text": ", while whole thunder-clouds swept aside from his brow. “That\nlively cry upon this deadly calm might almost convert a better\nman.—Where away?”\n\n“Three points on the starboard bow, sir, and bringing down her breeze\nto us!", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 4667, "position": 4667, "text": "on the starboard bow, sir, and bringing down her breeze\nto us!\n\n“Better and better, man. Would now St. Paul would come along that way,\nand to my breezelessness bring his breeze! O Nature, and O soul of man", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 4668, "position": 4668, "text": "my breezelessness bring his breeze! O Nature, and O soul of man!\nhow far beyond all utterance are your linked analogies! not the\nsmallest atom stirs or lives on matter, but has its cunning duplicate\nin mind.”\n\n\nCHAPTER 71", "labels": {"50": 3, "100": 71, "250": 33, "500": 395, "1000": 211, "2000": 817}}, {"id": 4669, "position": 4669, "text": "lives on matter, but has its cunning duplicate\nin mind.”\n\n\nCHAPTER 71. The Jeroboam’s Story.\n\nHand in hand, ship and breeze blew on; but the breeze came faster than\nthe ship, and soon the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4670, "position": 4670, "text": "but the breeze came faster than\nthe ship, and soon the Pequod began to rock.\n\nBy and by, through the glass the stranger’s boats and manned mast-heads\nproved her a whale-ship", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4671, "position": 4671, "text": "heads\nproved her a whale-ship. But as she was so far to windward, and\nshooting by, apparently making a passage to some other ground, the\nPequod could not hope to reach her", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 4672, "position": 4672, "text": "could not hope to reach her. So the signal was set to see what\nresponse would be made.\n\nHere be it said, that like the vessels of military marines, the ships\nof the American Whale Fleet have each a private signal; all which\nsignals being", "labels": {"50": 45, "100": 64, "250": 138, "500": 327, "1000": 327, "2000": 576}}, {"id": 4673, "position": 4673, "text": "of the American Whale Fleet have each a private signal; all which\nsignals being collected in a book with the names of the respective\nvessels attached, every captain is provided with it. Thereby, the whale\ncommanders are enabled to recognise each other upon the ocean,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4674, "position": 4674, "text": "Thereby, the whale\ncommanders are enabled to recognise each other upon the ocean, even at\nconsiderable distances and with no small facility.\n\nThe Pequod’s signal was at last responded to by the stranger’s setting\nher own; which proved the ship", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4675, "position": 4675, "text": "responded to by the stranger’s setting\nher own; which proved the ship to be the Jeroboam of Nantucket.\nSquaring her yards, she bore down, ranged abeam under the Pequod’s lee,\nand lowered", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4676, "position": 4676, "text": ", ranged abeam under the Pequod’s lee,\nand lowered a boat; it soon drew nigh; but, as the side-ladder was\nbeing rigged by Starbuck’s order to accommodate the visiting captain,\nthe stranger in question", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4677, "position": 4677, "text": "Starbuck’s order to accommodate the visiting captain,\nthe stranger in question waved his hand from his boat’s stern in token\nof that proceeding being entirely unnecessary. It turned out that the\nJeroboam had a malignant epidemic on board,", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 851, "2000": 1620}}, {"id": 4678, "position": 4678, "text": "out that the\nJeroboam had a malignant epidemic on board, and that Mayhew, her\ncaptain, was fearful of infecting the Pequod’s company. For, though\nhimself and boat’s crew remained untain", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4679, "position": 4679, "text": "s company. For, though\nhimself and boat’s crew remained untainted, and though his ship was\nhalf a rifle-shot off, and an incorruptible sea and air rolling and\nflowing between; yet conscientiously ad", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4680, "position": 4680, "text": "ble sea and air rolling and\nflowing between; yet conscientiously adhering to the timid quarantine\nof the land, he peremptorily refused to come into direct contact with\nthe Pequod.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4681, "position": 4681, "text": "into direct contact with\nthe Pequod.\n\nBut this did by no means prevent all communications. Preserving an\ninterval of some few yards between itself and the ship, the Jeroboam’s\nboat by the occasional use of its oars contri", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4682, "position": 4682, "text": "boam’s\nboat by the occasional use of its oars contrived to keep parallel to\nthe Pequod, as she heavily forged through the sea (for by this time it\nblew very fresh), with her main-topsail aback", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4683, "position": 4683, "text": "this time it\nblew very fresh), with her main-topsail aback; though, indeed, at times\nby the sudden onset of a large rolling wave, the boat would be pushed\nsome way ahead; but would be soon skilfully brought", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1028}}, {"id": 4684, "position": 4684, "text": "be pushed\nsome way ahead; but would be soon skilfully brought to her proper\nbearings again. Subject to this, and other the like interruptions now\nand then, a conversation was sustained between the two parties; but at\nintervals not without still", "labels": {"50": 2, "100": 69, "250": 173, "500": 429, "1000": 293, "2000": 474}}, {"id": 4685, "position": 4685, "text": "a conversation was sustained between the two parties; but at\nintervals not without still another interruption of a very different\nsort.\n\nPulling an oar in the Jeroboam’s boat, was a man of a singular\nappearance, even in that wild whaling", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4686, "position": 4686, "text": "boat, was a man of a singular\nappearance, even in that wild whaling life where individual\nnotabilities make up all totalities. He was a small, short, youngish\nman, sprinkled all over his face with freckles", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1495}}, {"id": 4687, "position": 4687, "text": "youngish\nman, sprinkled all over his face with freckles, and wearing redundant\nyellow hair. A long-skirted, cabalistically-cut coat of a faded walnut\ntinge enveloped him; the overlapping sleeves of which were rolled", "labels": {"50": 45, "100": 64, "250": 70, "500": 432, "1000": 300, "2000": 1014}}, {"id": 4688, "position": 4688, "text": "a faded walnut\ntinge enveloped him; the overlapping sleeves of which were rolled up on\nhis wrists. A deep, settled, fanatic delirium was in his eyes.\n\nSo soon as this figure had been first descried, Stubb had", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4689, "position": 4689, "text": "So soon as this figure had been first descried, Stubb had\nexclaimed—“That’s he! that’s he!—the long-togged scaramouch the\nTown-Ho’s company told us of!” Stu", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 858, "2000": 110}}, {"id": 4690, "position": 4690, "text": "amouch the\nTown-Ho’s company told us of!” Stubb here alluded to a strange story\ntold of the Jeroboam, and a certain man among her crew, some time\nprevious when the Pequod spoke the Town", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 4691, "position": 4691, "text": "among her crew, some time\nprevious when the Pequod spoke the Town-Ho. According to this account\nand what was subsequently learned, it seemed that the scaramouch in\nquestion had gained a wonderful ascendency over almost everybody in the\nJe", "labels": {"50": 45, "100": 38, "250": 65, "500": 421, "1000": 257, "2000": 47}}, {"id": 4692, "position": 4692, "text": "in\nquestion had gained a wonderful ascendency over almost everybody in the\nJeroboam. His story was this:\n\nHe had been originally nurtured among the crazy society of Neskyeuna\nShakers, where he had been a great prophet", "labels": {"50": 27, "100": 33, "250": 194, "500": 44, "1000": 503, "2000": 84}}, {"id": 4693, "position": 4693, "text": "of Neskyeuna\nShakers, where he had been a great prophet; in their cracked, secret\nmeetings having several times descended from heaven by the way of a\ntrap-door, announcing the speedy opening of the seventh vial, which he\ncarried in", "labels": {"50": 5, "100": 30, "250": 112, "500": 420, "1000": 977, "2000": 1625}}, {"id": 4694, "position": 4694, "text": "door, announcing the speedy opening of the seventh vial, which he\ncarried in his vest-pocket; but, which, instead of containing\ngunpowder, was supposed to be charged with laudanum. A strange,\napostolic whim having seized him, he", "labels": {"50": 23, "100": 17, "250": 160, "500": 358, "1000": 485, "2000": 1002}}, {"id": 4695, "position": 4695, "text": "laudanum. A strange,\napostolic whim having seized him, he had left Neskyeuna for Nantucket,\nwhere, with that cunning peculiar to craziness, he assumed a steady,\ncommon-sense exterior, and offered himself as", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 300, "2000": 472}}, {"id": 4696, "position": 4696, "text": ", he assumed a steady,\ncommon-sense exterior, and offered himself as a green-hand candidate\nfor the Jeroboam’s whaling voyage. They engaged him; but straightway\nupon the ship’s getting out of sight of land,", "labels": {"50": 45, "100": 64, "250": 138, "500": 389, "1000": 531, "2000": 1620}}, {"id": 4697, "position": 4697, "text": "but straightway\nupon the ship’s getting out of sight of land, his insanity broke out in\na freshet. He announced himself as the archangel Gabriel, and commanded\nthe captain to jump overboard. He published his manifesto, whereby he\nset himself forth", "labels": {"50": 45, "100": 29, "250": 138, "500": 327, "1000": 327, "2000": 1584}}, {"id": 4698, "position": 4698, "text": "captain to jump overboard. He published his manifesto, whereby he\nset himself forth as the deliverer of the isles of the sea and\nvicar-general of all Oceanica. The unflinching earnestness with which\nhe declared these things;—the", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 4699, "position": 4699, "text": "unflinching earnestness with which\nhe declared these things;—the dark, daring play of his sleepless,\nexcited imagination, and all the preternatural terrors of real\ndelirium, united to invest this Gabriel in the minds", "labels": {"50": 22, "100": 78, "250": 177, "500": 250, "1000": 890, "2000": 1163}}, {"id": 4700, "position": 4700, "text": "s of real\ndelirium, united to invest this Gabriel in the minds of the majority of\nthe ignorant crew, with an atmosphere of sacredness. Moreover, they\nwere afraid of him. As such a man, however, was not of much practical", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 282}}, {"id": 4701, "position": 4701, "text": "of him. As such a man, however, was not of much practical\nuse in the ship, especially as he refused to work except when he\npleased, the incredulous captain would fain have been rid of him; but\napprised that", "labels": {"50": 45, "100": 29, "250": 82, "500": 239, "1000": 139, "2000": 801}}, {"id": 4702, "position": 4702, "text": "captain would fain have been rid of him; but\napprised that that individual’s intention was to land him in the first\nconvenient port, the archangel forthwith opened all his seals and\nvials—devoting the ship and all hands to", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 4703, "position": 4703, "text": "all his seals and\nvials—devoting the ship and all hands to unconditional perdition, in\ncase this intention was carried out. So strongly did he work upon his\ndisciples among the crew, that at last in a body they went to", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 1904}}, {"id": 4704, "position": 4704, "text": "his\ndisciples among the crew, that at last in a body they went to the\ncaptain and told him if Gabriel was sent from the ship, not a man of\nthem would remain. He was therefore forced to relinquish his plan", "labels": {"50": 40, "100": 29, "250": 161, "500": 242, "1000": 250, "2000": 1766}}, {"id": 4705, "position": 4705, "text": ". He was therefore forced to relinquish his plan. Nor\nwould they permit Gabriel to be any way maltreated, say or do what he\nwould; so that it came to pass that Gabriel had the complete freedom of\nthe ship", "labels": {"50": 1, "100": 80, "250": 39, "500": 241, "1000": 353, "2000": 1163}}, {"id": 4706, "position": 4706, "text": "it came to pass that Gabriel had the complete freedom of\nthe ship. The consequence of all this was, that the archangel cared\nlittle or nothing for the captain and mates; and since the epidemic had\nbroken out, he carried a higher hand than ever;", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 1014}}, {"id": 4707, "position": 4707, "text": "since the epidemic had\nbroken out, he carried a higher hand than ever; declaring that the\nplague, as he called it, was at his sole command; nor should it be\nstayed but according to his good pleasure", "labels": {"50": 14, "100": 29, "250": 11, "500": 447, "1000": 143, "2000": 855}}, {"id": 4708, "position": 4708, "text": "stayed but according to his good pleasure. The sailors, mostly poor\ndevils, cringed, and some of them fawned before him; in obedience to\nhis instructions, sometimes rendering him personal homage, as to a god", "labels": {"50": 5, "100": 66, "250": 177, "500": 144, "1000": 440, "2000": 1893}}, {"id": 4709, "position": 4709, "text": "him personal homage, as to a god.\nSuch things may seem incredible; but, however wondrous, they are true.\nNor is the history of fanatics half so striking in respect to the\nmeasureless self-deception of the fanatic himself", "labels": {"50": 31, "100": 0, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 4710, "position": 4710, "text": "striking in respect to the\nmeasureless self-deception of the fanatic himself, as his measureless\npower of deceiving and bedevilling so many others. But it is time to\nreturn to the Pequod.", "labels": {"50": 1, "100": 53, "250": 44, "500": 19, "1000": 499, "2000": 629}}, {"id": 4711, "position": 4711, "text": "it is time to\nreturn to the Pequod.\n\n“I fear not thy epidemic, man,” said Ahab from the bulwarks, to Captain\nMayhew, who stood in the boat’s stern; “come on board", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4712, "position": 4712, "text": "w, who stood in the boat’s stern; “come on board.”\n\nBut now Gabriel started to his feet.\n\n“Think, think of the fevers, yellow and bilious! Beware of the horrible\nplague!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 282}}, {"id": 4713, "position": 4713, "text": "and bilious! Beware of the horrible\nplague!”\n\n“Gabriel! Gabriel!” cried Captain Mayhew; “thou must either—” But that\ninstant a headlong wave shot the boat far ahead, and its seethings\ndrowned", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4714, "position": 4714, "text": "headlong wave shot the boat far ahead, and its seethings\ndrowned all speech.\n\n“Hast thou seen the White Whale?” demanded Ahab, when the boat drifted\nback.\n\n“Think, think of thy whale-boat, stoven", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4715, "position": 4715, "text": "drifted\nback.\n\n“Think, think of thy whale-boat, stoven and sunk! Beware of the\nhorrible tail!”\n\n“I tell thee again, Gabriel, that—” But again the boat tore ahead as if\ndragged by fiends", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4716, "position": 4716, "text": "—” But again the boat tore ahead as if\ndragged by fiends. Nothing was said for some moments, while a\nsuccession of riotous waves rolled by, which by one of those occasional\ncaprices of the seas were tumbling, not heaving", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 282}}, {"id": 4717, "position": 4717, "text": "one of those occasional\ncaprices of the seas were tumbling, not heaving it. Meantime, the\nhoisted sperm whale’s head jogged about very violently, and Gabriel was\nseen eyeing it with rather more apprehensiveness than his archangel\nnature seemed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4718, "position": 4718, "text": "eyeing it with rather more apprehensiveness than his archangel\nnature seemed to warrant.\n\nWhen this interlude was over, Captain Mayhew began a dark story\nconcerning Moby Dick; not, however, without frequent interruptions from\nGabriel, whenever his", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4719, "position": 4719, "text": "Dick; not, however, without frequent interruptions from\nGabriel, whenever his name was mentioned, and the crazy sea that seemed\nleagued with him.\n\nIt seemed that the Jeroboam had not long left home, when upon speaking\na whale-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4720, "position": 4720, "text": "roboam had not long left home, when upon speaking\na whale-ship, her people were reliably apprised of the existence of\nMoby Dick, and the havoc he had made. Greedily sucking in this\nintelligence, Gabriel solemnly", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 723, "2000": 1620}}, {"id": 4721, "position": 4721, "text": "the havoc he had made. Greedily sucking in this\nintelligence, Gabriel solemnly warned the captain against attacking the\nWhite Whale, in case the monster should be seen; in his gibbering\ninsanity, pronouncing the White Whale to be no less", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4722, "position": 4722, "text": "bbering\ninsanity, pronouncing the White Whale to be no less a being than the\nShaker God incarnated; the Shakers receiving the Bible. But when, some\nyear or two afterwards, Moby Dick was fairly sighted from the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4723, "position": 4723, "text": ", some\nyear or two afterwards, Moby Dick was fairly sighted from the\nmast-heads, Macey, the chief mate, burned with ardour to encounter him;\nand the captain himself being not unwilling to let him have the\nopportunity, despite", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4724, "position": 4724, "text": "and the captain himself being not unwilling to let him have the\nopportunity, despite all the archangel’s denunciations and\nforewarnings, Macey succeeded in persuading five men to man his boat", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 723, "2000": 1584}}, {"id": 4725, "position": 4725, "text": "ading five men to man his boat.\nWith them he pushed off; and, after much weary pulling, and many\nperilous, unsuccessful onsets, he at last succeeded in getting one iron\nfast. Meantime, Gabriel, ascending to the main-", "labels": {"50": 1, "100": 80, "250": 181, "500": 497, "1000": 228, "2000": 687}}, {"id": 4726, "position": 4726, "text": "in getting one iron\nfast. Meantime, Gabriel, ascending to the main-royal mast-head, was\ntossing one arm in frantic gestures, and hurling forth prophecies of\nspeedy doom to the sacrilegious assailants of his divinity", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 4727, "position": 4727, "text": "speedy doom to the sacrilegious assailants of his divinity. Now, while\nMacey, the mate, was standing up in his boat’s bow, and with all the\nreckless energy of his tribe was venting his wild excl", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4728, "position": 4728, "text": "with all the\nreckless energy of his tribe was venting his wild exclamations upon the\nwhale, and essaying to get a fair chance for his poised lance, lo! a\nbroad white shadow rose from the sea; by its quick, fan", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1620}}, {"id": 4729, "position": 4729, "text": "! a\nbroad white shadow rose from the sea; by its quick, fanning motion,\ntemporarily taking the breath out of the bodies of the oarsmen. Next\ninstant, the luckless mate, so full of furious life, was smitten", "labels": {"50": 26, "100": 10, "250": 226, "500": 332, "1000": 469, "2000": 804}}, {"id": 4730, "position": 4730, "text": "the luckless mate, so full of furious life, was smitten bodily\ninto the air, and making a long arc in his descent, fell into the sea\nat the distance of about fifty yards. Not a chip of the boat was\nharmed,", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 778}}, {"id": 4731, "position": 4731, "text": "distance of about fifty yards. Not a chip of the boat was\nharmed, nor a hair of any oarsman’s head; but the mate for ever sank.\n\nIt is well to parenthesize here, that of the fatal accidents in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 692, "2000": 1620}}, {"id": 4732, "position": 4732, "text": "is well to parenthesize here, that of the fatal accidents in the\nSperm-Whale Fishery, this kind is perhaps almost as frequent as any.\nSometimes, nothing is injured but the man who is thus annihilated;\noftener the boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4733, "position": 4733, "text": "but the man who is thus annihilated;\noftener the boat’s bow is knocked off, or the thigh-board, in which the\nheadsman stands, is torn from its place and accompanies the body", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4734, "position": 4734, "text": "is torn from its place and accompanies the body. But\nstrangest of all is the circumstance, that in more instances than one,\nwhen the body has been recovered, not a single mark of violence is\ndiscernible; the man being stark", "labels": {"50": 43, "100": 39, "250": 79, "500": 118, "1000": 120, "2000": 1589}}, {"id": 4735, "position": 4735, "text": "not a single mark of violence is\ndiscernible; the man being stark dead.\n\nThe whole calamity, with the falling form of Macey, was plainly\ndescried from the ship. Raising a piercing shriek—“The vial! the", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 4736, "position": 4736, "text": "ied from the ship. Raising a piercing shriek—“The vial! the vial!”\nGabriel called off the terror-stricken crew from the further hunting of\nthe whale. This terrible event clothed the archangel with added\ninfluence; because his credulous disciples", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4737, "position": 4737, "text": "terrible event clothed the archangel with added\ninfluence; because his credulous disciples believed that he had\nspecifically fore-announced it, instead of only making a general\nprophecy, which any one might have done, and so have chanced to hit one\nof many", "labels": {"50": 5, "100": 66, "250": 66, "500": 350, "1000": 989, "2000": 161}}, {"id": 4738, "position": 4738, "text": "one might have done, and so have chanced to hit one\nof many marks in the wide margin allowed. He became a nameless terror\nto the ship.\n\nMayhew having concluded his narration, Ahab put such questions to him,\nthat the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4739, "position": 4739, "text": "having concluded his narration, Ahab put such questions to him,\nthat the stranger captain could not forbear inquiring whether he\nintended to hunt the White Whale, if opportunity should offer. To which\nAhab answered—“Aye.” Straight", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4740, "position": 4740, "text": "opportunity should offer. To which\nAhab answered—“Aye.” Straightway, then, Gabriel once more started to\nhis feet, glaring upon the old man, and vehemently exclaimed, with\ndownward pointed finger—“Think, think of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4741, "position": 4741, "text": "hemently exclaimed, with\ndownward pointed finger—“Think, think of the blasphemer—dead, and down\nthere!—beware of the blasphemer’s end!”", "labels": {"50": 18, "100": 87, "250": 102, "500": 205, "1000": 62, "2000": 1699}}, {"id": 4742, "position": 4742, "text": "emer’s end!”\n\nAhab stolidly turned aside; then said to Mayhew, “Captain, I have just\nbethought me of my letter-bag; there is a letter for one of thy\nofficers, if I", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 4743, "position": 4743, "text": "-bag; there is a letter for one of thy\nofficers, if I mistake not. Starbuck, look over the bag.”\n\nEvery whale-ship takes out a goodly number of letters for various\nships, whose delivery to the persons to whom", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4744, "position": 4744, "text": "ly number of letters for various\nships, whose delivery to the persons to whom they may be addressed,\ndepends upon the mere chance of encountering them in the four oceans.\nThus, most letters never reach their mark; and many are only received\nafter attaining", "labels": {"50": 8, "100": 40, "250": 74, "500": 258, "1000": 311, "2000": 1913}}, {"id": 4745, "position": 4745, "text": ", most letters never reach their mark; and many are only received\nafter attaining an age of two or three years or more.\n\nSoon Starbuck returned with a letter in his hand. It was sorely\ntumbled, damp, and covered with a dull,", "labels": {"50": 2, "100": 14, "250": 58, "500": 426, "1000": 650, "2000": 1457}}, {"id": 4746, "position": 4746, "text": ". It was sorely\ntumbled, damp, and covered with a dull, spotted, green mould, in\nconsequence of being kept in a dark locker of the cabin. Of such a\nletter, Death himself might well have been the post-boy.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 110}}, {"id": 4747, "position": 4747, "text": "such a\nletter, Death himself might well have been the post-boy.\n\n“Can’st not read it?” cried Ahab. “Give it me, man. Aye, aye, it’s but\na dim scrawl;—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4748, "position": 4748, "text": "Aye, aye, it’s but\na dim scrawl;—what’s this?” As he was studying it out, Starbuck took a\nlong cutting-spade pole, and with his knife slightly split the end, to\ninsert the", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 4749, "position": 4749, "text": "spade pole, and with his knife slightly split the end, to\ninsert the letter there, and in that way, hand it to the boat, without\nits coming any closer to the ship.\n\nMeantime, Ahab holding the letter, muttered, “Mr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4750, "position": 4750, "text": "the ship.\n\nMeantime, Ahab holding the letter, muttered, “Mr. Har—yes, Mr. Harry—(a\nwoman’s pinny hand,—the man’s wife, I’ll wager)—Aye—", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 4751, "position": 4751, "text": "the man’s wife, I’ll wager)—Aye—Mr. Harry Macey,\nShip Jeroboam;—why it’s Macey, and he’s dead!”", "labels": {"50": 41, "100": 64, "250": 163, "500": 180, "1000": 54, "2000": 1790}}, {"id": 4752, "position": 4752, "text": "and he’s dead!”\n\n“Poor fellow! poor fellow! and from his wife,” sighed Mayhew; “but let\nme have it.”\n\n“Nay, keep it thyself,” cried Gabriel to Ahab; “", "labels": {"50": 9, "100": 64, "250": 138, "500": 180, "1000": 851, "2000": 1620}}, {"id": 4753, "position": 4753, "text": ", keep it thyself,” cried Gabriel to Ahab; “thou art soon going\nthat way.”\n\n“Curses throttle thee!” yelled Ahab. “Captain Mayhew, stand by now to\nreceive it”; and taking the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4754, "position": 4754, "text": "Mayhew, stand by now to\nreceive it”; and taking the fatal missive from Starbuck’s hands, he\ncaught it in the slit of the pole, and reached it over towards the\nboat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4755, "position": 4755, "text": "and reached it over towards the\nboat. But as he did so, the oarsmen expectantly desisted from rowing;\nthe boat drifted a little towards the ship’s stern; so that, as if by\nmagic, the letter suddenly ranged", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 4756, "position": 4756, "text": "s stern; so that, as if by\nmagic, the letter suddenly ranged along with Gabriel’s eager hand. He\nclutched it in an instant, seized the boat-knife, and impaling the\nletter on it, sent it thus loaded back into", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4757, "position": 4757, "text": ", and impaling the\nletter on it, sent it thus loaded back into the ship. It fell at Ahab’s\nfeet. Then Gabriel shrieked out to his comrades to give way with their\noars, and in that manner the mutinous", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 4758, "position": 4758, "text": "give way with their\noars, and in that manner the mutinous boat rapidly shot away from the\nPequod.\n\nAs, after this interlude, the seamen resumed their work upon the jacket\nof the whale, many strange things were hinted in reference", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4759, "position": 4759, "text": "work upon the jacket\nof the whale, many strange things were hinted in reference to this wild\naffair.\n\n\nCHAPTER 72. The Monkey-Rope.\n\nIn the tumultuous business of cutting-in and attending to a whale,\nthere is much running backwards", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4760, "position": 4760, "text": "of cutting-in and attending to a whale,\nthere is much running backwards and forwards among the crew. Now hands\nare wanted here, and then again hands are wanted there. There is no\nstaying in any one place; for at one and the same", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4761, "position": 4761, "text": "There is no\nstaying in any one place; for at one and the same time everything has\nto be done everywhere. It is much the same with him who endeavors the\ndescription of the scene. We must now retrace our way a little", "labels": {"50": 48, "100": 20, "250": 49, "500": 334, "1000": 933, "2000": 1974}}, {"id": 4762, "position": 4762, "text": "the scene. We must now retrace our way a little. It was\nmentioned that upon first breaking ground in the whale’s back, the\nblubber-hook was inserted into the original hole there cut by the\nspades of the mates", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4763, "position": 4763, "text": "inserted into the original hole there cut by the\nspades of the mates. But how did so clumsy and weighty a mass as that\nsame hook get fixed in that hole? It was inserted there by my\nparticular friend Queequeg, whose duty", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4764, "position": 4764, "text": "It was inserted there by my\nparticular friend Queequeg, whose duty it was, as harpooneer, to\ndescend upon the monster’s back for the special purpose referred to.\nBut in very many cases, circumstances require that the harpoon", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4765, "position": 4765, "text": "referred to.\nBut in very many cases, circumstances require that the harpooneer shall\nremain on the whale till the whole flensing or stripping operation is\nconcluded. The whale, be it observed, lies almost entirely submerged,\nexcepting the immediate parts", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4766, "position": 4766, "text": ", be it observed, lies almost entirely submerged,\nexcepting the immediate parts operated upon. So down there, some ten\nfeet below the level of the deck, the poor harpooneer flounders about,\nhalf on the whale and half in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4767, "position": 4767, "text": "ooneer flounders about,\nhalf on the whale and half in the water, as the vast mass revolves like\na tread-mill beneath him. On the occasion in question, Queequeg figured\nin the Highland costume—a shirt and socks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4768, "position": 4768, "text": ", Queequeg figured\nin the Highland costume—a shirt and socks—in which to my eyes, at\nleast, he appeared to uncommon advantage; and no one had a better\nchance to observe him, as will presently be seen.", "labels": {"50": 18, "100": 31, "250": 228, "500": 410, "1000": 603, "2000": 1835}}, {"id": 4769, "position": 4769, "text": "a better\nchance to observe him, as will presently be seen.\n\nBeing the savage’s bowsman, that is, the person who pulled the bow-oar\nin his boat (the second one from forward), it was my cheerful duty to", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 4770, "position": 4770, "text": "boat (the second one from forward), it was my cheerful duty to\nattend upon him while taking that hard-scrabble scramble upon the dead\nwhale’s back. You have seen Italian organ-boys holding a dancing-ape by\na long", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4771, "position": 4771, "text": "You have seen Italian organ-boys holding a dancing-ape by\na long cord. Just so, from the ship’s steep side, did I hold Queequeg\ndown there in the sea, by what is technically called in the fishery a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4772, "position": 4772, "text": "down there in the sea, by what is technically called in the fishery a\nmonkey-rope, attached to a strong strip of canvas belted round his\nwaist.\n\nIt was a humorously perilous business for both of us", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 786}}, {"id": 4773, "position": 4773, "text": "humorously perilous business for both of us. For, before we\nproceed further, it must be said that the monkey-rope was fast at both\nends; fast to Queequeg’s broad canvas belt, and fast to my narrow", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 4774, "position": 4774, "text": "Queequeg’s broad canvas belt, and fast to my narrow\nleather one. So that for better or for worse, we two, for the time,\nwere wedded; and should poor Queequeg sink to rise no more,", "labels": {"50": 9, "100": 26, "250": 120, "500": 180, "1000": 272, "2000": 1765}}, {"id": 4775, "position": 4775, "text": "ded; and should poor Queequeg sink to rise no more, then both\nusage and honor demanded, that instead of cutting the cord, it should\ndrag me down in his wake. So, then, an elongated Siamese ligature\nunited us", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 637, "2000": 1886}}, {"id": 4776, "position": 4776, "text": "his wake. So, then, an elongated Siamese ligature\nunited us. Queequeg was my own inseparable twin brother; nor could I\nany way get rid of the dangerous liabilities which the hempen bond\nentailed.", "labels": {"50": 44, "100": 40, "250": 193, "500": 498, "1000": 849, "2000": 1620}}, {"id": 4777, "position": 4777, "text": "rid of the dangerous liabilities which the hempen bond\nentailed.\n\nSo strongly and metaphysically did I conceive of my situation then,\nthat while earnestly watching his motions, I seemed distinctly to\nperceive that my own individuality was now", "labels": {"50": 20, "100": 5, "250": 101, "500": 412, "1000": 711, "2000": 1278}}, {"id": 4778, "position": 4778, "text": "his motions, I seemed distinctly to\nperceive that my own individuality was now merged in a joint stock\ncompany of two; that my free will had received a mortal wound; and that\nanother’s mistake or misfortune might plunge innocent me into un", "labels": {"50": 20, "100": 5, "250": 125, "500": 349, "1000": 651, "2000": 896}}, {"id": 4779, "position": 4779, "text": "that\nanother’s mistake or misfortune might plunge innocent me into unmerited\ndisaster and death. Therefore, I saw that here was a sort of\ninterregnum in Providence; for its even-handed equity never could have\nso gross an", "labels": {"50": 20, "100": 5, "250": 125, "500": 349, "1000": 842, "2000": 1706}}, {"id": 4780, "position": 4780, "text": "in Providence; for its even-handed equity never could have\nso gross an injustice. And yet still further pondering—while I jerked\nhim now and then from between the whale and ship, which would threaten\nto jam him—still further pondering,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4781, "position": 4781, "text": "and ship, which would threaten\nto jam him—still further pondering, I say, I saw that this situation of\nmine was the precise situation of every mortal that breathes; only, in\nmost cases, he, one way or other, has", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 4782, "position": 4782, "text": "; only, in\nmost cases, he, one way or other, has this Siamese connexion with a\nplurality of other mortals. If your banker breaks, you snap; if your\napothecary by mistake sends you poison in your", "labels": {"50": 31, "100": 7, "250": 193, "500": 307, "1000": 849, "2000": 761}}, {"id": 4783, "position": 4783, "text": "snap; if your\napothecary by mistake sends you poison in your pills, you die. True,\nyou may say that, by exceeding caution, you may possibly escape these\nand the multitudinous other evil chances of life", "labels": {"50": 31, "100": 39, "250": 155, "500": 80, "1000": 117, "2000": 90}}, {"id": 4784, "position": 4784, "text": "these\nand the multitudinous other evil chances of life. But handle Queequeg’s\nmonkey-rope heedfully as I would, sometimes he jerked it so, that I\ncame very near sliding overboard", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4785, "position": 4785, "text": "it so, that I\ncame very near sliding overboard. Nor could I possibly forget that, do\nwhat I would, I only had the management of one end of it.*\n\n*The monkey-rope is found in all whalers; but it was", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 4786, "position": 4786, "text": "*The monkey-rope is found in all whalers; but it was only in the Pequod\nthat the monkey and his holder were ever tied together. This\nimprovement upon the original usage was introduced by no less a man\nthan Stubb, in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4787, "position": 4787, "text": "the original usage was introduced by no less a man\nthan Stubb, in order to afford the imperilled harpooneer the strongest\npossible guarantee for the faithfulness and vigilance of his\nmonkey-rope holder.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 4788, "position": 4788, "text": "gilance of his\nmonkey-rope holder.\n\nI have hinted that I would often jerk poor Queequeg from between the\nwhale and the ship—where he would occasionally fall, from the incessant\nrolling and swaying of both", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4789, "position": 4789, "text": ", from the incessant\nrolling and swaying of both. But this was not the only jamming jeopardy\nhe was exposed to. Unappalled by the massacre made upon them during the\nnight, the sharks now freshly and more keenly allured by", "labels": {"50": 37, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 783}}, {"id": 4790, "position": 4790, "text": "during the\nnight, the sharks now freshly and more keenly allured by the before\npent blood which began to flow from the carcass—the rabid creatures\nswarmed round it like bees in a beehive.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 4791, "position": 4791, "text": "ed round it like bees in a beehive.\n\nAnd right in among those sharks was Queequeg; who often pushed them\naside with his floundering feet. A thing altogether incredible were it\nnot that attracted by such prey as a dead", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4792, "position": 4792, "text": "A thing altogether incredible were it\nnot that attracted by such prey as a dead whale, the otherwise\nmiscellaneously carnivorous shark will seldom touch a man.\n\nNevertheless, it may well be believed that since they have such a\nravenous finger in the pie,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4793, "position": 4793, "text": "be believed that since they have such a\nravenous finger in the pie, it is deemed but wise to look sharp to\nthem. Accordingly, besides the monkey-rope, with which I now and then\njerked the poor fellow from too close a vicinity to", "labels": {"50": 23, "100": 17, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 4794, "position": 4794, "text": "which I now and then\njerked the poor fellow from too close a vicinity to the maw of what\nseemed a peculiarly ferocious shark—he was provided with still another\nprotection. Suspended over the side in one of the stages, Tashtego and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4795, "position": 4795, "text": "Suspended over the side in one of the stages, Tashtego and\nDaggoo continually flourished over his head a couple of keen\nwhale-spades, wherewith they slaughtered as many sharks as they could\nreach", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4796, "position": 4796, "text": "slaughtered as many sharks as they could\nreach. This procedure of theirs, to be sure, was very disinterested and\nbenevolent of them. They meant Queequeg’s best happiness, I admit; but\nin their hasty zeal to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4797, "position": 4797, "text": "’s best happiness, I admit; but\nin their hasty zeal to befriend him, and from the circumstance that\nboth he and the sharks were at times half hidden by the blood-muddled\nwater, those indiscreet spade", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4798, "position": 4798, "text": "hidden by the blood-muddled\nwater, those indiscreet spades of theirs would come nearer amputating a\nleg than a tail. But poor Queequeg, I suppose, straining and gasping\nthere with that great iron hook—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4799, "position": 4799, "text": "g, I suppose, straining and gasping\nthere with that great iron hook—poor Queequeg, I suppose, only prayed\nto his Yojo, and gave up his life into the hands of his gods.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4800, "position": 4800, "text": "life into the hands of his gods.\n\nWell, well, my dear comrade and twin-brother, thought I, as I drew in\nand then slacked off the rope to every swell of the sea—what matters\nit, after all? Are you", "labels": {"50": 36, "100": 10, "250": 226, "500": 56, "1000": 349, "2000": 400}}, {"id": 4801, "position": 4801, "text": "every swell of the sea—what matters\nit, after all? Are you not the precious image of each and all of us men\nin this whaling world? That unsounded ocean you gasp in, is Life; those\nsharks, your foes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4802, "position": 4802, "text": "ed ocean you gasp in, is Life; those\nsharks, your foes; those spades, your friends; and what between sharks\nand spades you are in a sad pickle and peril, poor lad.", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 174, "2000": 1203}}, {"id": 4803, "position": 4803, "text": "pickle and peril, poor lad.\n\nBut courage! there is good cheer in store for you, Queequeg. For now,\nas with blue lips and blood-shot eyes the exhausted savage at last\nclimbs up the chains and stands all", "labels": {"50": 25, "100": 5, "250": 136, "500": 180, "1000": 272, "2000": 1765}}, {"id": 4804, "position": 4804, "text": "-shot eyes the exhausted savage at last\nclimbs up the chains and stands all dripping and involuntarily\ntrembling over the side; the steward advances, and with a benevolent,\nconsolatory glance hands him—what? Some hot Cognac", "labels": {"50": 22, "100": 55, "250": 49, "500": 78, "1000": 933, "2000": 292}}, {"id": 4805, "position": 4805, "text": ",\nconsolatory glance hands him—what? Some hot Cognac? No! hands him, ye\ngods! hands him a cup of tepid ginger and water!\n\n“Ginger? Do I smell ginger?” suspiciously asked Stubb, coming", "labels": {"50": 37, "100": 99, "250": 47, "500": 444, "1000": 593, "2000": 1593}}, {"id": 4806, "position": 4806, "text": "“Ginger? Do I smell ginger?” suspiciously asked Stubb, coming near.\n“Yes, this must be ginger,” peering into the as yet untasted cup. Then\nstanding as if incredulous for a while, he calmly walked", "labels": {"50": 37, "100": 6, "250": 145, "500": 444, "1000": 488, "2000": 314}}, {"id": 4807, "position": 4807, "text": ". Then\nstanding as if incredulous for a while, he calmly walked towards the\nastonished steward slowly saying, “Ginger? ginger? and will you have\nthe goodness to tell me, Mr. Dough-Boy, where lies the virtue of\nginger?", "labels": {"50": 39, "100": 88, "250": 219, "500": 100, "1000": 488, "2000": 1593}}, {"id": 4808, "position": 4808, "text": "me, Mr. Dough-Boy, where lies the virtue of\nginger? Ginger! is ginger the sort of fuel you use, Dough-boy, to\nkindle a fire in this shivering cannibal? Ginger!—what the devil is\nginger", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 4809, "position": 4809, "text": "in this shivering cannibal? Ginger!—what the devil is\nginger? Sea-coal? firewood?—lucifer matches?—tinder?—gunpowder?—what\nthe devil is ginger, I say, that you offer this cup to", "labels": {"50": 45, "100": 64, "250": 193, "500": 498, "1000": 851, "2000": 1620}}, {"id": 4810, "position": 4810, "text": "what\nthe devil is ginger, I say, that you offer this cup to our poor\nQueequeg here.”\n\n“There is some sneaking Temperance Society movement about this\nbusiness,” he suddenly added, now approaching Starbuck, who had just\ncome", "labels": {"50": 37, "100": 6, "250": 174, "500": 444, "1000": 367, "2000": 220}}, {"id": 4811, "position": 4811, "text": ",” he suddenly added, now approaching Starbuck, who had just\ncome from forward. “Will you look at that kannakin, sir: smell of it,\nif you please.” Then watching the mate’s countenance, he", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 4812, "position": 4812, "text": "you please.” Then watching the mate’s countenance, he added, “The\nsteward, Mr. Starbuck, had the face to offer that calomel and jalap to\nQueequeg, there, this instant off", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 4813, "position": 4813, "text": "and jalap to\nQueequeg, there, this instant off the whale. Is the steward an\napothecary, sir? and may I ask whether this is the sort of bitters by\nwhich he blows back the life into a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4814, "position": 4814, "text": "is the sort of bitters by\nwhich he blows back the life into a half-drowned man?”\n\n“I trust not,” said Starbuck, “it is poor stuff enough.”\n\n“Aye, aye, steward,” cried Stubb", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4815, "position": 4815, "text": "stuff enough.”\n\n“Aye, aye, steward,” cried Stubb, “we’ll teach you to drug a\nharpooneer; none of your apothecary’s medicine here; you want to poison\nus, do ye?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4816, "position": 4816, "text": "ry’s medicine here; you want to poison\nus, do ye? You have got out insurances on our lives and want to murder\nus all, and pocket the proceeds, do ye?”\n\n“It was not me,” cried Dough-", "labels": {"50": 41, "100": 21, "250": 91, "500": 157, "1000": 230, "2000": 1939}}, {"id": 4817, "position": 4817, "text": ", do ye?”\n\n“It was not me,” cried Dough-Boy, “it was Aunt Charity that brought the\nginger on board; and bade me never give the harpooneers any spirits,\nbut only this ginger-jub—", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 4818, "position": 4818, "text": "the harpooneers any spirits,\nbut only this ginger-jub—so she called it.”\n\n“Ginger-jub! you gingerly rascal! take that! and run along with ye to\nthe lockers, and get something better", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4819, "position": 4819, "text": "and run along with ye to\nthe lockers, and get something better. I hope I do no wrong, Mr.\nStarbuck. It is the captain’s orders—grog for the harpooneer on a\nwhale.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4820, "position": 4820, "text": "grog for the harpooneer on a\nwhale.”\n\n“Enough,” replied Starbuck, “only don’t hit him again, but—”\n\n“Oh, I never hurt when I hit, except when I hit a whale or something", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4821, "position": 4821, "text": "I never hurt when I hit, except when I hit a whale or something of\nthat sort; and this fellow’s a weazel. What were you about saying,\nsir?”\n\n“Only this: go down with him, and get what", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4822, "position": 4822, "text": "sir?”\n\n“Only this: go down with him, and get what thou wantest thyself.”\n\nWhen Stubb reappeared, he came with a dark flask in one hand, and a\nsort of tea-caddy in the other", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4823, "position": 4823, "text": "in one hand, and a\nsort of tea-caddy in the other. The first contained strong spirits, and\nwas handed to Queequeg; the second was Aunt Charity’s gift, and that\nwas freely given to the waves.", "labels": {"50": 2, "100": 69, "250": 75, "500": 8, "1000": 59, "2000": 259}}, {"id": 4824, "position": 4824, "text": "Charity’s gift, and that\nwas freely given to the waves.\n\n\nCHAPTER 73. Stubb and Flask kill a Right Whale; and Then Have a Talk\nover Him.\n\nIt must be borne in mind that all this time we have a Sperm Whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4825, "position": 4825, "text": "It must be borne in mind that all this time we have a Sperm Whale’s\nprodigious head hanging to the Pequod’s side. But we must let it\ncontinue hanging there a while till we can get a chance to attend", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4826, "position": 4826, "text": "let it\ncontinue hanging there a while till we can get a chance to attend to\nit. For the present other matters press, and the best we can do now for\nthe head, is to pray heaven the tackles may hold.", "labels": {"50": 8, "100": 14, "250": 58, "500": 158, "1000": 42, "2000": 1031}}, {"id": 4827, "position": 4827, "text": ", is to pray heaven the tackles may hold.\n\nNow, during the past night and forenoon, the Pequod had gradually\ndrifted into a sea, which, by its occasional patches of yellow brit,\ngave unusual tokens of the vicinity of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4828, "position": 4828, "text": "its occasional patches of yellow brit,\ngave unusual tokens of the vicinity of Right Whales, a species of the\nLeviathan that but few supposed to be at this particular time lurking\nanywhere near. And though all hands commonly disdained the capture of\nthose inferior", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4829, "position": 4829, "text": "anywhere near. And though all hands commonly disdained the capture of\nthose inferior creatures; and though the Pequod was not commissioned to\ncruise for them at all, and though she had passed numbers of them near\nthe Crozetts without lowering a", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4830, "position": 4830, "text": "she had passed numbers of them near\nthe Crozetts without lowering a boat; yet now that a Sperm Whale had\nbeen brought alongside and beheaded, to the surprise of all, the\nannouncement was made that a Right Whale should be captured that day,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4831, "position": 4831, "text": ", the\nannouncement was made that a Right Whale should be captured that day,\nif opportunity offered.\n\nNor was this long wanting. Tall spouts were seen to leeward; and two\nboats, Stubb’s and Flask’s, were detached", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4832, "position": 4832, "text": "two\nboats, Stubb’s and Flask’s, were detached in pursuit. Pulling further\nand further away, they at last became almost invisible to the men at\nthe mast-head. But suddenly in the distance, they saw a great heap", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 4833, "position": 4833, "text": "mast-head. But suddenly in the distance, they saw a great heap of\ntumultuous white water, and soon after news came from aloft that one or\nboth the boats must be fast. An interval passed and the boats were in\nplain", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 282}}, {"id": 4834, "position": 4834, "text": "the boats must be fast. An interval passed and the boats were in\nplain sight, in the act of being dragged right towards the ship by the\ntowing whale. So close did the monster come to the hull, that at first\nit seemed as if he", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 4835, "position": 4835, "text": "the monster come to the hull, that at first\nit seemed as if he meant it malice; but suddenly going down in a\nmaelstrom, within three rods of the planks, he wholly disappeared from\nview, as if diving under the keel", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 4836, "position": 4836, "text": "s, he wholly disappeared from\nview, as if diving under the keel. “Cut, cut!” was the cry from the\nship to the boats, which, for one instant, seemed on the point of being\nbrought with a deadly dash against the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4837, "position": 4837, "text": "instant, seemed on the point of being\nbrought with a deadly dash against the vessel’s side. But having plenty\nof line yet in the tubs, and the whale not sounding very rapidly, they\npaid out abundance of rope, and at the same", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4838, "position": 4838, "text": "sounding very rapidly, they\npaid out abundance of rope, and at the same time pulled with all their\nmight so as to get ahead of the ship. For a few minutes the struggle\nwas intensely critical; for while they still slacked out the tightened\nline", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 4839, "position": 4839, "text": "struggle\nwas intensely critical; for while they still slacked out the tightened\nline in one direction, and still plied their oars in another, the\ncontending strain threatened to take them under. But it was only a few\nfeet advance they sought to", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 4840, "position": 4840, "text": "take them under. But it was only a few\nfeet advance they sought to gain. And they stuck to it till they did\ngain it; when instantly, a swift tremor was felt running like lightning\nalong the keel, as the strained line, scraping beneath", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 4841, "position": 4841, "text": "felt running like lightning\nalong the keel, as the strained line, scraping beneath the ship,\nsuddenly rose to view under her bows, snapping and quivering; and so\nflinging off its drippings, that the drops fell like bits of broken\nglass on the", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 4842, "position": 4842, "text": "its drippings, that the drops fell like bits of broken\nglass on the water, while the whale beyond also rose to sight, and once\nmore the boats were free to fly. But the fagged whale abated his speed,\nand blindly altering his", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 4843, "position": 4843, "text": ". But the fagged whale abated his speed,\nand blindly altering his course, went round the stern of the ship\ntowing the two boats after him, so that they performed a complete\ncircuit.\n\nMeantime, they hauled more and more upon their lines,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4844, "position": 4844, "text": "a complete\ncircuit.\n\nMeantime, they hauled more and more upon their lines, till close\nflanking him on both sides, Stubb answered Flask with lance for lance;\nand thus round and round the Pequod the battle went, while the\nmultitudes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4845, "position": 4845, "text": "round and round the Pequod the battle went, while the\nmultitudes of sharks that had before swum round the Sperm Whale’s body,\nrushed to the fresh blood that was spilled, thirstily drinking at every\nnew gash, as the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4846, "position": 4846, "text": "that was spilled, thirstily drinking at every\nnew gash, as the eager Israelites did at the new bursting fountains\nthat poured from the smitten rock.\n\nAt last his spout grew thick, and with a frightful roll and vomit,", "labels": {"50": 27, "100": 33, "250": 194, "500": 207, "1000": 756, "2000": 632}}, {"id": 4847, "position": 4847, "text": "his spout grew thick, and with a frightful roll and vomit, he\nturned upon his back a corpse.\n\nWhile the two headsmen were engaged in making fast cords to his flukes,\nand in other ways getting the mass in readiness for towing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4848, "position": 4848, "text": "his flukes,\nand in other ways getting the mass in readiness for towing, some\nconversation ensued between them.\n\n“I wonder what the old man wants with this lump of foul lard,” said\nStubb, not without some disgust at the thought", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4849, "position": 4849, "text": "lard,” said\nStubb, not without some disgust at the thought of having to do with so\nignoble a leviathan.\n\n“Wants with it?” said Flask, coiling some spare line in the boat’s bow,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4850, "position": 4850, "text": "Flask, coiling some spare line in the boat’s bow,\n“did you never hear that the ship which but once has a Sperm Whale’s\nhead hoisted on her starboard side, and at the same time a Right\nWhale’s on", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4851, "position": 4851, "text": "her starboard side, and at the same time a Right\nWhale’s on the larboard; did you never hear, Stubb, that that ship can\nnever afterwards capsize?”\n\n“Why not?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4852, "position": 4852, "text": "capsize?”\n\n“Why not?\n\n“I don’t know, but I heard that gamboge ghost of a Fedallah saying so,\nand he seems to know all about ships’ charms", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 4853, "position": 4853, "text": "know all about ships’ charms. But I sometimes think\nhe’ll charm the ship to no good at last. I don’t half like that chap,\nStubb. Did you ever notice how that tusk of his is a sort of", "labels": {"50": 39, "100": 41, "250": 91, "500": 407, "1000": 488, "2000": 51}}, {"id": 4854, "position": 4854, "text": ". Did you ever notice how that tusk of his is a sort of carved\ninto a snake’s head, Stubb?”\n\n“Sink him! I never look at him at all; but if ever I get a chance of a\ndark night", "labels": {"50": 30, "100": 64, "250": 183, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4855, "position": 4855, "text": "him at all; but if ever I get a chance of a\ndark night, and he standing hard by the bulwarks, and no one by; look\ndown there, Flask”—pointing into the sea with a peculiar motion of both", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4856, "position": 4856, "text": ", Flask”—pointing into the sea with a peculiar motion of both\nhands—“Aye, will I! Flask, I take that Fedallah to be the devil in\ndisguise. Do you believe that cock and bull story about his having", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 4857, "position": 4857, "text": "devil in\ndisguise. Do you believe that cock and bull story about his having been\nstowed away on board ship? He’s the devil, I say. The reason why you\ndon’t see his tail, is because he tucks it up", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 4858, "position": 4858, "text": "you\ndon’t see his tail, is because he tucks it up out of sight; he carries\nit coiled away in his pocket, I guess. Blast him! now that I think of\nit, he’s always wanting oakum to stuff", "labels": {"50": 39, "100": 99, "250": 174, "500": 5, "1000": 726, "2000": 1125}}, {"id": 4859, "position": 4859, "text": "that I think of\nit, he’s always wanting oakum to stuff into the toes of his boots.”\n\n“He sleeps in his boots, don’t he? He hasn’t got any hammock; but I’ve\nseen", "labels": {"50": 11, "100": 9, "250": 207, "500": 100, "1000": 488, "2000": 361}}, {"id": 4860, "position": 4860, "text": "He hasn’t got any hammock; but I’ve\nseen him lay of nights in a coil of rigging.”\n\n“No doubt, and it’s because of his cursed tail; he coils it down, do ye\nsee", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4861, "position": 4861, "text": "because of his cursed tail; he coils it down, do ye\nsee, in the eye of the rigging.”\n\n“What’s the old man have so much to do with him for?”", "labels": {"50": 41, "100": 21, "250": 91, "500": 180, "1000": 627, "2000": 1199}}, {"id": 4862, "position": 4862, "text": "to do with him for?”\n\n“Striking up a swap or a bargain, I suppose.”\n\n“Bargain?—about what?”\n\n“Why, do ye see, the old man is hard bent after that White Whale, and\nthe devil there", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4863, "position": 4863, "text": "the old man is hard bent after that White Whale, and\nthe devil there is trying to come round him, and get him to swap away\nhis silver watch, or his soul, or something of that sort, and then\nhe’ll surrender Moby", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4864, "position": 4864, "text": ", or something of that sort, and then\nhe’ll surrender Moby Dick.”\n\n“Pooh! Stubb, you are skylarking; how can Fedallah do that?”\n\n“I don’t know, Flask, but", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4865, "position": 4865, "text": "do that?”\n\n“I don’t know, Flask, but the devil is a curious chap, and a wicked\none, I tell ye. Why, they say as how he went a sauntering into the old\nflag-ship", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 4866, "position": 4866, "text": "say as how he went a sauntering into the old\nflag-ship once, switching his tail about devilish easy and\ngentlemanlike, and inquiring if the old governor was at home. Well, he\nwas at home, and asked the", "labels": {"50": 41, "100": 21, "250": 91, "500": 178, "1000": 333, "2000": 1082}}, {"id": 4867, "position": 4867, "text": "governor was at home. Well, he\nwas at home, and asked the devil what he wanted. The devil, switching\nhis hoofs, up and says, ‘I want John.’ ‘What for?’ says the old\ngovernor", "labels": {"50": 40, "100": 13, "250": 38, "500": 106, "1000": 31, "2000": 537}}, {"id": 4868, "position": 4868, "text": "want John.’ ‘What for?’ says the old\ngovernor. ‘What business is that of yours,’ says the devil, getting\nmad,—‘I want to use him.’ ‘Take him,’ says the governor—and by", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 31, "2000": 537}}, {"id": 4869, "position": 4869, "text": "use him.’ ‘Take him,’ says the governor—and by the\nLord, Flask, if the devil didn’t give John the Asiatic cholera before\nhe got through with him, I’ll eat this whale in one mouthful", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 4870, "position": 4870, "text": "through with him, I’ll eat this whale in one mouthful. But look\nsharp—ain’t you all ready there? Well, then, pull ahead, and let’s get\nthe whale alongside.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4871, "position": 4871, "text": "’s get\nthe whale alongside.”\n\n“I think I remember some such story as you were telling,” said Flask,\nwhen at last the two boats were slowly advancing with their burden\ntowards the ship, “but I can’t remember where", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4872, "position": 4872, "text": "with their burden\ntowards the ship, “but I can’t remember where.”\n\n“Three Spaniards? Adventures of those three bloody-minded soldadoes?\nDid ye read it there, Flask? I guess ye did?”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 730, "2000": 967}}, {"id": 4873, "position": 4873, "text": "it there, Flask? I guess ye did?”\n\n“No: never saw such a book; heard of it, though. But now, tell me,\nStubb, do you suppose that that devil you was speaking of just now, was", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 851, "2000": 1620}}, {"id": 4874, "position": 4874, "text": ", do you suppose that that devil you was speaking of just now, was\nthe same you say is now on board the Pequod?”\n\n“Am I the same man that helped kill this whale? Doesn’t the devil live\nfor ever;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4875, "position": 4875, "text": "that helped kill this whale? Doesn’t the devil live\nfor ever; who ever heard that the devil was dead? Did you ever see any\nparson a wearing mourning for the devil? And if the devil has a\nlatch-key to get into", "labels": {"50": 35, "100": 94, "250": 69, "500": 265, "1000": 919, "2000": 1061}}, {"id": 4876, "position": 4876, "text": "the devil? And if the devil has a\nlatch-key to get into the admiral’s cabin, don’t you suppose he can\ncrawl into a porthole? Tell me that, Mr. Flask?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 4877, "position": 4877, "text": "me that, Mr. Flask?”\n\n“How old do you suppose Fedallah is, Stubb?”\n\n“Do you see that mainmast there?” pointing to the ship; “well, that’s\nthe figure one;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4878, "position": 4878, "text": "pointing to the ship; “well, that’s\nthe figure one; now take all the hoops in the Pequod’s hold, and string\nalong in a row with that mast, for oughts, do you see; well,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4879, "position": 4879, "text": "row with that mast, for oughts, do you see; well, that\nwouldn’t begin to be Fedallah’s age. Nor all the coopers in creation\ncouldn’t show hoops enough to make oughts enough.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 4880, "position": 4880, "text": "creation\ncouldn’t show hoops enough to make oughts enough.”\n\n“But see here, Stubb, I thought you a little boasted just now, that you\nmeant to give Fedallah a sea-toss, if you got a good", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 4881, "position": 4881, "text": "to give Fedallah a sea-toss, if you got a good chance. Now, if\nhe’s so old as all those hoops of yours come to, and if he is going to\nlive for ever, what good will it do", "labels": {"50": 25, "100": 64, "250": 136, "500": 388, "1000": 533, "2000": 786}}, {"id": 4882, "position": 4882, "text": "and if he is going to\nlive for ever, what good will it do to pitch him overboard—tell me\nthat?\n\n“Give him a good ducking, anyhow.”\n\n“But he’d crawl back.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 4883, "position": 4883, "text": "”\n\n“But he’d crawl back.”\n\n“Duck him again; and keep ducking him.”\n\n“Suppose he should take it into his head to duck you, though—yes, and\ndrown you—what then?”", "labels": {"50": 11, "100": 99, "250": 47, "500": 356, "1000": 488, "2000": 51}}, {"id": 4884, "position": 4884, "text": "though—yes, and\ndrown you—what then?”\n\n“I should like to see him try it; I’d give him such a pair of black\neyes that he wouldn’t dare to show his face in the admiral’s cabin\nagain", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1199}}, {"id": 4885, "position": 4885, "text": "wouldn’t dare to show his face in the admiral’s cabin\nagain for a long while, let alone down in the orlop there, where he\nlives, and hereabouts on the upper decks where he sneaks so much", "labels": {"50": 31, "100": 7, "250": 193, "500": 453, "1000": 849, "2000": 1107}}, {"id": 4886, "position": 4886, "text": "hereabouts on the upper decks where he sneaks so much. Damn\nthe devil, Flask; so you suppose I’m afraid of the devil? Who’s afraid\nof him, except the old governor who daresn’t catch", "labels": {"50": 6, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 4887, "position": 4887, "text": "afraid\nof him, except the old governor who daresn’t catch him and put him in\ndouble-darbies, as he deserves, but lets him go about kidnapping\npeople; aye, and signed a bond with him, that all the people", "labels": {"50": 18, "100": 1, "250": 42, "500": 437, "1000": 250, "2000": 1492}}, {"id": 4888, "position": 4888, "text": "people; aye, and signed a bond with him, that all the people the devil\nkidnapped, he’d roast for him? There’s a governor!”\n\n“Do you suppose Fedallah wants to kidnap Captain Ahab?”", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 4889, "position": 4889, "text": "you suppose Fedallah wants to kidnap Captain Ahab?”\n\n“Do I suppose it? You’ll know it before long, Flask. But I am going now\nto keep a sharp look-out on him; and if I see anything", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4890, "position": 4890, "text": "to keep a sharp look-out on him; and if I see anything very suspicious\ngoing on, I’ll just take him by the nape of his neck, and say—Look\nhere, Beelzebub, you don’t do it", "labels": {"50": 25, "100": 64, "250": 91, "500": 72, "1000": 533, "2000": 786}}, {"id": 4891, "position": 4891, "text": "—Look\nhere, Beelzebub, you don’t do it; and if he makes any fuss, by the Lord\nI’ll make a grab into his pocket for his tail, take it to the capstan,\nand give him such", "labels": {"50": 1, "100": 80, "250": 190, "500": 263, "1000": 791, "2000": 959}}, {"id": 4892, "position": 4892, "text": "for his tail, take it to the capstan,\nand give him such a wrenching and heaving, that his tail will come\nshort off at the stump—do you see; and then, I rather guess when he\nfinds himself docked in that queer", "labels": {"50": 45, "100": 64, "250": 30, "500": 72, "1000": 692, "2000": 1620}}, {"id": 4893, "position": 4893, "text": "; and then, I rather guess when he\nfinds himself docked in that queer fashion, he’ll sneak off without the\npoor satisfaction of feeling his tail between his legs.”\n\n“And what will you do with the tail, Stubb?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4894, "position": 4894, "text": "“And what will you do with the tail, Stubb?”\n\n“Do with it? Sell it for an ox whip when we get home;—what else?”\n\n“Now, do you mean what you say, and have been saying all", "labels": {"50": 37, "100": 64, "250": 163, "500": 72, "1000": 54, "2000": 1620}}, {"id": 4895, "position": 4895, "text": "“Now, do you mean what you say, and have been saying all along, Stubb?”\n\n“Mean or not mean, here we are at the ship.”\n\nThe boats were here hailed, to tow the whale on the larboa", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4896, "position": 4896, "text": "The boats were here hailed, to tow the whale on the larboard side,\nwhere fluke chains and other necessaries were already prepared for\nsecuring him.\n\n“Didn’t I tell you so?” said Flask; “yes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4897, "position": 4897, "text": "Didn’t I tell you so?” said Flask; “yes, you’ll soon see this right\nwhale’s head hoisted up opposite that parmacetti’s.”\n\nIn good time, Flask’s saying proved true", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4898, "position": 4898, "text": "s.”\n\nIn good time, Flask’s saying proved true. As before, the Pequod steeply\nleaned over towards the sperm whale’s head, now, by the counterpoise of\nboth heads, she regained her even keel", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4899, "position": 4899, "text": ", by the counterpoise of\nboth heads, she regained her even keel; though sorely strained, you may\nwell believe. So, when on one side you hoist in Locke’s head, you go\nover that way; but now,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 4900, "position": 4900, "text": "in Locke’s head, you go\nover that way; but now, on the other side, hoist in Kant’s and you come\nback again; but in very poor plight. Thus, some minds for ever keep\ntrimming boat", "labels": {"50": 10, "100": 71, "250": 129, "500": 136, "1000": 811, "2000": 506}}, {"id": 4901, "position": 4901, "text": "poor plight. Thus, some minds for ever keep\ntrimming boat. Oh, ye foolish! throw all these thunder-heads overboard,\nand then you will float light and right.\n\nIn disposing of the body of a right whale, when brought", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4902, "position": 4902, "text": ".\n\nIn disposing of the body of a right whale, when brought alongside the\nship, the same preliminary proceedings commonly take place as in the\ncase of a sperm whale; only, in the latter instance, the head is cut\noff whole, but", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4903, "position": 4903, "text": "only, in the latter instance, the head is cut\noff whole, but in the former the lips and tongue are separately removed\nand hoisted on deck, with all the well known black bone attached to\nwhat is called the crown-piece", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4904, "position": 4904, "text": "black bone attached to\nwhat is called the crown-piece. But nothing like this, in the present\ncase, had been done. The carcases of both whales had dropped astern;\nand the head-laden ship not a little resembled a mule", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4905, "position": 4905, "text": "astern;\nand the head-laden ship not a little resembled a mule carrying a pair\nof overburdening panniers.\n\nMeantime, Fedallah was calmly eyeing the right whale’s head, and ever\nand anon glancing from the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4906, "position": 4906, "text": "the right whale’s head, and ever\nand anon glancing from the deep wrinkles there to the lines in his own\nhand. And Ahab chanced so to stand, that the Parsee occupied his\nshadow; while, if the Parsee", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4907, "position": 4907, "text": ", that the Parsee occupied his\nshadow; while, if the Parsee’s shadow was there at all it seemed only\nto blend with, and lengthen Ahab’s. As the crew toiled on, Laplandish\nspeculations were", "labels": {"50": 22, "100": 78, "250": 170, "500": 60, "1000": 155, "2000": 592}}, {"id": 4908, "position": 4908, "text": "s. As the crew toiled on, Laplandish\nspeculations were bandied among them, concerning all these passing\nthings.\n\n\nCHAPTER 74. The Sperm Whale’s Head—Contrasted View.\n\nHere, now, are two great whales, laying their", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4909, "position": 4909, "text": "—Contrasted View.\n\nHere, now, are two great whales, laying their heads together; let us\njoin them, and lay together our own.\n\nOf the grand order of folio leviathans, the Sperm Whale and the Right\nWhale are by far", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4910, "position": 4910, "text": "olio leviathans, the Sperm Whale and the Right\nWhale are by far the most noteworthy. They are the only whales\nregularly hunted by man. To the Nantucketer, they present the two\nextremes of all the known varieties of the whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4911, "position": 4911, "text": "they present the two\nextremes of all the known varieties of the whale. As the external\ndifference between them is mainly observable in their heads; and as a\nhead of each is this moment hanging from the Pequod’s side; and as", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4912, "position": 4912, "text": "is this moment hanging from the Pequod’s side; and as we\nmay freely go from one to the other, by merely stepping across the\ndeck:—where, I should like to know, will you obtain a better chance to\nstudy practical", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 4913, "position": 4913, "text": "I should like to know, will you obtain a better chance to\nstudy practical cetology than here?\n\nIn the first place, you are struck by the general contrast between\nthese heads. Both are massive enough in all conscience; but there is a\ncertain mathematical", "labels": {"50": 8, "100": 14, "250": 81, "500": 486, "1000": 956, "2000": 227}}, {"id": 4914, "position": 4914, "text": ". Both are massive enough in all conscience; but there is a\ncertain mathematical symmetry in the Sperm Whale’s which the Right\nWhale’s sadly lacks. There is more character in the Sperm Whale’s head", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4915, "position": 4915, "text": "in the Sperm Whale’s head.\nAs you behold it, you involuntarily yield the immense superiority to\nhim, in point of pervading dignity. In the present instance, too, this\ndignity is heightened by the pepper and salt", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4916, "position": 4916, "text": "the present instance, too, this\ndignity is heightened by the pepper and salt colour of his head at the\nsummit, giving token of advanced age and large experience. In short, he\nis what the fishermen technically call a “grey-headed whale.”", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4917, "position": 4917, "text": "he\nis what the fishermen technically call a “grey-headed whale.”\n\nLet us now note what is least dissimilar in these heads—namely, the two\nmost important organs, the eye and the ear", "labels": {"50": 3, "100": 24, "250": 14, "500": 403, "1000": 634, "2000": 1620}}, {"id": 4918, "position": 4918, "text": "important organs, the eye and the ear. Far back on the side of the\nhead, and low down, near the angle of either whale’s jaw, if you\nnarrowly search, you will at last see a lashless eye, which you would", "labels": {"50": 3, "100": 70, "250": 14, "500": 403, "1000": 825, "2000": 1620}}, {"id": 4919, "position": 4919, "text": "search, you will at last see a lashless eye, which you would\nfancy to be a young colt’s eye; so out of all proportion is it to the\nmagnitude of the head.\n\nNow, from this peculiar sideway position of the whale", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4920, "position": 4920, "text": "of the head.\n\nNow, from this peculiar sideway position of the whale’s eyes, it is\nplain that he can never see an object which is exactly ahead, no more\nthan he can one exactly astern", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4921, "position": 4921, "text": "more\nthan he can one exactly astern. In a word, the position of the whale’s\neyes corresponds to that of a man’s ears; and you may fancy, for\nyourself, how it would fare with you, did you sideways survey", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4922, "position": 4922, "text": ", for\nyourself, how it would fare with you, did you sideways survey objects\nthrough your ears. You would find that you could only command some\nthirty degrees of vision in advance of the straight side-line of sight;\nand about thirty more behind it", "labels": {"50": 10, "100": 71, "250": 33, "500": 395, "1000": 988, "2000": 998}}, {"id": 4923, "position": 4923, "text": "of the straight side-line of sight;\nand about thirty more behind it. If your bitterest foe were walking\nstraight towards you, with dagger uplifted in broad day, you would not\nbe able to see him, any more than if he", "labels": {"50": 31, "100": 24, "250": 49, "500": 417, "1000": 165, "2000": 145}}, {"id": 4924, "position": 4924, "text": ", you would not\nbe able to see him, any more than if he were stealing upon you from\nbehind. In a word, you would have two backs, so to speak; but, at the\nsame time, also, two fronts (side fronts", "labels": {"50": 3, "100": 24, "250": 213, "500": 403, "1000": 845, "2000": 268}}, {"id": 4925, "position": 4925, "text": "; but, at the\nsame time, also, two fronts (side fronts): for what is it that makes\nthe front of a man—what, indeed, but his eyes?\n\nMoreover, while in most other animals that I can now think of", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 18, "2000": 1274}}, {"id": 4926, "position": 4926, "text": "eyes?\n\nMoreover, while in most other animals that I can now think of, the eyes\nare so planted as imperceptibly to blend their visual power, so as to\nproduce one picture and not two to the brain; the peculiar position of", "labels": {"50": 3, "100": 71, "250": 232, "500": 395, "1000": 988, "2000": 154}}, {"id": 4927, "position": 4927, "text": "to\nproduce one picture and not two to the brain; the peculiar position of\nthe whale’s eyes, effectually divided as they are by many cubic feet of\nsolid head, which towers between them like a great mountain separating\ntwo lakes in valleys; this", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4928, "position": 4928, "text": "which towers between them like a great mountain separating\ntwo lakes in valleys; this, of course, must wholly separate the\nimpressions which each independent organ imparts. The whale, therefore,\nmust see one distinct picture on this side, and another distinct\npicture on", "labels": {"50": 3, "100": 70, "250": 33, "500": 403, "1000": 634, "2000": 1620}}, {"id": 4929, "position": 4929, "text": ",\nmust see one distinct picture on this side, and another distinct\npicture on that side; while all between must be profound darkness and\nnothingness to him. Man may, in effect, be said to look out on the\nworld from a sentry-", "labels": {"50": 10, "100": 71, "250": 196, "500": 483, "1000": 212, "2000": 1686}}, {"id": 4930, "position": 4930, "text": "effect, be said to look out on the\nworld from a sentry-box with two joined sashes for his window. But with\nthe whale, these two sashes are separately inserted, making two\ndistinct windows, but sadly impairing the view", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4931, "position": 4931, "text": "separately inserted, making two\ndistinct windows, but sadly impairing the view. This peculiarity of the\nwhale’s eyes is a thing always to be borne in mind in the fishery; and\nto be remembered by the reader in some subsequent scenes.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4932, "position": 4932, "text": "the fishery; and\nto be remembered by the reader in some subsequent scenes.\n\nA curious and most puzzling question might be started concerning this\nvisual matter as touching the Leviathan. But I must be content with a\nhint", "labels": {"50": 10, "100": 71, "250": 129, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4933, "position": 4933, "text": "But I must be content with a\nhint. So long as a man’s eyes are open in the light, the act of seeing\nis involuntary; that is, he cannot then help mechanically seeing\nwhatever objects are before him", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 18, "2000": 1944}}, {"id": 4934, "position": 4934, "text": "then help mechanically seeing\nwhatever objects are before him. Nevertheless, any one’s experience\nwill teach him, that though he can take in an undiscriminating sweep of\nthings at one glance, it is quite impossible for him, atten", "labels": {"50": 24, "100": 71, "250": 232, "500": 273, "1000": 988, "2000": 154}}, {"id": 4935, "position": 4935, "text": "of\nthings at one glance, it is quite impossible for him, attentively, and\ncompletely, to examine any two things—however large or however small—at\none and the same instant of time; never mind if they lie side by side\nand", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 18, "2000": 334}}, {"id": 4936, "position": 4936, "text": "the same instant of time; never mind if they lie side by side\nand touch each other. But if you now come to separate these two\nobjects, and surround each by a circle of profound darkness; then, in\norder to see one of them,", "labels": {"50": 36, "100": 35, "250": 242, "500": 274, "1000": 931, "2000": 872}}, {"id": 4937, "position": 4937, "text": "circle of profound darkness; then, in\norder to see one of them, in such a manner as to bring your mind to\nbear on it, the other will be utterly excluded from your contemporary\nconsciousness. How is it, then, with the whale?", "labels": {"50": 10, "100": 71, "250": 13, "500": 72, "1000": 134, "2000": 1620}}, {"id": 4938, "position": 4938, "text": "from your contemporary\nconsciousness. How is it, then, with the whale? True, both his eyes, in\nthemselves, must simultaneously act; but is his brain so much more\ncomprehensive, combining, and subtle than man’s, that he can at", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4939, "position": 4939, "text": "comprehensive, combining, and subtle than man’s, that he can at the\nsame moment of time attentively examine two distinct prospects, one on\none side of him, and the other in an exactly opposite direction? If he\ncan, then is", "labels": {"50": 31, "100": 75, "250": 13, "500": 307, "1000": 343, "2000": 1050}}, {"id": 4940, "position": 4940, "text": "and the other in an exactly opposite direction? If he\ncan, then is it as marvellous a thing in him, as if a man were able\nsimultaneously to go through the demonstrations of two distinct\nproblems in Euclid", "labels": {"50": 10, "100": 71, "250": 129, "500": 136, "1000": 368, "2000": 1858}}, {"id": 4941, "position": 4941, "text": "demonstrations of two distinct\nproblems in Euclid. Nor, strictly investigated, is there any\nincongruity in this comparison.\n\nIt may be but an idle whim, but it has always seemed to me, that the\nextraordinary vacillations", "labels": {"50": 3, "100": 63, "250": 50, "500": 33, "1000": 862, "2000": 1403}}, {"id": 4942, "position": 4942, "text": "but it has always seemed to me, that the\nextraordinary vacillations of movement displayed by some whales when\nbeset by three or four boats; the timidity and liability to queer\nfrights, so common to such whales; I think that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4943, "position": 4943, "text": "liability to queer\nfrights, so common to such whales; I think that all this indirectly\nproceeds from the helpless perplexity of volition, in which their\ndivided and diametrically opposite powers of vision must involve them.", "labels": {"50": 20, "100": 5, "250": 0, "500": 149, "1000": 443, "2000": 1217}}, {"id": 4944, "position": 4944, "text": "metrically opposite powers of vision must involve them.\n\nBut the ear of the whale is full as curious as the eye. If you are an\nentire stranger to their race, you might hunt over these two heads for\nhours, and never discover that organ", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4945, "position": 4945, "text": "might hunt over these two heads for\nhours, and never discover that organ. The ear has no external leaf\nwhatever; and into the hole itself you can hardly insert a quill, so\nwondrously minute is it", "labels": {"50": 3, "100": 70, "250": 13, "500": 403, "1000": 134, "2000": 458}}, {"id": 4946, "position": 4946, "text": ", so\nwondrously minute is it. It is lodged a little behind the eye. With\nrespect to their ears, this important difference is to be observed\nbetween the sperm whale and the right. While the ear of the former has\nan external opening,", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4947, "position": 4947, "text": "and the right. While the ear of the former has\nan external opening, that of the latter is entirely and evenly covered\nover with a membrane, so as to be quite imperceptible from without.", "labels": {"50": 3, "100": 70, "250": 152, "500": 403, "1000": 845, "2000": 268}}, {"id": 4948, "position": 4948, "text": "erceptible from without.\n\nIs it not curious, that so vast a being as the whale should see the\nworld through so small an eye, and hear the thunder through an ear\nwhich is smaller than a hare’s? But if his eyes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4949, "position": 4949, "text": "an ear\nwhich is smaller than a hare’s? But if his eyes were broad as the lens\nof Herschel’s great telescope; and his ears capacious as the porches of\ncathedrals; would that make him any longer of sight,", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 511}}, {"id": 4950, "position": 4950, "text": "porches of\ncathedrals; would that make him any longer of sight, or sharper of\nhearing? Not at all.—Why then do you try to “enlarge” your mind?\nSubtilize it.", "labels": {"50": 48, "100": 20, "250": 192, "500": 126, "1000": 747, "2000": 1560}}, {"id": 4951, "position": 4951, "text": "ge” your mind?\nSubtilize it.\n\nLet us now with whatever levers and steam-engines we have at hand, cant\nover the sperm whale’s head, that it may lie bottom up; then, ascending\nby a ladder", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4952, "position": 4952, "text": "head, that it may lie bottom up; then, ascending\nby a ladder to the summit, have a peep down the mouth; and were it not\nthat the body is now completely separated from it, with a lantern we\nmight descend into the great", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 51, "2000": 937}}, {"id": 4953, "position": 4953, "text": "now completely separated from it, with a lantern we\nmight descend into the great Kentucky Mammoth Cave of his stomach. But\nlet us hold on here by this tooth, and look about us where we are. What\na really beautiful and chaste-looking mouth", "labels": {"50": 3, "100": 24, "250": 155, "500": 403, "1000": 825, "2000": 1225}}, {"id": 4954, "position": 4954, "text": "us where we are. What\na really beautiful and chaste-looking mouth! from floor to ceiling,\nlined, or rather papered with a glistening white membrane, glossy as\nbridal satins.\n\nBut come out now, and look at this porte", "labels": {"50": 48, "100": 7, "250": 49, "500": 78, "1000": 933, "2000": 1717}}, {"id": 4955, "position": 4955, "text": "bridal satins.\n\nBut come out now, and look at this portentous lower jaw, which seems\nlike the long narrow lid of an immense snuff-box, with the hinge at one\nend, instead of one side", "labels": {"50": 3, "100": 24, "250": 49, "500": 288, "1000": 546, "2000": 1225}}, {"id": 4956, "position": 4956, "text": ", with the hinge at one\nend, instead of one side. If you pry it up, so as to get it overhead,\nand expose its rows of teeth, it seems a terrific portcullis; and such,\nalas! it proves", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4957, "position": 4957, "text": "seems a terrific portcullis; and such,\nalas! it proves to many a poor wight in the fishery, upon whom these\nspikes fall with impaling force. But far more terrible is it to behold,\nwhen fathoms down in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 692, "2000": 1620}}, {"id": 4958, "position": 4958, "text": "far more terrible is it to behold,\nwhen fathoms down in the sea, you see some sulky whale, floating there\nsuspended, with his prodigious jaw, some fifteen feet long, hanging\nstraight down at right-angles with his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4959, "position": 4959, "text": ", some fifteen feet long, hanging\nstraight down at right-angles with his body, for all the world like a\nship’s jib-boom. This whale is not dead; he is only dispirited; out of\nsorts, perhaps", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4960, "position": 4960, "text": "dead; he is only dispirited; out of\nsorts, perhaps; hypochondriac; and so supine, that the hinges of his\njaw have relaxed, leaving him there in that ungainly sort of plight,", "labels": {"50": 23, "100": 64, "250": 193, "500": 72, "1000": 851, "2000": 1620}}, {"id": 4961, "position": 4961, "text": "relaxed, leaving him there in that ungainly sort of plight, a\nreproach to all his tribe, who must, no doubt, imprecate lock-jaws upon\nhim.\n\nIn most cases this lower jaw—being easily unhing", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 531, "2000": 1620}}, {"id": 4962, "position": 4962, "text": "jaws upon\nhim.\n\nIn most cases this lower jaw—being easily unhinged by a practised\nartist—is disengaged and hoisted on deck for the purpose of extracting\nthe ivory teeth, and furnishing a supply of that hard white", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4963, "position": 4963, "text": "ing\nthe ivory teeth, and furnishing a supply of that hard white whalebone\nwith which the fishermen fashion all sorts of curious articles,\nincluding canes, umbrella-stocks, and handles to riding-whips.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4964, "position": 4964, "text": ", and handles to riding-whips.\n\nWith a long, weary hoist the jaw is dragged on board, as if it were an\nanchor; and when the proper time comes—some few days after the other\nwork—Queequeg,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4965, "position": 4965, "text": "comes—some few days after the other\nwork—Queequeg, Daggoo, and Tashtego, being all accomplished dentists,\nare set to drawing teeth. With a keen cutting-spade, Queequeg lances", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4966, "position": 4966, "text": "teeth. With a keen cutting-spade, Queequeg lances\nthe gums; then the jaw is lashed down to ringbolts, and a tackle being\nrigged from aloft, they drag out these teeth, as Michigan oxen drag", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4967, "position": 4967, "text": "from aloft, they drag out these teeth, as Michigan oxen drag\nstumps of old oaks out of wild wood lands. There are generally\nforty-two teeth in all; in old whales, much worn down, but undecayed;\nnor", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4968, "position": 4968, "text": "; in old whales, much worn down, but undecayed;\nnor filled after our artificial fashion. The jaw is afterwards sawn\ninto slabs, and piled away like joists for building houses.\n\n\nCHAPTER 75", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4969, "position": 4969, "text": "ists for building houses.\n\n\nCHAPTER 75. The Right Whale’s Head—Contrasted View.\n\nCrossing the deck, let us now have a good long look at the Right\nWhale’s head.\n\nAs in general shape the noble Sperm Whale’s head may", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4970, "position": 4970, "text": "s head.\n\nAs in general shape the noble Sperm Whale’s head may be compared to a\nRoman war-chariot (especially in front, where it is so broadly\nrounded); so, at a broad view, the Right Whale’s head bears", "labels": {"50": 3, "100": 70, "250": 14, "500": 403, "1000": 634, "2000": 1620}}, {"id": 4971, "position": 4971, "text": "; so, at a broad view, the Right Whale’s head bears a rather\ninelegant resemblance to a gigantic galliot-toed shoe. Two hundred\nyears ago an old Dutch voyager likened its shape to that of a\nshoemaker’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4972, "position": 4972, "text": "ago an old Dutch voyager likened its shape to that of a\nshoemaker’s last. And in this same last or shoe, that old woman of the\nnursery tale, with the swarming brood, might very comfortably be\nlodged, she and all her", "labels": {"50": 48, "100": 20, "250": 53, "500": 162, "1000": 995, "2000": 47}}, {"id": 4973, "position": 4973, "text": "the swarming brood, might very comfortably be\nlodged, she and all her progeny.\n\nBut as you come nearer to this great head it begins to assume different\naspects, according to your point of view. If you stand on its summit\nand look at", "labels": {"50": 48, "100": 20, "250": 49, "500": 334, "1000": 275, "2000": 1710}}, {"id": 4974, "position": 4974, "text": "to your point of view. If you stand on its summit\nand look at these two F-shaped spoutholes, you would take the whole\nhead for an enormous bass-viol, and these spiracles, the apertures in\nits sounding", "labels": {"50": 48, "100": 27, "250": 249, "500": 339, "1000": 832, "2000": 532}}, {"id": 4975, "position": 4975, "text": "viol, and these spiracles, the apertures in\nits sounding-board. Then, again, if you fix your eye upon this strange,\ncrested, comb-like incrustation on the top of the mass—this green,\nbarn", "labels": {"50": 3, "100": 24, "250": 213, "500": 331, "1000": 546, "2000": 1556}}, {"id": 4976, "position": 4976, "text": "like incrustation on the top of the mass—this green,\nbarnacled thing, which the Greenlanders call the “crown,” and the\nSouthern fishers the “bonnet” of the Right Whale; fixing your eyes\nsolely on this,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4977, "position": 4977, "text": "“bonnet” of the Right Whale; fixing your eyes\nsolely on this, you would take the head for the trunk of some huge oak,\nwith a bird’s nest in its crotch. At any rate, when you watch those\nlive crabs that nest", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4978, "position": 4978, "text": "its crotch. At any rate, when you watch those\nlive crabs that nestle here on this bonnet, such an idea will be almost\nsure to occur to you; unless, indeed, your fancy has been fixed by the\ntechnical term “crown” also", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 4979, "position": 4979, "text": "indeed, your fancy has been fixed by the\ntechnical term “crown” also bestowed upon it; in which case you will\ntake great interest in thinking how this mighty monster is actually a\ndiademed king of the sea, whose green crown has been put", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4980, "position": 4980, "text": "a\ndiademed king of the sea, whose green crown has been put together for\nhim in this marvellous manner. But if this whale be a king, he is a\nvery sulky looking fellow to grace a diadem", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4981, "position": 4981, "text": "very sulky looking fellow to grace a diadem. Look at that hanging lower\nlip! what a huge sulk and pout is there! a sulk and pout, by\ncarpenter’s measurement, about twenty feet long and five feet", "labels": {"50": 32, "100": 0, "250": 233, "500": 288, "1000": 856, "2000": 799}}, {"id": 4982, "position": 4982, "text": "ut, by\ncarpenter’s measurement, about twenty feet long and five feet deep; a\nsulk and pout that will yield you some 500 gallons of oil and more.\n\nA great pity, now, that this unfortunate whale should be hare-lip", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4983, "position": 4983, "text": "A great pity, now, that this unfortunate whale should be hare-lipped.\nThe fissure is about a foot across. Probably the mother during an\nimportant interval was sailing down the Peruvian coast, when\nearthquakes caused the beach to gape", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4984, "position": 4984, "text": "down the Peruvian coast, when\nearthquakes caused the beach to gape. Over this lip, as over a slippery\nthreshold, we now slide into the mouth. Upon my word were I at\nMackinaw, I should take this to be the inside of", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 887}}, {"id": 4985, "position": 4985, "text": "I at\nMackinaw, I should take this to be the inside of an Indian wigwam. Good\nLord! is this the road that Jonah went? The roof is about twelve feet\nhigh, and runs to a pretty sharp angle, as if", "labels": {"50": 12, "100": 93, "250": 209, "500": 344, "1000": 533, "2000": 624}}, {"id": 4986, "position": 4986, "text": "about twelve feet\nhigh, and runs to a pretty sharp angle, as if there were a regular\nridge-pole there; while these ribbed, arched, hairy sides, present us\nwith those wondrous, half vertical, scimetar-shaped", "labels": {"50": 12, "100": 93, "250": 192, "500": 423, "1000": 615, "2000": 1304}}, {"id": 4987, "position": 4987, "text": "us\nwith those wondrous, half vertical, scimetar-shaped slats of whalebone,\nsay three hundred on a side, which depending from the upper part of the\nhead or crown bone, form those Venetian blinds which have elsewhere\nbeen cu", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 4988, "position": 4988, "text": "the\nhead or crown bone, form those Venetian blinds which have elsewhere\nbeen cursorily mentioned. The edges of these bones are fringed with\nhairy fibres, through which the Right Whale strains the water, and in\nwhose intricacies he retains the", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4989, "position": 4989, "text": "Right Whale strains the water, and in\nwhose intricacies he retains the small fish, when openmouthed he goes\nthrough the seas of brit in feeding time. In the central blinds of\nbone, as they stand in their natural order, there are", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4990, "position": 4990, "text": "central blinds of\nbone, as they stand in their natural order, there are certain curious\nmarks, curves, hollows, and ridges, whereby some whalemen calculate the\ncreature’s age, as the age of an oak by its circular rings", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4991, "position": 4991, "text": "s age, as the age of an oak by its circular rings. Though the\ncertainty of this criterion is far from demonstrable, yet it has the\nsavor of analogical probability. At any rate, if we yield to it, we\nmust", "labels": {"50": 3, "100": 70, "250": 234, "500": 77, "1000": 478, "2000": 823}}, {"id": 4992, "position": 4992, "text": "ical probability. At any rate, if we yield to it, we\nmust grant a far greater age to the Right Whale than at first glance\nwill seem reasonable.\n\nIn old times, there seem to have prevailed the most curious fancies\nconcerning these blinds", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4993, "position": 4993, "text": ", there seem to have prevailed the most curious fancies\nconcerning these blinds. One voyager in Purchas calls them the wondrous\n“whiskers” inside of the whale’s mouth;* another, “hogs’ bristles”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4994, "position": 4994, "text": "whale’s mouth;* another, “hogs’ bristles”; a\nthird old gentleman in Hackluyt uses the following elegant language:\n“There are about two hundred and fifty fins growing on each side of his\nupper _chop_,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 4995, "position": 4995, "text": "hundred and fifty fins growing on each side of his\nupper _chop_, which arch over his tongue on each side of his mouth.”\n\n*This reminds us that the Right Whale really has a sort of whisker, or\nrather a moust", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4996, "position": 4996, "text": "Whale really has a sort of whisker, or\nrather a moustache, consisting of a few scattered white hairs on the\nupper part of the outer end of the lower jaw. Sometimes these tufts\nimpart a rather brigandish expression to his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 4997, "position": 4997, "text": "jaw. Sometimes these tufts\nimpart a rather brigandish expression to his otherwise solemn\ncountenance.\n\nAs every one knows, these same “hogs’ bristles,” “fins,” “whiskers,”\n“blinds,”", "labels": {"50": 31, "100": 24, "250": 49, "500": 288, "1000": 692, "2000": 1620}}, {"id": 4998, "position": 4998, "text": "” “fins,” “whiskers,”\n“blinds,” or whatever you please, furnish to the ladies their busks and\nother stiffening contrivances. But in this particular, the demand has\nlong been on the decline", "labels": {"50": 30, "100": 7, "250": 219, "500": 100, "1000": 676, "2000": 1199}}, {"id": 4999, "position": 4999, "text": ". But in this particular, the demand has\nlong been on the decline. It was in Queen Anne’s time that the bone was\nin its glory, the farthingale being then all the fashion. And as those\nancient dames moved about gail", "labels": {"50": 48, "100": 27, "250": 157, "500": 223, "1000": 953, "2000": 507}}, {"id": 5000, "position": 5000, "text": "being then all the fashion. And as those\nancient dames moved about gaily, though in the jaws of the whale, as\nyou may say; even so, in a shower, with the like thoughtlessness, do we\nnowadays fly under the same", "labels": {"50": 31, "100": 7, "250": 193, "500": 274, "1000": 203, "2000": 1107}}, {"id": 5001, "position": 5001, "text": "shower, with the like thoughtlessness, do we\nnowadays fly under the same jaws for protection; the umbrella being a\ntent spread over the same bone.\n\nBut now forget all about blinds and whiskers for a moment, and,\nstanding in the Right", "labels": {"50": 31, "100": 7, "250": 193, "500": 453, "1000": 203, "2000": 1107}}, {"id": 5002, "position": 5002, "text": "blinds and whiskers for a moment, and,\nstanding in the Right Whale’s mouth, look around you afresh. Seeing all\nthese colonnades of bone so methodically ranged about, would you not\nthink you were inside of the great", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5003, "position": 5003, "text": "methodically ranged about, would you not\nthink you were inside of the great Haarlem organ, and gazing upon its\nthousand pipes? For a carpet to the organ we have a rug of the softest\nTurkey—the tongue, which is glued,", "labels": {"50": 48, "100": 20, "250": 90, "500": 126, "1000": 90, "2000": 1107}}, {"id": 5004, "position": 5004, "text": "a rug of the softest\nTurkey—the tongue, which is glued, as it were, to the floor of the\nmouth. It is very fat and tender, and apt to tear in pieces in hoisting\nit on deck", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5005, "position": 5005, "text": "to tear in pieces in hoisting\nit on deck. This particular tongue now before us; at a passing glance I\nshould say it was a six-barreler; that is, it will yield you about that\namount of oil.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5006, "position": 5006, "text": "is, it will yield you about that\namount of oil.\n\nEre this, you must have plainly seen the truth of what I started\nwith—that the Sperm Whale and the Right Whale have almost entirely\ndifferent heads", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5007, "position": 5007, "text": "Right Whale have almost entirely\ndifferent heads. To sum up, then: in the Right Whale’s there is no\ngreat well of sperm; no ivory teeth at all; no long, slender mandible\nof a lower jaw, like the Sperm Whale", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5008, "position": 5008, "text": "long, slender mandible\nof a lower jaw, like the Sperm Whale’s. Nor in the Sperm Whale are\nthere any of those blinds of bone; no huge lower lip; and scarcely\nanything of a tongue", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5009, "position": 5009, "text": "lip; and scarcely\nanything of a tongue. Again, the Right Whale has two external\nspout-holes, the Sperm Whale only one.\n\nLook your last, now, on these venerable hooded heads, while they yet\nlie together; for one will soon", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5010, "position": 5010, "text": "these venerable hooded heads, while they yet\nlie together; for one will soon sink, unrecorded, in the sea; the other\nwill not be very long in following.\n\nCan you catch the expression of the Sperm Whale’s there? It", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5011, "position": 5011, "text": ".\n\nCan you catch the expression of the Sperm Whale’s there? It is the same\nhe died with, only some of the longer wrinkles in the forehead seem now\nfaded away. I think his broad brow to be full of a prairie-like", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5012, "position": 5012, "text": "away. I think his broad brow to be full of a prairie-like\nplacidity, born of a speculative indifference as to death. But mark the\nother head’s expression. See that amazing lower lip, pressed by\naccident against the vessel", "labels": {"50": 16, "100": 20, "250": 49, "500": 280, "1000": 747, "2000": 1717}}, {"id": 5013, "position": 5013, "text": "s expression. See that amazing lower lip, pressed by\naccident against the vessel’s side, so as firmly to embrace the jaw.\nDoes not this whole head seem to speak of an enormous practical\nresolution in facing death? This Right Whale I take to", "labels": {"50": 3, "100": 24, "250": 249, "500": 72, "1000": 878, "2000": 1620}}, {"id": 5014, "position": 5014, "text": "of an enormous practical\nresolution in facing death? This Right Whale I take to have been a\nStoic; the Sperm Whale, a Platonian, who might have taken up Spinoza in\nhis latter years.\n\n\nCHAPTER 76. The Battering-Ram.", "labels": {"50": 10, "100": 71, "250": 129, "500": 236, "1000": 220, "2000": 1601}}, {"id": 5015, "position": 5015, "text": "oza in\nhis latter years.\n\n\nCHAPTER 76. The Battering-Ram.\n\nEre quitting, for the nonce, the Sperm Whale’s head, I would have you,\nas a sensible physiologist, simply—particularly remark its", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5016, "position": 5016, "text": "you,\nas a sensible physiologist, simply—particularly remark its front\naspect, in all its compacted collectedness. I would have you\ninvestigate it now with the sole view of forming to yourself some\nunexaggerated, intelligent estimate of", "labels": {"50": 3, "100": 70, "250": 14, "500": 403, "1000": 109, "2000": 268}}, {"id": 5017, "position": 5017, "text": "sole view of forming to yourself some\nunexaggerated, intelligent estimate of whatever battering-ram power may\nbe lodged there. Here is a vital point; for you must either\nsatisfactorily settle this matter with yourself, or for ever", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5018, "position": 5018, "text": "either\nsatisfactorily settle this matter with yourself, or for ever remain an\ninfidel as to one of the most appalling, but not the less true events,\nperhaps anywhere to be found in all recorded history.", "labels": {"50": 4, "100": 29, "250": 82, "500": 327, "1000": 732, "2000": 1518}}, {"id": 5019, "position": 5019, "text": "events,\nperhaps anywhere to be found in all recorded history.\n\nYou observe that in the ordinary swimming position of the Sperm Whale,\nthe front of his head presents an almost wholly vertical plane to the\nwater; you observe that the lower part of that front slopes", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5020, "position": 5020, "text": "plane to the\nwater; you observe that the lower part of that front slopes\nconsiderably backwards, so as to furnish more of a retreat for the long\nsocket which receives the boom-like lower jaw; you observe that the\nmouth is entirely under the head", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 5021, "position": 5021, "text": "-like lower jaw; you observe that the\nmouth is entirely under the head, much in the same way, indeed, as\nthough your own mouth were entirely under your chin. Moreover you\nobserve that the whale has no external nose; and that what nose", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5022, "position": 5022, "text": "Moreover you\nobserve that the whale has no external nose; and that what nose he\nhas—his spout hole—is on the top of his head; you observe that his eyes\nand ears are at the sides of his head, nearly one third of", "labels": {"50": 3, "100": 70, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5023, "position": 5023, "text": "eyes\nand ears are at the sides of his head, nearly one third of his entire\nlength from the front. Wherefore, you must now have perceived that the\nfront of the Sperm Whale’s head is a dead, blind wall, without a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5024, "position": 5024, "text": "the Sperm Whale’s head is a dead, blind wall, without a single\norgan or tender prominence of any sort whatsoever. Furthermore, you are\nnow to consider that only in the extreme, lower, backward sloping part\nof the front of the head,", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5025, "position": 5025, "text": "the extreme, lower, backward sloping part\nof the front of the head, is there the slightest vestige of bone; and\nnot till you get near twenty feet from the forehead do you come to the\nfull cranial development", "labels": {"50": 48, "100": 27, "250": 249, "500": 322, "1000": 878, "2000": 180}}, {"id": 5026, "position": 5026, "text": "do you come to the\nfull cranial development. So that this whole enormous boneless mass is\nas one wad. Finally, though, as will soon be revealed, its contents\npartly comprise the most delicate oil; yet, you are now to be", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 5027, "position": 5027, "text": "contents\npartly comprise the most delicate oil; yet, you are now to be apprised\nof the nature of the substance which so impregnably invests all that\napparent effeminacy. In some previous place I have described to you how", "labels": {"50": 3, "100": 70, "250": 46, "500": 403, "1000": 109, "2000": 268}}, {"id": 5028, "position": 5028, "text": "effeminacy. In some previous place I have described to you how\nthe blubber wraps the body of the whale, as the rind wraps an orange.\nJust so with the head; but with this difference: about the head this\nenvelope,", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5029, "position": 5029, "text": "with the head; but with this difference: about the head this\nenvelope, though not so thick, is of a boneless toughness, inestimable\nby any man who has not handled it. The severest pointed harpoon, the\nsharpe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5030, "position": 5030, "text": "who has not handled it. The severest pointed harpoon, the\nsharpest lance darted by the strongest human arm, impotently rebounds\nfrom it. It is as though the forehead of the Sperm Whale were paved\nwith horses’ hoofs", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5031, "position": 5031, "text": "the forehead of the Sperm Whale were paved\nwith horses’ hoofs. I do not think that any sensation lurks in it.\n\nBethink yourself also of another thing. When two large, loaded Indiamen\nchance to crowd and crush towards each other", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5032, "position": 5032, "text": "When two large, loaded Indiamen\nchance to crowd and crush towards each other in the docks, what do the\nsailors do? They do not suspend between them, at the point of coming\ncontact, any merely hard substance, like iron or wood", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 5033, "position": 5033, "text": "of coming\ncontact, any merely hard substance, like iron or wood. No, they hold\nthere a large, round wad of tow and cork, enveloped in the thickest and\ntoughest of ox-hide", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 505, "2000": 1225}}, {"id": 5034, "position": 5034, "text": "and\ntoughest of ox-hide. That bravely and uninjured takes the jam which\nwould have snapped all their oaken handspikes and iron crow-bars. By\nitself this sufficiently illustrates the obvious fact I drive at", "labels": {"50": 48, "100": 24, "250": 52, "500": 334, "1000": 275, "2000": 1546}}, {"id": 5035, "position": 5035, "text": "By\nitself this sufficiently illustrates the obvious fact I drive at. But\nsupplementary to this, it has hypothetically occurred to me, that as\nordinary fish possess what is called a swimming bladder in them,\ncapable, at will, of distension or contraction", "labels": {"50": 3, "100": 85, "250": 14, "500": 288, "1000": 634, "2000": 1225}}, {"id": 5036, "position": 5036, "text": "bladder in them,\ncapable, at will, of distension or contraction; and as the Sperm Whale,\nas far as I know, has no such provision in him; considering, too, the\notherwise inexplicable manner in which he", "labels": {"50": 3, "100": 70, "250": 14, "500": 403, "1000": 825, "2000": 1620}}, {"id": 5037, "position": 5037, "text": "considering, too, the\notherwise inexplicable manner in which he now depresses his head\naltogether beneath the surface, and anon swims with it high elevated\nout of the water; considering the unobstructed elasticity of its", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5038, "position": 5038, "text": "out of the water; considering the unobstructed elasticity of its\nenvelope; considering the unique interior of his head; it has\nhypothetically occurred to me, I say, that those mystical lung-celled\nhoneycombs there may possibly have", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5039, "position": 5039, "text": ", that those mystical lung-celled\nhoneycombs there may possibly have some hitherto unknown and\nunsuspected connexion with the outer air, so as to be susceptible to\natmospheric distension and contraction", "labels": {"50": 3, "100": 70, "250": 50, "500": 425, "1000": 969, "2000": 1759}}, {"id": 5040, "position": 5040, "text": "as to be susceptible to\natmospheric distension and contraction. If this be so, fancy the\nirresistibleness of that might, to which the most impalpable and\ndestructive of all elements contributes.\n\nNow, mark", "labels": {"50": 10, "100": 75, "250": 106, "500": 307, "1000": 616, "2000": 1374}}, {"id": 5041, "position": 5041, "text": "of all elements contributes.\n\nNow, mark. Unerringly impelling this dead, impregnable, uninjurable\nwall, and this most buoyant thing within; there swims behind it all a\nmass of tremendous life, only", "labels": {"50": 10, "100": 71, "250": 13, "500": 395, "1000": 211, "2000": 458}}, {"id": 5042, "position": 5042, "text": "within; there swims behind it all a\nmass of tremendous life, only to be adequately estimated as piled wood\nis—by the cord; and all obedient to one volition, as the smallest\ninsect", "labels": {"50": 10, "100": 20, "250": 13, "500": 414, "1000": 15, "2000": 958}}, {"id": 5043, "position": 5043, "text": "volition, as the smallest\ninsect. So that when I shall hereafter detail to you all the\nspecialities and concentrations of potency everywhere lurking in this\nexpansive monster; when I shall show you some of his more\ninconsiderable braining", "labels": {"50": 3, "100": 24, "250": 213, "500": 255, "1000": 546, "2000": 1556}}, {"id": 5044, "position": 5044, "text": "when I shall show you some of his more\ninconsiderable braining feats; I trust you will have renounced all\nignorant incredulity, and be ready to abide by this; that though the\nSperm Whale stove a passage through", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5045, "position": 5045, "text": "to abide by this; that though the\nSperm Whale stove a passage through the Isthmus of Darien, and mixed\nthe Atlantic with the Pacific, you would not elevate one hair of your\neye-brow", "labels": {"50": 3, "100": 70, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5046, "position": 5046, "text": "evate one hair of your\neye-brow. For unless you own the whale, you are but a provincial and\nsentimentalist in Truth. But clear Truth is a thing for salamander\ngiants only to encounter; how small the chances for the provincial", "labels": {"50": 31, "100": 20, "250": 213, "500": 334, "1000": 825, "2000": 1710}}, {"id": 5047, "position": 5047, "text": "salamander\ngiants only to encounter; how small the chances for the provincials\nthen? What befell the weakling youth lifting the dread goddess’s veil\nat Lais?\n\n\nCHAPTER 77. The Great Heidelburgh Tun.", "labels": {"50": 18, "100": 83, "250": 240, "500": 433, "1000": 672, "2000": 430}}, {"id": 5048, "position": 5048, "text": "?\n\n\nCHAPTER 77. The Great Heidelburgh Tun.\n\nNow comes the Baling of the Case. But to comprehend it aright, you must\nknow something of the curious internal structure of the thing operated\nupon.", "labels": {"50": 14, "100": 32, "250": 92, "500": 477, "1000": 664, "2000": 754}}, {"id": 5049, "position": 5049, "text": "curious internal structure of the thing operated\nupon.\n\nRegarding the Sperm Whale’s head as a solid oblong, you may, on an\ninclined plane, sideways divide it into two quoins,* whereof the lower\nis the bony structure, forming the", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5050, "position": 5050, "text": "quoins,* whereof the lower\nis the bony structure, forming the cranium and jaws, and the upper an\nunctuous mass wholly free from bones; its broad forward end forming the\nexpanded vertical apparent forehead of the whale", "labels": {"50": 3, "100": 70, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5051, "position": 5051, "text": "broad forward end forming the\nexpanded vertical apparent forehead of the whale. At the middle of the\nforehead horizontally subdivide this upper quoin, and then you have two\nalmost equal parts, which before were naturally divided by an internal\nwall of a thick", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5052, "position": 5052, "text": "equal parts, which before were naturally divided by an internal\nwall of a thick tendinous substance.\n\n*Quoin is not a Euclidean term. It belongs to the pure nautical\nmathematics. I know not that it has been defined before", "labels": {"50": 3, "100": 70, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 5053, "position": 5053, "text": "mathematics. I know not that it has been defined before. A quoin is a\nsolid which differs from a wedge in having its sharp end formed by the\nsteep inclination of one side, instead of the mutual tapering of both\nsides.", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 704, "2000": 1225}}, {"id": 5054, "position": 5054, "text": "side, instead of the mutual tapering of both\nsides.\n\nThe lower subdivided part, called the junk, is one immense honeycomb of\noil, formed by the crossing and recrossing, into ten thousand\ninfiltrated cells, of tough elastic white fibre", "labels": {"50": 3, "100": 24, "250": 213, "500": 255, "1000": 546, "2000": 831}}, {"id": 5055, "position": 5055, "text": "rossing, into ten thousand\ninfiltrated cells, of tough elastic white fibres throughout its whole\nextent. The upper part, known as the Case, may be regarded as the great\nHeidelburgh Tun of the Sperm Whale", "labels": {"50": 3, "100": 70, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 5056, "position": 5056, "text": "great\nHeidelburgh Tun of the Sperm Whale. And as that famous great tierce is\nmystically carved in front, so the whale’s vast plaited forehead forms\ninnumerable strange devices for the emblematical adornment", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5057, "position": 5057, "text": "forehead forms\ninnumerable strange devices for the emblematical adornment of his\nwondrous tun. Moreover, as that of Heidelburgh was always replenished\nwith the most excellent of the wines of the Rhenish valleys", "labels": {"50": 48, "100": 27, "250": 189, "500": 297, "1000": 412, "2000": 535}}, {"id": 5058, "position": 5058, "text": "lenished\nwith the most excellent of the wines of the Rhenish valleys, so the tun\nof the whale contains by far the most precious of all his oily\nvintages; namely, the highly-prized spermaceti, in its absolutely pure", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 447}}, {"id": 5059, "position": 5059, "text": "; namely, the highly-prized spermaceti, in its absolutely pure,\nlimpid, and odoriferous state. Nor is this precious substance found\nunalloyed in any other part of the creature. Though in life it remains\nperfectly fluid, yet", "labels": {"50": 3, "100": 70, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 5060, "position": 5060, "text": "other part of the creature. Though in life it remains\nperfectly fluid, yet, upon exposure to the air, after death, it soon\nbegins to concrete; sending forth beautiful crystalline shoots, as when\nthe first thin delicate ice is just forming in water", "labels": {"50": 3, "100": 70, "250": 46, "500": 403, "1000": 109, "2000": 670}}, {"id": 5061, "position": 5061, "text": "shoots, as when\nthe first thin delicate ice is just forming in water. A large whale’s\ncase generally yields about five hundred gallons of sperm, though from\nunavoidable circumstances, considerable of it is spilled, leaks, and\ndribbles", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5062, "position": 5062, "text": "ble circumstances, considerable of it is spilled, leaks, and\ndribbles away, or is otherwise irrevocably lost in the ticklish\nbusiness of securing what you can.\n\nI know not with what fine and costly material the Heidelb", "labels": {"50": 42, "100": 7, "250": 163, "500": 432, "1000": 54, "2000": 887}}, {"id": 5063, "position": 5063, "text": "can.\n\nI know not with what fine and costly material the Heidelburgh Tun was\ncoated within, but in superlative richness that coating could not\npossibly have compared with the silken pearl-coloured membrane, like\nthe lining of a fine", "labels": {"50": 20, "100": 5, "250": 156, "500": 349, "1000": 421, "2000": 1559}}, {"id": 5064, "position": 5064, "text": "with the silken pearl-coloured membrane, like\nthe lining of a fine pelisse, forming the inner surface of the Sperm\nWhale’s case.\n\nIt will have been seen that the Heidelburgh Tun of the Sperm Whale\nembraces", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5065, "position": 5065, "text": "seen that the Heidelburgh Tun of the Sperm Whale\nembraces the entire length of the entire top of the head; and since—as\nhas been elsewhere set forth—the head embraces one third of the whole\nlength of the creature,", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5066, "position": 5066, "text": "—the head embraces one third of the whole\nlength of the creature, then setting that length down at eighty feet\nfor a good sized whale, you have more than twenty-six feet for the\ndepth of the tun, when it is lengthwise hoisted", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5067, "position": 5067, "text": "six feet for the\ndepth of the tun, when it is lengthwise hoisted up and down against a\nship’s side.\n\nAs in decapitating the whale, the operator’s instrument is brought\nclose to the spot where an entrance is subsequently forced", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5068, "position": 5068, "text": "’s instrument is brought\nclose to the spot where an entrance is subsequently forced into the\nspermaceti magazine; he has, therefore, to be uncommonly heedful, lest\na careless, untimely stroke should invade the sanctuary and wastingly", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 5069, "position": 5069, "text": "lest\na careless, untimely stroke should invade the sanctuary and wastingly\nlet out its invaluable contents. It is this decapitated end of the\nhead, also, which is at last elevated out of the water, and retained in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5070, "position": 5070, "text": "also, which is at last elevated out of the water, and retained in\nthat position by the enormous cutting tackles, whose hempen\ncombinations, on one side, make quite a wilderness of ropes in that\nquarter.", "labels": {"50": 42, "100": 42, "250": 131, "500": 247, "1000": 917, "2000": 1580}}, {"id": 5071, "position": 5071, "text": "wilderness of ropes in that\nquarter.\n\nThus much being said, attend now, I pray you, to that marvellous and—in\nthis particular instance—almost fatal operation whereby the Sperm\nWhale’s great Heidelburgh Tun is tapped.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5072, "position": 5072, "text": "Sperm\nWhale’s great Heidelburgh Tun is tapped.\n\n\nCHAPTER 78. Cistern and Buckets.\n\nNimble as a cat, Tashtego mounts aloft; and without altering his erect\nposture, runs straight out upon the over", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5073, "position": 5073, "text": "oft; and without altering his erect\nposture, runs straight out upon the overhanging mainyard-arm, to the\npart where it exactly projects over the hoisted Tun. He has carried\nwith him a light tackle called a whip, consisting of only two", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5074, "position": 5074, "text": "has carried\nwith him a light tackle called a whip, consisting of only two parts,\ntravelling through a single-sheaved block. Securing this block, so that\nit hangs down from the yard-arm, he swings one end of the rope, till", "labels": {"50": 42, "100": 42, "250": 49, "500": 78, "1000": 917, "2000": 616}}, {"id": 5075, "position": 5075, "text": "from the yard-arm, he swings one end of the rope, till it\nis caught and firmly held by a hand on deck. Then, hand-over-hand, down\nthe other part, the Indian drops through the air, till dexterously", "labels": {"50": 45, "100": 19, "250": 78, "500": 379, "1000": 381, "2000": 1905}}, {"id": 5076, "position": 5076, "text": "down\nthe other part, the Indian drops through the air, till dexterously he\nlands on the summit of the head. There—still high elevated above the\nrest of the company, to whom he vivaciously cries—he seems some Turkish\nMuez", "labels": {"50": 48, "100": 20, "250": 49, "500": 78, "1000": 806, "2000": 272}}, {"id": 5077, "position": 5077, "text": ", to whom he vivaciously cries—he seems some Turkish\nMuezzin calling the good people to prayers from the top of a tower. A\nshort-handled sharp spade being sent up to him, he diligently searches\nfor the proper place", "labels": {"50": 32, "100": 0, "250": 49, "500": 78, "1000": 806, "2000": 272}}, {"id": 5078, "position": 5078, "text": "being sent up to him, he diligently searches\nfor the proper place to begin breaking into the Tun. In this business\nhe proceeds very heedfully, like a treasure-hunter in some old house,\nsounding the walls to find where the", "labels": {"50": 39, "100": 51, "250": 49, "500": 78, "1000": 165, "2000": 1956}}, {"id": 5079, "position": 5079, "text": "treasure-hunter in some old house,\nsounding the walls to find where the gold is masoned in. By the time\nthis cautious search is over, a stout iron-bound bucket, precisely like\na well-bucket, has been attached to one end", "labels": {"50": 48, "100": 42, "250": 171, "500": 154, "1000": 873, "2000": 1830}}, {"id": 5080, "position": 5080, "text": "bucket, precisely like\na well-bucket, has been attached to one end of the whip; while the\nother end, being stretched across the deck, is there held by two or\nthree alert hands. These last now hoist the bucket within grasp of", "labels": {"50": 42, "100": 63, "250": 49, "500": 78, "1000": 933, "2000": 880}}, {"id": 5081, "position": 5081, "text": "or\nthree alert hands. These last now hoist the bucket within grasp of the\nIndian, to whom another person has reached up a very long pole.\nInserting this pole into the bucket, Tashtego downward guides the\nbucket into the Tun,", "labels": {"50": 12, "100": 42, "250": 131, "500": 329, "1000": 222, "2000": 1620}}, {"id": 5082, "position": 5082, "text": "the bucket, Tashtego downward guides the\nbucket into the Tun, till it entirely disappears; then giving the word\nto the seamen at the whip, up comes the bucket again, all bubbling like\na dairy-maid’s pail of new", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5083, "position": 5083, "text": "again, all bubbling like\na dairy-maid’s pail of new milk. Carefully lowered from its height, the\nfull-freighted vessel is caught by an appointed hand, and quickly\nemptied into a large tub", "labels": {"50": 42, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5084, "position": 5084, "text": ", and quickly\nemptied into a large tub. Then remounting aloft, it again goes through\nthe same round until the deep cistern will yield no more. Towards the\nend, Tashtego has to ram his long pole harder and harder", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5085, "position": 5085, "text": "end, Tashtego has to ram his long pole harder and harder, and deeper\nand deeper into the Tun, until some twenty feet of the pole have gone\ndown.\n\nNow, the people of the Pequod had been baling some time", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5086, "position": 5086, "text": "Now, the people of the Pequod had been baling some time in this way;\nseveral tubs had been filled with the fragrant sperm; when all at once\na queer accident happened. Whether it was that Tashtego, that", "labels": {"50": 12, "100": 55, "250": 95, "500": 72, "1000": 195, "2000": 1620}}, {"id": 5087, "position": 5087, "text": "a queer accident happened. Whether it was that Tashtego, that wild\nIndian, was so heedless and reckless as to let go for a moment his\none-handed hold on the great cabled tackles suspending the head; or\nwhether", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5088, "position": 5088, "text": "handed hold on the great cabled tackles suspending the head; or\nwhether the place where he stood was so treacherous and oozy; or\nwhether the Evil One himself would have it to fall out so, without\nstating his particular reasons; how it", "labels": {"50": 18, "100": 15, "250": 180, "500": 18, "1000": 709, "2000": 805}}, {"id": 5089, "position": 5089, "text": "have it to fall out so, without\nstating his particular reasons; how it was exactly, there is no telling\nnow; but, on a sudden, as the eightieth or ninetieth bucket came\nsuckingly up—my God! poor Ta", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 5090, "position": 5090, "text": "or ninetieth bucket came\nsuckingly up—my God! poor Tashtego—like the twin reciprocating bucket\nin a veritable well, dropped head-foremost down into this great Tun of\nHeidelburgh,", "labels": {"50": 34, "100": 60, "250": 217, "500": 252, "1000": 246, "2000": 1693}}, {"id": 5091, "position": 5091, "text": "head-foremost down into this great Tun of\nHeidelburgh, and with a horrible oily gurgling, went clean out of\nsight!\n\n“Man overboard!” cried Daggoo, who amid the general consternation first\ncame", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5092, "position": 5092, "text": "” cried Daggoo, who amid the general consternation first\ncame to his senses. “Swing the bucket this way!” and putting one foot\ninto it, so as the better to secure his slippery hand-hold on the whip\nitself,", "labels": {"50": 37, "100": 55, "250": 171, "500": 185, "1000": 612, "2000": 1111}}, {"id": 5093, "position": 5093, "text": "as the better to secure his slippery hand-hold on the whip\nitself, the hoisters ran him high up to the top of the head, almost\nbefore Tashtego could have reached its interior bottom", "labels": {"50": 12, "100": 13, "250": 56, "500": 167, "1000": 653, "2000": 1339}}, {"id": 5094, "position": 5094, "text": "go could have reached its interior bottom. Meantime, there\nwas a terrible tumult. Looking over the side, they saw the before\nlifeless head throbbing and heaving just below the surface of the sea,\nas if that moment seized with some momentous idea", "labels": {"50": 45, "100": 64, "250": 171, "500": 28, "1000": 99, "2000": 1347}}, {"id": 5095, "position": 5095, "text": "surface of the sea,\nas if that moment seized with some momentous idea; whereas it was only\nthe poor Indian unconsciously revealing by those struggles the perilous\ndepth to which he had sunk.\n\nAt this instant, while Daggoo, on", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 5096, "position": 5096, "text": "which he had sunk.\n\nAt this instant, while Daggoo, on the summit of the head, was clearing\nthe whip—which had somehow got foul of the great cutting tackles—a\nsharp cracking noise was heard; and to the unspeak", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5097, "position": 5097, "text": "tackles—a\nsharp cracking noise was heard; and to the unspeakable horror of all,\none of the two enormous hooks suspending the head tore out, and with a\nvast vibration the enormous mass sideways swung, till the drunk ship\nreeled", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 5098, "position": 5098, "text": "a\nvast vibration the enormous mass sideways swung, till the drunk ship\nreeled and shook as if smitten by an iceberg. The one remaining hook,\nupon which the entire strain now depended, seemed every instant to be\non the point of giving", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 5099, "position": 5099, "text": "entire strain now depended, seemed every instant to be\non the point of giving way; an event still more likely from the violent\nmotions of the head.\n\n“Come down, come down!” yelled the seamen to Daggoo, but with one hand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5100, "position": 5100, "text": "down!” yelled the seamen to Daggoo, but with one hand\nholding on to the heavy tackles, so that if the head should drop, he\nwould still remain suspended; the negro having cleared the foul line,\nrammed down the bucket into the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5101, "position": 5101, "text": "; the negro having cleared the foul line,\nrammed down the bucket into the now collapsed well, meaning that the\nburied harpooneer should grasp it, and so be hoisted out.\n\n“In heaven’s name, man,” cried Stubb,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 5102, "position": 5102, "text": ".\n\n“In heaven’s name, man,” cried Stubb, “are you ramming home a cartridge\nthere?—Avast! How will that help him; jamming that iron-bound bucket on\ntop of his head? Avast", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 5103, "position": 5103, "text": "jamming that iron-bound bucket on\ntop of his head? Avast, will ye!”\n\n“Stand clear of the tackle!” cried a voice like the bursting of a\nrocket.\n\nAlmost in the same instant, with a thunder-boom,", "labels": {"50": 37, "100": 86, "250": 145, "500": 180, "1000": 959, "2000": 160}}, {"id": 5104, "position": 5104, "text": "a\nrocket.\n\nAlmost in the same instant, with a thunder-boom, the enormous mass\ndropped into the sea, like Niagara’s Table-Rock into the whirlpool; the\nsuddenly relieved hull rolled away from it, to far down her", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 5105, "position": 5105, "text": "ool; the\nsuddenly relieved hull rolled away from it, to far down her glittering\ncopper; and all caught their breath, as half swinging—now over the\nsailors’ heads, and now over the water—Daggoo, through a thick mist of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5106, "position": 5106, "text": "and now over the water—Daggoo, through a thick mist of\nspray, was dimly beheld clinging to the pendulous tackles, while poor,\nburied-alive Tashtego was sinking utterly down to the bottom of the\nsea!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5107, "position": 5107, "text": "Tashtego was sinking utterly down to the bottom of the\nsea! But hardly had the blinding vapor cleared away, when a naked\nfigure with a boarding-sword in his hand, was for one swift moment seen\nhovering over the bulwarks", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 5108, "position": 5108, "text": "hand, was for one swift moment seen\nhovering over the bulwarks. The next, a loud splash announced that my\nbrave Queequeg had dived to the rescue. One packed rush was made to the\nside, and every eye counted", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5109, "position": 5109, "text": "rescue. One packed rush was made to the\nside, and every eye counted every ripple, as moment followed moment,\nand no sign of either the sinker or the diver could be seen. Some hands\nnow jumped into a boat alongside, and pushed a", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 5110, "position": 5110, "text": "be seen. Some hands\nnow jumped into a boat alongside, and pushed a little off from the\nship.\n\n“Ha! ha!” cried Daggoo, all at once, from his now quiet, swinging perch\noverhead; and looking further off from", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5111, "position": 5111, "text": ", from his now quiet, swinging perch\noverhead; and looking further off from the side, we saw an arm thrust\nupright from the blue waves; a sight strange to see, as an arm thrust\nforth from the grass over a grave.", "labels": {"50": 16, "100": 73, "250": 53, "500": 162, "1000": 35, "2000": 1735}}, {"id": 5112, "position": 5112, "text": "as an arm thrust\nforth from the grass over a grave.\n\n“Both! both!—it is both!”—cried Daggoo again with a joyful shout; and\nsoon after, Queequeg was seen boldly striking out with", "labels": {"50": 23, "100": 88, "250": 219, "500": 180, "1000": 345, "2000": 40}}, {"id": 5113, "position": 5113, "text": "and\nsoon after, Queequeg was seen boldly striking out with one hand, and\nwith the other clutching the long hair of the Indian. Drawn into the\nwaiting boat, they were quickly brought to the deck; but Tashtego was", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5114, "position": 5114, "text": ", they were quickly brought to the deck; but Tashtego was\nlong in coming to, and Queequeg did not look very brisk.\n\nNow, how had this noble rescue been accomplished? Why, diving after the\nslowly descending head,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5115, "position": 5115, "text": "this noble rescue been accomplished? Why, diving after the\nslowly descending head, Queequeg with his keen sword had made side\nlunges near its bottom, so as to scuttle a large hole there; then\ndropping his sword, had thrust", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5116, "position": 5116, "text": "scuttle a large hole there; then\ndropping his sword, had thrust his long arm far inwards and upwards,\nand so hauled out poor Tash by the head. He averred, that upon first\nthrusting in for him, a leg was", "labels": {"50": 40, "100": 83, "250": 170, "500": 60, "1000": 946, "2000": 203}}, {"id": 5117, "position": 5117, "text": "He averred, that upon first\nthrusting in for him, a leg was presented; but well knowing that that\nwas not as it ought to be, and might occasion great trouble;—he had\nthrust back the leg, and by a dexterous he", "labels": {"50": 23, "100": 17, "250": 160, "500": 358, "1000": 485, "2000": 1002}}, {"id": 5118, "position": 5118, "text": ";—he had\nthrust back the leg, and by a dexterous heave and toss, had wrought a\nsomerset upon the Indian; so that with the next trial, he came forth in\nthe good old way—head foremost", "labels": {"50": 23, "100": 86, "250": 145, "500": 180, "1000": 680, "2000": 40}}, {"id": 5119, "position": 5119, "text": "came forth in\nthe good old way—head foremost. As for the great head itself, that was\ndoing as well as could be expected.\n\nAnd thus, through the courage and great skill in obstetrics of\nQueequeg, the deliverance", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5120, "position": 5120, "text": "great skill in obstetrics of\nQueequeg, the deliverance, or rather, delivery of Tashtego, was\nsuccessfully accomplished, in the teeth, too, of the most untoward and\napparently hopeless impediments; which", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5121, "position": 5121, "text": ", of the most untoward and\napparently hopeless impediments; which is a lesson by no means to be\nforgotten. Midwifery should be taught in the same course with fencing\nand boxing, riding and rowing.", "labels": {"50": 24, "100": 61, "250": 109, "500": 130, "1000": 685, "2000": 1430}}, {"id": 5122, "position": 5122, "text": "with fencing\nand boxing, riding and rowing.\n\nI know that this queer adventure of the Gay-Header’s will be sure to\nseem incredible to some landsmen, though they themselves may have\neither seen or heard of some one’s falling into a", "labels": {"50": 31, "100": 28, "250": 175, "500": 130, "1000": 629, "2000": 834}}, {"id": 5123, "position": 5123, "text": "themselves may have\neither seen or heard of some one’s falling into a cistern ashore; an\naccident which not seldom happens, and with much less reason too than\nthe Indian’s, considering the exceeding slipperiness of the curb of the\nSperm", "labels": {"50": 10, "100": 75, "250": 30, "500": 333, "1000": 344, "2000": 374}}, {"id": 5124, "position": 5124, "text": "’s, considering the exceeding slipperiness of the curb of the\nSperm Whale’s well.\n\nBut, peradventure, it may be sagaciously urged, how is this? We thought\nthe tissued, infiltrated head of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5125, "position": 5125, "text": "how is this? We thought\nthe tissued, infiltrated head of the Sperm Whale, was the lightest and\nmost corky part about him; and yet thou makest it sink in an element of\na far greater specific gravity than itself", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5126, "position": 5126, "text": "it sink in an element of\na far greater specific gravity than itself. We have thee there. Not at\nall, but I have ye; for at the time poor Tash fell in, the case had\nbeen nearly emptied of its lighter contents, leaving", "labels": {"50": 41, "100": 26, "250": 193, "500": 498, "1000": 230, "2000": 1003}}, {"id": 5127, "position": 5127, "text": "fell in, the case had\nbeen nearly emptied of its lighter contents, leaving little but the\ndense tendinous wall of the well—a double welded, hammered substance,\nas I have before said, much heavier than the sea water, and a lump", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 723, "2000": 489}}, {"id": 5128, "position": 5128, "text": "I have before said, much heavier than the sea water, and a lump of\nwhich sinks in it like lead almost. But the tendency to rapid sinking\nin this substance was in the present instance materially counteracted\nby the other parts of the head", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1817}}, {"id": 5129, "position": 5129, "text": "the present instance materially counteracted\nby the other parts of the head remaining undetached from it, so that it\nsank very slowly and deliberately indeed, affording Queequeg a fair\nchance for performing his agile obstetrics on the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5130, "position": 5130, "text": "equeg a fair\nchance for performing his agile obstetrics on the run, as you may say.\nYes, it was a running delivery, so it was.\n\nNow, had Tashtego perished in that head, it had been a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5131, "position": 5131, "text": ", had Tashtego perished in that head, it had been a very precious\nperishing; smothered in the very whitest and daintiest of fragrant\nspermaceti; coffined, hearsed, and tombed in the", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 19, "2000": 1620}}, {"id": 5132, "position": 5132, "text": "spermaceti; coffined, hearsed, and tombed in the secret inner chamber\nand sanctum sanctorum of the whale. Only one sweeter end can readily be\nrecalled—the delicious death of an Ohio honey-hunter, who seeking", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5133, "position": 5133, "text": "be\nrecalled—the delicious death of an Ohio honey-hunter, who seeking honey\nin the crotch of a hollow tree, found such exceeding store of it, that\nleaning too far over, it sucked him in, so that he died embalmed", "labels": {"50": 3, "100": 24, "250": 213, "500": 255, "1000": 403, "2000": 831}}, {"id": 5134, "position": 5134, "text": "over, it sucked him in, so that he died embalmed. How\nmany, think ye, have likewise fallen into Plato’s honey head, and\nsweetly perished there?\n\n\nCHAPTER 79. The Prairie.", "labels": {"50": 44, "100": 37, "250": 143, "500": 130, "1000": 220, "2000": 1873}}, {"id": 5135, "position": 5135, "text": "?\n\n\nCHAPTER 79. The Prairie.\n\nTo scan the lines of his face, or feel the bumps on the head of this\nLeviathan; this is a thing which no Physiognomist or Phrenologist has\nas yet undertaken", "labels": {"50": 31, "100": 20, "250": 49, "500": 224, "1000": 90, "2000": 478}}, {"id": 5136, "position": 5136, "text": "iognomist or Phrenologist has\nas yet undertaken. Such an enterprise would seem almost as hopeful as\nfor Lavater to have scrutinized the wrinkles on the Rock of Gibraltar,\nor for Gall to have mounted a ladder and manipulated the", "labels": {"50": 10, "100": 71, "250": 129, "500": 395, "1000": 134, "2000": 506}}, {"id": 5137, "position": 5137, "text": "Rock of Gibraltar,\nor for Gall to have mounted a ladder and manipulated the Dome of the\nPantheon. Still, in that famous work of his, Lavater not only treats of\nthe various faces of men, but also attentively studies the faces of", "labels": {"50": 17, "100": 16, "250": 128, "500": 398, "1000": 799, "2000": 973}}, {"id": 5138, "position": 5138, "text": "the various faces of men, but also attentively studies the faces of\nhorses, birds, serpents, and fish; and dwells in detail upon the\nmodifications of expression discernible therein. Nor have Gall and his\ndisciple Spurzheim", "labels": {"50": 10, "100": 54, "250": 211, "500": 490, "1000": 878, "2000": 565}}, {"id": 5139, "position": 5139, "text": "discernible therein. Nor have Gall and his\ndisciple Spurzheim failed to throw out some hints touching the\nphrenological characteristics of other beings than man. Therefore,\nthough I am but ill qualified for a pioneer, in the application of\nthese", "labels": {"50": 10, "100": 71, "250": 129, "500": 111, "1000": 519, "2000": 604}}, {"id": 5140, "position": 5140, "text": "though I am but ill qualified for a pioneer, in the application of\nthese two semi-sciences to the whale, I will do my endeavor. I try all\nthings; I achieve what I can.\n\nPhysiognomically regarded, the Sperm", "labels": {"50": 3, "100": 70, "250": 14, "500": 72, "1000": 134, "2000": 1620}}, {"id": 5141, "position": 5141, "text": "achieve what I can.\n\nPhysiognomically regarded, the Sperm Whale is an anomalous creature. He\nhas no proper nose. And since the nose is the central and most\nconspicuous of the features; and since it perhaps most modifies", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5142, "position": 5142, "text": "central and most\nconspicuous of the features; and since it perhaps most modifies and\nfinally controls their combined expression; hence it would seem that\nits entire absence, as an external appendage, must very largely affect\nthe countenance of the whale", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 634, "2000": 612}}, {"id": 5143, "position": 5143, "text": "endage, must very largely affect\nthe countenance of the whale. For as in landscape gardening, a spire,\ncupola, monument, or tower of some sort, is deemed almost indispensable\nto the completion of the scene; so", "labels": {"50": 48, "100": 24, "250": 249, "500": 72, "1000": 878, "2000": 1620}}, {"id": 5144, "position": 5144, "text": "is deemed almost indispensable\nto the completion of the scene; so no face can be physiognomically in\nkeeping without the elevated open-work belfry of the nose. Dash the\nnose from Phidias’s marble", "labels": {"50": 10, "100": 71, "250": 196, "500": 483, "1000": 878, "2000": 565}}, {"id": 5145, "position": 5145, "text": "y of the nose. Dash the\nnose from Phidias’s marble Jove, and what a sorry remainder!\nNevertheless, Leviathan is of so mighty a magnitude, all his\nproportions are so stately, that the same deficiency which in the", "labels": {"50": 9, "100": 26, "250": 30, "500": 498, "1000": 849, "2000": 39}}, {"id": 5146, "position": 5146, "text": "all his\nproportions are so stately, that the same deficiency which in the\nsculptured Jove were hideous, in him is no blemish at all. Nay, it is\nan added grandeur. A nose to the whale would have been imp", "labels": {"50": 3, "100": 70, "250": 196, "500": 72, "1000": 878, "2000": 1620}}, {"id": 5147, "position": 5147, "text": "is\nan added grandeur. A nose to the whale would have been impertinent. As\non your physiognomical voyage you sail round his vast head in your\njolly-boat, your noble conceptions of him are never insulted", "labels": {"50": 31, "100": 7, "250": 69, "500": 453, "1000": 15, "2000": 1620}}, {"id": 5148, "position": 5148, "text": "in your\njolly-boat, your noble conceptions of him are never insulted by the\nreflection that he has a nose to be pulled. A pestilent conceit, which\nso often will insist upon obtruding even when beholding the might", "labels": {"50": 31, "100": 75, "250": 193, "500": 496, "1000": 637, "2000": 1394}}, {"id": 5149, "position": 5149, "text": "which\nso often will insist upon obtruding even when beholding the mightiest\nroyal beadle on his throne.\n\nIn some particulars, perhaps the most imposing physiognomical view to\nbe had of the Sperm Whale, is that of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5150, "position": 5150, "text": "gnomical view to\nbe had of the Sperm Whale, is that of the full front of his head. This\naspect is sublime.\n\nIn thought, a fine human brow is like the East when troubled with the\nmorning", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5151, "position": 5151, "text": "like the East when troubled with the\nmorning. In the repose of the pasture, the curled brow of the bull has\na touch of the grand in it. Pushing heavy cannon up mountain defiles,\nthe elephant’s brow is majestic", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 437, "2000": 709}}, {"id": 5152, "position": 5152, "text": "up mountain defiles,\nthe elephant’s brow is majestic. Human or animal, the mystical brow is\nas that great golden seal affixed by the German emperors to their\ndecrees. It signifies—“God: done this day by my hand.", "labels": {"50": 32, "100": 81, "250": 211, "500": 380, "1000": 236, "2000": 1030}}, {"id": 5153, "position": 5153, "text": "decrees. It signifies—“God: done this day by my hand.” But in most\ncreatures, nay in man himself, very often the brow is but a mere strip\nof alpine land lying along the snow line", "labels": {"50": 48, "100": 20, "250": 192, "500": 423, "1000": 816, "2000": 326}}, {"id": 5154, "position": 5154, "text": "of alpine land lying along the snow line. Few are the foreheads which\nlike Shakespeare’s or Melancthon’s rise so high, and descend so low,\nthat the eyes themselves seem clear, eternal, tideless mountain lakes;\nand", "labels": {"50": 16, "100": 73, "250": 133, "500": 334, "1000": 747, "2000": 523}}, {"id": 5155, "position": 5155, "text": "that the eyes themselves seem clear, eternal, tideless mountain lakes;\nand all above them in the forehead’s wrinkles, you seem to track the\nantlered thoughts descending there to drink, as the Highland hunters\ntrack the snow prints of the", "labels": {"50": 16, "100": 20, "250": 133, "500": 414, "1000": 747, "2000": 709}}, {"id": 5156, "position": 5156, "text": "descending there to drink, as the Highland hunters\ntrack the snow prints of the deer. But in the great Sperm Whale, this\nhigh and mighty god-like dignity inherent in the brow is so immensely\namplified, that gazing on it, in that full front", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5157, "position": 5157, "text": "brow is so immensely\namplified, that gazing on it, in that full front view, you feel the\nDeity and the dread powers more forcibly than in beholding any other\nobject in living nature. For you see no one point precisely; not one\ndistinct feature", "labels": {"50": 48, "100": 27, "250": 223, "500": 339, "1000": 832, "2000": 180}}, {"id": 5158, "position": 5158, "text": "living nature. For you see no one point precisely; not one\ndistinct feature is revealed; no nose, eyes, ears, or mouth; no face;\nhe has none, proper; nothing but that one broad firmament of a\nforehead, pleated", "labels": {"50": 31, "100": 16, "250": 196, "500": 483, "1000": 212, "2000": 1686}}, {"id": 5159, "position": 5159, "text": "proper; nothing but that one broad firmament of a\nforehead, pleated with riddles; dumbly lowering with the doom of boats,\nand ships, and men. Nor, in profile, does this wondrous brow diminish;\nthough", "labels": {"50": 31, "100": 75, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 5160, "position": 5160, "text": ", in profile, does this wondrous brow diminish;\nthough that way viewed its grandeur does not domineer upon you so. In\nprofile, you plainly perceive that horizontal, semi-crescentic\ndepression in the forehead’s middle", "labels": {"50": 31, "100": 71, "250": 13, "500": 483, "1000": 845, "2000": 955}}, {"id": 5161, "position": 5161, "text": "perceive that horizontal, semi-crescentic\ndepression in the forehead’s middle, which, in man, is Lavater’s mark\nof genius.\n\nBut how? Genius in the Sperm Whale? Has the Sperm Whale ever written a\nbook, spoken a", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5162, "position": 5162, "text": "the Sperm Whale? Has the Sperm Whale ever written a\nbook, spoken a speech? No, his great genius is declared in his doing\nnothing particular to prove it. It is moreover declared in his\npyramidical silence", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5163, "position": 5163, "text": "moreover declared in his\npyramidical silence. And this reminds me that had the great Sperm Whale\nbeen known to the young Orient World, he would have been deified by\ntheir child-magian thoughts. They deified the crocodile of the Nile,\nbecause", "labels": {"50": 3, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 199}}, {"id": 5164, "position": 5164, "text": "-magian thoughts. They deified the crocodile of the Nile,\nbecause the crocodile is tongueless; and the Sperm Whale has no tongue,\nor at least it is so exceedingly small, as to be incapable of\nprotrusion", "labels": {"50": 10, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 215}}, {"id": 5165, "position": 5165, "text": "exceedingly small, as to be incapable of\nprotrusion. If hereafter any highly cultured, poetical nation shall\nlure back to their birth-right, the merry May-day gods of old; and\nlivingly enthrone them", "labels": {"50": 17, "100": 68, "250": 193, "500": 449, "1000": 849, "2000": 1993}}, {"id": 5166, "position": 5166, "text": "merry May-day gods of old; and\nlivingly enthrone them again in the now egotistical sky; in the now\nunhaunted hill; then be sure, exalted to Jove’s high seat, the great", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 118, "2000": 523}}, {"id": 5167, "position": 5167, "text": "sure, exalted to Jove’s high seat, the great\nSperm Whale shall lord it.\n\nChampollion deciphered the wrinkled granite hieroglyphics. But there is\nno Champollion to decipher the Egypt of", "labels": {"50": 9, "100": 26, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5168, "position": 5168, "text": ". But there is\nno Champollion to decipher the Egypt of every man’s and every being’s\nface. Physiognomy, like every other human science, is but a passing\nfable", "labels": {"50": 10, "100": 71, "250": 232, "500": 273, "1000": 845, "2000": 753}}, {"id": 5169, "position": 5169, "text": "human science, is but a passing\nfable. If then, Sir William Jones, who read in thirty languages, could\nnot read the simplest peasant’s face in its profounder and more subtle\nmeanings, how may unlettered Ishmael hope to", "labels": {"50": 31, "100": 7, "250": 193, "500": 453, "1000": 355, "2000": 1394}}, {"id": 5170, "position": 5170, "text": "and more subtle\nmeanings, how may unlettered Ishmael hope to read the awful Chaldee of\nthe Sperm Whale’s brow? I but put that brow before you. Read it if you\ncan.\n\n\nCHAPTER 80. The Nut.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5171, "position": 5171, "text": "you. Read it if you\ncan.\n\n\nCHAPTER 80. The Nut.\n\nIf the Sperm Whale be physiognomically a Sphinx, to the phrenologist\nhis brain seems that geometrical circle which it is impossible to\nsquare.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5172, "position": 5172, "text": "seems that geometrical circle which it is impossible to\nsquare.\n\nIn the full-grown creature the skull will measure at least twenty feet\nin length. Unhinge the lower jaw, and the side view of this skull is as\nthe side of a moderately", "labels": {"50": 12, "100": 24, "250": 52, "500": 288, "1000": 825, "2000": 145}}, {"id": 5173, "position": 5173, "text": ", and the side view of this skull is as\nthe side of a moderately inclined plane resting throughout on a level\nbase. But in life—as we have elsewhere seen—this inclined plane is\nangularly filled up, and almost squared by the enormous super", "labels": {"50": 3, "100": 70, "250": 234, "500": 77, "1000": 478, "2000": 823}}, {"id": 5174, "position": 5174, "text": "inclined plane is\nangularly filled up, and almost squared by the enormous superincumbent\nmass of the junk and sperm. At the high end the skull forms a crater to\nbed that part of the mass; while under the long floor of this", "labels": {"50": 3, "100": 70, "250": 234, "500": 108, "1000": 634, "2000": 1998}}, {"id": 5175, "position": 5175, "text": "to\nbed that part of the mass; while under the long floor of this crater—in\nanother cavity seldom exceeding ten inches in length and as many in\ndepth—reposes the mere handful of this monster’s brain", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5176, "position": 5176, "text": "mere handful of this monster’s brain. The brain is at\nleast twenty feet from his apparent forehead in life; it is hidden away\nbehind its vast outworks, like the innermost citadel within the\namplified fortifications of Quebec", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 145}}, {"id": 5177, "position": 5177, "text": "innermost citadel within the\namplified fortifications of Quebec. So like a choice casket is it\nsecreted in him, that I have known some whalemen who peremptorily deny\nthat the Sperm Whale has any other brain than that palpable semb", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5178, "position": 5178, "text": "that the Sperm Whale has any other brain than that palpable semblance\nof one formed by the cubic-yards of his sperm magazine. Lying in\nstrange folds, courses, and convolutions, to their apprehensions, it\nseems more", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5179, "position": 5179, "text": ", and convolutions, to their apprehensions, it\nseems more in keeping with the idea of his general might to regard that\nmystic part of him as the seat of his intelligence.\n\nIt is plain, then, that phrenologically the", "labels": {"50": 10, "100": 71, "250": 210, "500": 41, "1000": 453, "2000": 998}}, {"id": 5180, "position": 5180, "text": "his intelligence.\n\nIt is plain, then, that phrenologically the head of this Leviathan, in\nthe creature’s living intact state, is an entire delusion. As for his\ntrue brain, you can then see no indications of it", "labels": {"50": 10, "100": 71, "250": 33, "500": 136, "1000": 134, "2000": 458}}, {"id": 5181, "position": 5181, "text": ". As for his\ntrue brain, you can then see no indications of it, nor feel any. The\nwhale, like all things that are mighty, wears a false brow to the\ncommon world.\n\nIf you unload his skull of its spermy heap", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5182, "position": 5182, "text": "the\ncommon world.\n\nIf you unload his skull of its spermy heaps and then take a rear view\nof its rear end, which is the high end, you will be struck by its\nresemblance to the human skull, beheld in the same", "labels": {"50": 31, "100": 24, "250": 49, "500": 403, "1000": 134, "2000": 1620}}, {"id": 5183, "position": 5183, "text": "be struck by its\nresemblance to the human skull, beheld in the same situation, and from\nthe same point of view. Indeed, place this reversed skull (scaled down\nto the human magnitude) among a plate of men’s skulls, and you", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 845, "2000": 313}}, {"id": 5184, "position": 5184, "text": "the human magnitude) among a plate of men’s skulls, and you would\ninvoluntarily confound it with them; and remarking the depressions on\none part of its summit, in phrenological phrase you would say—", "labels": {"50": 48, "100": 27, "250": 90, "500": 339, "1000": 619, "2000": 168}}, {"id": 5185, "position": 5185, "text": "one part of its summit, in phrenological phrase you would say—This man\nhad no self-esteem, and no veneration. And by those negations,\nconsidered along with the affirmative fact of his prodigious bulk and", "labels": {"50": 33, "100": 4, "250": 114, "500": 341, "1000": 649, "2000": 218}}, {"id": 5186, "position": 5186, "text": ",\nconsidered along with the affirmative fact of his prodigious bulk and\npower, you can best form to yourself the truest, though not the most\nexhilarating conception of what the most exalted potency is.", "labels": {"50": 31, "100": 75, "250": 13, "500": 236, "1000": 355, "2000": 1417}}, {"id": 5187, "position": 5187, "text": "of what the most exalted potency is.\n\nBut if from the comparative dimensions of the whale’s proper brain, you\ndeem it incapable of being adequately charted, then I have another idea\nfor you", "labels": {"50": 3, "100": 85, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5188, "position": 5188, "text": "then I have another idea\nfor you. If you attentively regard almost any quadruped’s spine, you\nwill be struck with the resemblance of its vertebræ to a strung\nnecklace of dwarfed skulls, all bearing rudimental", "labels": {"50": 3, "100": 70, "250": 14, "500": 403, "1000": 634, "2000": 313}}, {"id": 5189, "position": 5189, "text": "æ to a strung\nnecklace of dwarfed skulls, all bearing rudimental resemblance to the\nskull proper. It is a German conceit, that the vertebræ are absolutely\nundeveloped skulls. But the curious external resemblance, I take it the", "labels": {"50": 48, "100": 27, "250": 249, "500": 77, "1000": 478, "2000": 823}}, {"id": 5190, "position": 5190, "text": "are absolutely\nundeveloped skulls. But the curious external resemblance, I take it the\nGermans were not the first men to perceive. A foreign friend once\npointed it out to me, in the skeleton of a foe he had slain, and with\nthe vertebr", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 478, "2000": 823}}, {"id": 5191, "position": 5191, "text": "the skeleton of a foe he had slain, and with\nthe vertebræ of which he was inlaying, in a sort of basso-relievo, the\nbeaked prow of his canoe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5192, "position": 5192, "text": "the\nbeaked prow of his canoe. Now, I consider that the phrenologists have\nomitted an important thing in not pushing their investigations from the\ncerebellum through the spinal canal. For I believe that much of a man’s\ncharacter", "labels": {"50": 3, "100": 24, "250": 213, "500": 403, "1000": 634, "2000": 313}}, {"id": 5193, "position": 5193, "text": "the spinal canal. For I believe that much of a man’s\ncharacter will be found betokened in his backbone. I would rather feel\nyour spine than your skull, whoever you are. A thin joist of a spine\nnever yet upheld a", "labels": {"50": 31, "100": 20, "250": 132, "500": 388, "1000": 727, "2000": 887}}, {"id": 5194, "position": 5194, "text": "whoever you are. A thin joist of a spine\nnever yet upheld a full and noble soul. I rejoice in my spine, as in\nthe firm audacious staff of that flag which I fling half out to the\nworld.", "labels": {"50": 16, "100": 20, "250": 15, "500": 276, "1000": 174, "2000": 523}}, {"id": 5195, "position": 5195, "text": "staff of that flag which I fling half out to the\nworld.\n\nApply this spinal branch of phrenology to the Sperm Whale. His cranial\ncavity is continuous with the first neck-vertebra; and in that vertebra\nthe bottom of", "labels": {"50": 3, "100": 70, "250": 14, "500": 403, "1000": 634, "2000": 313}}, {"id": 5196, "position": 5196, "text": "neck-vertebra; and in that vertebra\nthe bottom of the spinal canal will measure ten inches across, being\neight in height, and of a triangular figure with the base downwards. As\nit passes through the remaining vertebræ the", "labels": {"50": 3, "100": 70, "250": 14, "500": 403, "1000": 634, "2000": 313}}, {"id": 5197, "position": 5197, "text": "the base downwards. As\nit passes through the remaining vertebræ the canal tapers in size, but\nfor a considerable distance remains of large capacity. Now, of course,\nthis canal is filled with much the same strangely fibrous substance—", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 294, "2000": 268}}, {"id": 5198, "position": 5198, "text": ",\nthis canal is filled with much the same strangely fibrous substance—the\nspinal cord—as the brain; and directly communicates with the brain. And\nwhat is still more, for many feet after emerging from the brain’s\ncavity, the", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 845, "2000": 268}}, {"id": 5199, "position": 5199, "text": "more, for many feet after emerging from the brain’s\ncavity, the spinal cord remains of an undecreasing girth, almost equal\nto that of the brain. Under all these circumstances, would it be\nunreasonable to survey and map out the", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 634, "2000": 313}}, {"id": 5200, "position": 5200, "text": "Under all these circumstances, would it be\nunreasonable to survey and map out the whale’s spine phrenologically?\nFor, viewed in this light, the wonderful comparative smallness of his\nbrain proper is more than compensated by the wonderful comparative\nmagnitude of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5201, "position": 5201, "text": "ness of his\nbrain proper is more than compensated by the wonderful comparative\nmagnitude of his spinal cord.\n\nBut leaving this hint to operate as it may with the phrenologists, I\nwould merely assume the spinal theory for a moment, in reference to the\nSperm", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 634, "2000": 511}}, {"id": 5202, "position": 5202, "text": "would merely assume the spinal theory for a moment, in reference to the\nSperm Whale’s hump. This august hump, if I mistake not, rises over one\nof the larger vertebræ, and is, therefore, in some sort", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5203, "position": 5203, "text": "the larger vertebræ, and is, therefore, in some sort, the outer\nconvex mould of it. From its relative situation then, I should call\nthis high hump the organ of firmness or indomitableness in the Sperm", "labels": {"50": 3, "100": 70, "250": 30, "500": 403, "1000": 634, "2000": 268}}, {"id": 5204, "position": 5204, "text": "hump the organ of firmness or indomitableness in the Sperm\nWhale. And that the great monster is indomitable, you will yet have\nreason to know.\n\n\nCHAPTER 81. The Pequod Meets The Virgin.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5205, "position": 5205, "text": "CHAPTER 81. The Pequod Meets The Virgin.\n\nThe predestinated day arrived, and we duly met the ship Jungfrau,\nDerick De Deer, master, of Bremen.\n\nAt one time the greatest whaling people in the world,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5206, "position": 5206, "text": ", of Bremen.\n\nAt one time the greatest whaling people in the world, the Dutch and\nGermans are now among the least; but here and there at very wide\nintervals of latitude and longitude, you still occasionally meet with\ntheir flag in the Pacific.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5207, "position": 5207, "text": "and longitude, you still occasionally meet with\ntheir flag in the Pacific.\n\nFor some reason, the Jungfrau seemed quite eager to pay her respects.\nWhile yet some distance from the Pequod, she rounded to, and dropping a\nboat, her", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5208, "position": 5208, "text": "the Pequod, she rounded to, and dropping a\nboat, her captain was impelled towards us, impatiently standing in the\nbows instead of the stern.\n\n“What has he in his hand there?” cried Starbuck, pointing to something\nwaving", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5209, "position": 5209, "text": "he in his hand there?” cried Starbuck, pointing to something\nwavingly held by the German. “Impossible!—a lamp-feeder!”\n\n“Not that,” said Stubb, “no, no, it’s a coffee", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 1620}}, {"id": 5210, "position": 5210, "text": "” said Stubb, “no, no, it’s a coffee-pot, Mr. Starbuck; he’s\ncoming off to make us our coffee, is the Yarman; don’t you see that big\ntin can there alongside", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 1620}}, {"id": 5211, "position": 5211, "text": "the Yarman; don’t you see that big\ntin can there alongside of him?—that’s his boiling water. Oh! he’s all\nright, is the Yarman.”\n\n“Go along with you,” cried Flask", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 5212, "position": 5212, "text": "the Yarman.”\n\n“Go along with you,” cried Flask, “it’s a lamp-feeder and an oil-can.\nHe’s out of oil, and has come a-begging.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 54, "2000": 1620}}, {"id": 5213, "position": 5213, "text": "oil, and has come a-begging.”\n\nHowever curious it may seem for an oil-ship to be borrowing oil on the\nwhale-ground, and however much it may invertedly contradict the old\nproverb about carrying coals to Newcastle,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5214, "position": 5214, "text": "invertedly contradict the old\nproverb about carrying coals to Newcastle, yet sometimes such a thing\nreally happens; and in the present case Captain Derick De Deer did\nindubitably conduct a lamp-feeder as Flask did declare.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 5215, "position": 5215, "text": "ubitably conduct a lamp-feeder as Flask did declare.\n\nAs he mounted the deck, Ahab abruptly accosted him, without at all\nheeding what he had in his hand; but in his broken lingo, the German\nsoon", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5216, "position": 5216, "text": "had in his hand; but in his broken lingo, the German\nsoon evinced his complete ignorance of the White Whale; immediately\nturning the conversation to his lamp-feeder and oil can, with some\nremarks touching his having to turn into his ham", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1014}}, {"id": 5217, "position": 5217, "text": "and oil can, with some\nremarks touching his having to turn into his hammock at night in\nprofound darkness—his last drop of Bremen oil being gone, and not a\nsingle flying-fish yet captured to supply the deficiency; concluding by\nhinting", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 692, "2000": 447}}, {"id": 5218, "position": 5218, "text": "single flying-fish yet captured to supply the deficiency; concluding by\nhinting that his ship was indeed what in the Fishery is technically\ncalled a _clean_ one (that is, an empty one), well deserving the name\nof Jungfrau", "labels": {"50": 45, "100": 64, "250": 138, "500": 252, "1000": 327, "2000": 1620}}, {"id": 5219, "position": 5219, "text": ", an empty one), well deserving the name\nof Jungfrau or the Virgin.\n\nHis necessities supplied, Derick departed; but he had not gained his\nship’s side, when whales were almost simultaneously raised from the\nmast-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5220, "position": 5220, "text": "ship’s side, when whales were almost simultaneously raised from the\nmast-heads of both vessels; and so eager for the chase was Derick, that\nwithout pausing to put his oil-can and lamp-feeder aboard, he slewed\nround", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5221, "position": 5221, "text": "his oil-can and lamp-feeder aboard, he slewed\nround his boat and made after the leviathan lamp-feeders.\n\nNow, the game having risen to leeward, he and the other three German\nboats that soon followed him,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 5222, "position": 5222, "text": "leeward, he and the other three German\nboats that soon followed him, had considerably the start of the\nPequod’s keels. There were eight whales, an average pod. Aware of their\ndanger, they were going all abreast", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5223, "position": 5223, "text": "average pod. Aware of their\ndanger, they were going all abreast with great speed straight before\nthe wind, rubbing their flanks as closely as so many spans of horses in\nharness. They left a great, wide wake, as though continually unroll", "labels": {"50": 12, "100": 55, "250": 95, "500": 435, "1000": 129, "2000": 114}}, {"id": 5224, "position": 5224, "text": "harness. They left a great, wide wake, as though continually unrolling\na great wide parchment upon the sea.\n\nFull in this rapid wake, and many fathoms in the rear, swam a huge,\nhumped old bull, which by", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5225, "position": 5225, "text": "in the rear, swam a huge,\nhumped old bull, which by his comparatively slow progress, as well as\nby the unusual yellowish incrustations overgrowing him, seemed\nafflicted with the jaundice, or some other in", "labels": {"50": 12, "100": 93, "250": 52, "500": 435, "1000": 653, "2000": 1652}}, {"id": 5226, "position": 5226, "text": ", seemed\nafflicted with the jaundice, or some other infirmity. Whether this\nwhale belonged to the pod in advance, seemed questionable; for it is\nnot customary for such venerable leviathans to be at all social", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5227, "position": 5227, "text": "customary for such venerable leviathans to be at all social.\nNevertheless, he stuck to their wake, though indeed their back water\nmust have retarded him, because the white-bone or swell at his broad\nmuzzle was a dashed one, like", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5228, "position": 5228, "text": "white-bone or swell at his broad\nmuzzle was a dashed one, like the swell formed when two hostile\ncurrents meet. His spout was short, slow, and laborious; coming forth\nwith a choking sort of gush, and spending itself in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5229, "position": 5229, "text": "; coming forth\nwith a choking sort of gush, and spending itself in torn shreds,\nfollowed by strange subterranean commotions in him, which seemed to\nhave egress at his other buried extremity, causing the waters behind\nhim to", "labels": {"50": 12, "100": 55, "250": 52, "500": 72, "1000": 129, "2000": 1620}}, {"id": 5230, "position": 5230, "text": "ss at his other buried extremity, causing the waters behind\nhim to upbubble.\n\n“Who’s got some paregoric?” said Stubb, “he has the stomach-ache, I’m\nafraid", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5231, "position": 5231, "text": "he has the stomach-ache, I’m\nafraid. Lord, think of having half an acre of stomach-ache! Adverse\nwinds are holding mad Christmas in him, boys. It’s the first foul wind\nI ever knew to blow from as", "labels": {"50": 41, "100": 64, "250": 91, "500": 229, "1000": 410, "2000": 1199}}, {"id": 5232, "position": 5232, "text": ". It’s the first foul wind\nI ever knew to blow from astern; but look, did ever whale yaw so\nbefore? it must be, he’s lost his tiller.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 5233, "position": 5233, "text": "lost his tiller.”\n\nAs an overladen Indiaman bearing down the Hindostan coast with a deck\nload of frightened horses, careens, buries, rolls, and wallows on her\nway; so did this old whale heave", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 5234, "position": 5234, "text": ", and wallows on her\nway; so did this old whale heave his aged bulk, and now and then partly\nturning over on his cumbrous rib-ends, expose the cause of his devious\nwake in the unnatural stump of his starboard", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5235, "position": 5235, "text": "expose the cause of his devious\nwake in the unnatural stump of his starboard fin. Whether he had lost\nthat fin in battle, or had been born without it, it were hard to say.\n\n“Only wait a bit, old chap, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 5236, "position": 5236, "text": "hard to say.\n\n“Only wait a bit, old chap, and I’ll give ye a sling for that wounded\narm,” cried cruel Flask, pointing to the whale-line near him.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5237, "position": 5237, "text": "the whale-line near him.\n\n“Mind he don’t sling thee with it,” cried Starbuck. “Give way, or the\nGerman will have him.”\n\nWith one intent all the combined rival boats were pointed for this one\nfish,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5238, "position": 5238, "text": "With one intent all the combined rival boats were pointed for this one\nfish, because not only was he the largest, and therefore the most\nvaluable whale, but he was nearest to them, and the other whales were\ngoing with such great velocity, moreover,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5239, "position": 5239, "text": "them, and the other whales were\ngoing with such great velocity, moreover, as almost to defy pursuit for\nthe time. At this juncture the Pequod’s keels had shot by the three\nGerman boats last lowered; but from the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5240, "position": 5240, "text": "keels had shot by the three\nGerman boats last lowered; but from the great start he had had,\nDerick’s boat still led the chase, though every moment neared by his\nforeign rivals. The only thing they feared, was, that from", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 642, "2000": 974}}, {"id": 5241, "position": 5241, "text": "by his\nforeign rivals. The only thing they feared, was, that from being\nalready so nigh to his mark, he would be enabled to dart his iron\nbefore they could completely overtake and pass him", "labels": {"50": 37, "100": 86, "250": 144, "500": 82, "1000": 836, "2000": 1086}}, {"id": 5242, "position": 5242, "text": "completely overtake and pass him. As for Derick, he\nseemed quite confident that this would be the case, and occasionally\nwith a deriding gesture shook his lamp-feeder at the other boats.", "labels": {"50": 45, "100": 64, "250": 163, "500": 363, "1000": 251, "2000": 1977}}, {"id": 5243, "position": 5243, "text": "feeder at the other boats.\n\n“The ungracious and ungrateful dog!” cried Starbuck; “he mocks and\ndares me with the very poor-box I filled for him not five minutes\nago!”—then in his", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5244, "position": 5244, "text": "box I filled for him not five minutes\nago!”—then in his old intense whisper—“Give way, greyhounds! Dog to\nit!”\n\n“I tell ye what it is, men”—cried Stubb to his crew—“", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5245, "position": 5245, "text": "what it is, men”—cried Stubb to his crew—“it’s against my\nreligion to get mad; but I’d like to eat that villainous\nYarman—Pull—won’t ye? Are ye going to let", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 1620}}, {"id": 5246, "position": 5246, "text": "Yarman—Pull—won’t ye? Are ye going to let that rascal beat ye? Do ye\nlove brandy? A hogshead of brandy, then, to the best man. Come, why\ndon’t some of ye burst", "labels": {"50": 23, "100": 88, "250": 219, "500": 180, "1000": 317, "2000": 1087}}, {"id": 5247, "position": 5247, "text": "to the best man. Come, why\ndon’t some of ye burst a blood-vessel? Who’s that been dropping an\nanchor overboard—we don’t budge an inch—we’re becalmed", "labels": {"50": 23, "100": 88, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 5248, "position": 5248, "text": "an inch—we’re becalmed. Halloo, here’s\ngrass growing in the boat’s bottom—and by the Lord, the mast there’s\nbudding. This won’t do, boys", "labels": {"50": 9, "100": 1, "250": 42, "500": 498, "1000": 50, "2000": 16}}, {"id": 5249, "position": 5249, "text": "budding. This won’t do, boys. Look at that Yarman! The short and long\nof it is, men, will ye spit fire or not?”\n\n“Oh! see the suds he makes!” cried Flask,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5250, "position": 5250, "text": "“Oh! see the suds he makes!” cried Flask, dancing up and down—“What a\nhump—Oh, _do_ pile on the beef—lays like a log! Oh! my lads, _do_\nspring", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5251, "position": 5251, "text": "—lays like a log! Oh! my lads, _do_\nspring—slap-jacks and quahogs for supper, you know, my lads—baked clams\nand muffins—oh, _do_, _do", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 5252, "position": 5252, "text": "clams\nand muffins—oh, _do_, _do_, spring,—he’s a hundred barreller—don’t lose\nhim now—don’t oh, _don’t!_—see that Ya", "labels": {"50": 41, "100": 21, "250": 163, "500": 281, "1000": 54, "2000": 1082}}, {"id": 5253, "position": 5253, "text": "don’t oh, _don’t!_—see that Yarman—Oh, won’t ye pull for your\nduff, my lads—such a sog! such a sogger! Don’t ye love sperm? There\ngoes", "labels": {"50": 41, "100": 21, "250": 193, "500": 498, "1000": 230, "2000": 68}}, {"id": 5254, "position": 5254, "text": "! such a sogger! Don’t ye love sperm? There\ngoes three thousand dollars, men!—a bank!—a whole bank! The bank of\nEngland!—Oh, _do_, _do_, _do!_", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 647, "2000": 421}}, {"id": 5255, "position": 5255, "text": "—Oh, _do_, _do_, _do!_—What’s that Yarman about now?”\n\nAt this moment Derick was in the act of pitching his lamp-feeder at the\nadvancing boats, and also his oil", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 5256, "position": 5256, "text": "of pitching his lamp-feeder at the\nadvancing boats, and also his oil-can; perhaps with the double view of\nretarding his rivals’ way, and at the same time economically\naccelerating his own by the momentary impetus of the backward toss.", "labels": {"50": 45, "100": 64, "250": 70, "500": 202, "1000": 692, "2000": 982}}, {"id": 5257, "position": 5257, "text": "same time economically\naccelerating his own by the momentary impetus of the backward toss.\n\n“The unmannerly Dutch dogger!” cried Stubb. “Pull now, men, like fifty\nthousand line-of-battle-ship loads of red-haired", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 5258, "position": 5258, "text": "like fifty\nthousand line-of-battle-ship loads of red-haired devils. What d’ye say,\nTashtego; are you the man to snap your spine in two-and-twenty pieces\nfor the honor of old Gayhead", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 5259, "position": 5259, "text": "spine in two-and-twenty pieces\nfor the honor of old Gayhead? What d’ye say?”\n\n“I say, pull like god-dam,”—cried the Indian.\n\nFiercely, but evenly incited by the taunts of", "labels": {"50": 37, "100": 6, "250": 174, "500": 24, "1000": 580, "2000": 65}}, {"id": 5260, "position": 5260, "text": "cried the Indian.\n\nFiercely, but evenly incited by the taunts of the German, the Pequod’s\nthree boats now began ranging almost abreast; and, so disposed,\nmomentarily neared him", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 5261, "position": 5261, "text": ", so disposed,\nmomentarily neared him. In that fine, loose, chivalrous attitude of the\nheadsman when drawing near to his prey, the three mates stood up\nproudly, occasionally backing the after oarsman with an exhilarating\ncry of", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 925, "2000": 1620}}, {"id": 5262, "position": 5262, "text": ", occasionally backing the after oarsman with an exhilarating\ncry of, “There she slides, now! Hurrah for the white-ash breeze! Down\nwith the Yarman! Sail over him!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5263, "position": 5263, "text": "the Yarman! Sail over him!”\n\nBut so decided an original start had Derick had, that spite of all\ntheir gallantry, he would have proved the victor in this race, had not\na righteous judgment descended upon him in a crab which caught", "labels": {"50": 22, "100": 78, "250": 229, "500": 336, "1000": 477, "2000": 425}}, {"id": 5264, "position": 5264, "text": "race, had not\na righteous judgment descended upon him in a crab which caught the\nblade of his midship oarsman. While this clumsy lubber was striving to\nfree his white-ash, and while, in consequence, Derick’", "labels": {"50": 9, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 5265, "position": 5265, "text": "free his white-ash, and while, in consequence, Derick’s boat was nigh\nto capsizing, and he thundering away at his men in a mighty rage;—that\nwas a good time for Starbuck, Stubb,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5266, "position": 5266, "text": "rage;—that\nwas a good time for Starbuck, Stubb, and Flask. With a shout, they took\na mortal start forwards, and slantingly ranged up on the German’s\nquarter", "labels": {"50": 16, "100": 73, "250": 133, "500": 498, "1000": 174, "2000": 1003}}, {"id": 5267, "position": 5267, "text": "on the German’s\nquarter. An instant more, and all four boats were diagonically in the\nwhale’s immediate wake, while stretching from them, on both sides, was\nthe foaming swell that he made.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5268, "position": 5268, "text": ", was\nthe foaming swell that he made.\n\nIt was a terrific, most pitiable, and maddening sight. The whale was\nnow going head out, and sending his spout before him in a continual\ntormented jet; while his one poor fin", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5269, "position": 5269, "text": "spout before him in a continual\ntormented jet; while his one poor fin beat his side in an agony of\nfright. Now to this hand, now to that, he yawed in his faltering\nflight, and still at every billow that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5270, "position": 5270, "text": "wed in his faltering\nflight, and still at every billow that he broke, he spasmodically sank\nin the sea, or sideways rolled towards the sky his one beating fin. So\nhave I seen a bird with clipped wing making af", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5271, "position": 5271, "text": "one beating fin. So\nhave I seen a bird with clipped wing making affrighted broken circles\nin the air, vainly striving to escape the piratical hawks. But the bird\nhas a voice, and with plaintive cries will", "labels": {"50": 25, "100": 20, "250": 132, "500": 334, "1000": 727, "2000": 1710}}, {"id": 5272, "position": 5272, "text": "hawks. But the bird\nhas a voice, and with plaintive cries will make known her fear; but the\nfear of this vast dumb brute of the sea, was chained up and enchanted\nin him; he had no voice, save that choking respiration", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 437, "2000": 573}}, {"id": 5273, "position": 5273, "text": "and enchanted\nin him; he had no voice, save that choking respiration through his\nspiracle, and this made the sight of him unspeakably pitiable; while\nstill, in his amazing bulk, portcullis jaw, and om", "labels": {"50": 9, "100": 26, "250": 240, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5274, "position": 5274, "text": "while\nstill, in his amazing bulk, portcullis jaw, and omnipotent tail, there\nwas enough to appal the stoutest man who so pitied.\n\nSeeing now that but a very few moments more would give the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5275, "position": 5275, "text": "Seeing now that but a very few moments more would give the Pequod’s\nboats the advantage, and rather than be thus foiled of his game, Derick\nchose to hazard what to him must have seemed a most unusually long\ndart, er", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5276, "position": 5276, "text": "to hazard what to him must have seemed a most unusually long\ndart, ere the last chance would for ever escape.\n\nBut no sooner did his harpooneer stand up for the stroke, than all\nthree tigers—Queequeg, Tash", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5277, "position": 5277, "text": "the stroke, than all\nthree tigers—Queequeg, Tashtego, Daggoo—instinctively sprang to their\nfeet, and standing in a diagonal row, simultaneously pointed their\nbarbs; and darted over the head of the German harp", "labels": {"50": 12, "100": 55, "250": 52, "500": 435, "1000": 653, "2000": 481}}, {"id": 5278, "position": 5278, "text": "simultaneously pointed their\nbarbs; and darted over the head of the German harpooneer, their three\nNantucket irons entered the whale. Blinding vapors of foam and\nwhite-fire! The three boats, in the first fury of the whale’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5279, "position": 5279, "text": "-fire! The three boats, in the first fury of the whale’s headlong\nrush, bumped the German’s aside with such force, that both Derick and\nhis baffled harpooneer were spilled out, and sailed over by the three", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5280, "position": 5280, "text": "his baffled harpooneer were spilled out, and sailed over by the three\nflying keels.\n\n“Don’t be afraid, my butter-boxes,” cried Stubb, casting a passing\nglance upon them as he shot by; “ye’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5281, "position": 5281, "text": ", casting a passing\nglance upon them as he shot by; “ye’ll be picked up presently—all\nright—I saw some sharks astern—St. Bernard’s dogs, you know—relieve\ndistressed travellers", "labels": {"50": 37, "100": 55, "250": 52, "500": 465, "1000": 204, "2000": 174}}, {"id": 5282, "position": 5282, "text": "s dogs, you know—relieve\ndistressed travellers. Hurrah! this is the way to sail now. Every keel\na sunbeam! Hurrah!—Here we go like three tin kettles at the tail of a\nmad cougar", "labels": {"50": 9, "100": 64, "250": 193, "500": 498, "1000": 327, "2000": 967}}, {"id": 5283, "position": 5283, "text": "go like three tin kettles at the tail of a\nmad cougar! This puts me in mind of fastening to an elephant in a\ntilbury on a plain—makes the wheel-spokes fly, boys, when you fasten to", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 54, "2000": 967}}, {"id": 5284, "position": 5284, "text": "makes the wheel-spokes fly, boys, when you fasten to\nhim that way; and there’s danger of being pitched out too, when you\nstrike a hill. Hurrah! this is the way a fellow feels when he’", "labels": {"50": 30, "100": 4, "250": 114, "500": 341, "1000": 649, "2000": 446}}, {"id": 5285, "position": 5285, "text": ". Hurrah! this is the way a fellow feels when he’s going\nto Davy Jones—all a rush down an endless inclined plane! Hurrah! this\nwhale carries the everlasting mail!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5286, "position": 5286, "text": "whale carries the everlasting mail!”\n\nBut the monster’s run was a brief one. Giving a sudden gasp, he\ntumultuously sounded. With a grating rush, the three lines flew round\nthe loggerheads with such a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5287, "position": 5287, "text": "ating rush, the three lines flew round\nthe loggerheads with such a force as to gouge deep grooves in them;\nwhile so fearful were the harpooneers that this rapid sounding would\nsoon exhaust the lines, that using all their dexterous might", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5288, "position": 5288, "text": "rapid sounding would\nsoon exhaust the lines, that using all their dexterous might, they\ncaught repeated smoking turns with the rope to hold on; till at\nlast—owing to the perpendicular strain from the lead-lined chocks of\nthe boats, whence", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5289, "position": 5289, "text": "perpendicular strain from the lead-lined chocks of\nthe boats, whence the three ropes went straight down into the blue—the\ngunwales of the bows were almost even with the water, while the three\nsterns tilted high in the air", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 5290, "position": 5290, "text": "with the water, while the three\nsterns tilted high in the air. And the whale soon ceasing to sound, for\nsome time they remained in that attitude, fearful of expending more\nline, though the position was a little ticklish", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5291, "position": 5291, "text": "of expending more\nline, though the position was a little ticklish. But though boats have\nbeen taken down and lost in this way, yet it is this “holding on,” as\nit is called; this hooking up by the sharp", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 5292, "position": 5292, "text": "on,” as\nit is called; this hooking up by the sharp barbs of his live flesh from\nthe back; this it is that often torments the Leviathan into soon rising\nagain to meet the sharp lance of his foes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5293, "position": 5293, "text": "into soon rising\nagain to meet the sharp lance of his foes. Yet not to speak of the\nperil of the thing, it is to be doubted whether this course is always\nthe best; for it is but reasonable to presume, that the", "labels": {"50": 47, "100": 60, "250": 106, "500": 22, "1000": 831, "2000": 391}}, {"id": 5294, "position": 5294, "text": "always\nthe best; for it is but reasonable to presume, that the longer the\nstricken whale stays under water, the more he is exhausted. Because,\nowing to the enormous surface of him—in a full grown sperm whale\nsomething less than 2000 square", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5295, "position": 5295, "text": "surface of him—in a full grown sperm whale\nsomething less than 2000 square feet—the pressure of the water is\nimmense. We all know what an astonishing atmospheric weight we\nourselves stand up under; even here, above-ground, in the air;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5296, "position": 5296, "text": "stand up under; even here, above-ground, in the air; how\nvast, then, the burden of a whale, bearing on his back a column of two\nhundred fathoms of ocean! It must at least equal the weight of fifty", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5297, "position": 5297, "text": "fathoms of ocean! It must at least equal the weight of fifty\natmospheres. One whaleman has estimated it at the weight of twenty\nline-of-battle ships, with all their guns, and stores, and men on\nboard.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5298, "position": 5298, "text": ", with all their guns, and stores, and men on\nboard.\n\nAs the three boats lay there on that gently rolling sea, gazing down\ninto its eternal blue noon; and as not a single groan or cry of any\nsort, nay, not so", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 5299, "position": 5299, "text": "as not a single groan or cry of any\nsort, nay, not so much as a ripple or a bubble came up from its depths;\nwhat landsman would have thought, that beneath all that silence and\nplacidity, the utmost monster of", "labels": {"50": 45, "100": 55, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5300, "position": 5300, "text": "that beneath all that silence and\nplacidity, the utmost monster of the seas was writhing and wrenching in\nagony! Not eight inches of perpendicular rope were visible at the bows.\nSeems it credible that by three such thin threads the great Leviathan", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5301, "position": 5301, "text": "bows.\nSeems it credible that by three such thin threads the great Leviathan\nwas suspended like the big weight to an eight day clock. Suspended? and\nto what? To three bits of board. Is this the creature of whom it was\nonce so triumphant", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5302, "position": 5302, "text": "bits of board. Is this the creature of whom it was\nonce so triumphantly said—“Canst thou fill his skin with barbed irons?\nor his head with fish-spears? The sword of him that layeth at him\ncannot hold,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5303, "position": 5303, "text": "-spears? The sword of him that layeth at him\ncannot hold, the spear, the dart, nor the habergeon: he esteemeth iron\nas straw; the arrow cannot make him flee; darts are counted as stubble;\nhe laugheth", "labels": {"50": 9, "100": 26, "250": 112, "500": 198, "1000": 616, "2000": 1464}}, {"id": 5304, "position": 5304, "text": "arrow cannot make him flee; darts are counted as stubble;\nhe laugheth at the shaking of a spear!” This the creature? this he? Oh!\nthat unfulfilments should follow the prophets", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 437, "2000": 1208}}, {"id": 5305, "position": 5305, "text": "filments should follow the prophets. For with the strength of\na thousand thighs in his tail, Leviathan had run his head under the\nmountains of the sea, to hide him from the Pequod’s fish-spears!", "labels": {"50": 9, "100": 26, "250": 141, "500": 72, "1000": 859, "2000": 1785}}, {"id": 5306, "position": 5306, "text": "from the Pequod’s fish-spears!\n\nIn that sloping afternoon sunlight, the shadows that the three boats\nsent down beneath the surface, must have been long enough and broad\nenough to shade half Xerxes’ army", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 778}}, {"id": 5307, "position": 5307, "text": "broad\nenough to shade half Xerxes’ army. Who can tell how appalling to the\nwounded whale must have been such huge phantoms flitting over his head!\n\n“Stand by, men; he stirs,” cried Starbuck", "labels": {"50": 26, "100": 10, "250": 226, "500": 332, "1000": 469, "2000": 1270}}, {"id": 5308, "position": 5308, "text": "!\n\n“Stand by, men; he stirs,” cried Starbuck, as the three lines suddenly\nvibrated in the water, distinctly conducting upwards to them, as by\nmagnetic wires, the life and death throbs of the whale, so that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5309, "position": 5309, "text": "wires, the life and death throbs of the whale, so that every\noarsman felt them in his seat. The next moment, relieved in great part\nfrom the downward strain at the bows, the boats gave a sudden bounce\nupwards, as", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5310, "position": 5310, "text": "downward strain at the bows, the boats gave a sudden bounce\nupwards, as a small icefield will, when a dense herd of white bears are\nscared from it into the sea.\n\n“Haul in! Haul in!” cried Starbuck again; “", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5311, "position": 5311, "text": ".\n\n“Haul in! Haul in!” cried Starbuck again; “he’s rising.”\n\nThe lines, of which, hardly an instant before, not one hand’s breadth\ncould have been gained, were now in long quick coils", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5312, "position": 5312, "text": "’s breadth\ncould have been gained, were now in long quick coils flung back all\ndripping into the boats, and soon the whale broke water within two\nship’s lengths of the hunters.\n\nHis motions plainly denoted his extreme exhaustion", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5313, "position": 5313, "text": "of the hunters.\n\nHis motions plainly denoted his extreme exhaustion. In most land\nanimals there are certain valves or flood-gates in many of their veins,\nwhereby when wounded, the blood is in some degree at least instantly\nshut off in certain directions", "labels": {"50": 12, "100": 24, "250": 52, "500": 417, "1000": 129, "2000": 145}}, {"id": 5314, "position": 5314, "text": "blood is in some degree at least instantly\nshut off in certain directions. Not so with the whale; one of whose\npeculiarities it is to have an entire non-valvular structure of the\nblood-vessels, so that when pierced even by so", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 5315, "position": 5315, "text": "lar structure of the\nblood-vessels, so that when pierced even by so small a point as a\nharpoon, a deadly drain is at once begun upon his whole arterial\nsystem; and when this is heightened by the extraordinary pressure of\nwater at a great", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5316, "position": 5316, "text": "; and when this is heightened by the extraordinary pressure of\nwater at a great distance below the surface, his life may be said to\npour from him in incessant streams. Yet so vast is the quantity of\nblood in him, and so distant and", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5317, "position": 5317, "text": "Yet so vast is the quantity of\nblood in him, and so distant and numerous its interior fountains, that\nhe will keep thus bleeding and bleeding for a considerable period; even\nas in a drought a river will flow, whose source is in the well-", "labels": {"50": 26, "100": 67, "250": 246, "500": 474, "1000": 454, "2000": 199}}, {"id": 5318, "position": 5318, "text": "in a drought a river will flow, whose source is in the well-springs\nof far-off and undiscernible hills. Even now, when the boats pulled\nupon this whale, and perilously drew over his swaying flukes,", "labels": {"50": 37, "100": 55, "250": 28, "500": 93, "1000": 661, "2000": 947}}, {"id": 5319, "position": 5319, "text": "upon this whale, and perilously drew over his swaying flukes, and the\nlances were darted into him, they were followed by steady jets from the\nnew made wound, which kept continually playing, while the natural\nspout-hole in his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5320, "position": 5320, "text": ", which kept continually playing, while the natural\nspout-hole in his head was only at intervals, however rapid, sending\nits affrighted moisture into the air. From this last vent no blood yet\ncame, because no vital part of him", "labels": {"50": 12, "100": 24, "250": 52, "500": 435, "1000": 505, "2000": 145}}, {"id": 5321, "position": 5321, "text": "From this last vent no blood yet\ncame, because no vital part of him had thus far been struck. His life,\nas they significantly call it, was untouched.\n\nAs the boats now more closely surrounded him, the whole upper part of\nhis form,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 5322, "position": 5322, "text": "boats now more closely surrounded him, the whole upper part of\nhis form, with much of it that is ordinarily submerged, was plainly\nrevealed. His eyes, or rather the places where his eyes had been, were\nbeheld", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 723, "2000": 576}}, {"id": 5323, "position": 5323, "text": "the places where his eyes had been, were\nbeheld. As strange misgrown masses gather in the knot-holes of the\nnoblest oaks when prostrate, so from the points which the whale’s eyes\nhad once occupied, now pro", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5324, "position": 5324, "text": "from the points which the whale’s eyes\nhad once occupied, now protruded blind bulbs, horribly pitiable to see.\nBut pity there was none. For all his old age, and his one arm, and his\nblind eyes, he must", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5325, "position": 5325, "text": "old age, and his one arm, and his\nblind eyes, he must die the death and be murdered, in order to light\nthe gay bridals and other merry-makings of men, and also to illuminate\nthe solemn churches that", "labels": {"50": 5, "100": 78, "250": 177, "500": 250, "1000": 890, "2000": 351}}, {"id": 5326, "position": 5326, "text": "makings of men, and also to illuminate\nthe solemn churches that preach unconditional inoffensiveness by all to\nall. Still rolling in his blood, at last he partially disclosed a\nstrangely discoloured bunch or protuberan", "labels": {"50": 22, "100": 64, "250": 70, "500": 162, "1000": 984, "2000": 110}}, {"id": 5327, "position": 5327, "text": "at last he partially disclosed a\nstrangely discoloured bunch or protuberance, the size of a bushel, low\ndown on the flank.\n\n“A nice spot,” cried Flask; “just let me prick him there once.”", "labels": {"50": 41, "100": 64, "250": 219, "500": 180, "1000": 54, "2000": 1620}}, {"id": 5328, "position": 5328, "text": "” cried Flask; “just let me prick him there once.”\n\n“Avast!” cried Starbuck, “there’s no need of that!”\n\nBut humane Starbuck was too late", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5329, "position": 5329, "text": "humane Starbuck was too late. At the instant of the dart an\nulcerous jet shot from this cruel wound, and goaded by it into more\nthan sufferable anguish, the whale now spouting thick blood, with swift\nfury blindly darted", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5330, "position": 5330, "text": ", the whale now spouting thick blood, with swift\nfury blindly darted at the craft, bespattering them and their glorying\ncrews all over with showers of gore, capsizing Flask’s boat and marring\nthe bows", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5331, "position": 5331, "text": ", capsizing Flask’s boat and marring\nthe bows. It was his death stroke. For, by this time, so spent was he\nby loss of blood, that he helplessly rolled away from the wreck he had\nmade; lay panting on", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5332, "position": 5332, "text": "that he helplessly rolled away from the wreck he had\nmade; lay panting on his side, impotently flapped with his stumped fin,\nthen over and over slowly revolved like a waning world; turned up the\nwhite secrets of his belly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 5333, "position": 5333, "text": "olved like a waning world; turned up the\nwhite secrets of his belly; lay like a log, and died. It was most\npiteous, that last expiring spout. As when by unseen hands the water is\ngradually drawn off from", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5334, "position": 5334, "text": "spout. As when by unseen hands the water is\ngradually drawn off from some mighty fountain, and with half-stifled\nmelancholy gurglings the spray-column lowers and lowers to the\nground—so the last long dying spout of the whale.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5335, "position": 5335, "text": "to the\nground—so the last long dying spout of the whale.\n\nSoon, while the crews were awaiting the arrival of the ship, the body\nshowed symptoms of sinking with all its treasures unrifled", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5336, "position": 5336, "text": "all its treasures unrifled.\nImmediately, by Starbuck’s orders, lines were secured to it at\ndifferent points, so that ere long every boat was a buoy; the sunken\nwhale being suspended a few inches beneath them by the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5337, "position": 5337, "text": "buoy; the sunken\nwhale being suspended a few inches beneath them by the cords. By very\nheedful management, when the ship drew nigh, the whale was transferred\nto her side, and was strongly secured there by the stiffest\nfluke", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5338, "position": 5338, "text": "to her side, and was strongly secured there by the stiffest\nfluke-chains, for it was plain that unless artificially upheld, the\nbody would at once sink to the bottom.\n\nIt so chanced that almost upon first cutting into him with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5339, "position": 5339, "text": "the bottom.\n\nIt so chanced that almost upon first cutting into him with the spade,\nthe entire length of a corroded harpoon was found imbedded in his\nflesh, on the lower part of the bunch before described", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5340, "position": 5340, "text": "flesh, on the lower part of the bunch before described. But as the\nstumps of harpoons are frequently found in the dead bodies of captured\nwhales, with the flesh perfectly healed around them, and no prominence\nof any kind to denote their place;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5341, "position": 5341, "text": "healed around them, and no prominence\nof any kind to denote their place; therefore, there must needs have\nbeen some other unknown reason in the present case fully to account for\nthe ulceration alluded to", "labels": {"50": 3, "100": 70, "250": 155, "500": 309, "1000": 294, "2000": 538}}, {"id": 5342, "position": 5342, "text": "ulceration alluded to. But still more curious was the fact of a\nlance-head of stone being found in him, not far from the buried iron,\nthe flesh perfectly firm about it. Who had darted that stone lance? And\nwhen?", "labels": {"50": 45, "100": 70, "250": 155, "500": 309, "1000": 294, "2000": 1109}}, {"id": 5343, "position": 5343, "text": "perfectly firm about it. Who had darted that stone lance? And\nwhen? It might have been darted by some Nor’ West Indian long before\nAmerica was discovered.\n\nWhat other marvels might have been rummaged out of this monstrous\ncabinet there is no", "labels": {"50": 25, "100": 5, "250": 234, "500": 185, "1000": 478, "2000": 893}}, {"id": 5344, "position": 5344, "text": "s might have been rummaged out of this monstrous\ncabinet there is no telling. But a sudden stop was put to further\ndiscoveries, by the ship’s being unprecedentedly dragged over sideways\nto the sea, owing to the body’s immensely increasing", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 5345, "position": 5345, "text": "dragged over sideways\nto the sea, owing to the body’s immensely increasing tendency to sink.\nHowever, Starbuck, who had the ordering of affairs, hung on to it to\nthe last; hung on to it so resolutely, indeed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5346, "position": 5346, "text": "to\nthe last; hung on to it so resolutely, indeed, that when at length the\nship would have been capsized, if still persisting in locking arms with\nthe body; then, when the command was given to break clear from", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 282}}, {"id": 5347, "position": 5347, "text": "with\nthe body; then, when the command was given to break clear from it, such\nwas the immovable strain upon the timber-heads to which the\nfluke-chains and cables were fastened, that it was impossible to cast\nthem off", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 5348, "position": 5348, "text": "and cables were fastened, that it was impossible to cast\nthem off. Meantime everything in the Pequod was aslant. To cross to the\nother side of the deck was like walking up the steep gabled roof of a\nhouse", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 5349, "position": 5349, "text": "was like walking up the steep gabled roof of a\nhouse. The ship groaned and gasped. Many of the ivory inlayings of her\nbulwarks and cabins were started from their places, by the unnatural\ndislocation", "labels": {"50": 22, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 5350, "position": 5350, "text": "from their places, by the unnatural\ndislocation. In vain handspikes and crows were brought to bear upon the\nimmovable fluke-chains, to pry them adrift from the timberheads; and so\nlow had the whale now settled that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5351, "position": 5351, "text": "rift from the timberheads; and so\nlow had the whale now settled that the submerged ends could not be at\nall approached, while every moment whole tons of ponderosity seemed\nadded to the sinking bulk, and the ship seemed on the point of going\nover", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1620}}, {"id": 5352, "position": 5352, "text": "to the sinking bulk, and the ship seemed on the point of going\nover.\n\n“Hold on, hold on, won’t ye?” cried Stubb to the body, “don’t be in\nsuch a devil of a hurry to sink", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5353, "position": 5353, "text": ", “don’t be in\nsuch a devil of a hurry to sink! By thunder, men, we must do something\nor go for it. No use prying there; avast, I say with your handspikes,\nand run one", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 5354, "position": 5354, "text": "; avast, I say with your handspikes,\nand run one of ye for a prayer book and a pen-knife, and cut the big\nchains.”\n\n“Knife? Aye, aye,” cried Queequeg, and seizing", "labels": {"50": 41, "100": 64, "250": 163, "500": 180, "1000": 672, "2000": 16}}, {"id": 5355, "position": 5355, "text": "Knife? Aye, aye,” cried Queequeg, and seizing the carpenter’s heavy\nhatchet, he leaned out of a porthole, and steel to iron, began slashing\nat the largest fluke-chains", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5356, "position": 5356, "text": ", began slashing\nat the largest fluke-chains. But a few strokes, full of sparks, were\ngiven, when the exceeding strain effected the rest. With a terrific\nsnap, every fastening went adrift; the ship righted,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 5357, "position": 5357, "text": "terrific\nsnap, every fastening went adrift; the ship righted, the carcase sank.\n\nNow, this occasional inevitable sinking of the recently killed Sperm\nWhale is a very curious thing; nor has any fisherman yet adequately\naccounted for it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5358, "position": 5358, "text": "curious thing; nor has any fisherman yet adequately\naccounted for it. Usually the dead Sperm Whale floats with great\nbuoyancy, with its side or belly considerably elevated above the\nsurface. If the only whales that thus sank were old, meagre,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5359, "position": 5359, "text": ". If the only whales that thus sank were old, meagre, and\nbroken-hearted creatures, their pads of lard diminished and all their\nbones heavy and rheumatic; then you might with some reason assert that\nthis sinking is caused by", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5360, "position": 5360, "text": "umatic; then you might with some reason assert that\nthis sinking is caused by an uncommon specific gravity in the fish so\nsinking, consequent upon this absence of buoyant matter in him. But it\nis not so", "labels": {"50": 3, "100": 70, "250": 50, "500": 288, "1000": 825, "2000": 447}}, {"id": 5361, "position": 5361, "text": "matter in him. But it\nis not so. For young whales, in the highest health, and swelling with\nnoble aspirations, prematurely cut off in the warm flush and May of\nlife, with all their panting lard about them; even these brawny", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5362, "position": 5362, "text": "life, with all their panting lard about them; even these brawny,\nbuoyant heroes do sometimes sink.\n\nBe it said, however, that the Sperm Whale is far less liable to this\naccident than any other species", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5363, "position": 5363, "text": "far less liable to this\naccident than any other species. Where one of that sort go down, twenty\nRight Whales do. This difference in the species is no doubt imputable\nin no small degree to the greater quantity of bone in the Right Whale;\nhis", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5364, "position": 5364, "text": "no small degree to the greater quantity of bone in the Right Whale;\nhis Venetian blinds alone sometimes weighing more than a ton; from this\nincumbrance the Sperm Whale is wholly free. But there are instances\nwhere, after the lapse of many hours", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5365, "position": 5365, "text": "free. But there are instances\nwhere, after the lapse of many hours or several days, the sunken whale\nagain rises, more buoyant than in life. But the reason of this is\nobvious. Gases are generated in him; he swells", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5366, "position": 5366, "text": "reason of this is\nobvious. Gases are generated in him; he swells to a prodigious\nmagnitude; becomes a sort of animal balloon. A line-of-battle ship\ncould hardly keep him under then", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 5367, "position": 5367, "text": "battle ship\ncould hardly keep him under then. In the Shore Whaling, on soundings,\namong the Bays of New Zealand, when a Right Whale gives token of\nsinking, they fasten buoys to him, with plenty of rope; so that when", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5368, "position": 5368, "text": "fasten buoys to him, with plenty of rope; so that when\nthe body has gone down, they know where to look for it when it shall\nhave ascended again.\n\nIt was not long after the sinking of the body that a cry was heard", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 99, "2000": 472}}, {"id": 5369, "position": 5369, "text": "It was not long after the sinking of the body that a cry was heard from\nthe Pequod’s mast-heads, announcing that the Jungfrau was again\nlowering her boats; though the only spout in sight was that of a\nFin", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5370, "position": 5370, "text": "her boats; though the only spout in sight was that of a\nFin-Back, belonging to the species of uncapturable whales, because of\nits incredible power of swimming. Nevertheless, the Fin-Back’s spout is\nso similar", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5371, "position": 5371, "text": "swimming. Nevertheless, the Fin-Back’s spout is\nso similar to the Sperm Whale’s, that by unskilful fishermen it is\noften mistaken for it. And consequently Derick and all his host were\nnow in valiant chase of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5372, "position": 5372, "text": ". And consequently Derick and all his host were\nnow in valiant chase of this unnearable brute. The Virgin crowding all\nsail, made after her four young keels, and thus they all disappeared\nfar to leeward, still in bold,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5373, "position": 5373, "text": ", and thus they all disappeared\nfar to leeward, still in bold, hopeful chase.\n\nOh! many are the Fin-Backs, and many are the Dericks, my friend.\n\n\nCHAPTER 82. The Honor and Glory of Whaling.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5374, "position": 5374, "text": "my friend.\n\n\nCHAPTER 82. The Honor and Glory of Whaling.\n\nThere are some enterprises in which a careful disorderliness is the\ntrue method.\n\nThe more I dive into this matter of whaling, and push my researches up\nto the very spring-head of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5375, "position": 5375, "text": "of whaling, and push my researches up\nto the very spring-head of it so much the more am I impressed with its\ngreat honorableness and antiquity; and especially when I find so many\ngreat demi-gods and heroes, prophets of all sorts,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5376, "position": 5376, "text": "find so many\ngreat demi-gods and heroes, prophets of all sorts, who one way or other\nhave shed distinction upon it, I am transported with the reflection\nthat I myself belong, though but subordinately, to so emblazoned a\nfraternity", "labels": {"50": 9, "100": 75, "250": 106, "500": 307, "1000": 27, "2000": 1037}}, {"id": 5377, "position": 5377, "text": "belong, though but subordinately, to so emblazoned a\nfraternity.\n\nThe gallant Perseus, a son of Jupiter, was the first whaleman; and to\nthe eternal honor of our calling be it said, that the first whale\nattacked", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5378, "position": 5378, "text": "the eternal honor of our calling be it said, that the first whale\nattacked by our brotherhood was not killed with any sordid intent.\nThose were the knightly days of our profession, when we only bore arms\nto succor the distressed,", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5379, "position": 5379, "text": "our profession, when we only bore arms\nto succor the distressed, and not to fill men’s lamp-feeders. Every one\nknows the fine story of Perseus and Andromeda; how the lovely\nAndromeda, the", "labels": {"50": 25, "100": 28, "250": 132, "500": 412, "1000": 421, "2000": 381}}, {"id": 5380, "position": 5380, "text": "seus and Andromeda; how the lovely\nAndromeda, the daughter of a king, was tied to a rock on the sea-coast,\nand as Leviathan was in the very act of carrying her off, Perseus, the", "labels": {"50": 26, "100": 82, "250": 135, "500": 332, "1000": 852, "2000": 188}}, {"id": 5381, "position": 5381, "text": "was in the very act of carrying her off, Perseus, the\nprince of whalemen, intrepidly advancing, harpooned the monster, and\ndelivered and married the maid. It was an admirable artistic exploit,\nrarely achieved", "labels": {"50": 17, "100": 16, "250": 146, "500": 473, "1000": 852, "2000": 188}}, {"id": 5382, "position": 5382, "text": "married the maid. It was an admirable artistic exploit,\nrarely achieved by the best harpooneers of the present day; inasmuch as\nthis Leviathan was slain at the very first dart. And let no man doubt\nthis Arkite story", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5383, "position": 5383, "text": "at the very first dart. And let no man doubt\nthis Arkite story; for in the ancient Joppa, now Jaffa, on the Syrian\ncoast, in one of the Pagan temples, there stood for many ages the vast\nskeleton of a whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5384, "position": 5384, "text": "the Pagan temples, there stood for many ages the vast\nskeleton of a whale, which the city’s legends and all the inhabitants\nasserted to be the identical bones of the monster that Perseus slew", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5385, "position": 5385, "text": "that Perseus slew.\nWhen the Romans took Joppa, the same skeleton was carried to Italy in\ntriumph. What seems most singular and suggestively important in this\nstory, is this: it was from Joppa that Jonah set sail.", "labels": {"50": 14, "100": 98, "250": 139, "500": 165, "1000": 725, "2000": 200}}, {"id": 5386, "position": 5386, "text": ", is this: it was from Joppa that Jonah set sail.\n\nAkin to the adventure of Perseus and Andromeda—indeed, by some supposed\nto be indirectly derived from it—is that famous story of St", "labels": {"50": 45, "100": 66, "250": 211, "500": 490, "1000": 622, "2000": 1620}}, {"id": 5387, "position": 5387, "text": "derived from it—is that famous story of St. George and\nthe Dragon; which dragon I maintain to have been a whale; for in many\nold chronicles whales and dragons are strangely jumbled together, and\noften stand for each other", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 1533}}, {"id": 5388, "position": 5388, "text": "strangely jumbled together, and\noften stand for each other. “Thou art as a lion of the waters, and as a\ndragon of the sea,” saith Ezekiel; hereby, plainly meaning a whale; in\ntruth, some versions of the", "labels": {"50": 10, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1533}}, {"id": 5389, "position": 5389, "text": "hereby, plainly meaning a whale; in\ntruth, some versions of the Bible use that word itself. Besides, it\nwould much subtract from the glory of the exploit had St. George but\nencountered a crawling reptile of the land, instead", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5390, "position": 5390, "text": "had St. George but\nencountered a crawling reptile of the land, instead of doing battle\nwith the great monster of the deep. Any man may kill a snake, but only\na Perseus, a St", "labels": {"50": 31, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 744}}, {"id": 5391, "position": 5391, "text": "a Perseus, a St. George, a Coffin, have the heart in them to march\nboldly up to a whale.\n\nLet not the modern paintings of this scene mislead us; for though the\ncreature encountered by that valiant whaleman", "labels": {"50": 17, "100": 82, "250": 211, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5392, "position": 5392, "text": "mislead us; for though the\ncreature encountered by that valiant whaleman of old is vaguely\nrepresented of a griffin-like shape, and though the battle is depicted\non land and the saint on horseback, yet considering the great ignorance\nof those times,", "labels": {"50": 14, "100": 83, "250": 92, "500": 4, "1000": 622, "2000": 1283}}, {"id": 5393, "position": 5393, "text": "and the saint on horseback, yet considering the great ignorance\nof those times, when the true form of the whale was unknown to artists;\nand considering that as in Perseus’ case, St. George’s whale might have\ncrawled up out of", "labels": {"50": 5, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1010}}, {"id": 5394, "position": 5394, "text": "’ case, St. George’s whale might have\ncrawled up out of the sea on the beach; and considering that the animal\nridden by St. George might have been only a large seal, or sea-horse;\nbearing all this in mind,", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 886, "2000": 1620}}, {"id": 5395, "position": 5395, "text": "a large seal, or sea-horse;\nbearing all this in mind, it will not appear altogether incompatible\nwith the sacred legend and the ancientest draughts of the scene, to\nhold this so-called dragon no other than the great Leviathan himself", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5396, "position": 5396, "text": "to\nhold this so-called dragon no other than the great Leviathan himself.\nIn fact, placed before the strict and piercing truth, this whole story\nwill fare like that fish, flesh, and fowl idol of the Philistines,\nDa", "labels": {"50": 3, "100": 66, "250": 211, "500": 288, "1000": 825, "2000": 199}}, {"id": 5397, "position": 5397, "text": ", flesh, and fowl idol of the Philistines,\nDagon by name; who being planted before the ark of Israel, his horse’s\nhead and both the palms of his hands fell off from him, and only the\nstump or", "labels": {"50": 18, "100": 66, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 5398, "position": 5398, "text": "the palms of his hands fell off from him, and only the\nstump or fishy part of him remained. Thus, then, one of our own noble\nstamp, even a whaleman, is the tutelary guardian of England; and by\ngood", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5399, "position": 5399, "text": "whaleman, is the tutelary guardian of England; and by\ngood rights, we harpooneers of Nantucket should be enrolled in the most\nnoble order of St. George. And therefore, let not the knights of that\nhonorable company (none", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5400, "position": 5400, "text": "George. And therefore, let not the knights of that\nhonorable company (none of whom, I venture to say, have ever had to do\nwith a whale like their great patron), let them never eye a Nantucketer\nwith disdain, since even", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5401, "position": 5401, "text": "), let them never eye a Nantucketer\nwith disdain, since even in our woollen frocks and tarred trowsers we\nare much better entitled to St. George’s decoration than they.", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 5402, "position": 5402, "text": "George’s decoration than they.\n\nWhether to admit Hercules among us or not, concerning this I long\nremained dubious: for though according to the Greek mythologies, that\nantique Crockett and Kit Carson—that brawny doer of rejoicing", "labels": {"50": 17, "100": 40, "250": 146, "500": 369, "1000": 515, "2000": 1993}}, {"id": 5403, "position": 5403, "text": "ockett and Kit Carson—that brawny doer of rejoicing good\ndeeds, was swallowed down and thrown up by a whale; still, whether that\nstrictly makes a whaleman of him, that might be mooted", "labels": {"50": 37, "100": 57, "250": 70, "500": 39, "1000": 346, "2000": 623}}, {"id": 5404, "position": 5404, "text": "whaleman of him, that might be mooted. It nowhere\nappears that he ever actually harpooned his fish, unless, indeed, from\nthe inside. Nevertheless, he may be deemed a sort of involuntary\nwhaleman; at any rate the whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5405, "position": 5405, "text": "may be deemed a sort of involuntary\nwhaleman; at any rate the whale caught him, if he did not the whale. I\nclaim him for one of our clan.\n\nBut, by the best contradictory authorities, this Grecian story of\nHercules and", "labels": {"50": 10, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5406, "position": 5406, "text": ", by the best contradictory authorities, this Grecian story of\nHercules and the whale is considered to be derived from the still more\nancient Hebrew story of Jonah and the whale; and vice versâ; certainly\nthey are very similar", "labels": {"50": 3, "100": 33, "250": 211, "500": 86, "1000": 880, "2000": 199}}, {"id": 5407, "position": 5407, "text": "and vice versâ; certainly\nthey are very similar. If I claim the demi-god then, why not the\nprophet?\n\nNor do heroes, saints, demigods, and prophets alone comprise the whole\nroll of our order", "labels": {"50": 5, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 215}}, {"id": 5408, "position": 5408, "text": "prophets alone comprise the whole\nroll of our order. Our grand master is still to be named; for like\nroyal kings of old times, we find the head waters of our fraternity in\nnothing short of the great gods themselves", "labels": {"50": 10, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1535}}, {"id": 5409, "position": 5409, "text": "in\nnothing short of the great gods themselves. That wondrous oriental\nstory is now to be rehearsed from the Shaster, which gives us the dread\nVishnoo, one of the three persons in the godhead of the Hindoos", "labels": {"50": 32, "100": 81, "250": 3, "500": 366, "1000": 555, "2000": 211}}, {"id": 5410, "position": 5410, "text": ", one of the three persons in the godhead of the Hindoos; gives\nus this divine Vishnoo himself for our Lord;—Vishnoo, who, by the first\nof his ten earthly incarnations, has for ever set apart", "labels": {"50": 10, "100": 81, "250": 3, "500": 11, "1000": 555, "2000": 211}}, {"id": 5411, "position": 5411, "text": "by the first\nof his ten earthly incarnations, has for ever set apart and sanctified\nthe whale. When Brahma, or the God of Gods, saith the Shaster, resolved\nto recreate the world after one of its periodical dissolution", "labels": {"50": 32, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1533}}, {"id": 5412, "position": 5412, "text": "Shaster, resolved\nto recreate the world after one of its periodical dissolutions, he gave\nbirth to Vishnoo, to preside over the work; but the Vedas, or mystical\nbooks, whose perusal would seem to have been ind", "labels": {"50": 17, "100": 16, "250": 87, "500": 4, "1000": 947, "2000": 91}}, {"id": 5413, "position": 5413, "text": "das, or mystical\nbooks, whose perusal would seem to have been indispensable to Vishnoo\nbefore beginning the creation, and which therefore must have contained\nsomething in the shape of practical hints to young architects, these\nVedas were lying at", "labels": {"50": 32, "100": 81, "250": 3, "500": 366, "1000": 555, "2000": 315}}, {"id": 5414, "position": 5414, "text": "the shape of practical hints to young architects, these\nVedas were lying at the bottom of the waters; so Vishnoo became\nincarnate in a whale, and sounding down in him to the uttermost depths,\nrescued the sacred volumes", "labels": {"50": 10, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 211}}, {"id": 5415, "position": 5415, "text": "down in him to the uttermost depths,\nrescued the sacred volumes. Was not this Vishnoo a whaleman, then? even\nas a man who rides a horse is called a horseman?\n\nPerseus, St", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5416, "position": 5416, "text": "called a horseman?\n\nPerseus, St. George, Hercules, Jonah, and Vishnoo! there’s a\nmember-roll for you! What club but the whaleman’s can head off like\nthat?\n\n\nCHAPTER 83", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5417, "position": 5417, "text": "the whaleman’s can head off like\nthat?\n\n\nCHAPTER 83. Jonah Historically Regarded.\n\nReference was made to the historical story of Jonah and the whale in\nthe preceding chapter. Now some Nantucketers rather distrust this\nhistorical story of Jonah and the whale", "labels": {"50": 27, "100": 33, "250": 194, "500": 86, "1000": 880, "2000": 354}}, {"id": 5418, "position": 5418, "text": "Now some Nantucketers rather distrust this\nhistorical story of Jonah and the whale. But then there were some\nsceptical Greeks and Romans, who, standing out from the orthodox pagans\nof their times, equally doubted the story of Hercules and the whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5419, "position": 5419, "text": "pagans\nof their times, equally doubted the story of Hercules and the whale,\nand Arion and the dolphin; and yet their doubting those traditions did\nnot make those traditions one whit the less facts, for all that.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5420, "position": 5420, "text": "one whit the less facts, for all that.\n\nOne old Sag-Harbor whaleman’s chief reason for questioning the Hebrew\nstory was this:—He had one of those quaint old-fashioned Bibles,\nembellished with curious", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5421, "position": 5421, "text": "of those quaint old-fashioned Bibles,\nembellished with curious, unscientific plates; one of which represented\nJonah’s whale with two spouts in his head—a peculiarity only true with\nrespect to a species of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5422, "position": 5422, "text": "his head—a peculiarity only true with\nrespect to a species of the Leviathan (the Right Whale, and the\nvarieties of that order), concerning which the fishermen have this\nsaying, “A penny roll would choke him”; his swallow is", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5423, "position": 5423, "text": "this\nsaying, “A penny roll would choke him”; his swallow is so very small.\nBut, to this, Bishop Jebb’s anticipative answer is ready. It is not\nnecessary, hints the Bishop, that we consider Jonah", "labels": {"50": 5, "100": 33, "250": 194, "500": 159, "1000": 989, "2000": 161}}, {"id": 5424, "position": 5424, "text": "ready. It is not\nnecessary, hints the Bishop, that we consider Jonah as tombed in the\nwhale’s belly, but as temporarily lodged in some part of his mouth. And\nthis seems reasonable enough in the good Bishop", "labels": {"50": 27, "100": 33, "250": 194, "500": 72, "1000": 880, "2000": 1620}}, {"id": 5425, "position": 5425, "text": ". And\nthis seems reasonable enough in the good Bishop. For truly, the Right\nWhale’s mouth would accommodate a couple of whist-tables, and\ncomfortably seat all the players. Possibly, too, Jonah might have\nensconced himself", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5426, "position": 5426, "text": "the players. Possibly, too, Jonah might have\nensconced himself in a hollow tooth; but, on second thoughts, the Right\nWhale is toothless.\n\nAnother reason which Sag-Harbor (he went by that name) urged for his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5427, "position": 5427, "text": "which Sag-Harbor (he went by that name) urged for his\nwant of faith in this matter of the prophet, was something obscurely in\nreference to his incarcerated body and the whale’s gastric juices", "labels": {"50": 45, "100": 64, "250": 30, "500": 72, "1000": 345, "2000": 1620}}, {"id": 5428, "position": 5428, "text": "and the whale’s gastric juices. But\nthis objection likewise falls to the ground, because a German exegetist\nsupposes that Jonah must have taken refuge in the floating body of a\n_dead_ whale—even as the French soldiers in", "labels": {"50": 45, "100": 66, "250": 211, "500": 72, "1000": 622, "2000": 1620}}, {"id": 5429, "position": 5429, "text": "floating body of a\n_dead_ whale—even as the French soldiers in the Russian campaign turned\ntheir dead horses into tents, and crawled into them. Besides, it has\nbeen divined by other continental commentators, that when Jonah was\nthrown overboard from the", "labels": {"50": 3, "100": 70, "250": 234, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5430, "position": 5430, "text": "divined by other continental commentators, that when Jonah was\nthrown overboard from the Joppa ship, he straightway effected his\nescape to another vessel near by, some vessel with a whale for a\nfigure-head; and, I would add, possibly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5431, "position": 5431, "text": "a whale for a\nfigure-head; and, I would add, possibly called “The Whale,” as some\ncraft are nowadays christened the “Shark,” the “Gull,” the “Eagle.” Nor\nhave there been wanting learned", "labels": {"50": 17, "100": 66, "250": 211, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5432, "position": 5432, "text": "Gull,” the “Eagle.” Nor\nhave there been wanting learned exegetists who have opined that the\nwhale mentioned in the book of Jonah merely meant a life-preserver—an\ninflated bag of wind—which the endangered prophet swam", "labels": {"50": 27, "100": 33, "250": 194, "500": 86, "1000": 880, "2000": 1676}}, {"id": 5433, "position": 5433, "text": "-preserver—an\ninflated bag of wind—which the endangered prophet swam to, and so was\nsaved from a watery doom. Poor Sag-Harbor, therefore, seems worsted all\nround. But he had still another reason for his want of", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 5434, "position": 5434, "text": "worsted all\nround. But he had still another reason for his want of faith. It was\nthis, if I remember right: Jonah was swallowed by the whale in the\nMediterranean Sea, and after three days he was vomited up somewhere\nwithin three days", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5435, "position": 5435, "text": "Sea, and after three days he was vomited up somewhere\nwithin three days’ journey of Nineveh, a city on the Tigris, very much\nmore than three days’ journey across from the nearest point of the\nMediterranean coast", "labels": {"50": 3, "100": 66, "250": 211, "500": 102, "1000": 622, "2000": 1821}}, {"id": 5436, "position": 5436, "text": "days’ journey across from the nearest point of the\nMediterranean coast. How is that?\n\nBut was there no other way for the whale to land the prophet within\nthat short distance of Nineveh? Yes. He might have carried him round by\nthe way", "labels": {"50": 39, "100": 99, "250": 57, "500": 468, "1000": 54, "2000": 1790}}, {"id": 5437, "position": 5437, "text": "Nineveh? Yes. He might have carried him round by\nthe way of the Cape of Good Hope. But not to speak of the passage\nthrough the whole length of the Mediterranean, and another passage up\nthe Persian Gulf and Red Sea, such a", "labels": {"50": 45, "100": 66, "250": 161, "500": 13, "1000": 622, "2000": 1097}}, {"id": 5438, "position": 5438, "text": "Mediterranean, and another passage up\nthe Persian Gulf and Red Sea, such a supposition would involve the\ncomplete circumnavigation of all Africa in three days, not to speak of\nthe Tigris waters, near the site of Nine", "labels": {"50": 45, "100": 70, "250": 50, "500": 13, "1000": 622, "2000": 199}}, {"id": 5439, "position": 5439, "text": "not to speak of\nthe Tigris waters, near the site of Nineveh, being too shallow for any\nwhale to swim in. Besides, this idea of Jonah’s weathering the Cape of\nGood Hope at so early a day would wr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5440, "position": 5440, "text": "s weathering the Cape of\nGood Hope at so early a day would wrest the honor of the discovery of\nthat great headland from Bartholomew Diaz, its reputed discoverer, and\nso make modern history a liar.", "labels": {"50": 45, "100": 29, "250": 161, "500": 13, "1000": 622, "2000": 1097}}, {"id": 5441, "position": 5441, "text": "and\nso make modern history a liar.\n\nBut all these foolish arguments of old Sag-Harbor only evinced his\nfoolish pride of reason—a thing still more reprehensible in him, seeing\nthat he had but little learning except what he", "labels": {"50": 45, "100": 75, "250": 129, "500": 13, "1000": 622, "2000": 1097}}, {"id": 5442, "position": 5442, "text": "hensible in him, seeing\nthat he had but little learning except what he had picked up from the\nsun and the sea. I say it only shows his foolish, impious pride, and\nabominable, devilish rebellion against the reverend clergy", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5443, "position": 5443, "text": "pride, and\nabominable, devilish rebellion against the reverend clergy. For by a\nPortuguese Catholic priest, this very idea of Jonah’s going to Nineveh\nvia the Cape of Good Hope was advanced as a signal magnification of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5444, "position": 5444, "text": "the Cape of Good Hope was advanced as a signal magnification of the\ngeneral miracle. And so it was. Besides, to this day, the highly\nenlightened Turks devoutly believe in the historical story of Jonah", "labels": {"50": 45, "100": 29, "250": 138, "500": 13, "1000": 327, "2000": 1097}}, {"id": 5445, "position": 5445, "text": "devoutly believe in the historical story of Jonah.\nAnd some three centuries ago, an English traveller in old Harris’s\nVoyages, speaks of a Turkish Mosque built in honor of Jonah, in which\nMosque was a miraculous lamp that burnt without any oil.", "labels": {"50": 5, "100": 66, "250": 233, "500": 105, "1000": 61, "2000": 588}}, {"id": 5446, "position": 5446, "text": "Jonah, in which\nMosque was a miraculous lamp that burnt without any oil.\n\n\nCHAPTER 84. Pitchpoling.\n\nTo make them run easily and swiftly, the axles of carriages are\nanointed; and for much the same purpose, some whalers", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5447, "position": 5447, "text": "are\nanointed; and for much the same purpose, some whalers perform an\nanalogous operation upon their boat; they grease the bottom. Nor is it\nto be doubted that as such a procedure can do no harm, it may possibly\nbe of no", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5448, "position": 5448, "text": "as such a procedure can do no harm, it may possibly\nbe of no contemptible advantage; considering that oil and water are\nhostile; that oil is a sliding thing, and that the object in view is to\nmake the boat slide bravely", "labels": {"50": 45, "100": 63, "250": 152, "500": 290, "1000": 611, "2000": 735}}, {"id": 5449, "position": 5449, "text": "that the object in view is to\nmake the boat slide bravely. Queequeg believed strongly in anointing\nhis boat, and one morning not long after the German ship Jungfrau\ndisappeared, took more than customary pains in that occupation;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5450, "position": 5450, "text": "ship Jungfrau\ndisappeared, took more than customary pains in that occupation;\ncrawling under its bottom, where it hung over the side, and rubbing in\nthe unctuousness as though diligently seeking to insure a crop of hair\nfrom the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5451, "position": 5451, "text": "as though diligently seeking to insure a crop of hair\nfrom the craft’s bald keel. He seemed to be working in obedience to\nsome particular presentiment. Nor did it remain unwarranted by the\nevent.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 5452, "position": 5452, "text": "Nor did it remain unwarranted by the\nevent.\n\nTowards noon whales were raised; but so soon as the ship sailed down to\nthem, they turned and fled with swift precipitancy; a disordered\nflight, as of Cleopatra’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5453, "position": 5453, "text": "precipitancy; a disordered\nflight, as of Cleopatra’s barges from Actium.\n\nNevertheless, the boats pursued, and Stubb’s was foremost. By great\nexertion, Tashtego at last succeeded in planting one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5454, "position": 5454, "text": "great\nexertion, Tashtego at last succeeded in planting one iron; but the\nstricken whale, without at all sounding, still continued his horizontal\nflight, with added fleetness. Such unintermitted strainings upon the\nplanted iron", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5455, "position": 5455, "text": "fleetness. Such unintermitted strainings upon the\nplanted iron must sooner or later inevitably extract it. It became\nimperative to lance the flying whale, or be content to lose him. But to\nhaul the boat up to his flank was impossible", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5456, "position": 5456, "text": "to lose him. But to\nhaul the boat up to his flank was impossible, he swam so fast and\nfurious. What then remained?\n\nOf all the wondrous devices and dexterities, the sleights of hand and\ncountless subtleties,", "labels": {"50": 22, "100": 55, "250": 28, "500": 28, "1000": 99, "2000": 1111}}, {"id": 5457, "position": 5457, "text": "dexterities, the sleights of hand and\ncountless subtleties, to which the veteran whaleman is so often forced,\nnone exceed that fine manœuvre with the lance called pitchpoling", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5458, "position": 5458, "text": "the lance called pitchpoling. Small\nsword, or broad sword, in all its exercises boasts nothing like it. It\nis only indispensable with an inveterate running whale; its grand fact\nand feature is the wonderful distance to which the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5459, "position": 5459, "text": "running whale; its grand fact\nand feature is the wonderful distance to which the long lance is\naccurately darted from a violently rocking, jerking boat, under extreme\nheadway. Steel and wood included, the entire spear is some ten or\ntwelve feet in length;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5460, "position": 5460, "text": "wood included, the entire spear is some ten or\ntwelve feet in length; the staff is much slighter than that of the\nharpoon, and also of a lighter material—pine. It is furnished with a\nsmall rope called a warp, of considerable", "labels": {"50": 42, "100": 42, "250": 131, "500": 288, "1000": 222, "2000": 628}}, {"id": 5461, "position": 5461, "text": "pine. It is furnished with a\nsmall rope called a warp, of considerable length, by which it can be\nhauled back to the hand after darting.\n\nBut before going further, it is important to mention here, that though\nthe harpoon may be pitch", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5462, "position": 5462, "text": "it is important to mention here, that though\nthe harpoon may be pitchpoled in the same way with the lance, yet it is\nseldom done; and when done, is still less frequently successful, on\naccount of the greater weight and inferior length", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5463, "position": 5463, "text": "is still less frequently successful, on\naccount of the greater weight and inferior length of the harpoon as\ncompared with the lance, which in effect become serious drawbacks. As a\ngeneral thing, therefore, you must first get fast to a whale, before", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5464, "position": 5464, "text": "general thing, therefore, you must first get fast to a whale, before\nany pitchpoling comes into play.\n\nLook now at Stubb; a man who from his humorous, deliberate coolness and\nequanimity in the direst emergencies,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5465, "position": 5465, "text": ", deliberate coolness and\nequanimity in the direst emergencies, was specially qualified to excel\nin pitchpoling. Look at him; he stands upright in the tossed bow of the\nflying boat; wrapt in fleecy foam, the towing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5466, "position": 5466, "text": "bow of the\nflying boat; wrapt in fleecy foam, the towing whale is forty feet\nahead. Handling the long lance lightly, glancing twice or thrice along\nits length to see if it be exactly straight, Stubb whistlingly gathers\nup the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5467, "position": 5467, "text": "to see if it be exactly straight, Stubb whistlingly gathers\nup the coil of the warp in one hand, so as to secure its free end in\nhis grasp, leaving the rest unobstructed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5468, "position": 5468, "text": "the rest unobstructed. Then holding the lance full\nbefore his waistband’s middle, he levels it at the whale; when,\ncovering him with it, he steadily depresses the butt-end in his hand,\nthereby elevating", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5469, "position": 5469, "text": "depresses the butt-end in his hand,\nthereby elevating the point till the weapon stands fairly balanced upon\nhis palm, fifteen feet in the air. He minds you somewhat of a juggler,\nbalancing a long staff on his chin", "labels": {"50": 31, "100": 24, "250": 49, "500": 288, "1000": 692, "2000": 982}}, {"id": 5470, "position": 5470, "text": "you somewhat of a juggler,\nbalancing a long staff on his chin. Next moment with a rapid, nameless\nimpulse, in a superb lofty arch the bright steel spans the foaming\ndistance, and quivers in the life spot of the whale", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5471, "position": 5471, "text": "the foaming\ndistance, and quivers in the life spot of the whale. Instead of\nsparkling water, he now spouts red blood.\n\n“That drove the spigot out of him!” cried Stubb", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5472, "position": 5472, "text": "out of him!” cried Stubb. “’Tis July’s immortal\nFourth; all fountains must run wine today! Would now, it were old\nOrleans whiskey, or old Ohio, or unspeakable old Monongahela! Then", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 327, "2000": 1934}}, {"id": 5473, "position": 5473, "text": "old Ohio, or unspeakable old Monongahela! Then,\nTashtego, lad, I’d have ye hold a canakin to the jet, and we’d drink\nround it! Yea, verily", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5474, "position": 5474, "text": "jet, and we’d drink\nround it! Yea, verily, hearts alive, we’d brew choice punch in the\nspread of his spout-hole there, and from that live punch-bowl quaff the\nliving stuff.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5475, "position": 5475, "text": ", and from that live punch-bowl quaff the\nliving stuff.”\n\nAgain and again to such gamesome talk, the dexterous dart is repeated,\nthe spear returning to its master like a greyhound held in skilful\nleash", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 5476, "position": 5476, "text": "to its master like a greyhound held in skilful\nleash. The agonized whale goes into his flurry; the tow-line is\nslackened, and the pitchpoler dropping astern, folds his hands, and\nmutely watches the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5477, "position": 5477, "text": "poler dropping astern, folds his hands, and\nmutely watches the monster die.\n\n\nCHAPTER 85. The Fountain.\n\nThat for six thousand years—and no one knows how many millions of ages\nbefore—the great whales should have been spouting", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5478, "position": 5478, "text": "many millions of ages\nbefore—the great whales should have been spouting all over the sea, and\nsprinkling and mistifying the gardens of the deep, as with so many\nsprinkling or mistifying pots; and that for some centuries", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5479, "position": 5479, "text": "so many\nsprinkling or mistifying pots; and that for some centuries back,\nthousands of hunters should have been close by the fountain of the\nwhale, watching these sprinklings and spoutings—that all this should\nbe, and yet", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5480, "position": 5480, "text": "klings and spoutings—that all this should\nbe, and yet, that down to this blessed minute (fifteen and a quarter\nminutes past one o’clock P.M. of this sixteenth day of December, A.D", "labels": {"50": 45, "100": 64, "250": 138, "500": 19, "1000": 499, "2000": 629}}, {"id": 5481, "position": 5481, "text": "M. of this sixteenth day of December, A.D.\n1851), it should still remain a problem, whether these spoutings are,\nafter all, really water, or nothing but vapor—this is surely a\nnoteworthy thing.", "labels": {"50": 3, "100": 70, "250": 46, "500": 197, "1000": 109, "2000": 670}}, {"id": 5482, "position": 5482, "text": ", or nothing but vapor—this is surely a\nnoteworthy thing.\n\nLet us, then, look at this matter, along with some interesting items\ncontingent. Every one knows that by the peculiar cunning of their\ngills, the finny tribes in general breathe the", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 5483, "position": 5483, "text": "the peculiar cunning of their\ngills, the finny tribes in general breathe the air which at all times\nis combined with the element in which they swim; hence, a herring or a\ncod might live a century, and never once raise its head above the", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 5484, "position": 5484, "text": "a\ncod might live a century, and never once raise its head above the\nsurface. But owing to his marked internal structure which gives him\nregular lungs, like a human being’s, the whale can only live by\ninhaling the disengaged", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5485, "position": 5485, "text": "s, the whale can only live by\ninhaling the disengaged air in the open atmosphere. Wherefore the\nnecessity for his periodical visits to the upper world. But he cannot\nin any degree breathe through his mouth, for, in his", "labels": {"50": 3, "100": 70, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5486, "position": 5486, "text": "But he cannot\nin any degree breathe through his mouth, for, in his ordinary attitude,\nthe Sperm Whale’s mouth is buried at least eight feet beneath the\nsurface; and what is still more, his windpipe has no connexion with", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5487, "position": 5487, "text": "what is still more, his windpipe has no connexion with his\nmouth. No, he breathes through his spiracle alone; and this is on the\ntop of his head.\n\nIf I say, that in any creature breathing is", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 5488, "position": 5488, "text": "top of his head.\n\nIf I say, that in any creature breathing is only a function\nindispensable to vitality, inasmuch as it withdraws from the air a\ncertain element, which being subsequently brought into contact with the\nblood imp", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 5489, "position": 5489, "text": "air a\ncertain element, which being subsequently brought into contact with the\nblood imparts to the blood its vivifying principle, I do not think I\nshall err; though I may possibly use some superfluous scientific words", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 5490, "position": 5490, "text": "I may possibly use some superfluous scientific words.\nAssume it, and it follows that if all the blood in a man could be\naerated with one breath, he might then seal up his nostrils and not\nfetch another for a considerable time", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 5491, "position": 5491, "text": "then seal up his nostrils and not\nfetch another for a considerable time. That is to say, he would then\nlive without breathing. Anomalous as it may seem, this is precisely the\ncase with the whale, who systematically lives, by intervals,", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5492, "position": 5492, "text": "is precisely the\ncase with the whale, who systematically lives, by intervals, his full\nhour and more (when at the bottom) without drawing a single breath, or\nso much as in any way inhaling a particle of air; for, remember,", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 1620}}, {"id": 5493, "position": 5493, "text": "as in any way inhaling a particle of air; for, remember, he has\nno gills. How is this? Between his ribs and on each side of his spine\nhe is supplied with a remarkable involved Cretan labyrinth of\nvermicelli", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 5494, "position": 5494, "text": "is supplied with a remarkable involved Cretan labyrinth of\nvermicelli-like vessels, which vessels, when he quits the surface, are\ncompletely distended with oxygenated blood. So that for an hour or\nmore, a thousand fat", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 5495, "position": 5495, "text": "oxygenated blood. So that for an hour or\nmore, a thousand fathoms in the sea, he carries a surplus stock of\nvitality in him, just as the camel crossing the waterless desert\ncarries a surplus supply of drink for future use", "labels": {"50": 3, "100": 70, "250": 13, "500": 72, "1000": 134, "2000": 458}}, {"id": 5496, "position": 5496, "text": "camel crossing the waterless desert\ncarries a surplus supply of drink for future use in its four\nsupplementary stomachs. The anatomical fact of this labyrinth is\nindisputable; and that the supposition founded upon it is reasonable\nand true, seems the", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 5497, "position": 5497, "text": "that the supposition founded upon it is reasonable\nand true, seems the more cogent to me, when I consider the otherwise\ninexplicable obstinacy of that leviathan in _having his spoutings out_,\nas", "labels": {"50": 10, "100": 85, "250": 129, "500": 32, "1000": 966, "2000": 511}}, {"id": 5498, "position": 5498, "text": "of that leviathan in _having his spoutings out_,\nas the fishermen phrase it. This is what I mean. If unmolested, upon\nrising to the surface, the Sperm Whale will continue there for a period\nof time exactly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5499, "position": 5499, "text": "the surface, the Sperm Whale will continue there for a period\nof time exactly uniform with all his other unmolested risings. Say he\nstays eleven minutes, and jets seventy times, that is, respires seventy\nbreaths; then whenever he", "labels": {"50": 3, "100": 70, "250": 155, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5500, "position": 5500, "text": "seventy times, that is, respires seventy\nbreaths; then whenever he rises again, he will be sure to have his\nseventy breaths over again, to a minute. Now, if after he fetches a few\nbreaths you alarm him, so that", "labels": {"50": 42, "100": 59, "250": 155, "500": 80, "1000": 8, "2000": 162}}, {"id": 5501, "position": 5501, "text": ", if after he fetches a few\nbreaths you alarm him, so that he sounds, he will be always dodging up\nagain to make good his regular allowance of air. And not till those\nseventy breaths are told, will he finally go down to", "labels": {"50": 31, "100": 24, "250": 52, "500": 417, "1000": 886, "2000": 145}}, {"id": 5502, "position": 5502, "text": "And not till those\nseventy breaths are told, will he finally go down to stay out his full\nterm below. Remark, however, that in different individuals these rates\nare different; but in any one they are alike", "labels": {"50": 31, "100": 76, "250": 24, "500": 37, "1000": 165, "2000": 1741}}, {"id": 5503, "position": 5503, "text": "but in any one they are alike. Now, why should the whale\nthus insist upon having his spoutings out, unless it be to replenish\nhis reservoir of air, ere descending for good? How obvious is it, too,\nthat", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5504, "position": 5504, "text": ", ere descending for good? How obvious is it, too,\nthat this necessity for the whale’s rising exposes him to all the fatal\nhazards of the chase. For not by hook or by net could this vast\nleviathan be caught,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5505, "position": 5505, "text": "For not by hook or by net could this vast\nleviathan be caught, when sailing a thousand fathoms beneath the\nsunlight. Not so much thy skill, then, O hunter, as the great\nnecessities that strike the victory to thee!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5506, "position": 5506, "text": "hunter, as the great\nnecessities that strike the victory to thee!\n\nIn man, breathing is incessantly going on—one breath only serving for\ntwo or three pulsations; so that whatever other business he has to\nattend to, waking", "labels": {"50": 31, "100": 61, "250": 155, "500": 314, "1000": 840, "2000": 1896}}, {"id": 5507, "position": 5507, "text": "lsations; so that whatever other business he has to\nattend to, waking or sleeping, breathe he must, or die he will. But the\nSperm Whale only breathes about one seventh or Sunday of his time.", "labels": {"50": 10, "100": 71, "250": 155, "500": 403, "1000": 845, "2000": 268}}, {"id": 5508, "position": 5508, "text": "one seventh or Sunday of his time.\n\nIt has been said that the whale only breathes through his spout-hole;\nif it could truthfully be added that his spouts are mixed with water,\nthen I opine we should be furnished with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5509, "position": 5509, "text": "outs are mixed with water,\nthen I opine we should be furnished with the reason why his sense of\nsmell seems obliterated in him; for the only thing about him that at\nall answers to his nose is that identical spout-hole;", "labels": {"50": 9, "100": 64, "250": 30, "500": 475, "1000": 902, "2000": 1620}}, {"id": 5510, "position": 5510, "text": "that at\nall answers to his nose is that identical spout-hole; and being so\nclogged with two elements, it could not be expected to have the power\nof smelling. But owing to the mystery of the spout—whether it be", "labels": {"50": 42, "100": 70, "250": 46, "500": 16, "1000": 134, "2000": 1333}}, {"id": 5511, "position": 5511, "text": "smelling. But owing to the mystery of the spout—whether it be water\nor whether it be vapor—no absolute certainty can as yet be arrived at\non this head. Sure it is, nevertheless, that the Sperm Whale has no\nproper olfa", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5512, "position": 5512, "text": "Sure it is, nevertheless, that the Sperm Whale has no\nproper olfactories. But what does he want of them? No roses, no\nviolets, no Cologne-water in the sea.", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5513, "position": 5513, "text": "-water in the sea.\n\nFurthermore, as his windpipe solely opens into the tube of his spouting\ncanal, and as that long canal—like the grand Erie Canal—is furnished\nwith a sort of locks (that open and shut) for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5514, "position": 5514, "text": "—is furnished\nwith a sort of locks (that open and shut) for the downward retention of\nair or the upward exclusion of water, therefore the whale has no voice;\nunless you insult him by saying, that when he so strangely rumbles, he", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5515, "position": 5515, "text": "you insult him by saying, that when he so strangely rumbles, he\ntalks through his nose. But then again, what has the whale to say?\nSeldom have I known any profound being that had anything to say to this\nworld, unless forced to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5516, "position": 5516, "text": "any profound being that had anything to say to this\nworld, unless forced to stammer out something by way of getting a\nliving. Oh! happy that the world is such an excellent listener!\n\nNow, the spouting canal of the Sperm Whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5517, "position": 5517, "text": "an excellent listener!\n\nNow, the spouting canal of the Sperm Whale, chiefly intended as it is\nfor the conveyance of air, and for several feet laid along,\nhorizontally, just beneath the upper surface of his head, and a little\nto", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5518, "position": 5518, "text": "horizontally, just beneath the upper surface of his head, and a little\nto one side; this curious canal is very much like a gas-pipe laid down\nin a city on one side of a street. But the question returns whether\nthis gas-pipe", "labels": {"50": 31, "100": 20, "250": 49, "500": 453, "1000": 134, "2000": 1081}}, {"id": 5519, "position": 5519, "text": "one side of a street. But the question returns whether\nthis gas-pipe is also a water-pipe; in other words, whether the spout\nof the Sperm Whale is the mere vapor of the exhaled breath, or whether\nthat exhaled breath is mixed", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5520, "position": 5520, "text": "the mere vapor of the exhaled breath, or whether\nthat exhaled breath is mixed with water taken in at the mouth, and\ndischarged through the spiracle. It is certain that the mouth\nindirectly communicates with the spouting canal; but it cannot", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 5521, "position": 5521, "text": "the mouth\nindirectly communicates with the spouting canal; but it cannot be\nproved that this is for the purpose of discharging water through the\nspiracle. Because the greatest necessity for so doing would seem to be,\nwhen in feeding he", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 5522, "position": 5522, "text": "the greatest necessity for so doing would seem to be,\nwhen in feeding he accidentally takes in water. But the Sperm Whale’s\nfood is far beneath the surface, and there he cannot spout even if he\nwould", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5523, "position": 5523, "text": "he cannot spout even if he\nwould. Besides, if you regard him very closely, and time him with your\nwatch, you will find that when unmolested, there is an undeviating\nrhyme between the periods of his jets and the", "labels": {"50": 31, "100": 7, "250": 49, "500": 78, "1000": 387, "2000": 1081}}, {"id": 5524, "position": 5524, "text": "there is an undeviating\nrhyme between the periods of his jets and the ordinary periods of\nrespiration.\n\nBut why pester one with all this reasoning on the subject? Speak out!\nYou have seen him spout; then declare what the spout", "labels": {"50": 31, "100": 7, "250": 49, "500": 453, "1000": 134, "2000": 1050}}, {"id": 5525, "position": 5525, "text": "out!\nYou have seen him spout; then declare what the spout is; can you not\ntell water from air? My dear sir, in this world it is not so easy to\nsettle these plain things", "labels": {"50": 3, "100": 70, "250": 46, "500": 72, "1000": 875, "2000": 1620}}, {"id": 5526, "position": 5526, "text": "so easy to\nsettle these plain things. I have ever found your plain things the\nknottiest of all. And as for this whale spout, you might almost stand\nin it, and yet be undecided as to what it is precisely.", "labels": {"50": 11, "100": 9, "250": 207, "500": 305, "1000": 568, "2000": 621}}, {"id": 5527, "position": 5527, "text": "it, and yet be undecided as to what it is precisely.\n\nThe central body of it is hidden in the snowy sparkling mist enveloping\nit; and how can you certainly tell whether any water falls from it,\nwhen, always, when", "labels": {"50": 48, "100": 20, "250": 192, "500": 126, "1000": 747, "2000": 1560}}, {"id": 5528, "position": 5528, "text": "you certainly tell whether any water falls from it,\nwhen, always, when you are close enough to a whale to get a close view\nof his spout, he is in a prodigious commotion, the water cascading all\naround him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5529, "position": 5529, "text": "a prodigious commotion, the water cascading all\naround him. And if at such times you should think that you really\nperceived drops of moisture in the spout, how do you know that they are\nnot merely condensed from its vapor;", "labels": {"50": 31, "100": 75, "250": 46, "500": 102, "1000": 875, "2000": 1548}}, {"id": 5530, "position": 5530, "text": ", how do you know that they are\nnot merely condensed from its vapor; or how do you know that they are\nnot those identical drops superficially lodged in the spout-hole\nfissure, which is countersunk into the summit of the whale’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5531, "position": 5531, "text": "hole\nfissure, which is countersunk into the summit of the whale’s head? For\neven when tranquilly swimming through the mid-day sea in a calm, with\nhis elevated hump sun-dried as a dromedary’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5532, "position": 5532, "text": "with\nhis elevated hump sun-dried as a dromedary’s in the desert; even then,\nthe whale always carries a small basin of water on his head, as under a\nblazing sun you will sometimes see a cavity in a rock", "labels": {"50": 32, "100": 0, "250": 233, "500": 72, "1000": 856, "2000": 1620}}, {"id": 5533, "position": 5533, "text": ", as under a\nblazing sun you will sometimes see a cavity in a rock filled up with\nrain.\n\nNor is it at all prudent for the hunter to be over curious touching the\nprecise nature of the whale spout", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5534, "position": 5534, "text": "touching the\nprecise nature of the whale spout. It will not do for him to be peering\ninto it, and putting his face in it. You cannot go with your pitcher to\nthis fountain and fill it, and bring it away", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5535, "position": 5535, "text": "to\nthis fountain and fill it, and bring it away. For even when coming into\nslight contact with the outer, vapory shreds of the jet, which will\noften happen, your skin will feverishly smart, from the acridness of", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 5536, "position": 5536, "text": "happen, your skin will feverishly smart, from the acridness of\nthe thing so touching it. And I know one, who coming into still closer\ncontact with the spout, whether with some scientific object in view, or\notherwise, I cannot", "labels": {"50": 3, "100": 70, "250": 46, "500": 395, "1000": 109, "2000": 458}}, {"id": 5537, "position": 5537, "text": "out, whether with some scientific object in view, or\notherwise, I cannot say, the skin peeled off from his cheek and arm.\nWherefore, among whalemen, the spout is deemed poisonous; they try to\nevade it", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5538, "position": 5538, "text": "the spout is deemed poisonous; they try to\nevade it. Another thing; I have heard it said, and I do not much doubt\nit, that if the jet is fairly spouted into your eyes, it will blind\nyou", "labels": {"50": 42, "100": 24, "250": 46, "500": 288, "1000": 109, "2000": 1548}}, {"id": 5539, "position": 5539, "text": "fairly spouted into your eyes, it will blind\nyou. The wisest thing the investigator can do then, it seems to me, is\nto let this deadly spout alone.\n\nStill, we can hypothesize, even if we", "labels": {"50": 39, "100": 39, "250": 79, "500": 376, "1000": 744, "2000": 882}}, {"id": 5540, "position": 5540, "text": "alone.\n\nStill, we can hypothesize, even if we cannot prove and establish. My\nhypothesis is this: that the spout is nothing but mist. And besides\nother reasons, to this conclusion I am impelled, by considerations\ntouching", "labels": {"50": 3, "100": 24, "250": 213, "500": 255, "1000": 546, "2000": 831}}, {"id": 5541, "position": 5541, "text": "besides\nother reasons, to this conclusion I am impelled, by considerations\ntouching the great inherent dignity and sublimity of the Sperm Whale; I\naccount him no common, shallow being, inasmuch as it is an undisputed\nfact that he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5542, "position": 5542, "text": "being, inasmuch as it is an undisputed\nfact that he is never found on soundings, or near shores; all other\nwhales sometimes are. He is both ponderous and profound. And I am\nconvinced that from the heads of all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5543, "position": 5543, "text": "ponderous and profound. And I am\nconvinced that from the heads of all ponderous profound beings, such as\nPlato, Pyrrho, the Devil, Jupiter, Dante, and so on, there always goes\nup a certain semi-visible steam", "labels": {"50": 10, "100": 71, "250": 69, "500": 455, "1000": 811, "2000": 506}}, {"id": 5544, "position": 5544, "text": ", and so on, there always goes\nup a certain semi-visible steam, while in the act of thinking deep\nthoughts. While composing a little treatise on Eternity, I had the\ncuriosity to place a mirror before me; and ere long saw reflected", "labels": {"50": 35, "100": 75, "250": 13, "500": 198, "1000": 616, "2000": 172}}, {"id": 5545, "position": 5545, "text": "the\ncuriosity to place a mirror before me; and ere long saw reflected\nthere, a curious involved worming and undulation in the atmosphere over\nmy head. The invariable moisture of my hair, while plunged in deep\nthought, after six cups", "labels": {"50": 16, "100": 73, "250": 26, "500": 441, "1000": 914, "2000": 193}}, {"id": 5546, "position": 5546, "text": "iable moisture of my hair, while plunged in deep\nthought, after six cups of hot tea in my thin shingled attic, of an\nAugust noon; this seems an additional argument for the above\nsupposition.", "labels": {"50": 31, "100": 20, "250": 132, "500": 412, "1000": 727, "2000": 1107}}, {"id": 5547, "position": 5547, "text": "for the above\nsupposition.\n\nAnd how nobly it raises our conceit of the mighty, misty monster, to\nbehold him solemnly sailing through a calm tropical sea; his vast, mild\nhead overhung by a canopy of vapor, eng", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5548, "position": 5548, "text": "his vast, mild\nhead overhung by a canopy of vapor, engendered by his incommunicable\ncontemplations, and that vapor—as you will sometimes see it—glorified\nby a rainbow, as if Heaven", "labels": {"50": 48, "100": 20, "250": 87, "500": 126, "1000": 727, "2000": 970}}, {"id": 5549, "position": 5549, "text": "will sometimes see it—glorified\nby a rainbow, as if Heaven itself had put its seal upon his thoughts.\nFor, d’ye see, rainbows do not visit the clear air; they only irradiate\nvapor", "labels": {"50": 16, "100": 20, "250": 210, "500": 162, "1000": 747, "2000": 1710}}, {"id": 5550, "position": 5550, "text": "visit the clear air; they only irradiate\nvapor. And so, through all the thick mists of the dim doubts in my\nmind, divine intuitions now and then shoot, enkindling my fog with a\nheavenly ray", "labels": {"50": 16, "100": 73, "250": 13, "500": 414, "1000": 747, "2000": 1555}}, {"id": 5551, "position": 5551, "text": "shoot, enkindling my fog with a\nheavenly ray. And for this I thank God; for all have doubts; many deny;\nbut doubts or denials, few along with them, have intuitions", "labels": {"50": 9, "100": 73, "250": 133, "500": 498, "1000": 637, "2000": 16}}, {"id": 5552, "position": 5552, "text": "with them, have intuitions. Doubts of\nall things earthly, and intuitions of some things heavenly; this\ncombination makes neither believer nor infidel, but makes a man who\nregards them both with equal eye.\n\n\nCHAPTER 86. The Tail.", "labels": {"50": 10, "100": 71, "250": 33, "500": 236, "1000": 368, "2000": 1201}}, {"id": 5553, "position": 5553, "text": "who\nregards them both with equal eye.\n\n\nCHAPTER 86. The Tail.\n\nOther poets have warbled the praises of the soft eye of the antelope,\nand the lovely plumage of the bird that never alights; less celestial,\nI celebrate a", "labels": {"50": 31, "100": 20, "250": 87, "500": 126, "1000": 944, "2000": 1560}}, {"id": 5554, "position": 5554, "text": "of the bird that never alights; less celestial,\nI celebrate a tail.\n\nReckoning the largest sized Sperm Whale’s tail to begin at that point\nof the trunk where it tapers to about the girth of a man, it comprises", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5555, "position": 5555, "text": "where it tapers to about the girth of a man, it comprises\nupon its upper surface alone, an area of at least fifty square feet.\nThe compact round body of its root expands into two broad, firm, flat\npalms or flukes,", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 505, "2000": 1905}}, {"id": 5556, "position": 5556, "text": "its root expands into two broad, firm, flat\npalms or flukes, gradually shoaling away to less than an inch in\nthickness. At the crotch or junction, these flukes slightly overlap,\nthen sideways recede from each other like wings, leaving", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 546, "2000": 1225}}, {"id": 5557, "position": 5557, "text": "kes slightly overlap,\nthen sideways recede from each other like wings, leaving a wide vacancy\nbetween. In no living thing are the lines of beauty more exquisitely\ndefined than in the crescentic borders of these flukes", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 5558, "position": 5558, "text": "the crescentic borders of these flukes. At its utmost\nexpansion in the full grown whale, the tail will considerably exceed\ntwenty feet across.\n\nThe entire member seems a dense webbed bed of welded sinews; but cut\ninto it, and you", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5559, "position": 5559, "text": "ed bed of welded sinews; but cut\ninto it, and you find that three distinct strata compose it:—upper,\nmiddle, and lower. The fibres in the upper and lower layers, are long\nand horizontal; those of the middle", "labels": {"50": 3, "100": 70, "250": 234, "500": 108, "1000": 37, "2000": 1409}}, {"id": 5560, "position": 5560, "text": "the upper and lower layers, are long\nand horizontal; those of the middle one, very short, and running\ncrosswise between the outside layers. This triune structure, as much as\nanything else, imparts power to the tail", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 634, "2000": 1225}}, {"id": 5561, "position": 5561, "text": "much as\nanything else, imparts power to the tail. To the student of old Roman\nwalls, the middle layer will furnish a curious parallel to the thin\ncourse of tiles always alternating with the stone in those wonderful\nrelics of the antique, and which", "labels": {"50": 48, "100": 20, "250": 213, "500": 255, "1000": 546, "2000": 831}}, {"id": 5562, "position": 5562, "text": "always alternating with the stone in those wonderful\nrelics of the antique, and which undoubtedly contribute so much to the\ngreat strength of the masonry.\n\nBut as if this vast local power in the tendinous tail were not enough,\nthe whole bulk of the levi", "labels": {"50": 48, "100": 27, "250": 157, "500": 339, "1000": 619, "2000": 168}}, {"id": 5563, "position": 5563, "text": "the tendinous tail were not enough,\nthe whole bulk of the leviathan is knit over with a warp and woof of\nmuscular fibres and filaments, which passing on either side the loins\nand running down into the flukes,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5564, "position": 5564, "text": "passing on either side the loins\nand running down into the flukes, insensibly blend with them, and\nlargely contribute to their might; so that in the tail the confluent\nmeasureless force of the whole whale seems concentrated to a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5565, "position": 5565, "text": "confluent\nmeasureless force of the whole whale seems concentrated to a point.\nCould annihilation occur to matter, this were the thing to do it.\n\nNor does this—its amazing strength, at all tend to cripple the graceful", "labels": {"50": 3, "100": 70, "250": 50, "500": 395, "1000": 134, "2000": 1374}}, {"id": 5566, "position": 5566, "text": "this—its amazing strength, at all tend to cripple the graceful\nflexion of its motions; where infantileness of ease undulates through a\nTitanism of power. On the contrary, those motions derive their most\nappalling beauty from", "labels": {"50": 10, "100": 75, "250": 232, "500": 483, "1000": 100, "2000": 1944}}, {"id": 5567, "position": 5567, "text": ". On the contrary, those motions derive their most\nappalling beauty from it. Real strength never impairs beauty or\nharmony, but it often bestows it; and in everything imposingly\nbeautiful, strength has much to do with the magic", "labels": {"50": 10, "100": 71, "250": 232, "500": 483, "1000": 100, "2000": 1916}}, {"id": 5568, "position": 5568, "text": "in everything imposingly\nbeautiful, strength has much to do with the magic. Take away the tied\ntendons that all over seem bursting from the marble in the carved\nHercules, and its charm would be gone. As devout Eckerman lifted the\nlinen sheet", "labels": {"50": 48, "100": 27, "250": 249, "500": 77, "1000": 878, "2000": 180}}, {"id": 5569, "position": 5569, "text": "its charm would be gone. As devout Eckerman lifted the\nlinen sheet from the naked corpse of Goethe, he was overwhelmed with\nthe massive chest of the man, that seemed as a Roman triumphal arch", "labels": {"50": 49, "100": 78, "250": 196, "500": 370, "1000": 375, "2000": 1252}}, {"id": 5570, "position": 5570, "text": "as a Roman triumphal arch.\nWhen Angelo paints even God the Father in human form, mark what\nrobustness is there. And whatever they may reveal of the divine love in\nthe Son, the soft, curled, hermaphroditical Italian pictures", "labels": {"50": 49, "100": 74, "250": 184, "500": 275, "1000": 762, "2000": 175}}, {"id": 5571, "position": 5571, "text": "the Son, the soft, curled, hermaphroditical Italian pictures, in which\nhis idea has been most successfully embodied; these pictures, so\ndestitute as they are of all brawniness, hint nothing of any power, but\nthe", "labels": {"50": 17, "100": 16, "250": 196, "500": 322, "1000": 212, "2000": 765}}, {"id": 5572, "position": 5572, "text": "are of all brawniness, hint nothing of any power, but\nthe mere negative, feminine one of submission and endurance, which on\nall hands it is conceded, form the peculiar practical virtues of his\nteachings.", "labels": {"50": 31, "100": 61, "250": 167, "500": 417, "1000": 821, "2000": 394}}, {"id": 5573, "position": 5573, "text": "peculiar practical virtues of his\nteachings.\n\nSuch is the subtle elasticity of the organ I treat of, that whether\nwielded in sport, or in earnest, or in anger, whatever be the mood it\nbe in, its flexions are invariably marked", "labels": {"50": 1, "100": 49, "250": 155, "500": 80, "1000": 141, "2000": 90}}, {"id": 5574, "position": 5574, "text": ", whatever be the mood it\nbe in, its flexions are invariably marked by exceeding grace. Therein\nno fairy’s arm can transcend it.\n\nFive great motions are peculiar to it. First, when used as a fin for\nprogression; Second", "labels": {"50": 24, "100": 71, "250": 232, "500": 464, "1000": 845, "2000": 1191}}, {"id": 5575, "position": 5575, "text": "peculiar to it. First, when used as a fin for\nprogression; Second, when used as a mace in battle; Third, in sweeping;\nFourth, in lobtailing; Fifth, in peaking flukes.", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 5576, "position": 5576, "text": "; Fifth, in peaking flukes.\n\nFirst: Being horizontal in its position, the Leviathan’s tail acts in a\ndifferent manner from the tails of all other sea creatures. It never\nwriggles", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 5577, "position": 5577, "text": ". It never\nwriggles. In man or fish, wriggling is a sign of inferiority. To the\nwhale, his tail is the sole means of propulsion. Scroll-wise coiled\nforwards beneath the body, and then rapidly sprung backwards,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5578, "position": 5578, "text": "Scroll-wise coiled\nforwards beneath the body, and then rapidly sprung backwards, it is\nthis which gives that singular darting, leaping motion to the monster\nwhen furiously swimming. His side-fins only serve to steer by.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5579, "position": 5579, "text": "-fins only serve to steer by.\n\nSecond: It is a little significant, that while one sperm whale only\nfights another sperm whale with his head and jaw, nevertheless, in his\nconflicts with man, he chiefly and contemptuously uses his tail", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5580, "position": 5580, "text": "his\nconflicts with man, he chiefly and contemptuously uses his tail. In\nstriking at a boat, he swiftly curves away his flukes from it, and the\nblow is only inflicted by the recoil. If it be made in the unobstructed", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 825, "2000": 1225}}, {"id": 5581, "position": 5581, "text": "inflicted by the recoil. If it be made in the unobstructed\nair, especially if it descend to its mark, the stroke is then simply\nirresistible. No ribs of man or boat can withstand it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 393, "2000": 1620}}, {"id": 5582, "position": 5582, "text": "man or boat can withstand it. Your only\nsalvation lies in eluding it; but if it comes sideways through the\nopposing water, then partly owing to the light buoyancy of the\nwhale-boat, and the elasticity of its materials, a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 99, "2000": 1904}}, {"id": 5583, "position": 5583, "text": "of the\nwhale-boat, and the elasticity of its materials, a cracked rib or a\ndashed plank or two, a sort of stitch in the side, is generally the\nmost serious result. These submerged side blows are so often received\nin the fishery", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5584, "position": 5584, "text": "most serious result. These submerged side blows are so often received\nin the fishery, that they are accounted mere child’s play. Some one\nstrips off a frock, and the hole is stopped.\n\nThird: I cannot demonstrate it, but it seems", "labels": {"50": 45, "100": 24, "250": 24, "500": 72, "1000": 692, "2000": 447}}, {"id": 5585, "position": 5585, "text": "the hole is stopped.\n\nThird: I cannot demonstrate it, but it seems to me, that in the whale\nthe sense of touch is concentrated in the tail; for in this respect\nthere is a delicacy in it only equalled by the dai", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5586, "position": 5586, "text": "respect\nthere is a delicacy in it only equalled by the daintiness of the\nelephant’s trunk. This delicacy is chiefly evinced in the action of\nsweeping, when in maidenly gentleness the whale with a certain", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5587, "position": 5587, "text": "action of\nsweeping, when in maidenly gentleness the whale with a certain soft\nslowness moves his immense flukes from side to side upon the surface of\nthe sea; and if he feel but a sailor’s whisker, woe to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5588, "position": 5588, "text": "if he feel but a sailor’s whisker, woe to that sailor,\nwhiskers and all. What tenderness there is in that preliminary touch!\nHad this tail any prehensile power, I should straightway bethink me", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5589, "position": 5589, "text": "tail any prehensile power, I should straightway bethink me of\nDarmonodes’ elephant that so frequented the flower-market, and with low\nsalutations presented nosegays to damsels, and then caressed their\nzones", "labels": {"50": 9, "100": 2, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 5590, "position": 5590, "text": "presented nosegays to damsels, and then caressed their\nzones. On more accounts than one, a pity it is that the whale does not\npossess this prehensile virtue in his tail; for I have heard of yet\nanother elephant, that", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5591, "position": 5591, "text": "virtue in his tail; for I have heard of yet\nanother elephant, that when wounded in the fight, curved round his\ntrunk and extracted the dart.\n\nFourth: Stealing unawares upon the whale in the fancied security of the\nmiddle of solitary seas", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5592, "position": 5592, "text": "upon the whale in the fancied security of the\nmiddle of solitary seas, you find him unbent from the vast corpulence\nof his dignity, and kitten-like, he plays on the ocean as if it were a\nhearth", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5593, "position": 5593, "text": "like, he plays on the ocean as if it were a\nhearth. But still you see his power in his play. The broad palms of his\ntail are flirted high into the air; then smiting the surface, the\nthunderous concussion resound", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1225}}, {"id": 5594, "position": 5594, "text": "the air; then smiting the surface, the\nthunderous concussion resounds for miles. You would almost think a\ngreat gun had been discharged; and if you noticed the light wreath of\nvapor from the spiracle at his other extremity", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 825, "2000": 1620}}, {"id": 5595, "position": 5595, "text": "light wreath of\nvapor from the spiracle at his other extremity, you would think that\nthat was the smoke from the touch-hole.\n\nFifth: As in the ordinary floating posture of the leviathan the flukes\nlie considerably below the level", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5596, "position": 5596, "text": "ordinary floating posture of the leviathan the flukes\nlie considerably below the level of his back, they are then completely\nout of sight beneath the surface; but when he is about to plunge into\nthe deeps, his entire flukes with at least thirty", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5597, "position": 5597, "text": "to plunge into\nthe deeps, his entire flukes with at least thirty feet of his body are\ntossed erect in the air, and so remain vibrating a moment, till they\ndownwards shoot out of view. Excepting the sublime _breach_—somewhere", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5598, "position": 5598, "text": "downwards shoot out of view. Excepting the sublime _breach_—somewhere\nelse to be described—this peaking of the whale’s flukes is perhaps the\ngrandest sight to be seen in all animated nature", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5599, "position": 5599, "text": "to be seen in all animated nature. Out of the bottomless\nprofundities the gigantic tail seems spasmodically snatching at the\nhighest heaven. So in dreams, have I seen majestic Satan thrusting\nforth his tormented colossal claw from the flame Baltic", "labels": {"50": 48, "100": 20, "250": 192, "500": 392, "1000": 705, "2000": 1974}}, {"id": 5600, "position": 5600, "text": "have I seen majestic Satan thrusting\nforth his tormented colossal claw from the flame Baltic of Hell. But in\ngazing at such scenes, it is all in all what mood you are in; if in the\nDantean, the devils will occur to you; if", "labels": {"50": 49, "100": 74, "250": 223, "500": 275, "1000": 517, "2000": 165}}, {"id": 5601, "position": 5601, "text": "; if in the\nDantean, the devils will occur to you; if in that of Isaiah, the\narchangels. Standing at the mast-head of my ship during a sunrise that\ncrimsoned sky and sea, I once saw a large herd of", "labels": {"50": 8, "100": 14, "250": 132, "500": 374, "1000": 27, "2000": 1037}}, {"id": 5602, "position": 5602, "text": "sunrise that\ncrimsoned sky and sea, I once saw a large herd of whales in the east,\nall heading towards the sun, and for a moment vibrating in concert with\npeaked flukes. As it seemed to me at the time, such a grand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5603, "position": 5603, "text": "flukes. As it seemed to me at the time, such a grand embodiment\nof adoration of the gods was never beheld, even in Persia, the home of\nthe fire worshippers. As Ptolemy Philopater testified of the African", "labels": {"50": 32, "100": 42, "250": 211, "500": 490, "1000": 507, "2000": 215}}, {"id": 5604, "position": 5604, "text": "of\nthe fire worshippers. As Ptolemy Philopater testified of the African\nelephant, I then testified of the whale, pronouncing him the most\ndevout of all beings. For according to King Juba, the military\nelephants of antiquity often hailed", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5605, "position": 5605, "text": ". For according to King Juba, the military\nelephants of antiquity often hailed the morning with their trunks\nuplifted in the profoundest silence.\n\nThe chance comparison in this chapter, between the whale and the\nelephant, so far as some aspects of the", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 505, "2000": 1620}}, {"id": 5606, "position": 5606, "text": ", between the whale and the\nelephant, so far as some aspects of the tail of the one and the trunk\nof the other are concerned, should not tend to place those two opposite\norgans on an equality, much less the creatures to which they\nrespectively belong", "labels": {"50": 3, "100": 85, "250": 14, "500": 403, "1000": 634, "2000": 313}}, {"id": 5607, "position": 5607, "text": "opposite\norgans on an equality, much less the creatures to which they\nrespectively belong. For as the mightiest elephant is but a terrier to\nLeviathan, so, compared with Leviathan’s tail, his trunk is but the\nstalk of a lily", "labels": {"50": 3, "100": 24, "250": 14, "500": 403, "1000": 134, "2000": 458}}, {"id": 5608, "position": 5608, "text": "Leviathan’s tail, his trunk is but the\nstalk of a lily. The most direful blow from the elephant’s trunk were\nas the playful tap of a fan, compared with the measureless crush and\ncrash of the sperm whale’s", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5609, "position": 5609, "text": ", compared with the measureless crush and\ncrash of the sperm whale’s ponderous flukes, which in repeated\ninstances have one after the other hurled entire boats with all their\noars and crews into the air, very much as an Indian juggler", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5610, "position": 5610, "text": "oars and crews into the air, very much as an Indian juggler tosses his\nballs.*\n\n*Though all comparison in the way of general bulk between the whale and\nthe elephant is preposterous, inasmuch as in that particular", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5611, "position": 5611, "text": "the elephant is preposterous, inasmuch as in that particular the\nelephant stands in much the same respect to the whale that a dog does\nto the elephant; nevertheless, there are not wanting some points of\ncurious similitude; among these", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5612, "position": 5612, "text": ", there are not wanting some points of\ncurious similitude; among these is the spout. It is well known that the\nelephant will often draw up water or dust in his trunk, and then\nelevating it, jet it forth in a", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 145}}, {"id": 5613, "position": 5613, "text": "his trunk, and then\nelevating it, jet it forth in a stream.\n\nThe more I consider this mighty tail, the more do I deplore my\ninability to express it. At times there are gestures in it, which,\nthough they", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 145}}, {"id": 5614, "position": 5614, "text": "express it. At times there are gestures in it, which,\nthough they would well grace the hand of man, remain wholly\ninexplicable. In an extensive herd, so remarkable, occasionally, are\nthese mystic gestures, that I have heard", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5615, "position": 5615, "text": ", so remarkable, occasionally, are\nthese mystic gestures, that I have heard hunters who have declared them\nakin to Free-Mason signs and symbols; that the whale, indeed, by these\nmethods intelligently conversed with the world", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5616, "position": 5616, "text": "by these\nmethods intelligently conversed with the world. Nor are there wanting\nother motions of the whale in his general body, full of strangeness,\nand unaccountable to his most experienced assailant", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5617, "position": 5617, "text": "to his most experienced assailant. Dissect him how I\nmay, then, I but go skin deep; I know him not, and never will. But if I\nknow not even the tail of this whale, how understand his head?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5618, "position": 5618, "text": "I\nknow not even the tail of this whale, how understand his head? much\nmore, how comprehend his face, when face he has none? Thou shalt see my\nback parts, my tail, he seems to say, but my face shall not", "labels": {"50": 27, "100": 97, "250": 112, "500": 72, "1000": 503, "2000": 1620}}, {"id": 5619, "position": 5619, "text": "parts, my tail, he seems to say, but my face shall not be seen.\nBut I cannot completely make out his back parts; and hint what he will\nabout his face, I say again he has no face.\n\n\nCHAPTER 87", "labels": {"50": 17, "100": 40, "250": 146, "500": 369, "1000": 667, "2000": 1520}}, {"id": 5620, "position": 5620, "text": "face, I say again he has no face.\n\n\nCHAPTER 87. The Grand Armada.\n\nThe long and narrow peninsula of Malacca, extending south-eastward from\nthe territories of Birmah, forms the most southerly point of all Asia", "labels": {"50": 32, "100": 42, "250": 130, "500": 247, "1000": 569, "2000": 1669}}, {"id": 5621, "position": 5621, "text": "h, forms the most southerly point of all Asia.\nIn a continuous line from that peninsula stretch the long islands of\nSumatra, Java, Bally, and Timor; which, with many others, form a vast\nmole, or rampart, length", "labels": {"50": 32, "100": 42, "250": 139, "500": 466, "1000": 569, "2000": 1669}}, {"id": 5622, "position": 5622, "text": ", with many others, form a vast\nmole, or rampart, lengthwise connecting Asia with Australia, and\ndividing the long unbroken Indian ocean from the thickly studded\noriental archipelagoes. This rampart is pierced by several sally-ports\nfor the", "labels": {"50": 3, "100": 85, "250": 234, "500": 102, "1000": 825, "2000": 1887}}, {"id": 5623, "position": 5623, "text": "archipelagoes. This rampart is pierced by several sally-ports\nfor the convenience of ships and whales; conspicuous among which are\nthe straits of Sunda and Malacca. By the straits of Sunda, chiefly,\nvessels bound to China from the west,", "labels": {"50": 45, "100": 29, "250": 161, "500": 13, "1000": 622, "2000": 887}}, {"id": 5624, "position": 5624, "text": "straits of Sunda, chiefly,\nvessels bound to China from the west, emerge into the China seas.\n\nThose narrow straits of Sunda divide Sumatra from Java; and standing\nmidway in that vast rampart of islands, buttressed by that bold green\npromo", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 567, "2000": 1669}}, {"id": 5625, "position": 5625, "text": "in that vast rampart of islands, buttressed by that bold green\npromontory, known to seamen as Java Head; they not a little correspond\nto the central gateway opening into some vast walled empire: and\nconsidering the inexhaustible wealth", "labels": {"50": 21, "100": 95, "250": 76, "500": 307, "1000": 343, "2000": 761}}, {"id": 5626, "position": 5626, "text": "into some vast walled empire: and\nconsidering the inexhaustible wealth of spices, and silks, and jewels,\nand gold, and ivory, with which the thousand islands of that oriental\nsea are enriched, it seems a significant provision of nature", "labels": {"50": 32, "100": 0, "250": 30, "500": 13, "1000": 825, "2000": 199}}, {"id": 5627, "position": 5627, "text": "islands of that oriental\nsea are enriched, it seems a significant provision of nature, that such\ntreasures, by the very formation of the land, should at least bear the\nappearance, however ineffectual, of being guarded from the all-grasping\nwestern", "labels": {"50": 3, "100": 29, "250": 34, "500": 306, "1000": 622, "2000": 1856}}, {"id": 5628, "position": 5628, "text": "however ineffectual, of being guarded from the all-grasping\nwestern world. The shores of the Straits of Sunda are unsupplied with\nthose domineering fortresses which guard the entrances to the\nMediterranean, the Baltic, and", "labels": {"50": 21, "100": 95, "250": 76, "500": 480, "1000": 451, "2000": 1536}}, {"id": 5629, "position": 5629, "text": "ering fortresses which guard the entrances to the\nMediterranean, the Baltic, and the Propontis. Unlike the Danes, these\nOrientals do not demand the obsequious homage of lowered top-sails from\nthe endless procession of ships before the wind", "labels": {"50": 26, "100": 67, "250": 246, "500": 23, "1000": 87, "2000": 98}}, {"id": 5630, "position": 5630, "text": "homage of lowered top-sails from\nthe endless procession of ships before the wind, which for centuries\npast, by night and by day, have passed between the islands of Sumatra\nand Java, freighted with the costliest cargoes of the east", "labels": {"50": 45, "100": 29, "250": 82, "500": 79, "1000": 354, "2000": 1200}}, {"id": 5631, "position": 5631, "text": "Java, freighted with the costliest cargoes of the east. But while\nthey freely waive a ceremonial like this, they do by no means renounce\ntheir claim to more solid tribute.\n\nTime out of mind the piratical proas of", "labels": {"50": 21, "100": 95, "250": 76, "500": 455, "1000": 581, "2000": 1184}}, {"id": 5632, "position": 5632, "text": "more solid tribute.\n\nTime out of mind the piratical proas of the Malays, lurking among the\nlow shaded coves and islets of Sumatra, have sallied out upon the\nvessels sailing through the straits, fiercely demanding tribute at the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 5633, "position": 5633, "text": "d out upon the\nvessels sailing through the straits, fiercely demanding tribute at the\npoint of their spears. Though by the repeated bloody chastisements they\nhave received at the hands of European cruisers, the audacity of these\ncorsairs has of", "labels": {"50": 45, "100": 29, "250": 82, "500": 79, "1000": 354, "2000": 1200}}, {"id": 5634, "position": 5634, "text": "of European cruisers, the audacity of these\ncorsairs has of late been somewhat repressed; yet, even at the present\nday, we occasionally hear of English and American vessels, which, in\nthose waters, have been remorselessly boarded and", "labels": {"50": 21, "100": 29, "250": 82, "500": 480, "1000": 451, "2000": 759}}, {"id": 5635, "position": 5635, "text": "American vessels, which, in\nthose waters, have been remorselessly boarded and pillaged.\n\nWith a fair, fresh wind, the Pequod was now drawing nigh to these\nstraits; Ahab purposing to pass through them into the Java", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5636, "position": 5636, "text": "these\nstraits; Ahab purposing to pass through them into the Javan sea, and\nthence, cruising northwards, over waters known to be frequented here\nand there by the Sperm Whale, sweep inshore by the Philippine Islands,\nand gain the far", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5637, "position": 5637, "text": "Sperm Whale, sweep inshore by the Philippine Islands,\nand gain the far coast of Japan, in time for the great whaling season\nthere. By these means, the circumnavigating Pequod would sweep almost\nall the known Sperm Whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5638, "position": 5638, "text": "umnavigating Pequod would sweep almost\nall the known Sperm Whale cruising grounds of the world, previous to\ndescending upon the Line in the Pacific; where Ahab, though everywhere\nelse foiled in his pursuit, firmly counted upon giving battle to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5639, "position": 5639, "text": "though everywhere\nelse foiled in his pursuit, firmly counted upon giving battle to Moby\nDick, in the sea he was most known to frequent; and at a season when he\nmight most reasonably be presumed to be haunting it.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5640, "position": 5640, "text": "might most reasonably be presumed to be haunting it.\n\nBut how now? in this zoned quest, does Ahab touch no land? does his\ncrew drink air? Surely, he will stop for water. Nay", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5641, "position": 5641, "text": "he will stop for water. Nay. For a long time,\nnow, the circus-running sun has raced within his fiery ring, and needs\nno sustenance but what’s in himself. So Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5642, "position": 5642, "text": "’s in himself. So Ahab. Mark this, too, in the\nwhaler. While other hulls are loaded down with alien stuff, to be\ntransferred to foreign wharves; the world-wandering whale-ship carries\nno cargo but", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5643, "position": 5643, "text": "wharves; the world-wandering whale-ship carries\nno cargo but herself and crew, their weapons and their wants. She has a\nwhole lake’s contents bottled in her ample hold. She is ballasted with\nutilities; not altogether with un", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5644, "position": 5644, "text": "her ample hold. She is ballasted with\nutilities; not altogether with unusable pig-lead and kentledge. She\ncarries years’ water in her. Clear old prime Nantucket water; which,\nwhen three years afloat, the Nan", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5645, "position": 5645, "text": "prime Nantucket water; which,\nwhen three years afloat, the Nantucketer, in the Pacific, prefers to\ndrink before the brackish fluid, but yesterday rafted off in casks,\nfrom the Peruvian or Indian streams", "labels": {"50": 42, "100": 59, "250": 46, "500": 16, "1000": 846, "2000": 1333}}, {"id": 5646, "position": 5646, "text": "ed off in casks,\nfrom the Peruvian or Indian streams. Hence it is, that, while other\nships may have gone to China from New York, and back again, touching at\na score of ports, the whale-ship, in all that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5647, "position": 5647, "text": "touching at\na score of ports, the whale-ship, in all that interval, may not have\nsighted one grain of soil; her crew having seen no man but floating\nseamen like themselves. So that did you carry them the news that\nanother flood had", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5648, "position": 5648, "text": "like themselves. So that did you carry them the news that\nanother flood had come; they would only answer—“Well, boys, here’s the\nark!”\n\nNow, as many Sperm Whales had been captured off the western coast of\nJava,", "labels": {"50": 45, "100": 64, "250": 138, "500": 425, "1000": 124, "2000": 1347}}, {"id": 5649, "position": 5649, "text": ", as many Sperm Whales had been captured off the western coast of\nJava, in the near vicinity of the Straits of Sunda; indeed, as most of\nthe ground, roundabout, was generally recognised by the fishermen as an\nexcellent spot for cruising; therefore", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5650, "position": 5650, "text": ", was generally recognised by the fishermen as an\nexcellent spot for cruising; therefore, as the Pequod gained more and\nmore upon Java Head, the look-outs were repeatedly hailed, and\nadmonished to keep wide awake", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 877}}, {"id": 5651, "position": 5651, "text": "hailed, and\nadmonished to keep wide awake. But though the green palmy cliffs of the\nland soon loomed on the starboard bow, and with delighted nostrils the\nfresh cinnamon was snuffed in the air, yet not a single jet was\ndes", "labels": {"50": 45, "100": 20, "250": 138, "500": 162, "1000": 35, "2000": 1735}}, {"id": 5652, "position": 5652, "text": "was snuffed in the air, yet not a single jet was\ndescried. Almost renouncing all thought of falling in with any game\nhereabouts, the ship had well nigh entered the straits, when the\ncustomary cheering cry was", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 5653, "position": 5653, "text": "ship had well nigh entered the straits, when the\ncustomary cheering cry was heard from aloft, and ere long a spectacle\nof singular magnificence saluted us.\n\nBut here be it premised, that owing to the unwearied", "labels": {"50": 45, "100": 29, "250": 54, "500": 384, "1000": 139, "2000": 1784}}, {"id": 5654, "position": 5654, "text": ".\n\nBut here be it premised, that owing to the unwearied activity with\nwhich of late they have been hunted over all four oceans, the Sperm\nWhales, instead of almost invariably sailing in small detached\ncompanies, as in former times, are now", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5655, "position": 5655, "text": "almost invariably sailing in small detached\ncompanies, as in former times, are now frequently met with in extensive\nherds, sometimes embracing so great a multitude, that it would almost\nseem as if numerous nations of them had sworn solemn league and\ncovenant for mutual assistance and", "labels": {"50": 21, "100": 29, "250": 76, "500": 107, "1000": 451, "2000": 1536}}, {"id": 5656, "position": 5656, "text": "if numerous nations of them had sworn solemn league and\ncovenant for mutual assistance and protection. To this aggregation of\nthe Sperm Whale into such immense caravans, may be imputed the\ncircumstance that even in the best cruising grounds, you may now\nsometimes sail for", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5657, "position": 5657, "text": "circumstance that even in the best cruising grounds, you may now\nsometimes sail for weeks and months together, without being greeted by\na single spout; and then be suddenly saluted by what sometimes seems\nthousands on thousands.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 5658, "position": 5658, "text": "by what sometimes seems\nthousands on thousands.\n\nBroad on both bows, at the distance of some two or three miles, and\nforming a great semicircle, embracing one half of the level horizon, a\ncontinuous chain of whale-jets were up-playing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5659, "position": 5659, "text": "the level horizon, a\ncontinuous chain of whale-jets were up-playing and sparkling in the\nnoon-day air. Unlike the straight perpendicular twin-jets of the Right\nWhale, which, dividing at top, fall over in two branches, like the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5660, "position": 5660, "text": ", which, dividing at top, fall over in two branches, like the\ncleft drooping boughs of a willow, the single forward-slanting spout of\nthe Sperm Whale presents a thick curled bush of white mist, continually\nrising and", "labels": {"50": 48, "100": 27, "250": 249, "500": 322, "1000": 878, "2000": 565}}, {"id": 5661, "position": 5661, "text": "the Sperm Whale presents a thick curled bush of white mist, continually\nrising and falling away to leeward.\n\nSeen from the Pequod’s deck, then, as she would rise on a high hill of\nthe sea, this host of vapory", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5662, "position": 5662, "text": "would rise on a high hill of\nthe sea, this host of vapory spouts, individually curling up into the\nair, and beheld through a blending atmosphere of bluish haze, showed\nlike the thousand cheerful chimneys of some dense metropolis, descr", "labels": {"50": 16, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1735}}, {"id": 5663, "position": 5663, "text": "haze, showed\nlike the thousand cheerful chimneys of some dense metropolis, descried\nof a balmy autumnal morning, by some horseman on a height.\n\nAs marching armies approaching an unfriendly defile in the mountains,\naccelerate their march", "labels": {"50": 16, "100": 78, "250": 240, "500": 286, "1000": 252, "2000": 606}}, {"id": 5664, "position": 5664, "text": "approaching an unfriendly defile in the mountains,\naccelerate their march, all eagerness to place that perilous passage in\ntheir rear, and once more expand in comparative security upon the\nplain; even so did this vast fleet of whales now", "labels": {"50": 12, "100": 38, "250": 209, "500": 344, "1000": 954, "2000": 1786}}, {"id": 5665, "position": 5665, "text": "comparative security upon the\nplain; even so did this vast fleet of whales now seem hurrying forward\nthrough the straits; gradually contracting the wings of their\nsemicircle, and swimming on, in one solid, but still crescentic centre.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5666, "position": 5666, "text": ", in one solid, but still crescentic centre.\n\nCrowding all sail the Pequod pressed after them; the harpooneers\nhandling their weapons, and loudly cheering from the heads of their yet\nsuspended boats", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5667, "position": 5667, "text": "the heads of their yet\nsuspended boats. If the wind only held, little doubt had they, that\nchased through these Straits of Sunda, the vast host would only deploy\ninto the Oriental seas to witness the capture of not a few of their\nnumber", "labels": {"50": 45, "100": 64, "250": 82, "500": 327, "1000": 327, "2000": 967}}, {"id": 5668, "position": 5668, "text": "the Oriental seas to witness the capture of not a few of their\nnumber. And who could tell whether, in that congregated caravan, Moby\nDick himself might not temporarily be swimming, like the worshipped\nwhite-elephant in the coronation procession of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 887}}, {"id": 5669, "position": 5669, "text": "be swimming, like the worshipped\nwhite-elephant in the coronation procession of the Siamese! So with\nstun-sail piled on stun-sail, we sailed along, driving these leviathans\nbefore us; when, of a sudden, the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5670, "position": 5670, "text": "driving these leviathans\nbefore us; when, of a sudden, the voice of Tashtego was heard, loudly\ndirecting attention to something in our wake.\n\nCorresponding to the crescent in our van, we beheld another in our\nrear", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 653, "2000": 1620}}, {"id": 5671, "position": 5671, "text": "the crescent in our van, we beheld another in our\nrear. It seemed formed of detached white vapors, rising and falling\nsomething like the spouts of the whales; only they did not so\ncompletely come and go; for they constantly hovered,", "labels": {"50": 12, "100": 93, "250": 55, "500": 233, "1000": 585, "2000": 1735}}, {"id": 5672, "position": 5672, "text": "only they did not so\ncompletely come and go; for they constantly hovered, without finally\ndisappearing. Levelling his glass at this sight, Ahab quickly revolved\nin his pivot-hole, crying, “Aloft there, and rig whips", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5673, "position": 5673, "text": "vot-hole, crying, “Aloft there, and rig whips and buckets to\nwet the sails;—Malays, sir, and after us!”\n\nAs if too long lurking behind the headlands, till the Pequod should", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5674, "position": 5674, "text": "if too long lurking behind the headlands, till the Pequod should\nfairly have entered the straits, these rascally Asiatics were now in\nhot pursuit, to make up for their over-cautious delay", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5675, "position": 5675, "text": "up for their over-cautious delay. But when the\nswift Pequod, with a fresh leading wind, was herself in hot chase; how\nvery kind of these tawny philanthropists to assist in speeding her on\nto her own chosen pursuit,—", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5676, "position": 5676, "text": "philanthropists to assist in speeding her on\nto her own chosen pursuit,—mere riding-whips and rowels to her, that\nthey were. As with glass under arm, Ahab to-and-fro paced the deck; in\nhis", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5677, "position": 5677, "text": ", Ahab to-and-fro paced the deck; in\nhis forward turn beholding the monsters he chased, and in the after one\nthe bloodthirsty pirates chasing _him_; some such fancy as the above\nseemed his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5678, "position": 5678, "text": "chasing _him_; some such fancy as the above\nseemed his. And when he glanced upon the green walls of the watery\ndefile in which the ship was then sailing, and bethought him that\nthrough that gate lay the route to his vengeance", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 5679, "position": 5679, "text": "and bethought him that\nthrough that gate lay the route to his vengeance, and beheld, how that\nthrough that same gate he was now both chasing and being chased to his\ndeadly end; and not only that, but a herd of remorseless", "labels": {"50": 18, "100": 83, "250": 60, "500": 238, "1000": 167, "2000": 290}}, {"id": 5680, "position": 5680, "text": "his\ndeadly end; and not only that, but a herd of remorseless wild pirates\nand inhuman atheistical devils were infernally cheering him on with\ntheir curses;—when all these conceits had passed through his brain,\nAhab’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5681, "position": 5681, "text": "all these conceits had passed through his brain,\nAhab’s brow was left gaunt and ribbed, like the black sand beach after\nsome stormy tide has been gnawing it, without being able to drag the\nfirm thing from its place", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 5682, "position": 5682, "text": "nawing it, without being able to drag the\nfirm thing from its place.\n\nBut thoughts like these troubled very few of the reckless crew; and\nwhen, after steadily dropping and dropping the pirates astern, the\nPequod at last shot by the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5683, "position": 5683, "text": "dropping the pirates astern, the\nPequod at last shot by the vivid green Cockatoo Point on the Sumatra\nside, emerging at last upon the broad waters beyond; then, the\nharpooneers seemed more to grieve that the swift", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5684, "position": 5684, "text": "then, the\nharpooneers seemed more to grieve that the swift whales had been\ngaining upon the ship, than to rejoice that the ship had so\nvictoriously gained upon the Malays. But still driving on in the wake\nof the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 5685, "position": 5685, "text": "gained upon the Malays. But still driving on in the wake\nof the whales, at length they seemed abating their speed; gradually the\nship neared them; and the wind now dying away, word was passed to\nspring to the boats", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 642, "2000": 1904}}, {"id": 5686, "position": 5686, "text": "now dying away, word was passed to\nspring to the boats. But no sooner did the herd, by some presumed\nwonderful instinct of the Sperm Whale, become notified of the three\nkeels that were after them,—though as yet a mile in their", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5687, "position": 5687, "text": "keels that were after them,—though as yet a mile in their rear,—than\nthey rallied again, and forming in close ranks and battalions, so that\ntheir spouts all looked like flashing lines of stacked bayonets, moved\non with", "labels": {"50": 4, "100": 18, "250": 218, "500": 232, "1000": 949, "2000": 1531}}, {"id": 5688, "position": 5688, "text": "outs all looked like flashing lines of stacked bayonets, moved\non with redoubled velocity.\n\nStripped to our shirts and drawers, we sprang to the white-ash, and\nafter several hours’ pulling were almost disposed to renounce the\nchase,", "labels": {"50": 25, "100": 93, "250": 55, "500": 233, "1000": 313, "2000": 1735}}, {"id": 5689, "position": 5689, "text": "and\nafter several hours’ pulling were almost disposed to renounce the\nchase, when a general pausing commotion among the whales gave animating\ntoken that they were now at last under the influence of that strange\nperplexity of inert irresolution,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5690, "position": 5690, "text": "influence of that strange\nperplexity of inert irresolution, which, when the fishermen perceive it\nin the whale, they say he is gallied. The compact martial columns in\nwhich they had been hitherto rapidly and steadily swimming,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5691, "position": 5691, "text": "martial columns in\nwhich they had been hitherto rapidly and steadily swimming, were now\nbroken up in one measureless rout; and like King Porus’ elephants in\nthe Indian battle with Alexander, they seemed going mad with\nconsternation", "labels": {"50": 26, "100": 67, "250": 235, "500": 87, "1000": 760, "2000": 450}}, {"id": 5692, "position": 5692, "text": "Indian battle with Alexander, they seemed going mad with\nconsternation. In all directions expanding in vast irregular circles,\nand aimlessly swimming hither and thither, by their short thick\nspoutings, they plainly betrayed their distraction of panic", "labels": {"50": 12, "100": 55, "250": 65, "500": 171, "1000": 954, "2000": 1635}}, {"id": 5693, "position": 5693, "text": "their short thick\nspoutings, they plainly betrayed their distraction of panic. This was\nstill more strangely evinced by those of their number, who, completely\nparalysed as it were, helplessly floated like water-logged dismantled\nships on the sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 447, "1000": 327, "2000": 282}}, {"id": 5694, "position": 5694, "text": "as it were, helplessly floated like water-logged dismantled\nships on the sea. Had these Leviathans been but a flock of simple\nsheep, pursued over the pasture by three fierce wolves, they could not\npossibly have evinced such excessive dismay", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5695, "position": 5695, "text": "fierce wolves, they could not\npossibly have evinced such excessive dismay. But this occasional\ntimidity is characteristic of almost all herding creatures. Though\nbanding together in tens of thousands, the lion-maned buffaloes of the\nWest have", "labels": {"50": 12, "100": 93, "250": 52, "500": 417, "1000": 129, "2000": 145}}, {"id": 5696, "position": 5696, "text": "tens of thousands, the lion-maned buffaloes of the\nWest have fled before a solitary horseman. Witness, too, all human\nbeings, how when herded together in the sheepfold of a theatre’s pit,\nthey will, at", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 5697, "position": 5697, "text": "in the sheepfold of a theatre’s pit,\nthey will, at the slightest alarm of fire, rush helter-skelter for the\noutlets, crowding, trampling, jamming, and remorselessly dashing each\nother to death", "labels": {"50": 22, "100": 88, "250": 70, "500": 163, "1000": 863, "2000": 1964}}, {"id": 5698, "position": 5698, "text": "trampling, jamming, and remorselessly dashing each\nother to death. Best, therefore, withhold any amazement at the\nstrangely gallied whales before us, for there is no folly of the beasts\nof the earth which is not infinitely outdon", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5699, "position": 5699, "text": "is no folly of the beasts\nof the earth which is not infinitely outdone by the madness of men.\n\nThough many of the whales, as has been said, were in violent motion,\nyet it is to be observed that as a whole the herd", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5700, "position": 5700, "text": "violent motion,\nyet it is to be observed that as a whole the herd neither advanced nor\nretreated, but collectively remained in one place. As is customary in\nthose cases, the boats at once separated, each making for some one lone\nwhale on the outskirts", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5701, "position": 5701, "text": "boats at once separated, each making for some one lone\nwhale on the outskirts of the shoal. In about three minutes’ time,\nQueequeg’s harpoon was flung; the stricken fish darted blinding spray\nin our faces, and then", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5702, "position": 5702, "text": "was flung; the stricken fish darted blinding spray\nin our faces, and then running away with us like light, steered\nstraight for the heart of the herd. Though such a movement on the part\nof the whale struck under such circumstances, is in no wise", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5703, "position": 5703, "text": "on the part\nof the whale struck under such circumstances, is in no wise\nunprecedented; and indeed is almost always more or less anticipated;\nyet does it present one of the more perilous vicissitudes of the\nfishery", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5704, "position": 5704, "text": "perilous vicissitudes of the\nfishery. For as the swift monster drags you deeper and deeper into the\nfrantic shoal, you bid adieu to circumspect life and only exist in a\ndelirious throb", "labels": {"50": 16, "100": 20, "250": 192, "500": 72, "1000": 692, "2000": 1710}}, {"id": 5705, "position": 5705, "text": "umspect life and only exist in a\ndelirious throb.\n\nAs, blind and deaf, the whale plunged forward, as if by sheer power of\nspeed to rid himself of the iron leech that had fastened to him; as we", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5706, "position": 5706, "text": "rid himself of the iron leech that had fastened to him; as we\nthus tore a white gash in the sea, on all sides menaced as we flew, by\nthe crazed creatures to and fro rushing about us; our beset boat", "labels": {"50": 45, "100": 64, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 5707, "position": 5707, "text": "the crazed creatures to and fro rushing about us; our beset boat was\nlike a ship mobbed by ice-isles in a tempest, and striving to steer\nthrough their complicated channels and straits, knowing not at what\nmoment it may be", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 5708, "position": 5708, "text": "through their complicated channels and straits, knowing not at what\nmoment it may be locked in and crushed.\n\nBut not a bit daunted, Queequeg steered us manfully; now sheering off\nfrom this monster directly across our route in advance", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5709, "position": 5709, "text": "fully; now sheering off\nfrom this monster directly across our route in advance; now edging away\nfrom that, whose colossal flukes were suspended overhead, while all the\ntime, Starbuck stood up in the bows, lance in hand, pricking", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5710, "position": 5710, "text": ", Starbuck stood up in the bows, lance in hand, pricking out of our\nway whatever whales he could reach by short darts, for there was no\ntime to make long ones. Nor were the oarsmen quite idle, though their\nwon", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5711, "position": 5711, "text": "long ones. Nor were the oarsmen quite idle, though their\nwonted duty was now altogether dispensed with. They chiefly attended to\nthe shouting part of the business. “Out of the way, Commodore!” cried\none, to", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5712, "position": 5712, "text": "business. “Out of the way, Commodore!” cried\none, to a great dromedary that of a sudden rose bodily to the surface,\nand for an instant threatened to swamp us. “Hard down with your tail,\nthere!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5713, "position": 5713, "text": "threatened to swamp us. “Hard down with your tail,\nthere!” cried a second to another, which, close to our gunwale, seemed\ncalmly cooling himself with his own fan-like extremity.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5714, "position": 5714, "text": "his own fan-like extremity.\n\nAll whaleboats carry certain curious contrivances, originally invented\nby the Nantucket Indians, called druggs. Two thick squares of wood of\nequal size are stoutly clenched together, so that they cross each", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5715, "position": 5715, "text": "wood of\nequal size are stoutly clenched together, so that they cross each\nother’s grain at right angles; a line of considerable length is then\nattached to the middle of this block, and the other end of the line\nbeing looped, it", "labels": {"50": 42, "100": 42, "250": 131, "500": 329, "1000": 222, "2000": 616}}, {"id": 5716, "position": 5716, "text": "this block, and the other end of the line\nbeing looped, it can in a moment be fastened to a harpoon. It is\nchiefly among gallied whales that this drugg is used. For then, more\nwhales are close round you than", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5717, "position": 5717, "text": "drugg is used. For then, more\nwhales are close round you than you can possibly chase at one time. But\nsperm whales are not every day encountered; while you may, then, you\nmust kill all you can", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5718, "position": 5718, "text": ", then, you\nmust kill all you can. And if you cannot kill them all at once, you\nmust wing them, so that they can be afterwards killed at your leisure.\nHence it is, that at times like these the drugg, comes", "labels": {"50": 40, "100": 24, "250": 52, "500": 288, "1000": 673, "2000": 744}}, {"id": 5719, "position": 5719, "text": ".\nHence it is, that at times like these the drugg, comes into\nrequisition. Our boat was furnished with three of them. The first and\nsecond were successfully darted, and we saw the whales staggeringly\nrunning off, fettered", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5720, "position": 5720, "text": "successfully darted, and we saw the whales staggeringly\nrunning off, fettered by the enormous sidelong resistance of the towing\ndrugg. They were cramped like malefactors with the chain and ball. But\nupon flinging the third, in the act", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5721, "position": 5721, "text": "the chain and ball. But\nupon flinging the third, in the act of tossing overboard the clumsy\nwooden block, it caught under one of the seats of the boat, and in an\ninstant tore it out and carried it away, dropping the oars", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1111}}, {"id": 5722, "position": 5722, "text": "in an\ninstant tore it out and carried it away, dropping the oarsman in the\nboat’s bottom as the seat slid from under him. On both sides the sea\ncame in at the wounded planks, but we stuffed two or three drawers", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 282}}, {"id": 5723, "position": 5723, "text": "came in at the wounded planks, but we stuffed two or three drawers and\nshirts in, and so stopped the leaks for the time.\n\nIt had been next to impossible to dart these drugged-harpoons, were it\nnot that as we advanced into", "labels": {"50": 25, "100": 93, "250": 91, "500": 388, "1000": 533, "2000": 1528}}, {"id": 5724, "position": 5724, "text": "dart these drugged-harpoons, were it\nnot that as we advanced into the herd, our whale’s way greatly\ndiminished; moreover, that as we went still further and further from\nthe circumference of commotion, the direful disorders seemed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5725, "position": 5725, "text": "further from\nthe circumference of commotion, the direful disorders seemed waning. So\nthat when at last the jerking harpoon drew out, and the towing whale\nsideways vanished; then, with the tapering force of his parting\nmomentum, we", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5726, "position": 5726, "text": "vanished; then, with the tapering force of his parting\nmomentum, we glided between two whales into the innermost heart of the\nshoal, as if from some mountain torrent we had slid into a serene\nvalley lake", "labels": {"50": 12, "100": 43, "250": 192, "500": 423, "1000": 615, "2000": 1735}}, {"id": 5727, "position": 5727, "text": "nt we had slid into a serene\nvalley lake. Here the storms in the roaring glens between the outermost\nwhales, were heard but not felt. In this central expanse the sea\npresented that smooth satin-like surface, called a sleek, produced by", "labels": {"50": 12, "100": 43, "250": 192, "500": 162, "1000": 615, "2000": 1735}}, {"id": 5728, "position": 5728, "text": "sea\npresented that smooth satin-like surface, called a sleek, produced by\nthe subtle moisture thrown off by the whale in his more quiet moods.\nYes, we were now in that enchanted calm which they say lurks at the\nheart of every commotion", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5729, "position": 5729, "text": "that enchanted calm which they say lurks at the\nheart of every commotion. And still in the distracted distance we\nbeheld the tumults of the outer concentric circles, and saw successive\npods of whales, eight or ten in each, swiftly going", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5730, "position": 5730, "text": "and saw successive\npods of whales, eight or ten in each, swiftly going round and round,\nlike multiplied spans of horses in a ring; and so closely shoulder to\nshoulder, that a Titanic circus-rider might easily have over-arched the\nmiddle ones", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5731, "position": 5731, "text": "that a Titanic circus-rider might easily have over-arched the\nmiddle ones, and so have gone round on their backs. Owing to the\ndensity of the crowd of reposing whales, more immediately surrounding\nthe embayed axis of the herd, no", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5732, "position": 5732, "text": "whales, more immediately surrounding\nthe embayed axis of the herd, no possible chance of escape was at\npresent afforded us. We must watch for a breach in the living wall that\nhemmed us in; the wall that had only admitted us in order", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5733, "position": 5733, "text": "that\nhemmed us in; the wall that had only admitted us in order to shut us\nup. Keeping at the centre of the lake, we were occasionally visited by\nsmall tame cows and calves; the women and children of this routed host.", "labels": {"50": 12, "100": 43, "250": 56, "500": 1, "1000": 381, "2000": 964}}, {"id": 5734, "position": 5734, "text": "cows and calves; the women and children of this routed host.\n\nNow, inclusive of the occasional wide intervals between the revolving\nouter circles, and inclusive of the spaces between the various pods in\nany one of those circles, the entire area at this juncture", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 5735, "position": 5735, "text": "pods in\nany one of those circles, the entire area at this juncture, embraced by\nthe whole multitude, must have contained at least two or three square\nmiles. At any rate—though indeed such a test at such a time might be\ndeceptive", "labels": {"50": 3, "100": 46, "250": 78, "500": 379, "1000": 782, "2000": 1051}}, {"id": 5736, "position": 5736, "text": "rate—though indeed such a test at such a time might be\ndeceptive—spoutings might be discovered from our low boat that seemed\nplaying up almost from the rim of the horizon. I mention this\ncircumstance, because, as if the cows and", "labels": {"50": 12, "100": 93, "250": 55, "500": 388, "1000": 585, "2000": 1243}}, {"id": 5737, "position": 5737, "text": "the horizon. I mention this\ncircumstance, because, as if the cows and calves had been purposely\nlocked up in this innermost fold; and as if the wide extent of the herd\nhad hitherto prevented them from learning the precise cause of its\nstopping", "labels": {"50": 45, "100": 43, "250": 34, "500": 306, "1000": 126, "2000": 1817}}, {"id": 5738, "position": 5738, "text": "herd\nhad hitherto prevented them from learning the precise cause of its\nstopping; or, possibly, being so young, unsophisticated, and every way\ninnocent and inexperienced; however it may have been, these smaller\nwhales—now and then", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5739, "position": 5739, "text": "inexperienced; however it may have been, these smaller\nwhales—now and then visiting our becalmed boat from the margin of the\nlake—evinced a wondrous fearlessness and confidence, or else a still\nbecharmed panic which it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5740, "position": 5740, "text": "fearlessness and confidence, or else a still\nbecharmed panic which it was impossible not to marvel at. Like\nhousehold dogs they came snuffling round us, right up to our gunwales,\nand touching them; till it almost seemed", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 5741, "position": 5741, "text": "up to our gunwales,\nand touching them; till it almost seemed that some spell had suddenly\ndomesticated them. Queequeg patted their foreheads; Starbuck scratched\ntheir backs with his lance; but fearful of the consequences, for the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5742, "position": 5742, "text": "scratched\ntheir backs with his lance; but fearful of the consequences, for the\ntime refrained from darting it.\n\nBut far beneath this wondrous world upon the surface, another and still\nstranger world met our eyes as we gazed over the side", "labels": {"50": 28, "100": 44, "250": 26, "500": 27, "1000": 668, "2000": 377}}, {"id": 5743, "position": 5743, "text": "and still\nstranger world met our eyes as we gazed over the side. For, suspended\nin those watery vaults, floated the forms of the nursing mothers of the\nwhales, and those that by their enormous girth seemed shortly to become\nmothers", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5744, "position": 5744, "text": "that by their enormous girth seemed shortly to become\nmothers. The lake, as I have hinted, was to a considerable depth\nexceedingly transparent; and as human infants while suckling will\ncalmly and fixedly gaze away from the breast, as if leading", "labels": {"50": 12, "100": 43, "250": 56, "500": 1, "1000": 381, "2000": 964}}, {"id": 5745, "position": 5745, "text": "ling will\ncalmly and fixedly gaze away from the breast, as if leading two\ndifferent lives at the time; and while yet drawing mortal nourishment,\nbe still spiritually feasting upon some unearthly reminiscence;—even", "labels": {"50": 32, "100": 90, "250": 121, "500": 74, "1000": 577, "2000": 1220}}, {"id": 5746, "position": 5746, "text": "ly feasting upon some unearthly reminiscence;—even so\ndid the young of these whales seem looking up towards us, but not at\nus, as if we were but a bit of Gulfweed in their new-born sight", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5747, "position": 5747, "text": "we were but a bit of Gulfweed in their new-born sight.\nFloating on their sides, the mothers also seemed quietly eyeing us. One\nof these little infants, that from certain queer tokens seemed hardly a\nday old, might have measured some", "labels": {"50": 7, "100": 22, "250": 55, "500": 318, "1000": 638, "2000": 1735}}, {"id": 5748, "position": 5748, "text": "from certain queer tokens seemed hardly a\nday old, might have measured some fourteen feet in length, and some six\nfeet in girth. He was a little frisky; though as yet his body seemed\nscarce yet recovered from that irksome", "labels": {"50": 22, "100": 24, "250": 52, "500": 465, "1000": 204, "2000": 174}}, {"id": 5749, "position": 5749, "text": "; though as yet his body seemed\nscarce yet recovered from that irksome position it had so lately\noccupied in the maternal reticule; where, tail to head, and all ready\nfor the final spring, the unborn whale lies bent like a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5750, "position": 5750, "text": "all ready\nfor the final spring, the unborn whale lies bent like a Tartar’s bow.\nThe delicate side-fins, and the palms of his flukes, still freshly\nretained the plaited crumpled appearance of a baby’s ears", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5751, "position": 5751, "text": "still freshly\nretained the plaited crumpled appearance of a baby’s ears newly arrived\nfrom foreign parts.\n\n“Line! line!” cried Queequeg, looking over the gunwale; “him fast! him\nfast!—Who line", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5752, "position": 5752, "text": "the gunwale; “him fast! him\nfast!—Who line him! Who struck?—Two whale; one big, one little!”\n\n“What ails ye, man?” cried Starbuck.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5753, "position": 5753, "text": "ye, man?” cried Starbuck.\n\n“Look-e here,” said Queequeg, pointing down.\n\nAs when the stricken whale, that from the tub has reeled out hundreds\nof fathoms of rope; as, after", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5754, "position": 5754, "text": "has reeled out hundreds\nof fathoms of rope; as, after deep sounding, he floats up again, and\nshows the slackened curling line buoyantly rising and spiralling\ntowards the air; so now, Starbuck saw long coils", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5755, "position": 5755, "text": "spiralling\ntowards the air; so now, Starbuck saw long coils of the umbilical cord\nof Madame Leviathan, by which the young cub seemed still tethered to\nits dam. Not seldom in the rapid vicissitudes of", "labels": {"50": 37, "100": 55, "250": 28, "500": 93, "1000": 99, "2000": 481}}, {"id": 5756, "position": 5756, "text": "ed to\nits dam. Not seldom in the rapid vicissitudes of the chase, this\nnatural line, with the maternal end loose, becomes entangled with the\nhempen one, so that the cub is thereby trapped", "labels": {"50": 31, "100": 42, "250": 131, "500": 417, "1000": 917, "2000": 616}}, {"id": 5757, "position": 5757, "text": "one, so that the cub is thereby trapped. Some of the subtlest\nsecrets of the seas seemed divulged to us in this enchanted pond. We\nsaw young Leviathan amours in the deep.*", "labels": {"50": 12, "100": 24, "250": 52, "500": 72, "1000": 129, "2000": 449}}, {"id": 5758, "position": 5758, "text": "athan amours in the deep.*\n\n*The sperm whale, as with all other species of the Leviathan, but\nunlike most other fish, breeds indifferently at all seasons; after a\ngestation which may probably be set down at nine months,", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5759, "position": 5759, "text": "; after a\ngestation which may probably be set down at nine months, producing but\none at a time; though in some few known instances giving birth to an\nEsau and Jacob:—a contingency provided for in suckling by two tea", "labels": {"50": 3, "100": 24, "250": 155, "500": 309, "1000": 8, "2000": 162}}, {"id": 5760, "position": 5760, "text": "Jacob:—a contingency provided for in suckling by two teats,\ncuriously situated, one on each side of the anus; but the breasts\nthemselves extend upwards from that. When by chance these precious\nparts in a nursing whale are cut", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 634, "2000": 612}}, {"id": 5761, "position": 5761, "text": "from that. When by chance these precious\nparts in a nursing whale are cut by the hunter’s lance, the mother’s\npouring milk and blood rivallingly discolour the sea for rods. The milk\nis very sweet and rich; it", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5762, "position": 5762, "text": "r the sea for rods. The milk\nis very sweet and rich; it has been tasted by man; it might do well\nwith strawberries. When overflowing with mutual esteem, the whales\nsalute _more hominum_.", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5763, "position": 5763, "text": "esteem, the whales\nsalute _more hominum_.\n\nAnd thus, though surrounded by circle upon circle of consternations and\naffrights, did these inscrutable creatures at the centre freely and\nfearlessly indulge in all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5764, "position": 5764, "text": "crutable creatures at the centre freely and\nfearlessly indulge in all peaceful concernments; yea, serenely revelled\nin dalliance and delight. But even so, amid the tornadoed Atlantic of\nmy being, do I myself still", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 27, "2000": 1107}}, {"id": 5765, "position": 5765, "text": "so, amid the tornadoed Atlantic of\nmy being, do I myself still for ever centrally disport in mute calm;\nand while ponderous planets of unwaning woe revolve round me, deep down\nand deep inland there I still bath", "labels": {"50": 8, "100": 14, "250": 193, "500": 374, "1000": 318, "2000": 1031}}, {"id": 5766, "position": 5766, "text": "revolve round me, deep down\nand deep inland there I still bathe me in eternal mildness of joy.\n\nMeanwhile, as we thus lay entranced, the occasional sudden frantic\nspectacles in the distance evinced the activity of the other", "labels": {"50": 20, "100": 5, "250": 26, "500": 57, "1000": 914, "2000": 1254}}, {"id": 5767, "position": 5767, "text": "sudden frantic\nspectacles in the distance evinced the activity of the other boats,\nstill engaged in drugging the whales on the frontier of the host; or\npossibly carrying on the war within the first circle, where abundance\nof room and some convenient retreat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5768, "position": 5768, "text": "the war within the first circle, where abundance\nof room and some convenient retreats were afforded them. But the sight\nof the enraged drugged whales now and then blindly darting to and fro\nacross the circles, was nothing to what at last met our eyes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5769, "position": 5769, "text": "fro\nacross the circles, was nothing to what at last met our eyes. It is\nsometimes the custom when fast to a whale more than commonly powerful\nand alert, to seek to hamstring him, as it were, by sundering or", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5770, "position": 5770, "text": "to hamstring him, as it were, by sundering or\nmaiming his gigantic tail-tendon. It is done by darting a short-handled\ncutting-spade, to which is attached a rope for hauling it back again", "labels": {"50": 48, "100": 24, "250": 49, "500": 247, "1000": 917, "2000": 616}}, {"id": 5771, "position": 5771, "text": "spade, to which is attached a rope for hauling it back again. A\nwhale wounded (as we afterwards learned) in this part, but not\neffectually, as it seemed, had broken away from the boat, carrying\nalong with him half of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5772, "position": 5772, "text": ", had broken away from the boat, carrying\nalong with him half of the harpoon line; and in the extraordinary agony\nof the wound, he was now dashing among the revolving circles like the\nlone mounted desperado Arnold, at the battle of", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 642, "2000": 1904}}, {"id": 5773, "position": 5773, "text": "revolving circles like the\nlone mounted desperado Arnold, at the battle of Saratoga, carrying\ndismay wherever he went.\n\nBut agonizing as was the wound of this whale, and an appalling\nspectacle enough, any way; yet the peculiar horror", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5774, "position": 5774, "text": "and an appalling\nspectacle enough, any way; yet the peculiar horror with which he seemed\nto inspire the rest of the herd, was owing to a cause which at first\nthe intervening distance obscured from us", "labels": {"50": 12, "100": 93, "250": 11, "500": 435, "1000": 653, "2000": 1652}}, {"id": 5775, "position": 5775, "text": "the intervening distance obscured from us. But at length we perceived\nthat by one of the unimaginable accidents of the fishery, this whale\nhad become entangled in the harpoon-line that he towed; he had also run\naway with the cutting", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5776, "position": 5776, "text": "oon-line that he towed; he had also run\naway with the cutting-spade in him; and while the free end of the rope\nattached to that weapon, had permanently caught in the coils of the\nharpoon-line round his tail,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5777, "position": 5777, "text": "caught in the coils of the\nharpoon-line round his tail, the cutting-spade itself had worked loose\nfrom his flesh. So that tormented to madness, he was now churning\nthrough the water, violently flailing with his flexible tail, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5778, "position": 5778, "text": "now churning\nthrough the water, violently flailing with his flexible tail, and\ntossing the keen spade about him, wounding and murdering his own\ncomrades.\n\nThis terrific object seemed to recall the whole herd from their\nstationary fright", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 778}}, {"id": 5779, "position": 5779, "text": "the whole herd from their\nstationary fright. First, the whales forming the margin of our lake\nbegan to crowd a little, and tumble against each other, as if lifted by\nhalf spent billows from afar; then the lake itself began faintly to\nheave", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5780, "position": 5780, "text": "spent billows from afar; then the lake itself began faintly to\nheave and swell; the submarine bridal-chambers and nurseries vanished;\nin more and more contracting orbits the whales in the more central\ncircles began to swim in thickening clusters", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 35, "2000": 1735}}, {"id": 5781, "position": 5781, "text": "the whales in the more central\ncircles began to swim in thickening clusters. Yes, the long calm was\ndeparting. A low advancing hum was soon heard; and then like to the\ntumultuous masses of block-ice when the great river Hudson", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5782, "position": 5782, "text": "the\ntumultuous masses of block-ice when the great river Hudson breaks up in\nSpring, the entire host of whales came tumbling upon their inner\ncentre, as if to pile themselves up in one common mountain", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5783, "position": 5783, "text": "pile themselves up in one common mountain. Instantly\nStarbuck and Queequeg changed places; Starbuck taking the stern.\n\n“Oars! Oars!” he intensely whispered, seizing the helm—“gripe your\noars, and clutch", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5784, "position": 5784, "text": "whispered, seizing the helm—“gripe your\noars, and clutch your souls, now! My God, men, stand by! Shove him off,\nyou Queequeg—the whale there!—prick him!—hit him!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5785, "position": 5785, "text": "queg—the whale there!—prick him!—hit him! Stand up—stand up,\nand stay so! Spring, men—pull, men; never mind their backs—scrape\nthem!—scrape away!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5786, "position": 5786, "text": "their backs—scrape\nthem!—scrape away!”\n\nThe boat was now all but jammed between two vast black bulks, leaving a\nnarrow Dardanelles between their long lengths. But by desperate\nendeavor we at last shot into a temporary opening; then", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1028}}, {"id": 5787, "position": 5787, "text": ". But by desperate\nendeavor we at last shot into a temporary opening; then giving way\nrapidly, and at the same time earnestly watching for another outlet.\nAfter many similar hair-breadth escapes, we at last swiftly glided into\nwhat had just been one", "labels": {"50": 25, "100": 5, "250": 136, "500": 233, "1000": 906, "2000": 1521}}, {"id": 5788, "position": 5788, "text": "-breadth escapes, we at last swiftly glided into\nwhat had just been one of the outer circles, but now crossed by random\nwhales, all violently making for one centre. This lucky salvation was\ncheaply purchased by the loss of Queequeg’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5789, "position": 5789, "text": "lucky salvation was\ncheaply purchased by the loss of Queequeg’s hat, who, while standing in\nthe bows to prick the fugitive whales, had his hat taken clean from his\nhead by the air-eddy made by the sudden tossing of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5790, "position": 5790, "text": "clean from his\nhead by the air-eddy made by the sudden tossing of a pair of broad\nflukes close by.\n\nRiotous and disordered as the universal commotion now was, it soon\nresolved itself into what seemed a systematic movement; for having\ncl", "labels": {"50": 37, "100": 64, "250": 145, "500": 73, "1000": 959, "2000": 324}}, {"id": 5791, "position": 5791, "text": ", it soon\nresolved itself into what seemed a systematic movement; for having\nclumped together at last in one dense body, they then renewed their\nonward flight with augmented fleetness. Further pursuit was useless;\nbut the boats still lingered in their wake to", "labels": {"50": 45, "100": 29, "250": 138, "500": 43, "1000": 737, "2000": 819}}, {"id": 5792, "position": 5792, "text": ". Further pursuit was useless;\nbut the boats still lingered in their wake to pick up what drugged\nwhales might be dropped astern, and likewise to secure one which Flask\nhad killed and waifed. The waif is a pennoned pole, two", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1620}}, {"id": 5793, "position": 5793, "text": "killed and waifed. The waif is a pennoned pole, two or three of\nwhich are carried by every boat; and which, when additional game is at\nhand, are inserted upright into the floating body of a dead whale, both\nto mark", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5794, "position": 5794, "text": "are inserted upright into the floating body of a dead whale, both\nto mark its place on the sea, and also as token of prior possession,\nshould the boats of any other ship draw near.\n\nThe result of this lowering was somewhat illustrative of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5795, "position": 5795, "text": "ship draw near.\n\nThe result of this lowering was somewhat illustrative of that sagacious\nsaying in the Fishery,—the more whales the less fish. Of all the\ndrugged whales only one was captured. The rest contrived to escape for\nthe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5796, "position": 5796, "text": "whales only one was captured. The rest contrived to escape for\nthe time, but only to be taken, as will hereafter be seen, by some\nother craft than the Pequod.\n\n\nCHAPTER 88. Schools and Schoolmasters.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5797, "position": 5797, "text": "than the Pequod.\n\n\nCHAPTER 88. Schools and Schoolmasters.\n\nThe previous chapter gave account of an immense body or herd of Sperm\nWhales, and there was also then given the probable cause inducing those\nvast aggregations.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5798, "position": 5798, "text": "the probable cause inducing those\nvast aggregations.\n\nNow, though such great bodies are at times encountered, yet, as must\nhave been seen, even at the present day, small detached bands are\noccasionally observed, embracing from twenty to fifty individuals each", "labels": {"50": 3, "100": 70, "250": 234, "500": 288, "1000": 37, "2000": 1905}}, {"id": 5799, "position": 5799, "text": "detached bands are\noccasionally observed, embracing from twenty to fifty individuals each.\nSuch bands are known as schools. They generally are of two sorts; those\ncomposed almost entirely of females, and those mustering none but young\nvigorous males, or bulls, as they", "labels": {"50": 12, "100": 42, "250": 131, "500": 329, "1000": 917, "2000": 616}}, {"id": 5800, "position": 5800, "text": "and those mustering none but young\nvigorous males, or bulls, as they are familiarly designated.\n\nIn cavalier attendance upon the school of females, you invariably see a\nmale of full grown magnitude, but not old; who, upon any alarm, ev", "labels": {"50": 3, "100": 86, "250": 52, "500": 417, "1000": 886, "2000": 145}}, {"id": 5801, "position": 5801, "text": "full grown magnitude, but not old; who, upon any alarm, evinces\nhis gallantry by falling in the rear and covering the flight of his\nladies. In truth, this gentleman is a luxurious Ottoman, swimming about\nover the watery world, surrounding", "labels": {"50": 32, "100": 0, "250": 49, "500": 78, "1000": 806, "2000": 799}}, {"id": 5802, "position": 5802, "text": "this gentleman is a luxurious Ottoman, swimming about\nover the watery world, surroundingly accompanied by all the solaces and\nendearments of the harem. The contrast between this Ottoman and his\nconcubines is striking; because, while he", "labels": {"50": 32, "100": 0, "250": 233, "500": 55, "1000": 806, "2000": 799}}, {"id": 5803, "position": 5803, "text": "this Ottoman and his\nconcubines is striking; because, while he is always of the largest\nleviathanic proportions, the ladies, even at full growth, are not more\nthan one-third of the bulk of an average-sized male", "labels": {"50": 32, "100": 0, "250": 233, "500": 247, "1000": 917, "2000": 616}}, {"id": 5804, "position": 5804, "text": "more\nthan one-third of the bulk of an average-sized male. They are\ncomparatively delicate, indeed; I dare say, not to exceed half a dozen\nyards round the waist. Nevertheless, it cannot be denied, that upon the\nwhole they are", "labels": {"50": 45, "100": 7, "250": 138, "500": 73, "1000": 199, "2000": 1620}}, {"id": 5805, "position": 5805, "text": "waist. Nevertheless, it cannot be denied, that upon the\nwhole they are hereditarily entitled to _en bon point_.\n\nIt is very curious to watch this harem and its lord in their indolent\nramblings", "labels": {"50": 1, "100": 7, "250": 49, "500": 78, "1000": 933, "2000": 370}}, {"id": 5806, "position": 5806, "text": "m and its lord in their indolent\nramblings. Like fashionables, they are for ever on the move in\nleisurely search of variety. You meet them on the Line in time for the\nfull flower of the Equatorial feeding season, having just", "labels": {"50": 31, "100": 7, "250": 114, "500": 453, "1000": 649, "2000": 1394}}, {"id": 5807, "position": 5807, "text": "Line in time for the\nfull flower of the Equatorial feeding season, having just returned,\nperhaps, from spending the summer in the Northern seas, and so cheating\nsummer of all unpleasant weariness and warmth. By the time they have\nlounged up and down", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 35, "2000": 1710}}, {"id": 5808, "position": 5808, "text": "weariness and warmth. By the time they have\nlounged up and down the promenade of the Equator awhile, they start for\nthe Oriental waters in anticipation of the cool season there, and so\nevade the other excessive temperature of the year.", "labels": {"50": 45, "100": 42, "250": 78, "500": 247, "1000": 917, "2000": 887}}, {"id": 5809, "position": 5809, "text": ", and so\nevade the other excessive temperature of the year.\n\nWhen serenely advancing on one of these journeys, if any strange\nsuspicious sights are seen, my lord whale keeps a wary eye on his\ninteresting family", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5810, "position": 5810, "text": "wary eye on his\ninteresting family. Should any unwarrantably pert young Leviathan\ncoming that way, presume to draw confidentially close to one of the\nladies, with what prodigious fury the Bashaw assails him,", "labels": {"50": 31, "100": 7, "250": 159, "500": 73, "1000": 387, "2000": 1620}}, {"id": 5811, "position": 5811, "text": "with what prodigious fury the Bashaw assails him, and chases\nhim away! High times, indeed, if unprincipled young rakes like him are\nto be permitted to invade the sanctity of domestic bliss;", "labels": {"50": 31, "100": 75, "250": 193, "500": 496, "1000": 290, "2000": 1394}}, {"id": 5812, "position": 5812, "text": "him are\nto be permitted to invade the sanctity of domestic bliss; though do\nwhat the Bashaw will, he cannot keep the most notorious Lothario out of\nhis bed; for, alas! all fish bed in common", "labels": {"50": 9, "100": 75, "250": 167, "500": 12, "1000": 985, "2000": 288}}, {"id": 5813, "position": 5813, "text": "bed; for, alas! all fish bed in common. As ashore, the ladies often\ncause the most terrible duels among their rival admirers; just so with\nthe whales, who sometimes come to deadly battle, and all for love", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5814, "position": 5814, "text": "whales, who sometimes come to deadly battle, and all for love. They\nfence with their long lower jaws, sometimes locking them together, and\nso striving for the supremacy like elks that warringly interweave their\nantlers", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5815, "position": 5815, "text": "like elks that warringly interweave their\nantlers. Not a few are captured having the deep scars of these\nencounters,—furrowed heads, broken teeth, scolloped fins; and in some\ninstances, wrenched and dislocated mouths", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 5816, "position": 5816, "text": "oped fins; and in some\ninstances, wrenched and dislocated mouths.\n\nBut supposing the invader of domestic bliss to betake himself away at\nthe first rush of the harem’s lord, then is it very diverting to", "labels": {"50": 31, "100": 7, "250": 167, "500": 436, "1000": 513, "2000": 357}}, {"id": 5817, "position": 5817, "text": "of the harem’s lord, then is it very diverting to watch\nthat lord. Gently he insinuates his vast bulk among them again and\nrevels there awhile, still in tantalizing vicinity to young Lothario,\nlike", "labels": {"50": 30, "100": 4, "250": 114, "500": 341, "1000": 649, "2000": 446}}, {"id": 5818, "position": 5818, "text": "awhile, still in tantalizing vicinity to young Lothario,\nlike pious Solomon devoutly worshipping among his thousand concubines.\nGranting other whales to be in sight, the fishermen will seldom give\nchase to one of these Grand Turks;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5819, "position": 5819, "text": "sight, the fishermen will seldom give\nchase to one of these Grand Turks; for these Grand Turks are too lavish\nof their strength, and hence their unctuousness is small. As for the\nsons and the daughters they beget, why, those", "labels": {"50": 21, "100": 42, "250": 54, "500": 246, "1000": 491, "2000": 1580}}, {"id": 5820, "position": 5820, "text": ". As for the\nsons and the daughters they beget, why, those sons and daughters must\ntake care of themselves; at least, with only the maternal help. For\nlike certain other omnivorous roving lovers that might be named, my\nLord Whale", "labels": {"50": 31, "100": 61, "250": 167, "500": 436, "1000": 985, "2000": 228}}, {"id": 5821, "position": 5821, "text": "certain other omnivorous roving lovers that might be named, my\nLord Whale has no taste for the nursery, however much for the bower;\nand so, being a great traveller, he leaves his anonymous babies all\nover the world; every baby an", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5822, "position": 5822, "text": "traveller, he leaves his anonymous babies all\nover the world; every baby an exotic. In good time, nevertheless, as\nthe ardour of youth declines; as years and dumps increase; as\nreflection lends her solemn pauses; in short,", "labels": {"50": 31, "100": 20, "250": 49, "500": 78, "1000": 165, "2000": 1081}}, {"id": 5823, "position": 5823, "text": "dumps increase; as\nreflection lends her solemn pauses; in short, as a general lassitude\novertakes the sated Turk; then a love of ease and virtue supplants the\nlove for maidens; our Ottoman enters upon the", "labels": {"50": 31, "100": 7, "250": 159, "500": 496, "1000": 290, "2000": 962}}, {"id": 5824, "position": 5824, "text": "supplants the\nlove for maidens; our Ottoman enters upon the impotent, repentant,\nadmonitory stage of life, forswears, disbands the harem, and grown to\nan exemplary, sulky", "labels": {"50": 32, "100": 0, "250": 64, "500": 83, "1000": 484, "2000": 784}}, {"id": 5825, "position": 5825, "text": "disbands the harem, and grown to\nan exemplary, sulky old soul, goes about all alone among the meridians\nand parallels saying his prayers, and warning each young Leviathan from\nhis amorous errors.", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 1107}}, {"id": 5826, "position": 5826, "text": "young Leviathan from\nhis amorous errors.\n\nNow, as the harem of whales is called by the fishermen a school, so is\nthe lord and master of that school technically known as the\nschoolmaster. It is therefore not in strict character, however", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5827, "position": 5827, "text": "known as the\nschoolmaster. It is therefore not in strict character, however\nadmirably satirical, that after going to school himself, he should then\ngo abroad inculcating not what he learned there, but the folly of it", "labels": {"50": 44, "100": 68, "250": 1, "500": 496, "1000": 485, "2000": 1002}}, {"id": 5828, "position": 5828, "text": "not what he learned there, but the folly of it.\nHis title, schoolmaster, would very naturally seem derived from the\nname bestowed upon the harem itself, but some have surmised that the\nman who first thus entitled this sort of Ottoman", "labels": {"50": 32, "100": 0, "250": 233, "500": 83, "1000": 61, "2000": 106}}, {"id": 5829, "position": 5829, "text": "have surmised that the\nman who first thus entitled this sort of Ottoman whale, must have read\nthe memoirs of Vidocq, and informed himself what sort of a\ncountry-schoolmaster that famous Frenchman was in his younger days, and\nwhat", "labels": {"50": 45, "100": 29, "250": 82, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5830, "position": 5830, "text": "country-schoolmaster that famous Frenchman was in his younger days, and\nwhat was the nature of those occult lessons he inculcated into some of\nhis pupils.\n\nThe same secludedness and isolation to which the schoolmaster whale\nbetakes himself in his advancing", "labels": {"50": 44, "100": 37, "250": 143, "500": 29, "1000": 355, "2000": 1873}}, {"id": 5831, "position": 5831, "text": "ness and isolation to which the schoolmaster whale\nbetakes himself in his advancing years, is true of all aged Sperm\nWhales. Almost universally, a lone whale—as a solitary Leviathan is\ncalled—proves an ancient one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5832, "position": 5832, "text": "Leviathan is\ncalled—proves an ancient one. Like venerable moss-bearded Daniel Boone,\nhe will have no one near him but Nature herself; and her he takes to\nwife in the wilderness of waters, and the best of wives she is, though", "labels": {"50": 31, "100": 20, "250": 192, "500": 334, "1000": 816, "2000": 1560}}, {"id": 5833, "position": 5833, "text": "in the wilderness of waters, and the best of wives she is, though\nshe keeps so many moody secrets.\n\nThe schools composing none but young and vigorous males, previously\nmentioned, offer a strong contrast to the harem schools", "labels": {"50": 32, "100": 33, "250": 194, "500": 105, "1000": 880, "2000": 357}}, {"id": 5834, "position": 5834, "text": "offer a strong contrast to the harem schools. For while\nthose female whales are characteristically timid, the young males, or\nforty-barrel-bulls, as they call them, are by far the most pugnacious\nof all Leviathans", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5835, "position": 5835, "text": "them, are by far the most pugnacious\nof all Leviathans, and proverbially the most dangerous to encounter;\nexcepting those wondrous grey-headed, grizzled whales, sometimes met,\nand these will fight", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5836, "position": 5836, "text": "headed, grizzled whales, sometimes met,\nand these will fight you like grim fiends exasperated by a penal gout.\n\nThe Forty-barrel-bull schools are larger than the harem schools", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5837, "position": 5837, "text": "are larger than the harem schools. Like a\nmob of young collegians, they are full of fight, fun, and wickedness,\ntumbling round the world at such a reckless, rollicking rate, that no\nprudent underwriter", "labels": {"50": 24, "100": 86, "250": 236, "500": 130, "1000": 629, "2000": 1549}}, {"id": 5838, "position": 5838, "text": "a reckless, rollicking rate, that no\nprudent underwriter would insure them any more than he would a riotous\nlad at Yale or Harvard. They soon relinquish this turbulence though,\nand when about three-fourths", "labels": {"50": 44, "100": 37, "250": 70, "500": 211, "1000": 984, "2000": 425}}, {"id": 5839, "position": 5839, "text": "relinquish this turbulence though,\nand when about three-fourths grown, break up, and separately go about\nin quest of settlements, that is, harems.\n\nAnother point of difference between the male and female schools is\nstill more characteristic of", "labels": {"50": 21, "100": 61, "250": 167, "500": 436, "1000": 513, "2000": 357}}, {"id": 5840, "position": 5840, "text": "Another point of difference between the male and female schools is\nstill more characteristic of the sexes. Say you strike a\nForty-barrel-bull—poor devil! all his comrades quit him. But strike a\nmember of the harem school, and her companions", "labels": {"50": 24, "100": 61, "250": 167, "500": 495, "1000": 553, "2000": 662}}, {"id": 5841, "position": 5841, "text": "him. But strike a\nmember of the harem school, and her companions swim around her with\nevery token of concern, sometimes lingering so near her and so long, as\nthemselves to fall a prey.\n\n\nCHAPTER 89. Fast-Fish and Loose-Fish", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 145}}, {"id": 5842, "position": 5842, "text": "to fall a prey.\n\n\nCHAPTER 89. Fast-Fish and Loose-Fish.\n\nThe allusion to the waif and waif-poles in the last chapter but one,\nnecessitates some account of the laws and regulations of the whale\nfishery", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5843, "position": 5843, "text": "necessitates some account of the laws and regulations of the whale\nfishery, of which the waif may be deemed the grand symbol and badge.\n\nIt frequently happens that when several ships are cruising in company,\na whale may be struck by one vessel", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5844, "position": 5844, "text": "several ships are cruising in company,\na whale may be struck by one vessel, then escape, and be finally killed\nand captured by another vessel; and herein are indirectly comprised\nmany minor contingencies, all partaking of this one grand feature", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5845, "position": 5845, "text": "many minor contingencies, all partaking of this one grand feature. For\nexample,—after a weary and perilous chase and capture of a whale, the\nbody may get loose from the ship by reason of a violent storm; and\ndrifting", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5846, "position": 5846, "text": "may get loose from the ship by reason of a violent storm; and\ndrifting far away to leeward, be retaken by a second whaler, who, in a\ncalm, snugly tows it alongside, without risk of life or line", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5847, "position": 5847, "text": ", snugly tows it alongside, without risk of life or line. Thus the\nmost vexatious and violent disputes would often arise between the\nfishermen, were there not some written or unwritten, universal,\nundisputed law applicable to all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 692, "2000": 447}}, {"id": 5848, "position": 5848, "text": "some written or unwritten, universal,\nundisputed law applicable to all cases.\n\nPerhaps the only formal whaling code authorized by legislative\nenactment, was that of Holland. It was decreed by the States-General in\nA.D. 1695", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5849, "position": 5849, "text": "decreed by the States-General in\nA.D. 1695. But though no other nation has ever had any written whaling\nlaw, yet the American fishermen have been their own legislators and\nlawyers in this matter. They have provided a system which for terse", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 447}}, {"id": 5850, "position": 5850, "text": "and\nlawyers in this matter. They have provided a system which for terse\ncomprehensiveness surpasses Justinian’s Pandects and the By-laws of the\nChinese Society for the Suppression of Meddling with other People’s\nBusiness", "labels": {"50": 21, "100": 90, "250": 121, "500": 328, "1000": 567, "2000": 640}}, {"id": 5851, "position": 5851, "text": "Society for the Suppression of Meddling with other People’s\nBusiness. Yes; these laws might be engraven on a Queen Anne’s farthing,\nor the barb of a harpoon, and worn round the neck, so small are", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 387, "2000": 1828}}, {"id": 5852, "position": 5852, "text": "b of a harpoon, and worn round the neck, so small are they.\n\nI. A Fast-Fish belongs to the party fast to it.\n\nII. A Loose-Fish is fair game for anybody who can soonest catch it.", "labels": {"50": 45, "100": 24, "250": 213, "500": 72, "1000": 692, "2000": 447}}, {"id": 5853, "position": 5853, "text": "-Fish is fair game for anybody who can soonest catch it.\n\nBut what plays the mischief with this masterly code is the admirable\nbrevity of it, which necessitates a vast volume of commentaries to\nexpound it.", "labels": {"50": 31, "100": 24, "250": 213, "500": 126, "1000": 692, "2000": 982}}, {"id": 5854, "position": 5854, "text": "which necessitates a vast volume of commentaries to\nexpound it.\n\nFirst: What is a Fast-Fish? Alive or dead a fish is technically fast,\nwhen it is connected with an occupied ship or boat, by any medium at\nall control", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5855, "position": 5855, "text": "is connected with an occupied ship or boat, by any medium at\nall controllable by the occupant or occupants,—a mast, an oar, a\nnine-inch cable, a telegraph wire, or a strand of cob", "labels": {"50": 45, "100": 64, "250": 149, "500": 73, "1000": 704, "2000": 1620}}, {"id": 5856, "position": 5856, "text": "nine-inch cable, a telegraph wire, or a strand of cobweb, it is all the\nsame. Likewise a fish is technically fast when it bears a waif, or any\nother recognised symbol of possession; so long as the party", "labels": {"50": 31, "100": 75, "250": 88, "500": 453, "1000": 581, "2000": 1376}}, {"id": 5857, "position": 5857, "text": "f, or any\nother recognised symbol of possession; so long as the party waifing it\nplainly evince their ability at any time to take it alongside, as well\nas their intention so to do.", "labels": {"50": 43, "100": 48, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5858, "position": 5858, "text": "as their intention so to do.\n\nThese are scientific commentaries; but the commentaries of the whalemen\nthemselves sometimes consist in hard words and harder knocks—the\nCoke-upon-Littleton of the fist. True, among the more upright and\nhonorable whalemen", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5859, "position": 5859, "text": "ton of the fist. True, among the more upright and\nhonorable whalemen allowances are always made for peculiar cases, where\nit would be an outrageous moral injustice for one party to claim\npossession of a whale previously chased or killed by another party", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5860, "position": 5860, "text": "to claim\npossession of a whale previously chased or killed by another party. But\nothers are by no means so scrupulous.\n\nSome fifty years ago there was a curious case of whale-trover litigated\nin England, wherein the plaintiffs set forth", "labels": {"50": 43, "100": 48, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5861, "position": 5861, "text": "whale-trover litigated\nin England, wherein the plaintiffs set forth that after a hard chase of\na whale in the Northern seas; and when indeed they (the plaintiffs) had\nsucceeded in harpooning the fish; they were at last,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5862, "position": 5862, "text": ") had\nsucceeded in harpooning the fish; they were at last, through peril of\ntheir lives, obliged to forsake not only their lines, but their boat\nitself. Ultimately the defendants (the crew of another ship) came up\nwith", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5863, "position": 5863, "text": "itself. Ultimately the defendants (the crew of another ship) came up\nwith the whale, struck, killed, seized, and finally appropriated it\nbefore the very eyes of the plaintiffs. And when those defendants were\nremonstrated with, their captain snapped", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5864, "position": 5864, "text": ". And when those defendants were\nremonstrated with, their captain snapped his fingers in the plaintiffs’\nteeth, and assured them that by way of doxology to the deed he had\ndone, he would now retain their line, harpoons,", "labels": {"50": 45, "100": 64, "250": 30, "500": 73, "1000": 851, "2000": 1620}}, {"id": 5865, "position": 5865, "text": "deed he had\ndone, he would now retain their line, harpoons, and boat, which had\nremained attached to the whale at the time of the seizure. Wherefore\nthe plaintiffs now sued for the recovery of the value of their whale,\nline", "labels": {"50": 43, "100": 48, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5866, "position": 5866, "text": "the plaintiffs now sued for the recovery of the value of their whale,\nline, harpoons, and boat.\n\nMr. Erskine was counsel for the defendants; Lord Ellenborough was the\njudge. In the course of the defence, the witty Erskine went on", "labels": {"50": 43, "100": 48, "250": 71, "500": 396, "1000": 336, "2000": 439}}, {"id": 5867, "position": 5867, "text": "the\njudge. In the course of the defence, the witty Erskine went on to\nillustrate his position, by alluding to a recent crim. con. case,\nwherein a gentleman, after in vain trying to bridle his wife’s\nvicious", "labels": {"50": 43, "100": 48, "250": 71, "500": 396, "1000": 336, "2000": 1965}}, {"id": 5868, "position": 5868, "text": "gentleman, after in vain trying to bridle his wife’s\nviciousness, had at last abandoned her upon the seas of life; but in\nthe course of years, repenting of that step, he instituted an action to\nrecover possession of her", "labels": {"50": 33, "100": 17, "250": 160, "500": 358, "1000": 138, "2000": 1262}}, {"id": 5869, "position": 5869, "text": "repenting of that step, he instituted an action to\nrecover possession of her. Erskine was on the other side; and he then\nsupported it by saying, that though the gentleman had originally\nharpooned the lady, and had once had her fast,", "labels": {"50": 43, "100": 48, "250": 71, "500": 396, "1000": 336, "2000": 1965}}, {"id": 5870, "position": 5870, "text": "had originally\nharpooned the lady, and had once had her fast, and only by reason of\nthe great stress of her plunging viciousness, had at last abandoned\nher; yet abandon her he did, so that she became a loose-fish;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 692, "2000": 982}}, {"id": 5871, "position": 5871, "text": "yet abandon her he did, so that she became a loose-fish; and\ntherefore when a subsequent gentleman re-harpooned her, the lady then\nbecame that subsequent gentleman’s property, along with whatever\nharpoon might have been found sticking in", "labels": {"50": 43, "100": 76, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5872, "position": 5872, "text": "’s property, along with whatever\nharpoon might have been found sticking in her.\n\nNow in the present case Erskine contended that the examples of the\nwhale and the lady were reciprocally illustrative of each other.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5873, "position": 5873, "text": "reciprocally illustrative of each other.\n\nThese pleadings, and the counter pleadings, being duly heard, the very\nlearned judge in set terms decided, to wit,—That as for the boat, he\nawarded it to the plaintiffs, because", "labels": {"50": 43, "100": 48, "250": 71, "500": 396, "1000": 336, "2000": 1965}}, {"id": 5874, "position": 5874, "text": "—That as for the boat, he\nawarded it to the plaintiffs, because they had merely abandoned it to\nsave their lives; but that with regard to the controverted whale,\nharpoons, and line, they belonged to the defendants; the whale", "labels": {"50": 43, "100": 48, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5875, "position": 5875, "text": ",\nharpoons, and line, they belonged to the defendants; the whale, because\nit was a Loose-Fish at the time of the final capture; and the harpoons\nand line because when the fish made off with them, it (the fish", "labels": {"50": 43, "100": 76, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5876, "position": 5876, "text": "and line because when the fish made off with them, it (the fish)\nacquired a property in those articles; and hence anybody who afterwards\ntook the fish had a right to them. Now the defendants afterwards took\nthe fish; ergo, the af", "labels": {"50": 43, "100": 76, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5877, "position": 5877, "text": "them. Now the defendants afterwards took\nthe fish; ergo, the aforesaid articles were theirs.\n\nA common man looking at this decision of the very learned Judge, might\npossibly object to it. But ploughed up to the primary rock of", "labels": {"50": 43, "100": 48, "250": 94, "500": 396, "1000": 336, "2000": 422}}, {"id": 5878, "position": 5878, "text": "possibly object to it. But ploughed up to the primary rock of the\nmatter, the two great principles laid down in the twin whaling laws\npreviously quoted, and applied and elucidated by Lord Ellenborough in\nthe above cited case; these", "labels": {"50": 14, "100": 76, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5879, "position": 5879, "text": "elucidated by Lord Ellenborough in\nthe above cited case; these two laws touching Fast-Fish and Loose-Fish,\nI say, will, on reflection, be found the fundamentals of all human\njurisprudence; for notwithstanding its complicated tracery", "labels": {"50": 43, "100": 48, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5880, "position": 5880, "text": "found the fundamentals of all human\njurisprudence; for notwithstanding its complicated tracery of\nsculpture, the Temple of the Law, like the Temple of the Philistines,\nhas but two props to stand on.", "labels": {"50": 10, "100": 71, "250": 129, "500": 236, "1000": 507, "2000": 215}}, {"id": 5881, "position": 5881, "text": "two props to stand on.\n\nIs it not a saying in every one’s mouth, Possession is half of the law:\nthat is, regardless of how the thing came into possession? But often\npossession is the whole of the law", "labels": {"50": 43, "100": 48, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5882, "position": 5882, "text": "possession? But often\npossession is the whole of the law. What are the sinews and souls of\nRussian serfs and Republican slaves but Fast-Fish, whereof possession\nis the whole of the law? What to the rapacious landlord is the", "labels": {"50": 10, "100": 75, "250": 88, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5883, "position": 5883, "text": "is the whole of the law? What to the rapacious landlord is the widow’s\nlast mite but a Fast-Fish? What is yonder undetected villain’s marble\nmansion with a door-plate for a waif; what", "labels": {"50": 31, "100": 73, "250": 193, "500": 498, "1000": 637, "2000": 1886}}, {"id": 5884, "position": 5884, "text": "’s marble\nmansion with a door-plate for a waif; what is that but a Fast-Fish?\nWhat is the ruinous discount which Mordecai, the broker, gets from poor\nWoebegone, the bankrupt, on", "labels": {"50": 31, "100": 7, "250": 151, "500": 369, "1000": 372, "2000": 1394}}, {"id": 5885, "position": 5885, "text": "the broker, gets from poor\nWoebegone, the bankrupt, on a loan to keep Woebegone’s family from\nstarvation; what is that ruinous discount but a Fast-Fish? What is the\nArchbishop of Savesoul’", "labels": {"50": 21, "100": 95, "250": 193, "500": 307, "1000": 581, "2000": 522}}, {"id": 5886, "position": 5886, "text": "but a Fast-Fish? What is the\nArchbishop of Savesoul’s income of £100,000 seized from the scant bread\nand cheese of hundreds of thousands of broken-backed laborers (all sure\nof heaven without any of Savesoul’", "labels": {"50": 21, "100": 95, "250": 32, "500": 307, "1000": 343, "2000": 761}}, {"id": 5887, "position": 5887, "text": "-backed laborers (all sure\nof heaven without any of Savesoul’s help) what is that globular\n£100,000 but a Fast-Fish? What are the Duke of Dunder’s hereditary\ntowns and hamlets but Fast-Fish", "labels": {"50": 31, "100": 7, "250": 193, "500": 37, "1000": 387, "2000": 1741}}, {"id": 5888, "position": 5888, "text": "the Duke of Dunder’s hereditary\ntowns and hamlets but Fast-Fish? What to that redoubted harpooneer,\nJohn Bull, is poor Ireland, but a Fast-Fish? What to that apostolic\nlancer, Brother Jonathan,", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 39}}, {"id": 5889, "position": 5889, "text": "a Fast-Fish? What to that apostolic\nlancer, Brother Jonathan, is Texas but a Fast-Fish? And concerning all\nthese, is not Possession the whole of the law?\n\nBut if the doctrine of Fast-Fish be pretty generally applicable,", "labels": {"50": 31, "100": 7, "250": 193, "500": 453, "1000": 165, "2000": 1394}}, {"id": 5890, "position": 5890, "text": "law?\n\nBut if the doctrine of Fast-Fish be pretty generally applicable, the\nkindred doctrine of Loose-Fish is still more widely so. That is\ninternationally and universally applicable.\n\nWhat was America in 1492 but a Loose-Fish, in which", "labels": {"50": 21, "100": 76, "250": 94, "500": 295, "1000": 913, "2000": 1778}}, {"id": 5891, "position": 5891, "text": ".\n\nWhat was America in 1492 but a Loose-Fish, in which Columbus struck the\nSpanish standard by way of waifing it for his royal master and\nmistress? What was Poland to the Czar? What Greece to the Turk? What\nIndia", "labels": {"50": 39, "100": 99, "250": 193, "500": 39, "1000": 849, "2000": 1585}}, {"id": 5892, "position": 5892, "text": "was Poland to the Czar? What Greece to the Turk? What\nIndia to England? What at last will Mexico be to the United States? All\nLoose-Fish.\n\nWhat are the Rights of Man and the Liberties of the World but\nLoose-Fish", "labels": {"50": 31, "100": 7, "250": 193, "500": 36, "1000": 849, "2000": 421}}, {"id": 5893, "position": 5893, "text": "are the Rights of Man and the Liberties of the World but\nLoose-Fish? What all men’s minds and opinions but Loose-Fish? What is\nthe principle of religious belief in them but a Loose-Fish? What to the\nostentat", "labels": {"50": 31, "100": 95, "250": 44, "500": 19, "1000": 499, "2000": 629}}, {"id": 5894, "position": 5894, "text": "belief in them but a Loose-Fish? What to the\nostentatious smuggling verbalists are the thoughts of thinkers but\nLoose-Fish? What is the great globe itself but a Loose-Fish? And what\nare you, reader, but a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5895, "position": 5895, "text": "but a Loose-Fish? And what\nare you, reader, but a Loose-Fish and a Fast-Fish, too?\n\n\nCHAPTER 90. Heads or Tails.\n\n“De balena vero sufficit, si rex habeat caput,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5896, "position": 5896, "text": "balena vero sufficit, si rex habeat caput, et regina caudam.”\n_Bracton, l. 3, c. 3._\n\nLatin from the books of the Laws of England, which taken along with the", "labels": {"50": 14, "100": 32, "250": 92, "500": 385, "1000": 47, "2000": 1283}}, {"id": 5897, "position": 5897, "text": "Latin from the books of the Laws of England, which taken along with the\ncontext, means, that of all whales captured by anybody on the coast of\nthat land, the King, as Honorary Grand Harpooneer, must have the head,\nand the", "labels": {"50": 14, "100": 29, "250": 82, "500": 79, "1000": 354, "2000": 447}}, {"id": 5898, "position": 5898, "text": ", as Honorary Grand Harpooneer, must have the head,\nand the Queen be respectfully presented with the tail. A division\nwhich, in the whale, is much like halving an apple; there is no\nintermediate remainder", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5899, "position": 5899, "text": "halving an apple; there is no\nintermediate remainder. Now as this law, under a modified form, is to\nthis day in force in England; and as it offers in various respects a\nstrange anomaly touching the general law of Fast and Loose-Fish", "labels": {"50": 21, "100": 76, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5900, "position": 5900, "text": "various respects a\nstrange anomaly touching the general law of Fast and Loose-Fish, it is\nhere treated of in a separate chapter, on the same courteous principle\nthat prompts the English railways to be at the expense of a separate\ncar, specially reserved", "labels": {"50": 3, "100": 85, "250": 52, "500": 417, "1000": 886, "2000": 15}}, {"id": 5901, "position": 5901, "text": "the English railways to be at the expense of a separate\ncar, specially reserved for the accommodation of royalty. In the first\nplace, in curious proof of the fact that the above-mentioned law is\nstill in force, I proceed to lay before you a", "labels": {"50": 15, "100": 62, "250": 80, "500": 224, "1000": 784, "2000": 177}}, {"id": 5902, "position": 5902, "text": "-mentioned law is\nstill in force, I proceed to lay before you a circumstance that\nhappened within the last two years.\n\nIt seems that some honest mariners of Dover, or Sandwich, or some one\nof the Cinque Ports, had after a hard", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 851, "2000": 1442}}, {"id": 5903, "position": 5903, "text": ", or some one\nof the Cinque Ports, had after a hard chase succeeded in killing and\nbeaching a fine whale which they had originally descried afar off from\nthe shore. Now the Cinque Ports are partially or somehow under the", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5904, "position": 5904, "text": "the shore. Now the Cinque Ports are partially or somehow under the\njurisdiction of a sort of policeman or beadle, called a Lord Warden.\nHolding the office directly from the crown, I believe, all the royal\nemoluments incident to", "labels": {"50": 23, "100": 88, "250": 244, "500": 202, "1000": 953, "2000": 1731}}, {"id": 5905, "position": 5905, "text": "the crown, I believe, all the royal\nemoluments incident to the Cinque Port territories become by assignment\nhis. By some writers this office is called a sinecure. But not so.\nBecause the Lord Warden is busily employed at", "labels": {"50": 14, "100": 76, "250": 193, "500": 202, "1000": 664, "2000": 1731}}, {"id": 5906, "position": 5906, "text": "ecure. But not so.\nBecause the Lord Warden is busily employed at times in fobbing his\nperquisites; which are his chiefly by virtue of that same fobbing of\nthem.\n\nNow when these poor sun-burnt mariners, bare", "labels": {"50": 23, "100": 76, "250": 32, "500": 37, "1000": 664, "2000": 374}}, {"id": 5907, "position": 5907, "text": "obbing of\nthem.\n\nNow when these poor sun-burnt mariners, bare-footed, and with their\ntrowsers rolled high up on their eely legs, had wearily hauled their\nfat fish high and dry, promising themselves a good £150", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 5908, "position": 5908, "text": "ily hauled their\nfat fish high and dry, promising themselves a good £150 from the\nprecious oil and bone; and in fantasy sipping rare tea with their\nwives, and good ale with their cronies, upon the strength of their\nrespective shares; up", "labels": {"50": 9, "100": 26, "250": 30, "500": 498, "1000": 637, "2000": 1003}}, {"id": 5909, "position": 5909, "text": "with their cronies, upon the strength of their\nrespective shares; up steps a very learned and most Christian and\ncharitable gentleman, with a copy of Blackstone under his arm; and\nlaying it upon the whale’s head, he says—“", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 5910, "position": 5910, "text": "; and\nlaying it upon the whale’s head, he says—“Hands off! this fish, my\nmasters, is a Fast-Fish. I seize it as the Lord Warden’s.” Upon this\nthe poor mariners in their respectful con", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5911, "position": 5911, "text": "Lord Warden’s.” Upon this\nthe poor mariners in their respectful consternation—so truly\nEnglish—knowing not what to say, fall to vigorously scratching their\nheads all round; meanwhile ruefully glancing from the whale to the\nstranger", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5912, "position": 5912, "text": "round; meanwhile ruefully glancing from the whale to the\nstranger. But that did in nowise mend the matter, or at all soften the\nhard heart of the learned gentleman with the copy of Blackstone", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 849, "2000": 1620}}, {"id": 5913, "position": 5913, "text": "gentleman with the copy of Blackstone. At\nlength one of them, after long scratching about for his ideas, made\nbold to speak,\n\n“Please, sir, who is the Lord Warden?”\n\n“The Duke.”", "labels": {"50": 23, "100": 68, "250": 244, "500": 320, "1000": 376, "2000": 1415}}, {"id": 5914, "position": 5914, "text": "Lord Warden?”\n\n“The Duke.”\n\n“But the duke had nothing to do with taking this fish?”\n\n“It is his.”\n\n“We have been at great trouble, and peril, and some expense, and is all\nthat to", "labels": {"50": 23, "100": 87, "250": 102, "500": 2, "1000": 376, "2000": 135}}, {"id": 5915, "position": 5915, "text": "trouble, and peril, and some expense, and is all\nthat to go to the Duke’s benefit; we getting nothing at all for our\npains but our blisters?”\n\n“It is his.”", "labels": {"50": 18, "100": 87, "250": 180, "500": 18, "1000": 709, "2000": 1237}}, {"id": 5916, "position": 5916, "text": "ers?”\n\n“It is his.”\n\n“Is the Duke so very poor as to be forced to this desperate mode of\ngetting a livelihood?”\n\n“It is his.”\n\n“I thought to relieve my old bed-ridden mother by part of", "labels": {"50": 36, "100": 87, "250": 102, "500": 170, "1000": 535, "2000": 1619}}, {"id": 5917, "position": 5917, "text": "”\n\n“I thought to relieve my old bed-ridden mother by part of my share of\nthis whale.”\n\n“It is his.”\n\n“Won’t the Duke be content with a quarter or a half?”\n\n“It is his.”", "labels": {"50": 23, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5918, "position": 5918, "text": "content with a quarter or a half?”\n\n“It is his.”\n\nIn a word, the whale was seized and sold, and his Grace the Duke of\nWellington received the money. Thinking that viewed in some particular\nlights, the case might by a", "labels": {"50": 17, "100": 40, "250": 81, "500": 374, "1000": 318, "2000": 1620}}, {"id": 5919, "position": 5919, "text": "money. Thinking that viewed in some particular\nlights, the case might by a bare possibility in some small degree be\ndeemed, under the circumstances, a rather hard one, an honest clergyman\nof the town respectfully addressed a note to his Grace, begging him", "labels": {"50": 23, "100": 17, "250": 160, "500": 14, "1000": 485, "2000": 1002}}, {"id": 5920, "position": 5920, "text": "clergyman\nof the town respectfully addressed a note to his Grace, begging him to\ntake the case of those unfortunate mariners into full consideration. To\nwhich my Lord Duke in substance replied (both letters were published)\nthat he had already done so, and received", "labels": {"50": 33, "100": 17, "250": 21, "500": 320, "1000": 376, "2000": 97}}, {"id": 5921, "position": 5921, "text": "(both letters were published)\nthat he had already done so, and received the money, and would be\nobliged to the reverend gentleman if for the future he (the reverend\ngentleman) would decline meddling with other people’s business", "labels": {"50": 43, "100": 48, "250": 8, "500": 214, "1000": 943, "2000": 1881}}, {"id": 5922, "position": 5922, "text": ") would decline meddling with other people’s business. Is this\nthe still militant old man, standing at the corners of the three\nkingdoms, on all hands coercing alms of beggars?", "labels": {"50": 31, "100": 20, "250": 49, "500": 126, "1000": 727, "2000": 1107}}, {"id": 5923, "position": 5923, "text": "alms of beggars?\n\nIt will readily be seen that in this case the alleged right of the Duke\nto the whale was a delegated one from the Sovereign. We must needs\ninquire then on what principle the Sovereign is originally invested\nwith", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5924, "position": 5924, "text": "must needs\ninquire then on what principle the Sovereign is originally invested\nwith that right. The law itself has already been set forth. But Plowdon\ngives us the reason for it. Says Plowdon, the whale so caught belongs\nto the", "labels": {"50": 43, "100": 76, "250": 94, "500": 295, "1000": 698, "2000": 1778}}, {"id": 5925, "position": 5925, "text": "for it. Says Plowdon, the whale so caught belongs\nto the King and Queen, “because of its superior excellence.” And by the\nsoundest commentators this has ever been held a cogent argument in such\nmatters.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5926, "position": 5926, "text": "ever been held a cogent argument in such\nmatters.\n\nBut why should the King have the head, and the Queen the tail? A reason\nfor that, ye lawyers!\n\nIn his treatise on “Queen-Gold,” or Queen-pinmoney", "labels": {"50": 45, "100": 64, "250": 193, "500": 73, "1000": 851, "2000": 1620}}, {"id": 5927, "position": 5927, "text": "his treatise on “Queen-Gold,” or Queen-pinmoney, an old King’s Bench\nauthor, one William Prynne, thus discourseth: “Ye tail is ye Queen’s,\nthat ye Queen’s wardrobe may be", "labels": {"50": 14, "100": 68, "250": 111, "500": 62, "1000": 953, "2000": 490}}, {"id": 5928, "position": 5928, "text": "tail is ye Queen’s,\nthat ye Queen’s wardrobe may be supplied with ye whalebone.” Now this\nwas written at a time when the black limber bone of the Greenland or\nRight whale was largely used in ladies’ bodices", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5929, "position": 5929, "text": "of the Greenland or\nRight whale was largely used in ladies’ bodices. But this same bone is\nnot in the tail; it is in the head, which is a sad mistake for a\nsagacious lawyer like Prynne", "labels": {"50": 31, "100": 7, "250": 138, "500": 72, "1000": 199, "2000": 1620}}, {"id": 5930, "position": 5930, "text": "sad mistake for a\nsagacious lawyer like Prynne. But is the Queen a mermaid, to be\npresented with a tail? An allegorical meaning may lurk here.\n\nThere are two royal fish so styled by the English law writers—the whale\nand", "labels": {"50": 45, "100": 75, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5931, "position": 5931, "text": "are two royal fish so styled by the English law writers—the whale\nand the sturgeon; both royal property under certain limitations, and\nnominally supplying the tenth branch of the crown’s ordinary revenue. I\nknow not that any other author has hinted of", "labels": {"50": 10, "100": 75, "250": 193, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5932, "position": 5932, "text": "’s ordinary revenue. I\nknow not that any other author has hinted of the matter; but by\ninference it seems to me that the sturgeon must be divided in the same\nway as the whale, the King receiving the highly dense and elastic head\npeculiar", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5933, "position": 5933, "text": "way as the whale, the King receiving the highly dense and elastic head\npeculiar to that fish, which, symbolically regarded, may possibly be\nhumorously grounded upon some presumed congeniality. And thus there\nseems a reason in all things, even in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5934, "position": 5934, "text": "eniality. And thus there\nseems a reason in all things, even in law.\n\n\nCHAPTER 91. The Pequod Meets The Rose-Bud.\n\n“In vain it was to rake for Ambergriese in the paunch of this\nLeviathan", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 5935, "position": 5935, "text": "to rake for Ambergriese in the paunch of this\nLeviathan, insufferable fetor denying not inquiry.” _Sir T. Browne,\nV.E._\n\nIt was a week or two after the last whaling scene recounted", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5936, "position": 5936, "text": "E._\n\nIt was a week or two after the last whaling scene recounted, and when\nwe were slowly sailing over a sleepy, vapory, mid-day sea, that the\nmany noses on the Pequod’s deck proved more vigil", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5937, "position": 5937, "text": "the\nmany noses on the Pequod’s deck proved more vigilant discoverers than\nthe three pairs of eyes aloft. A peculiar and not very pleasant smell\nwas smelt in the sea.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5938, "position": 5938, "text": "smelt in the sea.\n\n“I will bet something now,” said Stubb, “that somewhere hereabouts are\nsome of those drugged whales we tickled the other day. I thought they\nwould keel up before long.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5939, "position": 5939, "text": "day. I thought they\nwould keel up before long.”\n\nPresently, the vapors in advance slid aside; and there in the distance\nlay a ship, whose furled sails betokened that some sort of whale must\nbe alongside", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 5940, "position": 5940, "text": "betokened that some sort of whale must\nbe alongside. As we glided nearer, the stranger showed French colours\nfrom his peak; and by the eddying cloud of vulture sea-fowl that\ncircled, and hovered, and swooped around him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5941, "position": 5941, "text": "-fowl that\ncircled, and hovered, and swooped around him, it was plain that the\nwhale alongside must be what the fishermen call a blasted whale, that\nis, a whale that has died unmolested on the sea, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5942, "position": 5942, "text": ", a whale that has died unmolested on the sea, and so floated an\nunappropriated corpse. It may well be conceived, what an unsavory odor\nsuch a mass must exhale; worse than an Assyrian city in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5943, "position": 5943, "text": "y odor\nsuch a mass must exhale; worse than an Assyrian city in the plague,\nwhen the living are incompetent to bury the departed. So intolerable\nindeed is it regarded by some, that no cupidity could persuade them", "labels": {"50": 48, "100": 7, "250": 159, "500": 37, "1000": 387, "2000": 1279}}, {"id": 5944, "position": 5944, "text": "indeed is it regarded by some, that no cupidity could persuade them to\nmoor alongside of it. Yet are there those who will still do it;\nnotwithstanding the fact that the oil obtained from such subjects is of\na very inferior quality, and by", "labels": {"50": 42, "100": 63, "250": 46, "500": 197, "1000": 571, "2000": 694}}, {"id": 5945, "position": 5945, "text": "the oil obtained from such subjects is of\na very inferior quality, and by no means of the nature of\nattar-of-rose.\n\nComing still nearer with the expiring breeze, we saw that the Frenchman\nhad a second whale alongside; and", "labels": {"50": 45, "100": 43, "250": 34, "500": 48, "1000": 126, "2000": 1817}}, {"id": 5946, "position": 5946, "text": "ring breeze, we saw that the Frenchman\nhad a second whale alongside; and this second whale seemed even more of\na nosegay than the first. In truth, it turned out to be one of those\nproblematical whales that seem to dry up and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5947, "position": 5947, "text": "out to be one of those\nproblematical whales that seem to dry up and die with a sort of\nprodigious dyspepsia, or indigestion; leaving their defunct bodies\nalmost entirely bankrupt of anything like oil", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5948, "position": 5948, "text": "; leaving their defunct bodies\nalmost entirely bankrupt of anything like oil. Nevertheless, in the\nproper place we shall see that no knowing fisherman will ever turn up\nhis nose at such a whale as this, however much he may shun blasted\nwhales in general.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 5949, "position": 5949, "text": "whale as this, however much he may shun blasted\nwhales in general.\n\nThe Pequod had now swept so nigh to the stranger, that Stubb vowed he\nrecognised his cutting spade-pole entangled in the lines that were\nknotted round the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5950, "position": 5950, "text": "his cutting spade-pole entangled in the lines that were\nknotted round the tail of one of these whales.\n\n“There’s a pretty fellow, now,” he banteringly laughed, standing in the\nship’s bows, “there’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5951, "position": 5951, "text": "teringly laughed, standing in the\nship’s bows, “there’s a jackal for ye! I well know that these Crappoes\nof Frenchmen are but poor devils in the fishery; sometimes lowering\ntheir boats for breakers, mistaking", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 5952, "position": 5952, "text": "poor devils in the fishery; sometimes lowering\ntheir boats for breakers, mistaking them for Sperm Whale spouts; yes,\nand sometimes sailing from their port with their hold full of boxes of\ntallow candles, and cases of snuffers, fore", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 682}}, {"id": 5953, "position": 5953, "text": "boxes of\ntallow candles, and cases of snuffers, foreseeing that all the oil they\nwill get won’t be enough to dip the Captain’s wick into; aye, we all\nknow these things; but look ye", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5954, "position": 5954, "text": "wick into; aye, we all\nknow these things; but look ye, here’s a Crappo that is content with\nour leavings, the drugged whale there, I mean; aye, and is content too\nwith scraping the dry bones of", "labels": {"50": 6, "100": 64, "250": 193, "500": 498, "1000": 851, "2000": 1620}}, {"id": 5955, "position": 5955, "text": "I mean; aye, and is content too\nwith scraping the dry bones of that other precious fish he has there.\nPoor devil! I say, pass round a hat, some one, and let’s make him a\npresent of a little oil for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5956, "position": 5956, "text": "one, and let’s make him a\npresent of a little oil for dear charity’s sake. For what oil he’ll get\nfrom that drugged whale there, wouldn’t be fit to burn in a jail; no,\nnot in a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5957, "position": 5957, "text": "’t be fit to burn in a jail; no,\nnot in a condemned cell. And as for the other whale, why, I’ll agree to\nget more oil by chopping up and trying out these three masts of ours,\nthan", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5958, "position": 5958, "text": "by chopping up and trying out these three masts of ours,\nthan he’ll get from that bundle of bones; though, now that I think of\nit, it may contain something worth a good deal more than oil; yes,\nambergr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 556, "2000": 1668}}, {"id": 5959, "position": 5959, "text": "may contain something worth a good deal more than oil; yes,\nambergris. I wonder now if our old man has thought of that. It’s worth\ntrying. Yes, I’m for it;” and so saying he started for", "labels": {"50": 39, "100": 99, "250": 57, "500": 154, "1000": 311, "2000": 51}}, {"id": 5960, "position": 5960, "text": "Yes, I’m for it;” and so saying he started for the\nquarter-deck.\n\nBy this time the faint air had become a complete calm; so that whether\nor no, the Pequod was now fairly entrapped in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5961, "position": 5961, "text": "or no, the Pequod was now fairly entrapped in the smell, with no hope\nof escaping except by its breezing up again. Issuing from the cabin,\nStubb now called his boat’s crew, and pulled off for the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5962, "position": 5962, "text": "Stubb now called his boat’s crew, and pulled off for the stranger.\nDrawing across her bow, he perceived that in accordance with the\nfanciful French taste, the upper part of her stem-piece was carved in\nthe likeness of a huge", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5963, "position": 5963, "text": "upper part of her stem-piece was carved in\nthe likeness of a huge drooping stalk, was painted green, and for\nthorns had copper spikes projecting from it here and there; the whole\nterminating in a symmetrical folded bulb of a bright red colour", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 381, "2000": 52}}, {"id": 5964, "position": 5964, "text": "; the whole\nterminating in a symmetrical folded bulb of a bright red colour. Upon\nher head boards, in large gilt letters, he read “Bouton de\nRose,”—Rose-button, or Rose-bud; and this was the romantic", "labels": {"50": 0, "100": 91, "250": 189, "500": 297, "1000": 708, "2000": 218}}, {"id": 5965, "position": 5965, "text": "—Rose-button, or Rose-bud; and this was the romantic name of this\naromatic ship.\n\nThough Stubb did not understand the _Bouton_ part of the inscription,\nyet the word _rose_, and the bulbous figure-", "labels": {"50": 7, "100": 91, "250": 247, "500": 257, "1000": 177, "2000": 644}}, {"id": 5966, "position": 5966, "text": "inscription,\nyet the word _rose_, and the bulbous figure-head put together,\nsufficiently explained the whole to him.\n\n“A wooden rose-bud, eh?” he cried with his hand to his nose, “that will\ndo very", "labels": {"50": 22, "100": 78, "250": 229, "500": 286, "1000": 631, "2000": 644}}, {"id": 5967, "position": 5967, "text": "” he cried with his hand to his nose, “that will\ndo very well; but how like all creation it smells!”\n\nNow in order to hold direct communication with the people on deck, he\nhad to pull round the bows to the starboard side", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 5968, "position": 5968, "text": "people on deck, he\nhad to pull round the bows to the starboard side, and thus come close\nto the blasted whale; and so talk over it.\n\nArrived then at this spot, with one hand still to his nose, he\nbawled—“", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 5969, "position": 5969, "text": "spot, with one hand still to his nose, he\nbawled—“Bouton-de-Rose, ahoy! are there any of you Bouton-de-Roses that\nspeak English?”", "labels": {"50": 1, "100": 49, "250": 185, "500": 180, "1000": 994, "2000": 770}}, {"id": 5970, "position": 5970, "text": "Roses that\nspeak English?”\n\n“Yes,” rejoined a Guernsey-man from the bulwarks, who turned out to be\nthe chief-mate.\n\n“Well, then, my Bouton-de-Rose-bud, have you seen", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 5971, "position": 5971, "text": "then, my Bouton-de-Rose-bud, have you seen the White Whale?”\n\n“_What_ whale?”\n\n“The _White_ Whale—a Sperm Whale—Moby Dick, have ye seen him?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5972, "position": 5972, "text": "Sperm Whale—Moby Dick, have ye seen him?\n\n“Never heard of such a whale. Cachalot Blanche! White Whale—no.”\n\n“Very good, then; good bye now, and I’ll call again in a minute", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5973, "position": 5973, "text": "then; good bye now, and I’ll call again in a minute.”\n\nThen rapidly pulling back towards the Pequod, and seeing Ahab leaning\nover the quarter-deck rail awaiting his report, he moulded his two\nhands into", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5974, "position": 5974, "text": "-deck rail awaiting his report, he moulded his two\nhands into a trumpet and shouted—“No, Sir! No!” Upon which Ahab\nretired, and Stubb returned to the Frenchman.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 5975, "position": 5975, "text": "Stubb returned to the Frenchman.\n\nHe now perceived that the Guernsey-man, who had just got into the\nchains, and was using a cutting-spade, had slung his nose in a sort of\nbag.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 324}}, {"id": 5976, "position": 5976, "text": "nose in a sort of\nbag.\n\n“What’s the matter with your nose, there?” said Stubb. “Broke it?”\n\n“I wish it was broken, or that I didn’t have any nose at all!” answered", "labels": {"50": 11, "100": 64, "250": 91, "500": 432, "1000": 488, "2000": 51}}, {"id": 5977, "position": 5977, "text": ", or that I didn’t have any nose at all!” answered\nthe Guernsey-man, who did not seem to relish the job he was at very\nmuch. “But what are you holding _yours_ for?”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 5978, "position": 5978, "text": "“But what are you holding _yours_ for?”\n\n“Oh, nothing! It’s a wax nose; I have to hold it on. Fine day, ain’t\nit? Air rather gardenny, I should say; throw us", "labels": {"50": 37, "100": 88, "250": 91, "500": 100, "1000": 488, "2000": 1199}}, {"id": 5979, "position": 5979, "text": "’t\nit? Air rather gardenny, I should say; throw us a bunch of posies, will\nye, Bouton-de-Rose?”\n\n“What in the devil’s name do you want here?” roared the Guernseyman", "labels": {"50": 23, "100": 88, "250": 219, "500": 180, "1000": 627, "2000": 1091}}, {"id": 5980, "position": 5980, "text": "the devil’s name do you want here?” roared the Guernseyman,\nflying into a sudden passion.\n\n“Oh! keep cool—cool? yes, that’s the word! why don’t you pack those\nwhales in ice while you", "labels": {"50": 22, "100": 88, "250": 205, "500": 72, "1000": 533, "2000": 1781}}, {"id": 5981, "position": 5981, "text": "the word! why don’t you pack those\nwhales in ice while you’re working at ’em? But joking aside, though; do\nyou know, Rose-bud, that it’s all nonsense trying to get any oil out of\nsuch", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5982, "position": 5982, "text": ", that it’s all nonsense trying to get any oil out of\nsuch whales? As for that dried up one, there, he hasn’t a gill in his\nwhole carcase.”\n\n“I know that well enough; but, d’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5983, "position": 5983, "text": "carcase.”\n\n“I know that well enough; but, d’ye see, the Captain here won’t believe\nit; this is his first voyage; he was a Cologne manufacturer before. But\ncome aboard, and mayhap he’", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 5984, "position": 5984, "text": "a Cologne manufacturer before. But\ncome aboard, and mayhap he’ll believe you, if he won’t me; and so I’ll\nget out of this dirty scrape.”\n\n“Anything to oblige ye, my sweet and", "labels": {"50": 41, "100": 21, "250": 91, "500": 281, "1000": 230, "2000": 1199}}, {"id": 5985, "position": 5985, "text": "dirty scrape.”\n\n“Anything to oblige ye, my sweet and pleasant fellow,” rejoined Stubb,\nand with that he soon mounted to the deck. There a queer scene\npresented itself. The sailors, in tasselled caps of red", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 5986, "position": 5986, "text": "queer scene\npresented itself. The sailors, in tasselled caps of red worsted, were\ngetting the heavy tackles in readiness for the whales. But they worked\nrather slow and talked very fast, and seemed in anything but a good\nhumor", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 5987, "position": 5987, "text": "talked very fast, and seemed in anything but a good\nhumor. All their noses upwardly projected from their faces like so many\njib-booms. Now and then pairs of them would drop their work, and run up\nto the mast-head", "labels": {"50": 25, "100": 41, "250": 91, "500": 224, "1000": 90, "2000": 110}}, {"id": 5988, "position": 5988, "text": "of them would drop their work, and run up\nto the mast-head to get some fresh air. Some thinking they would catch\nthe plague, dipped oakum in coal-tar, and at intervals held it to their\nnostrils", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 5989, "position": 5989, "text": "tar, and at intervals held it to their\nnostrils. Others having broken the stems of their pipes almost short\noff at the bowl, were vigorously puffing tobacco-smoke, so that it\nconstantly filled their olfactories.", "labels": {"50": 12, "100": 93, "250": 219, "500": 43, "1000": 858, "2000": 110}}, {"id": 5990, "position": 5990, "text": "that it\nconstantly filled their olfactories.\n\nStubb was struck by a shower of outcries and anathemas proceeding from\nthe Captain’s round-house abaft; and looking in that direction saw a\nfiery face thrust from behind the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 5991, "position": 5991, "text": "ft; and looking in that direction saw a\nfiery face thrust from behind the door, which was held ajar from\nwithin. This was the tormented surgeon, who, after in vain\nremonstrating against the proceedings of the day, had betaken", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 141, "2000": 1975}}, {"id": 5992, "position": 5992, "text": "vain\nremonstrating against the proceedings of the day, had betaken himself\nto the Captain’s round-house (_cabinet_ he called it) to avoid the\npest; but still, could not help yelling out his entreaties", "labels": {"50": 23, "100": 17, "250": 219, "500": 202, "1000": 317, "2000": 1087}}, {"id": 5993, "position": 5993, "text": "pest; but still, could not help yelling out his entreaties and\nindignations at times.\n\nMarking all this, Stubb argued well for his scheme, and turning to the\nGuernsey-man had a little chat with him, during which", "labels": {"50": 45, "100": 11, "250": 163, "500": 199, "1000": 251, "2000": 73}}, {"id": 5994, "position": 5994, "text": "turning to the\nGuernsey-man had a little chat with him, during which the stranger mate\nexpressed his detestation of his Captain as a conceited ignoramus, who\nhad brought them all into so unsavory and unprofi", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 5995, "position": 5995, "text": "who\nhad brought them all into so unsavory and unprofitable a pickle.\nSounding him carefully, Stubb further perceived that the Guernsey-man\nhad not the slightest suspicion concerning the ambergris", "labels": {"50": 23, "100": 88, "250": 70, "500": 178, "1000": 434, "2000": 110}}, {"id": 5996, "position": 5996, "text": "the slightest suspicion concerning the ambergris. He therefore\nheld his peace on that head, but otherwise was quite frank and\nconfidential with him, so that the two quickly concocted a little plan\nfor both circumventing and satirizing the", "labels": {"50": 37, "100": 88, "250": 70, "500": 211, "1000": 962, "2000": 1964}}, {"id": 5997, "position": 5997, "text": "cted a little plan\nfor both circumventing and satirizing the Captain, without his at all\ndreaming of distrusting their sincerity. According to this little plan\nof theirs, the Guernsey-man, under cover of an interpreter’s office,", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 5998, "position": 5998, "text": ", the Guernsey-man, under cover of an interpreter’s office,\nwas to tell the Captain what he pleased, but as coming from Stubb; and\nas for Stubb, he was to utter any nonsense that should come uppermost\nin him", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 5999, "position": 5999, "text": "bb, he was to utter any nonsense that should come uppermost\nin him during the interview.\n\nBy this time their destined victim appeared from his cabin. He was a\nsmall and dark, but rather delicate looking man for a sea-captain, with\nlarge", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 6000, "position": 6000, "text": "dark, but rather delicate looking man for a sea-captain, with\nlarge whiskers and moustache, however; and wore a red cotton velvet\nvest with watch-seals at his side. To this gentleman, Stubb was now\npolitely introduced", "labels": {"50": 23, "100": 88, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 6001, "position": 6001, "text": "seals at his side. To this gentleman, Stubb was now\npolitely introduced by the Guernsey-man, who at once ostentatiously put\non the aspect of interpreting between them.\n\n“What shall I say to him first?” said he.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 6002, "position": 6002, "text": "them.\n\n“What shall I say to him first?” said he.\n\n“Why,” said Stubb, eyeing the velvet vest and the watch and seals, “you\nmay as well begin by telling him that he looks a sort of babyish", "labels": {"50": 39, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 324}}, {"id": 6003, "position": 6003, "text": "may as well begin by telling him that he looks a sort of babyish to me,\nthough I don’t pretend to be a judge.”\n\n“He says, Monsieur,” said the Guernsey-man, in French, turning to his\ncaptain", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 6004, "position": 6004, "text": ",” said the Guernsey-man, in French, turning to his\ncaptain, “that only yesterday his ship spoke a vessel, whose captain\nand chief-mate, with six sailors, had all died of a fever caught from a\nblasted whale they had", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 6005, "position": 6005, "text": "sailors, had all died of a fever caught from a\nblasted whale they had brought alongside.”\n\nUpon this the captain started, and eagerly desired to know more.\n\n“What now?” said the Guernsey-man to Stubb.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6006, "position": 6006, "text": "?” said the Guernsey-man to Stubb.\n\n“Why, since he takes it so easy, tell him that now I have eyed him\ncarefully, I’m quite certain that he’s no more fit to command a\nwhale-ship than", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6007, "position": 6007, "text": "certain that he’s no more fit to command a\nwhale-ship than a St. Jago monkey. In fact, tell him from me he’s a\nbaboon.”\n\n“He vows and declares, Monsieur, that the other whale", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 851, "2000": 1620}}, {"id": 6008, "position": 6008, "text": "on.”\n\n“He vows and declares, Monsieur, that the other whale, the dried one,\nis far more deadly than the blasted one; in fine, Monsieur, he conjures\nus, as we value our lives, to cut loose from", "labels": {"50": 1, "100": 49, "250": 185, "500": 2, "1000": 359, "2000": 1504}}, {"id": 6009, "position": 6009, "text": "conjures\nus, as we value our lives, to cut loose from these fish.”\n\nInstantly the captain ran forward, and in a loud voice commanded his\ncrew to desist from hoisting the cutting-tackles, and at once cast\nloose", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6010, "position": 6010, "text": "ist from hoisting the cutting-tackles, and at once cast\nloose the cables and chains confining the whales to the ship.\n\n“What now?” said the Guernsey-man, when the Captain had returned to\nthem.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6011, "position": 6011, "text": "Guernsey-man, when the Captain had returned to\nthem.\n\n“Why, let me see; yes, you may as well tell him now that—that—in fact,\ntell him I’ve diddled him, and (aside to himself)", "labels": {"50": 23, "100": 64, "250": 219, "500": 73, "1000": 851, "2000": 877}}, {"id": 6012, "position": 6012, "text": "tell him I’ve diddled him, and (aside to himself) perhaps somebody\nelse.”\n\n“He says, Monsieur, that he’s very happy to have been of any service to\nus.”", "labels": {"50": 1, "100": 49, "250": 63, "500": 402, "1000": 758, "2000": 1504}}, {"id": 6013, "position": 6013, "text": "of any service to\nus.”\n\nHearing this, the captain vowed that they were the grateful parties\n(meaning himself and mate) and concluded by inviting Stubb down into\nhis cabin to drink a bottle of Bordeaux.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 6014, "position": 6014, "text": "to drink a bottle of Bordeaux.\n\n“He wants you to take a glass of wine with him,” said the interpreter.\n\n“Thank him heartily; but tell him it’s against my principles to drink\nwith the man I’ve diddled", "labels": {"50": 34, "100": 77, "250": 117, "500": 263, "1000": 791, "2000": 1066}}, {"id": 6015, "position": 6015, "text": "’s against my principles to drink\nwith the man I’ve diddled. In fact, tell him I must go.”\n\n“He says, Monsieur, that his principles won’t admit of his drinking;\nbut that if Monsieur wants to live", "labels": {"50": 1, "100": 80, "250": 190, "500": 186, "1000": 306, "2000": 959}}, {"id": 6016, "position": 6016, "text": "won’t admit of his drinking;\nbut that if Monsieur wants to live another day to drink, then Monsieur\nhad best drop all four boats, and pull the ship away from these whales,\nfor it’s so calm they won’t drift.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 887}}, {"id": 6017, "position": 6017, "text": "these whales,\nfor it’s so calm they won’t drift.”\n\nBy this time Stubb was over the side, and getting into his boat, hailed\nthe Guernsey-man to this effect,—that having a long tow-line in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6018, "position": 6018, "text": "-man to this effect,—that having a long tow-line in his\nboat, he would do what he could to help them, by pulling out the\nlighter whale of the two from the ship’s side", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6019, "position": 6019, "text": "the two from the ship’s side. While the Frenchman’s\nboats, then, were engaged in towing the ship one way, Stubb\nbenevolently towed away at his whale the other way, ostentatiously\nslacking out a most unusually", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6020, "position": 6020, "text": "whale the other way, ostentatiously\nslacking out a most unusually long tow-line.\n\nPresently a breeze sprang up; Stubb feigned to cast off from the whale;\nhoisting his boats, the Frenchman soon increased his distance,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6021, "position": 6021, "text": "whale;\nhoisting his boats, the Frenchman soon increased his distance, while\nthe Pequod slid in between him and Stubb’s whale. Whereupon Stubb\nquickly pulled to the floating body, and hailing the Pequod to give", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6022, "position": 6022, "text": "pulled to the floating body, and hailing the Pequod to give\nnotice of his intentions, at once proceeded to reap the fruit of his\nunrighteous cunning. Seizing his sharp boat-spade, he commenced an\nexcavation in the body,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6023, "position": 6023, "text": "Seizing his sharp boat-spade, he commenced an\nexcavation in the body, a little behind the side fin. You would almost\nhave thought he was digging a cellar there in the sea; and when at\nlength his spade struck against the gaunt ribs, it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6024, "position": 6024, "text": "sea; and when at\nlength his spade struck against the gaunt ribs, it was like turning up\nold Roman tiles and pottery buried in fat English loam. His boat’s crew\nwere all in high excitement, eagerly helping their chief, and looking\nas", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 6025, "position": 6025, "text": "crew\nwere all in high excitement, eagerly helping their chief, and looking\nas anxious as gold-hunters.\n\nAnd all the time numberless fowls were diving, and ducking, and\nscreaming, and yelling, and fighting around them", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1243}}, {"id": 6026, "position": 6026, "text": "ing, and\nscreaming, and yelling, and fighting around them. Stubb was beginning\nto look disappointed, especially as the horrible nosegay increased,\nwhen suddenly from out the very heart of this plague, there stole a\nfaint stream of perfume, which", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 6027, "position": 6027, "text": "very heart of this plague, there stole a\nfaint stream of perfume, which flowed through the tide of bad smells\nwithout being absorbed by it, as one river will flow into and then\nalong with another, without at all blending with it for a time.", "labels": {"50": 22, "100": 55, "250": 28, "500": 469, "1000": 661, "2000": 213}}, {"id": 6028, "position": 6028, "text": "then\nalong with another, without at all blending with it for a time.\n\n“I have it, I have it,” cried Stubb, with delight, striking something\nin the subterranean regions, “a purse! a purse!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6029, "position": 6029, "text": "the subterranean regions, “a purse! a purse!”\n\nDropping his spade, he thrust both hands in, and drew out handfuls of\nsomething that looked like ripe Windsor soap, or rich mottled old\ncheese; very unctuous and sa", "labels": {"50": 23, "100": 88, "250": 219, "500": 154, "1000": 873, "2000": 1830}}, {"id": 6030, "position": 6030, "text": ", or rich mottled old\ncheese; very unctuous and savory withal. You might easily dent it with\nyour thumb; it is of a hue between yellow and ash colour. And this,\ngood friends, is ambergris", "labels": {"50": 42, "100": 59, "250": 10, "500": 16, "1000": 364, "2000": 1592}}, {"id": 6031, "position": 6031, "text": "yellow and ash colour. And this,\ngood friends, is ambergris, worth a gold guinea an ounce to any\ndruggist. Some six handfuls were obtained; but more was unavoidably\nlost in the sea, and still more,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 887}}, {"id": 6032, "position": 6032, "text": "more was unavoidably\nlost in the sea, and still more, perhaps, might have been secured were\nit not for impatient Ahab’s loud command to Stubb to desist, and come\non board, else the ship would bid them", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6033, "position": 6033, "text": "to desist, and come\non board, else the ship would bid them good bye.\n\n\nCHAPTER 92. Ambergris.\n\nNow this ambergris is a very curious substance, and so important as an\narticle of commerce, that in 1791 a certain", "labels": {"50": 42, "100": 46, "250": 46, "500": 197, "1000": 245, "2000": 307}}, {"id": 6034, "position": 6034, "text": ", and so important as an\narticle of commerce, that in 1791 a certain Nantucket-born Captain\nCoffin was examined at the bar of the English House of Commons on that\nsubject. For at that time, and indeed until a comparatively late day,\nthe", "labels": {"50": 15, "100": 76, "250": 200, "500": 421, "1000": 551, "2000": 936}}, {"id": 6035, "position": 6035, "text": ". For at that time, and indeed until a comparatively late day,\nthe precise origin of ambergris remained, like amber itself, a problem\nto the learned. Though the word ambergris is but the French compound\nfor grey amber, yet the", "labels": {"50": 26, "100": 66, "250": 198, "500": 156, "1000": 602, "2000": 1540}}, {"id": 6036, "position": 6036, "text": "word ambergris is but the French compound\nfor grey amber, yet the two substances are quite distinct. For amber,\nthough at times found on the sea-coast, is also dug up in some far\ninland soils, whereas ambergris is never", "labels": {"50": 3, "100": 70, "250": 46, "500": 197, "1000": 571, "2000": 307}}, {"id": 6037, "position": 6037, "text": "also dug up in some far\ninland soils, whereas ambergris is never found except upon the sea.\nBesides, amber is a hard, transparent, brittle, odorless substance,\nused for mouth-pieces to pipes, for beads and ornaments; but", "labels": {"50": 42, "100": 59, "250": 46, "500": 197, "1000": 976, "2000": 307}}, {"id": 6038, "position": 6038, "text": ",\nused for mouth-pieces to pipes, for beads and ornaments; but ambergris\nis soft, waxy, and so highly fragrant and spicy, that it is largely\nused in perfumery, in pastiles, precious candles, hair", "labels": {"50": 42, "100": 59, "250": 46, "500": 260, "1000": 976, "2000": 1333}}, {"id": 6039, "position": 6039, "text": "largely\nused in perfumery, in pastiles, precious candles, hair-powders, and\npomatum. The Turks use it in cooking, and also carry it to Mecca, for\nthe same purpose that frankincense is carried to", "labels": {"50": 32, "100": 0, "250": 233, "500": 55, "1000": 501, "2000": 1800}}, {"id": 6040, "position": 6040, "text": "to Mecca, for\nthe same purpose that frankincense is carried to St. Peter’s in Rome.\nSome wine merchants drop a few grains into claret, to flavor it.\n\nWho would think, then, that such fine ladies and gentlemen", "labels": {"50": 42, "100": 46, "250": 142, "500": 451, "1000": 210, "2000": 307}}, {"id": 6041, "position": 6041, "text": "flavor it.\n\nWho would think, then, that such fine ladies and gentlemen should\nregale themselves with an essence found in the inglorious bowels of a\nsick whale! Yet so it is. By some, ambergris is supposed to be", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6042, "position": 6042, "text": "Yet so it is. By some, ambergris is supposed to be the\ncause, and by others the effect, of the dyspepsia in the whale. How to\ncure such a dyspepsia it were hard to say", "labels": {"50": 42, "100": 70, "250": 155, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6043, "position": 6043, "text": "How to\ncure such a dyspepsia it were hard to say, unless by administering\nthree or four boat loads of Brandreth’s pills, and then running out of\nharm’s way, as laborers do in blasting rocks.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 9, "2000": 472}}, {"id": 6044, "position": 6044, "text": "out of\nharm’s way, as laborers do in blasting rocks.\n\nI have forgotten to say that there were found in this ambergris,\ncertain hard, round, bony plates, which at first Stubb thought might be\nsailors’ trowsers", "labels": {"50": 45, "100": 64, "250": 234, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6045, "position": 6045, "text": "plates, which at first Stubb thought might be\nsailors’ trowsers buttons; but it afterwards turned out that they were\nnothing more than pieces of small squid bones embalmed in that manner.\n\nNow that the incorruption of this most", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6046, "position": 6046, "text": "med in that manner.\n\nNow that the incorruption of this most fragrant ambergris should be\nfound in the heart of such decay; is this nothing? Bethink thee of that\nsaying of St", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 6047, "position": 6047, "text": "ink thee of that\nsaying of St. Paul in Corinthians, about corruption and incorruption;\nhow that we are sown in dishonor, but raised in glory. And likewise\ncall to mind that saying of Paracelsus", "labels": {"50": 31, "100": 75, "250": 106, "500": 333, "1000": 344, "2000": 1986}}, {"id": 6048, "position": 6048, "text": "raised in glory. And likewise\ncall to mind that saying of Paracelsus about what it is that maketh the\nbest musk. Also forget not the strange fact that of all things of\nill-savor, Cologne-water, in its ru", "labels": {"50": 9, "100": 26, "250": 30, "500": 307, "1000": 117, "2000": 1374}}, {"id": 6049, "position": 6049, "text": "all things of\nill-savor, Cologne-water, in its rudimental manufacturing stages, is\nthe worst.\n\nI should like to conclude the chapter with the above appeal, but\ncannot, owing to my anxiety to repel a charge often made", "labels": {"50": 31, "100": 7, "250": 90, "500": 224, "1000": 387, "2000": 1107}}, {"id": 6050, "position": 6050, "text": ", but\ncannot, owing to my anxiety to repel a charge often made against\nwhalemen, and which, in the estimation of some already biased minds,\nmight be considered as indirectly substantiated by what has been said\nof the Frenchman’s", "labels": {"50": 45, "100": 29, "250": 34, "500": 72, "1000": 622, "2000": 1620}}, {"id": 6051, "position": 6051, "text": "indirectly substantiated by what has been said\nof the Frenchman’s two whales. Elsewhere in this volume the slanderous\naspersion has been disproved, that the vocation of whaling is\nthroughout a slatternly, un", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6052, "position": 6052, "text": "that the vocation of whaling is\nthroughout a slatternly, untidy business. But there is another thing to\nrebut. They hint that all whales always smell bad. Now how did this\nodious stigma originate?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6053, "position": 6053, "text": "smell bad. Now how did this\nodious stigma originate?\n\nI opine, that it is plainly traceable to the first arrival of the\nGreenland whaling ships in London, more than two centuries ago. Because\nthose whalemen did not then, and do", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6054, "position": 6054, "text": "than two centuries ago. Because\nthose whalemen did not then, and do not now, try out their oil at sea\nas the Southern ships have always done; but cutting up the fresh\nblubber in small bits, thrust it through the bung holes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6055, "position": 6055, "text": "the fresh\nblubber in small bits, thrust it through the bung holes of large casks,\nand carry it home in that manner; the shortness of the season in those\nIcy Seas, and the sudden and violent storms to which they are exposed", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 6056, "position": 6056, "text": "those\nIcy Seas, and the sudden and violent storms to which they are exposed,\nforbidding any other course. The consequence is, that upon breaking\ninto the hold, and unloading one of these whale cemeteries, in the\nGreenland dock, a savor", "labels": {"50": 45, "100": 29, "250": 138, "500": 48, "1000": 327, "2000": 1620}}, {"id": 6057, "position": 6057, "text": "loading one of these whale cemeteries, in the\nGreenland dock, a savor is given forth somewhat similar to that arising\nfrom excavating an old city grave-yard, for the foundations of a\nLying-in Hospital.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6058, "position": 6058, "text": "the foundations of a\nLying-in Hospital.\n\nI partly surmise also, that this wicked charge against whalers may be\nlikewise imputed to the existence on the coast of Greenland, in former\ntimes, of a Dutch village called Schmerenburgh", "labels": {"50": 45, "100": 29, "250": 34, "500": 306, "1000": 9, "2000": 682}}, {"id": 6059, "position": 6059, "text": ", in former\ntimes, of a Dutch village called Schmerenburgh or Smeerenberg, which\nlatter name is the one used by the learned Fogo Von Slack, in his great\nwork on Smells, a text-book on that subject", "labels": {"50": 3, "100": 70, "250": 46, "500": 197, "1000": 656, "2000": 1548}}, {"id": 6060, "position": 6060, "text": "in his great\nwork on Smells, a text-book on that subject. As its name imports\n(smeer, fat; berg, to put up), this village was founded in order to\nafford a place for the blubber of the Dutch whale", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 9, "2000": 1620}}, {"id": 6061, "position": 6061, "text": "founded in order to\nafford a place for the blubber of the Dutch whale fleet to be tried\nout, without being taken home to Holland for that purpose. It was a\ncollection of furnaces, fat-kettles, and oil sheds; and when", "labels": {"50": 45, "100": 29, "250": 34, "500": 48, "1000": 997, "2000": 207}}, {"id": 6062, "position": 6062, "text": "of furnaces, fat-kettles, and oil sheds; and when the works\nwere in full operation certainly gave forth no very pleasant savor. But\nall this is quite different with a South Sea Sperm Whaler; which in a\nvoyage of four", "labels": {"50": 45, "100": 29, "250": 138, "500": 48, "1000": 723, "2000": 489}}, {"id": 6063, "position": 6063, "text": "different with a South Sea Sperm Whaler; which in a\nvoyage of four years perhaps, after completely filling her hold with\noil, does not, perhaps, consume fifty days in the business of boiling\nout; and in the state that it is casked", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6064, "position": 6064, "text": "the business of boiling\nout; and in the state that it is casked, the oil is nearly scentless.\nThe truth is, that living or dead, if but decently treated, whales as a\nspecies are by no means creatures of ill odor", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6065, "position": 6065, "text": "ly treated, whales as a\nspecies are by no means creatures of ill odor; nor can whalemen be\nrecognised, as the people of the middle ages affected to detect a Jew\nin the company, by the nose", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6066, "position": 6066, "text": "in the company, by the nose. Nor indeed can the whale possibly be\notherwise than fragrant, when, as a general thing, he enjoys such high\nhealth; taking abundance of exercise; always out of doors; though, it\nis true, seldom", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6067, "position": 6067, "text": "of exercise; always out of doors; though, it\nis true, seldom in the open air. I say, that the motion of a Sperm\nWhale’s flukes above water dispenses a perfume, as when a musk-scented", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6068, "position": 6068, "text": "water dispenses a perfume, as when a musk-scented\nlady rustles her dress in a warm parlor. What then shall I liken the\nSperm Whale to for fragrance, considering his magnitude? Must it not be\nto that famous elephant", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6069, "position": 6069, "text": "for fragrance, considering his magnitude? Must it not be\nto that famous elephant, with jewelled tusks, and redolent with myrrh,\nwhich was led out of an Indian town to do honor to Alexander the Great?\n\n\nCHAPTER 93", "labels": {"50": 9, "100": 75, "250": 216, "500": 289, "1000": 616, "2000": 1175}}, {"id": 6070, "position": 6070, "text": "out of an Indian town to do honor to Alexander the Great?\n\n\nCHAPTER 93. The Castaway.\n\nIt was but some few days after encountering the Frenchman, that a most\nsignificant event befell the most insignificant of the Pequod’s crew", "labels": {"50": 45, "100": 38, "250": 65, "500": 239, "1000": 532, "2000": 156}}, {"id": 6071, "position": 6071, "text": "significant event befell the most insignificant of the Pequod’s crew;\nan event most lamentable; and which ended in providing the sometimes\nmadly merry and predestinated craft with a living and ever accompanying\nprophecy of whatever shattered sequel might", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6072, "position": 6072, "text": "tinated craft with a living and ever accompanying\nprophecy of whatever shattered sequel might prove her own.\n\nNow, in the whale ship, it is not every one that goes in the boats.\nSome few hands are reserved called ship-keepers, whose province it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6073, "position": 6073, "text": "boats.\nSome few hands are reserved called ship-keepers, whose province it is\nto work the vessel while the boats are pursuing the whale. As a general\nthing, these ship-keepers are as hardy fellows as the men comprising\nthe boats’ crews", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6074, "position": 6074, "text": "-keepers are as hardy fellows as the men comprising\nthe boats’ crews. But if there happen to be an unduly slender, clumsy,\nor timorous wight in the ship, that wight is certain to be made a\nship-keeper", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 887}}, {"id": 6075, "position": 6075, "text": "ship, that wight is certain to be made a\nship-keeper. It was so in the Pequod with the little negro Pippin by\nnick-name, Pip by abbreviation. Poor Pip! ye have heard of him before;\nye must remember", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 6076, "position": 6076, "text": "abbreviation. Poor Pip! ye have heard of him before;\nye must remember his tambourine on that dramatic midnight, so\ngloomy-jolly.\n\nIn outer aspect, Pip and Dough-Boy made a match, like a black pony and\na white", "labels": {"50": 41, "100": 47, "250": 149, "500": 20, "1000": 175, "2000": 1867}}, {"id": 6077, "position": 6077, "text": "and Dough-Boy made a match, like a black pony and\na white one, of equal developments, though of dissimilar colour, driven\nin one eccentric span. But while hapless Dough-Boy was by nature dull\nand torpid", "labels": {"50": 23, "100": 86, "250": 145, "500": 180, "1000": 680, "2000": 1607}}, {"id": 6078, "position": 6078, "text": "But while hapless Dough-Boy was by nature dull\nand torpid in his intellects, Pip, though over tender-hearted, was at\nbottom very bright, with that pleasant, genial, jolly brightness\npeculiar to his tribe; a tribe", "labels": {"50": 37, "100": 12, "250": 16, "500": 178, "1000": 197, "2000": 110}}, {"id": 6079, "position": 6079, "text": "that pleasant, genial, jolly brightness\npeculiar to his tribe; a tribe, which ever enjoy all holidays and\nfestivities with finer, freer relish than any other race. For blacks,\nthe year’s calendar should show naught but three hundred", "labels": {"50": 31, "100": 7, "250": 158, "500": 279, "1000": 321, "2000": 27}}, {"id": 6080, "position": 6080, "text": "For blacks,\nthe year’s calendar should show naught but three hundred and sixty-five\nFourth of Julys and New Year’s Days. Nor smile so, while I write that\nthis little black was brilliant, for even blackness has its br", "labels": {"50": 31, "100": 7, "250": 91, "500": 453, "1000": 203, "2000": 1107}}, {"id": 6081, "position": 6081, "text": "I write that\nthis little black was brilliant, for even blackness has its brilliancy;\nbehold yon lustrous ebony, panelled in king’s cabinets. But Pip loved\nlife, and all life’s peaceable securities; so that", "labels": {"50": 23, "100": 68, "250": 193, "500": 202, "1000": 858, "2000": 110}}, {"id": 6082, "position": 6082, "text": "Pip loved\nlife, and all life’s peaceable securities; so that the panic-striking\nbusiness in which he had somehow unaccountably become entrapped, had\nmost sadly blurred his brightness; though, as ere long will be seen", "labels": {"50": 17, "100": 68, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 6083, "position": 6083, "text": "most sadly blurred his brightness; though, as ere long will be seen,\nwhat was thus temporarily subdued in him, in the end was destined to be\nluridly illumined by strange wild fires, that fictitiously showed him\noff to ten", "labels": {"50": 45, "100": 17, "250": 160, "500": 358, "1000": 485, "2000": 1002}}, {"id": 6084, "position": 6084, "text": "umined by strange wild fires, that fictitiously showed him\noff to ten times the natural lustre with which in his native Tolland\nCounty in Connecticut, he had once enlivened many a fiddler’s frolic on\nthe green;", "labels": {"50": 44, "100": 38, "250": 53, "500": 230, "1000": 995, "2000": 47}}, {"id": 6085, "position": 6085, "text": "livened many a fiddler’s frolic on\nthe green; and at melodious even-tide, with his gay ha-ha! had turned\nthe round horizon into one star-belled tambourine", "labels": {"50": 16, "100": 73, "250": 120, "500": 406, "1000": 779, "2000": 16}}, {"id": 6086, "position": 6086, "text": "horizon into one star-belled tambourine. So, though in the\nclear air of day, suspended against a blue-veined neck, the\npure-watered diamond drop will healthful glow; yet, when the cunning\njeweller would show", "labels": {"50": 16, "100": 20, "250": 49, "500": 498, "1000": 50, "2000": 523}}, {"id": 6087, "position": 6087, "text": "drop will healthful glow; yet, when the cunning\njeweller would show you the diamond in its most impressive lustre, he\nlays it against a gloomy ground, and then lights it up, not by the sun,\nbut by some unnatural gases", "labels": {"50": 16, "100": 73, "250": 205, "500": 154, "1000": 873, "2000": 85}}, {"id": 6088, "position": 6088, "text": "then lights it up, not by the sun,\nbut by some unnatural gases. Then come out those fiery effulgences,\ninfernally superb; then the evil-blazing diamond, once the divinest\nsymbol of the crystal skies, looks", "labels": {"50": 16, "100": 73, "250": 26, "500": 406, "1000": 779, "2000": 1860}}, {"id": 6089, "position": 6089, "text": "-blazing diamond, once the divinest\nsymbol of the crystal skies, looks like some crown-jewel stolen from\nthe King of Hell. But let us to the story.\n\nIt came to pass, that in the ambergris affair Stubb’s", "labels": {"50": 31, "100": 16, "250": 13, "500": 414, "1000": 581, "2000": 1828}}, {"id": 6090, "position": 6090, "text": "came to pass, that in the ambergris affair Stubb’s after-oarsman\nchanced so to sprain his hand, as for a time to become quite maimed;\nand, temporarily, Pip was put into his place.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6091, "position": 6091, "text": "quite maimed;\nand, temporarily, Pip was put into his place.\n\nThe first time Stubb lowered with him, Pip evinced much nervousness;\nbut happily, for that time, escaped close contact with the whale; and\ntherefore came off", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6092, "position": 6092, "text": "for that time, escaped close contact with the whale; and\ntherefore came off not altogether discreditably; though Stubb observing\nhim, took care, afterwards, to exhort him to cherish his courageousness\nto the utmost, for he might", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6093, "position": 6093, "text": "hort him to cherish his courageousness\nto the utmost, for he might often find it needful.\n\nNow upon the second lowering, the boat paddled upon the whale; and as\nthe fish received the darted iron, it gave its customary rap,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6094, "position": 6094, "text": "and as\nthe fish received the darted iron, it gave its customary rap, which\nhappened, in this instance, to be right under poor Pip’s seat. The\ninvoluntary consternation of the moment caused him to leap, paddle in\nhand, out", "labels": {"50": 37, "100": 64, "250": 163, "500": 363, "1000": 692, "2000": 778}}, {"id": 6095, "position": 6095, "text": "sternation of the moment caused him to leap, paddle in\nhand, out of the boat; and in such a way, that part of the slack whale\nline coming against his chest, he breasted it overboard with him, so as\nto become en", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6096, "position": 6096, "text": "chest, he breasted it overboard with him, so as\nto become entangled in it, when at last plumping into the water. That\ninstant the stricken whale started on a fierce run, the line swiftly\nstraightened; and presto! poor Pip", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6097, "position": 6097, "text": "a fierce run, the line swiftly\nstraightened; and presto! poor Pip came all foaming up to the chocks of\nthe boat, remorselessly dragged there by the line, which had taken\nseveral turns around his chest and neck.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 6098, "position": 6098, "text": ", which had taken\nseveral turns around his chest and neck.\n\nTashtego stood in the bows. He was full of the fire of the hunt. He\nhated Pip for a poltroon. Snatching the boat-knife from its sheath,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 6099, "position": 6099, "text": "a poltroon. Snatching the boat-knife from its sheath, he\nsuspended its sharp edge over the line, and turning towards Stubb,\nexclaimed interrogatively, “Cut?” Meantime Pip’s blue, choked face\nplainly looked", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 6100, "position": 6100, "text": ", “Cut?” Meantime Pip’s blue, choked face\nplainly looked, Do, for God’s sake! All passed in a flash. In less than\nhalf a minute, this entire thing happened.", "labels": {"50": 22, "100": 77, "250": 19, "500": 3, "1000": 959, "2000": 1066}}, {"id": 6101, "position": 6101, "text": "minute, this entire thing happened.\n\n“Damn him, cut!” roared Stubb; and so the whale was lost and Pip was\nsaved.\n\nSo soon as he recovered himself, the poor little negro was assailed by\nyells and execrations from", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6102, "position": 6102, "text": ", the poor little negro was assailed by\nyells and execrations from the crew. Tranquilly permitting these\nirregular cursings to evaporate, Stubb then in a plain, business-like,\nbut still half humorous manner, cursed Pip", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 6103, "position": 6103, "text": "a plain, business-like,\nbut still half humorous manner, cursed Pip officially; and that done,\nunofficially gave him much wholesome advice. The substance was, Never\njump from a boat, Pip, except—but all the rest was indefinite,", "labels": {"50": 23, "100": 88, "250": 193, "500": 202, "1000": 858, "2000": 110}}, {"id": 6104, "position": 6104, "text": "from a boat, Pip, except—but all the rest was indefinite, as the\nsoundest advice ever is. Now, in general, _Stick to the boat_, is your\ntrue motto in whaling; but cases will sometimes happen when _Leap", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6105, "position": 6105, "text": "is your\ntrue motto in whaling; but cases will sometimes happen when _Leap from\nthe boat_, is still better. Moreover, as if perceiving at last that if\nhe should give undiluted conscientious advice to Pip, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6106, "position": 6106, "text": "he should give undiluted conscientious advice to Pip, he would be\nleaving him too wide a margin to jump in for the future; Stubb suddenly\ndropped all advice, and concluded with a peremptory command, “Stick to\nthe", "labels": {"50": 23, "100": 88, "250": 70, "500": 178, "1000": 962, "2000": 110}}, {"id": 6107, "position": 6107, "text": "advice, and concluded with a peremptory command, “Stick to\nthe boat, Pip, or by the Lord, I won’t pick you up if you jump; mind\nthat. We can’t afford to lose whales by the likes of", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 6108, "position": 6108, "text": "mind\nthat. We can’t afford to lose whales by the likes of you; a whale would\nsell for thirty times what you would, Pip, in Alabama. Bear that in\nmind, and don’t jump any more.” Hereby perhaps", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6109, "position": 6109, "text": "in\nmind, and don’t jump any more.” Hereby perhaps Stubb indirectly hinted,\nthat though man loved his fellow, yet man is a money-making animal,\nwhich propensity too often interferes with his benevolence", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6110, "position": 6110, "text": ",\nwhich propensity too often interferes with his benevolence.\n\nBut we are all in the hands of the Gods; and Pip jumped again. It was\nunder very similar circumstances to the first performance; but this\ntime he did not breast", "labels": {"50": 17, "100": 16, "250": 151, "500": 71, "1000": 608, "2000": 131}}, {"id": 6111, "position": 6111, "text": "very similar circumstances to the first performance; but this\ntime he did not breast out the line; and hence, when the whale started\nto run, Pip was left behind on the sea, like a hurried traveller’s\ntrunk", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6112, "position": 6112, "text": "sea, like a hurried traveller’s\ntrunk. Alas! Stubb was but too true to his word. It was a beautiful,\nbounteous, blue day; the spangled sea calm and cool, and flatly\nstretching away, all round", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6113, "position": 6113, "text": "the spangled sea calm and cool, and flatly\nstretching away, all round, to the horizon, like gold-beater’s skin\nhammered out to the extremest. Bobbing up and down in that sea, Pip’s\nebon head", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 6114, "position": 6114, "text": "Bobbing up and down in that sea, Pip’s\nebon head showed like a head of cloves. No boat-knife was lifted when\nhe fell so rapidly astern. Stubb’s inexorable back was turned upon", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 967}}, {"id": 6115, "position": 6115, "text": "astern. Stubb’s inexorable back was turned upon him;\nand the whale was winged. In three minutes, a whole mile of shoreless\nocean was between Pip and Stubb. Out from the centre of the sea, poor", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6116, "position": 6116, "text": "between Pip and Stubb. Out from the centre of the sea, poor\nPip turned his crisp, curling, black head to the sun, another lonely\ncastaway, though the loftiest and the brightest.", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 531, "2000": 967}}, {"id": 6117, "position": 6117, "text": "loftiest and the brightest.\n\nNow, in calm weather, to swim in the open ocean is as easy to the\npractised swimmer as to ride in a spring-carriage ashore. But the awful\nlonesomeness is intolerable", "labels": {"50": 48, "100": 20, "250": 213, "500": 334, "1000": 275, "2000": 1710}}, {"id": 6118, "position": 6118, "text": "But the awful\nlonesomeness is intolerable. The intense concentration of self in the\nmiddle of such a heartless immensity, my God! who can tell it? Mark,\nhow when sailors in a dead calm bathe in the open", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 887}}, {"id": 6119, "position": 6119, "text": "? Mark,\nhow when sailors in a dead calm bathe in the open sea—mark how closely\nthey hug their ship and only coast along her sides.\n\nBut had Stubb really abandoned the poor little negro to his fate? No;\nhe did not", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6120, "position": 6120, "text": "really abandoned the poor little negro to his fate? No;\nhe did not mean to, at least. Because there were two boats in his wake,\nand he supposed, no doubt, that they would of course come up to Pip\nvery quickly, and", "labels": {"50": 37, "100": 11, "250": 163, "500": 432, "1000": 251, "2000": 1977}}, {"id": 6121, "position": 6121, "text": "doubt, that they would of course come up to Pip\nvery quickly, and pick him up; though, indeed, such considerations\ntowards oarsmen jeopardized through their own timidity, is not always\nmanifested by the hunters in all similar", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 692, "2000": 778}}, {"id": 6122, "position": 6122, "text": "own timidity, is not always\nmanifested by the hunters in all similar instances; and such instances\nnot unfrequently occur; almost invariably in the fishery, a coward, so\ncalled, is marked with the same ruthless detestation peculiar", "labels": {"50": 12, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 6123, "position": 6123, "text": "coward, so\ncalled, is marked with the same ruthless detestation peculiar to\nmilitary navies and armies.\n\nBut it so happened, that those boats, without seeing Pip, suddenly\nspying whales close to them on one side, turned, and gave chase", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6124, "position": 6124, "text": "suddenly\nspying whales close to them on one side, turned, and gave chase; and\nStubb’s boat was now so far away, and he and all his crew so intent\nupon his fish, that Pip’s ringed horizon began to expand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6125, "position": 6125, "text": "intent\nupon his fish, that Pip’s ringed horizon began to expand around him\nmiserably. By the merest chance the ship itself at last rescued him;\nbut from that hour the little negro went about the deck an idiot; such,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 6126, "position": 6126, "text": "from that hour the little negro went about the deck an idiot; such,\nat least, they said he was. The sea had jeeringly kept his finite body\nup, but drowned the infinite of his soul. Not drowned entirely, though", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 477, "2000": 958}}, {"id": 6127, "position": 6127, "text": "but drowned the infinite of his soul. Not drowned entirely, though.\nRather carried down alive to wondrous depths, where strange shapes of\nthe unwarped primal world glided to and fro before his passive eyes;\nand the miser-mer", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 437, "2000": 193}}, {"id": 6128, "position": 6128, "text": "to and fro before his passive eyes;\nand the miser-merman, Wisdom, revealed his hoarded heaps; and among the\njoyous, heartless, ever-juvenile eternities, Pip saw the multitudinous,", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 437, "2000": 1859}}, {"id": 6129, "position": 6129, "text": "ever-juvenile eternities, Pip saw the multitudinous,\nGod-omnipresent, coral insects, that out of the firmament of waters\nheaved the colossal orbs. He saw God’s foot upon the treadle of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6130, "position": 6130, "text": "colossal orbs. He saw God’s foot upon the treadle of the\nloom, and spoke it; and therefore his shipmates called him mad. So\nman’s insanity is heaven’s sense; and wandering from all mortal reason,", "labels": {"50": 9, "100": 26, "250": 133, "500": 414, "1000": 437, "2000": 16}}, {"id": 6131, "position": 6131, "text": "s insanity is heaven’s sense; and wandering from all mortal reason,\nman comes at last to that celestial thought, which, to reason, is\nabsurd and frantic; and weal or woe, feels then uncompromised,\nindifferent", "labels": {"50": 10, "100": 71, "250": 13, "500": 289, "1000": 368, "2000": 1555}}, {"id": 6132, "position": 6132, "text": "weal or woe, feels then uncompromised,\nindifferent as his God.\n\nFor the rest, blame not Stubb too hardly. The thing is common in that\nfishery; and in the sequel of the narrative, it will then be", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6133, "position": 6133, "text": "that\nfishery; and in the sequel of the narrative, it will then be seen what\nlike abandonment befell myself.\n\n\nCHAPTER 94. A Squeeze of the Hand.\n\nThat whale of Stubb’s, so dearly purchased, was duly brought to the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6134, "position": 6134, "text": "Stubb’s, so dearly purchased, was duly brought to the\nPequod’s side, where all those cutting and hoisting operations\npreviously detailed, were regularly gone through, even to the baling of\nthe Heidelburg", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6135, "position": 6135, "text": "regularly gone through, even to the baling of\nthe Heidelburgh Tun, or Case.\n\nWhile some were occupied with this latter duty, others were employed in\ndragging away the larger tubs, so soon as filled with the sperm; and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6136, "position": 6136, "text": "away the larger tubs, so soon as filled with the sperm; and\nwhen the proper time arrived, this same sperm was carefully manipulated\nere going to the try-works, of which anon.", "labels": {"50": 3, "100": 24, "250": 155, "500": 403, "1000": 109, "2000": 670}}, {"id": 6137, "position": 6137, "text": ", of which anon.\n\nIt had cooled and crystallized to such a degree, that when, with\nseveral others, I sat down before a large Constantine’s bath of it, I\nfound it strangely concreted into lumps, here and there", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 930, "2000": 937}}, {"id": 6138, "position": 6138, "text": "it, I\nfound it strangely concreted into lumps, here and there rolling about\nin the liquid part. It was our business to squeeze these lumps back\ninto fluid. A sweet and unctuous duty! No wonder that in old times this", "labels": {"50": 25, "100": 63, "250": 152, "500": 206, "1000": 678, "2000": 694}}, {"id": 6139, "position": 6139, "text": "A sweet and unctuous duty! No wonder that in old times this\nsperm was such a favourite cosmetic. Such a clearer! such a sweetener!\nsuch a softener! such a delicious molifier! After having my hands in it", "labels": {"50": 26, "100": 75, "250": 106, "500": 333, "1000": 344, "2000": 1475}}, {"id": 6140, "position": 6140, "text": "! such a delicious molifier! After having my hands in it\nfor only a few minutes, my fingers felt like eels, and began, as it\nwere, to serpentine and spiralise.", "labels": {"50": 42, "100": 59, "250": 10, "500": 16, "1000": 364, "2000": 1592}}, {"id": 6141, "position": 6141, "text": "serpentine and spiralise.\n\nAs I sat there at my ease, cross-legged on the deck; after the bitter\nexertion at the windlass; under a blue tranquil sky; the ship under\nindolent sail, and gliding so serene", "labels": {"50": 25, "100": 5, "250": 136, "500": 388, "1000": 272, "2000": 1765}}, {"id": 6142, "position": 6142, "text": "tranquil sky; the ship under\nindolent sail, and gliding so serenely along; as I bathed my hands\namong those soft, gentle globules of infiltrated tissues, woven almost\nwithin the hour; as they richly broke to my fingers", "labels": {"50": 16, "100": 20, "250": 132, "500": 388, "1000": 727, "2000": 887}}, {"id": 6143, "position": 6143, "text": "tissues, woven almost\nwithin the hour; as they richly broke to my fingers, and discharged all\ntheir opulence, like fully ripe grapes their wine; as I snuffed up that\nuncontaminated aroma,—literally and truly, like", "labels": {"50": 9, "100": 26, "250": 132, "500": 412, "1000": 27, "2000": 913}}, {"id": 6144, "position": 6144, "text": "ffed up that\nuncontaminated aroma,—literally and truly, like the smell of spring\nviolets; I declare to you, that for the time I lived as in a musky\nmeadow; I forgot all about our horrible oath; in that", "labels": {"50": 16, "100": 73, "250": 15, "500": 126, "1000": 944, "2000": 970}}, {"id": 6145, "position": 6145, "text": "a musky\nmeadow; I forgot all about our horrible oath; in that inexpressible\nsperm, I washed my hands and my heart of it; I almost began to credit\nthe old Paracelsan superstition that sperm is of rare virtue", "labels": {"50": 3, "100": 70, "250": 155, "500": 309, "1000": 294, "2000": 416}}, {"id": 6146, "position": 6146, "text": "credit\nthe old Paracelsan superstition that sperm is of rare virtue in\nallaying the heat of anger; while bathing in that bath, I felt divinely\nfree from all ill-will, or petulance, or malice, of any", "labels": {"50": 31, "100": 61, "250": 132, "500": 495, "1000": 27, "2000": 932}}, {"id": 6147, "position": 6147, "text": "all ill-will, or petulance, or malice, of any sort\nwhatsoever.\n\nSqueeze! squeeze! squeeze! all the morning long; I squeezed that sperm\ntill I myself almost melted into it; I squeezed that sperm till a\nstrange sort of", "labels": {"50": 8, "100": 14, "250": 81, "500": 374, "1000": 318, "2000": 1031}}, {"id": 6148, "position": 6148, "text": "myself almost melted into it; I squeezed that sperm till a\nstrange sort of insanity came over me; and I found myself unwittingly\nsqueezing my co-laborers’ hands in it, mistaking their hands for the\ngentle globules", "labels": {"50": 25, "100": 5, "250": 132, "500": 495, "1000": 553, "2000": 932}}, {"id": 6149, "position": 6149, "text": "in it, mistaking their hands for the\ngentle globules. Such an abounding, affectionate, friendly, loving\nfeeling did this avocation beget; that at last I was continually\nsqueezing their hands, and looking up into their", "labels": {"50": 48, "100": 20, "250": 90, "500": 126, "1000": 727, "2000": 1107}}, {"id": 6150, "position": 6150, "text": "that at last I was continually\nsqueezing their hands, and looking up into their eyes sentimentally; as\nmuch as to say,—Oh! my dear fellow beings, why should we longer cherish\nany social acerbities, or know the slightest ill", "labels": {"50": 31, "100": 28, "250": 132, "500": 318, "1000": 409, "2000": 381}}, {"id": 6151, "position": 6151, "text": "we longer cherish\nany social acerbities, or know the slightest ill-humor or envy! Come;\nlet us squeeze hands all round; nay, let us all squeeze ourselves into\neach other; let us squeeze ourselves universally into the very milk and", "labels": {"50": 31, "100": 7, "250": 193, "500": 19, "1000": 499, "2000": 761}}, {"id": 6152, "position": 6152, "text": "ourselves into\neach other; let us squeeze ourselves universally into the very milk and\nsperm of kindness.\n\nWould that I could keep squeezing that sperm for ever! For now, since\nby many prolonged, repeated experiences, I have perceived that in all\ncases man must", "labels": {"50": 10, "100": 75, "250": 13, "500": 236, "1000": 27, "2000": 1050}}, {"id": 6153, "position": 6153, "text": "many prolonged, repeated experiences, I have perceived that in all\ncases man must eventually lower, or at least shift, his conceit of\nattainable felicity; not placing it anywhere in the intellect or the\nfancy; but in the wife, the heart", "labels": {"50": 20, "100": 56, "250": 101, "500": 450, "1000": 121, "2000": 1169}}, {"id": 6154, "position": 6154, "text": "anywhere in the intellect or the\nfancy; but in the wife, the heart, the bed, the table, the saddle, the\nfireside, the country; now that I have perceived all this, I am ready\nto squeeze case eternally", "labels": {"50": 31, "100": 75, "250": 106, "500": 450, "1000": 27, "2000": 349}}, {"id": 6155, "position": 6155, "text": "have perceived all this, I am ready\nto squeeze case eternally. In thoughts of the visions of the night, I\nsaw long rows of angels in paradise, each with his hands in a jar of\nspermaceti.", "labels": {"50": 31, "100": 24, "250": 30, "500": 475, "1000": 345, "2000": 39}}, {"id": 6156, "position": 6156, "text": "hands in a jar of\nspermaceti.\n\nNow, while discoursing of sperm, it behooves to speak of other things\nakin to it, in the business of preparing the sperm whale for the\ntry-works.", "labels": {"50": 3, "100": 24, "250": 155, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6157, "position": 6157, "text": "of preparing the sperm whale for the\ntry-works.\n\nFirst comes white-horse, so called, which is obtained from the tapering\npart of the fish, and also from the thicker portions of his flukes", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6158, "position": 6158, "text": "the thicker portions of his flukes. It\nis tough with congealed tendons—a wad of muscle—but still contains some\noil. After being severed from the whale, the white-horse is first cut\ninto portable oblongs er", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6159, "position": 6159, "text": "whale, the white-horse is first cut\ninto portable oblongs ere going to the mincer. They look much like\nblocks of Berkshire marble.\n\nPlum-pudding is the term bestowed upon certain fragmentary parts of the\nwhale’s flesh,", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6160, "position": 6160, "text": "the term bestowed upon certain fragmentary parts of the\nwhale’s flesh, here and there adhering to the blanket of blubber, and\noften participating to a considerable degree in its unctuousness. It is\na most refreshing, convivial", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6161, "position": 6161, "text": "its unctuousness. It is\na most refreshing, convivial, beautiful object to behold. As its name\nimports, it is of an exceedingly rich, mottled tint, with a bestreaked\nsnowy and golden ground,", "labels": {"50": 42, "100": 46, "250": 142, "500": 451, "1000": 210, "2000": 657}}, {"id": 6162, "position": 6162, "text": "ttled tint, with a bestreaked\nsnowy and golden ground, dotted with spots of the deepest crimson and\npurple. It is plums of rubies, in pictures of citron. Spite of reason,\nit is hard to keep yourself from", "labels": {"50": 48, "100": 20, "250": 213, "500": 334, "1000": 275, "2000": 1710}}, {"id": 6163, "position": 6163, "text": "of citron. Spite of reason,\nit is hard to keep yourself from eating it. I confess, that once I\nstole behind the foremast to try it. It tasted something as I should\nconceive a royal cutlet from the thigh", "labels": {"50": 42, "100": 59, "250": 10, "500": 16, "1000": 364, "2000": 1592}}, {"id": 6164, "position": 6164, "text": "tasted something as I should\nconceive a royal cutlet from the thigh of Louis le Gros might have\ntasted, supposing him to have been killed the first day after the\nvenison season, and that particular venison season contemporary", "labels": {"50": 12, "100": 93, "250": 97, "500": 435, "1000": 718, "2000": 443}}, {"id": 6165, "position": 6165, "text": "after the\nvenison season, and that particular venison season contemporary with an\nunusually fine vintage of the vineyards of Champagne.\n\nThere is another substance, and a very singular one, which turns up in\nthe course of this business, but which I", "labels": {"50": 42, "100": 7, "250": 159, "500": 16, "1000": 364, "2000": 1333}}, {"id": 6166, "position": 6166, "text": "one, which turns up in\nthe course of this business, but which I feel it to be very puzzling\nadequately to describe. It is called slobgollion; an appellation\noriginal with the whalemen, and even so is the nature", "labels": {"50": 3, "100": 24, "250": 131, "500": 288, "1000": 505, "2000": 447}}, {"id": 6167, "position": 6167, "text": "appellation\noriginal with the whalemen, and even so is the nature of the substance.\nIt is an ineffably oozy, stringy affair, most frequently found in the\ntubs of sperm, after a prolonged squeezing, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6168, "position": 6168, "text": "frequently found in the\ntubs of sperm, after a prolonged squeezing, and subsequent decanting. I\nhold it to be the wondrously thin, ruptured membranes of the case,\ncoalescing.", "labels": {"50": 3, "100": 46, "250": 167, "500": 495, "1000": 553, "2000": 416}}, {"id": 6169, "position": 6169, "text": "of the case,\ncoalescing.\n\nGurry, so called, is a term properly belonging to right whalemen, but\nsometimes incidentally used by the sperm fishermen. It designates the\ndark, glutinous substance which is scraped off the", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6170, "position": 6170, "text": "designates the\ndark, glutinous substance which is scraped off the back of the\nGreenland or right whale, and much of which covers the decks of those\ninferior souls who hunt that ignoble Leviathan.\n\nNippers", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6171, "position": 6171, "text": "hunt that ignoble Leviathan.\n\nNippers. Strictly this word is not indigenous to the whale’s\nvocabulary. But as applied by whalemen, it becomes so. A whaleman’s\nnipper is a short firm strip of tend", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6172, "position": 6172, "text": ". A whaleman’s\nnipper is a short firm strip of tendinous stuff cut from the tapering\npart of Leviathan’s tail: it averages an inch in thickness, and for the\nrest, is about the size of the iron", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6173, "position": 6173, "text": "in thickness, and for the\nrest, is about the size of the iron part of a hoe. Edgewise moved along\nthe oily deck, it operates like a leathern squilgee; and by nameless\nblandishments, as of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6174, "position": 6174, "text": "n squilgee; and by nameless\nblandishments, as of magic, allures along with it all impurities.\n\nBut to learn all about these recondite matters, your best way is at\nonce to descend into the blubber-", "labels": {"50": 31, "100": 75, "250": 106, "500": 333, "1000": 290, "2000": 374}}, {"id": 6175, "position": 6175, "text": "matters, your best way is at\nonce to descend into the blubber-room, and have a long talk with its\ninmates. This place has previously been mentioned as the receptacle for\nthe blanket-pieces, when stript and hoisted from the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6176, "position": 6176, "text": "eptacle for\nthe blanket-pieces, when stript and hoisted from the whale. When the\nproper time arrives for cutting up its contents, this apartment is a\nscene of terror to all tyros, especially by night", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1620}}, {"id": 6177, "position": 6177, "text": "to all tyros, especially by night. On one side, lit by\na dull lantern, a space has been left clear for the workmen. They\ngenerally go in pairs,—a pike-and-gaffman and a spade-man", "labels": {"50": 31, "100": 20, "250": 49, "500": 78, "1000": 933, "2000": 1081}}, {"id": 6178, "position": 6178, "text": ",—a pike-and-gaffman and a spade-man. The\nwhaling-pike is similar to a frigate’s boarding-weapon of the same\nname. The gaff is something like a boat-hook", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6179, "position": 6179, "text": "The gaff is something like a boat-hook. With his gaff, the\ngaffman hooks on to a sheet of blubber, and strives to hold it from\nslipping, as the ship pitches and lurches about", "labels": {"50": 45, "100": 64, "250": 163, "500": 363, "1000": 692, "2000": 778}}, {"id": 6180, "position": 6180, "text": "from\nslipping, as the ship pitches and lurches about. Meanwhile, the\nspade-man stands on the sheet itself, perpendicularly chopping it into\nthe portable horse-pieces. This spade is sharp as hone can make it; the\nspade", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6181, "position": 6181, "text": "pieces. This spade is sharp as hone can make it; the\nspademan’s feet are shoeless; the thing he stands on will sometimes\nirresistibly slide away from him, like a sledge", "labels": {"50": 48, "100": 20, "250": 49, "500": 334, "1000": 275, "2000": 1710}}, {"id": 6182, "position": 6182, "text": "away from him, like a sledge. If he cuts off one of\nhis own toes, or one of his assistants’, would you be very much\nastonished? Toes are scarce among veteran blubber-room men.\n\n\nCHAPTER 95. The Cassock", "labels": {"50": 25, "100": 86, "250": 156, "500": 202, "1000": 329, "2000": 42}}, {"id": 6183, "position": 6183, "text": "scarce among veteran blubber-room men.\n\n\nCHAPTER 95. The Cassock.\n\nHad you stepped on board the Pequod at a certain juncture of this\npost-mortemizing of the whale; and had you strolled forward nigh the\nwind", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6184, "position": 6184, "text": "emizing of the whale; and had you strolled forward nigh the\nwindlass, pretty sure am I that you would have scanned with no small\ncuriosity a very strange, enigmatical object, which you would have seen\nthere, lying along lengthwise in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6185, "position": 6185, "text": "tical object, which you would have seen\nthere, lying along lengthwise in the lee scuppers. Not the wondrous\ncistern in the whale’s huge head; not the prodigy of his unhinged lower\njaw; not the miracle", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6186, "position": 6186, "text": "; not the prodigy of his unhinged lower\njaw; not the miracle of his symmetrical tail; none of these would so\nsurprise you, as half a glimpse of that unaccountable cone,—longer than\na Kentuckian is tall,", "labels": {"50": 37, "100": 55, "250": 52, "500": 465, "1000": 204, "2000": 174}}, {"id": 6187, "position": 6187, "text": "ccountable cone,—longer than\na Kentuckian is tall, nigh a foot in diameter at the base, and\njet-black as Yojo, the ebony idol of Queequeg", "labels": {"50": 12, "100": 24, "250": 174, "500": 451, "1000": 210, "2000": 1613}}, {"id": 6188, "position": 6188, "text": "idol of Queequeg. And an idol, indeed, it\nis; or, rather, in old times, its likeness was. Such an idol as that\nfound in the secret groves of Queen Maachah in Judea; and for\nworship", "labels": {"50": 27, "100": 97, "250": 216, "500": 201, "1000": 540, "2000": 319}}, {"id": 6189, "position": 6189, "text": "the secret groves of Queen Maachah in Judea; and for\nworshipping which, King Asa, her son, did depose her, and destroyed the\nidol, and burnt it for an abomination at the brook Kedron, as darkly", "labels": {"50": 27, "100": 33, "250": 240, "500": 135, "1000": 503, "2000": 84}}, {"id": 6190, "position": 6190, "text": "burnt it for an abomination at the brook Kedron, as darkly\nset forth in the 15th chapter of the First Book of Kings.\n\nLook at the sailor, called the mincer, who now comes along, and\nassisted by two allies, heavily", "labels": {"50": 32, "100": 0, "250": 233, "500": 72, "1000": 856, "2000": 1620}}, {"id": 6191, "position": 6191, "text": "mincer, who now comes along, and\nassisted by two allies, heavily backs the grandissimus, as the mariners\ncall it, and with bowed shoulders, staggers off with it as if he were a\ngrenadier carrying a dead comrade", "labels": {"50": 31, "100": 7, "250": 193, "500": 78, "1000": 849, "2000": 1081}}, {"id": 6192, "position": 6192, "text": "off with it as if he were a\ngrenadier carrying a dead comrade from the field. Extending it upon the\nforecastle deck, he now proceeds cylindrically to remove its dark pelt,\nas an African hunter the pelt of a boa", "labels": {"50": 31, "100": 24, "250": 49, "500": 73, "1000": 851, "2000": 1620}}, {"id": 6193, "position": 6193, "text": "dark pelt,\nas an African hunter the pelt of a boa. This done he turns the pelt\ninside out, like a pantaloon leg; gives it a good stretching, so as\nalmost to double its diameter; and at last", "labels": {"50": 31, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 744}}, {"id": 6194, "position": 6194, "text": "a good stretching, so as\nalmost to double its diameter; and at last hangs it, well spread, in\nthe rigging, to dry. Ere long, it is taken down; when removing some\nthree feet of it, towards the pointed ex", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 486, "2000": 628}}, {"id": 6195, "position": 6195, "text": "taken down; when removing some\nthree feet of it, towards the pointed extremity, and then cutting two\nslits for arm-holes at the other end, he lengthwise slips himself\nbodily into it. The mincer now stands before you invested in", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 486, "2000": 628}}, {"id": 6196, "position": 6196, "text": "slips himself\nbodily into it. The mincer now stands before you invested in the full\ncanonicals of his calling. Immemorial to all his order, this\ninvestiture alone will adequately protect him, while employed in the\npeculiar functions of his", "labels": {"50": 31, "100": 7, "250": 49, "500": 36, "1000": 435, "2000": 1974}}, {"id": 6197, "position": 6197, "text": "ure alone will adequately protect him, while employed in the\npeculiar functions of his office.\n\nThat office consists in mincing the horse-pieces of blubber for the\npots; an operation which is conducted at a curious wooden horse,\nplanted endwise against the", "labels": {"50": 42, "100": 7, "250": 49, "500": 78, "1000": 387, "2000": 1081}}, {"id": 6198, "position": 6198, "text": "operation which is conducted at a curious wooden horse,\nplanted endwise against the bulwarks, and with a capacious tub beneath\nit, into which the minced pieces drop, fast as the sheets from a rapt\norator’s desk", "labels": {"50": 31, "100": 7, "250": 49, "500": 78, "1000": 387, "2000": 1081}}, {"id": 6199, "position": 6199, "text": "drop, fast as the sheets from a rapt\norator’s desk. Arrayed in decent black; occupying a conspicuous pulpit;\nintent on bible leaves; what a candidate for an archbishopric, what a\nlad for a Pope were this mincer", "labels": {"50": 9, "100": 26, "250": 193, "500": 19, "1000": 499, "2000": 629}}, {"id": 6200, "position": 6200, "text": "for an archbishopric, what a\nlad for a Pope were this mincer!*\n\n*Bible leaves! Bible leaves! This is the invariable cry from the mates\nto the mincer. It enjoins him to be careful, and cut", "labels": {"50": 9, "100": 26, "250": 30, "500": 498, "1000": 637, "2000": 39}}, {"id": 6201, "position": 6201, "text": "the mincer. It enjoins him to be careful, and cut his work into as\nthin slices as possible, inasmuch as by so doing the business of\nboiling out the oil is much accelerated, and its quantity considerably\nincreased, besides perhaps", "labels": {"50": 42, "100": 59, "250": 10, "500": 260, "1000": 658, "2000": 129}}, {"id": 6202, "position": 6202, "text": "out the oil is much accelerated, and its quantity considerably\nincreased, besides perhaps improving it in quality.\n\n\nCHAPTER 96. The Try-Works.\n\nBesides her hoisted boats, an American whaler is outwardly\ndistinguished by her try-works", "labels": {"50": 45, "100": 63, "250": 138, "500": 290, "1000": 327, "2000": 735}}, {"id": 6203, "position": 6203, "text": "whaler is outwardly\ndistinguished by her try-works. She presents the curious anomaly of the\nmost solid masonry joining with oak and hemp in constituting the\ncompleted ship. It is as if from the open field a brick-kiln were\ntransported", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6204, "position": 6204, "text": "It is as if from the open field a brick-kiln were\ntransported to her planks.\n\nThe try-works are planted between the foremast and mainmast, the most\nroomy part of the deck", "labels": {"50": 45, "100": 64, "250": 138, "500": 327, "1000": 327, "2000": 887}}, {"id": 6205, "position": 6205, "text": ", the most\nroomy part of the deck. The timbers beneath are of a peculiar strength,\nfitted to sustain the weight of an almost solid mass of brick and\nmortar, some ten feet by eight square, and five in height", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 777, "2000": 1658}}, {"id": 6206, "position": 6206, "text": "ten feet by eight square, and five in height. The\nfoundation does not penetrate the deck, but the masonry is firmly\nsecured to the surface by ponderous knees of iron bracing it on all\nsides, and screwing it down to the timbers", "labels": {"50": 42, "100": 63, "250": 152, "500": 247, "1000": 542, "2000": 1658}}, {"id": 6207, "position": 6207, "text": "it on all\nsides, and screwing it down to the timbers. On the flanks it is cased\nwith wood, and at top completely covered by a large, sloping, battened\nhatchway. Removing this hatch we expose the great try-pots", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 887}}, {"id": 6208, "position": 6208, "text": "tened\nhatchway. Removing this hatch we expose the great try-pots, two in\nnumber, and each of several barrels’ capacity. When not in use, they\nare kept remarkably clean. Sometimes they are polished with soapstone\nand sand, till", "labels": {"50": 42, "100": 42, "250": 131, "500": 329, "1000": 917, "2000": 616}}, {"id": 6209, "position": 6209, "text": "kept remarkably clean. Sometimes they are polished with soapstone\nand sand, till they shine within like silver punch-bowls. During the\nnight-watches some cynical old sailors will crawl into them and coil\nthemselves away there for a nap", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 6210, "position": 6210, "text": "into them and coil\nthemselves away there for a nap. While employed in polishing them—one\nman in each pot, side by side—many confidential communications are\ncarried on, over the iron lips. It is a place also for profound\nmathematical meditation", "labels": {"50": 31, "100": 7, "250": 159, "500": 78, "1000": 387, "2000": 1081}}, {"id": 6211, "position": 6211, "text": "over the iron lips. It is a place also for profound\nmathematical meditation. It was in the left hand try-pot of the Pequod,\nwith the soapstone diligently circling round me, that I was first\nindirectly struck by the remarkable", "labels": {"50": 25, "100": 5, "250": 156, "500": 313, "1000": 329, "2000": 1559}}, {"id": 6212, "position": 6212, "text": "igently circling round me, that I was first\nindirectly struck by the remarkable fact, that in geometry all bodies\ngliding along the cycloid, my soapstone for example, will descend from\nany point in precisely the same time.", "labels": {"50": 3, "100": 70, "250": 50, "500": 33, "1000": 862, "2000": 1334}}, {"id": 6213, "position": 6213, "text": "will descend from\nany point in precisely the same time.\n\nRemoving the fire-board from the front of the try-works, the bare\nmasonry of that side is exposed, penetrated by the two iron mouths of\nthe furnaces, directly underneath the pots", "labels": {"50": 42, "100": 63, "250": 152, "500": 206, "1000": 678, "2000": 694}}, {"id": 6214, "position": 6214, "text": "by the two iron mouths of\nthe furnaces, directly underneath the pots. These mouths are fitted\nwith heavy doors of iron. The intense heat of the fire is prevented\nfrom communicating itself to the deck, by means of a shallow reservoir\nextending under the entire", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 611, "2000": 60}}, {"id": 6215, "position": 6215, "text": "itself to the deck, by means of a shallow reservoir\nextending under the entire inclosed surface of the works. By a tunnel\ninserted at the rear, this reservoir is kept replenished with water as\nfast as it evaporates", "labels": {"50": 42, "100": 63, "250": 152, "500": 290, "1000": 611, "2000": 735}}, {"id": 6216, "position": 6216, "text": "replenished with water as\nfast as it evaporates. There are no external chimneys; they open direct\nfrom the rear wall. And here let us go back for a moment.\n\nIt was about nine o’clock at night that the Pequ", "labels": {"50": 25, "100": 93, "250": 171, "500": 233, "1000": 906, "2000": 893}}, {"id": 6217, "position": 6217, "text": "moment.\n\nIt was about nine o’clock at night that the Pequod’s try-works were\nfirst started on this present voyage. It belonged to Stubb to oversee\nthe business.\n\n“All ready there? Off hatch, then, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6218, "position": 6218, "text": "oversee\nthe business.\n\n“All ready there? Off hatch, then, and start her. You cook, fire the\nworks.” This was an easy thing, for the carpenter had been thrusting\nhis shavings into the furnace throughout the passage", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 6219, "position": 6219, "text": "had been thrusting\nhis shavings into the furnace throughout the passage. Here be it said\nthat in a whaling voyage the first fire in the try-works has to be fed\nfor a time with wood. After that no wood is used, except as", "labels": {"50": 45, "100": 64, "250": 138, "500": 48, "1000": 997, "2000": 1931}}, {"id": 6220, "position": 6220, "text": "for a time with wood. After that no wood is used, except as a means of\nquick ignition to the staple fuel. In a word, after being tried out,\nthe crisp, shrivelled blubber, now called scraps or fritte", "labels": {"50": 45, "100": 63, "250": 138, "500": 72, "1000": 327, "2000": 694}}, {"id": 6221, "position": 6221, "text": "crisp, shrivelled blubber, now called scraps or fritters, still\ncontains considerable of its unctuous properties. These fritters feed\nthe flames. Like a plethoric burning martyr, or a self-consuming\nmisant", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 9, "2000": 1735}}, {"id": 6222, "position": 6222, "text": "Like a plethoric burning martyr, or a self-consuming\nmisanthrope, once ignited, the whale supplies his own fuel and burns by\nhis own body. Would that he consumed his own smoke! for his smoke is\nhorrible to inhale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6223, "position": 6223, "text": "that he consumed his own smoke! for his smoke is\nhorrible to inhale, and inhale it you must, and not only that, but you\nmust live in it for the time. It has an unspeakable, wild, Hindoo", "labels": {"50": 25, "100": 41, "250": 91, "500": 457, "1000": 514, "2000": 1631}}, {"id": 6224, "position": 6224, "text": "the time. It has an unspeakable, wild, Hindoo odor\nabout it, such as may lurk in the vicinity of funereal pyres. It smells\nlike the left wing of the day of judgment; it is an", "labels": {"50": 31, "100": 81, "250": 3, "500": 366, "1000": 15, "2000": 1394}}, {"id": 6225, "position": 6225, "text": "It smells\nlike the left wing of the day of judgment; it is an argument for the\npit.\n\nBy midnight the works were in full operation. We were clear from the\ncarcase; sail had been made; the wind was freshening; the wild", "labels": {"50": 25, "100": 93, "250": 55, "500": 318, "1000": 585, "2000": 448}}, {"id": 6226, "position": 6226, "text": "case; sail had been made; the wind was freshening; the wild ocean\ndarkness was intense. But that darkness was licked up by the fierce\nflames, which at intervals forked forth from the sooty flues, and\nilluminated every lofty rope", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 6227, "position": 6227, "text": "ed forth from the sooty flues, and\nilluminated every lofty rope in the rigging, as with the famed Greek\nfire. The burning ship drove on, as if remorselessly commissioned to\nsome vengeful deed", "labels": {"50": 45, "100": 64, "250": 82, "500": 28, "1000": 327, "2000": 1518}}, {"id": 6228, "position": 6228, "text": "remorselessly commissioned to\nsome vengeful deed. So the pitch and sulphur-freighted brigs of the\nbold Hydriote, Canaris, issuing from their midnight harbors, with broad\nsheets of flame for sails, bore down", "labels": {"50": 45, "100": 29, "250": 82, "500": 79, "1000": 300, "2000": 1014}}, {"id": 6229, "position": 6229, "text": "their midnight harbors, with broad\nsheets of flame for sails, bore down upon the Turkish frigates, and\nfolded them in conflagrations.\n\nThe hatch, removed from the top of the works, now afforded a wide\nhearth in front of them", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 327, "2000": 549}}, {"id": 6230, "position": 6230, "text": "top of the works, now afforded a wide\nhearth in front of them. Standing on this were the Tartarean shapes of\nthe pagan harpooneers, always the whale-ship’s stokers. With huge\npronged poles they pitched hissing masses", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 6231, "position": 6231, "text": "ship’s stokers. With huge\npronged poles they pitched hissing masses of blubber into the scalding\npots, or stirred up the fires beneath, till the snaky flames darted,\ncurling, out of the doors to catch them by", "labels": {"50": 40, "100": 10, "250": 226, "500": 380, "1000": 469, "2000": 122}}, {"id": 6232, "position": 6232, "text": "naky flames darted,\ncurling, out of the doors to catch them by the feet. The smoke rolled\naway in sullen heaps. To every pitch of the ship there was a pitch of\nthe boiling oil, which seemed all eagerness to leap", "labels": {"50": 22, "100": 64, "250": 205, "500": 28, "1000": 300, "2000": 1014}}, {"id": 6233, "position": 6233, "text": "was a pitch of\nthe boiling oil, which seemed all eagerness to leap into their faces.\nOpposite the mouth of the works, on the further side of the wide wooden\nhearth, was the windlass. This served for a sea-sofa", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 6234, "position": 6234, "text": ", was the windlass. This served for a sea-sofa. Here lounged the\nwatch, when not otherwise employed, looking into the red heat of the\nfire, till their eyes felt scorched in their heads", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 6235, "position": 6235, "text": "their eyes felt scorched in their heads. Their tawny\nfeatures, now all begrimed with smoke and sweat, their matted beards,\nand the contrasting barbaric brilliancy of their teeth, all these were\nstrangely revealed", "labels": {"50": 22, "100": 78, "250": 11, "500": 479, "1000": 475, "2000": 1554}}, {"id": 6236, "position": 6236, "text": "baric brilliancy of their teeth, all these were\nstrangely revealed in the capricious emblazonings of the works. As they\nnarrated to each other their unholy adventures, their tales of terror\ntold in words of mirth", "labels": {"50": 22, "100": 78, "250": 210, "500": 380, "1000": 57, "2000": 1365}}, {"id": 6237, "position": 6237, "text": "unholy adventures, their tales of terror\ntold in words of mirth; as their uncivilized laughter forked upwards\nout of them, like the flames from the furnace; as to and fro, in their\nfront, the harpoon", "labels": {"50": 9, "100": 64, "250": 193, "500": 498, "1000": 343, "2000": 110}}, {"id": 6238, "position": 6238, "text": "furnace; as to and fro, in their\nfront, the harpooneers wildly gesticulated with their huge pronged\nforks and dippers; as the wind howled on, and the sea leaped, and the\nship groaned and dived, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 6239, "position": 6239, "text": ", and the sea leaped, and the\nship groaned and dived, and yet steadfastly shot her red hell further\nand further into the blackness of the sea and the night, and scornfully\nchamped the white bone in her mouth,", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 16}}, {"id": 6240, "position": 6240, "text": "night, and scornfully\nchamped the white bone in her mouth, and viciously spat round her on\nall sides; then the rushing Pequod, freighted with savages, and laden\nwith fire, and burning a corpse, and plunging", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 6241, "position": 6241, "text": "savages, and laden\nwith fire, and burning a corpse, and plunging into that blackness of\ndarkness, seemed the material counterpart of her monomaniac commander’s\nsoul.\n\nSo seemed it to me, as I stood at her helm, and for", "labels": {"50": 40, "100": 13, "250": 182, "500": 27, "1000": 930, "2000": 1570}}, {"id": 6242, "position": 6242, "text": "So seemed it to me, as I stood at her helm, and for long hours silently\nguided the way of this fire-ship on the sea. Wrapped, for that\ninterval, in darkness myself, I but the better saw the redness, the", "labels": {"50": 25, "100": 5, "250": 125, "500": 411, "1000": 980, "2000": 1521}}, {"id": 6243, "position": 6243, "text": ", in darkness myself, I but the better saw the redness, the\nmadness, the ghastliness of others. The continual sight of the fiend\nshapes before me, capering half in smoke and half in fire, these at\nlast beg", "labels": {"50": 16, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1860}}, {"id": 6244, "position": 6244, "text": ", capering half in smoke and half in fire, these at\nlast begat kindred visions in my soul, so soon as I began to yield to\nthat unaccountable drowsiness which ever would come over me at a\nmidnight helm.", "labels": {"50": 25, "100": 5, "250": 136, "500": 411, "1000": 272, "2000": 1860}}, {"id": 6245, "position": 6245, "text": "able drowsiness which ever would come over me at a\nmidnight helm.\n\nBut that night, in particular, a strange (and ever since inexplicable)\nthing occurred to me. Starting from a brief standing sleep, I was\nhorribly conscious", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 6246, "position": 6246, "text": "occurred to me. Starting from a brief standing sleep, I was\nhorribly conscious of something fatally wrong. The jaw-bone tiller\nsmote my side, which leaned against it; in my ears was the low hum of\nsails, just beginning to shake", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 6247, "position": 6247, "text": "; in my ears was the low hum of\nsails, just beginning to shake in the wind; I thought my eyes were\nopen; I was half conscious of putting my fingers to the lids and\nmechanically stretching them still further apart", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 6248, "position": 6248, "text": "the lids and\nmechanically stretching them still further apart. But, spite of all\nthis, I could see no compass before me to steer by; though it seemed\nbut a minute since I had been watching the card, by the steady binnacle\nlamp illuminating", "labels": {"50": 25, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1192}}, {"id": 6249, "position": 6249, "text": "I had been watching the card, by the steady binnacle\nlamp illuminating it. Nothing seemed before me but a jet gloom, now and\nthen made ghastly by flashes of redness. Uppermost was the impression,\nthat whatever swift, rushing", "labels": {"50": 25, "100": 5, "250": 136, "500": 313, "1000": 313, "2000": 786}}, {"id": 6250, "position": 6250, "text": "of redness. Uppermost was the impression,\nthat whatever swift, rushing thing I stood on was not so much bound to\nany haven ahead as rushing from all havens astern. A stark, bewildered\nfeeling, as of death, came over me", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 51, "2000": 1521}}, {"id": 6251, "position": 6251, "text": "tern. A stark, bewildered\nfeeling, as of death, came over me. Convulsively my hands grasped the\ntiller, but with the crazy conceit that the tiller was, somehow, in\nsome enchanted way, inverted", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 6252, "position": 6252, "text": "the tiller was, somehow, in\nsome enchanted way, inverted. My God! what is the matter with me?\nthought I. Lo! in my brief sleep I had turned myself about, and was\nfronting the ship’s stern, with", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 6253, "position": 6253, "text": "turned myself about, and was\nfronting the ship’s stern, with my back to her prow and the compass. In\nan instant I faced back, just in time to prevent the vessel from flying\nup into the wind, and very probably caps", "labels": {"50": 25, "100": 5, "250": 125, "500": 388, "1000": 313, "2000": 1521}}, {"id": 6254, "position": 6254, "text": "to prevent the vessel from flying\nup into the wind, and very probably capsizing her. How glad and how\ngrateful the relief from this unnatural hallucination of the night, and\nthe fatal contingency of being brought by the lee!", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 6255, "position": 6255, "text": "and\nthe fatal contingency of being brought by the lee!\n\nLook not too long in the face of the fire, O man! Never dream with thy\nhand on the helm! Turn not thy back to the compass; accept the first\nhint of the", "labels": {"50": 9, "100": 26, "250": 133, "500": 307, "1000": 343, "2000": 761}}, {"id": 6256, "position": 6256, "text": "! Turn not thy back to the compass; accept the first\nhint of the hitching tiller; believe not the artificial fire, when its\nredness makes all things look ghastly. To-morrow, in the natural sun,\nthe skies will", "labels": {"50": 16, "100": 73, "250": 120, "500": 143, "1000": 637, "2000": 1886}}, {"id": 6257, "position": 6257, "text": "hastly. To-morrow, in the natural sun,\nthe skies will be bright; those who glared like devils in the forking\nflames, the morn will show in far other, at least gentler, relief; the\nglorious, golden,", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 637, "2000": 1886}}, {"id": 6258, "position": 6258, "text": "far other, at least gentler, relief; the\nglorious, golden, glad sun, the only true lamp—all others but liars!\n\nNevertheless the sun hides not Virginia’s Dismal Swamp, nor Rome’s\naccursed Camp", "labels": {"50": 9, "100": 73, "250": 133, "500": 307, "1000": 343, "2000": 761}}, {"id": 6259, "position": 6259, "text": "’s Dismal Swamp, nor Rome’s\naccursed Campagna, nor wide Sahara, nor all the millions of miles of\ndeserts and of griefs beneath the moon. The sun hides not the ocean,\nwhich is the dark side", "labels": {"50": 26, "100": 26, "250": 240, "500": 332, "1000": 663, "2000": 1475}}, {"id": 6260, "position": 6260, "text": "the moon. The sun hides not the ocean,\nwhich is the dark side of this earth, and which is two thirds of this\nearth. So, therefore, that mortal man who hath more of joy than sorrow\nin him, that mortal man cannot", "labels": {"50": 10, "100": 75, "250": 106, "500": 289, "1000": 616, "2000": 1175}}, {"id": 6261, "position": 6261, "text": "who hath more of joy than sorrow\nin him, that mortal man cannot be true—not true, or undeveloped. With\nbooks the same. The truest of all men was the Man of Sorrows, and the\ntruest of all books is", "labels": {"50": 31, "100": 75, "250": 13, "500": 482, "1000": 15, "2000": 1050}}, {"id": 6262, "position": 6262, "text": "was the Man of Sorrows, and the\ntruest of all books is Solomon’s, and Ecclesiastes is the fine hammered\nsteel of woe. “All is vanity.” ALL. This wilful world hath not got hold", "labels": {"50": 16, "100": 73, "250": 13, "500": 414, "1000": 437, "2000": 709}}, {"id": 6263, "position": 6263, "text": "is vanity.” ALL. This wilful world hath not got hold\nof unchristian Solomon’s wisdom yet. But he who dodges hospitals and\njails, and walks fast crossing graveyards, and would rather talk of\noperas than hell", "labels": {"50": 35, "100": 94, "250": 23, "500": 373, "1000": 201, "2000": 1945}}, {"id": 6264, "position": 6264, "text": "and walks fast crossing graveyards, and would rather talk of\noperas than hell; calls Cowper, Young, Pascal, Rousseau, poor devils\nall of sick men; and throughout a care-free lifetime swears by Rabelais\nas passing wise,", "labels": {"50": 17, "100": 16, "250": 128, "500": 398, "1000": 799, "2000": 1161}}, {"id": 6265, "position": 6265, "text": "a care-free lifetime swears by Rabelais\nas passing wise, and therefore jolly;—not that man is fitted to sit\ndown on tomb-stones, and break the green damp mould with unfathomably\nwondrous Solomon.", "labels": {"50": 17, "100": 16, "250": 87, "500": 307, "1000": 355, "2000": 1394}}, {"id": 6266, "position": 6266, "text": "the green damp mould with unfathomably\nwondrous Solomon.\n\nBut even Solomon, he says, “the man that wandereth out of the way of\nunderstanding shall remain” (_i.e._, even while living) “", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 944, "2000": 523}}, {"id": 6267, "position": 6267, "text": "remain” (_i.e._, even while living) “in the\ncongregation of the dead.” Give not thyself up, then, to fire, lest it\ninvert thee, deaden thee; as for the time it", "labels": {"50": 10, "100": 71, "250": 13, "500": 236, "1000": 548, "2000": 1555}}, {"id": 6268, "position": 6268, "text": "lest it\ninvert thee, deaden thee; as for the time it did me. There is a wisdom\nthat is woe; but there is a woe that is madness. And there is a\nCatskill eagle in some souls that can alike", "labels": {"50": 10, "100": 75, "250": 13, "500": 414, "1000": 616, "2000": 1859}}, {"id": 6269, "position": 6269, "text": "madness. And there is a\nCatskill eagle in some souls that can alike dive down into the blackest\ngorges, and soar out of them again and become invisible in the sunny\nspaces. And even if he for ever flies within the gorge,", "labels": {"50": 31, "100": 20, "250": 13, "500": 126, "1000": 747, "2000": 1710}}, {"id": 6270, "position": 6270, "text": "the sunny\nspaces. And even if he for ever flies within the gorge, that gorge is\nin the mountains; so that even in his lowest swoop the mountain eagle\nis still higher than other birds upon the plain, even though they soar.", "labels": {"50": 48, "100": 20, "250": 192, "500": 334, "1000": 816, "2000": 1710}}, {"id": 6271, "position": 6271, "text": "higher than other birds upon the plain, even though they soar.\n\n\nCHAPTER 97. The Lamp.\n\nHad you descended from the Pequod’s try-works to the Pequod’s\nforecastle, where the off duty watch were sleeping", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6272, "position": 6272, "text": "Pequod’s\nforecastle, where the off duty watch were sleeping, for one single\nmoment you would have almost thought you were standing in some\nilluminated shrine of canonized kings and counsellors. There they lay\nin their triangular oaken vaults", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 313, "2000": 631}}, {"id": 6273, "position": 6273, "text": "kings and counsellors. There they lay\nin their triangular oaken vaults, each mariner a chiselled muteness; a\nscore of lamps flashing upon his hooded eyes.\n\nIn merchantmen, oil for the sailor is more scarce than the milk", "labels": {"50": 31, "100": 7, "250": 49, "500": 78, "1000": 387, "2000": 1081}}, {"id": 6274, "position": 6274, "text": ".\n\nIn merchantmen, oil for the sailor is more scarce than the milk of\nqueens. To dress in the dark, and eat in the dark, and stumble in\ndarkness to his pallet, this is his usual lot", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 6275, "position": 6275, "text": "his pallet, this is his usual lot. But the whaleman, as he\nseeks the food of light, so he lives in light. He makes his berth an\nAladdin’s lamp, and lays him down in it; so that in", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6276, "position": 6276, "text": "ddin’s lamp, and lays him down in it; so that in the pitchiest night\nthe ship’s black hull still houses an illumination.\n\nSee with what entire freedom the whaleman takes his handful of\nlamps—often but old bottles and vial", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6277, "position": 6277, "text": "the whaleman takes his handful of\nlamps—often but old bottles and vials, though—to the copper cooler at\nthe try-works, and replenishes them there, as mugs of ale at a vat", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 1107}}, {"id": 6278, "position": 6278, "text": "there, as mugs of ale at a vat. He\nburns, too, the purest of oil, in its unmanufactured, and, therefore,\nunvitiated state; a fluid unknown to solar, lunar, or", "labels": {"50": 31, "100": 7, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 6279, "position": 6279, "text": "unvitiated state; a fluid unknown to solar, lunar, or astral\ncontrivances ashore. It is sweet as early grass butter in April. He\ngoes and hunts for his oil, so as to be sure of its freshness and", "labels": {"50": 48, "100": 20, "250": 193, "500": 334, "1000": 275, "2000": 110}}, {"id": 6280, "position": 6280, "text": "hunts for his oil, so as to be sure of its freshness and\ngenuineness, even as the traveller on the prairie hunts up his own\nsupper of game.\n\n\nCHAPTER 98. Stowing Down and Clearing Up.", "labels": {"50": 12, "100": 93, "250": 97, "500": 117, "1000": 938, "2000": 1953}}, {"id": 6281, "position": 6281, "text": ". Stowing Down and Clearing Up.\n\nAlready has it been related how the great leviathan is afar off\ndescried from the mast-head; how he is chased over the watery moors,\nand slaughtered in the valleys of the deep; how he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6282, "position": 6282, "text": "the watery moors,\nand slaughtered in the valleys of the deep; how he is then towed\nalongside and beheaded; and how (on the principle which entitled the\nheadsman of old to the garments in which the beheaded was killed) his\ngreat padded surtou", "labels": {"50": 18, "100": 83, "250": 170, "500": 433, "1000": 47, "2000": 1604}}, {"id": 6283, "position": 6283, "text": "to the garments in which the beheaded was killed) his\ngreat padded surtout becomes the property of his executioner; how, in\ndue time, he is condemned to the pots, and, like Shadrach, Meshach, and\nAbed", "labels": {"50": 32, "100": 33, "250": 194, "500": 207, "1000": 756, "2000": 632}}, {"id": 6284, "position": 6284, "text": "pots, and, like Shadrach, Meshach, and\nAbednego, his spermaceti, oil, and bone pass unscathed through the\nfire;—but now it remains to conclude the last chapter of this part of\nthe", "labels": {"50": 17, "100": 16, "250": 146, "500": 369, "1000": 667, "2000": 1601}}, {"id": 6285, "position": 6285, "text": "—but now it remains to conclude the last chapter of this part of\nthe description by rehearsing—singing, if I may—the romantic proceeding\nof decanting off his oil into the casks and striking them down into the\nhold, where", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 6286, "position": 6286, "text": "his oil into the casks and striking them down into the\nhold, where once again leviathan returns to his native profundities,\nsliding along beneath the surface as before; but, alas! never more to\nrise and blow.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6287, "position": 6287, "text": "but, alas! never more to\nrise and blow.\n\nWhile still warm, the oil, like hot punch, is received into the\nsix-barrel casks; and while, perhaps, the ship is pitching and rolling\nthis way and that in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 6288, "position": 6288, "text": ", perhaps, the ship is pitching and rolling\nthis way and that in the midnight sea, the enormous casks are slewed\nround and headed over, end for end, and sometimes perilously scoot\nacross the slippery deck, like so many", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 6289, "position": 6289, "text": "and sometimes perilously scoot\nacross the slippery deck, like so many land slides, till at last\nman-handled and stayed in their course; and all round the hoops, rap,\nrap, go as many hammers as can play upon", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 6290, "position": 6290, "text": "s, rap,\nrap, go as many hammers as can play upon them, for now, _ex officio_,\nevery sailor is a cooper.\n\nAt length, when the last pint is casked, and all is cool, then", "labels": {"50": 6, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 6291, "position": 6291, "text": "when the last pint is casked, and all is cool, then the\ngreat hatchways are unsealed, the bowels of the ship are thrown open,\nand down go the casks to their final rest in the sea", "labels": {"50": 31, "100": 7, "250": 193, "500": 453, "1000": 851, "2000": 1107}}, {"id": 6292, "position": 6292, "text": "down go the casks to their final rest in the sea. This done, the\nhatches are replaced, and hermetically closed, like a closet walled up.\n\nIn the sperm fishery, this is perhaps one of the most remarkable\nincidents in all", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 447}}, {"id": 6293, "position": 6293, "text": "the sperm fishery, this is perhaps one of the most remarkable\nincidents in all the business of whaling. One day the planks stream\nwith freshets of blood and oil; on the sacred quarter-deck enormous\nmasses of the whale’s head are prof", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6294, "position": 6294, "text": "the sacred quarter-deck enormous\nmasses of the whale’s head are profanely piled; great rusty casks lie\nabout, as in a brewery yard; the smoke from the try-works has besooted\nall the bulwarks;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6295, "position": 6295, "text": "the try-works has besooted\nall the bulwarks; the mariners go about suffused with unctuousness; the\nentire ship seems great leviathan himself; while on all hands the din\nis deafening.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 6296, "position": 6296, "text": "himself; while on all hands the din\nis deafening.\n\nBut a day or two after, you look about you, and prick your ears in this\nself-same ship; and were it not for the tell-tale boats and try-works,\nyou", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6297, "position": 6297, "text": "were it not for the tell-tale boats and try-works,\nyou would all but swear you trod some silent merchant vessel, with a\nmost scrupulously neat commander. The unmanufactured sperm oil\npossesses a singularly cleansing virtue", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6298, "position": 6298, "text": ". The unmanufactured sperm oil\npossesses a singularly cleansing virtue. This is the reason why the\ndecks never look so white as just after what they call an affair of\noil. Besides, from the ashes of the burned scraps of the", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6299, "position": 6299, "text": "of\noil. Besides, from the ashes of the burned scraps of the whale, a\npotent lye is readily made; and whenever any adhesiveness from the back\nof the whale remains clinging to the side, that lye quickly\nexterminate", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6300, "position": 6300, "text": "the whale remains clinging to the side, that lye quickly\nexterminates it. Hands go diligently along the bulwarks, and with\nbuckets of water and rags restore them to their full tidiness", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6301, "position": 6301, "text": "water and rags restore them to their full tidiness. The soot\nis brushed from the lower rigging. All the numerous implements which\nhave been in use are likewise faithfully cleansed and put away", "labels": {"50": 45, "100": 64, "250": 138, "500": 247, "1000": 327, "2000": 887}}, {"id": 6302, "position": 6302, "text": "ly cleansed and put away. The\ngreat hatch is scrubbed and placed upon the try-works, completely\nhiding the pots; every cask is out of sight; all tackles are coiled in\nunseen nooks; and when by the combined and simultaneous", "labels": {"50": 42, "100": 2, "250": 54, "500": 246, "1000": 491, "2000": 374}}, {"id": 6303, "position": 6303, "text": "are coiled in\nunseen nooks; and when by the combined and simultaneous industry of\nalmost the entire ship’s company, the whole of this conscientious duty\nis at last concluded, then the crew themselves proceed to their own\nablutions", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6304, "position": 6304, "text": "at last concluded, then the crew themselves proceed to their own\nablutions; shift themselves from top to toe; and finally issue to the\nimmaculate deck, fresh and all aglow, as bridegrooms new-leaped from\nout the dainti", "labels": {"50": 9, "100": 64, "250": 133, "500": 498, "1000": 327, "2000": 16}}, {"id": 6305, "position": 6305, "text": "low, as bridegrooms new-leaped from\nout the daintiest Holland.\n\nNow, with elated step, they pace the planks in twos and threes, and\nhumorously discourse of parlors, sofas, carpets,", "labels": {"50": 16, "100": 73, "250": 120, "500": 498, "1000": 118, "2000": 1003}}, {"id": 6306, "position": 6306, "text": "s, and\nhumorously discourse of parlors, sofas, carpets, and fine cambrics;\npropose to mat the deck; think of having hanging to the top; object not\nto taking tea by moonlight on the piazza of the forecastle", "labels": {"50": 48, "100": 20, "250": 193, "500": 126, "1000": 747, "2000": 1107}}, {"id": 6307, "position": 6307, "text": "object not\nto taking tea by moonlight on the piazza of the forecastle. To hint to\nsuch musked mariners of oil, and bone, and blubber, were little short\nof audacity. They know not the thing you distantly all", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 1107}}, {"id": 6308, "position": 6308, "text": "short\nof audacity. They know not the thing you distantly allude to. Away, and\nbring us napkins!\n\nBut mark: aloft there, at the three mast heads, stand three men intent\non spying out more whales, which", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6309, "position": 6309, "text": "three mast heads, stand three men intent\non spying out more whales, which, if caught, infallibly will again soil\nthe old oaken furniture, and drop at least one small grease-spot\nsomewhere", "labels": {"50": 31, "100": 20, "250": 49, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6310, "position": 6310, "text": "one small grease-spot\nsomewhere. Yes; and many is the time, when, after the severest\nuninterrupted labors, which know no night; continuing straight through\nfor ninety-six hours; when from the boat, where they", "labels": {"50": 9, "100": 20, "250": 193, "500": 19, "1000": 499, "2000": 629}}, {"id": 6311, "position": 6311, "text": "straight through\nfor ninety-six hours; when from the boat, where they have swelled their\nwrists with all day rowing on the Line,—they only step to the deck to\ncarry vast chains, and heave the heavy windlass, and cut and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6312, "position": 6312, "text": "carry vast chains, and heave the heavy windlass, and cut and slash,\nyea, and in their very sweatings to be smoked and burned anew by the\ncombined fires of the equatorial sun and the equatorial try-works;\nwhen,", "labels": {"50": 9, "100": 73, "250": 120, "500": 143, "1000": 637, "2000": 1886}}, {"id": 6313, "position": 6313, "text": "combined fires of the equatorial sun and the equatorial try-works;\nwhen, on the heel of all this, they have finally bestirred themselves\nto cleanse the ship, and make a spotless dairy room of it; many is the\ntime the", "labels": {"50": 31, "100": 20, "250": 49, "500": 334, "1000": 747, "2000": 1107}}, {"id": 6314, "position": 6314, "text": "and make a spotless dairy room of it; many is the\ntime the poor fellows, just buttoning the necks of their clean frocks,\nare startled by the cry of “There she blows!” and away they fly to\nfight another whale,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6315, "position": 6315, "text": "“There she blows!” and away they fly to\nfight another whale, and go through the whole weary thing again. Oh! my\nfriends, but this is man-killing! Yet this is life. For hardly have we\nmortals by long toiling", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6316, "position": 6316, "text": "! Yet this is life. For hardly have we\nmortals by long toilings extracted from this world’s vast bulk its\nsmall but valuable sperm; and then, with weary patience, cleansed\nourselves from its defilements, and learned to live", "labels": {"50": 16, "100": 20, "250": 13, "500": 126, "1000": 15, "2000": 970}}, {"id": 6317, "position": 6317, "text": "patience, cleansed\nourselves from its defilements, and learned to live here in clean\ntabernacles of the soul; hardly is this done, when—_There she\nblows!_—the ghost is spouted up, and away", "labels": {"50": 25, "100": 79, "250": 26, "500": 411, "1000": 533, "2000": 44}}, {"id": 6318, "position": 6318, "text": "she\nblows!_—the ghost is spouted up, and away we sail to fight some other\nworld, and go through young life’s old routine again.\n\nOh! the metempsychosis! Oh! Pythagoras", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 6319, "position": 6319, "text": "! the metempsychosis! Oh! Pythagoras, that in bright Greece, two\nthousand years ago, did die, so good, so wise, so mild; I sailed with\nthee along the Peruvian coast last voyage—and", "labels": {"50": 16, "100": 20, "250": 193, "500": 126, "1000": 727, "2000": 1107}}, {"id": 6320, "position": 6320, "text": "so mild; I sailed with\nthee along the Peruvian coast last voyage—and, foolish as I am, taught\nthee, a green simple boy, how to splice a rope!\n\n\nCHAPTER 99. The Doubloon.", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 6321, "position": 6321, "text": "!\n\n\nCHAPTER 99. The Doubloon.\n\nEre now it has been related how Ahab was wont to pace his quarter-deck,\ntaking regular turns at either limit, the binnacle and mainmast; but in\nthe multi", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6322, "position": 6322, "text": "limit, the binnacle and mainmast; but in\nthe multiplicity of other things requiring narration it has not been\nadded how that sometimes in these walks, when most plunged in his mood,\nhe was wont to pause in turn at each", "labels": {"50": 17, "100": 40, "250": 146, "500": 369, "1000": 314, "2000": 1928}}, {"id": 6323, "position": 6323, "text": "plunged in his mood,\nhe was wont to pause in turn at each spot, and stand there strangely\neyeing the particular object before him. When he halted before the\nbinnacle, with his glance fastened on the pointed needle in the\ncompass, that", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 6324, "position": 6324, "text": "le, with his glance fastened on the pointed needle in the\ncompass, that glance shot like a javelin with the pointed intensity of\nhis purpose; and when resuming his walk he again paused before the\nmainmast, then, as the same rivet", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 6325, "position": 6325, "text": "again paused before the\nmainmast, then, as the same riveted glance fastened upon the riveted\ngold coin there, he still wore the same aspect of nailed firmness, only\ndashed with a certain wild longing, if not hopefulness", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 300, "2000": 1014}}, {"id": 6326, "position": 6326, "text": "firmness, only\ndashed with a certain wild longing, if not hopefulness.\n\nBut one morning, turning to pass the doubloon, he seemed to be newly\nattracted by the strange figures and inscriptions stamped on it, as\nthough now for the", "labels": {"50": 22, "100": 78, "250": 229, "500": 469, "1000": 631, "2000": 1976}}, {"id": 6327, "position": 6327, "text": "by the strange figures and inscriptions stamped on it, as\nthough now for the first time beginning to interpret for himself in\nsome monomaniac way whatever significance might lurk in them. And some\ncertain significance lurks in all things, else all things are", "labels": {"50": 10, "100": 71, "250": 13, "500": 414, "1000": 548, "2000": 1555}}, {"id": 6328, "position": 6328, "text": ". And some\ncertain significance lurks in all things, else all things are little\nworth, and the round world itself but an empty cipher, except to sell\nby the cartload, as they do hills about Boston, to fill up some morass\nin", "labels": {"50": 31, "100": 20, "250": 69, "500": 453, "1000": 15, "2000": 24}}, {"id": 6329, "position": 6329, "text": ", as they do hills about Boston, to fill up some morass\nin the Milky Way.\n\nNow this doubloon was of purest, virgin gold, raked somewhere out of\nthe heart of gorgeous hills, whence, east and west,", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 523}}, {"id": 6330, "position": 6330, "text": "out of\nthe heart of gorgeous hills, whence, east and west, over golden sands,\nthe head-waters of many a Pactolus flows. And though now nailed amidst\nall the rustiness of iron bolts and the verdigris of copper", "labels": {"50": 16, "100": 73, "250": 15, "500": 406, "1000": 779, "2000": 1203}}, {"id": 6331, "position": 6331, "text": "amidst\nall the rustiness of iron bolts and the verdigris of copper spikes,\nyet, untouchable and immaculate to any foulness, it still preserved its\nQuito glow. Nor, though placed amongst a ruthless crew and every hour\npassed by", "labels": {"50": 37, "100": 19, "250": 78, "500": 268, "1000": 785, "2000": 1263}}, {"id": 6332, "position": 6332, "text": "glow. Nor, though placed amongst a ruthless crew and every hour\npassed by ruthless hands, and through the livelong nights shrouded with\nthick darkness which might cover any pilfering approach, nevertheless\nevery sunrise found the doubloon where the", "labels": {"50": 22, "100": 78, "250": 19, "500": 154, "1000": 57, "2000": 110}}, {"id": 6333, "position": 6333, "text": "lfering approach, nevertheless\nevery sunrise found the doubloon where the sunset left it last. For it\nwas set apart and sanctified to one awe-striking end; and however\nwanton in their sailor ways, one and all, the", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 16}}, {"id": 6334, "position": 6334, "text": "; and however\nwanton in their sailor ways, one and all, the mariners revered it as\nthe white whale’s talisman. Sometimes they talked it over in the weary\nwatch by night, wondering whose it was to be at last, and whether", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6335, "position": 6335, "text": "watch by night, wondering whose it was to be at last, and whether he\nwould ever live to spend it.\n\nNow those noble golden coins of South America are as medals of the sun\nand tropic token-pieces", "labels": {"50": 22, "100": 78, "250": 205, "500": 335, "1000": 631, "2000": 1140}}, {"id": 6336, "position": 6336, "text": "the sun\nand tropic token-pieces. Here palms, alpacas, and volcanoes; sun’s\ndisks and stars; ecliptics, horns-of-plenty, and rich banners waving,\nare in luxuriant profusion stamped", "labels": {"50": 16, "100": 20, "250": 49, "500": 162, "1000": 747, "2000": 1465}}, {"id": 6337, "position": 6337, "text": "plenty, and rich banners waving,\nare in luxuriant profusion stamped; so that the precious gold seems\nalmost to derive an added preciousness and enhancing glories, by\npassing through those fancy mints, so Spanishly poetic.", "labels": {"50": 17, "100": 16, "250": 193, "500": 449, "1000": 944, "2000": 1394}}, {"id": 6338, "position": 6338, "text": "by\npassing through those fancy mints, so Spanishly poetic.\n\nIt so chanced that the doubloon of the Pequod was a most wealthy\nexample of these things. On its round border it bore the letters,\nREPUBLICA DEL ECUADOR", "labels": {"50": 48, "100": 19, "250": 22, "500": 268, "1000": 498, "2000": 1263}}, {"id": 6339, "position": 6339, "text": "things. On its round border it bore the letters,\nREPUBLICA DEL ECUADOR: QUITO. So this bright coin came from a country\nplanted in the middle of the world, and beneath the great equator, and\nnamed after it; and it had been", "labels": {"50": 45, "100": 19, "250": 161, "500": 242, "1000": 730, "2000": 1814}}, {"id": 6340, "position": 6340, "text": "and beneath the great equator, and\nnamed after it; and it had been cast midway up the Andes, in the\nunwaning clime that knows no autumn. Zoned by those letters you saw the\nlikeness of three Andes’ summits; from", "labels": {"50": 12, "100": 19, "250": 78, "500": 379, "1000": 782, "2000": 636}}, {"id": 6341, "position": 6341, "text": "by those letters you saw the\nlikeness of three Andes’ summits; from one a flame; a tower on another;\non the third a crowing cock; while arching over all was a segment of\nthe partitioned zodiac, the signs all marked with", "labels": {"50": 9, "100": 66, "250": 211, "500": 475, "1000": 902, "2000": 1374}}, {"id": 6342, "position": 6342, "text": "all was a segment of\nthe partitioned zodiac, the signs all marked with their usual\ncabalistics, and the keystone sun entering the equinoctial point at\nLibra.\n\nBefore this equatorial coin, Ahab, not unobserved by others", "labels": {"50": 10, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1010}}, {"id": 6343, "position": 6343, "text": ".\n\nBefore this equatorial coin, Ahab, not unobserved by others, was now\npausing.\n\n“There’s something ever egotistical in mountain-tops and towers, and\nall other grand and lofty things; look here,—three", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6344, "position": 6344, "text": ", and\nall other grand and lofty things; look here,—three peaks as proud as\nLucifer. The firm tower, that is Ahab; the volcano, that is Ahab; the\ncourageous, the undaunted, and victorious fow", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 637, "2000": 39}}, {"id": 6345, "position": 6345, "text": "Ahab; the\ncourageous, the undaunted, and victorious fowl, that, too, is Ahab; all\nare Ahab; and this round gold is but the image of the rounder globe,\nwhich, like a magician’", "labels": {"50": 9, "100": 26, "250": 133, "500": 72, "1000": 437, "2000": 1620}}, {"id": 6346, "position": 6346, "text": "but the image of the rounder globe,\nwhich, like a magician’s glass, to each and every man in turn but\nmirrors back his own mysterious self. Great pains, small gains for\nthose who ask the world to solve them; it cannot", "labels": {"50": 1, "100": 49, "250": 128, "500": 415, "1000": 799, "2000": 522}}, {"id": 6347, "position": 6347, "text": ", small gains for\nthose who ask the world to solve them; it cannot solve itself. Methinks\nnow this coined sun wears a ruddy face; but see! aye, he enters the\nsign of storms, the equinox! and but", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 118, "2000": 193}}, {"id": 6348, "position": 6348, "text": ", he enters the\nsign of storms, the equinox! and but six months before he wheeled out\nof a former equinox at Aries! From storm to storm! So be it, then", "labels": {"50": 16, "100": 20, "250": 50, "500": 33, "1000": 862, "2000": 1403}}, {"id": 6349, "position": 6349, "text": "! So be it, then. Born\nin throes, ’tis fit that man should live in pains and die in pangs! So\nbe it, then! Here’s stout stuff for woe to work on", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 437, "2000": 1886}}, {"id": 6350, "position": 6350, "text": "’s stout stuff for woe to work on. So be it, then.”\n\n“No fairy fingers can have pressed the gold, but devil’s claws must\nhave left their mouldings there since yesterday,” murmured Starbuck to\nhimself", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6351, "position": 6351, "text": "left their mouldings there since yesterday,” murmured Starbuck to\nhimself, leaning against the bulwarks. “The old man seems to read\nBelshazzar’s awful writing. I have never marked the coin inspectingly", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 6352, "position": 6352, "text": "’s awful writing. I have never marked the coin inspectingly.\nHe goes below; let me read. A dark valley between three mighty,\nheaven-abiding peaks, that almost seem the Trinity, in some faint\nearthly symbol", "labels": {"50": 25, "100": 41, "250": 132, "500": 280, "1000": 533, "2000": 1849}}, {"id": 6353, "position": 6353, "text": ", that almost seem the Trinity, in some faint\nearthly symbol. So in this vale of Death, God girds us round; and over\nall our gloom, the sun of Righteousness still shines a beacon and a\nhope", "labels": {"50": 35, "100": 73, "250": 133, "500": 414, "1000": 136, "2000": 1470}}, {"id": 6354, "position": 6354, "text": "Righteousness still shines a beacon and a\nhope. If we bend down our eyes, the dark vale shows her mouldy soil;\nbut if we lift them, the bright sun meets our glance half way, to\ncheer", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 136, "2000": 709}}, {"id": 6355, "position": 6355, "text": "bright sun meets our glance half way, to\ncheer. Yet, oh, the great sun is no fixture; and if, at midnight, we\nwould fain snatch some sweet solace from him, we gaze for him in vain!\nThis coin speaks", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 193}}, {"id": 6356, "position": 6356, "text": "solace from him, we gaze for him in vain!\nThis coin speaks wisely, mildly, truly, but still sadly to me. I will\nquit it, lest Truth shake me falsely.”\n\n“There now’s the old Mogul,", "labels": {"50": 9, "100": 26, "250": 219, "500": 498, "1000": 317, "2000": 1087}}, {"id": 6357, "position": 6357, "text": "shake me falsely.”\n\n“There now’s the old Mogul,” soliloquized Stubb by the try-works, “he’s\nbeen twigging it; and there goes Starbuck from the same, and both with", "labels": {"50": 9, "100": 64, "250": 163, "500": 498, "1000": 54, "2000": 1620}}, {"id": 6358, "position": 6358, "text": "ging it; and there goes Starbuck from the same, and both with\nfaces which I should say might be somewhere within nine fathoms long.\nAnd all from looking at a piece of gold, which did I have it now on\nNegro Hill or", "labels": {"50": 41, "100": 21, "250": 215, "500": 281, "1000": 54, "2000": 1082}}, {"id": 6359, "position": 6359, "text": "a piece of gold, which did I have it now on\nNegro Hill or in Corlaer’s Hook, I’d not look at it very long ere\nspending it. Humph! in my poor, insignificant opinion, I regard this", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 6360, "position": 6360, "text": "it. Humph! in my poor, insignificant opinion, I regard this as\nqueer. I have seen doubloons before now in my voyagings; your doubloons\nof old Spain, your doubloons of Peru", "labels": {"50": 48, "100": 20, "250": 192, "500": 162, "1000": 9, "2000": 682}}, {"id": 6361, "position": 6361, "text": "doubloons\nof old Spain, your doubloons of Peru, your doubloons of Chili, your\ndoubloons of Bolivia, your doubloons of Popayan; with plenty of gold\nmoidores and pistol", "labels": {"50": 37, "100": 15, "250": 22, "500": 268, "1000": 785, "2000": 646}}, {"id": 6362, "position": 6362, "text": "loons of Popayan; with plenty of gold\nmoidores and pistoles, and joes, and half joes, and quarter joes. What\nthen should there be in this doubloon of the Equator that is so killing\nwonderful", "labels": {"50": 9, "100": 2, "250": 54, "500": 246, "1000": 491, "2000": 1345}}, {"id": 6363, "position": 6363, "text": "be in this doubloon of the Equator that is so killing\nwonderful? By Golconda! let me read it once. Halloa! here’s signs and\nwonders truly! That, now, is what old Bowditch in his", "labels": {"50": 16, "100": 73, "250": 193, "500": 498, "1000": 50, "2000": 421}}, {"id": 6364, "position": 6364, "text": "wonders truly! That, now, is what old Bowditch in his Epitome calls the\nzodiac, and what my almanac below calls ditto. I’ll get the almanac and\nas I have heard devils can be raised with Da", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6365, "position": 6365, "text": "get the almanac and\nas I have heard devils can be raised with Daboll’s arithmetic, I’ll try\nmy hand at raising a meaning out of these queer curvicues here with the\nMassachusetts calendar. Here’s the book", "labels": {"50": 24, "100": 40, "250": 50, "500": 33, "1000": 862, "2000": 1403}}, {"id": 6366, "position": 6366, "text": "curvicues here with the\nMassachusetts calendar. Here’s the book. Let’s see now. Signs and\nwonders; and the sun, he’s always among ’em. Hem, hem, hem; here they\nare—here they", "labels": {"50": 6, "100": 1, "250": 15, "500": 498, "1000": 50, "2000": 666}}, {"id": 6367, "position": 6367, "text": "’em. Hem, hem, hem; here they\nare—here they go—all alive:—Aries, or the Ram; Taurus, or the Bull and\nJimimi! here’s Gemini himself, or the Twins", "labels": {"50": 6, "100": 1, "250": 42, "500": 498, "1000": 50, "2000": 916}}, {"id": 6368, "position": 6368, "text": "Jimimi! here’s Gemini himself, or the Twins. Well; the sun he wheels\namong ’em. Aye, here on the coin he’s just crossing the threshold\nbetween two of twelve sitting-rooms all in a ring", "labels": {"50": 6, "100": 81, "250": 130, "500": 366, "1000": 719, "2000": 976}}, {"id": 6369, "position": 6369, "text": "threshold\nbetween two of twelve sitting-rooms all in a ring. Book! you lie there;\nthe fact is, you books must know your places. You’ll do to give us the\nbare words and facts, but we come in to supply the", "labels": {"50": 7, "100": 8, "250": 183, "500": 234, "1000": 798, "2000": 695}}, {"id": 6370, "position": 6370, "text": "give us the\nbare words and facts, but we come in to supply the thoughts. That’s my\nsmall experience, so far as the Massachusetts calendar, and Bowditch’s\nnavigator, and Daboll’s arithmetic go", "labels": {"50": 31, "100": 95, "250": 69, "500": 453, "1000": 581, "2000": 24}}, {"id": 6371, "position": 6371, "text": "’s\nnavigator, and Daboll’s arithmetic go. Signs and wonders, eh? Pity if\nthere is nothing wonderful in signs, and significant in wonders!\nThere’s a clue somewhere; wait a bit; hist—hark!", "labels": {"50": 9, "100": 26, "250": 42, "500": 498, "1000": 637, "2000": 916}}, {"id": 6372, "position": 6372, "text": "s a clue somewhere; wait a bit; hist—hark! By Jove, I have it!\nLook you, Doubloon, your zodiac here is the life of man in one round\nchapter; and now I’ll read", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 6373, "position": 6373, "text": "the life of man in one round\nchapter; and now I’ll read it off, straight out of the book. Come,\nAlmanack! To begin: there’s Aries, or the Ram—lecherous dog, he beg", "labels": {"50": 9, "100": 1, "250": 50, "500": 33, "1000": 587, "2000": 488}}, {"id": 6374, "position": 6374, "text": "s Aries, or the Ram—lecherous dog, he begets\nus; then, Taurus, or the Bull—he bumps us the first thing; then Gemini,\nor the Twins—that is, Virtue and Vice; we try", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 6375, "position": 6375, "text": "Gemini,\nor the Twins—that is, Virtue and Vice; we try to reach Virtue, when lo!\ncomes Cancer the Crab, and drags us back; and here, going from Virtue,\nLeo, a roaring Lion, lies in the path", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 437, "2000": 573}}, {"id": 6376, "position": 6376, "text": ", going from Virtue,\nLeo, a roaring Lion, lies in the path—he gives a few fierce bites and\nsurly dabs with his paw; we escape, and hail Virgo, the Virgin! that’s\nour first love; we", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 637, "2000": 39}}, {"id": 6377, "position": 6377, "text": "hail Virgo, the Virgin! that’s\nour first love; we marry and think to be happy for aye, when pop comes\nLibra, or the Scales—happiness weighed and found wanting; and while we\nare very sad about that, Lord", "labels": {"50": 16, "100": 73, "250": 120, "500": 441, "1000": 118, "2000": 1312}}, {"id": 6378, "position": 6378, "text": "weighed and found wanting; and while we\nare very sad about that, Lord! how we suddenly jump, as Scorpio, or the\nScorpion, stings us in the rear; we are curing the wound, when whang\ncome the arrows", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 27, "2000": 193}}, {"id": 6379, "position": 6379, "text": "rear; we are curing the wound, when whang\ncome the arrows all round; Sagittarius, or the Archer, is amusing\nhimself. As we pluck out the shafts, stand aside! here’s the\nbattering-ram", "labels": {"50": 32, "100": 90, "250": 121, "500": 74, "1000": 490, "2000": 1762}}, {"id": 6380, "position": 6380, "text": "out the shafts, stand aside! here’s the\nbattering-ram, Capricornus, or the Goat; full tilt, he comes rushing,\nand headlong we are tossed; when Aquarius, or the Water-bearer, pour", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 663, "2000": 1058}}, {"id": 6381, "position": 6381, "text": "we are tossed; when Aquarius, or the Water-bearer, pours\nout his whole deluge and drowns us; and to wind up with Pisces, or the\nFishes, we sleep", "labels": {"50": 9, "100": 82, "250": 30, "500": 244, "1000": 358, "2000": 1038}}, {"id": 6382, "position": 6382, "text": "or the\nFishes, we sleep. There’s a sermon now, writ in high heaven, and the\nsun goes through it every year, and yet comes out of it all alive and\nhearty. Jollily he, aloft there, wheels", "labels": {"50": 16, "100": 73, "250": 120, "500": 498, "1000": 174, "2000": 1886}}, {"id": 6383, "position": 6383, "text": "alive and\nhearty. Jollily he, aloft there, wheels through toil and trouble; and\nso, alow here, does jolly Stubb. Oh, jolly’s the word for aye! Adieu,\nDoubloon", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 6384, "position": 6384, "text": "jolly’s the word for aye! Adieu,\nDoubloon! But stop; here comes little King-Post; dodge round the\ntry-works, now, and let’s hear what he’ll have to say", "labels": {"50": 9, "100": 1, "250": 193, "500": 498, "1000": 50, "2000": 39}}, {"id": 6385, "position": 6385, "text": "and let’s hear what he’ll have to say. There; he’s\nbefore it; he’ll out with something presently. So, so; he’s beginning.”\n\n“I see nothing here, but a round thing made", "labels": {"50": 39, "100": 39, "250": 57, "500": 228, "1000": 798, "2000": 378}}, {"id": 6386, "position": 6386, "text": "s beginning.”\n\n“I see nothing here, but a round thing made of gold, and whoever raises\na certain whale, this round thing belongs to him. So, what’s all this\nstaring been about? It is worth sixteen dollars, that", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 54, "2000": 1620}}, {"id": 6387, "position": 6387, "text": "’s all this\nstaring been about? It is worth sixteen dollars, that’s true; and at\ntwo cents the cigar, that’s nine hundred and sixty cigars. I won’t\nsmoke dirty pipes like Stubb, but I like", "labels": {"50": 39, "100": 99, "250": 91, "500": 305, "1000": 488, "2000": 51}}, {"id": 6388, "position": 6388, "text": ". I won’t\nsmoke dirty pipes like Stubb, but I like cigars, and here’s nine\nhundred and sixty of them; so here goes Flask aloft to spy ’em out.”", "labels": {"50": 41, "100": 88, "250": 193, "500": 498, "1000": 54, "2000": 421}}, {"id": 6389, "position": 6389, "text": "oft to spy ’em out.”\n\n“Shall I call that wise or foolish, now; if it be really wise it has a\nfoolish look to it; yet, if it be really foolish, then has it a sort of\nwiseish look to", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 317, "2000": 1199}}, {"id": 6390, "position": 6390, "text": "it be really foolish, then has it a sort of\nwiseish look to it. But, avast; here comes our old Manxman—the old\nhearse-driver, he must have been, that is, before he took to the", "labels": {"50": 41, "100": 21, "250": 215, "500": 208, "1000": 516, "2000": 270}}, {"id": 6391, "position": 6391, "text": "driver, he must have been, that is, before he took to the sea.\nHe luffs up before the doubloon; halloa, and goes round on the other\nside of the mast; why, there’s a horse-", "labels": {"50": 41, "100": 21, "250": 91, "500": 229, "1000": 54, "2000": 1082}}, {"id": 6392, "position": 6392, "text": "the other\nside of the mast; why, there’s a horse-shoe nailed on that side; and\nnow he’s back again; what does that mean? Hark! he’s muttering—voice\nlike an old worn-out coffee", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 6393, "position": 6393, "text": "rk! he’s muttering—voice\nlike an old worn-out coffee-mill. Prick ears, and listen!”\n\n“If the White Whale be raised, it must be in a month and a day, when\nthe sun stands in some one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6394, "position": 6394, "text": "be in a month and a day, when\nthe sun stands in some one of these signs. I’ve studied signs, and know\ntheir marks; they were taught me two score years ago, by the old witch\nin Copenhagen", "labels": {"50": 18, "100": 87, "250": 219, "500": 437, "1000": 345, "2000": 1091}}, {"id": 6395, "position": 6395, "text": "score years ago, by the old witch\nin Copenhagen. Now, in what sign will the sun then be? The horse-shoe\nsign; for there it is, right opposite the gold. And what’s the\nhorse-shoe sign? The lion", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 707, "2000": 822}}, {"id": 6396, "position": 6396, "text": "the gold. And what’s the\nhorse-shoe sign? The lion is the horse-shoe sign—the roaring and\ndevouring lion. Ship, old ship! my old head shakes to think of thee.”", "labels": {"50": 39, "100": 99, "250": 57, "500": 305, "1000": 367, "2000": 274}}, {"id": 6397, "position": 6397, "text": "old head shakes to think of thee.”\n\n“There’s another rendering now; but still one text. All sorts of men in\none kind of world, you see. Dodge again! here comes Queequeg—all\ntattooing—looks", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6398, "position": 6398, "text": "Dodge again! here comes Queequeg—all\ntattooing—looks like the signs of the Zodiac himself. What says the\nCannibal? As I live he’s comparing notes; looking at his thigh bone;\nthinks the sun is in", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 24, "2000": 369}}, {"id": 6399, "position": 6399, "text": "s comparing notes; looking at his thigh bone;\nthinks the sun is in the thigh, or in the calf, or in the bowels, I\nsuppose, as the old women talk Surgeon’s Astronomy in the back country", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 1199}}, {"id": 6400, "position": 6400, "text": "women talk Surgeon’s Astronomy in the back country.\nAnd by Jove, he’s found something there in the vicinity of his thigh—I\nguess it’s Sagittarius, or the Archer", "labels": {"50": 37, "100": 12, "250": 91, "500": 475, "1000": 393, "2000": 677}}, {"id": 6401, "position": 6401, "text": "gittarius, or the Archer. No: he don’t know what to make\nof the doubloon; he takes it for an old button off some king’s\ntrowsers. But, aside again! here comes that ghost", "labels": {"50": 18, "100": 88, "250": 219, "500": 498, "1000": 627, "2000": 1091}}, {"id": 6402, "position": 6402, "text": "’s\ntrowsers. But, aside again! here comes that ghost-devil, Fedallah; tail\ncoiled out of sight as usual, oakum in the toes of his pumps as usual.\nWhat does he say, with that look of", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 6403, "position": 6403, "text": "of his pumps as usual.\nWhat does he say, with that look of his? Ah, only makes a sign to the\nsign and bows himself; there is a sun on the coin—fire worshipper,\ndepend upon it", "labels": {"50": 41, "100": 21, "250": 193, "500": 498, "1000": 849, "2000": 1082}}, {"id": 6404, "position": 6404, "text": "the coin—fire worshipper,\ndepend upon it. Ho! more and more. This way comes Pip—poor boy! would\nhe had died, or I; he’s half horrible to me. He too has been watching\nall of these interpreter", "labels": {"50": 6, "100": 1, "250": 42, "500": 498, "1000": 647, "2000": 666}}, {"id": 6405, "position": 6405, "text": "s half horrible to me. He too has been watching\nall of these interpreters—myself included—and look now, he comes to\nread, with that unearthly idiot face. Stand away again and hear him.\nHark!”", "labels": {"50": 5, "100": 30, "250": 40, "500": 160, "1000": 775, "2000": 1725}}, {"id": 6406, "position": 6406, "text": "face. Stand away again and hear him.\nHark!”\n\n“I look, you look, he looks; we look, ye look, they look.”\n\n“Upon my soul, he’s been studying Murray’s Grammar! Improving his", "labels": {"50": 41, "100": 31, "250": 228, "500": 208, "1000": 516, "2000": 699}}, {"id": 6407, "position": 6407, "text": "my soul, he’s been studying Murray’s Grammar! Improving his mind,\npoor fellow! But what’s that he says now—hist!”\n\n“I look, you look, he looks; we look, ye look, they", "labels": {"50": 41, "100": 31, "250": 215, "500": 208, "1000": 516, "2000": 1476}}, {"id": 6408, "position": 6408, "text": "look, you look, he looks; we look, ye look, they look.”\n\n“Why, he’s getting it by heart—hist! again.”\n\n“I look, you look, he looks; we look, ye look", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 6409, "position": 6409, "text": "“I look, you look, he looks; we look, ye look, they look.”\n\n“Well, that’s funny.”\n\n“And I, you, and he; and we, ye, and they, are all bats;", "labels": {"50": 23, "100": 88, "250": 57, "500": 100, "1000": 488, "2000": 1199}}, {"id": 6410, "position": 6410, "text": "and he; and we, ye, and they, are all bats; and I’m a\ncrow, especially when I stand a’top of this pine tree here. Caw! caw!\ncaw! caw! caw!", "labels": {"50": 41, "100": 21, "250": 215, "500": 276, "1000": 707, "2000": 822}}, {"id": 6411, "position": 6411, "text": "Caw! caw!\ncaw! caw! caw! caw! Ain’t I a crow? And where’s the scare-crow? There\nhe stands; two bones stuck into a pair of old trowsers,", "labels": {"50": 41, "100": 21, "250": 215, "500": 428, "1000": 333, "2000": 68}}, {"id": 6412, "position": 6412, "text": "he stands; two bones stuck into a pair of old trowsers, and two more\npoked into the sleeves of an old jacket.”\n\n“Wonder if he means me?—complimentary!—poor lad!—I could go hang\nmyself", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 967}}, {"id": 6413, "position": 6413, "text": "—complimentary!—poor lad!—I could go hang\nmyself. Any way, for the present, I’ll quit Pip’s vicinity. I can stand\nthe rest, for they have plain wits; but he’s too crazy-", "labels": {"50": 6, "100": 1, "250": 193, "500": 326, "1000": 849, "2000": 1479}}, {"id": 6414, "position": 6414, "text": "rest, for they have plain wits; but he’s too crazy-witty for my\nsanity. So, so, I leave him muttering.”\n\n“Here’s the ship’s navel, this doubloon here, and they", "labels": {"50": 9, "100": 64, "250": 193, "500": 180, "1000": 851, "2000": 1620}}, {"id": 6415, "position": 6415, "text": "ship’s navel, this doubloon here, and they are all on fire\nto unscrew it. But, unscrew your navel, and what’s the consequence?\nThen again, if it stays here, that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6416, "position": 6416, "text": "what’s the consequence?\nThen again, if it stays here, that is ugly, too, for when aught’s\nnailed to the mast it’s a sign that things grow desperate. Ha, ha! old\nAhab! the White", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6417, "position": 6417, "text": "that things grow desperate. Ha, ha! old\nAhab! the White Whale; he’ll nail ye! This is a pine tree. My father,\nin old Tolland county, cut down a pine tree once, and found a silver\nring", "labels": {"50": 12, "100": 43, "250": 95, "500": 344, "1000": 210, "2000": 657}}, {"id": 6418, "position": 6418, "text": "and county, cut down a pine tree once, and found a silver\nring grown over in it; some old darkey’s wedding ring. How did it get\nthere? And so they’ll say in the resurrection, when they come to fish", "labels": {"50": 41, "100": 21, "250": 215, "500": 276, "1000": 627, "2000": 1199}}, {"id": 6419, "position": 6419, "text": "And so they’ll say in the resurrection, when they come to fish\nup this old mast, and find a doubloon lodged in it, with bedded oysters\nfor the shaggy bark. Oh, the gold! the precious, precious", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6420, "position": 6420, "text": "s\nfor the shaggy bark. Oh, the gold! the precious, precious, gold! the\ngreen miser’ll hoard ye soon! Hish! hish! God goes ’mong the worlds\nblackberrying", "labels": {"50": 16, "100": 73, "250": 15, "500": 498, "1000": 174, "2000": 1003}}, {"id": 6421, "position": 6421, "text": "God goes ’mong the worlds\nblackberrying. Cook! ho, cook! and cook us! Jenny! hey, hey, hey, hey,\nhey, Jenny, Jenny! and get your hoe-cake done!”\n\n\nCHAPTER 100", "labels": {"50": 7, "100": 22, "250": 2, "500": 109, "1000": 688, "2000": 826}}, {"id": 6422, "position": 6422, "text": "! and get your hoe-cake done!”\n\n\nCHAPTER 100. Leg and Arm.\n\nThe Pequod, of Nantucket, Meets the Samuel Enderby, of London.\n\n“Ship, ahoy! Hast seen the White Whale?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6423, "position": 6423, "text": "London.\n\n“Ship, ahoy! Hast seen the White Whale?”\n\nSo cried Ahab, once more hailing a ship showing English colours,\nbearing down under the stern. Trumpet to mouth, the old man was\nstanding in his hoisted quarter", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6424, "position": 6424, "text": "stern. Trumpet to mouth, the old man was\nstanding in his hoisted quarter-boat, his ivory leg plainly revealed to\nthe stranger captain, who was carelessly reclining in his own boat’s\nbow", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6425, "position": 6425, "text": "his own boat’s\nbow. He was a darkly-tanned, burly, good-natured, fine-looking man, of\nsixty or thereabouts, dressed in a spacious roundabout, that hung round\nhim in festoons of blue pilot", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 693}}, {"id": 6426, "position": 6426, "text": "in a spacious roundabout, that hung round\nhim in festoons of blue pilot-cloth; and one empty arm of this jacket\nstreamed behind him like the broidered arm of a hussar’s surcoat.", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 313, "2000": 887}}, {"id": 6427, "position": 6427, "text": "a hussar’s surcoat.\n\n“Hast seen the White Whale?”\n\n“See you this?” and withdrawing it from the folds that had hidden it,\nhe held up a white arm of sperm whale bone, terminating in a wooden\nhead", "labels": {"50": 25, "100": 64, "250": 182, "500": 72, "1000": 533, "2000": 1620}}, {"id": 6428, "position": 6428, "text": "held up a white arm of sperm whale bone, terminating in a wooden\nhead like a mallet.\n\n“Man my boat!” cried Ahab, impetuously, and tossing about the oars near\nhim—“Stand by to lower!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6429, "position": 6429, "text": "tossing about the oars near\nhim—“Stand by to lower!”\n\nIn less than a minute, without quitting his little craft, he and his\ncrew were dropped to the water, and were soon alongside of the\nstranger", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 6430, "position": 6430, "text": "the water, and were soon alongside of the\nstranger. But here a curious difficulty presented itself. In the\nexcitement of the moment, Ahab had forgotten that since the loss of his\nleg he had never once stepped on board of any vessel at sea but", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6431, "position": 6431, "text": "his\nleg he had never once stepped on board of any vessel at sea but his\nown, and then it was always by an ingenious and very handy mechanical\ncontrivance peculiar to the Pequod, and a thing not to be rigged and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6432, "position": 6432, "text": "peculiar to the Pequod, and a thing not to be rigged and\nshipped in any other vessel at a moment’s warning. Now, it is no very\neasy matter for anybody—except those who are almost hourly used to it,\nlike whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6433, "position": 6433, "text": "for anybody—except those who are almost hourly used to it,\nlike whalemen—to clamber up a ship’s side from a boat on the open sea;\nfor the great swells now lift the boat high up towards the bul", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6434, "position": 6434, "text": "for the great swells now lift the boat high up towards the bulwarks,\nand then instantaneously drop it half way down to the kelson. So,\ndeprived of one leg, and the strange ship of course being altogether\nunsu", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 6435, "position": 6435, "text": "deprived of one leg, and the strange ship of course being altogether\nunsupplied with the kindly invention, Ahab now found himself abjectly\nreduced to a clumsy landsman again; hopelessly eyeing the uncertain\nchangeful height he could hardly", "labels": {"50": 22, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6436, "position": 6436, "text": "landsman again; hopelessly eyeing the uncertain\nchangeful height he could hardly hope to attain.\n\nIt has before been hinted, perhaps, that every little untoward\ncircumstance that befell him, and which indirectly sprang from his\nluckless mishap,", "labels": {"50": 44, "100": 37, "250": 229, "500": 481, "1000": 984, "2000": 425}}, {"id": 6437, "position": 6437, "text": "fell him, and which indirectly sprang from his\nluckless mishap, almost invariably irritated or exasperated Ahab. And\nin the present instance, all this was heightened by the sight of the\ntwo officers of the strange ship, leaning over the side,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6438, "position": 6438, "text": "sight of the\ntwo officers of the strange ship, leaning over the side, by the\nperpendicular ladder of nailed cleets there, and swinging towards him a\npair of tastefully-ornamented man-ropes; for at first they did not seem", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 6439, "position": 6439, "text": "-ornamented man-ropes; for at first they did not seem\nto bethink them that a one-legged man must be too much of a cripple to\nuse their sea bannisters", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 110}}, {"id": 6440, "position": 6440, "text": "use their sea bannisters. But this awkwardness only lasted a minute,\nbecause the strange captain, observing at a glance how affairs stood,\ncried out, “I see, I see!—avast heaving there! Jump, boys, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 6441, "position": 6441, "text": ", I see!—avast heaving there! Jump, boys, and swing\nover the cutting-tackle.”\n\nAs good luck would have it, they had had a whale alongside a day or two\nprevious, and the great tackles were still aloft", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6442, "position": 6442, "text": "alongside a day or two\nprevious, and the great tackles were still aloft, and the massive\ncurved blubber-hook, now clean and dry, was still attached to the end.\nThis was quickly lowered to Ahab, who at once comprehending", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6443, "position": 6443, "text": "end.\nThis was quickly lowered to Ahab, who at once comprehending it all,\nslid his solitary thigh into the curve of the hook (it was like sitting\nin the fluke of an anchor, or the crotch of an apple tree),", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6444, "position": 6444, "text": "fluke of an anchor, or the crotch of an apple tree), and then\ngiving the word, held himself fast, and at the same time also helped to\nhoist his own weight, by pulling hand-over-hand upon one of the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1028}}, {"id": 6445, "position": 6445, "text": "his own weight, by pulling hand-over-hand upon one of the running\nparts of the tackle. Soon he was carefully swung inside the high\nbulwarks, and gently landed upon the capstan head", "labels": {"50": 37, "100": 86, "250": 145, "500": 184, "1000": 959, "2000": 314}}, {"id": 6446, "position": 6446, "text": "gently landed upon the capstan head. With his ivory arm\nfrankly thrust forth in welcome, the other captain advanced, and Ahab,\nputting out his ivory leg, and crossing the ivory arm (like two\nsword-fish blades) cried out in his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6447, "position": 6447, "text": "the ivory arm (like two\nsword-fish blades) cried out in his walrus way, “Aye, aye, hearty! let\nus shake bones together!—an arm and a leg!—an arm that never can\nshrink, d’", "labels": {"50": 41, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1620}}, {"id": 6448, "position": 6448, "text": "arm and a leg!—an arm that never can\nshrink, d’ye see; and a leg that never can run. Where did’st thou see\nthe White Whale?—how long ago?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6449, "position": 6449, "text": "?—how long ago?”\n\n“The White Whale,” said the Englishman, pointing his ivory arm towards\nthe East, and taking a rueful sight along it, as if it had been a\ntelescope; “there I saw him, on the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6450, "position": 6450, "text": "if it had been a\ntelescope; “there I saw him, on the Line, last season.”\n\n“And he took that arm off, did he?” asked Ahab, now sliding down from\nthe capstan, and resting on the Englishman", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6451, "position": 6451, "text": "ab, now sliding down from\nthe capstan, and resting on the Englishman’s shoulder, as he did so.\n\n“Aye, he was the cause of it, at least; and that leg, too?”", "labels": {"50": 37, "100": 55, "250": 145, "500": 93, "1000": 661, "2000": 410}}, {"id": 6452, "position": 6452, "text": "least; and that leg, too?”\n\n“Spin me the yarn,” said Ahab; “how was it?”\n\n“It was the first time in my life that I ever cruised on the Line,”\nbegan the Englishman", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6453, "position": 6453, "text": "that I ever cruised on the Line,”\nbegan the Englishman. “I was ignorant of the White Whale at that time.\nWell, one day we lowered for a pod of four or five whales, and my boat\nfastened to one of them;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6454, "position": 6454, "text": "of four or five whales, and my boat\nfastened to one of them; a regular circus horse he was, too, that went\nmilling and milling round so, that my boat’s crew could only trim dish,\nby sitting all their sterns on", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1620}}, {"id": 6455, "position": 6455, "text": "’s crew could only trim dish,\nby sitting all their sterns on the outer gunwale. Presently up breaches\nfrom the bottom of the sea a bouncing great whale, with a milky-white\nhead and hump, all crows’ feet", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6456, "position": 6456, "text": ", with a milky-white\nhead and hump, all crows’ feet and wrinkles.”\n\n“It was he, it was he!” cried Ahab, suddenly letting out his suspended\nbreath.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6457, "position": 6457, "text": "letting out his suspended\nbreath.\n\n“And harpoons sticking in near his starboard fin.”\n\n“Aye, aye—they were mine—_my_ irons,” cried Ahab, exultingly—“but on!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6458, "position": 6458, "text": "Ahab, exultingly—“but on!”\n\n“Give me a chance, then,” said the Englishman, good-humoredly. “Well,\nthis old great-grandfather, with the white head and hump, runs all\naf", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6459, "position": 6459, "text": "great-grandfather, with the white head and hump, runs all\nafoam into the pod, and goes to snapping furiously at my fast-line!\n\n“Aye, I see!—wanted to part it; free the fast-fish—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6460, "position": 6460, "text": "I see!—wanted to part it; free the fast-fish—an old trick—I know\nhim.”\n\n“How it was exactly,” continued the one-armed commander, “I do not\nknow; but in biting the line,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6461, "position": 6461, "text": "armed commander, “I do not\nknow; but in biting the line, it got foul of his teeth, caught there\nsomehow; but we didn’t know it then; so that when we afterwards pulled\non the line, bounce we came plump on", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 6462, "position": 6462, "text": "so that when we afterwards pulled\non the line, bounce we came plump on to his hump! instead of the other\nwhale’s; that went off to windward, all fluking. Seeing how matters\nstood, and what a noble great whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6463, "position": 6463, "text": "all fluking. Seeing how matters\nstood, and what a noble great whale it was—the noblest and biggest I\never saw, sir, in my life—I resolved to capture him, spite of the\nboiling rage he seemed to be in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6464, "position": 6464, "text": "to capture him, spite of the\nboiling rage he seemed to be in. And thinking the hap-hazard line would\nget loose, or the tooth it was tangled to might draw (for I have a\ndevil of a boat’s crew for a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6465, "position": 6465, "text": "draw (for I have a\ndevil of a boat’s crew for a pull on a whale-line); seeing all this, I\nsay, I jumped into my first mate’s boat—Mr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6466, "position": 6466, "text": "mate’s boat—Mr. Mounttop’s here (by the\nway, Captain—Mounttop; Mounttop—the captain);—as I was saying, I jumped\ninto Mounttop’s boat, which, d’ye see", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 6467, "position": 6467, "text": "I jumped\ninto Mounttop’s boat, which, d’ye see, was gunwale and gunwale with\nmine, then; and snatching the first harpoon, let this old\ngreat-grandfather have it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6468, "position": 6468, "text": "oon, let this old\ngreat-grandfather have it. But, Lord, look you, sir—hearts and souls\nalive, man—the next instant, in a jiff, I was blind as a bat—both eyes\nout—all befo", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 6469, "position": 6469, "text": ", I was blind as a bat—both eyes\nout—all befogged and bedeadened with black foam—the whale’s tail\nlooming straight up out of it, perpendicular in the air, like a marble\nsteeple", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 6470, "position": 6470, "text": ", perpendicular in the air, like a marble\nsteeple. No use sterning all, then; but as I was groping at midday,\nwith a blinding sun, all crown-jewels; as I was groping, I say, after\nthe", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 1149}}, {"id": 6471, "position": 6471, "text": "crown-jewels; as I was groping, I say, after\nthe second iron, to toss it overboard—down comes the tail like a Lima\ntower, cutting my boat in two, leaving each half in splinters; and,\nflukes first", "labels": {"50": 25, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1192}}, {"id": 6472, "position": 6472, "text": "in two, leaving each half in splinters; and,\nflukes first, the white hump backed through the wreck, as though it was\nall chips. We all struck out. To escape his terrible flailings, I\nseized hold of my", "labels": {"50": 25, "100": 64, "250": 136, "500": 388, "1000": 313, "2000": 786}}, {"id": 6473, "position": 6473, "text": "out. To escape his terrible flailings, I\nseized hold of my harpoon-pole sticking in him, and for a moment clung\nto that like a sucking fish. But a combing sea dashed me off, and at\nthe same instant,", "labels": {"50": 25, "100": 64, "250": 125, "500": 72, "1000": 313, "2000": 1521}}, {"id": 6474, "position": 6474, "text": "But a combing sea dashed me off, and at\nthe same instant, the fish, taking one good dart forwards, went down\nlike a flash; and the barb of that cursed second iron towing along near\nme caught me here” (clapping his", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 6475, "position": 6475, "text": "that cursed second iron towing along near\nme caught me here” (clapping his hand just below his shoulder); “yes,\ncaught me just here, I say, and bore me down to Hell’s flames, I was\nthinking; when, when", "labels": {"50": 25, "100": 64, "250": 136, "500": 388, "1000": 313, "2000": 786}}, {"id": 6476, "position": 6476, "text": "me down to Hell’s flames, I was\nthinking; when, when, all of a sudden, thank the good God, the barb\nript its way along the flesh—clear along the whole length of my\narm—came out nigh", "labels": {"50": 9, "100": 26, "250": 141, "500": 180, "1000": 272, "2000": 1860}}, {"id": 6477, "position": 6477, "text": "flesh—clear along the whole length of my\narm—came out nigh my wrist, and up I floated;—and that gentleman there\nwill tell you the rest (by the way, captain—Dr", "labels": {"50": 25, "100": 64, "250": 163, "500": 180, "1000": 54, "2000": 786}}, {"id": 6478, "position": 6478, "text": "the way, captain—Dr. Bunger, ship’s surgeon:\nBunger, my lad,—the captain). Now, Bunger boy, spin your part of the\nyarn.”\n\nThe professional gentleman thus familiarly pointed out, had", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 6479, "position": 6479, "text": "of the\nyarn.”\n\nThe professional gentleman thus familiarly pointed out, had been all\nthe time standing near them, with nothing specific visible, to denote\nhis gentlemanly rank on board. His face was an exceedingly round but\nsober one; he was", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 6480, "position": 6480, "text": "board. His face was an exceedingly round but\nsober one; he was dressed in a faded blue woollen frock or shirt, and\npatched trowsers; and had thus far been dividing his attention between\na marlingspike he held", "labels": {"50": 39, "100": 88, "250": 57, "500": 228, "1000": 800, "2000": 42}}, {"id": 6481, "position": 6481, "text": "had thus far been dividing his attention between\na marlingspike he held in one hand, and a pill-box held in the other,\noccasionally casting a critical glance at the ivory limbs of the two\ncrippled captains", "labels": {"50": 23, "100": 88, "250": 219, "500": 180, "1000": 317, "2000": 1087}}, {"id": 6482, "position": 6482, "text": "the ivory limbs of the two\ncrippled captains. But, at his superior’s introduction of him to Ahab,\nhe politely bowed, and straightway went on to do his captain’s bidding.\n\n“It was a shocking bad wound,” began", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 6483, "position": 6483, "text": "captain’s bidding.\n\n“It was a shocking bad wound,” began the whale-surgeon; “and, taking my\nadvice, Captain Boomer here, stood our old Sammy—”\n\n“Samuel Enderby is the name of my ship,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6484, "position": 6484, "text": "Sammy—”\n\n“Samuel Enderby is the name of my ship,” interrupted the one-armed\ncaptain, addressing Ahab; “go on, boy.”\n\n“Stood our old Sammy off to the northward, to get out of the blazing", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 6485, "position": 6485, "text": "Stood our old Sammy off to the northward, to get out of the blazing\nhot weather there on the Line. But it was no use—I did all I could; sat\nup with him nights; was very severe with him in the matter of diet", "labels": {"50": 12, "100": 13, "250": 56, "500": 167, "1000": 922, "2000": 139}}, {"id": 6486, "position": 6486, "text": "up with him nights; was very severe with him in the matter of diet—”\n\n“Oh, very severe!” chimed in the patient himself; then suddenly\naltering his voice, “Drinking hot rum toddies with me every night, till\nhe couldn", "labels": {"50": 23, "100": 68, "250": 219, "500": 202, "1000": 141, "2000": 1975}}, {"id": 6487, "position": 6487, "text": ", “Drinking hot rum toddies with me every night, till\nhe couldn’t see to put on the bandages; and sending me to bed, half\nseas over, about three o’clock in the morning", "labels": {"50": 23, "100": 41, "250": 219, "500": 221, "1000": 851, "2000": 877}}, {"id": 6488, "position": 6488, "text": "three o’clock in the morning. Oh, ye stars! he sat up\nwith me indeed, and was very severe in my diet. Oh! a great watcher,\nand very dietetically severe, is Dr. Bunger", "labels": {"50": 8, "100": 28, "250": 175, "500": 158, "1000": 207, "2000": 711}}, {"id": 6489, "position": 6489, "text": "and very dietetically severe, is Dr. Bunger. (Bunger, you dog, laugh\nout! why don’t ye? You know you’re a precious jolly rascal.) But, heave\nahead, boy, I", "labels": {"50": 23, "100": 88, "250": 219, "500": 100, "1000": 307, "2000": 40}}, {"id": 6490, "position": 6490, "text": "precious jolly rascal.) But, heave\nahead, boy, I’d rather be killed by you than kept alive by any other\nman.”\n\n“My captain, you must have ere this perceived, respected sir”—said the\nimp", "labels": {"50": 25, "100": 64, "250": 136, "500": 180, "1000": 272, "2000": 1954}}, {"id": 6491, "position": 6491, "text": "you must have ere this perceived, respected sir”—said the\nimperturbable godly-looking Bunger, slightly bowing to Ahab—“is apt to\nbe facetious at times; he spins us many clever things of that", "labels": {"50": 23, "100": 64, "250": 219, "500": 180, "1000": 851, "2000": 1620}}, {"id": 6492, "position": 6492, "text": "to\nbe facetious at times; he spins us many clever things of that sort. But\nI may as well say—en passant, as the French remark—that I myself—that\nis to say, Jack Bunger, late of the reverend", "labels": {"50": 23, "100": 88, "250": 219, "500": 202, "1000": 851, "2000": 877}}, {"id": 6493, "position": 6493, "text": "myself—that\nis to say, Jack Bunger, late of the reverend clergy—am a strict total\nabstinence man; I never drink—”\n\n“Water!” cried the captain; “he never drinks it; it’s a sort", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 6494, "position": 6494, "text": "cried the captain; “he never drinks it; it’s a sort of fits to\nhim; fresh water throws him into the hydrophobia; but go on—go on with\nthe arm story.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 6495, "position": 6495, "text": "with\nthe arm story.”\n\n“Yes, I may as well,” said the surgeon, coolly. “I was about observing,\nsir, before Captain Boomer’s facetious interruption, that spite of my\nbest and severest endeavors,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 6496, "position": 6496, "text": "s facetious interruption, that spite of my\nbest and severest endeavors, the wound kept getting worse and worse;\nthe truth was, sir, it was as ugly gaping wound as surgeon ever saw;\nmore than two feet and several inches long", "labels": {"50": 20, "100": 17, "250": 101, "500": 120, "1000": 421, "2000": 1068}}, {"id": 6497, "position": 6497, "text": "as surgeon ever saw;\nmore than two feet and several inches long. I measured it with the lead\nline. In short, it grew black; I knew what was threatened, and off it\ncame. But I had no hand in shipping that ivory arm", "labels": {"50": 25, "100": 5, "250": 136, "500": 313, "1000": 51, "2000": 1456}}, {"id": 6498, "position": 6498, "text": "and off it\ncame. But I had no hand in shipping that ivory arm there; that thing is\nagainst all rule”—pointing at it with the marlingspike—“that is the\ncaptain’s work, not mine; he ordered the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 6499, "position": 6499, "text": "“that is the\ncaptain’s work, not mine; he ordered the carpenter to make it; he had\nthat club-hammer there put to the end, to knock some one’s brains out\nwith, I suppose, as he tried mine once", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 6500, "position": 6500, "text": "one’s brains out\nwith, I suppose, as he tried mine once. He flies into diabolical\npassions sometimes. Do ye see this dent, sir”—removing his hat, and\nbrushing aside his hair, and exposing a bowl-like", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 6501, "position": 6501, "text": "his hat, and\nbrushing aside his hair, and exposing a bowl-like cavity in his skull,\nbut which bore not the slightest scarry trace, or any token of ever\nhaving been a wound—“Well, the captain there will tell you how", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 6502, "position": 6502, "text": "having been a wound—“Well, the captain there will tell you how that\ncame here; he knows.”\n\n“No, I don’t,” said the captain, “but his mother did; he was born with\nit", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 851, "2000": 1495}}, {"id": 6503, "position": 6503, "text": ", “but his mother did; he was born with\nit. Oh, you solemn rogue, you—you Bunger! was there ever such another\nBunger in the watery world? Bunger, when you die, you ought to die in\npick", "labels": {"50": 23, "100": 87, "250": 219, "500": 221, "1000": 29, "2000": 1199}}, {"id": 6504, "position": 6504, "text": "world? Bunger, when you die, you ought to die in\npickle, you dog; you should be preserved to future ages, you rascal.”\n\n“What became of the White Whale?” now cried Ahab, who thus far", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6505, "position": 6505, "text": "became of the White Whale?” now cried Ahab, who thus far had been\nimpatiently listening to this by-play between the two Englishmen.\n\n“Oh!” cried the one-armed captain, “oh, yes! Well; after he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6506, "position": 6506, "text": "the one-armed captain, “oh, yes! Well; after he sounded, we\ndidn’t see him again for some time; in fact, as I before hinted, I\ndidn’t then know what whale it was that had served me", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6507, "position": 6507, "text": ", I\ndidn’t then know what whale it was that had served me such a trick,\ntill some time afterwards, when coming back to the Line, we heard about\nMoby Dick—as some call him—and then I knew it was he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6508, "position": 6508, "text": "y Dick—as some call him—and then I knew it was he.”\n\n“Did’st thou cross his wake again?”\n\n“Twice.”\n\n“But could not fasten?”\n\n“Didn’t want to try to: ain", "labels": {"50": 46, "100": 51, "250": 140, "500": 164, "1000": 168, "2000": 1206}}, {"id": 6509, "position": 6509, "text": "not fasten?”\n\n“Didn’t want to try to: ain’t one limb enough? What should I do without\nthis other arm? And I’m thinking Moby Dick doesn’t bite so much as he\nswallows.”", "labels": {"50": 11, "100": 21, "250": 207, "500": 53, "1000": 385, "2000": 361}}, {"id": 6510, "position": 6510, "text": "Moby Dick doesn’t bite so much as he\nswallows.”\n\n“Well, then,” interrupted Bunger, “give him your left arm for bait to\nget the right. Do you know, gentlemen”—very gravely and mathematically\nbowing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6511, "position": 6511, "text": "right. Do you know, gentlemen”—very gravely and mathematically\nbowing to each Captain in succession—“Do you know, gentlemen, that the\ndigestive organs of the whale are so inscrutably constructed by Divine\nProvidence, that it is", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6512, "position": 6512, "text": "whale are so inscrutably constructed by Divine\nProvidence, that it is quite impossible for him to completely digest\neven a man’s arm? And he knows it too. So that what you take for the\nWhite Whale’s malice is only his", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6513, "position": 6513, "text": "So that what you take for the\nWhite Whale’s malice is only his awkwardness. For he never means to\nswallow a single limb; he only thinks to terrify by feints. But\nsometimes he is like the old juggling fellow, formerly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6514, "position": 6514, "text": "feints. But\nsometimes he is like the old juggling fellow, formerly a patient of\nmine in Ceylon, that making believe swallow jack-knives, once upon a\ntime let one drop into him in good earnest, and there it stayed for a\ntwelve", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 627, "2000": 1087}}, {"id": 6515, "position": 6515, "text": "one drop into him in good earnest, and there it stayed for a\ntwelvemonth or more; when I gave him an emetic, and he heaved it up in\nsmall tacks, d’ye see", "labels": {"50": 8, "100": 65, "250": 224, "500": 10, "1000": 741, "2000": 1250}}, {"id": 6516, "position": 6516, "text": "tacks, d’ye see. No possible way for him to digest that\njack-knife, and fully incorporate it into his general bodily system.\nYes, Captain Boomer, if you are quick enough about it, and have a mind\nto pawn", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 6517, "position": 6517, "text": ", if you are quick enough about it, and have a mind\nto pawn one arm for the sake of the privilege of giving decent burial\nto the other, why in that case the arm is yours; only let the whale\nhave another chance at you shortly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6518, "position": 6518, "text": "the arm is yours; only let the whale\nhave another chance at you shortly, that’s all.”\n\n“No, thank ye, Bunger,” said the English Captain, “he’s welcome to the\narm he has, since I", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6519, "position": 6519, "text": "Captain, “he’s welcome to the\narm he has, since I can’t help it, and didn’t know him then; but not to\nanother one. No more White Whales for me; I’ve lowered for him once,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 6520, "position": 6520, "text": "No more White Whales for me; I’ve lowered for him once,\nand that has satisfied me. There would be great glory in killing him, I\nknow that; and there is a ship-load of precious sperm in him, but, ha", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6521, "position": 6521, "text": "there is a ship-load of precious sperm in him, but, hark\nye, he’s best let alone; don’t you think so, Captain?”—glancing at the\nivory leg.\n\n“He is", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 6522, "position": 6522, "text": "—glancing at the\nivory leg.\n\n“He is. But he will still be hunted, for all that. What is best let\nalone, that accursed thing is not always what least allures. He’s all a\nmagnet! How long", "labels": {"50": 30, "100": 8, "250": 183, "500": 234, "1000": 644, "2000": 1046}}, {"id": 6523, "position": 6523, "text": "always what least allures. He’s all a\nmagnet! How long since thou saw’st him last? Which way heading?”\n\n“Bless my soul, and curse the foul fiend’s,” cried Bunger, stoopingly", "labels": {"50": 41, "100": 88, "250": 219, "500": 498, "1000": 627, "2000": 1091}}, {"id": 6524, "position": 6524, "text": "the foul fiend’s,” cried Bunger, stoopingly\nwalking round Ahab, and like a dog, strangely snuffing; “this man’s\nblood—bring the thermometer!—it’s at the", "labels": {"50": 9, "100": 26, "250": 145, "500": 180, "1000": 345, "2000": 1620}}, {"id": 6525, "position": 6525, "text": "s\nblood—bring the thermometer!—it’s at the boiling point!—his pulse makes\nthese planks beat!—sir!”—taking a lancet from his pocket, and drawing\nnear to Ahab’s arm.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6526, "position": 6526, "text": "t from his pocket, and drawing\nnear to Ahab’s arm.\n\n“Avast!” roared Ahab, dashing him against the bulwarks—“Man the boat!\nWhich way heading?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6527, "position": 6527, "text": "Man the boat!\nWhich way heading?”\n\n“Good God!” cried the English Captain, to whom the question was put.\n“What’s the matter? He was heading east, I think.—Is your Captain\ncrazy?” whispering Fed", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 642, "2000": 1904}}, {"id": 6528, "position": 6528, "text": "heading east, I think.—Is your Captain\ncrazy?” whispering Fedallah.\n\nBut Fedallah, putting a finger on his lip, slid over the bulwarks to\ntake the boat’s steering oar, and Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6529, "position": 6529, "text": "warks to\ntake the boat’s steering oar, and Ahab, swinging the cutting-tackle\ntowards him, commanded the ship’s sailors to stand by to lower.\n\nIn a moment he was standing in the boat’s stern, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6530, "position": 6530, "text": ".\n\nIn a moment he was standing in the boat’s stern, and the Manilla men\nwere springing to their oars. In vain the English Captain hailed him.\nWith back to the stranger ship, and face set like a flint to his", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 730, "2000": 1904}}, {"id": 6531, "position": 6531, "text": "With back to the stranger ship, and face set like a flint to his own,\nAhab stood upright till alongside of the Pequod.\n\n\nCHAPTER 101. The Decanter.\n\nEre the English ship fades from sight, be it set down", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6532, "position": 6532, "text": "r.\n\nEre the English ship fades from sight, be it set down here, that she\nhailed from London, and was named after the late Samuel Enderby,\nmerchant of that city, the original of the famous whaling house of\nEnderby", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6533, "position": 6533, "text": "of that city, the original of the famous whaling house of\nEnderby & Sons; a house which in my poor whaleman’s opinion, comes not\nfar behind the united royal houses of the Tudors and Bourbons, in point\nof real", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6534, "position": 6534, "text": "united royal houses of the Tudors and Bourbons, in point\nof real historical interest. How long, prior to the year of our Lord\n1775, this great whaling house was in existence, my numerous\nfish-documents do not make plain; but in", "labels": {"50": 14, "100": 27, "250": 5, "500": 346, "1000": 953, "2000": 1731}}, {"id": 6535, "position": 6535, "text": "in existence, my numerous\nfish-documents do not make plain; but in that year (1775) it fitted out\nthe first English ships that ever regularly hunted the Sperm Whale;\nthough for some score of years previous (ever since 1726) our valiant\nCoffin", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6536, "position": 6536, "text": "though for some score of years previous (ever since 1726) our valiant\nCoffins and Maceys of Nantucket and the Vineyard had in large fleets\npursued that Leviathan, but only in the North and South Atlantic: not\nelsewhere", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6537, "position": 6537, "text": "only in the North and South Atlantic: not\nelsewhere. Be it distinctly recorded here, that the Nantucketers were\nthe first among mankind to harpoon with civilized steel the great Sperm\nWhale; and that for half a century they were the only people of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6538, "position": 6538, "text": "Sperm\nWhale; and that for half a century they were the only people of the\nwhole globe who so harpooned him.\n\nIn 1778, a fine ship, the Amelia, fitted out for the express purpose,\nand at the sole charge of the vigorous", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6539, "position": 6539, "text": "fitted out for the express purpose,\nand at the sole charge of the vigorous Enderbys, boldly rounded Cape\nHorn, and was the first among the nations to lower a whale-boat of any\nsort in the great South Sea", "labels": {"50": 45, "100": 29, "250": 138, "500": 48, "1000": 327, "2000": 887}}, {"id": 6540, "position": 6540, "text": "a whale-boat of any\nsort in the great South Sea. The voyage was a skilful and lucky one;\nand returning to her berth with her hold full of the precious sperm,\nthe Amelia’s example was soon followed by other ships,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6541, "position": 6541, "text": "precious sperm,\nthe Amelia’s example was soon followed by other ships, English and\nAmerican, and thus the vast Sperm Whale grounds of the Pacific were\nthrown open. But not content with this good deed, the indefatigable\nhouse again best", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6542, "position": 6542, "text": "content with this good deed, the indefatigable\nhouse again bestirred itself: Samuel and all his Sons—how many, their\nmother only knows—and under their immediate auspices, and partly, I\nthink, at their expense, the", "labels": {"50": 27, "100": 33, "250": 194, "500": 135, "1000": 503, "2000": 84}}, {"id": 6543, "position": 6543, "text": "their immediate auspices, and partly, I\nthink, at their expense, the British government was induced to send the\nsloop-of-war Rattler on a whaling voyage of discovery into the South\nSea. Commanded by a naval Post-Captain, the Rattle", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 1749}}, {"id": 6544, "position": 6544, "text": "into the South\nSea. Commanded by a naval Post-Captain, the Rattler made a rattling\nvoyage of it, and did some service; how much does not appear. But this\nis not all. In 1819, the same house fitted out a discovery", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 1950}}, {"id": 6545, "position": 6545, "text": "this\nis not all. In 1819, the same house fitted out a discovery whale ship\nof their own, to go on a tasting cruise to the remote waters of Japan.\nThat ship—well called the “Syren”—made a noble experimental cruise", "labels": {"50": 45, "100": 29, "250": 138, "500": 327, "1000": 327, "2000": 887}}, {"id": 6546, "position": 6546, "text": "ship—well called the “Syren”—made a noble experimental cruise; and\nit was thus that the great Japanese Whaling Ground first became\ngenerally known. The Syren in this famous voyage was commanded by a\nCaptain Coffin, a Nantucketer.", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 732, "2000": 1584}}, {"id": 6547, "position": 6547, "text": "this famous voyage was commanded by a\nCaptain Coffin, a Nantucketer.\n\nAll honor to the Enderbies, therefore, whose house, I think, exists to\nthe present day; though doubtless the original Samuel must long ago\nhave slipped his cable", "labels": {"50": 25, "100": 28, "250": 132, "500": 412, "1000": 727, "2000": 381}}, {"id": 6548, "position": 6548, "text": "day; though doubtless the original Samuel must long ago\nhave slipped his cable for the great South Sea of the other world.\n\nThe ship named after him was worthy of the honor, being a very fast\nsailer and a noble craft every way", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 327, "2000": 887}}, {"id": 6549, "position": 6549, "text": ", being a very fast\nsailer and a noble craft every way. I boarded her once at midnight\nsomewhere off the Patagonian coast, and drank good flip down in the\nforecastle. It was a fine gam we had, and they were", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 6550, "position": 6550, "text": "forecastle. It was a fine gam we had, and they were all trumps—every\nsoul on board. A short life to them, and a jolly death. And that fine\ngam I had—long, very long after old Ah", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1028}}, {"id": 6551, "position": 6551, "text": "And that fine\ngam I had—long, very long after old Ahab touched her planks with his\nivory heel—it minds me of the noble, solid, Saxon hospitality of that\nship; and may my parson forget me, and the", "labels": {"50": 9, "100": 26, "250": 133, "500": 73, "1000": 779, "2000": 16}}, {"id": 6552, "position": 6552, "text": "hospitality of that\nship; and may my parson forget me, and the devil remember me, if I ever\nlose sight of it. Flip? Did I say we had flip? Yes, and we flipped it\nat the rate of ten gallons the hour", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 6553, "position": 6553, "text": "? Yes, and we flipped it\nat the rate of ten gallons the hour; and when the squall came (for it’s\nsqually off there by Patagonia), and all hands—visitors and all—were\ncalled to reef", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 6554, "position": 6554, "text": "nia), and all hands—visitors and all—were\ncalled to reef topsails, we were so top-heavy that we had to swing each\nother aloft in bowlines; and we ignorantly furled the skirts of our\njackets into", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 851, "2000": 967}}, {"id": 6555, "position": 6555, "text": "bowlines; and we ignorantly furled the skirts of our\njackets into the sails, so that we hung there, reefed fast in the\nhowling gale, a warning example to all drunken tars. However, the masts\ndid not go overboard", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 6556, "position": 6556, "text": "to all drunken tars. However, the masts\ndid not go overboard; and by and by we scrambled down, so sober, that\nwe had to pass the flip again, though the savage salt spray bursting\ndown the forecastle scuttle,", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 6557, "position": 6557, "text": ", though the savage salt spray bursting\ndown the forecastle scuttle, rather too much diluted and pickled it to\nmy taste.\n\nThe beef was fine—tough, but with body in it. They said it was\nbull-beef; others", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 6558, "position": 6558, "text": "but with body in it. They said it was\nbull-beef; others, that it was dromedary beef; but I do not know, for\ncertain, how that was. They had dumplings too; small, but substantial,\nsymmetrical", "labels": {"50": 32, "100": 42, "250": 56, "500": 1, "1000": 222, "2000": 1689}}, {"id": 6559, "position": 6559, "text": "that was. They had dumplings too; small, but substantial,\nsymmetrically globular, and indestructible dumplings. I fancied that\nyou could feel them, and roll them about in you after they were\nswallowed", "labels": {"50": 25, "100": 41, "250": 91, "500": 150, "1000": 533, "2000": 251}}, {"id": 6560, "position": 6560, "text": "could feel them, and roll them about in you after they were\nswallowed. If you stooped over too far forward, you risked their\npitching out of you like billiard-balls. The bread—but that couldn’t be\nhelped; besides,", "labels": {"50": 1, "100": 80, "250": 190, "500": 186, "1000": 306, "2000": 1493}}, {"id": 6561, "position": 6561, "text": "balls. The bread—but that couldn’t be\nhelped; besides, it was an anti-scorbutic; in short, the bread\ncontained the only fresh fare they had. But the forecastle was not very\nlight, and it was", "labels": {"50": 45, "100": 64, "250": 212, "500": 21, "1000": 690, "2000": 401}}, {"id": 6562, "position": 6562, "text": "they had. But the forecastle was not very\nlight, and it was very easy to step over into a dark corner when you\nate it. But all in all, taking her from truck to helm, considering the\ndimensions of the cook’s boilers", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 1790}}, {"id": 6563, "position": 6563, "text": "her from truck to helm, considering the\ndimensions of the cook’s boilers, including his own live parchment\nboilers; fore and aft, I say, the Samuel Enderby was a jolly ship; of\ngood fare and plenty; fine flip and strong", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 6564, "position": 6564, "text": "was a jolly ship; of\ngood fare and plenty; fine flip and strong; crack fellows all, and\ncapital from boot heels to hat-band.\n\nBut why was it, think ye, that the Samuel Enderby, and some other\nEnglish whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6565, "position": 6565, "text": "think ye, that the Samuel Enderby, and some other\nEnglish whalers I know of—not all though—were such famous, hospitable\nships; that passed round the beef, and the bread, and the can, and the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6566, "position": 6566, "text": "passed round the beef, and the bread, and the can, and the\njoke; and were not soon weary of eating, and drinking, and laughing? I\nwill tell you. The abounding good cheer of these English whalers is\nmatter for", "labels": {"50": 45, "100": 64, "250": 55, "500": 388, "1000": 313, "2000": 887}}, {"id": 6567, "position": 6567, "text": ". The abounding good cheer of these English whalers is\nmatter for historical research. Nor have I been at all sparing of\nhistorical whale research, when it has seemed needed.\n\nThe English were preceded in the whale fishery by the Hollanders,", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6568, "position": 6568, "text": "needed.\n\nThe English were preceded in the whale fishery by the Hollanders,\nZealanders, and Danes; from whom they derived many terms still extant\nin the fishery; and what is yet more, their fat old fashions, touching\nplenty to eat and", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6569, "position": 6569, "text": "is yet more, their fat old fashions, touching\nplenty to eat and drink. For, as a general thing, the English\nmerchant-ship scrimps her crew; but not so the English whaler", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6570, "position": 6570, "text": "but not so the English whaler. Hence,\nin the English, this thing of whaling good cheer is not normal and\nnatural, but incidental and particular; and, therefore, must have some\nspecial origin, which is here pointed out, and will", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6571, "position": 6571, "text": ", must have some\nspecial origin, which is here pointed out, and will be still further\nelucidated.\n\nDuring my researches in the Leviathanic histories, I stumbled upon an\nancient Dutch volume, which, by the musty whaling smell of", "labels": {"50": 17, "100": 66, "250": 111, "500": 490, "1000": 622, "2000": 47}}, {"id": 6572, "position": 6572, "text": "upon an\nancient Dutch volume, which, by the musty whaling smell of it, I knew\nmust be about whalers. The title was, “Dan Coopman,” wherefore I\nconcluded that this must be the invaluable memoirs", "labels": {"50": 45, "100": 40, "250": 138, "500": 13, "1000": 995, "2000": 47}}, {"id": 6573, "position": 6573, "text": "wherefore I\nconcluded that this must be the invaluable memoirs of some Amsterdam\ncooper in the fishery, as every whale ship must carry its cooper. I was\nreinforced in this opinion by seeing that it was the production of one\n“Fitz Sw", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6574, "position": 6574, "text": "in this opinion by seeing that it was the production of one\n“Fitz Swackhammer.” But my friend Dr. Snodhead, a very learned man,\nprofessor of Low Dutch and High German in the college of Santa Claus\nand St", "labels": {"50": 44, "100": 68, "250": 1, "500": 202, "1000": 258, "2000": 47}}, {"id": 6575, "position": 6575, "text": "of Low Dutch and High German in the college of Santa Claus\nand St. Pott’s, to whom I handed the work for translation, giving him a\nbox of sperm candles for his trouble—this same Dr", "labels": {"50": 25, "100": 28, "250": 169, "500": 59, "1000": 576, "2000": 184}}, {"id": 6576, "position": 6576, "text": "candles for his trouble—this same Dr. Snodhead, so soon as\nhe spied the book, assured me that “Dan Coopman” did not mean “The\nCooper,” but “The Merchant.” In short, this ancient", "labels": {"50": 39, "100": 88, "250": 70, "500": 163, "1000": 383, "2000": 1563}}, {"id": 6577, "position": 6577, "text": "The\nCooper,” but “The Merchant.” In short, this ancient and learned Low\nDutch book treated of the commerce of Holland; and, among other\nsubjects, contained a very interesting account of its whale fishery", "labels": {"50": 44, "100": 76, "250": 53, "500": 261, "1000": 995, "2000": 47}}, {"id": 6578, "position": 6578, "text": "very interesting account of its whale fishery.\nAnd in this chapter it was, headed, “Smeer,” or “Fat,” that I found a\nlong detailed list of the outfits for the larders and cellars of 180\nsail of Dutch", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6579, "position": 6579, "text": "the outfits for the larders and cellars of 180\nsail of Dutch whalemen; from which list, as translated by Dr. Snodhead,\nI transcribe the following:\n\n400,000 lbs. of beef", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 364, "2000": 1620}}, {"id": 6580, "position": 6580, "text": "ibe the following:\n\n400,000 lbs. of beef. 60,000 lbs. Friesland pork. 150,000 lbs. of stock\nfish. 550,000 lbs. of biscuit. 72,000 lbs. of soft bread", "labels": {"50": 21, "100": 76, "250": 32, "500": 131, "1000": 245, "2000": 1121}}, {"id": 6581, "position": 6581, "text": "of biscuit. 72,000 lbs. of soft bread. 2,800 firkins\nof butter. 20,000 lbs. Texel & Leyden cheese. 144,000 lbs. cheese\n(probably an inferior article)", "labels": {"50": 42, "100": 59, "250": 10, "500": 430, "1000": 997, "2000": 306}}, {"id": 6582, "position": 6582, "text": "000 lbs. cheese\n(probably an inferior article). 550 ankers of Geneva. 10,800 barrels of\nbeer.\n\nMost statistical tables are parchingly dry in the reading; not so in\nthe present case, however, where the reader is flooded", "labels": {"50": 21, "100": 76, "250": 32, "500": 37, "1000": 815, "2000": 1903}}, {"id": 6583, "position": 6583, "text": "; not so in\nthe present case, however, where the reader is flooded with whole\npipes, barrels, quarts, and gills of good gin and good cheer.\n\nAt the time, I devoted three days to the studious digesting of all this", "labels": {"50": 25, "100": 28, "250": 193, "500": 412, "1000": 849, "2000": 381}}, {"id": 6584, "position": 6584, "text": "time, I devoted three days to the studious digesting of all this\nbeer, beef, and bread, during which many profound thoughts were\nincidentally suggested to me, capable of a transcendental and Platonic\napplication; and, furthermore, I", "labels": {"50": 20, "100": 28, "250": 132, "500": 412, "1000": 773, "2000": 1278}}, {"id": 6585, "position": 6585, "text": "of a transcendental and Platonic\napplication; and, furthermore, I compiled supplementary tables of my\nown, touching the probable quantity of stock-fish, etc., consumed by\nevery Low Dutch harpooneer in that ancient Greenland and Spitzberg", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6586, "position": 6586, "text": "by\nevery Low Dutch harpooneer in that ancient Greenland and Spitzbergen\nwhale fishery. In the first place, the amount of butter, and Texel and\nLeyden cheese consumed, seems amazing. I impute it, though, to their", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6587, "position": 6587, "text": "cheese consumed, seems amazing. I impute it, though, to their\nnaturally unctuous natures, being rendered still more unctuous by the\nnature of their vocation, and especially by their pursuing their game\nin those frigid Polar", "labels": {"50": 31, "100": 7, "250": 193, "500": 496, "1000": 290, "2000": 962}}, {"id": 6588, "position": 6588, "text": "cation, and especially by their pursuing their game\nin those frigid Polar Seas, on the very coasts of that Esquimaux\ncountry where the convivial natives pledge each other in bumpers of\ntrain oil.", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6589, "position": 6589, "text": "each other in bumpers of\ntrain oil.\n\nThe quantity of beer, too, is very large, 10,800 barrels. Now, as those\npolar fisheries could only be prosecuted in the short summer of that\nclimate, so that the whole cruise of one", "labels": {"50": 42, "100": 63, "250": 138, "500": 72, "1000": 825, "2000": 447}}, {"id": 6590, "position": 6590, "text": "in the short summer of that\nclimate, so that the whole cruise of one of these Dutch whalemen,\nincluding the short voyage to and from the Spitzbergen sea, did not\nmuch exceed three months, say, and reckoning 30 men to", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 327, "2000": 1620}}, {"id": 6591, "position": 6591, "text": "did not\nmuch exceed three months, say, and reckoning 30 men to each of their\nfleet of 180 sail, we have 5,400 Low Dutch seamen in all; therefore, I\nsay, we have precisely two barrels of beer per man, for", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 327, "2000": 1584}}, {"id": 6592, "position": 6592, "text": ", I\nsay, we have precisely two barrels of beer per man, for a twelve weeks’\nallowance, exclusive of his fair proportion of that 550 ankers of gin.\nNow, whether these gin and beer harpooneers, so fuddled as one", "labels": {"50": 45, "100": 64, "250": 193, "500": 16, "1000": 846, "2000": 756}}, {"id": 6593, "position": 6593, "text": ", whether these gin and beer harpooneers, so fuddled as one might\nfancy them to have been, were the right sort of men to stand up in a\nboat’s head, and take good aim at flying whales; this would seem\nsomewhat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6594, "position": 6594, "text": "s head, and take good aim at flying whales; this would seem\nsomewhat improbable. Yet they did aim at them, and hit them too. But\nthis was very far North, be it remembered, where beer agrees well with\nthe constitution", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6595, "position": 6595, "text": "very far North, be it remembered, where beer agrees well with\nthe constitution; upon the Equator, in our southern fishery, beer would\nbe apt to make the harpooneer sleepy at the mast-head and boozy in his\nboat; and gr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6596, "position": 6596, "text": "sleepy at the mast-head and boozy in his\nboat; and grievous loss might ensue to Nantucket and New Bedford.\n\nBut no more; enough has been said to show that the old Dutch whalers of\ntwo or three", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6597, "position": 6597, "text": "has been said to show that the old Dutch whalers of\ntwo or three centuries ago were high livers; and that the English\nwhalers have not neglected so excellent an example. For, say they, when\ncruising in an empty ship, if you", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6598, "position": 6598, "text": ". For, say they, when\ncruising in an empty ship, if you can get nothing better out of the\nworld, get a good dinner out of it, at least. And this empties the\ndecanter.\n\n\nCHAPTER 102", "labels": {"50": 31, "100": 7, "250": 159, "500": 453, "1000": 387, "2000": 1107}}, {"id": 6599, "position": 6599, "text": "And this empties the\ndecanter.\n\n\nCHAPTER 102. A Bower in the Arsacides.\n\nHitherto, in descriptively treating of the Sperm Whale, I have chiefly\ndwelt upon the marvels of his outer aspect;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6600, "position": 6600, "text": "I have chiefly\ndwelt upon the marvels of his outer aspect; or separately and in detail\nupon some few interior structural features. But to a large and thorough\nsweeping comprehension of him, it behooves me now to unbutton him", "labels": {"50": 25, "100": 64, "250": 219, "500": 72, "1000": 851, "2000": 1620}}, {"id": 6601, "position": 6601, "text": "of him, it behooves me now to unbutton him still\nfurther, and untagging the points of his hose, unbuckling his garters,\nand casting loose the hooks and the eyes of the joints of his inner", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 39}}, {"id": 6602, "position": 6602, "text": ",\nand casting loose the hooks and the eyes of the joints of his innermost\nbones, set him before you in his ultimatum; that is to say, in his\nunconditional skeleton.\n\nBut how now, Ishmael? How is it,", "labels": {"50": 22, "100": 55, "250": 52, "500": 72, "1000": 345, "2000": 1620}}, {"id": 6603, "position": 6603, "text": "ditional skeleton.\n\nBut how now, Ishmael? How is it, that you, a mere oarsman in the\nfishery, pretend to know aught about the subterranean parts of the\nwhale? Did erudite Stubb, mounted upon your", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6604, "position": 6604, "text": "parts of the\nwhale? Did erudite Stubb, mounted upon your capstan, deliver lectures\non the anatomy of the Cetacea; and by help of the windlass, hold up a\nspecimen rib for exhibition? Explain thyself,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6605, "position": 6605, "text": "lass, hold up a\nspecimen rib for exhibition? Explain thyself, Ishmael. Can you land a\nfull-grown whale on your deck for examination, as a cook dishes a\nroast-pig? Surely not", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6606, "position": 6606, "text": "cook dishes a\nroast-pig? Surely not. A veritable witness have you hitherto been,\nIshmael; but have a care how you seize the privilege of Jonah alone;\nthe privilege of discoursing upon the joists and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6607, "position": 6607, "text": "of Jonah alone;\nthe privilege of discoursing upon the joists and beams; the rafters,\nridge-pole, sleepers, and under-pinnings, making up the frame-work of\nleviathan; and belike of the tall", "labels": {"50": 31, "100": 20, "250": 193, "500": 498, "1000": 747, "2000": 1620}}, {"id": 6608, "position": 6608, "text": "up the frame-work of\nleviathan; and belike of the tallow-vats, dairy-rooms, butteries, and\ncheeseries in his bowels.\n\nI confess, that since Jonah, few whalemen have penetrated very far\nbeneath", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6609, "position": 6609, "text": "I confess, that since Jonah, few whalemen have penetrated very far\nbeneath the skin of the adult whale; nevertheless, I have been blessed\nwith an opportunity to dissect him in miniature. In a ship I belonged\nto, a small cub Sperm", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6610, "position": 6610, "text": "him in miniature. In a ship I belonged\nto, a small cub Sperm Whale was once bodily hoisted to the deck for his\npoke or bag, to make sheaths for the barbs of the harpoons, and for the\nheads of the lances", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6611, "position": 6611, "text": "barbs of the harpoons, and for the\nheads of the lances. Think you I let that chance go, without using my\nboat-hatchet and jack-knife, and breaking the seal and reading all the\ncontents of that young cub?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 723, "2000": 1620}}, {"id": 6612, "position": 6612, "text": ", and breaking the seal and reading all the\ncontents of that young cub?\n\nAnd as for my exact knowledge of the bones of the leviathan in their\ngigantic, full grown development, for that rare knowledge I am indebted\nto my late royal friend", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6613, "position": 6613, "text": ", for that rare knowledge I am indebted\nto my late royal friend Tranquo, king of Tranque, one of the Arsacides.\nFor being at Tranque, years ago, when attached to the trading-ship Dey\nof", "labels": {"50": 8, "100": 56, "250": 18, "500": 349, "1000": 34, "2000": 136}}, {"id": 6614, "position": 6614, "text": "que, years ago, when attached to the trading-ship Dey\nof Algiers, I was invited to spend part of the Arsacidean holidays with\nthe lord of Tranque, at his retired palm villa at Pupella; a sea-side", "labels": {"50": 45, "100": 0, "250": 233, "500": 55, "1000": 523, "2000": 674}}, {"id": 6615, "position": 6615, "text": "que, at his retired palm villa at Pupella; a sea-side\nglen not very far distant from what our sailors called Bamboo-Town, his\ncapital.\n\nAmong many other fine qualities, my royal friend Tranquo, being gifted\nwith a devout", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1495}}, {"id": 6616, "position": 6616, "text": "fine qualities, my royal friend Tranquo, being gifted\nwith a devout love for all matters of barbaric vertu, had brought\ntogether in Pupella whatever rare things the more ingenious of his\npeople could invent; chiefly carved", "labels": {"50": 20, "100": 56, "250": 125, "500": 349, "1000": 651, "2000": 1586}}, {"id": 6617, "position": 6617, "text": "things the more ingenious of his\npeople could invent; chiefly carved woods of wonderful devices,\nchiselled shells, inlaid spears, costly paddles, aromatic canoes; and\nall these distributed among whatever natural wonders, the\nwonder-freight", "labels": {"50": 0, "100": 91, "250": 188, "500": 267, "1000": 32, "2000": 164}}, {"id": 6618, "position": 6618, "text": "s; and\nall these distributed among whatever natural wonders, the\nwonder-freighted, tribute-rendering waves had cast upon his shores.\n\nChief among these latter was a great Sperm Whale, which, after an\nunusually long raging gale, had been found dead", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6619, "position": 6619, "text": "Whale, which, after an\nunusually long raging gale, had been found dead and stranded, with his\nhead against a cocoa-nut tree, whose plumage-like, tufted droopings\nseemed his verdant jet", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6620, "position": 6620, "text": "droopings\nseemed his verdant jet. When the vast body had at last been stripped of\nits fathom-deep enfoldings, and the bones become dust dry in the sun,\nthen the skeleton was carefully transported up the Pupella glen", "labels": {"50": 25, "100": 5, "250": 26, "500": 412, "1000": 533, "2000": 187}}, {"id": 6621, "position": 6621, "text": "in the sun,\nthen the skeleton was carefully transported up the Pupella glen, where\na grand temple of lordly palms now sheltered it.\n\nThe ribs were hung with trophies; the vertebræ were carved with\nArsacidean annals, in", "labels": {"50": 48, "100": 27, "250": 249, "500": 370, "1000": 375, "2000": 965}}, {"id": 6622, "position": 6622, "text": "the vertebræ were carved with\nArsacidean annals, in strange hieroglyphics; in the skull, the priests\nkept up an unextinguished aromatic flame, so that the mystic head again\nsent forth its vapory", "labels": {"50": 16, "100": 78, "250": 205, "500": 380, "1000": 890, "2000": 1027}}, {"id": 6623, "position": 6623, "text": "hed aromatic flame, so that the mystic head again\nsent forth its vapory spout; while, suspended from a bough, the\nterrific lower jaw vibrated over all the devotees, like the hair-hung\nsword that so affrighted Damoc", "labels": {"50": 9, "100": 26, "250": 240, "500": 365, "1000": 517, "2000": 1208}}, {"id": 6624, "position": 6624, "text": ", like the hair-hung\nsword that so affrighted Damocles.\n\nIt was a wondrous sight. The wood was green as mosses of the Icy Glen;\nthe trees stood high and haughty, feeling their living sap", "labels": {"50": 26, "100": 82, "250": 240, "500": 332, "1000": 469, "2000": 1330}}, {"id": 6625, "position": 6625, "text": "Glen;\nthe trees stood high and haughty, feeling their living sap; the\nindustrious earth beneath was as a weaver’s loom, with a gorgeous\ncarpet on it, whereof the ground-vine tendrils formed the warp", "labels": {"50": 16, "100": 26, "250": 240, "500": 406, "1000": 779, "2000": 471}}, {"id": 6626, "position": 6626, "text": "on it, whereof the ground-vine tendrils formed the warp and\nwoof, and the living flowers the figures. All the trees, with all their\nladen branches; all the shrubs, and ferns, and grasses; the\nmessage-carrying", "labels": {"50": 16, "100": 81, "250": 3, "500": 380, "1000": 67, "2000": 874}}, {"id": 6627, "position": 6627, "text": "; all the shrubs, and ferns, and grasses; the\nmessage-carrying air; all these unceasingly were active. Through the\nlacings of the leaves, the great sun seemed a flying shuttle weaving\nthe unwearied verdure", "labels": {"50": 19, "100": 80, "250": 53, "500": 401, "1000": 252, "2000": 280}}, {"id": 6628, "position": 6628, "text": "great sun seemed a flying shuttle weaving\nthe unwearied verdure. Oh, busy weaver! unseen weaver!—pause!—one\nword!—whither flows the fabric? what palace may it deck? wherefore all\nthese cease", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 437, "2000": 573}}, {"id": 6629, "position": 6629, "text": "the fabric? what palace may it deck? wherefore all\nthese ceaseless toilings? Speak, weaver!—stay thy hand!—but one single\nword with thee! Nay—the shuttle flies—the figures float from forth the\nlo", "labels": {"50": 9, "100": 73, "250": 133, "500": 122, "1000": 663, "2000": 573}}, {"id": 6630, "position": 6630, "text": "thee! Nay—the shuttle flies—the figures float from forth the\nloom; the freshet-rushing carpet for ever slides away. The weaver-god,\nhe weaves; and by that weaving is he deafened, that he hears no", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 573}}, {"id": 6631, "position": 6631, "text": "s; and by that weaving is he deafened, that he hears no mortal\nvoice; and by that humming, we, too, who look on the loom are deafened;\nand only when we escape it shall we hear the thousand voices that", "labels": {"50": 9, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 573}}, {"id": 6632, "position": 6632, "text": "ened;\nand only when we escape it shall we hear the thousand voices that speak\nthrough it. For even so it is in all material factories. The spoken\nwords that are inaudible among the flying spindles; those same words\nare plainly heard without", "labels": {"50": 16, "100": 20, "250": 26, "500": 414, "1000": 914, "2000": 150}}, {"id": 6633, "position": 6633, "text": "udible among the flying spindles; those same words\nare plainly heard without the walls, bursting from the opened\ncasements. Thereby have villainies been detected. Ah, mortal! then, be\nheedful; for so, in all this din", "labels": {"50": 9, "100": 73, "250": 133, "500": 19, "1000": 499, "2000": 629}}, {"id": 6634, "position": 6634, "text": "! then, be\nheedful; for so, in all this din of the great world’s loom, thy\nsubtlest thinkings may be overheard afar.\n\nNow, amid the green, life-restless loom of that Arsacide", "labels": {"50": 9, "100": 26, "250": 133, "500": 307, "1000": 343, "2000": 761}}, {"id": 6635, "position": 6635, "text": ", amid the green, life-restless loom of that Arsacidean wood, the\ngreat, white, worshipped skeleton lay lounging—a gigantic idler! Yet,\nas the ever-woven verdant warp and woof intermi", "labels": {"50": 16, "100": 73, "250": 133, "500": 126, "1000": 727, "2000": 970}}, {"id": 6636, "position": 6636, "text": ",\nas the ever-woven verdant warp and woof intermixed and hummed around\nhim, the mighty idler seemed the cunning weaver; himself all woven over\nwith the vines; every month assuming greener, fresher verdure;", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 118, "2000": 523}}, {"id": 6637, "position": 6637, "text": "the vines; every month assuming greener, fresher verdure; but\nhimself a skeleton. Life folded Death; Death trellised Life; the grim\ngod wived with youthful Life, and begat him curly-headed glories.", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 118, "2000": 523}}, {"id": 6638, "position": 6638, "text": "with youthful Life, and begat him curly-headed glories.\n\nNow, when with royal Tranquo I visited this wondrous whale, and saw the\nskull an altar, and the artificial smoke ascending from where the real\njet had issued", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6639, "position": 6639, "text": "an altar, and the artificial smoke ascending from where the real\njet had issued, I marvelled that the king should regard a chapel as an\nobject of vertu. He laughed. But more I marvelled that the priests\nshould swear that smoky jet", "labels": {"50": 9, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1860}}, {"id": 6640, "position": 6640, "text": "laughed. But more I marvelled that the priests\nshould swear that smoky jet of his was genuine. To and fro I paced\nbefore this skeleton—brushed the vines aside—broke through the ribs—and\nwith a ball of Arsacidean twin", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 930, "2000": 1657}}, {"id": 6641, "position": 6641, "text": "broke through the ribs—and\nwith a ball of Arsacidean twine, wandered, eddied long amid its many\nwinding, shaded colonnades and arbours. But soon my line was out; and\nfollowing it back, I emerged", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 377}}, {"id": 6642, "position": 6642, "text": ". But soon my line was out; and\nfollowing it back, I emerged from the opening where I entered. I saw no\nliving thing within; naught was there but bones.\n\nCutting me a green measuring-rod, I once more dived within", "labels": {"50": 25, "100": 5, "250": 26, "500": 72, "1000": 825, "2000": 1225}}, {"id": 6643, "position": 6643, "text": ".\n\nCutting me a green measuring-rod, I once more dived within the\nskeleton. From their arrow-slit in the skull, the priests perceived me\ntaking the altitude of the final rib, “How now!” they shouted; “Dar’", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 930, "2000": 377}}, {"id": 6644, "position": 6644, "text": "the final rib, “How now!” they shouted; “Dar’st\nthou measure this our god! That’s for us.” “Aye, priests—well, how long\ndo ye make him, then?” But hereupon", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 6645, "position": 6645, "text": ", how long\ndo ye make him, then?” But hereupon a fierce contest rose among them,\nconcerning feet and inches; they cracked each other’s sconces with\ntheir yard-sticks—the great skull echoed—and seizing that", "labels": {"50": 18, "100": 87, "250": 219, "500": 180, "1000": 627, "2000": 1091}}, {"id": 6646, "position": 6646, "text": "ces with\ntheir yard-sticks—the great skull echoed—and seizing that lucky chance,\nI quickly concluded my own admeasurements.\n\nThese admeasurements I now propose to set before you", "labels": {"50": 48, "100": 20, "250": 192, "500": 126, "1000": 727, "2000": 1710}}, {"id": 6647, "position": 6647, "text": "I now propose to set before you. But first, be it\nrecorded, that, in this matter, I am not free to utter any fancied\nmeasurement I please. Because there are skeleton authorities you can\nrefer to, to test my accuracy", "labels": {"50": 3, "100": 70, "250": 14, "500": 118, "1000": 478, "2000": 415}}, {"id": 6648, "position": 6648, "text": "Because there are skeleton authorities you can\nrefer to, to test my accuracy. There is a Leviathanic Museum, they tell\nme, in Hull, England, one of the whaling ports of that country, where\nthey have some fine specimens of fin-", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 956, "2000": 952}}, {"id": 6649, "position": 6649, "text": "whaling ports of that country, where\nthey have some fine specimens of fin-backs and other whales. Likewise,\nI have heard that in the museum of Manchester, in New Hampshire, they\nhave what the proprietors call “the only perfect specimen of a", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6650, "position": 6650, "text": ", they\nhave what the proprietors call “the only perfect specimen of a\nGreenland or River Whale in the United States.” Moreover, at a place in\nYorkshire, England, Burton Constable by name, a certain Sir Clifford\nConstable has in his possession the", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 886, "2000": 145}}, {"id": 6651, "position": 6651, "text": "Burton Constable by name, a certain Sir Clifford\nConstable has in his possession the skeleton of a Sperm Whale, but of\nmoderate size, by no means of the full-grown magnitude of my friend\nKing Tranquo’s.", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 1620}}, {"id": 6652, "position": 6652, "text": "of my friend\nKing Tranquo’s.\n\nIn both cases, the stranded whales to which these two skeletons\nbelonged, were originally claimed by their proprietors upon similar\ngrounds. King Tranquo seizing his because he wanted it; and Sir\nClifford,", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6653, "position": 6653, "text": "King Tranquo seizing his because he wanted it; and Sir\nClifford, because he was lord of the seignories of those parts. Sir\nClifford’s whale has been articulated throughout; so that, like a great\nchest of drawers, you can", "labels": {"50": 9, "100": 26, "250": 219, "500": 72, "1000": 317, "2000": 1620}}, {"id": 6654, "position": 6654, "text": "articulated throughout; so that, like a great\nchest of drawers, you can open and shut him, in all his bony\ncavities—spread out his ribs like a gigantic fan—and swing all day upon\nhis lower jaw", "labels": {"50": 42, "100": 70, "250": 155, "500": 403, "1000": 109, "2000": 268}}, {"id": 6655, "position": 6655, "text": "fan—and swing all day upon\nhis lower jaw. Locks are to be put upon some of his trap-doors and\nshutters; and a footman will show round future visitors with a bunch of\nkeys at his side", "labels": {"50": 48, "100": 20, "250": 59, "500": 397, "1000": 542, "2000": 504}}, {"id": 6656, "position": 6656, "text": "visitors with a bunch of\nkeys at his side. Sir Clifford thinks of charging twopence for a peep\nat the whispering gallery in the spinal column; threepence to hear the\necho in the hollow of his cerebellum; and six", "labels": {"50": 23, "100": 88, "250": 193, "500": 202, "1000": 849, "2000": 1081}}, {"id": 6657, "position": 6657, "text": "hear the\necho in the hollow of his cerebellum; and sixpence for the unrivalled\nview from his forehead.\n\nThe skeleton dimensions I shall now proceed to set down are copied\nverbatim from my right arm, where I", "labels": {"50": 3, "100": 70, "250": 132, "500": 403, "1000": 773, "2000": 202}}, {"id": 6658, "position": 6658, "text": "to set down are copied\nverbatim from my right arm, where I had them tattooed; as in my wild\nwanderings at that period, there was no other secure way of preserving\nsuch valuable statistics. But as I was crowded for space, and", "labels": {"50": 12, "100": 42, "250": 78, "500": 1, "1000": 381, "2000": 1689}}, {"id": 6659, "position": 6659, "text": "of preserving\nsuch valuable statistics. But as I was crowded for space, and wished\nthe other parts of my body to remain a blank page for a poem I was then\ncomposing—at least, what untattooed parts might remain—I did not", "labels": {"50": 48, "100": 40, "250": 74, "500": 258, "1000": 417, "2000": 53}}, {"id": 6660, "position": 6660, "text": "at least, what untattooed parts might remain—I did not\ntrouble myself with the odd inches; nor, indeed, should inches at all\nenter into a congenial admeasurement of the whale.\n\n\nCHAPTER 103", "labels": {"50": 3, "100": 85, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6661, "position": 6661, "text": "l admeasurement of the whale.\n\n\nCHAPTER 103. Measurement of The Whale’s Skeleton.\n\nIn the first place, I wish to lay before you a particular, plain\nstatement, touching the living bulk of this leviathan, whose skeleton\nwe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6662, "position": 6662, "text": "plain\nstatement, touching the living bulk of this leviathan, whose skeleton\nwe are briefly to exhibit. Such a statement may prove useful here.\n\nAccording to a careful calculation I have made, and which I partly base\nupon Captain Scoresby’s estimate,", "labels": {"50": 3, "100": 70, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6663, "position": 6663, "text": "made, and which I partly base\nupon Captain Scoresby’s estimate, of seventy tons for the largest sized\nGreenland whale of sixty feet in length; according to my careful\ncalculation, I say, a Sperm Whale of the largest magnitude, between\neighty-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6664, "position": 6664, "text": ", I say, a Sperm Whale of the largest magnitude, between\neighty-five and ninety feet in length, and something less than forty\nfeet in its fullest circumference, such a whale will weigh at least\nninety tons; so that,", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6665, "position": 6665, "text": "ference, such a whale will weigh at least\nninety tons; so that, reckoning thirteen men to a ton, he would\nconsiderably outweigh the combined population of a whole village of one\nthousand one hundred inhabitants.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6666, "position": 6666, "text": "village of one\nthousand one hundred inhabitants.\n\nThink you not then that brains, like yoked cattle, should be put to\nthis leviathan, to make him at all budge to any landsman’s imagination?", "labels": {"50": 31, "100": 20, "250": 13, "500": 126, "1000": 15, "2000": 1107}}, {"id": 6667, "position": 6667, "text": "any landsman’s imagination?\n\nHaving already in various ways put before you his skull, spout-hole,\njaw, teeth, tail, forehead, fins, and divers other parts, I shall now\nsimply point out what is most interesting in the", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6668, "position": 6668, "text": "other parts, I shall now\nsimply point out what is most interesting in the general bulk of his\nunobstructed bones. But as the colossal skull embraces so very large a\nproportion of the entire extent of the skeleton; as it is by far", "labels": {"50": 3, "100": 85, "250": 14, "500": 403, "1000": 634, "2000": 313}}, {"id": 6669, "position": 6669, "text": "a\nproportion of the entire extent of the skeleton; as it is by far the\nmost complicated part; and as nothing is to be repeated concerning it\nin this chapter, you must not fail to carry it in your mind, or under\nyour arm, as", "labels": {"50": 3, "100": 70, "250": 155, "500": 403, "1000": 845, "2000": 268}}, {"id": 6670, "position": 6670, "text": "not fail to carry it in your mind, or under\nyour arm, as we proceed, otherwise you will not gain a complete notion\nof the general structure we are about to view.\n\nIn length, the Sperm Whale’s skeleton at Tranque measured seventy", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6671, "position": 6671, "text": ".\n\nIn length, the Sperm Whale’s skeleton at Tranque measured seventy-two\nfeet; so that when fully invested and extended in life, he must have\nbeen ninety feet long; for in the whale, the skeleton loses about one\nfifth in length", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6672, "position": 6672, "text": "long; for in the whale, the skeleton loses about one\nfifth in length compared with the living body. Of this seventy-two\nfeet, his skull and jaw comprised some twenty feet, leaving some fifty\nfeet of plain back-bone", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6673, "position": 6673, "text": "feet, leaving some fifty\nfeet of plain back-bone. Attached to this back-bone, for something less\nthan a third of its length, was the mighty circular basket of ribs\nwhich once enclosed his vitals.", "labels": {"50": 3, "100": 70, "250": 155, "500": 309, "1000": 294, "2000": 1109}}, {"id": 6674, "position": 6674, "text": "ribs\nwhich once enclosed his vitals.\n\nTo me this vast ivory-ribbed chest, with the long, unrelieved spine,\nextending far away from it in a straight line, not a little resembled\nthe hull of a great ship new-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6675, "position": 6675, "text": "straight line, not a little resembled\nthe hull of a great ship new-laid upon the stocks, when only some\ntwenty of her naked bow-ribs are inserted, and the keel is otherwise,\nfor the time, but a long, disconnected timber.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 6676, "position": 6676, "text": "keel is otherwise,\nfor the time, but a long, disconnected timber.\n\nThe ribs were ten on a side. The first, to begin from the neck, was\nnearly six feet long; the second, third, and fourth were each\nsuccessively longer,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6677, "position": 6677, "text": "feet long; the second, third, and fourth were each\nsuccessively longer, till you came to the climax of the fifth, or one\nof the middle ribs, which measured eight feet and some inches. From\nthat part, the remaining ribs diminished, till", "labels": {"50": 25, "100": 5, "250": 45, "500": 349, "1000": 51, "2000": 937}}, {"id": 6678, "position": 6678, "text": "feet and some inches. From\nthat part, the remaining ribs diminished, till the tenth and last only\nspanned five feet and some inches. In general thickness, they all bore\na seemly correspondence to their length. The middle ribs were the most\narched", "labels": {"50": 3, "100": 70, "250": 234, "500": 233, "1000": 842, "2000": 1998}}, {"id": 6679, "position": 6679, "text": "seemly correspondence to their length. The middle ribs were the most\narched. In some of the Arsacides they are used for beams whereon to lay\nfootpath bridges over small streams.\n\nIn considering these ribs, I could not but be struck an", "labels": {"50": 3, "100": 70, "250": 249, "500": 77, "1000": 765, "2000": 1334}}, {"id": 6680, "position": 6680, "text": "small streams.\n\nIn considering these ribs, I could not but be struck anew with the\ncircumstance, so variously repeated in this book, that the skeleton of\nthe whale is by no means the mould of his invested form", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6681, "position": 6681, "text": "no means the mould of his invested form. The largest of\nthe Tranque ribs, one of the middle ones, occupied that part of the\nfish which, in life, is greatest in depth. Now, the greatest depth of\nthe invested body of", "labels": {"50": 3, "100": 24, "250": 30, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6682, "position": 6682, "text": "is greatest in depth. Now, the greatest depth of\nthe invested body of this particular whale must have been at least\nsixteen feet; whereas, the corresponding rib measured but little more\nthan eight feet. So that this rib only conveyed half of the true notion", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6683, "position": 6683, "text": "than eight feet. So that this rib only conveyed half of the true notion\nof the living magnitude of that part. Besides, for some way, where I\nnow saw but a naked spine, all that had been once wrapped round with\ntons of added bulk", "labels": {"50": 3, "100": 70, "250": 249, "500": 403, "1000": 845, "2000": 1620}}, {"id": 6684, "position": 6684, "text": "naked spine, all that had been once wrapped round with\ntons of added bulk in flesh, muscle, blood, and bowels. Still more, for\nthe ample fins, I here saw but a few disordered joints; and in place of\nthe weight", "labels": {"50": 25, "100": 5, "250": 125, "500": 72, "1000": 842, "2000": 1620}}, {"id": 6685, "position": 6685, "text": "here saw but a few disordered joints; and in place of\nthe weighty and majestic, but boneless flukes, an utter blank!\n\nHow vain and foolish, then, thought I, for timid untravelled man to try\nto", "labels": {"50": 25, "100": 5, "250": 136, "500": 349, "1000": 272, "2000": 937}}, {"id": 6686, "position": 6686, "text": ", thought I, for timid untravelled man to try\nto comprehend aright this wondrous whale, by merely poring over his\ndead attenuated skeleton, stretched in this peaceful wood. No", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6687, "position": 6687, "text": ", stretched in this peaceful wood. No. Only in\nthe heart of quickest perils; only when within the eddyings of his\nangry flukes; only on the profound unbounded sea, can the fully\ninvested whale be truly and livingly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6688, "position": 6688, "text": "unbounded sea, can the fully\ninvested whale be truly and livingly found out.\n\nBut the spine. For that, the best way we can consider it is, with a\ncrane, to pile its bones high up on end. No speedy enterprise", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6689, "position": 6689, "text": "a\ncrane, to pile its bones high up on end. No speedy enterprise. But now\nit’s done, it looks much like Pompey’s Pillar.\n\nThere are forty and odd vertebræ in all, which in the skeleton", "labels": {"50": 3, "100": 24, "250": 249, "500": 288, "1000": 878, "2000": 1620}}, {"id": 6690, "position": 6690, "text": "are forty and odd vertebræ in all, which in the skeleton are not\nlocked together. They mostly lie like the great knobbed blocks on a\nGothic spire, forming solid courses of heavy masonry. The largest, a\nmiddle one, is in", "labels": {"50": 48, "100": 27, "250": 249, "500": 63, "1000": 765, "2000": 180}}, {"id": 6691, "position": 6691, "text": "solid courses of heavy masonry. The largest, a\nmiddle one, is in width something less than three feet, and in depth\nmore than four. The smallest, where the spine tapers away into the\ntail, is only two inches in width, and", "labels": {"50": 48, "100": 27, "250": 249, "500": 77, "1000": 384, "2000": 147}}, {"id": 6692, "position": 6692, "text": "tapers away into the\ntail, is only two inches in width, and looks something like a white\nbilliard-ball. I was told that there were still smaller ones, but they\nhad been lost by some little cannibal urchins,", "labels": {"50": 12, "100": 43, "250": 56, "500": 1, "1000": 381, "2000": 1905}}, {"id": 6693, "position": 6693, "text": "but they\nhad been lost by some little cannibal urchins, the priest’s children,\nwho had stolen them to play marbles with. Thus we see how that the\nspine of even the hugest of living things tapers off at", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 825, "2000": 1225}}, {"id": 6694, "position": 6694, "text": "that the\nspine of even the hugest of living things tapers off at last into\nsimple child’s play.\n\n\nCHAPTER 104. The Fossil Whale.\n\nFrom his mighty bulk the whale affords a most congenial theme whereon\nto enlarge", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6695, "position": 6695, "text": "whale affords a most congenial theme whereon\nto enlarge, amplify, and generally expatiate. Would you, you could not\ncompress him. By good rights he should only be treated of in imperial\nfolio", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6696, "position": 6696, "text": ". By good rights he should only be treated of in imperial\nfolio. Not to tell over again his furlongs from spiracle to tail, and\nthe yards he measures about the waist; only think of the gigantic\ninvolutions of his int", "labels": {"50": 31, "100": 75, "250": 106, "500": 496, "1000": 165, "2000": 1956}}, {"id": 6697, "position": 6697, "text": "the waist; only think of the gigantic\ninvolutions of his intestines, where they lie in him like great cables\nand hawsers coiled away in the subterranean orlop-deck of a\nline-of-battle-ship.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6698, "position": 6698, "text": "orlop-deck of a\nline-of-battle-ship.\n\nSince I have undertaken to manhandle this Leviathan, it behooves me to\napprove myself omnisciently exhaustive in the enterprise; not\noverlooking the minutes", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1192}}, {"id": 6699, "position": 6699, "text": "myself omnisciently exhaustive in the enterprise; not\noverlooking the minutest seminal germs of his blood, and spinning him\nout to the uttermost coil of his bowels. Having already described him\nin most of his present habitatory and", "labels": {"50": 8, "100": 14, "250": 101, "500": 496, "1000": 148, "2000": 1037}}, {"id": 6700, "position": 6700, "text": "bowels. Having already described him\nin most of his present habitatory and anatomical peculiarities, it now\nremains to magnify him in an archæological, fossiliferous, and\nantediluvian point of view", "labels": {"50": 31, "100": 7, "250": 193, "500": 202, "1000": 849, "2000": 1107}}, {"id": 6701, "position": 6701, "text": ", and\nantediluvian point of view. Applied to any other creature than the\nLeviathan—to an ant or a flea—such portly terms might justly be deemed\nunwarrantably grandiloquent", "labels": {"50": 3, "100": 24, "250": 213, "500": 288, "1000": 546, "2000": 1556}}, {"id": 6702, "position": 6702, "text": "be deemed\nunwarrantably grandiloquent. But when Leviathan is the text, the case\nis altered. Fain am I to stagger to this emprise under the weightiest\nwords of the dictionary", "labels": {"50": 31, "100": 7, "250": 193, "500": 307, "1000": 849, "2000": 1107}}, {"id": 6703, "position": 6703, "text": "under the weightiest\nwords of the dictionary. And here be it said, that whenever it has been\nconvenient to consult one in the course of these dissertations, I have\ninvariably used a huge quarto edition of Johnson, expressly purchased\nfor that", "labels": {"50": 17, "100": 40, "250": 74, "500": 355, "1000": 162, "2000": 510}}, {"id": 6704, "position": 6704, "text": "used a huge quarto edition of Johnson, expressly purchased\nfor that purpose; because that famous lexicographer’s uncommon personal\nbulk more fitted him to compile a lexicon to be used by a whale author\nlike me.", "labels": {"50": 17, "100": 40, "250": 241, "500": 355, "1000": 926, "2000": 850}}, {"id": 6705, "position": 6705, "text": "lexicon to be used by a whale author\nlike me.\n\nOne often hears of writers that rise and swell with their subject,\nthough it may seem but an ordinary one. How, then, with me, writing of\nthis Leviathan? Unconsciously my", "labels": {"50": 31, "100": 40, "250": 132, "500": 374, "1000": 417, "2000": 53}}, {"id": 6706, "position": 6706, "text": ", then, with me, writing of\nthis Leviathan? Unconsciously my chirography expands into placard\ncapitals. Give me a condor’s quill! Give me Vesuvius’ crater for an\ninkstand! Friends, hold my", "labels": {"50": 31, "100": 20, "250": 193, "500": 498, "1000": 849, "2000": 1107}}, {"id": 6707, "position": 6707, "text": "me Vesuvius’ crater for an\ninkstand! Friends, hold my arms! For in the mere act of penning my\nthoughts of this Leviathan, they weary me, and make me faint with their\noutreaching comprehensiveness of sweep, as", "labels": {"50": 31, "100": 64, "250": 193, "500": 72, "1000": 849, "2000": 1620}}, {"id": 6708, "position": 6708, "text": ", and make me faint with their\noutreaching comprehensiveness of sweep, as if to include the whole\ncircle of the sciences, and all the generations of whales, and men, and\nmastodons, past, present, and to come, with all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6709, "position": 6709, "text": "and\nmastodons, past, present, and to come, with all the revolving panoramas\nof empire on earth, and throughout the whole universe, not excluding\nits suburbs. Such, and so magnifying, is the virtue of a large and", "labels": {"50": 48, "100": 20, "250": 193, "500": 126, "1000": 727, "2000": 1107}}, {"id": 6710, "position": 6710, "text": "Such, and so magnifying, is the virtue of a large and\nliberal theme! We expand to its bulk. To produce a mighty book, you\nmust choose a mighty theme. No great and enduring volume can ever be\nwritten on the flea,", "labels": {"50": 48, "100": 40, "250": 74, "500": 126, "1000": 727, "2000": 1107}}, {"id": 6711, "position": 6711, "text": "theme. No great and enduring volume can ever be\nwritten on the flea, though many there be who have tried it.\n\nEre entering upon the subject of Fossil Whales, I present my\ncredentials as a geologist, by stating that in my miscellaneous time I", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 6712, "position": 6712, "text": "present my\ncredentials as a geologist, by stating that in my miscellaneous time I\nhave been a stone-mason, and also a great digger of ditches, canals and\nwells, wine-vaults, cellars, and cisterns of all sorts", "labels": {"50": 3, "100": 85, "250": 234, "500": 486, "1000": 956, "2000": 952}}, {"id": 6713, "position": 6713, "text": "wine-vaults, cellars, and cisterns of all sorts. Likewise, by\nway of preliminary, I desire to remind the reader, that while in the\nearlier geological strata there are found the fossils of monsters now\nalmost completely extinct; the subsequent", "labels": {"50": 3, "100": 70, "250": 234, "500": 108, "1000": 478, "2000": 1219}}, {"id": 6714, "position": 6714, "text": "strata there are found the fossils of monsters now\nalmost completely extinct; the subsequent relics discovered in what are\ncalled the Tertiary formations seem the connecting, or at any rate\nintercepted links, between the antichronical creatures, and those whose\nremote posterity are", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 6715, "position": 6715, "text": "between the antichronical creatures, and those whose\nremote posterity are said to have entered the Ark; all the Fossil\nWhales hitherto discovered belong to the Tertiary period, which is the\nlast preceding the superficial formations", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 478, "2000": 612}}, {"id": 6716, "position": 6716, "text": ", which is the\nlast preceding the superficial formations. And though none of them\nprecisely answer to any known species of the present time, they are yet\nsufficiently akin to them in general respects, to justify their taking\nrank as Cetacean fossils.", "labels": {"50": 3, "100": 70, "250": 234, "500": 108, "1000": 37, "2000": 1219}}, {"id": 6717, "position": 6717, "text": "respects, to justify their taking\nrank as Cetacean fossils.\n\nDetached broken fossils of pre-adamite whales, fragments of their bones\nand skeletons, have within thirty years past, at various intervals,\nbeen found at the base of the Alps,", "labels": {"50": 3, "100": 70, "250": 234, "500": 108, "1000": 478, "2000": 1219}}, {"id": 6718, "position": 6718, "text": "past, at various intervals,\nbeen found at the base of the Alps, in Lombardy, in France, in England,\nin Scotland, and in the States of Louisiana, Mississippi, and Alabama.\nAmong the more curious of such remains is part of a", "labels": {"50": 3, "100": 70, "250": 234, "500": 77, "1000": 478, "2000": 823}}, {"id": 6719, "position": 6719, "text": ", and Alabama.\nAmong the more curious of such remains is part of a skull, which in the\nyear 1779 was disinterred in the Rue Dauphine in Paris, a short street\nopening almost directly upon the palace of the Tuileries;", "labels": {"50": 3, "100": 70, "250": 155, "500": 309, "1000": 478, "2000": 1109}}, {"id": 6720, "position": 6720, "text": "a short street\nopening almost directly upon the palace of the Tuileries; and bones\ndisinterred in excavating the great docks of Antwerp, in Napoleon’s\ntime. Cuvier pronounced these fragments to have belonged to some\nutterly unknown Levi", "labels": {"50": 48, "100": 27, "250": 59, "500": 397, "1000": 162, "2000": 504}}, {"id": 6721, "position": 6721, "text": "time. Cuvier pronounced these fragments to have belonged to some\nutterly unknown Leviathanic species.\n\nBut by far the most wonderful of all Cetacean relics was the almost\ncomplete vast skeleton of an extinct monster, found in the year 1842,\non", "labels": {"50": 3, "100": 85, "250": 234, "500": 343, "1000": 825, "2000": 612}}, {"id": 6722, "position": 6722, "text": "complete vast skeleton of an extinct monster, found in the year 1842,\non the plantation of Judge Creagh, in Alabama. The awe-stricken\ncredulous slaves in the vicinity took it for the bones of one of the\nfallen angels", "labels": {"50": 3, "100": 85, "250": 234, "500": 77, "1000": 478, "2000": 823}}, {"id": 6723, "position": 6723, "text": "the vicinity took it for the bones of one of the\nfallen angels. The Alabama doctors declared it a huge reptile, and\nbestowed upon it the name of Basilosaurus. But some specimen bones of\nit being taken across the sea to Owen, the English", "labels": {"50": 40, "100": 70, "250": 210, "500": 420, "1000": 57, "2000": 1588}}, {"id": 6724, "position": 6724, "text": "some specimen bones of\nit being taken across the sea to Owen, the English Anatomist, it turned\nout that this alleged reptile was a whale, though of a departed\nspecies. A significant illustration of the fact, again and again\nrepeated in this", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 634, "2000": 1219}}, {"id": 6725, "position": 6725, "text": "species. A significant illustration of the fact, again and again\nrepeated in this book, that the skeleton of the whale furnishes but\nlittle clue to the shape of his fully invested body. So Owen\nrechristened the monster Zeuglodon", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 1346}}, {"id": 6726, "position": 6726, "text": "invested body. So Owen\nrechristened the monster Zeuglodon; and in his paper read before the\nLondon Geological Society, pronounced it, in substance, one of the most\nextraordinary creatures which the mutations of the globe have blotted\nout", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 6727, "position": 6727, "text": "the most\nextraordinary creatures which the mutations of the globe have blotted\nout of existence.\n\nWhen I stand among these mighty Leviathan skeletons, skulls, tusks,\njaws, ribs, and vertebræ, all characterized by partial resemblances", "labels": {"50": 3, "100": 70, "250": 234, "500": 72, "1000": 825, "2000": 631}}, {"id": 6728, "position": 6728, "text": ", ribs, and vertebræ, all characterized by partial resemblances to\nthe existing breeds of sea-monsters; but at the same time bearing on\nthe other hand similar affinities to the annihilated antichronical\nLeviathan", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 6729, "position": 6729, "text": "affinities to the annihilated antichronical\nLeviathans, their incalculable seniors; I am, by a flood, borne back to\nthat wondrous period, ere time itself can be said to have begun", "labels": {"50": 16, "100": 73, "250": 13, "500": 414, "1000": 437, "2000": 1555}}, {"id": 6730, "position": 6730, "text": "wondrous period, ere time itself can be said to have begun; for\ntime began with man. Here Saturn’s grey chaos rolls over me, and I\nobtain dim, shuddering glimpses into those Polar eternities; when\nwedged", "labels": {"50": 16, "100": 73, "250": 26, "500": 414, "1000": 914, "2000": 193}}, {"id": 6731, "position": 6731, "text": "dim, shuddering glimpses into those Polar eternities; when\nwedged bastions of ice pressed hard upon what are now the Tropics; and\nin all the 25,000 miles of this world’s circumference, not an", "labels": {"50": 3, "100": 20, "250": 192, "500": 162, "1000": 35, "2000": 204}}, {"id": 6732, "position": 6732, "text": ",000 miles of this world’s circumference, not an\ninhabitable hand’s breadth of land was visible. Then the whole world\nwas the whale’s; and, king of creation, he left his wake along the\npresent lines", "labels": {"50": 9, "100": 26, "250": 133, "500": 122, "1000": 437, "2000": 1208}}, {"id": 6733, "position": 6733, "text": "; and, king of creation, he left his wake along the\npresent lines of the Andes and the Himmalehs. Who can show a pedigree\nlike Leviathan? Ahab’s harpoon had shed older blood than the Pharaoh’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6734, "position": 6734, "text": "? Ahab’s harpoon had shed older blood than the Pharaoh’s.\nMethuselah seems a school-boy. I look round to shake hands with Shem. I\nam horror-struck at this antemosaic, un", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6735, "position": 6735, "text": "m. I\nam horror-struck at this antemosaic, unsourced existence of the\nunspeakable terrors of the whale, which, having been before all time,\nmust needs exist after all humane ages are over.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6736, "position": 6736, "text": "before all time,\nmust needs exist after all humane ages are over.\n\nBut not alone has this Leviathan left his pre-adamite traces in the\nstereotype plates of nature, and in limestone and marl bequeathed his\nancient bust; but upon Egyptian", "labels": {"50": 16, "100": 73, "250": 211, "500": 414, "1000": 747, "2000": 1821}}, {"id": 6737, "position": 6737, "text": ", and in limestone and marl bequeathed his\nancient bust; but upon Egyptian tablets, whose antiquity seems to claim\nfor them an almost fossiliferous character, we find the unmistakable\nprint of his fin. In an apartment of the great temple of Denderah", "labels": {"50": 32, "100": 0, "250": 249, "500": 77, "1000": 878, "2000": 1821}}, {"id": 6738, "position": 6738, "text": "of his fin. In an apartment of the great temple of Denderah, some\nfifty years ago, there was discovered upon the granite ceiling a\nsculptured and painted planisphere, abounding in centaurs, griffins,\nand", "labels": {"50": 48, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 215}}, {"id": 6739, "position": 6739, "text": "phere, abounding in centaurs, griffins,\nand dolphins, similar to the grotesque figures on the celestial globe\nof the moderns. Gliding among them, old Leviathan swam as of yore; was\nthere swimming in that plan", "labels": {"50": 48, "100": 27, "250": 189, "500": 261, "1000": 338, "2000": 22}}, {"id": 6740, "position": 6740, "text": "old Leviathan swam as of yore; was\nthere swimming in that planisphere, centuries before Solomon was\ncradled.\n\nNor must there be omitted another strange attestation of the antiquity\nof the whale, in his own osseous post-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6741, "position": 6741, "text": "of the antiquity\nof the whale, in his own osseous post-diluvian reality, as set down by\nthe venerable John Leo, the old Barbary traveller.\n\n“Not far from the Sea-side, they have a Temple,", "labels": {"50": 3, "100": 66, "250": 211, "500": 490, "1000": 655, "2000": 1620}}, {"id": 6742, "position": 6742, "text": ".\n\n“Not far from the Sea-side, they have a Temple, the Rafters and Beams\nof which are made of Whale-Bones; for Whales of a monstrous size are\noftentimes cast up dead upon that shore", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6743, "position": 6743, "text": "are\noftentimes cast up dead upon that shore. The Common People imagine,\nthat by a secret Power bestowed by God upon the Temple, no Whale can\npass it without immediate death. But the truth of the Matter is, that\non either side of", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6744, "position": 6744, "text": "death. But the truth of the Matter is, that\non either side of the Temple, there are Rocks that shoot two Miles into\nthe Sea, and wound the Whales when they light upon ’em. They keep a\nWhale’s Rib of an incredible", "labels": {"50": 48, "100": 20, "250": 138, "500": 72, "1000": 9, "2000": 1620}}, {"id": 6745, "position": 6745, "text": "light upon ’em. They keep a\nWhale’s Rib of an incredible length for a Miracle, which lying upon the\nGround with its convex part uppermost, makes an Arch, the Head of which\ncannot be reached by a Man upon a Camel’", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 134, "2000": 1374}}, {"id": 6746, "position": 6746, "text": ", the Head of which\ncannot be reached by a Man upon a Camel’s Back. This Rib (says John\nLeo) is said to have layn there a hundred Years before I saw it. Their\nHistorians affirm, that a Prophet who prop", "labels": {"50": 32, "100": 0, "250": 233, "500": 55, "1000": 501, "2000": 1135}}, {"id": 6747, "position": 6747, "text": "before I saw it. Their\nHistorians affirm, that a Prophet who prophesy’d of Mahomet, came from\nthis Temple, and some do not stand to assert, that the Prophet Jonas\nwas cast forth by the Whale at the Base", "labels": {"50": 45, "100": 33, "250": 211, "500": 72, "1000": 825, "2000": 199}}, {"id": 6748, "position": 6748, "text": "assert, that the Prophet Jonas\nwas cast forth by the Whale at the Base of the Temple.”\n\nIn this Afric Temple of the Whale I leave you, reader, and if you be a\nNantucketer, and a whaleman, you will", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6749, "position": 6749, "text": "if you be a\nNantucketer, and a whaleman, you will silently worship there.\n\n\nCHAPTER 105. Does the Whale’s Magnitude Diminish?—Will He Perish?\n\nInasmuch, then, as this Leviathan comes fl", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6750, "position": 6750, "text": "Perish?\n\nInasmuch, then, as this Leviathan comes floundering down upon us from\nthe head-waters of the Eternities, it may be fitly inquired, whether,\nin the long course of his generations, he has", "labels": {"50": 10, "100": 75, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 6751, "position": 6751, "text": "ly inquired, whether,\nin the long course of his generations, he has not degenerated from the\noriginal bulk of his sires.\n\nBut upon investigation we find, that not only are the whales of the\npresent day superior in magnitude to those whose", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6752, "position": 6752, "text": "not only are the whales of the\npresent day superior in magnitude to those whose fossil remains are\nfound in the Tertiary system (embracing a distinct geological period\nprior to man), but of the whales found in that Tertiary system, those\nbelonging to its latter formations", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 6753, "position": 6753, "text": "of the whales found in that Tertiary system, those\nbelonging to its latter formations exceed in size those of its earlier\nones.\n\nOf all the pre-adamite whales yet exhumed, by far the largest is the\nAlabama one mentioned in the last chapter", "labels": {"50": 3, "100": 85, "250": 234, "500": 343, "1000": 825, "2000": 1219}}, {"id": 6754, "position": 6754, "text": "ed, by far the largest is the\nAlabama one mentioned in the last chapter, and that was less than\nseventy feet in length in the skeleton. Whereas, we have already seen,\nthat the tape-measure gives seventy-two feet for the skeleton of", "labels": {"50": 3, "100": 70, "250": 234, "500": 108, "1000": 478, "2000": 823}}, {"id": 6755, "position": 6755, "text": ",\nthat the tape-measure gives seventy-two feet for the skeleton of a\nlarge sized modern whale. And I have heard, on whalemen’s authority,\nthat Sperm Whales have been captured near a hundred feet long at the\ntime of capture.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6756, "position": 6756, "text": "Whales have been captured near a hundred feet long at the\ntime of capture.\n\nBut may it not be, that while the whales of the present hour are an\nadvance in magnitude upon those of all previous geological periods; may\nit not be, that since Adam", "labels": {"50": 3, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6757, "position": 6757, "text": "those of all previous geological periods; may\nit not be, that since Adam’s time they have degenerated?\n\nAssuredly, we must conclude so, if we are to credit the accounts of\nsuch gentlemen as Pliny, and the ancient naturalist", "labels": {"50": 3, "100": 85, "250": 234, "500": 343, "1000": 276, "2000": 204}}, {"id": 6758, "position": 6758, "text": "to credit the accounts of\nsuch gentlemen as Pliny, and the ancient naturalists generally. For\nPliny tells us of whales that embraced acres of living bulk, and\nAldrovandus of others which measured eight hundred feet in length—Rope\nWalks and", "labels": {"50": 3, "100": 24, "250": 14, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6759, "position": 6759, "text": "vandus of others which measured eight hundred feet in length—Rope\nWalks and Thames Tunnels of Whales! And even in the days of Banks and\nSolander, Cooke’s naturalists, we find a Danish member of the Academy\nof Sciences setting down certain", "labels": {"50": 17, "100": 85, "250": 129, "500": 343, "1000": 134, "2000": 1676}}, {"id": 6760, "position": 6760, "text": "s, we find a Danish member of the Academy\nof Sciences setting down certain Iceland Whales (reydan-siskur, or\nWrinkled Bellies) at one hundred and twenty yards; that is, three\nhundred and sixty feet", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6761, "position": 6761, "text": "; that is, three\nhundred and sixty feet. And Lacépède, the French naturalist, in his\nelaborate history of whales, in the very beginning of his work (page\n3), sets down the Right Whale at one hundred metres, three hundred", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6762, "position": 6762, "text": "3), sets down the Right Whale at one hundred metres, three hundred and\ntwenty-eight feet. And this work was published so late as A.D. 1825.\n\nBut will any whaleman believe these stories? No", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6763, "position": 6763, "text": "But will any whaleman believe these stories? No. The whale of to-day is\nas big as his ancestors in Pliny’s time. And if ever I go where Pliny\nis, I, a whaleman (more than he was", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6764, "position": 6764, "text": "where Pliny\nis, I, a whaleman (more than he was), will make bold to tell him so.\nBecause I cannot understand how it is, that while the Egyptian mummies\nthat were buried thousands of years before even Pliny was", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6765, "position": 6765, "text": "the Egyptian mummies\nthat were buried thousands of years before even Pliny was born, do not\nmeasure so much in their coffins as a modern Kentuckian in his socks;\nand while the cattle and other animals sculptured on the oldest\nEgyptian and", "labels": {"50": 3, "100": 85, "250": 211, "500": 77, "1000": 478, "2000": 823}}, {"id": 6766, "position": 6766, "text": ";\nand while the cattle and other animals sculptured on the oldest\nEgyptian and Nineveh tablets, by the relative proportions in which they\nare drawn, just as plainly prove that the high-bred, stall-fed, prize\ncattle of Smithfield,", "labels": {"50": 3, "100": 85, "250": 52, "500": 58, "1000": 940, "2000": 15}}, {"id": 6767, "position": 6767, "text": "the high-bred, stall-fed, prize\ncattle of Smithfield, not only equal, but far exceed in magnitude the\nfattest of Pharaoh’s fat kine; in the face of all this, I will not\nadmit that of all animals", "labels": {"50": 21, "100": 76, "250": 32, "500": 417, "1000": 815, "2000": 1903}}, {"id": 6768, "position": 6768, "text": "in the face of all this, I will not\nadmit that of all animals the whale alone should have degenerated.\n\nBut still another inquiry remains; one often agitated by the more\nrecondite Nantucketers", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6769, "position": 6769, "text": "more\nrecondite Nantucketers. Whether owing to the almost omniscient\nlook-outs at the mast-heads of the whale-ships, now penetrating even\nthrough Behring’s straits, and into the remotest secret drawers and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6770, "position": 6770, "text": "Behring’s straits, and into the remotest secret drawers and\nlockers of the world; and the thousand harpoons and lances darted along\nall continental coasts; the moot point is, whether Leviathan can long\nendure so wide a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6771, "position": 6771, "text": "the moot point is, whether Leviathan can long\nendure so wide a chase, and so remorseless a havoc; whether he must not\nat last be exterminated from the waters, and the last whale, like the\nlast man, smoke his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6772, "position": 6772, "text": "the waters, and the last whale, like the\nlast man, smoke his last pipe, and then himself evaporate in the final\npuff.\n\nComparing the humped herds of whales with the humped herds of buffalo,\nwhich, not forty years ago", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6773, "position": 6773, "text": "whales with the humped herds of buffalo,\nwhich, not forty years ago, overspread by tens of thousands the\nprairies of Illinois and Missouri, and shook their iron manes and\nscowled with their thunder-clotted brows upon the sites of", "labels": {"50": 12, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6774, "position": 6774, "text": "manes and\nscowled with their thunder-clotted brows upon the sites of populous\nriver-capitals, where now the polite broker sells you land at a dollar\nan inch; in such a comparison an irresistible argument would seem\nfurnished, to show that the hunted", "labels": {"50": 48, "100": 57, "250": 137, "500": 224, "1000": 525, "2000": 525}}, {"id": 6775, "position": 6775, "text": "such a comparison an irresistible argument would seem\nfurnished, to show that the hunted whale cannot now escape speedy\nextinction.\n\nBut you must look at this matter in every light. Though so short a\nperiod ago—not a good lifetime—the census of the buffalo", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 6776, "position": 6776, "text": "short a\nperiod ago—not a good lifetime—the census of the buffalo in Illinois\nexceeded the census of men now in London, and though at the present day\nnot one horn or hoof of them remains in all that region; and though the\ncause", "labels": {"50": 12, "100": 38, "250": 52, "500": 417, "1000": 451, "2000": 981}}, {"id": 6777, "position": 6777, "text": "or hoof of them remains in all that region; and though the\ncause of this wondrous extermination was the spear of man; yet the far\ndifferent nature of the whale-hunt peremptorily forbids so inglorious", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6778, "position": 6778, "text": "of the whale-hunt peremptorily forbids so inglorious\nan end to the Leviathan. Forty men in one ship hunting the Sperm Whales\nfor forty-eight months think they have done extremely well, and thank\nGod, if at last", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6779, "position": 6779, "text": "months think they have done extremely well, and thank\nGod, if at last they carry home the oil of forty fish. Whereas, in the\ndays of the old Canadian and Indian hunters and trappers of the West,\nwhen the far west (in whose", "labels": {"50": 12, "100": 43, "250": 209, "500": 344, "1000": 554, "2000": 624}}, {"id": 6780, "position": 6780, "text": "hunters and trappers of the West,\nwhen the far west (in whose sunset suns still rise) was a wilderness\nand a virgin, the same number of moccasined men, for the same number of\nmonths, mounted on horse instead of sailing", "labels": {"50": 12, "100": 6, "250": 137, "500": 210, "1000": 972, "2000": 939}}, {"id": 6781, "position": 6781, "text": "men, for the same number of\nmonths, mounted on horse instead of sailing in ships, would have slain\nnot forty, but forty thousand and more buffaloes; a fact that, if need\nwere, could be statistically stated.", "labels": {"50": 12, "100": 38, "250": 137, "500": 210, "1000": 972, "2000": 939}}, {"id": 6782, "position": 6782, "text": ", if need\nwere, could be statistically stated.\n\nNor, considered aright, does it seem any argument in favour of the\ngradual extinction of the Sperm Whale, for example, that in former\nyears (the latter part of the last century, say", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 276, "2000": 612}}, {"id": 6783, "position": 6783, "text": ", that in former\nyears (the latter part of the last century, say) these Leviathans, in\nsmall pods, were encountered much oftener than at present, and, in\nconsequence, the voyages were not so prolonged, and were also much", "labels": {"50": 45, "100": 29, "250": 161, "500": 13, "1000": 312, "2000": 887}}, {"id": 6784, "position": 6784, "text": ", in\nconsequence, the voyages were not so prolonged, and were also much more\nremunerative. Because, as has been elsewhere noticed, those whales,\ninfluenced by some views to safety, now swim the seas in immense\ncaravans, so that to", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6785, "position": 6785, "text": "to safety, now swim the seas in immense\ncaravans, so that to a large degree the scattered solitaries, yokes,\nand pods, and schools of other days are now aggregated into vast but\nwidely separated, unfrequent armies", "labels": {"50": 21, "100": 95, "250": 76, "500": 455, "1000": 746, "2000": 336}}, {"id": 6786, "position": 6786, "text": "are now aggregated into vast but\nwidely separated, unfrequent armies. That is all. And equally\nfallacious seems the conceit, that because the so-called whale-bone\nwhales no longer haunt many grounds in former years abound", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6787, "position": 6787, "text": "called whale-bone\nwhales no longer haunt many grounds in former years abounding with\nthem, hence that species also is declining. For they are only being\ndriven from promontory to cape; and if one coast is no longer enlivened", "labels": {"50": 3, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6788, "position": 6788, "text": "ry to cape; and if one coast is no longer enlivened\nwith their jets, then, be sure, some other and remoter strand has been\nvery recently startled by the unfamiliar spectacle.\n\nFurthermore: concerning these last mentioned Leviathans,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6789, "position": 6789, "text": "by the unfamiliar spectacle.\n\nFurthermore: concerning these last mentioned Leviathans, they have two\nfirm fortresses, which, in all human probability, will for ever remain\nimpregnable. And as upon the invasion of their valleys, the frosty", "labels": {"50": 12, "100": 43, "250": 34, "500": 48, "1000": 525, "2000": 207}}, {"id": 6790, "position": 6790, "text": "gnable. And as upon the invasion of their valleys, the frosty\nSwiss have retreated to their mountains; so, hunted from the savannas\nand glades of the middle seas, the whale-bone whales can at last resort\nto their Polar citadel", "labels": {"50": 3, "100": 24, "250": 234, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6791, "position": 6791, "text": "seas, the whale-bone whales can at last resort\nto their Polar citadels, and diving under the ultimate glassy barriers\nand walls there, come up among icy fields and floes; and in a charmed\ncircle of everlasting December,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6792, "position": 6792, "text": "floes; and in a charmed\ncircle of everlasting December, bid defiance to all pursuit from man.\n\nBut as perhaps fifty of these whale-bone whales are harpooned for one\ncachalot, some philosophers of the forecastle have", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6793, "position": 6793, "text": "ooned for one\ncachalot, some philosophers of the forecastle have concluded that this\npositive havoc has already very seriously diminished their battalions.\nBut though for some time past a number of these whales, not less than\n13,000, have been annually", "labels": {"50": 45, "100": 24, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6794, "position": 6794, "text": "number of these whales, not less than\n13,000, have been annually slain on the nor’ west coast by the\nAmericans alone; yet there are considerations which render even this\ncircumstance of little or no account as an opposing argument in this\nmatter.", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6795, "position": 6795, "text": "circumstance of little or no account as an opposing argument in this\nmatter.\n\nNatural as it is to be somewhat incredulous concerning the populousness\nof the more enormous creatures of the globe, yet what shall we say to\nHarto, the historian of Goa", "labels": {"50": 26, "100": 66, "250": 198, "500": 490, "1000": 622, "2000": 199}}, {"id": 6796, "position": 6796, "text": "globe, yet what shall we say to\nHarto, the historian of Goa, when he tells us that at one hunting the\nKing of Siam took 4,000 elephants; that in those regions elephants are\nnumerous as droves of cattle in the temperate cl", "labels": {"50": 26, "100": 82, "250": 198, "500": 473, "1000": 575, "2000": 199}}, {"id": 6797, "position": 6797, "text": "in those regions elephants are\nnumerous as droves of cattle in the temperate climes. And there seems\nno reason to doubt that if these elephants, which have now been hunted\nfor thousands of years, by Semiramis, by Porus, by", "labels": {"50": 3, "100": 24, "250": 52, "500": 417, "1000": 505, "2000": 145}}, {"id": 6798, "position": 6798, "text": "for thousands of years, by Semiramis, by Porus, by Hannibal, and by all\nthe successive monarchs of the East—if they still survive there in\ngreat numbers, much more may the great whale outlast all hunting, since\nhe", "labels": {"50": 26, "100": 75, "250": 106, "500": 333, "1000": 344, "2000": 795}}, {"id": 6799, "position": 6799, "text": ", much more may the great whale outlast all hunting, since\nhe has a pasture to expatiate in, which is precisely twice as large as\nall Asia, both Americas, Europe and Africa, New Holland, and all the\nIsles of the", "labels": {"50": 45, "100": 24, "250": 52, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6800, "position": 6800, "text": "Americas, Europe and Africa, New Holland, and all the\nIsles of the sea combined.\n\nMoreover: we are to consider, that from the presumed great longevity of\nwhales, their probably attaining the age of a century and more,\ntherefore at any one period", "labels": {"50": 3, "100": 85, "250": 14, "500": 343, "1000": 825, "2000": 1620}}, {"id": 6801, "position": 6801, "text": "probably attaining the age of a century and more,\ntherefore at any one period of time, several distinct adult generations\nmust be contemporary. And what that is, we may soon gain some idea of,\nby imagining all the grave-yards, cemeteries, and", "labels": {"50": 48, "100": 27, "250": 157, "500": 126, "1000": 619, "2000": 168}}, {"id": 6802, "position": 6802, "text": "some idea of,\nby imagining all the grave-yards, cemeteries, and family vaults of\ncreation yielding up the live bodies of all the men, women, and\nchildren who were alive seventy-five years ago; and adding this\ncountless host to the present", "labels": {"50": 5, "100": 66, "250": 177, "500": 250, "1000": 890, "2000": 988}}, {"id": 6803, "position": 6803, "text": "alive seventy-five years ago; and adding this\ncountless host to the present human population of the globe.\n\nWherefore, for all these things, we account the whale immortal in his\nspecies, however perishable in his individuality", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 6804, "position": 6804, "text": "in his\nspecies, however perishable in his individuality. He swam the seas\nbefore the continents broke water; he once swam over the site of the\nTuileries, and Windsor Castle, and the Kremlin", "labels": {"50": 23, "100": 88, "250": 70, "500": 202, "1000": 858, "2000": 1966}}, {"id": 6805, "position": 6805, "text": "and Windsor Castle, and the Kremlin. In Noah’s flood he\ndespised Noah’s Ark; and if ever the world is to be again flooded, like\nthe Netherlands, to kill off its rats, then the eternal whale will\nstill survive", "labels": {"50": 44, "100": 68, "250": 1, "500": 237, "1000": 102, "2000": 138}}, {"id": 6806, "position": 6806, "text": "Netherlands, to kill off its rats, then the eternal whale will\nstill survive, and rearing upon the topmost crest of the equatorial\nflood, spout his frothed defiance to the skies.\n\n\nCHAPTER 106. Ahab’s Leg.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6807, "position": 6807, "text": "defiance to the skies.\n\n\nCHAPTER 106. Ahab’s Leg.\n\nThe precipitating manner in which Captain Ahab had quitted the Samuel\nEnderby of London, had not been unattended with some small violence to\nhis own person", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6808, "position": 6808, "text": ", had not been unattended with some small violence to\nhis own person. He had lighted with such energy upon a thwart of his\nboat that his ivory leg had received a half-splintering shock", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 531, "2000": 1620}}, {"id": 6809, "position": 6809, "text": "a half-splintering shock. And when\nafter gaining his own deck, and his own pivot-hole there, he so\nvehemently wheeled round with an urgent command to the steersman (it\nwas, as ever, something about his not", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 6810, "position": 6810, "text": "to the steersman (it\nwas, as ever, something about his not steering inflexibly enough);\nthen, the already shaken ivory received such an additional twist and\nwrench, that though it still remained entire, and to all appearances\nlust", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6811, "position": 6811, "text": "wrench, that though it still remained entire, and to all appearances\nlusty, yet Ahab did not deem it entirely trustworthy.\n\nAnd, indeed, it seemed small matter for wonder, that for all his\npervading, mad reckless", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6812, "position": 6812, "text": "small matter for wonder, that for all his\npervading, mad recklessness, Ahab did at times give careful heed to the\ncondition of that dead bone upon which he partly stood. For it had not\nbeen very long prior to the Pe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6813, "position": 6813, "text": "he partly stood. For it had not\nbeen very long prior to the Pequod’s sailing from Nantucket, that he\nhad been found one night lying prone upon the ground, and insensible;\nby some unknown, and seemingly inex", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6814, "position": 6814, "text": "ground, and insensible;\nby some unknown, and seemingly inexplicable, unimaginable casualty, his\nivory limb having been so violently displaced, that it had stake-wise\nsmitten, and all but pierced his groin", "labels": {"50": 19, "100": 17, "250": 160, "500": 358, "1000": 138, "2000": 1262}}, {"id": 6815, "position": 6815, "text": "it had stake-wise\nsmitten, and all but pierced his groin; nor was it without extreme\ndifficulty that the agonizing wound was entirely cured.\n\nNor, at the time, had it failed to enter his monomaniac mind, that", "labels": {"50": 22, "100": 78, "250": 229, "500": 336, "1000": 448, "2000": 1976}}, {"id": 6816, "position": 6816, "text": "the time, had it failed to enter his monomaniac mind, that all\nthe anguish of that then present suffering was but the direct issue of\na former woe; and he too plainly seemed to see, that as the most\npoisonous reptile of", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 32, "2000": 1469}}, {"id": 6817, "position": 6817, "text": "he too plainly seemed to see, that as the most\npoisonous reptile of the marsh perpetuates his kind as inevitably as\nthe sweetest songster of the grove; so, equally with every felicity,\nall miserable events do naturally beget their", "labels": {"50": 17, "100": 16, "250": 87, "500": 182, "1000": 448, "2000": 958}}, {"id": 6818, "position": 6818, "text": "so, equally with every felicity,\nall miserable events do naturally beget their like. Yea, more than\nequally, thought Ahab; since both the ancestry and posterity of Grief\ngo further than the ancestry and posterity of Joy", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 637, "2000": 1886}}, {"id": 6819, "position": 6819, "text": "of Grief\ngo further than the ancestry and posterity of Joy. For, not to hint of\nthis: that it is an inference from certain canonic teachings, that\nwhile some natural enjoyments here shall have no children born to them\nfor the other world", "labels": {"50": 26, "100": 54, "250": 106, "500": 333, "1000": 344, "2000": 1475}}, {"id": 6820, "position": 6820, "text": "natural enjoyments here shall have no children born to them\nfor the other world, but, on the contrary, shall be followed by the\njoy-childlessness of all hell’s despair; whereas, some guilty mortal\nmiseries shall still fertilely beg", "labels": {"50": 21, "100": 95, "250": 88, "500": 107, "1000": 451, "2000": 1073}}, {"id": 6821, "position": 6821, "text": "s despair; whereas, some guilty mortal\nmiseries shall still fertilely beget to themselves an eternally\nprogressive progeny of griefs beyond the grave; not at all to hint of\nthis, there still seems an inequality in the deeper analysis of the", "labels": {"50": 17, "100": 16, "250": 87, "500": 64, "1000": 256, "2000": 515}}, {"id": 6822, "position": 6822, "text": "hint of\nthis, there still seems an inequality in the deeper analysis of the\nthing. For, thought Ahab, while even the highest earthly felicities\never have a certain unsignifying pettiness lurking in them, but, at\nbottom", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6823, "position": 6823, "text": "unsignifying pettiness lurking in them, but, at\nbottom, all heartwoes, a mystic significance, and, in some men, an\narchangelic grandeur; so do their diligent tracings-out not belie", "labels": {"50": 17, "100": 16, "250": 87, "500": 307, "1000": 355, "2000": 1601}}, {"id": 6824, "position": 6824, "text": "ur; so do their diligent tracings-out not belie the\nobvious deduction. To trail the genealogies of these high mortal\nmiseries, carries us at last among the sourceless primogenitures of the\ngods;", "labels": {"50": 10, "100": 71, "250": 211, "500": 414, "1000": 368, "2000": 1374}}, {"id": 6825, "position": 6825, "text": "at last among the sourceless primogenitures of the\ngods; so that, in the face of all the glad, hay-making suns, and soft\ncymballing, round harvest-moons, we must needs give in to this:", "labels": {"50": 9, "100": 75, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 6826, "position": 6826, "text": "lling, round harvest-moons, we must needs give in to this: that\nthe gods themselves are not for ever glad. The ineffaceable, sad\nbirth-mark in the brow of man, is but the stamp of sorrow in the\nsign", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 437, "2000": 1886}}, {"id": 6827, "position": 6827, "text": "in the brow of man, is but the stamp of sorrow in the\nsigners.\n\nUnwittingly here a secret has been divulged, which perhaps might more\nproperly, in set way, have been disclosed before", "labels": {"50": 35, "100": 94, "250": 23, "500": 198, "1000": 793, "2000": 1470}}, {"id": 6828, "position": 6828, "text": "properly, in set way, have been disclosed before. With many other\nparticulars concerning Ahab, always had it remained a mystery to some,\nwhy it was, that for a certain period, both before and after the\nsailing of the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6829, "position": 6829, "text": "a certain period, both before and after the\nsailing of the Pequod, he had hidden himself away with such\nGrand-Lama-like exclusiveness; and, for that one interval, sought\nspeechless refuge, as it were, among the marble senate", "labels": {"50": 22, "100": 87, "250": 245, "500": 43, "1000": 62, "2000": 1554}}, {"id": 6830, "position": 6830, "text": "one interval, sought\nspeechless refuge, as it were, among the marble senate of the dead.\nCaptain Peleg’s bruited reason for this thing appeared by no means\nadequate; though, indeed, as touching all Ahab’s deeper part", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6831, "position": 6831, "text": "adequate; though, indeed, as touching all Ahab’s deeper part, every\nrevelation partook more of significant darkness than of explanatory\nlight. But, in the end, it all came out; this one matter did, at least", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6832, "position": 6832, "text": "the end, it all came out; this one matter did, at least.\nThat direful mishap was at the bottom of his temporary recluseness. And\nnot only this, but to that ever-contracting, dropping circle ashore,", "labels": {"50": 0, "100": 88, "250": 0, "500": 98, "1000": 443, "2000": 1217}}, {"id": 6833, "position": 6833, "text": "not only this, but to that ever-contracting, dropping circle ashore,\nwho, for any reason, possessed the privilege of a less banned approach\nto him; to that timid circle the above hinted casualty—remaining, as it\ndid, moodily", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 1620}}, {"id": 6834, "position": 6834, "text": "id circle the above hinted casualty—remaining, as it\ndid, moodily unaccounted for by Ahab—invested itself with terrors, not\nentirely underived from the land of spirits and of wails", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6835, "position": 6835, "text": "from the land of spirits and of wails. So that,\nthrough their zeal for him, they had all conspired, so far as in them\nlay, to muffle up the knowledge of this thing from others; and hence it\nwas", "labels": {"50": 27, "100": 33, "250": 112, "500": 135, "1000": 454, "2000": 214}}, {"id": 6836, "position": 6836, "text": "muffle up the knowledge of this thing from others; and hence it\nwas, that not till a considerable interval had elapsed, did it\ntranspire upon the Pequod’s decks.\n\nBut be all this as it may; let the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6837, "position": 6837, "text": "od’s decks.\n\nBut be all this as it may; let the unseen, ambiguous synod in the air,\nor the vindictive princes and potentates of fire, have to do or not\nwith earthly Ahab, yet, in this present", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6838, "position": 6838, "text": "have to do or not\nwith earthly Ahab, yet, in this present matter of his leg, he took\nplain practical procedures;—he called the carpenter.\n\nAnd when that functionary appeared before him, he bade him without\ndelay set about making", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6839, "position": 6839, "text": "functionary appeared before him, he bade him without\ndelay set about making a new leg, and directed the mates to see him\nsupplied with all the studs and joists of jaw-ivory (Sperm Whale) which\nhad thus far been accumulated on", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6840, "position": 6840, "text": "of jaw-ivory (Sperm Whale) which\nhad thus far been accumulated on the voyage, in order that a careful\nselection of the stoutest, clearest-grained stuff might be secured.\nThis done, the carpenter received orders to have the leg", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6841, "position": 6841, "text": "might be secured.\nThis done, the carpenter received orders to have the leg completed that\nnight; and to provide all the fittings for it, independent of those\npertaining to the distrusted one in use. Moreover, the ship’s forge was\nordered", "labels": {"50": 45, "100": 63, "250": 152, "500": 206, "1000": 678, "2000": 489}}, {"id": 6842, "position": 6842, "text": "distrusted one in use. Moreover, the ship’s forge was\nordered to be hoisted out of its temporary idleness in the hold; and,\nto accelerate the affair, the blacksmith was commanded to proceed at\nonce to the forging of whatever iron", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 6843, "position": 6843, "text": "the blacksmith was commanded to proceed at\nonce to the forging of whatever iron contrivances might be needed.\n\n\nCHAPTER 107. The Carpenter.\n\nSeat thyself sultanically among the moons of Saturn, and take high\nabstracted man alone; and he", "labels": {"50": 22, "100": 63, "250": 152, "500": 206, "1000": 678, "2000": 1850}}, {"id": 6844, "position": 6844, "text": "the moons of Saturn, and take high\nabstracted man alone; and he seems a wonder, a grandeur, and a woe. But\nfrom the same point, take mankind in mass, and for the most part, they\nseem a mob of", "labels": {"50": 8, "100": 20, "250": 49, "500": 280, "1000": 268, "2000": 1849}}, {"id": 6845, "position": 6845, "text": "mankind in mass, and for the most part, they\nseem a mob of unnecessary duplicates, both contemporary and hereditary.\nBut most humble though he was, and far from furnishing an example of\nthe high, humane abstraction; the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6846, "position": 6846, "text": "nishing an example of\nthe high, humane abstraction; the Pequod’s carpenter was no duplicate;\nhence, he now comes in person on this stage.\n\nLike all sea-going ship carpenters, and more especially those belonging\nto whaling vessels", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6847, "position": 6847, "text": "sea-going ship carpenters, and more especially those belonging\nto whaling vessels, he was, to a certain off-handed, practical extent,\nalike experienced in numerous trades and callings collateral to his\nown; the carpenter’s pursuit being the ancient", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6848, "position": 6848, "text": "callings collateral to his\nown; the carpenter’s pursuit being the ancient and outbranching trunk\nof all those numerous handicrafts which more or less have to do with\nwood as an auxiliary material", "labels": {"50": 31, "100": 7, "250": 193, "500": 307, "1000": 343, "2000": 1394}}, {"id": 6849, "position": 6849, "text": "do with\nwood as an auxiliary material. But, besides the application to him of\nthe generic remark above, this carpenter of the Pequod was singularly\nefficient in those thousand nameless mechanical emergencies continually\nrecurring in a large ship, upon a three or", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6850, "position": 6850, "text": "nameless mechanical emergencies continually\nrecurring in a large ship, upon a three or four years’ voyage, in\nuncivilized and far-distant seas. For not to speak of his readiness in\nordinary duties:—repairing stove boats, sprung spars", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6851, "position": 6851, "text": "of his readiness in\nordinary duties:—repairing stove boats, sprung spars, reforming the\nshape of clumsy-bladed oars, inserting bull’s eyes in the deck, or new\ntree-nails in the side planks, and other miscellaneous", "labels": {"50": 44, "100": 37, "250": 143, "500": 481, "1000": 477, "2000": 1966}}, {"id": 6852, "position": 6852, "text": ", or new\ntree-nails in the side planks, and other miscellaneous matters more\ndirectly pertaining to his special business; he was moreover\nunhesitatingly expert in all manner of conflicting aptitudes, both\nuseful and capricious.", "labels": {"50": 32, "100": 90, "250": 121, "500": 74, "1000": 577, "2000": 1220}}, {"id": 6853, "position": 6853, "text": "of conflicting aptitudes, both\nuseful and capricious.\n\nThe one grand stage where he enacted all his various parts so manifold,\nwas his vice-bench; a long rude ponderous table furnished with several\nvices, of different sizes, and", "labels": {"50": 23, "100": 52, "250": 244, "500": 202, "1000": 833, "2000": 1039}}, {"id": 6854, "position": 6854, "text": "rude ponderous table furnished with several\nvices, of different sizes, and both of iron and of wood. At all times\nexcept when whales were alongside, this bench was securely lashed\nathwartships against the rear of the Try-works.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 851, "2000": 1620}}, {"id": 6855, "position": 6855, "text": "lashed\nathwartships against the rear of the Try-works.\n\nA belaying pin is found too large to be easily inserted into its hole:\nthe carpenter claps it into one of his ever-ready vices, and\nstraightway files it", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 6856, "position": 6856, "text": "into one of his ever-ready vices, and\nstraightway files it smaller. A lost land-bird of strange plumage\nstrays on board, and is made a captive: out of clean shaved rods of\nright-whale bone, and cross-", "labels": {"50": 9, "100": 24, "250": 213, "500": 72, "1000": 825, "2000": 1225}}, {"id": 6857, "position": 6857, "text": ": out of clean shaved rods of\nright-whale bone, and cross-beams of sperm whale ivory, the carpenter\nmakes a pagoda-looking cage for it. An oarsman sprains his wrist: the\ncarpenter concocts a soothing lot", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6858, "position": 6858, "text": "man sprains his wrist: the\ncarpenter concocts a soothing lotion. Stubb longed for vermillion stars\nto be painted upon the blade of his every oar; screwing each oar in his\nbig vice of wood, the", "labels": {"50": 31, "100": 20, "250": 49, "500": 78, "1000": 165, "2000": 1081}}, {"id": 6859, "position": 6859, "text": "oar; screwing each oar in his\nbig vice of wood, the carpenter symmetrically supplies the\nconstellation. A sailor takes a fancy to wear shark-bone ear-rings: the\ncarpenter drills his ears", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 6860, "position": 6860, "text": ": the\ncarpenter drills his ears. Another has the toothache: the carpenter out\npincers, and clapping one hand upon his bench bids him be seated there;\nbut the poor fellow unmanageably winces under the unconcluded\noperation", "labels": {"50": 5, "100": 78, "250": 177, "500": 250, "1000": 890, "2000": 988}}, {"id": 6861, "position": 6861, "text": "poor fellow unmanageably winces under the unconcluded\noperation; whirling round the handle of his wooden vice, the carpenter\nsigns him to clap his jaw in that, if he would have him draw the tooth.", "labels": {"50": 31, "100": 16, "250": 49, "500": 78, "1000": 165, "2000": 1394}}, {"id": 6862, "position": 6862, "text": "in that, if he would have him draw the tooth.\n\nThus, this carpenter was prepared at all points, and alike indifferent\nand without respect in all. Teeth he accounted bits of ivory; heads he\ndeemed but top-blocks; men themselves he lightly", "labels": {"50": 1, "100": 56, "250": 128, "500": 415, "1000": 799, "2000": 973}}, {"id": 6863, "position": 6863, "text": "of ivory; heads he\ndeemed but top-blocks; men themselves he lightly held for capstans. But\nwhile now upon so wide a field thus variously accomplished and with\nsuch liveliness of expertness in him, too; all this would seem to", "labels": {"50": 0, "100": 69, "250": 0, "500": 98, "1000": 443, "2000": 218}}, {"id": 6864, "position": 6864, "text": "liveliness of expertness in him, too; all this would seem to argue\nsome uncommon vivacity of intelligence. But not precisely so. For\nnothing was this man more remarkable, than for a certain impersonal\nstolidity as it were;", "labels": {"50": 23, "100": 88, "250": 244, "500": 202, "1000": 962, "2000": 638}}, {"id": 6865, "position": 6865, "text": ", than for a certain impersonal\nstolidity as it were; impersonal, I say; for it so shaded off into the\nsurrounding infinite of things, that it seemed one with the general\nstolidity discernible in the whole", "labels": {"50": 0, "100": 91, "250": 0, "500": 98, "1000": 443, "2000": 1217}}, {"id": 6866, "position": 6866, "text": "it seemed one with the general\nstolidity discernible in the whole visible world; which while\npauselessly active in uncounted modes, still eternally holds its peace,\nand ignores you, though you dig foundations for cathedrals", "labels": {"50": 48, "100": 27, "250": 223, "500": 339, "1000": 832, "2000": 180}}, {"id": 6867, "position": 6867, "text": "peace,\nand ignores you, though you dig foundations for cathedrals. Yet was\nthis half-horrible stolidity in him, involving, too, as it appeared, an\nall-ramifying heartlessness;—yet was it oddly dashed at times", "labels": {"50": 31, "100": 75, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 6868, "position": 6868, "text": "all-ramifying heartlessness;—yet was it oddly dashed at times, with an\nold, crutch-like, antediluvian, wheezing humorousness, not unstreaked\nnow and then with a certain gr", "labels": {"50": 17, "100": 68, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 6869, "position": 6869, "text": "humorousness, not unstreaked\nnow and then with a certain grizzled wittiness; such as might have\nserved to pass the time during the midnight watch on the bearded\nforecastle of Noah’s ark", "labels": {"50": 7, "100": 57, "250": 70, "500": 204, "1000": 858, "2000": 602}}, {"id": 6870, "position": 6870, "text": "on the bearded\nforecastle of Noah’s ark. Was it that this old carpenter had been a\nlife-long wanderer, whose much rolling, to and fro, not only had\ngathered no moss; but what is more, had rubbed off", "labels": {"50": 22, "100": 78, "250": 229, "500": 286, "1000": 631, "2000": 1027}}, {"id": 6871, "position": 6871, "text": "not only had\ngathered no moss; but what is more, had rubbed off whatever small\noutward clingings might have originally pertained to him? He was a\nstript abstract; an unfractioned integral; uncompromised as a new", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 984, "2000": 1469}}, {"id": 6872, "position": 6872, "text": "an unfractioned integral; uncompromised as a new-born\nbabe; living without premeditated reference to this world or the next.\nYou might almost say, that this strange uncompromisedness in him\ninvolved a", "labels": {"50": 17, "100": 16, "250": 87, "500": 182, "1000": 355, "2000": 1601}}, {"id": 6873, "position": 6873, "text": "say, that this strange uncompromisedness in him\ninvolved a sort of unintelligence; for in his numerous trades, he did\nnot seem to work so much by reason or by instinct, or simply because he\nhad been tutored", "labels": {"50": 43, "100": 48, "250": 71, "500": 118, "1000": 943, "2000": 237}}, {"id": 6874, "position": 6874, "text": "much by reason or by instinct, or simply because he\nhad been tutored to it, or by any intermixture of all these, even or\nuneven; but merely by a kind of deaf and dumb, spontaneous literal\nprocess", "labels": {"50": 10, "100": 71, "250": 232, "500": 273, "1000": 134, "2000": 998}}, {"id": 6875, "position": 6875, "text": "by a kind of deaf and dumb, spontaneous literal\nprocess. He was a pure manipulator; his brain, if he had ever had one,\nmust have early oozed along into the muscles of his fingers", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 872, "2000": 213}}, {"id": 6876, "position": 6876, "text": "ozed along into the muscles of his fingers. He was\nlike one of those unreasoning but still highly useful, _multum in\nparvo_, Sheffield contrivances, assuming the exterior—though a little\nswelled—of a", "labels": {"50": 23, "100": 64, "250": 193, "500": 202, "1000": 851, "2000": 110}}, {"id": 6877, "position": 6877, "text": "contrivances, assuming the exterior—though a little\nswelled—of a common pocket knife; but containing, not only blades of\nvarious sizes, but also screw-drivers, cork-screws, tweezers, awls,\npens, rulers", "labels": {"50": 7, "100": 88, "250": 193, "500": 202, "1000": 383, "2000": 110}}, {"id": 6878, "position": 6878, "text": "cork-screws, tweezers, awls,\npens, rulers, nail-filers, countersinkers. So, if his superiors wanted\nto use the carpenter for a screw-driver, all they had to do was to open\nthat", "labels": {"50": 37, "100": 11, "250": 19, "500": 184, "1000": 932, "2000": 1284}}, {"id": 6879, "position": 6879, "text": "for a screw-driver, all they had to do was to open\nthat part of him, and the screw was fast: or if for tweezers, take him\nup by the legs, and there they were.", "labels": {"50": 37, "100": 12, "250": 212, "500": 21, "1000": 690, "2000": 401}}, {"id": 6880, "position": 6880, "text": "by the legs, and there they were.\n\nYet, as previously hinted, this omnitooled, open-and-shut carpenter,\nwas, after all, no mere machine of an automaton", "labels": {"50": 22, "100": 51, "250": 19, "500": 206, "1000": 678, "2000": 1850}}, {"id": 6881, "position": 6881, "text": "mere machine of an automaton. If he did not have a\ncommon soul in him, he had a subtle something that somehow anomalously\ndid its duty. What that was, whether essence of quicksilver, or a few\ndrops of", "labels": {"50": 22, "100": 78, "250": 19, "500": 469, "1000": 631, "2000": 213}}, {"id": 6882, "position": 6882, "text": "that was, whether essence of quicksilver, or a few\ndrops of hartshorn, there is no telling. But there it was; and there it\nhad abided for now some sixty years or more", "labels": {"50": 48, "100": 27, "250": 53, "500": 223, "1000": 995, "2000": 1102}}, {"id": 6883, "position": 6883, "text": "for now some sixty years or more. And this it was, this same\nunaccountable, cunning life-principle in him; this it was, that kept\nhim a great part of the time soliloquizing; but only like an\nun", "labels": {"50": 17, "100": 60, "250": 217, "500": 252, "1000": 712, "2000": 813}}, {"id": 6884, "position": 6884, "text": "great part of the time soliloquizing; but only like an\nunreasoning wheel, which also hummingly soliloquizes; or rather, his\nbody was a sentry-box and this soliloquizer on guard there,", "labels": {"50": 31, "100": 75, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 6885, "position": 6885, "text": "a sentry-box and this soliloquizer on guard there, and talking\nall the time to keep himself awake.\n\n\nCHAPTER 108. Ahab and the Carpenter.\n\nThe Deck—First Night Watch.", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 6886, "position": 6886, "text": "Deck—First Night Watch.\n\n(_Carpenter standing before his vice-bench, and by the light of two\nlanterns busily filing the ivory joist for the leg, which joist is\nfirmly fixed in the vice", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 6887, "position": 6887, "text": "joist is\nfirmly fixed in the vice. Slabs of ivory, leather straps, pads, screws,\nand various tools of all sorts lying about the bench. Forward, the red\nflame of the forge is seen, where the blacksmith is at work.", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 497, "2000": 1259}}, {"id": 6888, "position": 6888, "text": "red\nflame of the forge is seen, where the blacksmith is at work._)\n\nDrat the file, and drat the bone! That is hard which should be soft,\nand that is soft which should be hard", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 174, "2000": 916}}, {"id": 6889, "position": 6889, "text": ",\nand that is soft which should be hard. So we go, who file old jaws and\nshinbones. Let’s try another. Aye, now, this works better (_sneezes_)", "labels": {"50": 6, "100": 1, "250": 193, "500": 326, "1000": 24, "2000": 369}}, {"id": 6890, "position": 6890, "text": "better (_sneezes_).\nHalloa, this bone dust is (_sneezes_)—why it’s (_sneezes_)—yes it’s\n(_sneezes_)—bless my", "labels": {"50": 40, "100": 47, "250": 27, "500": 283, "1000": 112, "2000": 919}}, {"id": 6891, "position": 6891, "text": "—yes it’s\n(_sneezes_)—bless my soul, it won’t let me speak! This is what an old\nfellow gets now for working in dead lumber. Saw a live tree, and you\ndon’t get", "labels": {"50": 34, "100": 77, "250": 164, "500": 192, "1000": 427, "2000": 900}}, {"id": 6892, "position": 6892, "text": "in dead lumber. Saw a live tree, and you\ndon’t get this dust; amputate a live bone, and you don’t get it\n(_sneezes_). Come, come, you old Smut, there", "labels": {"50": 41, "100": 21, "250": 91, "500": 5, "1000": 333, "2000": 355}}, {"id": 6893, "position": 6893, "text": "neezes_). Come, come, you old Smut, there, bear a hand, and let’s\nhave that ferule and buckle-screw; I’ll be ready for them presently", "labels": {"50": 6, "100": 1, "250": 193, "500": 36, "1000": 849, "2000": 421}}, {"id": 6894, "position": 6894, "text": "’ll be ready for them presently.\nLucky now (_sneezes_) there’s no knee-joint to make; that might puzzle\na little; but a mere shinbone—why it’s easy as making hop-poles;", "labels": {"50": 41, "100": 64, "250": 193, "500": 498, "1000": 54, "2000": 68}}, {"id": 6895, "position": 6895, "text": "mere shinbone—why it’s easy as making hop-poles; only I\nshould like to put a good finish on. Time, time; if I but only had the\ntime, I could turn him out as neat a leg now as ever", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 851, "2000": 1620}}, {"id": 6896, "position": 6896, "text": "the\ntime, I could turn him out as neat a leg now as ever (_sneezes_)\nscraped to a lady in a parlor. Those buckskin legs and calves of legs\nI’ve seen in shop windows wouldn’t compare at", "labels": {"50": 48, "100": 27, "250": 157, "500": 63, "1000": 765, "2000": 1696}}, {"id": 6897, "position": 6897, "text": "calves of legs\nI’ve seen in shop windows wouldn’t compare at all. They soak water,\nthey do; and of course get rheumatic, and have to be doctored\n(_sneezes_) with washes and", "labels": {"50": 11, "100": 8, "250": 183, "500": 356, "1000": 798, "2000": 51}}, {"id": 6898, "position": 6898, "text": "to be doctored\n(_sneezes_) with washes and lotions, just like live legs. There; before\nI saw it off, now, I must call his old Mogulship, and see whether the\nlength will be all", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 6899, "position": 6899, "text": "call his old Mogulship, and see whether the\nlength will be all right; too short, if anything, I guess. Ha! that’s\nthe heel; we are in luck; here he comes, or it’s somebody else,", "labels": {"50": 23, "100": 64, "250": 193, "500": 229, "1000": 54, "2000": 1790}}, {"id": 6900, "position": 6900, "text": "are in luck; here he comes, or it’s somebody else, that’s\ncertain.\n\nAHAB (_advancing_). (_During the ensuing scene, the carpenter continues\nsneezing at times._)", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 719, "2000": 1479}}, {"id": 6901, "position": 6901, "text": "the carpenter continues\nsneezing at times._)\n\nWell, manmaker!\n\nJust in time, sir. If the captain pleases, I will now mark the length.\nLet me measure, sir.\n\nMeasured for a leg! good", "labels": {"50": 6, "100": 1, "250": 42, "500": 326, "1000": 719, "2000": 1253}}, {"id": 6902, "position": 6902, "text": "Let me measure, sir.\n\nMeasured for a leg! good. Well, it’s not the first time. About it!\nThere; keep thy finger on it. This is a cogent vice thou hast here,\ncarpenter; let me feel", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6903, "position": 6903, "text": "is a cogent vice thou hast here,\ncarpenter; let me feel its grip once. So, so; it does pinch some.\n\nOh, sir, it will break bones—beware, beware!", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6904, "position": 6904, "text": "bones—beware, beware!\n\nNo fear; I like a good grip; I like to feel something in this slippery\nworld that can hold, man. What’s Prometheus about there?—the\nblacksmith, I mean—what’", "labels": {"50": 6, "100": 49, "250": 30, "500": 244, "1000": 345, "2000": 1773}}, {"id": 6905, "position": 6905, "text": "Prometheus about there?—the\nblacksmith, I mean—what’s he about?\n\nHe must be forging the buckle-screw, sir, now.\n\nRight. It’s a partnership; he supplies the muscle part", "labels": {"50": 39, "100": 99, "250": 57, "500": 133, "1000": 488, "2000": 51}}, {"id": 6906, "position": 6906, "text": "It’s a partnership; he supplies the muscle part. He makes a\nfierce red flame there!\n\nAye, sir; he must have the white heat for this kind of fine work.\n\nUm-m. So he must", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 488, "2000": 1199}}, {"id": 6907, "position": 6907, "text": "work.\n\nUm-m. So he must. I do deem it now a most meaning thing, that that old\nGreek, Prometheus, who made men, they say, should have been a\nblacksmith, and animated them with fire; for", "labels": {"50": 9, "100": 75, "250": 13, "500": 307, "1000": 343, "2000": 761}}, {"id": 6908, "position": 6908, "text": "say, should have been a\nblacksmith, and animated them with fire; for what’s made in fire must\nproperly belong to fire; and so hell’s probable. How the soot flies!\nThis must be the remainder the Greek made the Africans", "labels": {"50": 9, "100": 26, "250": 30, "500": 475, "1000": 902, "2000": 1374}}, {"id": 6909, "position": 6909, "text": "the soot flies!\nThis must be the remainder the Greek made the Africans of. Carpenter,\nwhen he’s through with that buckle, tell him to forge a pair of steel\nshoulder-blades; there’s a pedlar aboard with a", "labels": {"50": 45, "100": 64, "250": 212, "500": 21, "1000": 690, "2000": 401}}, {"id": 6910, "position": 6910, "text": "steel\nshoulder-blades; there’s a pedlar aboard with a crushing pack.\n\nSir?\n\nHold; while Prometheus is about it, I’ll order a complete man after a\ndesirable pattern", "labels": {"50": 6, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 6911, "position": 6911, "text": "complete man after a\ndesirable pattern. Imprimis, fifty feet high in his socks; then, chest\nmodelled after the Thames Tunnel; then, legs with roots to ’em, to stay\nin one place; then, arms three feet through the wrist", "labels": {"50": 31, "100": 7, "250": 193, "500": 307, "1000": 849, "2000": 1107}}, {"id": 6912, "position": 6912, "text": ", to stay\nin one place; then, arms three feet through the wrist; no heart at all,\nbrass forehead, and about a quarter of an acre of fine brains; and let\nme see—shall I order eyes to see outwards? No", "labels": {"50": 8, "100": 14, "250": 132, "500": 374, "1000": 27, "2000": 1204}}, {"id": 6913, "position": 6913, "text": "and let\nme see—shall I order eyes to see outwards? No, but put a sky-light on\ntop of his head to illuminate inwards. There, take the order, and away.", "labels": {"50": 9, "100": 1, "250": 42, "500": 244, "1000": 358, "2000": 1038}}, {"id": 6914, "position": 6914, "text": ", take the order, and away.\n\nNow, what’s he speaking about, and who’s he speaking to, I should like\nto know? Shall I keep standing here? (_aside_).", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 719, "2000": 1253}}, {"id": 6915, "position": 6915, "text": "here? (_aside_).\n\n’Tis but indifferent architecture to make a blind dome; here’s one. No,\nno, no; I must have a lantern.\n\nHo, ho! That’s it, hey? Here are two", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 719, "2000": 916}}, {"id": 6916, "position": 6916, "text": ".\n\nHo, ho! That’s it, hey? Here are two, sir; one will serve my turn.\n\nWhat art thou thrusting that thief-catcher into my face for, man?\nThrusted light is worse than presented pistols.", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 6917, "position": 6917, "text": "for, man?\nThrusted light is worse than presented pistols.\n\nI thought, sir, that you spoke to carpenter.\n\nCarpenter? why that’s—but no;—a very tidy, and, I may say, an extremely\ngentlemanlike sort", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 6918, "position": 6918, "text": "a very tidy, and, I may say, an extremely\ngentlemanlike sort of business thou art in here, carpenter;—or would’st\nthou rather work in clay?\n\nSir?—Clay? clay, sir? That’s mud; we", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 317, "2000": 1087}}, {"id": 6919, "position": 6919, "text": "Sir?—Clay? clay, sir? That’s mud; we leave clay to ditchers, sir.\n\nThe fellow’s impious! What art thou sneezing about?\n\nBone is rather dusty, sir.", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 6920, "position": 6920, "text": "zing about?\n\nBone is rather dusty, sir.\n\nTake the hint, then; and when thou art dead, never bury thyself under\nliving people’s noses.\n\nSir?—oh! ah!—I guess so;—yes—oh", "labels": {"50": 9, "100": 26, "250": 193, "500": 498, "1000": 849, "2000": 1620}}, {"id": 6921, "position": 6921, "text": "?—oh! ah!—I guess so;—yes—oh, dear!\n\nLook ye, carpenter, I dare say thou callest thyself a right good\nworkmanlike workman, eh? Well, then, will it speak", "labels": {"50": 35, "100": 94, "250": 23, "500": 198, "1000": 201, "2000": 172}}, {"id": 6922, "position": 6922, "text": "workmanlike workman, eh? Well, then, will it speak thoroughly well for\nthy work, if, when I come to mount this leg thou makest, I shall\nnevertheless feel another leg in the same identical place with it; that\nis", "labels": {"50": 9, "100": 26, "250": 141, "500": 198, "1000": 616, "2000": 1859}}, {"id": 6923, "position": 6923, "text": "shall\nnevertheless feel another leg in the same identical place with it; that\nis, carpenter, my old lost leg; the flesh and blood one, I mean. Canst\nthou not drive that old Adam away?", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6924, "position": 6924, "text": "not drive that old Adam away?\n\nTruly, sir, I begin to understand somewhat now. Yes, I have heard\nsomething curious on that score, sir; how that a dismasted man never\nentirely loses the feeling of his old spar, but", "labels": {"50": 30, "100": 45, "250": 179, "500": 310, "1000": 797, "2000": 1972}}, {"id": 6925, "position": 6925, "text": "smasted man never\nentirely loses the feeling of his old spar, but it will be still\npricking him at times. May I humbly ask if it be really so, sir?\n\nIt is, man", "labels": {"50": 23, "100": 88, "250": 193, "500": 36, "1000": 849, "2000": 421}}, {"id": 6926, "position": 6926, "text": ", sir?\n\nIt is, man. Look, put thy live leg here in the place where mine once\nwas; so, now, here is only one distinct leg to the eye, yet two to the\nsoul", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 6927, "position": 6927, "text": "eye, yet two to the\nsoul. Where thou feelest tingling life; there, exactly there, there to\na hair, do I. Is’t a riddle?\n\nI should humbly call it a poser, sir.\n\nHist, then", "labels": {"50": 9, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 6928, "position": 6928, "text": "should humbly call it a poser, sir.\n\nHist, then. How dost thou know that some entire, living, thinking thing\nmay not be invisibly and uninterpenetratingly standing precisely where\nthou now standest", "labels": {"50": 9, "100": 26, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 6929, "position": 6929, "text": "and uninterpenetratingly standing precisely where\nthou now standest; aye, and standing there in thy spite? In thy most\nsolitary hours, then, dost thou not fear eavesdroppers? Hold, don’t\nspeak!", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 946}}, {"id": 6930, "position": 6930, "text": "thou not fear eavesdroppers? Hold, don’t\nspeak! And if I still feel the smart of my crushed leg, though it be\nnow so long dissolved; then, why mayst not thou, carpenter, feel the\nfiery pains of", "labels": {"50": 9, "100": 26, "250": 120, "500": 180, "1000": 50, "2000": 1859}}, {"id": 6931, "position": 6931, "text": "then, why mayst not thou, carpenter, feel the\nfiery pains of hell for ever, and without a body? Hah!\n\nGood Lord! Truly, sir, if it comes to that, I must calculate over\nagain; I think I didn", "labels": {"50": 9, "100": 26, "250": 42, "500": 198, "1000": 589, "2000": 39}}, {"id": 6932, "position": 6932, "text": "it comes to that, I must calculate over\nagain; I think I didn’t carry a small figure, sir.\n\nLook ye, pudding-heads should never grant premises.—How long before the\nleg is done?\n\nPerhaps an hour, sir.", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 6933, "position": 6933, "text": "—How long before the\nleg is done?\n\nPerhaps an hour, sir.\n\nBungle away at it then, and bring it to me (_turns to go_). Oh, Life!\nHere I am, proud as Greek god, and yet", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 6934, "position": 6934, "text": "Oh, Life!\nHere I am, proud as Greek god, and yet standing debtor to this\nblockhead for a bone to stand on! Cursed be that mortal\ninter-indebtedness which will not do away with ledgers", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 50, "2000": 1886}}, {"id": 6935, "position": 6935, "text": "indebtedness which will not do away with ledgers. I would be free\nas air; and I’m down in the whole world’s books. I am so rich, I could\nhave given bid for bid with the wealthiest Præ", "labels": {"50": 31, "100": 75, "250": 106, "500": 496, "1000": 290, "2000": 1741}}, {"id": 6936, "position": 6936, "text": "so rich, I could\nhave given bid for bid with the wealthiest Prætorians at the auction of\nthe Roman empire (which was the world’s); and yet I owe for the flesh\nin the tongue I brag with", "labels": {"50": 9, "100": 26, "250": 42, "500": 244, "1000": 50, "2000": 1439}}, {"id": 6937, "position": 6937, "text": "I owe for the flesh\nin the tongue I brag with. By heavens! I’ll get a crucible, and into\nit, and dissolve myself down to one small, compendious vertebra. So.", "labels": {"50": 37, "100": 64, "250": 163, "500": 72, "1000": 533, "2000": 1620}}, {"id": 6938, "position": 6938, "text": ", compendious vertebra. So.\n\nCARPENTER (_resuming his work_).\n\nWell, well, well! Stubb knows him best of all, and Stubb always says\nhe’s queer; says nothing but that one", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 849, "2000": 1620}}, {"id": 6939, "position": 6939, "text": "and Stubb always says\nhe’s queer; says nothing but that one sufficient little word queer;\nhe’s queer, says Stubb; he’s queer—queer, queer; and keeps dinning it\ninto Mr", "labels": {"50": 23, "100": 88, "250": 219, "500": 100, "1000": 488, "2000": 1199}}, {"id": 6940, "position": 6940, "text": ", queer; and keeps dinning it\ninto Mr. Starbuck all the time—queer—sir—queer, queer, very queer. And\nhere’s his leg! Yes, now that I think of it, here’s his bedfell", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6941, "position": 6941, "text": "Yes, now that I think of it, here’s his bedfellow! has\na stick of whale’s jaw-bone for a wife! And this is his leg; he’ll\nstand on this", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6942, "position": 6942, "text": "leg; he’ll\nstand on this. What was that now about one leg standing in three\nplaces, and all three places standing in one hell—how was that? Oh! I\ndon’t wonder he looked so scornful at me!", "labels": {"50": 6, "100": 64, "250": 163, "500": 180, "1000": 54, "2000": 1620}}, {"id": 6943, "position": 6943, "text": "! I\ndon’t wonder he looked so scornful at me! I’m a sort of\nstrange-thoughted sometimes, they say; but that’s only haphazard-like.\nThen, a short, little old body like", "labels": {"50": 25, "100": 41, "250": 91, "500": 128, "1000": 798, "2000": 1199}}, {"id": 6944, "position": 6944, "text": "haphazard-like.\nThen, a short, little old body like me, should never undertake to wade\nout into deep waters with tall, heron-built captains; the water chucks\nyou under the chin pretty quick, and there’s a", "labels": {"50": 25, "100": 64, "250": 163, "500": 388, "1000": 533, "2000": 693}}, {"id": 6945, "position": 6945, "text": "water chucks\nyou under the chin pretty quick, and there’s a great cry for\nlife-boats. And here’s the heron’s leg! long and slim, sure enough!\nNow, for most folks one pair of legs lasts a", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 6946, "position": 6946, "text": ", sure enough!\nNow, for most folks one pair of legs lasts a lifetime, and that must be\nbecause they use them mercifully, as a tender-hearted old lady uses her\nroly-poly old coach-horses", "labels": {"50": 48, "100": 20, "250": 53, "500": 126, "1000": 727, "2000": 1107}}, {"id": 6947, "position": 6947, "text": "lady uses her\nroly-poly old coach-horses. But Ahab; oh he’s a hard driver. Look,\ndriven one leg to death, and spavined the other for life, and now wears\nout bone legs by the cord", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6948, "position": 6948, "text": "d the other for life, and now wears\nout bone legs by the cord. Halloa, there, you Smut! bear a hand there\nwith those screws, and let’s finish it before the resurrection fellow\ncomes a-calling with his", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6949, "position": 6949, "text": "let’s finish it before the resurrection fellow\ncomes a-calling with his horn for all legs, true or false, as\nbrewery-men go round collecting old beer barrels, to fill ’em up again", "labels": {"50": 25, "100": 41, "250": 193, "500": 180, "1000": 627, "2000": 421}}, {"id": 6950, "position": 6950, "text": "to fill ’em up again.\nWhat a leg this is! It looks like a real live leg, filed down to\nnothing but the core; he’ll be standing on this to-morrow; he’ll be\ntaking altitudes on it", "labels": {"50": 37, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 6951, "position": 6951, "text": "this to-morrow; he’ll be\ntaking altitudes on it. Halloa! I almost forgot the little oval slate,\nsmoothed ivory, where he figures up the latitude. So, so; chisel, file,\nand sand-paper, now", "labels": {"50": 39, "100": 88, "250": 57, "500": 228, "1000": 962, "2000": 638}}, {"id": 6952, "position": 6952, "text": "So, so; chisel, file,\nand sand-paper, now!\n\n\nCHAPTER 109. Ahab and Starbuck in the Cabin.\n\nAccording to usage they were pumping the ship next morning; and lo! no\ninconsiderable oil came up", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6953, "position": 6953, "text": "ship next morning; and lo! no\ninconsiderable oil came up with the water; the casks below must have\nsprung a bad leak. Much concern was shown; and Starbuck went down into\nthe cabin to report this unfavourable", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1028}}, {"id": 6954, "position": 6954, "text": "and Starbuck went down into\nthe cabin to report this unfavourable affair.*\n\n*In Sperm-whalemen with any considerable quantity of oil on board, it\nis a regular semi-weekly duty to conduct a hose into the hold, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6955, "position": 6955, "text": "a regular semi-weekly duty to conduct a hose into the hold, and\ndrench the casks with sea-water; which afterwards, at varying\nintervals, is removed by the ship’s pumps", "labels": {"50": 45, "100": 29, "250": 138, "500": 239, "1000": 327, "2000": 887}}, {"id": 6956, "position": 6956, "text": "by the ship’s pumps. Hereby the casks are sought\nto be kept damply tight; while by the changed character of the\nwithdrawn water, the mariners readily detect any serious leakage in the\nprecious cargo.", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 887}}, {"id": 6957, "position": 6957, "text": "any serious leakage in the\nprecious cargo.\n\nNow, from the South and West the Pequod was drawing nigh to Formosa and\nthe Bashee Isles, between which lies one of the tropical outlets from\nthe China waters into the Pacific", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 6958, "position": 6958, "text": "lies one of the tropical outlets from\nthe China waters into the Pacific. And so Starbuck found Ahab with a\ngeneral chart of the oriental archipelagoes spread before him; and\nanother separate one representing the long eastern coasts of the\nJapanese islands—Niphon", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6959, "position": 6959, "text": "another separate one representing the long eastern coasts of the\nJapanese islands—Niphon, Matsmai, and Sikoke. With his snow-white new\nivory leg braced against the screwed leg of his table, and with a long\npruning-", "labels": {"50": 45, "100": 90, "250": 130, "500": 499, "1000": 582, "2000": 370}}, {"id": 6960, "position": 6960, "text": "the screwed leg of his table, and with a long\npruning-hook of a jack-knife in his hand, the wondrous old man, with\nhis back to the gangway door, was wrinkling his brow, and tracing", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 6961, "position": 6961, "text": "to the gangway door, was wrinkling his brow, and tracing his\nold courses again.\n\n“Who’s there?” hearing the footstep at the door, but not turning round\nto it", "labels": {"50": 23, "100": 88, "250": 57, "500": 468, "1000": 800, "2000": 638}}, {"id": 6962, "position": 6962, "text": ", but not turning round\nto it. “On deck! Begone!”\n\n“Captain Ahab mistakes; it is I. The oil in the hold is leaking, sir.\nWe must up Burtons and break out.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 6963, "position": 6963, "text": ".\nWe must up Burtons and break out.”\n\n“Up Burtons and break out? Now that we are nearing Japan; heave-to here\nfor a week to tinker a parcel of old hoops?”", "labels": {"50": 39, "100": 41, "250": 57, "500": 187, "1000": 488, "2000": 51}}, {"id": 6964, "position": 6964, "text": "tinker a parcel of old hoops?”\n\n“Either do that, sir, or waste in one day more oil than we may make\ngood in a year. What we come twenty thousand miles to get is worth\nsaving, sir.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1620}}, {"id": 6965, "position": 6965, "text": "come twenty thousand miles to get is worth\nsaving, sir.”\n\n“So it is, so it is; if we get it.”\n\n“I was speaking of the oil in the hold, sir.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 877}}, {"id": 6966, "position": 6966, "text": "in the hold, sir.”\n\n“And I was not speaking or thinking of that at all. Begone! Let it\nleak! I’m all aleak myself. Aye! leaks in leaks! not only full of leaky\ncasks,", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 6967, "position": 6967, "text": "Aye! leaks in leaks! not only full of leaky\ncasks, but those leaky casks are in a leaky ship; and that’s a far\nworse plight than the Pequod’s, man", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6968, "position": 6968, "text": "plight than the Pequod’s, man. Yet I don’t stop to plug my leak;\nfor who can find it in the deep-loaded hull; or how hope to plug it,\neven if found, in this life’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6969, "position": 6969, "text": "how hope to plug it,\neven if found, in this life’s howling gale? Starbuck! I’ll not have the\nBurtons hoisted.”\n\n“What will the owners say, sir?”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 1620}}, {"id": 6970, "position": 6970, "text": "the owners say, sir?”\n\n“Let the owners stand on Nantucket beach and outyell the Typhoons. What\ncares Ahab? Owners, owners? Thou art always prating to me, Starbuck,\nabout those miserly owners,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6971, "position": 6971, "text": "always prating to me, Starbuck,\nabout those miserly owners, as if the owners were my conscience. But\nlook ye, the only real owner of anything is its commander; and hark ye,\nmy conscience is in this ship’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 6972, "position": 6972, "text": "commander; and hark ye,\nmy conscience is in this ship’s keel.—On deck!”\n\n“Captain Ahab,” said the reddening mate, moving further into the cabin,\nwith a daring so strangely respectful and cautious that", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6973, "position": 6973, "text": "moving further into the cabin,\nwith a daring so strangely respectful and cautious that it almost\nseemed not only every way seeking to avoid the slightest outward\nmanifestation of itself, but within also seemed more than half\ndistrustful of itself; “A better man than I", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 6974, "position": 6974, "text": "seemed more than half\ndistrustful of itself; “A better man than I might well pass over in\nthee what he would quickly enough resent in a younger man; aye, and in\na happier, Captain Ahab.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6975, "position": 6975, "text": "and in\na happier, Captain Ahab.”\n\n“Devils! Dost thou then so much as dare to critically think of me?—On\ndeck!”\n\n“Nay, sir, not yet; I do entreat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6976, "position": 6976, "text": "sir, not yet; I do entreat. And I do dare, sir—to be forbearing!\nShall we not understand each other better than hitherto, Captain Ahab?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6977, "position": 6977, "text": ", Captain Ahab?”\n\nAhab seized a loaded musket from the rack (forming part of most\nSouth-Sea-men’s cabin furniture), and pointing it towards Starbuck,\nexclaimed: “There is one God that is Lord", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6978, "position": 6978, "text": "it towards Starbuck,\nexclaimed: “There is one God that is Lord over the earth, and one\nCaptain that is lord over the Pequod.—On deck!”\n\nFor an instant in the flashing eyes of the mate, and his fiery", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6979, "position": 6979, "text": "”\n\nFor an instant in the flashing eyes of the mate, and his fiery cheeks,\nyou would have almost thought that he had really received the blaze of\nthe levelled tube. But, mastering his emotion, he half calmly rose, and\nas he quit", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 6980, "position": 6980, "text": "But, mastering his emotion, he half calmly rose, and\nas he quitted the cabin, paused for an instant and said: “Thou hast\noutraged, not insulted me, sir; but for that I ask thee not to beware\nof Star", "labels": {"50": 45, "100": 64, "250": 102, "500": 73, "1000": 925, "2000": 142}}, {"id": 6981, "position": 6981, "text": ", sir; but for that I ask thee not to beware\nof Starbuck; thou wouldst but laugh; but let Ahab beware of Ahab;\nbeware of thyself, old man.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6982, "position": 6982, "text": "of thyself, old man.”\n\n“He waxes brave, but nevertheless obeys; most careful bravery that!”\nmurmured Ahab, as Starbuck disappeared. “What’s that he said—Ahab\nbeware of Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6983, "position": 6983, "text": "“What’s that he said—Ahab\nbeware of Ahab—there’s something there!” Then unconsciously using the\nmusket for a staff, with an iron brow he paced to and fro in the little\ncabin;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6984, "position": 6984, "text": "with an iron brow he paced to and fro in the little\ncabin; but presently the thick plaits of his forehead relaxed, and\nreturning the gun to the rack, he went to the deck.", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 925, "2000": 967}}, {"id": 6985, "position": 6985, "text": "he went to the deck.\n\n“Thou art but too good a fellow, Starbuck,” he said lowly to the mate;\nthen raising his voice to the crew: “Furl the t’gallant-sails, and\nclose-reef the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 967}}, {"id": 6986, "position": 6986, "text": "“Furl the t’gallant-sails, and\nclose-reef the top-sails, fore and aft; back the main-yard; up Burton,\nand break out in the main-hold.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 6987, "position": 6987, "text": "in the main-hold.”\n\nIt were perhaps vain to surmise exactly why it was, that as respecting\nStarbuck, Ahab thus acted. It may have been a flash of honesty in him;\nor mere prudential policy which, under", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 6988, "position": 6988, "text": "flash of honesty in him;\nor mere prudential policy which, under the circumstance, imperiously\nforbade the slightest symptom of open disaffection, however transient,\nin the important chief officer of his ship", "labels": {"50": 23, "100": 17, "250": 160, "500": 358, "1000": 485, "2000": 1002}}, {"id": 6989, "position": 6989, "text": "transient,\nin the important chief officer of his ship. However it was, his orders\nwere executed; and the Burtons were hoisted.\n\n\nCHAPTER 110. Queequeg in His Coffin.\n\nUpon searching, it was found that the casks last struck", "labels": {"50": 45, "100": 64, "250": 82, "500": 73, "1000": 851, "2000": 967}}, {"id": 6990, "position": 6990, "text": "His Coffin.\n\nUpon searching, it was found that the casks last struck into the hold\nwere perfectly sound, and that the leak must be further off. So, it\nbeing calm weather, they broke out deeper and deeper, disturbing the\nslumbers", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 6991, "position": 6991, "text": "calm weather, they broke out deeper and deeper, disturbing the\nslumbers of the huge ground-tier butts; and from that black midnight\nsending those gigantic moles into the daylight above. So deep did they\ngo; and so ancient, and", "labels": {"50": 22, "100": 78, "250": 53, "500": 316, "1000": 995, "2000": 1071}}, {"id": 6992, "position": 6992, "text": "the daylight above. So deep did they\ngo; and so ancient, and corroded, and weedy the aspect of the lowermost\npuncheons, that you almost looked next for some mouldy corner-stone\ncask containing coins of", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 327, "2000": 887}}, {"id": 6993, "position": 6993, "text": "looked next for some mouldy corner-stone\ncask containing coins of Captain Noah, with copies of the posted\nplacards, vainly warning the infatuated old world from the flood.\nTierce after tierce, too, of water", "labels": {"50": 22, "100": 78, "250": 205, "500": 154, "1000": 873, "2000": 1465}}, {"id": 6994, "position": 6994, "text": "world from the flood.\nTierce after tierce, too, of water, and bread, and beef, and shooks of\nstaves, and iron bundles of hoops, were hoisted out, till at last the\npiled decks were hard to get", "labels": {"50": 45, "100": 64, "250": 30, "500": 475, "1000": 902, "2000": 1526}}, {"id": 6995, "position": 6995, "text": ", were hoisted out, till at last the\npiled decks were hard to get about; and the hollow hull echoed under\nfoot, as if you were treading over empty catacombs, and reeled and\nrolled in the sea like an air-freight", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 6996, "position": 6996, "text": "mbs, and reeled and\nrolled in the sea like an air-freighted demijohn. Top-heavy was the\nship as a dinnerless student with all Aristotle in his head. Well was\nit that the Typhoons did not visit them then", "labels": {"50": 22, "100": 78, "250": 229, "500": 389, "1000": 879, "2000": 956}}, {"id": 6997, "position": 6997, "text": "his head. Well was\nit that the Typhoons did not visit them then.\n\nNow, at this time it was that my poor pagan companion, and fast\nbosom-friend, Queequeg, was seized with a fever, which brought him", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1620}}, {"id": 6998, "position": 6998, "text": ", Queequeg, was seized with a fever, which brought him nigh\nto his endless end.\n\nBe it said, that in this vocation of whaling, sinecures are unknown;\ndignity and danger go hand in hand; till you", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 6999, "position": 6999, "text": "ecures are unknown;\ndignity and danger go hand in hand; till you get to be Captain, the\nhigher you rise the harder you toil. So with poor Queequeg, who, as\nharpooneer, must not only face all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7000, "position": 7000, "text": "queg, who, as\nharpooneer, must not only face all the rage of the living whale, but—as\nwe have elsewhere seen—mount his dead back in a rolling sea; and\nfinally descend into the gloom of the hold, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7001, "position": 7001, "text": "a rolling sea; and\nfinally descend into the gloom of the hold, and bitterly sweating all\nday in that subterraneous confinement, resolutely manhandle the\nclumsiest casks and see to their stowage", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7002, "position": 7002, "text": "clumsiest casks and see to their stowage. To be short, among whalemen,\nthe harpooneers are the holders, so called.\n\nPoor Queequeg! when the ship was about half disembowelled,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7003, "position": 7003, "text": "queg! when the ship was about half disembowelled, you should\nhave stooped over the hatchway, and peered down upon him there; where,\nstripped to his woollen drawers, the tattooed savage was crawling about\namid that damp", "labels": {"50": 45, "100": 64, "250": 138, "500": 180, "1000": 327, "2000": 1620}}, {"id": 7004, "position": 7004, "text": "to his woollen drawers, the tattooed savage was crawling about\namid that dampness and slime, like a green spotted lizard at the bottom\nof a well. And a well, or an ice-house, it somehow proved to him, poor\npagan", "labels": {"50": 48, "100": 20, "250": 53, "500": 389, "1000": 995, "2000": 110}}, {"id": 7005, "position": 7005, "text": ", or an ice-house, it somehow proved to him, poor\npagan; where, strange to say, for all the heat of his sweatings, he\ncaught a terrible chill which lapsed into a fever; and at last, after\nsome days", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 300, "2000": 489}}, {"id": 7006, "position": 7006, "text": "chill which lapsed into a fever; and at last, after\nsome days’ suffering, laid him in his hammock, close to the very sill\nof the door of death. How he wasted and wasted away in those few\nlong-lingering", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 475, "2000": 351}}, {"id": 7007, "position": 7007, "text": "of death. How he wasted and wasted away in those few\nlong-lingering days, till there seemed but little left of him but his\nframe and tattooing. But as all else in him thinned, and his\ncheek-bones grew sharper,", "labels": {"50": 22, "100": 55, "250": 52, "500": 389, "1000": 129, "2000": 449}}, {"id": 7008, "position": 7008, "text": "else in him thinned, and his\ncheek-bones grew sharper, his eyes, nevertheless, seemed growing fuller\nand fuller; they became of a strange softness of lustre; and mildly but\ndeeply looked out at you there from his sickness, a", "labels": {"50": 23, "100": 45, "250": 219, "500": 180, "1000": 74, "2000": 1954}}, {"id": 7009, "position": 7009, "text": "; and mildly but\ndeeply looked out at you there from his sickness, a wondrous testimony\nto that immortal health in him which could not die, or be weakened. And\nlike circles on the water, which, as they grow fainter, expand", "labels": {"50": 22, "100": 78, "250": 205, "500": 335, "1000": 779, "2000": 396}}, {"id": 7010, "position": 7010, "text": "like circles on the water, which, as they grow fainter, expand; so his\neyes seemed rounding and rounding, like the rings of Eternity. An awe\nthat cannot be named would steal over you as you sat by the side of\nthis waning", "labels": {"50": 16, "100": 20, "250": 13, "500": 414, "1000": 747, "2000": 1735}}, {"id": 7011, "position": 7011, "text": "named would steal over you as you sat by the side of\nthis waning savage, and saw as strange things in his face, as any\nbeheld who were bystanders when Zoroaster died. For whatever is truly\nwondrous and fearful", "labels": {"50": 40, "100": 10, "250": 182, "500": 27, "1000": 574, "2000": 1570}}, {"id": 7012, "position": 7012, "text": "when Zoroaster died. For whatever is truly\nwondrous and fearful in man, never yet was put into words or books. And\nthe drawing near of Death, which alike levels all, alike impresses all\nwith a last revelation, which only", "labels": {"50": 10, "100": 75, "250": 13, "500": 414, "1000": 548, "2000": 1555}}, {"id": 7013, "position": 7013, "text": "alike levels all, alike impresses all\nwith a last revelation, which only an author from the dead could\nadequately tell. So that—let us say it again—no dying Chaldee or Greek\nhad higher and holier thoughts than those, whose", "labels": {"50": 17, "100": 66, "250": 129, "500": 111, "1000": 256, "2000": 1605}}, {"id": 7014, "position": 7014, "text": "Chaldee or Greek\nhad higher and holier thoughts than those, whose mysterious shades you\nsaw creeping over the face of poor Queequeg, as he quietly lay in his\nswaying hammock, and the rolling sea seemed gently rocking him to", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 7015, "position": 7015, "text": "his\nswaying hammock, and the rolling sea seemed gently rocking him to his\nfinal rest, and the ocean’s invisible flood-tide lifted him higher and\nhigher towards his destined heaven.\n\nNot a man of the crew but gave him up; and", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7016, "position": 7016, "text": "destined heaven.\n\nNot a man of the crew but gave him up; and, as for Queequeg himself,\nwhat he thought of his case was forcibly shown by a curious favour he\nasked. He called one to him in the grey morning watch", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 7017, "position": 7017, "text": "curious favour he\nasked. He called one to him in the grey morning watch, when the day was\njust breaking, and taking his hand, said that while in Nantucket he had\nchanced to see certain little canoes of dark wood, like the", "labels": {"50": 12, "100": 38, "250": 95, "500": 344, "1000": 554, "2000": 482}}, {"id": 7018, "position": 7018, "text": "had\nchanced to see certain little canoes of dark wood, like the rich\nwar-wood of his native isle; and upon inquiry, he had learned that all\nwhalemen who died in Nantucket, were laid in those same dark canoes,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 723, "2000": 1766}}, {"id": 7019, "position": 7019, "text": "who died in Nantucket, were laid in those same dark canoes,\nand that the fancy of being so laid had much pleased him; for it was\nnot unlike the custom of his own race, who, after embalming a dead\nwarrior,", "labels": {"50": 12, "100": 38, "250": 65, "500": 171, "1000": 714, "2000": 668}}, {"id": 7020, "position": 7020, "text": "of his own race, who, after embalming a dead\nwarrior, stretched him out in his canoe, and so left him to be floated\naway to the starry archipelagoes; for not only do they believe that the\nstars are isles, but", "labels": {"50": 26, "100": 19, "250": 161, "500": 13, "1000": 312, "2000": 1097}}, {"id": 7021, "position": 7021, "text": "es; for not only do they believe that the\nstars are isles, but that far beyond all visible horizons, their own\nmild, uncontinented seas, interflow with the blue heavens; and so form\nthe white breakers of the milky way", "labels": {"50": 3, "100": 70, "250": 50, "500": 102, "1000": 747, "2000": 1374}}, {"id": 7022, "position": 7022, "text": "the blue heavens; and so form\nthe white breakers of the milky way. He added, that he shuddered at the\nthought of being buried in his hammock, according to the usual\nsea-custom, tossed like something vile to the death-dev", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 531, "2000": 967}}, {"id": 7023, "position": 7023, "text": "the usual\nsea-custom, tossed like something vile to the death-devouring sharks.\nNo: he desired a canoe like those of Nantucket, all the more congenial\nto him, being a whaleman, that like a whale-boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7024, "position": 7024, "text": "l\nto him, being a whaleman, that like a whale-boat these coffin-canoes\nwere without a keel; though that involved but uncertain steering, and\nmuch lee-way adown the dim ages.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7025, "position": 7025, "text": "-way adown the dim ages.\n\nNow, when this strange circumstance was made known aft, the carpenter\nwas at once commanded to do Queequeg’s bidding, whatever it might\ninclude. There was some heathenish, coffin-coloured", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7026, "position": 7026, "text": "whatever it might\ninclude. There was some heathenish, coffin-coloured old lumber aboard,\nwhich, upon a long previous voyage, had been cut from the aboriginal\ngroves of the Lackaday islands, and from these dark planks the coffin\nwas recommended", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 899, "2000": 52}}, {"id": 7027, "position": 7027, "text": "the Lackaday islands, and from these dark planks the coffin\nwas recommended to be made. No sooner was the carpenter apprised of the\norder, than taking his rule, he forthwith with all the indifferent\npromptitude of his character, proceeded", "labels": {"50": 45, "100": 64, "250": 138, "500": 370, "1000": 375, "2000": 965}}, {"id": 7028, "position": 7028, "text": ", he forthwith with all the indifferent\npromptitude of his character, proceeded into the forecastle and took\nQueequeg’s measure with great accuracy, regularly chalking Queequeg’s\nperson as he shifted the rule.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7029, "position": 7029, "text": "Queequeg’s\nperson as he shifted the rule.\n\n“Ah! poor fellow! he’ll have to die now,” ejaculated the Long Island\nsailor.\n\nGoing to his vice-bench, the carpenter for convenience sake and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7030, "position": 7030, "text": "sailor.\n\nGoing to his vice-bench, the carpenter for convenience sake and general\nreference, now transferringly measured on it the exact length the\ncoffin was to be, and then made the transfer permanent by cutting two\nnotches at its extremities", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 7031, "position": 7031, "text": "made the transfer permanent by cutting two\nnotches at its extremities. This done, he marshalled the planks and his\ntools, and to work.\n\nWhen the last nail was driven, and the lid duly planed and fitted, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 7032, "position": 7032, "text": "last nail was driven, and the lid duly planed and fitted, he\nlightly shouldered the coffin and went forward with it, inquiring\nwhether they were ready for it yet in that direction.\n\nOverhearing the indignant but half-humorous cries", "labels": {"50": 41, "100": 21, "250": 205, "500": 370, "1000": 375, "2000": 965}}, {"id": 7033, "position": 7033, "text": "in that direction.\n\nOverhearing the indignant but half-humorous cries with which the people\non deck began to drive the coffin away, Queequeg, to every one’s\nconsternation, commanded that the thing should be instantly brought", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7034, "position": 7034, "text": "one’s\nconsternation, commanded that the thing should be instantly brought to\nhim, nor was there any denying him; seeing that, of all mortals, some\ndying men are the most tyrannical; and certainly, since they will\nshortly trouble", "labels": {"50": 26, "100": 67, "250": 246, "500": 87, "1000": 454, "2000": 214}}, {"id": 7035, "position": 7035, "text": "are the most tyrannical; and certainly, since they will\nshortly trouble us so little for evermore, the poor fellows ought to be\nindulged.\n\nLeaning over in his hammock, Queequeg long regarded the coffin with an", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7036, "position": 7036, "text": "his hammock, Queequeg long regarded the coffin with an\nattentive eye. He then called for his harpoon, had the wooden stock\ndrawn from it, and then had the iron part placed in the coffin along\nwith one of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7037, "position": 7037, "text": ", and then had the iron part placed in the coffin along\nwith one of the paddles of his boat. All by his own request, also,\nbiscuits were then ranged round the sides within: a flask of fresh\nwater was placed at the head", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 282}}, {"id": 7038, "position": 7038, "text": "the sides within: a flask of fresh\nwater was placed at the head, and a small bag of woody earth scraped up\nin the hold at the foot; and a piece of sail-cloth being rolled up for\na pillow, Queequeg", "labels": {"50": 45, "100": 43, "250": 34, "500": 306, "1000": 126, "2000": 1817}}, {"id": 7039, "position": 7039, "text": "of sail-cloth being rolled up for\na pillow, Queequeg now entreated to be lifted into his final bed, that\nhe might make trial of its comforts, if any it had", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7040, "position": 7040, "text": "s, if any it had. He lay without\nmoving a few minutes, then told one to go to his bag and bring out his\nlittle god, Yojo. Then crossing his arms on his breast with Yojo\nbetween, he called for the coffin", "labels": {"50": 32, "100": 90, "250": 130, "500": 499, "1000": 582, "2000": 1156}}, {"id": 7041, "position": 7041, "text": "his arms on his breast with Yojo\nbetween, he called for the coffin lid (hatch he called it) to be placed\nover him. The head part turned over with a leather hinge, and there lay\nQueequeg in his coffin with", "labels": {"50": 40, "100": 13, "250": 131, "500": 370, "1000": 375, "2000": 1980}}, {"id": 7042, "position": 7042, "text": "leather hinge, and there lay\nQueequeg in his coffin with little but his composed countenance in\nview. “Rarmai” (it will do; it is easy), he murmured at last, and\nsigned to be replaced", "labels": {"50": 23, "100": 96, "250": 153, "500": 457, "1000": 897, "2000": 1701}}, {"id": 7043, "position": 7043, "text": "it is easy), he murmured at last, and\nsigned to be replaced in his hammock.\n\nBut ere this was done, Pip, who had been slily hovering near by all\nthis while, drew nigh to him where he lay", "labels": {"50": 23, "100": 88, "250": 219, "500": 367, "1000": 670, "2000": 1816}}, {"id": 7044, "position": 7044, "text": "hovering near by all\nthis while, drew nigh to him where he lay, and with soft sobbings, took\nhim by the hand; in the other, holding his tambourine.\n\n“Poor rover! will ye never have done with all this", "labels": {"50": 16, "100": 73, "250": 140, "500": 370, "1000": 838, "2000": 1474}}, {"id": 7045, "position": 7045, "text": "bourine.\n\n“Poor rover! will ye never have done with all this weary roving? where\ngo ye now? But if the currents carry ye to those sweet Antilles where\nthe beaches are only beat with water-lilies, will ye do one", "labels": {"50": 33, "100": 69, "250": 173, "500": 245, "1000": 9, "2000": 1132}}, {"id": 7046, "position": 7046, "text": "the beaches are only beat with water-lilies, will ye do one little\nerrand for me? Seek out one Pip, who’s now been missing long: I think\nhe’s in those far Antilles", "labels": {"50": 16, "100": 24, "250": 213, "500": 331, "1000": 987, "2000": 72}}, {"id": 7047, "position": 7047, "text": "think\nhe’s in those far Antilles. If ye find him, then comfort him; for he\nmust be very sad; for look! he’s left his tambourine behind;—I found\nit", "labels": {"50": 16, "100": 73, "250": 15, "500": 498, "1000": 174, "2000": 16}}, {"id": 7048, "position": 7048, "text": "ine behind;—I found\nit. Rig-a-dig, dig, dig! Now, Queequeg, die; and I’ll beat ye your\ndying march.”\n\n“I have heard,” murmured Starbuck, gazing down", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7049, "position": 7049, "text": "march.”\n\n“I have heard,” murmured Starbuck, gazing down the scuttle, “that in\nviolent fevers, men, all ignorance, have talked in ancient tongues; and\nthat when the mystery is probed, it turns out", "labels": {"50": 41, "100": 31, "250": 219, "500": 498, "1000": 317, "2000": 1087}}, {"id": 7050, "position": 7050, "text": "ancient tongues; and\nthat when the mystery is probed, it turns out always that in their\nwholly forgotten childhood those ancient tongues had been really spoken\nin their hearing by some lofty scholars. So, to my fond faith, poor\nPip, in this", "labels": {"50": 17, "100": 40, "250": 111, "500": 7, "1000": 85, "2000": 1380}}, {"id": 7051, "position": 7051, "text": "y scholars. So, to my fond faith, poor\nPip, in this strange sweetness of his lunacy, brings heavenly vouchers\nof all our heavenly homes. Where learned he that, but there?—Hark! he\nspeaks again: but", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 616, "2000": 1859}}, {"id": 7052, "position": 7052, "text": "he that, but there?—Hark! he\nspeaks again: but more wildly now.”\n\n“Form two and two! Let’s make a General of him! Ho, where’s his\nharpoon? Lay it across here.—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7053, "position": 7053, "text": "Ho, where’s his\nharpoon? Lay it across here.—Rig-a-dig, dig, dig! huzza! Oh for a game\ncock now to sit upon his head and crow! Queequeg dies game!—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7054, "position": 7054, "text": "sit upon his head and crow! Queequeg dies game!—mind ye\nthat; Queequeg dies game!—take ye good heed of that; Queequeg dies\ngame! I say; game, game, game", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7055, "position": 7055, "text": "Queequeg dies\ngame! I say; game, game, game! but base little Pip, he died a coward;\ndied all a’shiver;—out upon Pip! Hark ye; if ye find Pip, tell all the\nAntilles", "labels": {"50": 41, "100": 21, "250": 166, "500": 69, "1000": 516, "2000": 1649}}, {"id": 7056, "position": 7056, "text": "Pip! Hark ye; if ye find Pip, tell all the\nAntilles he’s a runaway; a coward, a coward, a coward! Tell them he\njumped from a whale-boat! I’d never beat my tambourine over", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 7057, "position": 7057, "text": "a whale-boat! I’d never beat my tambourine over base Pip,\nand hail him General, if he were once more dying here. No, no! shame\nupon all cowards—shame upon them! Let ’em go drown", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7058, "position": 7058, "text": "shame\nupon all cowards—shame upon them! Let ’em go drown like Pip, that\njumped from a whale-boat. Shame! shame!”\n\nDuring all this, Queequeg lay with closed eyes, as if in a dream", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7059, "position": 7059, "text": "Queequeg lay with closed eyes, as if in a dream. Pip\nwas led away, and the sick man was replaced in his hammock.\n\nBut now that he had apparently made every preparation for death; now\nthat his coffin was proved", "labels": {"50": 22, "100": 51, "250": 38, "500": 335, "1000": 496, "2000": 160}}, {"id": 7060, "position": 7060, "text": "he had apparently made every preparation for death; now\nthat his coffin was proved a good fit, Queequeg suddenly rallied; soon\nthere seemed no need of the carpenter’s box: and thereupon, when some\nexpressed their delighted surprise,", "labels": {"50": 45, "100": 64, "250": 30, "500": 370, "1000": 375, "2000": 1620}}, {"id": 7061, "position": 7061, "text": "s box: and thereupon, when some\nexpressed their delighted surprise, he, in substance, said, that the\ncause of his sudden convalescence was this;—at a critical moment, he\nhad just recalled a little duty ashore,", "labels": {"50": 44, "100": 17, "250": 9, "500": 377, "1000": 485, "2000": 1749}}, {"id": 7062, "position": 7062, "text": "—at a critical moment, he\nhad just recalled a little duty ashore, which he was leaving undone;\nand therefore had changed his mind about dying: he could not die yet,\nhe averred. They asked him, then, whether to live or", "labels": {"50": 45, "100": 29, "250": 138, "500": 28, "1000": 300, "2000": 282}}, {"id": 7063, "position": 7063, "text": ",\nhe averred. They asked him, then, whether to live or die was a matter\nof his own sovereign will and pleasure. He answered, certainly. In a\nword, it was Queequeg’s conceit, that if", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 477, "2000": 1554}}, {"id": 7064, "position": 7064, "text": ", it was Queequeg’s conceit, that if a man made up his mind to\nlive, mere sickness could not kill him: nothing but a whale, or a gale,\nor some violent, ungovernable, un", "labels": {"50": 45, "100": 64, "250": 125, "500": 384, "1000": 139, "2000": 1243}}, {"id": 7065, "position": 7065, "text": ", or a gale,\nor some violent, ungovernable, unintelligent destroyer of that sort.\n\nNow, there is this noteworthy difference between savage and civilized;\nthat while a sick, civilized man may be six months convalescing", "labels": {"50": 28, "100": 44, "250": 48, "500": 277, "1000": 4, "2000": 881}}, {"id": 7066, "position": 7066, "text": "that while a sick, civilized man may be six months convalescing,\ngenerally speaking, a sick savage is almost half-well again in a day.\nSo, in good time my Queequeg gained strength; and at length after\nsitting", "labels": {"50": 20, "100": 5, "250": 125, "500": 349, "1000": 651, "2000": 1586}}, {"id": 7067, "position": 7067, "text": "good time my Queequeg gained strength; and at length after\nsitting on the windlass for a few indolent days (but eating with a\nvigorous appetite) he suddenly leaped to his feet, threw out his arms\nand legs, gave himself a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7068, "position": 7068, "text": "leaped to his feet, threw out his arms\nand legs, gave himself a good stretching, yawned a little bit, and then\nspringing into the head of his hoisted boat, and poising a harpoon,\npronounced himself fit for a fight.", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 54, "2000": 1620}}, {"id": 7069, "position": 7069, "text": "and poising a harpoon,\npronounced himself fit for a fight.\n\nWith a wild whimsiness, he now used his coffin for a sea-chest; and\nemptying into it his canvas bag of clothes, set them in order there", "labels": {"50": 23, "100": 64, "250": 219, "500": 202, "1000": 851, "2000": 1620}}, {"id": 7070, "position": 7070, "text": "ing into it his canvas bag of clothes, set them in order there.\nMany spare hours he spent, in carving the lid with all manner of\ngrotesque figures and drawings; and it seemed that hereby he was\nstriving, in his rude way", "labels": {"50": 22, "100": 63, "250": 196, "500": 154, "1000": 390, "2000": 85}}, {"id": 7071, "position": 7071, "text": "it seemed that hereby he was\nstriving, in his rude way, to copy parts of the twisted tattooing on\nhis body. And this tattooing had been the work of a departed prophet\nand seer of his island, who, by", "labels": {"50": 45, "100": 13, "250": 182, "500": 27, "1000": 930, "2000": 1766}}, {"id": 7072, "position": 7072, "text": "work of a departed prophet\nand seer of his island, who, by those hieroglyphic marks, had written\nout on his body a complete theory of the heavens and the earth, and a\nmystical treatise on the art of attaining truth; so", "labels": {"50": 5, "100": 66, "250": 211, "500": 490, "1000": 507, "2000": 1010}}, {"id": 7073, "position": 7073, "text": "the earth, and a\nmystical treatise on the art of attaining truth; so that Queequeg in\nhis own proper person was a riddle to unfold; a wondrous work in one\nvolume; but whose mysteries not even himself could read,", "labels": {"50": 17, "100": 68, "250": 1, "500": 64, "1000": 256, "2000": 411}}, {"id": 7074, "position": 7074, "text": "us work in one\nvolume; but whose mysteries not even himself could read, though his own\nlive heart beat against them; and these mysteries were therefore\ndestined in the end to moulder away with the living parchment whereon\nthey were inscribed, and so", "labels": {"50": 16, "100": 78, "250": 26, "500": 414, "1000": 668, "2000": 1555}}, {"id": 7075, "position": 7075, "text": "ulder away with the living parchment whereon\nthey were inscribed, and so be unsolved to the last. And this thought\nit must have been which suggested to Ahab that wild exclamation of his,\nwhen one morning turning away from", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7076, "position": 7076, "text": "that wild exclamation of his,\nwhen one morning turning away from surveying poor Queequeg—“Oh,\ndevilish tantalization of the gods!”\n\n\nCHAPTER 111. The Pacific.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1668}}, {"id": 7077, "position": 7077, "text": "CHAPTER 111. The Pacific.\n\nWhen gliding by the Bashee isles we emerged at last upon the great\nSouth Sea; were it not for other things, I could have greeted my dear\nPacific with uncounted thanks, for now the long supp", "labels": {"50": 45, "100": 29, "250": 34, "500": 72, "1000": 126, "2000": 187}}, {"id": 7078, "position": 7078, "text": "dear\nPacific with uncounted thanks, for now the long supplication of my\nyouth was answered; that serene ocean rolled eastwards from me a\nthousand leagues of blue.\n\nThere is, one knows not what sweet mystery about this sea,", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 9, "2000": 887}}, {"id": 7079, "position": 7079, "text": "blue.\n\nThere is, one knows not what sweet mystery about this sea, whose gently\nawful stirrings seem to speak of some hidden soul beneath; like those\nfabled undulations of the Ephesian sod over the buried Evangelist St.\nJohn", "labels": {"50": 48, "100": 20, "250": 223, "500": 334, "1000": 747, "2000": 682}}, {"id": 7080, "position": 7080, "text": "s of the Ephesian sod over the buried Evangelist St.\nJohn. And meet it is, that over these sea-pastures, wide-rolling watery\nprairies and Potters’ Fields of all four continents, the waves should\nrise and fall", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 7081, "position": 7081, "text": "Potters’ Fields of all four continents, the waves should\nrise and fall, and ebb and flow unceasingly; for here, millions of\nmixed shades and shadows, drowned dreams, somnambulisms, reveries; all", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 573}}, {"id": 7082, "position": 7082, "text": ", drowned dreams, somnambulisms, reveries; all\nthat we call lives and souls, lie dreaming, dreaming, still; tossing\nlike slumberers in their beds; the ever-rolling waves but made so by\ntheir restlessness", "labels": {"50": 9, "100": 26, "250": 120, "500": 333, "1000": 122, "2000": 712}}, {"id": 7083, "position": 7083, "text": "their beds; the ever-rolling waves but made so by\ntheir restlessness.\n\nTo any meditative Magian rover, this serene Pacific, once beheld, must\never after be the sea of his adoption", "labels": {"50": 16, "100": 20, "250": 133, "500": 162, "1000": 9, "2000": 682}}, {"id": 7084, "position": 7084, "text": "be the sea of his adoption. It rolls the midmost waters of\nthe world, the Indian ocean and Atlantic being but its arms. The same\nwaves wash the moles of the new-built Californian towns, but yesterday\nplanted by the recentest", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7085, "position": 7085, "text": "the new-built Californian towns, but yesterday\nplanted by the recentest race of men, and lave the faded but still\ngorgeous skirts of Asiatic lands, older than Abraham; while all between\nfloat milky-ways of coral isles, and low-", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 709}}, {"id": 7086, "position": 7086, "text": "; while all between\nfloat milky-ways of coral isles, and low-lying, endless, unknown\nArchipelagoes, and impenetrable Japans. Thus this mysterious, divine\nPacific zones the world’s whole bulk about; makes all coasts one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7087, "position": 7087, "text": "divine\nPacific zones the world’s whole bulk about; makes all coasts one bay to\nit; seems the tide-beating heart of earth. Lifted by those eternal\nswells, you needs must own the seductive god, bowing your head to Pan.", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 573}}, {"id": 7088, "position": 7088, "text": "you needs must own the seductive god, bowing your head to Pan.\n\nBut few thoughts of Pan stirred Ahab’s brain, as standing like an iron\nstatue at his accustomed place beside the mizen rigging, with one\nnostril he un", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 1107}}, {"id": 7089, "position": 7089, "text": "place beside the mizen rigging, with one\nnostril he unthinkingly snuffed the sugary musk from the Bashee isles\n(in whose sweet woods mild lovers must be walking), and with the other\nconsciously inhaled the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 531, "2000": 1904}}, {"id": 7090, "position": 7090, "text": "woods mild lovers must be walking), and with the other\nconsciously inhaled the salt breath of the new found sea; that sea in\nwhich the hated White Whale must even then be swimming. Launched at\nlength upon these almost final waters, and gliding towards the", "labels": {"50": 16, "100": 20, "250": 132, "500": 412, "1000": 727, "2000": 913}}, {"id": 7091, "position": 7091, "text": "swimming. Launched at\nlength upon these almost final waters, and gliding towards the Japanese\ncruising-ground, the old man’s purpose intensified itself. His firm\nlips met like the lips of a vice; the Delta of his forehead’s veins\nswelled like", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7092, "position": 7092, "text": "lips of a vice; the Delta of his forehead’s veins\nswelled like overladen brooks; in his very sleep, his ringing cry ran\nthrough the vaulted hull, “Stern all! the White Whale spouts thick\nblood!”\n\n\nCHAPTER 112", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7093, "position": 7093, "text": "Stern all! the White Whale spouts thick\nblood!”\n\n\nCHAPTER 112. The Blacksmith.\n\nAvailing himself of the mild, summer-cool weather that now reigned in\nthese latitudes, and in preparation for the peculiarly active pursuits\nshortly to be anticipated", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7094, "position": 7094, "text": "s, and in preparation for the peculiarly active pursuits\nshortly to be anticipated, Perth, the begrimed, blistered old\nblacksmith, had not removed his portable forge to the hold again, after\nconcluding his contributory work for Ahab’", "labels": {"50": 45, "100": 63, "250": 138, "500": 72, "1000": 678, "2000": 1620}}, {"id": 7095, "position": 7095, "text": "to the hold again, after\nconcluding his contributory work for Ahab’s leg, but still retained it\non deck, fast lashed to ringbolts by the foremast; being now almost\nincessantly invoked by the headsmen, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7096, "position": 7096, "text": "t; being now almost\nincessantly invoked by the headsmen, and harpooneers, and bowsmen to do\nsome little job for them; altering, or repairing, or new shaping their\nvarious weapons and boat furniture", "labels": {"50": 45, "100": 42, "250": 131, "500": 329, "1000": 569, "2000": 338}}, {"id": 7097, "position": 7097, "text": "or new shaping their\nvarious weapons and boat furniture. Often he would be surrounded by an\neager circle, all waiting to be served; holding boat-spades,\npike-heads, harpoons, and lances, and jealously watching his every\nsoo", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 7098, "position": 7098, "text": ", harpoons, and lances, and jealously watching his every\nsooty movement, as he toiled. Nevertheless, this old man’s was a\npatient hammer wielded by a patient arm", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7099, "position": 7099, "text": "elded by a patient arm. No murmur, no impatience, no\npetulance did come from him. Silent, slow, and solemn; bowing over\nstill further his chronically broken back, he toiled away, as if toil\nwere life", "labels": {"50": 22, "100": 78, "250": 70, "500": 163, "1000": 496, "2000": 396}}, {"id": 7100, "position": 7100, "text": "ally broken back, he toiled away, as if toil\nwere life itself, and the heavy beating of his hammer the heavy beating\nof his heart. And so it was.—Most miserable!\n\nA peculiar walk in this old man, a certain", "labels": {"50": 46, "100": 78, "250": 53, "500": 286, "1000": 838, "2000": 396}}, {"id": 7101, "position": 7101, "text": ".—Most miserable!\n\nA peculiar walk in this old man, a certain slight but painful appearing\nyawing in his gait, had at an early period of the voyage excited the\ncuriosity of the mariners. And to the importunity of their persisted", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7102, "position": 7102, "text": "the\ncuriosity of the mariners. And to the importunity of their persisted\nquestionings he had finally given in; and so it came to pass that every\none now knew the shameful story of his wretched fate.", "labels": {"50": 22, "100": 78, "250": 229, "500": 370, "1000": 300, "2000": 1392}}, {"id": 7103, "position": 7103, "text": "shameful story of his wretched fate.\n\nBelated, and not innocently, one bitter winter’s midnight, on the road\nrunning between two country towns, the blacksmith half-stupidly felt\nthe deadly numbness stealing over him, and sought", "labels": {"50": 22, "100": 78, "250": 229, "500": 469, "1000": 477, "2000": 213}}, {"id": 7104, "position": 7104, "text": "half-stupidly felt\nthe deadly numbness stealing over him, and sought refuge in a leaning,\ndilapidated barn. The issue was, the loss of the extremities of both\nfeet. Out of this revelation, part by part, at last", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 839, "2000": 1562}}, {"id": 7105, "position": 7105, "text": "of both\nfeet. Out of this revelation, part by part, at last came out the four\nacts of the gladness, and the one long, and as yet uncatastrophied\nfifth act of the grief of his life’s drama", "labels": {"50": 22, "100": 88, "250": 70, "500": 163, "1000": 872, "2000": 425}}, {"id": 7106, "position": 7106, "text": "astrophied\nfifth act of the grief of his life’s drama.\n\nHe was an old man, who, at the age of nearly sixty, had postponedly\nencountered that thing in sorrow’s technicals called ruin", "labels": {"50": 36, "100": 35, "250": 245, "500": 114, "1000": 850, "2000": 842}}, {"id": 7107, "position": 7107, "text": "that thing in sorrow’s technicals called ruin. He had been\nan artisan of famed excellence, and with plenty to do; owned a house\nand garden; embraced a youthful, daughter-like, loving wife, and three\nblithe,", "labels": {"50": 9, "100": 73, "250": 120, "500": 143, "1000": 118, "2000": 1003}}, {"id": 7108, "position": 7108, "text": "youthful, daughter-like, loving wife, and three\nblithe, ruddy children; every Sunday went to a cheerful-looking church,\nplanted in a grove. But one night, under cover of darkness, and further\nconcealed in a most cunning", "labels": {"50": 7, "100": 22, "250": 53, "500": 371, "1000": 995, "2000": 602}}, {"id": 7109, "position": 7109, "text": "one night, under cover of darkness, and further\nconcealed in a most cunning disguisement, a desperate burglar slid into\nhis happy home, and robbed them all of everything. And darker yet to\ntell, the blacksmith himself did ignorantly conduct this", "labels": {"50": 40, "100": 50, "250": 36, "500": 316, "1000": 817, "2000": 12}}, {"id": 7110, "position": 7110, "text": ". And darker yet to\ntell, the blacksmith himself did ignorantly conduct this burglar into\nhis family’s heart. It was the Bottle Conjuror! Upon the opening of\nthat fatal cork, forth flew the fiend, and shrivel", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 1003}}, {"id": 7111, "position": 7111, "text": "opening of\nthat fatal cork, forth flew the fiend, and shrivelled up his home. Now,\nfor prudent, most wise, and economic reasons, the blacksmith’s shop was\nin the basement of his dwelling, but with a", "labels": {"50": 22, "100": 78, "250": 212, "500": 21, "1000": 990, "2000": 401}}, {"id": 7112, "position": 7112, "text": "blacksmith’s shop was\nin the basement of his dwelling, but with a separate entrance to it; so\nthat always had the young and loving healthy wife listened with no\nunhappy nervousness, but with vigorous pleasure, to the stout ringing\nof her young-", "labels": {"50": 0, "100": 3, "250": 89, "500": 88, "1000": 839, "2000": 1432}}, {"id": 7113, "position": 7113, "text": "ness, but with vigorous pleasure, to the stout ringing\nof her young-armed old husband’s hammer; whose reverberations, muffled\nby passing through the floors and walls, came up to her, not unsweetly,\nin her", "labels": {"50": 41, "100": 21, "250": 75, "500": 100, "1000": 59, "2000": 501}}, {"id": 7114, "position": 7114, "text": "walls, came up to her, not unsweetly,\nin her nursery; and so, to stout Labor’s iron lullaby, the blacksmith’s\ninfants were rocked to slumber.\n\nOh, woe on woe! Oh, Death", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 7115, "position": 7115, "text": "to slumber.\n\nOh, woe on woe! Oh, Death, why canst thou not sometimes be timely?\nHadst thou taken this old blacksmith to thyself ere his full ruin came\nupon him, then had the young widow", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 50, "2000": 1003}}, {"id": 7116, "position": 7116, "text": "f ere his full ruin came\nupon him, then had the young widow had a delicious grief, and her\norphans a truly venerable, legendary sire to dream of in their after\nyears; and all of them a care-killing competency", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 637, "2000": 1003}}, {"id": 7117, "position": 7117, "text": "years; and all of them a care-killing competency. But Death plucked\ndown some virtuous elder brother, on whose whistling daily toil solely\nhung the responsibilities of some other family, and left the worse than\nuseless old man standing, till", "labels": {"50": 31, "100": 75, "250": 193, "500": 307, "1000": 343, "2000": 958}}, {"id": 7118, "position": 7118, "text": "some other family, and left the worse than\nuseless old man standing, till the hideous rot of life should make him\neasier to harvest.\n\nWhy tell the whole? The blows of the basement hammer every day grew\nmore and more between; and each blow every", "labels": {"50": 48, "100": 24, "250": 213, "500": 255, "1000": 403, "2000": 831}}, {"id": 7119, "position": 7119, "text": "the basement hammer every day grew\nmore and more between; and each blow every day grew fainter than the\nlast; the wife sat frozen at the window, with tearless eyes,\nglitteringly gazing into the weeping faces of her children; the bellows", "labels": {"50": 28, "100": 12, "250": 190, "500": 186, "1000": 407, "2000": 466}}, {"id": 7120, "position": 7120, "text": ",\nglitteringly gazing into the weeping faces of her children; the bellows\nfell; the forge choked up with cinders; the house was sold; the mother\ndived down into the long church-yard grass; her children twice followed\nher thith", "labels": {"50": 16, "100": 73, "250": 15, "500": 406, "1000": 779, "2000": 523}}, {"id": 7121, "position": 7121, "text": "into the long church-yard grass; her children twice followed\nher thither; and the houseless, familyless old man staggered off a\nvagabond in crape; his every woe unreverenced; his grey head", "labels": {"50": 16, "100": 73, "250": 133, "500": 498, "1000": 174, "2000": 1003}}, {"id": 7122, "position": 7122, "text": "e; his every woe unreverenced; his grey head a scorn to\nflaxen curls!\n\nDeath seems the only desirable sequel for a career like this; but Death\nis only a launching into the region of the strange Untri", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 946}}, {"id": 7123, "position": 7123, "text": "; but Death\nis only a launching into the region of the strange Untried; it is but\nthe first salutation to the possibilities of the immense Remote, the\nWild, the Watery, the Unshored; therefore, to the death-longing", "labels": {"50": 16, "100": 73, "250": 132, "500": 414, "1000": 914, "2000": 872}}, {"id": 7124, "position": 7124, "text": "the Watery, the Unshored; therefore, to the death-longing eyes of\nsuch men, who still have left in them some interior compunctions\nagainst suicide, does the all-contributed and all-receptive ocean\nalluringly spread", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7125, "position": 7125, "text": "does the all-contributed and all-receptive ocean\nalluringly spread forth his whole plain of unimaginable, taking\nterrors, and wonderful, new-life adventures; and from the hearts of\ninfinite Pacifics, the thousand mermaids", "labels": {"50": 16, "100": 20, "250": 13, "500": 414, "1000": 747, "2000": 1555}}, {"id": 7126, "position": 7126, "text": "adventures; and from the hearts of\ninfinite Pacifics, the thousand mermaids sing to them—“Come hither,\nbroken-hearted; here is another life without the guilt of intermediate\ndeath; here are wonders supernatural, without dying for them", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 463}}, {"id": 7127, "position": 7127, "text": "of intermediate\ndeath; here are wonders supernatural, without dying for them. Come\nhither! bury thyself in a life which, to your now equally abhorred and\nabhorring, landed world, is more oblivious than death", "labels": {"50": 31, "100": 14, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 7128, "position": 7128, "text": "abhorring, landed world, is more oblivious than death. Come hither! put\nup _thy_ gravestone, too, within the churchyard, and come hither, till\nwe marry thee!”", "labels": {"50": 9, "100": 73, "250": 193, "500": 498, "1000": 343, "2000": 761}}, {"id": 7129, "position": 7129, "text": ", till\nwe marry thee!”\n\nHearkening to these voices, East and West, by early sunrise, and by\nfall of eve, the blacksmith’s soul responded, Aye, I come! And so Perth\nwent a-whaling.\n\n\nCHAPTER 113", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7130, "position": 7130, "text": "Aye, I come! And so Perth\nwent a-whaling.\n\n\nCHAPTER 113. The Forge.\n\nWith matted beard, and swathed in a bristling shark-skin apron, about\nmid-day, Perth was standing between his forge and an", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 7131, "position": 7131, "text": "apron, about\nmid-day, Perth was standing between his forge and anvil, the latter\nplaced upon an iron-wood log, with one hand holding a pike-head in the\ncoals, and with the other at his forge’s lungs", "labels": {"50": 18, "100": 63, "250": 152, "500": 290, "1000": 678, "2000": 1850}}, {"id": 7132, "position": 7132, "text": "in the\ncoals, and with the other at his forge’s lungs, when Captain Ahab came\nalong, carrying in his hand a small rusty-looking leathern bag. While\nyet a little distance from the forge, moody Ahab paused;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7133, "position": 7133, "text": ". While\nyet a little distance from the forge, moody Ahab paused; till at last,\nPerth, withdrawing his iron from the fire, began hammering it upon the\nanvil—the red mass sending off the sparks in thick hovering flights,\nsome of", "labels": {"50": 45, "100": 63, "250": 152, "500": 206, "1000": 678, "2000": 1850}}, {"id": 7134, "position": 7134, "text": "—the red mass sending off the sparks in thick hovering flights,\nsome of which flew close to Ahab.\n\n“Are these thy Mother Carey’s chickens, Perth? they are always flying\nin thy wake; birds of good omen, too,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7135, "position": 7135, "text": "are always flying\nin thy wake; birds of good omen, too, but not to all;—look here, they\nburn; but thou—thou liv’st among them without a scorch.”", "labels": {"50": 9, "100": 26, "250": 141, "500": 365, "1000": 859, "2000": 1307}}, {"id": 7136, "position": 7136, "text": "them without a scorch.”\n\n“Because I am scorched all over, Captain Ahab,” answered Perth, resting\nfor a moment on his hammer; “I am past scorching; not easily can’st\nthou scor", "labels": {"50": 41, "100": 31, "250": 228, "500": 180, "1000": 516, "2000": 1620}}, {"id": 7137, "position": 7137, "text": "I am past scorching; not easily can’st\nthou scorch a scar.”\n\n“Well, well; no more. Thy shrunk voice sounds too calmly, sanely woeful\nto me", "labels": {"50": 9, "100": 26, "250": 42, "500": 180, "1000": 50, "2000": 39}}, {"id": 7138, "position": 7138, "text": "calmly, sanely woeful\nto me. In no Paradise myself, I am impatient of all misery in others\nthat is not mad. Thou should’st go mad, blacksmith; say, why dost thou\nnot go mad? How can’", "labels": {"50": 9, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 7139, "position": 7139, "text": "blacksmith; say, why dost thou\nnot go mad? How can’st thou endure without being mad? Do the heavens\nyet hate thee, that thou can’st not go mad?—What wert thou making\nthere?”", "labels": {"50": 18, "100": 26, "250": 180, "500": 18, "1000": 709, "2000": 805}}, {"id": 7140, "position": 7140, "text": "go mad?—What wert thou making\nthere?”\n\n“Welding an old pike-head, sir; there were seams and dents in it.”\n\n“And can’st thou make it all smooth again, blacksmith, after such hard", "labels": {"50": 18, "100": 87, "250": 102, "500": 61, "1000": 672, "2000": 1091}}, {"id": 7141, "position": 7141, "text": "can’st thou make it all smooth again, blacksmith, after such hard\nusage as it had?”\n\n“I think so, sir.”\n\n“And I suppose thou can’st smoothe almost any seams and dents; never\nmind how", "labels": {"50": 18, "100": 83, "250": 219, "500": 221, "1000": 627, "2000": 1091}}, {"id": 7142, "position": 7142, "text": "’st smoothe almost any seams and dents; never\nmind how hard the metal, blacksmith?”\n\n“Aye, sir, I think I can; all seams and dents but one.”", "labels": {"50": 39, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 1199}}, {"id": 7143, "position": 7143, "text": "and dents but one.”\n\n“Look ye here, then,” cried Ahab, passionately advancing, and leaning\nwith both hands on Perth’s shoulders; “look ye here—_here_—can ye\nsmoothe out a seam", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7144, "position": 7144, "text": "look ye here—_here_—can ye\nsmoothe out a seam like this, blacksmith,” sweeping one hand across his\nribbed brow; “if thou could’st, blacksmith, glad enough would I lay my\nhead upon thy anvil", "labels": {"50": 41, "100": 21, "250": 219, "500": 180, "1000": 230, "2000": 1091}}, {"id": 7145, "position": 7145, "text": "st, blacksmith, glad enough would I lay my\nhead upon thy anvil, and feel thy heaviest hammer between my eyes.\nAnswer! Can’st thou smoothe this seam?”\n\n“Oh! that is the one, sir! Said I not", "labels": {"50": 9, "100": 26, "250": 219, "500": 180, "1000": 345, "2000": 1091}}, {"id": 7146, "position": 7146, "text": "?”\n\n“Oh! that is the one, sir! Said I not all seams and dents but one?”\n\n“Aye, blacksmith, it is the one; aye, man, it is unsmoothable; for\nthough thou only", "labels": {"50": 9, "100": 64, "250": 219, "500": 180, "1000": 345, "2000": 1620}}, {"id": 7147, "position": 7147, "text": "aye, man, it is unsmoothable; for\nthough thou only see’st it here in my flesh, it has worked down into\nthe bone of my skull—_that_ is all wrinkles! But, away with child’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7148, "position": 7148, "text": "_that_ is all wrinkles! But, away with child’s\nplay; no more gaffs and pikes to-day. Look ye here!” jingling the\nleathern bag, as if it were full of gold coins", "labels": {"50": 41, "100": 64, "250": 193, "500": 180, "1000": 54, "2000": 68}}, {"id": 7149, "position": 7149, "text": "the\nleathern bag, as if it were full of gold coins. “I, too, want a harpoon\nmade; one that a thousand yoke of fiends could not part, Perth;\nsomething that will stick in a whale like his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7150, "position": 7150, "text": "could not part, Perth;\nsomething that will stick in a whale like his own fin-bone. There’s the\nstuff,” flinging the pouch upon the anvil. “Look ye, blacksmith, these\nare the gathered nail-stubbs", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7151, "position": 7151, "text": ". “Look ye, blacksmith, these\nare the gathered nail-stubbs of the steel shoes of racing horses.”\n\n“Horse-shoe stubbs, sir? Why, Captain Ahab, thou hast here, then, the\nbest and stubborn", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7152, "position": 7152, "text": "Captain Ahab, thou hast here, then, the\nbest and stubbornest stuff we blacksmiths ever work.”\n\n“I know it, old man; these stubbs will weld together like glue from the\nmelted bones of murderers", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7153, "position": 7153, "text": "will weld together like glue from the\nmelted bones of murderers. Quick! forge me the harpoon. And forge me\nfirst, twelve rods for its shank; then wind, and twist, and hammer\nthese twelve together like the yarns and strands", "labels": {"50": 16, "100": 64, "250": 163, "500": 180, "1000": 520, "2000": 1620}}, {"id": 7154, "position": 7154, "text": ", and twist, and hammer\nthese twelve together like the yarns and strands of a tow-line. Quick!\nI’ll blow the fire.”\n\nWhen at last the twelve rods were made, Ahab tried them, one by one, by", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7155, "position": 7155, "text": "twelve rods were made, Ahab tried them, one by one, by\nspiralling them, with his own hand, round a long, heavy iron bolt. “A\nflaw!” rejecting the last one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7156, "position": 7156, "text": "!” rejecting the last one. “Work that over again, Perth.”\n\nThis done, Perth was about to begin welding the twelve into one, when\nAhab stayed his hand, and said he would weld his own iron", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7157, "position": 7157, "text": "hand, and said he would weld his own iron. As, then,\nwith regular, gasping hems, he hammered on the anvil, Perth passing to\nhim the glowing rods, one after the other, and the hard pressed forge\nshooting up", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7158, "position": 7158, "text": "glowing rods, one after the other, and the hard pressed forge\nshooting up its intense straight flame, the Parsee passed silently, and\nbowing over his head towards the fire, seemed invoking some curse or\nsome blessing on the toil", "labels": {"50": 22, "100": 55, "250": 205, "500": 180, "1000": 496, "2000": 1593}}, {"id": 7159, "position": 7159, "text": "seemed invoking some curse or\nsome blessing on the toil. But, as Ahab looked up, he slid aside.\n\n“What’s that bunch of lucifers dodging about there for?” muttered\nStubb, looking on from the forecast", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7160, "position": 7160, "text": "ging about there for?” muttered\nStubb, looking on from the forecastle. “That Parsee smells fire like a\nfusee; and smells of it himself, like a hot musket’s powder-pan.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 7161, "position": 7161, "text": "a hot musket’s powder-pan.”\n\nAt last the shank, in one complete rod, received its final heat; and as\nPerth, to temper it, plunged it all hissing into the cask of water near\nby, the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7162, "position": 7162, "text": ", plunged it all hissing into the cask of water near\nby, the scalding steam shot up into Ahab’s bent face.\n\n“Would’st thou brand me, Perth?” wincing for a moment with the pain;\n“", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7163, "position": 7163, "text": "me, Perth?” wincing for a moment with the pain;\n“have I been but forging my own branding-iron, then?”\n\n“Pray God, not that; yet I fear something, Captain Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7164, "position": 7164, "text": "that; yet I fear something, Captain Ahab. Is not this\nharpoon for the White Whale?”\n\n“For the white fiend! But now for the barbs; thou must make them\nthyself, man", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7165, "position": 7165, "text": "; thou must make them\nthyself, man. Here are my razors—the best of steel; here, and make the\nbarbs sharp as the needle-sleet of the Icy Sea.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7166, "position": 7166, "text": "eet of the Icy Sea.”\n\nFor a moment, the old blacksmith eyed the razors as though he would\nfain not use them.\n\n“Take them, man, I have no need for them; for I now neither shave, sup,", "labels": {"50": 45, "100": 64, "250": 170, "500": 60, "1000": 946, "2000": 363}}, {"id": 7167, "position": 7167, "text": "have no need for them; for I now neither shave, sup,\nnor pray till—but here—to work!”\n\nFashioned at last into an arrowy shape, and welded by Perth to the\nshank, the steel soon pointed the end", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7168, "position": 7168, "text": "and welded by Perth to the\nshank, the steel soon pointed the end of the iron; and as the\nblacksmith was about giving the barbs their final heat, prior to\ntempering them, he cried to Ahab to place the water-cas", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7169, "position": 7169, "text": "tempering them, he cried to Ahab to place the water-cask near.\n\n“No, no—no water for that; I want it of the true death-temper. Ahoy,\nthere! Tashtego, Quee", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7170, "position": 7170, "text": "-temper. Ahoy,\nthere! Tashtego, Queequeg, Daggoo! What say ye, pagans! Will ye give me\nas much blood as will cover this barb?” holding it high up", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7171, "position": 7171, "text": "blood as will cover this barb?” holding it high up. A cluster\nof dark nods replied, Yes. Three punctures were made in the heathen\nflesh, and the White Whale’s barbs were then tempered.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7172, "position": 7172, "text": "and the White Whale’s barbs were then tempered.\n\n“Ego non baptizo te in nomine patris, sed in nomine diaboli!”\ndeliriously howled Ahab, as the malignant iron scor", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7173, "position": 7173, "text": "”\ndeliriously howled Ahab, as the malignant iron scorchingly devoured the\nbaptismal blood.\n\nNow, mustering the spare poles from below, and selecting one of\nhickory, with the bark still investing it, Ahab fitted", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7174, "position": 7174, "text": "selecting one of\nhickory, with the bark still investing it, Ahab fitted the end to the\nsocket of the iron. A coil of new tow-line was then unwound, and some\nfathoms of it taken to the windlass,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7175, "position": 7175, "text": "und, and some\nfathoms of it taken to the windlass, and stretched to a great tension.\nPressing his foot upon it, till the rope hummed like a harp-string,\nthen eagerly bending over it, and seeing no strandings,", "labels": {"50": 16, "100": 64, "250": 138, "500": 28, "1000": 520, "2000": 16}}, {"id": 7176, "position": 7176, "text": "-string,\nthen eagerly bending over it, and seeing no strandings, Ahab exclaimed,\n“Good! and now for the seizings.”\n\nAt one extremity the rope was unstranded, and the separate spread yarns\nwere all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7177, "position": 7177, "text": "the rope was unstranded, and the separate spread yarns\nwere all braided and woven round the socket of the harpoon; the pole\nwas then driven hard up into the socket; from the lower end the rope\nwas traced half-way along", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7178, "position": 7178, "text": "the socket; from the lower end the rope\nwas traced half-way along the pole’s length, and firmly secured so,\nwith intertwistings of twine. This done, pole, iron, and rope—like the\nThree", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 7179, "position": 7179, "text": "e. This done, pole, iron, and rope—like the\nThree Fates—remained inseparable, and Ahab moodily stalked away with\nthe weapon; the sound of his ivory leg, and the sound of the hickory\npole, both hollow", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7180, "position": 7180, "text": "of his ivory leg, and the sound of the hickory\npole, both hollowly ringing along every plank. But ere he entered his\ncabin, light, unnatural, half-bantering, yet most piteous sound was\nheard", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7181, "position": 7181, "text": "bantering, yet most piteous sound was\nheard. Oh, Pip! thy wretched laugh, thy idle but unresting eye; all thy\nstrange mummeries not unmeaningly blended with the black tragedy of the\nmelancholy ship, and", "labels": {"50": 9, "100": 64, "250": 133, "500": 498, "1000": 327, "2000": 16}}, {"id": 7182, "position": 7182, "text": "meaningly blended with the black tragedy of the\nmelancholy ship, and mocked it!\n\n\nCHAPTER 114. The Gilder.\n\nPenetrating further and further into the heart of the Japanese cruising\nground, the Pequod was soon all astir in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7183, "position": 7183, "text": "cruising\nground, the Pequod was soon all astir in the fishery. Often, in mild,\npleasant weather, for twelve, fifteen, eighteen, and twenty hours on\nthe stretch, they were engaged in the boats, steadily pulling, or", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7184, "position": 7184, "text": "on\nthe stretch, they were engaged in the boats, steadily pulling, or\nsailing, or paddling after the whales, or for an interlude of sixty or\nseventy minutes calmly awaiting their uprising; though with but small\nsuccess for their pains.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7185, "position": 7185, "text": "their uprising; though with but small\nsuccess for their pains.\n\nAt such times, under an abated sun; afloat all day upon smooth, slow\nheaving swells; seated in his boat, light as a birch canoe; and so\nsociably", "labels": {"50": 16, "100": 73, "250": 53, "500": 126, "1000": 252, "2000": 970}}, {"id": 7186, "position": 7186, "text": "in his boat, light as a birch canoe; and so\nsociably mixing with the soft waves themselves, that like hearth-stone\ncats they purr against the gunwale; these are the times of dreamy\nquietude, when beholding", "labels": {"50": 16, "100": 20, "250": 133, "500": 414, "1000": 747, "2000": 970}}, {"id": 7187, "position": 7187, "text": "e; these are the times of dreamy\nquietude, when beholding the tranquil beauty and brilliancy of the\nocean’s skin, one forgets the tiger heart that pants beneath it; and\nwould not willingly remember, that this", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 437, "2000": 970}}, {"id": 7188, "position": 7188, "text": "tiger heart that pants beneath it; and\nwould not willingly remember, that this velvet paw but conceals a\nremorseless fang.\n\nThese are the times, when in his whale-boat the rover softly feels a\ncertain filial, confident, land-", "labels": {"50": 22, "100": 55, "250": 52, "500": 465, "1000": 204, "2000": 174}}, {"id": 7189, "position": 7189, "text": "boat the rover softly feels a\ncertain filial, confident, land-like feeling towards the sea; that he\nregards it as so much flowery earth; and the distant ship revealing\nonly the tops of her masts, seems struggling forward, not", "labels": {"50": 16, "100": 20, "250": 49, "500": 334, "1000": 747, "2000": 1710}}, {"id": 7190, "position": 7190, "text": "ship revealing\nonly the tops of her masts, seems struggling forward, not through high\nrolling waves, but through the tall grass of a rolling prairie: as when\nthe western emigrants’ horses only show their erected ears, while their\nhidden bodies widely wade", "labels": {"50": 22, "100": 20, "250": 28, "500": 162, "1000": 35, "2000": 1128}}, {"id": 7191, "position": 7191, "text": "grants’ horses only show their erected ears, while their\nhidden bodies widely wade through the amazing verdure.\n\nThe long-drawn virgin vales; the mild blue hill-sides; as over these\nthere steals the hush, the hum; you almost", "labels": {"50": 9, "100": 73, "250": 120, "500": 498, "1000": 637, "2000": 1886}}, {"id": 7192, "position": 7192, "text": "sides; as over these\nthere steals the hush, the hum; you almost swear that play-wearied\nchildren lie sleeping in these solitudes, in some glad May-time, when\nthe flowers of the woods are plucked", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 463}}, {"id": 7193, "position": 7193, "text": ", when\nthe flowers of the woods are plucked. And all this mixes with your most\nmystic mood; so that fact and fancy, half-way meeting, interpenetrate,\nand form one seamless whole.", "labels": {"50": 48, "100": 20, "250": 192, "500": 126, "1000": 747, "2000": 1560}}, {"id": 7194, "position": 7194, "text": ",\nand form one seamless whole.\n\nNor did such soothing scenes, however temporary, fail of at least as\ntemporary an effect on Ahab. But if these secret golden keys did seem\nto open in him his own secret golden treasuries,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7195, "position": 7195, "text": "did seem\nto open in him his own secret golden treasuries, yet did his breath\nupon them prove but tarnishing.\n\nOh, grassy glades! oh, ever vernal endless landscapes in the soul; in\nye,—though", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 1886}}, {"id": 7196, "position": 7196, "text": "ever vernal endless landscapes in the soul; in\nye,—though long parched by the dead drought of the earthy life,—in ye,\nmen yet may roll, like young horses in new morning clover; and for some\nfew fleeting", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 193}}, {"id": 7197, "position": 7197, "text": "roll, like young horses in new morning clover; and for some\nfew fleeting moments, feel the cool dew of the life immortal on them.\nWould to God these blessed calms would last. But the mingled, mingling\nthreads of life are woven by", "labels": {"50": 16, "100": 73, "250": 13, "500": 414, "1000": 437, "2000": 970}}, {"id": 7198, "position": 7198, "text": "would last. But the mingled, mingling\nthreads of life are woven by warp and woof: calms crossed by storms, a\nstorm for every calm. There is no steady unretracing progress in this\nlife; we do not advance through", "labels": {"50": 31, "100": 20, "250": 13, "500": 482, "1000": 15, "2000": 1050}}, {"id": 7199, "position": 7199, "text": "steady unretracing progress in this\nlife; we do not advance through fixed gradations, and at the last one\npause:—through infancy’s unconscious spell, boyhood’s thoughtless\nfaith, adolescence’ doubt (the common doom", "labels": {"50": 31, "100": 20, "250": 13, "500": 126, "1000": 15, "2000": 970}}, {"id": 7200, "position": 7200, "text": "boyhood’s thoughtless\nfaith, adolescence’ doubt (the common doom), then scepticism, then\ndisbelief, resting at last in manhood’s pondering repose of If. But\nonce gone through, we trace the round", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 437, "2000": 709}}, {"id": 7201, "position": 7201, "text": "ing repose of If. But\nonce gone through, we trace the round again; and are infants, boys, and\nmen, and Ifs eternally. Where lies the final harbor, whence we unmoor\nno more? In what rapt", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 709}}, {"id": 7202, "position": 7202, "text": "final harbor, whence we unmoor\nno more? In what rapt ether sails the world, of which the weariest will\nnever weary? Where is the foundling’s father hidden? Our souls are like\nthose orphans whose unwedded mothers", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 709}}, {"id": 7203, "position": 7203, "text": "s father hidden? Our souls are like\nthose orphans whose unwedded mothers die in bearing them: the secret of\nour paternity lies in their grave, and we must there to learn it.\n\nAnd that same day, too, gazing far down", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 10}}, {"id": 7204, "position": 7204, "text": "there to learn it.\n\nAnd that same day, too, gazing far down from his boat’s side into that\nsame golden sea, Starbuck lowly murmured:—\n\n“Loveliness unfathomable, as ever lover saw in his young bride", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7205, "position": 7205, "text": "Loveliness unfathomable, as ever lover saw in his young bride’s\neye!—Tell me not of thy teeth-tiered sharks, and thy kidnapping\ncannibal ways. Let faith oust fact; let fancy oust memory", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7206, "position": 7206, "text": "nibal ways. Let faith oust fact; let fancy oust memory; I look deep\ndown and do believe.”\n\nAnd Stubb, fish-like, with sparkling scales, leaped up in that same\ngolden light:—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 7207, "position": 7207, "text": "scales, leaped up in that same\ngolden light:—\n\n“I am Stubb, and Stubb has his history; but here Stubb takes oaths that\nhe has always been jolly!”\n\n\nCHAPTER 115. The Pequod Meets The Bachelor.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7208, "position": 7208, "text": "been jolly!”\n\n\nCHAPTER 115. The Pequod Meets The Bachelor.\n\nAnd jolly enough were the sights and the sounds that came bearing down\nbefore the wind, some few weeks after Ahab’s harpoon had been welded.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7209, "position": 7209, "text": "after Ahab’s harpoon had been welded.\n\nIt was a Nantucket ship, the Bachelor, which had just wedged in her\nlast cask of oil, and bolted down her bursting hatches; and now, in\nglad holiday apparel,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7210, "position": 7210, "text": "bolted down her bursting hatches; and now, in\nglad holiday apparel, was joyously, though somewhat vain-gloriously,\nsailing round among the widely-separated ships on the ground, previous\nto pointing her prow for home.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 7211, "position": 7211, "text": "the ground, previous\nto pointing her prow for home.\n\nThe three men at her mast-head wore long streamers of narrow red\nbunting at their hats; from the stern, a whale-boat was suspended,\nbottom down; and hanging captive", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 7212, "position": 7212, "text": "stern, a whale-boat was suspended,\nbottom down; and hanging captive from the bowsprit was seen the long\nlower jaw of the last whale they had slain. Signals, ensigns, and jacks\nof all colours were flying from her rig", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7213, "position": 7213, "text": ", ensigns, and jacks\nof all colours were flying from her rigging, on every side. Sideways\nlashed in each of her three basketed tops were two barrels of sperm;\nabove which, in her top-mast cross-trees, you", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7214, "position": 7214, "text": "sperm;\nabove which, in her top-mast cross-trees, you saw slender breakers of\nthe same precious fluid; and nailed to her main truck was a brazen\nlamp.\n\nAs was afterwards learned, the Bachelor had met with the most\nsurprising success", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 7215, "position": 7215, "text": ".\n\nAs was afterwards learned, the Bachelor had met with the most\nsurprising success; all the more wonderful, for that while cruising in\nthe same seas numerous other vessels had gone entire months without\nsecuring a single fish", "labels": {"50": 13, "100": 3, "250": 154, "500": 88, "1000": 215, "2000": 1322}}, {"id": 7216, "position": 7216, "text": "months without\nsecuring a single fish. Not only had barrels of beef and bread been\ngiven away to make room for the far more valuable sperm, but additional\nsupplemental casks had been bartered for, from the ships she had met;\nand these were st", "labels": {"50": 45, "100": 29, "250": 34, "500": 239, "1000": 723, "2000": 1584}}, {"id": 7217, "position": 7217, "text": "bartered for, from the ships she had met;\nand these were stowed along the deck, and in the captain’s and\nofficers’ state-rooms. Even the cabin table itself had been knocked\ninto kindling-wood; and the cabin", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 887}}, {"id": 7218, "position": 7218, "text": "cabin table itself had been knocked\ninto kindling-wood; and the cabin mess dined off the broad head of an\noil-butt, lashed down to the floor for a centrepiece. In the\nforecastle, the sailors had actually caulked", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 7219, "position": 7219, "text": "centrepiece. In the\nforecastle, the sailors had actually caulked and pitched their chests,\nand filled them; it was humorously added, that the cook had clapped a\nhead on his largest boiler, and filled it; that the steward had", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 7220, "position": 7220, "text": "a\nhead on his largest boiler, and filled it; that the steward had plugged\nhis spare coffee-pot and filled it; that the harpooneers had headed the\nsockets of their irons and filled them; that indeed everything was\nfilled with sperm", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 7221, "position": 7221, "text": "of their irons and filled them; that indeed everything was\nfilled with sperm, except the captain’s pantaloons pockets, and those\nhe reserved to thrust his hands into, in self-complacent testimony of\nhis entire satisfaction.", "labels": {"50": 45, "100": 64, "250": 70, "500": 73, "1000": 925, "2000": 110}}, {"id": 7222, "position": 7222, "text": ", in self-complacent testimony of\nhis entire satisfaction.\n\nAs this glad ship of good luck bore down upon the moody Pequod, the\nbarbarian sound of enormous drums came from her forecastle; and drawing\nstill nearer, a crowd of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7223, "position": 7223, "text": "drums came from her forecastle; and drawing\nstill nearer, a crowd of her men were seen standing round her huge\ntry-pots, which, covered with the parchment-like _poke_ or stomach skin\nof the black fish, gave forth a loud", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 531, "2000": 967}}, {"id": 7224, "position": 7224, "text": "_poke_ or stomach skin\nof the black fish, gave forth a loud roar to every stroke of the\nclenched hands of the crew. On the quarter-deck, the mates and\nharpooneers were dancing with the olive-hued girls who had", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 531, "2000": 778}}, {"id": 7225, "position": 7225, "text": "and\nharpooneers were dancing with the olive-hued girls who had eloped with\nthem from the Polynesian Isles; while suspended in an ornamented boat,\nfirmly secured aloft between the foremast and mainmast, three Long", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 531, "2000": 187}}, {"id": 7226, "position": 7226, "text": "secured aloft between the foremast and mainmast, three Long\nIsland negroes, with glittering fiddle-bows of whale ivory, were\npresiding over the hilarious jig. Meanwhile, others of the ship’s\ncompany were tumultuously", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7227, "position": 7227, "text": ". Meanwhile, others of the ship’s\ncompany were tumultuously busy at the masonry of the try-works, from\nwhich the huge pots had been removed. You would have almost thought\nthey were pulling down the cursed Bastille, such", "labels": {"50": 1, "100": 80, "250": 190, "500": 186, "1000": 623, "2000": 1952}}, {"id": 7228, "position": 7228, "text": "would have almost thought\nthey were pulling down the cursed Bastille, such wild cries they\nraised, as the now useless brick and mortar were being hurled into the\nsea.\n\nLord and master over all this scene, the captain stood erect on the\nship’", "labels": {"50": 1, "100": 87, "250": 11, "500": 479, "1000": 359, "2000": 687}}, {"id": 7229, "position": 7229, "text": "and master over all this scene, the captain stood erect on the\nship’s elevated quarter-deck, so that the whole rejoicing drama was\nfull before him, and seemed merely contrived for his own individual\ndiversion.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 7230, "position": 7230, "text": "seemed merely contrived for his own individual\ndiversion.\n\nAnd Ahab, he too was standing on his quarter-deck, shaggy and black,\nwith a stubborn gloom; and as the two ships crossed each other’s\nwakes—one all jubil", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7231, "position": 7231, "text": "as the two ships crossed each other’s\nwakes—one all jubilations for things passed, the other all forebodings\nas to things to come—their two captains in themselves impersonated the\nwhole striking contrast of the scene.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7232, "position": 7232, "text": "captains in themselves impersonated the\nwhole striking contrast of the scene.\n\n“Come aboard, come aboard!” cried the gay Bachelor’s commander, lifting\na glass and a bottle in the air.\n\n“Hast seen the White Whale?” gritted", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 7233, "position": 7233, "text": "bottle in the air.\n\n“Hast seen the White Whale?” gritted Ahab in reply.\n\n“No; only heard of him; but don’t believe in him at all,” said the\nother good-humoredly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7234, "position": 7234, "text": "at all,” said the\nother good-humoredly. “Come aboard!”\n\n“Thou art too damned jolly. Sail on. Hast lost any men?”\n\n“Not enough to speak of—two islanders, that’s all;—", "labels": {"50": 16, "100": 64, "250": 163, "500": 406, "1000": 779, "2000": 16}}, {"id": 7235, "position": 7235, "text": "Not enough to speak of—two islanders, that’s all;—but come aboard, old\nhearty, come along. I’ll soon take that black from your brow. Come\nalong, will ye (merry’s the play);", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 7236, "position": 7236, "text": "brow. Come\nalong, will ye (merry’s the play); a full ship and homeward-bound.”\n\n“How wondrous familiar is a fool!” muttered Ahab; then aloud, “Thou art\na full ship and", "labels": {"50": 9, "100": 26, "250": 138, "500": 498, "1000": 327, "2000": 1620}}, {"id": 7237, "position": 7237, "text": "” muttered Ahab; then aloud, “Thou art\na full ship and homeward bound, thou sayst; well, then, call me an\nempty ship, and outward-bound. So go thy ways, and I will mine", "labels": {"50": 9, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7238, "position": 7238, "text": "-bound. So go thy ways, and I will mine. Forward\nthere! Set all sail, and keep her to the wind!”\n\nAnd thus, while the one ship went cheerily before the breeze, the other\nstubbornly fought against it;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 7239, "position": 7239, "text": "went cheerily before the breeze, the other\nstubbornly fought against it; and so the two vessels parted; the crew\nof the Pequod looking with grave, lingering glances towards the\nreceding Bachelor; but the Bachelor’s men never heeding", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7240, "position": 7240, "text": "towards the\nreceding Bachelor; but the Bachelor’s men never heeding their gaze for\nthe lively revelry they were in. And as Ahab, leaning over the\ntaffrail, eyed the homeward-bound craft, he took from", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7241, "position": 7241, "text": "taffrail, eyed the homeward-bound craft, he took from his pocket a\nsmall vial of sand, and then looking from the ship to the vial, seemed\nthereby bringing two remote associations together, for that vial was\nfilled with Nantucket sounding", "labels": {"50": 45, "100": 29, "250": 138, "500": 162, "1000": 300, "2000": 47}}, {"id": 7242, "position": 7242, "text": "bringing two remote associations together, for that vial was\nfilled with Nantucket soundings.\n\n\nCHAPTER 116. The Dying Whale.\n\nNot seldom in this life, when, on the right side, fortune’s favourites\nsail close by us, we, though all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7243, "position": 7243, "text": "side, fortune’s favourites\nsail close by us, we, though all adroop before, catch somewhat of the\nrushing breeze, and joyfully feel our bagging sails fill out. So seemed\nit with the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7244, "position": 7244, "text": "fill out. So seemed\nit with the Pequod. For next day after encountering the gay Bachelor,\nwhales were seen and four were slain; and one of them by Ahab.\n\nIt was far down the afternoon; and when all the spear", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7245, "position": 7245, "text": "Ahab.\n\nIt was far down the afternoon; and when all the spearings of the\ncrimson fight were done: and floating in the lovely sunset sea and sky,\nsun and whale both stilly died together; then, such a sweetness and\nsuch plain", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7246, "position": 7246, "text": "whale both stilly died together; then, such a sweetness and\nsuch plaintiveness, such inwreathing orisons curled up in that rosy\nair, that it almost seemed as if far over from the deep green convent\nvalleys of the Mani", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7247, "position": 7247, "text": "almost seemed as if far over from the deep green convent\nvalleys of the Manilla isles, the Spanish land-breeze, wantonly turned\nsailor, had gone to sea, freighted with these vesper hymns.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 730, "2000": 1814}}, {"id": 7248, "position": 7248, "text": "freighted with these vesper hymns.\n\nSoothed again, but only soothed to deeper gloom, Ahab, who had sterned\noff from the whale, sat intently watching his final wanings from the\nnow tranquil boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7249, "position": 7249, "text": "his final wanings from the\nnow tranquil boat. For that strange spectacle observable in all sperm\nwhales dying—the turning sunwards of the head, and so expiring—that\nstrange spectacle, beheld of such a plac", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7250, "position": 7250, "text": "expiring—that\nstrange spectacle, beheld of such a placid evening, somehow to Ahab\nconveyed a wondrousness unknown before.\n\n“He turns and turns him to it,—how slowly, but how steadfastly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7251, "position": 7251, "text": "turns him to it,—how slowly, but how steadfastly, his\nhomage-rendering and invoking brow, with his last dying motions. He too\nworships fire; most faithful, broad, baronial vassal of the sun!—", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 637, "2000": 1886}}, {"id": 7252, "position": 7252, "text": "fire; most faithful, broad, baronial vassal of the sun!—Oh\nthat these too-favouring eyes should see these too-favouring sights.\nLook! here, far water-locked; beyond all hum of human weal or wo", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 573}}, {"id": 7253, "position": 7253, "text": ", far water-locked; beyond all hum of human weal or woe; in\nthese most candid and impartial seas; where to traditions no rocks\nfurnish tablets; where for long Chinese ages, the billows have still\nrolled on", "labels": {"50": 9, "100": 73, "250": 193, "500": 307, "1000": 343, "2000": 761}}, {"id": 7254, "position": 7254, "text": "tablets; where for long Chinese ages, the billows have still\nrolled on speechless and unspoken to, as stars that shine upon the\nNiger’s unknown source; here, too, life dies sunwards full of faith;\nbut see! no sooner", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 1203}}, {"id": 7255, "position": 7255, "text": ", life dies sunwards full of faith;\nbut see! no sooner dead, than death whirls round the corpse, and it\nheads some other way.\n\n“Oh, thou dark Hindoo half of nature, who of drowned bones hast", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 596}}, {"id": 7256, "position": 7256, "text": ", thou dark Hindoo half of nature, who of drowned bones hast builded\nthy separate throne somewhere in the heart of these unverdured seas;\nthou art an infidel, thou queen, and too truly speakest to me in", "labels": {"50": 9, "100": 26, "250": 141, "500": 122, "1000": 663, "2000": 1208}}, {"id": 7257, "position": 7257, "text": "infidel, thou queen, and too truly speakest to me in the\nwide-slaughtering Typhoon, and the hushed burial of its after calm. Nor\nhas this thy whale sunwards turned his dying head, and then gone round\nagain,", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7258, "position": 7258, "text": "whale sunwards turned his dying head, and then gone round\nagain, without a lesson to me.\n\n“Oh, trebly hooped and welded hip of power! Oh, high aspiring,\nrainbowed jet!—that one strivest, this", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7259, "position": 7259, "text": ", high aspiring,\nrainbowed jet!—that one strivest, this one jettest all in vain! In\nvain, oh whale, dost thou seek intercedings with yon all-quickening\nsun, that only calls forth life,", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 1203}}, {"id": 7260, "position": 7260, "text": "with yon all-quickening\nsun, that only calls forth life, but gives it not again. Yet dost thou,\ndarker half, rock me with a prouder, if a darker faith. All thy\nunnamable imminglings float", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 193}}, {"id": 7261, "position": 7261, "text": ", if a darker faith. All thy\nunnamable imminglings float beneath me here; I am buoyed by breaths of\nonce living things, exhaled as air, but water now.\n\n“Then hail, for ever hail, O sea,", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 193}}, {"id": 7262, "position": 7262, "text": "but water now.\n\n“Then hail, for ever hail, O sea, in whose eternal tossings the wild\nfowl finds his only rest. Born of earth, yet suckled by the sea; though\nhill and valley mothered me, ye", "labels": {"50": 16, "100": 73, "250": 240, "500": 406, "1000": 779, "2000": 596}}, {"id": 7263, "position": 7263, "text": "suckled by the sea; though\nhill and valley mothered me, ye billows are my foster-brothers!”\n\n\nCHAPTER 117. The Whale Watch.\n\nThe four whales slain that evening had died wide apart; one, far to\nwindward; one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7264, "position": 7264, "text": "that evening had died wide apart; one, far to\nwindward; one, less distant, to leeward; one ahead; one astern. These\nlast three were brought alongside ere nightfall; but the windward one\ncould not be reached till", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 7265, "position": 7265, "text": "alongside ere nightfall; but the windward one\ncould not be reached till morning; and the boat that had killed it lay\nby its side all night; and that boat was Ahab’s.\n\nThe waif-pole was thrust upright into the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7266, "position": 7266, "text": "Ahab’s.\n\nThe waif-pole was thrust upright into the dead whale’s spout-hole; and\nthe lantern hanging from its top, cast a troubled flickering glare upon\nthe black, glossy back, and far out upon the midnight", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7267, "position": 7267, "text": "flickering glare upon\nthe black, glossy back, and far out upon the midnight waves, which\ngently chafed the whale’s broad flank, like soft surf upon a beach.\n\nAhab and all his boat’s crew seemed asleep but the Parsee", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7268, "position": 7268, "text": "Ahab and all his boat’s crew seemed asleep but the Parsee; who\ncrouching in the bow, sat watching the sharks, that spectrally played\nround the whale, and tapped the light cedar planks with their tails", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7269, "position": 7269, "text": ", and tapped the light cedar planks with their tails. A\nsound like the moaning in squadrons over Asphaltites of unforgiven\nghosts of Gomorrah, ran shuddering through the air.\n\nStarted from his slumbers, Ahab,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7270, "position": 7270, "text": "shuddering through the air.\n\nStarted from his slumbers, Ahab, face to face, saw the Parsee; and\nhooped round by the gloom of the night they seemed the last men in a\nflooded world", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7271, "position": 7271, "text": "seemed the last men in a\nflooded world. “I have dreamed it again,” said he.\n\n“Of the hearses? Have I not said, old man, that neither hearse nor\ncoffin can be thine?”", "labels": {"50": 16, "100": 73, "250": 15, "500": 406, "1000": 779, "2000": 524}}, {"id": 7272, "position": 7272, "text": "neither hearse nor\ncoffin can be thine?”\n\n“And who are hearsed that die on the sea?”\n\n“But I said, old man, that ere thou couldst die on this voyage, two\nhearses must verily be", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 7273, "position": 7273, "text": "thou couldst die on this voyage, two\nhearses must verily be seen by thee on the sea; the first not made by\nmortal hands; and the visible wood of the last one must be grown in\nAmerica.”", "labels": {"50": 16, "100": 64, "250": 138, "500": 406, "1000": 9, "2000": 16}}, {"id": 7274, "position": 7274, "text": "the last one must be grown in\nAmerica.”\n\n“Aye, aye! a strange sight that, Parsee:—a hearse and its plumes\nfloating over the ocean with the waves for the pall-bearers", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 9, "2000": 16}}, {"id": 7275, "position": 7275, "text": "with the waves for the pall-bearers. Ha! Such a\nsight we shall not soon see.”\n\n“Believe it or not, thou canst not die till it be seen, old man.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 142}}, {"id": 7276, "position": 7276, "text": "it be seen, old man.”\n\n“And what was that saying about thyself?”\n\n“Though it come to the last, I shall still go before thee thy pilot.”\n\n“And when thou art so gone before—if that ever", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 7277, "position": 7277, "text": "pilot.”\n\n“And when thou art so gone before—if that ever befall—then ere I can\nfollow, thou must still appear to me, to pilot me still?—Was it not so?\nWell, then, did I believe", "labels": {"50": 9, "100": 26, "250": 141, "500": 365, "1000": 859, "2000": 1307}}, {"id": 7278, "position": 7278, "text": "still?—Was it not so?\nWell, then, did I believe all ye say, oh my pilot! I have here two\npledges that I shall yet slay Moby Dick and survive it.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7279, "position": 7279, "text": "Moby Dick and survive it.”\n\n“Take another pledge, old man,” said the Parsee, as his eyes lighted up\nlike fire-flies in the gloom—“Hemp only can kill thee.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7280, "position": 7280, "text": "“Hemp only can kill thee.”\n\n“The gallows, ye mean.—I am immortal then, on land and on sea,” cried\nAhab, with a laugh of derision;—“Immortal on land and on sea!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7281, "position": 7281, "text": "a laugh of derision;—“Immortal on land and on sea!”\n\nBoth were silent again, as one man. The grey dawn came on, and the\nslumbering crew arose from the boat’s bottom, and ere noon the", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 7282, "position": 7282, "text": "ing crew arose from the boat’s bottom, and ere noon the dead\nwhale was brought to the ship.\n\n\nCHAPTER 118. The Quadrant.\n\nThe season for the Line at length drew near; and every day when Ahab,\ncoming from his cabin", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7283, "position": 7283, "text": "length drew near; and every day when Ahab,\ncoming from his cabin, cast his eyes aloft, the vigilant helmsman would\nostentatiously handle his spokes, and the eager mariners quickly run to\nthe braces, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7284, "position": 7284, "text": "spokes, and the eager mariners quickly run to\nthe braces, and would stand there with all their eyes centrally fixed\non the nailed doubloon; impatient for the order to point the ship’s\nprow for the equator", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7285, "position": 7285, "text": "order to point the ship’s\nprow for the equator. In good time the order came. It was hard upon\nhigh noon; and Ahab, seated in the bows of his high-hoisted boat, was\nabout taking his wonted daily observation", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7286, "position": 7286, "text": "of his high-hoisted boat, was\nabout taking his wonted daily observation of the sun to determine his\nlatitude.\n\nNow, in that Japanese sea, the days in summer are as freshets of\neffulgences", "labels": {"50": 20, "100": 28, "250": 132, "500": 499, "1000": 27, "2000": 1495}}, {"id": 7287, "position": 7287, "text": "as freshets of\neffulgences. That unblinkingly vivid Japanese sun seems the blazing\nfocus of the glassy ocean’s immeasurable burning-glass. The sky looks\nlacquered; clouds there are none; the horizon", "labels": {"50": 45, "100": 20, "250": 138, "500": 162, "1000": 9, "2000": 682}}, {"id": 7288, "position": 7288, "text": ". The sky looks\nlacquered; clouds there are none; the horizon floats; and this\nnakedness of unrelieved radiance is as the insufferable splendors of\nGod’s throne", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 887}}, {"id": 7289, "position": 7289, "text": "ble splendors of\nGod’s throne. Well that Ahab’s quadrant was furnished with coloured\nglasses, through which to take sight of that solar fire. So, swinging\nhis seated form to the roll of the ship, and with his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7290, "position": 7290, "text": ", swinging\nhis seated form to the roll of the ship, and with his\nastrological-looking instrument placed to his eye, he remained in that\nposture for some moments to catch the precise instant when the sun\nshould gain its precise meridian", "labels": {"50": 45, "100": 64, "250": 50, "500": 33, "1000": 862, "2000": 1692}}, {"id": 7291, "position": 7291, "text": "the precise instant when the sun\nshould gain its precise meridian. Meantime while his whole attention\nwas absorbed, the Parsee was kneeling beneath him on the ship’s deck,\nand with face thrown up like Ahab’s, was eyeing the same sun", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7292, "position": 7292, "text": "with face thrown up like Ahab’s, was eyeing the same sun with him;\nonly the lids of his eyes half hooded their orbs, and his wild face was\nsubdued to an earthly passionlessness", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7293, "position": 7293, "text": "subdued to an earthly passionlessness. At length the desired\nobservation was taken; and with his pencil upon his ivory leg, Ahab\nsoon calculated what his latitude must be at that precise instant. Then\nfalling into a moment’s revery, he again", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7294, "position": 7294, "text": "precise instant. Then\nfalling into a moment’s revery, he again looked up towards the sun and\nmurmured to himself: “Thou sea-mark! thou high and mighty Pilot! thou\ntellest me truly where I _am_—but cans", "labels": {"50": 9, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7295, "position": 7295, "text": "Pilot! thou\ntellest me truly where I _am_—but canst thou cast the least hint where\nI _shall_ be? Or canst thou tell where some other thing besides me is\nthis moment living? Where is Moby Dick?", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7296, "position": 7296, "text": "other thing besides me is\nthis moment living? Where is Moby Dick? This instant thou must be\neyeing him. These eyes of mine look into the very eye that is even now\nbeholding him; aye, and into the eye that is even now", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7297, "position": 7297, "text": "now\nbeholding him; aye, and into the eye that is even now equally beholding\nthe objects on the unknown, thither side of thee, thou sun!”\n\nThen gazing at his quadrant, and handling, one after the other, its", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7298, "position": 7298, "text": "Then gazing at his quadrant, and handling, one after the other, its\nnumerous cabalistical contrivances, he pondered again, and muttered:\n“Foolish toy! babies’ plaything of haughty Admirals, and Commodores,\nand", "labels": {"50": 45, "100": 64, "250": 229, "500": 73, "1000": 448, "2000": 958}}, {"id": 7299, "position": 7299, "text": "’ plaything of haughty Admirals, and Commodores,\nand Captains; the world brags of thee, of thy cunning and might; but\nwhat after all canst thou do, but tell the poor, pitiful point, where\nthou", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 637, "2000": 39}}, {"id": 7300, "position": 7300, "text": "t thou do, but tell the poor, pitiful point, where\nthou thyself happenest to be on this wide planet, and the hand that\nholds thee: no! not one jot more! Thou canst not tell where one drop", "labels": {"50": 9, "100": 26, "250": 141, "500": 365, "1000": 859, "2000": 1307}}, {"id": 7301, "position": 7301, "text": "! not one jot more! Thou canst not tell where one drop of\nwater or one grain of sand will be to-morrow noon; and yet with thy\nimpotence thou insultest the sun! Science! Curse thee, thou vain toy", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 50, "2000": 1502}}, {"id": 7302, "position": 7302, "text": "nce thou insultest the sun! Science! Curse thee, thou vain toy;\nand cursed be all the things that cast man’s eyes aloft to that heaven,\nwhose live vividness but scorches him, as these old eyes are even", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 193}}, {"id": 7303, "position": 7303, "text": "live vividness but scorches him, as these old eyes are even now\nscorched with thy light, O sun! Level by nature to this earth’s horizon\nare the glances of man’s eyes; not shot from the crown of", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 193}}, {"id": 7304, "position": 7304, "text": "are the glances of man’s eyes; not shot from the crown of his head, as\nif God had meant him to gaze on his firmament. Curse thee, thou\nquadrant!” dashing it to the deck, “no longer will I", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7305, "position": 7305, "text": "quadrant!” dashing it to the deck, “no longer will I guide my earthly\nway by thee; the level ship’s compass, and the level dead-reckoning, by\nlog and by line; _these_ shall conduct me,", "labels": {"50": 9, "100": 26, "250": 133, "500": 232, "1000": 437, "2000": 1620}}, {"id": 7306, "position": 7306, "text": "ing, by\nlog and by line; _these_ shall conduct me, and show me my place on the\nsea. Aye,” lighting from the boat to the deck, “thus I trample on thee,\nthou paltry thing that feebly", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 779, "2000": 16}}, {"id": 7307, "position": 7307, "text": "“thus I trample on thee,\nthou paltry thing that feebly pointest on high; thus I split and\ndestroy thee!”\n\nAs the frantic old man thus spoke and thus trampled with his live and\ndead feet, a sneering", "labels": {"50": 9, "100": 26, "250": 141, "500": 143, "1000": 437, "2000": 1859}}, {"id": 7308, "position": 7308, "text": "and thus trampled with his live and\ndead feet, a sneering triumph that seemed meant for Ahab, and a\nfatalistic despair that seemed meant for himself—these passed over the\nmute, motionless Parsee’s face", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7309, "position": 7309, "text": "passed over the\nmute, motionless Parsee’s face. Unobserved he rose and glided away;\nwhile, awestruck by the aspect of their commander, the seamen clustered\ntogether on the forecastle, till Ahab, troubledly pacing the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7310, "position": 7310, "text": "clustered\ntogether on the forecastle, till Ahab, troubledly pacing the deck,\nshouted out—“To the braces! Up helm!—square in!”\n\nIn an instant the yards swung round; and as the ship half-wheeled upon", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7311, "position": 7311, "text": "an instant the yards swung round; and as the ship half-wheeled upon\nher heel, her three firm-seated graceful masts erectly poised upon her\nlong, ribbed hull, seemed as the three Horatii pirouetting on one", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7312, "position": 7312, "text": "hull, seemed as the three Horatii pirouetting on one\nsufficient steed.\n\nStanding between the knight-heads, Starbuck watched the Pequod’s\ntumultuous way, and Ahab’s also, as he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7313, "position": 7313, "text": "tumultuous way, and Ahab’s also, as he went lurching along the deck.\n\n“I have sat before the dense coal fire and watched it all aglow, full\nof its tormented flaming life; and I have seen", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7314, "position": 7314, "text": "all aglow, full\nof its tormented flaming life; and I have seen it wane at last, down,\ndown, to dumbest dust. Old man of oceans! of all this fiery life of\nthine, what will at length remain but", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 193}}, {"id": 7315, "position": 7315, "text": "of all this fiery life of\nthine, what will at length remain but one little heap of ashes!”\n\n“Aye,” cried Stubb, “but sea-coal ashes—mind ye that, Mr", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7316, "position": 7316, "text": "ashes—mind ye that, Mr.\nStarbuck—sea-coal, not your common charcoal. Well, well; I heard Ahab\nmutter, ‘Here some one thrusts these cards into these old hands of\nmine; swears that I must play", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7317, "position": 7317, "text": "these cards into these old hands of\nmine; swears that I must play them, and no others.’ And damn me, Ahab,\nbut thou actest right; live in the game, and die in it!”\n\n\nCHAPTER 119", "labels": {"50": 31, "100": 7, "250": 193, "500": 202, "1000": 858, "2000": 933}}, {"id": 7318, "position": 7318, "text": "live in the game, and die in it!”\n\n\nCHAPTER 119. The Candles.\n\nWarmest climes but nurse the cruellest fangs: the tiger of Bengal\ncrouches in spiced groves of ceaseless verdure", "labels": {"50": 23, "100": 96, "250": 153, "500": 457, "1000": 897, "2000": 1701}}, {"id": 7319, "position": 7319, "text": "es in spiced groves of ceaseless verdure. Skies the most\neffulgent but basket the deadliest thunders: gorgeous Cuba knows\ntornadoes that never swept tame northern lands. So, too, it is, that in\nthese resple", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 1203}}, {"id": 7320, "position": 7320, "text": "northern lands. So, too, it is, that in\nthese resplendent Japanese seas the mariner encounters the direst of\nall storms, the Typhoon. It will sometimes burst from out that\ncloudless sky, like an exploding bomb upon a", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 887}}, {"id": 7321, "position": 7321, "text": "sometimes burst from out that\ncloudless sky, like an exploding bomb upon a dazed and sleepy town.\n\nTowards evening of that day, the Pequod was torn of her canvas, and\nbare-poled was left to fight a Typhoon which had struck", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7322, "position": 7322, "text": ", and\nbare-poled was left to fight a Typhoon which had struck her directly\nahead. When darkness came on, sky and sea roared and split with the\nthunder, and blazed with the lightning, that showed the disabled masts\nfluttering here and there", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7323, "position": 7323, "text": "blazed with the lightning, that showed the disabled masts\nfluttering here and there with the rags which the first fury of the\ntempest had left for its after sport.\n\nHolding by a shroud, Starbuck was standing on the quarter-deck; at\nevery", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 7324, "position": 7324, "text": "shroud, Starbuck was standing on the quarter-deck; at\nevery flash of the lightning glancing aloft, to see what additional\ndisaster might have befallen the intricate hamper there; while Stubb\nand Flask were directing the men in", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7325, "position": 7325, "text": "hamper there; while Stubb\nand Flask were directing the men in the higher hoisting and firmer\nlashing of the boats. But all their pains seemed naught. Though lifted\nto the very top of the cranes, the windward", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7326, "position": 7326, "text": "ught. Though lifted\nto the very top of the cranes, the windward quarter boat (Ahab’s) did\nnot escape. A great rolling sea, dashing high up against the reeling\nship’s high teetering side, stove in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7327, "position": 7327, "text": "up against the reeling\nship’s high teetering side, stove in the boat’s bottom at the stern,\nand left it again, all dripping through like a sieve.\n\n“Bad work, bad work! Mr", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 7328, "position": 7328, "text": ".\n\n“Bad work, bad work! Mr. Starbuck,” said Stubb, regarding the wreck,\n“but the sea will have its way. Stubb, for one, can’t fight it. You\nsee, Mr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7329, "position": 7329, "text": "one, can’t fight it. You\nsee, Mr. Starbuck, a wave has such a great long start before it leaps,\nall round the world it runs, and then comes the spring! But as for me,\nall the start I", "labels": {"50": 2, "100": 58, "250": 183, "500": 234, "1000": 798, "2000": 408}}, {"id": 7330, "position": 7330, "text": "and then comes the spring! But as for me,\nall the start I have to meet it, is just across the deck here. But\nnever mind; it’s all in fun: so the old song says;”—(_sings_", "labels": {"50": 41, "100": 21, "250": 193, "500": 498, "1000": 849, "2000": 68}}, {"id": 7331, "position": 7331, "text": "in fun: so the old song says;”—(_sings_.)\n\n\n  Oh! jolly is the gale, And a joker is the whale, A’ flourishin’ his\n  tail,— Such a funny, sporty, gamy,", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 849, "2000": 68}}, {"id": 7332, "position": 7332, "text": "’ his\n  tail,— Such a funny, sporty, gamy, jesty, joky, hoky-poky lad, is the\n  Ocean, oh!\n\n  The scud all a flyin’, That’s his flip only foam", "labels": {"50": 41, "100": 21, "250": 91, "500": 72, "1000": 54, "2000": 1082}}, {"id": 7333, "position": 7333, "text": "scud all a flyin’, That’s his flip only foamin’; When he stirs in\n  the spicin’,— Such a funny, sporty, gamy, jesty, joky, hoky-po", "labels": {"50": 41, "100": 21, "250": 215, "500": 281, "1000": 671, "2000": 68}}, {"id": 7334, "position": 7334, "text": "y, gamy, jesty, joky, hoky-poky lad,\n  is the Ocean, oh!\n\n  Thunder splits the ships, But he only smacks his lips, A tastin’ of\n  this flip,— Such a funny", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 7335, "position": 7335, "text": "lips, A tastin’ of\n  this flip,— Such a funny, sporty, gamy, jesty, joky, hoky-poky lad,\n  is the Ocean, oh!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 16}}, {"id": 7336, "position": 7336, "text": "is the Ocean, oh!\n\n\n\n“Avast Stubb,” cried Starbuck, “let the Typhoon sing, and strike his\nharp here in our rigging; but if thou art a brave man thou wilt hold\nthy peace.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7337, "position": 7337, "text": "thou art a brave man thou wilt hold\nthy peace.”\n\n“But I am not a brave man; never said I was a brave man; I am a coward;\nand I sing to keep up my spirits", "labels": {"50": 9, "100": 82, "250": 135, "500": 332, "1000": 345, "2000": 1475}}, {"id": 7338, "position": 7338, "text": "and I sing to keep up my spirits. And I tell you what it is, Mr.\nStarbuck, there’s no way to stop my singing in this world but to cut my\nthroat. And when that’s done, ten to one", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 7339, "position": 7339, "text": "to cut my\nthroat. And when that’s done, ten to one I sing ye the doxology for a\nwind-up.”\n\n“Madman! look through my eyes if thou hast none of thine own.”", "labels": {"50": 22, "100": 41, "250": 19, "500": 3, "1000": 939, "2000": 693}}, {"id": 7340, "position": 7340, "text": "eyes if thou hast none of thine own.”\n\n“What! how can you see better of a dark night than anybody else, never\nmind how foolish?”\n\n“Here!” cried Starbuck, seizing Stubb by the shoulder, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7341, "position": 7341, "text": "Here!” cried Starbuck, seizing Stubb by the shoulder, and pointing his\nhand towards the weather bow, “markest thou not that the gale comes\nfrom the eastward, the very course Ahab is to run for Moby Dick? the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7342, "position": 7342, "text": ", the very course Ahab is to run for Moby Dick? the\nvery course he swung to this day noon? now mark his boat there; where\nis that stove? In the stern-sheets, man; where he is wont to stand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7343, "position": 7343, "text": "In the stern-sheets, man; where he is wont to stand—his\nstand-point is stove, man! Now jump overboard, and sing away, if thou\nmust!\n\n“I don’t half understand ye: what’s in", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7344, "position": 7344, "text": "must!\n\n“I don’t half understand ye: what’s in the wind?”\n\n“Yes, yes, round the Cape of Good Hope is the shortest way to\nNantucket,” soliloquized Starbuck suddenly, heedless", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7345, "position": 7345, "text": "Nantucket,” soliloquized Starbuck suddenly, heedless of Stubb’s\nquestion. “The gale that now hammers at us to stave us, we can turn it\ninto a fair wind that will drive us towards home", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7346, "position": 7346, "text": ", we can turn it\ninto a fair wind that will drive us towards home. Yonder, to windward,\nall is blackness of doom; but to leeward, homeward—I see it lightens up\nthere; but not with the lightning", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 136, "2000": 471}}, {"id": 7347, "position": 7347, "text": "ward—I see it lightens up\nthere; but not with the lightning.”\n\nAt that moment in one of the intervals of profound darkness, following\nthe flashes, a voice was heard at his side; and almost at the same\ninstant a volley of", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 925, "2000": 1904}}, {"id": 7348, "position": 7348, "text": "was heard at his side; and almost at the same\ninstant a volley of thunder peals rolled overhead.\n\n“Who’s there?”\n\n“Old Thunder!” said Ahab, groping his way along the bulwarks to his\npi", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7349, "position": 7349, "text": "ab, groping his way along the bulwarks to his\npivot-hole; but suddenly finding his path made plain to him by elbowed\nlances of fire.\n\nNow, as the lightning rod to a spire on shore is intended to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7350, "position": 7350, "text": ".\n\nNow, as the lightning rod to a spire on shore is intended to carry off\nthe perilous fluid into the soil; so the kindred rod which at sea some\nships carry to each mast, is intended to conduct it into the water", "labels": {"50": 10, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1374}}, {"id": 7351, "position": 7351, "text": "ships carry to each mast, is intended to conduct it into the water. But\nas this conductor must descend to considerable depth, that its end may\navoid all contact with the hull; and as moreover, if kept constantly\ntowing there, it would be liable", "labels": {"50": 45, "100": 63, "250": 138, "500": 290, "1000": 327, "2000": 887}}, {"id": 7352, "position": 7352, "text": "; and as moreover, if kept constantly\ntowing there, it would be liable to many mishaps, besides interfering\nnot a little with some of the rigging, and more or less impeding the\nvessel’s way in the water; because of", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 887}}, {"id": 7353, "position": 7353, "text": "or less impeding the\nvessel’s way in the water; because of all this, the lower parts of a\nship’s lightning-rods are not always overboard; but are generally made\nin long slender links, so as to be the more readily", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 7354, "position": 7354, "text": "are generally made\nin long slender links, so as to be the more readily hauled up into the\nchains outside, or thrown down into the sea, as occasion may require.\n\n“The rods! the rods!” cried Starbuck to the crew, suddenly", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7355, "position": 7355, "text": "The rods! the rods!” cried Starbuck to the crew, suddenly admonished\nto vigilance by the vivid lightning that had just been darting\nflambeaux, to light Ahab to his post", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7356, "position": 7356, "text": ", to light Ahab to his post. “Are they overboard? drop them\nover, fore and aft. Quick!”\n\n“Avast!” cried Ahab; “let’s have fair play here, though we be the\nweaker side", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7357, "position": 7357, "text": "let’s have fair play here, though we be the\nweaker side. Yet I’ll contribute to raise rods on the Himmalehs and\nAndes, that all the world may be secured; but out on privileges! Let\nthem be, sir", "labels": {"50": 9, "100": 26, "250": 219, "500": 498, "1000": 317, "2000": 39}}, {"id": 7358, "position": 7358, "text": "world may be secured; but out on privileges! Let\nthem be, sir.”\n\n“Look aloft!” cried Starbuck. “The corpusants! the corpusants!”\n\nAll the yard-arms were tipped with a pallid fire;", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7359, "position": 7359, "text": "!”\n\nAll the yard-arms were tipped with a pallid fire; and touched at each\ntri-pointed lightning-rod-end with three tapering white flames, each of\nthe three tall masts was silently burning in that sulphurous", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 7360, "position": 7360, "text": "of\nthe three tall masts was silently burning in that sulphurous air, like\nthree gigantic wax tapers before an altar.\n\n“Blast the boat! let it go!” cried Stubb at this instant, as a swashing\nsea", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 7361, "position": 7361, "text": "!” cried Stubb at this instant, as a swashing\nsea heaved up under his own little craft, so that its gunwale violently\njammed his hand, as he was passing a lashing", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 7362, "position": 7362, "text": "he was passing a lashing. “Blast it!”—but slipping\nbackward on the deck, his uplifted eyes caught the flames; and\nimmediately shifting his tone he cried—“The corpusants have mercy on us\nall!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7363, "position": 7363, "text": "cried—“The corpusants have mercy on us\nall!”\n\nTo sailors, oaths are household words; they will swear in the trance of\nthe calm, and in the teeth of the tempest; they will imprecate curses\nfrom the topsail", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 7364, "position": 7364, "text": "teeth of the tempest; they will imprecate curses\nfrom the topsail-yard-arms, when most they teeter over to a seething\nsea; but in all my voyagings, seldom have I heard a common oath when\nGod", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7365, "position": 7365, "text": "my voyagings, seldom have I heard a common oath when\nGod’s burning finger has been laid on the ship; when His “Mene, Mene,\nTekel Upharsin” has been woven into the shrouds and", "labels": {"50": 9, "100": 26, "250": 133, "500": 232, "1000": 779, "2000": 16}}, {"id": 7366, "position": 7366, "text": "Tekel Upharsin” has been woven into the shrouds and the cordage.\n\nWhile this pallidness was burning aloft, few words were heard from the\nenchanted crew; who in one thick cluster stood on the forecastle, all", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 7367, "position": 7367, "text": "enchanted crew; who in one thick cluster stood on the forecastle, all\ntheir eyes gleaming in that pale phosphorescence, like a far away\nconstellation of stars. Relieved against the ghostly light, the\ngigantic jet negro, Daggoo, loomed", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 7368, "position": 7368, "text": "against the ghostly light, the\ngigantic jet negro, Daggoo, loomed up to thrice his real stature, and\nseemed the black cloud from which the thunder had come. The parted\nmouth of Tashtego revealed his shark-white teeth,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7369, "position": 7369, "text": "The parted\nmouth of Tashtego revealed his shark-white teeth, which strangely\ngleamed as if they too had been tipped by corpusants; while lit up by\nthe preternatural light, Queequeg’s tattooing burned like", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7370, "position": 7370, "text": "ternatural light, Queequeg’s tattooing burned like Satanic blue\nflames on his body.\n\nThe tableau all waned at last with the pallidness aloft; and once more\nthe Pequod and every soul on", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7371, "position": 7371, "text": "ness aloft; and once more\nthe Pequod and every soul on her decks were wrapped in a pall. A moment\nor two passed, when Starbuck, going forward, pushed against some one.\nIt was Stubb", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7372, "position": 7372, "text": "forward, pushed against some one.\nIt was Stubb. “What thinkest thou now, man; I heard thy cry; it was not\nthe same in the song.”\n\n“No, no, it wasn’t; I said the corpus", "labels": {"50": 41, "100": 64, "250": 163, "500": 180, "1000": 54, "2000": 16}}, {"id": 7373, "position": 7373, "text": "”\n\n“No, no, it wasn’t; I said the corpusants have mercy on us all; and I\nhope they will, still. But do they only have mercy on long faces?—have\nthey no bowels for a laugh?", "labels": {"50": 41, "100": 21, "250": 91, "500": 356, "1000": 798, "2000": 1199}}, {"id": 7374, "position": 7374, "text": "mercy on long faces?—have\nthey no bowels for a laugh? And look ye, Mr. Starbuck—but it’s too dark\nto look. Hear me, then: I take that mast-head flame we saw for a sign", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7375, "position": 7375, "text": ", then: I take that mast-head flame we saw for a sign\nof good luck; for those masts are rooted in a hold that is going to be\nchock a’ block with sperm-oil, d’ye see; and so", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 7376, "position": 7376, "text": "a’ block with sperm-oil, d’ye see; and so, all that sperm will\nwork up into the masts, like sap in a tree. Yes, our three masts will\nyet be as three spermaceti candles—that", "labels": {"50": 42, "100": 46, "250": 30, "500": 451, "1000": 210, "2000": 828}}, {"id": 7377, "position": 7377, "text": "our three masts will\nyet be as three spermaceti candles—that’s the good promise we saw.”\n\nAt that moment Starbuck caught sight of Stubb’s face slowly beginning\nto glimmer into sight", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7378, "position": 7378, "text": "s face slowly beginning\nto glimmer into sight. Glancing upwards, he cried: “See! see!” and once\nmore the high tapering flames were beheld with what seemed redoubled\nsupernaturalness in their pallor.", "labels": {"50": 22, "100": 78, "250": 205, "500": 469, "1000": 783, "2000": 889}}, {"id": 7379, "position": 7379, "text": "what seemed redoubled\nsupernaturalness in their pallor.\n\n“The corpusants have mercy on us all,” cried Stubb, again.\n\nAt the base of the mainmast, full beneath the doubloon and the flame,\nthe", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7380, "position": 7380, "text": "mast, full beneath the doubloon and the flame,\nthe Parsee was kneeling in Ahab’s front, but with his head bowed away\nfrom him; while near by, from the arched and overhanging rigging, where", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7381, "position": 7381, "text": "while near by, from the arched and overhanging rigging, where\nthey had just been engaged securing a spar, a number of the seamen,\narrested by the glare, now cohered together, and hung pendulous, like a\nknot", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 7382, "position": 7382, "text": ", now cohered together, and hung pendulous, like a\nknot of numbed wasps from a drooping, orchard twig. In various\nenchanted attitudes, like the standing, or stepping, or running\nskeletons in Herculaneum, others", "labels": {"50": 48, "100": 78, "250": 189, "500": 380, "1000": 728, "2000": 1171}}, {"id": 7383, "position": 7383, "text": "standing, or stepping, or running\nskeletons in Herculaneum, others remained rooted to the deck; but all\ntheir eyes upcast.\n\n“Aye, aye, men!” cried Ahab. “Look up at it; mark it well;", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7384, "position": 7384, "text": "” cried Ahab. “Look up at it; mark it well; the white\nflame but lights the way to the White Whale! Hand me those mainmast\nlinks there; I would fain feel this pulse, and let mine beat against\nit", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7385, "position": 7385, "text": "; I would fain feel this pulse, and let mine beat against\nit; blood against fire! So.”\n\nThen turning—the last link held fast in his left hand, he put his foot\nupon the Parsee; and with fixed upward eye", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 779, "2000": 1860}}, {"id": 7386, "position": 7386, "text": ", he put his foot\nupon the Parsee; and with fixed upward eye, and high-flung right arm,\nhe stood erect before the lofty tri-pointed trinity of flames.\n\n“Oh! thou clear spirit of clear fire, whom on these", "labels": {"50": 9, "100": 26, "250": 141, "500": 365, "1000": 859, "2000": 1307}}, {"id": 7387, "position": 7387, "text": "flames.\n\n“Oh! thou clear spirit of clear fire, whom on these seas I as Persian\nonce did worship, till in the sacramental act so burned by thee, that\nto this hour I bear the scar; I now know thee, thou clear", "labels": {"50": 9, "100": 26, "250": 141, "500": 365, "1000": 859, "2000": 1307}}, {"id": 7388, "position": 7388, "text": "to this hour I bear the scar; I now know thee, thou clear spirit, and I\nnow know that thy right worship is defiance. To neither love nor\nreverence wilt thou be kind; and e’en for hate thou canst but", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 10}}, {"id": 7389, "position": 7389, "text": "t thou be kind; and e’en for hate thou canst but kill; and\nall are killed. No fearless fool now fronts thee. I own thy speechless,\nplaceless power; but to the last gasp of my earthquake life will\ndispute its", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 663, "2000": 908}}, {"id": 7390, "position": 7390, "text": "less power; but to the last gasp of my earthquake life will\ndispute its unconditional, unintegral mastery in me. In the midst of\nthe personified impersonal, a personality stands here", "labels": {"50": 20, "100": 28, "250": 132, "500": 236, "1000": 27, "2000": 872}}, {"id": 7391, "position": 7391, "text": "ersonal, a personality stands here. Though but a\npoint at best; whencesoe’er I came; wheresoe’er I go; yet while I\nearthly live, the queenly personality lives in me, and feels her royal\nrights", "labels": {"50": 16, "100": 73, "250": 201, "500": 441, "1000": 50, "2000": 232}}, {"id": 7392, "position": 7392, "text": "live, the queenly personality lives in me, and feels her royal\nrights. But war is pain, and hate is woe. Come in thy lowest form of\nlove, and I will kneel and kiss thee; but at thy highest, come", "labels": {"50": 9, "100": 10, "250": 226, "500": 56, "1000": 349, "2000": 1826}}, {"id": 7393, "position": 7393, "text": "and I will kneel and kiss thee; but at thy highest, come as mere\nsupernal power; and though thou launchest navies of full-freighted\nworlds, there’s that in here that still remains indifferent", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 1859}}, {"id": 7394, "position": 7394, "text": "there’s that in here that still remains indifferent. Oh, thou\nclear spirit, of thy fire thou madest me, and like a true child of\nfire, I breathe it back to thee.”", "labels": {"50": 9, "100": 26, "250": 141, "500": 365, "1000": 859, "2000": 1307}}, {"id": 7395, "position": 7395, "text": "it back to thee.”\n\n[_Sudden, repeated flashes of lightning; the nine flames leap\nlengthwise to thrice their previous height; Ahab, with the rest, closes\nhis eyes, his right hand pressed hard upon them._]", "labels": {"50": 27, "100": 97, "250": 112, "500": 198, "1000": 654, "2000": 216}}, {"id": 7396, "position": 7396, "text": "closes\nhis eyes, his right hand pressed hard upon them._]\n\n“I own thy speechless, placeless power; said I not so? Nor was it wrung\nfrom me; nor do I now drop these links", "labels": {"50": 9, "100": 26, "250": 141, "500": 365, "1000": 859, "2000": 946}}, {"id": 7397, "position": 7397, "text": "me; nor do I now drop these links. Thou canst blind; but I can\nthen grope. Thou canst consume; but I can then be ashes. Take the\nhomage of these poor eyes, and shutter-hands", "labels": {"50": 9, "100": 26, "250": 133, "500": 198, "1000": 437, "2000": 1859}}, {"id": 7398, "position": 7398, "text": "the\nhomage of these poor eyes, and shutter-hands. I would not take it. The\nlightning flashes through my skull; mine eye-balls ache and ache; my\nwhole beaten brain seems as beheaded, and rolling on some stunning\nground", "labels": {"50": 36, "100": 35, "250": 242, "500": 450, "1000": 893, "2000": 872}}, {"id": 7399, "position": 7399, "text": "beaten brain seems as beheaded, and rolling on some stunning\nground. Oh, oh! Yet blindfold, yet will I talk to thee. Light though\nthou be, thou leapest out of darkness; but I am darkness leaping out of\nlight, leaping", "labels": {"50": 9, "100": 26, "250": 141, "500": 198, "1000": 136, "2000": 1859}}, {"id": 7400, "position": 7400, "text": "est out of darkness; but I am darkness leaping out of\nlight, leaping out of thee! The javelins cease; open eyes; see, or not?\nThere burn the flames! Oh, thou magnanimous! now I do glory in my", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 663, "2000": 908}}, {"id": 7401, "position": 7401, "text": "flames! Oh, thou magnanimous! now I do glory in my\ngenealogy. But thou art but my fiery father; my sweet mother, I know\nnot. Oh, cruel! what hast thou done with her? There lies my puzzle;", "labels": {"50": 9, "100": 73, "250": 42, "500": 225, "1000": 589, "2000": 946}}, {"id": 7402, "position": 7402, "text": "cruel! what hast thou done with her? There lies my puzzle; but\nthine is greater. Thou knowest not how came ye, hence callest thyself\nunbegotten; certainly knowest not thy beginning, hence callest", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 193}}, {"id": 7403, "position": 7403, "text": "unbegotten; certainly knowest not thy beginning, hence callest thyself\nunbegun. I know that of me, which thou knowest not of thyself, oh, thou\nomnipotent", "labels": {"50": 9, "100": 26, "250": 141, "500": 198, "1000": 437, "2000": 1859}}, {"id": 7404, "position": 7404, "text": "self, oh, thou\nomnipotent. There is some unsuffusing thing beyond thee, thou clear\nspirit, to whom all thy eternity is but time, all thy creativeness\nmechanical. Through thee, thy flaming self, my sc", "labels": {"50": 9, "100": 73, "250": 133, "500": 414, "1000": 437, "2000": 193}}, {"id": 7405, "position": 7405, "text": "all thy creativeness\nmechanical. Through thee, thy flaming self, my scorched eyes do dimly\nsee it. Oh, thou foundling fire, thou hermit immemorial, thou too hast\nthy incommunicable riddle, thy", "labels": {"50": 16, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 193}}, {"id": 7406, "position": 7406, "text": "al, thou too hast\nthy incommunicable riddle, thy unparticipated grief. Here again with\nhaughty agony, I read my sire. Leap! leap up, and lick the sky! I leap\nwith thee;", "labels": {"50": 9, "100": 26, "250": 141, "500": 143, "1000": 437, "2000": 193}}, {"id": 7407, "position": 7407, "text": "Leap! leap up, and lick the sky! I leap\nwith thee; I burn with thee; would fain be welded with thee; defyingly\nI worship thee!”\n\n“The boat! the boat!” cried Starbuck, “look", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7408, "position": 7408, "text": "”\n\n“The boat! the boat!” cried Starbuck, “look at thy boat, old man!”\n\nAhab’s harpoon, the one forged at Perth’s fire, remained firmly lashed\nin its conspicuous crotch, so that it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7409, "position": 7409, "text": "’s fire, remained firmly lashed\nin its conspicuous crotch, so that it projected beyond his whale-boat’s\nbow; but the sea that had stove its bottom had caused the loose leather\nsheath to drop off; and from the keen steel barb", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7410, "position": 7410, "text": "the loose leather\nsheath to drop off; and from the keen steel barb there now came a\nlevelled flame of pale, forked fire. As the silent harpoon burned there\nlike a serpent’s tongue, Starbuck grasped Ahab by the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7411, "position": 7411, "text": "there\nlike a serpent’s tongue, Starbuck grasped Ahab by the arm—“God, God is\nagainst thee, old man; forbear! ’tis an ill voyage! ill begun, ill\ncontinued; let me square the yards,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7412, "position": 7412, "text": "ill voyage! ill begun, ill\ncontinued; let me square the yards, while we may, old man, and make a\nfair wind of it homewards, to go on a better voyage than this.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7413, "position": 7413, "text": "on a better voyage than this.”\n\nOverhearing Starbuck, the panic-stricken crew instantly ran to the\nbraces—though not a sail was left aloft. For the moment all the aghast\nmate’s thoughts seemed theirs;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7414, "position": 7414, "text": "For the moment all the aghast\nmate’s thoughts seemed theirs; they raised a half mutinous cry. But\ndashing the rattling lightning links to the deck, and snatching the\nburning harpoon, Ahab waved it like a torch", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7415, "position": 7415, "text": "and snatching the\nburning harpoon, Ahab waved it like a torch among them; swearing to\ntransfix with it the first sailor that but cast loose a rope’s end.\nPetrified by his aspect, and still more shrinking from the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7416, "position": 7416, "text": "s end.\nPetrified by his aspect, and still more shrinking from the fiery dart\nthat he held, the men fell back in dismay, and Ahab again spoke:—\n\n“All your oaths to hunt the White Whale are as binding as mine", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7417, "position": 7417, "text": "“All your oaths to hunt the White Whale are as binding as mine; and\nheart, soul, and body, lungs and life, old Ahab is bound. And that ye\nmay know to what tune this heart beats; look ye here;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7418, "position": 7418, "text": "that ye\nmay know to what tune this heart beats; look ye here; thus I blow out\nthe last fear!” And with one blast of his breath he extinguished the\nflame.\n\nAs in the hurricane that sweeps the plain, men fly the neighborhood of", "labels": {"50": 16, "100": 73, "250": 13, "500": 414, "1000": 668, "2000": 193}}, {"id": 7419, "position": 7419, "text": ".\n\nAs in the hurricane that sweeps the plain, men fly the neighborhood of\nsome lone, gigantic elm, whose very height and strength but render it\nso much the more unsafe, because so much the more a mark for\nthunderbolts; so at those", "labels": {"50": 47, "100": 53, "250": 101, "500": 134, "1000": 915, "2000": 609}}, {"id": 7420, "position": 7420, "text": "because so much the more a mark for\nthunderbolts; so at those last words of Ahab’s many of the mariners did\nrun from him in a terror of dismay.\n\n\nCHAPTER 120. The Deck Towards the End of the First Night Watch.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7421, "position": 7421, "text": ".\n\n\nCHAPTER 120. The Deck Towards the End of the First Night Watch.\n\n_Ahab standing by the helm. Starbuck approaching him._\n\n“We must send down the main-top-sail yard, sir", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7422, "position": 7422, "text": "main-top-sail yard, sir. The band is working\nloose and the lee lift is half-stranded. Shall I strike it, sir?”\n\n“Strike nothing; lash it. If I had sky-sail poles, I’d sway", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 7423, "position": 7423, "text": "lash it. If I had sky-sail poles, I’d sway them up\nnow.”\n\n“Sir!—in God’s name!—sir?”\n\n“Well.”\n\n“The anchors are working, sir", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7424, "position": 7424, "text": "Well.”\n\n“The anchors are working, sir. Shall I get them inboard?”\n\n“Strike nothing, and stir nothing, but lash everything. The wind rises,\nbut it has not got up to my table-lands yet", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 7425, "position": 7425, "text": "but it has not got up to my table-lands yet. Quick, and see to it.—By\nmasts and keels! he takes me for the hunch-backed skipper of some\ncoasting smack", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7426, "position": 7426, "text": "-backed skipper of some\ncoasting smack. Send down my main-top-sail yard! Ho, gluepots! Loftiest\ntrucks were made for wildest winds, and this brain-truck of mine now\nsails amid the cloud-scud", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 54, "2000": 1192}}, {"id": 7427, "position": 7427, "text": "and this brain-truck of mine now\nsails amid the cloud-scud. Shall I strike that? Oh, none but cowards\nsend down their brain-trucks in tempest time. What a hooroosh aloft\nthere! I would e’", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7428, "position": 7428, "text": "time. What a hooroosh aloft\nthere! I would e’en take it for sublime, did I not know that the colic\nis a noisy malady. Oh, take medicine, take medicine!”\n\n\nCHAPTER 121", "labels": {"50": 41, "100": 21, "250": 215, "500": 157, "1000": 141, "2000": 1939}}, {"id": 7429, "position": 7429, "text": "Oh, take medicine, take medicine!”\n\n\nCHAPTER 121. Midnight.—The Forecastle Bulwarks.\n\n_Stubb and Flask mounted on them, and passing additional lashings over\nthe anchors there hanging._", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7430, "position": 7430, "text": "additional lashings over\nthe anchors there hanging._\n\n“No, Stubb; you may pound that knot there as much as you please, but\nyou will never pound into me what you were just now saying", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7431, "position": 7431, "text": "what you were just now saying. And how\nlong ago is it since you said the very contrary? Didn’t you once say\nthat whatever ship Ahab sails in, that ship should pay something extra\non its insurance policy, just as though it were", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7432, "position": 7432, "text": "ship should pay something extra\non its insurance policy, just as though it were loaded with powder\nbarrels aft and boxes of lucifers forward? Stop, now; didn’t you say\nso?”\n\n“Well, suppose I did? What then? I", "labels": {"50": 39, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 877}}, {"id": 7433, "position": 7433, "text": "say\nso?”\n\n“Well, suppose I did? What then? I’ve part changed my flesh since that\ntime, why not my mind? Besides, supposing we _are_ loaded with powder\nbarrels aft and lucifers forward; how", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 7434, "position": 7434, "text": "we _are_ loaded with powder\nbarrels aft and lucifers forward; how the devil could the lucifers get\nafire in this drenching spray here? Why, my little man, you have pretty\nred hair, but you couldn’t get", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 925, "2000": 967}}, {"id": 7435, "position": 7435, "text": "little man, you have pretty\nred hair, but you couldn’t get afire now. Shake yourself; you’re\nAquarius, or the water-bearer, Flask; might fill pitchers at your coat\ncollar", "labels": {"50": 6, "100": 88, "250": 183, "500": 100, "1000": 488, "2000": 1199}}, {"id": 7436, "position": 7436, "text": "ask; might fill pitchers at your coat\ncollar. Don’t you see, then, that for these extra risks the Marine\nInsurance companies have extra guarantees? Here are hydrants, Flask.\nBut hark, again, and I’ll answer", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 7437, "position": 7437, "text": ", Flask.\nBut hark, again, and I’ll answer ye the other thing. First take your\nleg off from the crown of the anchor here, though, so I can pass the\nrope; now listen", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7438, "position": 7438, "text": "so I can pass the\nrope; now listen. What’s the mighty difference between holding a mast’s\nlightning-rod in the storm, and standing close by a mast that hasn’t\ngot any lightning-rod at all in a storm?", "labels": {"50": 45, "100": 64, "250": 42, "500": 244, "1000": 358, "2000": 967}}, {"id": 7439, "position": 7439, "text": "that hasn’t\ngot any lightning-rod at all in a storm? Don’t you see, you\ntimber-head, that no harm can come to the holder of the rod, unless the\nmast is first struck? What are you talking about", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7440, "position": 7440, "text": "the rod, unless the\nmast is first struck? What are you talking about, then? Not one ship in\na hundred carries rods, and Ahab,—aye, man, and all of us,—were in no\nmore danger then, in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7441, "position": 7441, "text": ", and all of us,—were in no\nmore danger then, in my poor opinion, than all the crews in ten\nthousand ships now sailing the seas. Why, you King-Post, you, I suppose\nyou would have every man in the", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 877}}, {"id": 7442, "position": 7442, "text": "King-Post, you, I suppose\nyou would have every man in the world go about with a small\nlightning-rod running up the corner of his hat, like a militia\nofficer’s skewered feather, and trailing behind like his sash", "labels": {"50": 25, "100": 41, "250": 193, "500": 407, "1000": 851, "2000": 110}}, {"id": 7443, "position": 7443, "text": "officer’s skewered feather, and trailing behind like his sash. Why\ndon’t ye be sensible, Flask? it’s easy to be sensible; why don’t ye,\nthen? any man with half an eye can be", "labels": {"50": 6, "100": 1, "250": 42, "500": 498, "1000": 851, "2000": 967}}, {"id": 7444, "position": 7444, "text": "don’t ye,\nthen? any man with half an eye can be sensible.”\n\n“I don’t know that, Stubb. You sometimes find it rather hard.”\n\n“Yes, when a fellow’s soaked through, it’", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 1620}}, {"id": 7445, "position": 7445, "text": ".”\n\n“Yes, when a fellow’s soaked through, it’s hard to be sensible, that’s\na fact. And I am about drenched with this spray. Never mind; catch the\nturn there, and pass it", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 99, "2000": 1668}}, {"id": 7446, "position": 7446, "text": ". Never mind; catch the\nturn there, and pass it. Seems to me we are lashing down these anchors\nnow as if they were never going to be used again. Tying these two\nanchors here, Flask, seems like tying a man’", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7447, "position": 7447, "text": "Tying these two\nanchors here, Flask, seems like tying a man’s hands behind him. And\nwhat big generous hands they are, to be sure. These are your iron\nfists, hey? What a hold they have, too! I wonder", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7448, "position": 7448, "text": "iron\nfists, hey? What a hold they have, too! I wonder, Flask, whether the\nworld is anchored anywhere; if she is, she swings with an uncommon long\ncable, though. There, hammer that knot down, and we’", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 7449, "position": 7449, "text": "long\ncable, though. There, hammer that knot down, and we’ve done. So; next\nto touching land, lighting on deck is the most satisfactory. I say,\njust wring out my jacket skirts, will ye? Thank ye", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 7450, "position": 7450, "text": ",\njust wring out my jacket skirts, will ye? Thank ye. They laugh at\nlong-togs so, Flask; but seems to me, a long tailed coat ought always\nto be worn in all storms afloat", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7451, "position": 7451, "text": "coat ought always\nto be worn in all storms afloat. The tails tapering down that way,\nserve to carry off the water, d’ye see. Same with cocked hats; the\ncocks form gable-end eave-troughs,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7452, "position": 7452, "text": "hats; the\ncocks form gable-end eave-troughs, Flask. No more monkey-jackets and\ntarpaulins for me; I must mount a swallow-tail, and drive down a\nbeaver; so", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 50, "2000": 39}}, {"id": 7453, "position": 7453, "text": "swallow-tail, and drive down a\nbeaver; so. Halloa! whew! there goes my tarpaulin overboard; Lord,\nLord, that the winds that come from heaven should be so unmannerly!\nThis is a nasty night", "labels": {"50": 16, "100": 64, "250": 163, "500": 498, "1000": 174, "2000": 16}}, {"id": 7454, "position": 7454, "text": "come from heaven should be so unmannerly!\nThis is a nasty night, lad.”\n\n\nCHAPTER 122. Midnight Aloft.—Thunder and Lightning.\n\n_The main-top-sail yard_.—_Tashtego passing new lash", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7455, "position": 7455, "text": "top-sail yard_.—_Tashtego passing new lashings around it_.\n\n“Um, um, um. Stop that thunder! Plenty too much thunder up here. What’s\nthe use of thunder? Um, um,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7456, "position": 7456, "text": "up here. What’s\nthe use of thunder? Um, um, um. We don’t want thunder; we want rum;\ngive us a glass of rum. Um, um, um!”\n\n\nCHAPTER 123. The Musket.", "labels": {"50": 22, "100": 55, "250": 145, "500": 3, "1000": 661, "2000": 1593}}, {"id": 7457, "position": 7457, "text": "Um, um, um!”\n\n\nCHAPTER 123. The Musket.\n\nDuring the most violent shocks of the Typhoon, the man at the Pequod’s\njaw-bone tiller had several times been reelingly hurled to the deck by\nits", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7458, "position": 7458, "text": "bone tiller had several times been reelingly hurled to the deck by\nits spasmodic motions, even though preventer tackles had been attached\nto it—for they were slack—because some play to the tiller was\nindispensable.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7459, "position": 7459, "text": "—because some play to the tiller was\nindispensable.\n\nIn a severe gale like this, while the ship is but a tossed shuttlecock\nto the blast, it is by no means uncommon to see the needles in the\ncompasses, at", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7460, "position": 7460, "text": "is by no means uncommon to see the needles in the\ncompasses, at intervals, go round and round. It was thus with the\nPequod’s; at almost every shock the helmsman had not failed to notice\nthe whirling velocity", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7461, "position": 7461, "text": "every shock the helmsman had not failed to notice\nthe whirling velocity with which they revolved upon the cards; it is a\nsight that hardly anyone can behold without some sort of unwonted\nemotion.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 7462, "position": 7462, "text": "sort of unwonted\nemotion.\n\nSome hours after midnight, the Typhoon abated so much, that through the\nstrenuous exertions of Starbuck and Stubb—one engaged forward and the\nother aft—the shivered remnants of the jib", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7463, "position": 7463, "text": "one engaged forward and the\nother aft—the shivered remnants of the jib and fore and main-top-sails\nwere cut adrift from the spars, and went eddying away to leeward, like\nthe feathers of an albatross,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7464, "position": 7464, "text": "ing away to leeward, like\nthe feathers of an albatross, which sometimes are cast to the winds\nwhen that storm-tossed bird is on the wing.\n\nThe three corresponding new sails were now bent and reefed, and a\nstorm-try", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 7465, "position": 7465, "text": "corresponding new sails were now bent and reefed, and a\nstorm-trysail was set further aft; so that the ship soon went through\nthe water with some precision again; and the course—for the present,\nEast-south-east—", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1028}}, {"id": 7466, "position": 7466, "text": "; and the course—for the present,\nEast-south-east—which he was to steer, if practicable, was once more\ngiven to the helmsman. For during the violence of the gale, he had only\nsteered according to its", "labels": {"50": 45, "100": 29, "250": 138, "500": 73, "1000": 327, "2000": 1028}}, {"id": 7467, "position": 7467, "text": "For during the violence of the gale, he had only\nsteered according to its vicissitudes. But as he was now bringing the\nship as near her course as possible, watching the compass meanwhile,\nlo! a good sign! the wind seemed coming", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 7468, "position": 7468, "text": "watching the compass meanwhile,\nlo! a good sign! the wind seemed coming round astern; aye, the foul\nbreeze became fair!\n\nInstantly the yards were squared, to the lively song of “_Ho! the fair\nwind! oh-ye-", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 7469, "position": 7469, "text": "lively song of “_Ho! the fair\nwind! oh-ye-ho, cheerly men!_” the crew singing for joy, that so\npromising an event should so soon have falsified the evil portents\npreceding it.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7470, "position": 7470, "text": "so soon have falsified the evil portents\npreceding it.\n\nIn compliance with the standing order of his commander—to report\nimmediately, and at any one of the twenty-four hours, any decided\nchange in the affairs of the deck,—Star", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7471, "position": 7471, "text": "four hours, any decided\nchange in the affairs of the deck,—Starbuck had no sooner trimmed the\nyards to the breeze—however reluctantly and gloomily,—than he\nmechanically went below to apprise Captain Ahab of the circumstance.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7472, "position": 7472, "text": "mechanically went below to apprise Captain Ahab of the circumstance.\n\nEre knocking at his state-room, he involuntarily paused before it a\nmoment. The cabin lamp—taking long swings this way and that—was burning\nfitfully", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7473, "position": 7473, "text": "cabin lamp—taking long swings this way and that—was burning\nfitfully, and casting fitful shadows upon the old man’s bolted door,—a\nthin one, with fixed blinds inserted, in place of upper panels", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 786}}, {"id": 7474, "position": 7474, "text": "with fixed blinds inserted, in place of upper panels. The\nisolated subterraneousness of the cabin made a certain humming silence\nto reign there, though it was hooped round by all the roar of the\nelements", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 7475, "position": 7475, "text": "round by all the roar of the\nelements. The loaded muskets in the rack were shiningly revealed, as\nthey stood upright against the forward bulkhead. Starbuck was an\nhonest, upright man; but out of Starbuck’s heart,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7476, "position": 7476, "text": "an\nhonest, upright man; but out of Starbuck’s heart, at that instant when\nhe saw the muskets, there strangely evolved an evil thought; but so\nblent with its neutral or good accompaniments that for the instant he\nhardly", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 7477, "position": 7477, "text": "blent with its neutral or good accompaniments that for the instant he\nhardly knew it for itself.\n\n“He would have shot me once,” he murmured, “yes, there’s the very\nmusket that he pointed at me;—", "labels": {"50": 30, "100": 69, "250": 203, "500": 204, "1000": 676, "2000": 1991}}, {"id": 7478, "position": 7478, "text": "there’s the very\nmusket that he pointed at me;—that one with the studded stock; let me\ntouch it—lift it. Strange, that I, who have handled so many deadly\nlances, strange, that I should", "labels": {"50": 18, "100": 87, "250": 102, "500": 227, "1000": 393, "2000": 677}}, {"id": 7479, "position": 7479, "text": ", who have handled so many deadly\nlances, strange, that I should shake so now. Loaded? I must see. Aye,\naye; and powder in the pan;—that’s not good. Best spill it?—wait", "labels": {"50": 9, "100": 26, "250": 42, "500": 225, "1000": 647, "2000": 666}}, {"id": 7480, "position": 7480, "text": "—that’s not good. Best spill it?—wait. I’ll\ncure myself of this. I’ll hold the musket boldly while I think.—I come\nto report a fair wind to him", "labels": {"50": 23, "100": 88, "250": 219, "500": 498, "1000": 627, "2000": 1199}}, {"id": 7481, "position": 7481, "text": ".—I come\nto report a fair wind to him. But how fair? Fair for death and\ndoom,—_that’s_ fair for Moby Dick. It’s a fair wind that’s only fair\nfor that accursed", "labels": {"50": 9, "100": 45, "250": 42, "500": 225, "1000": 647, "2000": 39}}, {"id": 7482, "position": 7482, "text": "’s a fair wind that’s only fair\nfor that accursed fish.—The very tube he pointed at me!—the very one;\n_this_ one—I hold it here; he would have killed me with the very thing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7483, "position": 7483, "text": "—I hold it here; he would have killed me with the very thing\nI handle now.—Aye and he would fain kill all his crew. Does he not say\nhe will not strike his spars to any gale? Has he not dashed", "labels": {"50": 36, "100": 64, "250": 163, "500": 219, "1000": 29, "2000": 610}}, {"id": 7484, "position": 7484, "text": "he will not strike his spars to any gale? Has he not dashed his\nheavenly quadrant? and in these same perilous seas, gropes he not his\nway by mere dead reckoning of the error-abounding log? and", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 573}}, {"id": 7485, "position": 7485, "text": "by mere dead reckoning of the error-abounding log? and in this very\nTyphoon, did he not swear that he would have no lightning-rods? But\nshall this crazed old man be tamely suffered to drag a whole ship’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7486, "position": 7486, "text": "this crazed old man be tamely suffered to drag a whole ship’s\ncompany down to doom with him?—Yes, it would make him the wilful\nmurderer of thirty men and more, if this ship come to any deadly harm;\nand come", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 7487, "position": 7487, "text": "men and more, if this ship come to any deadly harm;\nand come to deadly harm, my soul swears this ship will, if Ahab have\nhis way. If, then, he were this instant—put aside, that crime would not", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7488, "position": 7488, "text": ", then, he were this instant—put aside, that crime would not\nbe his. Ha! is he muttering in his sleep? Yes, just there,—in there,\nhe’s sleeping. Sleeping? aye, but still alive, and", "labels": {"50": 9, "100": 26, "250": 120, "500": 406, "1000": 779, "2000": 1554}}, {"id": 7489, "position": 7489, "text": ",\nhe’s sleeping. Sleeping? aye, but still alive, and soon awake again. I\ncan’t withstand thee, then, old man. Not reasoning; not remonstrance;\nnot entreaty wilt thou hearken", "labels": {"50": 9, "100": 1, "250": 42, "500": 225, "1000": 589, "2000": 946}}, {"id": 7490, "position": 7490, "text": "remonstrance;\nnot entreaty wilt thou hearken to; all this thou scornest. Flat\nobedience to thy own flat commands, this is all thou breathest. Aye,\nand say’st the men have vow’", "labels": {"50": 9, "100": 26, "250": 42, "500": 19, "1000": 499, "2000": 629}}, {"id": 7491, "position": 7491, "text": "thou breathest. Aye,\nand say’st the men have vow’d thy vow; say’st all of us are Ahabs.\nGreat God forbid!—But is there no other way? no lawful way?—Make him a", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7492, "position": 7492, "text": "But is there no other way? no lawful way?—Make him a\nprisoner to be taken home? What! hope to wrest this old man’s living\npower from his own living hands? Only a fool would try it", "labels": {"50": 34, "100": 77, "250": 164, "500": 192, "1000": 992, "2000": 840}}, {"id": 7493, "position": 7493, "text": "his own living hands? Only a fool would try it. Say he were\npinioned even; knotted all over with ropes and hawsers; chained down to\nring-bolts on this cabin floor; he would be more hideous than a caged\ntiger", "labels": {"50": 22, "100": 64, "250": 145, "500": 127, "1000": 927, "2000": 1154}}, {"id": 7494, "position": 7494, "text": "on this cabin floor; he would be more hideous than a caged\ntiger, then. I could not endure the sight; could not possibly fly his\nhowlings; all comfort, sleep itself, inestimable reason would leave me\non the long", "labels": {"50": 45, "100": 64, "250": 125, "500": 388, "1000": 313, "2000": 1495}}, {"id": 7495, "position": 7495, "text": ", sleep itself, inestimable reason would leave me\non the long intolerable voyage. What, then, remains? The land is\nhundreds of leagues away, and locked Japan the nearest. I stand alone\nhere upon an open sea, with", "labels": {"50": 20, "100": 5, "250": 132, "500": 280, "1000": 813, "2000": 1273}}, {"id": 7496, "position": 7496, "text": "locked Japan the nearest. I stand alone\nhere upon an open sea, with two oceans and a whole continent between me\nand law.—Aye, aye, ’tis so.—Is heaven a murderer when its lightning\nstrikes a would-be murderer in", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 1192}}, {"id": 7497, "position": 7497, "text": "—Is heaven a murderer when its lightning\nstrikes a would-be murderer in his bed, tindering sheets and skin\ntogether?—And would I be a murderer, then, if”—and slowly, stealthily,\nand half sideways looking,", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 24, "2000": 369}}, {"id": 7498, "position": 7498, "text": ", if”—and slowly, stealthily,\nand half sideways looking, he placed the loaded musket’s end against\nthe door.\n\n“On this level, Ahab’s hammock swings within; his head this way", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7499, "position": 7499, "text": "ab’s hammock swings within; his head this way. A\ntouch, and Starbuck may survive to hug his wife and child again.—Oh\nMary! Mary!—boy! boy! boy!—But if I wake thee not", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7500, "position": 7500, "text": "!—boy! boy! boy!—But if I wake thee not to death, old man,\nwho can tell to what unsounded deeps Starbuck’s body this day week may\nsink, with all the crew! Great God", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7501, "position": 7501, "text": "s body this day week may\nsink, with all the crew! Great God, where art Thou? Shall I? shall\nI?—The wind has gone down and shifted, sir; the fore and main topsails\nare reefed and set;", "labels": {"50": 9, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 7502, "position": 7502, "text": "sir; the fore and main topsails\nare reefed and set; she heads her course.”\n\n“Stern all! Oh Moby Dick, I clutch thy heart at last!”\n\nSuch were the sounds that now came hurtling from out the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7503, "position": 7503, "text": "last!”\n\nSuch were the sounds that now came hurtling from out the old man’s\ntormented sleep, as if Starbuck’s voice had caused the long dumb dream\nto speak.\n\nThe yet levelled musket shook like a drunkard", "labels": {"50": 37, "100": 55, "250": 95, "500": 93, "1000": 195, "2000": 1620}}, {"id": 7504, "position": 7504, "text": "to speak.\n\nThe yet levelled musket shook like a drunkard’s arm against the panel;\nStarbuck seemed wrestling with an angel; but turning from the door, he\nplaced the death-tube in its rack, and left the place", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 7505, "position": 7505, "text": ", he\nplaced the death-tube in its rack, and left the place.\n\n“He’s too sound asleep, Mr. Stubb; go thou down, and wake him, and tell\nhim. I must see to the deck here", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7506, "position": 7506, "text": "him, and tell\nhim. I must see to the deck here. Thou know’st what to say.”\n\n\nCHAPTER 124. The Needle.\n\nNext morning the not-yet-subsided sea rolled in long slow billows of\nmighty bulk, and st", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7507, "position": 7507, "text": "-subsided sea rolled in long slow billows of\nmighty bulk, and striving in the Pequod’s gurgling track, pushed her on\nlike giants’ palms outspread. The strong, unstaggering breeze abounded", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7508, "position": 7508, "text": "palms outspread. The strong, unstaggering breeze abounded\nso, that sky and air seemed vast outbellying sails; the whole world\nboomed before the wind. Muffled in the full morning light, the\ninvisible sun was only known by", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 9, "2000": 1904}}, {"id": 7509, "position": 7509, "text": ". Muffled in the full morning light, the\ninvisible sun was only known by the spread intensity of his place;\nwhere his bayonet rays moved on in stacks. Emblazonings, as of crowned\nBabylonian kings and queens, reigned over everything", "labels": {"50": 22, "100": 78, "250": 205, "500": 414, "1000": 631, "2000": 213}}, {"id": 7510, "position": 7510, "text": "zonings, as of crowned\nBabylonian kings and queens, reigned over everything. The sea was as a\ncrucible of molten gold, that bubblingly leaps with light and heat.\n\nLong maintaining an enchanted silence, Ahab stood apart; and every time\nthe", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7511, "position": 7511, "text": "Long maintaining an enchanted silence, Ahab stood apart; and every time\nthe tetering ship loweringly pitched down her bowsprit, he turned to\neye the bright sun’s rays produced ahead; and when she profoundly\nsettled by the stern, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7512, "position": 7512, "text": "s rays produced ahead; and when she profoundly\nsettled by the stern, he turned behind, and saw the sun’s rearward\nplace, and how the same yellow rays were blending with his undeviating\nwake.", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 945, "2000": 1893}}, {"id": 7513, "position": 7513, "text": "blending with his undeviating\nwake.\n\n“Ha, ha, my ship! thou mightest well be taken now for the sea-chariot\nof the sun. Ho, ho! all ye nations before my prow, I bring the sun to\nye", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7514, "position": 7514, "text": "! all ye nations before my prow, I bring the sun to\nye! Yoke on the further billows; hallo! a tandem, I drive the sea!”\n\nBut suddenly reined back by some counter thought, he hurried towards\nthe", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 779, "2000": 16}}, {"id": 7515, "position": 7515, "text": "”\n\nBut suddenly reined back by some counter thought, he hurried towards\nthe helm, huskily demanding how the ship was heading.\n\n“East-sou-east, sir,” said the frightened steersman.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 7516, "position": 7516, "text": "sir,” said the frightened steersman.\n\n“Thou liest!” smiting him with his clenched fist. “Heading East at this\nhour in the morning, and the sun astern?”\n\nUpon this every soul was confounded; for the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7517, "position": 7517, "text": "sun astern?”\n\nUpon this every soul was confounded; for the phenomenon just then\nobserved by Ahab had unaccountably escaped every one else; but its very\nblinding palpableness must have been the cause.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 7518, "position": 7518, "text": "blinding palpableness must have been the cause.\n\nThrusting his head half way into the binnacle, Ahab caught one glimpse\nof the compasses; his uplifted arm slowly fell; for a moment he almost\nseemed to stagger", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7519, "position": 7519, "text": "ed arm slowly fell; for a moment he almost\nseemed to stagger. Standing behind him Starbuck looked, and lo! the two\ncompasses pointed East, and the Pequod was as infallibly going West.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7520, "position": 7520, "text": "quod was as infallibly going West.\n\nBut ere the first wild alarm could get out abroad among the crew, the\nold man with a rigid laugh exclaimed, “I have it! It has happened\nbefore. Mr", "labels": {"50": 37, "100": 99, "250": 145, "500": 437, "1000": 496, "2000": 1593}}, {"id": 7521, "position": 7521, "text": "I have it! It has happened\nbefore. Mr. Starbuck, last night’s thunder turned our compasses—that’s\nall. Thou hast before now heard of such a thing, I take it.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7522, "position": 7522, "text": "of such a thing, I take it.”\n\n“Aye; but never before has it happened to me, sir,” said the pale mate,\ngloomily.\n\nHere, it must needs be said, that accidents like this have in more than\none", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 786}}, {"id": 7523, "position": 7523, "text": "it must needs be said, that accidents like this have in more than\none case occurred to ships in violent storms. The magnetic energy, as\ndeveloped in the mariner’s needle, is, as all know, essentially one\nwith the electricity beheld", "labels": {"50": 45, "100": 63, "250": 50, "500": 33, "1000": 83, "2000": 1541}}, {"id": 7524, "position": 7524, "text": "needle, is, as all know, essentially one\nwith the electricity beheld in heaven; hence it is not to be much\nmarvelled at, that such things should be. Instances where the lightning\nhas actually struck the vessel, so as to smite", "labels": {"50": 3, "100": 70, "250": 50, "500": 395, "1000": 109, "2000": 817}}, {"id": 7525, "position": 7525, "text": "Instances where the lightning\nhas actually struck the vessel, so as to smite down some of the spars\nand rigging, the effect upon the needle has at times been still more\nfatal; all its loadstone virtue being annihilated, so", "labels": {"50": 45, "100": 63, "250": 152, "500": 290, "1000": 611, "2000": 1541}}, {"id": 7526, "position": 7526, "text": "more\nfatal; all its loadstone virtue being annihilated, so that the before\nmagnetic steel was of no more use than an old wife’s knitting needle.\nBut in either case, the needle never again, of itself, recovers the", "labels": {"50": 35, "100": 94, "250": 23, "500": 206, "1000": 83, "2000": 1541}}, {"id": 7527, "position": 7527, "text": "in either case, the needle never again, of itself, recovers the\noriginal virtue thus marred or lost; and if the binnacle compasses be\naffected, the same fate reaches all the others that may be in the ship;\neven were the", "labels": {"50": 10, "100": 75, "250": 129, "500": 395, "1000": 256, "2000": 1986}}, {"id": 7528, "position": 7528, "text": "fate reaches all the others that may be in the ship;\neven were the lowermost one inserted into the kelson.\n\nDeliberately standing before the binnacle, and eyeing the transpointed\ncompasses, the old man, with the sharp of his", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7529, "position": 7529, "text": "transpointed\ncompasses, the old man, with the sharp of his extended hand, now took\nthe precise bearing of the sun, and satisfied that the needles were\nexactly inverted, shouted out his orders for the ship’s course to be\nchanged accordingly", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1668}}, {"id": 7530, "position": 7530, "text": ", shouted out his orders for the ship’s course to be\nchanged accordingly. The yards were hard up; and once more the Pequod\nthrust her undaunted bows into the opposing wind, for the supposed fair\none had only been juggling", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7531, "position": 7531, "text": "into the opposing wind, for the supposed fair\none had only been juggling her.\n\nMeanwhile, whatever were his own secret thoughts, Starbuck said\nnothing, but quietly he issued all requisite orders; while Stubb and\nFlask—who in some", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 54, "2000": 1620}}, {"id": 7532, "position": 7532, "text": "all requisite orders; while Stubb and\nFlask—who in some small degree seemed then to be sharing his\nfeelings—likewise unmurmuringly acquiesced. As for the men, though some\nof them lowly rumbled, their fear", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7533, "position": 7533, "text": "As for the men, though some\nof them lowly rumbled, their fear of Ahab was greater than their fear\nof Fate. But as ever before, the pagan harpooneers remained almost\nwholly unimpressed; or if impressed, it was only", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7534, "position": 7534, "text": "eers remained almost\nwholly unimpressed; or if impressed, it was only with a certain\nmagnetism shot into their congenial hearts from inflexible Ahab’s.\n\nFor a space the old man walked the deck in rolling reveries", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7535, "position": 7535, "text": "s.\n\nFor a space the old man walked the deck in rolling reveries. But\nchancing to slip with his ivory heel, he saw the crushed copper\nsight-tubes of the quadrant he had the day before dashed to the deck.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 7536, "position": 7536, "text": "the quadrant he had the day before dashed to the deck.\n\n“Thou poor, proud heaven-gazer and sun’s pilot! yesterday I wrecked\nthee, and to-day the compasses would fain have wrecked me. So, so", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7537, "position": 7537, "text": "day the compasses would fain have wrecked me. So, so. But\nAhab is lord over the level loadstone yet. Mr. Starbuck—a lance without\na pole; a top-maul, and the smallest of the sail", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7538, "position": 7538, "text": "a pole; a top-maul, and the smallest of the sail-maker’s needles.\nQuick!”\n\nAccessory, perhaps, to the impulse dictating the thing he was now about\nto do, were certain prudential motives,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7539, "position": 7539, "text": "thing he was now about\nto do, were certain prudential motives, whose object might have been to\nrevive the spirits of his crew by a stroke of his subtile skill, in a\nmatter so wondrous as that of the inverted compasses", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7540, "position": 7540, "text": ", in a\nmatter so wondrous as that of the inverted compasses. Besides, the old\nman well knew that to steer by transpointed needles, though clumsily\npracticable, was not a thing to be passed over by super", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 448, "2000": 825}}, {"id": 7541, "position": 7541, "text": "ily\npracticable, was not a thing to be passed over by superstitious\nsailors, without some shudderings and evil portents.\n\n“Men,” said he, steadily turning upon the crew, as the mate handed him\nthe things he had", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7542, "position": 7542, "text": "steadily turning upon the crew, as the mate handed him\nthe things he had demanded, “my men, the thunder turned old Ahab’s\nneedles; but out of this bit of steel Ahab can make one of his own,\nthat will point", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7543, "position": 7543, "text": "bit of steel Ahab can make one of his own,\nthat will point as true as any.”\n\nAbashed glances of servile wonder were exchanged by the sailors, as\nthis was said; and with fascinated eyes they awaited whatever magic\nmight follow", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7544, "position": 7544, "text": "as\nthis was said; and with fascinated eyes they awaited whatever magic\nmight follow. But Starbuck looked away.\n\nWith a blow from the top-maul Ahab knocked off the steel head of the\nlance, and then handing to the mate the long", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7545, "position": 7545, "text": "the steel head of the\nlance, and then handing to the mate the long iron rod remaining, bade\nhim hold it upright, without its touching the deck. Then, with the\nmaul, after repeatedly smiting the upper end of this iron rod", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7546, "position": 7546, "text": "the\nmaul, after repeatedly smiting the upper end of this iron rod, he\nplaced the blunted needle endwise on the top of it, and less strongly\nhammered that, several times, the mate still holding the rod as before", "labels": {"50": 12, "100": 42, "250": 155, "500": 309, "1000": 294, "2000": 538}}, {"id": 7547, "position": 7547, "text": ", several times, the mate still holding the rod as before.\nThen going through some small strange motions with it—whether\nindispensable to the magnetizing of the steel, or merely intended to\naugment the awe of the crew, is uncertain", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 7548, "position": 7548, "text": ", or merely intended to\naugment the awe of the crew, is uncertain—he called for linen thread;\nand moving to the binnacle, slipped out the two reversed needles there,\nand horizontally suspended the sail-needle by its middle, over", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7549, "position": 7549, "text": "needles there,\nand horizontally suspended the sail-needle by its middle, over one of\nthe compass-cards. At first, the steel went round and round, quivering\nand vibrating at either end; but at last it settled to its place, when\nAh", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7550, "position": 7550, "text": "at either end; but at last it settled to its place, when\nAhab, who had been intently watching for this result, stepped frankly\nback from the binnacle, and pointing his stretched arm towards it,\nexclaimed,—“Look ye,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7551, "position": 7551, "text": "and pointing his stretched arm towards it,\nexclaimed,—“Look ye, for yourselves, if Ahab be not lord of the level\nloadstone! The sun is East, and that compass swears it!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7552, "position": 7552, "text": "and that compass swears it!”\n\nOne after another they peered in, for nothing but their own eyes could\npersuade such ignorance as theirs, and one after another they slunk\naway.\n\nIn his fiery eyes of scorn and triumph, you then saw", "labels": {"50": 40, "100": 12, "250": 212, "500": 21, "1000": 990, "2000": 401}}, {"id": 7553, "position": 7553, "text": "away.\n\nIn his fiery eyes of scorn and triumph, you then saw Ahab in all his\nfatal pride.\n\n\nCHAPTER 125. The Log and Line.\n\nWhile now the fated Pequod had been so long afloat this voyage, the log\nand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7554, "position": 7554, "text": "Pequod had been so long afloat this voyage, the log\nand line had but very seldom been in use. Owing to a confident reliance\nupon other means of determining the vessel’s place, some merchantmen,\nand many whalemen, especially", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7555, "position": 7555, "text": "vessel’s place, some merchantmen,\nand many whalemen, especially when cruising, wholly neglect to heave\nthe log; though at the same time, and frequently more for form’s sake\nthan anything else, regularly putting down upon the customary", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7556, "position": 7556, "text": "for form’s sake\nthan anything else, regularly putting down upon the customary slate the\ncourse steered by the ship, as well as the presumed average rate of\nprogression every hour. It had been thus with the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7557, "position": 7557, "text": "It had been thus with the Pequod. The wooden\nreel and angular log attached hung, long untouched, just beneath the\nrailing of the after bulwarks. Rains and spray had damped it; sun and\nwind had warped it; all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7558, "position": 7558, "text": "and spray had damped it; sun and\nwind had warped it; all the elements had combined to rot a thing that\nhung so idly. But heedless of all this, his mood seized Ahab, as he\nhappened to glance upon the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7559, "position": 7559, "text": "this, his mood seized Ahab, as he\nhappened to glance upon the reel, not many hours after the magnet\nscene, and he remembered how his quadrant was no more, and recalled his\nfrantic oath about the level log and line", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7560, "position": 7560, "text": "and recalled his\nfrantic oath about the level log and line. The ship was sailing\nplungingly; astern the billows rolled in riots.\n\n“Forward, there! Heave the log!”\n\nTwo seamen came", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7561, "position": 7561, "text": "the log!”\n\nTwo seamen came. The golden-hued Tahitian and the grizzly Manxman.\n“Take the reel, one of ye, I’ll heave.”\n\nThey went towards the extreme stern, on the ship", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 324}}, {"id": 7562, "position": 7562, "text": "ll heave.”\n\nThey went towards the extreme stern, on the ship’s lee side, where the\ndeck, with the oblique energy of the wind, was now almost dipping into\nthe creamy, sidelong-rushing sea.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7563, "position": 7563, "text": "dipping into\nthe creamy, sidelong-rushing sea.\n\nThe Manxman took the reel, and holding it high up, by the projecting\nhandle-ends of the spindle, round which the spool of line revolved, so\nstood with the", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 692, "2000": 778}}, {"id": 7564, "position": 7564, "text": ", round which the spool of line revolved, so\nstood with the angular log hanging downwards, till Ahab advanced to\nhim.\n\nAhab stood before him, and was lightly unwinding some thirty or forty\nturns to form a preliminary hand-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7565, "position": 7565, "text": "lightly unwinding some thirty or forty\nturns to form a preliminary hand-coil to toss overboard, when the old\nManxman, who was intently eyeing both him and the line, made bold to\nspeak.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 7566, "position": 7566, "text": "line, made bold to\nspeak.\n\n“Sir, I mistrust it; this line looks far gone, long heat and wet have\nspoiled it.”\n\n“’Twill hold, old gentleman. Long heat and wet, have they spoiled thee", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7567, "position": 7567, "text": "l hold, old gentleman. Long heat and wet, have they spoiled thee?\nThou seem’st to hold. Or, truer perhaps, life holds thee; not thou it.”\n\n“I hold the spool, sir", "labels": {"50": 9, "100": 1, "250": 42, "500": 498, "1000": 647, "2000": 666}}, {"id": 7568, "position": 7568, "text": "it.”\n\n“I hold the spool, sir. But just as my captain says. With these grey\nhairs of mine ’tis not worth while disputing, ’specially with a\nsuperior, who’ll ne’er confess.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 7569, "position": 7569, "text": "specially with a\nsuperior, who’ll ne’er confess.”\n\n“What’s that? There now’s a patched professor in Queen Nature’s\ngranite-founded College; but methinks he’s too subservient", "labels": {"50": 41, "100": 21, "250": 174, "500": 5, "1000": 333, "2000": 514}}, {"id": 7570, "position": 7570, "text": "founded College; but methinks he’s too subservient. Where wert\nthou born?”\n\n“In the little rocky Isle of Man, sir.”\n\n“Excellent! Thou’st hit the world by that.”", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 672, "2000": 1091}}, {"id": 7571, "position": 7571, "text": "“Excellent! Thou’st hit the world by that.”\n\n“I know not, sir, but I was born there.”\n\n“In the Isle of Man, hey? Well, the other way, it’s good", "labels": {"50": 23, "100": 31, "250": 219, "500": 221, "1000": 627, "2000": 1199}}, {"id": 7572, "position": 7572, "text": "? Well, the other way, it’s good. Here’s a man\nfrom Man; a man born in once independent Man, and now unmanned of Man;\nwhich is sucked in—by what? Up with the reel! The dead,", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 719, "2000": 653}}, {"id": 7573, "position": 7573, "text": "is sucked in—by what? Up with the reel! The dead, blind wall\nbutts all inquiring heads at last. Up with it! So.”\n\nThe log was heaved. The loose coils rapidly straightened out in a long\ndragging", "labels": {"50": 22, "100": 55, "250": 28, "500": 185, "1000": 99, "2000": 1111}}, {"id": 7574, "position": 7574, "text": "log was heaved. The loose coils rapidly straightened out in a long\ndragging line astern, and then, instantly, the reel began to whirl. In\nturn, jerkingly raised and lowered by the rolling billows, the towing\nresistance of", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7575, "position": 7575, "text": "jerkingly raised and lowered by the rolling billows, the towing\nresistance of the log caused the old reelman to stagger strangely.\n\n“Hold hard!”\n\nSnap! the overstrained line sagged down in one long festoon; the\ntugging log", "labels": {"50": 37, "100": 55, "250": 145, "500": 363, "1000": 99, "2000": 1111}}, {"id": 7576, "position": 7576, "text": "overstrained line sagged down in one long festoon; the\ntugging log was gone.\n\n“I crush the quadrant, the thunder turns the needles, and now the mad\nsea parts the log-line. But Ahab can mend all", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7577, "position": 7577, "text": "parts the log-line. But Ahab can mend all. Haul in here, Tahitian;\nreel up, Manxman. And look ye, let the carpenter make another log, and\nmend thou the line", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7578, "position": 7578, "text": "carpenter make another log, and\nmend thou the line. See to it.”\n\n“There he goes now; to him nothing’s happened; but to me, the skewer\nseems loosening out of the middle of the world", "labels": {"50": 37, "100": 64, "250": 171, "500": 363, "1000": 327, "2000": 1620}}, {"id": 7579, "position": 7579, "text": "skewer\nseems loosening out of the middle of the world. Haul in, haul in,\nTahitian! These lines run whole, and whirling out: come in broken, and\ndragging slow", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 7580, "position": 7580, "text": "come in broken, and\ndragging slow. Ha, Pip? come to help; eh, Pip?”\n\n“Pip? whom call ye Pip? Pip jumped from the whale-boat. Pip’s missing", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 7581, "position": 7581, "text": "boat. Pip’s missing.\nLet’s see now if ye haven’t fished him up here, fisherman. It drags\nhard; I guess he’s holding on. Jerk him, Tahiti! Jerk him off; we haul\nin", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 7582, "position": 7582, "text": "on. Jerk him, Tahiti! Jerk him off; we haul\nin no cowards here. Ho! there’s his arm just breaking water. A hatchet!\na hatchet! cut it off—we haul in no cowards here", "labels": {"50": 6, "100": 1, "250": 42, "500": 180, "1000": 531, "2000": 324}}, {"id": 7583, "position": 7583, "text": "a hatchet! cut it off—we haul in no cowards here. Captain Ahab! sir,\nsir! here’s Pip, trying to get on board again.”\n\n“Peace, thou crazy loon,” cried the Manx", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 967}}, {"id": 7584, "position": 7584, "text": ".”\n\n“Peace, thou crazy loon,” cried the Manxman, seizing him by the arm.\n“Away from the quarter-deck!”\n\n“The greater idiot ever scolds the lesser,” muttered Ahab, advancing", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7585, "position": 7585, "text": "idiot ever scolds the lesser,” muttered Ahab, advancing.\n“Hands off from that holiness! Where sayest thou Pip was, boy?\n\n“Astern there, sir, astern! Lo! lo!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7586, "position": 7586, "text": ", sir, astern! Lo! lo!”\n\n“And who art thou, boy? I see not my reflection in the vacant pupils of\nthy eyes. Oh God! that man should be a thing for immortal souls to\nsieve through! Who", "labels": {"50": 9, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 7587, "position": 7587, "text": "that man should be a thing for immortal souls to\nsieve through! Who art thou, boy?”\n\n“Bell-boy, sir; ship’s-crier; ding, dong, ding! Pip! Pip! Pip! One\nhundred pounds", "labels": {"50": 23, "100": 64, "250": 219, "500": 180, "1000": 851, "2000": 967}}, {"id": 7588, "position": 7588, "text": "ding, dong, ding! Pip! Pip! Pip! One\nhundred pounds of clay reward for Pip; five feet high—looks\ncowardly—quickest known by that! Ding, dong, ding! Who’s seen Pip the\ncoward?”", "labels": {"50": 37, "100": 86, "250": 91, "500": 178, "1000": 54, "2000": 68}}, {"id": 7589, "position": 7589, "text": "Ding, dong, ding! Who’s seen Pip the\ncoward?”\n\n“There can be no hearts above the snow-line. Oh, ye frozen heavens!\nlook down here. Ye did beget this luckless child, and have abandoned\nhim", "labels": {"50": 11, "100": 12, "250": 16, "500": 276, "1000": 707, "2000": 822}}, {"id": 7590, "position": 7590, "text": "here. Ye did beget this luckless child, and have abandoned\nhim, ye creative libertines. Here, boy; Ahab’s cabin shall be Pip’s\nhome henceforth, while Ahab lives", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7591, "position": 7591, "text": "s\nhome henceforth, while Ahab lives. Thou touchest my inmost centre, boy;\nthou art tied to me by cords woven of my heart-strings. Come, let’s\ndown.”", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7592, "position": 7592, "text": ", let’s\ndown.”\n\n“What’s this? here’s velvet shark-skin,” intently gazing at Ahab’s\nhand, and feeling it. “Ah, now, had poor Pip but felt so kind a thing\nas", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 54, "2000": 1620}}, {"id": 7593, "position": 7593, "text": "“Ah, now, had poor Pip but felt so kind a thing\nas this, perhaps he had ne’er been lost! This seems to me, sir, as a\nman-rope; something that weak souls may hold by", "labels": {"50": 9, "100": 64, "250": 219, "500": 180, "1000": 345, "2000": 1620}}, {"id": 7594, "position": 7594, "text": "man-rope; something that weak souls may hold by. Oh, sir, let old Perth\nnow come and rivet these two hands together; the black one with the\nwhite, for I will not let this go.”", "labels": {"50": 18, "100": 87, "250": 102, "500": 205, "1000": 621, "2000": 1951}}, {"id": 7595, "position": 7595, "text": ", for I will not let this go.”\n\n“Oh, boy, nor will I thee, unless I should thereby drag thee to worse\nhorrors than are here. Come, then, to my cabin. Lo! ye believers in\ngods all goodness,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 7596, "position": 7596, "text": "then, to my cabin. Lo! ye believers in\ngods all goodness, and in man all ill, lo you! see the omniscient gods\noblivious of suffering man; and man, though idiotic, and knowing not\nwhat he does,", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 16}}, {"id": 7597, "position": 7597, "text": "; and man, though idiotic, and knowing not\nwhat he does, yet full of the sweet things of love and gratitude. Come!\nI feel prouder leading thee by thy black hand, than though I grasped an\nEmperor’s!”", "labels": {"50": 9, "100": 81, "250": 153, "500": 366, "1000": 236, "2000": 976}}, {"id": 7598, "position": 7598, "text": "thy black hand, than though I grasped an\nEmperor’s!”\n\n“There go two daft ones now,” muttered the old Manxman. “One daft with\nstrength, the other daft with weakness", "labels": {"50": 18, "100": 31, "250": 228, "500": 205, "1000": 621, "2000": 428}}, {"id": 7599, "position": 7599, "text": "with\nstrength, the other daft with weakness. But here’s the end of the\nrotten line—all dripping, too. Mend it, eh? I think we had best have a\nnew line altogether. I’ll see Mr", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 693}}, {"id": 7600, "position": 7600, "text": "had best have a\nnew line altogether. I’ll see Mr. Stubb about it.”\n\n\nCHAPTER 126. The Life-Buoy.\n\nSteering now south-eastward by Ahab’s levelled steel, and her progress\nsolely determined by Ah", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7601, "position": 7601, "text": "Ahab’s levelled steel, and her progress\nsolely determined by Ahab’s level log and line; the Pequod held on her\npath towards the Equator. Making so long a passage through such\nunfrequented waters, des", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7602, "position": 7602, "text": "Making so long a passage through such\nunfrequented waters, descrying no ships, and ere long, sideways\nimpelled by unvarying trade winds, over waves monotonously mild; all\nthese seemed the strange calm things pre", "labels": {"50": 45, "100": 64, "250": 138, "500": 13, "1000": 300, "2000": 1014}}, {"id": 7603, "position": 7603, "text": "over waves monotonously mild; all\nthese seemed the strange calm things preluding some riotous and\ndesperate scene.\n\nAt last, when the ship drew near to the outskirts, as it were, of the\nEquatorial fishing-ground, and in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7604, "position": 7604, "text": ", as it were, of the\nEquatorial fishing-ground, and in the deep darkness that goes before\nthe dawn, was sailing by a cluster of rocky islets; the watch—then\nheaded by Flask—was startled by a cry so plaintively", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 531, "2000": 1904}}, {"id": 7605, "position": 7605, "text": "—then\nheaded by Flask—was startled by a cry so plaintively wild and\nunearthly—like half-articulated wailings of the ghosts of all Herod’s\nmurdered Innocents—that one and all, they started from their rev", "labels": {"50": 16, "100": 78, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 7606, "position": 7606, "text": "s\nmurdered Innocents—that one and all, they started from their reveries,\nand for the space of some moments stood, or sat, or leaned all\ntransfixedly listening, like the carved Roman slave, while that wild\ncry remained within hearing", "labels": {"50": 16, "100": 26, "250": 26, "500": 254, "1000": 850, "2000": 689}}, {"id": 7607, "position": 7607, "text": "listening, like the carved Roman slave, while that wild\ncry remained within hearing. The Christian or civilized part of the\ncrew said it was mermaids, and shuddered; but the pagan harpooneers\nremained unappalled", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1904}}, {"id": 7608, "position": 7608, "text": "pagan harpooneers\nremained unappalled. Yet the grey Manxman—the oldest mariner of\nall—declared that the wild thrilling sounds that were heard, were the\nvoices of newly drowned men in the sea.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 472}}, {"id": 7609, "position": 7609, "text": "voices of newly drowned men in the sea.\n\nBelow in his hammock, Ahab did not hear of this till grey dawn, when he\ncame to the deck; it was then recounted to him by Flask, not\nunaccompanied", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7610, "position": 7610, "text": "was then recounted to him by Flask, not\nunaccompanied with hinted dark meanings. He hollowly laughed, and thus\nexplained the wonder.\n\nThose rocky islands the ship had passed were the resort of great\nnumbers of seals, and some young", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 1014}}, {"id": 7611, "position": 7611, "text": "ship had passed were the resort of great\nnumbers of seals, and some young seals that had lost their dams, or\nsome dams that had lost their cubs, must have risen nigh the ship and\nkept company with her, crying and sobbing with their human", "labels": {"50": 45, "100": 29, "250": 34, "500": 48, "1000": 997, "2000": 207}}, {"id": 7612, "position": 7612, "text": "gh the ship and\nkept company with her, crying and sobbing with their human sort of\nwail. But this only the more affected some of them, because most\nmariners cherish a very superstitious feeling about seals, arising not\nonly from their peculiar", "labels": {"50": 45, "100": 64, "250": 138, "500": 48, "1000": 327, "2000": 1931}}, {"id": 7613, "position": 7613, "text": "a very superstitious feeling about seals, arising not\nonly from their peculiar tones when in distress, but also from the\nhuman look of their round heads and semi-intelligent faces, seen\npeeringly uprising from the water alongside", "labels": {"50": 3, "100": 24, "250": 52, "500": 288, "1000": 505, "2000": 207}}, {"id": 7614, "position": 7614, "text": ", seen\npeeringly uprising from the water alongside. In the sea, under certain\ncircumstances, seals have more than once been mistaken for men.\n\nBut the bodings of the crew were destined to receive a most plausible\nconfirmation in the fate of one of", "labels": {"50": 45, "100": 29, "250": 138, "500": 28, "1000": 723, "2000": 1584}}, {"id": 7615, "position": 7615, "text": "crew were destined to receive a most plausible\nconfirmation in the fate of one of their number that morning. At\nsun-rise this man went from his hammock to his mast-head at the fore;\nand whether it was that he was not yet", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 7616, "position": 7616, "text": "-head at the fore;\nand whether it was that he was not yet half waked from his sleep (for\nsailors sometimes go aloft in a transition state), whether it was thus\nwith the man, there is now no telling; but,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 7617, "position": 7617, "text": "it was thus\nwith the man, there is now no telling; but, be that as it may, he had\nnot been long at his perch, when a cry was heard—a cry and a\nrushing—and looking up, they saw a falling", "labels": {"50": 18, "100": 83, "250": 60, "500": 238, "1000": 395, "2000": 290}}, {"id": 7618, "position": 7618, "text": "—a cry and a\nrushing—and looking up, they saw a falling phantom in the air; and\nlooking down, a little tossed heap of white bubbles in the blue of the\nsea.\n\nThe life-buoy—a long slender cask—", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 7619, "position": 7619, "text": "the\nsea.\n\nThe life-buoy—a long slender cask—was dropped from the stern, where it\nalways hung obedient to a cunning spring; but no hand rose to seize it,\nand the sun having long beat upon this cas", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7620, "position": 7620, "text": "hand rose to seize it,\nand the sun having long beat upon this cask it had shrunken, so that it\nslowly filled, and that parched wood also filled at its every pore; and\nthe studded iron-bound cask", "labels": {"50": 16, "100": 83, "250": 240, "500": 406, "1000": 520, "2000": 596}}, {"id": 7621, "position": 7621, "text": "at its every pore; and\nthe studded iron-bound cask followed the sailor to the bottom, as if to\nyield him his pillow, though in sooth but a hard one.\n\nAnd thus the first man of the Pequod that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7622, "position": 7622, "text": "a hard one.\n\nAnd thus the first man of the Pequod that mounted the mast to look out\nfor the White Whale, on the White Whale’s own peculiar ground; that man\nwas swallowed up in the deep", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7623, "position": 7623, "text": "; that man\nwas swallowed up in the deep. But few, perhaps, thought of that at the\ntime. Indeed, in some sort, they were not grieved at this event, at\nleast as a portent; for they regarded it,", "labels": {"50": 46, "100": 72, "250": 85, "500": 214, "1000": 722, "2000": 1589}}, {"id": 7624, "position": 7624, "text": "this event, at\nleast as a portent; for they regarded it, not as a foreshadowing of\nevil in the future, but as the fulfilment of an evil already presaged", "labels": {"50": 12, "100": 38, "250": 65, "500": 43, "1000": 737, "2000": 819}}, {"id": 7625, "position": 7625, "text": "of an evil already presaged.\nThey declared that now they knew the reason of those wild shrieks they\nhad heard the night before. But again the old Manxman said nay.\n\nThe lost life-buoy was now to be replaced;", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 9, "2000": 472}}, {"id": 7626, "position": 7626, "text": "said nay.\n\nThe lost life-buoy was now to be replaced; Starbuck was directed to see\nto it; but as no cask of sufficient lightness could be found, and as in\nthe feverish eagerness of what seemed the approaching", "labels": {"50": 16, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 16}}, {"id": 7627, "position": 7627, "text": "found, and as in\nthe feverish eagerness of what seemed the approaching crisis of the\nvoyage, all hands were impatient of any toil but what was directly\nconnected with its final end, whatever that might prove to be;\ntherefore, they were going", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 1028}}, {"id": 7628, "position": 7628, "text": "final end, whatever that might prove to be;\ntherefore, they were going to leave the ship’s stern unprovided with a\nbuoy, when by certain strange signs and inuendoes Queequeg hinted a\nhint concerning his", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7629, "position": 7629, "text": "signs and inuendoes Queequeg hinted a\nhint concerning his coffin.\n\n“A life-buoy of a coffin!” cried Starbuck, starting.\n\n“Rather queer, that, I should say,” said Stubb.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7630, "position": 7630, "text": "Rather queer, that, I should say,” said Stubb.\n\n“It will make a good enough one,” said Flask, “the carpenter here can\narrange it easily.”\n\n“Bring it up; there’s nothing else for it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7631, "position": 7631, "text": "easily.”\n\n“Bring it up; there’s nothing else for it,” said Starbuck, after a\nmelancholy pause. “Rig it, carpenter; do not look at me so—the coffin,\nI mean", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7632, "position": 7632, "text": "at me so—the coffin,\nI mean. Dost thou hear me? Rig it.”\n\n“And shall I nail down the lid, sir?” moving his hand as with a hammer.\n\n“Aye.”", "labels": {"50": 25, "100": 5, "250": 136, "500": 180, "1000": 375, "2000": 1657}}, {"id": 7633, "position": 7633, "text": "as with a hammer.\n\n“Aye.”\n\n“And shall I caulk the seams, sir?” moving his hand as with a\ncaulking-iron.\n\n“Aye.”\n\n“And shall I then pay over the same with pitch", "labels": {"50": 41, "100": 64, "250": 163, "500": 180, "1000": 54, "2000": 967}}, {"id": 7634, "position": 7634, "text": "“Aye.”\n\n“And shall I then pay over the same with pitch, sir?” moving his hand\nas with a pitch-pot.\n\n“Away! what possesses thee to this? Make a life-buoy of the coffin, and\nno", "labels": {"50": 9, "100": 64, "250": 138, "500": 180, "1000": 327, "2000": 1620}}, {"id": 7635, "position": 7635, "text": "to this? Make a life-buoy of the coffin, and\nno more.—Mr. Stubb, Mr. Flask, come forward with me.”\n\n“He goes off in a huff", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7636, "position": 7636, "text": "He goes off in a huff. The whole he can endure; at the parts he\nbaulks. Now I don’t like this. I make a leg for Captain Ahab, and he\nwears it like a gentleman; but I make a", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 851, "2000": 1620}}, {"id": 7637, "position": 7637, "text": "Ahab, and he\nwears it like a gentleman; but I make a bandbox for Queequeg, and he\nwon’t put his head into it. Are all my pains to go for nothing with\nthat coffin? And now I’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7638, "position": 7638, "text": "all my pains to go for nothing with\nthat coffin? And now I’m ordered to make a life-buoy of it. It’s like\nturning an old coat; going to bring the flesh on the other side now", "labels": {"50": 45, "100": 64, "250": 212, "500": 21, "1000": 690, "2000": 401}}, {"id": 7639, "position": 7639, "text": "; going to bring the flesh on the other side now. I\ndon’t like this cobbling sort of business—I don’t like it at all; it’s\nundignified; it’s not my place", "labels": {"50": 6, "100": 1, "250": 68, "500": 326, "1000": 719, "2000": 653}}, {"id": 7640, "position": 7640, "text": "s\nundignified; it’s not my place. Let tinkers’ brats do tinkerings; we\nare their betters. I like to take in hand none but clean, virgin,\nfair-and-square mathematical jobs, something", "labels": {"50": 41, "100": 21, "250": 91, "500": 221, "1000": 627, "2000": 1199}}, {"id": 7641, "position": 7641, "text": "none but clean, virgin,\nfair-and-square mathematical jobs, something that regularly begins at\nthe beginning, and is at the middle when midway, and comes to an end at\nthe conclusion; not a cobbler’s job, that’s", "labels": {"50": 7, "100": 7, "250": 214, "500": 36, "1000": 373, "2000": 834}}, {"id": 7642, "position": 7642, "text": "at\nthe conclusion; not a cobbler’s job, that’s at an end in the middle,\nand at the beginning at the end. It’s the old woman’s tricks to be\ngiving cobbling jobs", "labels": {"50": 31, "100": 20, "250": 49, "500": 78, "1000": 933, "2000": 1081}}, {"id": 7643, "position": 7643, "text": "woman’s tricks to be\ngiving cobbling jobs. Lord! what an affection all old women have for\ntinkers. I know an old woman of sixty-five who ran away with a\nbald-headed young tinker once", "labels": {"50": 11, "100": 41, "250": 91, "500": 229, "1000": 24, "2000": 1199}}, {"id": 7644, "position": 7644, "text": "away with a\nbald-headed young tinker once. And that’s the reason I never would work\nfor lonely widow old women ashore, when I kept my job-shop in the\nVineyard; they might have taken it into their lonely old heads to", "labels": {"50": 23, "100": 64, "250": 91, "500": 221, "1000": 851, "2000": 1199}}, {"id": 7645, "position": 7645, "text": "in the\nVineyard; they might have taken it into their lonely old heads to run\noff with me. But heigh-ho! there are no caps at sea but snow-caps. Let\nme see. Nail down the lid; caulk the", "labels": {"50": 6, "100": 1, "250": 42, "500": 244, "1000": 719, "2000": 16}}, {"id": 7646, "position": 7646, "text": "caps. Let\nme see. Nail down the lid; caulk the seams; pay over the same with\npitch; batten them down tight, and hang it with the snap-spring over\nthe ship’s stern", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 7647, "position": 7647, "text": "the snap-spring over\nthe ship’s stern. Were ever such things done before with a coffin? Some\nsuperstitious old carpenters, now, would be tied up in the rigging, ere\nthey would do the job", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7648, "position": 7648, "text": "in the rigging, ere\nthey would do the job. But I’m made of knotty Aroostook hemlock; I\ndon’t budge. Cruppered with a coffin! Sailing about with a grave-yard\ntray!", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 967}}, {"id": 7649, "position": 7649, "text": "uppered with a coffin! Sailing about with a grave-yard\ntray! But never mind. We workers in woods make bridal-bedsteads and\ncard-tables, as well as coffins and hearses", "labels": {"50": 16, "100": 20, "250": 15, "500": 370, "1000": 375, "2000": 1657}}, {"id": 7650, "position": 7650, "text": "as well as coffins and hearses. We work by the month, or\nby the job, or by the profit; not for us to ask the why and wherefore\nof our work, unless it be too confounded cobbling, and", "labels": {"50": 31, "100": 7, "250": 193, "500": 370, "1000": 375, "2000": 965}}, {"id": 7651, "position": 7651, "text": "e\nof our work, unless it be too confounded cobbling, and then we stash it\nif we can. Hem! I’ll do the job, now, tenderly. I’ll have me—let’s\nsee—how many", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 7652, "position": 7652, "text": "tenderly. I’ll have me—let’s\nsee—how many in the ship’s company, all told? But I’ve forgotten. Any\nway, I’ll have me thirty separate, Turk’s-headed life-lines", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7653, "position": 7653, "text": "’ll have me thirty separate, Turk’s-headed life-lines, each three\nfeet long hanging all round to the coffin. Then, if the hull go down,\nthere’ll be thirty lively fellows all fighting for one coffin, a sight", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 851, "2000": 967}}, {"id": 7654, "position": 7654, "text": "there’ll be thirty lively fellows all fighting for one coffin, a sight\nnot seen very often beneath the sun! Come hammer, caulking-iron,\npitch-pot, and marling-spike! Let’s to it.”", "labels": {"50": 37, "100": 86, "250": 122, "500": 9, "1000": 920, "2000": 1974}}, {"id": 7655, "position": 7655, "text": ", and marling-spike! Let’s to it.”\n\n\nCHAPTER 127. The Deck.\n\n_The coffin laid upon two line-tubs, between the vice-bench and the\nopen hatchway; the Carpenter caulking its seams", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 7656, "position": 7656, "text": "bench and the\nopen hatchway; the Carpenter caulking its seams; the string of twisted\noakum slowly unwinding from a large roll of it placed in the bosom of\nhis frock.—Ahab comes slowly from the cabin", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7657, "position": 7657, "text": "bosom of\nhis frock.—Ahab comes slowly from the cabin-gangway, and hears Pip\nfollowing him._\n\n“Back, lad; I will be with ye again presently. He goes! Not this hand\ncomplies with my", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7658, "position": 7658, "text": "ye again presently. He goes! Not this hand\ncomplies with my humor more genially than that boy.—Middle aisle of a\nchurch! What’s here?”\n\n“Life-buoy, sir. Mr", "labels": {"50": 22, "100": 88, "250": 205, "500": 180, "1000": 24, "2000": 369}}, {"id": 7659, "position": 7659, "text": "?”\n\n“Life-buoy, sir. Mr. Starbuck’s orders. Oh, look, sir! Beware the\nhatchway!”\n\n“Thank ye, man. Thy coffin lies handy to the vault.”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 1620}}, {"id": 7660, "position": 7660, "text": "man. Thy coffin lies handy to the vault.”\n\n“Sir? The hatchway? oh! So it does, sir, so it does.”\n\n“Art not thou the leg-maker? Look, did not this stump come from thy\nshop", "labels": {"50": 9, "100": 26, "250": 133, "500": 180, "1000": 672, "2000": 1091}}, {"id": 7661, "position": 7661, "text": "the leg-maker? Look, did not this stump come from thy\nshop?”\n\n“I believe it did, sir; does the ferrule stand, sir?”\n\n“Well enough. But art thou not also the undertaker?”", "labels": {"50": 1, "100": 49, "250": 185, "500": 263, "1000": 791, "2000": 959}}, {"id": 7662, "position": 7662, "text": "“Well enough. But art thou not also the undertaker?”\n\n“Aye, sir; I patched up this thing here as a coffin for Queequeg; but\nthey’ve set me now to turning it into something else.”", "labels": {"50": 41, "100": 64, "250": 219, "500": 180, "1000": 375, "2000": 1620}}, {"id": 7663, "position": 7663, "text": "they’ve set me now to turning it into something else.”\n\n“Then tell me; art thou not an arrant, all-grasping, intermeddling,\nmonopolising, heathenish old scamp, to be one day making", "labels": {"50": 31, "100": 75, "250": 30, "500": 475, "1000": 616, "2000": 39}}, {"id": 7664, "position": 7664, "text": "polising, heathenish old scamp, to be one day making legs, and the\nnext day coffins to clap them in, and yet again life-buoys out of those\nsame coffins? Thou art as unprincipled", "labels": {"50": 23, "100": 87, "250": 219, "500": 498, "1000": 317, "2000": 1087}}, {"id": 7665, "position": 7665, "text": "out of those\nsame coffins? Thou art as unprincipled as the gods, and as much of a\njack-of-all-trades.”\n\n“But I do not mean anything, sir. I do as I do.”", "labels": {"50": 9, "100": 26, "250": 141, "500": 307, "1000": 616, "2000": 1859}}, {"id": 7666, "position": 7666, "text": "I do not mean anything, sir. I do as I do.”\n\n“The gods again. Hark ye, dost thou not ever sing working about a\ncoffin? The Titans, they say, hummed snatches when chipping out the\ncraters", "labels": {"50": 31, "100": 7, "250": 69, "500": 187, "1000": 343, "2000": 1199}}, {"id": 7667, "position": 7667, "text": "The Titans, they say, hummed snatches when chipping out the\ncraters for volcanoes; and the grave-digger in the play sings, spade in\nhand. Dost thou never?”\n\n“Sing, sir? Do I sing? Oh, I", "labels": {"50": 41, "100": 21, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 7668, "position": 7668, "text": "never?”\n\n“Sing, sir? Do I sing? Oh, I’m indifferent enough, sir, for that; but\nthe reason why the grave-digger made music must have been because there\nwas none in his spade, sir", "labels": {"50": 16, "100": 73, "250": 193, "500": 498, "1000": 174, "2000": 0}}, {"id": 7669, "position": 7669, "text": "must have been because there\nwas none in his spade, sir. But the caulking mallet is full of it. Hark\nto it.”\n\n“Aye, and that’s because the lid there’s a sounding-board; and", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 317, "2000": 1087}}, {"id": 7670, "position": 7670, "text": "that’s because the lid there’s a sounding-board; and what in\nall things makes the sounding-board is this—there’s naught beneath. And\nyet, a coffin with a body in it rings pretty much the same,", "labels": {"50": 25, "100": 39, "250": 79, "500": 3, "1000": 462, "2000": 378}}, {"id": 7671, "position": 7671, "text": "yet, a coffin with a body in it rings pretty much the same, Carpenter.\nHast thou ever helped carry a bier, and heard the coffin knock against\nthe churchyard gate, going in?\n\n“Faith, sir, I’ve——", "labels": {"50": 16, "100": 73, "250": 193, "500": 180, "1000": 174, "2000": 16}}, {"id": 7672, "position": 7672, "text": "gate, going in?\n\n“Faith, sir, I’ve——”\n\n“Faith? What’s that?”\n\n“Why, faith, sir, it’s only a sort of exclamation-like—that’s all", "labels": {"50": 35, "100": 94, "250": 219, "500": 265, "1000": 74, "2000": 421}}, {"id": 7673, "position": 7673, "text": "only a sort of exclamation-like—that’s all,\nsir.”\n\n“Um, um; go on.”\n\n“I was about to say, sir, that——”", "labels": {"50": 39, "100": 64, "250": 163, "500": 53, "1000": 54, "2000": 1790}}, {"id": 7674, "position": 7674, "text": "sir, that——”\n\n“Art thou a silk-worm? Dost thou spin thy own shroud out of thyself?\nLook at thy bosom! Despatch! and get these traps out of sight.”", "labels": {"50": 9, "100": 26, "250": 120, "500": 12, "1000": 19, "2000": 1275}}, {"id": 7675, "position": 7675, "text": "patch! and get these traps out of sight.”\n\n“He goes aft. That was sudden, now; but squalls come sudden in hot\nlatitudes. I’ve heard that the Isle of Albemarle, one of the", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 7676, "position": 7676, "text": "’ve heard that the Isle of Albemarle, one of the\nGallipagos, is cut by the Equator right in the middle. Seems to me some\nsort of Equator cuts yon old man, too, right in his middle", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 533, "2000": 1082}}, {"id": 7677, "position": 7677, "text": "of Equator cuts yon old man, too, right in his middle. He’s always\nunder the Line—fiery hot, I tell ye! He’s looking this way—come, oakum;\nquick. Here we go again", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7678, "position": 7678, "text": "way—come, oakum;\nquick. Here we go again. This wooden mallet is the cork, and I’m the\nprofessor of musical glasses—tap, tap!”\n\n(_Ahab to himself_.)", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7679, "position": 7679, "text": "!”\n\n(_Ahab to himself_.)\n\n“There’s a sight! There’s a sound! The greyheaded woodpecker tapping\nthe hollow tree! Blind and dumb might well be envied now", "labels": {"50": 16, "100": 12, "250": 16, "500": 331, "1000": 987, "2000": 72}}, {"id": 7680, "position": 7680, "text": "! Blind and dumb might well be envied now. See! that\nthing rests on two line-tubs, full of tow-lines. A most malicious wag,\nthat fellow. Rat-tat! So man’s seconds tick", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 7681, "position": 7681, "text": ",\nthat fellow. Rat-tat! So man’s seconds tick! Oh! how immaterial are all\nmaterials! What things real are there, but imponderable thoughts? Here\nnow’s the very dreaded symbol of grim", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 50, "2000": 916}}, {"id": 7682, "position": 7682, "text": "erable thoughts? Here\nnow’s the very dreaded symbol of grim death, by a mere hap, made the\nexpressive sign of the help and hope of most endangered life. A\nlife-buoy of a coffin! Does it go further", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7683, "position": 7683, "text": "life. A\nlife-buoy of a coffin! Does it go further? Can it be that in some\nspiritual sense the coffin is, after all, but an immortality-preserver!\nI’ll think of that. But no", "labels": {"50": 45, "100": 64, "250": 163, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7684, "position": 7684, "text": "preserver!\nI’ll think of that. But no. So far gone am I in the dark side of earth,\nthat its other side, the theoretic bright one, seems but uncertain\ntwilight to me", "labels": {"50": 22, "100": 78, "250": 229, "500": 286, "1000": 252, "2000": 1027}}, {"id": 7685, "position": 7685, "text": "one, seems but uncertain\ntwilight to me. Will ye never have done, Carpenter, with that accursed\nsound? I go below; let me not see that thing here when I return again.\nNow, then, Pip, we’ll talk", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7686, "position": 7686, "text": "when I return again.\nNow, then, Pip, we’ll talk this over; I do suck most wondrous\nphilosophies from thee! Some unknown conduits from the unknown worlds\nmust empty into thee!”\n\n\nCHAPTER 128", "labels": {"50": 10, "100": 75, "250": 13, "500": 414, "1000": 27, "2000": 1201}}, {"id": 7687, "position": 7687, "text": "duits from the unknown worlds\nmust empty into thee!”\n\n\nCHAPTER 128. The Pequod Meets The Rachel.\n\nNext day, a large ship, the Rachel, was descried, bearing directly down\nupon the Pequod, all her spa", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 300, "2000": 1014}}, {"id": 7688, "position": 7688, "text": "cried, bearing directly down\nupon the Pequod, all her spars thickly clustering with men. At the time\nthe Pequod was making good speed through the water; but as the\nbroad-winged windward stranger shot nigh", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7689, "position": 7689, "text": "the water; but as the\nbroad-winged windward stranger shot nigh to her, the boastful sails all\nfell together as blank bladders that are burst, and all life fled from\nthe smitten hull.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 7690, "position": 7690, "text": "all life fled from\nthe smitten hull.\n\n“Bad news; she brings bad news,” muttered the old Manxman. But ere her\ncommander, who, with trumpet to mouth, stood up in his boat; ere he\ncould", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 7691, "position": 7691, "text": "with trumpet to mouth, stood up in his boat; ere he\ncould hopefully hail, Ahab’s voice was heard.\n\n“Hast seen the White Whale?”\n\n“Aye, yesterday. Have ye seen a whale-boat adrift?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7692, "position": 7692, "text": "“Aye, yesterday. Have ye seen a whale-boat adrift?”\n\nThrottling his joy, Ahab negatively answered this unexpected question;\nand would then have fain boarded the stranger, when the stranger\ncaptain himself, having stopped his vessel", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7693, "position": 7693, "text": "n boarded the stranger, when the stranger\ncaptain himself, having stopped his vessel’s way, was seen descending\nher side. A few keen pulls, and his boat-hook soon clinched the\nPequod’s main-chains, and he sprang", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7694, "position": 7694, "text": "soon clinched the\nPequod’s main-chains, and he sprang to the deck. Immediately he was\nrecognised by Ahab for a Nantucketer he knew. But no formal salutation\nwas exchanged.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7695, "position": 7695, "text": "no formal salutation\nwas exchanged.\n\n“Where was he?—not killed!—not killed!” cried Ahab, closely advancing.\n“How was it?”\n\nIt seemed that somewhat late on the afternoon of the day previous,\nwhile three of", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7696, "position": 7696, "text": "seemed that somewhat late on the afternoon of the day previous,\nwhile three of the stranger’s boats were engaged with a shoal of\nwhales, which had led them some four or five miles from the ship; and\nwhile they were yet in swift chase", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7697, "position": 7697, "text": "or five miles from the ship; and\nwhile they were yet in swift chase to windward, the white hump and head\nof Moby Dick had suddenly loomed up out of the water, not very far to\nleeward; whereupon, the fourth rigged", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7698, "position": 7698, "text": "the water, not very far to\nleeward; whereupon, the fourth rigged boat—a reserved one—had been\ninstantly lowered in chase. After a keen sail before the wind, this\nfourth boat—the swiftest keeled of all—seemed to", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 7699, "position": 7699, "text": ", this\nfourth boat—the swiftest keeled of all—seemed to have succeeded in\nfastening—at least, as well as the man at the mast-head could tell\nanything about it. In the distance he saw the diminished dotted boat;", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1668}}, {"id": 7700, "position": 7700, "text": "tell\nanything about it. In the distance he saw the diminished dotted boat;\nand then a swift gleam of bubbling white water; and after that nothing\nmore; whence it was concluded that the stricken whale must have\nindefinitely run away with his pursuers,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7701, "position": 7701, "text": "concluded that the stricken whale must have\nindefinitely run away with his pursuers, as often happens. There was\nsome apprehension, but no positive alarm, as yet. The recall signals\nwere placed in the rigging; darkness came on; and forced to pick", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 7702, "position": 7702, "text": "were placed in the rigging; darkness came on; and forced to pick up her\nthree far to windward boats—ere going in quest of the fourth one in the\nprecisely opposite direction—the ship had not only been necessitated to\nleave that boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 7703, "position": 7703, "text": "precisely opposite direction—the ship had not only been necessitated to\nleave that boat to its fate till near midnight, but, for the time, to\nincrease her distance from it. But the rest of her crew being at last\nsafe aboard, she crowded all", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 282}}, {"id": 7704, "position": 7704, "text": "But the rest of her crew being at last\nsafe aboard, she crowded all sail—stunsail on stunsail—after the\nmissing boat; kindling a fire in her try-pots for a beacon; and every\nother man aloft on", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7705, "position": 7705, "text": "her try-pots for a beacon; and every\nother man aloft on the look-out. But though when she had thus sailed a\nsufficient distance to gain the presumed place of the absent ones when\nlast seen; though she then paused to lower her", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 7706, "position": 7706, "text": "of the absent ones when\nlast seen; though she then paused to lower her spare boats to pull all\naround her; and not finding anything, had again dashed on; again\npaused, and lowered her boats; and though she had thus continued doing\ntill daylight", "labels": {"50": 45, "100": 29, "250": 82, "500": 327, "1000": 732, "2000": 1518}}, {"id": 7707, "position": 7707, "text": ", and lowered her boats; and though she had thus continued doing\ntill daylight; yet not the least glimpse of the missing keel had been\nseen.\n\nThe story told, the stranger Captain immediately went on to reveal his\nobject in boarding the Pequod", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7708, "position": 7708, "text": "Captain immediately went on to reveal his\nobject in boarding the Pequod. He desired that ship to unite with his\nown in the search; by sailing over the sea some four or five miles\napart, on parallel lines, and so sweeping a double horizon", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 7709, "position": 7709, "text": "or five miles\napart, on parallel lines, and so sweeping a double horizon, as it were.\n\n“I will wager something now,” whispered Stubb to Flask, “that some one\nin that missing boat wore off that Captain’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7710, "position": 7710, "text": ", “that some one\nin that missing boat wore off that Captain’s best coat; mayhap, his\nwatch—he’s so cursed anxious to get it back. Who ever heard of two\npious whale-ships cruising after one missing whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7711, "position": 7711, "text": ". Who ever heard of two\npious whale-ships cruising after one missing whale-boat in the height\nof the whaling season? See, Flask, only see how pale he looks—pale in\nthe very buttons of his eyes—look—it wasn", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7712, "position": 7712, "text": "looks—pale in\nthe very buttons of his eyes—look—it wasn’t the coat—it must have been\nthe—”\n\n“My boy, my own boy is among them. For God’s sake—I beg, I\nconjure", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 851, "2000": 1199}}, {"id": 7713, "position": 7713, "text": "among them. For God’s sake—I beg, I\nconjure”—here exclaimed the stranger Captain to Ahab, who thus far had\nbut icily received his petition. “For eight-and-forty hours let me\ncharter your ship", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7714, "position": 7714, "text": "petition. “For eight-and-forty hours let me\ncharter your ship—I will gladly pay for it, and roundly pay for it—if\nthere be no other way—for eight-and-forty hours only—only that—you", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 701, "2000": 1793}}, {"id": 7715, "position": 7715, "text": "way—for eight-and-forty hours only—only that—you\nmust, oh, you must, and you _shall_ do this thing.”\n\n“His son!” cried Stubb, “oh, it’s his son he", "labels": {"50": 40, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7716, "position": 7716, "text": "!” cried Stubb, “oh, it’s his son he’s lost! I take back the\ncoat and watch—what says Ahab? We must save that boy.”\n\n“He’s drowned with the rest on ’em", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7717, "position": 7717, "text": "that boy.”\n\n“He’s drowned with the rest on ’em, last night,” said the old Manx\nsailor standing behind them; “I heard; all of ye heard their spirits.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 7718, "position": 7718, "text": "of ye heard their spirits.”\n\nNow, as it shortly turned out, what made this incident of the Rachel’s\nthe more melancholy, was the circumstance, that not only was one of the\nCaptain’s sons among the number of the missing boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 239, "1000": 851, "2000": 801}}, {"id": 7719, "position": 7719, "text": "was one of the\nCaptain’s sons among the number of the missing boat’s crew; but among\nthe number of the other boat’s crews, at the same time, but on the\nother hand, separated from the ship during the dark vic", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 7720, "position": 7720, "text": ", but on the\nother hand, separated from the ship during the dark vicissitudes of the\nchase, there had been still another son; as that for a time, the\nwretched father was plunged to the bottom of the cruellest per", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 282}}, {"id": 7721, "position": 7721, "text": "the\nwretched father was plunged to the bottom of the cruellest perplexity;\nwhich was only solved for him by his chief mate’s instinctively\nadopting the ordinary procedure of a whale-ship in such emergencies,\nthat is, when placed between", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7722, "position": 7722, "text": "of a whale-ship in such emergencies,\nthat is, when placed between jeopardized but divided boats, always to\npick up the majority first. But the captain, for some unknown\nconstitutional reason, had refrained from mentioning all this, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7723, "position": 7723, "text": "for some unknown\nconstitutional reason, had refrained from mentioning all this, and not\ntill forced to it by Ahab’s iciness did he allude to his one yet\nmissing boy; a little lad, but twelve years old, whose father with", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7724, "position": 7724, "text": "missing boy; a little lad, but twelve years old, whose father with the\nearnest but unmisgiving hardihood of a Nantucketer’s paternal love, had\nthus early sought to initiate him in the perils and wonders of a\nvo", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7725, "position": 7725, "text": "thus early sought to initiate him in the perils and wonders of a\nvocation almost immemorially the destiny of all his race. Nor does it\nunfrequently occur, that Nantucket captains will send a son of such\ntender age", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7726, "position": 7726, "text": "ly occur, that Nantucket captains will send a son of such\ntender age away from them, for a protracted three or four years’ voyage\nin some other ship than their own; so that their first knowledge of a\nwhaleman’s career shall", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7727, "position": 7727, "text": "own; so that their first knowledge of a\nwhaleman’s career shall be unenervated by any chance display of a\nfather’s natural but untimely partiality, or undue apprehensiveness and\nconcern.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7728, "position": 7728, "text": "ity, or undue apprehensiveness and\nconcern.\n\nMeantime, now the stranger was still beseeching his poor boon of Ahab;\nand Ahab still stood like an anvil, receiving every shock, but without\nthe least quivering of", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7729, "position": 7729, "text": "like an anvil, receiving every shock, but without\nthe least quivering of his own.\n\n“I will not go,” said the stranger, “till you say _aye_ to me. Do to me\nas you would have me do to you", "labels": {"50": 23, "100": 88, "250": 145, "500": 266, "1000": 296, "2000": 1810}}, {"id": 7730, "position": 7730, "text": "_ to me. Do to me\nas you would have me do to you in the like case. For _you_ too have a\nboy, Captain Ahab—though but a child, and nestling safely at home now—a\nchild of your", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 877}}, {"id": 7731, "position": 7731, "text": "a child, and nestling safely at home now—a\nchild of your old age too—Yes, yes, you relent; I see it—run, run, men,\nnow, and stand by to square in the yards.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 7732, "position": 7732, "text": "men,\nnow, and stand by to square in the yards.”\n\n“Avast,” cried Ahab—“touch not a rope-yarn”; then in a voice that\nprolongingly moulded every word—“Captain Gardiner,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7733, "position": 7733, "text": "voice that\nprolongingly moulded every word—“Captain Gardiner, I will not do it.\nEven now I lose time. Good-bye, good-bye. God bless ye, man, and may I\nforgive myself, but I must", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7734, "position": 7734, "text": "God bless ye, man, and may I\nforgive myself, but I must go. Mr. Starbuck, look at the binnacle\nwatch, and in three minutes from this present instant warn off all\nstrangers: then brace forward again, and let", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7735, "position": 7735, "text": "this present instant warn off all\nstrangers: then brace forward again, and let the ship sail as before.”\n\nHurriedly turning, with averted face, he descended into his cabin,\nleaving the strange captain transfixed at this unconditional and utter\nrejection", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7736, "position": 7736, "text": ",\nleaving the strange captain transfixed at this unconditional and utter\nrejection of his so earnest suit. But starting from his enchantment,\nGardiner silently hurried to the side; more fell than stepped into his\nboat, and returned to his ship.", "labels": {"50": 45, "100": 64, "250": 138, "500": 43, "1000": 737, "2000": 142}}, {"id": 7737, "position": 7737, "text": "; more fell than stepped into his\nboat, and returned to his ship.\n\nSoon the two ships diverged their wakes; and long as the strange vessel\nwas in view, she was seen to yaw hither and thither at every dark spot", "labels": {"50": 9, "100": 26, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 7738, "position": 7738, "text": "was seen to yaw hither and thither at every dark spot,\nhowever small, on the sea. This way and that her yards were swung\nround; starboard and larboard, she continued to tack; now she beat\nagainst a", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 7739, "position": 7739, "text": "larboard, she continued to tack; now she beat\nagainst a head sea; and again it pushed her before it; while all the\nwhile, her masts and yards were thickly clustered with men, as three\ntall cherry trees, when", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 7740, "position": 7740, "text": "yards were thickly clustered with men, as three\ntall cherry trees, when the boys are cherrying among the boughs.\n\nBut by her still halting course and winding, woeful way, you plainly\nsaw that this ship that so wept", "labels": {"50": 16, "100": 73, "250": 240, "500": 232, "1000": 779, "2000": 16}}, {"id": 7741, "position": 7741, "text": ", woeful way, you plainly\nsaw that this ship that so wept with spray, still remained without\ncomfort. She was Rachel, weeping for her children, because they were\nnot.\n\n\nCHAPTER 129. The Cabin.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 282}}, {"id": 7742, "position": 7742, "text": "not.\n\n\nCHAPTER 129. The Cabin.\n\n(_Ahab moving to go on deck; Pip catches him by the hand to follow._)\n\n“Lad, lad, I tell thee thou must not follow Ahab now", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7743, "position": 7743, "text": "tell thee thou must not follow Ahab now. The hour is\ncoming when Ahab would not scare thee from him, yet would not have thee\nby him. There is that in thee, poor lad, which I feel too curing to my\nmala", "labels": {"50": 9, "100": 26, "250": 102, "500": 198, "1000": 616, "2000": 1859}}, {"id": 7744, "position": 7744, "text": "in thee, poor lad, which I feel too curing to my\nmalady. Like cures like; and for this hunt, my malady becomes my most\ndesired health. Do thou abide below here, where they shall serve thee,\nas", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 118, "2000": 1393}}, {"id": 7745, "position": 7745, "text": ". Do thou abide below here, where they shall serve thee,\nas if thou wert the captain. Aye, lad, thou shalt sit here in my own\nscrewed chair; another screw to it, thou must be.”", "labels": {"50": 9, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 7746, "position": 7746, "text": "chair; another screw to it, thou must be.”\n\n“No, no, no! ye have not a whole body, sir; do ye but use poor me for\nyour one lost leg; only tread upon me, sir; I ask no", "labels": {"50": 9, "100": 64, "250": 219, "500": 180, "1000": 345, "2000": 1620}}, {"id": 7747, "position": 7747, "text": "your one lost leg; only tread upon me, sir; I ask no more, so I remain\na part of ye.”\n\n“Oh! spite of million villains, this makes me a bigot in the fadeless\nfidelity of man!—and", "labels": {"50": 23, "100": 87, "250": 219, "500": 73, "1000": 317, "2000": 1087}}, {"id": 7748, "position": 7748, "text": "makes me a bigot in the fadeless\nfidelity of man!—and a black! and crazy!—but methinks like-cures-like\napplies to him too; he grows so sane again.”", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 7749, "position": 7749, "text": "too; he grows so sane again.”\n\n“They tell me, sir, that Stubb did once desert poor little Pip, whose\ndrowned bones now show white, for all the blackness of his living skin", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7750, "position": 7750, "text": "the blackness of his living skin.\nBut I will never desert ye, sir, as Stubb did him. Sir, I must go with\nye.”\n\n“If thou speakest thus to me much more, Ahab’s purpose keels up", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7751, "position": 7751, "text": "est thus to me much more, Ahab’s purpose keels up in him.\nI tell thee no; it cannot be.”\n\n“Oh good master, master, master!\n\n“Weep so, and I will murder thee! have a care", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7752, "position": 7752, "text": "master!\n\n“Weep so, and I will murder thee! have a care, for Ahab too is mad.\nListen, and thou wilt often hear my ivory foot upon the deck, and still\nknow that I am there", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7753, "position": 7753, "text": "the deck, and still\nknow that I am there. And now I quit thee. Thy hand!—Met! True art\nthou, lad, as the circumference to its centre. So: God for ever bless\nthee; and if it", "labels": {"50": 9, "100": 26, "250": 120, "500": 143, "1000": 637, "2000": 1886}}, {"id": 7754, "position": 7754, "text": "to its centre. So: God for ever bless\nthee; and if it come to that,—God for ever save thee, let what will\nbefall.”\n\n(_Ahab goes; Pip steps one step forward._)", "labels": {"50": 17, "100": 16, "250": 151, "500": 71, "1000": 258, "2000": 1020}}, {"id": 7755, "position": 7755, "text": "Ahab goes; Pip steps one step forward._)\n\n“Here he this instant stood; I stand in his air,—but I’m alone. Now\nwere even poor Pip here I could endure it, but he’s missing", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7756, "position": 7756, "text": "poor Pip here I could endure it, but he’s missing. Pip! Pip!\nDing, dong, ding! Who’s seen Pip? He must be up here; let’s try the\ndoor", "labels": {"50": 6, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 967}}, {"id": 7757, "position": 7757, "text": "; let’s try the\ndoor. What? neither lock, nor bolt, nor bar; and yet there’s no opening\nit. It must be the spell; he told me to stay here: Aye, and told me\nthis screwed chair was", "labels": {"50": 25, "100": 5, "250": 45, "500": 313, "1000": 51, "2000": 742}}, {"id": 7758, "position": 7758, "text": "told me to stay here: Aye, and told me\nthis screwed chair was mine. Here, then, I’ll seat me, against the\ntransom, in the ship’s full middle, all her keel and her three masts\nbefore me", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 313, "2000": 1192}}, {"id": 7759, "position": 7759, "text": "’s full middle, all her keel and her three masts\nbefore me. Here, our old sailors say, in their black seventy-fours\ngreat admirals sometimes sit at table, and lord it over rows of\ncaptains and lieutenants", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 7760, "position": 7760, "text": "table, and lord it over rows of\ncaptains and lieutenants. Ha! what’s this? epaulets! epaulets! the\nepaulets all come crowding! Pass round the decanters; glad to see ye;\nfill", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 7761, "position": 7761, "text": "ing! Pass round the decanters; glad to see ye;\nfill up, monsieurs! What an odd feeling, now, when a black boy’s host\nto white men with gold lace upon their coats!—Monsieurs, have ye", "labels": {"50": 16, "100": 64, "250": 138, "500": 498, "1000": 327, "2000": 1620}}, {"id": 7762, "position": 7762, "text": "white men with gold lace upon their coats!—Monsieurs, have ye seen\none Pip?—a little negro lad, five feet high, hang-dog look, and\ncowardly! Jumped from a whale-boat once;—seen him?", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 7763, "position": 7763, "text": "cowardly! Jumped from a whale-boat once;—seen him? No! Well then, fill\nup again, captains, and let’s drink shame upon all cowards! I name no\nnames", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7764, "position": 7764, "text": "s! I name no\nnames. Shame upon them! Put one foot upon the table. Shame upon all\ncowards.—Hist! above there, I hear ivory—Oh, master! master! I am\nindeed down-hearted when you walk", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 647, "2000": 216}}, {"id": 7765, "position": 7765, "text": "Oh, master! master! I am\nindeed down-hearted when you walk over me. But here I’ll stay, though\nthis stern strikes rocks; and they bulge through; and oysters come to\njoin me.”\n\n\nCHAPTER 130. The Hat", "labels": {"50": 31, "100": 64, "250": 219, "500": 73, "1000": 851, "2000": 877}}, {"id": 7766, "position": 7766, "text": "; and oysters come to\njoin me.”\n\n\nCHAPTER 130. The Hat.\n\nAnd now that at the proper time and place, after so long and wide a\npreliminary cruise, Ahab,—all other whaling waters swept—seemed to have\nchased his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7767, "position": 7767, "text": "Ahab,—all other whaling waters swept—seemed to have\nchased his foe into an ocean-fold, to slay him the more securely there;\nnow, that he found himself hard by the very latitude and longitude\nwhere his tormenting wound had", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7768, "position": 7768, "text": "found himself hard by the very latitude and longitude\nwhere his tormenting wound had been inflicted; now that a vessel had\nbeen spoken which on the very day preceding had actually encountered\nMoby Dick;—and now that all his successive meetings with various ships\ncontrasting", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7769, "position": 7769, "text": "y Dick;—and now that all his successive meetings with various ships\ncontrastingly concurred to show the demoniac indifference with which\nthe white whale tore his hunters, whether sinning or sinned against;\nnow it was that there lurked a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7770, "position": 7770, "text": "sinning or sinned against;\nnow it was that there lurked a something in the old man’s eyes, which\nit was hardly sufferable for feeble souls to see. As the unsetting\npolar star, which through the livelong", "labels": {"50": 22, "100": 44, "250": 140, "500": 160, "1000": 543, "2000": 344}}, {"id": 7771, "position": 7771, "text": "see. As the unsetting\npolar star, which through the livelong, arctic, six months’ night\nsustains its piercing, steady, central gaze; so Ahab’s purpose now\nfixedly gleamed down upon the constant midnight of the gloom", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7772, "position": 7772, "text": "’s purpose now\nfixedly gleamed down upon the constant midnight of the gloomy crew. It\ndomineered above them so, that all their bodings, doubts, misgivings,\nfears, were fain to hide beneath their souls,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7773, "position": 7773, "text": "misgivings,\nfears, were fain to hide beneath their souls, and not sprout forth a\nsingle spear or leaf.\n\nIn this foreshadowing interval too, all humor, forced or natural,\nvanished", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 193}}, {"id": 7774, "position": 7774, "text": ", all humor, forced or natural,\nvanished. Stubb no more strove to raise a smile; Starbuck no more\nstrove to check one. Alike, joy and sorrow, hope and fear, seemed\nground to finest dust, and powdered", "labels": {"50": 9, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 1003}}, {"id": 7775, "position": 7775, "text": "sorrow, hope and fear, seemed\nground to finest dust, and powdered, for the time, in the clamped\nmortar of Ahab’s iron soul. Like machines, they dumbly moved about the\ndeck, ever conscious that the old man’", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 7776, "position": 7776, "text": "they dumbly moved about the\ndeck, ever conscious that the old man’s despot eye was on them.\n\nBut did you deeply scan him in his more secret confidential hours; when\nhe thought no glance but one was on him; then you would", "labels": {"50": 22, "100": 19, "250": 70, "500": 481, "1000": 300, "2000": 1014}}, {"id": 7777, "position": 7777, "text": "; when\nhe thought no glance but one was on him; then you would have seen that\neven as Ahab’s eyes so awed the crew’s, the inscrutable Parsee’s glance\nawed his; or somehow, at", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7778, "position": 7778, "text": "crutable Parsee’s glance\nawed his; or somehow, at least, in some wild way, at times affected it.\nSuch an added, gliding strangeness began to invest the thin Fedallah\nnow; such ceaseless shudderings shook", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7779, "position": 7779, "text": "to invest the thin Fedallah\nnow; such ceaseless shudderings shook him; that the men looked dubious\nat him; half uncertain, as it seemed, whether indeed he were a mortal\nsubstance, or else a tremulous shadow cast upon the", "labels": {"50": 22, "100": 78, "250": 205, "500": 142, "1000": 131, "2000": 397}}, {"id": 7780, "position": 7780, "text": "were a mortal\nsubstance, or else a tremulous shadow cast upon the deck by some unseen\nbeing’s body. And that shadow was always hovering there. For not by\nnight, even, had Fedallah ever certainly been known to slumber", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7781, "position": 7781, "text": "night, even, had Fedallah ever certainly been known to slumber, or go\nbelow. He would stand still for hours: but never sat or leaned; his wan\nbut wondrous eyes did plainly say—We two watchmen never rest", "labels": {"50": 22, "100": 64, "250": 138, "500": 432, "1000": 531, "2000": 967}}, {"id": 7782, "position": 7782, "text": "but wondrous eyes did plainly say—We two watchmen never rest.\n\nNor, at any time, by night or day could the mariners now step upon the\ndeck, unless Ahab was before them; either standing in his pivot-hole", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7783, "position": 7783, "text": "unless Ahab was before them; either standing in his pivot-hole,\nor exactly pacing the planks between two undeviating limits,—the\nmain-mast and the mizen; or else they saw him standing in the\ncabin-sc", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7784, "position": 7784, "text": "the mizen; or else they saw him standing in the\ncabin-scuttle,—his living foot advanced upon the deck, as if to step;\nhis hat slouched heavily over his eyes; so that however motionless he\nstood, however", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7785, "position": 7785, "text": "ouched heavily over his eyes; so that however motionless he\nstood, however the days and nights were added on, that he had not swung\nin his hammock; yet hidden beneath that slouching hat, they could never\ntell unerringly", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 531, "2000": 1904}}, {"id": 7786, "position": 7786, "text": "hidden beneath that slouching hat, they could never\ntell unerringly whether, for all this, his eyes were really closed at\ntimes; or whether he was still intently scanning them; no matter,\nthough he stood so in the scuttle", "labels": {"50": 41, "100": 21, "250": 219, "500": 180, "1000": 54, "2000": 1620}}, {"id": 7787, "position": 7787, "text": "scanning them; no matter,\nthough he stood so in the scuttle for a whole hour on the stretch, and\nthe unheeded night-damp gathered in beads of dew upon that stone-carved\ncoat and hat", "labels": {"50": 16, "100": 64, "250": 138, "500": 406, "1000": 779, "2000": 16}}, {"id": 7788, "position": 7788, "text": "dew upon that stone-carved\ncoat and hat. The clothes that the night had wet, the next day’s\nsunshine dried upon him; and so, day after day, and night after night;\nhe went no more beneath the planks; whatever", "labels": {"50": 16, "100": 73, "250": 15, "500": 406, "1000": 174, "2000": 1003}}, {"id": 7789, "position": 7789, "text": "and night after night;\nhe went no more beneath the planks; whatever he wanted from the cabin\nthat thing he sent for.\n\nHe ate in the same open air; that is, his two only meals,—breakfast and\ndinner: supper he never", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 1790}}, {"id": 7790, "position": 7790, "text": "is, his two only meals,—breakfast and\ndinner: supper he never touched; nor reaped his beard; which darkly\ngrew all gnarled, as unearthed roots of trees blown over, which still\ngrow idly on at naked base,", "labels": {"50": 31, "100": 7, "250": 193, "500": 498, "1000": 849, "2000": 39}}, {"id": 7791, "position": 7791, "text": "of trees blown over, which still\ngrow idly on at naked base, though perished in the upper verdure. But\nthough his whole life was now become one watch on deck; and though the\nParsee’s mystic watch was without intermission", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 1904}}, {"id": 7792, "position": 7792, "text": "deck; and though the\nParsee’s mystic watch was without intermission as his own; yet these\ntwo never seemed to speak—one man to the other—unless at long intervals\nsome passing unmomentous matter made it necessary", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 7793, "position": 7793, "text": "long intervals\nsome passing unmomentous matter made it necessary. Though such a potent\nspell seemed secretly to join the twain; openly, and to the awe-struck\ncrew, they seemed pole-like asunder", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7794, "position": 7794, "text": "they seemed pole-like asunder. If by day they chanced to speak\none word; by night, dumb men were both, so far as concerned the\nslightest verbal interchange. At times, for longest hours, without a\nsingle hail, they stood", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1790}}, {"id": 7795, "position": 7795, "text": ". At times, for longest hours, without a\nsingle hail, they stood far parted in the starlight; Ahab in his\nscuttle, the Parsee by the mainmast; but still fixedly gazing upon each\nother; as if", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7796, "position": 7796, "text": "mainmast; but still fixedly gazing upon each\nother; as if in the Parsee Ahab saw his forethrown shadow, in Ahab the\nParsee his abandoned substance.\n\nAnd yet, somehow, did Ahab—in his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7797, "position": 7797, "text": "his abandoned substance.\n\nAnd yet, somehow, did Ahab—in his own proper self, as daily, hourly,\nand every instant, commandingly revealed to his subordinates,—Ahab\nseemed an independent lord; the Parsee but his slave", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7798, "position": 7798, "text": ",—Ahab\nseemed an independent lord; the Parsee but his slave. Still again both\nseemed yoked together, and an unseen tyrant driving them; the lean\nshade siding the solid rib. For be this Parsee what he may, all rib", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7799, "position": 7799, "text": "the solid rib. For be this Parsee what he may, all rib and\nkeel was solid Ahab.\n\nAt the first faintest glimmering of the dawn, his iron voice was heard\nfrom aft,—“Man the mast-heads!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7800, "position": 7800, "text": "iron voice was heard\nfrom aft,—“Man the mast-heads!”—and all through the day, till after\nsunset and after twilight, the same voice every hour, at the striking\nof the helmsman’s bell, was heard—", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7801, "position": 7801, "text": ", at the striking\nof the helmsman’s bell, was heard—“What d’ye see?—sharp! sharp!”\n\nBut when three or four days had slided by, after meeting the\nchildren-seeking Rachel; and no sp", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 7802, "position": 7802, "text": "slided by, after meeting the\nchildren-seeking Rachel; and no spout had yet been seen; the monomaniac\nold man seemed distrustful of his crew’s fidelity; at least, of nearly\nall except the Pagan harpooneers;", "labels": {"50": 37, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1668}}, {"id": 7803, "position": 7803, "text": "fidelity; at least, of nearly\nall except the Pagan harpooneers; he seemed to doubt, even, whether\nStubb and Flask might not willingly overlook the sight he sought. But\nif these suspicions were really his, he sagaciously refrain", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7804, "position": 7804, "text": "sought. But\nif these suspicions were really his, he sagaciously refrained from\nverbally expressing them, however his actions might seem to hint them.\n\n“I will have the first sight of the whale myself,”—he said", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 7805, "position": 7805, "text": "the first sight of the whale myself,”—he said. “Aye! Ahab\nmust have the doubloon!” and with his own hands he rigged a nest of\nbasketed bowlines; and sending a hand aloft, with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7806, "position": 7806, "text": "nest of\nbasketed bowlines; and sending a hand aloft, with a single sheaved\nblock, to secure to the main-mast head, he received the two ends of the\ndownward-reeved rope; and attaching one to his basket", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7807, "position": 7807, "text": "of the\ndownward-reeved rope; and attaching one to his basket prepared a pin\nfor the other end, in order to fasten it at the rail. This done, with\nthat end yet in his hand and standing beside the pin, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7808, "position": 7808, "text": ", with\nthat end yet in his hand and standing beside the pin, he looked round\nupon his crew, sweeping from one to the other; pausing his glance long\nupon Daggoo, Queequeg, Tashtego; but shunni", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7809, "position": 7809, "text": "oo, Queequeg, Tashtego; but shunning Fedallah; and then\nsettling his firm relying eye upon the chief mate, said,—“Take the\nrope, sir—I give it into thy hands, Star", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7810, "position": 7810, "text": "“Take the\nrope, sir—I give it into thy hands, Starbuck.” Then arranging his\nperson in the basket, he gave the word for them to hoist him to his\nperch, Starbuck being the one who secured the rope at", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7811, "position": 7811, "text": "him to his\nperch, Starbuck being the one who secured the rope at last; and\nafterwards stood near it. And thus, with one hand clinging round the\nroyal mast, Ahab gazed abroad upon the sea for miles and miles,—ahead,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7812, "position": 7812, "text": "Ahab gazed abroad upon the sea for miles and miles,—ahead,\nastern, this side, and that,—within the wide expanded circle commanded\nat so great a height.\n\nWhen in working with his hands at some lofty almost isolated place", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7813, "position": 7813, "text": "height.\n\nWhen in working with his hands at some lofty almost isolated place in\nthe rigging, which chances to afford no foothold, the sailor at sea is\nhoisted up to that spot, and sustained there by the rope; under these\ncircumstances,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7814, "position": 7814, "text": "to that spot, and sustained there by the rope; under these\ncircumstances, its fastened end on deck is always given in strict\ncharge to some one man who has the special watch of it. Because in such\na wilderness of running rigging, whose various", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7815, "position": 7815, "text": "of it. Because in such\na wilderness of running rigging, whose various different relations\naloft cannot always be infallibly discerned by what is seen of them at\nthe deck; and when the deck-ends of these ropes are being every", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7816, "position": 7816, "text": "the deck; and when the deck-ends of these ropes are being every few\nminutes cast down from the fastenings, it would be but a natural\nfatality, if, unprovided with a constant watchman, the hoisted sailor\nshould", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7817, "position": 7817, "text": ", unprovided with a constant watchman, the hoisted sailor\nshould by some carelessness of the crew be cast adrift and fall all\nswooping to the sea. So Ahab’s proceedings in this matter were not\nunusual; the only", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7818, "position": 7818, "text": "So Ahab’s proceedings in this matter were not\nunusual; the only strange thing about them seemed to be, that Starbuck,\nalmost the one only man who had ever ventured to oppose him with\nanything in the slightest degree approaching to decision—one", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7819, "position": 7819, "text": "ventured to oppose him with\nanything in the slightest degree approaching to decision—one of those\ntoo, whose faithfulness on the look-out he had seemed to doubt\nsomewhat;—it was strange, that this was the very man he should select\nfor his", "labels": {"50": 33, "100": 17, "250": 160, "500": 43, "1000": 737, "2000": 819}}, {"id": 7820, "position": 7820, "text": "it was strange, that this was the very man he should select\nfor his watchman; freely giving his whole life into such an otherwise\ndistrusted person’s hands.\n\nNow, the first time Ahab was perched aloft; ere he had", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7821, "position": 7821, "text": ", the first time Ahab was perched aloft; ere he had been there ten\nminutes; one of those red-billed savage sea-hawks which so often fly\nincommodiously close round the manned mast-heads of whalemen in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7822, "position": 7822, "text": "ommodiously close round the manned mast-heads of whalemen in these\nlatitudes; one of these birds came wheeling and screaming round his\nhead in a maze of untrackably swift circlings", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7823, "position": 7823, "text": "trackably swift circlings. Then it darted a\nthousand feet straight up into the air; then spiralized downwards, and\nwent eddying again round his head.\n\nBut with his gaze fixed upon the dim and distant horizon, Ahab seemed\nnot to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7824, "position": 7824, "text": "his gaze fixed upon the dim and distant horizon, Ahab seemed\nnot to mark this wild bird; nor, indeed, would any one else have marked\nit much, it being no uncommon circumstance; only now almost the least\nheedful eye seemed to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7825, "position": 7825, "text": "no uncommon circumstance; only now almost the least\nheedful eye seemed to see some sort of cunning meaning in almost every\nsight.\n\n“Your hat, your hat, sir!” suddenly cried the Sicilian seaman, who\nbeing posted at the mizen-", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 7826, "position": 7826, "text": "” suddenly cried the Sicilian seaman, who\nbeing posted at the mizen-mast-head, stood directly behind Ahab, though\nsomewhat lower than his level, and with a deep gulf of air dividing\nthem.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7827, "position": 7827, "text": "deep gulf of air dividing\nthem.\n\nBut already the sable wing was before the old man’s eyes; the long\nhooked bill at his head: with a scream, the black hawk darted away with\nhis prize.", "labels": {"50": 37, "100": 55, "250": 145, "500": 142, "1000": 131, "2000": 1145}}, {"id": 7828, "position": 7828, "text": "hawk darted away with\nhis prize.\n\nAn eagle flew thrice round Tarquin’s head, removing his cap to replace\nit, and thereupon Tanaquil, his wife, declared that Tarquin would be\nking of Rome", "labels": {"50": 26, "100": 67, "250": 235, "500": 413, "1000": 469, "2000": 1330}}, {"id": 7829, "position": 7829, "text": "wife, declared that Tarquin would be\nking of Rome. But only by the replacing of the cap was that omen\naccounted good. Ahab’s hat was never restored; the wild hawk flew on\nand on with it; far in advance of", "labels": {"50": 26, "100": 66, "250": 211, "500": 490, "1000": 630, "2000": 1922}}, {"id": 7830, "position": 7830, "text": "; the wild hawk flew on\nand on with it; far in advance of the prow: and at last disappeared;\nwhile from the point of that disappearance, a minute black spot was\ndimly discerned, falling from that vast height into the sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 472}}, {"id": 7831, "position": 7831, "text": "spot was\ndimly discerned, falling from that vast height into the sea.\n\n\nCHAPTER 131. The Pequod Meets The Delight.\n\nThe intense Pequod sailed on; the rolling waves and days went by; the\nlife-buoy-coffin", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7832, "position": 7832, "text": "the rolling waves and days went by; the\nlife-buoy-coffin still lightly swung; and another ship, most miserably\nmisnamed the Delight, was descried. As she drew nigh, all eyes were\nfixed upon her", "labels": {"50": 16, "100": 73, "250": 140, "500": 406, "1000": 779, "2000": 471}}, {"id": 7833, "position": 7833, "text": "cried. As she drew nigh, all eyes were\nfixed upon her broad beams, called shears, which, in some\nwhaling-ships, cross the quarter-deck at the height of eight or nine\nfeet; serving to carry the spare,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7834, "position": 7834, "text": "at the height of eight or nine\nfeet; serving to carry the spare, unrigged, or disabled boats.\n\nUpon the stranger’s shears were beheld the shattered, white ribs, and\nsome few splintered planks, of what had", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 327, "2000": 1735}}, {"id": 7835, "position": 7835, "text": ", white ribs, and\nsome few splintered planks, of what had once been a whale-boat; but you\nnow saw through this wreck, as plainly as you see through the peeled,\nhalf-unhinged, and bleaching skeleton", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7836, "position": 7836, "text": "through the peeled,\nhalf-unhinged, and bleaching skeleton of a horse.\n\n“Hast seen the White Whale?”\n\n“Look!” replied the hollow-cheeked captain from his taffrail; and with\nhis trumpet he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7837, "position": 7837, "text": "-cheeked captain from his taffrail; and with\nhis trumpet he pointed to the wreck.\n\n“Hast killed him?”\n\n“The harpoon is not yet forged that ever will do that,” answered the\nother, sadly glancing upon a", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7838, "position": 7838, "text": "that ever will do that,” answered the\nother, sadly glancing upon a rounded hammock on the deck, whose\ngathered sides some noiseless sailors were busy in sewing together.\n\n“Not forged!” and snatching Perth’s levelled iron", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7839, "position": 7839, "text": ".\n\n“Not forged!” and snatching Perth’s levelled iron from the crotch, Ahab\nheld it out, exclaiming—“Look ye, Nantucketer; here in this hand I hold\nhis death! Tempered in blood, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7840, "position": 7840, "text": "; here in this hand I hold\nhis death! Tempered in blood, and tempered by lightning are these\nbarbs; and I swear to temper them triply in that hot place behind the\nfin, where the White Whale most feels his accursed life", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7841, "position": 7841, "text": "behind the\nfin, where the White Whale most feels his accursed life!”\n\n“Then God keep thee, old man—see’st thou that”—pointing to the\nhammock—“I bury but one of five stout men,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7842, "position": 7842, "text": "the\nhammock—“I bury but one of five stout men, who were alive only\nyesterday; but were dead ere night. Only _that_ one I bury; the rest\nwere buried before they died; you sail upon their tomb.", "labels": {"50": 45, "100": 64, "250": 163, "500": 388, "1000": 851, "2000": 786}}, {"id": 7843, "position": 7843, "text": "; the rest\nwere buried before they died; you sail upon their tomb.” Then turning\nto his crew—“Are ye ready there? place the plank then on the rail, and\nlift the body; so, then—Oh! God”—", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 16}}, {"id": 7844, "position": 7844, "text": ", and\nlift the body; so, then—Oh! God”—advancing towards the hammock with\nuplifted hands—“may the resurrection and the life——”\n\n“Brace forward! Up helm!” cried Ahab like lightning", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7845, "position": 7845, "text": "—”\n\n“Brace forward! Up helm!” cried Ahab like lightning to his men.\n\nBut the suddenly started Pequod was not quick enough to escape the\nsound of the splash that the corpse soon made as it struck the sea; not\nso", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7846, "position": 7846, "text": "the splash that the corpse soon made as it struck the sea; not\nso quick, indeed, but that some of the flying bubbles might have\nsprinkled her hull with their ghostly baptism.\n\nAs Ahab now glided from the dejected Delight, the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7847, "position": 7847, "text": "ghostly baptism.\n\nAs Ahab now glided from the dejected Delight, the strange life-buoy\nhanging at the Pequod’s stern came into conspicuous relief.\n\n“Ha! yonder! look yonder, men!” cried a fore", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7848, "position": 7848, "text": "Ha! yonder! look yonder, men!” cried a foreboding voice in her wake.\n“In vain, oh, ye strangers, ye fly our sad burial; ye but turn us your\ntaffrail to show us your coffin", "labels": {"50": 9, "100": 26, "250": 133, "500": 180, "1000": 295, "2000": 1885}}, {"id": 7849, "position": 7849, "text": "burial; ye but turn us your\ntaffrail to show us your coffin!”\n\n\nCHAPTER 132. The Symphony.\n\nIt was a clear steel-blue day. The firmaments of air and sea were\nhardly separable in that all-perva", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 7850, "position": 7850, "text": "s of air and sea were\nhardly separable in that all-pervading azure; only, the pensive air was\ntransparently pure and soft, with a woman’s look, and the robust and\nman-like sea heaved with long,", "labels": {"50": 16, "100": 44, "250": 26, "500": 401, "1000": 252, "2000": 849}}, {"id": 7851, "position": 7851, "text": "s look, and the robust and\nman-like sea heaved with long, strong, lingering swells, as Samson’s\nchest in his sleep.\n\nHither, and thither, on high, glided the snow-white wings of small,", "labels": {"50": 22, "100": 78, "250": 229, "500": 481, "1000": 631, "2000": 1140}}, {"id": 7852, "position": 7852, "text": "ither, on high, glided the snow-white wings of small,\nunspeckled birds; these were the gentle thoughts of the feminine air;\nbut to and fro in the deeps, far down in the bottomless blue, rushed", "labels": {"50": 16, "100": 73, "250": 15, "500": 406, "1000": 779, "2000": 471}}, {"id": 7853, "position": 7853, "text": "o in the deeps, far down in the bottomless blue, rushed\nmighty leviathans, sword-fish, and sharks; and these were the strong,\ntroubled, murderous thinkings of the masculine sea.", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 663, "2000": 16}}, {"id": 7854, "position": 7854, "text": "murderous thinkings of the masculine sea.\n\nBut though thus contrasting within, the contrast was only in shades and\nshadows without; those two seemed one; it was only the sex, as it were,\nthat distinguished them.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 7855, "position": 7855, "text": "as it were,\nthat distinguished them.\n\nAloft, like a royal czar and king, the sun seemed giving this gentle\nair to this bold and rolling sea; even as bride to groom. And at the\ngirdling line of the horizon,", "labels": {"50": 7, "100": 44, "250": 189, "500": 297, "1000": 708, "2000": 426}}, {"id": 7856, "position": 7856, "text": "bride to groom. And at the\ngirdling line of the horizon, a soft and tremulous motion—most seen\nhere at the equator—denoted the fond, throbbing trust, the loving\nalarms, with which the poor bride gave her bosom", "labels": {"50": 0, "100": 4, "250": 114, "500": 341, "1000": 649, "2000": 218}}, {"id": 7857, "position": 7857, "text": "trust, the loving\nalarms, with which the poor bride gave her bosom away.\n\nTied up and twisted; gnarled and knotted with wrinkles; haggardly firm\nand unyielding; his eyes glowing like coals, that still glow", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 573}}, {"id": 7858, "position": 7858, "text": "unyielding; his eyes glowing like coals, that still glow in the\nashes of ruin; untottering Ahab stood forth in the clearness of the\nmorn; lifting his splintered helmet of a brow to the fair girl’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7859, "position": 7859, "text": "; lifting his splintered helmet of a brow to the fair girl’s\nforehead of heaven.\n\nOh, immortal infancy, and innocency of the azure! Invisible winged\ncreatures that frolic all round us! Sweet childhood of air and sky! how", "labels": {"50": 16, "100": 73, "250": 133, "500": 401, "1000": 136, "2000": 193}}, {"id": 7860, "position": 7860, "text": "that frolic all round us! Sweet childhood of air and sky! how\noblivious were ye of old Ahab’s close-coiled woe! But so have I seen\nlittle Miriam and Martha, laughing-eyed elves, heedlessly ga", "labels": {"50": 16, "100": 64, "250": 138, "500": 498, "1000": 327, "2000": 1620}}, {"id": 7861, "position": 7861, "text": "little Miriam and Martha, laughing-eyed elves, heedlessly gambol around\ntheir old sire; sporting with the circle of singed locks which grew on\nthe marge of that burnt-out crater of his brain.", "labels": {"50": 28, "100": 12, "250": 53, "500": 316, "1000": 839, "2000": 32}}, {"id": 7862, "position": 7862, "text": "of that burnt-out crater of his brain.\n\nSlowly crossing the deck from the scuttle, Ahab leaned over the side\nand watched how his shadow in the water sank and sank to his gaze, the\nmore and the more that he strove", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 7863, "position": 7863, "text": "and sank to his gaze, the\nmore and the more that he strove to pierce the profundity. But the\nlovely aromas in that enchanted air did at last seem to dispel, for a\nmoment, the cankerous thing in", "labels": {"50": 22, "100": 78, "250": 205, "500": 469, "1000": 631, "2000": 1976}}, {"id": 7864, "position": 7864, "text": "to dispel, for a\nmoment, the cankerous thing in his soul. That glad, happy air, that\nwinsome sky, did at last stroke and caress him; the step-mother world,\nso long cruel—forbidding—", "labels": {"50": 9, "100": 78, "250": 133, "500": 143, "1000": 437, "2000": 958}}, {"id": 7865, "position": 7865, "text": "him; the step-mother world,\nso long cruel—forbidding—now threw affectionate arms round his stubborn\nneck, and did seem to joyously sob over him, as if over one, that\nhowever wilful and erring, she could", "labels": {"50": 19, "100": 10, "250": 226, "500": 308, "1000": 123, "2000": 61}}, {"id": 7866, "position": 7866, "text": "as if over one, that\nhowever wilful and erring, she could yet find it in her heart to save\nand to bless. From beneath his slouched hat Ahab dropped a tear into\nthe sea; nor did all the Pacific contain such", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 1620}}, {"id": 7867, "position": 7867, "text": "ab dropped a tear into\nthe sea; nor did all the Pacific contain such wealth as that one wee\ndrop.\n\nStarbuck saw the old man; saw him, how he heavily leaned over the side;\nand he seemed to hear in his own true heart", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7868, "position": 7868, "text": "leaned over the side;\nand he seemed to hear in his own true heart the measureless sobbing\nthat stole out of the centre of the serenity around. Careful not to\ntouch him, or be noticed by him, he yet drew near to him,", "labels": {"50": 22, "100": 78, "250": 229, "500": 469, "1000": 631, "2000": 1976}}, {"id": 7869, "position": 7869, "text": "him, or be noticed by him, he yet drew near to him, and stood\nthere.\n\nAhab turned.\n\n“Starbuck!”\n\n“Sir.”\n\n“Oh, Starbuck! it is a mild, mild wind, and a mild looking", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7870, "position": 7870, "text": "Starbuck! it is a mild, mild wind, and a mild looking sky. On such\na day—very much such a sweetness as this—I struck my first whale—a\nboy-harpooneer of eighteen! Forty—forty—forty", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7871, "position": 7871, "text": "—a\nboy-harpooneer of eighteen! Forty—forty—forty years ago!—ago! Forty\nyears of continual whaling! forty years of privation, and peril, and\nstorm-time! forty years on the pitiless sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7872, "position": 7872, "text": "il, and\nstorm-time! forty years on the pitiless sea! for forty years has Ahab\nforsaken the peaceful land, for forty years to make war on the horrors\nof the deep! Aye and yes, Starbuck, out", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 327, "2000": 16}}, {"id": 7873, "position": 7873, "text": "on the horrors\nof the deep! Aye and yes, Starbuck, out of those forty years I have not\nspent three ashore. When I think of this life I have led; the\ndesolation of solitude it has been; the masoned,", "labels": {"50": 31, "100": 64, "250": 138, "500": 126, "1000": 727, "2000": 887}}, {"id": 7874, "position": 7874, "text": "; the\ndesolation of solitude it has been; the masoned, walled-town of a\nCaptain’s exclusiveness, which admits but small entrance to any\nsympathy from the green country without—oh, weariness! heaviness!\nGuinea", "labels": {"50": 45, "100": 29, "250": 82, "500": 79, "1000": 354, "2000": 1584}}, {"id": 7875, "position": 7875, "text": "the green country without—oh, weariness! heaviness!\nGuinea-coast slavery of solitary command!—when I think of all this;\nonly half-suspected, not so keenly known to me before—and how for forty\nyears I", "labels": {"50": 25, "100": 28, "250": 193, "500": 412, "1000": 159, "2000": 381}}, {"id": 7876, "position": 7876, "text": "not so keenly known to me before—and how for forty\nyears I have fed upon dry salted fare—fit emblem of the dry nourishment\nof my soil!—when the poorest landsman has had fresh fruit to his daily", "labels": {"50": 48, "100": 27, "250": 157, "500": 223, "1000": 79, "2000": 1731}}, {"id": 7877, "position": 7877, "text": "!—when the poorest landsman has had fresh fruit to his daily\nhand, and broken the world’s fresh bread to my mouldy crusts—away,\nwhole oceans away, from that young girl-wife I wedded past fifty", "labels": {"50": 20, "100": 5, "250": 45, "500": 57, "1000": 711, "2000": 1167}}, {"id": 7878, "position": 7878, "text": "whole oceans away, from that young girl-wife I wedded past fifty, and\nsailed for Cape Horn the next day, leaving but one dent in my marriage\npillow—wife? wife?—rather a widow with her husband alive! Aye, I", "labels": {"50": 16, "100": 73, "250": 15, "500": 498, "1000": 50, "2000": 916}}, {"id": 7879, "position": 7879, "text": "? wife?—rather a widow with her husband alive! Aye, I\nwidowed that poor girl when I married her, Starbuck; and then, the\nmadness, the frenzy, the boiling blood and the smoking brow, with\nwhich, for a thousand", "labels": {"50": 6, "100": 1, "250": 42, "500": 225, "1000": 50, "2000": 916}}, {"id": 7880, "position": 7880, "text": ", the boiling blood and the smoking brow, with\nwhich, for a thousand lowerings old Ahab has furiously, foamingly\nchased his prey—more a demon than a man!—aye, aye! what a forty years’\nfool—fool—", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7881, "position": 7881, "text": "!—aye, aye! what a forty years’\nfool—fool—old fool, has old Ahab been! Why this strife of the chase?\nwhy weary, and palsy the arm at the oar, and the iron, and the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7882, "position": 7882, "text": "palsy the arm at the oar, and the iron, and the lance?\nhow the richer or better is Ahab now? Behold. Oh, Starbuck! is it not\nhard, that with this weary load I bear, one poor leg", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7883, "position": 7883, "text": "it not\nhard, that with this weary load I bear, one poor leg should have been\nsnatched from under me? Here, brush this old hair aside; it blinds me,\nthat I seem to weep. Locks so grey did never grow but from out", "labels": {"50": 16, "100": 73, "250": 133, "500": 406, "1000": 779, "2000": 596}}, {"id": 7884, "position": 7884, "text": "that I seem to weep. Locks so grey did never grow but from out some\nashes! But do I look very old, so very, very old, Starbuck? I feel\ndeadly faint, bowed, and humped, as though I were Adam", "labels": {"50": 20, "100": 79, "250": 132, "500": 280, "1000": 813, "2000": 1273}}, {"id": 7885, "position": 7885, "text": "feel\ndeadly faint, bowed, and humped, as though I were Adam, staggering\nbeneath the piled centuries since Paradise. God! God! God!—crack my\nheart!—stave my brain!—mockery! mockery! bitter,", "labels": {"50": 9, "100": 73, "250": 193, "500": 498, "1000": 437, "2000": 421}}, {"id": 7886, "position": 7886, "text": "—stave my brain!—mockery! mockery! bitter, biting mockery of grey\nhairs, have I lived enough joy to wear ye; and seem and feel thus\nintolerably old? Close! stand close to me, Starbuck", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 16}}, {"id": 7887, "position": 7887, "text": "thus\nintolerably old? Close! stand close to me, Starbuck; let me look into a\nhuman eye; it is better than to gaze into sea or sky; better than to\ngaze upon God", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7888, "position": 7888, "text": "better than to\ngaze upon God. By the green land; by the bright hearth-stone! this is\nthe magic glass, man; I see my wife and my child in thine eye. No, no;\nstay on board, on board!", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 174, "2000": 709}}, {"id": 7889, "position": 7889, "text": "thine eye. No, no;\nstay on board, on board!—lower not when I do; when branded Ahab gives\nchase to Moby Dick. That hazard shall not be thine. No, no! not with\nthe far away", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7890, "position": 7890, "text": "shall not be thine. No, no! not with\nthe far away home I see in that eye!”\n\n“Oh, my Captain! my Captain! noble soul! grand old heart, after all!\nwhy should any one give chase to that", "labels": {"50": 16, "100": 45, "250": 245, "500": 225, "1000": 50, "2000": 946}}, {"id": 7891, "position": 7891, "text": "grand old heart, after all!\nwhy should any one give chase to that hated fish! Away with me! let us\nfly these deadly waters! let us home! Wife and child, too, are\nStarbuck’s—wife and child of his", "labels": {"50": 16, "100": 73, "250": 133, "500": 72, "1000": 779, "2000": 1620}}, {"id": 7892, "position": 7892, "text": "child, too, are\nStarbuck’s—wife and child of his brotherly, sisterly, play-fellow\nyouth; even as thine, sir, are the wife and child of thy loving,\nlonging, paternal old age! Away!", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 193}}, {"id": 7893, "position": 7893, "text": "wife and child of thy loving,\nlonging, paternal old age! Away! let us away!—this instant let me alter\nthe course! How cheerily, how hilariously, O my Captain, would we bowl\non our way to see old Nan", "labels": {"50": 16, "100": 73, "250": 120, "500": 498, "1000": 50, "2000": 16}}, {"id": 7894, "position": 7894, "text": ", O my Captain, would we bowl\non our way to see old Nantucket again! I think, sir, they have some\nsuch mild blue days, even as this, in Nantucket.”\n\n“They have, they have", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7895, "position": 7895, "text": "in Nantucket.”\n\n“They have, they have. I have seen them—some summer days in the\nmorning. About this time—yes, it is his noon nap now—the boy\nvivaciously wakes; sits up in bed; and", "labels": {"50": 45, "100": 20, "250": 138, "500": 162, "1000": 9, "2000": 682}}, {"id": 7896, "position": 7896, "text": "now—the boy\nvivaciously wakes; sits up in bed; and his mother tells him of me, of\ncannibal old me; how I am abroad upon the deep, but will yet come back\nto dance him again.”", "labels": {"50": 17, "100": 16, "250": 87, "500": 182, "1000": 355, "2000": 1601}}, {"id": 7897, "position": 7897, "text": "deep, but will yet come back\nto dance him again.”\n\n“’Tis my Mary, my Mary herself! She promised that my boy, every\nmorning, should be carried to the hill to catch the first glimpse of\nhis father’s sail!", "labels": {"50": 28, "100": 58, "250": 140, "500": 383, "1000": 549, "2000": 350}}, {"id": 7898, "position": 7898, "text": "to the hill to catch the first glimpse of\nhis father’s sail! Yes, yes! no more! it is done! we head for\nNantucket! Come, my Captain, study out the course, and let us away!\nSee, see", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7899, "position": 7899, "text": "Captain, study out the course, and let us away!\nSee, see! the boy’s face from the window! the boy’s hand on the hill!”\n\nBut Ahab’s glance was averted; like a blighted", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7900, "position": 7900, "text": "But Ahab’s glance was averted; like a blighted fruit tree he shook, and\ncast his last, cindered apple to the soil.\n\n“What is it, what nameless, inscrutable, unearthly thing is", "labels": {"50": 9, "100": 26, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7901, "position": 7901, "text": "it, what nameless, inscrutable, unearthly thing is it; what\ncozening, hidden lord and master, and cruel, remorseless emperor\ncommands me; that against all natural lovings and longings, I so keep\npushing", "labels": {"50": 9, "100": 15, "250": 180, "500": 18, "1000": 709, "2000": 1237}}, {"id": 7902, "position": 7902, "text": "; that against all natural lovings and longings, I so keep\npushing, and crowding, and jamming myself on all the time; recklessly\nmaking me ready to do what in my own proper, natural heart, I durst not\nso", "labels": {"50": 31, "100": 75, "250": 132, "500": 126, "1000": 27, "2000": 1204}}, {"id": 7903, "position": 7903, "text": "do what in my own proper, natural heart, I durst not\nso much as dare? Is Ahab, Ahab? Is it I, God, or who, that lifts this\narm? But if the great sun move not of himself;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7904, "position": 7904, "text": "that lifts this\narm? But if the great sun move not of himself; but is as an errand-boy\nin heaven; nor one single star can revolve, but by some invisible\npower; how then can this one small heart beat;", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 16}}, {"id": 7905, "position": 7905, "text": "but by some invisible\npower; how then can this one small heart beat; this one small brain\nthink thoughts; unless God does that beating, does that thinking, does\nthat living, and not I. By heaven, man, we are turned round and", "labels": {"50": 16, "100": 73, "250": 15, "500": 406, "1000": 174, "2000": 16}}, {"id": 7906, "position": 7906, "text": ", and not I. By heaven, man, we are turned round and round\nin this world, like yonder windlass, and Fate is the handspike. And all\nthe time, lo! that smiling sky, and this unsound", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 779, "2000": 16}}, {"id": 7907, "position": 7907, "text": "all\nthe time, lo! that smiling sky, and this unsounded sea! Look! see yon\nAlbicore! who put it into him to chase and fang that flying-fish? Where\ndo murderers go, man! Who’", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 16}}, {"id": 7908, "position": 7908, "text": "fang that flying-fish? Where\ndo murderers go, man! Who’s to doom, when the judge himself is dragged\nto the bar? But it is a mild, mild wind, and a mild looking sky; and\nthe air smells now,", "labels": {"50": 16, "100": 73, "250": 15, "500": 232, "1000": 174, "2000": 16}}, {"id": 7909, "position": 7909, "text": "mild wind, and a mild looking sky; and\nthe air smells now, as if it blew from a far-away meadow; they have\nbeen making hay somewhere under the slopes of the Andes, Starbuck, and\nthe mowers are sleeping among", "labels": {"50": 16, "100": 73, "250": 91, "500": 276, "1000": 174, "2000": 16}}, {"id": 7910, "position": 7910, "text": "of the Andes, Starbuck, and\nthe mowers are sleeping among the new-mown hay. Sleeping? Aye, toil we\nhow we may, we all sleep at last on the field", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 198}}, {"id": 7911, "position": 7911, "text": "sleep at last on the field. Sleep? Aye, and rust\namid greenness; as last year’s scythes flung down, and left in the\nhalf-cut swaths—Starbuck!”", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 198}}, {"id": 7912, "position": 7912, "text": "swaths—Starbuck!”\n\nBut blanched to a corpse’s hue with despair, the Mate had stolen away.\n\nAhab crossed the deck to gaze over on the other side; but started at\ntwo reflected, fixed eyes in the water there", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7913, "position": 7913, "text": "other side; but started at\ntwo reflected, fixed eyes in the water there. Fedallah was motionlessly\nleaning over the same rail.\n\n\nCHAPTER 133. The Chase—First Day.\n\nThat night, in the mid-watch, when the old man", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 99, "2000": 1904}}, {"id": 7914, "position": 7914, "text": "Day.\n\nThat night, in the mid-watch, when the old man—as his wont at\nintervals—stepped forth from the scuttle in which he leaned, and went\nto his pivot-hole, he suddenly thrust out his face", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 7915, "position": 7915, "text": "and went\nto his pivot-hole, he suddenly thrust out his face fiercely, snuffing\nup the sea air as a sagacious ship’s dog will, in drawing nigh to some\nbarbarous isle", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7916, "position": 7916, "text": "in drawing nigh to some\nbarbarous isle. He declared that a whale must be near. Soon that\npeculiar odor, sometimes to a great distance given forth by the living\nsperm whale, was palpable to all the watch; nor was any", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 7917, "position": 7917, "text": "sperm whale, was palpable to all the watch; nor was any mariner\nsurprised when, after inspecting the compass, and then the dog-vane,\nand then ascertaining the precise bearing of the odor as nearly as\npossible, Ah", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7918, "position": 7918, "text": "certaining the precise bearing of the odor as nearly as\npossible, Ahab rapidly ordered the ship’s course to be slightly\naltered, and the sail to be shortened.\n\nThe acute policy dictating these movements was sufficiently vindicated\nat daybreak", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 7919, "position": 7919, "text": "The acute policy dictating these movements was sufficiently vindicated\nat daybreak, by the sight of a long sleek on the sea directly and\nlengthwise ahead, smooth as oil, and resembling in the pleated watery\nwrinkles bordering it, the polished", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 576}}, {"id": 7920, "position": 7920, "text": ", and resembling in the pleated watery\nwrinkles bordering it, the polished metallic-like marks of some swift\ntide-rip, at the mouth of a deep, rapid stream.\n\n“Man the mast-heads! Call all hands!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7921, "position": 7921, "text": ".\n\n“Man the mast-heads! Call all hands!”\n\nThundering with the butts of three clubbed handspikes on the forecastle\ndeck, Daggoo roused the sleepers with such judgment claps that they\nseemed to ex", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1620}}, {"id": 7922, "position": 7922, "text": "roused the sleepers with such judgment claps that they\nseemed to exhale from the scuttle, so instantaneously did they appear\nwith their clothes in their hands.\n\n“What d’ye see?” cried Ahab, flatten", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7923, "position": 7923, "text": ".\n\n“What d’ye see?” cried Ahab, flattening his face to the sky.\n\n“Nothing, nothing sir!” was the sound hailing down in reply.\n\n“T’gallant sails!—stunsails!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7924, "position": 7924, "text": "in reply.\n\n“T’gallant sails!—stunsails! alow and aloft, and on both sides!”\n\nAll sail being set, he now cast loose the life-line, reserved for\nswaying him to the main royal-", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 7925, "position": 7925, "text": "loose the life-line, reserved for\nswaying him to the main royal-mast head; and in a few moments they were\nhoisting him thither, when, while but two thirds of the way aloft, and\nwhile peering ahead through", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7926, "position": 7926, "text": "while but two thirds of the way aloft, and\nwhile peering ahead through the horizontal vacancy between the\nmain-top-sail and top-gallant-sail, he raised a gull-like cry in the\nair", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 7927, "position": 7927, "text": "gull-like cry in the\nair. “There she blows!—there she blows! A hump like a snow-hill! It is\nMoby Dick!”\n\nFired by the cry which seemed simultaneously taken up by the three\nlook-outs", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7928, "position": 7928, "text": "Fired by the cry which seemed simultaneously taken up by the three\nlook-outs, the men on deck rushed to the rigging to behold the famous\nwhale they had so long been pursuing. Ahab had now gained his final\nperch, some feet above the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7929, "position": 7929, "text": "pursuing. Ahab had now gained his final\nperch, some feet above the other look-outs, Tashtego standing just\nbeneath him on the cap of the top-gallant-mast, so that the Indian’s\nhead was almost on a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7930, "position": 7930, "text": "gallant-mast, so that the Indian’s\nhead was almost on a level with Ahab’s heel. From this height the whale\nwas now seen some mile or so ahead, at every roll of the sea revealing\nhis high sparkling hump,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7931, "position": 7931, "text": "ahead, at every roll of the sea revealing\nhis high sparkling hump, and regularly jetting his silent spout into\nthe air. To the credulous mariners it seemed the same silent spout they\nhad so long ago beheld in the moon", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7932, "position": 7932, "text": "the same silent spout they\nhad so long ago beheld in the moonlit Atlantic and Indian Oceans.\n\n“And did none of ye see it before?” cried Ahab, hailing the perched men\nall around him.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7933, "position": 7933, "text": ", hailing the perched men\nall around him.\n\n“I saw him almost that same instant, sir, that Captain Ahab did, and I\ncried out,” said Tashtego.\n\n“Not the same instant; not the same—no", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7934, "position": 7934, "text": "shtego.\n\n“Not the same instant; not the same—no, the doubloon is mine, Fate\nreserved the doubloon for me. _I_ only; none of ye could have raised\nthe White Whale first", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7935, "position": 7935, "text": "I_ only; none of ye could have raised\nthe White Whale first. There she blows!—there she blows!—there she\nblows! There again!—there again!” he cried, in long-drawn, lingering,\nmethodic tones", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7936, "position": 7936, "text": "!” he cried, in long-drawn, lingering,\nmethodic tones, attuned to the gradual prolongings of the whale’s\nvisible jets. “He’s going to sound! In stunsails! Down\ntop-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7937, "position": 7937, "text": "’s going to sound! In stunsails! Down\ntop-gallant-sails! Stand by three boats. Mr. Starbuck, remember, stay\non board, and keep the ship. Helm there! Luff, luff a point", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7938, "position": 7938, "text": "and keep the ship. Helm there! Luff, luff a point! So;\nsteady, man, steady! There go flukes! No, no; only black water! All\nready the boats there? Stand by, stand by! Lower", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 7939, "position": 7939, "text": "water! All\nready the boats there? Stand by, stand by! Lower me, Mr. Starbuck;\nlower, lower,—quick, quicker!” and he slid through the air to the deck.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7940, "position": 7940, "text": "through the air to the deck.\n\n“He is heading straight to leeward, sir,” cried Stubb, “right away from\nus; cannot have seen the ship yet.”\n\n“Be dumb, man! Stand by the braces! Hard", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 7941, "position": 7941, "text": ".”\n\n“Be dumb, man! Stand by the braces! Hard down the helm!—brace up!\nShiver her!—shiver her!—So; well that! Boats, boats!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 7942, "position": 7942, "text": "! Boats, boats!”\n\nSoon all the boats but Starbuck’s were dropped; all the boat-sails\nset—all the paddles plying; with rippling swiftness, shooting to\nleeward; and Ahab heading the onset", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7943, "position": 7943, "text": "swiftness, shooting to\nleeward; and Ahab heading the onset. A pale, death-glimmer lit up\nFedallah’s sunken eyes; a hideous motion gnawed his mouth.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7944, "position": 7944, "text": "motion gnawed his mouth.\n\nLike noiseless nautilus shells, their light prows sped through the sea;\nbut only slowly they neared the foe. As they neared him, the ocean grew\nstill more smooth; seemed drawing a carpet over its", "labels": {"50": 45, "100": 64, "250": 205, "500": 72, "1000": 825, "2000": 631}}, {"id": 7945, "position": 7945, "text": "him, the ocean grew\nstill more smooth; seemed drawing a carpet over its waves; seemed a\nnoon-meadow, so serenely it spread. At length the breathless hunter\ncame so nigh his seemingly unsuspecting prey, that his entire dazzling", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7946, "position": 7946, "text": "so nigh his seemingly unsuspecting prey, that his entire dazzling\nhump was distinctly visible, sliding along the sea as if an isolated\nthing, and continually set in a revolving ring of finest, fleecy,\ngreenish foam", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 7947, "position": 7947, "text": "a revolving ring of finest, fleecy,\ngreenish foam. He saw the vast, involved wrinkles of the slightly\nprojecting head beyond. Before it, far out on the soft Turkish-rugged\nwaters, went the glistening white shadow from his broad, milky", "labels": {"50": 22, "100": 55, "250": 28, "500": 72, "1000": 531, "2000": 110}}, {"id": 7948, "position": 7948, "text": "Turkish-rugged\nwaters, went the glistening white shadow from his broad, milky\nforehead, a musical rippling playfully accompanying the shade; and\nbehind, the blue waters interchangeably flowed over into the moving\nvalley of his steady wake; and on either hand bright", "labels": {"50": 12, "100": 43, "250": 192, "500": 423, "1000": 35, "2000": 1735}}, {"id": 7949, "position": 7949, "text": "over into the moving\nvalley of his steady wake; and on either hand bright bubbles arose and\ndanced by his side. But these were broken again by the light toes of\nhundreds of gay fowl softly feathering the sea, alternate with their\nfitful", "labels": {"50": 16, "100": 73, "250": 53, "500": 162, "1000": 35, "2000": 1735}}, {"id": 7950, "position": 7950, "text": "gay fowl softly feathering the sea, alternate with their\nfitful flight; and like to some flag-staff rising from the painted hull\nof an argosy, the tall but shattered pole of a recent lance projected\nfrom the white whale’", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 747, "2000": 573}}, {"id": 7951, "position": 7951, "text": "the tall but shattered pole of a recent lance projected\nfrom the white whale’s back; and at intervals one of the cloud of\nsoft-toed fowls hovering, and to and fro skimming like a canopy over\nthe fish, silently", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7952, "position": 7952, "text": "and to and fro skimming like a canopy over\nthe fish, silently perched and rocked on this pole, the long tail\nfeathers streaming like pennons.\n\nA gentle joyousness—a mighty mildness of repose in swiftness, invested\nthe", "labels": {"50": 12, "100": 24, "250": 192, "500": 162, "1000": 35, "2000": 1710}}, {"id": 7953, "position": 7953, "text": "ness—a mighty mildness of repose in swiftness, invested\nthe gliding whale. Not the white bull Jupiter swimming away with\nravished Europa clinging to his graceful horns; his lovely, leering\neyes sideways intent upon the maid; with smooth be", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7954, "position": 7954, "text": "his lovely, leering\neyes sideways intent upon the maid; with smooth bewitching fleetness,\nrippling straight for the nuptial bower in Crete; not Jove, not that\ngreat majesty Supreme! did surpass the glor", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 118, "2000": 573}}, {"id": 7955, "position": 7955, "text": "Jove, not that\ngreat majesty Supreme! did surpass the glorified White Whale as he so\ndivinely swam.\n\nOn each soft side—coincident with the parted swell, that but once\nleaving him, then flowed so wide away—on", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 7956, "position": 7956, "text": "swell, that but once\nleaving him, then flowed so wide away—on each bright side, the whale\nshed off enticings. No wonder there had been some among the hunters who\nnamelessly transported and allured by all this serenity, had", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7957, "position": 7957, "text": "hunters who\nnamelessly transported and allured by all this serenity, had ventured\nto assail it; but had fatally found that quietude but the vesture of\ntornadoes. Yet calm, enticing calm, oh, whale! thou glidest", "labels": {"50": 9, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 1620}}, {"id": 7958, "position": 7958, "text": "Yet calm, enticing calm, oh, whale! thou glidest on, to all\nwho for the first time eye thee, no matter how many in that same way\nthou may’st have bejuggled and destroyed before.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7959, "position": 7959, "text": "thou may’st have bejuggled and destroyed before.\n\nAnd thus, through the serene tranquillities of the tropical sea, among\nwaves whose hand-clappings were suspended by exceeding rapture, Moby\nDick moved on, still with", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7960, "position": 7960, "text": "were suspended by exceeding rapture, Moby\nDick moved on, still withholding from sight the full terrors of his\nsubmerged trunk, entirely hiding the wrenched hideousness of his jaw.\nBut soon the fore part of him slowly rose from the water;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7961, "position": 7961, "text": "jaw.\nBut soon the fore part of him slowly rose from the water; for an\ninstant his whole marbleized body formed a high arch, like Virginia’s\nNatural Bridge, and warningly waving his bannered flukes in the air,\nthe grand", "labels": {"50": 22, "100": 55, "250": 205, "500": 72, "1000": 825, "2000": 1620}}, {"id": 7962, "position": 7962, "text": "and warningly waving his bannered flukes in the air,\nthe grand god revealed himself, sounded, and went out of sight.\nHoveringly halting, and dipping on the wing, the white sea-fowls\nlongingly lingered over the", "labels": {"50": 22, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 472}}, {"id": 7963, "position": 7963, "text": "the wing, the white sea-fowls\nlongingly lingered over the agitated pool that he left.\n\nWith oars apeak, and paddles down, the sheets of their sails adrift,\nthe three boats now stilly floated, awaiting Mob", "labels": {"50": 9, "100": 26, "250": 240, "500": 122, "1000": 779, "2000": 16}}, {"id": 7964, "position": 7964, "text": "their sails adrift,\nthe three boats now stilly floated, awaiting Moby Dick’s reappearance.\n\n“An hour,” said Ahab, standing rooted in his boat’s stern; and he gazed\nbeyond the whale’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7965, "position": 7965, "text": "in his boat’s stern; and he gazed\nbeyond the whale’s place, towards the dim blue spaces and wide wooing\nvacancies to leeward. It was only an instant; for again his eyes seemed\nwhirling round in his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7966, "position": 7966, "text": "only an instant; for again his eyes seemed\nwhirling round in his head as he swept the watery circle. The breeze\nnow freshened; the sea began to swell.\n\n“The birds!—the birds!” cried Tashtego.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7967, "position": 7967, "text": "“The birds!—the birds!” cried Tashtego.\n\nIn long Indian file, as when herons take wing, the white birds were now\nall flying towards Ahab’s boat; and when within a few yards began\nfluttering over", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7968, "position": 7968, "text": "Ahab’s boat; and when within a few yards began\nfluttering over the water there, wheeling round and round, with joyous,\nexpectant cries. Their vision was keener than man’s; Ahab could\ndiscover no sign in the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7969, "position": 7969, "text": "keener than man’s; Ahab could\ndiscover no sign in the sea. But suddenly as he peered down and down\ninto its depths, he profoundly saw a white living spot no bigger than a\nwhite weasel, with wonderful celerity uprising,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7970, "position": 7970, "text": "spot no bigger than a\nwhite weasel, with wonderful celerity uprising, and magnifying as it\nrose, till it turned, and then there were plainly revealed two long\ncrooked rows of white, glistening teeth, floating up from the\nundisco", "labels": {"50": 37, "100": 24, "250": 52, "500": 465, "1000": 204, "2000": 174}}, {"id": 7971, "position": 7971, "text": "crooked rows of white, glistening teeth, floating up from the\nundiscoverable bottom. It was Moby Dick’s open mouth and scrolled jaw;\nhis vast, shadowed bulk still half blending with the blue of the sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7972, "position": 7972, "text": ", shadowed bulk still half blending with the blue of the sea.\nThe glittering mouth yawned beneath the boat like an open-doored marble\ntomb; and giving one sidelong sweep with his steering oar, Ahab whirled\nthe craft aside from this tremendous", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7973, "position": 7973, "text": "with his steering oar, Ahab whirled\nthe craft aside from this tremendous apparition. Then, calling upon\nFedallah to change places with him, went forward to the bows, and\nseizing Perth’s harpoon, commanded his crew to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7974, "position": 7974, "text": "the bows, and\nseizing Perth’s harpoon, commanded his crew to grasp their oars and\nstand by to stern.\n\nNow, by reason of this timely spinning round the boat upon its axis,\nits bow, by anticipation, was made to face", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7975, "position": 7975, "text": "boat upon its axis,\nits bow, by anticipation, was made to face the whale’s head while yet\nunder water. But as if perceiving this stratagem, Moby Dick, with that\nmalicious intelligence ascribed to him, sideling", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7976, "position": 7976, "text": ", Moby Dick, with that\nmalicious intelligence ascribed to him, sidelingly transplanted\nhimself, as it were, in an instant, shooting his pleated head\nlengthwise beneath the boat.\n\nThrough and through; through every plank and each rib,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7977, "position": 7977, "text": "beneath the boat.\n\nThrough and through; through every plank and each rib, it thrilled for\nan instant, the whale obliquely lying on his back, in the manner of a\nbiting shark, slowly and feelingly taking its bows full within his\nmouth,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7978, "position": 7978, "text": "biting shark, slowly and feelingly taking its bows full within his\nmouth, so that the long, narrow, scrolled lower jaw curled high up into\nthe open air, and one of the teeth caught in a row-lock", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 7979, "position": 7979, "text": "one of the teeth caught in a row-lock. The bluish\npearl-white of the inside of the jaw was within six inches of Ahab’s\nhead, and reached higher than that. In this attitude the White Whale\nnow shook the slight", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7980, "position": 7980, "text": "reached higher than that. In this attitude the White Whale\nnow shook the slight cedar as a mildly cruel cat her mouse. With\nunastonished eyes Fedallah gazed, and crossed his arms; but the\ntiger-yellow crew were tumbling over each other", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 531, "2000": 1904}}, {"id": 7981, "position": 7981, "text": "crossed his arms; but the\ntiger-yellow crew were tumbling over each other’s heads to gain the\nuttermost stern.\n\nAnd now, while both elastic gunwales were springing in and out, as the\nwhale dallied with the doomed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7982, "position": 7982, "text": "springing in and out, as the\nwhale dallied with the doomed craft in this devilish way; and from his\nbody being submerged beneath the boat, he could not be darted at from\nthe bows, for the bows were almost inside of him", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7983, "position": 7983, "text": "be darted at from\nthe bows, for the bows were almost inside of him, as it were; and while\nthe other boats involuntarily paused, as before a quick crisis\nimpossible to withstand, then it was that monomaniac Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7984, "position": 7984, "text": "quick crisis\nimpossible to withstand, then it was that monomaniac Ahab, furious with\nthis tantalizing vicinity of his foe, which placed him all alive and\nhelpless in the very jaws he hated; frenzied with all this, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7985, "position": 7985, "text": "the very jaws he hated; frenzied with all this, he seized\nthe long bone with his naked hands, and wildly strove to wrench it from\nits gripe. As now he thus vainly strove, the jaw slipped from", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 7986, "position": 7986, "text": "e. As now he thus vainly strove, the jaw slipped from him; the\nfrail gunwales bent in, collapsed, and snapped, as both jaws, like an\nenormous shears, sliding further aft, bit the craft completely in\ntwain", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7987, "position": 7987, "text": "an\nenormous shears, sliding further aft, bit the craft completely in\ntwain, and locked themselves fast again in the sea, midway between the\ntwo floating wrecks. These floated aside, the broken ends drooping, the\ncrew at the stern-wreck", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 7988, "position": 7988, "text": "aside, the broken ends drooping, the\ncrew at the stern-wreck clinging to the gunwales, and striving to hold\nfast to the oars to lash them across.\n\nAt that preluding moment, ere the boat was", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 282}}, {"id": 7989, "position": 7989, "text": "them across.\n\nAt that preluding moment, ere the boat was yet snapped, Ahab, the first\nto perceive the whale’s intent, by the crafty upraising of his head, a\nmovement that loosed his hold for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7990, "position": 7990, "text": "upraising of his head, a\nmovement that loosed his hold for the time; at that moment his hand had\nmade one final effort to push the boat out of the bite. But only\nslipping further into the whale’s mouth, and tilting", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7991, "position": 7991, "text": "bite. But only\nslipping further into the whale’s mouth, and tilting over sideways as\nit slipped, the boat had shaken off his hold on the jaw; spilled him\nout of it, as he leaned to the push; and so he fell flat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7992, "position": 7992, "text": "of it, as he leaned to the push; and so he fell flat-faced upon the\nsea.\n\nRipplingly withdrawing from his prey, Moby Dick now lay at a little\ndistance, vertically thrusting his oblong white head up and down in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7993, "position": 7993, "text": "a little\ndistance, vertically thrusting his oblong white head up and down in the\nbillows; and at the same time slowly revolving his whole spindled body;\nso that when his vast wrinkled forehead rose—some twenty or more feet\nout of the water", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7994, "position": 7994, "text": "his vast wrinkled forehead rose—some twenty or more feet\nout of the water—the now rising swells, with all their confluent waves,\ndazzlingly broke against it; vindictively tossing their shivered spray\nstill higher into the air.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 1620}}, {"id": 7995, "position": 7995, "text": "it; vindictively tossing their shivered spray\nstill higher into the air.* So, in a gale, the but half baffled Channel\nbillows only recoil from the base of the Eddystone, triumphantly to\noverleap its summit with their sc", "labels": {"50": 48, "100": 20, "250": 192, "500": 102, "1000": 875, "2000": 1710}}, {"id": 7996, "position": 7996, "text": "the Eddystone, triumphantly to\noverleap its summit with their scud.\n\n*This motion is peculiar to the sperm whale. It receives its\ndesignation (pitchpoling) from its being likened to that preliminary\nup-and-down poise", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7997, "position": 7997, "text": ") from its being likened to that preliminary\nup-and-down poise of the whale-lance, in the exercise called\npitchpoling, previously described. By this motion the whale must best\nand most comprehensively view whatever objects may be enci", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7998, "position": 7998, "text": "the whale must best\nand most comprehensively view whatever objects may be encircling him.\n\nBut soon resuming his horizontal attitude, Moby Dick swam swiftly round\nand round the wrecked crew; sideways churning the water in his vengeful\nwake,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 7999, "position": 7999, "text": "the wrecked crew; sideways churning the water in his vengeful\nwake, as if lashing himself up to still another and more deadly\nassault. The sight of the splintered boat seemed to madden him, as the\nblood of grapes and mulber", "labels": {"50": 22, "100": 64, "250": 28, "500": 28, "1000": 99, "2000": 1904}}, {"id": 8000, "position": 8000, "text": "boat seemed to madden him, as the\nblood of grapes and mulberries cast before Antiochus’s elephants in the\nbook of Maccabees. Meanwhile Ahab half smothered in the foam of the\nwhale’s insolent", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8001, "position": 8001, "text": "half smothered in the foam of the\nwhale’s insolent tail, and too much of a cripple to swim,—though he\ncould still keep afloat, even in the heart of such a whirlpool as that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8002, "position": 8002, "text": "oat, even in the heart of such a whirlpool as that;\nhelpless Ahab’s head was seen, like a tossed bubble which the least\nchance shock might burst. From the boat’s fragmentary stern, Fedallah\ninc", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8003, "position": 8003, "text": "burst. From the boat’s fragmentary stern, Fedallah\nincuriously and mildly eyed him; the clinging crew, at the other\ndrifting end, could not succor him; more than enough was it for them to\nlook to themselves", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8004, "position": 8004, "text": "ccor him; more than enough was it for them to\nlook to themselves. For so revolvingly appalling was the White Whale’s\naspect, and so planetarily swift the ever-contracting circles he made,\nthat he seemed horizontally sw", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8005, "position": 8005, "text": "ly swift the ever-contracting circles he made,\nthat he seemed horizontally swooping upon them. And though the other\nboats, unharmed, still hovered hard by; still they dared not pull into\nthe eddy to strike, lest that should be the signal for", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8006, "position": 8006, "text": "not pull into\nthe eddy to strike, lest that should be the signal for the instant\ndestruction of the jeopardized castaways, Ahab and all; nor in that\ncase could they themselves hope to escape", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8007, "position": 8007, "text": "that\ncase could they themselves hope to escape. With straining eyes, then,\nthey remained on the outer edge of the direful zone, whose centre had\nnow become the old man’s head.\n\nMeantime, from the beginning all this had been descr", "labels": {"50": 22, "100": 55, "250": 205, "500": 185, "1000": 783, "2000": 399}}, {"id": 8008, "position": 8008, "text": "’s head.\n\nMeantime, from the beginning all this had been descried from the ship’s\nmast heads; and squaring her yards, she had borne down upon the scene;\nand was now so nigh, that Ahab in", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8009, "position": 8009, "text": "upon the scene;\nand was now so nigh, that Ahab in the water hailed her!—“Sail on\nthe”—but that moment a breaking sea dashed on him from Moby Dick, and\nwhelmed him for the time", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8010, "position": 8010, "text": "him from Moby Dick, and\nwhelmed him for the time. But struggling out of it again, and chancing\nto rise on a towering crest, he shouted,—“Sail on the whale!—Drive him\noff!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8011, "position": 8011, "text": "—“Sail on the whale!—Drive him\noff!”\n\nThe Pequod’s prows were pointed; and breaking up the charmed circle,\nshe effectually parted the white whale from his victim", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8012, "position": 8012, "text": "parted the white whale from his victim. As he sullenly\nswam off, the boats flew to the rescue.\n\nDragged into Stubb’s boat with blood-shot, blinded eyes, the white\nbrine caking in his wrinkles; the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8013, "position": 8013, "text": "blinded eyes, the white\nbrine caking in his wrinkles; the long tension of Ahab’s bodily\nstrength did crack, and helplessly he yielded to his body’s doom: for a\ntime, lying all crushed in the bottom of Stu", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8014, "position": 8014, "text": "s doom: for a\ntime, lying all crushed in the bottom of Stubb’s boat, like one trodden\nunder foot of herds of elephants. Far inland, nameless wails came from\nhim, as desolate sounds from out ravine", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8015, "position": 8015, "text": "nameless wails came from\nhim, as desolate sounds from out ravines.\n\nBut this intensity of his physical prostration did but so much the more\nabbreviate it. In an instant’s compass, great hearts sometimes condense", "labels": {"50": 22, "100": 78, "250": 205, "500": 469, "1000": 631, "2000": 1976}}, {"id": 8016, "position": 8016, "text": "te it. In an instant’s compass, great hearts sometimes condense\nto one deep pang, the sum total of those shallow pains kindly diffused\nthrough feebler men’s whole lives. And so, such hearts, though summary\nin each one", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 573}}, {"id": 8017, "position": 8017, "text": "s whole lives. And so, such hearts, though summary\nin each one suffering; still, if the gods decree it, in their life-time\naggregate a whole age of woe, wholly made up of instantaneous\nintensities; for even", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 193}}, {"id": 8018, "position": 8018, "text": "woe, wholly made up of instantaneous\nintensities; for even in their pointless centres, those noble natures\ncontain the entire circumferences of inferior souls.\n\n“The harpoon,” said Ahab, half way rising,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8019, "position": 8019, "text": ".\n\n“The harpoon,” said Ahab, half way rising, and draggingly leaning on\none bended arm—“is it safe?”\n\n“Aye, sir, for it was not darted; this is it,” said Stubb", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8020, "position": 8020, "text": ", for it was not darted; this is it,” said Stubb, showing it.\n\n“Lay it before me;—any missing men?”\n\n“One, two, three, four, five;—there were five oars, sir", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8021, "position": 8021, "text": ", three, four, five;—there were five oars, sir, and here are\nfive men.”\n\n“That’s good.—Help me, man; I wish to stand. So, so, I see him! there!", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 327, "2000": 967}}, {"id": 8022, "position": 8022, "text": "I wish to stand. So, so, I see him! there!\nthere! going to leeward still; what a leaping spout!—Hands off from me!\nThe eternal sap runs up in Ahab’s bones again! Set the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8023, "position": 8023, "text": "The eternal sap runs up in Ahab’s bones again! Set the sail; out oars;\nthe helm!”\n\nIt is often the case that when a boat is stove, its crew, being picked\nup by another boat, help to work", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8024, "position": 8024, "text": "stove, its crew, being picked\nup by another boat, help to work that second boat; and the chase is\nthus continued with what is called double-banked oars. It was thus now.\nBut the added power of the boat did not", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 8025, "position": 8025, "text": ". It was thus now.\nBut the added power of the boat did not equal the added power of the\nwhale, for he seemed to have treble-banked his every fin; swimming with\na velocity which plainly showed, that if now, under", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1620}}, {"id": 8026, "position": 8026, "text": "fin; swimming with\na velocity which plainly showed, that if now, under these\ncircumstances, pushed on, the chase would prove an indefinitely\nprolonged, if not a hopeless one; nor could any crew endure for so long\na period, such an unint", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8027, "position": 8027, "text": "nor could any crew endure for so long\na period, such an unintermitted, intense straining at the oar; a thing\nbarely tolerable only in some one brief vicissitude. The ship itself,\nthen, as it sometimes", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 8028, "position": 8028, "text": "one brief vicissitude. The ship itself,\nthen, as it sometimes happens, offered the most promising intermediate\nmeans of overtaking the chase. Accordingly, the boats now made for her,\nand were soon swayed up to their cranes—the two parts", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 8029, "position": 8029, "text": "for her,\nand were soon swayed up to their cranes—the two parts of the wrecked\nboat having been previously secured by her—and then hoisting everything\nto her side, and stacking her canvas high up, and sideways\noutstretching", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 300, "2000": 282}}, {"id": 8030, "position": 8030, "text": ", and stacking her canvas high up, and sideways\noutstretching it with stun-sails, like the double-jointed wings of an\nalbatross; the Pequod bore down in the leeward wake of Moby-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8031, "position": 8031, "text": "the Pequod bore down in the leeward wake of Moby-Dick. At\nthe well known, methodic intervals, the whale’s glittering spout was\nregularly announced from the manned mast-heads; and when he would be\nreported as", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8032, "position": 8032, "text": "announced from the manned mast-heads; and when he would be\nreported as just gone down, Ahab would take the time, and then pacing\nthe deck, binnacle-watch in hand, so soon as the last second of the\nallotted hour", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8033, "position": 8033, "text": "-watch in hand, so soon as the last second of the\nallotted hour expired, his voice was heard.—“Whose is the doubloon now?\nD’ye see him?” and if the reply was, No, sir!", "labels": {"50": 23, "100": 88, "250": 219, "500": 73, "1000": 317, "2000": 1087}}, {"id": 8034, "position": 8034, "text": "ye see him?” and if the reply was, No, sir! straightway he commanded\nthem to lift him to his perch. In this way the day wore on; Ahab, now\naloft and motionless; anon, unrestingly pacing", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8035, "position": 8035, "text": "Ahab, now\naloft and motionless; anon, unrestingly pacing the planks.\n\nAs he was thus walking, uttering no sound, except to hail the men\naloft, or to bid them hoist a sail still higher, or", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8036, "position": 8036, "text": "aloft, or to bid them hoist a sail still higher, or to spread one to a\nstill greater breadth—thus to and fro pacing, beneath his slouched hat,\nat every turn he passed his own wrecked boat, which had", "labels": {"50": 9, "100": 26, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8037, "position": 8037, "text": "ched hat,\nat every turn he passed his own wrecked boat, which had been dropped\nupon the quarter-deck, and lay there reversed; broken bow to shattered\nstern. At last he paused before it; and as in an already over-clouded\nsky", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 8038, "position": 8038, "text": "last he paused before it; and as in an already over-clouded\nsky fresh troops of clouds will sometimes sail across, so over the old\nman’s face there now stole some such added gloom as this.", "labels": {"50": 22, "100": 78, "250": 229, "500": 286, "1000": 448, "2000": 1027}}, {"id": 8039, "position": 8039, "text": "some such added gloom as this.\n\nStubb saw him pause; and perhaps intending, not vainly, though, to\nevince his own unabated fortitude, and thus keep up a valiant place in\nhis Captain’s mind, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8040, "position": 8040, "text": "and thus keep up a valiant place in\nhis Captain’s mind, he advanced, and eyeing the wreck exclaimed—“The\nthistle the ass refused; it pricked his mouth too keenly, sir; ha! ha!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 8041, "position": 8041, "text": "too keenly, sir; ha! ha!”\n\n“What soulless thing is this that laughs before a wreck? Man, man! did\nI not know thee brave as fearless fire (and as mechanical) I could\nswear thou wert a pol", "labels": {"50": 9, "100": 26, "250": 133, "500": 406, "1000": 437, "2000": 1860}}, {"id": 8042, "position": 8042, "text": "fearless fire (and as mechanical) I could\nswear thou wert a poltroon. Groan nor laugh should be heard before a\nwreck.”\n\n“Aye, sir,” said Starbuck drawing near, “’tis a solemn sight; an om", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8043, "position": 8043, "text": "said Starbuck drawing near, “’tis a solemn sight; an omen,\nand an ill one.”\n\n“Omen? omen?—the dictionary! If the gods think to speak outright to\nman, they will honorably speak outright", "labels": {"50": 26, "100": 10, "250": 226, "500": 56, "1000": 349, "2000": 1475}}, {"id": 8044, "position": 8044, "text": "the gods think to speak outright to\nman, they will honorably speak outright; not shake their heads, and\ngive an old wives’ darkling hint.—Begone! Ye two are the opposite poles\nof one thing; Starbuck is Stubb", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8045, "position": 8045, "text": "Ye two are the opposite poles\nof one thing; Starbuck is Stubb reversed, and Stubb is Starbuck; and ye\ntwo are all mankind; and Ahab stands alone among the millions of the\npeopled earth, nor gods nor men his", "labels": {"50": 9, "100": 26, "250": 133, "500": 498, "1000": 327, "2000": 1620}}, {"id": 8046, "position": 8046, "text": "alone among the millions of the\npeopled earth, nor gods nor men his neighbors! Cold, cold—I shiver!—How\nnow? Aloft there! D’ye see him? Sing out for every spout, though he\nspout ten", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 136, "2000": 1203}}, {"id": 8047, "position": 8047, "text": "see him? Sing out for every spout, though he\nspout ten times a second!”\n\nThe day was nearly done; only the hem of his golden robe was rustling.\nSoon, it was almost dark, but the look-out men still", "labels": {"50": 40, "100": 83, "250": 170, "500": 433, "1000": 520, "2000": 1604}}, {"id": 8048, "position": 8048, "text": ".\nSoon, it was almost dark, but the look-out men still remained unset.\n\n“Can’t see the spout now, sir;—too dark”—cried a voice from the air.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 8049, "position": 8049, "text": "—cried a voice from the air.\n\n“How heading when last seen?”\n\n“As before, sir,—straight to leeward.”\n\n“Good! he will travel slower now ’tis night. Down royals and\ntop-gallant stun-", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 8050, "position": 8050, "text": "slower now ’tis night. Down royals and\ntop-gallant stun-sails, Mr. Starbuck. We must not run over him before\nmorning; he’s making a passage now, and may heave-to a while", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8051, "position": 8051, "text": "a passage now, and may heave-to a while. Helm\nthere! keep her full before the wind!—Aloft! come down!—Mr. Stubb, send\na fresh hand to the fore-mast head, and see it", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 967}}, {"id": 8052, "position": 8052, "text": ", send\na fresh hand to the fore-mast head, and see it manned till\nmorning.”—Then advancing towards the doubloon in the main-mast—“Men,\nthis gold is mine, for I earned it; but I", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 8053, "position": 8053, "text": "“Men,\nthis gold is mine, for I earned it; but I shall let it abide here till\nthe White Whale is dead; and then, whosoever of ye first raises him,\nupon the day he shall be killed, this gold", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8054, "position": 8054, "text": "ye first raises him,\nupon the day he shall be killed, this gold is that man’s; and if on\nthat day I shall again raise him, then, ten times its sum shall be\ndivided among all of ye! Away now!—", "labels": {"50": 18, "100": 83, "250": 102, "500": 61, "1000": 672, "2000": 1091}}, {"id": 8055, "position": 8055, "text": "times its sum shall be\ndivided among all of ye! Away now!—the deck is thine, sir!”\n\nAnd so saying, he placed himself half way within the scuttle, and\nslouching his hat, stood there till dawn", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8056, "position": 8056, "text": "scuttle, and\nslouching his hat, stood there till dawn, except when at intervals\nrousing himself to see how the night wore on.\n\n\nCHAPTER 134. The Chase—Second Day.\n\nAt day-break, the three mast-heads", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8057, "position": 8057, "text": "Chase—Second Day.\n\nAt day-break, the three mast-heads were punctually manned afresh.\n\n“D’ye see him?” cried Ahab after allowing a little space for the light\nto spread.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8058, "position": 8058, "text": "allowing a little space for the light\nto spread.\n\n“See nothing, sir.”\n\n“Turn up all hands and make sail! he travels faster than I thought\nfor;—the top-gallant sails!—aye, they should have been kept on", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 8059, "position": 8059, "text": "the top-gallant sails!—aye, they should have been kept on her all\nnight. But no matter—’tis but resting for the rush.”\n\nHere be it said, that this pertinacious pursuit of one particular\nwhale, continued through", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8060, "position": 8060, "text": "said, that this pertinacious pursuit of one particular\nwhale, continued through day into night, and through night into day, is\na thing by no means unprecedented in the South sea fishery. For such is\nthe wonderful skill, prescience of experience", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8061, "position": 8061, "text": "sea fishery. For such is\nthe wonderful skill, prescience of experience, and invincible\nconfidence acquired by some great natural geniuses among the Nantucket\ncommanders; that from the simple observation of a whale when last\ndescried, they will, under", "labels": {"50": 45, "100": 29, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8062, "position": 8062, "text": "simple observation of a whale when last\ndescried, they will, under certain given circumstances, pretty\naccurately foretell both the direction in which he will continue to\nswim for a time, while out of sight, as well as his probable rate of\nprogression", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8063, "position": 8063, "text": "time, while out of sight, as well as his probable rate of\nprogression during that period. And, in these cases, somewhat as a\npilot, when about losing sight of a coast, whose general trending he\nwell knows, and which he desires", "labels": {"50": 10, "100": 71, "250": 50, "500": 33, "1000": 862, "2000": 1403}}, {"id": 8064, "position": 8064, "text": "a coast, whose general trending he\nwell knows, and which he desires shortly to return to again, but at\nsome further point; like as this pilot stands by his compass, and takes\nthe precise bearing of the cape at present visible, in order", "labels": {"50": 10, "100": 75, "250": 106, "500": 333, "1000": 256, "2000": 1986}}, {"id": 8065, "position": 8065, "text": ", and takes\nthe precise bearing of the cape at present visible, in order the more\ncertainly to hit aright the remote, unseen headland, eventually to be\nvisited: so does the fisherman, at his compass, with the whale; for\nafter being", "labels": {"50": 45, "100": 29, "250": 34, "500": 306, "1000": 899, "2000": 1950}}, {"id": 8066, "position": 8066, "text": "does the fisherman, at his compass, with the whale; for\nafter being chased, and diligently marked, through several hours of\ndaylight, then, when night obscures the fish, the creature’s future\nwake through the darkness is almost as", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8067, "position": 8067, "text": "the fish, the creature’s future\nwake through the darkness is almost as established to the sagacious\nmind of the hunter, as the pilot’s coast is to him. So that to this\nhunter’s wondrous skill, the proverb", "labels": {"50": 3, "100": 24, "250": 213, "500": 72, "1000": 692, "2000": 982}}, {"id": 8068, "position": 8068, "text": "So that to this\nhunter’s wondrous skill, the proverbial evanescence of a thing writ in\nwater, a wake, is to all desired purposes well nigh as reliable as the\nsteadfast land", "labels": {"50": 31, "100": 75, "250": 106, "500": 417, "1000": 692, "2000": 374}}, {"id": 8069, "position": 8069, "text": "gh as reliable as the\nsteadfast land. And as the mighty iron Leviathan of the modern railway\nis so familiarly known in its every pace, that, with watches in their\nhands, men time his rate as doctors that of a baby’", "labels": {"50": 48, "100": 27, "250": 53, "500": 223, "1000": 784, "2000": 1650}}, {"id": 8070, "position": 8070, "text": "in their\nhands, men time his rate as doctors that of a baby’s pulse; and lightly\nsay of it, the up train or the down train will reach such or such a\nspot, at such or such an hour; even so, almost", "labels": {"50": 37, "100": 20, "250": 49, "500": 292, "1000": 784, "2000": 177}}, {"id": 8071, "position": 8071, "text": "such a\nspot, at such or such an hour; even so, almost, there are occasions\nwhen these Nantucketers time that other Leviathan of the deep,\naccording to the observed humor of his speed; and say to themselves, so\nmany hours", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8072, "position": 8072, "text": "the observed humor of his speed; and say to themselves, so\nmany hours hence this whale will have gone two hundred miles, will have\nabout reached this or that degree of latitude or longitude. But to\nrender this acuteness at all successful in the end", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8073, "position": 8073, "text": "or longitude. But to\nrender this acuteness at all successful in the end, the wind and the\nsea must be the whaleman’s allies; for of what present avail to the\nbecalmed or windbound mariner is the skill that assure", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8074, "position": 8074, "text": "to the\nbecalmed or windbound mariner is the skill that assures him he is\nexactly ninety-three leagues and a quarter from his port? Inferable\nfrom these statements, are many collateral subtile matters touching the\nchase of whales.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8075, "position": 8075, "text": "these statements, are many collateral subtile matters touching the\nchase of whales.\n\nThe ship tore on; leaving such a furrow in the sea as when a\ncannon-ball, missent, becomes a plough-share and turns up the level\nfield", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8076, "position": 8076, "text": "missent, becomes a plough-share and turns up the level\nfield.\n\n“By salt and hemp!” cried Stubb, “but this swift motion of the deck\ncreeps up one’s legs and tingles at the heart", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8077, "position": 8077, "text": "deck\ncreeps up one’s legs and tingles at the heart. This ship and I are two\nbrave fellows!—Ha, ha! Some one take me up, and launch me, spine-wise,\non the sea,—for by", "labels": {"50": 9, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8078, "position": 8078, "text": "and launch me, spine-wise,\non the sea,—for by live-oaks! my spine’s a keel. Ha, ha! we go the gait\nthat leaves no dust behind!”", "labels": {"50": 16, "100": 73, "250": 15, "500": 276, "1000": 174, "2000": 16}}, {"id": 8079, "position": 8079, "text": "that leaves no dust behind!”\n\n“There she blows—she blows!—she blows!—right ahead!” was now the\nmast-head cry.\n\n“Aye, aye!” cried Stubb, “I knew it—ye can’", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8080, "position": 8080, "text": "aye!” cried Stubb, “I knew it—ye can’t escape—blow on and split\nyour spout, O whale! the mad fiend himself is after ye! blow your\ntrump—blister your lungs!—Ah", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8081, "position": 8081, "text": "after ye! blow your\ntrump—blister your lungs!—Ahab will dam off your blood, as a miller\nshuts his watergate upon the stream!”\n\nAnd Stubb did but speak out for well nigh all that crew", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8082, "position": 8082, "text": "And Stubb did but speak out for well nigh all that crew. The frenzies\nof the chase had by this time worked them bubblingly up, like old wine\nworked anew. Whatever pale fears and forebodings some of", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8083, "position": 8083, "text": "wine\nworked anew. Whatever pale fears and forebodings some of them might\nhave felt before; these were not only now kept out of sight through the\ngrowing awe of Ahab, but they were broken up, and on all sides routed,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8084, "position": 8084, "text": "Ahab, but they were broken up, and on all sides routed,\nas timid prairie hares that scatter before the bounding bison. The hand\nof Fate had snatched all their souls; and by the stirring perils of the\nprevious day", "labels": {"50": 12, "100": 55, "250": 65, "500": 171, "1000": 954, "2000": 1635}}, {"id": 8085, "position": 8085, "text": "snatched all their souls; and by the stirring perils of the\nprevious day; the rack of the past night’s suspense; the fixed,\nunfearing, blind, reckless way in which their wild craft went plunging\ntowards its flying mark; by", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 8086, "position": 8086, "text": "reckless way in which their wild craft went plunging\ntowards its flying mark; by all these things, their hearts were bowled\nalong. The wind that made great bellies of their sails, and rushed the\nvessel on by arms invisible as irresistible; this seemed the", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 576}}, {"id": 8087, "position": 8087, "text": ", and rushed the\nvessel on by arms invisible as irresistible; this seemed the symbol of\nthat unseen agency which so enslaved them to the race.\n\nThey were one man, not thirty. For as the one ship that held them all;\nthough it was put", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 8088, "position": 8088, "text": ". For as the one ship that held them all;\nthough it was put together of all contrasting things—oak, and maple,\nand pine wood; iron, and pitch, and hemp—yet all these ran into each\nother in the one concrete", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 8089, "position": 8089, "text": "and hemp—yet all these ran into each\nother in the one concrete hull, which shot on its way, both balanced\nand directed by the long central keel; even so, all the individualities\nof the crew, this man’s valor,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8090, "position": 8090, "text": ", all the individualities\nof the crew, this man’s valor, that man’s fear; guilt and guiltiness,\nall varieties were welded into oneness, and were all directed to that\nfatal goal which Ahab their one lord and keel", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8091, "position": 8091, "text": "were all directed to that\nfatal goal which Ahab their one lord and keel did point to.\n\nThe rigging lived. The mast-heads, like the tops of tall palms, were\noutspreadingly tufted with arms and legs", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8092, "position": 8092, "text": ", were\noutspreadingly tufted with arms and legs. Clinging to a spar with one\nhand, some reached forth the other with impatient wavings; others,\nshading their eyes from the vivid sunlight, sat far out on the rocking\nyards", "labels": {"50": 45, "100": 64, "250": 138, "500": 162, "1000": 327, "2000": 1904}}, {"id": 8093, "position": 8093, "text": "ding their eyes from the vivid sunlight, sat far out on the rocking\nyards; all the spars in full bearing of mortals, ready and ripe for\ntheir fate. Ah! how they still strove through that infinite blueness to\nseek out the thing", "labels": {"50": 22, "100": 55, "250": 28, "500": 93, "1000": 661, "2000": 410}}, {"id": 8094, "position": 8094, "text": "how they still strove through that infinite blueness to\nseek out the thing that might destroy them!\n\n“Why sing ye not out for him, if ye see him?” cried Ahab, when, after\nthe lapse of some minutes since the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8095, "position": 8095, "text": "cried Ahab, when, after\nthe lapse of some minutes since the first cry, no more had been heard.\n“Sway me up, men; ye have been deceived; not Moby Dick casts one odd\njet that way, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8096, "position": 8096, "text": "eived; not Moby Dick casts one odd\njet that way, and then disappears.”\n\nIt was even so; in their headlong eagerness, the men had mistaken some\nother thing for the whale-spout, as the event itself soon", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8097, "position": 8097, "text": "some\nother thing for the whale-spout, as the event itself soon proved; for\nhardly had Ahab reached his perch; hardly was the rope belayed to its\npin on deck, when he struck the key-note to an orchestra, that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8098, "position": 8098, "text": "on deck, when he struck the key-note to an orchestra, that made the\nair vibrate as with the combined discharges of rifles. The triumphant\nhalloo of thirty buckskin lungs was heard, as—much nearer to the ship\nthan the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8099, "position": 8099, "text": "buckskin lungs was heard, as—much nearer to the ship\nthan the place of the imaginary jet, less than a mile ahead—Moby Dick\nbodily burst into view! For not by any calm and indolent spoutings; not\nby the", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8100, "position": 8100, "text": "For not by any calm and indolent spoutings; not\nby the peaceable gush of that mystic fountain in his head, did the\nWhite Whale now reveal his vicinity; but by the far more wondrous\nphenomenon of breaching", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8101, "position": 8101, "text": "; but by the far more wondrous\nphenomenon of breaching. Rising with his utmost velocity from the\nfurthest depths, the Sperm Whale thus booms his entire bulk into the\npure element of air, and piling up a mountain of dazzling foam", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8102, "position": 8102, "text": "the\npure element of air, and piling up a mountain of dazzling foam, shows\nhis place to the distance of seven miles and more. In those moments,\nthe torn, enraged waves he shakes off, seem his mane; in some cases,\nthis", "labels": {"50": 16, "100": 20, "250": 192, "500": 423, "1000": 875, "2000": 1374}}, {"id": 8103, "position": 8103, "text": "enraged waves he shakes off, seem his mane; in some cases,\nthis breaching is his act of defiance.\n\n“There she breaches! there she breaches!” was the cry, as in his\nimmeasurable bravadoes the", "labels": {"50": 45, "100": 64, "250": 49, "500": 78, "1000": 747, "2000": 1620}}, {"id": 8104, "position": 8104, "text": "was the cry, as in his\nimmeasurable bravadoes the White Whale tossed himself salmon-like to\nHeaven. So suddenly seen in the blue plain of the sea, and relieved\nagainst the still bluer margin of the sky, the spray", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8105, "position": 8105, "text": ", and relieved\nagainst the still bluer margin of the sky, the spray that he raised,\nfor the moment, intolerably glittered and glared like a glacier; and\nstood there gradually fading and fading away from its first sparkling\nintensity, to the", "labels": {"50": 16, "100": 78, "250": 205, "500": 469, "1000": 683, "2000": 889}}, {"id": 8106, "position": 8106, "text": "stood there gradually fading and fading away from its first sparkling\nintensity, to the dim mistiness of an advancing shower in a vale.\n\n“Aye, breach your last to the sun, Moby Dick!” cried Ahab, “thy hour\nand thy", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8107, "position": 8107, "text": ", Moby Dick!” cried Ahab, “thy hour\nand thy harpoon are at hand!—Down! down all of ye, but one man at the\nfore. The boats!—stand by!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8108, "position": 8108, "text": ". The boats!—stand by!”\n\nUnmindful of the tedious rope-ladders of the shrouds, the men, like\nshooting stars, slid to the deck, by the isolated backstays and\nhalyards; while", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 8109, "position": 8109, "text": "the deck, by the isolated backstays and\nhalyards; while Ahab, less dartingly, but still rapidly was dropped\nfrom his perch.\n\n“Lower away,” he cried, so soon as he had reached his boat—a spare", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8110, "position": 8110, "text": "” he cried, so soon as he had reached his boat—a spare one,\nrigged the afternoon previous. “Mr. Starbuck, the ship is thine—keep\naway from the boats, but keep near them. Lower, all!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8111, "position": 8111, "text": "away from the boats, but keep near them. Lower, all!”\n\nAs if to strike a quick terror into them, by this time being the first\nassailant himself, Moby Dick had turned, and was now coming for the\nthree crews", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8112, "position": 8112, "text": ", Moby Dick had turned, and was now coming for the\nthree crews. Ahab’s boat was central; and cheering his men, he told\nthem he would take the whale head-and-head,—that is, pull straight up", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8113, "position": 8113, "text": "the whale head-and-head,—that is, pull straight up\nto his forehead,—a not uncommon thing; for when within a certain limit,\nsuch a course excludes the coming onset from the whale’s sidelong\nvision", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8114, "position": 8114, "text": "excludes the coming onset from the whale’s sidelong\nvision. But ere that close limit was gained, and while yet all three\nboats were plain as the ship’s three masts to his eye; the White Whale\nchurning himself into furious", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8115, "position": 8115, "text": "s three masts to his eye; the White Whale\nchurning himself into furious speed, almost in an instant as it were,\nrushing among the boats with open jaws, and a lashing tail, offered\nappalling battle on every side; and hee", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8116, "position": 8116, "text": "lashing tail, offered\nappalling battle on every side; and heedless of the irons darted at him\nfrom every boat, seemed only intent on annihilating each separate plank\nof which those boats were made", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8117, "position": 8117, "text": "ting each separate plank\nof which those boats were made. But skilfully manœuvred, incessantly\nwheeling like trained chargers in the field; the boats for a while\neluded him; though, at times, but by a", "labels": {"50": 47, "100": 60, "250": 82, "500": 79, "1000": 559, "2000": 1200}}, {"id": 8118, "position": 8118, "text": "for a while\neluded him; though, at times, but by a plank’s breadth; while all the\ntime, Ahab’s unearthly slogan tore every other cry but his to shreds.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8119, "position": 8119, "text": "other cry but his to shreds.\n\nBut at last in his untraceable evolutions, the White Whale so crossed\nand recrossed, and in a thousand ways entangled the slack of the three\nlines now fast to him, that", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8120, "position": 8120, "text": "ways entangled the slack of the three\nlines now fast to him, that they foreshortened, and, of themselves,\nwarped the devoted boats towards the planted irons in him; though now\nfor a moment the whale drew aside a little,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8121, "position": 8121, "text": "in him; though now\nfor a moment the whale drew aside a little, as if to rally for a more\ntremendous charge. Seizing that opportunity, Ahab first paid out more\nline: and then was rapidly hauling and jerking in upon it again—hoping", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8122, "position": 8122, "text": "line: and then was rapidly hauling and jerking in upon it again—hoping\nthat way to disencumber it of some snarls—when lo!—a sight more savage\nthan the embattled teeth of sharks!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8123, "position": 8123, "text": "savage\nthan the embattled teeth of sharks!\n\nCaught and twisted—corkscrewed in the mazes of the line, loose harpoons\nand lances, with all their bristling barbs and points, came flashing\nand dripping up to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8124, "position": 8124, "text": "their bristling barbs and points, came flashing\nand dripping up to the chocks in the bows of Ahab’s boat. Only one\nthing could be done. Seizing the boat-knife, he critically reached\nwithin—through—and then", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8125, "position": 8125, "text": "Seizing the boat-knife, he critically reached\nwithin—through—and then, without—the rays of steel; dragged in the line\nbeyond, passed it, inboard, to the bowsman, and then, twice sundering\nthe rope near", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8126, "position": 8126, "text": "to the bowsman, and then, twice sundering\nthe rope near the chocks—dropped the intercepted fagot of steel into\nthe sea; and was all fast again. That instant, the White Whale made a\nsudden rush among the remaining", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8127, "position": 8127, "text": "again. That instant, the White Whale made a\nsudden rush among the remaining tangles of the other lines; by so\ndoing, irresistibly dragged the more involved boats of Stubb and Flask\ntowards his flukes; dashed them together like", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8128, "position": 8128, "text": "of Stubb and Flask\ntowards his flukes; dashed them together like two rolling husks on a\nsurf-beaten beach, and then, diving down into the sea, disappeared in a\nboiling maelstrom, in which, for a space", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8129, "position": 8129, "text": ", disappeared in a\nboiling maelstrom, in which, for a space, the odorous cedar chips of\nthe wrecks danced round and round, like the grated nutmeg in a swiftly\nstirred bowl of punch.", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 327, "2000": 967}}, {"id": 8130, "position": 8130, "text": "meg in a swiftly\nstirred bowl of punch.\n\nWhile the two crews were yet circling in the waters, reaching out after\nthe revolving line-tubs, oars, and other floating furniture, while\naslope little Flask bobbed up and down", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 8131, "position": 8131, "text": "other floating furniture, while\naslope little Flask bobbed up and down like an empty vial, twitching\nhis legs upwards to escape the dreaded jaws of sharks; and Stubb was\nlustily singing out for some one to ladle him up;", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8132, "position": 8132, "text": "bb was\nlustily singing out for some one to ladle him up; and while the old\nman’s line—now parting—admitted of his pulling into the creamy pool to\nrescue whom he could;—in that wild simultaneousness of a thousand", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 967}}, {"id": 8133, "position": 8133, "text": "to\nrescue whom he could;—in that wild simultaneousness of a thousand\nconcreted perils,—Ahab’s yet unstricken boat seemed drawn up towards\nHeaven by invisible wires,—as, arrow-like, shooting perpendicularly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8134, "position": 8134, "text": "Heaven by invisible wires,—as, arrow-like, shooting perpendicularly\nfrom the sea, the White Whale dashed his broad forehead against its\nbottom, and sent it, turning over and over, into the air; till it fell\nagain—gunwal", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8135, "position": 8135, "text": "over and over, into the air; till it fell\nagain—gunwale downwards—and Ahab and his men struggled out from under\nit, like seals from a sea-side cave.\n\nThe first uprising momentum of the whale—modifying its direction", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8136, "position": 8136, "text": "-side cave.\n\nThe first uprising momentum of the whale—modifying its direction as he\nstruck the surface—involuntarily launched him along it, to a little\ndistance from the centre of the destruction he had made; and with his\nback to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8137, "position": 8137, "text": "from the centre of the destruction he had made; and with his\nback to it, he now lay for a moment slowly feeling with his flukes from\nside to side; and whenever a stray oar, bit of plank, the least chip or\ncr", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8138, "position": 8138, "text": "whenever a stray oar, bit of plank, the least chip or\ncrumb of the boats touched his skin, his tail swiftly drew back, and\ncame sideways smiting the sea. But soon, as if satisfied that his work\nfor that time was", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 8139, "position": 8139, "text": "sea. But soon, as if satisfied that his work\nfor that time was done, he pushed his pleated forehead through the\nocean, and trailing after him the intertangled lines, continued his\nleeward way at a traveller’s methodic pace.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 723, "2000": 489}}, {"id": 8140, "position": 8140, "text": ", continued his\nleeward way at a traveller’s methodic pace.\n\nAs before, the attentive ship having descried the whole fight, again\ncame bearing down to the rescue, and dropping a boat, picked up the\nfloating mariners,", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 142}}, {"id": 8141, "position": 8141, "text": "to the rescue, and dropping a boat, picked up the\nfloating mariners, tubs, oars, and whatever else could be caught at,\nand safely landed them on her decks. Some sprained shoulders, wrists,\nand ankles; livid con", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 887}}, {"id": 8142, "position": 8142, "text": "decks. Some sprained shoulders, wrists,\nand ankles; livid contusions; wrenched harpoons and lances;\ninextricable intricacies of rope; shattered oars and planks; all these\nwere there; but no fatal", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 8143, "position": 8143, "text": "shattered oars and planks; all these\nwere there; but no fatal or even serious ill seemed to have befallen\nany one. As with Fedallah the day before, so Ahab was now found grimly\nclinging to his boat’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8144, "position": 8144, "text": "before, so Ahab was now found grimly\nclinging to his boat’s broken half, which afforded a comparatively easy\nfloat; nor did it so exhaust him as the previous day’s mishap.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8145, "position": 8145, "text": "’s mishap.\n\nBut when he was helped to the deck, all eyes were fastened upon him; as\ninstead of standing by himself he still half-hung upon the shoulder of\nStarbuck, who had thus far been the foremost to assist him", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8146, "position": 8146, "text": "shoulder of\nStarbuck, who had thus far been the foremost to assist him. His ivory\nleg had been snapped off, leaving but one short sharp splinter.\n\n“Aye, aye, Starbuck, ’tis sweet to lean sometimes, be the leaner", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8147, "position": 8147, "text": ", Starbuck, ’tis sweet to lean sometimes, be the leaner who he\nwill; and would old Ahab had leaned oftener than he has.”\n\n“The ferrule has not stood, sir,” said the carpenter, now", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8148, "position": 8148, "text": "ferrule has not stood, sir,” said the carpenter, now coming up; “I\nput good work into that leg.”\n\n“But no bones broken, sir, I hope,” said Stubb with true concern.", "labels": {"50": 23, "100": 88, "250": 219, "500": 221, "1000": 317, "2000": 1087}}, {"id": 8149, "position": 8149, "text": ", I hope,” said Stubb with true concern.\n\n“Aye! and all splintered to pieces, Stubb!—d’ye see it.—But even with a\nbroken bone, old Ahab is untouched; and I account no", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8150, "position": 8150, "text": "with a\nbroken bone, old Ahab is untouched; and I account no living bone of\nmine one jot more me, than this dead one that’s lost. Nor white whale,\nnor man, nor fiend, can so much as graz", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8151, "position": 8151, "text": "white whale,\nnor man, nor fiend, can so much as graze old Ahab in his own proper and\ninaccessible being. Can any lead touch yonder floor, any mast scrape\nyonder roof?—Aloft there! which way?", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8152, "position": 8152, "text": "any mast scrape\nyonder roof?—Aloft there! which way?”\n\n“Dead to leeward, sir.”\n\n“Up helm, then; pile on the sail again, ship keepers! down the rest of\nthe spare boats and rig them", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8153, "position": 8153, "text": "again, ship keepers! down the rest of\nthe spare boats and rig them—Mr. Starbuck away, and muster the boat’s\ncrews.”\n\n“Let me first help thee towards the bulwarks, sir.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8154, "position": 8154, "text": "help thee towards the bulwarks, sir.”\n\n“Oh, oh, oh! how this splinter gores me now! Accursed fate! that the\nunconquerable captain in the soul should have such a craven mate!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8155, "position": 8155, "text": "conquerable captain in the soul should have such a craven mate!”\n\n“Sir?”\n\n“My body, man, not thee. Give me something for a cane—there, that\nshivered lance will do. Muster the men", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 8156, "position": 8156, "text": "there, that\nshivered lance will do. Muster the men. Surely I have not seen him yet.\nBy heaven it cannot be!—missing?—quick! call them all.”\n\nThe old man’s hinted thought was true", "labels": {"50": 18, "100": 87, "250": 102, "500": 205, "1000": 317, "2000": 1951}}, {"id": 8157, "position": 8157, "text": ".”\n\nThe old man’s hinted thought was true. Upon mustering the company, the\nParsee was not there.\n\n“The Parsee!” cried Stubb—“he must have been caught in——”", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 642, "2000": 160}}, {"id": 8158, "position": 8158, "text": "“he must have been caught in——”\n\n“The black vomit wrench thee!—run all of ye above, alow, cabin,\nforecastle—find him—not gone—not gone!”", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 54, "2000": 324}}, {"id": 8159, "position": 8159, "text": "—not gone—not gone!”\n\nBut quickly they returned to him with the tidings that the Parsee was\nnowhere to be found.\n\n“Aye, sir,” said Stubb—“caught among the tangles of your line—I", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8160, "position": 8160, "text": "said Stubb—“caught among the tangles of your line—I thought\nI saw him dragging under.”\n\n“_My_ line! _my_ line? Gone?—gone? What means that little word?—What\ndeath-kn", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8161, "position": 8161, "text": "?—gone? What means that little word?—What\ndeath-knell rings in it, that old Ahab shakes as if he were the belfry.\nThe harpoon, too!—toss over the litter there,—d’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8162, "position": 8162, "text": "harpoon, too!—toss over the litter there,—d’ye see it?—the forged\niron, men, the white whale’s—no, no, no,—blistered fool! this hand did\ndart it!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8163, "position": 8163, "text": ", no,—blistered fool! this hand did\ndart it!—’tis in the fish!—Aloft there! Keep him nailed—Quick!—all\nhands to the rigging of the boats—collect the oars—harp", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8164, "position": 8164, "text": "hands to the rigging of the boats—collect the oars—harpooneers! the\nirons, the irons!—hoist the royals higher—a pull on all the\nsheets!—helm there! steady, steady for your life", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8165, "position": 8165, "text": "on all the\nsheets!—helm there! steady, steady for your life! I’ll ten times girdle\nthe unmeasured globe; yea and dive straight through it, but I’ll slay\nhim yet!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8166, "position": 8166, "text": "straight through it, but I’ll slay\nhim yet!”\n\n“Great God! but for one single instant show thyself,” cried Starbuck;\n“never, never wilt thou capture him, old man—In Jesus’ name", "labels": {"50": 9, "100": 26, "250": 133, "500": 180, "1000": 272, "2000": 1620}}, {"id": 8167, "position": 8167, "text": ", never wilt thou capture him, old man—In Jesus’ name no more of\nthis, that’s worse than devil’s madness. Two days chased; twice stove\nto splinters; thy very leg once more snatched from under thee;", "labels": {"50": 9, "100": 26, "250": 120, "500": 180, "1000": 672, "2000": 39}}, {"id": 8168, "position": 8168, "text": "stove\nto splinters; thy very leg once more snatched from under thee; thy evil\nshadow gone—all good angels mobbing thee with warnings:—what more\nwouldst thou have?—Shall we keep chasing this murderous fish till he\nswamps the last", "labels": {"50": 9, "100": 64, "250": 30, "500": 72, "1000": 692, "2000": 982}}, {"id": 8169, "position": 8169, "text": "have?—Shall we keep chasing this murderous fish till he\nswamps the last man? Shall we be dragged by him to the bottom of the\nsea? Shall we be towed by him to the infernal world? Oh, oh,—Impie", "labels": {"50": 9, "100": 26, "250": 42, "500": 225, "1000": 589, "2000": 216}}, {"id": 8170, "position": 8170, "text": "him to the infernal world? Oh, oh,—Impiety\nand blasphemy to hunt him more!”\n\n“Starbuck, of late I’ve felt strangely moved to thee; ever since that\nhour we both saw—", "labels": {"50": 36, "100": 45, "250": 245, "500": 141, "1000": 641, "2000": 1459}}, {"id": 8171, "position": 8171, "text": "ve felt strangely moved to thee; ever since that\nhour we both saw—thou know’st what, in one another’s eyes. But in this\nmatter of the whale, be the front of thy face to me as the palm of this\nhand", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8172, "position": 8172, "text": ", be the front of thy face to me as the palm of this\nhand—a lipless, unfeatured blank. Ahab is for ever Ahab, man. This\nwhole act’s immutably decreed", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8173, "position": 8173, "text": ". This\nwhole act’s immutably decreed. ’Twas rehearsed by thee and me a billion\nyears before this ocean rolled. Fool! I am the Fates’ lieutenant; I act\nunder orders", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 8174, "position": 8174, "text": "’ lieutenant; I act\nunder orders. Look thou, underling! that thou obeyest mine.—Stand round\nme, men. Ye see an old man cut down to the stump; leaning on a shivered\nlance; propped up on a lonely foot", "labels": {"50": 9, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 967}}, {"id": 8175, "position": 8175, "text": "the stump; leaning on a shivered\nlance; propped up on a lonely foot. ’Tis Ahab—his body’s part; but\nAhab’s soul’s a centipede, that moves upon a hundred legs", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8176, "position": 8176, "text": "a centipede, that moves upon a hundred legs. I feel\nstrained, half stranded, as ropes that tow dismasted frigates in a\ngale; and I may look so. But ere I break, ye’ll hear me crack;", "labels": {"50": 9, "100": 73, "250": 193, "500": 498, "1000": 637, "2000": 1886}}, {"id": 8177, "position": 8177, "text": "so. But ere I break, ye’ll hear me crack; and till\nye hear _that_, know that Ahab’s hawser tows his purpose yet. Believe\nye, men, in the things called omens?", "labels": {"50": 9, "100": 26, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8178, "position": 8178, "text": "purpose yet. Believe\nye, men, in the things called omens? Then laugh aloud, and cry encore!\nFor ere they drown, drowning things will twice rise to the surface;\nthen rise again, to sink for evermore", "labels": {"50": 9, "100": 26, "250": 141, "500": 143, "1000": 437, "2000": 1859}}, {"id": 8179, "position": 8179, "text": "the surface;\nthen rise again, to sink for evermore. So with Moby Dick—two days he’s\nfloated—tomorrow will be the third. Aye, men, he’ll rise once more,—but\nonly to spout his", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8180, "position": 8180, "text": ", he’ll rise once more,—but\nonly to spout his last! D’ye feel brave men, brave?”\n\n“As fearless fire,” cried Stubb.\n\n“And as mechanical,” muttered Ahab", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8181, "position": 8181, "text": "bb.\n\n“And as mechanical,” muttered Ahab. Then as the men went forward, he\nmuttered on: “The things called omens! And yesterday I talked the same\nto Starbuck there, concerning my broken boat", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8182, "position": 8182, "text": "same\nto Starbuck there, concerning my broken boat. Oh! how valiantly I seek\nto drive out of others’ hearts what’s clinched so fast in mine!—The\nParsee—the Parsee!—gone, gone? and he", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8183, "position": 8183, "text": "The\nParsee—the Parsee!—gone, gone? and he was to go before:—but still was\nto be seen again ere I could perish—How’s that?—There’s a riddle now\nmight baffle", "labels": {"50": 16, "100": 73, "250": 120, "500": 498, "1000": 50, "2000": 16}}, {"id": 8184, "position": 8184, "text": "How’s that?—There’s a riddle now\nmight baffle all the lawyers backed by the ghosts of the whole line of\njudges:—like a hawk’s beak it pecks my brain", "labels": {"50": 6, "100": 1, "250": 193, "500": 498, "1000": 849, "2000": 421}}, {"id": 8185, "position": 8185, "text": "beak it pecks my brain. _I’ll_, _I’ll_ solve it,\nthough!”\n\nWhen dusk descended, the whale was still in sight to leeward.\n\nSo once more the sail was shortened, and everything passed nearly", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8186, "position": 8186, "text": "leeward.\n\nSo once more the sail was shortened, and everything passed nearly as on\nthe previous night; only, the sound of hammers, and the hum of the\ngrindstone was heard till nearly daylight, as the men toiled by\nlanterns in", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1028}}, {"id": 8187, "position": 8187, "text": "stone was heard till nearly daylight, as the men toiled by\nlanterns in the complete and careful rigging of the spare boats and\nsharpening their fresh weapons for the morrow. Meantime, of the broken\nkeel of Ahab’s wrecked craft the carpenter", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8188, "position": 8188, "text": "Meantime, of the broken\nkeel of Ahab’s wrecked craft the carpenter made him another leg; while\nstill as on the night before, slouched Ahab stood fixed within his\nscuttle; his hid, heliotrope glance anticipating", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8189, "position": 8189, "text": "within his\nscuttle; his hid, heliotrope glance anticipatingly gone backward on its\ndial; sat due eastward for the earliest sun.\n\n\nCHAPTER 135. The Chase.—Third Day.\n\nThe morning of the third day dawned fair and fresh", "labels": {"50": 9, "100": 26, "250": 141, "500": 73, "1000": 859, "2000": 1307}}, {"id": 8190, "position": 8190, "text": ".—Third Day.\n\nThe morning of the third day dawned fair and fresh, and once more the\nsolitary night-man at the fore-mast-head was relieved by crowds of the\ndaylight look-outs, who dotted every mast and almost every spa", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1014}}, {"id": 8191, "position": 8191, "text": "of the\ndaylight look-outs, who dotted every mast and almost every spar.\n\n“D’ye see him?” cried Ahab; but the whale was not yet in sight.\n\n“In his infallible wake, though; but follow", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8192, "position": 8192, "text": "in sight.\n\n“In his infallible wake, though; but follow that wake, that’s all. Helm\nthere; steady, as thou goest, and hast been going. What a lovely day\nagain! were it a new-", "labels": {"50": 16, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 8193, "position": 8193, "text": "t been going. What a lovely day\nagain! were it a new-made world, and made for a summer-house to the\nangels, and this morning the first of its throwing open to them, a\nfairer day could not dawn upon that", "labels": {"50": 16, "100": 20, "250": 132, "500": 412, "1000": 914, "2000": 913}}, {"id": 8194, "position": 8194, "text": "its throwing open to them, a\nfairer day could not dawn upon that world. Here’s food for thought, had\nAhab time to think; but Ahab never thinks; he only feels, feels, feels;\n_that’s_", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8195, "position": 8195, "text": "thinks; he only feels, feels, feels;\n_that’s_ tingling enough for mortal man! to think’s audacity. God only\nhas that right and privilege. Thinking is, or ought to be, a coolness\nand a", "labels": {"50": 6, "100": 1, "250": 42, "500": 307, "1000": 343, "2000": 761}}, {"id": 8196, "position": 8196, "text": "privilege. Thinking is, or ought to be, a coolness\nand a calmness; and our poor hearts throb, and our poor brains beat too\nmuch for that. And yet, I’ve sometimes thought my brain was very\ncalm—", "labels": {"50": 31, "100": 20, "250": 132, "500": 280, "1000": 27, "2000": 1483}}, {"id": 8197, "position": 8197, "text": ". And yet, I’ve sometimes thought my brain was very\ncalm—frozen calm, this old skull cracks so, like a glass in which the\ncontents turned to ice, and shiver it. And still this hair is growing\nnow; this moment growing", "labels": {"50": 25, "100": 13, "250": 182, "500": 353, "1000": 113, "2000": 139}}, {"id": 8198, "position": 8198, "text": "and shiver it. And still this hair is growing\nnow; this moment growing, and heat must breed it; but no, it’s like\nthat sort of common grass that will grow anywhere, between the earthy\nclefts of Greenland ice or", "labels": {"50": 31, "100": 7, "250": 69, "500": 453, "1000": 581, "2000": 1828}}, {"id": 8199, "position": 8199, "text": "will grow anywhere, between the earthy\nclefts of Greenland ice or in Vesuvius lava. How the wild winds blow\nit; they whip it about me as the torn shreds of split sails lash the\ntossed ship they cling to", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 185, "2000": 709}}, {"id": 8200, "position": 8200, "text": "torn shreds of split sails lash the\ntossed ship they cling to. A vile wind that has no doubt blown ere this\nthrough prison corridors and cells, and wards of hospitals, and\nventilated them, and now comes blowing hither", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 437, "2000": 573}}, {"id": 8201, "position": 8201, "text": "of hospitals, and\nventilated them, and now comes blowing hither as innocent as fleeces.\nOut upon it!—it’s tainted. Were I the wind, I’d blow no more on such a\nwicked, miserable world", "labels": {"50": 16, "100": 73, "250": 133, "500": 414, "1000": 437, "2000": 709}}, {"id": 8202, "position": 8202, "text": ", I’d blow no more on such a\nwicked, miserable world. I’d crawl somewhere to a cave, and slink\nthere. And yet, ’tis a noble and heroic thing, the wind! who ever\nconquered it? In every", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 193}}, {"id": 8203, "position": 8203, "text": "noble and heroic thing, the wind! who ever\nconquered it? In every fight it has the last and bitterest blow. Run\ntilting at it, and you but run through it. Ha! a coward wind that\nstrikes stark naked men, but will", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 463}}, {"id": 8204, "position": 8204, "text": "it. Ha! a coward wind that\nstrikes stark naked men, but will not stand to receive a single blow.\nEven Ahab is a braver thing—a nobler thing than _that_. Would now the\nwind but had a body;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8205, "position": 8205, "text": "thing than _that_. Would now the\nwind but had a body; but all the things that most exasperate and\noutrage mortal man, all these things are bodiless, but only bodiless as\nobjects, not as agents", "labels": {"50": 9, "100": 26, "250": 120, "500": 498, "1000": 343, "2000": 761}}, {"id": 8206, "position": 8206, "text": "diless, but only bodiless as\nobjects, not as agents. There’s a most special, a most cunning, oh, a\nmost malicious difference! And yet, I say again, and swear it now, that\nthere’s something", "labels": {"50": 39, "100": 8, "250": 0, "500": 98, "1000": 798, "2000": 935}}, {"id": 8207, "position": 8207, "text": ", I say again, and swear it now, that\nthere’s something all glorious and gracious in the wind. These warm\nTrade Winds, at least, that in the clear heavens blow straight on, in\nstrong and steadfast, vigorous mild", "labels": {"50": 8, "100": 14, "250": 58, "500": 280, "1000": 42, "2000": 1031}}, {"id": 8208, "position": 8208, "text": "clear heavens blow straight on, in\nstrong and steadfast, vigorous mildness; and veer not from their mark,\nhowever the baser currents of the sea may turn and tack, and mightiest\nMississippies of the land swift and swer", "labels": {"50": 9, "100": 73, "250": 133, "500": 143, "1000": 437, "2000": 1374}}, {"id": 8209, "position": 8209, "text": "and tack, and mightiest\nMississippies of the land swift and swerve about, uncertain where to go\nat last. And by the eternal Poles! these same Trades that so directly\nblow my good ship on; these Trades, or something like them", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 916, "2000": 16}}, {"id": 8210, "position": 8210, "text": "so directly\nblow my good ship on; these Trades, or something like them—something so\nunchangeable, and full as strong, blow my keeled soul along! To it!\nAloft there! What d’ye see?”", "labels": {"50": 9, "100": 26, "250": 133, "500": 498, "1000": 50, "2000": 1620}}, {"id": 8211, "position": 8211, "text": "To it!\nAloft there! What d’ye see?”\n\n“Nothing, sir.”\n\n“Nothing! and noon at hand! The doubloon goes a-begging! See the sun!\nAye, aye, it must be so", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8212, "position": 8212, "text": "-begging! See the sun!\nAye, aye, it must be so. I’ve oversailed him. How, got the start? Aye,\nhe’s chasing _me_ now; not I, _him_—that’s", "labels": {"50": 6, "100": 1, "250": 136, "500": 180, "1000": 272, "2000": 916}}, {"id": 8213, "position": 8213, "text": "_me_ now; not I, _him_—that’s bad; I might have known it,\ntoo. Fool! the lines—the harpoons he’s towing. Aye, aye, I have run him\nby last night", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8214, "position": 8214, "text": "s towing. Aye, aye, I have run him\nby last night. About! about! Come down, all of ye, but the regular look\nouts! Man the braces!”\n\nSteering as she had done, the wind had been somewhat on", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8215, "position": 8215, "text": "s!”\n\nSteering as she had done, the wind had been somewhat on the Pequod’s\nquarter, so that now being pointed in the reverse direction, the braced\nship sailed hard upon the breeze as she rechurned the cream in her", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 8216, "position": 8216, "text": "ship sailed hard upon the breeze as she rechurned the cream in her own\nwhite wake.\n\n“Against the wind he now steers for the open jaw,” murmured Starbuck to\nhimself, as he coiled the new-hauled main-brace upon", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8217, "position": 8217, "text": "buck to\nhimself, as he coiled the new-hauled main-brace upon the rail. “God\nkeep us, but already my bones feel damp within me, and from the inside\nwet my flesh. I misdoubt me that I disobey", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8218, "position": 8218, "text": "inside\nwet my flesh. I misdoubt me that I disobey my God in obeying him!”\n\n“Stand by to sway me up!” cried Ahab, advancing to the hempen basket", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8219, "position": 8219, "text": ", advancing to the hempen basket.\n“We should meet him soon.”\n\n“Aye, aye, sir,” and straightway Starbuck did Ahab’s bidding, and once\nmore Ahab swung on high.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8220, "position": 8220, "text": ", and once\nmore Ahab swung on high.\n\nA whole hour now passed; gold-beaten out to ages. Time itself now held\nlong breaths with keen suspense. But at last, some three points off the\nweather bow, Ahab descried", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8221, "position": 8221, "text": "last, some three points off the\nweather bow, Ahab descried the spout again, and instantly from the\nthree mast-heads three shrieks went up as if the tongues of fire had\nvoiced it.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8222, "position": 8222, "text": "the tongues of fire had\nvoiced it.\n\n“Forehead to forehead I meet thee, this third time, Moby Dick! On deck\nthere!—brace sharper up; crowd her into the wind’s eye", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8223, "position": 8223, "text": "her into the wind’s eye. He’s too far\noff to lower yet, Mr. Starbuck. The sails shake! Stand over that\nhelmsman with a top-maul! So, so; he travels fast, and I must", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8224, "position": 8224, "text": "-maul! So, so; he travels fast, and I must down. But\nlet me have one more good round look aloft here at the sea; there’s\ntime for that. An old, old sight, and yet somehow so", "labels": {"50": 45, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 16}}, {"id": 8225, "position": 8225, "text": "s\ntime for that. An old, old sight, and yet somehow so young; aye, and\nnot changed a wink since I first saw it, a boy, from the sand-hills of\nNantucket! The same!—the same!—", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 8226, "position": 8226, "text": "sand-hills of\nNantucket! The same!—the same!—the same to Noah as to me. There’s a\nsoft shower to leeward. Such lovely leewardings! They must lead\nsomewhere—to something else than common land", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 9, "2000": 1620}}, {"id": 8227, "position": 8227, "text": "leewardings! They must lead\nsomewhere—to something else than common land, more palmy than the\npalms. Leeward! the white whale goes that way; look to windward, then;\nthe better if the bitterer quarter", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8228, "position": 8228, "text": "windward, then;\nthe better if the bitterer quarter. But good bye, good bye, old\nmast-head! What’s this?—green? aye, tiny mosses in these warped cracks", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 8229, "position": 8229, "text": "tiny mosses in these warped cracks.\nNo such green weather stains on Ahab’s head! There’s the difference now\nbetween man’s old age and matter’s. But aye, old mast, we both grow old\ntogether; sound", "labels": {"50": 16, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8230, "position": 8230, "text": "s. But aye, old mast, we both grow old\ntogether; sound in our hulls, though, are we not, my ship? Aye, minus a\nleg, that’s all. By heaven this dead wood has the better of my", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8231, "position": 8231, "text": "that’s all. By heaven this dead wood has the better of my live\nflesh every way. I can’t compare with it; and I’ve known some ships\nmade of dead trees outlast the lives of men made of the most", "labels": {"50": 45, "100": 64, "250": 138, "500": 432, "1000": 327, "2000": 1192}}, {"id": 8232, "position": 8232, "text": "made of dead trees outlast the lives of men made of the most vital\nstuff of vital fathers. What’s that he said? he should still go before\nme, my pilot; and yet to be seen again? But where? Will I", "labels": {"50": 16, "100": 64, "250": 91, "500": 276, "1000": 533, "2000": 1860}}, {"id": 8233, "position": 8233, "text": "my pilot; and yet to be seen again? But where? Will I have eyes at\nthe bottom of the sea, supposing I descend those endless stairs? and\nall night I’ve been sailing from him, wherever he did sink to", "labels": {"50": 16, "100": 5, "250": 45, "500": 388, "1000": 964, "2000": 1860}}, {"id": 8234, "position": 8234, "text": "night I’ve been sailing from him, wherever he did sink to. Aye,\naye, like many more thou told’st direful truth as touching thyself, O\nParsee; but, Ahab, there thy shot fell short", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8235, "position": 8235, "text": "O\nParsee; but, Ahab, there thy shot fell short. Good-bye, mast-head—keep\na good eye upon the whale, the while I’m gone. We’ll talk to-morrow,\nnay, to-", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8236, "position": 8236, "text": "m gone. We’ll talk to-morrow,\nnay, to-night, when the white whale lies down there, tied by head and\ntail.”\n\nHe gave the word; and still gazing round him, was steadily lowered\nthrough the cloven", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8237, "position": 8237, "text": "word; and still gazing round him, was steadily lowered\nthrough the cloven blue air to the deck.\n\nIn due time the boats were lowered; but as standing in his shallop’s\nstern, Ahab just hovered upon the point of the descent", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8238, "position": 8238, "text": "op’s\nstern, Ahab just hovered upon the point of the descent, he waved to the\nmate,—who held one of the tackle-ropes on deck—and bade him pause.\n\n“Starbuck!”\n\n“Sir?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8239, "position": 8239, "text": "bade him pause.\n\n“Starbuck!”\n\n“Sir?”\n\n“For the third time my soul’s ship starts upon this voyage, Starbuck.”\n\n“Aye, sir, thou wilt have it so.”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8240, "position": 8240, "text": ", sir, thou wilt have it so.”\n\n“Some ships sail from their ports, and ever afterwards are missing,\nStarbuck!”\n\n“Truth, sir: saddest truth.”\n\n“Some men die at ebb tide; some", "labels": {"50": 9, "100": 73, "250": 133, "500": 498, "1000": 437, "2000": 16}}, {"id": 8241, "position": 8241, "text": "dest truth.”\n\n“Some men die at ebb tide; some at low water; some at the full of the\nflood;—and I feel now like a billow that’s all one crested comb,\nStarbuck", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 8242, "position": 8242, "text": "ow that’s all one crested comb,\nStarbuck. I am old;—shake hands with me, man.”\n\nTheir hands met; their eyes fastened; Starbuck’s tears the glue.", "labels": {"50": 45, "100": 64, "250": 163, "500": 432, "1000": 327, "2000": 967}}, {"id": 8243, "position": 8243, "text": "’s tears the glue.\n\n“Oh, my captain, my captain!—noble heart—go not—go not!—see, it’s a\nbrave man that weeps; how great the agony of the persuasion then!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 851, "2000": 967}}, {"id": 8244, "position": 8244, "text": "weeps; how great the agony of the persuasion then!”\n\n“Lower away!”—cried Ahab, tossing the mate’s arm from him. “Stand by\nthe crew!”\n\nIn an instant the boat was pulling round close under the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8245, "position": 8245, "text": "the crew!”\n\nIn an instant the boat was pulling round close under the stern.\n\n“The sharks! the sharks!” cried a voice from the low cabin-window\nthere; “O master, my master, come back!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 8246, "position": 8246, "text": "; “O master, my master, come back!”\n\nBut Ahab heard nothing; for his own voice was high-lifted then; and the\nboat leaped on.\n\nYet the voice spake true; for scarce had he pushed from the ship,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8247, "position": 8247, "text": "the voice spake true; for scarce had he pushed from the ship, when\nnumbers of sharks, seemingly rising from out the dark waters beneath\nthe hull, maliciously snapped at the blades of the oars, every time\nthey dipped in the water;", "labels": {"50": 45, "100": 55, "250": 138, "500": 72, "1000": 99, "2000": 1620}}, {"id": 8248, "position": 8248, "text": "the blades of the oars, every time\nthey dipped in the water; and in this way accompanied the boat with\ntheir bites. It is a thing not uncommonly happening to the whale-boats\nin those swarming seas; the sharks at times apparently", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8249, "position": 8249, "text": "the whale-boats\nin those swarming seas; the sharks at times apparently following them\nin the same prescient way that vultures hover over the banners of\nmarching regiments in the east. But these were the first sharks that\nhad been observed by", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8250, "position": 8250, "text": "in the east. But these were the first sharks that\nhad been observed by the Pequod since the White Whale had been first\ndescried; and whether it was that Ahab’s crew were all such\ntiger-yellow barbarians, and therefore", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8251, "position": 8251, "text": "Ahab’s crew were all such\ntiger-yellow barbarians, and therefore their flesh more musky to the\nsenses of the sharks—a matter sometimes well known to affect\nthem,—however it was, they seemed to follow that one boat without\nmole", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8252, "position": 8252, "text": ",—however it was, they seemed to follow that one boat without\nmolesting the others.\n\n“Heart of wrought steel!” murmured Starbuck gazing over the side, and\nfollowing with his eyes the receding boat—“canst thou yet", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8253, "position": 8253, "text": "and\nfollowing with his eyes the receding boat—“canst thou yet ring boldly\nto that sight?—lowering thy keel among ravening sharks, and followed by\nthem, open-mouthed to the chase; and this the critical third day?", "labels": {"50": 9, "100": 26, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8254, "position": 8254, "text": ", open-mouthed to the chase; and this the critical third day?—For\nwhen three days flow together in one continuous intense pursuit; be\nsure the first is the morning, the second the noon, and the third the\nevening and the end of", "labels": {"50": 1, "100": 18, "250": 44, "500": 19, "1000": 499, "2000": 629}}, {"id": 8255, "position": 8255, "text": ", the second the noon, and the third the\nevening and the end of that thing—be that end what it may. Oh! my God!\nwhat is this that shoots through me, and leaves me so deadly calm, yet\nexpectant,—", "labels": {"50": 16, "100": 5, "250": 205, "500": 3, "1000": 51, "2000": 742}}, {"id": 8256, "position": 8256, "text": "through me, and leaves me so deadly calm, yet\nexpectant,—fixed at the top of a shudder! Future things swim before me,\nas in empty outlines and skeletons; all the past is somehow grown dim", "labels": {"50": 16, "100": 20, "250": 132, "500": 334, "1000": 747, "2000": 1710}}, {"id": 8257, "position": 8257, "text": "; all the past is somehow grown dim.\nMary, girl! thou fadest in pale glories behind me; boy! I seem to see\nbut thy eyes grown wondrous blue. Strangest problems of life seem\nclearing; but clouds sweep", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 185, "2000": 1203}}, {"id": 8258, "position": 8258, "text": "drous blue. Strangest problems of life seem\nclearing; but clouds sweep between—Is my journey’s end coming? My legs\nfeel faint; like his who has footed it all day. Feel thy heart,—beats\nit yet? Stir thy", "labels": {"50": 16, "100": 73, "250": 15, "500": 441, "1000": 779, "2000": 1203}}, {"id": 8259, "position": 8259, "text": "it all day. Feel thy heart,—beats\nit yet? Stir thyself, Starbuck!—stave it off—move, move! speak\naloud!—Mast-head there! See ye my boy’s hand on the hill", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8260, "position": 8260, "text": "Mast-head there! See ye my boy’s hand on the hill?—Crazed;—aloft\nthere!—keep thy keenest eye upon the boats:—mark well the whale!—Ho!\nagain!—drive off that hawk", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8261, "position": 8261, "text": "mark well the whale!—Ho!\nagain!—drive off that hawk! see! he pecks—he tears the vane”—pointing\nto the red flag flying at the main-truck—“Ha! he soars away with\nit!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8262, "position": 8262, "text": "the main-truck—“Ha! he soars away with\nit!—Where’s the old man now? see’st thou that sight, oh Ahab!—shudder,\nshudder!”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8263, "position": 8263, "text": "—shudder,\nshudder!”\n\nThe boats had not gone very far, when by a signal from the mast-heads—a\ndownward pointed arm, Ahab knew that the whale had sounded; but\nintending to be near him at the next rising, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8264, "position": 8264, "text": "had sounded; but\nintending to be near him at the next rising, he held on his way a\nlittle sideways from the vessel; the becharmed crew maintaining the\nprofoundest silence, as the head-beat waves hammered and hammered\nagainst the opposing bow", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8265, "position": 8265, "text": "silence, as the head-beat waves hammered and hammered\nagainst the opposing bow.\n\n“Drive, drive in your nails, oh ye waves! to their uttermost heads\ndrive them in! ye but strike a thing without a lid; and no coffin and", "labels": {"50": 45, "100": 64, "250": 240, "500": 28, "1000": 520, "2000": 16}}, {"id": 8266, "position": 8266, "text": "in! ye but strike a thing without a lid; and no coffin and\nno hearse can be mine:—and hemp only can kill me! Ha! ha!”\n\nSuddenly the waters around them slowly swelled in broad circles; then\nquickly up", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 8267, "position": 8267, "text": "”\n\nSuddenly the waters around them slowly swelled in broad circles; then\nquickly upheaved, as if sideways sliding from a submerged berg of ice,\nswiftly rising to the surface. A low rumbling sound was heard; a\nsubterraneous hum; and", "labels": {"50": 45, "100": 55, "250": 171, "500": 48, "1000": 377, "2000": 207}}, {"id": 8268, "position": 8268, "text": "A low rumbling sound was heard; a\nsubterraneous hum; and then all held their breaths; as bedraggled with\ntrailing ropes, and harpoons, and lances, a vast form shot lengthwise,\nbut obliquely from the sea", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 8269, "position": 8269, "text": "s, a vast form shot lengthwise,\nbut obliquely from the sea. Shrouded in a thin drooping veil of mist,\nit hovered for a moment in the rainbowed air; and then fell swamping\nback into the deep", "labels": {"50": 25, "100": 5, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 8270, "position": 8270, "text": "rainbowed air; and then fell swamping\nback into the deep. Crushed thirty feet upwards, the waters flashed for\nan instant like heaps of fountains, then brokenly sank in a shower of\nflakes, leaving the circling surface creamed like new", "labels": {"50": 37, "100": 55, "250": 192, "500": 162, "1000": 99, "2000": 1111}}, {"id": 8271, "position": 8271, "text": "in a shower of\nflakes, leaving the circling surface creamed like new milk round the\nmarble trunk of the whale.\n\n“Give way!” cried Ahab to the oarsmen, and the boats darted forward to\nthe attack; but maddened", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8272, "position": 8272, "text": "arsmen, and the boats darted forward to\nthe attack; but maddened by yesterday’s fresh irons that corroded in\nhim, Moby Dick seemed combinedly possessed by all the angels that fell\nfrom heaven", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8273, "position": 8273, "text": "possessed by all the angels that fell\nfrom heaven. The wide tiers of welded tendons overspreading his broad\nwhite forehead, beneath the transparent skin, looked knitted together;\nas head on, he came churning his tail among the boats; and", "labels": {"50": 22, "100": 78, "250": 205, "500": 469, "1000": 475, "2000": 213}}, {"id": 8274, "position": 8274, "text": ";\nas head on, he came churning his tail among the boats; and once more\nflailed them apart; spilling out the irons and lances from the two\nmates’ boats, and dashing in one side of the upper part of their bows", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8275, "position": 8275, "text": "boats, and dashing in one side of the upper part of their bows,\nbut leaving Ahab’s almost without a scar.\n\nWhile Daggoo and Queequeg were stopping the strained planks; and as the\nwhale swimming out from", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8276, "position": 8276, "text": "g were stopping the strained planks; and as the\nwhale swimming out from them, turned, and showed one entire flank as he\nshot by them again; at that moment a quick cry went up. Lashed round\nand round to the fish’s back", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8277, "position": 8277, "text": "quick cry went up. Lashed round\nand round to the fish’s back; pinioned in the turns upon turns in\nwhich, during the past night, the whale had reeled the involutions of\nthe lines around him, the half torn", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8278, "position": 8278, "text": "ed the involutions of\nthe lines around him, the half torn body of the Parsee was seen; his\nsable raiment frayed to shreds; his distended eyes turned full upon old\nAhab.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 531, "2000": 1620}}, {"id": 8279, "position": 8279, "text": "distended eyes turned full upon old\nAhab.\n\nThe harpoon dropped from his hand.\n\n“Befooled, befooled!”—drawing in a long lean breath—“Aye, Parsee! I see\nthee again.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8280, "position": 8280, "text": "long lean breath—“Aye, Parsee! I see\nthee again.—Aye, and thou goest before; and this, _this_ then is the\nhearse that thou didst promise. But I hold thee to the last letter of", "labels": {"50": 9, "100": 73, "250": 120, "500": 143, "1000": 118, "2000": 1312}}, {"id": 8281, "position": 8281, "text": "that thou didst promise. But I hold thee to the last letter of\nthy word. Where is the second hearse? Away, mates, to the ship! those\nboats are useless now; repair them if ye can in time, and return to", "labels": {"50": 9, "100": 64, "250": 163, "500": 180, "1000": 851, "2000": 689}}, {"id": 8282, "position": 8282, "text": "are useless now; repair them if ye can in time, and return to me;\nif not, Ahab is enough to die—Down, men! the first thing that but\noffers to jump from this boat I stand in, that thing I harp", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8283, "position": 8283, "text": "but\noffers to jump from this boat I stand in, that thing I harpoon. Ye are\nnot other men, but my arms and my legs; and so obey me.—Where’s the\nwhale? gone down again?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8284, "position": 8284, "text": "—Where’s the\nwhale? gone down again?”\n\nBut he looked too nigh the boat; for as if bent upon escaping with the\ncorpse he bore, and as if the particular place of the last encounter\nhad been but a stage in his", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8285, "position": 8285, "text": "if the particular place of the last encounter\nhad been but a stage in his leeward voyage, Moby Dick was now again\nsteadily swimming forward; and had almost passed the ship,—which thus\nfar had been sailing in the contrary direction to him,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8286, "position": 8286, "text": ",—which thus\nfar had been sailing in the contrary direction to him, though for the\npresent her headway had been stopped. He seemed swimming with his\nutmost velocity, and now only intent upon pursuing his own straight\npath in the sea.", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 925, "2000": 576}}, {"id": 8287, "position": 8287, "text": "now only intent upon pursuing his own straight\npath in the sea.\n\n“Oh! Ahab,” cried Starbuck, “not too late is it, even now, the third\nday, to desist. See! Moby Dick seeks thee not", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8288, "position": 8288, "text": "third\nday, to desist. See! Moby Dick seeks thee not. It is thou, thou, that\nmadly seekest him!”\n\nSetting sail to the rising wind, the lonely boat was swiftly impelled\nto leeward, by both o", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8289, "position": 8289, "text": ", the lonely boat was swiftly impelled\nto leeward, by both oars and canvas. And at last when Ahab was sliding\nby the vessel, so near as plainly to distinguish Starbuck’s face as he\nleaned over the rail, he", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8290, "position": 8290, "text": "to distinguish Starbuck’s face as he\nleaned over the rail, he hailed him to turn the vessel about, and\nfollow him, not too swiftly, at a judicious interval. Glancing upwards,\nhe saw Tashtego, Quee", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8291, "position": 8291, "text": "ious interval. Glancing upwards,\nhe saw Tashtego, Queequeg, and Daggoo, eagerly mounting to the three\nmast-heads; while the oarsmen were rocking in the two staved boats\nwhich had but just", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8292, "position": 8292, "text": "arsmen were rocking in the two staved boats\nwhich had but just been hoisted to the side, and were busily at work in\nrepairing them. One after the other, through the port-holes, as he\nsped, he also caught flying", "labels": {"50": 45, "100": 0, "250": 56, "500": 28, "1000": 856, "2000": 359}}, {"id": 8293, "position": 8293, "text": ", through the port-holes, as he\nsped, he also caught flying glimpses of Stubb and Flask, busying\nthemselves on deck among bundles of new irons and lances. As he saw all\nthis; as he heard the hammer", "labels": {"50": 45, "100": 64, "250": 163, "500": 73, "1000": 851, "2000": 967}}, {"id": 8294, "position": 8294, "text": "and lances. As he saw all\nthis; as he heard the hammers in the broken boats; far other hammers\nseemed driving a nail into his heart. But he rallied. And now marking\nthat the vane or flag was gone from the main", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 8295, "position": 8295, "text": "rallied. And now marking\nthat the vane or flag was gone from the main-mast-head, he shouted to\nTashtego, who had just gained that perch, to descend again for another\nflag, and a hammer and nails, and so", "labels": {"50": 45, "100": 64, "250": 82, "500": 327, "1000": 327, "2000": 967}}, {"id": 8296, "position": 8296, "text": "to descend again for another\nflag, and a hammer and nails, and so nail it to the mast.\n\nWhether fagged by the three days’ running chase, and the resistance to\nhis swimming in the knotted hamper he bore; or whether it was", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8297, "position": 8297, "text": "to\nhis swimming in the knotted hamper he bore; or whether it was some\nlatent deceitfulness and malice in him: whichever was true, the White\nWhale’s way now began to abate, as it seemed, from the boat so", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8298, "position": 8298, "text": "way now began to abate, as it seemed, from the boat so rapidly\nnearing him once more; though indeed the whale’s last start had not\nbeen so long a one as before. And still as Ahab glided over the waves\nthe un", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8299, "position": 8299, "text": "one as before. And still as Ahab glided over the waves\nthe unpitying sharks accompanied him; and so pertinaciously stuck to\nthe boat; and so continually bit at the plying oars, that the blades\nbecame jagged and crunch", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8300, "position": 8300, "text": "bit at the plying oars, that the blades\nbecame jagged and crunched, and left small splinters in the sea, at\nalmost every dip.\n\n“Heed them not! those teeth but give new rowlocks to your oars", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 8301, "position": 8301, "text": "not! those teeth but give new rowlocks to your oars. Pull\non! ’tis the better rest, the shark’s jaw than the yielding water.”\n\n“But at every bite, sir, the thin blades grow smaller and smaller", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8302, "position": 8302, "text": "“But at every bite, sir, the thin blades grow smaller and smaller!”\n\n“They will last long enough! pull on!—But who can tell”—he\nmuttered—“whether these sharks swim to feast on the whale or on\nAh", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1620}}, {"id": 8303, "position": 8303, "text": "muttered—“whether these sharks swim to feast on the whale or on\nAhab?—But pull on! Aye, all alive, now—we near him. The helm! take the\nhelm! let me pass,”—and so saying two", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8304, "position": 8304, "text": "! take the\nhelm! let me pass,”—and so saying two of the oarsmen helped him forward\nto the bows of the still flying boat.\n\nAt length as the craft was cast to one side, and ran ranging along with\nthe White", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 8305, "position": 8305, "text": "the craft was cast to one side, and ran ranging along with\nthe White Whale’s flank, he seemed strangely oblivious of its\nadvance—as the whale sometimes will—and Ahab was fairly within the\nsmoky mountain mist, which, thrown off from", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8306, "position": 8306, "text": "Ahab was fairly within the\nsmoky mountain mist, which, thrown off from the whale’s spout, curled\nround his great, Monadnock hump; he was even thus close to him; when,\nwith body arched back, and both", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8307, "position": 8307, "text": "even thus close to him; when,\nwith body arched back, and both arms lengthwise high-lifted to the\npoise, he darted his fierce iron, and his far fiercer curse into the\nhated whale", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8308, "position": 8308, "text": "fiercer curse into the\nhated whale. As both steel and curse sank to the socket, as if sucked\ninto a morass, Moby Dick sideways writhed; spasmodically rolled his\nnigh flank against the bow, and, without st", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8309, "position": 8309, "text": "dically rolled his\nnigh flank against the bow, and, without staving a hole in it, so\nsuddenly canted the boat over, that had it not been for the elevated\npart of the gunwale to which he then clung,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 8310, "position": 8310, "text": "for the elevated\npart of the gunwale to which he then clung, Ahab would once more have\nbeen tossed into the sea. As it was, three of the oarsmen—who foreknew\nnot the precise instant of the dart", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8311, "position": 8311, "text": "arsmen—who foreknew\nnot the precise instant of the dart, and were therefore unprepared for\nits effects—these were flung out; but so fell, that, in an instant two\nof them clutched the gunwale again", "labels": {"50": 26, "100": 67, "250": 235, "500": 87, "1000": 760, "2000": 450}}, {"id": 8312, "position": 8312, "text": ", that, in an instant two\nof them clutched the gunwale again, and rising to its level on a\ncombing wave, hurled themselves bodily inboard again; the third man\nhelplessly dropping astern, but still afloat and swimming.", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 8313, "position": 8313, "text": "third man\nhelplessly dropping astern, but still afloat and swimming.\n\nAlmost simultaneously, with a mighty volition of ungraduated,\ninstantaneous swiftness, the White Whale darted through the weltering\nsea", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8314, "position": 8314, "text": "darted through the weltering\nsea. But when Ahab cried out to the steersman to take new turns with\nthe line, and hold it so; and commanded the crew to turn round on their\nseats, and tow the boat up to the mark", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8315, "position": 8315, "text": "to turn round on their\nseats, and tow the boat up to the mark; the moment the treacherous line\nfelt that double strain and tug, it snapped in the empty air!\n\n“What breaks in me? Some sinew cracks!—’tis whole", "labels": {"50": 45, "100": 64, "250": 138, "500": 498, "1000": 327, "2000": 1620}}, {"id": 8316, "position": 8316, "text": "“What breaks in me? Some sinew cracks!—’tis whole again; oars! oars!\nBurst in upon him!”\n\nHearing the tremendous rush of the sea-crashing boat, the whale wheeled\nround to present his blank forehead at", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8317, "position": 8317, "text": "sea-crashing boat, the whale wheeled\nround to present his blank forehead at bay; but in that evolution,\ncatching sight of the nearing black hull of the ship; seemingly seeing\nin it the source of all his persecutions; bethinking it—it", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8318, "position": 8318, "text": "in it the source of all his persecutions; bethinking it—it may be—a\nlarger and nobler foe; of a sudden, he bore down upon its advancing\nprow, smiting his jaws amid fiery showers of foam.", "labels": {"50": 22, "100": 55, "250": 205, "500": 479, "1000": 475, "2000": 481}}, {"id": 8319, "position": 8319, "text": "prow, smiting his jaws amid fiery showers of foam.\n\nAhab staggered; his hand smote his forehead. “I grow blind; hands!\nstretch out before me that I may yet grope my way. Is’t night?”", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8320, "position": 8320, "text": "that I may yet grope my way. Is’t night?”\n\n“The whale! The ship!” cried the cringing oarsmen.\n\n“Oars! oars! Slope downwards to thy depths, O sea, that ere", "labels": {"50": 9, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8321, "position": 8321, "text": "oars! Slope downwards to thy depths, O sea, that ere it be for\never too late, Ahab may slide this last, last time upon his mark! I\nsee: the ship! the ship! Dash on, my men!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8322, "position": 8322, "text": "I\nsee: the ship! the ship! Dash on, my men! Will ye not save my ship?”\n\nBut as the oarsmen violently forced their boat through the\nsledge-hammering seas, the before whale-smitten bow-", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 8323, "position": 8323, "text": "sledge-hammering seas, the before whale-smitten bow-ends of two planks\nburst through, and in an instant almost, the temporarily disabled boat\nlay nearly level with the waves; its half-wading, splashing crew,", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 99, "2000": 1904}}, {"id": 8324, "position": 8324, "text": "level with the waves; its half-wading, splashing crew,\ntrying hard to stop the gap and bale out the pouring water.\n\nMeantime, for that one beholding instant, Tashtego’s mast-head hammer\nremained suspended", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8325, "position": 8325, "text": "ing instant, Tashtego’s mast-head hammer\nremained suspended in his hand; and the red flag, half-wrapping him as\nwith a plaid, then streamed itself straight out from him, as his own\nforward-flowing heart; while", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8326, "position": 8326, "text": "itself straight out from him, as his own\nforward-flowing heart; while Starbuck and Stubb, standing upon the\nbowsprit beneath, caught sight of the down-coming monster just as soon\nas he.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8327, "position": 8327, "text": "coming monster just as soon\nas he.\n\n“The whale, the whale! Up helm, up helm! Oh, all ye sweet powers of\nair, now hug me close! Let not Starbuck die, if die he must, in a\nwoman’", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8328, "position": 8328, "text": "Let not Starbuck die, if die he must, in a\nwoman’s fainting fit. Up helm, I say—ye fools, the jaw! the jaw! Is\nthis the end of all my bursting prayers? all my life-long", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8329, "position": 8329, "text": "Is\nthis the end of all my bursting prayers? all my life-long fidelities?\nOh, Ahab, Ahab, lo, thy work. Steady! helmsman, steady. Nay, nay! Up\nhelm again! He turns to", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8330, "position": 8330, "text": "sman, steady. Nay, nay! Up\nhelm again! He turns to meet us! Oh, his unappeasable brow drives on\ntowards one, whose duty tells him he cannot depart. My God, stand by me\nnow!”", "labels": {"50": 18, "100": 83, "250": 240, "500": 61, "1000": 672, "2000": 596}}, {"id": 8331, "position": 8331, "text": "he cannot depart. My God, stand by me\nnow!”\n\n“Stand not by me, but stand under me, whoever you are that will now\nhelp Stubb; for Stubb, too, sticks here", "labels": {"50": 22, "100": 55, "250": 28, "500": 479, "1000": 612, "2000": 1554}}, {"id": 8332, "position": 8332, "text": "Stubb, too, sticks here. I grin at thee, thou grinning\nwhale! Who ever helped Stubb, or kept Stubb awake, but Stubb’s own\nunwinking eye? And now poor Stubb goes to bed upon a", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8333, "position": 8333, "text": "unwinking eye? And now poor Stubb goes to bed upon a mattrass that is\nall too soft; would it were stuffed with brushwood! I grin at thee,\nthou grinning whale! Look ye, sun, moon, and stars", "labels": {"50": 9, "100": 73, "250": 133, "500": 72, "1000": 50, "2000": 1620}}, {"id": 8334, "position": 8334, "text": "thee,\nthou grinning whale! Look ye, sun, moon, and stars! I call ye assassins\nof as good a fellow as ever spouted up his ghost. For all that, I would\nyet ring glasses with ye, would ye but hand", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 1620}}, {"id": 8335, "position": 8335, "text": "all that, I would\nyet ring glasses with ye, would ye but hand the cup! Oh, oh! oh, oh!\nthou grinning whale, but there’ll be plenty of gulping soon! Why fly ye\nnot, O Ahab!", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8336, "position": 8336, "text": "plenty of gulping soon! Why fly ye\nnot, O Ahab! For me, off shoes and jacket to it; let Stubb die in his\ndrawers! A most mouldy and over salted death, though;—cherries!", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8337, "position": 8337, "text": "mouldy and over salted death, though;—cherries!\ncherries! cherries! Oh, Flask, for one red cherry ere we die!”\n\n“Cherries? I only wish that we were where they grow", "labels": {"50": 30, "100": 45, "250": 4, "500": 310, "1000": 846, "2000": 756}}, {"id": 8338, "position": 8338, "text": "”\n\n“Cherries? I only wish that we were where they grow. Oh, Stubb, I hope\nmy poor mother’s drawn my part-pay ere this; if not, few coppers will\nnow come to her, for the", "labels": {"50": 11, "100": 22, "250": 84, "500": 35, "1000": 991, "2000": 408}}, {"id": 8339, "position": 8339, "text": "; if not, few coppers will\nnow come to her, for the voyage is up.”\n\nFrom the ship’s bows, nearly all the seamen now hung inactive; hammers,\nbits of plank, lances, and harpoons, mechanically", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8340, "position": 8340, "text": "hammers,\nbits of plank, lances, and harpoons, mechanically retained in their\nhands, just as they had darted from their various employments; all\ntheir enchanted eyes intent upon the whale, which from side to side\nstrangely vibrating his predes", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8341, "position": 8341, "text": "intent upon the whale, which from side to side\nstrangely vibrating his predestinating head, sent a broad band of\noverspreading semicircular foam before him as he rushed. Retribution,\nswift vengeance, eternal malice were in his whole aspect", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8342, "position": 8342, "text": "he rushed. Retribution,\nswift vengeance, eternal malice were in his whole aspect, and spite of\nall that mortal man could do, the solid white buttress of his forehead\nsmote the ship’s starboard bow, till men and timbers reeled", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8343, "position": 8343, "text": "ote the ship’s starboard bow, till men and timbers reeled. Some fell\nflat upon their faces. Like dislodged trucks, the heads of the\nharpooneers aloft shook on their bull-like necks", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8344, "position": 8344, "text": "eers aloft shook on their bull-like necks. Through the breach,\nthey heard the waters pour, as mountain torrents down a flume.\n\n“The ship! The hearse!—the second hearse!” cried Ahab from the", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8345, "position": 8345, "text": "hearse!—the second hearse!” cried Ahab from the boat;\n“its wood could only be American!”\n\nDiving beneath the settling ship, the whale ran quivering along its\nkeel; but turning under water, swiftly shot to the surface", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8346, "position": 8346, "text": "quivering along its\nkeel; but turning under water, swiftly shot to the surface again, far\noff the other bow, but within a few yards of Ahab’s boat, where, for a\ntime, he lay quiescent.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8347, "position": 8347, "text": "where, for a\ntime, he lay quiescent.\n\n“I turn my body from the sun. What ho, Tashtego! let me hear thy\nhammer. Oh! ye three unsurrendered spires of mine; thou", "labels": {"50": 9, "100": 26, "250": 240, "500": 406, "1000": 779, "2000": 1502}}, {"id": 8348, "position": 8348, "text": "Oh! ye three unsurrendered spires of mine; thou uncracked keel;\nand only god-bullied hull; thou firm deck, and haughty helm, and\nPole-pointed prow,—death-glorious", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 16}}, {"id": 8349, "position": 8349, "text": "ughty helm, and\nPole-pointed prow,—death-glorious ship! must ye then perish, and\nwithout me? Am I cut off from the last fond pride of meanest\nshipwrecked captains? Oh, lonely death on", "labels": {"50": 9, "100": 26, "250": 133, "500": 143, "1000": 437, "2000": 1859}}, {"id": 8350, "position": 8350, "text": "pride of meanest\nshipwrecked captains? Oh, lonely death on lonely life! Oh, now I feel\nmy topmost greatness lies in my topmost grief. Ho, ho! from all your\nfurthest bounds, pour ye now in", "labels": {"50": 9, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 1620}}, {"id": 8351, "position": 8351, "text": "Ho, ho! from all your\nfurthest bounds, pour ye now in, ye bold billows of my whole foregone\nlife, and top this one piled comber of my death! Towards thee I roll,\nthou all-destroying but un", "labels": {"50": 16, "100": 73, "250": 133, "500": 441, "1000": 437, "2000": 1203}}, {"id": 8352, "position": 8352, "text": "of my death! Towards thee I roll,\nthou all-destroying but unconquering whale; to the last I grapple with\nthee; from hell’s heart I stab at thee; for hate’s sake I spit my last\nbreath at", "labels": {"50": 9, "100": 26, "250": 133, "500": 441, "1000": 589, "2000": 946}}, {"id": 8353, "position": 8353, "text": "stab at thee; for hate’s sake I spit my last\nbreath at thee. Sink all coffins and all hearses to one common pool!\nand since neither can be mine, let me then tow to pieces, while still\nchasing thee, though", "labels": {"50": 9, "100": 26, "250": 240, "500": 244, "1000": 663, "2000": 908}}, {"id": 8354, "position": 8354, "text": "mine, let me then tow to pieces, while still\nchasing thee, though tied to thee, thou damned whale! _Thus_, I give up\nthe spear!”\n\nThe harpoon was darted; the stricken whale flew forward; with igniting\nvelocity", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8355, "position": 8355, "text": "harpoon was darted; the stricken whale flew forward; with igniting\nvelocity the line ran through the grooves;—ran foul. Ahab stooped to\nclear it; he did clear it; but the flying turn caught him round the\nneck, and", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8356, "position": 8356, "text": "did clear it; but the flying turn caught him round the\nneck, and voicelessly as Turkish mutes bowstring their victim, he was\nshot out of the boat, ere the crew knew he was gone", "labels": {"50": 45, "100": 64, "250": 163, "500": 28, "1000": 642, "2000": 1904}}, {"id": 8357, "position": 8357, "text": "ere the crew knew he was gone. Next instant, the\nheavy eye-splice in the rope’s final end flew out of the stark-empty\ntub, knocked down an oarsman, and smiting the sea, disappeared in its", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 531, "2000": 1904}}, {"id": 8358, "position": 8358, "text": "down an oarsman, and smiting the sea, disappeared in its\ndepths.\n\nFor an instant, the tranced boat’s crew stood still; then turned. “The\nship? Great God, where is the ship?” Soon they through", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8359, "position": 8359, "text": "The\nship? Great God, where is the ship?” Soon they through dim, bewildering\nmediums saw her sidelong fading phantom, as in the gaseous Fata\nMorgana; only the uppermost masts out of water;", "labels": {"50": 45, "100": 64, "250": 138, "500": 73, "1000": 327, "2000": 967}}, {"id": 8360, "position": 8360, "text": "Fata\nMorgana; only the uppermost masts out of water; while fixed by\ninfatuation, or fidelity, or fate, to their once lofty perches, the\npagan harpooneers still maintained their sinking lookouts on the sea", "labels": {"50": 26, "100": 66, "250": 211, "500": 156, "1000": 602, "2000": 1283}}, {"id": 8361, "position": 8361, "text": ", the\npagan harpooneers still maintained their sinking lookouts on the sea.\nAnd now, concentric circles seized the lone boat itself, and all its\ncrew, and each floating oar, and every lance-pole, and spinning,\nanimate", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8362, "position": 8362, "text": "floating oar, and every lance-pole, and spinning,\nanimate and inanimate, all round and round in one vortex, carried the\nsmallest chip of the Pequod out of sight.", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8363, "position": 8363, "text": "quod out of sight.\n\nBut as the last whelmings intermixingly poured themselves over the\nsunken head of the Indian at the mainmast, leaving a few inches of the\nerect spar yet visible, together with long streaming yards of", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1620}}, {"id": 8364, "position": 8364, "text": "inches of the\nerect spar yet visible, together with long streaming yards of the flag,\nwhich calmly undulated, with ironical coincidings, over the destroying\nbillows they almost touched;—at that instant, a red arm and a", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 1904}}, {"id": 8365, "position": 8365, "text": "ows they almost touched;—at that instant, a red arm and a hammer\nhovered backwardly uplifted in the open air, in the act of nailing the\nflag faster and yet faster to the subsiding spar", "labels": {"50": 28, "100": 44, "250": 48, "500": 447, "1000": 960, "2000": 1461}}, {"id": 8366, "position": 8366, "text": "faster and yet faster to the subsiding spar. A sky-hawk that\ntauntingly had followed the main-truck downwards from its natural home\namong the stars, pecking at the flag, and incommoding Tashtego there", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8367, "position": 8367, "text": "ing at the flag, and incommoding Tashtego there;\nthis bird now chanced to intercept its broad fluttering wing between\nthe hammer and the wood; and simultaneously feeling that etherial\nthrill, the submerged savage beneath, in his death", "labels": {"50": 45, "100": 55, "250": 145, "500": 28, "1000": 959, "2000": 1904}}, {"id": 8368, "position": 8368, "text": "simultaneously feeling that etherial\nthrill, the submerged savage beneath, in his death-gasp, kept his\nhammer frozen there; and so the bird of heaven, with archangelic\nshrieks, and his imperial beak thrust upwards, and his whole captive\nform folded", "labels": {"50": 22, "100": 78, "250": 205, "500": 469, "1000": 783, "2000": 1976}}, {"id": 8369, "position": 8369, "text": "s, and his imperial beak thrust upwards, and his whole captive\nform folded in the flag of Ahab, went down with his ship, which, like\nSatan, would not sink to hell till she had dragged a living part of\nheaven along with her", "labels": {"50": 45, "100": 64, "250": 138, "500": 28, "1000": 327, "2000": 16}}, {"id": 8370, "position": 8370, "text": "sink to hell till she had dragged a living part of\nheaven along with her, and helmeted herself with it.\n\nNow small fowls flew screaming over the yet yawning gulf; a sullen\nwhite surf beat against its steep sides; then", "labels": {"50": 28, "100": 44, "250": 48, "500": 28, "1000": 9, "2000": 472}}, {"id": 8371, "position": 8371, "text": "ing gulf; a sullen\nwhite surf beat against its steep sides; then all collapsed, and the\ngreat shroud of the sea rolled on as it rolled five thousand years ago.\n\n\nEpilogue\n\n“AND I ONLY AM ESCAPED ALONE TO TELL THEE” Job.", "labels": {"50": 16, "100": 73, "250": 133, "500": 232, "1000": 779, "2000": 1203}}, {"id": 8372, "position": 8372, "text": ".\n\n\nEpilogue\n\n“AND I ONLY AM ESCAPED ALONE TO TELL THEE” Job.\n\nThe drama’s done. Why then here does any one step forth?—Because one\ndid survive the wreck.\n\nIt so chanced, that after the Parsee’s", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 8373, "position": 8373, "text": "the wreck.\n\nIt so chanced, that after the Parsee’s disappearance, I was he whom the\nFates ordained to take the place of Ahab’s bowsman, when that bowsman\nassumed the vacant post; the same, who,", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 327, "2000": 1620}}, {"id": 8374, "position": 8374, "text": ", when that bowsman\nassumed the vacant post; the same, who, when on the last day the three\nmen were tossed from out of the rocking boat, was dropped astern. So,\nfloating on the margin of the ensuing scene, and in", "labels": {"50": 45, "100": 64, "250": 138, "500": 43, "1000": 925, "2000": 576}}, {"id": 8375, "position": 8375, "text": "tern. So,\nfloating on the margin of the ensuing scene, and in full sight of it,\nwhen the halfspent suction of the sunk ship reached me, I was then, but\nslowly, drawn towards the closing vortex", "labels": {"50": 20, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1254}}, {"id": 8376, "position": 8376, "text": "was then, but\nslowly, drawn towards the closing vortex. When I reached it, it had\nsubsided to a creamy pool. Round and round, then, and ever contracting\ntowards the button-like black bubble at the axis of that slowly\nwheeling circle,", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 783, "2000": 377}}, {"id": 8377, "position": 8377, "text": "the button-like black bubble at the axis of that slowly\nwheeling circle, like another Ixion I did revolve. Till, gaining that\nvital centre, the black bubble upward burst; and now, liberated by\nreason of its cunning spring, and", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1254}}, {"id": 8378, "position": 8378, "text": "upward burst; and now, liberated by\nreason of its cunning spring, and, owing to its great buoyancy, rising\nwith great force, the coffin life-buoy shot lengthwise from the sea,\nfell over, and floated by my side", "labels": {"50": 25, "100": 5, "250": 26, "500": 411, "1000": 914, "2000": 1521}}, {"id": 8379, "position": 8379, "text": "shot lengthwise from the sea,\nfell over, and floated by my side. Buoyed up by that coffin, for almost\none whole day and night, I floated on a soft and dirgelike main", "labels": {"50": 45, "100": 64, "250": 138, "500": 388, "1000": 313, "2000": 1521}}, {"id": 8380, "position": 8380, "text": "a soft and dirgelike main. The\nunharming sharks, they glided by as if with padlocks on their mouths;\nthe savage sea-hawks sailed with sheathed beaks. On the second day, a\nsail drew near, nearer", "labels": {"50": 45, "100": 64, "250": 138, "500": 72, "1000": 825, "2000": 1014}}, {"id": 8381, "position": 8381, "text": "ed beaks. On the second day, a\nsail drew near, nearer, and picked me up at last. It was the\ndevious-cruising Rachel, that in her retracing search after her missing\nchildren, only found another orphan.", "labels": {"50": 13, "100": 79, "250": 41, "500": 153, "1000": 470, "2000": 1108}}]};
